INSERT INTO song_list (LISTID, NUM, NAME, TEXT_EN, TEXT_DE) VALUES
(9, '0001', 'Ich danke alles Jesus, verdanke alles Jesus', 'I owe it all to Jesus, I owe it all to Jesus.\nIf I am ever anything, all the praise to Him I bring.\nI owe it all to Jesus, I owe it all to Jesus.\nThis song of love from deep within, I owe it all to Him.\r\nIf I\'ve been used in some small way,\nto help someone in need today.\nAny good is found in me,\niIt\'s just because of Calvary.\r\nHe touched this blinded heart of mine,\nand now these precious ways I find.\nWhere He leads me I will go,\nso many others need to know.', 'Ich danke alles Jesus, verdanke alles Jesus.\nWenn jemals etwas war in mir, treuer Herr ich dank\' es Dir.\nIch danke alles Jesus, verdanke alles Jesus.\nAuch dieses Lied, das singt von Dir, nur Deine Gnade gab es mir.\r\nFindet sich Gutes heut\' an mir,\nund etwas spricht zurück zu dir;\nwenn jemals Echtes in mir war,\ndann durch den Sieg von Golgatha.\r\nDu hast mein blindes Herz berührt,\nhast mich auf Deinen Weg geführt.\nWo Du mich führst will ich heut\' geh\'n,\nauf das noch viele Jesus seh\'n.'),
(9, '0002', 'Magnify the Lord with me,come exalt His Name together - I sought the Lord and He answered me   (Psalm 34)', 'I sought the Lord and He answered me,\nand delivered me from every fear.\nThose who look on Him are radiant,\nthey\'ll never be ashamed, they\'ll never be ashamed.\r\nThis poor man cried and the Lord heard me,\nand saved me from my enemies.\nThe Son of God surrounds His saints,\nHe will deliver them,  He will deliver them.\r\nMagnify the Lord with me,\ncome exalt His name together.\nGlorify the Lord with me,\ncome exalt His name forever.\r\nOh taste and see that the Lord is good.\nOh blessed is he who hides in Him.\nOh fear the Lord oh all you saints.\nHe\'ll give you everything, He\'ll give you everything.\r\nLet us bless the Lord every day and night.\nNever ending praise may our incense rise.', 'Ich suchte den Herrn und er antwortete mir,\nund befreite mich von jeder Angst.\nDiejenigen, die auf Ihn schauen, sind leuchtend,\nsie werden sich niemals schämen, sie werden sich niemals schämen.\r\nDieser arme Mann schrie, und der Herr erhörte mich,\nund rettete mich vor meinen Feinden.\nDer Sohn Gottes umgibt seine Heiligen,\nEr wird sie erlösen,  Er wird sie erlösen.\r\nLobt den Herrn mit mir,\nkommt und preist gemeinsam seinen Namen.\nVerherrlicht den Herrn mit mir,\nkommt und preist seinen Namen für immer.\r\nO schmecke und sieh, dass der Herr gut ist.\nOh, gesegnet ist der, der sich in ihm verbirgt.\nOh, fürchtet den Herrn, oh, ihr alle Heiligen.\nEr wird euch alles geben, Er wird euch alles geben.\r\nLasst uns den Herrn loben, Tag und Nacht.\nUnendlicher Lobpreis möge unser Weihrauch aufsteigen.'),
(9, '0003', 'A different point of view', 'Lord, I look,\nlook away to You,\nthat will give me, Lord,\na different point of view.\r\nA different point of view,\nto see what God can do (2x)', '(Herr, ich schaue,\nschaue weg zu Dir,\ndas wird mir, Herr,\neinen anderen Blickwinkel.)\r\n(Eine andere Sichtweise,\num zu sehen, was Gott tun kann)'),
(9, '0004', 'A woman tried many Physicians yet grew worse  -  Eine Frau versuchte es bei vielen Ärzten   (Ihn berühren, allein ist von Bedeutung)', 'A woman tried many physicians\nyet grew worse, so to Jesus she came.\nAnd when the crowd tried to restrain her\nshe whispered these words through her pain.\r\nTouching Jesus is all that really matters,\nand my life will never be the same.\nThere is only one way to touch Him,\njust believe when you call on His name.\r\nI was bound when I knelt at that old altar,\nbut they said Jesus could meet ev’ry need.\nAnd when this pris’ner finally touched Jesus,\nHe set me free, praise the Lord, free indeed!', 'Eine Frau versuchte es bei vielen Ärzten,\ndoch es wurde immer schlimmer, also kam sie zu Jesus.\nUnd als die Menge versuchte, sie zurückzuhalten\nflüsterte sie diese Worte durch ihren Schmerz hindurch.\r\nIhn berühren, allein, ist von Bedeutung,\ndann wird mein Leben nie dasselbe mehr sein.\nDoch du kannst nur so Ihn berühren,\neinfach glaub\', wenn du Jesus anrufst.\r\nIch war gebunden, als ich vor dem alten Altar kniete,\naber sie sagten, Jesus könne jede Not lindern.\nUnd als dieser Gefangene schließlich Jesus berührte,\nmachte er mich frei, gelobt sei der Herr, wirklich frei!'),
(9, '0005', 'Abba, Vater Deine Lieb  -  Abba Father, let me be   (Chorus)', 'Abba Father, let me be, Yours and Yours alone.\nMay my will forever be evermore Your own.\nNever let my heart grow cold, never let me go.\nAbba Father, let me be, Yours and Yours alone.', 'Abba, Vater Deine Lieb\' nahm das Herz mir ein.\nOhne Deiner Nähe Licht kann ich nicht mehr sein.\nVater, halt\' mich immer fest, lass mich nie mehr geh\'n.\nDir vertrau\' ich Tag für Tag, Vater, ich bin Dein.'),
(9, '0006', 'Above all Powers, above all Kings  -  Herr, Du bist mächtig, bist hoch erhöht', 'Above all powers, above all kings.\nAbove all nature and all created things.\nAbove all wisdom and all the ways of man,\nYou were here before the world began.\r\nAbove all kingdoms, above all thrones.\nAbove all wonders the world has ever known.\nAbove all wealth and treasures of the earth,\nthere \'s no way to measure what You\'re worth.\r\nCrucified, laid behind a stone.\nYou lived to die, rejected and alone.\nLike a rose trampled on the ground.\nYou took the fall, and thought of me,\nabove all. (2x)', 'Herr, Du bist mächtig, bist hoch erhöht!\nHerr, Du bist prächtig, und was durch Dich geschieht.\nHerr, Deine Weisheit erstrahlt in Ewigkeit,\ndenn Du warst der Herr vor aller Zeit.\r\nHerr, Du bist König auf Deinem Thron!\nHerr, Du bist Schöpfer und schenkst uns Deinen Sohn.\nHerr, Deine Schönheit ist unermesslich groß.\nDeine Liebe lässt mich nicht mehr los.\r\nGroßer Gott, Du hast Dich klein gemacht.\nDu starbst für mich und riefst: Es ist vollbracht!\nWie ein Lamm nahmst Du es auf Dich,\nall meine Schuld und rettest mich.\nMächtiger Herr. (2x)'),
(9, '0007', 'Ach, Blätter nur! Das ist betrübt  -  Nothing but Leaves! The Spirit grieves', 'Nothing but leaves! The Spirit grieves\no\'er years of wasted life.\nO\'er sins indulged while conscience slept,\no\'er vows and promises unkept,\nand reap from years of strife.\nNothing but leaves! Nothing but leaves!\r\nNothing but leaves! No gathered sheaves\nof life\'s fair ripening grain.\nWe sow our seeds; lo! tares and weeds,\nwords, idle words, for earnest deeds,\nthen reap, with toil and pain.\nNothing but leaves! Nothing but leaves!\r\nNothing but leaves! Sad mem\'ry weaves\nno vail to hide the past.\nAnd as we trace our weary way,\nand count each lost and misspent day,\nwe sadly find at last.\nNothing but leaves! Nothing but leaves!\r\nAh, who shall thus The Master meet,\nand bring but withered leaves?\nAh, who shall at the Saviour\'s feet,\nbefore the awful judgment seat\nlay down for golden sheaves.\nNothing but leaves! Nothing but leaves!', 'Ach, Blätter nur! Das ist betrübt;\nsieh, wie dein Heiland weint!\nSo wenig Treu hast du geübt,\nso wenig hast du Ihn geliebt,\ndass nichts an dir erscheint\nals Blätter nur, ach, Blätter nur!\r\nAch, Blätter nur! Wo ist die Frucht\nvon deiner Lebenssaat?\nSchon lang hat sie dein Herr gesucht.\nBald wird es heißen:\n"Sei verflucht!" O wehe, wer nichts hat\nals Blätter nur, ach, Blätter nur!\r\nAch, Blätter nur! O Schmach und Leid!\nDas Leben eilt dahin.\nVerloren hast du deine Zeit,\nversäumt hast du die Ewigkeit!\nWas hast du zum Gewinn?\nAch, Blätter nur, ach Blätter nur!\r\nAch, Blätter nur! Wie kannst du\nso vor deinem Herrn bestehn?\nDa wirst du keiner Garbe froh,\nda brennt die Flamme lichterloh,\nwie Spreu wirst du verweh\'n!\nAch, Blätter nur, ach Blätter nur!'),
(9, '0008', 'Ach, bleib mit Deiner Gnade', NULL, 'Ach, bleib mit Deiner Gnade\nbei uns, Herr Jesus Christ,\ndass uns hinfort nicht schade\ndes bösen Feindes List!\r\nAch, bleib mit Deinem Worte\nbei uns, Erlöser wert,\ndass uns stets hier und dorte\nsei Güt und Heil beschert!\r\nAch, bleib mit Deinem Glanze\nbei uns, Du wertes Licht;\nDein Wahrheit uns umschanze,\ndamit wir irren nicht!\r\nAch, bleib mit Deinem Segen\nbei uns, Du reicher Herr,\nDein Gnad und alls Vermögen\nin uns reichlich vermehr!\r\nAch, bleib mit Deinem Schutze\nbei uns, Du starker Held,\ndass uns der Feind nicht trutze,\nnoch fäll die böse Welt!\r\nAch bleib mit Deiner Treue\nbei uns, mein Herr und Gott,\nBeständigkeit verleihe,\nhilf uns aus aller Not!'),
(9, '0009', 'Ach, mein Herr Jesus, wenn ich dich nicht hätte', NULL, 'Ach, mein Herr Jesus, wenn ich dich nicht hätte,\nund wenn dein Blut nicht für die Sünder red\'te,\nwo sollt ich Ärmster unter den Elenden\nmich sonst hinwenden?\r\nIch wüsste nicht, wo ich vor Jammer bliebe;\ndenn wo ist solch ein Herz, wie Dein\'s, voll Liebe?\nDu, Du bist meine Zuversicht alleine;\nsonst weiß ich keine.\r\nIch bin in Wahrheit eins der schlecht\'sten Wesen,\ndas Du Dir, lieber Heiland, hast erlesen,\nund was Du tust, das sind Barmherzigkeiten\nauf allen Seiten.\r\nHätt\'st Du Dich nicht zuerst an mich gehangen,\nich wär\' von selbst Dich wohl nicht suchen \'gangen;\nd\'rum sucht\'st Du mich, umfingst mich voll Erbarmen\nmit Deinen Armen.\r\nNun dank\' ich Dir vom Grunde meiner Seelen,\ndass Du nach Deinem ewigen Erwählen\nauch mich zu deiner Blutsgemeinde brachtest\nund selig machtest.\r\nHör\' niemals auf, Dich so zu offenbaren,\nwie wir\'s bis an den heut\'gen Tag erfahren.\nVerherrliche an uns Herr, Deinen Namen\nohn\' Ende. Amen.'),
(9, '0010', 'Ach, sagt mir nichts von Gold und Schätzen   (Ein jeder liebe was er will, ich liebe Jesus, Er mein Ziel)', NULL, 'Ach, sagt mir nichts von Gold und Schätzen,\nvon Pracht  und Schönheit dieser Welt.\nEs kann mich ja kein Ding ergötzen,\ndas mir die Welt vor Augen stellt.\r\nEin jeder liebe was er will,\nich liebe Jesus, Er mein Ziel.\nEin jeder liebe was er will,\nich liebe Jesus, Er mein Ziel.\r\nEr ist alleine meine Freude,\nmein Gold, mein Schatz, mein schönstes Bild,\nan dem ich meine Augen weide\nund finde, was mein Herze stillt.\r\nDie Welt vergeht mit ihren Lüsten,\ndes Fleisches Schönheit dauert nicht.\nDie Zeit kann alles das verwüsten,\nwas Menschenhände zugericht\'.\r\nEr kann mich über alles heben\nund Seiner Klarheit machen gleich.\nEr kann mir so viel Schätze geben,\ndass ich werd\' unerschöpflich reich.'),
(9, '0011', 'Ach, wann ist mein Pilgern hier aus, wann öffnet der Himmel sich mir   (Sei gegrüßt tönt es dort, willkommen im Namen des Herrn)', NULL, 'Ach, wann ist mein Pilgern hier aus,\nwann öffnet der Himmel sich mir?\nUnd wenn ich einst komme nach Haus\',\nblüht mir ein Willkomm\'n an der Tür?\r\nSei gegrüßt! tönt es dort, willkommen im Namen des Herrn!\nSüßes Heim, sel\'ger Ort, ich grüß\' dich von fern!\r\nGeliebte, im Herrn mir verwandt,\nmit denen ich einstens hier sang,\ndarf seh\'n ich im himmlischen Land\nund grüßen im freudigen Drang.\r\nWie herrlich, wenn dann sich enthüllt\nJerusalems Edelgestein!\nAch, da wird mein Heimweh gestillt,\ndann darf ich bei Jesus stets sein.\r\nDann bring\' ich, gewaschen im Blut,\nlobpreisend dem Lamme die Ehr\';\ndort haben wir\'s ewiglich gut,\nwie freu\' ich mich darauf so sehr!'),
(9, '0012', 'Adresse', 'AM EGELSBERG 87\n47802 KREFELD', NULL),
(9, '0013', 'Agnus dei', 'Alleluia, Alleluia\nFor the Lord God Almighty reigns\nAlleluia, Alleluia\nFor the Lord God Almighty reigns\nAlleluia\r\nHoly, Holy\nAre You Lord God, Almighty\nWorthy is the Lamb, worthy is the Lamb\nYou are Holy, Holy\nAre You Lord God, Almighty\nWorthy is the Lamb, worthy is the Lamb\nAmen', 'Halleluja, Halleluja\nDenn der Herr, der allmächtige Gott, regiert\nHalleluja, Halleluja\nDenn der Herr, der allmächtige Gott, regiert\nHalleluja\r\nHeilig, heilig\nBist Du Herr, Gott, Allmächtiger\nWürdig ist das Lamm, würdig ist das Lamm\nDu bist heilig, heilig\nBist Du Herr, Gott, Allmächtiger\nWürdig ist das Lamm, würdig ist das Lamm\nAmen'),
(9, '0014', 'All I want is You Lord  -  Alles, was ich will, bist Du, Herr   (Chorus)', 'All I want is You Lord,\nall I want is You.\nNo one else but You Lord.\nAll I want is You.', '(Alles, was ich will, bist Du, Herr,\nalles, was ich will, bist Du.\nNiemand anderes als Dich, Herr.\nAlles, was ich will, bist Du.)'),
(9, '0015', 'All I want to do is love Him  -  Alles was ich tun möchte, ist Ihn zu lieben   (Chorus)', 'All I want to do is love Him,\nso glad I feel His love for me.\nJesus paid the price of redemption\non the cross of Calvary.\nSo, every day my heart will praise Him\nI know I\'ll never be the same.\nAll I want to do is love Him,\nlove His holy name.', 'Alles was ich tun möchte, ist Ihn zu lieben,\nich bin so froh, dass ich Seine Liebe zu mir spüre.\nJesus hat den Preis der Erlösung\nam Kreuz auf Golgatha bezahlt.\nSo, jeden Tag wird mein Herz Ihn preisen\nund ich weiß, ich werde nie mehr derselbe sein.\nAlles, was ich tun will, ist Ihn zu lieben,\nSeinen heiligen Namen lieben.'),
(9, '0016', 'All that I am, all that I have  -  Alles was ich bin, alles was ich habe   (Lord I offer my Life to You / Herr, ich opfere Dir mein Leben)', 'All that I am, all that I have,\nI lay them down before You, oh Lord.\nAll my regrets, all my acclaims,\nthe joy and the pain, I\'m making them Yours.\r\nLord, I offer my life to You,\neverything I\'ve been through, use it for Your glory.\nLord I offer my days to You,\nlifting my praise to You as a pleasing sacrifice.\nLord I offer You my life.\r\nThings in the past, things yet unseen,\nwishes and dreams that are yet to come true.\nAll of my heart, all of my praise,\nmy heart and my hands are lifted to You.\r\nWhat can we give that You have not given?\nAnd what do we have that is not already Yours?\nAll we possess are these lives we\'re living,\nthat\'s what we give to You, Lord.\r\nLord, I offer my life to You, everything I\'ve been through,\nuse it for Your glory.\nLord I offer my days to You, lifting my praise to You\nas a pleasing sacrifice.\nLord I offer You my life, Lord I offer You my life.', '(Alles was ich bin, alles was ich habe,\nich lege es vor Dir nieder, oh Herr.\nAlles, was ich bedau\'re, alles, was ich bejub\'le,\ndie Freude und den Schmerz, ich mache sie zu Deinem.)\r\n(Herr, ich opfere Dir mein Leben,\nalles, was ich durchgemacht habe, benutze es zu Deinem Ruhm.\nHerr, ich opfere Dir meine Tage,\nerhebe mein Lob zu Dir als ein angenehmes Opfer.\nHerr, ich opfere Dir mein Leben.)\r\nDinge der Vergangenheit, noch nicht geschehene Dinge,\nWünsche und Träume, die noch nicht in Erfüllung gegangen sind.\nMein ganzes Herz, mein ganzer Lobpreis,\nmein Herz und meine Hände sind zu Dir empor gehoben.\r\nWas können wir geben, was Du nicht gegeben hast?\nUnd was haben wir, das nicht schon Dein ist?\nAlles, was wir besitzen, ist das Leben, das wir führen,\ndas ist es, was wir Dir geben, Herr.\r\nHerr, ich opfere Dir mein Leben, alles, was ich durchgemacht habe,\nbenutze es zu Deinem Ruhm.\nHerr, ich opfere Dir meine Tage, erhebe mein Lob zu Dir\nals ein wohlgefälliges Opfer.\nHerr, ich opfere Dir mein Leben, Herr, ich opfere Dir mein Leben.'),
(9, '0017', 'All they who put their Trust in God can never be removed   (Like the Mount of God)', 'All they who put their trust in God\ncan never be removed.\nThey stand secure like Zion\'s mount,\nby many ages proved.\r\nLike the mount of God,\nlike the mount of God.\nThey stand secure like Zion\'s mount,\nby many ages proved.\nThey can never be removed, removed.\nThey stand secure like Zion\'s mount,\nthey can never be removed.\r\nAs round about Jerusalem\nthe rugged mountains lie,\nso round about His holy saints\nour God is ever nigh.\r\nTho\' fierce the storm in fury beat\nand awful thunders roar,\nthe children of the mighty God\nare safe forevermore.\r\nThus over-shadowed by His love,\nwhere harm can ne\'er betide,\nwithin this refuge safe and sure\nI ever would abide.', NULL),
(9, '0018', 'All Things, all Things work together', 'All things, all things,\nall things work together\nfor those that love Him.\nAll things, all things,\nall things work together\nfor good.\r\nSometimes you cannot see\nwhat your life\'s going to be\nbut God will make a way\nand turn your night to day.\r\nAnd when He is your friend\nHe holds you in His hand\nand when He is your Lord\nHe leads you by His Word.\r\nForever Jesus knew\nwhat you have to go through\nand when He helps, you see\nHe´s greater than your needs.\r\n\r\n\r\n', '\r\n\r\n\r\n\r\nAlles, alles, alles führt der\nHeiland für Seine Kinder.\nAlles, alles, alles führt der\nHeiland für uns.\r\nManchmal kannst du nichts seh\'n,\ndein Leben nicht versteh\'n,\ndoch Gott bahnt dir den Weg\nund führt dich hin zum Sieg.\r\nUnd ist dein Weg auch schwer\ndas wusste schon dein Herr,\nEr hilft dir in der Not,\nja, so groß ist dein Gott!'),
(9, '0019', 'Alle Wege leitet Jesus mich  -  All the Way my Lord is leading me   (Halleluja ist mein Gesang)   [Pfingstjubel]', 'All the way my Lord is leading me.\nPraise His name, praise His name!\nWith His heav’nly manna feeding me,\npraise His holy name.\r\nJesus, Jesus! This is my song,\nJesus, Jesus the whole day long.\nHe is mine, a Saviour divine.\nPraise His holy name.\r\n\r\n\r\n\r\n\r\n', 'Alle Wege leitet Jesus mich!\nLob und Dank, Lob und Dank!\nHimmlisch Mann speist und lechzet mich;\nLob und Dank und Preis!\r\nHalleluja ist mein Gesang,\nJesu sing ich mein Leben lang.\nEr hat gestillt meines Herzens Drang!\nEhre sei dem Herrn!\r\nAlles ist in Ihm gegeben hier;\nLob und Dank, Lob und Dank!\nSeinen Tisch bereitet Er vor mir,\nLob und Dank und Preis!\r\nGegen Feinde schützt Er mich all\'zeit,\nLob und Dank, Lob und Dank!\nMir zu helfen ist Er stets bereit.\nLob und Dank und Preis!\r\nNiemals hat Er übersehen mich,\nLob und Dank, Lob und Dank!\nWenn mich Satan anficht\' mächtiglich!\nLob und Dank und Preis!\r\nAus der Welt hat Er genommen mich,\nLob und Dank, Lob und Dank!\nUnd ein ewig Reich erwartet mich!\nLob und Dank und Preis!\r\nJedes Rätsel löset Jesus mir.\nLob und Dank, Lob und Dank.\nAlle Wege freu\' ich mich in Dir!\nLob und Dank und Preis!'),
(9, '0020', 'Allein Deine Gnade genügt - Your grace is sufficient for me ()', 'Your grace is sufficient for me,\nYour strength is made perfect.\nWhen I am weak all that I cling to, I lay at Your feet.\nYour grace is sufficient for me.\r\nI\'m longer striving to merit Your love,\nI rest in Your promise to me.\nThat all of my sins have been washed in Your blood.\nYour mercy is all that I need.\r\nYou see me as righteous because of the blood,\nthat made me the atonement for me.\nYour mercy has triumphed where I should be judged,\nso now by Your grace I am free.', 'Allein Deine Gnade genügt,\ndie in meiner Schwachheit Stärke mir gibt.\nIch geb\' Dir mein Leben und was mich bewegt.\nAllein Deine Gnade genügt.\r\nIch muss mich nicht länger um Liebe bemüh\'n,\nich ruh\' im Vertrauen zu Dir.\nDu hast meine Sünde getilgt durch Dein Blut,\nund Gnade ist für mich genug.\r\nDas Blut Jesu lässt mich gerecht vor Dir steh\'n,\nes hat alle Schuld gesühnt.\nDie Gnade hat über Gericht triumphiert,\nund nun bin ich frei in Dir.'),
(9, '0021', 'Allein durch Gnade steh ich hier  -  By Grace alone somehow I stand   (Mutig komm ich vor den Thron / Boldly I approach Your Throne)', 'By grace alone somehow I stand\nwhere even angels fear to tread.\nInvited by redeeming love\nbefore the throne of God above.\nHe pulls me close with nail-scarred hands\ninto his everlasting arms.\r\nWhen condemnation grips my heart\nand satan tempts me to despair.\nI hear the voice that scatters fear\nthe Great I AM The Lord is here.\nOh praise the One who fights for me\nand shields my soul eternally.\r\nBoldly I approach Your throne,\nblameless now I\'m running home.\nBy your blood I come\nwelcomed as your own\ninto the arms of Majesty.\r\nBehold the bright and risen Son,\nmore beauty than this world has known,\nI\'m face to face with love Himself.\nHis perfect spotless righteousness.\nA thousand years, a thousand tongues\nare not enough to sing his praise.\r\nThis is the art of celebration,\nknowing we\'re free from condemnation.\nOh praise the One, praise the One\nwho make an end to all my sin. (2x)', 'Allein durch Gnade steh ich hier,\nvor Deinem Thron mein Gott bei Dir.\nDer mich erlöst hat, lädt mich ein,\nganz nah an Seinem Herz zu sein.\nDurchbohrte Hände halten mich.\nIch darf bei Dir sein ewiglich.\r\nWenn mich mein Herz erneut verdammt,\nund Satan flößt mir Zweifel ein.\nHör ich die Stimme meines Herrn,\ndie Furcht muss fliehen denn ich bin Sein.\nOh preist den Herrn, der für mich kämpft.\nUnd meine Seele ewig schützt.\r\nMutig komm ich vor den Thron,\nfreigesprochen durch den Sohn.\nDein Blut macht mich rein.\nDu nennst mich ganz Dein.\nIn Deinen Armen darf ich sein.\r\nSeht doch wie herrlich Jesus ist,\nder alle Schönheit übertrifft.\nDie Liebe in Person ist hier,\ngerecht und treu steht Er zu mir.\nAll unser Lob reicht niemals aus,\nIhn so zu ehr\'n, wie\'s Ihm gebührt.\r\nDas ist der Grund, warum wir feiern.\nWir sind befreit, Er trug das Urteil.\nPreist den Herrn, preist den Herrn.\nEr hat für meine Schuld bezahlt. (2x)'),
(9, '0022', 'Alles bereitet, kommt zu dem Mahl  -  All Things are ready, come to the Feast   (Hört die Stimme rufen: Komm, wer da immer will)', 'All things are ready: "Come to the feast!"\nCome, for the table now is spread.\nYe famishing, ye weary, come,\nand thou shalt be richly fed.\r\nHear the invitation: "Come, whosoever will"\nPraise God for full salvation, for "whosoever will."\r\nAll things are ready: "Come to the feast!"\nCome, for the door is open wide.\nA place of honour is reserved,\nfor you at the Master\'s side.\r\nAll things are ready "Come to the feast!"\nCome, while He waits to welcome thee.\nDelay not while this day is thine,\ntomorrow may never be.\r\nAll things are ready "Come to the feast!"\nLeave every care and worldly strife.\nCome, feast upon the love of God,\nand drink everlasting life.', 'Alles bereitet, kommt zu dem Mahl!\nKommt, denn der Tisch ist reich gedeckt.\nIhr Hungernden, ja kommt und seht,\nwie köstlich die Gnade schmeckt.\r\nHört die Stimme rufen: "Komm, wer da immer will!"\nPreis Gott für Heil und Leben, für jeden der da will.\r\nAlles bereitet, kommt zu dem Mahl!\nKommt, denn die Tür steht offen weit.\nEin Platz der Gnade ist bereit für dich\nan des Heilands Seit\'.\r\nAlles bereitet, kommt zu dem Mahl!\nEr hat die Arme ausgebreit\'.\nVergeude nicht die Gnadenzeit\nund komm zu dem Herrn noch heut\'!\r\nAlles bereitet, kommt zu dem Mahl!\nLasse die Welt doch jetzt zurück!\nKomm, speise doch an Seinem Tisch\nund finde das wahre Glück!'),
(9, '0023', 'Alles das was ich hab, was mir teuer und wert  -  The Things that I love and hold dear to my Heart   (Zieh hinweg den Vorhang)', 'The things that I love and hold dear to my heart,\nare just borrowd, they\'re not mine at all.\nJesus only let me use them to brighten my life,\nso remind me, remind me dear Lord.\r\nRoll back the curtain of mem\'ry now and then\nshow me where You brought me from, and where I could have been.\nRemember I\'m human, and humans forget,\nso remind me, remind me dear Lord.\r\nNothing good have I done to derserve God\'s own Son,\nI’m not worthy of the scars in His hands.\nYet He chose the road to Calvary to die in my stead,\nwhy He loved me I cant\'t understand.\r\n(Looking up to You I may now be confident,\nfor You have revealed Your word to me.\nFill me with your spirit, keep me always faithful to you!\nYes, I love you, because you have loved me.)', 'Alles das was ich hab, was mir teuer und wert,\nist geliehen; Gott hat\'s mir gewährt.\nJesus schenkt mir viele Dinge, macht Mut auf dem Weg.\nLass mich denken, ja denken daran.\r\nZieh hinweg den Vorhang, dass ich seh\', was Du getan.\nZeig mir, wo ich heute wär\', und dass Du nahmst mich an.\nBedenk\', wir sind Menschen, vergesslich und schwach,\nsei uns gnädig, halt über uns Wacht.\r\nNiemals hab\' ich verdient Gottes Liebe so groß,\ndass am Kreuze Er kaufte mich los.\nDort starb Er an meiner Stelle, ja trug meine Schuld.\nSolche Liebe, ich kann\'s nicht versteh\'n.\r\nIm  Aufblick zu Dir darf getrost ich nun sein,\ndenn Du hast mir Dein Wort offenbart.\nFüll\' mich doch mit deinem Geiste, halt mich stets Dir treu!\nJa, ich lieb\' Dich, weil Du mich geliebt.'),
(9, '0024', 'Alles ist Dein und alles ist mein in Dir   (Halleluja, Halleluja, Halleluja, ich bin ein Königskind)', NULL, 'Alles ist Dein und alles ist mein in Dir.\nDein ist die Macht, ich rühm\' Deine Kraft an mir.\nIch bin Dein Kind, ich preis\' Deine Lieb\'\nfür Christus, der einst ans Kreuz für mich ging.\nO Heiland, hab\' Dank, in Dir bin ich reich gemacht.\r\nHalleluja, Halleluja, Halleluja, ich bin ein Königskind!\nHalleluja, Halleluja, Halleluja, ich bin ein Königskind!\r\nDu bist der Herr und Du bist der König ewiglich.\nSprich durch Dein Wort, Dein Name ist süß, ich rühme Dich.\nIch will Dich anschau\'n in Ewigkeit,\ndie Herrlichkeit hältst Du für mich bereit.\nDurch Deine Kraft wirst Du führen Dein Volk zum Ziel.\r\nIn Dir ist Frieden, in Dir ist Ruh\' für ewig da.\nIch flieh\' zu Dir, in Schwachheit und Not bist Du mir nah.\nAll meine Sorgen bring ich zu Dir,\nund so bleibt ein tiefer Friede in mir.\nO Vater, bewahr\' mich ewig in Deinem Wort.'),
(9, '0025', 'Alles ist gut, alles ist gut  -  All is well, all is well', 'All is well, all is well,\nI have heard the message\n"Shalom" and all is well.\nThere is a place of perfect rest,\nbehind the inner veil.\nSo, rest, little Bride,\nrest, for all is well!', 'Alles ist gut, alles ist gut,\nich hab\' gehört die Botschaft\n"Shalom", alles ist gut.\nEin Ruheort hinterm Vorhang\ndort ist schon für mich bereit.\nRuh in Ihm, kleine Braut,\nin Ihm, alles ist gut!'),
(9, '0026', 'Alles Leben strömt aus Dir', NULL, 'Alles Leben strömt aus Dir,\nund durchwallt in tausend Bächen,\nalle Welten; alle sprechen:\nDeiner Hände Werk sind wir!\r\nDass ich fühle, dass ich bin,\ndas ich Dich, Du Großer kenne\ndass ich froh Dich Vater nenne;\no, ich sinke vor Dir hin!\r\nWelch ein Trost und unbegrenzt,\nund unnennbar ist die Wonne,\ndass, gleich Deiner milden Sonne,\nmich Dein Vateraug umglänzt!\r\nDeiner Gegenwart Gefühl\nsei mein Engel, der mich leite,\ndass mein schwacher Fuß nicht gleite,\nnicht sich irre von dem Ziel!'),
(9, '0027', 'Alles was mir einst so wertvoll schien  -  All I once held dear built my Life upon   (Dich erkennen, Jesus, Dir nahe sein)', 'All I once held dear built my life upon.\nAll this world reverses and wants to own.\nAll I once thought gain I have counted loss.\nSpent and worthless now compared to this.\r\nKnowing You Jesus, knowing You,\nthere is no greater thing.\nYou\'re my all You\'re the best.\nYou\'re my joy my righteousness\nand I love You Lord.\r\nNow my heart\'s desire is to know You more,\nto be found in You and known as Yours.\nTo possess by faith what I could not earn.\nAll surpassing gift of righteousness.\r\nOh to know the power of Your risen life\nand to know You in Your sufferings.\nTo become like You in Your death my Lord.\nSo with You to live and never die.', 'Alles was mir einst so wertvoll schien,\nwas die Welt verehrte als Gewinn,\nachte ich für nichts, lauter Schaden nur,\nleer und wertlos im Vergleich zu Dir!\r\nDich erkennen, Jesus,\nDir nahe sein,\ndas ist mein höchstes Ziel.\nDu bist alles für mich,\nFreude, Trost und Zuversicht,\nund ich lieb‘ Dich, Herr!\r\nImmer mehr mit Dir verbunden sein,\nganz erfüllt von Dir soll mein Leben sein.\nNur durch Glauben und nicht durch mein\'n Verdienst,\ndenn Gerechtigkeit ist Dein Geschenk!\r\nDeine Kraft der Auferstehung seh\'n,\ndie Gemeinschaft Deiner Leiden versteh\'n.\nGleich zu werden wie Du in Deinem Tod\nund für ewig leben mit Dir, mein Gott!'),
(9, '0028', 'Alles will ich Jesus weihen  -  All to Jesus I surrender   (Alles will ich weihn / I surrender all)', 'All to Jesus I surrender,\nall to Him I freely give.\nI will ever love and trust him,\nin his presence daily live.\r\nI surrender all,\nI surrender all,\nall to Thee, my blessed Saviour,\nI surrender all.\r\nAll to Jesus I surrender,\nhumbly at his feet I bow.\nWordly pleasures all forsaken,\ntake me, Jesus, take me now.\r\nAll to Jesus I surrender.\nmake me, Saviour, wholly Thine.\nLet me feel Thy Holy Spirit,\ntruly know that Thou art mine.\r\nAll to Jesus I surrender,\nLord, I give myself to Thee.\nFill me with Thy love and power,\nlet Thy blessing fall on me.\r\nAll to Jesus I surrender,\nnow I feel the sacred flame.\nOh, the joy of full salvation!\nGlory, glory to His name!', 'Alles will ich Jesus weihen,\nnichts mehr will ich nennen mein.\nLeib und Seele, Gut und Habe,\nalles soll Sein eigen sein.\r\nAlles will ich weih\'n,\nalles will ich weih\'n,\nDir, mein Herr, mein Gott, mein Heiland,\nwill ich alles weih\'n.\r\nAlles will ich Jesus weihen,\nall mein Herz zu Ihm sich neigt.\nAll mein sünd\'ger stolzer Wille,\nsich dem Herrn gehorsam beugt.\r\nAlles will ich Jesus weihen,\nhalte alle Welt für Spreu.\nDoch was ich dem Heiland schenke,\ngibt Er mir verklärt und neu.\r\nAlles will ich Jesus weihen,\nmeines Geistes beste Kraft.\nAll mein Denken, all mein Streben,\nalles, was mein Tagwerk schafft.\r\nAlles will ich Jesus weihen.\nNimm mein Opfer gnädig auf.\nSprich zu meinem Wort Dein Amen,\ndrück\' Dein heilig Siegel drauf!'),
(9, '0029', 'Alles will ich, Herr, verlassen  -  Jesus, I my Cross have taken', 'Jesus, I my cross have taken,\nall to leave and follow Thee.\nDestitute, despised, forsaken,\nThou from hence my all shalt be.\nPerish ev\'ry fond ambition,\nall I\'ve sought or hoped or known.\nYet how rich is my condition,\nGod and heav\'n are still my own.\r\nLet the world despise and leave me,\nthey have left my Saviour too.\nHuman hearts and looks deceive me,\nThou art not, like man, untrue.\nAnd while thou shalt smile upon me,\nGod of wisdom, love, and might.\nFoes may hate and friends may shun me,\nshow Thy face and all is bright.\r\nArm yourself with the sword of spirit,\nfirmly grasp the shield of faith.\nTread down world and lusts,\nfor the victor\'s wreath it is.\nCourage, your course is soon completed,\nfight right to the end!\nThe Lord waits for you and gives,\nrich reward to the faithful servant.', 'Alles will ich, Herr, verlassen,\nDir allein zu folgen nach.\nArm und bloß, auf öden Straßen,\nstill wie Du mein Kreuz ich trag’.\nAll\' mein Suchen, Trachten, Streben,\nird’scher Hoffnung eitler Schein.\nFahre hin! Mein wahres Leben\nbleibt mir doch: Der Herr ist mein!\r\nMag die Welt mich immer hassen,\nJesus hat sie auch geschmäht!\nMögen Menschen mich verlassen,\nJesu Treue nie vergeht.\nLass mir leuchten deine Gnade,\nGott der Weisheit, Lieb’ und Macht.\nSegen wird mir dann der Schade,\nFreud’ der Schmerz und Licht die Nacht.\r\nMit des Geistes Schwert dich rüste,\nfasse fest des Glaubens Schild.\nTritt darnieder Welt und Lüste,\ndenn des Siegers Kranz es gilt.\nMut, dein Lauf ist bald vollendet,\nkämpf\' nur bis zum Ende recht!\nDeiner harrt der Herr und spendet\nreichen Lohn dem treuen Knecht.'),
(9, '0030', 'Alles, was man braucht für seinen Weg, hast Du schon in uns hineingelegt   (Gottes Geist, komm und füll uns neu)', NULL, 'Alles, was man braucht für seinen Weg,\nhast Du schon in uns hineingelegt,\nJesus, durch den Geist, der in uns lebt,\nJesus, durch den Geist, der uns bewegt!\r\nGottes Geist, komm und füll\' uns neu,\nGottes Geist, komm und mach\' uns frei,\nGottes Geist, komm\' zu uns und bleib\',\nführe uns hin zur Ewigkeit,\nhin zur Ewigkeit!\r\nJesus, dieser Geist, den du uns gabst,\nbrachte Dich auch einst selbst aus dem Grab,\nund der Geist, der dich lebendig macht,\ngibt uns jeden Tag die Lebenskraft.\r\nHerr, wir wollen Dir gehorsam sein,\ndoch wie oft tun wir es ganz allein,\ndoch wenn uns Dein Geist die Salbung schenkt,\ndann passiert viel mehr, als man sich denkt!'),
(9, '0031', 'Allmächtig, allmächtig, ich weiß, mein Herr ist mächtig  -  He\'s able, He\'s able, I know my Lord is able', 'He\'s able, He\'s able,\nI know my Lord is able.\nI know my Lord is able\nto carry me through. (2x)\r\nHe heals the broken hearted,\nand sets the captives free.\nHe makes the lame to walk again\nand causes the blind  to see.\r\nFor He is able, He\'s able,\nI know my Lord is able.\nI know my Lord is able,\nto carry me through.', 'Allmächtig, allmächtig,\nich weiß, mein Herr ist mächtig,\nGebund\'ne und Gefang\'ne\nmacht Er frei. (2x)\r\nEr heilt gebroch\'ne Herzen\nund tröstet in der Not,\ndie Blinden macht Er sehend\nund Kranke ganz gesund.\r\nDenn Er ist mächtig, allmächtig,\nich weiß, mein Herr ist mächtig,\nGebund\'ne und Gefang\'ne\nmacht Er frei.'),
(9, '0032', 'Als der Heil\'ge Geist auf mich kam  -  It\'s the old-time Holy Spirit   (Gib mir den Glauben der Väter)', 'It\'s the old-time Holy Spirit,\nand the devil won\'t go near it,\nthat\'s the reason people fear it,\nbut it\'s good enough for me.\r\nGive me that old-time religion,\ngive me that old-time religion,\ngive me that old-time religion,\nit\'s good enough for me.\r\nIt will make you stop your lying,\nit will save you when you\'re dying,\nit will start the devil flying,\nand It\'s good enough for me.\r\nIt\'s so good I want no other,\nfor It makes me love my brother,\nand It brings things from under cover,\nand It\'s good enough for me.\r\nMakes me love everybody,\nmakes me love everybody,\nmakes me love everybody,\nand it\'s good enough for me.\r\nIt was good for Paul and Silas,\nit was good for brother Branham,\nit will take us all to heaven,\nand it\'s good enough for me.\r\nIt was good for our fathers,\nit was good for our fathers,\nit was good for our fathers,\nand It\'s good enough for me.\r\nIt was good for our mothers,\nit was good for our mothers,\nit was good for our mothers,\nand it\'s good enough for me\r\nIt was good for Brother Branham,\nit was good for Brother Branham,\nit was good for Brother Branham,\nand It\'s good enough for me.\r\nIt will take us all to Heaven,\nit will take us all to Heaven,\nit will take us all to Heaven,\nand It\'s good enough for me.', 'Als der Heil\'ge Geist auf mich kam,\nEr die Furcht mir vor dem Feind nahm.\nWenn auch and\'re Ihn nicht wollen\nist Er doch so gut für mich.\r\nGib mir den Glauben der Väter,\ngib mir den Glauben der Väter,\ngib mir den Glauben der Väter,\ner ist so gut für mich.\r\nMit dem Lügen wird\'s aufhören\nund der Feind kann nicht mehr stören.\nJa, selbst Sterben bringt nicht schrecken,\ndenn Er ist so gut für mich.\r\nEr ist gut ich will keinen and\'ren,\ndenn ich liebe meine Brüder,\nEr zeigt Dinge die verborgen,\ndenn er ist so gut für mich.\r\nEr gibt Liebe mir für jeden,\nEr gibt Liebe mir für jeden,\nEr gibt Liebe mir für jeden,\nEr ist so gut für mich.\r\nEr war gut für Paulus und Silas,\nEr war gut für Bruder Branham,\nEr bringt uns alle in den Himmel,\nEr ist so gut für uns.\r\nEr war gut für uns\'re Väter,\nEr war gut für uns\'re Väter,\nEr war gut für uns\'re Väter,\nEr ist so gut für mich.\r\nEr ist gut für uns\'re Mütter,\nEr ist gut für uns\'re Mütter,\nEr ist gut für uns\'re Mütter,\nEr ist so gut für mich.\r\nEr war gut für Bruder Branham,\nEr war gut für Bruder Branham,\nEr war gut für Bruder Branham,\nEr ist so gut für mich.\r\nEr ist gut für die Entrückung,\nEr ist gut für die Entrückung,\nEr ist gut für die Entrückung,\nEr ist so gut für mich.'),
(9, '0033', 'Als eine frohe Schnitterschar wir unsre Garben bringen dar   (Drum schauet hin und seht das Feld zur Ernte weiß)', NULL, 'Als eine frohe Schnitterschar\nwir unsre Garben bringen dar.\nWir sammeln ein zu Jesu Ruhm,\nwas Sein erkauftes Eigentum.\nWie man zur Ernte fröhlich singt,\nso weit hinaus es jubelnd klingt,\nwir preisen Den, der uns befreit\nund uns zu Seinem Dienst geweiht.\r\nD\'rum schauet hin und seht das Feld,\nzur Ernte weiß,\nund hört den Meister werben,\nwenn gleich auch sind die Arbeitstage heiß,\new\'gen Lohn sollt ihr ererben.\nD\'rum eilet, schnell  die kurze Zeit vergeht,\nund bald, ja bald ihr vor dem König steht,\nja bald ihr vor Ihm steht,\nja bald ihr vor Ihm steht,\nja bald ihr vor dem König steht.\r\nWir wirken froh den ganzen Tag,\nwo unser Herr uns brauchen mag.\nGroß ist des Meisters Ernte ja,\nund Schnitter sind nur wenig da.\nEs neigt das Korn sich reif und schwer\nim ganzen Felde ringsumher,\nund ach, der Feind ist auch bereit\nzu Raub und Schaden allezeit.\r\nSchnell eilt die Erntezeit dahin\nmit ihrem ewigen Gewinn.\nD\'rum fassen wir die Sichel fest\nund sammeln, was sich ernten lässt.\nDie Krone winkt uns schon von fern,\nwo bald wir sind bei unserm Herrn.\nDort freu\'n wir uns in Ewigkeit\nder schönen, sel\'gen Erntezeit.'),
(9, '0034', 'Als einst der Blinde am Wegesrand rief   (Ich war blind doch nun seh\' ich klar, preist den Herrn)', NULL, 'Als einst der Blinde am Wegesrand rief\n"Jesus erbarm\' Dich des Schadens so tief".\nSprach der Herr Jesus ein einziges Wort,\nund alle Krankheit und Blindheit war fort.\r\nIch war blind doch nun seh\' ich klar, preist den Herrn!\nFerne liegt was einst finster war, preist den Herrn!\nNun sind Schatten und Nacht entfloh\'n,\nfern\' seh\' ich den Gnadenthron.\nGruß sei Dir, o Du Gottessohn, preis den Herrn.\r\nBlind war auch ich als von Jesus ich hört\',\nmich hatten Weltlust und Sünde betört.\nLicht wurd\' es plötzlich als Jesus mich sah\',\ntraf mich der Lichtstrahl von Golgatha.\r\nNoch geht der Heiland auch heute vorbei,\nöffnet die Augen und hört jeden Schrei.\nWerd\' heute sehend und werde Sein Kind,\ndenn ohne Jesus bleibst ewig du blind.'),
(9, '0035', 'Als einst der Himmel mit Lobpreis erfüllt war  -  One Day when Heaven was filled with His Praises   (Lebend Er liebt mich,  sterbend erlöst Er mich)', 'One day when Heaven was filled with His praises.\nOne day when sin was as black as could be.\nJesus came forth to be born of a virgin.\nDwelt among men, my example is He.\r\nLiving, He loved me, dying, He saved me,\nburied, He carried my sins far away.\nRising, He justified freely forever:\nOne day He´s coming - oh, glorious day!\r\nOne day they led Him up Calvary\'s mountain.\nOne day they nailed Him to die on a tree.\nSuffering anguish, despised and rejected.\nBearing our sins, my Redeemer is He.\r\nOne day they left Him alone in the garden,\none day He rested, from suffering free.\nAngels came down o’er His tomb to keep vigil.\nHope of the hopeless, my Saviour is He.\r\nOne day the grave could conceal Him no longer.\nOne day the stone rolled away from the door.\nThen He arose, over death He had conquered.\nNow is ascended, my Lord evermore.\r\nOne day the trumpet will sound for His coming.\nOne day the skies with His glories will shine.\nWonderful day, my Beloved One bringing.\nMy Saviour Jesus is mine.', 'Als einst der Himmel mit Lobpreis erfüllt war,\nals einst die Sünde war schwarz wie die Nacht,\nwurde uns Jesus gebor\'n von der Jungfrau,\nlebte als Vorbild bei Menschen auf Erd\'.\r\nLebend Er liebt mich, sterbend erlöst\' Er mich,\nnahm meine Sünden im Grabe auf sich.\nIst auferstanden, wir sind gerecht gemacht,\nbald kommt Er wieder, o glorreicher Tag.\r\nEinst führten sie Ihn auf Golgathas Hügel,\num dort gekreuzigt zu sterben für uns.\nLitt dort und wurde von Menschen verachtet,\ntrug unsere Sünden, mein Retter ist Er.\r\nEinst ließen sie Ihn allein in dem Garten,\nruhte im Grabe von Leiden befreit.\nEngel sie kamen das Grab zu bewachen.\nHoffnung für alle in Jesus ist da.\r\nEinst konnte Ihn dann das Grab nicht mehr halten,\neinst rollte weg dort der Stein vor dem Grab.\nDann stand Er auf, den Tod überwand Er,\nist aufgefahren, mein Herr ewiglich.\r\nBald wird erschallen für uns die Posaune,\ndann wird Er kommen in Gloria und Glanz.\nHerrlicher Tag, den die Seinen Er bringet,\nglorreicher Heiland, ja Jesus ist mein.'),
(9, '0036', 'Als ich durch Tränen aufwärts sah  -  In looking thro\' my Tears one Day   (Gnade, tief wie die tiefste See)', 'In looking thro\' my tears one day,\nI found Mount Calvary.\nBeneath the cross there flowed a stream\nof grace, enough for me.\r\nGrace is flowing from Calvary,\nGrace as fathomless as the sea,\nGrace for time and eternity,\nGrace enough for me.\r\nWhile standing there, my trembling heart,\nonce full of agony,\ncould scarce believe the sight I saw\nof grace, enough for me.\r\nWhen I beheld my ev\'ry sin\nnailed to the cruel tree,\nI felt a flood go thro\' my soul\nof grace, enough for me.\r\nWhen I am safe within the veil,\nmy portion there will be,\nto sing thro\' all the years to come\nof grace, enough for me.', 'Als ich durch Tränen aufwärts sah,\nerblickt ich Golgatha.\nUnd von dem Kreuz floss gnädiglich\nder Gnadenstrom für mich.\r\nGnade, tief wie die tiefste See,\nGnade fließt von des Kreuzes Höh,\nGnade genug für die Ewigkeit,\nGnade genug für mich allzeit!\r\nAls ich so stand in meinem Schmerz,\nda konnt mein zitternd Herz\nkaum fassen, dass nie mehr entwich\nder Gnadenstrom für mich!\r\nAls ich geheftet sah die Schuld\nans Kreuz durch Jesu Huld,\ndurch meine Seele, Heiland, strich\nder Gnadenstrom für mich.\r\nUnd wenn ich einstmals droben steh\nauf Zions heil\'ger Höh,\ndann dank ich ewig, denn es floss\nder Gnadenstrom für mich.'),
(9, '0037', 'Als ich Ihn anrief rührte mich mein Heiland an', NULL, 'Als ich Ihn anrief, rührte mich mein Heiland an,\nrührte mich mein Heiland an, rührte mich mein Heiland an.\nAls ich Ihn anrief, rührte mich mein Heiland an,\nja, es war die Hand des Herrn.\r\nSein Blut bedeckt meine Schuld,\nSein Blut bedeckt meine Schuld,\nSein Blut bedeckt meine Sündenschuld,\nvon Satans Macht bin ich ganz frei.\r\nGanz frei, ganz frei, ganz frei!\nGanz frei, ganz frei, ganz frei!\nSein Blut bedeckt meine Sündenschuld,\nvon Satans Macht bin ich ganz frei.'),
(9, '0038', 'Als Israel war in Ägyptenland: Lass mein Volk doch ziehn  -  When Israel was in Egypt’s Land, let My People go   (Gehe, Moses, geh hinab nach Ägyptenland)', 'When Israel was in Egypt’s land,\nlet My people go!\nOppressed so hard they could not stand,\nlet My people go!\r\nGo down, Moses,\nway down in Egypt’s land,\ntell old Pharaoh,\nto let My people go!\r\nNo more shall they in bondage toil,\nlet My people go!\nLet them come out with Egypt’s spoil,\nlet My people go!\r\nOh, let us all from bondage flee,\nlet My people go!\nAnd you’ll possess fair Canaan’s land,\nLet My people go!', 'Als Israel war in Ägyptenland:\nLass mein Volk doch ziehn!\nSie hielten kaum dem Druck noch stand:\nLass Mein Volk doch zieh\'n!\r\nGehe, Moses,\ngeh hinab nach Ägyptenland!\nSag dem Pharao:\nGott befreit Sein Volk mit starker Hand.\r\nGott sprach durch Mose zu Pharao:\nLass mein Volk doch zieh\'n;\ndenn gehen werden sie sowieso:\nLass Mein Volk doch zieh\'n!\r\nUnd nie mehr sollen sie Frondienst tun:\nLass mein Volk doch zieh\'n!\nSie werden in Kanans Weiten ruh\'n:\nLass Mein Volk doch zieh\'n!'),
(9, '0039', 'Als müd und sündenelend ich ganz verloren war  -  In Tenderness He sought me   (Hand die mich gesucht hat, Blut das mich erkauft hat)', 'In tenderness He sought me,\nweary and sick with sin,\nand on His shoulders brought me\nback to His fold again.\nWhile angels in His presence sang\nuntil the courts of heaven rang.\r\nO the love that sought me!\nO the blood that bought me!\nO the grace that brought me to the fold,\nwondrous grace that brought me to the fold!\r\nHe washed the bleeding sin-wounds\nand poured in oil and wine.\nHe whispered to assure me,\n"I’ve found thee, thou art Mine."\nI never heard a sweeter voice;\nit made my aching heart rejoice!\r\nHe pointed to the nail prints,\nfor me His blood was shed.\nA mocking crown so thorny\nwas placed upon His head.\nI wondered what He saw in me\nto suffer such deep agony.\r\nI’m sitting in His presence,\nthe sunshine of His face.\nWhile with adoring wonder\nHis blessings I retrace.\nIt seems as if eternal days\nare far too short to sound His praise.\r\nSo while the hours are passing,\nall now is perfect rest.\nI’m waiting for the morning,\nthe brightest and the best.\nWhen He will call us to His side,\nto be with Him, His spotless bride.', 'Als müd\' und sündenelend\nich ganz verloren war,\nda fand und trug der Hirte\nmich heim zu seiner Schar.\nDie Engel haben zugeschaut\nund preisen seinen Namen laut.\r\nHand die mich gesucht hat,\nBlut das mich erkauft hat.\nGnade die mich wieder heim gebracht.\nLob und Preis sei Seiner Liebe Macht!\r\nEr selbst wusch meine Wunden,\ngoss Öl und Wein darein,\nEr flüsterte ins Ohr mir:\n"Ich fand dich, du bist mein."\nNie hört ich einen süßer\'n Klang,\nEr füllt das Herz mit Lob und Dank.\r\nEr zeigt die Nägelmale\nan Fuß und Händen mir,\ndie blut\'ge Dornenkrone,\ndie ihn gekrönet hier.\nIch werd\' es niemals ganz versteh\'n,\nwie alles das für mich gescheh\'n.\r\nNun darf ich selig leben\nvor Seinem Angesicht\nund Seine Wunderwege\nhier schau\'n in Seinem Licht.\nZum Preise Seiner Herrlichkeit\ndünkt mir zu kurz die Ewigkeit.\r\nIndem die Stunden fliehen,\nso mit dem Herrn vereint,\nerwarte ich den Morgen,\nan dem Er mir erscheint,\nwo Ihn die wohlgeschmückte Braut\nin Klarheit und Vollendung schaut.'),
(9, '0040', 'Alte Stunden, alte Tage lässt du zögernd nur zurück   (Geh unter der Gnade, geh mit Gottes Segen)', NULL, 'Geh unter der Gnade, geh mit Gottes Segen,\ngeh in seinem Frieden, was auch immer du tust.\nGeh unter der Gnade, hör auf Gottes Worte,\nbleib in seiner Nähe, ob du wachst oder ruhst.\r\nAlte Stunden, alte Tage\nlässt du zögernd nur zurück.\nWohlvertraut wie alte Kleider\nsind sie dir durch Leid und Glück\r\nNeue Stunden, neue Tage\nzögernd nur steigst du hinein.\nWird die neue Zeit dir passen?\nIst sie dir zu groß, zu klein?\r\nGute Wünsche, gute Worte\nwollen dir Begleiter sein.\nDoch die besten Wünsche münden\nalle in den einen ein:'),
(9, '0041', 'Am Gnadentor stand ich als ein verlorner Sohn', NULL, 'Am Gnadentor stand ich als ein verlor\'ner Sohn,\ndurchs Herz ging mir ein Stich, es war der Sünde Lohn.\nMit Schrecken kam mir\'s ein, es sei für mich zu spät,\nmüsst ewig draußen sein! Da rang ich im Gebet,\nda rang ich im Gebet.\r\nUm Gnade schrie ich laut: "O Herr, erbarm\' dich mein!"\nHab nicht umsonst vertraut, Er ließ mich gnädig ein.\nEr nahm mir ab die Schuld und sprach mir freundlich zu.\nEr küsste mich voll Huld, so fand ich Fried\' und Ruh\',\nso fand ich Fried\' und Ruh\'.\r\nNun kenn\' ich meinen Herrn, der weinend um mich warb,\nmich suchte nah und fern und liebend für mich starb.\nIch ruh\' in seinem Schoß nach all der Sündenpein,\nnicht draußen ist mein Los.\nNein, Jesus ließ mich ein.'),
(9, '0042', 'Am Kreuze meines Heilands, da ist mein sichrer Stand  -  Beneath the Cross of Jesus, I fain would take my Stand', 'Beneath the cross of Jesus,\nI fain would take my stand.\nThe shadow of a mighty Rock\nwithin a weary land.\nA home within the wilderness,\na rest upon the way,\nfrom the burning of the noontide heat,\nand the burden of the day.\r\nOh, safe and happy shelter,\noh, refuge tried and sweet!\nOh, trysting place where heaven’s love\nand heaven’s justice meet.\nAs to the holy patriarch\nthat wondrous dream was given.\nSo is my Saviour by the cross\na ladder up to heaven.\r\nThere lies beneath its shadow,\nbut on the farther side.\nThe darkness of an awful grave\nthat gapes both deep and wide.\nAnd there between us stands the cross,\ntwo arms outstretched to save,\nlike a watchman set to guard the way,\nfrom that eternal grave.\r\nUpon that cross of Jesus\nmine eye at times can see,\nthe very dying form of One,\nwho suffered there for me.\nAnd from my smitten heart, with tears,\ntwo wonders I confess,\nthe wonders of His glorious love,\nand my own worthlessness.\r\nI take, O cross, thy shadow\nfor my abiding place.\nI ask no other sunshine than\nThe sunshine of His face\ncontent to let the world go by.\nTo know no gain nor loss,\nmy sinful self my only shame,\nmy glory all the cross.', 'Am Kreuze meines Heilands,\nda ist mein sich\'rer Stand,\nda labt der Allmacht Schatten mich\nim dürren Wüstenland.\nHier beut sich mir ein süßes Heim,\nder Seele Ruhestatt,\nwenn Trübsalshitze ringsum brennt,\nwenn ich werd\' müd\' und matt.\r\nO sichre, sel\'ge Zuflucht,\nerprobter Felsengrund,\nwo Gottes Liebe ewig steht\nmit Gottes Macht im Bund!\nIch sehe wie ein Jakob einst\ndie Himmelsleiter hier;\ndas Kreuz des Heilands zeigt ja klar\nden Himmelsweg auch mir.\r\nHier unter diesem Kreuze\nverliert der Tod sein Grau\'n;\nin Jesu Wunden, tief und weit,\ndarf ich die Rettung schau\'n.\nDie Arme hält Er ausgestreckt\nzu aller Sünder Heil;\nals Himmelsherold weist Er hin\nnach unserm Erb\' und Teil.\r\nDa blick ich auf und sehe\nim Geiste Gottes Lamm,\nwie es für mich geblutet hat\nund starb am Kreuzesstamm;\ndann muss ich schamerfüllt gestehn:\nZwei Wunder ich hier find\',\ndas Wunder Seiner großen Lieb\nund meiner großen Sünd\'.\r\nIm stillen Kreuzesschatten\nbleib ich fortan allein.\nO Herr, ich will kein andres Licht,\nDu bist mein Sonnenschein!\nDie ganze Welt mag mir vergeh\'n,\nich frage nichts darum.\nMein eig\'nes Ich sink\' hin in Schmach,\ndas Kreuz ist all mein Ruhm.'),
(9, '0043', 'Amen! Amen! Amen! Amen! Amen! Möchtest du Ihn lieben? Amen!  -  Are you going to love Him?  Amen!', 'Amen! Amen! Amen! Amen! Amen!\r\nAre you going to love Him?  Amen!\nAre you going to praise Him? Amen!\nAre you going to worship Him? Amen!\nAmen, Amen!\r\nThe Bible \'s true. Amen!\nI believe it. Amen!\nIt\'s the Word of God. Amen!\nAmen, Amen!\r\nWe believe You\'re coming. Amen!\nWe\'re ready to meet You. Amen!\nCome, Lord Jesus. Amen!\nAmen, Amen!\r\nDo you love Him? Amen!\nWill you serve Him? Amen!\nDo you believe Him? Amen!\nAmen, Amen!', '\r\nMöchtest du Ihn lieben? Amen!\nMöchtest du Ihn preisen? Amen!\nMöchtest du Ihn anbeten? Amen!\nAmen, Amen!\r\nDie Bibel ist wahr. Amen\nIch glaube es. Amen!\nSie ist das Wort Gottes. Amen!\nAmen, Amen!\r\nWir glauben dass Du kommst. Amen!\nWir sind bereit Dich zu treffen. Amen!\nKomm Herr Jesus. Amen!\nAmen, Amen!\r\nLiebst du Ihn? Amen!\nWillst du Ihn dienen? Amen!\nGlaubst du Ihn? Amen!\nAmen, Amen!'),
(9, '0044', 'An dem Auferstehungsmorgen die Posaune laut ertönt  -  In the resurrection Morning, when the Trump of God shall sound   (Auferstehn, Halleluja, auferstehn)', 'In the resurrection morning,\nwhen the trump of God shall sound.\nWe shall rise, Hallelujah! we shall rise!\nThen the saints will come rejoicing,\nand no tears will e’er be found.\nWe shall rise, Hallelujah! we shall rise.\r\nWe shall rise, Hallelujah! we shall rise!\nAmen! We shall rise! Hallelujah!\nIn the resurrection morning,\nWhen death’s prison bars are broken,\nWe shall rise, Hallelujah! We shall rise.\r\nIn the resurrection morning,\nwhat a meeting it will be.\nWe shall rise, Hallelujah! we shall rise!\nWhen our fathers and our mothers,\nand our loved ones we shall see.\nWe shall rise, Hallelujah! we shall rise!\r\nIn the resurrection morning,\nBlessèd thought it is to me,\nWe shall rise, Hallelujah! we shall rise!\nI shall see my blessèd Saviour,\nWho so freely died for me,\nWe shall rise, Hallelujah! we shall rise!\r\nIn the resurrection morning,\nwe shall meet Him in the air.\nWe shall rise, Hallelujah! we shall rise!\nAnd be carried up to glory,\nto our home so bright and fair,\nWe shall rise, Hallelujah! we shall rise!', 'An dem Auferstehungsmorgen,\ndie Posaune laut ertönt.\nAufersteh\'n, Halleluja, aufersteh\'n.\nDann die Heil\'gen kommen jubelnd\nund vor Gottes Throne steh\'n.\nAufersteh\'n, Halleluja, aufersteh\'n.\r\nAufersteh\'n, Halleluja, aufersteh\'n.\nAufersteh\'n an dem Auferstehungsmorgen,\nwenn die Heil\'gen aufersteh\'n,\nAufersteh\'n, Halleluja, aufersteh\'n.\r\nAn dem Auferstehungsmorgen,\nwelche Freude wird das sein!\nAufersteh\'n, Halleluja, aufersteh\'n.\nUns\'re Lieben wir dort treffen\nin dem ew\'gen Heimatland.\nAufersteh\'n, Halleluja, aufersteh\'n.\r\nAn dem Auferstehungsmorgen\ndarf ich sehen meinen Herrn.\nAufersteh\'n, Halleluja, aufersteh\'n.\nDer mich so sehr hat geliebet\nund mich teuer hat erkauft.\nAufersteh\'n, Halleluja, aufersteh\'n.\r\nAn dem Auferstehungsmorgen,\nbei dem Treffen in der Luft.\nAufersteh\'n, Halleluja, aufersteh\'n.\nWerden wir dem Herrn begegnen\nund Er führt uns dann nach Haus\'.\nAufersteh\'n, Halleluja, aufersteh\'n.'),
(9, '0045', 'An dem hehren, gold\'nen Morgen, wenn einst kommt der Menschensohn  -  On that bright and golden morning, when the Son of Man shall come   (Welche Scharen, welche Scharen)', 'On that bright and golden morning, when the Son of Man shall come,\nand the radiance of His glory we shall see,\nwhen from ev’ry clime and nation He shall call His people home.\nWhat a gath’ring of the ransomed that will be!\r\nWhat a gath’ring, what a gath’ring,\nwhat a gath’ring of the ransomed in the summer land of love!\nWhat a gath’ring, what a gath’ring,\nof the ransomed in that happy home above!\r\nWhen our eyes behold the city, with its many mansions bright,\nand its river, calm and restful, flowing free.\nWhen the friends that death hath parted shall in bliss again unite,\nwhat a gath’ring and a greeting there will be!\r\nO the King is surely coming, and the time is drawing nigh\nwhen blessed day of promise we shall see.\nThen the changing "in a moment, in the twinkling of an eye,"\nand forever in His presence we shall be.', 'An dem hehren, gold\'nen Morgen, wenn einst kommt der Menschensohn\nund im prächt\'gen Schmuck des Siegers wir Ihn seh\'n,\nwenn von Ost und West der Völker Menge steht vor Seinem Thron,\nwerden all die Gotterlösten auferstehn.\r\nWelche Scharen, welche Scharen!\nWelche Scharen der Erlösten die das Lamm gerettet hat!\nWelche Scharen, welche Scharen!\nWelche Scharen der Erlösten in der sel\'gen Gottesstadt!\r\nWenn wir durch die Perlentore, durch die goldnen Straßen zieh\'n,\nwo der Silberstrom im ew\'gen Frieden fließt,\nwie wird hell das Antlitz glänzen, wie wird aller Kummer fliehn,\nwenn nach all der Trennung Aug und Mund sich schließt.\r\nAuf, der König kommt als Sieger! Machet hoch das Tor der Welt!\nWas so lang gehofft wir, soll das Auge sehn!\nDer verhöhnet und gekreuzigt, kommt als königlicher Held,\nund die mitgelitten, will Er mit erhöh\'n.'),
(9, '0046', 'An dem Kreuz fand ich den Heiland  -  At the Cross I found my Saviour   (Sonnenschein der Gnade strahlet)', 'At the cross I found my Saviour,\nthere my heart was satisfied.\nStilled each aeger, anxiouus  longing,\nlookling at the Crucified.\r\nO the sushine, blessed sunshine,\nflooding all my soul today.\nFor the precious smile of Jesus\ndives the darkness far away.\r\nNow no longer heavy laden\nwith the sins a cannot bear.\nFor my loving Saviour bids me,\ncast on Him my every care.\r\nAll my doubts and fears I bring Him,\nall my sorrow, all my grief.\nAnd his tender touch of healing,\never gives me sweet relief.\r\nO what peace, what joy, what comfort\nin my Saviour I have found.\nHelp, o help my sound His praises\nuntil heav\'n and earth resound.', 'An dem Kreuz fand ich den Heiland,\nallem Leid ward ich entrückt,\nund gestillt ist jedes Sehnen,\nwenn ich auf das Kreuz geblickt.\r\nSonnenschein der Gnade strahlet\ntäglich in dem Herzen mein,\ndenn wo Jesu Liebe leuchtet,\nkann es nicht mehr dunkel sein.\r\nNun nicht länger mehr beladen\nsteh ich mit der Sünden Last,\nmein Erretter hat die Bürde\nmit durchgrab\'ner Hand erfasst.\r\nJeden Zweifel bring ich Jesu,\njede Sorge, jedes Leid,\nund Sein freundliches Berühren\nheilt und stärkt mich allezeit.\r\nWelcher Friede, welche Freude\nward am Kreuz des Heilands mein!\nJubelnd rühm\' ich\'s: Halleluja,\nes ist lauter Sonnenschein!'),
(9, '0047', 'An Dir allein, an Dir hab ich gesündigt und übel oft vor Dir getan', NULL, 'An Dir allein, an Dir hab ich gesündigt,\nund übel oft vor Dir getan.\nDu siehst die Schuld, die mir den Fluch verkündigt;\nsieh, Gott, auch meinen Jammer an.\r\nDir ist mein Fleh\'n, mein Seufzen nicht verborgen,\nund meine Tränen sind vor Dir.\nAch Gott, mein Gott, wie lange soll ich sorgen?\nWie lang verbirgst Du Dich vor mir?\r\nHerr, handle nicht mit mir nach meinen Sünden,\nvergelt\' mir nicht nach meiner Schuld.\nIch suche Dich; lass mich Dein Antlitz finden,\nDu Gott der Langmut und Geduld.\r\nFrüh woll\'st Du mich mit Deiner Gnade füllen,\nGott, Vater der Barmherzigkeit.\nErfreue mich um Deines Namens willen;\nDu bist ein Gott, der gern erfreut.\r\nLass Deinen Weg mich wieder freudig wallen,\nund lehre mich Dein heilig\' Recht.\nMich täglich tun nach Deinem Wohlgefallen;\nDu bist mein Gott, ich bin Dein Knecht.\r\nHerr, eile Du, mein Schutz, mir beizustehen\nund leite mich auf eb\'ner Bahn!\nErhört mein Schrein, der Herr erhört mein Flehen\nund nimmt sich meiner Seele an.'),
(9, '0048', 'An einem Tag im Frühling war ein Brunnen dort am Weg   (Der Elieserruf. O macht euch bereit, die Abendschatten falln)', '\r\nOh, get ready! The evening shadows fall.\nDon\'t you hear the Eliezer call?\nThere\'s going to be a wedding, and your joy will soon begin,\nin the evening when the camel-train comes in.\r\n\r\n', 'An einem Tag im Frühling war ein Brunnen dort am Weg,\nElieser ließ die Karawane ruh\'n.\nDort fand er die Braut für Isaak als die Abendschatten fiel\'n,\nund so war die lange Reise nicht umsonst.\nJa, Rebekka war sehr schön und mit Juwelen reich geschmückt,\nund so brachte er sie dann zu ihrem Mann.\nUnd Rebekka liebte Isaak und auch er gewann sie lieb.\nEine frohe Zeit für beide dann begann.\r\nO, macht euch bereit, die Abendschatten fall\'n,\nhört ihr nicht den Elieserruf!\nEin Hochzeitsmahl wird\'s geben, uns\'re Freude bald beginnt,\nwenn am Abend dann die Karawane kommt.\r\nAn diesem Tag war wieder Elieser ausgesandt,\num für seinen Herrn zu suchen eine Braut,\nund auch er ging nicht umsonst aus, um zu finden eine Braut,\ndenn Gott sah auch dies\' geschehen schon vorn fern.\nJa, sie hört\' von ihrem Isaak und ein Quell\' in ihr springt auf,\netwas zieht sie fort mit auf den langen Weg.\nNiemand kann sie hier noch halten, alles ist bereits erfüllt.\nEs muss weichen was ihr noch im Wege steht.\r\nDie Reise geht zu Ende, wenn die Abendschatten fall\'n,\nman sieht Isaak dort schon in der ferne steh\'n.\nJa, er geht ihr schon entgegen an dem Ende dieser Zeit,\nund Rebekka kann im Geiste ihn schon seh\'n.\nAll\' die Hitze dieses Tages und der Staub des Wüstensand\'s\nsind vergessen, wenn sie gehen Hand in Hand.\nDenn ein Heim ist schon bereitet, doch was größer noch als dies:\nSeiner Braut des Bräut\'gams Liebe ist gewiss.'),
(9, '0049', 'An Jesu Hand lässt sich’s so herrlich gehen, denn sie führt gut   (Ja, an Jesu Hand, da geht es immer gut)', NULL, 'An Jesu Hand lässt sich’s so herrlich gehen, denn sie führt gut.\nEr hört dein leises und dein lautes Flehen, d\'rum habe Mut.\r\nJa, an Jesu Hand, da geht es immer gut,\nja, an Jesu Hand geht’s gut!\nkann die Welt uns nicht betrüben,\nwenn wir Jesus innig lieben,\nja, an Jesu Hand geht es gut!\r\nLass nie dein Herz aus seiner Nähe weichen, sonst folgt die Nacht.\nBlick stets empor zu seinem Kreuzeszeichen, trau Seiner Macht.\r\nBist du betrübt, sag\'s deinem guten Hirten, klag Ihm dein Leid,\nEr wird mit Himmelsmanna dich bewirten, gibt Mut zum Streit.\r\nSolang du wallst auf dieser Erden Fluren, bist Fremdling du.\nDoch wandle treu, folg\' deines Heiland\'s Spuren, Er führt zur Ruh\'!'),
(9, '0050', 'Anointing fall on me   (3 Chorusse)', 'Anointing fall on me.\nAnointing fall on me.\nLet the power of the Holy Ghost\nfall on me.\nAnointing fall on me\r\nSpirit fall on me.\nSpirit fall on me.\nLet the power of the Holy Ghost\nfall on me.\nSpirit fall on me.\r\nJesus eternal life\nEmmanuel, Lord with us.\nWas revealed to us by a prophet\nto turn our hearts back.\nThat we may live\nand walk right.', NULL),
(9, '0051', 'Anybody know about the Love of Jesus', 'Anybody know\nabout the Love of Jesus?\nI do, I do.\nAnybody know\nabout the Love of Jesus?\nI do, yes I do.\r\nAnybody know\nabout the Pow\'r of Jesus?\nI do, I do.\nAnybody know\nabout the Pow\'r of Jesus?\nI do, yes I do.\r\nAnybody know\nabout the Grace of Jesus?\nI do, I do.\nAnybody know\nabout the Grace of Jesus?\nI do, yes I do.\r\nWhen I was searching\nHe brought me out.\nHe gave me answers,\ntook away my doubt.\nWhen I was struggling\nto find my place,\nI heard the sweetest song\nsent to me from the throne\nA song of love and grace.\r\nHe came and broke the chains\nof sin and death and hell\nSaid that I could use His Name\nto defend myself.\nHis Power is my constant source\nof help.', NULL),
(9, '0052', 'Are you on the Lords side   (We are on the Lords Side)', 'Are you on the Lord\'s side\nto serve the king?\nIs he living,\nis he living in\nyour hearts now?\nAre you on the Lord\'s side?\r\nWe are on the Lord\'s side.\nWe are on the Lord\'s side.\nGoing up we know.\nHe\'s the life giver.\nWe are on the Lord\'s side.\r\nAre you blind\ncan\'t you not see\nthat the Lord,\nyes He died for me.\nAre you willing\nto give a testimony\nthat you are\non the Lord\'s side.\r\nWho is He\nWho you call your God?\nIs it a man that\nrose from the dead?\nIs he reigning,\nIs he reigning\nin your hearts now?\nAre you on the Lord\'s side?\r\nWhat is his name?\nJesus, Jesus, Jesus.\nWe are on the Lords side.\nWhat is his name?\nJesus, Jesus, Jesus.\nWe are on His side.', NULL),
(9, '0053', 'Arise, my soul, arise, shake off thy guilty fears.', 'Arise, my soul, arise, shake off thy guilty fears.\nThe bleeding sacrifice in my behalf appears.\nBefore the throne my surety stands,\nbefore the throne my surety stands,\nMy name is written on His hands.\r\nHe ever lives above, for me to intercede.\nHis all redeeming love, His precious blood, to plead.\nHis blood atoned for all our race.\nHis blood atoned for all our race.\nAnd sprinkles now the throne of grace.\r\nFive bleeding wounds He bears, received on Calvary.\nThey pour effectual prayers, they strongly plead for me.\n"Forgive him, Oh forgive," they cry,\n"forgive him, Oh forgive," they cry,\n"nor let that ransomed sinner die!"\r\nThe Father hears Him pray, His dear anointed One.\nHe cannot turn away, the presence of His Son.\nHis Spirit answers to the blood,\nHis Spirit answers to the blood,\nand tells me I am born of God.\r\nMy God is reconciled, His pardoning voice I hear.\nHe owns me for His child, I can no longer fear.\nWith confidence I now draw nigh,\nwith confidence I now draw nigh,\nand "Father, Abba, Father," cry.', NULL),
(9, '0054', 'Armes Herz, sieh Jesus an! Sieh und leb, sieh und leb   (Siehe, das ist Gotteslamm)', NULL, 'Armes Herz, sieh Jesus an! Sieh: und leb\', sieh: und leb\'!\nSieh, was Er für dich getan, sieh und leb\'!\nSieh dies teure Gottes Lamm, sieh und leb\'! sieh und leb;!\nStarb für dich am Kreuzesstamm! Sieh und leb\'!\r\nSiehe, das ist Gotteslamm,\ndas der Welt Schuld auf sich nahm,\nnun quillt Heil vom Kreuzesstamm!\nSieh und leb\'!\r\nDu bist schlecht, dein Recht ist hin! Sieh und leb\', sieh und leb\'!\nBlick von dir hinweg auf Ihn, sieh und leb\'!\nWarum willst du sterben noch! Sieh und leb\'!\nTrag\' nicht länger Satans Joch! Sieh und leb\'!\r\nHör\' und glaub\', was Jesus spricht! Sieh und leb\', sieh und leb\'!\nO verstock\' dein Herze nicht! Sieh und leb\'!\nEw\'ges Leben beut Er dir! Sieh und leb\', sieh und leb\'!\nStets noch ruft Er: "Komm zu mir!" Sieh und leb\'!'),
(9, '0055', 'As of old, when the Hosts of Israel where compelled in the Wilderness to dwell   (So the Sign of the Fire by Night)', 'As of old, when the hosts of Israel\nwhere compelled in the wilderness to dwell,\ntrusting they in their God to lead the way,\nto the light of perfect day.\r\nSo the sign of the fire by night\nand the sign of the cloud by day,\nhovering o\'er, just before,\nas they journey on their way,\nshall a guide and a leader be,\ntill the wilderness be past,\nfor the Lord, our God, in His own good\ntime shall lead to the light at last.\r\nTo and fro, as a ship without a sail,\nnot a compass to guide them through\nthe vale,\nbut the sign of their God was ever near,\nthus their fainting hearts to cheer.\r\nAll the days of their wand\'rings they\nwere fed,\nto the land of the promise they were led,\nby the hand of the Lord in guidance\nsure they were brought to Canaan\'s shore.', NULL),
(9, '0056', 'As the World looks upon usas we struggle along   (I have a Roof up above me)', 'I have a roof up above me,\nI have a good place to sleep.\nThere\'s food on my table\nand there are shoes on my feet.\nYou gave me Your love, Lord,\nand a fine family.\nThank You, Lord,\nfor Your blessings on me.\r\nAs the world looks upon us\nas we struggle along,\nthey say we have nothing,\nbut they are so wrong.\nIn my heart I\'m rejoicing,\nhow I wish they could see.\nThank You, Lord,\nfor Your blessings on me.\r\nI know I\'m not wealthy\nand these cloth are not new.\nI don\'t have much money\nbut, Lord, I have you.\nAnd for me that\'s all that matters,\nso the world may not see.\nThank You, Lord,\nfor Your blessings on me.', NULL),
(9, '0057', 'As we seek Your Face   (3 Chorusse)', 'As we seek Your face,\nmay we know Your heart.\nFeel Your presence, acceptance,\nas we seek Your face.\r\nAt Your feet we fall,\nsovereign Lord.\nWe cry Holy Holy,\nat Your feet we fall.\r\nJesus draw me close,\ncloser, Lord to You.\nLet the world around me fade away.\nJesus draw me close,\ncloser, Lord to You,\nfor I desire to worship and obey. (2x)', 'Wenn wir Dein Angesicht suchen,\nmögen wir Dein Herz erkennen.\nSpüre Deine Gegenwart, Deine Annahme,\nwährend wir Dein Antlitz suchen.\r\nZu Deinen Füßen fallen wir,\nsouveräner Herr.\nWir rufen Heilig Heilig,\nzu Deinen Füßen fallen wir.\r\nJesus, zieh mich zu Dir,\nnäher, Herr, zu Dir.\nLass die Welt um mich herum verblassen.\nJesus zieh mich zu Dir,\nnäher, Herr, zu Dir,\ndenn ich will anbeten und gehorchen.'),
(9, '0058', 'As you travel along this pilgrim way  (Don\'t lose your Vision of Jesus)', 'As you travel along this pilgrim way,\nthere are heartaches and trials to bear.\nBut with a vision of Jesus and Heaven in view,\nour burdens are much easier to bear.\r\nDon\'t lose your vision of Jesus,\nkeep your eyes ever on Him.\nMany friends and dear loved ones\nhave lost their way,\nthey have lost their vision of Him.\r\nDon\'t ever look back, just keep traveling on,\nthere\'s nothing in this world of sin.\nDon\'t ever look back at the world of care,\nlest you lose your vision of Him.\r\nI remember the time, I remember the place,\nwhen Jesus so sweetly came in.\nHow He lifted the burden I had carried so long,\nand gave me a vision of Him.', NULL),
(9, '0059', 'Auch ich bin einer, den die Gnade fand   (Auch ich bin einer, den die Gnade fand)', NULL, 'Auch ich bin einer, den die Gnade fand.\nSie führte mich aus jenem finstern Land,\nda man der Sünde und dem Satan dient\nund in Vermessenheit\nsich seiner Schande rühmt.\r\nAuch ich bin einer, den die Gnade fand,\nauch mich ergriff des guten Hirten Hand.\nSie heilte meinen tiefen Sündenschmerz\nund lässt mich ruhn an Gottes Vaterherz.\r\nAuch ich war einst in vielen Sünden tot,\nfern von dem Leben, das da ist aus Gott.\nIn Satans Netzen war mein Fuß verstrickt,\nvom Geist der Schlange ganz\nmein Herz und Sinn berückt.\r\nAuch mich hat Er von Ewigkeit geliebt.\nIch weiß gewiss, dass Er auch mir vergibt.\nAuch gegen mich\nist Ihm Sein Herz entbrannt.\nAuch mich hat Er zuvor\nin Seinem Sohn erkannt.\r\nAuch ich hing einst mit Ihm an jenem Kreuz.\nDa ward getötet aller Sünden Reiz.\nMan hat auch mich\nmit Ihm ins Grab gelegt,\nauf dass der alte Mensch\nhinfort sich nimmer regt.\r\nUnd da mein Heiland herrlich auferstand,\nging aus dem Grabe ich an Seiner Hand;\nich bin mit Ihm zum Leben auferweckt;\nmir ist ein neues Ziel\nfür meinen Lauf gesteckt.\r\nEr führte mich mit Sich zum Himmel ein,\nhier darf ich nun ein Überwinder sein.\nMich wusch das Blut von allen Sünden rein,\nund auch aus Gnaden\nist des Segens Fülle mein.\r\nDies alles nicht aus mir, Gott hat\'s getan,\ndie freie Gnade nahm sich meiner an.\nMein einzger Ruhm,\ndes Glaubens fester Stand:\nAuch ich, auch ich bin einer,\nden die Gnade fand.'),
(9, '0060', 'Auf Adlers Flügeln getragen übers brausende Meer der Zeit', NULL, 'Auf Adlers Flügeln getragen\nübers brausende Meer der Zeit,\ngetragen auf Adlers Flügeln\nbis hinein in die Ewigkeit.\nÜber Berge und Täler und Gründe.\nImmer höher zur himmlischen Höh.\nDie Flügel sind stark, die mich tragen,\ndie Flügel, auf denen ich steh.\r\nUnd unter denselbigen Flügeln\nwie wunderbar ruhe ich aus.\nDa ist meine Zufluchtsstätte,\nmein festes sicheres Haus.\nDer Falke mag über mir kreisen\nund zielen und spähn wie er will.\nDie Flügel sind stark, die mich decken,\nund unter den Flügeln bleibt\'s still.\r\nJa, unter den Flügeln geborgen\nund auf den Flügeln bewahrt,\ndas gibt ein seliges Ruhen,\ndas gibt eine selige Fahrt.\ndas gibt ein sicheres Wissen\nbei wechselnder Pilgerschaft,\ndenn unter den Flügeln ist Frieden\nund auf den Flügeln ist Frieden\nund auf den Flügeln ist Kraft.'),
(9, '0061', 'Auf Christen, stimmt ein Loblied an, und lasst uns fröhlich sein', NULL, 'Auf Christen, stimmt ein Loblied an,\nund lasst uns fröhlich sein!\nDer Herr hat viel an uns getan,\nwir wollen Dank Ihm weihn.\nDas Gotteslamm ist\'s wahrlich wert,\ndass jedes Herz es ewig ehrt,\ndass jedes Herz es ewig ehrt.\r\nWo waren wir? Wir waren fern\nvon Gott und Seiner Gnad\'.\nWo sind wir nun? Erlöst vom Herrn\nsind wir auf ew\'gem Pfad,\nder uns zu unserm Heiland bringt,\nbei dem man ewig Psalmen singt,\nbei dem man ewig Psalmen singt.\r\nHier sieht\'s uns freilich niemand an,\nwas wir einst werden sein;\narmselig sind wir angetan;\nund unter vieler Pein\ngeh\'n wir den schmalen Weg verschmäht;\nmit Tränen wird von uns gesät,\nmit Tränen wird von uns gesät.\r\nDoch wir sind froh, denn Er, der Herr,\nwird immer bei uns sein.\nEr ist um uns, die Seinen, her,\nja lässt uns nie allein.\nUnd droht die ganze Welt mit Krieg,\nso bleibt mit Ihm uns doch der Sieg,\nso bleibt mit Ihm uns doch der Sieg.\r\nGar bald wird\'s überstanden sein;\nihr Streiter frisch voran!\nDann gehen wir zur Freude ein\nund singen jubelnd dann\ndem Lamme, das uns hat befreit,\nLob, Preis und Dank in Ewigkeit,\nLob, Preis und Dank in Ewigkeit.'),
(9, '0062', 'Auf Deinen Ruf, o Herr, tret ich vor Dich allda  -  I hear Thy welcome Voice, that calls me, Lord, to Thee   (Ich komme jetzt zu Dir)', 'I hear Thy welcome voice,\nthat calls me, Lord, to Thee,\nfor cleansing in Thy precious blood,\nthat flowed on Calvary.\r\nI am coming, Lord!\nComing now to Thee!\nWash me, cleanse me in the blood\nthat flowed on Calvary!\r\nTho\' coming weak and vile,\nThou dost my strength assure.\nThou dost my vileness fully cleanse,\ntill spotless all, and pure.\r\n\'Tis Jesus calls me on\nto perfect faith and love.\nTo perfect hope and peace and trust,\nfor earth and heav\'n above.\r\n\'Tis Jesus who confirms\nthe blessed work within.\nBy adding grace to welcom\'d grace,\nwhere reign\'d the pow\'r of sin.\r\nAnd He the witness gives\nto loyal hearts and free,\nthat ev\'ry promise is fulfilled,\nif faith but brings the plea.\r\nAll hail! atoning blood!\nAll hail! redeeming grace!\nAll hail! the gift of Christ our Lord,\nour strength and righteousness.', 'Auf Deinen Ruf, o Herr,\ntret\' ich vor Dich allda\nund suche Heil in Deinem Blut,\ndas floss auf Golgatha.\r\nIch komme jetzt zu Dir,\no Herr, tritt Du mir nah,\nund wasche mich in Deinem Blut,\ndas floss auf Golgatha!\r\nWeil ich so elend bin,\nwillst Du mein alles sein,\nDein Blut macht mich aufs völligste\nvon jedem Flecken rein.\r\nDein Wort verheißt mir klar\nder Liebe volles Heil,\ndass Friede, Freud und Zuversicht\nsei\'n stets mein Segensteil.\r\nVollführen willst Du ja\nDein Gnadenwerk in mir,\ndass ich mit festem Herzen hang\nnur ganz allein an Dir!\r\nDein Geist bezeugt es auch,\ndass, was wir gläubig fleh\'n,\nnach der Verheißung treu und wahr\nan uns soll ganz gescheh\'n.\r\nHeil Dir, o Gottessohn!\nHeil Dir, Du hast vollbracht!\nHeil Dir für Dein Erlösungsblut,\ndas völlig selig macht!'),
(9, '0063', 'Auf dem Berge von Zion  -  On the top of Mt. Zion is a city   (Siehst du die Stadt dort auf Zions Hügel)', 'On the top of Mt. Zion is a city\nand the earth with glory it doth fill.\nI shall look on its beauty in the morning\nwhen I reach that city on the hill.\r\nOh, that city on Mt. Zion,\ntho’ a pilgrim, yet I love thee still.\nI’ll not leave thee, through the ages,\nwhen I reach that city on the hill.\r\nI’m invited to come home to that city,\nfthe Word says, "Whosoever will."\nAnd I’ll find there a mansion for me waiting\nwhen I reach that city on the hill.\r\nDeath will never molest me in that city,\nnever leave me lying cold and chill.\nBut I’ll enter to live up there forever,\nwhen I reach that city on the hill.\r\nSo I’ll stay here until my Saviour calls me,\ntrying daily to perform His will.\nThen He’ll say unto me, "Well done" up yonder\nwhen I reach that city in the hill.', 'Auf dem Berge von Zion ist die goldene Stadt,\njeder Platz ist dort voll Herrlichkeit\nIch werd\' schauen jene Schönheit an dem Morgen,\nwenn ich steh vor diesem Perlentor.\r\nSiehst du die Stadt dort auf Zions Hügel?\nAls ein Pilger hab ich sie so lieb!\nDurch alle Zeiten darf ich dort bleiben,\ndarf dort bleiben in alle Ewigkeit.\r\nEingeladen in das Heim jener herrlichen Stadt,\nund das Wort spricht: "Wen da dürstet komm!"\nich hab dann ein Heim auf mich wartend,\nwenn ich steh vor diesem Perlentor.\r\nIn der Stadt kein Tod mehr mich erreichen kann\nniemals lieg\' ich kalt und leblos da.\nWir zieh\'n ein um zu leben dort in Ewigkeit,\nnie mehr Krankheit, Schmerz und auch kein Leid!\r\nUnd so wart\' ich auf Erden bis der Herr mich ruft,\nfolge täglich seinem Willen treu.\nEr dann zu mir spricht: "Recht und gut getan,\ngehe ein in die Freuden deines Herrn!"'),
(9, '0064', 'Auf dem Hügel weit weg stand verwittert ein Kreuz  -  On a Hil far away, stood an old rugget Cross   (Ja, ich ehre das schmachvolle Kreuz)   [Siegesklänge]', 'On a hill far away\nstood an old rugged cross,\nthe emblem of suff\'ring and shame.\nAnd I love that old cross,\nwhere the Dearest and Best,\nfor a world of lost sinners was slain.\r\nSo I\'ll cherish the old rugged cross,\ntill my trophies at last I lay down.\nI will cling to the old rugged cross,\nand exchange it one day for a crown.\r\nOh, that old rugged cross,\nso despised by the world,\nhas a wondrous attraction for me.\nFor the dear Lamb of God\nleft His glory above,\nto bear it to dark calvary.\r\nIn the old rugged cross,\nstained with blood so divine,\na wondrous beauty I see.\nFor \'twas on the old cross,\nJesus suffered and died,\nto pardon and sanctify me.\r\nTo the old rugged cross I will ever be true,\nits shame and reproach gladly bear.\nThen He\'ll call me some day\nto my home far away,\nwhere His glory forever I\'ll share.', 'Auf dem Hügel weit weg\nstand verwittert ein Kreuz,\nals Zeichen der Schande und Pein.\nDoch ich liebe das Kreuz,\ndenn mein treuester Freund\nstarb dort für mich Sünder allein.\r\nJa, ich ehre das schmachvolle Kreuz,\nbis die Waffen des Glaubens einst ruh\'n.\nJa, ich ehre das kostbare Kreuz\nund vertausche es einst mit der Kron\'.\r\nDem verwitterten Kreuz,\nso verachtet, gehasst,\nentströmt eine ewige Kraft;\ndenn das Gotteslamm kam\nvon dem Himmel herab,\nhat Vergebung und Heil mir verschafft.\r\nIn dem Kreuz, so befleckt\nmit dem heiligen Blut,\nkann die Herrlichkeit Gottes ich sehn.\nDenn nur dort an dem Kreuz,\nwo mein Heiland einst starb,\nkann geheiligt vor Jesus ich steh\'n.\r\nDem verwitterten Kreuz will ich immer treu sein,\ndie Schmach nehm\' ich auf mich so gern.\nJesus ruft mich bald heim,\nwo schon alles bereit\nund den Lohn ich empfange vom Herrn.'),
(9, '0065', 'Auf dem Lamm ruht meine Seele, betet voll Bewundrung an', NULL, 'Auf dem Lamm ruht meine Seele,\nbetet voll Bewund\'rung an.\nAlle, alle meine Sünden\nhat Sein Blut hinweg getan.\r\nSel\'ger Ruheort! Süßer Friede\nfüllet meine Seele jetzt,\nda wo Gott mit Wonne ruhet,\nbin auch ich in Ruh\' gesetzt.\r\nRuhe fand hier mein Gewissen,\ndenn Sein Blut - o reicher Quell!\nhat von allen meinen Sünden\nmich gewaschen rein und hell.\r\nUnd mit süßer Ruh\' im Herzen\ngeh ich hier durch Kampf und Leid;\new\'ge Ruhe find\' ich droben\nin des Lammes Herrlichkeit.\r\nDort wird Ihn mein Auge sehen,\ndessen Lieb mich hier erquickt,\ndessen Treue mich geleitet\ndessen Gnad\' mich reich beglückt.\r\nDort besingt des Lammes Liebe\nSeine teu\'r erkaufte Schar,\nbringt in Zions sel\'ger Ruhe\nIhm ein ew\'ges Loblied dar.'),
(9, '0066', 'Auf dem stillen Obersaale harrten einmütig sie aus  -  They were in an upper Chamber, they were all with one Accord   (Herr, sende die Kraft doch jetzt)', 'They were in an upper chamber,\nthey were all with one accord,\nwhen the Holy Ghost descended\nas was promised by our Lord.\r\nLord, send the power just now,\nLord, send the power just now,\nLord, send the power just now\nand baptize every one.\r\nYes, this power from heaven descended\nwith the sound of rushing wind.\nTongues of fire came down upon them,\nas the Lord said He would send.\r\nYes, this "old-time" power was given\nto our fathers who were true.\nThis is promised to believers,\nand we all may have it too.\r\n\r\n\r\n', 'Auf dem stillen Obersaale\nharrten einmütig sie aus,\nbis der Heil\'ge Geist mit Brausen\nkam und füllete das Haus.\r\nHerr, sende die Kraft doch jetzt,\nHerr, sende die Kraft doch jetzt,\nHerr, sende die Kraft doch jetzt!\nErfülle jeden hier!\r\nJene Kraft hast Du gesendet\nmit des Sturmwinds heil\'ger Macht.\nFeuerzungen fielen nieder,\nwie\'s Dein ew\'ger Mund gesagt.\r\nJene Kraft des Heilgen Geistes,\njene Kraft der ersten Zeit,\njedem Glaubenden verheißen,\nsie ist auch für uns bereit.\r\nSprich das Wort, es wird geschehen.\nGlaube nur und es trifft ein.\nAlles ist bereits vollendet,\nwir werden ewig bei Ihm sein.\r\n"Vollkommenheit", sprich früh am Morgen,\nden Helm des Heil\'s setze dir auf!\nDann ergreif\' den Schild des Glaubens,\nund so beginn den Tageslauf.\r\nRed\' nur Gutes über and\'re,\nred\' von Jesus, Seiner Kraft!\nNimm die Bibel und erkenne,\ndass Du Seine Vollmacht hast.'),
(9, '0067', 'Auf dem Weg den du gehst, wo dein Leben auch steht  -  All along on the Road to the Soul\'s true abode   (Schaut nach dir, schaut nach dir)', 'All along on the road to the soul\'s true abode,\nthere\'s an Eye watching you.\nEvery step that you take, this great Eye is awake,\nthere\'s an Eye watching you.\r\nWatching you, watching you,\nevery day mind the course you pursue.\nWatching you, watching you,\nthere\'s an all-seeing Eye watching you.\r\nAs you make life\'s great flight, keep the pathway of right,\nthere\'s an Eye watching you.\nGod will warn not to go in the path of the foe,\nthere\'s an Eye watching you.\r\nFix your mind on the goal, that sweet home of the soul,\nthere\'s an Eye watching you.\nNever turn from the way to the kingdom of day,\nthere\'s an Eye watching you.', 'Auf dem Weg den du gehst, wo dein Leben auch steht,\nGottes Aug\' schaut nach dir.\nJeden Schritt den du machst, ob du schläfst oder wachst,\nGottes Aug\' schaut nach dir.\r\nSchaut nach dir, schaut nach dir\nwas du tief auch bewegst Er ist hier.\nSchaut nach dir, schaut nach dir,\nganz gewiss, Jesus Christ schaut nach dir.\r\nWenn du Pläne noch hast und du kommst nicht zur Rast,\nGottes Aug\' schaut nach dir.\nGott wird warnen dein Herz wenn\'s nicht geht himmelwärts\nGottes Aug\' schaut nach dir.\r\nSchau das Ziel freudig an, dass dein Herr kommen kann,\nGottes Aug\' schaut nach dir.\nDenk im Leben daran, dass nur Er retten kann,\nGottes Aug\' schaut nach dir.'),
(9, '0068', 'Auf diesem großen, weiten Weltenmeere  (Am andern Ufer da gibt es kein Leid)', NULL, 'Auf diesem großen, weiten Weltenmeere\nein Schifflein eilt dem andern Ufer zu.\nDem Steuermann allein gebührt die Ehre,\nes ist der Herr, das Schifflein, das bist du.\nWenn Stürme brausen und Gewitter toben,\ndein Schifflein schwankt, es scheint, ob alles bricht.\nLenk\' deinen Blick vertrauensvoll nach oben,\ndein Steuermann, der schläft und schlummert nicht.\r\nAm andern Ufer da gibt es kein Leid,\nam andern Ufer da herrschet nur Freud.\nAm andern Ufer da weint man nicht mehr;\nam andern Ufer da wohnt unser Herr.\r\nO zweifle nicht, dein Glaube darf nicht wanken.\nViel schneller als dein Schifflein eilt die Zeit.\nUnd sinnend stehst du oftmals in Gedanken,\nob weit die Fahrt noch bis zur Ewigkeit?\nNeigt sich der Tag, wird\'s Dunkel immer trüber,\ntrau deinem Führer, trau der starken Hand.\nEr bringt dein Schifflein durch den Sturm hinüber\nans andre Ufer, ins gelobte Land.\r\nAm andern Ufer, in den lichten Höhen\nerwarten dich die Sel\'gen ohne Zahl.\nDort wird nur Freud und holder Friede wehen\nbeim Herrn der Herrlichkeit, beim Hochzeitsmahl.\nDort werden Scharen jubeln, Harfen klingen\nund alles ist zu Dienen ihm bereit.\nOhn\' Ende wird man Lob und Preis darbringen\nGott und dem Herrn in alle Ewigkeit.'),
(9, '0069', 'Auf dieser Welt gibt es viele Straßen   (Weit über\'m Sternenzelt, ja, weit entfernt der Welt.)', NULL, 'Auf dieser Welt gibt es viele Straßen,\nund jede Straße die hat ein Ziel.\nDoch diese Welt muss ein jeder verlassen,\nund wohin geht es, so fragen sich viel.\r\nWeit über\'m Sternenzelt, ja, weit entfernt der Welt.\nDort ist ein herrlich Land, ist es Dir bekannt?\nWeit über\'m Sternenzelt, ist die bess\'re Welt.\nDort ist mein Heimatland, das mein Glaub\' hat erkannt.\r\nAuf dieser Welt gibt es viele Wege,\ndoch nur ein einz\'ger führt himmelan.\nJa, dieser Weg geht nach Golgatha\'s Hügel,\ngehst Du vorbei, mein Freund, was dann?\r\nAuf dieser Welt schlägt so manche Stunde,\nund eine Stunde schlägt auch für dich.\nHast du gehört von der herrlichen Kunde?\nEin Heim erwartet dich ewiglich.'),
(9, '0070', 'Auf Erden hier gehts oft durchs Tal voll Sorgen, Not und Pein  -  Upon our Journey here below we meet with Pain and Loss   (Wenn wir sind dort in jener Stadt von Perlentorn und Gold)', 'Upon our journey here below we mett with pain and loss,\nsometimes there is a crown of thorns, sometimes the heavy cross.\nThe dreary road to Calvary, the bitter goad and sting,\nbut what\'s inside the gates of pearl will be worth ev\'ry thing.\r\nWhe we\'re inside the gates of pearl, we\'ll learn a lot of things.\nWe\'ll have a harp that\'s made of gold, perhaps a thousand strings.\nWe\'ll sing and shout and dance about, the Lamb will dry our tears.\nWe\'l have a grand homecoming week, the first ten thousand years.\r\nThe shadows now beginn to fall, the time is drawing nigh,\nwhen Christ our Lord shall come again like lightning from the sky.\nAnd while we wait and suffer here, prais God, we\'ll shout and sing,\nfor one glimpse thro\' those gates of pearl will be worth ev\'ry thing.\r\nThe precious blood of God\' own Son has saved and sanctified,\na wondrous people for His name and they are called the bride.\nTho\' here neglected and despised, one day the Lord will bring,\nHis chosen ones within the gates, and that\'s worth ev\'ry thing.', 'Auf Erden hier geht\'s oft durch\'s Tal voll Sorgen, Not und Pein,\ndenn unser Herr Er prüft uns, ob wir Ihm doch ganz vertrau\'n.\nDas Kreuz, das Er uns auferlegt, scheint manchmal uns sehr schwer,\ndoch für die Überwinder wartet ja ein weißes Kleid.\r\nWenn wir sind dort in jener Stadt von Perlentor\'n und Gold.\nMit Harfen und mit Saitenspiel, so preisen wir den Herrn.\nWir singen, jauchzen, jubilier\'n, dem Lamm das uns erkauft.\nEr trocknet alle Tränen ab, denn wir sind dann zu Haus.\r\nDie Zeit neigt sich dem Ende zu, denn unser Herr kommt bald.\nIn Wolken Er erscheinen wird, zu holen seine Braut.\nUnd während wir durch Teste geh\'n, da schau\'n wir himmelwärts\nzu jenen Perlentoren dort und preisen unser\'n Gott.\r\nDas teure Blut von Jesus Christ\' hat es für uns vollbracht,\ndass rein und heilig ich darf steh\'n an jenem großen Tag.\nGehör\'n zur Schar, die heimwärts eilt als Seine kleine Braut,\ndas ist für mich der größte Lohn, bei Ihm sein allezeit.'),
(9, '0071', 'Auf ewig bei dem Herrn soll meine Losung sein  -  Forever with the Lord, Amen, so let it be', 'Forever with the Lord!\nAmen! so let it be.\nLife from the dead is in that word,\n\'tis immortality.\nHere in the body pent,\nabsent from Him, I roam,\nyet nightly pitch my moving tent\na day\'s march nearer home.\r\nMy Father\'s house on high,\nhome of my soul, how\nat times to faith\'s foreseeing eye,\nthy golden gates appear!\nAh, then my spirit faints\nto reach the land I love,\nthe bright inheritance of saints,\nJerusalem above!\r\nForever with the Lord!\nO Father, \'tis Thy will.\nThe promise of that faithful word\ne\'en here to me fulfil.\nBe Thou at my right hand,\nthen can I never fail.\nUphold Thou me, and I shall stand;\nfight Thou, and I\'ll prevail.\r\nSo when my dying breath\nShall set my spirit free,\nby death I shall escape from death\nto endless life with Thee.\nKnowing as I am known,\nhow shall I love that word\nand oft repeat before the throne,\n"Forever with the Lord!"', '"Auf ewig bei dem Herrn!"\nsoll meine Losung sein!\nDies Wort sei in der Nacht mein Stern,\nes führ\' mich aus und ein.\nIch walle durch die Welt,\nbin nur ein Fremdling hier\nund schlage auf mein Pilgerzelt,\no Herr, stets näher Dir!\nNäher Dir, näher Dir,\no Herr, stets näher Dir!\r\nZur Höhe blick ich auf,\ndort winkt die Heimat mir,\nund oft ist mir\'s im Glaubenslauf,\nals säh\' ich sie schon hier.\nDann seh\'n ich mich hinein,\no dass ich zu Dir kam,\ndu goldne Stadt voll Himmelsschein,\ndu Neu-Jerusalem!\nGoldne Stadt, goldne Stadt,\ndu Neu-Jerusalem!\r\nDoch oft seh\' ich\'s nicht mehr,\nes trübet sich mein Blick,\nich flieg wie Noahs Taub umher,\nzur Arche geht\'s zurück.\nDie Wolken teilen sich,\nund nach dem Sturm und Schmerz\nerfreut der Friedensbogen mich\nund tröstet mir das Herz.\nFriedenslicht, Friedenslicht,\nwie tröstest du mein Herz!\r\nWenn einst mein Pulsschlag steht,\ndie Seele los sich reißt\nund aus dem Tod ins Leben geht,\ndann triumphiert mein Geist.\nDann seh\' ich alles klar,\nwas hier mir schien so fern,\ndann bin ich, o wie wunderbar,\nauf ewig bei dem Herrn!\nWunderbar, wunderbar!\nAuf ewig bei dem Herrn!'),
(9, '0072', 'Auf Geschwister zu dem Streite in dem Glaubenskrieg   (Ja, unter diesem Zeichen siegen wir)', NULL, 'Auf, Geschwister zu dem Streite,\nin dem Glaubenskrieg.\nJesus steht uns treu zur Seite:\nUnser ist der Sieg.\r\nJa, unter diesem Zeichen siegen wir,\ngeht\'s auch durch die Nacht.\nDenn an dem Kreuzesstamm auf Golgatha,\nist der Sieg vollbracht.\r\nRichtet auf die läss\'gen Hände,\nund die müden Knie.\nAuf, es geht zum Weltenende,\nkämpfet wie noch nie.\r\nWollen doch nicht denen gleichen,\ndie verloren gehen.\nWollen doch das Ziel erreichen und\nvor Gott besteh\'n.\r\nHaltet aus, es gibt kein Weichen,\nauch in stärkster Pein.\nUnter diesem Kreuzeszeichen\nist der Himmel mein.'),
(9, '0073', 'Auf Golgatha litt einst der Herr den bittern Kreuzestod   (Nach Golgatha geh ich getrost)', NULL, 'Auf Golgatha litt einst der Herr\nden bitter\'n Kreuzestod;\ndort trug Er meine Sündenlast,\nhalf mir aus aller Not.\r\nNach Golgatha geh ich getrost,\ndort hat mein Heiland mich erlöst;\nSein teures Blut herniederfloss,\ndas Er vergoss, für mich vergoss, vergoss.\r\nWie ward des Menschen Sohn verhöhnt\nvon jener blinden Schar,\nals Er die ganze Welt versöhnt,\nder Fluch der Menschen war.\r\nLebt wohl, ihr Freuden dieser Welt,\nmich zieht\'s nach Golgatha;\nauf Jesum ist mein Ziel gestellt,\nseit ich Ihn leiden sah.\r\nWas ich auf Golgatha vernahm,\ndas bleibt mein Trost fortan;\ndass ich einmal zum Kreuze kam,\nerhebt mich himmelan.'),
(9, '0074', 'Auf Golgathas Hügel da stand einst ein Kreuz   (Das Lamm an dem Kreuz ist der Grund meiner Freud)', NULL, 'Auf Golgathas Hügel da stand einst ein Kreuz,\nan welchem ein Sterbender hing.\nEs war ja der Heiland der damals bereits,\nfür alle den Leidensweg ging.\r\nDas Lamm an dem Kreuz ist der Grund meiner Freud\',\ndas herrliche Lamm an dem Kreuz.\nEs vergab meine Sünd\' und ich bin nun Sein Kind,\ndarum preise ich Ihn alle Zeit.\r\nSie wussten es nicht wen sie schlugen an\'s Kreuz.\noh Vater vergib, rief Er aus.\nSie schmähten den Herrn und erkannten Ihn nicht,\nals einzige Pforte nach Haus.\r\nDoch du kennst das Kreuz und auch den der dort starb,\ngeh nicht an dem Kreuze vorbei.\nEr will nur dein Herze, lass du Ihn herein,\nEr macht auch Dein Leben ganz neu.'),
(9, '0075', 'Auf zum Werk! Denn sieh, der Morgen bricht mit Strahlenglanz dir an  -  Up! and work; behold, the Morning sheds afar its golden Ray', 'Up! and work; behold, the morning\nsheds afar its golden ray.\nCan you sleep, when souls are dying?\nUp! and labor with the day.\nGod has called, and you have heard Him,\nwill you slight His great command?\nWill you plead your want of courage,\nwhen before His bar you stand?\r\nDo you love the blessed Saviour?\nHave you faith in God above?\nBy a life of self denial\nprove the ardor of your love.\nFeed the lambs with hunger pining\nin the rugged wilds of sin.\nYou can find them all around you,\nyou can help to bring them in.\r\nNot the smallest seed you scatter\nfrom your hand shall fall in vain.\nYou will see the cloud arising,\nGod will bring the promised rain.\nBe content for Him to labor,\ncount it gain to suffer loss.\nIf you wear a crown of glory,\nyou must win it by the cross.', 'Auf zum Werk! Denn sieh,\nder Morgen bricht mit Strahlenglanz dir an!\nSchlafen, während Sünder sterben?\nNein, o nein! Drum auf und dran.\nGott der Herr hat dich gerufen,\nd\'rum so säume länger nicht!\nOder was willst du einst sagen,\nwenn du kommst vor Sein Gericht?\r\nLiebst du Jesus ganz von Herzen,\ntraust du Seiner Gnad\' und Treu,\nso beweis\' durch deinen Wandel,\ndass dein Herz aufrichtig sei.\nSuche die verirrten Schafe,\nweide sie nach Christi Wort;\nführe sie zu Jesu Herde,\ndenn dort sind sie wohl versorgt.\r\nMunter streue deinen Samen,\nund es wird gesegnet sein,\ndenn der Herr wird Regen geben,\nso wird\'s wachsen und gedeih\'n.\nSei nur froh, für Gott zu wirken,\nhast du auch Verlust allhier;\nwillst du einst die Krone tragen,\nnach der Arbeit winket sie.'),
(9, '0076', 'Auf, denn die Nacht wird kommen  -  Work, for the Night is coming', 'Work, for the night is coming,\nwork thru the morning hours.\nWork while the dew is sparkling,\nwork \'mid springing flow\'rs.\nWork when the day grows brighter,\nwork in the glowing sun.\nWork, for the night is coming,\nwhen man\'s work is done.\r\nWork, for the night is coming,\nwork thru the sunny noon.\nFill brightest hours with labor,\nrest comes sure and soon.\nGive ev\'ry flying minute,\nsomething to keep in store.\nWork, for the night is coming,\nwhen man works no more.\r\nWork, for the night is coming,\nunder the sunset skies.\nWhile their bright tints are glowing,\nwork, for daylight flies.\nWork till the last beam fadeth,\nfadeth to shine no more.\nWork, while the night is dark\'ning,\nwhen man\'s work is o\'er.', 'Auf, denn die Nacht wird kommen,\nauf mit dem jungen Tag!\nWirket am frühen Morgen,\neh\'s zu spät sein mag!\nWirket im Licht der Sonnen,\nfangt beizeiten an!\nAuf, denn die Nacht wird kommen,\nda man nicht mehr kann!\r\nAuf, denn die Nacht wird kommen,\nauf, wenn es Mittag ist;\nweihet die besten Kräfte\ndem Herrn Jesu Christ!\nWirket mit Ernst, ihr Frommen,\ngebt alles Andre dran!\nAuf, denn die Nacht wird kommen,\nda man nicht mehr kann!\r\nAuf, denn die Nacht wird kommen,\nauf, wenn die Sonne weicht!\nAuf, wenn der Abend mahnet,\nwenn der Tag entfleucht!\nAuf, bis zum letzten Zuge,\nwendet nur Fleiß daran!\nAuf, denn die Nacht wird kommen,\nda man nicht mehr kann!'),
(9, '0077', 'Auf, zu dem Herrn heb die Hände  -  Up with thy Hands to Jesus   (Drum auf, zu dem Herrn heb die Hände)', '"Up with thy hands to Jesus,"\noh, guilty tempest-tossed.\n"Up with thy hands to Jesus,"\nor, sinner, thou art lost.\nThe waves are wildly dashing,\nthy boat is light and frail,\nthe lightnings sharp are flashing,\nand fiercely sweeps the gale.\r\nThen "up with thy hands to Jesus,"\noh guilty tempest-tossed.\n"Up with thy hands to Jesus,"\nor, sinner, thou art lost.\r\n"Up with thy hands to Jesus,"\nHe walks upon the sea.\n"Up with thy hands to Jesus,"\nHe stoopeth now for thee.\nSay not thy hands are feeble,\nthy fingers can not cling.\nHis mighty grasp shall hold thee,\nand sure salvation bring.\r\n"Up with thy hands to Jesus,"\nHe hears thy piteous cry.\n"Up with thy hands to Jesus,"\nno other help is nigh.\nEven now thy bark is sinking,\nthe billows o’er thee roll,\n"Up with thy hands to Jesus,"\noh, sinner, save thy soul.\r\n"Up with thy hands to Jesus,"\nHe ruleth wind and wave.\n"Up with thy hands to Jesus,"\nHis love now yearns to save.\nOh, if thou wilt but trust Him,\nHis help He’ll quickly give.\nHaste, then, no longer doubting,\n"Up with thy hands," and live.', 'Auf, zu dem Herrn heb\' die Hände,\no armer Sünder du!\nFlehend zu Jesus dich wende,\nbei Ihm nur find\'st du Ruh\'!\nHier toben wild die Wogen,\nda wird\'s dem Herzen bang,\nder Sturmwind kommt gezogen\nund droht dir Untergang.\r\nD\'rum auf, zu dem Herrn heb\' die Hände,\no armer Sünder du!\nFlehend zu Jesus dich wende,\nbei Ihm nur find\'st du Ruh\'!\r\nAuf, zu dem Herrn heb\' die Hände,\nEr wandelt auf dem Meer,\nflehend zu Jesus dich wende,\nEr tritt jetzt zu dir her!\nSag nicht: "Ich kann\'s nicht fassen,\nzu schwach ist mein Verstand!"\nEr wird dich nimmer lassen,\nEr stärket deine Hand.\r\nAuf zu dem Herrn heb\' die Hände,\nglaub nur, Er hört dein Schrein,\nflehend zu Jesus dich wende,\nEr kann allein befrei\'n.\nMag selbst dein Schifflein sinken,\nhalt dich nur fest an Ihn,\nEr lässt dich nicht ertrinken,\nEr bringt ans Land dich hin.\r\nAuf, zu dem Herrn heb\' die Hände,\nEr lenket Wind und See,\nflehend zu Jesus dich wende,\nEr heilt von allem Weh.\nWirst du Ihm fest vertrauen,\nhilft Er dir sicherlich,\nund du wirst fröhlich schauen,\nwir Er dich zieht zu sich.'),
(9, '0078', 'Auferstanden aus des Grabes Nacht, Jesus hat uns helles Licht gebracht   (Und wir werden mit Ihm leben)', NULL, 'Auferstanden aus des Grabes Nacht,\nJesus hat uns helles Licht gebracht.\nFreude bricht durch alle Dunkelheit:\nJesus lebt in Ewigkeit!\r\nUnd wir werden mit Ihm leben\nin der Herrlichkeit bei Ihm allein;\nwas kann es noch Schön\'res geben,\nals Freunde des Herrn schon hier zu sein.\r\nJesus lebt, Er hat am Kreuz gesiegt,\njede Macht Ihm bald zu Füßen liegt.\nSingen werden wir es alle Zeit:\nJesus lebt in Ewigkeit!\r\nHerrlich ist es ja erlöst zu sein,\naller Glanz der Welt verliert den Schein.\nEr hat wunderbar auch uns befreit.\nJesus lebt in Ewigkeit!'),
(9, '0079', 'Auferstanden! Halleluja! Sei gegrüßt, du Morgenrot  -  Christ hath risen! Hallelujah! Blessed Morn of Life and Light   (Auferstanden! Halleluja! Freue dich erlöste Welt)', 'Christ hath risen! Hallelujah!\nBlessèd morn of life and light!\nLo, the grave is rent asunder,\ndeath is conquered through His might.\r\nChrist is risen! Hallelujah!\nGladness fills the world today.\nFrom the tomb that could not hold Him,\nsee, the stone is rolled away!\r\nChrist hath risen! Hallelujah!\nFriends of Jesus, dry your tears.\nThrough the veil of gloom and darkness,\nlo, the Son of God appears!\r\nChrist hath risen! Hallelujah!\nHe hath risen, as He said.\nHe is now the King of glory,\nand our great exalted Head.', 'Auferstanden! Halleluja!\nSei gegrüßt, du Morgenrot!\nSeht, des Grabes Gruft steht offen!\nWo ist nun dein Stachel, Tod?\r\nAuferstanden! Halleluja!\nFreue dich, erlöste Welt,\ndenn das Grab den Lebensfürsten\nnicht in seiner Macht behält!\r\nAuferstanden! Halleluja!\nFreunde Jesu weinet nicht!\nSchaut durch euren Tränenschleier\nSein verklärtes Angesicht!\r\nAuferstanden! Halleluja!\nAn den Auferstand\'nen glaubt,\nan den König, Gott zur Rechten,\nder Gemeinde herrlich Haupt!'),
(9, '0080', 'Aus Erbarmen nimm mich Armen   (Herr, ich suche, Herr, ich finde)', NULL, 'Aus Erbarmen nimm mich Armen,\nnimm mich, Jesus, wie ich bin!\nDir, dem Einen, Heilgen, Reinen,\nDir gehöre ich forthin.\r\nHerr, ich suche, Herr, ich finde\nmeine Ruhe nur in Dir.\nGib den Segen Deinem Kinde\nund bewahre Du ihn mir!\r\nAuf Dich schauend, Dir vertrauend,\nwill ich meine Straße ziehn;\nhalt mich immer, lass mich nimmer,\nHerr, von Deiner Seite fliehn.\r\nWill es dunkeln, lass mir funkeln\nDeiner Gnade hellen Strahl.\nGott der Wahrheit und der Klarheit,\nführe mich im finstern Tal!\r\nDir ergeben will ich leben,\nwill in Deinem Lichte stehn,\nbis da taugen meine Augen,\nDich von Angesicht zu sehn.'),
(9, '0081', 'Aus Himmelsherrlichkeit kam Er herab  -  Down from His Splendor in Glory He came   (Wie sollt ich Ihn nicht lieben)', 'Down from His splendor in glory He came,\ninto a world of woe.\nTook on Himself all my guilt and my shame,\nwhy should He love me so?\r\nHow can I help but love Him,\nwhen He loved me so?\nHow can I help but love Him,\nwhen He loved me so?\r\nI am unworthy to take of His grace,\nwonderful grace so free.\nYes Jesus suffered and died in my place,\ne\'en for a soul like me.\r\nHe is the fairest of thousands to me,\nHis love is sweet and true.\nWonderful beauty in Him I now see,\nmore than I ever knew.', 'Aus Himmelsherrlichkeit kam Er herab\nin eine Welt voll Schmerz,\nnahm meine Schuld, meinen Jammer mir ab;\nLiebe nur füllt Sein Herz.\r\nWie sollt ich Ihn nicht lieben,\nder mir alles gibt!\nWie sollt ich Ihn nicht lieben,\nder so treu mich liebt!\r\nUnwert der göttlichen Liebe bin ich.\nO welche große Gnad!\nleiden und Tod nahm mein Jesus auf sich,\nlitt sie an meiner statt.\r\nEr ist der Schönste, der Herrlichste mir,\nsüß Seine Lieb und rein.\nWundersam strahlt Seine Güte auch dir.\nWillst du Sein Eigen sein?'),
(9, '0082', 'Aus meinen Banden, Kummer und Leid  -  Out of my Bondage, Sorrow and Night', 'Out of my bondage, sorrow and night,\nJesus, I come, Jesus, I come.\nInto Thy freedom, gladness and light,\nJesus, I come to Thee.\nOut of my sickness into Thy health,\nout of my want and into Thy wealth,\nout of my sin and into Thyself,\nJesus, I come to Thee.\r\nOut of my shameful failure and loss,\nJesus, I come, Jesus, I come.\nInto the glorious gain of Thy cross,\nJesus, I come to Thee.\nOut of earth\'s sorrows into Thy balm,\nout of life\'s storms and into Thy calm,\nout of distress to jubilant psalm,\nJesus, I come to Thee.\r\nOut of unrest and arrogant pride,\nJesus, I come, Jesus, I come.\nInto Thy blessed will to abide,\nJesus, I come to Thee.\nOut of myself to dwell in Thy love,\nout of despair into raptures above,\nupward for aye on wings like a dove,\nJesus, I come to Thee.', 'Aus meinen Banden, Kummer und Leid,\n|: Jesus, ich komm; :|\nzu Deiner Freiheit, Wonne und Freud,\nJesus, ich komm zu Dir.\nAus den Gebrechen zu Dir, mein Heil,\naus meiner Armut zum Erbeteil,\naus all dem Meinen zu Dir ich eil\',\nJesus, ich komm zu Dir.\r\nAus meinem Irren, aus dem Verlust,\n|: Jesus, ich komm; :|\nan meines Mittlers liebende Brust,\nJesus, ich komm zu Dir.\nAus meinem Zagen zum Dankesdrang,\nzu Dir im Sturm, wo nimmer mir bang\'.\nAus Erdennot zum Jubelgesang.\nJesus, ich komm zu Dir.\r\nAus meiner Unruh, aus stolzem Wahn,\n|: Jesus, ich komm; :|\nzu Deines Willens göttlichem Plan,\nJesus, ich komm zu Dir.\nAus Eigenliebe in Deine Lieb,\nstatt des Versagens mutvoller Trieb.\nDir nur zu leben, Gnade mir gib!\nJesus, ich komm zu Dir.'),
(9, '0083', 'Aus tiefer Not schrei ich zu Dir, Herr Gott, erhör mein Rufen', NULL, 'Aus tiefer Not schrei\' ich zu Dir,\nHerr Gott, erhör\' mein Rufen!\nDein gnädig Ohr neig\' her zu mir\nund meiner Bitt\' es öffne!\nDenn so Du willst das sehen an,\nwas Sünd\' und Unrecht ist getan,\nwer kann, Herr, vor Dir bleiben?\r\nBei Dir gilt nichts denn Gnad\' und Gunst,\ndie Sünde zu vergeben;\nes ist doch unser Tun umsonst\nauch in dem besten Leben.\nVor Dir niemand sich rühmen kann,\nes muss Dich fürchten jedermann\nund Deiner Gnade leben.\r\nDarum auf Gott will hoffen ich,\nauf mein Verdienst nicht bauen;\nauf Ihn mein Herz soll lassen sich\nund Seiner Güte trauen,\ndie mir zusagt Sein wertes Wort;\ndas ist mein Trost und treuer Hort,\ndes will ich all\'zeit harren.\r\nUnd ob es währt bis in die Nacht\nund wieder an den Morgen,\nsoll doch mein Herz an Gottes Macht\nverzweifeln nicht, noch sorgen.\nSo tut Israel rechter Art,\nder aus dem Geist gezeuget ward\nund seines Gottes harret.\r\nOb bei uns ist der Sünden viel,\nbei Gott ist viel mehr Gnade.\nSein Hand zu helfen hat kein Ziel,\nwie groß auch sei der Schade.\nEr ist allein der gute Hirt\',\nder Israel erlösen wird\naus seinen Sünden allen.'),
(9, '0084', 'Auserwählung ist das Höchste   (Erwählt zu sein, ja erwählt zu sein, erwählt zu sein für alle Zeit)', NULL, 'Auserwählung ist das Höchste,\nAuserwählung ist genug,\nob ich arm bin, reich und fröhlich,\nweiß ich, Gott ist immer gut.\r\nErwählt zu sein, ja erwählt zu sein,\nerwählt zu sein für alle Zeit.\nErwählung ist alles, ich bin gewiss,\nEr erwählte mich und das ist genug.\r\nOb Er meinen Wunsch erfüllet,\nob Er mein Gebet erhört,\nund die Tränen manchmal fließen,\nund mir alles scheint verkehrt.\r\nAuserwählung ist das Beste,\nAuserwählung ist nur Gnad\',\nSeine Wahl war für mich Liebe,\ndarf heut\' gehen diesen Pfad.\r\nManchmal scheint es, Gott Er schweiget,\nund ich weiß nicht ein noch aus,\ndarf ich danken für Erwählung,\ndie mich bringt von hier nach Haus.'),
(9, '0085', 'Away in a Manger, no crib for a Bed', 'Away in a manger, no crib for a bed,\nthe little Lord Jesus laid down His sweet head.\nThe stars in the sky looked down where He lay,\nthe little Lord Jesus, asleep on the hay.\r\nThe cattle are lowing, the Baby awakes,\nbut little Lord Jesus, no crying He makes.\nI love Thee, Lord Jesus! Look down from the sky,\nand stay by my cradle, till morning is nigh.\r\nBe near me, Lord Jesus, I ask Thee to stay.\nClose by me forever, and love me, I pray.\nBless all the dear children in Thy tender care,\nAnd take us to heaven, to live with Thee there.', NULL),
(9, '0086', 'Ähnlich, o Jesus Dir, ist meine Hoffnung hier   (Chorus)', NULL, 'Ähnlich, o Jesus Dir, ist meine Hoffnung hier.\nDenken, handeln wie Du, auch lieben so wie Du.\nÄhnlich o Jesus Dir, ist meine Hoffnung hier,\ndurch Deinen Geist mach mich ähnlich nur Dir!'),
(9, '0087', 'Back in Eternity, before the World began   (We are His Bride)', 'Back in eternity, before the world began,\nGod looked through history and knew ev\'ry name,\nHe knew He would have a church,\nHe knew He would have a Bride,\nthe people that walk in the Gospel Light.\r\nWe are His Bride,\nwe are His Bride,\nthe one that came\nfrom His Side. (2x)\r\nSo He called ev\'ry name, He called ev\'ryone,\nthat would fall in love with His dear Son.\nSo no matter what comes, God is on His Throne,\nand one thing is sure: The Lord knows His own!\r\nSo there\'s no reason to fear that we\'ll be left behind,\nthere\'s no reason to fear, that we\'ll be left in the night,\nfor we are flesh of His flesh, we are bone of His bone,\nand the ones that He loves, He\'ll take them home!\r\nSo let\'s look up to Him, let\'s look up to God,\nHe went to the cross and He shed His Blood,\nwe\'re no longer bound, He loosed all the chains,\nthe Rapture will come, and we\'ll be where He is!', 'Zurück in der Ewigkeit, bevor die Welt begann,\nschaute Gott durch die Geschichte und kannte jeden Namen,\nEr wusste, dass Er eine Gemeinde haben würde,\nEr wusste, Er würde eine Braut haben,\ndie Menschen, die im Licht des Evangeliums wandeln.\r\n(Wir sind Seine Braut,\nwir sind Seine Braut,\ndiejenige, die kam\nvon Seiner Seite. (2x))\r\nSo rief Er jeden Namen, Er rief jede Person,\ndie sich in Seinen lieben Sohn verlieben würden.\nSo, egal was kommt, Gott ist auf Seinem Thron,\nund eines ist sicher: Der Herr kennt die Seinen!\r\nEs gibt also keinen Grund zu befürchten,\ndass wir zurückbleiben werden,\nes gibt keinen Grund zu fürchten,\ndass wir in der Nacht zurückgelassen werden,\ndenn wir sind Fleisch von Seinem Fleisch,\nwir sind Bein von Seinem Bein,\nund die, die Er liebt, die wird Er nach Hause holen!\r\nAlso lasst uns zu Ihm aufschauen,\nlasst uns zu Gott aufschauen,\nEr ging ans Kreuz und vergoss Sein Blut,\nwir sind nicht mehr gebunden, Er löste alle Ketten,\ndie Entrückung wird kommen,\nund wir werden dort sein, wo Er ist!'),
(9, '0088', 'Bald erscheint jener Tag  -  There is coming a Day   (Welch ein Tag wird das sein, wenn einst Jesus mich holt heim)', 'There is coming a day,\nwhen no heartaches shall come,\nno more clouds in the sky,\nno more tears to dim the eye.\nAll is peace forevermore,\non that happy golden shore.\nWhat a day, glorious day that will be.\r\nWhat a day that will be,\nwhen my Jesus I shall see,\nwhen I look upon His face,\nthe One who saved me by His grace.\nWhen He takes me by the hand,\nand leads me through the Promised Land.\nWhat a day, glorious day that will be.\r\nThere\'ll be no sorrow there,\nno more burdens to bear,\nno more sickness, no pain,\nno more parting over there.\nAnd forever I will be\nwith the One who died for me.\nWhat a day, glorious day that will be.\r\n', 'Bald erscheint jener Tag,\nwo kein Herzeleid wird sein,\nkeine Trübsal und Not,\nkeine Tränen, Angst und Tod.\nFriede herrscht in jenem Land,\nan dem sel\'gen gold\'nen Strand.\nWelch ein Tag, glorreicher Tag wird das sein!\r\nWelch ein Tag wird das sein,\nwenn einst Jesus mich holt heim.\nMeinen Heiland ich darf seh\'n,\nder aus Gnaden mich erseh\'n,\nund Er nimmt mich an der Hand,\nführt mich durchs verheiß\'ne Land.\nWelch ein Tag, glorreicher Tag wird das sein!\r\nKeine Sorgen sind dort,\nFried\' und Freud\' erfüll\'n den Ort,\nweder Krankheit noch Leid,\ndoch ein Jauchzen allezeit.\nUnd für immer werd\' ich sein\nmit dem Heiland dort vereint.\nWelch ein Tag, glorreicher Tag, wird das sein!\r\nUnser Heiland kommt bald,\ndie Posaune laut erschallt.\nO mein Freund bist du bereit?\nDenkst du an die Ewigkeit?\nIst dein Kleid gewaschen rein,\nwird ein Jauchzen droben sein.\nWelch ein Tag, glorreicher Tag wird das sein!'),
(9, '0089', 'Bald erscheint Jesus wie Ers gesagt  -  Jesus is coming to Earth again   (Ehre! Ehre! Ihm gehört Reich und Macht!)', 'Jesus is coming to earth again,\nwhat if it were today?\nComing in power and love to reign,\nwhat if it were today?\nComing to claim His chosen Bride,\nall the redeemed and purified,\nover this whole earth scattered wide.\nWhat if it were today?\r\nGlory, glory! Joy to my heart \'twill bring.\nGlory, glory! When we shall crown Him King.\nGlory, glory! Haste to prepare the way.\nGlory, glory! Jesus will come someday.\r\nSatan\'s dominion will then be o\'er,\no that it were today!\nSorrow and sighing shall be no more,\no that it were today!\nThen shall the dead in Christ arise,\ncaught up to meet Him in the skies.\nWhen shall these glories meet our eyes?\nWhat if it were today?\r\nFaithful and true would He find us here,\nif He should come today?\nWatching in gladness and not in fear,\nif He should come today?\nSigns of His coming multiply,\nmorning light breaks in eastern sky.\nWatch, for the time is drawing nigh.\nWhat if it were today?', 'Bald erscheint Jesus wie Er\'s gesagt,\ndenk, wenn Er heute käm\'!\nKommt in den Wolken mit großer Kraft,\ndenk, wenn Er heute käm\'!\nSammelt zu sich die erlöste Schar,\ndie hier im Pilgerlauf treu Ihm war,\nstellt sie geschmückt dem Vater dar,\ndenk, wenn Er heute käm!\r\nEhre! Ehre! Ihm gehört Reich und Macht!\nEhre! Ehre! Er hat das Werk vollbracht!\nEhre! Ehre! Machet dem König Bahn!\nEhre! Ehre! Jesus, Er naht heran!\r\nDann fällt die irische Hülle ab,\ndenk, wenn es heute wär\'!\nSchmerzen und Leid alles sinkt ins Grab,\no dass es heute wär\'!\nDie, die in Christo entschlafen schon,\nwerden erweckt durch Posaunenton\nmit uns entrückt zu Gottes Thron.\nDenk, wenn es heute wär\'!\r\nFänd\' Er dich wachend bereitet steh\'n,\nwenn Jesus heute käm\'?\nKönntest du Ihm freudig entgegen geh\'n,\nwenn Jesus heute käm\'?\nDeutlich sich lösen die Zeichen ein,\nheller erglänzet der Morgenschein,\nbald zieht der Friedenskönig ein.\nDenk, wenn es heute wär\'!'),
(9, '0090', 'Bald geht zu Ende diese Zeit  -  In these, the closing Days of Time   (Der Herr kommt bald)   [Linn]', 'In these, the closing days of time,\nwhat joy the glorious hope affords,\nthat soon, oh, wondrous truth sublime!\nHe shall reign, King of Kings and Lord of Lords.\r\nHe\'s coming soon, He\'s coming soon,\nwith joy I welcome His returning.\nIt may be morn\', it may be night or noon,\npraise God, He\'s coming soon.\r\nThe signs around, in earth and air,\nor painted on the starlit sky.\nGod\'s faithful witnesses declare\nthat the coming of the Saviour draweth nigh.\r\nThe dead in Christ who \'neath us lie,\nin countless numbers, all shall rise.\nWhen through the portals of the sky\nHe shall come to prepare our Paradise.\r\nAnd we who, living, yet remain,\ncaught up, shall meet our faithful Lord.\nThis hope we cherish not in vain,\nbut we comfort one another by this word.', 'Bald geht zu Ende diese Zeit,\ndoch lebt die Hoffnung nah und fern,\ndass bald ein Wunder uns befreit;\nJesus herrschet über Könige und Herrn.\r\nDer Herr kommt bald, der Herr kommt bald.\nmit Freude heiß\' ich ihn willkommen.\nOb morgens früh, ob in der Abendzeit,\nich weiß, der Herr kommt bald.\r\nDie Zeichen, die wir rundum seh\'n,\nsoweit sie unser Aug ermisst,\nGott gibt durch sie uns zu versteh\'n,\ndass des Heilandes Kommen sehr nah ist.\r\nDie Toten im Herrn Jesus Christ\nverlassen bald die kühle Gruft;\nwenn sich des Himmels Tor erschließt,\ndann sie schweben ihm entgegen in der Luft.\r\nUnd wir, die noch am Leben sind,\nwir werden auch zu ihm entrückt;\nwelch süßer Trost dem Gotteskind,\nköstlich\' Wort, mit dem Er uns so oft beglückt.'),
(9, '0091', 'Bald in dem obern Heimatland  -  Not now, but in the coming Years   (Drum trau auf Gott bei Tag und Nacht)   [Siegesklänge]', 'Not now, but in the coming years,\nit may be in the better land,\nwe\'ll read the meaning of our tears,\nand there, some time, we\'ll understand.\r\nThen trust in God thro\' all the days.\nFear not, for He doth hold thy hand.\nThough dark thy way, still sing and praise,\nsome time, some time, we\'ll understand.\r\nWe\'ll catch the broken thread again,\nand finish what we here began.\nHeav\'n will the mysteries explain,\nand then, ah, then, we\'ll understand.\r\nGod knows the way, He holds the key,\nHe guides us with unerring hand.\nSome time with tearless eyes we\'ll see.\nYes, there, up there, we\'ll understand.', 'Bald in dem ober\'n Heimatland,\nwerden wir in Klarheit seh\'n,\nwie Er uns führt an Seiner Hand,\nwir werden Gottes Lieb\' versteh\'n.\r\nD\'rum trau auf Gott bei Tag und Nacht!\nSei furchtlos, Er hält deine Hand,\nund sing wie es auch kommen mag.\nBald, bald bist du im Heimatland.\r\nWir knüpfen das zerbroch\'ne Band,\nvollenden, was schon hier begann.\nUnd uns\'res Glaubens Unterpfand\nverklärt wir seh\'n im Heimatland.\r\nGott weiß den Weg, Er kennt das Ziel,\nEr führt uns heim mit sich\'rer Hand.\nUnd säten Tränen wir hier viel,\ndort ernten wir im Heimatland.'),
(9, '0092', 'Bald kommt der Herr, Halleluja! doch nicht in Niedrigkeit   (Seid bereit, vor Ihm zu stehn)', NULL, 'Bald kommt der Herr, Halleluja!\ndoch nicht in Niedrigkeit,\ndas Reich ist Sein, Halleluja!\nin alle Ewigkeit\r\nSeid bereit, vor Ihm zu steh\'n,\nSeine Herrlichkeit zu seh\'n!\nWas Er verheißt, Halleluja!\ndas wird an uns geschehn.\r\nBald kommt der Herr, Halleluja!\nder einst als stilles Lamm\ndie Sünden trug, Halleluja!\nund starb am Kreuzesstamm.\r\nBald kommt der Herr, Halleluja!\nMit königlicher Pracht,\nSein ist das Reich, Halleluja!\nSein ist Gewalt und Macht!\r\nBald kommt der Herr, Halleluja!\nRegiert den Erdenkreis\nund füllt ihn ganz, Halleluja!\nmit Seines Namens Preis.'),
(9, '0093', 'Bald kommt der schöne neue Morgen  -  There waits for me a glad Tomorrow   (Bald wird das Sterbliche vorüber sein)', 'There waits for me a glad tomorrow\nwhere gates of pearl swing open wide.\nAnd when I\'ve passed this vale of sorrow,\nI\'ll dwell upon the other side.\r\nSome day beyond the reach of mortalken,\nsome day, God only knows just where and when,\nthe wheels of alife shall all stand still,\nand I shall go to dwell on Zion\'s hill.\r\nSome day I\'ll hear the angels singing,\nbeyond the shadows of the tomb.\nAnd all the bells of heaven ringing,\nwhile saints are singing, "Home, sweet home."\r\nSome day my labors will be ended,\nand all my wand\'rings will be o\'er.\nAnd all earth\'s broken ties be mended,\nand I shall sigh and weep no more.\r\nSome day the dark clouds will be rifted,\nand all the night of gloom be past.\nAnd all life\'s burdens will be lifted,\nthe day of rest shall dawn at last.', 'Bald kommt der schöne neue Morgen,\nwenn Perlentore offen steh\'n.\nUnd nach dem Tal der Not und Sorgen,\nweiß ich, mein Haus wird schon dort steh\'n.\r\nBald wird das Sterbliche vorüber sein,\nschon bald, doch Gott weiß Tag und Stund allein.\nUnd wenn die Lebensräder stille steh\'n,\nweiß ich auf Zions Hügel ist mein Heim.\r\nUnd wenn die Engel dann dort singen,\ndann ist die Grabesnacht vorbei.\nDann werden Himmelsglocken klingen\nund Heil\'ge singen "Süßes Heim!"\r\nBald enden alle Erdenstunden,\nja diese ird\'sche Wanderszeit.\nUnd Gott heilt alle uns\'re Wunden\nund nimmt von uns die Traurigkeit.\r\nBald werden dunkle Wolken fliehen,\nbald endet diese Erdennacht.\nBald wird die Sonn\' des Heil\'s aufgehen\nund dann bricht an der neue Tag.'),
(9, '0094', 'Bald schon kommt für mich der große Morgen  -  Some glad Morning when this Life is over   (Ich flieg davon, wie herrlich)', 'Some glad morning when this life is o\'er,\nI\'ll fly away,\nTo a home on God\'s celestial shore,\nI\'ll fly away.\r\nI\'ll fly away, oh glory, I\'ll fly away;\nWhen I die, Halleluja by and by,\nI\'ll fly away.\r\nWhen the shadows of this life have grown,\nI\'ll fly away.\nLike a bird from prison bars has flown,\nI\'ll fly away.\r\nJust a few more weary days and then,\nI\'ll fly away;\nTo a land where joy shall never end,\nI\'ll fly away.\r\n', 'Bald schon kommt für mich der große Morgen.\nIch flieg davon.\nLasse allen Kummer und die Sorgen.\nIch flieg davon.\r\nIch flieg davon, wie herrlich!\nIch flieg davon.\nWie ein Adler in die Lüfte steigt,\nflieg ich davon.\r\nWenn mein kurzes Erdenleben endet.\nFlieg ich davon.\nDarum ist mein Blick zum Herrn gewendet.\nIch flieg davon.\r\nNur noch ein paar letzte Prüfungstage.\nIch flieg davon.\nEnde aller Last und Erdenplage.\nIch flieg davon.\r\nDann darf ich den großen König sehen.\nIch flieg davon.\nDarf aus Gnaden dann bei Jesus stehen.\nIch flieg davon.'),
(9, '0095', 'Bald, ja bald, werd ich den König seh\'n   (2 Chorusse)', NULL, 'Bald, ja bald, werd\' ich den König seh\'n,\nBald, ja bald, werd\' ich den König seh\'n,\nBald, ja bald, werd\' ich den König seh\'n\nverwandelt in Sein Bild.\r\nBald, ja bald, werd\' ich den König seh\'n,\nBald, ja bald, werd\' ich den König seh\'n,\nBald, ja bald, werd\' ich den König seh\'n\nvor Seinem Throne steh\'n.'),
(9, '0096', 'Bald, ja schon sehr bald, werden wir den König sehn  -  Soon and very soon, we are going to see the King', 'Soon and very soon,\nwe are going to see the King.\nSoon and very soon,\nwe are going to see the King.\nSoon and very soon,\nwe are going to see the King.\nHalleluja, Halleluja,\nwe are going to see the King.\r\nNo more crying there,\nwe are going to see the King.\nNo more crying there,\nwe are going to see the King.\nNo more crying there,\nwe are going to see the King.\nHalleluja, Halleluja,\nwe are going to see the King.\r\nJesus will be there,\nwe are going to see the King.\nJesus will be there,\nwe are going to see the King.\nJesus will be there,\nwe are going to see the King.\nHalleluja, Halleluja,\nwe are going to see the King.', 'Bald, ja schon sehr bald,\nwerden wir den König seh\'n.\nBald, ja schon sehr bald,\nwerden wir den König seh\'n.\nBald, ja schon sehr bald,\nwerden wir den König seh\'n.\nHallelujah, Hallelujah,\nwerden wir den König seh\'n.\r\nKeine Tränen mehr,\ndenn wir werden den König seh\'n.\nKeine Tränen mehr,\ndenn wir werden den König seh\'n.\nKeine Tränen mehr,\ndenn wir werden den König seh\'n.\nHallelujah, Hallelujah,\nwir werden den König seh\'n.\r\nJesus wird dort sein,\nja wir werden den König seh\'n.\nJesus wird dort sein,\nja wir werden den König seh\'n.\nJesus wird dort sein,\nja wir werden den König sehn.\nHallelujah, Hallelujah,\nwir werden den König seh\'n.'),
(9, '0097', 'Bald, ja, bald seh\'n wir den Heiland  -  By and by we shall know Jesus   (Ja, bald, ja, bald, wir singens leise)', 'By and by we shall know Jesus,\nby and by, oh, by and by.\nEven now He looks and sees us,\njourneying toward His home on high.\nAnd He smiles upon us, saying,\nby and by, oh, by and by,\nCares and trials you’ll be laying\nwith your earthly garments by.\r\nOh by and by, oh sing it softly,\nthinking not of earthly care,\nbut the by and by of Heaven\nwaiting for us over there.\r\nBy and by we shall be standing,\nby and by, oh, by and by.\nAt fair heaven’s shining landing,\nwhile the river murmurs by.\nAnd our friends will round us gather,\nby and by, oh, by and by.\nSaying Welcome, for the Father\nloves to have His children nigh.\r\nBy and by! we say it gently,\nlooking on our peaceful dead.\nAnd we do not think of earth life,\nbut of Heaven’s sweet life instead.\nBy and by we all shall gather,\nby and by, oh, by and by.\nIn the life of God our Father\nthat shall know no by and by.', 'Bald, ja, bald seh\'n wir den Heiland,\nbald, ja, bald sind wir bei Ihm!\nJetzt schaut Er noch auf uns nieder,\nwie wir folgen Seiner Stimm\'.\nUnd Er blickt uns an so freundlich,\nspricht uns zu: O habt nur Mut!\nBald ist alles überwunden\ndurch mein eigen Bundesblut.\r\nJa, bald, ja, bald, wir singen\'s leise,\nachten nicht der Erde Pein;\nwir sind auf der Himmelsreise,\nbald, bald werden wir dort sein!\r\nBald, ja bald steh\'n wir dort oben\nbald, ja bald, o Herrlichkeit,\nwo die Lebensströme fließen,\nwo die Heimat uns bereit.\nUns\'re Lieben, die schon drüben\nbei der sel\'gen Geisterschar,\nwerden bald uns wieder grüßen,\nstellen uns dem Vater dar.\r\nBald, ja bald, so lasst uns sprechen,\nwenn wir steh\'n an Sarg und Grab;\nwenn der Erde Bande brechen\nschaut empor und nicht hinab!\nBald, ja bald, auf Wiedersehen\nbei dem Herrn nach kurzer Zeit!\nDann wird unser Jubel währen\nbis in alle Ewigkeit.'),
(9, '0098', 'Banges Herz dein Gott dich rufet, kehrt zu dir Sein Angesicht  -  Troubled Heart, thy God is calling, He is drawing very near   (Komm, dein Heil ist gar nicht weit)', 'Troubled heart, thy God is calling,\nHe is drawing very near.\nDo not hide thy deep emotion,\ndo not check that falling tear.\r\nO, be saved, His grace is free!\nO, be saved, His grace is free!\nO, be saved, His grace is free!\r\nCome, the Spirit still is pleading,\ncome to Him, the meek and mild.\nHe is waiting now to save you,\nwilt thou not be reconciled?\r\nArt thou waiting till the morrow?\nThou may\'st never see its light.\nCome at once! accept His mercy;\nHe is waiting - come tonight.\r\nLet the angels bear the tidings\nupward to the courts of heav\'n!\nLet them sing, with holy rapture,\no\'er another soul forgiv\'n!', 'Banges Herz, dein Gott dich rufet,\nkehrt zu dir Sein Angesicht.\nO, verbirg nicht deine Rührung,\nwehre deinen Tränen nicht.\r\nKomm, dein Heil ist gar nicht weit.\nTue Buße, tu\' es heut\'.\nSuch den Frieden, es ist Zeit!\r\nFühlst du\'s nicht? Der Geist dich mahnet.\nDir ja, dir die Stimme gilt.\nFlieh\' in jene off\'ne Arme!\nJesus ist so sanft und mild.\r\nWillst du noch bis morgen warten?\nMorgen ist\'s vielleicht zu spät.\nHeute, heute nimm die Gnade.\nKomm, o komm, die Frist vergeht!\r\nLass der Engel Chor die Botschaft\njubelnd tragen himmelwärts.\n"Wieder tat ein Sünder Buße,\nwieder schmilzt ein starres Herz!"'),
(9, '0099', 'Be it unto me', 'Be it unto me\nAccording to your Word\nAccording to your promises\nI can stand secure\nCarve upon my heart\nThe truth that sets me free\nAccording to your Word O Lord\nBe it unto me\r\nYou promised your blood will deliver\nLord, we believe it\'s true\nYou promised us joy like a river\nLord we receive it from you\nThese things you have spoken\nAnd you\'re bringing to pass\nThis world\'s disappearing\nBut your word will last\r\nYou promised to carry our sorrows\nLord, we believe it\'s true\nYou promised unending tomorrows\nLord we receive them from you\nYou\'ll be our Provider\nIn Your word it\'s revealed\nBy the stripes that You bore\nLord We have been healed', 'Mir geschehe\nnach deinem Wort\nNach deinen Verheißungen\nIch kann sicher stehen\nSchreibe auf mein Herz\nDie Wahrheit, die mich frei macht\nNach deinem Wort, oh Herr\ngeschehe es für mich\r\nDu hast versprochen, dass dein Blut erlösen wird\nHerr, wir glauben, dass es wahr ist\nDu hast uns Freude versprochen wie einen Fluss\nHerr, wir empfangen sie von dir\nDiese Dinge hast du gesprochen\nUnd du lässt sie geschehen\nDiese Welt verschwindet\nAber dein Wort wird bleiben\r\n(Du hast versprochen, unsere Sorgen zu tragen\nHerr, wir glauben, dass es wahr ist\nDu versprachst eine unendliche Zukunft\nHerr, wir empfangen sie von dir\nDu wirst unser Versorger sein\nIn Deinem Wort ist es offenbart\nDurch die Striemen, die Du getragen hast\nHerr, sind wir geheilt worden)'),
(9, '0100', 'Be not afraid, put fear aside', 'Be not afraid, put fear aside\nI have sent my Prophet to prepare my Bride.\nI am coming soon, for our honeymoon\nand to take my loved one with me to the sky.\nThere\'s a table spread and greetings to be said\nand some tears to wipe away from off your eyes.\nDo not cry anymore, it is written thus before,\nfor it\'s all over now my beloved.\r\nThe parting\'s been a time of trial,\nweary moments and distress for just a while.\nThat I would be true I have said to you\nand My promise I have never passed aside.\nYou have never seen the half of what I mean,\nnor can understand the things prepared for you.\nFace to face, will it be, what a rapture and for thee,\nfor it\'s all over now, my beloved.\r\nThere is a joy, a greeting sweet,\ncares and sorrows leave,\nwhen loved ones come to meet.\nWhere the burdens fall, to be not at all.\nHeart to heart and eye to eye eternally.\nHear the Bridegroom\'s call, it\'s not to one and all\nbut to her who stays within My every Word.\nPart of Me, of My heart, we will gather not to part\nfor it\'s all over now, my beloved.', NULL),
(9, '0101', 'Be still for the Presence of the Lord, the Holy One is here  -  Sei still, denn die Gegenwart des Herrn, der Heilige ist hier', 'Be still, for the presence of the Lord,\nthe Holy One is here.\nCome, bow before Him now\nwith reverence and fear.\nIn Him no sin is found,\nwe stand on Holy ground.\nBe still, for the presence of the Lord,\nthe Holy One is here.\r\nBe still, for the Glory of the Lord\nis shining all around.\nHe burns with holy fire,\nwith splendor He is crowned.\nHow awesome is the sight,\nour radiant King of light.\nBe still, for the Glory of the Lord,\nis shining all around.\r\nBe still, for the power of the Lord,\nis moving in this place.\nHe comes to cleanse and heal,\nto minister His grace.\nNo work too hard for Him,\nin faith recieve from Him.\nBe still, for the power of the Lord,\nis moving in this place.', 'Sei still, denn die Gegenwart des Herrn,\nder Heilige ist hier.\nKommt, verneigt euch jetzt vor ihm\nmit Ehrfurcht und Furcht.\nIn Ihm ist keine Sünde zu finden,\nwir stehen auf heiligem Boden.\nSeid still, denn die Gegenwart des Herrn,\nder Heilige ist hier.\r\nSei still, denn die Herrlichkeit des Herrn\nleuchtet ringsumher.\nEr brennt mit heiligem Feuer,\nmit Pracht ist Er gekrönt.\nWie herrlich ist der Anblick,\nunser strahlender König des Lichts.\nSeid still, denn die Herrlichkeit des Herrn\nleuchtet ringsumher.\r\nSei still, denn die Kraft des Herrn\nbewegt sich an diesem Ort.\nEr kommt, um zu reinigen und zu heilen,\num seine Gnade zu erweisen.\nKeine Arbeit ist zu schwer für Ihn,\nim Glauben von Ihm zu empfangen.\nSei still, denn die Kraft des Herrn,\nbewegt sich an diesem Ort.'),
(9, '0102', 'Beautiful Christ, beautiful Christ   (Chorus)', 'Beautiful Christ, beautiful Christ,\nKing of my life is He.\nBeautiful Christ, beautiful Christ,\nThine evermore we shall be.\r\nLet me exalt the beauty of Christ,\nfairer than all is He.\nWonderful, marvellous beauty Divine,\nOh that the world might see.\r\nLet me exalt His Power to save,\nSave to the uttermost.\nPower to give life eternal to all,\nPurchased at such a cost.\r\nLet me exalt His power to heal,\nAll who will just believe.\nPower to fill with His Spirit Divine,\nAll who will just receive.', NULL),
(9, '0103', 'Beautiful Lord, wonderful Saviour  -  Herrlicher Herr, wunderbarer Erlöser', 'Beautiful Lord, wonderful Saviour,\nI know for sure, all of my days are held in Your hands,\ncrafted into Your perfect plan.\r\nYou gently called me into Your presence,\nguiding me by Your Holy Spirit.\nTeach me dear Lord, to live all of my life\nthrough Your eyes.\r\nI\'m captured by Your Holy calling.\nSet me apart, I know You\'re drawing me to Yourself.\nLead me Lord, I pray.\r\nOh take me, mold me, use me, fill me.\nI give my life to the Potter\'s hand.\nOh call me, guide me, lead me, walk beside me.\nI give my life to the Potter\'s hand.', 'Herrlicher Herr, wunderbarer Erlöser,\nich weiß sicher, dass alle meine Tage in Deinen Händen gehalten werden,\ngeformt in Deinem perfekten Plan.\r\nDu hast mich sanft in Deine Gegenwart gerufen,\nund führst mich durch Deinen Heiligen Geist.\nLehre mich, lieber Herr, mein ganzes Leben\ndurch Deine Augen zu sehen.\r\nIch bin gefangen von Deiner heiligen Berufung.\nNimm mich beiseite, ich weiß, Du ziehst mich zu Dir.\nFühre mich, Herr, ich bete.\r\nOh nimm mich, forme mich, benutze mich, fülle mich.\nIch gebe mein Leben in die Hand des Töpfers.\nOh rufe mich, führe mich, leite mich, gehe neben mir.\nIch übergebe mein Leben in die Hand des Töpfers.'),
(9, '0104', 'because of who you are', 'Because of who you are, I give you glory\nBecause of who you are, I give you praise\nBecause of who you are, I will lift my voice and say\nLord, I worship you because of who you are\nLord, I worship you because of who you are\r\nJehovah Jireh, my provider\nJehovah Nissi, Lord, You reign in victory\nJehovah Shalom, my Prince of Peace\nAnd I worship because of who you are', NULL),
(9, '0105', 'Because of who You are I give You Glory   (2 Chorusse)', 'Because of who You are I give you glory.\nBecause of who You are I give you praise.\nBecause of who You are I will lift my voice and say:\nLord I worship you because of who You are.\r\nJehovah-Jireh, my provider.\nJehovah-Nissi, Lord you reign in victory.\nJehovah-Shalom, my prince of peace.\nAnd I worship you because of who you are.', NULL),
(9, '0106', 'Bedecke mich Herr  -  Cover me Lord   (Chorus)', 'Cover me Lord, cover me Lord,\nextend the borders Thy garment over me,\nbecause Thou art my nearest kinsman.\nCover me Lord, cover me Lord, cover me.', 'Bedecke mich, Herr, bedecke mich, Herr\nbreite den Saum Deines Gewandes über mich aus,\ndenn Du bist mein nächster Verwandter.\nBedecke mich, Herr, bedecke mich, Herr, bececke mich.'),
(9, '0107', 'Bedrückt durch eine schwere Bürde  -  Shackled by a heavy Burden   (Er berührte mich, oh, Er berührte mich)', 'Shackled by a heavy burden,\n\'neath a load of guilt and shame.\nThen the hand of Jesus touched me,\nand now I am no longer the same.\r\nHe touched me, oh, He touched me,\nand oh, the joy that floods my soul.\nSomething happened, and now I know,\nHe touched me and made me whole.\r\nSince I\'ve met this blessed Saviour,\nsince He cleansed and made me whole.\nI shall never cease to praise Him,\nI\'ll shout it while eternity rolls.\r\nSo, your heart is burdened,\nI\'ll tell you what you do then.\nPut all your faith in Jesus,\nHis salvation is good for you too.', 'Bedrückt durch eine schwere Bürde,\nmein Leben war mit Schuld geplagt,\ndoch seit Jesu Hand mich berührte,\nhat Er mich von Schuld losgemacht.\r\nEr Berührte mich, oh, Er berührte mich,\nund Freude füllt nun meine Seel\'.\nEtwas geschah und nun weiß ich,\nEr berührte mich und heilte mich ganz.\r\nSeit der Heiland mir begegnet\nund Er mich von Schuld befreit,\nkann ich Ihn von Herzen loben.\nIch rühme Jesus in Ewigkeit.\r\nSo, ist dein Herz beladen,\nich sag\' dir, was du dann tust.\nLeg allen Glauben in Jesus,\nSein Heil ist auch für dich gut.'),
(9, '0108', 'Behold what manner of Man is this   (He is the Lord of Glory, He is the great I AM)', 'Behold what manner of Man is this\nwho stills the raging sea.\nHe heals the sick, the lame, the halt,\nand makes the blind to see.\nHe opens all the prison doors,\nand sets the captives free.\nBehold what manner of man is this,\nwhat manner of man is He!\r\nHe\'s the Lord of Glory, He is the great I AM.\nThe Alpha and Omega, the beginning and the end.\nHis name is Wonderful, the Prince of Peace is He.\nThe Everlasting Father, throughout Eternity.\r\nBehold what manner of man is this,\nWho spake to the woman at the well.\nEverlasting life I will give tio thee,\nfarr richer than man can tell.\nAnd whosoever shall drink of the well\nshall live eternally.\nBehold what manner of man is this,\nwhat manner of man is He?\r\nBehold what manner of man is this,\nWho speaks to the lame and halt.\nHe says: "Thy sins be forgiven thee,\ntake up thy bed and walk."\nHe stands as the mighty Healer now,\nand cries: "Come unto Me."\nBehold what manner of man is this,\nwhat manner of man is He!\r\nBehold what manner of man is this,\nWho stands between God and man.\nHis eyes are as a flame of fire,\nHis fan is in His hands.\nJohn saw Him in the seven churches\nas the sun in brilliancy.\nBehold what manner of man is this,\nwhat manner of man is He!\r\nBehold what manner of man is this,\nWho sits on His heavenly throne.\nHe rules and reigns from heaven abov\nHis beloved and His own.\nHe\'s the lion of the tribe of Judah\nthe root of David is He.\nBehold what manner of man is this,\nwhat manner of man is He!', NULL),
(9, '0109', 'Bei Dir Jesus will ich bleiben, stets in Deinem Dienste stehn', NULL, 'Bei Dir, Jesus, will ich bleiben,\nstets in Deinem Dienste steh\'n;\nnichts soll mich von Dir vertreiben,\nwill auf Deinen Wegen geh\'n!\nDu bist meines Lebens Leben,\nmeiner Seele Trieb und Kraft,\nwie der Weinstock seinen Reben\nzuströmt Kraft und Lebenssaft.\r\nKönnt ich\'s irgend besser haben\nals bei Dir, der allezeit\nso viel tausend Gnadengaben\nfür mich Armen hat bereit?\nKönnt ich je getroster werden,\nals bei Dir, Herr Jesus Christ,\ndem im Himmel und auf Erden\nalle Macht gegeben ist?\r\nWo ist solch ein Herr zu finden,\nder, was Jesus tat, mir tut:\nMich erkauft von Tod und Sünden\nmit dem eignen, teuren Blut?\nSollt ich dem nicht angehören,\nder Sein Leben für uns gab?\nSollt ich Ihm nicht Treue schwören,\nTreue bis in Tod und Grab?\r\nJa, Herr Jesus, bei Dir bleib ich,\nso in Freude wie in Leid;\nbei Dir bleib ich, Dir verschreib ich\nmich für Zeit und Ewigkeit!\nDeines Winks bin ich gewärtig,\nauch des Ruf\'s aus dieser Welt;\ndenn der ist zum Sterben fertig,\nder sich lebend zu Dir hält.\r\nBleib mir nah auf dieser Erden,\nbleib, auch wann mein Tag sich neigt,\nwenn es nun will Abend werden\nund die Nacht herniedersteigt!\nLege segnend dann die Hände\nmir aufs müde, schwache Haupt,\nsprechend: "Kind, hier geht\'s zu Ende,\ndoch dort lebet, wer hier glaubt."'),
(9, '0110', 'Beinah bekehret, es fehlt nicht viel  -  Almost persuaded, now to believe', '"Almost persuaded", now to believe,\n"almost persuaded", Christ to receive.\nSeems now some soul to say, "Go, Spirit, go Thy way,\nsome more convenient day On Thee I\'ll call."\r\n"Almost persuaded", come, come today,\n"Almost persuaded", Turn not away.\nJesus invites you here, Angels are ling\'ring near.\nPrayers rise from hearts so dear, oh wand\'rer, come.\r\n"Almost persuaded," Harvest is past!\n"Almost persuaded," doom comes at last!\n"Almost" cannot avail, "Almost" is but to fail!\nSad, sad, that bitter wail, "Almost - but lost!"', 'Beinah bekehret, es fehlt nicht viel;\nBeinah bekehret, nahe am Ziel!\nSo heißt\'s in manchem Fall:\n"Geh hin für dieses Mal,\nspäter treff ich die Wahl, heute noch nicht!"\r\nBeinah bekehret, jetzt ist es Zeit!\nBeinah bekehret, komm doch noch heut!\nJesus wirbt um dein Herz,\nEngel berührt deinen Schmerz,\nSeufzer gehn himmelwärts: Seele, o komm!\r\nBeinah bekehret, schnell naht der Tod.\nBeinah bekehret, jetzt welche Not!\nBeinah, o schlimmer Wahn!\n„Beinah“ reicht nicht hinan;\nNun geht der Jammer an: Ewig zu spät!'),
(9, '0111', 'Beleb Dein Werk, o Herr, zeig Deinen starken Arm  -  Revive Thy Work, oh Lord, Thy mighty Arm make bare   (Beleb Dein Werk, gib neuen Gnadenschein)', 'Revive thy work, oh Lord,\nthy mighty arm make bare,\nspeak with the voice that wakes the dead,\nand make thy people hear.\r\nRevive Thy work, oh Lord!\nWhile here to Thee we bow.\nDescend, oh gracious Lord, descend.\nO come and bless us now.\r\nRevive thy work, oh Lord,\ndisturb this sleep of death,\nquicken the smould\'ring embers now\nby thine almighty breath.\r\nRevive thy work, oh Lord,\ncreate soul-thirst for thee,\nand hung\'ring for the Bread of Life\noh may our spirits be.\r\nRevive thy work, Oh Lord,\nexalt thy precious name,\nand by the Holy Ghost, our love\nfor thee and thine inflame.', 'Beleb\' Dein Werk, o Herr,\nzeig Deinen starken Arm,\nweck\' durch Dein Wort die Toten auf,\nder Deinen Herz mach warm.\r\nBeleb\' Dein Werk,\ngib neuen Gnadenschein.\nDir wird dafür dann Preis und Ehr\'\nund uns der Segen sein.\r\nBeleb\' Dein Werk, o Herr,\nvertreib den Schlaf geschwind,\nden Docht, der glimmt, fach an zur Flamm\'\ndurch Deines Geistes Wind.\r\nBeleb\' Dein Werk, o Herr,\nwas krank ist mache wohl,\nden Durst und Hunger still mit Dir,\nmach uns des Geistes voll.\r\nBeleb\' Dein Werk, o Herr,\nDein Heil werd\' offenbar,\ndass bald die ganze Welt Dich kennt\nund Dir sich weiht fürwahr.'),
(9, '0112', 'Berge mich in Deinem Arm  -  Hide me now, under Your Wings   (Wenn die Meere toben Stürme wehn)', 'Hide me now\nunder Your wings.\nCover me\nWithin Your mighty hands.\r\nWhen the oceans rise and thunders roar,\nI will soar with you above the storm.\nFather, You are King over the flood,\nI will be still and know, You are God!\r\nFind rest my soul,\nin Christ alone.\nKnow His power,\nin quitness and trusts.', 'Berge mich,\nin Deinem Arm.\nSchütze mich,\nmit Deiner starken Hand.\r\nWenn die Meere toben Stürme weh\'n,\nwerd\' ich mit Dir über\'s Wasser geh\'n.\nDu bist König über Wind und Flut,\nmein Herz wird still, denn Du bist gut.\r\nKomm, ruh\' dich aus,\nbei deinem Gott.\nTrau auf Ihn,\nund seine große Kraft.'),
(9, '0113', 'Berühr Dein Volk noch einmal Herr - We need Wisdom we need Power and true Love for each other)', 'We need wisdom we need power\nand true love for each other.\nWe have had so many big but empty words.\nSo we come before Your face, asking for Your grace.\nBring Your people to a state of kingdom life.\nRestore Your church again.\r\nTouch your people once again,\nwith Your precious holy hand, I pray,\nlet Your Kingdom shine upon this earth,\nthrough a wondrous glorious Bride!\nNot for temporary deeds,\nbut to restore authority and pow\'r.\nLet a rushing mighty wind blow,\ntouch Your people once again!\r\nLord You see Your tired servants,\nand the broken wounded soldiers.\nOh how much we need Your precious healing hand.\nWe need the power of the cross,\nas the only source for us.\nWhen we stand up facing final battle cry.\nRestore your church again.', '\r\nBerühr\' Dein Volk noch einmal, Herr,\nmit Deiner heil\'gen Hand, o Herr, ich bet\',\nlass auf Erden strahl\'n Dein Königreich\ndurch Deine wunderbare Braut!\nNicht durch eine Heldentat,\nnein, werd\' Du Selber in uns groß und stark,\ngib ein mächt\'ges Geisteswehen,\nberühr\' Dein Volk noch einmal, Herr!\r\n'),
(9, '0114', 'Berühr Du mich doch Herr auch dieses Mal  -  Just another Touch Lord from You   (Chorus)', 'Just another touch, Lord, from You,\nto help in hard trials I go through.\nThough dark may be the night,\nYou\'ll send a ray of light,\nwhen I get a touch, Lord, from You.', 'Berühr\' Du mich doch, Herr, auch dieses Mal\nhilf mir in diesem Tale der Qual,\nda dunkel war die Nacht,\nhast Du das Abendlicht gebracht.\nBerühre, Herr, mich auch dieses Mal.'),
(9, '0115', 'Bete den Herrn an in Seiner Gegenwart  -  Worship the Lord in whose Presence we stand', 'Worship the Lord in whose presence we stand.\nHe cares for you and He understands.\nCome, Holy Spirit, and spek to us now:\nGrace, joy and peace and love around.\r\nHe is mighty,\nmighty, mighty,\nmighty is the Lord.\r\nHe is holy,\nholy, holy,\nholy is the Lord.\r\nHe is worthy,\nworthy, worthy,\nworthy is the Lord.\r\nHe is faithful,\nfaithful, faithful,\nfaithful is the Lord.', 'Bete den Herrn an in Seiner Gegenwart.\nEr sorgt für dich, Er ist für dich da.\nKomm, Heil\'ger Geist, verkläre Dein Wort.\nFüll\' uns mit Kraft, Gnad\' und Frieden.\r\nEr ist mächtig,\nmächtig, mächtig,\nmächtig ist der Herr.\r\nEr ist heilig,\nheilig, heilig,\nheilig ist der Herr.\r\nEr ist würdig,\nwürdig, würdig,\nwürdig ist der Herr.\r\nEr ist getreu,\ngetreu, getreu,\ngetreu ist der Herr.'),
(9, '0116', 'Betet den König an, preiset Immanuel  -  All Hail King Jesus, all Hail Emmanuel', 'All hail King Jesus, all hail Emmanuel.\nKing of Kings, Lord of Lords,\nbright morning star.\nAnd throughout eternity\nI\'m going to praise Him,\nand forevermore, I will reign with Him.', 'Betet den König an, preiset Immanuel,\nHöchster Gott, mächtiger Herr,\nheller Morgenstern.\nUnd in alle Ewigkeit\nwollen wir Ihn preisen,\nund wir herrschen mit Ihm jetzt und allezeit.'),
(9, '0117', 'Bethesda ist offen der Engel ist da  -  Bethesda is open, the angel has come   (Die Heilung ist frei, die Heilung ist frei)', 'Bethesda is open, the angel has come,\nthe Spirit is calling for thee.\nThe waters are troubled, behold, there is room,\nsalvation through Jesus is free.\r\nSalvation is free, salvation is free,\nsalvation through Jesus is free.\nThe waters are troubled, behold, there is room,\nbethesda is open for thee.\r\nCome press to the waters while mercy is here,\naccept of a cleansing complete.\nO, hear the entreaty, dismissing your fear.\nLo, judgment and mercy now meet.\r\nThe house of Bethesda for sinners was built,\nthe pool is a fountain of love.\nThe waters are troubled for canceling guilt,\nand still for our healing they move.\r\nThen come to the fountain, ye needy and lost,\ncome now while the Saviour is nigh.\nThis grace has been purchased at infinite cost,\nand the that reject it must die.', 'Bethesda ist offen, der Engel ist da;\nder Geist und die Braut sprechen: "Komm!"\nDas Wasser bewegt sich, das Heil ist dir nah,\nd\'rum auf und hinein in den Strom!\r\nDie Heilung ist frei, die Heilung ist frei,\ndie Heilung in Jesus ist frei!\nDas Wasser bewegt sich, der Engel ist da,\ndie Heilung für dich ist jetzt da.\r\nO, zaud\'re doch nicht vor der schwellenden Flut,\nsie wäscht ja von Sünden dich rein.\nErgreif\' das von Christus erworbene Gut,\nentscheide und sage nicht nein!\r\nDer Born von Bethesda dem Ärmsten auch quillt,\nund allen steht offen Sein Tor.\nHinab, denn dann werden die Schmerzen gestillt,\nund neu steigst du wieder empor.\r\nOh, nütze die Stunde und glaube dem Heil.\nOh, höre, wie Jesus dich fleht!\nDenn folgst du nicht jetzt, dann wird Qual nur dein Teil,\nund ewig wird\'s heißen: "Zu spät!"'),
(9, '0118', 'Bethlehem', 'Overnight a new law was passed\nsending Joseph on a journey, fast\nwhile he felt a little fear inside\nhe knew there had to be a greater reason why\nso with Mary and her child on the way\nhe stepped out in faith and something made him say\r\nGoing back to Bethlehem to the place where it all began\nI know that God will lead us there\nseeking God’s mystery in this place of simplicity\nI know that we will find Him going back to Bethlehem\r\nThese are days of uncertainty\nonly God knows where I need to be\nComplicated minds are torn\ntoo far away from where Jesus can be born\nI desire for God to lead me to the place\nwhere the world can see in me His glorious grace', 'Über Nacht wurde ein neues Gesetz verabschiedet,\ndas Joseph auf eine Reise schickte, schnell\nWährend er innerlich ein wenig Angst verspürte,\nwusste er, dass es dafür einen tieferen Grund geben musste.\nAlso mit der hochschwangeren Maria\nging er im Glauben los und etwas ließ ihn sagen\r\nZurückgehend nach Bethlehem, an den Ort, an dem alles begann,\nweiß ich, dass Gott uns dorthin führen wird\nauf der Suche nach dem Geheimnis Gottes an diesem Ort der Einfachheit\nIch weiß, dass wir ihn finden werden, wenn wir nach Bethlehem zurückkehren\r\nDies sind Tage der Ungewissheit\nnur Gott weiß, wo ich sein muss\nKomplizierte Sinne sind zerrissen\nzu weit weg von dem Ort, an dem Jesus geboren werden kann\nIch wünsche mir von Gott, dass er mich an den Ort führt\nwo die Welt in mir seine herrliche Gnade sehen kann'),
(9, '0119', 'Bethlehem, Bethlehem, du, der Städte Diadem', NULL, 'Bethlehem, Bethlehem,\ndu, der Städte Diadem!\nAus dir sollte Jesus kommen\ndarauf freuten sich die Frommen.\nJauchze laut, Jerusalem!\nBethlehem, Bethlehem!\r\nJesus Christ, Jesus Christ,\nder Du unser Heiland bist!\nDu erscheinst, wie uns verheißen;\ndafür wollen wir Dich preisen,\nwie es Deine Freude ist,\nJesus Christ, Jesus Christ!\r\nGottes Sohn, Gottes Sohn,\nsei gegrüßt auf Deinem Thron!\n"Hosianna" lasst uns singen\nund Dir uns\'re Herzen bringen;\nDu bist unsre Lebenskron\',\nGottes Sohn, Gottes Sohn!'),
(9, '0120', 'Beug die Knie  -  Bow the knee   (Beug die Knie. Trau auf Gott, deinen Vater)', 'There are moments on our journey folloing the Lord,\nwhere God illumines every step we take.\nThere are times when circumstances make perfect sence to us,\nas we try to understand each move He makes.\nWhen the path grows dim and our questions have no answers,\nturn to Him.\r\nBow the knee.\nTrust the heart of your Father  when the answer goes beyond what you can see.\nBow the knee.\nLift your eyes toward heaven and believe the One who holds eternity. And when you don’t understand the purpose of His plan,\nin the Presence of the King, bow the knee.\r\nThere are days when clouds surround us, and the rain begins to fall,\nthe cold and lonely winds don’t cease to blow.\nAnd there seems to be no reason for the suffering we feel,\nwe are tempted to believe God does not know.\nWhen the storms arise, don’t forget we live by faith and not by sight!', 'Manchmal auf der Reise, auf dem schmalen Weg,\nsendet Gott dir Licht für jeden nächsten Schritt.\nUnd es scheint so, als ob alles, was geschieht, verständlich sei,\nund du spürst und siehst es, Gott geht mit dir mit.\nDoch wenn das Licht erlischt, und deine Fragen keine Antwort haben\ngeh\', zu Ihm.\r\nBeug\' die Knie.\nTrau auf Gott, deinen Vater, der die Antwort hat, die du jetzt noch nicht siehst.\nBeugt die Knie.\nSchaue auf zum Himmel und vertraue dem der dich unendlich liebt.\nAuch dann, wenn du nicht verstehst, den Weg den Gott dich führt.\nIn der Gegenwart von Ihm, beug\' die Knie.\r\nEs gibt Tage voller Wolken, an denen Regen auf dich fällt,\nund es scheint, als wär\' ein Ende nicht in Sicht.\nManchmal siehst du keine Gründe, für den Schmerz der dich g\'rad quält,\nund du wirst versucht zu glauben, Gott kümmert\'s nicht!\nWenn der Sturm auch tobt, leb\' im Glauben nicht im Schauen,\nschau auf Gott.'),
(9, '0121', 'Bewahr mich, Herr, von Tag zu Tag  -  Lord, keep my Soul from Day to Day   (Unter dem Blut, dem teuren Blut)   [Pfingstjubel]', 'Lord, keep my soul from day to day,\nunder the blood, under the blood.\nTake doubt and fear and sin away,\nunder the precious blood.\r\nUnder the blood, the precious blood,\nunder the cleansing, healing flood.\nKeep me, Saviour, from day to day,\nunder the precious blood.\r\nThe sinner\'s refuge here alone,\nunder the blood, under the blood.\nHere Jesus makes salvation known,\nunder the precious blood.\r\nSweet peace abides within the heart,\nunder the blood ,under the blood.\nAnd gifts divine their joy impart,\nunder the precious blood.\r\nThe Holy Spirit, hour by hour,\nunder the blood, under the blood.\nExerts His sanctifying power,\nunder the precious blood.', 'Bewahr\' mich, Herr, von Tag zu Tag\nunter dem Blut, unter dem Blut.\nTilg\' Sünde, Furcht und Zweifelsplag\'\nunter dem teuren Blut.\r\nUnter dem Blut, dem teuren Blut,\nunter des vollen Heiles Flut,\nHerr bewahre mich Tag für Tag,\nunter dem teuren Blut.\r\nDes Sünders Ruh\' ist hier allein\nunter dem Blut, unter dem Blut,\ndenn Jesus macht ihn völlig rein\ndurch das teure Blut.\r\nDein süßer Friede strömt in mich\nunter dem Blut, unter dem Blut,\nmein Herz freut Deiner Gaben sich\nunter dem teuren Blut.\r\nDein Geist beweist sich Tag und Nacht\nunter dem Blut, unter dem Blut,\nan mir mit wunderbarer Macht\nunter dem teuren Blut.'),
(9, '0122', 'Bigger than all my Problems   (2 Chorusse)', 'Bigger than all my problems,\nbigger than all my gear,\nGod is bigger than any mountain\nthat I can or cannot see!\r\nBigger than all my questions,\nbigger than anything,\nGod is bigger than any mountain\nthat I can or cannot see!', NULL),
(9, '0123', 'Bin ne neue Schöpfung  -  I\'m a new Creation (Hallelujah He redeemed me)', 'Hallelujah He redeemed me,\nI\'ve been born again to win,\nI thank God He justified me,\nof His fullness have we all received of Him.\r\nI\'m a new creation, I\'m a brand new man.\nOld things are passed away, I\'ve been born again.\nMore than a conqueror, that\'s what I am,\nI\'m a new creation, I\'m a brand new man!\r\nI\'ve received the Christ of Calv\'ry,\nI have no sense of sin.\nWe have a oneness and a fellowship,\ndelivered from authority of sin.\r\nGod has wrought for me redemption,\none that covers ev\'ry need.\nPerfectly He\'s restored our fellowship,\nwith no sense of guilt or memory.', '\r\nBin \'ne neue Schöpfung, bin ein neuer Mensch.\nAlte Dinge sind dahin, ich bin neu gebor\'n.\nMehr als ein Sieger, das ist was ich bin.\nBin \'ne neue Schöpfung, bin ein neuer Mensch.\r\n\r\n'),
(9, '0124', 'Bin nur ein Waffenträger doch folg ich gern   (Hört, hört das Feldgeschrei: Brüder, voran)', NULL, 'Bin nur ein Waffenträger, doch folg\' ich gern\nmeinem geliebten, sieggekrönten Herrn.\nRuft Er zum Kampf Sein Streiterheer heraus,\nfolg\' ich Ihm zur Seite in den blut\'gen Streit.\r\nHört, hört das Feldgeschrei: Brüder, voran!\nWagt euer Alles, nur mutig daran!\nIch folge meinem Feldherrn immerhin,\nob ich auch nur Sein Waffenträger bin!\nIch folge meinem Feldherrn immerhin,\nob ich auch nur Sein Waffenträger bin!\r\nBin nur ein Waffenträger, doch hoch geehrt\ntrag\' ich des Herren Kleid, Helm, Schild und Schwert.\nStill wart ich, bis Sein Ruf er geht an mich,\nstets bereit zur Antwort: Hier, mein Herr, bin ich!\r\nBin nur ein Waffenträger, doch welch ein Lohn\nwinkt mir von ferne von des Königs Thron!\nWenn ich getreu ausharr\' und Ihm vertrau,\nehrt Er herrlich mich einst bei der Heeresschau!'),
(9, '0125', 'Bin so froh, denn Jesus macht\' mich frei  -  I\'m so glad Jesus set me free   (4 Chorusse)', 'I\'m so glad Jesus set me free,\nI\'m so glad Jesus set me free,\nI\'m so glad Jesus set me free,\nSinging, glory, halleluja,\nJesus set me free.\r\nI\'m so glad Jesus lifted me,\nI\'m so glad Jesus lifted me,\nI\'m so glad Jesus lifted me,\nSinging, glory, halleluja,\nJesus set me free.\r\nI\'m so glad Jesus lifted me,\nI\'m so glad Jesus lifted me,\nI\'m so glad Jesus lifted me,\nSinging, glory, halleluja,\nJesus set me free.\r\nSatan had me bound, but Jesus set me free,\nSatan had me bound, but Jesus set me free,\nSatan had me bound, but Jesus set me free,\nSinging, glory, halleluja, Jesus set me free.', 'Bin so froh, denn Jesus macht\' mich frei.\nBin so froh, denn Jesus macht\' mich frei.\nBin so froh, denn Jesus macht\' mich frei.\nSinge Glory Hallelujah, denn Jesus macht\' mich frei.\r\nBin so froh, denn Jesus hob mich auf.\nBin so froh, denn Jesus hob mich auf.\nBin so froh, denn Jesus hob mich auf.\nSinge Glory Hallelujah, denn Jesus hob mich auf.\r\nBringt mich empor auf höheres Niveau.\nBringt mich empor auf höheres Niveau.\nBringt mich empor auf höheres Niveau.\nSinge Glory Hallelujah, auf höheres Niveau.\r\nSatan band mich einst, doch Jesus macht mich frei.\nSatan band mich einst, doch Jesus macht mich frei.\nSatan band mich einst, doch Jesus macht mich frei.\nSinge Glory Hallelujah, durch Jesus wurd\' ich frei.'),
(9, '0126', 'Bin so müde von dem Kämpfen  -  I am tired and weary but I must go along   (Dort in dem Tale des Friedens werd ich dann sein)', 'Well, I\'m tired and weary but I must  go along,\ntill the Lord comes and calls me away.\nWhere the morning is bright and the Lamb is the light\nand the night, nihgt is as fair as the day.\r\nThere\'ll be peace in the valley for me some day.\nThere\'ll be peace in the valley for me oh Lord I pray.\nThere\'ll be no sadness, no sorrow, no trouble I\'ll see.\nThere\'ll be peace in the valley for me.\r\nThere the flow\'rs will be blooming, the grass will be green\nand the skies will be clear and serene.\nWell, the sun ever beames, in this valley of dreams,\nand no clouds there will ever be seen.\r\nWell, the bear will be gentle, and the wolf will be tame,\nand the lion shall lay down by the lamb.\nWell, the beast from the wild shall be led by a little Child.\nAnd I\'ll be changed, changed from this creature that I am.\r\nNo headaches or heartaches or misunderstands\nno confusion or trouble won\'t be.\nNo frowns to defile, just a big endless smile\nthere#ll be peace and contentment for me.', 'Bin so müde von dem Kämpfen aber trotzdem geh ich weiter\nbis der Herr kommt und ruft mich dann zu Sich nach Haus.\nWo der Morgen anbricht, und das Lamm ist das Licht,\nund die Nacht wird vorbei sein für alle Ewigkeit.\r\nDort in dem Tale des Friedens werd\' ich dann sein,\ndort in dem Tale des Friedens, o Herr, bete ich.\nDort wird kein Leid, keine Krankheit, keine Sorge mehr sein.\nDort in dem Tale des Friedens werd\' ich sein.\r\nDort die Blumen nie verblühen und das Gras ist immer grün\nund die Luft rein und sauber klar wie ein Kristall.\nAuch scheint immer die Sonne in dem Land der Freud\' und Wonne,\nkeine Wolke wird jemals dort zu finden sein.\r\nDort das Kind spielt mit dem Löwen, Wolf und Lamm tun sich nichts an,\nfriedlich sind sie beisammen dort in jenem Land.\nJa die Tiere so zahm, Er die Angst völlig nahm!\nAuch ich werd\' ganz verwandelt in jenem Lande sein.\r\nKeine Kopfschmerzen, Herzschmerzen oder Missverständnisse,\nkeine Verwirrung oder Ärger werden dort mehr sein.\nKein Stirnrunzeln, nur ein großes, endloses Lächeln\nwird es Frieden und Zufriedenheit für mich geben.'),
(9, '0127', 'Bin unterwegs nach Kanaan  -  I\'m on my Way to Canaan\'s Land   (2 Chorusse)', 'I\'m on my way to Canaan\'s land,\nI\'m on my way to Canaan\'s land,\nI\'m on my way to Canaan\'s land,\nI\'m on my way, praise God! I\'m on my way.\r\n', 'Bin unterwegs nach Kanaan,\nbin unterwegs nach Kanaan,\nbin unterwegs nach Kanaan.\nbin unterwegs, preis Gott! bin unterwegs!\r\nWenn du nicht willst, halt mich nicht auf,\nwenn du nicht willst, halt mich nicht auf,\nwenn du nicht willst, halt mich nicht auf.\nBin unterwegs, preis Gott! bin unterwegs!'),
(9, '0128', 'Bis du erkennst die Liebeshand (If you could own all the World and its Money)', 'If you could own all the world and its money,\nbuild castels tall enough to reach the sky above,\nif you could know everything\nthere is to know about His name,\nstill you know nothing until you\'ve known\nthe love of God.\r\nUntil you\'ve known the loving hand,\nthat reaches down to fallen man,\nand picks him up from out of sin,\nwhere he has trod.\nUntil you\'ve known just how it feels,\nto know that God is really real,\nthen you know nothing\nuntil you know the love of God.\r\nIf in your life time you could meet everybody\nand you could call every name from here to yon,\nbut till you come face to face with Jesus\nand His saving grace,\nthen you know nothing\nuntil you\'ve known the love of Got.', '\r\nBis du erkennst die Liebeshand,\ndie reicht\' herab, dich Sünder fand\nund hebt dich auf,\nbringt dich auf höheres Niveau.\nBis du erkennst, was du erlebst,\nwenn Gott zeigt wie Er wirklich ist,\nweißt du gar nichts,\nbis du erkennst, Gott liebt dich so.\r\n'),
(9, '0129', 'Bist du bereit wenn Christus erscheint?', NULL, 'Bist du bereit, wenn Christus erscheint?\nEr liebt dich sehr und Er hat dich gemeint,\nals Er für die Welt alle Schuld auf sich nahm.\nChristus kommt bald: Nimm Ihn an!\r\nBist du bereit, wenn Christus erscheint?\nLebe nicht so, als sei Jesus dein Feind.\nSage "Ja" zu Ihm und fang\' jetzt mit Ihm an.\nChristus kommt bald: Nimm Ihn an!\r\nBist du bereit, wenn Christus erscheint?\nDu wirst Ihn seh\'n, hast du Ihn auch verneint\nund nur dich geseh\'n und den eigenen Plan.\nChristus kommt bald: Nimm Ihn an!\r\nBist du bereit, wenn Christus erscheint?\nNoch ruft dich Gott und noch ist Er dein Freund,\ndoch die Zeit rückt vor, der Gerichtstag bricht an.\nChristus kommt bald: Nimm Ihn an!'),
(9, '0130', 'Bist du bereit zu der Stunde, wenn Gott die Seinen heim holt   (Herrlich auf goldenen Straßen)', NULL, 'Bist du bereit zu der Stunde,\nwenn Gott die Seinen heim holt?\nHast du vernommen die Kunde,\nwie Er die Seinen belohnt.\nWenn Er erscheint in den Wolken,\nin Majestät und in Pracht.\nIch kann\'s nicht sagen in Worten,\nmein Herz, es jubelt und lacht.\r\nHerrlich auf goldenen Straßen,\nherrlich im Vaterland,\nwundervoll sind Seine Werke,\nherrlich im weißen Gewand.\r\nKannst du begreifen die Liebe,\ndie Jesus Christus dir weiht?\nBist du mit Ihm dann im Frieden,\nwenn Jesus käme noch heut\'?\nEr hat die Stätte bereitet\nfür die noch wartende Schar,\ndie immer treu für Ihn streitet.\nEs kommt der verheißene Tag.\r\nNichts ist vom Leid mehr geblieben,\nSpott und Hohn sind dann vorbei.\nJesus ich all\'zeit will lieben,\ndies meine Losung soll sein.\nMöchtest du mit in die Heimat,\nwillst Jesus du einmal seh\'n?\nEr nur bringt dich in die schöne Stadt,\ndu brauchst nur zu Jesus zu geh\'n.'),
(9, '0131', 'Bist du fertig, wartest du des Herrn  -  Are you ready, waiting for the Lord   (Ja Du kommst mein Herr und Heiland)', 'Are you ready, waiting for the Lord?\nSee, the signs proclaim Him near,\nin the awful thunders of His word,\nnow His coming steps we hear.\r\nThou art coming, O my Saviour,\nwho can stand Thy flaming light?\nNow the burning of Thy Spirit\nsweeps away the words of night.\nQuickly coming in Thy glory,\nwith Thy bright, angelic train.\nWe shall see Thee in Thy beauty,\nand forever with Thee reign.\r\nNow are many running to and fro,\nspreading holiness around.\nAnd the evening light begins to glow,\nsoon we’ll hear the trumpet’s sound.\r\nHark! the solemn warning unto all,\njudgment’s coming, oh, how soon!\nFlee, o man, at Mercy’s final call,\nheaven trembles at your doom.\r\nAs the lightning flashes east to west,\ncomes the Lord in flaming fire.\nOh, what glory thrills each holy breast!\nSinners melt beneath His ire.\r\nChrist is coming, oh, the heav’nly sight!\nOur Beloved can’t delay,\nfor His bride is robed in snowy white,\nready for that glorious day.', 'Bist du fertig, wartest du des Herrn,\nsieh schon ist er vor der Tür.\nIn dem lauten Donner seines Wort\'s,\nSeine Tritte hören wir.\r\nJa Du kommst mein Herr und Heiland,\nwer kann steh\'n in Deinem Licht.\nJetzt durchs Brennen Deines Geistes\nund Dein Wort hältst Du Gericht.\nBald kommst Du in Deinem Glanze\nmit der ganzen Engelschaar,\nund dann werden Deine Heil\'gen\nmit Dir sein auf immerdar.\r\nViele ziehen jetzt schon hin und her,\npredigen Heiligung im Herrn.\nHell das wahre Licht uns leuchtet nun,\nwie ein heller Morgenstern.\r\nHört die Warnung die an all\' ergeht,\ndas Gericht kommt ohne Fehl.\nDarum harrt der Gnade letzten Ruf\nund errettet eure Seel\'.\r\nWie der Blitz von Ost und Westen fährt,\nkommt der Herr im Flammenlicht.\nWelche Wonne füllt jede heil\'ge Brust.\nSünder schaudern vorm Gericht.\r\nChristus kommet mit des Himmels Heer,\nder Geliebte bald erscheint.\nDann die Braut, die weiß gekleidet ist,\newig wird mit Ihm vereint.'),
(9, '0132', 'Bist du geborgen, o Seele, sag an', NULL, 'Bist du geborgen, o Seele, sag an?\nSag, kennst du den Herrn? Kennst du den Herrn?\nHat dich gefunden der Schmerzensmann?\nSag, kennst du den freundlichen Herr?\nEr ist nah, nah, Jesus ist dir nah!\nEr ist nah, Er ist nah!\nEr ist nah, nah, Jesus ist dir nah!\nO so öffne dein Herz Ihm noch heut\'!\r\nSterbend hat Er dein am Kreuze gedacht.\nSag, hörtest du\'s je? Hörtest du\'s je?\nAls Er dort ausrief: "Vollbracht, ja, vollbracht!"\nSag, Seele, o hörtest du\'s je?\nBlicke hin, hin, blick zum Kreuze hin;\nblicke hin, blicke hin!\nBlicke hin, hin, blick zum Kreuze hin!\nDort ist Heilung für dich, ja, für dich!\r\nSag, hat die Welt dich denn glücklich gemacht?\nO, sag bist du frei? Sag, bist du frei?\nHat sie dir bleibenden Frieden gebracht?\nO sag, bist in Wahrheit du frei?\nKomm noch heut\', heut\', komm zum Kreuz noch heut\'!\nKomm noch heut\', komm noch heut\'!\nKomm noch heut\', heut, komm zum Kreuz noch heut\',\nselig sollst du, o Herz, heut\' noch sein!\r\nFröhlich, so zieh\'n wir vereint dann die Bahn\nmit Ihm unserm Herrn, Ihm unserm Herrn.\nEr führt die Seinen zum Himmel hinan;\nwie herrlich ist\'s hier schon beim Herrn!\nHeiland, sieh, sieh! Sieh der Deinen Schar!\nFühr\' uns heim, führ\' uns heim!\nHeiland, sieh, sieh! Sieh, wir folgen Dir!\nFühr\' uns alle zur Herrlichkeit ein!'),
(9, '0133', 'Bist du traurig, ist dein Herz beschweret  -  Are you weary, are you heavy-hearted   (Sage es Jesus, sage es Jesus, Er ist ein Freund, der dich versteht)', 'Are you weary, are you heavy-hearted?\nTell it to Jesus, Tell it to Jesus.\nAre you grieving over joys departed?\nTell it to Jesus alone.\r\nTell it to Jesus, Tell it to Jesus,\nHe is a friend that\'s well-known.\nYou\'ve no other such a friend or brother,\ntell it to Jesus alone.\r\nDo the tears flow down your cheeks unbidden,\ntell it to Jesus, Tell it to Jesus.\nHave you sins that to men\'s eyes are hidden?\nTell it to Jesus alone.\r\nDo you fear the gath\'ring clouds of sorrow?\nTell it to Jesus, Tell it to Jesus.\nAre you anxious what shall be tomorrow?\nTell it to Jesus alone.\r\nAre you troubled at the thought of dying?\nTell it to Jesus, Tell it to Jesus.\nFor Christ\'s coming Kingdom are you sighing?\nTell it to Jesus alone.', 'Bist du traurig,  ist dein Herz beschweret?\nSage es Jesus, sage es Jesus.\nGrämst du dich, weil dir die Freude schwindet?\nSage es Jesus allein.\r\nSage es Jesus, sage es Jesus,\nEr ist ein Freund, der dich versteht.\nDu hast nirgends solchen Freund und Bruder,\nsage es Jesus allein!\r\nWenn die Tränen unaufhaltsam fließen,\nSage es Jesus, sage es Jesus.\nDrückt dich Sünde, die kein Auge siehet?\nSage es Jesus allein.\r\nFürchtest du die Wolke voller Sorgen?\nSage es Jesus, sage es Jesus.\nFragst du ängstlich, wie es sein wird morgen?\nSage es Jesus allein.\r\nFühlst du Schrecken, wenn du denkst ans Sterben?\nSage es Jesus, sage es Jesus.\nSehnst du dich, Sein Königreich zu erben?\nSage es Jesus allein.'),
(9, '0134', 'Bist du vom Lebenskampf müde und matt   (Ruhe zu Füßen bei Ihm im Gebet)', NULL, 'Bist du vom Lebenskampf müde und matt,\nSorge und Kummer geschlagen dich hat,\ngehe zu Jesus, denn Er dich versteht,\nruhe zu Füßen bei Ihm im Gebet..\r\nRuhe zu Füßen bei Ihm im Gebet,\ndort kannst du rasten, sei\'s früh oder spät.\nDu, find\'st Erquickung, Himmelsluft weht.\nRuhe zu Füßen bei Ihm im Gebet.\r\nBitte um kraft, für den Weg der zu geh\'n,\nbitte um Gnade, den Tag zu besteh\'n,\nkämpfe gerüstet, denn Er mit dir geht.\nRuhe zu Füßen bei Ihm im Gebet.\r\nJesus will Ruhe und Lebensbrot sein!\nTrink von der Quelle des Lebens so rein!\nSünde, Verzweiflung, sie dich versteht,\nruhe bei Ihm im Gebet.'),
(9, '0135', 'Bleibend ist deine Treu, o Gott, mein Vater  -  Great is Thy faithfulness, oh God my Father   (Bleibend ist Deine Treu)', '"Great is Thy faithfulness," oh God my Father,\nthere is no shadow of turning with Thee.\nThou changest not, Thy compassions, they fail not,\nas Thou hast been Thou forever wilt be.\r\nGreat is thy faithfulness! Great is Thy faithfulness!\nMorning by morning new mercies I see.\nAll I have needed Thy hand hath provided,\ngreat is Thy faithfulness, Lord, unto me!\r\nSummer and winter, and springtime and harvest,\nsun, moon and stars in their courses above.\nJoin with all nature in manifold witness,\nto Thy great faithfulness, mercy and love.\r\nPardon for sin and a peace that endureth.\nThy own dear presence to cheer and to guide.\nStrength for today and bright hope for tomorrow,\nblessings all mine, with ten thousand beside!', 'Bleibend ist Deine Treu, o Gott, mein Vater,\nDu kennst nicht Schatten, noch wechselt Dein Licht.\nDu bist derselbe, der Du warst vor Zeiten,\nan Deiner Gnade es niemals gebricht.\r\nBleibend ist Deine Treu, bleibend ist Deine Treu,\nMorgen für Morgen Dein Sorgen ich seh\'.\nAll meinen Mangel hast Du mir gestillet,\nbleibend ist Deine Treu wo ich auch geh.\r\nOb es der Frühling ist, ob Herbst, ob Winter;\nob ich den Sommer seh\' in seiner Pracht.\nDu hast die Welt Dir geschaffen zum Zeugnis,\nDir nur zum Ruhm und zum Preis Deiner Macht.\r\nFrieden und ew\'ges Heil, Freude die Fülle\nfließet auch dir von dem Kreuze her zu.\nGott gibt im Fleische Sein Liebstes für Sünder,\nführet im Opfer die Seinen zur Ruh\'.'),
(9, '0136', 'Blessed be,  blessed be', 'You, oh Lord,  are strong\nAnd mighty tower\nAn ever present help in\nMy darkest hour,\nYou\'re my hiding place,\nYou\'re the ancient of days\nThe rock on which I\'m standing\nYou are worthy of my praise\r\nBlessed be,  blessed be\nBlessed be your name\nBlessed be,  blessed be\nBlessed be your name\r\nYou, oh Lord are the deep that\nI have searched for\nThe ever flowing fountain that\nmy heart always thirsts for\nYou\'re the one who makes me whole\nYou\'re the lover of my soul\nAnd whatever comes my way,\nI know you\'re in control\r\nLet your people proclaim\nYou are holy\nYou are holy God\nAnd we lift up your name\nAnd give glory\nGlory to your name', NULL),
(9, '0137', 'Blessed Redeemer, full of Compassion   (Blessed Redeemer, wonderful Saviour)', 'Blessed Redeemer, full of compassion,\ngreat is Thy mercy, boundless and free.\nNow in my weakness, seeking Thy favour,\nLord, I am coming closer to Thee.\r\nBlessed Redeemer, wonderful Saviour,\nfountain of wisdom, Ancient of Days.\nHope of the faithful, Light of all ages,\nJesus, my Saviour, Thee I will praise.\r\nBlessed Redeemer, Thou art my refuge,\nunder Thy watch-care, safe I shall be.\nGladly adoring, joyfully trusting,\nstill I am coming closer to Thee.\r\nBlessed Redeemer, gracious and tender,\nnew and forever dwell Thou in me.\nThou, my protector, shield and defender,\ndraw me and keep me closer to Thee.', NULL),
(9, '0138', 'Blessing and Honour, Glory and Power   (2 Chorusse)', 'Blessing and Honour\nGlory and Power.\nRiches and Wisdom\nand strength.               2x\r\nBe unto You, unto You\nwho sits at the right hand\nof God                         2x\nunto You.', NULL),
(9, '0139', 'Blessing Honour and Glory to the Lamb   (Chorus)', 'Blessing, honour,\nglory to the Lamb.\nHoly, righteous,\nworthy is the Lamb.\nDeath could not hold Him down,\nfor He is risen.\nSeated upon the throne,\nHe is the Lamb of God.\n-Lamb of God.-', NULL),
(9, '0140', 'Blicke nur auf Jesus, Seele eil Ihm zu  -  Look away to Jesus, Soul by woe oppressed', 'Look away to Jesus, soul by woe oppressed.\n’Twas for thee He suffered: come to Him and rest.\nAll thy griefs He carried, all thy sins He bore.\nLook away to Jesus: trust Him evermore.\r\nLook away to Jesus, soldier in the fight.\nWhen the battle thickens, keep thine armor bright.\nThough thy foes be many, though thy strength be small,\nlook away to Jesus; He shall conquer all.\r\nLook away to Jesus, when the skies are fair.\nCalm seas have their dangers; mariner, beware!\nEarthly joys are fleeting, going as they came,\nlook away to Jesus, evermore the same.\r\nLook away to Jesus, ’mid the toil and heat.\nSoon will come the resting at the Master’s feet.\nFor the guests are bidden, and the feast is spread.\nLook away to Jesus, in His footsteps tread.\r\nWhen, amid the music of the endless feast,\nsaints will sing His praises, thine shall not be least.\nThen, amid the glories of the crystal sea,\nlook away to Jesus, through eternity.', 'Blicke nur auf Jesus, Seele eil\' Ihm zu!\nDer für dich gelitten, gibt dir Fried\' und Ruh\'.\nEr trug deine Schmerzen, alle deine Schuld,\nblicke nur auf Jesus, traue Seiner Huld.\r\nBlicke nur auf Jesus mitten in dem Streit!\nWird der Kampf auch heißer, Hilfe ist bereit.\nIst der Feind gleich mächtig, deine Kraft nur klein,\nblicke nur auf Jesus, Sein Sieg ist auch dein!\r\nBlicke nur auf Jesus, wenn der Himmel hell!\nOft wenn alles ruhig, kommt Versuchung schnell.\nErdenfreuden schwinden wie des Tages Licht,\nblicke nur auf Jesus, Er entweichet nicht!\r\nBlicke nur auf Jesus bei der Arbeit Last!\nDenn zu Seinen Füßen find\'st du süße Rast.\nHorch, Er ruft so gnädig: "Alles ist bereit!"\nBlicke nur auf Jesus, folg\' Ihm allezeit!\r\nEinst wird\'s herrlich klingen dort im Himmelssaal;\ndann wirst du mitsingen bei dem Hochzeitsmahl.\nDoch bei allem Glanze, der dort ist bereit,\nblicke nur auf Jesus bis in Ewigkeit!'),
(9, '0141', 'Bloodline', 'Even though my spirit\'s low, and it seems I can\'t hardly go\nBut still I see victory\nMany times I\'m walking by faith And can\'t see what lies before me\nbut still I see victory.\r\nI just gotta tell you satan, you can\'t cross the bloodline\nBecause I\'m covered by His - blood\nYou may stare and you may fight\nBut you\'re gonna lose this battle tonight\nCause remember you can\'t cross the bloodline.\r\nSometimes our battles get hot\nAnd it seems we\'re fighting alot\nOh I remember, I\'m standing on the rock\nSo satan, if I were you I\'d turn around and give up too\nCause I do believe - you\'re bound to lose.', 'Auch wenn mein Geist niedergeschlagen ist, und es aussieht, als könnte ich kaum weitergehen.\nAber dennoch sehe ich den Sieg.\nHäufig gehe ich im Glauben,\nUnd kann nicht sehen, was vor mir liegt, aber dennoch sehe ich den Sieg.\r\nSatan, ich muss dir einfach sagen, du kannst die Blutlinie nicht durchkreuzen,\nWeil ich durch Sein Blut bedeckt bin.\nDu kannst starren und du kannst kämpfen,\nAber du wirst diesen Kampf heute Abend verlieren.\nDenn, denk dran, du kannst die Blutlinie nicht durchkreuzen.\r\nManchmal werden unsere Schlachten intensiv,\nUnd es scheint, dass wir viel kämpfen.\nAber ich erinnere mich,  ich stehe auf dem Felsen.\nAlso Satan, wenn ich du wäre,\nWürde auch ich mich umdrehen und aufgeben.\nWeil ich glaube, du bist bestimmt zu Verlieren.'),
(9, '0142', 'Born, born, born again, thank God I\'m born again   (Chorus)', 'Born, born, born again,\nthank God I\'m born again.\nBorn, born, born again,\nthank God I\'m born again.\nBorn of the water\nand the Spirit and the blood.\nThank God I\'m born again.\nBorn of the water\nand the Spirit and the blood.\nThank God I\'m born again.', NULL),
(9, '0143', 'Bow\'d beneath your Burden, is there none to share   (Yes He understands, all His ways are best)', 'Bow\'d beneath your burden,\nis there none to share?\nWeary with the journey,\nis there none to care?\nCourage, way-worn trav\'ler,\nheed your Lord\'s commands,\nThere\'s a tho\'t to cheer you,\nJesus understands.\r\nYes He understands,\nall His ways are best.\nHear, He calls to you,\n"come to me and rest."\nLeave the unknown future\nin the Master\'s hand.\nWhether sad or joyful,\nJesus understands.\r\nEv\'ry heavy burden\nHe will gladly share,\nAre you sad and weary?\nJesus has a care;\nWell He knows the pathway\no\'er life\'s burning sands,\nCourage, fainting pilgrim,\nJesus understands.\r\nTho\' temptation meet you,\nJesus can sustain,\nLife has vexing problems\nwhich He can explain;\nServe Him where He sends you\nthough in distant lands,\nDo not doubt or question,\nJesus understands.\r\nWeary heart He calls you,\n"Come to me and rest,"\nDoes the path grow rugged?\nYet His way is best;\nLeave the unknown future\nin the Master\'s hands,\nWhether sad or joyful,\nJesus understands.', NULL),
(9, '0144', 'Brenn, brenn, Heilger Geist, brenn in mir  -  Burn, Holy Spirit, burn in me', 'Burn, burn Holy Spirit, burn in me!\nSet my heart on fire.\nFill me with the Holy Ghost\nLord, that\'s my desire.\nMake me like the Christ of old,\nhealing and raising the dead.\nGive me the power that Jesus had,\ntrough the blood that was shed.', 'Brenn\', brenn\', Heil\'ger Geist, brenn\' in mir!\nSetz\' mein Herz in Flammen!\nFüll\' mich mit der Gotteslieb\'\nund mit heil\'gem Verlangen!\nMach mich wie ein Christ sein soll,\nerfüllt mit heil\'gem Geist!\nGib mir den Glauben, der sehend macht,\nChristus lebend in mir!'),
(9, '0145', 'Brich mir das Lebensbrot, Du großer Herr  -  Break Thou the Bread of Life, dear Lord to me', 'Break Thou the bread of life, dear Lord, to me,\nas Thou didst break the loaves beside the sea.\nBeyond the sacred page I seek Thee, Lord.\nMy spirit pants for Thee, O living Word!\r\nThou art the bread of life, O Lord, to me,\nThy holy Word the truth that saveth me.\nGive me to eat and live with Thee above.\nTeach me to love Thy truth, for Thou art love.\r\nOh, send Thy Spirit, Lord, now unto me,\nthat He may touch my eyes, and make me see:\nShow me the truth concealed within Thy Word,\nand in Thy Book revealed I see the Lord.\r\nBless Thou the truth, dear Lord, to me, to me,\nas Thou didst bless the bread by Galilee.\nThen shall all bondage cease, all fetters fall.\nAnd I shall find my peace, my all in all.', 'Brich mir das Lebensbrot, o lieber Herr,\nwie du das Brot einst brachst am stillen Meer.\nIm Worte such ich Dich, das ist der Ort,\nmein Geist verlangt nach Dir, lebend\'ges Wort.\r\nDu bist ja selber, Herr, das Lebensbrot,\nDein teures Wort mach frei von Sünd\' und Tod.\nDein Licht erleuchte mich von oben her,\ndass ich Dein Wort erfüll\', o Liebesmeer.\r\nO gieße Deinen Geist, Herr, jetzt auf mich,\ndass er mein Aug berühr\', zu sehen dich.\nIm Worte nahst Du mir, doch ich bin blind,\nHerr, offenbare Dich nur Deinem Kind.\r\nLeg deinen Segen doch, Herr auf Dein Wort,\nwie Du das ird\'sche Brot gesegnet dort!\nDie Ketten sprengen dann, und ich werd\' frei,\nund schmeck\' in sel\'ger Lust, was Friede sei.'),
(9, '0146', 'Bring mich höher auf die Berge   (Bring mich höher auf die Berge)', NULL, 'Bring mich höher auf die Berge,\nin Gemeinschaft nur mit Dir.\nIn dem Licht seh\' ich die Quelle,\nund Dein Blut macht rein mich hier.\r\nBring mich höher auf die Berge\nin Gemeinschaft nur mit Dir.\nIn dem Licht seh\' ich die Quelle\nund Dein Blut macht rein schon hier.\r\nBring mich höher auf die Berge,\nDeinem Herzen nah, ganz nah,\ndass ich tu\' stets Deinen Willen\nDir zum Preis, Halleluja!\r\nBring mich höher auf die Berge,\ngib mir, Herr, ein brennend Herz,\nDeine Liebe zu verkünden,\nSeelen retten allerwärts.\r\nBring mich höher auf die Berge,\nauf Dich wartend, Gottes Sohn.\nDir will ich entgegeneilen,\nkomme bald, Herr Jesu, komm.'),
(9, '0147', 'Bring mir die Kunde von Jesus  -  Tell me the story of Jesus', 'Tell me the story of Jesus,\nwrite on my heart every word.\nTell me the story most precious,\nsweetest that ever was heard.\nTell how the angels, in chorus,\nsang as they welcomed His birth,\n"Glory to God in the highest!\nPeace and good tidings to earth."\r\nFasting alone in the desert,\ntell of the days that are past.\nHow for our sins He was tempted,\nyet was triumphant at last.\nTell of the years of His labor,\ntell of the sorrow He bore.\nHe was despised and afflicted,\nhomeless, rejected, and poor.\r\nTell of the cross where they nailed Him,\nwrithing in anguish and pain.\ntell of the grave where they laid Him,\ntell how He liveth again.\nLove in that story so tender,\nclearer than ever I see.\nStay, let me weep while you whisper,\nlove paid the ransom for me.\r\n\r\n', 'Bring mir die Kunde von Jesus,\nschreib auf mein Herz jedes Wort,\nbring mir die Kunde so herrlich\nvon unserm köstlichsten Hort.\nSag mir, wie Engel im Chore\nsangen, als Er uns beschert:\nEhre sei Gott in der Höhe,\nFriede den Menschen auf Erd\'.\r\nSag\'s  wie allein in der Wüste\nJesus versucht ward vom Feind,\nder dort den einsamen Retter\nlistig zu fällen gemeint.\nSprich von den Jahren der Sorge,\nsprich von dem Leid, das Er trug,\nwie man mit Dornen Ihn krönte\nund an das Kreuz Ihn dann schlug.\r\nSag mir von Golgathas Hügel,\nwo Er in Angst war und Pein.\nSprich von dem Grab, das versiegelt,\nund wie Er sprengte den Stein.\nLiebe nur war es in allem,\ndie sich für uns gab dahin,\num zu dem Herzen des Vaters\nalle Verlor\'nen zu zieh\'n.\r\nSag mir von Seiner Verheißung,\ndie sich so herrlich erfüllt,\nals Er die Sehnsucht der Seinen\ndort auf dem Söller gestillt.\nWie Er mit Geist und mit Feuer\ntaufte die wartende Schar,\nwie sie in Zungen Ihn lobte,\nvoll Seiner Herrlichkeit war.\r\nJesus, Du herrlicher Heiland,\nvöll\'ger Erlöser Du bist,\nschaff Dir ein Volk reinen Herzens,\ndas dann geheiligt Dir ist.\nSchaff´s durch die Kraft Deines Blutes,\ntauf\' uns mit Feuer und Geist,\ndass wir in Zungen dich rühmen,\ndass unser Herz Dich lobpreist.'),
(9, '0148', 'Bringt sie herein, denn es ist noch Raum  -  Gather them in, for there yet is Room   (Geht auf die Straßen, sucht in den Gassen)', 'Gather them in, for there yet is room\nat the feast that a King has spread.\nO gather them in, let His house be filled,\nand the hungry and poor be fed.\r\nOut in the highway, out in the by-way,\nout in the dark depths of sin.\nGo forth, go forth with a loving heart,\nand gather the wand\'rers in.\r\nGather them in, for there yet is room,\nbut our hearts, how they throb with pain,\nto think of the many who slight the call,\nthat may never be heard again.\r\nGather them in, for there yet is room,\n\'tis a message from God above.\nO gather them in to the fold of grace,\nand the arms of the Saviour\'s love.', 'Bringt sie herein, denn es ist noch Raum\nin dem glänzenden Königssaal.\nO, bringt sie herein, füllet an das Haus\nzu des Königs Hochzeitsmahl.\r\nGeht auf die Straßen, sucht in den Gassen,\nnötiget alle herein!\nGeht hin, geht hin, tragt die Botschaft aus\nund nötiget sie herein.\r\nBringt sie herein, denn es ist noch Raum!\nJa, wir geh\'n, doch das Herz wird müd\',\ndenn mancher hört wohl, doch sein Herz bleibt kalt,\nweil die Lust dieser Welt ihn zieht.\r\nBringt sie herein, denn es ist noch Raum!\nWir sind Botschafter unser\'s Herrn.\nO, bringt sie herein! Jesus starb für sie,\nund der Vater empfängt sie gern.'),
(9, '0149', 'Bringt sie rein  -  Bring them in, bring them in    &    Segne sie, segne sie  -  Bless them, bless them', 'Bring them in, bring them in,\nbring them in from the fields of sin,\nbring them in, bring them in,\nbring the little ones today to Jesus.\r\nBless them, bless them,\nbless them, bless them!\nJust now in this hour,\ndear Saviour, bless them!\r\n', 'Bringt sie rein, bringt sie rein,\nbringt sie rein vom Land der Sünd\' und Pein.\nBringt sie rein, bringt sie rein,\nbringt die Kleinen heut\' zu Jesus.\r\nSegne sie, segne sie,\nsegne sie segne sie!\nG\'rade jetzt in dieser Stunde,\nlieber Heiland, segne sie!\r\nSegne ihn, segne ihn,\nsegne ihn segne ihn!\nG\'rade jetzt in dieser Stunde,\nlieber Heiland, segne ihn!'),
(9, '0150', 'Bruder, so fern von dem Retter noch heut  -  Brother afar from the Saviour today   (Was hast du dann, was hast du dann)', 'Brother afar from the Saviour today,\nrisking your soul for the things that decay.\nOh, if today God should call it away,\nwhat would you give in exchange for your soul?\r\nWhat would you give? What would you give?\nWhat would you give in exchange for your soul?\nOh, if today God should call it away,\nwhat would you give in exchange for your soul?\r\nMercy is calling you, won’t you give heed?\nMust the dear Saviour still tenderly plead?\nRisk not your soul, it is precious indeed.\nWhat would you give in exchange for your soul?\r\nMore than the silver and gold of the earth,\nmore than all jewels thy spirit is worth!\nGod, the Creator, has given it birth!\nWhat would you give in exchange for your soul?\r\nIf, when you stand at the bar by and by,\nwhen you are weighed in the balance on high,\nyou should be sentenced forever to die!\nWhat would you give in exchange for your soul?', 'Bruder, so fern von dem Retter noch heut\',\nvoll ist dein Leben mit Dingen der Zeit.\nWenn heut\' dein Leben zu Ende hier geht,\nwas hast du dann, was dich noch retten kann?\r\nWas hast du dann, was hast du dann.\nWas hast du dann, was dich noch retten kann?\nWenn heut\' zu Ende dein Leben hier geht,\nwas hast du dann, was dich noch retten kann?\r\nGnade ruft immer noch, achte darauf!\nHör auf den Heiland und änd\'re den Lauf!\nEr hat dich teuer mit Blut doch erkauft,\nwas gibt es denn, was dich sonst retten kann?\r\nMehr als das Silber und Gold dieser Welt,\nals aller Reichtum ist dein Leben wert.\nGott ist\'s allein der zum Leben dich führt,\nEr ganz allein ist\'s, der dich retten kann.\r\nWenn an dem Throne du stehst im Gericht\nund du den Herrn siehst im ewigen Licht,\nund über dich Er das Urteil nur spricht,\nwas hast du dann, was dich noch retten kann?'),
(9, '0151', 'Brüder auf zu dem Werk in dem Dienste des Herrn  -  To the Work, to the Work, we are Servants of God   (Seid getreu, nur getreu, folgt dem Herrn immer gern)', 'To the work! to the work! we are servants of God,\nlet us follow the path that our Master has trod.\nWith the balm of His counsel our strength to renew,\nlet us do with our might what our hands find to do.\r\nToiling on, toiling on,\ntoiling on, toiling on.\nLet us hope, let us watch,\nand labor till the Master comes.\r\nTo the work! to the work! let the hungry be fed,\nTo the fountain of life let the weary be led.\nIn the cross and its banner our glory shall be,\nwhile we herald the tidings, "Salvation is free!"\r\nTo the work! to the work! there is labor for all,\nFor the kingdom of darkness and error shall fall.\nAnd the name of Jehovah exalted shall be\nin the loud swelling chorus, "Salvation is free!"\r\nTo the work! to the work! in the strength of the Lord,\nand a robe and a crown shall our labor reward.\nWhen the home of the faithful our dwelling shall be,\nand we shout with the ransomed, "Salvation is free!"\r\n', 'Brüder, auf zu dem Werk in dem Dienste des Herrn!\nLasst uns geh\'n Seinen Weg, jeder folge Ihm gern!\nIn der göttlichen Kraft, die uns selig erneut,\nlasst uns freudig nur tun, was die Liebe gebeut!\r\nSeid getreu, nur getreu,\nfolgt dem Herrn immer gern!\nNah ist Sieg, nah ist Heil,\nd\'rum wirket, bis der Meister kommt.\r\nAuf die heilige Wacht hat der Herr uns gestellt.\nZeuget froh von dem Heil, das Er brachte der Welt!\nMacht es überall kund, was für Sünder geschah.\nRufet laut allen zu: Die Erlösung ist da!\r\nFrisch voran in dem Werk, denn es gilt Gottes Ehr\'\nin dem Kampf mit der Welt und der Finsternis Heer!\nHier gibt\'s Arbeit für uns, Brüder, lasst sie uns tun.\nDer Getreue wird einst bei dem Herrn ewig ruh\'n.\r\nBrüder, jauchzt, jubiliert, o welch selig Ruh\'\nwinkt in himmlischer Pracht aus der Heimat uns zu!\nSeht, der Herr macht sich auf, gibt den Siegern zum Lohn\nin die Hand eine Palm\', auf das Haupt eine Kron\'!\r\nSucht Verlorene auf, wie der Meister getan.\nDen Verlass\'nen bringt Trost, nehmt der Armen euch an.\nBringet Licht in die Nacht alles Kummers hinein.\nZeigt in Liebe dem Feind, was ein Christ heißt zu sein!'),
(9, '0152', 'Brüder seht die Bundesfahne in den Lüften wehn  -  Ho my comrades, see the signal, wavin in the Sky   (Gott mit uns sei unsre Losung, vorwärts, Gloria)', 'Ho! my comrades, see the signal,\nwaving in the sky!\nReinforcements now appearing,\nvictory is nigh!\r\nHold the fort, for I am coming,”\nJesus signals still.\nWave the answer back to Heaven,\n“by Thy grace we will.”\r\nSee the mighty host advancing,\nSatan leading on.\nMighty men around us falling,\ncourage almost gone.\r\nSee the glorious banner waving,\nhear the bugle blow.\nIn our Leader’s Name we triumph\nover every foe.\r\nFierce and long the battle rages,\nbut our help is near.\nOnward comes our great Commander,\ncheer, my comrades, cheer!', 'Brüder seht die Bundesfahne\nin den Lüften weh\'n.\nNeu belebt sollt ihr die Rechte\nGottes siegen seh\'n.\r\n"Gott mit uns!" sei unsre Losung,\nvorwärts, Gloria.\nSeht, uns winkt die Lebenskrone,\nMut, Halleluja.\r\nSeht des Satans mächt\'ge Heere\nwüten in dem Streit.\nManche sahn wir um uns fallen;\nd\'rum seid kampfbereit.\r\nBlickt auf Jesu Kreuzesbanner,\nhört auf Sein Signal,\ndass ihr bald in Seinem Namen\nsieget überall.\r\n"Seid getreu!" ruft unser Jesus,\n"denn ich komme bald!"\n"Nimm uns Herr, Dir ganz zu eigen",\nsage jung und alt!'),
(9, '0153', 'Burdens now are lighter, brighter is my Way  -  Die Lasten sind nun leichter, heller ist mein Weg', 'Burdens now are lighter brighter is my way,\nit is such a joy to walk with Him.\nWhen this journey here is o’er\nI’ll set my feet on heaven’s shore.\nEternity all joy will just begin.\nOh glory, glory hallelujah.\nPraise the Lord today I know I’m free.\nHe is with me and if I stay close to Him,\nsafe from harm and danger I will be.', 'Die Lasten sind nun leichter, heller ist mein Weg,\nes ist eine solche Freude, mit Ihm zu gehen.\nWenn diese Reise hier zu Ende ist\nsetze ich meine Füße an des Himmels Ufer.\nIn der Ewigkeit wird die ganze Freude erst beginnen.\nOh Herrlichkeit, Herrlichkeit Hallelujah.\nGelobt sei der Herr, heute weiß ich, dass ich frei bin.\nEr ist bei mir und wenn ich in seiner Nähe bleibe\nbin ich sicher vor Schaden und Gefahr.'),
(9, '0154', 'Burn on, burn on, oh Fire of God burn on   (2 Chorusse)', 'Burn on, burn on,\noh fire of God burn on!\nTill all my dross is burned away,\nprepare me for the testing day.\nOh, fire of God burn on!\r\nBurn on, Burn on,\noh, fire of God, burn on!\n\'Til all my soul, Christ\'s image bears,\nHis holy, heavenly nature wears.\nOh, fire of God, burn on!', NULL),
(9, '0155', 'By His Stripes', 'By His Stripes I am healed,\nBy His Wounds I\'m set free,\nBy His Blood I can live,\nFor my Jesus died for me!\r\nHe\'s my Lord, He\'s my King,\nBroke my chains, so I can sing,\nHe\'s my Lord, He\'s my King,\nI will give Him ev\'rything!\r\nI was dead in my sin,\nBut my Christ took me in,\nSet me free from my shame,\nNow I live in Jesus\' Name!', 'Weil man Ihn so sehr schlug,\nWeil Er starb, lebe ich,\nDurch das Leid, das Er trug,\nFand die Gnade Gottes mich!\r\nEr ist Herr, Er macht frei,\nHat die Ketten mir gesprengt,\nEr ist Herr, Er macht neu,\nJesus, meine Seele singt!\r\nIch war tot, ich war leer,\nDoch mein Herr kam zu mir,\nMacht\' mich frei, als Er kam,\nJetzt leb\' ich in Jesu Nam!'),
(9, '0156', 'Cast them in the fire and they\'ll never get burnt   (Chorus)', 'Cast them in the fire and they\'ll never get burnt.\nCast them in the fire and they\'ll never get burnt.\nShadreck, Misheck and Abednego,\ncast them in the fire and they\'ll never get burnt.', NULL),
(9, '0157', 'Center of my Life', 'Seems I have a million things to do\nEverything gets placed in front of you\nBut Lord it\'s not my desire\nTo see it go that way. So I rearrange priorities\nSeeking for your will. Down on my knees\nGiving you the first place. Knowing it\'s your strength\nI can\'t replace\r\nYou are the center\nThe center of my life\nYou\'re the reason why\nI can live more abundantly\nLet there be nothing\nNothing placed before you\nSo I can see you in plain view\nI want to do everything through Christ,\nThe center, the center of my life\r\nWhenever I begin my day with prayer\nYou have never failed\nTo meet me there and all the other things of life\nJust seem to work out right\nMy eyes are fixed on you and you alone\nLord please come and rule\nUpon this throne so that in this life of mine\nI can feel your presence\nAll the time', 'Es scheint, dass ich eine Million Dinge zu tun habe\nAlles wird vor dich gestellt Aber Herr, es ist nicht mein Wunsch\nDass es so weitergeht\nAlso ordne ich die Prioritäten neu Suche nach deinem WillenAuf meinen Knien\nIch gebe dir den ersten Platz Wissend, dass es deine Stärke ist die ich nicht ersetzen kann\r\nDu bist das Zentrum\nDer Mittelpunkt meines Lebens\nDu bist der Grund, warum\nIch kann in Fülle leben\nEs soll nichts geben\nNichts soll vor dir stehen\nDamit ich dich ganz klar sehen kann\nIch will alles tun Durch Christus, das Zentrum meines Lebens\r\nDas Zentrum, das Zentrum meines Lebens\nWann immer ich meinen Tag mit einem Gebet beginne\nDu hast nie versagt\nMich dort zu treffen\nUnd all die anderen Dinge des Lebens\nScheinen einfach richtig zu laufen\nMeine Augen sind auf dich gerichtet\nUnd auf dich allein\nHerr, bitte komm und regiere\nauf diesen Thron\nSo dass ich in meinem Leben\nDeine Gegenwart spüren kann\ndie ganze Zeit'),
(9, '0158', 'Change my Heart oh God - Nimm mein altes Herz (2 Chorusse)', 'Change my heart Oh God\nMake it ever true\nChange my heart Oh God\nmay I be like You (2x)\r\nYou are the Potter, I am the clay.\nMold me and make me, this is what I pray.\nChange my heart Oh God, Make it ever true.\nChange my heart Oh God, may I be like You.', 'Nimm mein altes Herz,\nJesus, aus mir fort,\nschaff ein neues Herz,\nJesus, durch Dein Wort. (2x)\r\nDu bist der Töpfer, der Ton bin ich,\nnimm mich, Herr Jesus, und forme mich.\nNimm mein altes Herz, Jesus, aus mir fort,\nschaff ein neues Herz, Jesus, durch Dein Wort.'),
(9, '0159', 'Christ, the Lord, is ris\'n today, Hallelujah', 'Christ the Lord is ris\'n today,\nHallelujah!\nSons of men and angels say:\nHallelujah!\nRaise your joys and triumphs high,\nHallelujah!\nSing, ye heav\'ns and earth reply,\nHallelujah!\r\nLives again our glorious King:\nHallelujah!\nWhere, Oh death, is now thy sting?\nHallelujah!\nDying once, He all doth save:\nHallelujah!\nWhere thy victory, Oh grave?\nHallelujah!\r\nLove\'s redeeming work is done,\nHallelujah!\nFought the fight, the battle won;\nHallelujah!\nDeath in vain forbids Him rise;\nHallelujah!\nChrist has opened Paradise.\nHallelujah!\r\nSoar we now, where Christ has led,\nHallelujah!\nFoll\'wing our exalted Head;\nHallelujah!\nMade like Him, like Him we rise;\nHallelujah!\nOurs the cross, the grave, the skies.\nHallelujah!', NULL),
(9, '0160', 'Christ, unser Heiland kam; Christ, unser Retter nahm   (O Liebe, wunderreich, was kommt der Liebe gleich)', NULL, 'Christ, unser Heiland, kam; Christ, unser Retter nahm\nauf sich aus Liebeskraft all unser Leid.\nHerz, das in Gram vergeht, Herz, das um Frieden fleht,\nkomm, komm zum Heiland; Er hört dich noch heut\'.\r\nO Liebe, wunderreich! Was kommt der Liebe gleich,\nLiebe, die uns so liebt, dass sie ihr Leben gibt?\nO Liebe, wunderreich ! Nichts kommt der Liebe gleich,\ndie an dem Kreuze ihr Lebensblut gibt.\r\nIn all der Menschen Not, in eine Welt voll Tod\ntrat mit der Allmacht der Liebe ein Held.\nSchlug unsre Ketten ab, sprengte das finst\'re Grab,\nbrachte das ewige Leben der Welt.\r\nChristus, der Gottessohn, stieg von des Vaters Thron,\ngab sich als Opfer zur Tilgung der Schuld.\nNun ruft Er freundlich dich, ladet so inniglich,\nach, widersteh\' nicht der göttlichen Huld.'),
(9, '0161', 'Christus der Retter starb einst am Kreuz  -  Christ our Redeemer died on the Cross   (Denn seh ich das Blut, werde Ich an dir vorüber ziehn)', 'Christ our Redeemer died on the cross,\ndied for the sinner, paid all His due.\nSprinkle your soul with the blood of the lamb,\nand I will pass, will pass over you.\r\nWhen I see the blood,\nwhen I see the blood,\nwhen I see the blood,\nI will pass, I will pass over you.\r\nChiefest of sinners, Jesus willl save,\nall He has promised, that He will do.\nWash in the fountain opened for sin,\nand I will pass, will pass over you.\r\nJudgment is coming, all will be there,\neach one receiving justly his due.\nHide in the saving, sin-cleansing blood,\nand I will pass, will pass over you.\r\nOh, great compassion! O boundless love!\nOh, loving kindness, faithful and true!\nFind peace and shelter under the blood,\nand I will pass, will pass over you.', 'Christus der Retter starb einst am Kreuz,\nstarb für mich Sünder, hat mich erneu\'t.\nLass dich heut\' waschen im heiligen Blut,\ndas dich bewahrt, bewahrt dich so gut.\r\nDenn seh\' ich das Blut,\ndenn seh\' ich das Blut,\nja seh\' Ich das Blut angebracht,\nwerde Ich an dir vorüber zieh\'n.\r\nDen schlimmsten Sünder rettet Er gern,\ndas ist verheißen durch unsern Herrn.\nKomm zu der Quelle und werde rein!\nWasch\' dich im Blut und frei darfst du sein.\r\nAlle gerufen in ein Gericht,\nsehen den Richter, Sein Angesicht.\nBist du verborgen unter dem Blut,\nkannst du dort steh\'n und alles wird gut.\r\nWelch große Liebe, Barmherzigkeit!\nHerrliche Gnade die Er erzeigt.\nheut\' deine Seele im Zufluchtsort!\nEins ist gewiss: Es trägt dich Sein Wort.'),
(9, '0162', 'Christus, die Antwort auf all mein Sehnen  -  Christ is the Answer to all my Longing   (Chorus)', 'Christ is the answer to all my longing,\nChrist is the answer to all I need.\nSaviour, Baptizer, the great Physician,\noh, Hallalujah, He`s all I need.', 'Christus, die Antwort auf all mein Sehnen,\nChristus die Antwort auf meine Not.\nRetter, Erlöser, Er ist mein Heiland,\no Halleluja, Jesus, mein Gott.'),
(9, '0163', 'Come away', 'There`s a table dressed in linnen\nthe banquet is prepared\nA host of angels gathered\nfor the celebration there\nthe bride is almost ready\nin spotless white array\na hush falls over heaven\nas the groom begins to say\r\nCome away my love\ncome away my love\nI`ve waited for this day\nwhen I can give to you My name\neternity awaits us\nCome away my love\r\nI have loved you from creation\nlong before you came to me\nI`ve carried that love with me\nall the way to calvary\nAnd though it wasn`t over\nwhen they laid me in the tomb\nI proved my love would never die\nI rose again for you', 'Dort ist ein Tisch mit Leinen bekleidet\ndas Festmahl ist bereitet\nDie Herrscharen der Engel versammelt\nfür das Fest dort\nDie Braut ist fast fertig\nin fleckenlosem weißen Gewand\nEIne Ruhe erfüllt den Himmel während der Bräutigam spricht:\r\n(Komm hinweg meine Geliebte\nIch habe auf diesen Tag gewartet\nwo Ich dir meinen Namen geben kann\nDie Ewigkeit erwartet uns)\r\nIch habe dich von der Schöpfung an geliebt\nlange bevor du zu mit kamst\nIch trug diese Liebe mit mir\nden ganzen Weg nach Golgatha\nDoch war es nicht vorbei als sie mich ins Grab legten\nI bewies dass meine Liebe niemals stirbt\nIch stand für dich wieder auf'),
(9, '0164', 'Come now is the time to worship', 'Come, now is the time to worship\nCome, now is the time to give your heart\nCome, just as you are to worship\nCome, just as you are before your God\nCome\r\nOne day every tongue will confess You are God\nOne day every knee will bow\nStill the greatest treasure remains for those\nWho gladly choose You now\r\nWillingly we choose to surrender our lives\nWillingly our knees will bow\nWith all our heart, soul, mind and strength\nWe gladly choose You now', NULL),
(9, '0165', 'Consider the Lilies they don\'t toil nor spin   (We have a Heavenly Father above)', 'Consider the lilies, they don’t toil nor spin\nand there’s not a king with more splendor than them.\nConsider the sparrows, they don’t plant nor sow,\nbut they’re fed by the Master who watches them grow.\r\nWe have a Heavenly Father above\nwith eyes so full of mercy and a heart full of love.\nHe really cares when Your head is bowed low.\nConsider the lilies and then you will know.\r\nMay I introduce you to this friend of mine,\nwho hangs out the stars and tells the sun when to shine.\nHe kisses the flowers each morning with dew,\nbut He’s not too busy to care about you.', NULL),
(9, '0166', 'Cover me', 'Peace of God, cover me\nCover me, cover me\nPeace of God, cover me.\nThrough the storm, cover me\r\nOnly in you I am safe\nOnly in you I\'m secure\nOnly in you I find peace\nSo cover me, cover me (2x)\r\nCover me when I am hurting\nCover me when I\'m not strong\nCover me when I am going through\nThe storm!\nCover me when all seems hopeless\nCover me when my faith is gone\nLet the peace that passes all I understand\nCover me, cover me', '(Friede Gottes bedecke mich,  durch den Sturm\nbedecke mich)\r\n(Nur in Dir bin ich sicher\nNur in Dir bin ich in Sicherheit\nNur in Dir finde ich Frieden\nSo bedecke mich)\r\nBedecke mich wenn ich Schmerzen habe\nBedecke mich wenn ich schwach bin\nBedecke mich wenn ich durch den Sturm gehe\nBedecke mich wenn alles hoffnungslos erscheint\nBedecke mich wenn jeder Glaube weg ist\nLass den Frieden der meinen Verstand übersteigt\nmich bedecken'),
(9, '0167', 'Da ist Jubel jeden Tag hier auf meinem Pilgerpfad  -  I\'m rejoicing Night and Day, as I walk the Pilgrim Way   (Nah bei mir, nah bei mir)', 'I\'m rejoicing night and day, as I walk the pilgrim way,\nfor the hand of God in all my life I see,\nand the reason of my bliss, yes, the secret all is this:\nThat the Comforter abides with me.\r\nHe abides, He abides,\nHalleluja, He abides with me.\nI\'m rejoicing night and day,\nas I walk the narrow way.\nFor the Comforter abides with me.\r\nOnce my heart was full of sin,\nonce I had no peace within,\ntill I heard how Jesus died upon the tree.\nThen I fell down at His feet, and there came a peace so sweet.\nNow the Comforter abides with me.\r\nHe is with me everywhere, and He knows my every care.\nI\'m as happy as a bird and just as free;\nfor the Spirit has control, Jesus satisfies my soul,\nsince the Comforter abides with me!\r\nThere\'s no thirsting for the things of the world,\nthey\'ve taken wings, long ago I gave them up.\nAnd instantly all my night was turned to day,\nall my burdens rolled away, now the Comforter abides with me!', 'Da ist Jubel jeden Tag hier auf meinem Pilgerpfad,\nGottes Hand in meinem Leben ich doch seh\'.\nUnd der Grund für meine Freud\', mein Geheimnis, das ist heut\':\nGottes Beistand tief im Herzen nah bei mir.\r\nNah bei mir, nah bei mir,\nHallelujah, Er bleibt nah bei mir!\nMein Herz, es jubelt, weil ich seh\'\nauf dem Weg, auf dem ich geh\',\nbleibt Sein Beistand tief im Herzen nah bei mir.\r\nEinst mein Herz von Sünd\' erfüllt,\nund der Durst war nicht gestillt,\nbis ich hörte, wie mein JESUS für mich starb.\nIch fiel nieder dort vor Ihm, Gnade ließ mich zu Ihm flieh\'n.\nHeut\' darf ich im Frieden meine Straße zieh\'n.\r\nEr ist mit mir überall und weiß Rat in jedem Fall,\nendlich freigemacht in Ihm darf ich jetzt sein!\nHeut\' sitzt Er auf meinem Thron, es regiert der Gottessohn,\nGottes Beistand führt und leitet mich nach Haus.\r\nFern der Lust nach Gut und Geld,\nes zog aus der Fürst der Welt,\nund gebrochen ist die Macht des Feinds in mir.\nEs zog Licht ein in mein Haus und die Dunkelheit zog aus\nNun bleibt Sonnenschein mit mir bei Tag und Nacht.'),
(9, '0168', 'Da war ein junges Mädchen, Maria war ihr Nam\'  -  There was a Girl named Mary back in the Bible Days   (Mir geschehe heut nach Deinem Wort, oh Herr)', 'There was a girl named Mary back in the Bible days,\nshe lived in Nazareth, in such a sinful place,\nbut Mary was a virgin, as pure as she coluld be,\nand when the angel came, she said: "Be it unto me!"\r\nBe it unto me according to Thy Word,\nI want to obey and serve You, my Lord!\nI want to believe and I want to receive\nJesus Christ, the Word of this day!\r\nAnd in this day the Bride was lost and gone in sin,\nbut then came Jesus Christ, He came and took her in,\nredeemed her by the Blood, restored virginity,\nand when He spoke to us, we said: "Be it unto me!"\r\nYes, this was God\'s great purpose: A bride for His Own Son,\nand God\'s Blood purifies and it says: "Never done!"\nAnd when the Word comes to us, it\'s born in you and me,\nyes, when the Master speaketh, we say: "Be it unto me!"', 'Da war ein junges Mädchen, Maria war ihr Nam\',\nsie wohnt\' in Nazareth, der Stadt voll Sünd\' und Schand\'.\nDoch sie war eine Jungfrau, so unschuldig und schön,\nund als der Engel kam, sprach sie: "Es soll so gescheh\'n!"\r\nMir geschehe heut\' nach Deinem Wort, oh Herr!\nIch will Dir gehorchen und dienen immer mehr,\nglauben und empfangen das Wort in dieser Zeit,\nJesus, mach mich dafür bereit!\r\nUnd heute war die Braut in Sünde ganz verlor\'n,\ndoch dann kam sie zum Kreuz und wurde neu gebor\'n,\nund Gottes eig\'nes Blut macht sie unschuldig und schön,\nund wenn sie Sein Wort hört, spricht sie: "Es soll so gescheh\'n!"\r\nJa, heute wird die Welt wie Sodom immer mehr,\ndoch dort gibt\'s eine Braut, und Gott lebt Selbst in ihr.\nUnd wenn Er auf sie schaut, dann kann das Wort Er seh\'n,\nund wenn der Meister spricht, sagen wir: "Es soll gescheh\'n!"'),
(9, '0169', 'Da war niemals so ein Tag wie dieser Tag für mich  -  There\'s never been a Day like this Day to me', 'There\'s never been a day like this day to me.\nThere\'s never been a day like this day I see.\nThere\'s never been a light to shine so bright\nlike this day, this glorious day.\r\nFor Christ is revealing Himself to me.\nHe\'s opened mine eyes and now I can see.\nHis Word is becoming a reality,\nin this day, this glorious day.', 'Da war niemals so ein Tag wie dieser Tag für mich.\nDa war niemals so ein Tag bereitet für mich.\nDa war niemals so ein Licht, das scheint so hell\nan diesem Tag, welch herrlicher Tag.\r\nDenn Christus offenbart sich nun selber mir.\ner öffnet meine Augen, so dass ich nun seh\'.\nSein Wort wird für mich zur Realität\nan diesem Tag, welch herrlicher Tag.'),
(9, '0170', 'Daniel forschte in der Schrift, er war ein Prophet   (Geh doch ins Gebet)', NULL, 'Daniel forschte in der Schrift, er war ein Prophet,\nals er sah, wie spät es ist, da ging er ins Gebet.\nDann hat er den Herrn gesucht und er tat es lang genug,\nbis der Engel kam und sprach in Gottes Nam\'.\r\nGeh doch ins Gebet,\ngeh doch ins Gebet,\nrede doch mit deinem Herrn,\ndenn Er hört Sein Kind so gern,\ngeh doch ins Gebet.\r\nWenn du grad\' durch Nöte gehst, geh doch ins Gebet.\nWenn das Wort du nicht verstehst, dann geh doch ins Gebet.\nWenn dich eine Krankheit quält oder dir die Freude fehlt,\nrufe zu dem Herrn, denn Er hört dich so gern.\r\nBeten kannst du nie genug, geh doch ins Gebet.\nDann merkst du wie gut es tut, ja geh doch ins Gebet.\nGott hat dich mit Blut erkauft und hilft deiner Schwachheit auf,\nEr kommt zu dir und füllt mit Worten dir den Mund.\r\nWenn Sein Wort die Seele trifft, geh doch ins Gebet,\nweil Sein Kommen nahe ist, geh doch ins Gebet,\neins kann nur die Antwort sein: Dass wir uns Ihm viel mehr weih\'n,\ngeben noch mehr Acht, auf das was Er heut\' sprach.'),
(9, '0171', 'Dank Gott ich bin frei  -  Thank God I am free (For a long Time I traveled down a long lonely Road)', 'For a long time I traveled down a long lonely road.\nMy heart was so heavy, in sin I sank low.\nThen I heard about Jesus, what a wonderful hour,\nI\'m so glad that I found out, He could bring me out,\nthrough His saving power.\r\nThank God I am free, free, free, from this world of sin.\nWashed in the blood of Jesus, I`ve been born again.\nHalleluja!\nI`m saved, saved, saved by His wonderful grace,\nI`m so glad that I found out, He could bring me out,\nand show me the way.\r\nLike a bird out of prison, that has taken its flight.\nLike a blind man that God gave back his sight.\nLike a poor wretched beggar, that\'s found fortune and fame.\nI\'m so glad that I found out, He could bring me out,\nthrough His holy Name.', '\r\nDank Gott ich bin frei, frei, frei, frei von der Sünd\' dieser Welt.\nGewaschen im Blute Jesu, geboren auf\'s Neu\'.\nHallelujah!\nIch bin los, los, los, welch\' glorreiche Gnad\'.\nBin so froh dass ich\'s merkte, Er machte mich frei\nund zeigt\' mir den Weg.\r\n'),
(9, '0172', 'Dank sei Dir, was Du mir getan  -  Thank You Lord, for saving my Soul   (2 Chorusse)', 'Thank You Lord, for saving my soul,\nthank You Lord for making me whole.\nThank You Lord, for giving to me,\nThy great salvation so rich and free.\r\nThank You, You have set me free.\nThank You, You have renewed me.\nThank You, You make me ready,\nLord, for Your coming in Eternity.', 'Dank sei Dir, was Du mir getan.\nDank sei Dir, Du nahmest mich an.\nDank sei Dir, Du gabest mir Heil,\nvolle Erlösung ward mir zuteil.\r\nDank sei Dir, Du hast mich befreit.\nDank sei Dir, Du hast mich erneu\'t.\nDank sei Dir, Du machst mich bereit,\nHerr auf Dein Kommen in Ewigkeit.'),
(9, '0173', 'Danke für diesen guten Morgen', NULL, 'Danke für diesen guten Morgen,\ndanke für jeden neuen Tag.\nDanke, dass ich all meine Sorgen auf Dich werfen mag.\r\nDanke für alle guten Freunde,\ndanke, oh Herr, für jedermann.\nDanke, wenn auch dem größten Feinde ich verzeihen kann.\r\nDanke für meine Arbeitsstelle,\ndanke für jedes kleine Glück.\nDanke für alles Frohe, Helle und für die Musik.\r\nDanke für manche Traurigkeiten,\ndanke für jedes gute Wort.\nDanke, dass Deine Hand mich leiten will an jedem Ort.\r\nDanke, dass ich Dein Wort verstehe,\ndanke, dass Deinen Geist Du gibst.\nDanke, dass in der Fern und Nähe Du die Menschen liebst.\r\nDanke, Dein Heil kennt keine Schranken,\ndanke, ich halt mich fest daran.\nDanke, ach Herr, ich will Dir danken, dass ich danken kann.'),
(9, '0174', 'Danke Herr', '(Thank you Lord, that you have rescued me from this world.\nThat you always love me no matter\nwhat. That you draw me to you and give me faith.\nThank you Lord, that you gave me your word and redeemed me,\nthat you give revelation\nthrough your spirit, that you let me see who you really are.)\r\n(Thank you Lord, for every morning that you give me, \nfor your forgiveness again and again, that\nyou have washed me clean through your blood.\nThank you Lord, that you are always there, even when I fail, \nwhen I turn away, you never leave\nme, you show me the way back to you)\r\n(Thank you Lord, that I can be one of your children. \nAnd even when I feel alone, you are always by my side.\nThank you, Lord, that you care for me every day, \nthat you give me gifts to praise and glorify, that)\r\n(I thank you that you chose me. \nYou give me the strength to resist Satan. Come, move into me. \nI want to be yours. I thank you for everything, Lord)\r\n(You went to the cross for my sins. \nOnly you make me one of your children. \nOnly you open myeyes so that I can see.)', 'Danke Herr, dass du mich befreit hast aus dieser Welt.\nDass du mich egal was ist immer liebst.\nDass du mich zu dir ziehst und mir glauben schenkst.\nDanke Herr das du mir dein Wort gabst und mich hast erlöst,\ndass du Offenbarung schenkst\ndurch deinen Geist, dass du mich erkennen lässt wer du wirklich bist.\r\nDanke Herr, für jeden morgen den du mir schenkst, \nfür deine Vergebung immer wieder, \ndass du mich hast rein gewaschen durch dein Blut.\nDanke Herr, dass du immer da bist auch wenn ich versag,\nwenn ich mich abwend du mich\nniemals verlässt, du mir den Weg zeigst, zurück zu dir.\r\nDanke Herr, dass ich darf eins deiner Kinder sein. \nUnd wenn ich mich auch mal alleine fühl, \ndu immer an meiner Seite bist.\nDanke Herr, dass du aufs Neu täglich für mich sorgst, \ndass du gibts mir Gaben zum loben und\npreisen, dass ich Leben darf, zu deiner Ehr.\r\nIch dank dir dass du mich erwählt hast. Du gibts mir die Kraft, \nSatan zu widerstehen. \nKomm zieh in mich ein. Ich möchte dein sein. \nIch dank dir für alles Herr.\r\nDu gingst ans Kreuz für meine Sünden. \nNur du machst mich zu einem deiner Kinder. \nNur du öffnest mir die Augen, damit ich sehen kann.'),
(9, '0175', 'Danke Jesus, Amen  -  Thank You Jesus, Amen   (Chorus)', 'Thank you Jesus, Amen,  (3x)\nO Hallelujah, Amen.', 'Danke Jesus, Amen,  (3x)\nO Halleluja, Amen.'),
(9, '0176', 'Danket dem Herrn, wir danken dem Herrn', NULL, 'Danket dem Herrn!\nWir danken dem Herrn,\ndenn Er ist freundlich,\nund seine Güte währet ewiglich,\nsie währet ewiglich,\nsie währet ewiglich!\r\nLobet den Herrn!\nJa, lobe den Herrn,\nauch meine Seele\nvergiss es nie, was Er Dir Gut\'s getan,\nwas Er Dir Gut\'s getan,\nwas Er Dir Gut\'s getan.\r\nSein ist die Macht!\nAllmächtig ist Gott!\nSein Tun ist weise,\nund Seine Huld ist jeden Morgen neu,\nist jeden Morgen neu,\nist jeden Morgen neu.\r\nGroß ist der Herr,\nja, groß ist der Herr!\nSein Nam\' ist heilig,\nund alle Welt ist Seiner Ehre voll,\nist Seiner Ehre voll,\nist Seiner Ehre voll.\r\nBetet ihn an!\nAnbetung dem Herrn!\nMit hoher Ehrfurcht\nwerd\' auch von uns sein Name stets genannt,\nsein Name stets genannt,\nsein Name stets genannt.\r\nSinget dem Herrn!\nLobsinget dem Herrn\nin frohen Chören;\ndenn Er vernimmt auch unsern Lobgesang,\nauch unsern Lobgesang,\nauch unsern Lobgesang.'),
(9, '0177', 'Dankt dem Herrn mit frohem Mut   (Seine Güt ermüdet nie, ewig, ewig währet sie)', NULL, 'Dankt dem Herrn mit frohem Mut,\nEr ist freundlich, Er ist gut.\r\nSeine Güt\' ermüdet nie,\newig, ewig währet sie.\r\nDankt dem Herrn, gebt Ihm nur Ehr\',\nEr ist aller Herren Herr!\r\nDer, Sein Heil uns zu verleih\'n,\ngroße Wunder tut allein.\r\nDer mit Weisheit, Ordnung, Pracht\nHimmel schuf und an uns dacht\'.\r\nDer Sein Volk durch Wüsten führt\nund doch väterlich regiert.\r\nBringt dem Gott des Himmels Dank;\nschweige nie, mein Lobgesang!'),
(9, '0178', 'Das Blut des Lammes reinigt uns   (2 Chorusse)', NULL, 'Das Blut des Lammes reinigt uns,\ndas Blut des Lammes reinigt uns,\ndas Blut des Lammes reinigt uns und machet alles neu.\nAlles neu, alles neu.\nDas Blut des Lammes reinigt uns und machet alles neu.\r\nDer Heiland starb am Kreuz für mich,\nder Heiland starb am Kreuz für mich,\nder Heiland starb am Kreuz für mich und machte alles neu.\nAlles neu, alles neu.\nDer Heiland starb am Kreuz für mich und machte alles neu.'),
(9, '0179', 'Das Blut, das Jesus für mich vergoss  -  The blood that Jesus shed for me   (Es reicht bis an die höchsten Berge)', 'The blood that Jesus shed for me\nway back on Calvary.\nThe blood that gives me strength, from day to day,\nit will never lose its power.\r\nIt reaches to the highest mountains,\nit flows to the lowest valley.\nThe blood that gives me strength from day to day,\nit will never lose its pow\'r.\r\nIt soothes my doubts and calms my fears\nand it dries all my tears.\nThe blood that gives me strength from day to day,\nit will never lose its power.', 'Das Blut, das Jesus für mich vergoss\ndamals auf Golgatha.\nDas Blut macht rein und stärkt von Tag zu Tag,\nes verliert niemals seine Kraft.\r\nEs reicht bis an die höchsten Berge,\nes fließt in die tiefsten Täler.\nDas Blut macht rein und stärkt von Tag zu Tag,\nes verliert niemals seine Kraft.\r\nEs nimmt die Zweifel und stillt die Angst\nund wischt die Tränen ab.\nDas Blut macht rein und stärkt von Tag zu Tag,\nes verliert niemals seine Kraft.'),
(9, '0180', 'Das Grab ist nun leer  -  The tomb now is empty', 'The tomb now is empty,\nthe stone is rolled away,\nand Christ is alive in my heart.\nAnd death which is conquered\nin me hath no part,\nfor Christ is alive in my heart.\r\nThe seals now are opened,\nthe mysteries revealed,\nand Christ is alive in His bride.\nAnd death which He conquered,\nin her hath no part,\nfor Christ is the live of her heart.', 'Das Grab ist nun leer,\nder Stein hinweg gerollt,\nund Christus, Er lebt nun in mir.\nDer Tod ist überwunden,\nhat keiner Teil an mir,\ndenn Christus, Er lebt nun in mir.\r\nDie Siegel sind geöffnet,\nGeiheimnisse enthüllt,\nund Christus lebt in Seiner Braut.\nDer Tod ist überwunden,\nhat keinen Teil an ihr,\ndenn Christus Er lebt nun in ihr.'),
(9, '0181', 'Das große Erbteil ich bald empfange   (Ja was macht das aus, wenn die Menschen sagen)', NULL, 'Das große Erbteil ich bald empfange,\nwenn auch auf Erden ich nichts bedeut\',\nTrotz schwerer Zeiten, bin ich nicht bange,\nbald holt mich Jesus zur Herrlichkeit.\r\nJa was macht das aus, wenn die Menschen sagen,\ndass wir so arm sind und and\'res mehr?\nWenn wir im Himmel das Erbteil haben,\ndann sind wir mehr als ein Millionär.\r\nWer überwindet, wird alles erben,\nso spricht die Bibel, was will ich mehr?\nWir dürfen leben, wenn wir auch sterben,\nwir haben mehr als ein Millionär.\r\nSolch Glück und Reichtum wir hier schon preisen,\nwer kann uns schätzen, wie reich wir sind?\nDie Lebenskrone ist mir verheißen,\nIch bin durch Christus ein Gotteskind.\r\nAm anderen Strande wir dürfen gehen,\nbefreit vom ird\'schen Spott und Hohn.\nAuf gold\'nen Gassen wir singend stehen,\nvor\'m Lamme dort auf dem Gottesthron.\r\nSo woll\'n wir fröhlich nach Zion eilen,\nWenn auch die Welt uns verachtet sehr,\nund Freud und Leid miteinander teilen,\nWir sind ja mehr als ein Millionär.'),
(9, '0182', 'Das große Los ist mein   (Er macht den Pfad mir lichter)', NULL, 'Das große Los ist mein, vorbei ist Sorg\' und Plag\'\nd\'rum muss ich immer singen froh den ganzen Tag.\nWer kam, mich zu befrei\'n, als ich gefangen lag?\nNur Jesus! Und Ihm sing ich: Gloria.\r\nEr macht den Pfad mir lichter, wo ich geh\' und steh\'.\nDie stärksten Ketten bricht Er und heilet jedes Weh.\nIch traue Seinem Wort, auch wenn ich gar nichts seh\'\nund immer wieder sing\' ich: "Gloria!"\r\nEr löste mir den Mund, dass ich Ihn preisen kann,\nseitdem muss stets singen diesem Wundermann.\nHört Sünder, jetzt zur Stund\' tilgt Jesus Sündenbann,\nd\'rum darf ich froh auch singen: Gloria.\r\nIn Gnaden stellt er mich auf ew\'gen Felsengrund,\nseitdem muss ich Ihm singen, Preis zu aller Stund\'.\nNun glaub ich festiglich, was mir zusagt Sein Mund,\nund immer muss ich singen: Gloria.'),
(9, '0183', 'Das höchste Gut ist Jesus, mein Erlöser  -  What gift of Grace, is Jesus my Redeemer   [Original]', 'What gift of grace is Jesus my redeemer,\nthere is no more for heaven now to give.\nHe is my joy, my righteousness and freedom,\nmy steadfast love, my deep and boundless peace.\nTo this I hold, my hope is only Jesus,\nfor my life is wholly bound to His.\nOh how strange and divine, I can sing: all is mine,\nyet not I, but through Christ in me.\r\nThe night is dark but I am not forsaken,\nfor by my side, the Saviour He will stay.\nI labour on in weakness and rejoicing,\nfor in my need, His power is displayed.\nTo this I hold, my Shepherd will defend me,\nthrough the deepest valley He will lead.\nOh the night has been won, and I shall overcome,\nyet not I, but through Christ in me.\r\nNo fate I dread, I know I am forgiven,\nthe future sure, the price it has been paid.\nFor Jesus bled and suffered for my pardon,\nand He was raised, to overthrow the grave.\nTo this I hold, my sin has been defeated,\nJesus now and ever is my plea.\nOh the chains are released, I can sing: "I am free"\nyet not I, but through Christ in me.\r\nWith every breath, I long to follow Jesus,\nfor He has said, that He will bring me home.\nAnd day by day, I know He will renew me,\nuntil I stand, with joy before the throne.\nTo this I hold, my hope is only Jesus,\nall the glory evermore to Him.\nWhen the race is complete, still my lips shall repeat,\nyet not I, but through Christ in me.\r\nTo this I hold, my hope is only Jesus,\nall the glory evermore to Him.\nWhen my race is complete, still my lips shall repeat,\nyet not I, but through Christ in me.\nWhen the race is complete, still my lips shall repeat,\nyet not I, but through Christ in me,\nyet not I, but through Christ in me,\nyet not I, but through Christ in me.', 'Das höchste Gut ist Jesus, mein Erlöser,\nes gibt nichts mehr, was Gott mir schenken kann.\nEr, meine Freud\', Gerechtigkeit und Freiheit,\nLiebe so treu, mein Frieden grenzenlos.\nIch bin gewiss: Der Herr ist meine Hoffnung,\nfest verbunden bin ich nun mit Ihm.\nIch bin Sein, Er ist mein, wir sind ewig vereint,\nnicht durch mich, nur durch Christus in mir.\r\nDie Nacht bricht an, doch ich bin nicht verlassen,\nan meiner Seite ist und bleibt der Herr.\nIch schau auf Ihn, in Schwachheit und in Freude,\ndenn Seine Kraft zeigt sich in meiner Not.\nIch bin gewiss: Meine Hirte wird mich schützen,\ndurch das Tal des Todes führt Er mich.\nJa, die Nacht ist besiegt und die Sorge verfliegt,\nnicht durch mich, nur durch Christus in mir.\r\nIch fürchte nichts. Ich weiß: mir ist vergeben,\ndie Zukunft fest, das Lösegeld bezahlt.\nDurch Jesu Blut und Leid bin ich begnadigt,\nder Tod besiegt, weil Jesus auferstand.\nIch bin gewiss: Besiegt bleibt meine Sünde,\ndenn mein Herr steht ewig für mich ein.\nVon den Ketten befreit sing ich jetzt: Ich bin frei,\nnicht durch mich, nur durch Christus in mir.\r\nNun folg\' ich Ihm im Leben und im Sterben,\ndenn Er versprach, dass Er nach Haus\' mich bringt.\nJa, Tag für Tag wird Jesus mich erneuern,\nbis ich voll Freude steh vor seinem Thron.\nIch bin gewiss: Der Herr ist meine Hoffnung,\naller Dank und Ehre sei nur Ihm!\nIst mein Lauf dann vollbracht, bleibt mein Lied immer noch:\nNicht durch mich, nur durch Christus in mir.\r\nIch bin gewiss: Der Herr ist meine Hoffnung,\naller Dank und Ehre sei nur Ihm!\nIst mein Lauf dann vollbracht, bleibt mein Lied immer noch:\nNicht durch mich, nur durch Christus in mir.\nIst mein Lauf dann vollbracht, bleibt mein Lied immer noch:\nNicht durch mich, nur durch Christus in mir,\nnicht durch mich, nur durch Christus in mir,\nnicht durch mich, nur durch Christus in mir.'),
(9, '0184', 'Das Höchste meines Lebens ist  -  The greatest thing in all my Life', 'The greatest thing in all my life, is knowing You.\nThe greatest thing in all my life, is knowing You.\nTo know You more and more.\nTo know You more and more.\nThe greatest thing in all my life, is knowing You.\r\nThe greatest thing in all my life, is loving You.\nThe greatest thing in all my life, is loving You.\nTo love You more and more.\nTo love You more and more.\nThe greatest thing in all my life, is loving You.\r\nThe greatest thing in all my life, is serving You.\nThe greatest thing in all my life, is serving You.\nTo serve You more and more.\nTo serve You more and more.\nThe greatest thing in all my life, is serving You.', 'Das Höchste meines Lebens ist, Dich kennen, Herr!\nDas Höchste meines Lebens ist, Dich kennen, Herr!\nDich kennen mehr und mehr.\nDich kennen mehr und mehr.\nDas Höchste meines Lebens ist, Dich kennen, Herr!\r\nDas Höchste meines Lebens ist, Dich lieben, Herr!\nDas Höchste meines Lebens ist, Dich lieben, Herr!\nDich lieben mehr und mehr.\nDich lieben mehr und mehr.\nDas Höchste meines Lebens ist, Dich lieben, Herr!\r\nDas Höchste meines Lebens ist, Dir dienen, Herr!\nDas Höchste meines Lebens ist, Dir dienen, Herr!\nDir dienen mehr und mehr.\nDir dienen mehr und mehr.\nDas Höchste meines Lebens ist, Dir dienen, Herr!'),
(9, '0185', 'Das Jahr ist nun zu Ende, doch, Herr, Dein Lieben nicht', NULL, 'Das Jahr ist nun zu Ende,\ndoch, Herr, Dein Lieben nicht;\nnoch segnen Deine Hände,\nnoch scheint Dein Gnadenlicht!\r\nDes Glückes Säulen wanken,\nder Erde Gut zerstäubt,\ndie alten Freunde wanken,\ndoch Deine Liebe bleibt!\r\nDer Jugend Reiz vergehet,\ndes Mannes Kraft wird matt,\ndoch innerlich bestehet,\nwer Dich zum Freunde hat.\r\nMein Tag ist hingeschwunden,\nmein Abend bricht herein;\ndoch weil ich Dich gefunden,\nso kann ich fröhlich sein!\r\nDas Dunkel ist gelichtet,\ndas auf dem Grabe liegt;\ndas Kreuz ist aufgerichtet,\nan dem Du hast gesiegt.\r\nDu heilst der Sünden Schaden,\nhilfst mir aus der Gefahr\nund siehst mich an in Gnaden\nauch in dem neuen Jahr.'),
(9, '0186', 'Das Kreuz an dem Jesus einst starb  -  The Cross upon which Jesus died   (Am Kreuze ist Raum für dich)', 'The cross upon which Jesus died,\nis a shelter in which we can hide.\nAnd its grace so free is sufficient for me,\nand deep is its fountain, as wide as the sea.\r\nThere\'s room at the cross for you,\nthere\'s room at the cross for you.\nThough millions have come,\nthere\'s still room for one.\nYes, there\'s room at the cross for you.\r\nThough millions have found Him a friend\nand hav turned from the sins they have sinned,\nthe Saviour still waits to open the gates,\nand welcom a sinner before it\'s too late.\r\nThe hand of my saviour is strong\nand the love of my saviour is long,\nthrough sunshine or rain, throgh loss or in gain,\nthe blood flows from Calv\'ry to cleanse every stain.', 'Das Kreuz, an dem Jesus einst starb,\nwo er völliges Heil uns erwarb,\nsteht noch immer dort als ein heil\'ger Ort,\nals Stätte des Friedens, als sicherer Hort.\r\nAm Kreuze ist Raum für dich!\nAm Kreuze ist Raum für dich!\nSchon wurde das Heil Millionen zuteil.\nDoch ist Raum an dem Kreuz für dich.\r\nNoch immer strömt Leben und Kraft,\nwird Heilung und Heil uns verschafft.\nAn dem Kreuze, wo er für uns litt so sehr,\nkannst Gnade du finden so tief wie das Meer.\r\nBald kommt er vom Himmel mit Macht,\nbekleidet mit Ehre und Pracht.\nO wie werden wir singen: Ehre dem Lamm,\ndas herrlich gesiegt hat am Kreuzesstamm!'),
(9, '0187', 'Das Kreuz fordert Opfer, denn an ihm wird das Herz von sich entleert   (Bist du wirklich bereit für den Weg an das Kreuz)', NULL, 'Das Kreuz fordert Opfer, denn an ihm\nwird das Herz von sich entleert\nund legt auf den Altar still sein Leben hin,\nwo Feuer es verzehrt.\r\nBist du wirklich bereit für den Weg an das Kreuz?\nLass die Furcht, lass die Scheu, und die Angst,\nüberlass\' dich nur Gott, Er räumt hinweg,\nwovor du dich jetzt noch bangt.\r\nWie schnell, ach wie schnell sagt man das Wort:\n"Ja, ich gebe mich jetzt ganz!"\nWenn es dann aber heißt in die Tiefen gehen,\nwo ist des Kreuzes Glanz?\r\nWillst du nun noch ängstlich rückwärts schaun?\nAch nein, nimm Sein Kreuz auf dich\nund versuche Ihm blind, aber ganz zu traun.\nEr reinigt dich für Sich.\r\nDer Plan, den der Herr für dich gemacht,\nheißt: mit Ihm gekreuzigt sein,\ndass Sein Leben durch dich Er hier leben kann,\nIhm, Ihm zum Ruhm allein.'),
(9, '0188', 'Das Kreuz überwiegt nicht die Gnade  -  The Cross that He gave may be heavy   (Das Kreuz ist nicht größer als die Gnad)', 'The cross that He gave may be heavy,\nbut it ne’er outweighs His grace.\nThe storm that I feared may surround me,\nbut it ne’er excludes His face.\r\nThe cross is not greater than His grace,\nthe storm cannot hide His blessed face.\nI am satisfied to know,\nthat with Jesus here below,\nI can conquer ev\'ry foe.\r\nThe thorns in my path are not sharper\nthan composed His crown for me.\nThe cup which I drink not more bitter\nthan He drank in Gethsemane.\r\nThe light of His love shineth brighter,\nas it falls on paths of woe.\nThe toil of my work groweth lighter,\nas I stoop to raise the low.\r\nHis will I have joy in fulfilling,\nas I\'m walking in His sight.\nMy all to the blood I am bringing,\nit alone can keep me right.', 'Das Kreuz überwiegt nicht die Gnade,\nauch wenn’s drückt und mich abschreckt.\nDer Sturm, den ich fürcht\', mich umzingelt,\ndoch Sein Antlitz nie verdeckt.\r\nDas Kreuz ist nicht größer als die Gnad\',\ntrotz Sturm seh\' Sein Antlitz auf dem Pfad.\nBin zufrieden, dass ich weiß,\nJesus hilft auf meiner Reis\',\nÜberwind, empfang\' den Preis.\r\nMein Pfad ist trotz Dornen erträglich,\nSeine Krone tat mehr weh.\nDer Kelch, den ich trink, ist nicht bitt\'rer\nals Er trank in Gethsemane.\r\nDas Licht Seiner Liebe scheint heller,\nwenn’s im Leid erhellt die Sicht.\nDie Last meiner Arbeit wird leichter,\nwenn ich den, der fiel, aufricht\'.\r\nHab\' Freude zu tun Seinen Willen,\ndenn Sein Angesicht schau ich.\nDie Trübsal mehr Segen wird bringen,\ndoch in ihr freut Christus mich.'),
(9, '0189', 'Das Kreuz, es stehet fest  -  The Cross it standeth fast   (Halleluja rühmt das Kreuz)', 'The cross it standeth fast,\nHallelujah, hallelujah!\nDefying ev\'ry blast,\nHallelujah, hallelujah!\nThe winds of hell have blown,\nthe world its hate hath shown.\nYet it is not overthrown -\nHallelujah for the cross!\r\nHallelujah, hallelujah,\nhallelujah for the cross.\nHallelujah, hallelujah,\nit shall never suffer loss!\r\nIt is the old cross still,\nHallelujah, hallelujah!\nIts triumph let us tell,\nHallelujah, hallelujah!\nThe grace of God here shone,\nthru Christ, the blessed Son,\nwho did for sin atone,\nHallelujah for the cross!\r\n\'Twas here the debt was paid,\nHallelujah, hallelujah!\nOur sins on Jesus laid,\nHallelujah, hallelujah!\nSo round the cross we sing,\nof Christ, our offering,\nof Christ, our living King,\nHallelujah for the cross!', 'Das Kreuz, es stehet fest,\nHalleluja! Halleluja!\nWie wild der Sturm auch bläst,\nHalleluja! Halleluja!\nDie Höll\' erhebt ihr Haupt,\nes droht die Welt und schnaubt.\nDas Kreuz uns keiner raubt,\nHalleluja, rühmt das Kreuz!\r\nHalleluja, Halleluja,\nHalleluja rühmt das Kreuz.\nHalleluja, Halleluja,\newig steht uns fest das Kreuz.\r\nDas alte Kreuz ist\'s noch,\nHalleluja! Halleluja!\nEs triumphieret doch,\nHalleluja! Halleluja!\nAm Kreuze ward vollbracht,\nwas Gott aus Lieb erdacht,\nwas Sünder selig macht,\nHalleluja, rühmt das Kreuz!\r\nO rühmt des Kreuzes Kraft,\nHalleluja! Halleluja!\nDie neue Menschen schafft,\nHalleluja! Halleluja!\nDas Kreuz ist unsre Zier,\nist unser Kriegspanier,\nim Kreuze siegen wir,\nHalleluja, rühmt das Kreuz!'),
(9, '0190', 'Das Öl der Freude hat der Herr gegossen auf mein Haupt   (Heilige Salbung, bleibe auf mir ruhn)', NULL, 'Das Öl der Freude hat der Herr\ngegossen auf mein Haupt!\nWo kam mir dieser Segen her?\nIch hab Sein Wort geglaubt!\r\nHeilige Salbung, bleibe auf mir ruh\'n;\nGöttlicher Tröster, leite all mein Tun!\r\nIch ahnte nicht, dass mir so nah\ndies wunderbare Heil,\nbis dass ich kam nach Golgatha;\nda ward es mir zuteil!\r\nIch hielt noch dies und jenes fest,\nbetrübte meinen Herrn:\nNur wenn die Seele alles lässt,\nerscheint der Morgenstern!\r\nDie Räder meines Seins, die nie\nsonst wollten richtig geh\'n,\nin friedevoller Harmonie\nnun Nacht und Tag sich dreh\'n.\r\nO teurer, werter Himmelsgast,\nDu Heil\'ger Gottesgeist:\nHalt nun auf ewig in mir Rast,\nwie\'s Jesus uns verheißt.\r\nDu Geist der Wahrheit, leite mich\nin alle Wahrheit nun!\nLass mich, ich bitt\' Dich inniglich,\nall\'zeit in Christo ruh\'n!\r\nVerkläre meinen Heiland mir\nim tiefsten Herzensgrund,\nso will ich all\'zeit danken Dir\nmit Herz und Hand und Mund.'),
(9, '0191', 'Das Wort es wirkt jetzt mächtig auch in mir  -  The Word is working mightily in me', 'The Word is working mightily in me.\nThe Word is working mightily in me.\nNo matter what the circumstance or what I feel or see.\nThe Word is working mightily in me.\r\nThe Word is working mightily in you.\nThe Word is working mightily in you.\nNo matter what the circumstance, or what I feel or see.\nThe Word is working mightily in you.\r\nThe Word is working mightily in us.\nThe Word is working mightily in us.\nNo matter what the circumstance, or what I feel or see.\nThe Word is working mightily in us.', 'Das Wort es wirkt jetzt mächtig auch in mir.\nDas Wort es wirkt jetzt mächtig auch in mir.\nEgal wie auch der Umstand ist und was ich fühl\' und seh\'.\nDas Wort es wirkt jetzt mächtig auch in mir.\r\nDas Wort es wirkt jetzt mächtig auch in dir.\nDas Wort es wirkt jetzt mächtig auch in dir.\nEgal wie auch der Umstand ist und was ich fühl\' und seh\'.\nDas Wort es wirkt jetzt mächtig auch in dir.\r\nDas Wort es wirkt jetzt mächtig auch in uns.\nDas Wort es wirkt jetzt mächtig auch in uns.\nEgal wie auch der Umstand ist und was ich fühl\' und seh\'.\nDas Wort es wirkt jetzt mächtig auch in uns.'),
(9, '0192', 'Dass Gott in Lieb\' an mich den Sünder dacht\'  -  That God should love a Sinner such as I   (O Liebe wunderbar, o Liebe wunderbar)', 'That God should love a sinner such as I,\nshould yearn to change my sorrow into bliss.\nNor rest till He had planned to bring me nigh,\nhow wonderful is love like this!\r\nSuch love, such wondrous love,\nSuch love, such wondrous love,\nThat God should love a sinner such as I,\nhow wonderful is love like this!\r\nThat Christ should join so freely in the scheme,\nalthough it meant His death on Calvary.\nDid ever human tongue Find nobler theme,\nthan love divine that ransomed me?\r\nThat for a wilful outcast such as I,\nThe Father planned, the Saviour bled and died;\nRedemption for a worthless slave to buy,\nWho long had law and grace defied.\r\nAnd now He takes me to His heart, a son,\nHe asks me not to fill a servant\'s place.\nThe "far-off country" wand\'rings all are done,\nwide open are His arms of grace.', 'Das Gott in Lieb\' an mich den Sünder dacht\',\nverwandelt alles Leid in Wonne hier.\nEr ruhte nicht, bis Er mich zu sich bracht\'!\nWelch wunderbare Lieb\' zu mir!\r\nO Liebe wunderbar, o Liebe wunderbar,\ndie mich geliebt in meiner Sündennot!\nO welche Liebe wunderbar!\r\nDas Christus willig Mensch für mich einst war,\nobgleich es brachte Ihm nur Tod und Leid,\nist unaussprechlich und ganz wunderbar.\nWelch große Lieb\' hat mich befreit.\r\nDer Vater gab den Heiland in den Tod für mich,\nden Sklaven, der Ihm unterstand.\nUm mich zu retten aus der Sündennot,\nreicht Er in Liebe mir die Hand.\r\nDas Vaterhaus ist weit geöffnet schon,\nnicht länger soll ich sein der Sünde Knecht.\nEr zieht mich an Sein Herz als Kind und Sohn.\nIn Liebe bringt er mich zurecht.'),
(9, '0193', 'Dein Wort ist der Fels', 'Your word is the rock on which I stand. You give me strength to walk your path. Your word is the rock on which I stand. You give me strength.\r\nYou gave me your word to follow you. Everything I need to walk the right path is in your word. All you want from me is to love and honor you as it is written.\r\nWhen I have taken a wrong turn on the path. I am your child. You will not let me down. You will lead me back to the right path and show me how I can live faithfully according to your word.\r\nEven through hard times you lead me through, trusting you is all I need, you have a way for me that is often not easy, but I have to go through it so that you can work in me.', 'Dein Wort ist der Fels auf dem steh. Du gibts mir Kraft, deinen Weg zu gehn. Dein Wort ist der Fels auf dem ich steh. Du gibts mir Kraft\r\nUm dir nachzufolgen gabst du mir dein Wort. Alles was ich brauch um den rechten Weg zu gehen, steht in deinem Wort. Alles was du von mir willst, ist dich zu lieben und zu ehren, sowie es geschrieben ist.\r\nWenn ich auf dem Weg falsch abgebogen bin. Ich bin dein Kind. Du lässt mich nicht im Stich. Du führst mich auf den rechten Weg zurück und zeigst mir wie ich treu leben kann nach deinem Wort.\r\nAuch durch harte Zeiten führst du mich hindurch, dir zu vertrauen ist alles was ich brauch du hast einen Weg für mich der ist oft nicht leicht, doch ich muss  hindurch, damit du in mir wirken kannst.'),
(9, '0194', 'Dein Wort ist meines Fußes Leuchte', NULL, '||: Dein Wort\nIst meines Fußes Leuchte\nund ein Licht\nauf dem Weg. :||\r\n||: Es leitet mich auf\nallen meinen Wegen.\nDein Wort, es leitet mich. :||\r\n||: Und nichts kann\nmich irreführen.\nDein Wort, es leitet mich. :||\r\n||: Es leitet mich heim\nbis zum Himmel.\nDein Wort, es leitet mich! :||'),
(9, '0195', 'Dein Wort, o Herr, ich hört es heut   (Chorus)', NULL, 'Dein Wort, o Herr, ich hört\' es heut\'.\nMein Herz beglückt Dich heute preist.\nIch hört\' Dein Wort und dürste nach mehr.\nVon Deinem Wort, Herr, möcht\' ich mehr.'),
(9, '0196', 'Deine Gemeinde betet Dich an   (Chorus)', NULL, 'Deine Gemeinde betet Dich an\nfür das, was Du, Herr, an ihr getan;\nhast sie geliebt, erkauft und geweiht.\nEhre Dir, Jesus und Herrlichkeit!'),
(9, '0197', 'Deine Liebe', NULL, 'Jesus, Dein Herz ist offen für uns,\nJesus, darum sind wir heute hier,\nJesus, Du zeigst uns heut\' Deinen Plan,\nJesus, der nur aus Liebe besteht!\r\nDeine Liebe (3x) ist so groß,\nDeine Liebe (3x) macht uns\nvon uns selber los!\r\nJesus, wie oft hab\' ich schon gedacht,\nJesus, dass Gott sich aus mir nichts macht,\nJesus, jetzt schaue ich himmelwärts, (denn)\nJesus, Du selber bist Gottes Herz!'),
(9, '0198', 'Deine Liebe sieht mich anders', NULL, 'Herr, wie oft enttäusch\' ich mich,\nHab\'s wieder nicht geschafft,\nDoch dann kommt Dein Wort zu mir\nUnd gibt mir neue Kraft,\nHerr, Du weißt eh alles schon,\nDann befreist du mich davon...\r\nDenn deine Liebe sieht mich anders,\nDeine Gnade macht mich frei,\nUnd ich muss nicht mehr\nDer Mensch sein, der ich war,\nDeine Liebe sieht mich anders,\nDeine Gnade macht mich neu,\nHerr, ich glaube an\nDie Kraft von Golgatha!\r\nDu bist Gott, der alles kennt -\nEin gutes Argument...\nAlles, was ich denk\' und tu\',\nWeißt Du schon sowieso,\nDoch Du schaust mich anders an,\nDu hast für mich einen Plan...\r\nHerr, Du änderst meinen Blick,\nIch müh\' mich nicht mehr ab,\nAll das alte, was ich war,\nGing längst mit dir ins Grab,\nDas, was man bei dir loslässt,\nDas hält einen nicht mehr fest...\r\nBridge\nHerr, Du hast mich\nSchon lang\' erwählt,\nIch gehe nicht\nDen Weg der Welt,\nDu änderst mich,\nHerr, in Dein Bild,\nIch darf ein Sieger sein,\nJesus, in Dir allein!'),
(9, '0199', 'Deinen Königsthron und die Ehrenkron\'  -  Thou didst leave Thy Throne and Thy kingly Crown   (O komm in mein Herz, Herr Jesus)', 'Thou didst leave Thy throne and Thy kingly crown,\nwhen Thou camest to earth for me.\nBut in Bethlehem\'s home was there found no room\nfor Thy holy nativity.\r\nO come to my heart, Lord Jesus,\nthere is room in my heart for Thee.\r\nHeaven\'s arches rang when the angels sang,\nproclaiming Thy royal degree.\nBut of lowly birth didst Thou come to earth,\nand in great humility.\r\nThe foxes found rest, and the birds their nest\nin the shade of the forest tree.\nBut Thy couch was the sod, O Thou Son of God,\nin the deserts of Galilee.\r\nThou camest, O Lord, with the living word\nthat should set Thy people free.\nBut with mocking scorn, and with crown of thorn,\nthey bore Thee to Calvary.\r\nWhen the heavens shall ring, and the angels sing,\nat Thy coming to victory.\nLet Thy voice call me home, saying "Yet there is room,\nthere is room at My side for thee."\r\nMy heart shall rejoice, Lord Jesus,\nwhen Thou comest and callest for me.', 'Deinen Königsthron und die Ehrenkron’,\nließest Du, kamst zu uns herab;\ndoch findet kaum man in Bethlehem\nRaum für die ewige Liebesgab\'!\r\nO komm in mein Herz, Herr Jesus!\nDa ist Raum, da ist Raum für Dich!\r\nEngellobgesang auf der Erd’ erklang:\nEhre sei nun Gott in der Höh\'!\nDoch in Niedrigkeit, zu dem Werk bereit,\nnahmst Du auf Dich der Menschen Weh\'.\r\nJedes Vögellein hat sein Nestchen\nfein auf dem Feld oder auf dem Baum;\ndoch die Erde hart Dir zum Lager ward,\ndenn Du fandest sonst keinen Raum.\r\nMit der Wahrheit Wort, Herr, von Ort zu Ort\nbringst dem Volk Du den Frieden nah;\ndoch mit Spott und Hohn und der Dornenkron\nführt man hin Dich nach Golgatha.\r\nEinst Dein Lob erschall, dass es widerhallt,\nwenn Du kommest in Deiner Macht;\no zu mir dann sprich: Es ist Raum für dich,\nkomm herein, der Du treu gewacht!\r\nMein Herz soll frohlocken, Herr Jesus,\nwenn Du kommst und nach mir rufst.'),
(9, '0200', 'Dem Heiligen Geiste der gnädig dich straft  -  The Spirit, oh, Sinner, in Mercy doth move', 'The Spirit, oh, sinner, in mercy doth move,\nthy heart, so long hardened, of sin to reprove.\nResist not the Spirit, nor longer delay,\nGod’s gracious entreaties, may end with today.\r\nOh, child of the kingdom, from sin service cease,\nbe filled with the Spirit, with comfort and peace.\nOh, grieve not the Spirit, Thy Teacher is He,\nthat Jesus, Thy Saviour, may glorified be.\r\nDefiled is the temple, its beauty laid low,\non God’s holy altar the embers faint glow.\nBy love yet rekindled, a flame may be fanned,\nOh, quench not the Spirit, the Lord is at hand.', 'Dem Heiligen Geiste, der gnädig dich straft\nund Sich am Gewissen bezeuget mit Kraft,\ndem sollst du nicht länger, o Mensch, widersteh\'n!\nVersäumst du die Gnade, ist\'s um dich gescheh\'n.\r\nUnd bist du bekehret von Sünde und Tod\nzu Jesu, dem Heiland und Retter in Not,\nso werde voll Geistes, betrübe Ihn nicht,\no folge Ihm stündlich und wandle im Licht!\r\nOft wird man im Laufe so müd\' und so matt,\ndass manchmal die Seele kaum Leben mehr hat.\nDa braucht\'s neue Flammen von oben herab;\nd\'rum dämpfe den Geist nicht, dass Er dich erlab!');
INSERT INTO song_list (LISTID, NUM, NAME, TEXT_EN, TEXT_DE) VALUES
(9, '0201', 'Dem Herrscher aller Welt sei Ruhm  -  All Praise to Him who reigns above   (Gepriesen sei der Nam)', 'All praise to Him who reigns above\nin majesty supreme.\nWho gave his Son for man to die,\nthat he might man redeem.\r\nBlessed be the name,\nblessed be the name,\nblessed be the name of the Lord.\nblessed be the name,\nblessed be the name,\nblessed be the name of the Lord.\r\nHis name above all names shall stand,\nexalted more and more.\nAt God the Father\'s own right hand,\nwhere angel hosts adore.\r\nJesus is the name, Jesus is the name,\nJesus is the name of the Lord.\nJesus is the name, Jesus is the name,\nJesus is the name of the Lord.\r\nRedeemer, Saviour, friend of all,\nonce ruined by the fall.\nThou hast devised salvation\'s call,\nfor Thou hast died for all.\r\nMagnify His name, Magnify His name,\nMagnify the name of the Lord.\nMagnify His name, Magnify His name,\nMagnify the name of the Lord.\r\nHis name shall be the Counselor,\nthe mighty Prince of Peace.\nOf all earth\'s kingdoms Conqueror,\nwhose reign shall never cease.', 'Dem Herrscher aller Welt sei Ruhm\nund Ehre dargebracht!\nSein Sohn hat uns auf Golgatha\nerlöst aus Satans Macht.\r\nGepriesen sei der Nam\',\ngepriesen sei der Nam\',\ngepriesen sei der Name des Herrn.\nGepriesen sei der Nam\',\ngepriesen sei der Nam\',\ngepriesen sei der Name des Herrn.\r\nSein Name sei in Ewigkeit\nvon aller Welt erhöht.\nEr, der von Engeln wird verehrt,\nzur Rechten Gottes steht.\r\nJesus ist der Nam\', Jesus ist der Nam\',\nJesus ist der Name des Herrn.\nJesus ist der Nam\', Jesus ist der Nam\',\nJesus ist der Name des Herrn.\r\nErlöser, Heiland, Freund der Welt,\ndie tief im Sündenfall,\nDu hast der Welt das Heil gebracht,\ndenn Du starbst für uns all\'.\r\nAnbete diesen Nam\', anbete diesen Nam\',\nanbete diesen Namen des Herrn.\nAnbete diesen Nam\', anbete diesen Nam\',\nanbete diesen Namen des Herrn.\r\nEr heißt der Wunderbare Rat,\nder Friedefürst und Held.\nDer Vater aller Ewigkeit,\ndes Herrschaft nie zerfällt.'),
(9, '0202', 'Den Blick über\'n Jordan und was seh\' ich dort  -  I looked over Jordan and what do I see   (Komm, komm, o komm, Herr Jesus)', 'I looked over Jordan and what did I see?\nComing forward to carry me home.\nA band of angels coming after me,\ncoming fo to carry me home.\r\nSwing low, sweet chariot,\ncoming for to carry me home.\nSwing low, sweet chariot,\ncoming for to carry me home.\r\nIf you got there before I do\ncoming for to carry me home.\nTell all my friends I\'m coming too.\nComing for to carry me home.', 'Den Blick über\'n Jordan und was seh\' ich dort?\nkomm bald und hole mich heim.\nDie Engel steh\'n für mich schon bereit.\nKomm bald und hole mich heim.\r\nKomm, komm, o komm, Herr Jesus!\nKomme bald, ich warte auf Dich.\nKomm, komm, o Feuerwagen!\nKomme bald und hole Du mich.\r\nWenn du vor mir ankommst -\nKomm bald und hole mich heim.\nSag meinen Freunden ich komme bald -\nKomm bald und hole mich heim.'),
(9, '0203', 'Den ganzen Weg, ich geh den ganzen Weg  -  All the Way, I\'m going all the Way', 'All the way, I\'m going all the way.\nAll the way, I\'m going all the way.\nAll the way, I\'m going all the way.\nDon\'t you know I\'m going all the way with the Lord.\r\nNo turning back, I\'m going all the way.\nNo turning back, I\'m going all the way.\nNo turning back, I\'m going all the way.\nDon\'t you know I\'m going all the way with the Lord.\r\nI have made my decision, I\'m going all the way.\nI have made my decision, I\'m going all the way.\nI have made my decision, I\'m going all the way.\nDon\'t you know I\'m going all the way with the Lord.', 'Den ganzen Weg, ich geh\' den ganzen Weg.\nDen ganzen Weg, ich geh\' den ganzen Weg.\nDen ganzen Weg, ich geh\' den ganzen Weg.\nWeißt du nicht ich geh\' den ganzen Weg mit meinem Herrn.\r\nNiemals zurück, ich geh\' den ganzen Weg.\nNiemals zurück, ich geh\' den ganzen Weg.\nNiemals zurück, ich geh\' den ganzen Weg.\nWeißt du nicht ich geh\' den ganzen Weg mit meinem Herrn.\r\nIch hab\' mich entschieden, ich geh\' den ganzen Weg.\nIch hab\' mich entschieden, ich geh\' den ganzen Weg.\nIch hab\' mich entschieden, ich geh\' den ganzen Weg.\nWeißt du nicht ich geh\' den ganzen Weg mit meinem Herrn.'),
(9, '0204', 'Den königlichen Schmuck bringt her', NULL, 'Den königlichen Schmuck bringt her!\nHier ist der Siegesheld.\nKommt, huldigt Jesu, Ihm sei Ehr\'!\nO krönt Ihn, krönt Ihn,\nkrönt Ihn zum Herrscher aller Welt!\r\nDer einst sich hat in Knechtsgestalt\nden Ärmsten zugesellt,\nIhm ist gegeben die Gewalt.\nO krönt Ihn, krönt Ihn,\nkrönt Ihn zum Herrscher aller Welt!\r\nDem hier das königliche Haupt\nmit Dornen ward entstellt,\nden aller Ehren man beraubt.\nO krönt Ihn, krönt Ihn,\nkrönt Ihn zum Herrscher aller Welt!\r\nDer einst für uns die Strafe trug,\nden Mördern gleichgestellt,\nden man ans Holz des Fluches schlug.\nO krönt Ihn, krönt Ihn,\nkrönt Ihn zum Herrscher aller Welt!\r\nIhr Sünder alle, die ihr jetzt\ndurch Jesu Lösegeld\nIns Reich des Friedens seid versetzt.\nO krönt Ihn, krönt Ihn,\nkrönt Ihn zum Herrscher aller Welt!\r\nIhr Frommen, die ihr längst euch\nschon in Seinen Dienst gestellt,\nO werft euch hin vor Seinem Thron!\nO krönt Ihn, krönt Ihn,\nkrönt Ihn zum Herrscher aller Welt!\r\nIhr Völker, kommt von nah und fern,\nkommt her aus aller Welt!\nKommt, huldigt, huldigt unserm Herrn!\nO krönt Ihn, krönt Ihn,\nkrönt Ihn zum Herrscher aller Welt!'),
(9, '0205', 'Den Namen hör\' ich gar so gern  -  There is a Name I love to hear   (O, wie lieb ich Jesus)', 'There is a name I love to hear,\nI love to sing its worth;\nit sounds like music in mine ear,\nthe sweetest name on earth.\r\nOh how I love Jesus,\noh how I love Jesus,\noh how I love Jesus,\nbecause He first loved me.\r\nIt tells me of a Saviour\'s love,\nwho died to set me free.\nIt tells me of His precious blood,\nthe sinner\'s perfect plea.\r\nIt tells me what my Father hath\nin store for every day.\nAnd through I tread a darksome path,\nyields sunshine all the way.\r\nIt tells of One whose loving heart\ncan feel my deepest woe.\nWho in each sorrow bears a part,\nthat none can bear below.\r\nI never leave Him,\nI never leave Him\nI never leave Him,\nbecause Jesus holds me tight.', 'Den Namen hör\' ich gar so gern\nich spreche gern von Ihm!\nEr tönt wie Musik aus der Fern\';\n"O ja, ich liebe Ihn!"\r\nO, wie lieb\' ich Jesus,\no, wie lieb\' ich Jesus,\no, wie lieb\' ich Jesus.\nEr hat mich zuerst geliebt.\r\nEr redet von des Heilands Tod,\nvom Kreuz, woran Er starb.\nEr spricht von allem teuren Blut,\nwomit Er mich erwarb.\r\nEr sagt mir, was der Vater hat\nfür jeden Tag bereit,\nund geh\' ich auch auf dunklem Pfad,\ner führt zur Herrlichkeit.\r\nEr sagt mir, dass ein liebend Herz\nall meine Sorgen kennt.\nEr trägt mit mir an jedem Schmerz,\nund nichts von Ihm mich trennt.\r\nIch lasse Ihn niemals,\nich lasse Ihn niemals,\nich lasse Ihn niemals,\ndenn Jesus hält mich so fest.'),
(9, '0206', 'Denn der Geist und die Braut, sie sprechen komm   (Halleluja, gelobt sei Gott)', NULL, 'Denn der Geist und die Braut, sie sprechen: Komm!\nUnd wer es hört, der spreche: Komm!\nUnd wen da dürstet, der komme herzu\nund nehme das Wasser des Lebens umsonst!\r\nHalleluja, gelobt sei Gott!\nHalleluja, gelobt sei Gott!\nHalleluja, gelobt sei Gott!\nHalleluja, gelobet sei Gott!'),
(9, '0207', 'Denn Du bist der Höchste, oh Herr, über Himmel und Erde (Psalm 97, 9)   (2 Chorusse)', 'For Thou, o Lord,\nart high above all the earth,\nThou art exalted far above all gods. (2x)\r\nWe exalt Thee,\nwe exalt Thee,\nwe exalt Thee, o Lord. (2x)', 'Denn Du bist der Höchste, o Herr,\nüber Himmel und Erde,\nDu bist erhoben über alle Kreatur. (2x)\r\nWir erheben Dich,\nwir erheben Dich,\nwir erheben Dich, oh Herr. (2x)'),
(9, '0208', 'Denn Du bist groß, ein Gott der Wunder tut  -  For Thou are great and doeth wondrous Things', 'For Thou art great, and doeth wondrous things.\nThou art God alone, teach me Thy way, oh, Lord.\nI will walk in Thy truth, Unite my heart to fear Thy name.\nI will praise Thee, oh, Lord, my God, with all my heart,\nand I will glorify Thy Name for evermore.', 'Denn Du bist groß, ein Gott, der Wunder tut,\nDu bist Gott allein, weis\' mir den Weg, oh, Herr.\nIch will wandeln vor Dir, erhalt\' mein Herz in Deiner Furcht.\nDich nur preise ich, Herr, mein Gott, von ganzem Herzen,\nund Deinem Namen geb\' ich Ehr\' in Ewigkeit.'),
(9, '0209', 'Denn ein großer Gott ist der Herr - (Kommt und lasst uns unserm Herrn zujubeln)', 'Come and let us sing unto the Lord,\nMake a joyful noise unto the Rock,\nCome before His presence with Thanksgiving \nMake a joyful noise to Him with songs!\r\nFor a great God is our Lord,\nHe is a great King above all gods,\nHe is our God, and we are of His pasture,\nThe people that He made with His own hands.\r\nIn His Hand are all the deep places,\nEvery mountain does belong to Him,\nEvery sea is His, because He made it,\nand His hands formed all the dry Lands!\r\nCome, and let us Worship our maker,\nLet us bow and kneel before the Lord,\nHe created us for praise and Worship \nfor the Wonders He has done for us!', 'Kommt und lasst uns unser\'m Herrn zujubeln,\nrufen zu dem Fels uns\'res Heils,\nlasst uns nun mit Danken vor Ihn treten\nund mit Liedern singen unser\'m Herrn!\r\nDenn ein großer Gott ist der Herr,\nein großer König über alle Götter,\nja Er ist unser Gott, der uns gemacht hat,\nund wir sind die Herde Seiner Hand.\r\nIhm gehören alle tiefen Täler,\nBerge sind Sein Eigentum,\nalle Meere hat der Herr geschaffen,\nalles ist von Seiner Hand gemacht!\r\nKommt und lasst uns vor dem Herrn anbeten,\nbeugen vor dem König uns\'re Knie,\ndenn wir sind die Werke Seiner Hände,\nerlöst zum Preise Seiner Herrlichkeit!'),
(9, '0210', 'Denn wer ist Gott außer dem Herrn   (Psalm 18, 32-34)', NULL, 'Denn wer ist Gott außer dem Herrn,\nwer ist ein Fels als nur unser Gott?\nDenn wer ist Gott außer dem Herrn,\nwer ist ein Fels als nur unser Gott?\r\nDer Gott, der mich mit Macht umgürtet hat,\nuntadelig all\' meine Wege gemacht,\nEr stellte meine Füße auf den festen Grund,\nHerr, mein Fels, meine Stärke!\nEr hörte meine Stimme, als ich schrie zu Ihm,\nJahwe lebt, ja, Er lebt!'),
(9, '0211', 'Der auferstand\'ne Jesus geht jetzt durch alle Welt  -  I serve a risen Saviour, He\'s in the World today   (Er lebt, Er lebt, mein Jesus lebt auch heut)   [Jesu Name Band 1]', 'I serve a risen Saviour, He\'s in the world today.\nI know that He is living, whatever men may say.\nI see His hand of mercy, I hear His voice of cheer,\nand just the time I need Him, He\'s always near.\r\nHe lives, He lives, Christ Jesus lives today.\nHe walks with me and talks with me,\nalong life\'s narrow way.\nHe lives, He lives salvation to impart!\nYou ask me how I know He lives!\nHe lives within my heart.\r\nIn all the world around me, I see His loving care,\nand though my heart grows weary, I never will despair.\nI know that He is leading, through all the stormy blast,\nthe day of His appearing, will come at last.\r\nRejoice, rejoice, o Christian lift up your voice and sing,\neternal hallelujahs, to Jesus Christ, the King.\nThe hope of all who seek Him, the help of all who find,\nnone other is so loving, so good and kind.', 'Der auferstand\'ne Jesus geht jetzt durch alle Welt,\nEr lebt, wenn Ihn auch mancher, für längst gestorben hält!\nBarmherzig hilft Er denen, die sich, ob fern\', ob nah\',\nnach Seiner Hilfe sehnen, Halleluja.\r\nEr lebt, Er lebt! Mein Jesus lebt auch heut\'!\nEr geht mit mir, Er spricht mit mir, Er führt mich allezeit.\nEr lebt, er lebt, gibt Heil und Sieg schon hier.\nDu fragst, wie weißt du\'s, dass Er lebt?\nEr lebt im Herzen mir.\r\nAuch in dem Lauf der Zeiten, erzeigt Er sich als Herr.\nDarum, mein armes Herze: Nie darfst du zagen mehr!\nIch weiß, Er wird mich leiten, weil Er es gut nur meint,\nmich auf den Weg bereiten, wann Er erscheint.\r\nD\'rum Christen lasst erschallen ein laut\' Halleluja,\ndenn Jesus, unser König, ist uns ja stets so nah.\nIhm alle Ehre bringet, lobt Ihn zu leder Stund\'\nund  Seinen Rum verkündet mit Herz und Mund.'),
(9, '0212', 'Der Erste der starb für den Erlösungsplan  -  The first one to die for this Holy Ghost Plan   (Es tropfet von Blut)', 'It\'s dripping with blood, yes, it\'s dripping with blood.\nThis Holy Ghost Gospel is dripping with blood.\nThe blood of disciples who died for the Truth,\nthis Holy Ghost Gospel is dripping with blood.\r\nThe first one to die for this Holy Ghost plan,\nwas John the Baptist, but he died like a man.\nThen came the Lord Jesus, they crucified Him,\nHe taught that the Spirit would save men from sin.\r\nThere was Peter and Paul, and John the divine,\nthey gave up their lives so this Gospel could shine.\nThey mingled their blood, like the prophets of old,\nso the true Word of God could honest be told.\r\nThen they stoned Stephen, he preached against sin,\nHe made them so angry, they dashed his head in.\nBut he died in the Spirit, and gave up the ghost,\nand went to join others, in that life-giving host.\r\nThere\'s souls under the altar, crying, "How Long?"\nfor the Lord to punish those who\'ve done wrong.\nbut there\'s going to be more who\'ll give their life\'s blood\nfor this Holy Ghost Gospel and its crimson flood.', 'Es tropfet von Blut, ja, es tropfet von Blut.\nDas Wort seines Geistes, es tropfet von Blut.\nDas Blut seiner Jünger für die Wahrheit es floss.\nDie Heilig\' Geist Botschaft, sie tropfet von Blut.\r\nDer Erste, der starb für den Erlösungsplan,\nwar Johannes der Täufer, er starb wie ein Mann.\nDann starb der Herr Jeus, zum Kreuze Er kam,\nEr lehrte vom Geiste, dem Erlösungsplan.\r\nJohannes und Petrus und Paulus dann auch,\nsie gaben ihr Leben dann für ihren Herrn.\nWie einst die Propheten gab jeder sein Blut,\naufrichtig sich opfernd, ihr Zeugnis war gut.\r\nAls sie Stephanus hörten, ihre Wut war entbrannt.\nSie erstickten die Predigt mit dem Stein in der Hand.\nDoch starb er im Geiste, gab sein Leben dahin,\ner war nicht der Letzte, and\'re folgten auch ihm.\r\nUnter\'m Altar die Seelen, sie rufen: "Wie lang?\ngesühnt wird die Blutschuld und was uns getan."\nDoch bis zum Ende werden Märtyrer sein,\ndie ganz Ihm ergeben und Ihm sich ganz weih\'n.'),
(9, '0213', 'Der Geist ist gekommen, der Tröster ist da   (Mich haben die Arme des Heilands umhüllt)', NULL, 'Der Geist ist gekommen, der Tröster ist da!\nDas Licht ging mir auf in der Nacht!\nNun ist mir mein Jesus so wunderbar nah,\nEr hat in mir Wohnung gemacht.\r\nMich haben die Arme des Heilands umhüllt,\ndie Sünde entwich, ich bin rein!\nMein Herz ist mit göttlicher Liebe erfüllt,\no selig, in Jesu zu sein!\r\nIch hatte es früher mir niemals gedacht,\nwelch Heil der Geist Jesu uns bringt.\nIch kann es nicht sagen, wie selig Er macht,\nwelch Jubel im Innern erklingt.\r\nIch hatte zuvor nach dem Geist nicht gefragt\nund wusste nicht, wie er beglückt.\nDa hat mich nur immer die Sünde geplagt;\njetzt bin ich ihr gänzlich entrückt.\r\nWohl ficht mich Versuchung und Sünde noch an,\ndoch kommt aus der Höhe mir Kraft.\nEs geht mir im Streite mein Heiland voran,\nder liebend den Sieg mir verschafft.\r\nSo labt mich ein Himmel im Heiligen Geist\nhienieden im Pilgerkleid schon,\nbis droben mein Herz ohne Unterlass preist\ndas Lamm auf dem himmlischen Thron.'),
(9, '0214', 'Der Glaube ist ein selges Lachen', NULL, 'Der Glaube ist ein sel\'ges Lachen,\ngleich wie ein Kind zur Mutter lacht.\nWir lassen unsern Vater machen,\nEr hat ja alles schon vollbracht.\nO sel\'ges Ruh\'n in Vaterarmen!\nWir sind so schwach, wir sind so klein\nund woll\'n vor Dir nichts anders werden,\nals nur ganz kleine Kinderlein.\r\nEs ist der Glaube ein Vergessen,\nein Wegsehn von der Sichtbarkeit.\nWir schau\'n dem Heiland in die Augen\nund wissen nichts von Lust und Leid.\nWir schau\'n dem Heiland in die Augen,\nuns lächelt Seiner Liebe Gruß.\nWir haben alle Erdenlasten\nund Welt und Teufel unterm Fuß.\r\nDer Glaube ist der Atem Jesu,\nder in uns wandelt, in uns schafft.\nGestorben ist das eigne Leben,\ngestorben jede eigne Kraft.\nDann wird es stille in der Seele;\nnur Jesu Füße rauschen sacht,\nwenn aus dem Dunkel dieses Lebens\nzum Lichte wir emporgebracht.\r\nO Glaube, seliges Geheimnis,\no tiefer muss ich Dich versteh\'n!\nAls Gottes Wort die Welt geschaffen,\nda sprach Er nur, so war\'s gescheh\'n.\nDu Lebenspuls der Söhne Gottes,\nmein Königsszepter sollst Du sein!\nMein Siegesschwert, mein Feuerwagen,\ndurch Jesu Leben bist Du mein!'),
(9, '0215', 'Der Gott der mich heilt', NULL, 'Du bist der Gott der mich heilt,\nDu bist der Gott der mich heilt,\nheilst jede Krankheit,\ndie auf mir liegt,  auf mir liegt.  (2x)\nDu bist der Gott, der vergibt,\nDu bist der Gott, der vergibt,\nnimmst jede Sünde weit\nvon mir fort,  von mir fort.  (2x)'),
(9, '0216', 'Der große Arzt ist jetzt uns nah  -  The great Physician now is near', 'The great Physician now is near,\nthe sympathizing Jesus.\nHe speaks the drooping heart to cheer,\noh hear the voice of Jesus.\r\nSweetest note in seraph song,\nsweetest name on mortal tongue.\nSweetest carol ever sung,\nJesus, blessed Jesus.\r\nYour many sins are all forgiven,\noh hear the voice of Jesus.\nGo on your way in peace to heaven,\nand wear a crown with Jesus.\r\nAll glory to the dying Lamb!\nI now believe in Jesus.\nI love the blessed Saviour\'s name,\nI love the name of Jesus\r\nHis name dispels my guilt and fear,\nno other name but Jesus.\nOh how my soul delights to hear,\nthe charming name of Jesus.\r\n\r\n\r\n', 'Der große Arzt ist jetzt uns nah,\nder liebe, teure Jesus.\nEr ist mit Seinem Troste da,\nkein Heil ist außer Jesus!\r\nHorch, wie tönt der Engel Sang!\nO welch süßer Jubelklang!\nSing, mein Herz, mit freud\'gem Drang:\nJesus, Jesus, Jesus!\r\nGetilgt ist unsre Sündenschuld,\ndenn dafür büßte Jesus.\nEr führt zum Himmel uns voll Huld.\ndort krönt uns wieder Jesus.\r\nDu starbst für mich am Kreuzesstamm,\nPreis Dir dafür, o Jesus.\nIch glaub an Dich, o Gotteslamm,\nund liebe Dich, mein Jesus!\r\nHinweg ist alle Sündenpein,\ndas macht der teure Jesus!\nIn Ihm fand ich mein Heil allein,\nja, volles Heil, o Jesus!\r\nKommt Brüder, stimmt ein Loblied an\nund preiset mit mir Jesum!\nUnd, Schwestern, kommt auch Ihr heran\nund rühmt den Namen Jesu!\r\nIhr Gotteskinder, groß und klein,\no lasst uns lieben Jesus!\nLasst Ihm uns alle Kräfte weih\'n\nund loben unsern Jesus!\r\nKommt dann der große Tag herbei,\ndann seh\'n wir unsern Jesus\nund rühmen ewig Seine Treu,\no süßer Name Jesus!'),
(9, '0217', 'Der große Befreier', NULL, 'Jesus, der große Befreier,\nJesus, von Gott mir gesandt,\nzog mich, sein Kind, aus dem Feuer\nmit Seiner mächtigen Hand!\nJesus, der große Erretter,\nJesus, voll Sieg und voll Macht,\nbrach um mich her jede Kette,\nhat mir die Freiheit gebracht!\r\nIch bin frei, denn Jesus\nhat mich freigemacht,\nich bin frei, denn Jesus\nhat mich freigemacht!\r\nJesus, der große Erlöser,\nkeiner ist größer als Er,\nEr hat mit Macht uns errettet\nvor dem, der größer als wir.\nJesus, der Herr aller Herren,\nJesus, der mächtige Held\nKam uns zur Hilfe und hat uns\nEngel zur Seite gestellt.\r\nJesus, der Gott für die Schwachen,\nJesus, der hilft und befreit,\nund weil Er zu uns so gut ist,\n/:preisen wir Ihn allezeit! (4x):/'),
(9, '0218', 'Der gute Hirte ist mein Gott  -  The Lord’s my shepherd, I’ll not want   (Psalm 23)', 'The Lord’s my shepherd, I’ll not want,\nHe makes me lie in pastures green.\nHe leads me by the still, still waters,\nHis goodness restores my soul.\r\nAnd I will trust in You alone,\nand I will trust in You alone,\nfor Your endless mercy follows me,\nYour goodness will lead me home.\r\nHe guides my ways in righteousness,\nand He anoints my head with oil.\nAnd my cup, it overflows with joy,\nI feast on His pure delights.\r\nAnd though I walk the darkest path,\nI will not fear the evil one.\nFor You are with me, and Your rod and staff\nare the comfort I need to know.', 'Der gute Hirte ist mein Gott,\nauf grünen Auen lag\'re ich.\nEr führt mich hin zu stillen Wassern,\nvoll\' Güte erquickt Er mich.\r\nUnd ich vertrau\' auf Dich allein,\nund ich vertrau\' auf Dich allein,\nDeine Gnade ist unendlich groß,\nBarmherzigkeit führt mich heim.\r\nMein Haupt salbt Er mit Seinem Öl\nund führt mich in Gerechtigkeit.\nMein Becher fließt vor Freude über,\nSein Tisch ist für mich bereit.\r\nUnd geh\' ich auch durch\'s finst\'re Tal,\nfürchte ich selbst den Bösen nicht.\nJa, denn ich weiß: Dein Stecken und Dein Stab,\nsie führen und trösten mich.'),
(9, '0219', 'Der Heiland sorgt für dich, fürchte dich nicht  -  God will take care of you, be not afraid   (Der Heiland sorgt für dich täglich und neu)', 'God will take care of you, be not afraid,\nHe is your safeguard through sunshine and shade.\nTenderly watching and keeping His own,\nHe will not leave you to wander alone.\r\nGod will take care of you still to the end,\noh, what a Father, Redeemer, and Friend!\nJesus will answer whenever you call,\nHe will take care of you, trust Him for all.\r\nGod will take care of you, through all the day,\nshielding your footsteps, directing your way.\nHe is your shepherd, protector, and guide,\nleading His children where still waters glide.\r\nGod will take care of you long as you live,\ngranting you blessings no other can give.\nHe will take care of you when time is past,\nsafe to His kingdom will bring you at last.', 'Der Heiland sorgt für dich, fürchte dich nicht!\nEr ist dein Leitstern durch Schatten und Licht.\nZärtlich behütet Er alles, was Sein;\nEr lässt dich nirgends und niemals allein.\r\nDer Heiland sorgt für dich täglich und neu,\nes ist kein Freund wie Er, liebevoll, treu.\nSelig, wer sich all\'zeit auf Ihn verlässt,\nder Heiland sorgt für dich, traue Ihm fest!\r\nDer Heiland sorgt für dich, glaube es nur,\nleitet dich Schritt für Schritt in Seiner Spur.\nEr ist dein treuer Hirt\'; an Seiner Hand\nwanderst du sicher durchs irdische Land.\r\nDer Heiland sorgt für dich, sei nur getrost,\nmit Ihm das beste Teil hast du erlost!\nEr heiligt sich Sein Kind, macht es bereit\nfür Seine Herrlichkeit nach Kampf und Streit.'),
(9, '0220', 'Der Heiland steht an deiner Herzenstür  -  The Saviour now is standing at the Door   (Jesus, Er ruft dich)', 'The Saviour now is standing at the door,\nHe seeks to enter in.\nAnd if you’ll heed His loving call today,\nHe’ll save you from all sin.\r\nJesus is calling, is calling, is calling,\nJesus is calling.\nOpen your heart’s door wide and let Him in.\r\nThough long He’s stood and tarried there in vain,\nin love He waits today.\nO hear His precious gentle voice that calls,\nand turn Him not away.\r\nJust now admit this glorious heav’nly guest,\nwhy longer cling to sin?\nEternal life and joy He waits to give,\nto those who let Him in.\r\nO do not grieve Him longer by delay,\nthe door swing open wide.\nInvite Him now to quickly enter in,\nforever to abide.', 'Der Heiland steht an deiner Herzenstür\nund bittet: Lass mich ein!\nBeachte heut\' doch Seinen Liebesruf\ndann wirst du frei und rein.\r\nJesus, Er ruft dich, Er ruft dich, Er ruft dich!\nJesus, Er ruft dich.\nÖffne Ihm dein Herz und lass Ihn ein.\r\nSchon lange wartet Er vergeblich dort;\ndoch groß ist Seine Lieb.\nSo höre Seine Stimme zart und mild\nund Ihm dein Herze gib!\r\nLass diesen teuren Himmelsgast jetzt ein.\nWas gibt dir Welt und Sünd\'?\nDein Leben wird erst reich und glücklich sein,\nwenn du bist Gottes Kind.\r\nBetrübe doch nicht länger deinen Herrn,\nder Heil und Frieden bringt.\nSchließ\' auf dein Herz und lass den Heiland ein,\nSein Geist dich dann durchdringt.'),
(9, '0221', 'Der Herr ist mein Hirte mir mangelt nichts   (Psalm 23)', NULL, 'Der Herr ist mein Hirte mir mangelt nichts,\nEr führet mich wunderbar.\nAuf grünen Auen lab\' ich mich,\nan Quellen hell und klar.\r\nEr führet zum Brunnen des Lebens mich hin,\nich tauche hinein, Sein Werk ist vollbracht!\nNun geh ich im Lichte, wo immer ich bin,\nEr führt mich bei Tag und bei Nacht.\r\nEr führet auf rechtem Pfade sein Kind,\nwie ich mich auch verirrt.\nEr suchet das Verlor\'ne auf,\nEr ist ein treuer Hirt\'.\r\nEr decket den Tisch und schenket mir ein,\nerquickt mein armes Herz.\nEr salbt mein Haupt Er macht mich rein,\nund stillet jeden Schmerz.\r\nUnd ob ich auch wand\'re im finster\'n Tal,\nso fürchte ich keine Not.\nEr steht mir bei im Kampfe und Streit,\nverlässt mich nicht im Tod.'),
(9, '0222', 'Der Herr ist mein Hirte mir wird nichts mangeln   (Psalm 23)', NULL, 'Der Herr ist mein Hirte,\nmir wird nichts mangeln,\nEr führt mich zu Weiden,\nerquickt mich an Wassern. (2x)\r\nGutes und Barmherzigkeit\nwerden mir folgen\nall‘ mein Leben lang,\nall‘ mein Leben lang\nund ich werde bleiben\nim Haus des Herrn\nbis in Ewigkeit,\nbis in Ewigkeit.\r\nHerr, Du tust mir wohl,\nDu hast meine Seele\nlebendig gemacht,\nlebendig gemacht.\nUnd in Deinem Namen,\noh Du, mein Herr Jesus,\nhast Du mich geführt,\nzu Dir hin gebracht!\r\nUnd ob ich auch wand’re\nim finsteren Tale,\nmuss ich mich nicht fürchten,\ndenn Du bist bei mir,\nHerr, trotz aller Feinde\ndarf ich bei Dir speisen,\nHerr, Du gibst so reichlich\nund ich will Dich preisen!'),
(9, '0223', 'Der Herr, mein Hirte, führet mich, fürwahr, nichts mangelt mir  -  The Lord’s my Shepherd, I’ll not want   (Psalm 23)', 'The Lord’s my shepherd, I’ll not want.\nHe makes me down to lie.\nIn pastures green; He leadeth me\nthe quiet waters by.\r\nMy soul He doth restore again,\nand me to walk doth make.\nWithin the paths of righteousness,\ne’en for His own name’s sake.\r\nYea, though I walk in death’s dark vale,\nyet will I fear none ill,\nfor Thou art with me and Thy rod\nand staff me comfort still.\r\nMy table Thou hast furnished\nin presence of my foes.\nMy head Thou dost with oil anoint,\nand my cup overflows.\r\nGoodness and mercy all my life\nshall surely follow me.\nAnd in God’s house forevermore\nmy dwelling place shall be.', 'Der Herr, mein Hirte, führet mich,\nfürwahr, nichts mangelt mir.\nEr lagert mich auf grünen Au\'n\nbei frischem Wasser hier.\r\nErquickung schenkt er meiner Seel\'\nund führet gnädiglich\num seines hohen Namens Ehr\'\nauf rechter Straße mich.\r\nGeh ich durch\'s dunkle Todestal,\nich fürcht\' kein Unglück dort.\nDenn Du bist da, Dein Stecken und Stab\nsind Tröstung mir und Hort.\r\nDen Tisch bereitest Du vor mir,\nselbst vor der Feinde Schar.\nMein Haupt salbst Du mit deinem Öl,\nmein Kelch fließt über gar.\r\nJa, Deine Güte folget mir\nmein ganzes Leben lang,\nund immerdar im Haus des Herrn\nertönt mein Lobgesang.'),
(9, '0224', 'Der Himmel ist ein herrlicher Ort  -  Heaven is a wonderful Place   (Chorus)', 'Heaven is a wonderful place,\nfilled with glory and grace.\nI want to see my Saviour\'s face.\nHeaven is a wonderful place.', 'Der Himmel ist ein herrlicher Ort,\nkeine Sünde gibt\'s dort.\nGlaube an Jesus, an Gottes Wort!\nDer Himmel ist ein herrlicher Ort.'),
(9, '0225', 'Der Himmel steht offen; Herz, weißt du, warum?', NULL, 'Der Himmel steht offen; Herz, weißt du, warum?\nWeil Jesus gekämpft und geblutet: darum.\r\nAuf Golgathas Hügel, da litt Er für dich,\nals Er für dich Sünder am Kreuze verblich.\r\nSo komm doch, o Seele, komm her zu dem Herrn\nund klag deine Sünden; Er hilft ja so gern.\r\nWenngleich deine Sünden so rot sind wie Blut,\nes machen die Wunden des Heilands sie gut.\r\nUnd wenn du dich mühest in Sorge und Schmerz,\nleg\' alles dem liebenden Heiland an\'s Herz.\r\nO Jesu, mein Heiland, mein Hort und mein Teil,\nin Dir nur ist Frieden, in Dir nur ist Heil.'),
(9, '0226', 'Der Himmel zeugt von der Herrlichkeit  -  All Heaven declares the Glory of the risen Lord   (In Ewigkeit bist Du, das Lamm auf Gottes Thron)', 'All Heaven declares,\nThe glory of the risen Lord.\nWho can compare,\nwith the beauty of the Lord?\r\nForever He will be,\nthe lamb upon the throne.\nI gladly bow to Thee,\nand worship Him alone.\r\nI will proclaim,\nthe glory of the risen Lord.\nWho once was slain,\nto reconcile man to God.', 'Der Himmel zeugt,\nvon der Herrlichkeit des Herrn der Herrn.\nWer ist Ihm gleich,\ndem siegreich Auferstandenem?\r\nIn Ewigkeit bist Du,\ndas Lamm auf Gottes Thron.\nIch beuge meine Knie\nund bete an den Sohn.\r\nVerkündet laut,\ndie Herrlichkeit des Herrn der Herrn.\nEr starb am Kreuz,\ndie Menschheit zu erlösen.'),
(9, '0227', 'Der Marsch ist an  -  The March is on   (auch bekannt unter: The Move is on)', 'The march is on, oh Lord, the march is on.\nThe march is on, oh Lord, the march is on.\nI can hear the rustle in the mulberry tree\nand I know, I know, I know, the march is on.\r\nGo on brother, go on sister,\nthis is the day of march.\nRun a little closer, where the currents flow;\nrun, brother, run!', 'Der  Marsch ist an, o Herr, der Marsch ist an.\nDer  Marsch ist an, o Herr, der Marsch ist an.\nIch kann hören das Rauschen in dem Maulbeerbaum\nund ich weiß, ich weiß, ich weiß, der Marsch ist an.\r\nGeh weiter Bruder, geh weiter Schwester,\ndies ist der Aufmarschtag.\nLauf ein wenig näher, wo die Ströme fließen;\nlauf los, Bruder, lauf los!'),
(9, '0228', 'Der Name des Herrn ist meine Zuflucht  -  The Name of the Lord is a strong tower   (Spürche 18, 10)', 'The Name of the Lord is a strong tower\nThe righteouss run into it and they are safe.\nThe Name of the Lord is a strong tower,\nThe righteouss run into it and they are safe.\r\nBlessed be the name of the Lord,\nBlessed be the name of the Lord,\nBlessed be the name of the Lord most high.\nBlessed be the name of the Lord,\nBlessed be the name of the Lord,\nBlessed be the name of the Lord most high.\r\nJesus is the name of the Lord,\nJesus is the name of the Lord,\nJesus is the name of the Lord,\nmost high.', 'Der Name des Herrn ist meine Zuflucht,\noh Jesus, in Dir find\' ich die Sicherheit,\nDer Name des Herrn ist meine Zuflucht,\noh Jesus, in Dir find\' ich die Sicherheit.\r\nEhre sei dem Namen des Herrn,\nEhre sei dem Namen des Herrn,\nEhre sei dem Namen des Herrn allein.\nEhre sei dem Namen des Herrn,\nEhre sei dem Namen des Herrn,\nEhre sei dem Namen des Herrn allein.\r\nJesus ist der Name des Herrn,\nJesus ist der Name des Herrn,\nJesus ist der Name des Herrn,\nder Höchste.'),
(9, '0229', 'Der Name Jesus ist so süß  -  The Name of Jesus is so sweet   (Jesus ist mein Glück allein)', 'The name of Jesus is so sweet,\nI love its music to repeat.\nIt makes my joys full and complete,\nthe precious name of Jesus!\r\n"Jesus", O how sweet the name!\n"Jesus", ev\'ry day the same.\n"Jesus", let all saints proclaim:\nIts worthy praise forever.\r\nI love the name of Him whose heart\nknows all my griefs, and bears a part.\nWho bids all anxious fears depart -\nI love the name of Jesus.\r\nThat name I fondly love to hear,\nit never fails my heart to cheer.\nIts music dries the falling tear,\nexalt the name of Jesus.\r\nNo word of man can ever tell\nhow sweet the name I love so well.\nOh, let its praises ever swell,\noh, praise the name of Jesus.', 'Der Name Jesus ist so süß,\nEr macht mich meines Heil\'s gewiss\nund schafft schon hier das Paradies.\nWie hold der Name Jesus!\r\nJesus ist mein Glück allein!\nJesus soll mein Alles sein!\nJesus! O stimmt alle ein\nund ehret Seinen Namen!\r\nDen Namen Jesus liebt mein Herz.\nEr nimmt von mir der Sünde Schmerz\nund zieht mich zu Sich himmelwärts.\nWie lieb der Name Jesus!\r\nWenn dieser Name uns erklingt,\nist mir\'s, als ob\'s im Herzen singt,\nweil Seine Liebe mich durchdringt.\nO Preis dem Namen Jesus!\r\nJa, Jesus, welch ein süßes Wort!\nDer schönste Name hier und dort.\nEr sei gepriesen immerfort.\nErhöht den Namen Jesus!'),
(9, '0230', 'Der Ruf erschallt rings tönt es laut  -  The Chimes of Time ring out the News   (Es ist kein Gehimnis, was Gott vermag)', 'The chimes of time ring out the news, another day is through.\nSomeone slipped and fell was that someone you?\nYou may have longed for added strength your courage to renew.\nDo not be disheartened for I have news to you:\r\nIt is no secret what God can do.\nWhat He\'s done for others, He\'ll do for you.\nWith arms wide open, He\'ll pardon you,\nIt is no secret what God can do.\r\nThere is no night for in His light you’ll never walk alone.\nYou’ll always feel at home wherever you may roam.\nThere is no power can conquer you, while God is on your side,\njust take Him at His promise.\r\n', 'Der Ruf erschallt, rings tönt es laut: Ein neuer Tag bricht an!\nMancher ohne Kraft vom Feind wird weggerafft.\nHast du auch oft nach neuer Kraft mit Sehnsucht ausgeschaut,\nhör jetzt die frohe Kunde, rings um uns tönt sie laut:\r\nEs ist kein Geheimnis, was Gott vermag.\nWas Er tat für and\'re, auch für dich Er tut.\nMit off\'nen Armen lädt Er dich ein.\nEs ist kein Geheimnis, was Gott vermag.\r\nNicht länger Nacht, weil Jesu Macht aufs Neu\' wird offenbar,\nfreu dich immerdar, bald folgt das Jubeljahr!\nFürcht keine Macht der Welt, mit dir ist Jesus, Gottes Wort!\nGlaub an die Verheißung und geh nicht zweifelnd fort!\r\nBald kommt die Zeit, wo ausgekämpft der lange, schwere Streit,\nalle, die bereit, geh\'n dann zur Herrlichkeit!\nDoch jetzt im letzten Geistesweh\'n, steh auf, du Streiterheer!\nErhebt das Siegesbanner, mit uns ist Gott, der Herr!'),
(9, '0231', 'Der Schwache sage: "Ich bin stark"  -  Let the Weak say I am strong   (Hosianna, lobt das Lamm, das starb für mich /Hosanna to the Lamb that was slain.)   (Joel 3, 10)', 'Let the weak say I am strong\nlet the poor say I am rich\nlet the blind say I can see\nit\'s what the Lord has done in me (2x)\r\nHosanna hosanna\nto the Lamb that was slain.\nHosanna hosanna\nJesus died and rose again.\r\nInto the river I will wade\nthere my sins are washed away.\nFrom the heavens mercy streams\nof the Saviour\'s love for me.\nI will rise from waters deep\ninto the saving arms of God.\nI will sing salvation songs\nJesus Christ has set me free.', 'Der Schwache sage: "Ich bin stark",\nDer Arme sage: "Ich bin reich",\nDer Blinde sage: "Ich kann seh\'n,\ndas hat der Herr an mir getan". (2x)\r\nHosianna, Hosianna,\nlobt das Lamm, das starb für mich!\nHosianna, Hosianna,\ngab Sein Leben auch für Dich.\r\nIn den Strom tauch’ ich ein,\nder von Sünden mich macht rein.\nDie Gnade kam vom Himmel her\ndurch meines Retters Lieb’ zu mir.\nAus tiefen Gründen zog Er mich\nin die Arme meines Herrn.\nMit meinem Lied bezeuge ich:\nJesus Christus nur macht frei!'),
(9, '0232', 'Der Tag des Heils brach für mich an   (O süßer, selger Gottesfried)', NULL, 'Der Tag des Heil\'s brach für mich an,\nHalleluja, Preis sei Gott!\nDie kalte, dunkle Nacht verrann,\nHalleluja, Preis sei Gott!\nNun scheint die Sonne warm und hell\nund strahlt in Herz und Sinn und Seel!\nIch schöpf\' aus Jesu Freudenquell\'!\nHalleluja, Preis sei Gott!\r\nO süßer, sel\'ger Gottesfried\'!\nMein Herze singt ein Jubellied!\nHört\'s alle, ihr in Nord und Süd:\nHalleluja, Preis sei Gott!\r\nMein altes Wesen ist dahin,\nHalluluja, Preis sei Gott!\nIch suchte, und ich fand ja Ihn.\nHalleluja, Preis sei Gott!\nIch stehe nun auf Felsengrund,\ndenn Er ist mein all  Zeit und Stund\'!\nIch tu es allen Menschen kund;\nHalleluja, Preis sei Gott!\r\nDie Zukunft liegt in lichtem Schein,\nHalleluja, Preis sei Gott!\nVor mir durch Jesu Gnad\' allein,\nHalleluja, Preis sei Gott!\nIch seh\' Ihn nah und nicht mehr fern;\nEr meine Burg, mein Hort, mein Stern,\nhilft gegen alle Feinde gern.\nHalleluja, Preis sei Gott!\r\nIch singe voller Liebsbegier,\nHalleluja, Preis sei Gott!\nIm Himmel wandle ich schon hier,\nHalleluja, Preis sei Gott!\nIch woh\'n in sel\'ger Sicherheit,\nin Frieden und Glückseligkeit\nmit Gottes Volk in Ewigkeit.\nHalleluja, Preis sei Gott!'),
(9, '0233', 'Der Tag ist am Erscheinen, es weicht die dunkle Nacht  -  The Morning Light is breaking, the Darkness disappears', 'The morning light is breaking,\nthe darkness disappears.\nThe sons of earth are waking,\nto penitential tears.\nEach breeze that sweeps the ocean\nbrings tidings from afar.\nOf nations in commotion,\nprepared for Zion\'s war.\r\nRich dews of grace come o’er us,\nin many a gentle shower.\nAnd brighter scenes before us,\nare opening every hour.\nEach cry to Heaven going,\nabundant answers brings,\nand heav’nly winds are blowing,\nwith peace upon their wings.\r\nSee heathen nations bending\nbefore the God we love,\nand thousand hearts ascending\nin gratitude above.\nWhile sinners, now confessing,\nthe gospel call obey,\nand seek the Saviour\'s blessing,\na nation in a day.\r\nBlest river of salvation,\npursue thine onward way.\nFlow thou to every nation,\nnor in thy richness stay.\nStay not till all the lowly\ntriumphant reach their home.\nStay not till all the holy\nproclaim: "The Lord is come!"', 'Der Tag ist am Erscheinen;\nes weicht die dunkle Nacht,\nund Menschenkinder weinen,\nvom Sündenschlaf erwacht.\nSchon flieget über Meere\ndie Botschaft weit und breit;\nes treten Völkerheere\nfür Zion in den Streit.\r\nGleich Tau und Regen feuchtet\nein Gnadenstrom uns an,\nund herrlicher beleuchtet,\nseh\'n wir die Hirnmelsbahn.\nErhört wird jede Bitte,\ndie auf zum Throne geht,\nund sanft wird unsre Mitte\nvom Friedenshauch durchweht.\r\nSeht, wie der Heiden Menge\nzu unsrem Gott sich kehrt,\nund man schon Lobgesänge\nvon tausend Zungen hört!\nVom Heiland auserkoren,\nzu tragen Seine Schmach,\nbeschau\'n wir, neugeboren,\nein Volk auf einen Tag!\r\nDu Strom des Heiles, fließe\nin alle Welt hinaus,\nund auf die Völker gieße\ndie Segensfülle aus!\nFließ hin, bis dort am Throne\nman preist, was hier geschah,\nund es im Jubeltone\nerschallt: "Der Herr ist da!"'),
(9, '0234', 'Der Teufel hat\'s nicht gerne, dass ich mit dem König geh   (Halleluja, der König geht mit mir)', NULL, 'Halleluja, der König geht mit mir!\nLob und Preis sei Dir! Immer ist Er gleich.\nHalleluja, der König geht mit mir!\nJeden Tag geht Gott, der Herr, mit mir.\r\nDer Teufel hat\'s nicht gerne,\ndass ich mit dem König geh\',\nmit dem König geh\', mit dem König geh\'.\nDer Teufel hat\'s nicht gerne,\ndass ich mit dem König geh\'.\nJeden Tag geht Gott, der Herr, mit mir.\r\nDie Leute wundern sich,\nweil ich mit Dir, o König, geh\',\nmit Dir, o König, geh\', mit Dir, o König, geh\'.\nDie Leute wundern sich,\nweil ich mit Dir, o König, geh\'.\nJeden Tag geht Gott, der Herr, mit mir.'),
(9, '0235', 'Der Weg, die Wahrheit und das Leben   (Er ist ein Freund, ein guter Freund)', NULL, 'Der Weg, die Wahrheit und das Leben,\nist Jesus, ja, der Herr allein.\nSein Wort hat er uns doch gegeben,\ndies Licht der Herrlichkeit.\nHast Du das Licht in Deinem Herzen,\nfolgt Friede, Freude Dir hernach.\r\nEr ist ein Freund, ein guter Freund.\nEr ist ein Freund in Ewigkeit.\nEr ist ein Freund, ein wahrer Freund.\nEr ist ein Freund, Halleluja.\r\nHaben gute Freunde Dich verlassen,\nstehst einsam Du auf weiter Flur.\nDoch Einer folgt Dir durch die Gassen,\ner sucht und findet Deine Spur.\nEr ist der gute, alte Hirte,\ndas verlor\'ne Schaf bringt er nach Haus.\r\nWenn alle Namen einst verbleichen,\nso steht der Name Jesus noch.\nDient uns als ew\'ges Siegeszeichen\nam Himmel her und hoch.\nEr ziehet alle die Erlösten,\ndie seinem Namen nach genannt.'),
(9, '0236', 'Derselbe noch, derselbe noch   (3 Chorusse)', NULL, 'Derselbe noch, derselbe noch, Jesus ist derselbe noch.\nDerselbe noch, derselbe noch, Jesus ist derselbe noch.\r\nDieselbe Kraft, dieselbe Kraft, Jesus hat dieselbe Kraft.\nDieselbe Kraft, dieselbe Kraft, Jesus hat dieselbe Kraft.\r\nDenselben Sieg, denselben Sieg, Jesus hat denselben Sieg.\nDenselben Sieg, denselben Sieg, Jesus hat denselben Sieg'),
(9, '0237', 'Des Lebens Kraft, der Seele Licht, ist Christus unser Herr   (Werfet eure Sorgen auf Ihn)', NULL, 'Des Lebens Kraft, der Seele Licht,\nist Christus unser Herr;\nwenn mich der Feind auch hart anficht\',\nist Christus meine Wehr.\r\nWerfet eure Sorgen auf Ihn,\nwerfet eure Sorgen auf Ihn,\nwerfet eure Sorgen auf Ihn,\ndenn Er sorget, Er sorget für euch!\r\nEs ist so gut dem Herrn vertrau\'n\nund Seiner Allmacht Kraft,\nzu wissen, dass mir Seine Hand\nstets neuen Sieg verschafft.\r\nDu willst, dass ich vertrauen soll,\nnimmst meine last auf Dich.\nWenn Not und Kummer sich erhebt,\ndarf zu Dir flüchten ich.\r\nIch darf vertrauen Deiner Lieb\',\nvertrauen Dir allein,\nund lernen, vor Dir stille sein,\nmich betend Dir zu weih\'n.\r\nNichts soll bedrängen hier mein Herz,\nes komme wie es will.\nIch sorge nicht, weil Er mein Herr,\nstets für mich sorgen will.'),
(9, '0238', 'Dich anbeten (Dich anbeten)  -  I will worship   (I will worship)', 'I will worship (I will worship),\nwith all of my heart (with all of my heart).\nI will praise You (I will praise You),\nwith all of my strength (all my strength).\nI will seek You (I will seek You),\nall of my days (all of my days).\nI will follow (I will follow),\nall of Your ways (all Your ways).\r\nI will give You all my worship,\nI will give You all my praise.\nYou alone I long to worship,\nYou alone are worthy of my praise.\r\nI will bow down (I will bow down),\nhail You as King (hail You as King).\nI will serve You (I will serve You),\ngive You everything (give You ev\'rything).\nI will lift up (I will lift up),\nmy eyes to Your throne (my eyes to Your throne).\nI will trust You (I will trust You),\n(I) will trust You alone (trust You alone).', 'Dich anbeten (Dich anbeten),\nmit all meinem Sein (mit all meinem Sein).\nDich nur preisen (Dich nur preisen),\nwill ich allein (will ich allein).\nDich nur suchen (Dich nur suchen),\nan jedem Tag neu (an jedem Tag neu).\nDir nur folgen (Dir nur folgen),\nauf jedem Weg treu (jedem Weg treu).\r\nDich, o Herr, will ich nur preisen,\nAll mein Lob geb\' ich Dir allein.\nDenn nur Dich will ich anbeten,\nAlles Lob gebührt nur Dir allein.\r\nDu bist König (Du bist König),\nich beug\' mich vor Dir (ich beug\' mich vor Dir.)\nDir nur dien\' ich (Dir nur dien\' ich),\ngeb\' Dir alles hin (geb\' Dir alles hin).\nMeine Augen (Meine Augen),\nschauen zu Dir (schauen zu Dir).\nDir vertrau\' ich (Dir vertrau\' ich),\nfolge Dir allein (folg\' Dir allein).'),
(9, '0239', 'Dich erfass ich, o Herr Jesus, Du nur sollst mein Führer sein', NULL, 'Dich erfass\' ich, o Herr Jesus\nDu nur sollst mein Führer sein.\nDir will ich mich ganz vertrauen;\nSeele, Geist und Leib sind Dein.\r\nNur der Glaubensweg ist sicher,\nunerreichbar für den Feind,\nstrahlend hell von Gottes Lichte,\nob er uns auch dunkel scheint.\r\nSonne, die vom Kreuz hernieder\nleuchtet stets auf meinen Pfad,\nso kann ich nicht mehr abirren,\ndenn mich leitet Seine Gnad\'.\r\nGeht\'s auch hin an Abgrunds Rande,\nwo man fürchtet hinzuschau\'n,\ngilt\'s das schwerste Opfer bringen,\nlass ich mir doch nimmer grau\'n.\r\nDenn mein Heiland hat\'s verheißen,\ndass mir nichts mehr Schaden kann;\nSeiner Weisheit, Seinem Willen\nbin ich fröhlich untertan.'),
(9, '0240', 'Dich Gotteslamm, wir die Erlösten beten an   (Halleluja, halleluja, halleluja! Lamm, Lamm, das geschlacht)', NULL, 'Dich, Gotteslamm,\nwir, die Erlösten, beten an,\nbei Tag und Nacht.\nIn Liebesglut zerbrachst\ndurch Dein Erlösungsblut\nDu Satans Macht.\r\nHalleluja, halleluja, halleluja!\nLamm, Lamm, das geschlacht\',\nwürdig für Preis und Macht,\nDank, Ruhm, Anbetung in Ewigkeit!\nAmen, amen, amen, amen!\r\nWir sind befreit,\nin Deiner Liebe auszuruhn\nin Freud und Leid,\nund auch bereit,\nDir Königspriesterdienst zu tun\nin Ewigkeit.\r\nSieg allezeit ist uns\nbeschert durch Deine Macht\nin Glück und Not,\nda wir geweiht, Dir, Lamm,\nzu folgen auch im Leid\nbis in den Tod.\r\nWir sehnen uns\nnach Deinem Tag der Herrlichkeit,\no Friedefürst,\nwo Du mit uns die Reiche dieser Welt\nim Nu zerschmettern wirst.\r\nWir sind bereit,\nDir zu begegnen in der Luft\nim weißen Kleid,\nzu beten an Dich,\nLamm und Leu aus Judas Stamm,\nin Ewigkeit.'),
(9, '0241', 'Die Attribute Gottes werden sichtbar  -  God\'s attributes were manifested   (Das originale Leben, das originale Wort)', 'God\'s attributes were manifested To His Bride in this last age.\nWe have caught the revelation by the last prophet\'s message.\nAnd we know who we are and what we are raised up for,\npraise the Lord, for the Original Life.\r\nThe Original Life, the Original Seed.\nThe Original Word is what I believe.\nThe Son of Man is revealed.\nThe seventh seal is unveiled\nThe Original Life, the Original Seed.\r\nWe are the Word made flesh today,\nthis is what the Scriptures say.\nAnd our names are seen within,\nredeemed and perfect without sin.\nYes, we are anointed and inspired,\nby our God, Who\'s the Original Life.\r\nOur eyes of understanding He has opened up at last.\nAnd sweet victory is ours who were chained down in the past.\nTrue Jubilee has sounded and we have responded\nto our God, Who\'s the Original Life.\r\nWe are called unto adoption, full authority and power.\nSleeping saints will wake and join us For translation in this hour.\nGentiles\' days will soon be over glory, hallelujah!\nTo our God, Who\'s the Original Life.', 'Die Attribute Gottes werden sichtbar nun in dieser Zeit.\nSeine Braut wird durch das Wort der Stunde mehr und mehr Ihm gleich.\nVollkommen geborgen, das Wort ist unsere Kraft,\nPreis dem Herrn, Der es in uns schafft!\r\nDas originale Leben, das originale Wort,\nder originale Same, unser Bergungsort.\nDie sieben Siegel geöffnet, das Wort geoffenbart,\nPreis dem Herrn für Seine Gnad\'.\r\nWir sind das Wort heut\' fleisch gemacht,\nja das ist, was die Schrift uns sagt.\nUns\'re Namen steh\'n darin,\nerlöst und ohne Sünd\' durch Ihn.\nJa, wir sind gesalbt und inspiriert,\nPreis dem Herrn, durch unsern Gott.\r\nUns\'re Augen sind geöffnet nun in dieser Abendzeit\nund der Sieg gehört uns jetzt, die wir war\'n in Gebundenheit.\nDas Jubeljahr ist verkündet und wir geben Antwort\nunserm Gott durch Seine Gnad\'.\r\nWir sind eins in Gottes Sohnschaft, haben Vollmacht nun in Ihm.\nBald vereint mit all den Heil\'gen wir in die Entrückung geh\'n.\nNicht mehr lang sind uns\'re Tage, Glory,\nHalleluja! unserem Gott, dem originalen Wort.'),
(9, '0242', 'Die Augen Gottes gehn durch die Lande   (Ja, einen Menschen, der einfach glaubt)', NULL, 'Die Augen Gottes geh\'n durch die Lande\nEr sucht von einem zum andern Ende.\nWeißt du, wonach denn der Herr ausschaut?\nNach einen Menschen, der einfach glaubt.\r\nJa, einen Menschen, der einfach glaubt,\nder nicht auf Wissen und Stärke baut,\nder jeden Tag nur dem Herrn vertraut.\nJa, das sucht Gott,\nja das sucht Gott\r\nSo viele dachten, dass sie es haben,\nsie hatten Wissen und keinen Glauben\nund viele haben auf Sand gebaut.\nDoch Gott sucht jemand,\nder einfach glaubt.\r\nJa, Gott sprach zu uns in diesen Tagen.\nDu darfst die Worte im Herze tragen.\nJa, diese Botschaft ist für die Braut,\nsie ist für jeden, der einfach glaubt.\r\nVersuch doch niemals, es zu erklären,\nes zu verstehen und auszulegen.\nSei doch ein Kind, das nur Gott vertraut.\nGott freut Sich, wenn man Ihm einfach glaubt.\r\nDie Augen Gottes geh\'n durch die Lande,\nsie suchen, ob sich die Braut nicht fände.\nVielleicht bist du\'s ja, auf den Er schaut,\nweil du ein Mensch bist, der einfach glaubt.'),
(9, '0243', 'Die da harren auf den Herrn (Lehr mich Herr auszuharren auf den Knien  -  Teach me Lord to wait down on my Knees)', 'Teach me, Lord, to wait down on my knees,\ntill in Your own good time You answer my pleas.\nTeach me not to rely on what others do,\nbut to wait in prayer for an answer from You.\r\nThey that wait upon the Lord,\nshall renew their strength,\nthey shall mount up with wings as an eagle,\nthey shall run and not be weary,\nthey shall walk and not faint.\nTeach me Lord, teach me, Lord, to wait.\r\nTeach me, Lord, to wait, while hearts areaflame,\nhelp me humble my pride and call on Your name.\nKeep my faith renewed, keep my eeyes on Thee,\nhelp me be on this earth what You want me to be.\r\nTeach me, Lord, to wait and to stand on Thy word\nthat I hear what You say and I see what You mean.\nThat the Spoken Word is the original seed\nand that nothing can help me but only Thy  word.', 'Lehr\' mich, Herr, auszuharren auf den Knien in der Nacht,\num zu warten auf die Antwort, bis die Sonne wieder lacht.\nLehr\' mich, Herr, nicht zu schauen was die anderen tun.\nLehr mich in der Verheißung Deines Wortes zu ruh\'n.\r\nDie da harren auf den Herrn,\ndie erneuern ihre Kraft,\nschwingen auf sich empor wie ein Adler,\nwerden laufen und nicht müde,\nwerden gehen und nicht matt.\nLehr\' mich Herr, lehr\' mich warten auf Dich.\r\nLehr\' mich, Herr, auszuharren wenn es um uns noch so grau,\num zu warten auf die Antwort, die nur Du kennst ganz genau.\nNimm was Dir nicht gefällt und den Stolz dieser Welt!\nLass mich Dir weiter folgen und nicht Gut und Geld.\r\nLehr\' mich, Herr, auszuharren und zu steh\'n auf deinem Wort,\nbis Du schenkst mir Offenbarung, die der wahre Ruheort.\nLehr mich, Herr, zu erkennen, dieses Wort das gesandt.\nLass die Botschaft durch mich leben als ein Christ an Deiner Hand.'),
(9, '0244', 'Die Erinn\'rung Jesu Schmerzen, neu zu meiner Seel gesandt   (Die Erinnrung Jesu Schmerzen, die am Kreuz für mich er trug)', NULL, 'Die Erinn\'rung Jesu Schmerzen,\nneu zu meiner Seel gesandt.\nBLeib\' es immer in dem Herzen,\nwas er für mich aufgewandt.\r\nDie Erinn\'rung Jesu Schmerzen\ndie am Kreuz für mich er trug,\nlässt meine Herze dankbar werden.\nO, es war für mich genug!\r\nAuf dem Wege meines Lebens\nist es immer für mich neu.\nDie Erinn\'rung Deiner Schmerzen,\no, mein Heiland Du bist treu!\r\nTreuer Vater, Herr und Heiland,\nDeine Liebe war so groß!\nNie vergess\' ich solche Treue,\nkomm von dieser Tat nicht los!'),
(9, '0245', 'Die Fenster des Himmels stehn offen  -  The Windows of Heaven are open   [Jesu Name Band 3]', 'The windows of Heaven are open,\nthe blessings are falling tonight.\nThere\'s joy, joy, joy in my heart,\nsince Jesus made everything right.\nI gave Him my old tattered garment,\nHe gave me a robe of pure white.\nI\'m feasting today on the Manna,\nand that\'s why I\'m happy tonight.\r\n', 'Die Fenster des Himmels steh\'n offen,\nder Segen strömt mächtig herab.\n\'s ist Freud\', Freud\', Freud\' in dem Herrn,\nseitdem ich mein Leben Ihm gab.\nEr nahm mir die Lumpen der Sünde\nund gab mir ein schneeweißes Kleid.\nNun speis\' ich vom himmlischen Manna\nund freu\' mich in Ihm allezeit.\r\nDie Freude am Herrn gibt mir Stärke,\ndie Freude am Herrn gibt mir Kraft;\nund in allem meinem Werke weiß ich:\nJesus ist es, der es schafft.\nEr hilft mir die Lasten zu tragen,\nEr gibt mir ein fröhliches Herz.\nEr stärkt mich in schwierigen Lagen,\nEr führt mich himmelwärts.'),
(9, '0246', 'Die Gnade des Herrn gleicht der wogenden See  -  The mercy of God is an Ocean divine   (Stoß ab aufs weite Meer, wir fahren auf die Höh)', 'The mercy of God is an ocean divine,\na boundless and fathomless flood;\nlaunch out in the deep, cut away the shoreline,\nand be lost in the fullness of God,\r\nLaunch out into the deep, oh, let the shoreline go,\nlaunch out, launch out in the ocean divine.\nOut where the full tides flow.\r\nBut many, alas! only stand on the shore,\nand gaze on the ocean so wide;\nthey never have ventured its depths to explore,\nor to launch on the fathomless tide.\r\nAnd others just venture away from the land,\nand linger so near to the shore.\nThat the surf and the slime that beat over the strand,\nDash o\'er them in floods evermore.\r\nOh, let us launch out on this ocean so broad,\nwhere the floods of salvation e\'er flow.\nOh, let us be lost in the mercy of God,\ntill the depths of His fullness we know.\r\n\r\n\r\n', 'Die Gnade des Herrn gleicht der wogenden See,\ndem weiten, unendlichen Meer.\nstoßt ab denn vom Strand, fahrt hinaus auf die Höh\'!\nO zaudert und zweifelt nicht mehr!\r\nStoß ab! auf\'s weite Meer! Wir fahren auf die Höh\'!\nHolt die Anker auf! Schnell das Segel gesetzt!\nAuf, in die tiefe See!\r\nEs wandeln gar manche am Ufer entlang,\nsie schauen der Wellen Gebraus;\nsie lauschen der Wogen gewalt\'gem Gesang,\ndoch fahren sie nimmer hinaus!\r\nUnd andre besteigen den schwankenden Kahn\nund rudern am Ufer umher.\nDoch nimmer erreichen sie, müde und lahm,\ndas so majestätische Meer!\r\nDie Fülle des Segens wird dann uns zuteil,\nwenn jegliches Band bricht entzwei.\nDann öffnet sich uns das unendliche Heil,\ndann schafft uns die Gnade ganz neu.\r\nO Seele, verlasse den eigenen Sinn,\nverlasse die Welt und die Sünd\'.\nLass fahren das Alte, gib völlig dich hin\nund werde ein fröhliches Kind.\r\nDer Ozean Gottes, die mächtige Flut\nder ewigen Liebe im Sohn,\nverschlingt dein Verderben; und alles ist gut,\ndie Woge, sie trägt dich zum Thron!\r\nDas gläserne Meer in der himmlischen Welt,\nso stille, kristallhell und rein,\nbald wird es, zerbricht dieses irdische Zelt,\ndein Auge auf ewig erfreu\'n!'),
(9, '0247', 'Die Gnade des Herrn ist so wunderbar   (4 Chorusse)', NULL, 'Die Gnade des Herrn ist so wunderbar,\nso wunderbar, Halleluja.\nDie Gnade des Herrn ist so wunderbar,\nso wunderbar für mich.\r\nDie Liebe des Herrn ist so wunderbar,\nso wunderbar, Halleluja.\nDie Liebe des Herrn ist so wunderbar,\nso wunderbar für mich.\r\nDie Treue des Herrn ist so wunderbar,\nso wunderbar, Halleluja.\nDie Treue des Herrn ist so wunderbar,\nso wunderbar für mich.\r\nDie Freude am Herrn ist so wunderbar,\nso wunderbar, Halleluja.\nDie Freude am Herrn ist so wunderbar,\nso wunderbar für mich.'),
(9, '0248', 'Die güldne Sonne voll Freud und Wonne  -  The golden Sunbeams with their joyous Gleams', 'The golden sunbeams with their joyous gleams,\nare kindling o\'er earth, her life and mirth,\nshedding forth lovely and heart-cheering light.\nThrough the dark hours\' chill I lay silent and still,\nbut risen at length to gladness and strength,\nI gaze on the heavens all glowing and bright.\r\nMine eyes now behold Thy works, that of old\nand ever are telling to all men here dwelling,\nhow great is Thy glory, how wondrous Thy power.\nThey tell of the home where the faithful shall come,\nwho depart to that peace that can change not or cease,\nfrom earth where all passeth as passes the hour.\r\nO come let us raise our voices, and praise\nthe Maker of all, at His feet let us fall,\noffering to Him again all He hath given,\nthe best that is ours, our hearts and our powers.\nGlad songs that we sing Him, thanks that we bring Him,\nthese are the incense most grateful to Heaven.\r\nEvening and morning thus ever he cares for us,\nblessing, renewing, warding off ruin,\nthese are His works, thus His goodness we prove.\nWhen we are sleeping, watch He is keeping,\nwhe we arise, He gladdens our eyes\nwith the sunshine of mercy, the glow of His love.\r\nAll passeth away, but God liveth aye,\nand changeth in nought; eternal His thought,\nHis Word and His Will are steadfast and sure.\nNever His grace nor His mercy decays,\nit heals the sad heart from its deadliest smart,\ngiving it life that shall ever endure.', 'Die güld\'ne Sonne voll Freud und Wonne\nbringt unsern Grenzen mit ihrem Glänzen\nein herzerquickendes, liebliches Licht.\nMein Haupt und Glieder, die lagen darnieder,\naber nun steh ich, bin munter und fröhlich,\nschaue den Himmel mit meinem Gesicht.\r\nMein Auge schauet, was Gott gebauet\nzu Seinen Ehren und uns zu lehren,\nwie Sein Vermögen sei mächtig und groß,\nund wo die Frommen dann sollen hinkommen,\nwann sie mit Frieden von hinnen geschieden\naus dieser Erde vergänglichem Schoß.\r\nLasset uns singen, dem Schöpfer bringen\nGüter und Gaben, was wir nur haben,\nalles sei Gotte zum Opfer gesetzt.\nDie besten Güter sind unsre Gemüter,\ndankbare Lieder sind Weihrauch und Widder,\nan welchen Er Sich am meisten ergötzt.\r\nAbend und Morgen sind Seine Sorgen;\nsegnen und mehren, Unglück verwehren,\nsind Seine Werke und Taten allein.\nWenn wir uns legen, so ist Er zugegen;\nwenn wir aufstehen, so lässt Er aufgehen\nüber uns Seiner Barmherzigkeit Schein.\r\nAlles vergehet, Gott aber stehet\nohn\' alles Wanken, Seine Gedanken,\nSein Wort und Wille hat ewigen Grund.\nSein Heil und Gnaden, die nehmen nicht Schaden,\nheilen im Herzen die tödlichen Schmerzen,\nhalten uns zeitlich und ewig gesund.'),
(9, '0249', 'Die Güte des Herrn hat kein Ende   (Chorus)', NULL, 'Die Güte des Herrn hat kein Ende, kein Ende.\nSein Erbarmen höret niemals auf.\nEs ist neu jeden Morgen, neu jeden Morgen.\nGroß ist Deine Treue, oh Herr, groß ist Deine Treue.'),
(9, '0250', 'Die Hand Satan\'s kann ich spüren  -  I can feel the hand of Satan   (So Gott schlägt mich ich vertrau Ihm)', 'I can feel the hand of Satan\nas the tempter presses me sore.\nHe has been before the father\nasking leave to test me more.\r\nThough God slay me yet I\'ll trust Him\nI shall then come forth as gold.\nAnd I know my redeemer liveth\nfor I feel it in my soul.\r\nI can hear the father grant it,\nsaying "do not touch his life."\nThough you chrush him he\'ll not falter\nhe will rise above the strife\r\nThough I\'ll struggle I\'ll not stagger,\nby His grace I\'ll make it through.\nFor His grace is all sufficient\nand I know that God is true.\r\nWhen I\'ve looked all around me\nAnd His face I cannot see;\nThen I know that through the lattice\nHe beholdeth even me.', 'Die Hand Satans kann ich spüren,\nder Versucher schlägt mich wund.\nMeinen himmlisch\' Vater bat er,\nmich zu schlagen noch viel mehr.\r\nSo Gott schlägt mich ich vertrau\' Ihm,\ngehe dann als Gold hervor.\nMein Erlöser lebt, das weiß ich,\ndenn ich fühl\'s in meiner Seel\'.\r\nSatans Bitte Gott gewähret,\n"doch sein Leben rühr\' nicht an."\nZerbrichst du ihn, er liebt mich dennoch,\ngeht als Sieger d\'raus hervor.\r\nQuält\'s mich sehr, doch ich nicht strauchel,\nSeine Gnade bringt mich durch.\nAllgenügend Seine Gnad\' ist,\nund ich weiß, dass Gott ist treu.\r\nWenn auch nirgends ich Ihn sehe,\nund Sein Antlitz mir verhüllt,\nweiß ich über mir ER wachet,\nund selbst meiner ER gedenkt.'),
(9, '0251', 'Die Hand, die man grausam ans Kreuz einst schlug  -  The Hand that was nailed to the Cross of Woe   (Die Hand meines Heilands ich seh)', 'The hand that was nailed to the cross of woe,\nin love reaches out to the world below.\n’Tis beckoning now to the souls that roam,\nand pointing the way to the heav’nly home.\r\nThe hand of my Saviour I see,\nthe hand that was wounded for me,\n’Twill lead me in love to the mansions above,\nthe hand that was wounded for me!\r\nE’en now I can see, through a mist of tears,\nthat hand still outstretched o’er the gulf of years.\nWith healing and hope for my sin sick soul,\none touch of its finger will make me whole!\r\nThe hand that wrought wonders in days of old,\nholds treasure more precious than gems or gold.\nThe price of redemption from sin and shame,\nthe gift of salvation through Jesus’ name.', 'Die Hand, die man grausam ans Kreuz einst schlug,\ndie schuldlos den bittersten Schmerz einst trug,\nstreckt liebend  sich über die Welt hinaus\nund weiset Verlor\'nen den Weg nach Haus.\r\nDie Hand meines Heilands ich seh\',\nam Kreuze voll Schmerzen und Weh.\nSie führet mich ein in das himmlische Heim,\ndie Hand voller Schmerzen und Weh!\r\nMein tränenvoll\' Auge erblickt noch heut\',\ndie Hand, die da reicht über\'s Meer der Zeit.\nSie legt sich mir heilend auf\'s wunde Herz,\nverbannet für immer der Seele Schmerz.\r\nDie Hand, die vorzeiten manch Wunder tat,\nfür mich viele himmlischen Schätze hat.\nDen Kaufpreis der Seele, Sein teures Blut,\ndie ew\'ge Erlösung mein höchstes Gut.'),
(9, '0252', 'Die Heilge-Geist Kraft bewegt sich wie ein Magnet   (Chorus)', NULL, 'Die Heil\'ge-Geist-Kraft bewegt sich wie ein Magnet.\nDie Heil\'ge-Geist-Kraft bewegt sich wie ein Magnet.\nBewegt sich hier, bewegt sich dort,\nbewegt sich nun an jedem Ort.\nDie Heil\'ge-Geist-Kraft bewegt sich wie ein Magnet.'),
(9, '0253', 'Die Herrlichkeit des Herrn bleibe ewiglich  -  Let the Glory of the Lord endure forever   (Chorus)', 'Let the glory of the Lord endure forever.\nLet the Lord be glad in His works.\nI will sing unto the Lord as long as I live.\nI will sing praise to my God while I have my being.', 'Die Herrlichkeit des Herrn bleibe ewiglich.\nDer Herr freue sich Seiner Werke.\nIch will singen dem Herrn mein Leben lang.\nIch will loben meinen Gott so lang ich bin.'),
(9, '0254', 'Die Kraft die einst zu Pfingsten kam  -  The Pow’r that fell at Pentecost   (Die Kraft, die Kraft, des Heilgen Geistes Kraft)', 'The pow’r that fell at Pentecost,\nwhen in that upper room,\nupon the watching, waiting ones,\nthe Holy Ghost had come.\nRemaineth evermore the same.\nUnchanging still, oh praise His name.\r\nThe pow’r, the pow’r, the Pentecostal pow’r,\nis just the same today,\nis Just the same today.\nThe pow’r, the pow’r, the Pentecostal pow’r,\nis just the same today.\r\n“Ye shall have pow’r" ,said Jesus, when\nThy Holy Ghost is come.\n“Your loosened tongues shall speak His praise,\nyour lips no more be dumb.\nThe timid, shrinking ones be brave,\nto reach a hand the lost to save.\r\nThe wav’ring shall steadfast become,\nthe weak in faith be strong,\nwith holy boldness going forth,\nDenouncing sin and wrong.\nWith burning zeal each heart aflame,\na whole salvation to proclaim.\r\nBreathe on us now the Holy Ghost,\nthe young and old inspire.\nLet each receive his Pentecost,\nsend hearts and tongues of fire.\nThou wonderful transforming pow’r,\ncome now in this accepted hour.', 'Die Kraft die einst zu Pfingsten kam\nauf jene kleine Schar,\ndie wachend, wartend im Gebet\nvor Gott beisammen war,\ndieselbe Kraft ist heute noch\nder Heil\'ge Geist, o glaubt es doch!\r\nDie Kraft, die Kraft,\ndes Heilgen Geistes Kraft\nist stets dieselbe noch,\nist stets dieselbe noch,\ndie Kraft, die Kraft,\ndes Heilgen Geistes Kraft,\nsie nimmt von uns Besitz.\r\nIm Heilgen Geist ist Kraft genug,\nja, Gottes Kraft ist Er;\nwen Er erfüllt, der lobt und preist\nund kann nicht schweigen mehr.\nDa werden Schwache stark und treu,\nzum Retterdienst Gebund\'ne frei.\r\nStandhaft macht Er die Wankenden,\ndie Glaubensarmen reich,\ndass sie für Jesus vorwärts geh\'n\nund ruh\'n in Ihm zugleich,\ndass völlige Erlösung sie\nmit Macht bezeugen spät und früh.\r\nErfüll\' uns alle, Heil\'ger Geist,\nmit mächt\'gem Lebenstrieb!\nGib Herzen, drin Dein Feuer brennt,\nund Feuerzungen gib!\nDu, der ein völlig Neues schafft,\nkomm jetzt, Du wunderbare Kraft!'),
(9, '0255', 'Die Liebe Gottes ist viel mehr als eine Zunge sagen kann  -  The Love of God is greater far the Tongue or Pen can ever tell   (O, Liebe Gottes, reich und rein)', 'The love of God is greater far\nthan tongue or pen can ever tell.\nIt goes beyond the highest star,\nand reaches to the lowest hell.\nThe guilty pair, bowed down with care,\nGod gave His son to win.\nHis erring child He reconciled,\nand pardoned from his sin.\r\nOh, love of God, how rich and pure!\nHow measureless and strong!\nIt shall forevermore endure,\nthe saints and angels song.\r\nWhen hoary time shall pass away,\nand earthly thrones and kingdoms fall,\nwhen men who here refuse to pray,\non rocks and hill and mountains call,\nGod\'s love, so sure, shall still endure,\nall measureless and strong;\nredeeming grace to Adam\'s race,\nthe saints\' and angels\' song.\r\nCould we with ink the ocean fill,\nand were the skies of parchment made;\nwere every stalk on earth a quill,\nand every man a scribe by trade;\nto write the love of God above\nwould drain the ocean dry;\nnor could the scroll contain the whole,\nthough stretched from sky to sky.', 'Die Liebe Gottes ist viel mehr,\nals eine Zunge sagen kann.\nSie reicht hinauf zum höchsten Stern\nund greift zur tiefsten Sündenbahn.\nFür schuldbelad\'ne Sünderherzen\ngab Gott den Sohn dahin.\nSein irrend Kind versöhnte Er,\nvergab die Sünden ihm.\r\nO, Liebe Gottes, reich und rein!\nSo grenzenlos und rein!\nIn Ewigkeit soll diese Liebe\ndas Lied der Heiligen sein.\r\nWenn einst entschwindet diese Zeit\nund ird\'sche Reiche hier vergeh\'n;\nwenn Menschen, die nie beten wollten,\nzu Berg und Fels um Hilfe fleh\'n;\ndann bleibt die Liebe Gottes steh\'n,\nso grenzenlos und rein;\nErlösungsgnade für den Sünder\nwird stets der Heil\'gen Lied sein.\r\nWenn wir das Meer mit Tinte füllten\nund wär\' der Himmel Pergament;\nwär\' jeder Halm hier eine Feder,\nund jeder damit schreiben könnt\';\ndie Liebe Gottes aufzuschreiben,\ndas weite Meer verzehrt;\nwie könnten Bücher alles fassen,\nwär\' noch so groß ihr Wert.'),
(9, '0256', 'Die Pilger zur Heimat der Seligen ziehn   (Keine Nacht kann da sein)', NULL, 'Die Pilger zur Heimat der Seligen zieh\'n,\nwo Tränen nie werden geweint;\nwo himmlische Rosen unsterblich erblüh\'n,\nweil da Jesus als Sonne stets scheint.\r\nKeine Nacht kann da sein,\nkeine Nacht kann da sein,\nweil da Jesus als Sonne stets scheint,\nweil da Jesus als Sonne stets scheint.\r\nDort gibt es kein Leiden, noch Jammer, noch Schmerz;\nvon Todeshauch ist keine Spur.\nDort gibt es kein Scheiden, kein brechendes Herz,\nnein, nur Wonne auf himmlischer Flur.\r\nO selige Heimat, bald bist du erreicht!\nDer Tabor von ferne schon winkt,\nwo das Loblied des Lammes auf ewig nicht schweigt,\nwo es immer entzückend erklingt.\r\nWo selige Scharen am Lebensstrom steh\'n,\nvon Sünden in Jesu Blut rein,\nund alle die Herrlichkeit Gottes nur seh\'n,\nwo kein Nachten noch Sterben wird sein.\r\nIns Lebensbuch Gott sie mit Jesu Blut schrieb,\nerhob sie zum göttlichen Stand.\nEr trocknet die Tränen so hold und so lieb\nin der Heimat mit zärtlicher Hand.'),
(9, '0257', 'Die Sach ist Dein Herr Jesus Christ, die Sach, an der wir stehn', NULL, 'Die Sach\' ist Dein Herr Jesus Christ,\ndie Sach\', an der wir steh\'n\nund weil es Deine Sache ist,\nkann Sie nicht untergeh\'n.\nAllein das Weizenkorn, bevor\nes fruchtbar sprosst zum Licht empor,\nwird sterbend in der Erde Schoß\nvorher vom eignen Wesen los,\nim Sterben los, vom eignen Wesen los.\r\nDu gingest, Jesus, unser Haupt,\ndurch Leiden himmelan\nund führest jeden, der da glaubt,\nmit Dir die gleiche Bahn.\nWohlan, so führ\' uns allzugleich\nzum Teil am Leiden und am Reich.\nFühr\' uns durch Deines Todes Tor\nsamt Deiner Sach\' zum Licht empor,\nzum Licht empor durch\nDeines Todes Tor.\r\nDu starbest selbst als Weizenkorn\nund sankest in das Grab.\nBelebe denn, o Lebensborn\ndie Welt, die Gott Dir gab.\nSend\' Boten aus in jedes Land,\ndass bald Dein Name werd\' erkannt.\nDein Name voller Herrlichkeit.\nAuch wir steh\'n Dir zum Dienst bereit,\nzum Dienst bereit,\nzum Dienst in Kampf und Streit.'),
(9, '0258', 'Die Sonne meines Lebens ist Jesus   (Chorus)', NULL, 'Die Sonne meines Lebens ist Jesus,\nEr allein nur macht mich froh.\nWas immer kommen mag,\nEr führt mich Tag für Tag,\nd\'rum ist all mein Glück in Jesus.'),
(9, '0259', 'Die Stadt, nach der ich ausschau\', ist nicht gemacht von Hand  -  I\'m looking for a City, the one not made by Hands   (Jetzt hab ich die ewge Freude tief in mir)', 'I\'m looking for a city, the one not made by hands.\nI\'m looking over Jordan, I see the promised land.\nThe waters will be parted and I\'ll be on my way,\nas we\'re crossing over Jordan I can say:\r\nNow I have that everlasting joy within,\nsince He came and took away my sin.\nThe moment that He blessed me, He made me fully whole,\nwith that everlasting joy within my soul.\r\nI\'m drinking from the fountain tThat floweth from on high.\nA well of blessed waters that never shall run dry.\nI\'m feasting on God\'s manna, I\'m praying day by day,\nand that everlasting joy is here to stay.\r\nI\'ve heard the prophet\'s message, I\'ve placed it in my heart.\nI\'ve got the revelation that never shall depart.\nThe Rapture is upon us, the stage is set to go,\nwe have this precious promise we all know.,', 'Die Stadt, nach der ich ausschau\', ist nicht gemacht von Hand.\nIch schaue über\'n Jordan zu dem verheiß\'nen Land.\nDas Wasser wird sich teilen, ich bin auf meinem Weg,\nwenn wir ziehen durch den Jordan sage ich:\r\nJetzt hab\' ich die ew\'ge Freude tief in mir\nseit Er kam und meine Sünde nahm.\nEr hat mich dort gesegnet, Er machte mich ganz heil\nmit der ew\'gen wahren Freud\' in meiner Seel\'.\r\nIch trinke von der Quelle, die droben sich ergießt.\nEin Brunn\' lebend\'gen Wassers, der nimmermehr versiegt.\nIch speise Gottes Manna, ich bete Tag für Tag\nund die ew\'ge Freude bleibet immerdar!\r\nIch hörte Gottes Botschaft durch des Propheten Mund.\nIch hab\' die Offenbarung, die Christus tat mir kund.\nWir geh\'n in die Entrückung und machen uns bereit,\ndenn verheißen ist uns Seine Herrlichkeit.'),
(9, '0260', 'Die Welt ist nicht mein Heim, ich bin im Pilgerstand  -  This World is not my Home, I\'m just a passing through   (O Herr, Du weißt, Du bist mein Freund allein)', 'This world is not my home, I\'m just a passing through,\nmy treasures are laid up somewhere beyond the blue.\nThe angels beckon me from heaven\'s open door.\nAnd I can\'t feel at home in this world anymore.\r\nO Lord, you know I have no friend like you,\nif heaven\'s not my home, then Lord what will I do?\nThe angels beckon me from heaven\'s open door,\nand I can\'t feel at home in this world anymore.\r\nThey\'re all expecting me, and that\'s one thing I know,\nmy Saviour pardoned me and now I onward go.\nI know He\'ll take me thro\' tho\' I am weak and poor,\nand I can\'t feel at home in this world anymore.\r\nI have a loving Saviour up in glory-land,\nI don\'t expect to stop until I with Him stand,\nHe\'s waiting now for me in heaven\'s open door.\nAnd I can\'t feel at home in this world anymore.\r\nJust up in glory-land we\'ll live eternally,\nthe saints on every hand are shouting victory.\nTheir songs of sweetest praise drift back from heaven\'s shore.\nAnd I can\'t feel at home in this world anymore.\r\n', 'Die Welt ist nicht mein Heim, ich bin im Pilgerstand.\nMein Sehnen steht allein nach jenem Heimatland.\nGeöffnet seh\' ich hier des Himmel Perlentür.\nUnd ich fühl\' in der Welt niemals mehr mich daheim!\r\nO Herr, Du weißt, Du bist mein Freund allein,\nwär\' der Himmel nicht mein Heim, es würde trostlos sein.\nIch flehe, Herr, zu Dir, hol\' uns bald ab von hier,\ndenn ich fühl\' in der Welt niemals mehr mich daheim!\r\nMein Herr hat mich befreit, das weiß ich ganz genau,\nEr macht mich auch bereit, wenn ich Ihm nur vertrau\'.\nBald holt Er uns mit Seinem großen Himmelsheer,\ndenn ich fühl\' in der Welt niemals mehr mich daheim!\r\nErwartet werd\' ich dort zum großen Liebesmahl,\nmich zieht es weiter fort, wo Heil\'ge ohne Zahl\nversammeln sich beim Herrn; der Tag ist nicht mehr fern.\nUnd ich fühl\' in der Welt niemals mehr mich daheim!\r\nGehorsam woll\'n wir seinin dieser Erdenzeit\nund so geh\'n wir mit ein in Deine Herrlichkeit.\nO brauch uns, lieber Herr, hier als Dein Siegesheer.\nUnd ich fühl\' in der Welt niemals mehr mich daheim!\r\nDer Herr sprach heut\' zu uns durch des Propheten Mund.\nEr tat am Horizont die Wolke für uns kund,\ndenn das ist Sein Gefährt; entrückt uns von der Erd\';\ndenn ich fühl\' in der Welt niemals mehr mich daheim.'),
(9, '0261', 'Die Welt war verloren im Dunkel der Sünd  -  The whole World was lost in the Darkness of Sin   (Komm zu dem Licht, es scheint ja für dich)   [Bieselsberg]', 'The whole world was lost in the darkness of sin.\nThe Light of the world is Jesus!\nLike sunshine at noonday, His glory shone in.\nThe Light of the world is Jesus!\r\nCome to the light, ’tis shining for thee,\nsweetly the light has dawned upon me.\nOnce I was blind, but now I can see,\nthe Light of the world is Jesus!\r\nNo darkness have we who in Jesus abide.\nThe Light of the world is Jesus!\nWe walk in the light when we follow our Guide!\nThe Light of the world is Jesus!\r\nYe dwellers in darkness with sin-blinded eyes.\nThe Light of the world is Jesus!\nGo, wash at His bidding, and light will arise.\nThe Light of the world is Jesus!\r\nNo need of the sunlight in Heaven we’re told.\nThe Light of the world is Jesus!\nThe Lamb is the Light in the city of gold.\nThe light of this city is Jesus!', 'Die Welt war verloren im Dunkel der Sünd\',\n- das Licht dieser Welt ist Jesus.\nWie Sonnenschein leuchtet Er hell Seinem Kind,\n- das Licht dieser Welt ist Jesus.\r\nKomm zu dem Licht, es scheint ja für dich!\nO welches Licht, hell scheint es für mich!\nBlind war ich einst, doch jetzt sehe ich,\ndas Licht dieser Welt ist Jesus.\r\nDas Dunkel vorbei, wenn in Jesus ich bleib\'\n- das Licht dieser Welt ist Jesus!\nSein Wort ist das Licht, welches führt mich so treu\n- das Licht dieser Welt ist Jesus!\r\nAm Ende der Zeit sieht so dunkel es aus\n- das Licht dieser Welt ist Jesus!\nDas Abendlicht leuchtet und führt uns nach Haus\n- das Licht dieser Welt ist Jesus!\r\nDie himmlische Stadt braucht die Sonne nicht mehr\n- das Licht dieser Welt ist Jesus!\nDas Lamm ist das Licht dort, wir freu\'n uns so sehr\n- das Licht dieser Stadt ist Jesus!'),
(9, '0262', 'Die Zeit, sie rennt in großen Schritten  -  Time, is filled with swift Transition   (Halte fest an Gottes Hand)', 'Time, is filled with swift transition,\nnaught of earth unmoved can stand.\nBuild your hopes on things eternal,\nhold to God\'s unchanging hand!\r\nHold to God\'s unchanging hand!\nHold to God\'s unchanging hand!\nBuild your hopes on things eternal,\nHold to God\'s unchanging hand.\r\nTrust in Him who will not leave you,\nwhatsoever years may bring.\nIf by earthly friends forsaken,\nstill more closely to Him cling!\r\nCovet not this world\'s vain riches,\nthat so rapidly decay.\nSeek to gain the heavenly treasures,\nthey will never pass away!\r\nWhen your journey is completed,\nif to God you have been true.\nFair and bright the home in glory,\nyour enraptured soul will view!', 'Die Zeit, sie rennt in großen Schritten,\nnichts auf Erden bleibt besteh\'n.\nBau\' dein Leben nur auf das, was hat Bestand,\nund halt dich fest an Gottes Hand.\r\nHalte fest an Gottes Hand!\nHalte fest an Gottes Hand!\nBau\' alle Hoffnung auf das Ewige,\nhalte fest an Gottes Hand!\r\nVertrau\' auf Ihn, der dich niemals verlässt,\nwas das Leben dir auch bringt.\nWenn dich jeder Freund auf Erden auch vergisst,\nSeine Treu bleibt dir gewiss.\r\n\r\n'),
(9, '0263', 'Die Zeiten kommen, Zeiten gehn  -  They come and go, the Seasons fair   (Wie wird es sein, wenn der König kommt)', 'They come and go, the seasons fair,\nand bring their spoil to vale and hills.\nBut oh! there is waiting in the air,\nand a passionate hope the spirit fills,\nwhy doth He tarry, the absent Lord?\nWhen shall the kingdom be restored,\nand earth and Heav’n, with one accord,\nring out the cry that the King comes?\r\nWhat will it be when the King comes!\nWhat will it be when the King comes!\nWhat will it be when He comes, when He comes!\nWhat will it be when the King comes!\r\nThe floods have lifted up their voice—\nThe King hath come to His own, His own!\nThe little hills and vales rejoice,\nHis right it is to take the crown.\nSleepers, awake, and meet Him first!\nNow let the marriage hymn outburst,\nand powers of darkness flee, dispersed:\nWhat will it be when the King comes!\r\nA ransomed earth breaks forth in song,\nhHer sin-stained ages overpast.\nHer yearning, Lord, how long, how long?\nExchanged for joy at last, at last!\nAngels carry the royal commands;\nPeace beams forth throughout all the lands;\nThe trees of the fields shall clap their hands:\nWhat will it be when the King comes!\r\nNow Zion’s hill, with glory crowned,\nuUplifts her head with joy once more.\nAnd Zion’s King, once scorned, disowned,\nextends her rule from shore to shore.\nSing, for the land her Lord regains!\nSing, for the Son of David reigns!\nAnd living streams o’erflow her plains:\nWhat will it be when the King comes!\r\nOh, brothers, stand as men that wait.\nThe dawn is purpling from the east,\nand banners wave from Heaven’s high gate.\nThe conflict now - but soon the feast!\nMercy and truth shall meet again.\nWorthy the Lamb that once was slain!\nWe can suffer now - He will know us then:\nWhat will it be when the King comes!', 'Die Zeiten kommen, Zeiten geh\'n,\nund durch des Sommers reichste Pracht\nzieht leise doch ein sehnend Fleh\'n,\nein heiß Verlangen ist erwacht.\nWas säumst Du, Herr, in Deinem Lauf?\nWann richtest denn Dein Reich Du auf,\ndass Erd\' und Himmel komm zu Hauf\'?\nO Jubelruf: Der König kommt!\r\nWie wird es sein, wenn der König kommt?\nWie wird es sein, wenn der König kommt?\nWie wird es sein, wenn Er kommt?\nWie wird es sein, wenn der König kommt?\r\nDie Wasserströme heben sich,\nder Ruf erbraust: "Der König kommt!"\nDurch Berg und Tal tönt´s mächtiglich,\ndass Ihm allein die Krone frommt.\nIhr Schläfer, auf und macht Ihm Bahn!\nIhr Sänger, hebt das Brautlied an!\nDie Finsternis ist abgetan!\nWie wird es sein, wenn der König kommt?\r\nHorch der erlösten Erde Sang\npreist den, der sie vom Fluch befreit;\nihr sehnsuchtsvolles: "Herr, wie lang?"\nverwandelt sich in Seligkeit.\nDie Engelsbotschaft widerhallt\nauf Berg und Hain, durch Flur und Wald,\nden Frieden kündend, sie erschallt:\nWie wird es sein, wenn der König kommt?\r\nZion gekrönt mit neuem Glanz,\ngeschmückt wie eine Braut sie steht;\nihr König, einst im Dornenkranz,\nregiert in Macht und Majestät.\nZu Seinem Land der König kehrt,\no Davids Sohn, sei hochverehrt!\nStrömt, Lebenswasser, unverwehrt!\nWie wird es sein, wenn der König kommt?\r\nO Brüder, steht auf Manneswacht!\nEs dämmert fern im Osten schon.\nHabt auf das Himmelsbanner acht,\nes naht der Kampf, doch auch die Kron\';\nGnade und Wahrheit geh\'n zuvor.\n"Würdig das Lamm !" erschallt´s im Chor.\nDurch Trübsal jetzt und dann empor!\nWie wird es sein, wenn der König kommt?'),
(9, '0264', 'Dient dem Herrn mit Freuden, das ist sein Geheiß   (Lobet unsern König freudig, preist und singt)', NULL, 'Dient dem Herrn mit Freuden, das ist Sein Geheiß,\nkommet, jauchzt und singet Ihm zum Preis.\nEr ist unser König, Er ist unser Gott,\nEr ist unser Stab in aller Not.\r\nLobet unsern König freudig, preist und singt,\ndient Ihm, alles Volk, und Ehr\' Ihm bringt,\nlasst uns Ihm vertrauen hier im Land der Zeit,\ndroben schau\'n wir Ihn in Herrlichkeit.\r\nDient dem Herrn mit Freuden, vor Sein Angesicht\nkommet mit Frohlocken, säumet nicht,\ndenn wir sind Sein Volk, das Er sich teu\'r erwarb,\nals für uns am Kreuze Jesus starb.\r\nHin zum frischen Wasser und zum grünen Rain\nführt Er wie ein Hirte was da Sein,\nbis der Lauf vollendet und in Gottes Hut\nselig Hirt\' und Herde droben ruht.'),
(9, '0265', 'Dies ist der Tag den der Herr gemacht  -  This is the Day that the Lord has made', 'This is the day, this is the day,\nthat the Lord has made, that the Lord has made.\nThis is the day, this is the day,\nthat the Lord has made.\nLet us rejoice and praise the Lord.\nLet us rejoice and praise the Lord.\nThis is the day, this is the day that the Lord has made.', 'Dies ist der Tag, dies ist der Tag,\nden der Herr gemacht, den der Herr gemacht.\nDies ist der Tag, dies ist der Tag,\nden der Herr gemacht.\nLasset uns freu\'n und fröhlich sein.\nLasset uns freu\'n und fröhlich sein.\nDies ist der Tag, dies ist der Tag, den der Herr gemacht.'),
(9, '0266', 'Dies ist die Abendzeit', NULL, 'II:Dies ist die Abendzeit,\ndies ist die Abendzeit.\nDie Braut macht sich bereit,\ndie Braut macht sich bereit.:II\r\nII:Bald werden wir ihn wiederseh\'n\nund mit Ihm nach Hause geh\'n.\nBald werden wir Ihn wiederse\'n,\nund mit Ihm nach Hause geh\'n.:II'),
(9, '0267', 'Dies ist die Abendzeit, der Tag ist nicht mehr fern  -  This is the evening time; it\'s later than you think   (Chorus)', 'This is the evening time, it\'s later than you think.\nThe Bride is perparing now for Her Lord to meet.\nAll things are ready now, the Bridegroom I hear.\nHe that hath an ear to hear: The evening time is here!', 'Dies ist die Abendzeit, der Tag ist nicht mehr fern,\ndie Braut macht sich jetzt bereit, zu treffen ihren Herrn\nAlles ist schon bereit, den Bräutigam ich hör!\nJa wer es hören kann: Die Abendzeit ist hier!'),
(9, '0268', 'Dies ist mein Gebot, dass ihr euch liebt einander  -  This is my Commandment that you love each other', 'This is my commandment that you love one another,\nthat your joy may be full.\nThis is my commandment that you love one another,\nthat your joy may be full.\nThat your joy may be full,\nthat your joy may be full.\nThis is my commandment that you love one another,\nthat your joy may be full.', 'Dies ist mein Gebot dass ihr euch liebt einander,\ndass die Freude völlig sei.\nDies ist mein Gebot dass ihr euch liebt einander,\ndass die Freude völlig sei.\nDass die Freude völlig sei,\ndass die Freude völlig sei.\nDies ist mein Gebot dass ihr euch liebt einander,\ndass die Freude völlig sei.'),
(9, '0269', 'Dies ist mein Verlangen, Dich preisen Herr  -  This is my Desire, to honour You', 'This is my desire to honour You.\nLord, with all my heart I worship You!\nAll I have within me I give You praise.\nAll that I adore is in You!\r\nLord, I give You my heart\nI give You my soul.\nI live for You alone.\nEvery breath that I take,\nevery moment awake.\nLord have your way in me.', 'Dies ist mein Verlangen, Dich preisen, Herr!\nDich mit vollem Herzen anbeten, Herr!\nAlles was in mir ist, das gibt Dir Ehr\'!\nAll\' was ich bewunder\' das bist Du!\r\n[: Herr, ich geb\' Dir mein Herz,\nund meine Seel\',\nich leb\' für Dich allein!\nJeden Atemzug,\njeden wachen Augenblick,\nHerr, wandle Du in mir. :]'),
(9, '0270', 'Dies sind die Tage Elias  -  These are the Days of Elijah   (Sieh, Er kommt, bald schon ist die Zeit, Wolken sind um Ihn)', 'These are the days of Elijah,\ndeclaring the Word of the Lord.\nAnd these are the days of Your servant, Moses,\nrighteousness being restored.\nAnd though these are days of great trial,\nof famine and darkness and sword,\nstill we are the voice in the desert crying\n"Prepare ye the Way of the Lord"\r\nBehold He comes riding on the clouds,\nshining like the sun at the trumpet call.\nLift your voice, it\'s the year of jubilee,\nout of Zion\'s hill salvation comes.\r\nThese are the days of Ezekiel,\nthe dry bones becoming as flesh.\nAnd these are the days of your servant, David,\nrebuilding a temple of praise.\nThese are the days of the harvest,\nthe fields are as white in world.\nAnd we are the lab\'rers in your vineyard,\ndeclaring the Word of the Lord.', 'Dies sind die Tage Elias,\ndas Wort Gottes ist voller Macht.\nUnd dies sind die Tage des Dieners Moses,\ndas Recht strahlt als Licht in die Nacht.\nUnd sind dies auch Tage voll Trübsal,\nso ist uns\'re Freude nicht fern.\nUnd wir stehen hier in der Wüste, rufen:\n"Verkündet das Kommen des Herrn!"\r\nSieh, Er kommt, bald schon ist die Zeit,\nWolken sind um Ihn,\nvoller Herrlichkeit.\nSingt es laut, dies ist das Jubeljahr,\nund aus Zion ist das Heil schon nah!\r\nDies sind die Tage Hesekiels,\nwo Gott alles Tote belebt.\nUnd dies sind die Tages des Dieners David,\nwo Lobpreis den König erhebt.\nUnd dies sind die Tage der Ernte,\ndie Felder sind reif für den Herrn.\nUnd wir wirken mit an dem Werk des Meisters,\nerheben das Wort uns\'res Herrn!'),
(9, '0271', 'Diese Welt kann mich nicht halten  -  This old World can never hold me   (Chorus)', 'This old world can never hold me,\nany moment I\'ll be gone.\nFor I\'ve made my consecration,\nand I have my wedding garment on.', 'Diese Welt kann mich nicht halten,\naugenblicklich werd\' ich geh\'n.\nDie Entscheidung ist getroffen,\nund das Brautkleid trage ich schon hier.'),
(9, '0272', 'Dieses kleine Licht in mir  -  This little Light of mine', 'This little light of mine, I\'m gonna let it shine.\nThis little light of mine, I\'m gonna let it shine.\nThis little light of mine, I\'m gonna let it shine.\nLet it shine, let it shine, let it shine.\r\nHide it under a bushel (no!)\nI’m gonna let it shine.\nHide it under a bushel, (no!)\nI’m gonna let it shine.\nHide it under a bushel, (no!)\nI’m gonna let it shine.\nLet it shine, let it shine, let it shine.\r\nDon’t let Satan blow it out (no!)\nI’m gonna let it shine.\nDon’t let Satan blow it out (no!)\nI’m gonna let it shine.\nDon’t let Satan blow it out (no!)\nI’m gonna let it shine.\nLet it shine, let it shine, let it shine.\r\nLet it shine ’til Jesus comes, (yes!)\nI’m gonna let it shine.\nLet it shine ’til Jesus comes, (yes!)\nI’m gonna let it shine.\nLet it shine ’til Jesus comes, (yes!)\nI’m gonna let it shine.\nLet it shine, let it shine, let it shine.', 'Dieses kleine Licht in mir, ich will dass es scheint.\nDieses kleine Licht in mir, ich will dass es scheint.\nDieses kleine Licht in mir, ich will dass es scheint.\nDass es scheint, dass es scheint, dass es scheint.\r\n\r\n\r\n'),
(9, '0273', 'Dir fehlt wohl noch der Friede, dein Herz ist freudenleer   (O dass du könntest glauben, du würdest Wunder sehn)', NULL, 'Dir fehlt wohl noch der Friede?\nDein Herz ist freudenleer,\ndein Auge blickt so müde,\ndein Gang ist matt und schwer.\r\nO dass du könntest glauben!\nDu würdest Wunder seh\'n,\nes würde dir dein Jesus\nall\'zeit zur Seite steh\'n!\r\nJa, nur bei Ihm ist Friede\nund Trost in allem Schmerz\nfürs arme, kranke, müde\nund sorgenvolle Herz.\r\nDenn nur aus Seinen Wunden\nquillt für die Seele Heil;\nwer ihn noch nicht gefunden,\ndem fehlt das beste Teil.\r\nDu ringst mit deinen Sünden\nund weißt nicht aus noch ein,\ndu kannst nicht Ruhe finden\nin deiner Angst und Pein.\r\nUnd fragst du: "Was ist Wahrheit?",\nweil du im Zweifel bist,\nso bitte Den um Klarheit,\nder selbst die Wahrheit ist.'),
(9, '0274', 'Dir folg ich, Jesus, in die Flut, Du gingst mir einst voran', NULL, 'Dir folg\' ich, Jesus, in die Flut,\nDu gingst mir einst voran,\nDu tilgtest meine Schuld im Blut,\ndass ich Dir folgen kann.\nVersiegle Deinem Eigentum\nden sel\'gen Friedensbund,\nbestrahle hell zu Deinem Ruhm\nmein Herz in dieser Stund\'!\r\nO, welche Freude, welches Glück\nwird heute mir zuteil!\nIch darf mit frohem Kindesblick\nDir folgen, Dir, mein Heil!\nIn Liebe und in Dankbarkeit\nbetret\' ich Deinen Pfad;\nDu wirst mich führen allezeit\nnach Deinem Gnadenrat.\r\nDein bitt\'rer Tod, Dein Aufersteh\'n\nist meines Glaubens Grund!\nAuf diesem Felsen bleib\' ich steh\'n,\nes spricht Dein heil\'ger Mund:\nWer gläubig ist und wird getauft,\nsoll ewig selig sein!\nDu hast so teuer mich erkauft –\nIch bin und bleibe Dein!'),
(9, '0275', 'Dir Gebührt die Ehre und Anbetung  -  You deserve the Glory and the Honor   (2 Chorusse)', 'You deserve the glory and the honor.\nLord we lift our hands to worship\nLord we lift your holy name  (2x)\r\nFor you are great\nYou do miracles so great\nthere is no one else like you\nthere is no one else like you   (2x)', 'Dir gebührt die Ehre und Anbetung.\nWir erheben uns\'re Hände,\nwir erheben Deinen Nam\'.    (2x)\r\nDenn Du bist groß,\nDu tust große Wunder, groß.\nNiemand anders ist wie Du,\nniemand anders ist wie Du.   (2x)'),
(9, '0276', 'Dir zur Verfügung, mein Gott und mein Herr', NULL, 'Dir zur Verfügung, mein Gott und mein Herr!\nDir zur Verfügung, je länger, je mehr!\nDir zur Verfügung in Freud\' und in Leid\ntäglich und stündlich für Jesus bereit.\r\nDir zur Verfügung! Einst war es nicht so,\naber nun bin ich so selig und froh.\nDu brachest Ketten und Bann mir entzwei,\nauf dass ich völlig Dein Eigentum sei.\r\nDir zur Verfügung! O seliges Los,\nsei nun mein Tagewerk klein oder groß;\ndraußen und drinnen im Schaffen und Ruh\'n\nimmer nur fragen, was würd\' Jesus tun.\r\nDir zur Verfügung! Es bleibe dabei!\nDas ist ein Stand, der macht selig und frei.\nDas schafft ein sieghaft\' und friedevoll\' Geh\'n,\nJesus, Dir ganz zur Verfügung zu steh\'n!'),
(9, '0277', 'Dir, Dir, Jehova, will ich singen, denn wo ist doch ein solcher Gott wie du', NULL, 'Dir, Dir, Jehova, will ich singen;\ndenn wo ist doch ein solcher Gott wie du?\nDir will ich meine Lieder bringen.\nAch, gib mir Deines Geistes Kraft dazu,\ndass ich es tu im Namen Jesu Christ,\nso wie es Dir durch Ihn gefällig ist.\r\nZieh mich, o Vater, zu dem Sohne,\ndamit Dein Sohn mich wieder zieh zu Dir;\nDein Geist in meinem Herzen wohne\nund meine Sinne und Verstand regier\';\ndass ich den Frieden Gottes schmeck\'\nund fühl\' und Dir fortan im Herzen\nsing und spiel\'.\r\nVerleih mir, Höchster, solche Güte,\nso wird gewiss mein Singen recht getan;\nso klingt es schön in meinem Liede,\nund ich bet\' Dich in Geist und Wahrheit an;\nso hebt Dein Geist mein Herz zu Dir empor,\ndass ich Dir Psalmen sing im höher\'n Chor.\r\nWas mich Dein Geist selbst bitten lehret,\ndas ist nach Deinem Willen eingericht\'\nund wird gewiss von Dir erhöret,\nweil es im Namen Deines Sohns geschieht,\ndurch welchen ich Dein Kind und Erbe bin\nund nehme von Dir Gnad\' um Gnade hin.\r\nWohl mir, dass ich dies Zeugnis habe;\nd\'rum bin ich voller Trost und Freudigkeit\nund weiß, dass alle gute Gabe,\ndie ich von Dir verlange jederzeit,\ndie gibst Du und tust überschwänglich mehr,\nals ich verstehe, bitte und begehr\'!'),
(9, '0278', 'Do you hear them coming, Brother, thronging up the Steeps of Light   (\'Tis a glorious Church without Spot or Wrinkle)', 'Do you hear them coming, brother,\nthronging up the steeps of light.\nGlad in glorious shining garments,\nbloodwashed, garments pure and white?\r\n\'Tis a glorious church without spot or wrinkle,\nwashed in the blood of the Lamb.\n\'Tis a glorious church without spot or wrinkle,\nwashed in the blood of the Lamb.\r\nDo you hear the stirring anthems,\nfilling all the earth and sky.\n\'Tis a grand victorious army,\nlift its banner up on high!\r\nNever fear the clouds of sorrow,\nnever fear the storms of sin.\nWe shall triumph on the morrow,\neven now our joys begin.\r\nWave the banner, shout His praises,\nfor our victory is nigh!\nWe shall join our conquering Saviour,\nwe shall reign with Him on high!\r\n\'Tis a glorious church and I am a member,\nwashed in the blood of the Lamb.\n\'Tis a glorious church and I am a member,\nwashed in the blood of the Lamb.', NULL),
(9, '0279', 'Don\'t be afraid', '"Don\'t be afraid, my love is stronger,\nmy love is stronger than your fear,\ndon\'t be afraid, my love is stronger,\nand I have promised,\npromised to be always near!"\r\nI\'m not afraid, your love is stronger,\nyour love is stronger than my fear,\nI\'m not afraid, your love is stronger,\nand you have promised,\npromised to be always near!\r\nI\'m not afraid, Your Name is greater\nthan any trouble that I know,\nI\'m not afraid, Your Name is greater,\nmy Jesus, Saviour, Healer\nand my Comforter!', '"Fürchte dich nicht, denn meine Liebe,\nsie ist viel größer als die Not,\nfürchte dich nicht, in meiner Liebe\nhab\' ich dir versprochen:\nIch bin dir ein naher Gott!"\r\nIch fürcht mich nicht, denn deine Liebe,\nsie ist viel größer als die Not,\nich fürcht mich nicht, in deiner Liebe\nhast du mir versprochen:\nDu bist mir ein naher Gott!\r\nIch fürcht\' mich nicht, in Deinem Namen\nist mir die Freiheit voll geschenkt,\nich fürcht\' mich nicht, in Deinem Namen,\nmein Jesus, ist die Kraft des Höchsten\nunbeschränkt!'),
(9, '0280', 'Dort auf Golgatha stand einst ein altrauhes Kreuz  -  On a Hill far away stood an old rugged Cross   (Schätzen werd ich das altrauhe Kreuz)   [Jesu Name Band 2]', 'On a hill far away stood an old rugged cross,\nthe emblem of suffering and shame.\nAnd I love that old cross where the dearest and best\nfor a world of lost sinners was slain.\r\nSo I\'ll cherish the old rugged cross,\ntill my trophies at last I lay down.\nI will cling to the old rugged cross,\nand exchange it some day for a crown.\r\nO that old rugged cross, so despised by the world,\nhas a wondrous attraction for me.\nFor the dear Lamb of God left his glory above\nto bear it to dark Calvary.\r\nTo that old rugged cross I will ever be true,\nits shame and reproach gladly bear.\nThen He\'ll call me some day to my home far away,\nwhere His glory forever I\'ll share.', 'Dort auf Golgatha stand einst ein altrauhes Kreuz,\nstets ein Sinnbild von Leiden und Weh.\nDoch ich liebe das Kreuz, denn dort hing einst der Herr,\nund in Ihm ich das Gotteslamm seh\'.\r\nSchätzen werd\' ich das altrauhe Kreuz,\nbis ich Jesum erblick\' auf dem Thron.\nIch will halten mich fest an dem Kreuz,\neinst erhalt\' ich dafür eine Kron\'.\r\nDieses altrauhe Kreuz, von der Welt so verhöhnt,\nzieht mich wunderbar mächtiglich an.\nHat doch dort Gottes Lamm, das vom Thron zu uns kam,\nfür uns Sünder genüge getan.\r\nDiesem altrauhen Kreuz bleib auf immer ich treu,\ntrage williglich Schande und Hohn.\nEinstens ruft Er mich heim, wo ich ewig darf schau\'n\nSeine Herrlichkeit vor Gottes Thron.'),
(9, '0281', 'Dort in dem Garten Gethsemane rang unser Jesus voll Leid und Weh   (Jesus ist Sieger über den Tod)', NULL, 'Dort in dem Garten Gethsemane\nrang unser Jesus voll Leid und Weh.\nBlutstropfen fielen, der Kampf war schwer,\ndie Jünger schliefen, allein war der Herr.\r\nJesus ist Sieger, über den Tod,\nJesus ist Sieger, bricht alle Not.\nJesus ist Sieger, in Ewigkeit,\nfür mich hat Jesus den Sieg schon bereit.\r\nSein Kreuz trug Jesus nach  Golgatha,\num dich zu retten litt Er allda;\nund stehst du heute in dunkler Nacht:\nHör, Jesus rufet: "Es ist schon vollbracht!"\r\nWeißt du, was heute noch Wunder tut?\nNur unser\'s Heilands kostbares Blut!\nAuch wenn die Hölle und Erde bebt,\nglaub dieser Botschaft, denn Jesus, Er lebt!\r\nUnd kommt noch heute der Tod heran,\nkannst du es glauben, was Er getan?\nJesus, dein Heiland, Er liebt dich noch,\nkomm, fasse Mut nur und glaube es doch!\r\nJesus ist Sieger, über die Welt,\nJesus ist Sieger, der dich erhält.\nO werde Sieger, täglich in mir,\nJesus mein Heiland ich weihe mich Dir.'),
(9, '0282', 'Dort ist ein Strom, so glänzend wie Kristall (There came a Sound from Heaven like a rushing, mighty Wind)', 'There came a sound from heaven like a rushing, mighty wind,\nit filled their hearts with singing, and gave them peace within.\nThe prophet gave the promise, the Spirit will descend,\nand from your inner being, a river with no end.\r\nThere is a river, that flows from deep within,\nthere is a fountain that frees the soul from sin.\nCome to these waters, there is a vast supply.\nThere is a river, that never shall run dry.\r\nThere was a thirsty woman, who was drawing from a well,\nher life was ruined and wasted, her soul was bound for hell.\nThen she met the Master, Who told of her great sin,\nand if you drink this water, you shall never thirst again!\r\nThere is a river, that flows from God above.\nThere is a fountain, that\'s filled with God\'s great love.\nCome to this water, there is a vast supply,\nthere is a river, that never shall run dry!', '\r\nDort ist ein Strom, so glänzend wie Kristall,\nWasser des Lebens strömet, vom Throne Gottes dem Lamm.\nKomm zu dem Wasser und trinke umsonst dich satt;\nkomm zum Quell des Lebens, der Heil und Errettung schafft!\r\n\r\n'),
(9, '0283', 'Down here we toil struggling to sail   (But there is a Place called Heaven)', 'Down here we toil, struggling to sail\non this troubled sea of life.\nWe meet foes, we make friends,\ntogether we enjoy fellowship.\nBut one by one we miss out.\nPerharps we\'ll never meet again on this side.\nIt give us inward pain when we part.\r\n(But) There is a place called heaven.\nThere is a land called heaven.\nIt\'s a dimension called heaven.\nFull of peace, joy and love.\nAnd someday soon we will be gone\nto meet the saints of all ages.\nThere\'ll be no parting, there\'ll be no crying.\nMy friend will you be there?\n(Friend I\'ll be looking for you)\r\nWalking one day, down the road I\'ll see\nsaints who slept in the Holy Ghost.\nI\'ll see Brother Branham,\nI\'ll see Brother Bosworth,\nReady in the rapture to go.\nStep by step we will count down.\nNothing here on earth shall hold me down.\nIn the twinkling of an eye we\'ll be gone!', NULL),
(9, '0284', 'Down the Valleys, up the Mountains   (Chorus)', 'We’re going down the valley, up the mountain, Jerusalem is my home.\nWe’re going down the valley, up the mountain, Jerusalem is my home.\nIt’s my home, sweet home, Jerusalem is my home.\nIt’s my home, sweet home, Jerusalem is my home.', NULL),
(9, '0285', 'Drohn auch in finstrer Sündennacht die Wetterwolken schwer  -  Though dark the Night and Clouds look black and Stormy overhead   (Ein Blick auf Jesus macht mein Herze still, so still)', 'Though dark the night, and clouds look black and stormy overhead,\nand trials of almost ev’ry kind across my path are spread.\nHow soon I conquer all, as to the Lord I call:\nA little talk with Jesus makes it right, all right!\r\nA little talk with Jesus makes it right, all right!\nA little talk with Jesus makes it right, all right!\nIn trials of ev’ry kind, praise God, I always find\na little talk with Jesus makes it right, all right!\r\nWhen those who once were dearest friends begin to persecute,\nand more who once profess’d to love vave distant grown, and mute,\nI tell Him all my grief, He quickly sends relief:\nA little talk with Jesus makes it right, all right!\r\nAnd thus, by frequent little talks, I gain the victory,\nand march along with cheerful song, enjoying liberty.\nWith Jesus as my Friend, I’ll prove unto the end.\nA little talk with Jesus makes it right, all right!', 'Droh\'n auch in finst\'rer Sündennacht die Wetterwolken schwer,\nund braust der Stürme wilde Macht verheerend um mich her,\nso ist mir doch nicht bang, bleibt auch der Retter lang\';\nein Blick auf Jesus macht mein Herze still, so still.\r\nEin Blick auf Jesus macht mein Herze still, so still.\nEin Blick auf Jesus macht mein Herze still, so still.\nBin ich auch oft verzagt und seufzt mein Herz und klagt,\nein Blick auf Jesus macht mein Herze stillt, so still.\r\nWenn meine Lieben ferne steh\'n und Freunde mich verschmäh\'n,\nwenn die, die mir die Nächsten sind, an mir vorübergeh\'n,\ndann klag ich Ihm mein Leid, so wandelt Er\'s in Freud;\nein Blick auf Jesus macht mein Herze still, so still.\r\nSo zieh ich froh durch Kampf und Streit gerüstet meine Bahn;\nmich zieht ein stilles Sehnen hin nach jenem Kanaan.\nUnd kommt dann auch der Tod, so hat es keine Not,\nein Blick auf Jesus macht mein Herze still, so still.'),
(9, '0286', 'Drunten im Tale, wo die Stillen Wasser ziehn  -  Down in the Valley with my Saviour I will go   (Ich will folgen, Jesus ich will folgen)', 'Down in the valley with my Saviour I will go,\nwhere the flow’rs are blooming and the sweet waters flow.\nEverywhere He leads me I will follow, follow on,\nwalking in His footsteps till the crown be won.\r\nFollow! follow! I will follow Jesus!\nAnywhere, everywhere, I will follow on!\nFollow! follow! I will follow Jesus!\nEverywhere He leads me I will follow on!\r\nDown in the valley with my Saviour I will go,\nwhere the storms are sweeping and the dark waters flow.\nWith His hand to lead me I will never, never fear,\ndanger cannot fright me if my Lord is near.\r\nDown in the valley, or upon the mountain steep,\nclose beside my Saviour will my soul ever keep.\nHe will lead me safely in the path that He has trod,\nup to where they gather on the hills of God.', 'Drunten im Tale, wo die Stillen Wasser zieh\'n,\ngrüne Auen sprießen, und Blümelein blüh\'n,\nwenn mich Jesus dahin führet, folg\' ich froh Ihm nach,\ngehe still an Seiner Seite Tag für Tag.\r\nIch will folgen, Jesus will ich folgen.\nÜberall, allezeit, folg\' ich Jesus nach.\nIch will folgen, Jesus will ich folgen,\nüberall und allezeit, ja Tag für Tag.\r\nDrunten im Tale, wo die zack\'gen Felsen steh\'n,\nwilde Bäche stürzen und Sturmwinde weh\'n,\nwill mich Jesus dahin führen, folgt auch da mein Schritt,\ndenn kein Unheil fürchte ich, geht Jesus mit.\r\nDrunten im Tale oder auf den sonn\'gen Höh\'n,\nfolge ich, wo immer seine Fußstapfen geh\'n.\nJesus führt mich treu, wie Er mich stets geführet hat,\nbringt mich endlich in die gold\'ne Gottesstadt.'),
(9, '0287', 'Du allein bist würdig, Herr! Du allein bist heilig, Herr!', NULL, 'Du allein bist würdig, Herr!\nDu allein bist heilig, Herr!\nDu allein bist wunderbar,\nSiegesheld von Golgatha.\nDeine Kraft, Herr, brauchen wir,\nDeine Reinheit, Deine Zier;\nlass uns, Herr, Dein Antlitz seh\'n,\nwenn vor Dir wir betend steh\'n.'),
(9, '0288', 'Du bist bei mir', NULL, 'Jesus, Dein Name macht mir Mut,\nJesus, mit Dir wird alles gut,\nJesus, Du Helfer in der Not,\nJesus, Du ewig treuer Gott!\r\nDu bist bei mir, bei mir,\nDu bist mir so nah, immer für mich da,\nDu bist bei mir, bei mir,\nniemals bist du weit, immer hast Du Zeit,\njeden Tag!\r\nJesus, ich weiß, dass Du mich liebst,\nJesus, und dass Du mich umgibst,\nJesus, selbst in dem fernsten Land,\nJesus, wäre ich in Deiner Hand!\r\nJesus, Du weißt, was mich bewegt,\nJesus, und Deine Liebe trägt,\nJesus, am Ende dieser Welt,\nJesus, weiß ich doch, Wer mich hält!\r\nJesus, weil Du gut zu mir bist,\nJesus, und Du mich nie vergisst,\nJesus, habe ich aus Dankbarkeit,\nJesus, mein Leben Dir geweiht!'),
(9, '0289', 'Du bist der Hirte, Du willst mein Leben leiten', NULL, 'Du bist der Hirte,\nDu willst mein Leben leiten.\nDu bist der Herr, der\nMich annimmt jederzeit.\nDu bist die Zuflucht,\nwenn Sorgen mich begleiten.\nDu bist mein Felsen\nund meine Sicherheit.\r\nDu bist das Licht, kannst\ndie Dunkelheit erhellen.\nDu bist der Retter,\nbefreist von meiner Schuld.\nDu bist allwissend,\nich brauch mich nicht verstellen.\nDu bist mir treu, hast\nunendlich viel Geduld.\r\nDu bist der einzig wahre\nund wunderbare Gott.\nEs gibt niemand neben Dir.\nDu bist ganz unbeschreiblich\nund so unendlich groß.\nAlles kommt von Dir.\nDu lädst mich zu Dir ein\nund willst ein Vater für mich sein.\r\nDu bist die Wahrheit,\nerzählst uns keine Lügen.\nDu bist der Schöpfer,\nhast alles gut gemacht.\nDu bist gerecht und\nwirst mich niemals betrügen.\nDu bist mein Schutz, gibst\nauf meine Wege Acht.\r\nDu bist mein Freund, willst\nmit mir durchs Leben gehen.\nDu bist die Burg, wenn\ndie Angst mich überfällt.\nDu bist voll Mitleid\nund kannst mich gut verstehen.\nDu bist der Helfer,\nder in der Not mich hält.\r\nMit off\'nen Armen stehst du da.\nDurch Jesus kamst Du mir so nah.\nDu breitest deine Hände aus.\nDu bist die Liebe,\nführst mich zu Dir nach Haus.'),
(9, '0290', 'Du bist des Lebens wahre Quelle   (Gott, lass mich immer Heimweh haben)', NULL, 'Du bist des Lebens wahre Quelle,\nsprichst Du ein Wort, so wird es licht;\nbist Du mein Führer hier auf Erden,\ngeh ich getrost und irre nicht.\nDoch ohne Dich, geliebter Heiland,\nbrächt\' mir das Schönste kein\' Gewinn.\r\nGott, lass mich immer Heimweh haben,\nwenn ich nicht nahe bei Dir bin!\nJa, lass mich immer Heimweh haben,\nwenn ich nicht nahe bei Dir bin!\r\nGing ich auf viel bewegten Straßen,\nhätt\' liebe Menschen um mich her,\nsie könnten Dich, Herr, nicht ersetzen,\nes bliebe doch im Herzen leer.\nEs hätte ohne Dich, mein Leben\nim tiefsten Grunde keinen Sinn.\r\nUnd hätt\' ich alles, was ich wünschte,\nund schien mein Leben voller Glück\nund käm\' Versuchung gar, käm\' Leiden,\nzu wem erhöb\' ich dann den Blick?\nWo eilt\' mit meinen tiefsten Schmerzen,\nmit der verborg\'nen Not ich hin?\r\nSo will ich geh\'n an Deiner Seite,\nverbunden Deinem Kreuzpanier,\ndurch lichte und durch trübe Tage,\nHerr Jesu, ich gehöre Dir!\nUnd leise klingt\'s in meinem Herzen\nund lenkt den Blick zur Heimat hin:\r\nJa, du sollst immer Heimweh haben,\nwenn ich nicht nahe bei Dir bin!\nJa, du sollst immer Heimweh haben,\nwenn ich nicht nahe bei Dir bin!'),
(9, '0291', 'Du bist die Kraft die mir oft fehlt  -  You are my Strength when I am weak   (Jesus, Gottes Lamm, Ehre Deinem Namen)', 'You are my strength when I am weak,\nYou are the treasure that I seek,\nYou are my all in all.\nSeeking You as a precious jewel,\nI want the Holy Ghost to rule,\nYou are my all in all.\r\nJesus, Lamb of God, worthy is Your name,\nJesus, Lamb of God, worthy is Your name!\r\nTaking my sin, my cross, my shame,\nRising again, I bless Your name.\nYou are my all in all.\nWhen I fall down, You pick me up,\nWhen I am dry, You fill my cup,\nYou are my all in all.', 'Du bist die Kraft, die mir oft fehlt,\nDu bist der Wert, der wirklich zählt.\nAlles bist Du mir, Herr.\nFalle ich hin, stehst Du mir bei,\nstillst meinen Durst und sprichst mich frei.\nAlles bist Du mir, Herr!\r\nJesus, Gottes Lamm, Ehre Deinem Namen\nJesus, Gottes Lamm, Ehre sei Dir, Herr!\r\nBei aller Last von Schuld und Scham\nlobe ich Dich, der mir sie nahm.\nAlles bist Du mir, Herr.\nDich, meinen Retter, meinen Herrn,\nlobe ich für mein Leben gern.\nAlles bist Du mir, Herr.'),
(9, '0292', 'Du bist ein wunderbarer Hirt   (Ich komm, ich komm an Deinen Tisch)   (Psalm 23)', NULL, 'Du bist ein wunderbarer Hirt\',\nder mich zu frischem Wasser führt.\nDu hast so reich gedeckt\ndes Königs Tisch für mich, für mich.\r\nIch komm, ich komm an Deinen Tisch.\nIch komm, ich komm und ich bin gewiss,\nDu bist mein wunderbarer Hirt\'.\r\nDu bist mein Stecken und mein Stab,\nund wand\'re ich im finst\'ren Tal,\nfürcht\' ich kein Unheil mehr,\ndenn Du bist hier bei mir, bei mir.\r\nDu hast mein Haupt gesalbt mit Öl,\nden Becher bis zum Rand gefüllt.\nIch weiß an Deiner Hand wird\nmeine Seele still, ganz still.'),
(9, '0293', 'Du bist groß (Danke, Jesus)', NULL, 'Danke, Jesus,\ndass Du mich nicht vergisst,\ndass Du mein Retter bist,\ndanke, Jesus,\ndass Du mich nicht vergisst,\ndass Du mein Heiler bist,\nich bet\' Dich an, ich bet\' Dich an!\r\nDu bist groß, so groß,\nein Gott, der Wunder tut,\nund Du machst alles gut,\ngroß, so groß,\nwer Deinem Wort vertraut,\nder hat auf Fels gebaut.\r\nGroß, so groß,\nHerr,  keine Mauer ist\nmir noch ein Hindernis,\ngroß, so groß,\nHerr,  wenn der Feind Dich sieht,\nmacht er sich auf und flieht!'),
(9, '0294', 'Du bist mein Gott! Ich will Dich frei bekennen', NULL, 'Du bist mein Gott!\nIch will Dich frei bekennen:\nDu bist und bleibst mein Gott!\nNichts soll mich von Dir trennen,\nnicht Leid, nicht Not, nicht Spott.\nIch möchte Deinen Ruhm vermehren\nund Dich von ganzem Herzen ehren.\nDu bist mein Gott, Du bleibst mein Gott!\r\nDu bist mein Herr!\nDir will ich freudig dienen.\nDu bist und bleibst mein Herr!\nSeit Du mir bist erschienen,\nweiß ich von keinem mehr.\nDich will ich immer lassen walten\nund Deinem Winke stille halten;\nDu bist mein Herr, Du bleibst mein Herr!\r\nDu bist mein Hirt\'!\nO Herr, Du sollst mich führen.\nDu bist und bleibst mein Hirt.\nDank Dir, ich darf es spüren,\ndass mir nichts mangeln wird.\nDu weidest mich auf grünen Auen:\nWie sollte ich Dir nicht vertrauen.\nDu bist mein Hirt\', Du bleibst mein Hirt\'!\r\nDu bist mein Teil,\no Herr, spricht meine Seele,\nDu bist und bleibst mein Teil.\nWenn ich nur Dich erwähle,\nblüht mir ein volles Heil.\nUnd ginge es durch Todesschatten,\nDu lässt mich dort doch nicht ermatten.\nDu bist mein Teil, Du bleibst mein Teil!\r\nDu bist genug!\nMich hält nichts mehr gebunden,\nDu bist und bleibst genug.\nIch habe Dich gefunden.\nDas andre ist nur Trug.\nNun kann ich still zum Himmel wallen\nund lasse froh Dein Lob erschallen.\nDu bist genug, Du bleibst genug!'),
(9, '0295', 'Du bist mein Hirte, willst mich führen  -  You make me lie down in green Pastures', 'You make me lie down in green pastures.\nYou make me wanting for nothing.\nYou fill my hunger with honey from your sweet sweet word.\nYou let me worship before You.\nSo I will love You and adore You.\nYou are my Shepherd, You are my Jesus, You are my Lord.', 'Du bist mein Hirte, willst mich führen.\nIch darf die Liebe von Dir spüren.\nDu stillst den Hunger mit Honig Deines Wortes, Herr.\nAn Deinem Tische darf ich speisen,\ndafür will ich Dich heute preisen.\nDu bist mein Hirte, Du bist mein Jesus, Du bist mein Gott.'),
(9, '0296', 'Du bist mein Zufluchtsort  -  You are my hiding Place', 'You are my hiding place.\nYou always fill my heart\nwith songs, of deliverance,\nwhen ever I am afraid,\nI will trust in You,\nI will trust in You.\nLet the weak say: I am strong\nin the strength of the Lord.', 'Du bist mein Zufluchtsort,\nich berge mich in Deiner Hand,\ndenn Du schützt mich Herr,\nwann immer mich Angst befällt\ntraue ich auf Dich,\nja, ich trau auf Dich.\nUnd ich sage, ich bin stark\nin der Kraft meines Herrn.'),
(9, '0297', 'Du bist weit mehr für mich als die ganze Welt   (Chorus)', NULL, 'Du bist weit mehr für mich als die ganze Welt.\nWo bleibt da all ihr Glanz in Dein Licht gestellt?\nIn Deiner großen Lieb\' hast Du mich erwählt,\nd\'rum bist Du mehr für mich als die ganze Welt.'),
(9, '0298', 'Du bist würdig um zu nehmen das Buch und die Siegel aufzutun', NULL, 'Du bist würdig um zu nehmen das Buch\nund die Siegel aufzutun,\nhast mit Deinem teuren Blut erkauft aus jedem Volk,\nNation und jedem Land.\nHalleluja, Halleluja, teuer erkauft durch Jesu Blut.\nHalleluja, Halleluja, bin erkauft durch Jesu Blut.'),
(9, '0299', 'Du bist würdig, Du bist würdig, o Herr  -  Thou art worthy, Thou art worthy, oh Lord', 'Thou art worthy,\nThou art worthy,\nThou art worthy, oh Lord.\nThou art worthy\nto receive glory and honour and praise.\r\nFor Thou hast created, hast all things created.\nThou hast created all things,\nand for Thy pleasure they are created.\nThou art worthy O Lord.', 'Du bist würdig,\nDu bist würdig,\nDu bist würdig, o Herr.\nDu bist würdig,\nvon uns zu nehmen Preis und Ehre und Dank.\r\nDenn Du schufst das All und aus Dir kam das Leben.\nIn Dir ist die Fülle, die Kraft.\nDu nur bist würdig, von uns zu nehmen\nPreis und Ehre und Dank.'),
(9, '0300', 'Du bist würdig, großer Jehova  -  Thou art worthy, great Jehovah   (Chorus)', 'Thou art worthy, great Jehovah,\nThou art worthy, mighty God,\nThou art worthy, Abba Father,\nThou art worthy, Lamb of God.', 'Du bist würdig, großer Jehova,\nDu bist würdig, mächtiger Gott,\nDu bist würdig, Abba Vater,\nDu bist würdig, Lamm von Gott.'),
(9, '0301', 'Du bist würdig, o mein Gott; Herr allmächtig, und ich preise Dich', NULL, 'Du bist würdig, o mein Gott;\nHerr allmächtig, und ich preise Dich;\nDir allein gilt Preis und Ehr\'.\nHerr ich liebe Dich, und anbete Dich,\nDu bist würdig, oh, mein Gott;\nDu bist würdig, Du bist würdig,\nDir allein gilt Preis und Ehr\'.'),
(9, '0302', 'Du denkst zuviel an morgen,quälst dich mit deinen Sorgen   (Ich bin bei dir, kein\' Augenblick bist du allein)', NULL, 'Ich bin bei dir,\nkein\' Augenblick bist du allein!\nVertraue Mir,\ndann kehrt in dir bald Ruhe ein!\nWirf zu Mir her,\nwas dich beschwert und was dich lähmt.\nIch bin Dein Gott,\nder dich und deine Nöte kennt!\r\nDu denkst zuviel an morgen,\nquälst dich mit deinen Sorgen!\nKomm, lebe heut\' an diesem Tag!\nIch will dir immer helfen!\nWerd\' an deiner Seite kämpfen!\nJetzt hör Mir zu, was ich Dir sag!\r\nIn dir sind viele Fragen,\ndie auf eine Antwort warten.\nKomm hab Geduld, leb\' diesen Tag!\nBerg dich in Meinen Händen!\nIch will dir Vertrauen schenken!\nUnd hör Mir zu, was ich dir sag!'),
(9, '0303', 'Du gibst den Worten Bedeutung  -  You are the Words to the Music', 'You are the words to the music,\nYou are the song that I sing.\nYou are the melody,\nYou are the harmony,\npraise to your name I will bring.\r\nYou are the mighty God,\nYou are the Lord of Lords,\nYou are the King of all Kings.\nNow I return to you\nthe song that you gave to me,\nYou are the song that I sing.', 'Du gibst den Worten Bedeutung,\nDu bist das Lied, das ich sing\'.\nDu bist die Melodie,\nDu bist die Harmonie,\nPreis Deinem Namen ich bring\'.\r\nDu bist der Mächtige,\nDu bist der Herr der Herr\'n,\nDu bist mein König allein.\nDu gabst mir dieses Lied,\nich geb\' es Dir zurück,\nDu bist das Lied, das ich sing\'.'),
(9, '0304', 'Du großer Gott, wenn ich die Welt betrachte  -  O Lord my God, when I in awesome Wonder   (Dann jauchzt mein Herz Dir großer Herrscher zu)', 'Oh Lord my God, when I in awesome wonder,\nconsider all the worlds Thy hands have made.\nI see the stars, I hear the might thunder,\nThy pow\'r throughout the universe displayed:\r\nThen sings my soul, my Saviour God to Thee.\nHow great Thou art, how great Thou art!\nThen sings my soul, my Saviour God to Thee.\nHow great Thou art, how great Thou art!\r\n\r\n\r\n\r\nWhen through the woods, and forest glades I wander\nand hear the birds, sing sweetly in the trees,\nwhen I look down, from lofty mountain grandeur,\nand hear the brook and feel the gentle breeze.\r\nAnd when I think that God His Son not sparing,\nsent Him to die, I scarce can take it in.\nThat on the cross, my burden gladly bearing,\nHe bled and died, to take away my sin.\r\nWhen Christ shall come with shout of acclamation\nand take me home, what joy shall fill my heart.\nThen I shall bow in humble adoration\nand there proclaim, my God, how great Thou art!', 'Du großer Gott, wenn ich die Welt betrachte,\ndie Du geschaffen durch Dein Allmachtswort.\nWenn ich auf alle jene Wesen achte,\ndie Du regierst und nährest fort und fort.\r\nDann jauchzt mein Herz Dir großer Herrscher zu.\nWie groß bist Du, wie groß bist Du!\nDann jauchzt mein Herz Dir, großer Herrscher, zu.\nWie groß bist Du, wie groß bist Du!\r\nBlick\' ich empor zu jenen lichten Welten\nund seh\' der Sterne unzählbare Schar,\nwie Sonn\' und Mond im lichten Äther zelten\ngleich goldnen Schiffen, hehr und wunderbar.\r\nWenn mir der Herr in Seinem Wort begegnet,\nwenn ich die großen Gnadentaten seh\',\nwie Er das Volk des Eigentums gesegnet,\nwie Er\'s geliebt, begnadigt je und je.\r\nUnd seh\' ich Jesus auf der Erde wandeln,\nin Knechtsgestalt voll Lieb und großer Huld.\nWenn ich im Geiste seh\' Sein göttlich\' Handeln,\nam Kreuz bezahlen vieler Sünder Schuld.\r\n\r\n\r\n'),
(9, '0305', 'Du hast Dich mir geoffenbart, o Herr, in großer Huld   (Drum bete ich Dich an, mein Gott ich bete an)', NULL, 'Du hast Dich mir geoffenbart,\no Herr, in großer Huld.\nDu trägst als Hirte mich so zart\nmit liebender Geduld.\r\nD\'rum bete ich Dich an,\nmein Gott ich bete an.\nAus tiefstem Herzen wie ich kann,\nbet\' ich Dich, Jesus, an.\r\nDu bist der gute Hirte mir;\nam Kreuz hast Du\'s bewährt.\nHerr Jesus, ich gehöre Dir,\nDu seist allein geehrt!\r\nHerr, lass mich nur Dein Schäflein sein,\nhalt mich in Deiner Hut.\nAch, führe Du mich aus und ein,\ndann habe ich es gut.\r\nDu hast mich je und je gepflegt\nmit sanftem Liebessinn,\nd\'rum ist mir\'s tief ins Herz gelegt,\nwas ich Dir schuldig bin.\r\nKein eig\'ner Weg und Wille mehr!\nBestimme Du allein!\nIch gebe mich Dir gänzlich her,\nmein Alles sollst Du sein.'),
(9, '0306', 'Du kannst alles überwinden, mein Heiland, mein Heiland   (Ja, ich will auf Gott vertrauen und ich werde Sieger sein)', NULL, 'Du kannst alles überwinden,\nmein Heiland, mein Heiland!\nUnd den Weg des Sieges finden,\nmein Heiland, mein Heiland!\r\nJa, ich will auf Gott vertrauen,\nund ich werde Sieger sein,\nganz allein auf Ihn nur bauen.\nIch bin Sein, und Er ist mein.\nIch bin Sein, Er ist mein;\nund ich werde Sieger sein!\r\nSei mit mir in dieser Stunde,\nmein Heiland, mein Heiland!\nSei das Wort in meinem Munde,\nmein Heiland, mein Heiland!\r\nO, errette viele Seelen,\nmein Heiland, mein Heiland!\nÖffne jetzt die Lebensquellen,\nmein Heiland, mein Heiland!\r\nDass mit Kraft Dein Reich jetzt komme,\nmein Heiland, mein Heiland!\nRette alle, Bös und Fromme,\nmein Heiland, mein Heiland!\r\nAlle Macht ist Dir gegeben,\nmein Heiland, mein Heiland!\nDu kannst senden Licht und Leben,\nmein Heiland, mein Heiland!'),
(9, '0307', 'Du kannst nichts verbergen vor Gott  -  You cannot hide it from God   (Chorus)', 'You cannot hide it from God,\nyou cannot hide it from God.\nYou can cover your sins that the world may not see,\nbut you cannot hide it from God.', 'Du kannst nichts verbergen vor Gott,\ndu kannst nichts verbergen vor Gott.\nDu kannst Sünde verbergen vor den Augen der Welt,\naber nichts verbergen vor Gott.'),
(9, '0308', 'Du mein ew\'ges Teil und Leben  -  Thou my everlasting portion   (Nah bei Dir, nah bei Dir)', 'Thou my everlasting portion,\nmore than friend or life to me.\nAll along my pilgrim journey,\nSaviour, let me walk with Thee.\r\nClose to Thee, close to Thee,\nclose to Thee, close to Thee.\nAll along my pilgrim journey,\nSaviour, let me walk with Thee.\r\nNot for ease or worldly pleasure,\nnor for fame my prayer shall be.\nGladly will I toil and suffer,\nonly let me walk with Thee.\r\nClose to Thee, close to Thee,\nClose to Thee, close to Thee,\nGladly will I toil and suffer,\nOnly let me walk with Thee.\r\nLead me through the vale of shadows,\nbear me o’er life’s fitful sea.\nThen the gate of life eternal\nmay I enter, Lord, with Thee.\r\nClose to Thee, close to Thee,\nclose to Thee, close to Thee,\nThen the gate of life eternal\nmay I enter, Lord, with Thee.', 'Du mein ew\'ges Teil und Leben,\nmehr als Freund und Reichtum mir,\nleite mich in meinem Streben,\nJesus, lass mich zieh\'n mit Dir!\r\nNah bei Dir, nah bei Dir,\nNah bei Dir, nah bei Dir.\nAuf meiner ganzen Pilgerreise,\nHeiland lass mich geh\'n mit Dir.\r\nNicht nach Ehre, Lust und Freuden\ngeht mein Ziel und Bitten hier;\ngerne will ich streiten, leiden,\nlass mich ziehen nur mit Dir!\r\nNah bei Dir, nah bei Dir,\nnahe bei Dir, nahe bei Dir.\nGerne will ich müh\'n und leiden,\nlass mich gehen nur mit Dir.\r\nFühr\' mich aus dem Schattentale\ndurch des ew\'gen Lebens Tür;\nzu des Himmels Hochzeitssaale\nlass mich einzieh\'n, Herr, mit Dir!\r\nNah bei Dir, nah bei Dir,\nnah bei Dir, nah bei Dir,\nDurch das Tor des ewig\'n Lebens\ndarf ich geh\'n, o Herr, mit Dir.'),
(9, '0309', 'Du mein ewig treuer Jesus  -  Thou my everlasting Portion   (Herr mit Dir, Herr mit Dir)   [Siegesklänge]', 'Thou my everlasting portion,\nmore than friend or life to me.\nAll along my pilgrim journey,\nSaviour, let me walk with thee.\r\nClose to Thee, Close to Thee,\nclose to Thee, Close to Thee.\nAll along my pilgrim journey,\nSaviour, let me walk with Thee.\r\nNot for ease or worldly pleasure,\nnor for fame my prayer shall be.\nGladly will I toil and suffer,\nonly let me walk with Thee.\r\nLead me through the vale of shadows,\nbear me o\'er life\'s fitful sea.\nThen the gate of life eternal\nmay I enter, Lord, with Thee.', 'Du mein ewig treuer Jesus,\nmehr als Freund und Leben mir.\nDurch mein ganzes Erdenleben,\nlass mich ziehen, Herr, mit Dir.\r\nHerr mit Dir, Herr mit Dir,\nHerr mit Dir, Herr mit Dir.\nDurch mein ganzes Erdenleben,\nlass mich ziehen, Herr mit Dir.\r\nNicht um Lust und Erdenfreuden,\nnicht um Rum fleh\' ich zu Dir.\nFreudig will ich leiden, wirken,\naber lass mich zieh\'n mit Dir.\r\nTrag\' mich durch der Wogen Brausen,\ndurch das dunkle Tal mich führ\'.\nUnd zum Tor des ew\'gen Lebens,\nlass mich einzie\'n , Herr mit Dir.'),
(9, '0310', 'Du meine Seele, singe, wohlauf und singe schön', NULL, 'Du meine Seele, singe,\nwohlauf und singe schön\nDem, welchem alle Dinge\nzu Dienst und Willen steh\'n.\nIch will den Herren droben\nhier preisen auf der Erd\';\nich will Ihn herzlich loben,\nso lang ich ich leben werd\'.\r\nWohl dem, der einzig schauet\nnach Jakobs Gott und Heil,\nwer dem sich anvertrauet,\nder hat das beste Teil,\ndas höchste Gut erlesen,\nden schönsten Schatz geliebt;\nsein Herz und ganzes Wesen\nbleibt ewig unbetrübt.\r\nHier sind die starken Kräfte,\ndie unerschöpfte Macht;\ndas weisen die Geschäfte,\ndie Seine Hand gemacht:\nDer Himmel und die Erde\nmit ihrem ganzen Heer,\nder Fisch unzählge Herde\nim großen, wilden Meer.\r\nGott hat viel tausend Weisen,\nzu retten aus dem Tod.\nEr nährt und gibt auch Speisen\nzur Zeit der Hungersnot;\nmacht schöne, rote Wangen\noft bei geringem Mahl;\nund die da sind gefangen,\ndie reißt Er aus der Qual.\r\nAch, ich bin viel zu wenig,\nzu künden Seinen Ruhm.\nDer Herr allein ist König,\nich eine welke Blum\';\njedoch, weil ich gehöre\ngen Zion in Sein Zelt,\nist\'s billig, dass ich mehre\nSein Lob vor aller Welt.'),
(9, '0311', 'Du müdes Herz, es wartet dein  -  The Home where Changes never come   (Drum still! Warte still und murre nicht)', 'The home where changes never come,\nnor pain nor sorrow, toil nor care.\nYes! \'tis a bright and blessed home;\nwho would not fain be resting there?\r\nO, wait, meekly wait, and murmur not,\no, wait, meekly wait, and murmur not.\nO, wait, o, wait,\no, wait, and murmur not.\r\nYet when bow\'d down beneath the load\nby heav\'n allowed, thine earthly lot.\nThou yearn\'st to reach that blest abode,\nwait, meekly wait, and murmur not.\r\nToil on, nor deem, tho\' sore it be,\none sigh unheard, one pray\'r forgot,\nthe day of rest will dawn for me.\nWait, meekly wait, and murmur not.', 'Du müdes Herz, es wartet dein\ndie Ruh nach all der Müh\' und Last.\nKein Gram, kein Leid wird dort mehr sein;\nes schmeckt so süß daheim die Rast.\r\nD\'rum still! Warte still und murre nicht!\nD\'rum still! Warte still und murre nicht!\nD\'rum still, d\'rum still, nur still und murre nicht!\r\nDein Fuß ist wund, dein Weg ist rau,\ndein Kreuz dünkt dich ein schwer Gewicht;\nblick auf, dort winkt die Himmelsau!\nD\'rum still, nur still und murre nicht!\r\nNur still, vorbei ist bald die Nacht,\nleis\' dämmert schon des Tages Licht.\nVon ferne winkt\'s in goldner Pracht.\nD\'rum still, nur still und murre nicht!'),
(9, '0312', 'Du nur o Jesus, bist es der mein Herze stillt   (Jesus, treuer Jesus, ich bin Dein und Du bist mein)', NULL, 'Du nur, o Jesus, bist es, der mein Herze stillt,\nder es mit Frieden und mit Heil erfüllt.\nNirgends fand ich Ruhe, bis zu Deinem Kreuz ich kam\nund zu Deinen Wunden meine Zuflucht nahm.\r\nJesus, treuer Jesus, ich bin Dein und Du bist mein!\nEwig treu und innig soll die Liebe sein!\r\nAls ich im Glauben, Jesus, Dich am Kreuz erblickt,\nda wurde himmlisch mir mein Herz erquickt.\nWelch ein Meer von Wonne strömte da durch meine Brust,\nheiße Tränen flossen mir vor Leid und Lust.\r\nO welche Wonne strömt mir jetzt durch Herz und Sinn,\nwenn ich bedenke, dass ich Dein nun bin!\nDein, so hoch begnadet und mit ew\'gem Heil gekrönt,\nDein, im Blut gebadet und mit Gott versöhnt.\r\nNun sollst, o Jesus, Du mir stets vor Augen steh\'n,\nhängend am Kreuze dort so marterschön.\nDass Du für mich starbest, das ist meiner Hoffnung Grund\nund mein Trost, mein Sehnen bis zur letzten Stund\'.'),
(9, '0313', 'Du sagst, wo die Sonne aufgeht, Du bestimmst den Lauf der Zeit   (Es gibt keinen der Dir gleicht, Du mein Gott bist größer)', NULL, 'Du sagst, wo die Sonne aufgeht,\nDu bestimmst den Lauf der Zeit,\nzeigst der Dunkelheit die Grenzen\nund Du spannst den Himmel weit.\r\nDu liebst den, der\'s nicht verdient hat,\nhilfst dem Schwachen aufzustehen,\nwählst den Tod für meine Rettung,\ngibst mir Kraft, nach vorn zu sehen.\r\nEs gibt keinen der Dir gleicht,\nDu mein Gott bist größer,\nhöher, weiter als der Himmel,\nund Deine Liebe ist tiefer als das Meer.\nUnd was Du sagst bleibt, es bleibt für alle Zeit,\ndarum halt ich fest an Dir, dem Schöpfer der Welt.\r\nJesus Du stehst hoch über allem,\nich will Dich ehren mit allem in mir.\nIch werd\' Deine Wege niemals ganz verstehen,\nich kann Dich nicht greifen,\ndoch mein Herz kann Dich sehen.'),
(9, '0314', 'Du sollst nicht müde werden, selbst wenn das Licht auf Erden   (Wir werden sein wie die Träumenden, die noch nicht fassen, was sie sehn)', NULL, 'Du sollst nicht müde werden,\nselbst wenn das Licht auf Erden\nallmählich zu verlöschen scheint.\nDenn über Hass und Kriegen\nwird Gottes Zukunft siegen,\nund wenn Sein großer Tag erscheint:\r\nWir werden sein wie die Träumenden,\ndie noch nicht fassen, was sie seh\'n.\nWir werden lachen und glücklich sein,\nwenn wir vor Jesus steh\'n.\r\nWillst du den Mut verlieren?\nWillst du schon resignieren,\nweil es nichts mehr zu hoffen gibt?\nDu sollst nicht sinnlos enden,\nGott will dein Leben wenden,\nweil Er dich ja unendlich liebt.\r\nD\'rum lass die Traurigkeiten,\nlass dich zur Freude leiten.\nBald wirst du seh\'n: das Fest beginnt.\nAuch du bist eingeladen;\ndann heilt Gott allen Schaden.\nEin neues Lied wird angestimmt.'),
(9, '0315', 'Du stehst an der Schwelle des Lebens  -  You’re starting, my boy, on Life’s Journey   (O Bruder, hab Mut und sag nein)', 'You’re starting, my boy, on life’s journey,\nalong the grand highway of life.\nYou’ll meet with a thousand temptations,\neach city with evil is rife.\nThis world is a stage of excitement,\nthere’s danger wherever you go.\nBut if you are tempted to weakness,\nhave courage, my boy, to say No!\r\nHave courage, my boy, to say No!\nHave courage, my boy, to say No!\nHave courage, my boy,\nhave courage, my boy,\nhave courage, my boy, to say No!\r\nIn courage, my boy, lies your safety,\nwen you the long journey begin,\nyour trust in a heavenly Father\nwill keep you unspotted from sin.\nTemptations will go on increasing,\nas streams from a rivulet flow.\nBut if you’d be true to your manhood,\nhave courage, my boy, to say No!\r\nBe careful in choosing companions,\nseek only the brave and the true,\nand stand by your friends when in trial,\nne’er changing the old for the new.\nAnd when by false friends you are tempted\nthe taste of the wine cup to know,\nwith firmness, with patience and kindness,\nhave courage, my boy, to say No!', 'Du stehst an der Schwelle des Lebens,\ndir winkt in der Ferne das Glück.\nEs lacht dir die Welt noch entgegen\nund schillert verlockend dem Blick.\nDoch zischt unter Blumen die Schlange,\nes lauert im Lachen die Pein;\nd\'rum wenn die Versuchung dir nahet,\no Bruder, hab Mut und sag nein!\r\nO Bruder, hab Mut und sag nein!\nO Bruder, hab Mut und sag nein!\nO Bruder, hab Mut\no Bruder, hab Mut,\no Bruder, hab Mut und sag nein!\r\nDein Heil liegt in christlichem Mute,\ndein Schild sei der Glaube an Gott!\nWer Christus im Herzen bewahret,\nden kümmert nicht Lachen und Spott.\nD\'rum wie dich die Welt auch umgleißet,\nhalt keusch deine Seele und rein,\nund flüstert sie trüg\'risch und schmeichelnd,\no Bruder, hab Mut und sag nein!\r\nUnd wähl\' dir nur die zu Gefährten,\ndie wacker und lauter und wahr.\nUnd hasche nicht töricht nach neuem,\nbeim alten, erprobten beharr\'!\nUnd wenn man dich locket und dränget,\nund funkelt im Glase der Wein,\nheb\' auf zu dem Heiland die Seele,\no Bruder, hab Mut und sag nein!'),
(9, '0316', 'Du vernahmst vom kleinen Mose  -  You have heard of little Moses   (Es wird ein Treffen dort sein in der Luft)', 'You have heard of little Moses in the bulrush,\nyou have heard of fearless David and his sling,\nyou have heard the story told of dreaming Joseph,\nand of Jonah and the whale you often sing.\nThere are many, many others through the Bible,\nI should like to meet them all, I do declare!\nBy and by the Lord will surely let us meet them,\nat the meeting in the air.\r\nThere is going to be a meeting in the air,\nin the sweet, sweet by and by.\nI am going to meet you, meet you over there\nin that home beyond the sky.\nSuch singing you will hear, never heard by mortal ear,\n\'Twill be glorious, I do declare!\nAnd God\'s own Son will be the leading One,\nat the meeting in the air.\r\nMany things will there be missing in that meeting:\nfor the mourners bench will have no place at all;\nthere will never be a sermon preached to sinners,\nfor the sinner had refused to heed the call.\nThere will be no mourning Over wayward loved ones,\nthere will be no lonely nights of pleading prayer;\nall our burdens and our anguish will be lifted\nat that meeting in the air.\r\nThere the doubters will be missing altogether,\nall the skeptics will be absent on that day;\nthere will be no grumblers present to disturb us,\nand the Achans will be busy far away.\nThere the saints will have His seal upon their foreheads,\ndressed in raiment none but ransomed ones can wear;\nall who have the wedding garments will be present,\nat the meeting in the air.', 'Du vernahmst vom kleinen Mose in dem Schilfkorb,\nDavids Schleuder ist dir auch sehr gut bekannt.\nDu hörtest vieles über Josephs Träume,\nüber Jona singst du sehr oft allerhand.\nDa sind viele, viele andre in der Bibel.\nSie zu treffen, dahin geht mein Ruf.\nIm Himmel wird es uns der Herr gewähren\nbei dem Treffen in der Luft.\r\nEs wird ein Treffen dort sein in der Luft,\nin dem schönen Himmelsland.\nWir werden uns sehen und begrüßen allezeit\nin dem Land der Ewigkeit.\nEin Singen wirst du hören, was kein sterblich Ohr gehört.\nEs wird einfach herrlich sein.\nUnd Gott, der Herr, wird unser Führer sein\nbei dem Treffen in der Luft.\r\nViele Dinge werden fehlen bei dem Treffen.\nEin Gericht für Leidgeprüfte gibt\'s dort nicht.\nKeine Predigt zu den Bösen wird gesprochen,\ndenn nicht hörte auf den Ruf der Bösewicht.\nNie mehr Leiden werden sein dort für Geliebte,\nnirgendwo ein Sünder laut nach Buße sucht.\nAlle Lasten und die Schmerzen werden fort sein\nbei dem Treffen in der Luft.\r\nAlle Zweifler werden dort dann gänzlich fehlen.\nAuch die Nörgler werden dann nicht bei uns sein,\nauch die Meckerziegen werden uns nicht stören,\nund die Schmerzen sind dann weg, wie ist das fein.\nUnd die Heil\'gen mit dem Siegel auf dem Haupte,\nin der Kleidung, die für seine Braut bestimmt,\nnur die damit sind bekleidet werden dort sein,\nbei dem Treffen in der Luft.'),
(9, '0317', 'Du warst das Wort direkt am Anfang  -  You were the Word at the Beginning   (Oh wie schön dieser Name ist)', 'You were the Word at the beginning,\none with God the Lord Most High.\nYour hidden glory in creation,\nnow revealed in You our Christ.\r\nWhat a beautiful Name it is,\nwhat a beautiful Name it is,\nthe Name of Jesus Christ my King.\nWhat a beautiful Name it is,\nnothing compares to this,\nwhat a beautiful Name it is,\nthe Name of Jesus.\r\nYou didn\'t want heaven without us,\nso Jesus, You brought heaven down.\nMy sin was great, Your love was greater,\nwhat could separate us now.\r\nWhat a wonderful name it is.\nWhat a wonderful name it is.\nThe name of Jesus Christ my King.\nWhat a wonderful name it is,\nnothing compares to this.\nWhat a wonderful name it is,\nthe name of Jesus.\r\nDeath could not hold You\nThe veil tore before You\nYou silenced the boast of sin and grave\nThe heavens are roaring\nThe praise of Your glory\nFor You are raised to life again.\r\nYou have no rival,\nYou have no equal,\nnow and forever, God You reign.\nYours is the kingdom,\nYours is the glory,\nYours is the name above all names.\r\nWhat a powerful name it is\nWhat a powerful name it is\nThe name of Jesus Christ my King.\nWhat a powerful name it is,\nnothing can stand against.\nWhat a powerful name it is,\nthe name of Jesus.\r\nYou have no rival,\nYou have no equal,\nnow and forever, God You reign.\nYours is the kingdom,\nYours is the glory,\nYours is the name above all names.\r\nWhat a beautiful Name it is,\nwhat a beautiful Name it is,\nthe Name of Jesus Christ my King.\nWhat a beautiful Name it is,\nnothing compares to this.\nWhat a beautiful Name it is,\nthe Name of Jesus.\nWhat a beautiful Name it is,\nthe Name of Jesus.', 'Du warst das Wort direkt am Anfang,\neins mit Gott dem höchsten Herrn.\nDie Kraft verborgen in der Schöpfung,\nund durch Christus nun zu seh\'n.\r\nOh wie schön dieser Name ist.\nOh wie schön dieser Name ist.\nDer Name Jesus Christus, Herr.\nOh wie schön dieser Name ist,\nder unvergleichbar ist.\nOh wie schön dieser Name ist,\nder Name Jesus.\r\nDen Himmel wolltest Du nur mit uns,\nso brachtest Du Jesus ihn her.\nDie Schuld war groß, die Liebe größer.\nnichts trennt uns jemals von Dir.\r\nO, wie herrlich der Name ist.\nO, wie herrlich der Name ist.\nDer Name Jesus Christus, Herr.\nO, wie herrlich der Name ist,\nder unvergleichbar ist.\nO, wie herrlich der Name ist,\nder Name Jesus.\r\nDer Tod hat verloren,\nzerrissen der Vorgang,\nSünde und Grab schweigen vor Dir.\nDie Himmel laut tosend,\nvoll Herrlichkeit lobend,\nweil Du nun auferstanden bist.\r\nDu hast keinen Gegner,\nkeiner vergleichbar,\nGott, Du regierst für alle Zeit.\nDein ist das Reich und\nDein ist die Ehre,\nDein Name thront in Ewigkeit.\r\nO, wie kraftvoll der Name ist.\nO, wie kraftvoll der Name ist.\nDer Name Jesus Christus, Herr.\nO, wie kraftvoll der Name ist\nder unbesiegbar ist.\nO, wie kraftvoll der Name ist.\nDer Name Jesus.\r\nDu hast keinen Gegner,\nkeiner vergleichbar,\nGott, Du regierst für alle Zeit.\nDein ist das Reich und\nDein ist die Ehre,\nDein Name thront in Ewigkeit.\r\nOh wie schön dieser Name ist.\nOh wie schön dieser Name ist.\nDer Name Jesus Christus, Herr.\nOh wie schön dieser Name ist,\nder unvergleichbar ist.\nOh wie schön dieser Name ist,\nder Name Jesus.\nOh wie schön dieser Name ist,\nder Name Jesus.'),
(9, '0318', 'Du, mein Jesus hast Dich jetzt in dieser Zeit geoffenbart   (Chorus)', NULL, 'Du, mein Jesus, Du, mein Jesus\nhast Dich jetzt in dieser Zeit geoffenbart\nund als Sohn des Menschen kamst Du auf die Erde\nund erfüllest Deine Braut mit Deinem Wort.'),
(9, '0319', 'Durch herrlichen Auen, so blühend und licht  -  In shady, green Pastures, so rich and so sweet   (Er führt durchs Wasser, durch tiefe Flut)', 'In shady, green pastures, so rich and so sweet,\nGod leads His dear children along;\nWhere the water\'s cool flow bathes the weary one\'s feet,\nGod leads His dear children along.\r\nSome through the waters, some through the flood,\nSome through the fire, but all through the blood;\nSome through great sorrow, but God gives a song,\nIn the night season and all the day long.\r\nSometimes on the mount where the sun shines so bright,\nGod leads His dear children along;\nSometimes in the valley, in darkest of night,\nGod leads His dear children along.\r\nThough sorrows befall us and Satan oppose,\nGod leads His dear children along;\nThrough grace we can conquer, defeat all our foes,\nGod leads His dear children along.', 'Auf herrlichen Auen so reich und so grün,\nbahnt Gott Seinen Kindern den Weg.\nWo das Wasser kühl fliesset, erfrischend und schön,\nbahnt Gott Seinen Kindern den Weg.\r\nManche durchs Wasser, sogar durch die Flut,\nmanche durchs Feuer, doch alle durchs Blut.\nDurch Not und Sorgen doch Gott gibt ein Lied,\nbei Nacht und Tage zur Seit\' Er mir steht.\r\nAuf bergigen Höh\'n wo die Sonne so lacht,\nbahnt Gott Seinen Kindern den Weg.\nUnd auch durch die Täler im Dunkel der Nacht\nbahnt Gott Seinen Kindern den Weg.\r\nWenn Sorg\' uns befällt und der Feind uns anficht,\nbahnt Gott seinen Kindern den Weg.\nDurch Gnad\' sind wir siegreich, es scheinet Sein Licht.\nbahnt Gott seinen Kindern den Weg.'),
(9, '0320', 'Durchflute mein Herz  -  Sweep over my Soul   (Chorus)', 'Sweep over my soul,\nsweep over my soul,\nsweet spirit sweep over my soul!\nMy rest is complete\nwhile I sit at Your feet,\nsweet spirit sweep over my soul.', 'Durchflute mein Herz,\ndurchflute mein Herz,\nGeist Gottes durchflute mein Herz!\nIn Dir hab\' ich Ruh\',\nmein Alles bist Du,\nGeist Gottes durchflute mein Herz.'),
(9, '0321', 'EAGLES WINGS', 'Here I am waiting\nAbide in me I pray\nHere I am longing\nFor You\nHide me in Your love\nBring me to my knees\nMay I know Jesus\nMore and more\r\nCome live in me\nAll my life\nTake over\nCome breathe in me\nAnd I will rise\nOn eagle\'s wings', 'Hier bin ich und warte\nBleib in mir, ich bete\nHier sehne ich mich\nnach Dir\nBerge mich in Deiner Liebe\nBring mich auf meine Knie\nMöge ich Jesus kennenlernen\nMehr und mehr\r\nKomm und lebe in mir\nMein ganzes Leben\nÜbernimm\nKomm und atme in mir\nUnd ich werde aufsteigen\nAuf Adlerflügel'),
(9, '0322', 'Eh\' da kommt der große Schreckenstag auf Erd\'   (Sieben Siegel sind geöffnet)', NULL, 'Eh\' da kommt der große Schreckenstag auf Erd\'\nhat uns Gott gesandt\' Elia, den Prophet,\nmit dem Weckruf, der aus Babel ruft heraus\nund in Christus bringt hinein.\r\nSieben Siegel sind geöffnet in der Hand des starken Engels,\nder da steht auf Meer und Land.\nChristus, das Geheimnis Gottes, ist bekannt.\nNimm das Buch und iss es auf.\r\nJa, der ganze Heil\'ge Geist ist jetzt auf Erd\',\ndass die Braut mit Ihm, dem Wort, vereinigt wird.\nDenn der Geist kommt auf das inspirierte Wort,\nund das Wort wird in uns Fleisch.\r\nChristus kam zurück in Form des Menschensohns,\num das Wort zu bringen, welches war verlor\'n.\nBald wird Er verlassen auch den Gnadenthron,\nwenn die Braut wird gehen heim.\r\nMache dich bereit! Noch ist es Gnadenzeit.\nPrüf\' das Öl im Krug, ob es dir wohl auch reicht.\nBist du schon bekleidet mit dem Hochzeitskleid?\nwelches ist: "So sein wie Er."'),
(9, '0323', 'Ehre sei dem Lamm, Ehre sei dem Lamm in der Höh', NULL, 'Ehre sei dem Lamm, Ehre sei dem Lamm,\nEhre sei dem Lamm in der Höh\'!\nEhre sei dem Lamm, Ehre sei dem Lamm,\nEhre sei dem Lamm in der Höh\'!\nHalleluja, Halleluja,\nEhre sei dem Lamm in der Höh\'!\nHalleluja, Halleluja,\nEhre sei dem Lamm in der Höh\'!\r\nJesus überwand, Jesus überwand,\nJesus überwand Satans Macht!\nJesus überwand, Jesus überwand,\nJesus überwand Satans Macht!\nHalleluja, Halleluja,\nJesus überwand Satans Macht!\nHalleluja, Halleluja,\nJesus überwand Satans Macht!\r\nÜberwind\' auch du, überwind\' auch du,\nüberwind\' auch du Satans Macht!\nÜberwind\' auch du, überwind\' auch du,\nüberwind\' auch du Satans Macht!\nHalleluja, Halleluja,\nüberwind\' auch du Satans Macht!\nHalleluja, Halleluja,\nüberwind\' auch du Satans Macht!'),
(9, '0324', 'Ehre sei Gott in der Höhe und Friede auf Erden', NULL, 'Ehre sei Gott in der Höhe\nund Friede auf Erden und Friede auf Erden\nund den Menschen ein Wohlgefallen!\nUnd den Menschen ein Wohlgefallen!\r\nLasst uns frohlocken dem Sohne,\nder gnädig erschienen uns Gott zu versühnen\nund uns schenket die Lebenskrone.\nUnd uns schenket die Lebenskrone.\r\nHerrlich wird\'s sein ihn zu schauen,\nwenn Er einst den Seinen wird wieder erscheinen.\nWohl den Seelen, die Ihm vertrauen.\nWohl den Seelen, die Ihm vertrauen.'),
(9, '0325', 'Ehre und Herrlichkeit sei Gott in der Höhe', NULL, 'Ehre und Herrlichkeit,\nsei Gott in der Höhe.\nEhre und Herrlichkeit\nsei Gott in der Höhe!\r\nUnd Frieden auf der Erd’\nbei den Menschen\nSeines Wohlgefall’ns!\nUnd Frieden auf der Erd’\nbei den Menschen\nSeines Wohlgefall’ns!\r\nHerr, meine Seele preist\nund mein Geist\nerhebt Dich voller Freud’!\nDu hast mich angeseh’n\nvoller Gnade\nund Barmherzigkeit!\r\nWer bin ich denn, oh Herr?\nDoch Großes hat der\nMächtige getan!\nHeut’ bin ich voller Glück,\ndenn voller Macht zeigt\nsich dein starker Arm!'),
(9, '0326', 'Ehre, Ehre sei Gott. Glücklich wir heimwärts gehn', NULL, 'Ehre, Ehre sei Gott!\nGlücklich wir heimwärts geh\'n.\nEhre, Ehre sei Gott!\nBald wir den Heiland seh\'n.\nEhre, Halleluja!\nEr nahet schon heran.\nEr kommt in den Wolken\nund dann wir folgen himmelan.'),
(9, '0327', 'Ein feste Burg ist unser Gott  -  A mighty Fortress is our God', 'A mighty fortress is our God,\na bulwark never failing.\nOur helper he, amid the flood\nof mortal ills prevailing.\nFor still our ancient foe\ndoes seek to work us woe.\nHis craft and power are great,\nand armed with cruel hate,\non earth is not his equal.\r\nDid we in our own strength confide,\nour striving would be losing.\nWere not the right Man on our side,\nthe Man of God\'s own choosing.\nYou ask who that may be?\nChrist Jesus, it is He;\nLord Sabaoth his name,\nfrom age to age the same.\nAnd he must win the battle.\r\nAnd though this world, with devils filled,\nshould threaten to undo us,\nwe will not fear, for God has willed\nhis truth to triumph through us.\nThe prince of darkness grim,\nwe tremble not for him.\nHis rage we can endure,\nfor lo! his doom is sure!\nOne little word shall fell him.\r\nThat Word above all earthly powers\nno thanks to them abideth.\nThe Spirit and the gifts are ours\nthrough him who with us sideth.\nLet goods and kindred go,\nthis mortal life also.\nThe body they may kill,\nGod\'s truth abideth still.\nHis kingdom is forever!', 'Ein feste Burg ist unser Gott,\nein gute Wehr und Waffen!\nEr hilft uns frei aus aller Not,\ndie uns jetzt hat betroffen.\nDer alt böse Feind,\nmit Ernst er\'s jetzt meint.\nGroß mach und viel List\nsein grausam Rüstung ist;\nauf Erd\' ist nicht sein\'sgleichen.\r\nMit unsrer Macht ist nichts getan,\nwir sind gar bald verloren;\nes streit\' für uns der rechte Mann,\nden Gott selbst hat erkoren!\nFragst du, wer der ist?\nEr heißt Jesus Christ,\nder Herr Zebaoth,\nund ist kein andrer Gott;\ndas Feld muss Er behalten.\r\nUnd wenn die Welt voll Teufel wär\'\nund wollt uns gar verschlingen,\nso fürchten wir uns nicht so sehr,\nes soll uns doch gelingen!\nDer Fürst dieser Welt,\nwie sau\'r er sich stellt,\ntut Er uns doch nichts;\ndas macht, er ist gericht\',\nein Wörtlein kann ihn fällen.\r\nDas Wort sie sollen lassen stahn\nund kein\' Dank dazu haben;\nEr ist bei uns wohl auf dem Plan\nmit Seinem Geist und Gaben.\nNehmen sie den Leib,\nGut, Ehr\', Kind und Weib;\nlass fahren dahin,\nsie haben\'s kein\' Gewinn;\ndas Reich muss uns doch bleiben.'),
(9, '0328', 'Ein fester Felsengrund ist Gottes Wort   (Chorus)', NULL, 'Ein fester Felsengrund ist Gottes Wort,\nin Zeiten dunkler Nacht ein sich\'rer Hort.\nWenn alles Menschenwort einst längst vergangen,\nsteht Gottes Wort doch fest.'),
(9, '0329', 'Ein Freund ist mir so teuer, wie\'s keiner sonst kann sein', NULL, 'Ein Freund ist mir so teuer,\nwie\'s keiner sonst kann sein,\nEr denkt in zarter Liebe mein\nund lässt mich nie allein.\nIch kann nicht leben ohne Ihn\nund Er nicht ohne mich.\nSo sind wir stets zusammen, mein Herr und ich.\r\nEr hat mich angenommen,\neh ich es noch gedacht.\nEr ist\'s, der für mich sorgt und wacht\nso treu bei Tag und Nacht.\nEr liebt mich warm und inniglich\nund gibt Sich hin für mich.\nSo passen wir zusammen, mein Herr und ich.\r\nEr trug all meine Sünden\nund hat für mich gebüßt.\nEr hat in Liebe mich gegrüßt,\nmein Leben mir versüßt.\nEr liebte mehr als mütterlich,\nals Er am Kreuz verblich.\nSo kamen wir zusammen, mein Herr und ich.\r\nEr ist für mich gestorben\nund lebt doch immerfort.\nEr ist bei mir an jedem Ort\nund trägt mich durch Sein Wort.\nEr lebt, und mit Ihm lebe ich.\nIch lebe ewiglich.\nSo leben wir zusammen, mein Herr und ich.\r\nZwar thront Er jetzt im Himmel;\ndoch gibt Er mir den Geist,\nder mich lehrt tun, was Er mich heißt,\nund mich stets unterweist.\nGar selig liebt und labt Er mich,\nbis Er mich holt zu Sich.\nDann sind wir neu zusammen,\nmein Herr und ich.'),
(9, '0330', 'Ein Größerer als Salomo ist hier', NULL, 'Ein Größerer als Salomo ist hier.\nDen Tempel baut Er sich aus dir und mir.\nJa, Gottes Tempel ist nicht mehr aus Stein.\nEr wählte dich und mich Sein Haus zu sein.\r\nUnd weil wir jetzt lebend\'ge Steine sind,\nist Bruderliebe die das Haus verbind\'t.\nJa, jeder echte und lebend\'ge Stein\nmöcht\' nicht mehr ohne all die andern sein.\r\nUnd treffen wir uns jetzt in Gottes Haus,\ndann geht davon ein großer Segen aus.\nJa, Gott lenkt zur Gemeinschaft unser\'n Schritt,\ndenn jeder bringt ein Stück des Segens mit.\r\nVielleicht bist du ein Stein so wunderschön,\nvielleicht aber auch klein und kaum zu seh\'n.\nDoch wenn du deinen Platz gefunden hast,\ndann glaube, dass kein and\'rer Stein dort passt.\r\nGemeinschaft haben wollen wir so sehr,\ndann brennt das Feuer Gottes oft viel mehr.\nDoch sind wir viele oder nur zu zwei\'n,\nder Heiland wird in seinem Tempel sein.'),
(9, '0331', 'Ein Haus zu Gottes Ehre ist dieses liebe Haus', NULL, 'Ein Haus zu Gottes Ehre ist dieses liebe Haus,\nin welchem Jesu Lehre strömt Licht und Leben aus.\nDa jauchzen Gottes Kinder, da fleht der Knecht des Herrn,\nda weinen arme Sünder; da weilen alle gern,\nda weilen alle gern!\r\nHier säuselt süßer Frieden um jedes wunde Herz!\nHier stärken sich die Müden, zu tragen Erdenschmerz.\nUnd will die Welt sich brüsten, tobt Satan noch so sehr,\ndie Gotteskinder rüsten sich hier mit guter Wehr,\nsich hier mit guter Wehr!\r\nAn diesem sel\'gen Orte erscheint uns wunderbar\ndes Himmelreiches Pforte geöffnet ganz und gar.\nAuf lichten Glaubensschwingen erhebt die Seele sich,\nbis sie darf droben singen dem Herrn einst ewiglich,\ndem Herrn einst ewiglich!\r\nSo lasst uns denn nun heute in heiligem Verein\ndies Haus mit sel\'ger Freude dem Herrn im Glauben weih\'n!\nMög\' Gottes Segen fließen stets reichlich auf dies Haus!\nMög\' d\'raus sich Heil ergießen in alle Lande aus,\nin alle Lande aus!'),
(9, '0332', 'Ein heilger Born gefüllt mit Blut  -  There is a fountain filled with Blood', 'There is a fountain filled with blood,\ndrawn from Emmanuel\'s veins,\nand sinners, plunged beneath that flood,\nlose all their guilty stains.\nLose all their guilty stains, lose all their guilty stains.\nAnd sinners, plunged beneath that flood,\nlose all their guilty stains.\r\nThe dying thief rejoiced to see\nthat fountain in his day.\nAnd there may I, though vile as he,\nwash all my sins away.\nWash all my sins away, wash all my sins away.\nAnd there may I, though vile as he,\nwash all my sins away.\r\nE\'er since by faith I saw the stream\nThy flowing wounds supply.\nRedeeming love has been my theme,\nand shall be till I die.\nAnd shall be till I die, and shall be till I die.\nRedeeming love has been my theme,\nand shall be till I die.\r\nThou dying Lamb, Thy precious blood\nshall never lose its power.\nTill all the ransomed church of God\nbe saved, to sin no more.\nBe saved, to sin no more, be saved, to sin no more.\nTill all the ransomed church of God\nbe saved, to sin no more.\r\nThen in a nobler, sweeter song,\nI\'ll sing Thy power to save.\nWhen this poor lisping, stammering tongue\nlies silent in the grave.\nLies silent in the grave, lies silent in the grave.\nWhen this poor lisping, stammering tongue\nlies silent in the grave.', 'Ein heil\'ger Born, gefüllt mit Blut,\naus Jesu Wunden floss,\nund wer sich taucht in diese Flut,\nist aller Flecken los.\nIst aller Flecken los, ist aller Flecken los.\nUnd wer sich taucht in diese Flut,\nist aller Flecken los.\r\nDer Schächer, der am Kreuz verblich,\ndurft\' dieses Borns sich freu\'n.\nDa können Sünder, schnöd\' wie ich,\nvon Sünden werden rein.\nVon Sünden werden rein, von Sünden werden rein.\nDa können Sünder, schnöd\' wie ich,\nvon Sünden werden rein.\r\nSeit ich den Strom im Glauben sah,\nder quoll aus Wunden rot.\nVerweilt mein Geist auf Golgatha,\nund preiset Jesu Tod.\nUnd preiset Jesu Tod, und preiset Jesu Tod.\nVerweilt mein Geist auf Golgatha,\nund preiset Jesu Tod.\r\nDu sterbend Lamm, Dein köstlich Blut\nverliert nie seine Kraft,\nbis es Erlöste rein und gut\nund endlich selig macht.\nUnd endlich selig macht, und endlich selig macht.\nBis es Erlöste rein und gut\nund endlich selig macht.\r\nEinst bring ich Dir ein schön\'res Lied\nim ob\'ren Heiligtum.\nWenn schon mein Leib vom Kampfe müd\'\nim Grab liegt still und stumm.\nIm Grab liegt still und stumm, im Grab liegt still und stumm.\nWenn schon mein Leib vom Kampfe müd\'\nim Grab liegt still und stumm.'),
(9, '0333', 'Ein herrlich\'s Land verheißt uns Gott', NULL, 'Ein herrlich\'s Land verheißt uns Gott.\nWelch ein Glück! Welch ein Glück!\nD\'raus ist verbannt all Schmerz und Not.\nWelch ein Glück! Welch ein Glück!\nDort hören wir der Engel Sang,\nder Heil\'gen Preis und Harfenklang,\nGott lobend Ewigkeiten lang.\nWelch ein Glück! Welch ein Glück!\r\nDort geht kein Tod, kein Übel ein,\nnein, o nein! Nein, o nein!\nAuch nicht, was unrein und gemein,\nnein, o nein! Nein, o nein!\nDer Sünder, der nicht wusch sein Kleid\nin Christi Blutgerechtigkeit,\nererbet nicht die Seligkeit.\nNein, o nein! Nein, o nein!\r\nWohl sind wir Sünder allzugleich,\nja, o ja! Ja, o ja!\nAus Gnaden erbt man nur das Reich.\nJa, o ja! Ja, o ja!\nDer Unschuld Krone sank dahin,\ndoch Jesus ließ sie neu erblüh\'n.\nEr heiligte uns Herz und Sinn.\nJa, o ja! Ja, o ja!\r\nMit Jesus werden wir gekrönt,\nja, gekrönt! Ja, gekrönt!\nEr lebt und hat auch euch versöhnt,\nja, versöhnt! Ja, versöhnt!\nDoch geht die Gnadenzeit vorbei,\nkommt ihr zu spät, welch Jammerschrei!\nNoch quillt das Lebenswasser frei,\nkommt herbei! Kommt herbei!'),
(9, '0334', 'Ein herrlicher Retter ist Jesus, mein Herr  -  A wonderful Saviour is Jesus my Lord   (Er birgt mich im Felsen des Heils wunderbar)   [Siegesklänge]', 'A wonderful Saviour is Jesus my Lord,\na wonderful Saviour to me.\nHe hideth my soul\nin the cleft of the rock,\nwhere rivers of pleasure I see.\r\nHe hideth my soul in the cleft of the rock,\nthat shadows a dry, thirsty land.\nHe hideth my life in the depths of His love,\nand covers me there with His hand,\nand covers me there with His hand.\r\nA wonderful Saviour is Jesus my Lord,\nHe taketh my burden away.\nHe holdeth me up and I shall not be moved,\nHe giveth me strength as my day.\r\nWith numberless blessings each moment He crowns,\nand filled with His fullness divine.\nI sing in my rapture, oh, glory to God,\nfor such a Redeemer as mine!\r\nWhen clothed in His brightness, transported I rise,\nto meet Him in clouds of the sky.\nHis perfect salvation, His wonderful love,\nI\'ll shout with the millions on high.', 'Ein herrlicher Retter ist Jesus, mein Herr,\nein Heiland und Helfer so treu!\nEr birgt meine Seele im Felsen des Heil\'s,\nschenkt Gnade und Kraft täglich neu.\r\nEr birgt mich im Felsen des Heil\'s wunderbar,\nwo volle Erquickung ich fand.\nEr bleibt mir in ewiger Liebe so nah\nund deckt mich mit schützender Hand,\nund deckt mich mit schützender Hand.\r\nEin herrlicher Retter ist Jesus, mein Herr,\nEr nahm meine Bürde von mir!\nEr hält mich im Kampfe, dass nichts mich bewegt,\ndie Kraft meines Lebens ist Er.\r\nEr krönt mich mit Gnade und Segen stets neu,\nlässt voll seines Geistes mich sein.\nNun juble und jauchze ich: Ehre sei Gott,\ndass solch ein Erlöser ist mein!\r\nEr hüllet mich ein in Sein leuchtendes Kleid\nund hilft mir, dass vor ihm ich steh\'.\nDie volle Erlösung, die ewige Lieb\'\nwill rühmen ich dort in der Höh\'.'),
(9, '0335', 'Ein Herz und eine Seele war der ersten Christen Menge', NULL, 'Ein Herz und eine Seele war der ersten Christen Menge,\nzum Tempel zog die fromme Schar in fröhlichem Gedränge.\nIhr heller Chor klang voll empor als wie aus einer Kehle.\nEin Glaubensgrund, ein Liebesbund, ein Herz und eine Seele!\r\nO goldne Zeit, wo bist du hin, du Zeit der ersten Liebe?\nWo wohnst du noch, o Brudersinn im wüsten Weltgetriebe?\nOb Christi Heer durch Land und Meer nach Millionen zähle,\ndie Krone, ach! Die Liebe brach: Ein Herz und Eine Seele!\r\nDie Jünger Christi hadern sehr in ihres Meisters Namen.\nDer Widersacher schleicht umher und säet Schlangensamen.\nDer alte Feind, mit List er\'s meint, dass er den Sieg uns stehle.\nMein Volk Hab Acht! Steh\' auf der Wacht, ein Herz und Eine Seele!\r\nDie treue Mutter Zion weint ob den entzweiten Söhnen,\nkommt, Brüder, lasst uns neu vereint ihr Haupt mit Rosen krönen.\nGebt her die Hand zum Liebesband nach unsres Herrn Befehle.\nWeg Hass und Neid, weg Zank und Streit! Ein Herz und eine Seele!\r\nWo ist\'s noch gut auf Erden sein? Wo Lieb und Friede thronen,\nwo fromm in herzlichem Verein beisammen Brüder wohnen!\nZu flüchtig ist des Lebens Frist, dass man mit Streit sich quäle.\nGenießt die Freud\', versüßt das Leid: Ein Herz und eine Seele!\r\nWann kommt zurück die goldne Zeit auf der zerstörten Erden?\nWann ausgekämpft der letzte Streit, wann Schwerter Sicheln werden!\nEin Liebesband von Land zu Land, o dass kein Bruder fehle!\nEin Friedensbund ums Erdenrund! Ein Herz und Eine Seele!'),
(9, '0336', 'Ein Mann am Kreuze einsam allein   (Jesus am Kreuze, Er starb für dich)', NULL, 'Ein Mann am Kreuze einsam allein.\nEin Mann am Kreuze wer mag es sein?\nEin Mann in Wunden, ein Mann in Blut.\nEin Mann zerschunden im Grabe ruht.\r\nJesus am Kreuze, Er starb für dich.\nEr ruft voll Liebe ganz inniglich:\n"Kommt her ihr Müden voll Traurigkeit.\nIch geb\' euch Frieden und Glück und Freud".\r\nSo manche Herzen noch hart geplagt.\nIn Sorg\' und Schmerzen gar oft verzagt.\nSo mache Seele auf Sand gebaut,\nso manches Auge nach Gott nicht schaut.\r\nDie Wälder schweigen, der Mond zieht still.\nDer Sternen Reigen nicht enden will.\nEin milder Abend, mein Herz voll Fried\'.\nMich füllt erlabend ein Jubellied.'),
(9, '0337', 'Ein neu\' Gebot gebe ich euch  -  A new Commandment I give unto you', 'A new commandment I give unto you:\nthat you love one another as I have loved you,\nthat you love one another as I have loved you.\nBy this shall all men know that you are my disciples,\nif you have love one to another.\nBy this shall all men know that you are my disciples,\nif you have love one to another.\r\nA new commandment I give unto you:\nthat you love one another as I have loved you,\nthat you love one another as I have loved you.\nYou are my friends if you do what I command you,\nwithout my help you can do nothing.\nYou are my friends if you do what I command you,\nwithout my help you can do nothing.\r\nA new commandment I give unto you:\nthat you love one another as I have loved you,\nthat you love one another as I have loved you.\nTrue love is patient, nor arrogant nor boastful,\nLove bears all things, love is eternal.\nTrue love is patient, nor arrogant nor boastful,\nLove bears all things, love is eternal.\r\nA new commandment I give unto you:\nthat you love one another as I have loved you,\nthat you love one another as I have loved you.\nI am the true vie, my Father is the gard\'ner.\nAbide in me: I will be with you.\nI am the true vie, my Father is the gard\'ner.\nAbide in me: I will be with you.', 'Ein neu\' Gebot gebe ich euch:\ndass ihr liebet einander, wie ich euch geliebt,\ndass ihr liebet einander, wie ich euch geliebt.\nDaran wird jeder meine Jünger erkennen,\nso ihr Liebe habt untereinander.\nDaran wird jeder meine Jünger erkennen,\nso ihr Liebe habt untereinander.\r\n\r\n\r\n'),
(9, '0338', 'Ein neuer Tag und ein neuer Morgen  -  The Sun comes up, it\'s a new Day dawning   (Zehntausend Gründe)', 'Bless the Lord, O my soul, O my soul\nworship His holy name.\nSing like never before, O my soul\nI\'ll worship Your holy name.\r\nThe sun comes up, it\'s a new day dawning,\nit\'s time to sing Your song again.\nWhatever may pass, and whatever lies before me -\nlet me be singing when the evening comes.\r\nYou\'re rich in love, and You\'re slow to anger,\nYour name is great, and Your heart is kind.\nFor all Your goodness I will keep on singing -\nten thousand reasons for my heart to find\r\nAnd on that day when my strength is failing,\nthe end draws near and my time has come.\nStill my soul will sing Your praise unending -\nten thousand years and then forevermore.', 'Komm und lobe den Herrn, meine Seele sing,\nbete den König an.\nSing wie niemals zuvor, nur für Ihn,\nund bete den König an.\r\nEin neuer Tag und ein neuer Morgen,\nund wieder bring ich dir mein Lob.\nWas auch vor mir liegt und was immer auch geschehen mag,\nlass mich noch singen, wenn der Abend kommt.\r\nDu liebst so sehr und vergibst geduldig,\nschenkst Gnade, Trost und Barmherzigkeit.\nVon deiner Güte will ich immer singen,\nzehntausend Gründe gibst du mir dafür.\r\nUnd wenn am Ende die Kräfte schwinden,\nwenn meine Zeit dann gekommen ist.\nWird meine Seele dich weiter preisen,\nzehntausend Jahre und in Ewigkeit.'),
(9, '0339', 'Ein neues Lied hab ich gelernt, des Heilands Lobgesang  -  I’ve learned to sing a glad new Song of Praise unto our King   (Es schall mein Leben lang dem Herrn mein Lobgesang)', 'I’ve learned to sing a glad new song\nof praise unto our king!\nAnd now with all my ransomed powers\nHis praises I will sing.\r\nHis praises will I sing,\nHe is my Lord and king.\nAnd now with all my ransomed powers\nHis praises will I sing\r\nI’ve learned to sing the song of peace,\n’tis sweeter every day,\nsince Jesus calmed my troubled soul,\nand bore my sins away.\r\nI sing the song of perfect love,\nit casteth out all fear!\nO breadth, o length, o depth, o height!\nO love so full of cheer.\r\nI’ve learned to sing the song of joy,\nmy cup is running o’er.\nWith blessings full of peace and love,\nand still there’s more and more.\r\nSoon I shall sing the new, new song\nof Moses and the lamb.\nWith all the sainted hosts above,\nbefore the great I Am!', 'Ein neues Lied hab ich gelernt,\ndes Heilands Lobgesang;\nnun sing\' ich Ihm, erlöst, befreit,\nmit frischem Liebesdrang.\r\nEs schall\' mein Leben lang\ndem Herrn mein Lobgesang;\nich singe Ihm, erlöst, befreit,\nmit ew\'gem Liebesdrang.\r\nEin Lied des Friedens sing\' ich jetzt,\ndenn Jesus gab mir Ruh\';\nden Sturm des Herzens stille Er,\nund sprach mir Frieden zu.\r\nIch sing\' der neuen Liebe Lied,\nwiewohl kein Lied ermisst,\nwie hoch, wie lang, wie breit,\nwie tief die Liebe Jesu ist.\r\nMein Lied ist wahrer Freude Lied,\nEr salbt mein Haupt mit Öl.\nEr schenkt den Gnadenbecher voll,\nEr macht mein Auge hell.\r\nUnd einst sing\' ich das beste Lied,\ndas nie ein Mensch erdacht.\nBis es die gold\'ne Stadt durchzieht,\nin Jesu Bild erwacht.'),
(9, '0340', 'Ein Oberster kam einst zu Jesus bei Nacht  -  A Ruler once came to Jesus by Night   (Wer nicht aus Gott geboren, geht ewig einst verloren)', 'A ruler once came to Jesus by night\nto ask Him the way of salvation and light.\nThe Master made answer in words true and plain:\n"Ye must be born again."\r\nYe must be born again,\nye must be born again.\nI verily, verily say unto thee:\n"Ye must be born again."\r\nYe children of men, attend to the word,\nso solemnly uttered by Jesus the Lord.\nAnd let not this message to you be in vain,\n"Ye must be born again."\r\nO ye who would enter that glorious rest,\nand sing with the ransomed the song of the blest.\nThe life everlasting if ye would obtain,\n"Ye must be born again."\r\nA dear one in heaven thy heart yearns to see,\nat the beautiful gate may be watching for thee.\nThen list to the note of this solemn refrain,\n"Ye must be born again."', 'Ein Oberster kam einst zu Jesus bei Nacht\nund fragt, was zu Erben des Himmelsreichs macht.\nDa sagte ihm Jesus die Wahrheit ganz fein:\n"Ihr müsset von Neuem geboren sein!"\r\nWer nicht aus Gott geboren,\ngeht ewig einst verloren.\nD\'rum höret es: Wahrlich, in Christus\ngilt nur eine neue Kreatur!\r\nO Sünder, vernehmt dies wahrhaftige Wort,\ndas Jesus so mächtig verkündigte dort.\nAch, ging es euch heute durch Mark und durch Bein:\n"Ihr müsset von Neuem geboren sein!"\r\nIhr Lieben, wer möcht\' nicht das Himmelreich seh\'n\nund droben zur Rechten des Vaters einst steh\'n?\nSo hört\'s, die ihr wollet als Erben hinein:\n"Ihr müsset von Neuem geboren sein!"\r\nO, denkt an die Sei\'gen, die euch schon voran\nund sehnsuchtsvoll warten auch euch zu umfahn!\nAch, wollt ihr so werden, so himmlisch und rein,\nihr müsset von Neuem geboren sein!'),
(9, '0341', 'Ein Ort ist mir gar lieb und wert, wo keine Last uns mehr beschwert  -  From ev\'ry stormy Wind that blows, from ev\'ry swelling Tide of Woes   (O Gnadenthron, o Gnadenthron)', 'From ev\'ry stormy wind that blows,\nfrom ev\'ry swelling tide of woes,\nthere is a calm, a sure retreat;\n\'tis found beneath the mercy seat.\r\nO throne of grace, o throne of grace,\no blessed throne of grace!\nHere I found salvation in the Son.\r\nThere is a place where Jesus sheds\nthe oil of gladness on our heads,\na place than all besides more sweet;\nit is the blood-stained mercy seat.\r\nThere is a spot where spirits blend,\nwhere friend holds fellowship with friend,\ntho\' sundered far; by faith they meet\naround the common mercy seat.\r\nThere, there on eagle wings we soar,\nand time and sense seem all no more,\nand heav\'n comes down our souls to greet,\nand glory crowns the mercy seat.', 'Ein Ort ist mir gar lieb und wert,\nwo keine Last uns mehr beschwert!\nHier singt das Herz in süßem Ton!\nO, das ist Gottes Gnadenthron!\r\nO Gnadenthron, o Gnadenthron,\no sel‘ger Gnadenthron!\nHier fand ich Heil im Sohn.\r\nHier gießt der Herr sein Freudenöl\nauf jede kindlich gläub\'ge Seel\'!\nUnd ist ihr Schild und großer Lohn,\no teurer, sel\'ger Gnadenthron!\r\nHier wird der Feind zum besten Freund\nund singt mit ihm im Herrn vereint.\nDes Satans Heer flieht scheu davon,\no, blutbesprengter Gnadenthron!\r\nAuf Adlersflügeln schwingt das Herz\nsich hoch empor aus allem Schmerz.\nHier fällt ihm zu die Lebenskron\',\no, ewig teurer Gnadenthron!'),
(9, '0342', 'Ein reines Herz', NULL, 'Schaffe in mir ein reines Herz\nUnd gib mir einen neuen Geist\nVerwirf mich nicht von deinem Angesicht\nNimm deinen Heiligen Geist nicht von mir\nHilf mir wieder auf und gib mir wieder neue Kraft\n(2x)'),
(9, '0343', 'Ein schöner Abend, ich blick zurück   (Am Ende Jesus das ist, was bleibt)', NULL, 'Ein schöner Abend, ich blick zurück,\ndurch all die Jahre schweift jetzt mein Blick.\nDie Trauer ging und auch das Glück,\nam Ende blieb Jesus allein!\r\nAm Ende Jesus das ist, was bleibt; das andre geht\ndoch mit der Zeit, so wie der Wind die Spreu vertreibt;\nNur Jesus nicht, nur Jesus nicht.\r\nIch kenn\' das Leben von jeder Seite,\nGutes und Schlechtes, ich kenn\' es beides.\nUnd nach dem Jauchzen kam oft das Leiden.\nNur eines blieb: Jesus allein!\r\nO Pilger, was noch wird vor uns sein?\nIn was kommst du, komm ich hinein?\nAuch das wird einmal zu Ende sein,\nam Ende bleibt Jesus allein!'),
(9, '0344', 'Ein Tagwerk für den Heiland  -  One more day’s Work for Jesus   (Ein Tagwerk für den Heiland)', 'One more day’s work for Jesus,\none less of life for me!\nBut heav’n is nearer,\nand Christ is dearer,\nthan yesterday to me.\nHis love and light\nfill all my soul tonight.\r\nOne more day’s work for Jesus,\none more day’s work for Jesus,\none more day’s work for Jesus,\none less of life for me!\r\nOne more day’s work for Jesus,\nhow glorious is my King!\n’Tis joy, not duty,\nto speak His beauty.\nMy soul mounts on the wing\nat the mere thought\nhow Christ my life has bought.\r\nOne more day’s work for Jesus,\nhow sweet the work has been.\nTo tell the story,\nto show the glory,\nwhen Christ’s flock enter in!\nHow it did shine\nin this poor heart of mine!\r\nOne more day’s work for Jesus!\nOh, yes, a weary day.\nBut heav’n shines clearer\nand rest comes nearer\nat each step of the way.\nAnd Christ in all -\nBefore His face I fall.\r\nOh, blessed work for Jesus!\nOh, rest, at Jesus’ feet!\nThere toil seems pleasure,\nmy wants are treasure,\nand pain for Him is sweet.\nLord, if I may,\nI’ll serve another day.', 'Ein Tagwerk für den Heiland,\ndas ist der Mühe wert.\nDie Welt wird kleiner,\ndas Herz wird reiner,\ndas ist\'s, was er beschert,\nwas er uns heißt,\ngibt er durch seinen Geist.\r\nEin Tagwerk für den Heiland,\nein Tagwerk für den Heiland,\nein Tagwerk für den Heiland,\ndas ist der Mühe wert.\r\nEin Tagwerk für den Heiland,\nwie groß ist der Beruf!\nEs ist kein Zwingen,\nes ist ein Dringen\nder Liebe, die mich schuf.\nIch bin nicht mein,\nmein alles ist ja sein.\r\nEin Tagwerk für den Heiland,\ndie Arbeit ist so süß.\nDas Heil von Sünden\nlaut zu verkünden,\ndas bringet Lohn gewiss.\nAuf Erden schon\ngibt er uns seinen Lohn.\r\nEin Tagwerk für den Heiland!\nOft wird man freilich matt;\ndoch gibt er Stärke\nzu seinem Werke,\nsteht bei mit Rat und Tat.\nHerr, hilf du mir,\nnoch fleißig wirken hier!\r\nEin Tagwerk für den Heiland.\nO, wirket immer zu!\nTrotz Weltgetümmel\nist man im Himmel,\nhat in der Unruh Ruh\'!\nHerr, hilf Du mir\nnoch fleißig wirken hier!'),
(9, '0345', 'Ein volles, freies, ewges Heil  -  Salvation full and free is ours', 'Salvation full and free is ours\nby Jesus\' off\'ring brought.\nTake gratefully these godly pow\'rs,\nour blessedness they\'ve wrought!\r\nToday He offers once again\nHis Spirit\'s strength and pow\'r,\nthat thro\' His word we may obtain\nnew life and strength each hour.\r\nThe word of God is crystal clear,\nupheld so loyally\nby Jesus Christ, eternal,\nnear, our Saviour true is He!\r\nThe Saviour died, the Saviour lives.\nHis death had this effect:\nHis sacrifice our sin forgives,\nHe died for His elect.\r\nLord Jesus, I lay at Thy feet\nmy heart, and supplicate;\nThy Spirit make my life complete,\nmy being penetrate.', 'Ein volles, freies, ewg\'es Heil\nhat Jesus uns gebracht.\nMein Herz, ergreife jetzt dein Teil,\ndas völlig selig macht!\r\nO zweifle nicht am Wort des Herrn!\nO klügle nicht daran!\nNein, glaub vielmehr: Gott tut so gern\nmehr, als man denken kann!\r\nSein Wort verheißt ja sonnenklar,\ngestützt auf Gottes Treu,\nwie Jesus Christus, ewig wahr,\nein ganzer Heiland sei.\r\nD\'rum starb Er auch, d\'rum lebt Er nun,\nd\'rum wirkt Sein Heil\'ger Geist.\nWas Er tut, will Er völlig tun,\ndas Ihn Sein Werk auch preist.\r\nHerr Jesus, sieh, hier leg ich mich\nDir ganz zum Opfer hin!\nIch glaub von Herzensgrund an Dich;\nDich preist mein ganzer Sinn.'),
(9, '0346', 'Ein wunderbarer Name hier auf Erden  -  I\'ve learned to know a Name I highly treasure   (Er ist so wunderbar, der Name Jesus)', 'I\'ve learned to know a name I highly treasure,\no how it thrills my spirit through and through!\nO precious name, beyond degree or measure,\nmy heart is stirred whene\'er I think of You!\r\nMy heart is stirred when e\'er I think of Jesus,\nthat blessed name which sets the captive free.\nThe only name through which I find salvation,\nno name on earth has meant so much to me.\r\nHe is a name above all names,\nin Him everything is given us by God,\nin Him the Word of God is Yes and Amen,\nin Him is victory in life and in death.\r\nThat name brings gladness to a soul in sorrow,\nit makes life\'s shadows and its clouds depart.\nBrings strength in weakness for today, tomorrow,\nthat names brings healing to an aching heart.\r\nThat name still lives and will live on forever,\nwhile kings and kingdoms will forgotten be.\nThrough mist and rain, \'twill be beclouded never,\nthat name shall shine and shine eternally.', 'Ein wunderbarer Name hier auf Erden\nerfüllt mit Freud\' mein Herz und meinen Sinn.\nWohl kann ich deshalb missverstanden werden,\nund doch durch Ihn ich mehr als glücklich bin.\r\nEr ist so wunderbar, der Name Jesus,\nklingt süßer als die schönste Melodie.\nIn Ihm ist Heil und völlige Erlösung,\nEr schenkt mir Frieden, Ruh\' und Harmonie.\r\nEr ist ein Name über alle Namen,\nin Ihm ist alles uns geschenkt von Gott,\nin Ihm hat Gottes Wort Sein Ja und Amen,\nin Ihm ist Sieg im Leben und im Tod.\r\nEr bringt mir Trost in schweren Prüfungsstunden,\nwenn\'s dunkel wird und alles wankt und bricht.\nJa, wenn es scheint als gehe alles unter,\nschenkt Er auf\'s neu mir Mut und Zuversicht.\r\nSein Ruhm ist groß und mehr noch wird Er finden,\nbald legt mit Macht Er alles unter sich.\nUnd wenn einst andre große Namen schwinden,\ndann strahlt der Name Jesus ewiglich.'),
(9, '0347', 'Einen Freund hab ich in Jesus  -  I\'ve found a Friend in Jesus   (Die Lilie im Tale, der helle Morgenstern)', 'I have found a friend in Jesus, He\'s everything to me,\nHe\'s the Fairest of ten thousand to my soul.\nThe Lily of the Valley in Him alone I see,\nall I need to cleanse and make me fully whole.\nIn sorrow He\'s my comfort, in trouble He\'s my stay.\nHe tells me every care on Him to roll.\r\nHe\'s the Lily of the Valley, the Bright and Morning Star,\nHe\'s the fairest of ten thousand to my soul.\r\nHe all my grief has taken, and all my sorrows borne,\nin temptation He\'s my strong and mighty tower.\nI have all for Him forsaken, and all my idols torn from my heart,\nand now He keeps me by His power.\nThough all the world forsake me, And Satan tempts me sore,\nthrough Jesus I shall Safely reach the goal.\r\nHe will never, never leave me, nor yet forsake me here,\nwhile I live by faith and do His blessed will.\nA wall of fire about me, I\'ve nothing now to fear,\nwith His manna He my hungry soul shall fill.\nThen sweeping up to glory, to see His blessed face,\nWhere rivers of delight shall ever roll!', 'Einen Freund hab ich in Jesus,\nder ist an Gnaden reich;\nder Schönste unter Tausenden ist Er.\nDie Lilie im Tale, der keine Blume gleich,\nSeine Liebe ist viel tiefer als das Meer.\nIn Trübsal und in Leiden steht Er mir niemals fern.\n"Auf Mich wirf die Sorgen alle!" spricht der Herr.\r\nDie Lilie im Tale, der helle Morgenstern,\nauserkoren unter Tausenden ist Er!\r\nMeine Schuld hat Er bezahlet mit Seinem teuren Blut,\nin Versuchung will Er mächtig bei mir sein.\nIch hab mich Ihm ergeben mit Seele, Leib und Gut,\nund mit Seinem Reichtum ist Er völlig mein.\nOb mich die Welt verhöhnet, ich trag es alles gern.\n"Auf Mich wirf die Sorgen alle!" spricht der Herr.\r\nEr wird nimmer mich verlassen, wird treulich bei mir sein,\nauf den grünen Auen weidet mich mein Hirt\'.\nGetrost will ich mit Jesus durchs dunkle Tal auch zieh\'n,\ndenn kein Unheil fürchte ich, wenn Jesus führt.\nUnd steh ich vor dem Throne und schaue meinen Herrn,\nsing ich jauchzend mit Erlösten nur noch mehr:'),
(9, '0348', 'Einen goldnen Wanderstab ich in meinen Händen hab', NULL, 'Einen goldnen Wanderstab\nich in meinen Händen hab;\naus dem Himmel ist er her,\nnach dem Himmel weist er:\nDieser Stab, seht, ist mein Glaube,\nhält mich aufrecht hier im Staube,\ntrennt auch Leib und Seele sich,\nauf Ihn trau und baue ich.\r\nUnd ein Engel freundlich mild,\nmeines Gottes Ebenbild,\nwohnt in meiner Seele still,\nlenket mich, wie Gott es will.\nDieser Engel ist die Liebe,\no dass sie "die erste" bliebe!\nSie macht uns zu Brüdern gleich,\nführet uns zu Gottes Reich.\r\nUnd am Himmel, hell und rein,\nsteht ein Sternlein, das ist mein;\nwinkt und lächelt mir zur Lust,\nfüllt mit Wonne meine Brust.\nDieses Sternlein ist das Hoffen,\nsieht von fern den Himmel offen;\nführet die, die Ihm vertrau\'n,\nzu des Himmels sel\'gen Au\'n.'),
(9, '0349', 'Einer bleibt König, wenn alles erlieget', NULL, 'Einer bleibt König, wenn alles erlieget;\nEiner wird leben, wenn alles erstirbt;\nJesus, der Starke, der alles besieget,\nder uns das Erbteil der Himmel erwirbt.\nAlles mag brechen, zerfallen, zerstäuben,\nJesu Erbarmung wird ewig doch bleiben.\r\nAmen! Sie bleibt uns auf ewig geschenket!\nSpottet, ihr Feinde, wir bleiben doch steh\'n!\nOb man uns hasset, verfolget und kränket,\nmögen auch manche von Jesu noch geh\'n:\nBleiben wir gläubig am Haupte nur hangen,\nwerden wir dennoch das Kleinod erlangen!\r\nJesus hat alles in mächtigen Händen,\nherrschet auch unter der feindlichen Schar;\nEr, der da konnte am Kreuze vollenden,\nbietet auch heute Sein Leben uns dar.\nDie uns hier wollen vertilgen und stören,\nmüssen das Heil uns noch fördern und mehren.\r\nHier ist Immanuel vor seinem Heere,\nder die Gemeinde sich selber erhält!\nEr in der Mitte, als Mauer und Wehre,\nbleibt auch bei uns bis ans Ende der Welt.\nEr ist derselbige, gestern und heute,\nja, bis in Ewigkeit mächtig im Streite!'),
(9, '0350', 'Einer der Wenigen, Herr, darf ich sein  -  I am one of the few, yes, one of the few', 'I am one of the few, yes, one of the few,\nand by faith in God\'s word I can claim it.\nThough the way may seem long,\nand the opposition strong,\nfor the bride there\'s a way provided!\r\nIf I plan to go through,\njust to hope will not do,\nfor I must firmly be decided.\nTo follow the Lord,\nby obeying His Word,\nand believe that I\'m one of the few.', 'Einer der Wenigen, Herr, darf ich sein,\nund mein Anspruch im Wort ist begründet.\nMag der Weg lang auch sein,\nund der Feind gar nicht klein,\nfür die Braut ist ein Weg bereitet!\r\nWenn ich hoff\' dort zu sein,\ndas genügt nicht allein,\nnur die feste Entscheidung, die bringt es.\nZu folgen dem Wort, gehorchen sofort,\nund zu glauben: Wir seh\'n uns einst dort!'),
(9, '0351', 'Eines Tages hörte ich dass Jesus lebt   (Und Seine Liebe ist viel wärmer als der wärmste Sonnenschein)', '\r\nHis love is warmer than the warmest sunshine, softer than a sigh.\nHis love is deeper than the deepest ocean, wider than the sky.\nHis love is brighter than the brightest star, that shines every night above.\nAnd there is nothing in this world that can ever change His love.\r\n', 'Eines Tages hörte ich, dass Jesus lebt,\ndass Er für mich starb und auferstand.\nSeine Freude füllte nun mein Leben ganz.\nAlles wurde neu, als ich Ihn fand.\r\nUnd Seine Liebe ist viel wärmer als der wärmste Sonnenschein,\nsie ist viel tiefer als das Meer und als der tiefste Ozean.\nSie ist viel weiter als der Kosmos und der weiteste Stern\nund es gibt nichts, was Gottes Liebe überragt.\r\nKennst du Jesus schon, der Dich unendlich liebt?\nEr nimmt deine Schuld und macht dich froh.\nEr kennt deinen Weg und führt dich jeden Tag.\nLebe doch mit Ihm, Er liebt dich so.'),
(9, '0352', 'Eines wünsch\' ich mir vor allem andern', NULL, 'Eines wünsch\' ich mir vor allem andern,\neine Speise früh und spät.\nSelig lässt\'s im Tränental sich wandern,\nwenn dies eine mit uns geht:\nUnverwandt auf einen Mann zu schauen,\nder mit blutig\'m Schweiß und Todesgrauen\nauf sein Antlitz niedersank\nund den Kelch des Vaters trank.\r\nEwig soll Er mir vor Augen stehen,\nwie Er als ein stilles Lamm\ndort so blutend und so bleich zu sehen,\nhängend an des Kreuzes Stamm,\nwie Er dürstend rang um meine Seele,\ndass sie Ihm zu Seinem Lohn nicht fehle,\nund dann auch an mich gedacht,\nals Er rief : "Es ist vollbracht!"\r\nJa, mein Jesus, lass mich nie vergessen\nmeine Schuld und deine Huld!\nAls ich in der Finsternis gesessen,\ntrugest Du mit mir Geduld,\nhattest längst nach Deinem Schaf getrachtet,\neh\' es auf des Hirten Ruf geachtet,\nund mit teurem Lösegeld\nmich erkauft von dieser Welt.\r\nIch bin Dein! Sprich Du darauf dein Amen!\nTreu\'ster Jesus, Du bist mein!\nDrücke Deinen süßen Jesusnamen\nbrennend in mein Herz hinein!\nMit Dir alles tun und alles lassen,\nin Dir leben und in Dir verblassen,\ndas sei bis zur letzten Stund\'\nunser Wandel, unser Bund!'),
(9, '0353', 'Einst ging es Noah nicht anders als dir   (On the Wings of a snow-white Dove)', '\r\nOn the wings of a snow-white dove,\nGod sends His pure sweet love.\nA Sign from above,\non the wings of a dove.\r\n\r\n\r\n', 'Einst ging es Noah nicht anders als dir.\nRundum nur noch Wogen, so geht\'s oft auch mir.\nden Blick stets nach oben vor dem Fenster er stand.\nZurück kam die Taube und flog in seine Hand.\r\nEine schneeweiße Taube fliegt,\nbringt Gottes reine Lieb,\nkommt als Zeichen herab,\ndass Gott Gnade dir gab.\r\nJesus dein Retter kam einstmals herab,\nim Stall eine Krippe und Stroh man Ihm gab.\nVon Menschen verachtet und gering nur geschätzt.\nDas Lamm war Er dennoch, und die Taube sich setzt.\r\nich hab gelitten bei Tag und bei Nacht,\nder Glaube bekannte was das Kreuz mir gebracht.\nJa, Gott kam mit Heilung, und ein Zeichen Er gab:\nSanft wie eine Taube kam die Gnade herab.\r\nWillst du anbeten in Wahrheit und Geist,\ndann komm heut\' zu Jesus und sprich zu Ihm leis\':\n"Herr, ich bin ein Sünder, doch ich glaube Dein Wort.\nMach heut\' für die Taube auch mich zum Ruheort."'),
(9, '0354', 'Einst sing ich nicht mehr wie ich sang  -  Some day the silver cord will break   (Dort rühm ich: Herr, Du hasts vollbracht)', 'Some day the silver cord will break,\nand I no more as now shall sing.\nBut oh, the joy when I shall wake\nwithin the palace of the King!\r\nAnd I shall see Him face to face,\nand tell the story – Saved by grace.\nAnd I shall see Him face to face,\nand tell the story – Saved by grace.\r\nSome day my earthly house will fall,\nI cannot tell how soon ’twill be.\nBut this I know – my All in All\nhas now a place in heav’n for me.\r\nSome day, when fades the golden sun\nbeneath the rosy-tinted west.\nMy blessed Lord will say, “Well done!”\nAnd I shall enter into rest.\r\nSome day: Till then I’ll watch and wait,\nmy lamp all trimmed and burning bright.\nThat when my Saviour opes the gate,\nmy soul to Him may take its flight.', 'Einst sing ich nicht mehr wie ich sang.\nDie Saite springt, es naht die Nacht\nDoch sel\'ge Lust, es währt nicht lang\ndann bin beim König ich erwacht.\r\nDort rühm\' ich: "Herr, Du hast\'s vollbracht!\nNur Gnade ist\'s die selig macht."\nDort rühm\' ich: "Herr, Du hast\'s vollbracht!\nNur Gnade ist\'s die selig macht."\r\nEinst wankt mein Leib hier und zerfällt.\nich weiß nicht Ort, ich weiß nicht Zeit.\nDoch ist\'s gewiss, mein Jesus hält\nschon Wohnung droben mir bereit.\r\nJa einst, vielleicht im Abendschein,\nwird auch an mich der Ruf ergeh\'n.\nKomm, Kindlein, stell die Arbeit ein!\nDu darfst jetzt ruh\'n und Jesus seh\'n!\r\nJa einst, bis dahin wart ich still,\ndie Lampe brennt, und unverweilt\nwenn mir mein König auftun will,\ndie Seele jubelnd zu Ihm eilt.'),
(9, '0355', 'Einst war Christus ganz verborgen  -  Once our blessed Christ of beauty   (O, siehst du den Mann der Schmerzen)', 'Once our blessed Christ of beauty\nwas veiled off from human view.\nBut thro\' suffering, death and sorrow\nHe has rent the veil in two.\r\nO behold the Man of Sorrows,\no behold Him in plain view.\nLo! He is the mighty conqu\'ror,\nsince He rent the veil in two.\nLo! He is the mighty conqu\'ror,\nsince He rent the veil in two.\r\nNow He is with God the Father,\ninterceding there for you.\nFor He is the mighty conqu\'ror,\nsince He rent the veil in two.\r\nHoly angels bow before Him,\nmen of earth give praises due.\nFor He is the well-belovèd\nsince He rent the veil in two.\r\nThro\'out time and endless ages,\nheights and depths of love so true.\nHe alone can be the giver\nsince He rent the veil in two.\r\nThrough the word in this time,\nwhich has been given to us,\nwe can see the Christ,\nbecause the curtain He tore.', 'Einst war Christus ganz verborgen,\nnicht zu seh\'n für dich und mich.\nDoch als Er am Kreuz gestorben,\ndann der Vorhang ganz zerriss.\r\nO, siehst du den Mann der Schmerzen,\nganz enthüllt vor deinem Blick?\nEr, der mächtige Eroberer,\nseit den Vorhang er zerriss.\nEr, der mächtige Eroberer,\nseit den Vorhang er zerriss.\r\nJetzt ist Er mit Gott dem Vater,\ntritt dort ein für dich und mich,\nEr der mächtige Eroberer,\nseit den Vorhang Er zerriss.\r\nEngel fallen vor Ihm nieder,\nder des Preises würdig ist.\nUnd wir Menschen sind so dankbar,\ndass den Vorhang Er zerriss.\r\nDurch die Zeit und Ewigkeiten,\nsind wir Seiner Lieb\' gewiss.\nIhm, dem Geber alles Guten,\nseit den Vorhang Er zerriss.\r\nDurch das Wort in dieser Zeit,\ndas uns gegeben worden ist,\nkönnen wir den Christus sehen,\nweil den Vorhang Er zerriss.'),
(9, '0356', 'Einst war ich ganz in Sünden tot, alle Hoffnung war dahin   (Ists möglich gab denn Jesus sich auch in den Tod für mich)', NULL, 'Einst war ich ganz in Sünden tot,\nalle Hoffnung war dahin.\nDoch hab ich nun durch Christi Tod\nSein Leben zum Gewinn.\r\nIst\'s möglich? Gab denn Jesus sich\nauch in den Tod für mich?\nMein Heiland, ja, ich glaub an Dich\nund lieb Dich ewiglich!\r\nO, welche Höhe unerreicht!\nWelch Tiefe ohne Grund!\nO Liebe, die das Herz erweicht,\nDu machtest mich gesund!\r\nO undankbares, kaltes Herz,\ndas sich von Jesus trennt,\nstatt dass es liebend himmelwärts\nin Flammen schlägt und brennt!\r\nIch lebe, aber nun nicht ich,\nnein, Christus lebt in mir.\nDer in den Tod sich gab für mich\nund hebt mich für und für.'),
(9, '0357', 'Einst war ich gar weit von dem Heiland  -  I was once far away from the Saviour', 'I was once far away from the Saviour,\nand as vile as a sinner could be.\nI wondered if Christ, the Redeemer,\ncould save a poor sinner like me.\r\nI wandered on in the darkness,\nnot a ray of light could I see.\nAnd the tho\'t filled my heart with sadness,\nthere\'s no help for a sinner like me.\r\nAnd then in that dark, lonely hour,\na voice sweetly whispered to me,\nsaying Christ, the Redeemer, has power\nto save a poor sinner like me.\r\nI listened, and lo! \'twas the Saviour\nwho was speaking so kindly to me.\nI cried, I\'m the chief of sinners,\noh, save a poor sinner like me.\r\nI then fully trusted in Jesus,\nand, oh, what a joy came to me!\nMy heart was filled with his praises,\nfor saving a sinner like me.\r\nNo longer in darkness I\'m walking,\nfor the light is now shining on me,\nand now unto others I\'m telling\nhow he saved a poor sinner like me.\r\nAnd when life\'s journey is over,\nand I the dear Saviour shall see,\nI\'ll praise him for ever and ever,\nfor saving a sinner like me.', 'Einst war ich gar weit von dem Heiland,\nso weit, wie ein Mensch nur kann sein;\nund ich dachte: "Lässt Christ, der Erlöser,\neinen Sünder wie mich wohl herein?\r\nIch irrte alleine im Finstern,\nder letzte Stern auch verblich;\nich seufzte: "Es gibt keine Hoffnung\nfür solch einen Sünder wie mich."\r\nDoch da, in der dunkelsten Stunde\nsprach sanft eine Stimme zu mir:\n"Nein, Jesus gibt Heil und Vergebung\neinem reuigen Sünder wie dir."\r\nIch horchte und sah, es war Jesus;\nEr neigte so huldreich sich.\nIch rief: "Jesus, hast Du noch Gnade\nfür den größten der Sünder, für mich?"\r\nDa gab ich mein Herz meinem Heiland,\nda ward mir Sein Friede zuteil;\nnun preis ich, begnadigter Sünder,\nSein freies und völliges Heil.\r\nJetzt irre ich nicht mehr im Finstern!\nJetzt dien\' ich dem Herrn, der mich liebt,\nund erzähl es den anderen allen,\nwie Jesus den Sündern vergibt.\r\nUnd rufst Du mich heim, o mein Jesus,\ndann preis ich in Ewigkeit Dich;\nDu suchtest und fandst einen armen,\nverlorenen Sünder wie mich.'),
(9, '0358', 'Einst war meine Seel gebunden von den Dingen dieser Welt  -  Once my Heart and soul were fettered by the binding Chains of Sin   (Glory, glory, Halleluja, preis sei Seinem heilgen Nam)', 'Once my heart and soul were fettered\nby the binding chains of sin.\nBut the great Emancipator\nset me free to worship Him.\r\nGlory, glory, Hallelujah,\nblessed be His holy name!\nHe\'s the great Emancipator,\nthat\'s the song of the redeemed.\r\nLike a lost lamb i was drifting\no so helpless and alone.\nBut the seeking Shepherd found me,\nled me to my Fathers home.\r\nHe died for me on the cross,\npaid the price for me.\nYes the mighty Emancipator\nconquered over sin and grave.\r\nOh how wonderful it\'s with Jesus,\nHe faithfully cares for me His child,\nWith Him I\'m safe and sound,\nuntil he takes me home.', 'Einst war meine Seel\' gebunden\nvon den Dingen dieser Welt.\nDoch der mächtige Befreier\nmacht\' mich frei, zu dienem Ihm.\r\nGlory, glory, Halleluja,\npreis sei Seinem heil\'gen Nam\'!\nEr, der mächtige Befreier,\noh wie bete ich Ihn an!\r\nWie ein Lamm war ich verloren,\no so hilflos und allein,\ndoch der gute Hirte fand mich,\nführte mich zum Vater heim.\r\nEr starb dort für mich am Kreuze,\nhat den Preis für mich bezahlt.\nJa der mächtige Befreierr\nsiegte über Sünd\' und Grab.\r\nO wie herrlich ist\'s bei Jesus,\nEr sorgt treu für mich Sein Kind,\nbei Ihm bin ich recht geborgen,\nbis er mich nach Hause nimmt.'),
(9, '0359', 'Einst war weit ich entfernt von dem himmlischen Weg  -  Once my Soul was astray from the heavently Way   (Als Er reichte die Hand zu mir)', 'Once my soul was astray from the heavently way\nand was wretched und vile, as coud be.\nBut my Saviour above gave me peace, joy and love,\nwhen He reach\'d down His hand for me.\r\nWhen He reached down His hand for me,\nwhen He reach\'d down His hand for me.\nI was lost and undone without God or His Son,\nwhen He raech\'d down His hand for me.\r\nI was nearing dispair, whe He came to me there\nand He showed me that I could be free.\nThen He lifted my feet, gave me glory complete,\nwhen He reach\'d down his hand for me.\r\nHow my heart doth rejoice since I made Him my choice\nfrom the tempest to Him now I flee.\nNow I leen on His arme I\'m secure from all barm,\nsince He reach\'d down his hand for me.\r\nSince the Lord gave me peace, heav\'nly joys never cease,\nLord I give all my life unto Thee.\nGuide my feet, hold ny hand, grant with Thee I may stand.\nFor You reached down Your hand for me.', 'Einst war weit ich entfernt von dem himmlischen Weg\nund war elend , unwürdig, beschwert.\nDoch mein Heiland, der Herr, gab mir Fried\', Freud\' und Lieb\',\nals Er reichte die Hand zu mir.\r\nAls Er reichte die Hand zu mir,\nwar verloren und tot,\nohne Gott unserm Herrn\nals Er reichte die Hand zu mir.\r\nAls verzweifelt ich war, kam der Herr dort zu mir\nund Er sagte mir: "Frei kannst du sein!"\nUnd Er hob mich hier auf, gab mir Fried\', Freud\' und Lieb,\nals Er reichte die Hand zu mir.\r\nWie mein Herz sich erfreut, seit ich Dich hab erwählt.\nVon Stürmen flieh\' ich jetzt zu Dir.\nNun lehn\' ich mich auf Dich, bin geborgen vor Angst,\nseit Du reichtest die Hand zu mir.\r\nSeit ich hab Deinen Fried\' hört die Freude nicht auf.\nHerr ich gab nun mein Leben ganz Dir.\nFühre Du mich, o Herr, halt Du meine Hand.\nHerr, ich reich\' meine Hand nur Dir.'),
(9, '0360', 'Einst wars nur der Segen, jetzt ist Gott mein Hort  -  Once it was the Blessing, now it is the Lord   (Alles , alles Jesus, Jesus nur allein)', 'Once it was the blessing, now it is the Lord.\nOnce it was the feeling, now it is His Word.\nOnce His gift I wanted, now the Giver own.\nOnce I sought for healing, now Himself alone.\r\n\r\nOnce ’twas painful trying, now ’tis perfect trust.\nOnce a half salvation, now the uttermost.\nOnce ’twas ceaseless holding, ow He holds me fast.\nOnce ’twas constant drifting, now my anchor’s cast.\r\nOnce ’twas busy planning, now ’tis trustful pray’r.\nOnce ’twas anxious caring, now He has the care.\nOnce ’twas what I wanted, now what Jesus says.\nOnce ’twas constant asking, now ’tis ceaseless praise.\r\nOnce it was my working, His it hence shall be.\nOnce I tried to use Him, now He uses me.\nOnce the pow’r I wanted, now the Mighty One.\nOnce for self I labored, now for Him alone.\r\nOnce I hoped in Jesus, now I know He’s mine.\nOnce my lamps were dying, now they brightly shine.\nOnce for death I waited, now His coming hail.\nAnd my hopes are anchored, safe within the veil.', 'Einst war\'s nur der Segen, jetzt ist Gott mein Hort.\nEinst sucht ich Gefühle, jetzt ruh\' ich im Wort.\nEinst wünscht ich die Gaben, eh der Geber mein.\nEinst wollt ich die Heilung, jetzt nur Ihn allein.\r\nAlles, alles Jesus,\nJesus nur allein.\nAlles nur in allem\nsoll Jesus selbst mir sein.\r\nEinstmals kämpft ich mühsam, nun vertrau ich still.\nEinst war\'s halbes Leben, jetzt hab ich die Füll\'.\nEinst hielt ich mich krampfhaft, jetzt hält Er mich fest.\nEinst trieb ich im Sturm, jetzt nie mein Halt mich lässt.\r\nEinst gab\'s eigne Pläne, jetzt heißt\'s: Nicht mehr ich.\nEinst macht ich mir Sorgen, jetzt sorgt Er für mich.\nEinst galt\'s meine Wünsche, jetzt was Jesus will.\nEinst fragt ich: Warum nur? Jetzt bin ich ganz still.\r\nEinst war\'s meine Arbeit. Jetzt tut Er\'s allein.\nEinst wollt ich Ihn brauchen jetzt bin ich nur Sein.\nEinst erstrebt ich Kräfte, jetzt in Ihm ich ruh\'.\nEinst wollt ich\'s erzwingen, jetzt schau ich nur zu.\r\nEinst sprach ich vom Hoffen, jetzt ist alles klar;\nmeine Lampe leuchtet, die einst trübe war.\nEinst harrt ich des Todes, jetzt weiß ich, Er naht.\nWas ich weiß und habe, dank ich Seiner Gnad\'!'),
(9, '0361', 'Einzig Dich mein Herzensheiland  -  Only Thee, my Soul’s Redeemer   (Einzig Dich meine ich, liebster Heiland, einzig Dich)', 'Only Thee, my soul’s Redeemer!\nWhom have I in Heaven beside?\nWho on earth, with love so tender,\nall my wandering steps will guide?\r\nOnly Thee, only Thee.\nLoving Saviour, only Thee.\r\nOnly Thee! no joy I covet\nbut the joy to call Thee mine.\nJoy that gives the blest assurance,\nThou hast owned and sealed me Thine.\r\nOnly Thee! I ask no other,\nThou art more than all to me.\nLife, or health, or creature comfort,\nI would give them all for Thee.\r\nOnly Thee, whose blood has cleansed me,\nwould my raptured vision see,\nwhile my faith is reaching upward,\never upward, Lord, to Thee.', 'Einzig Dich, mein Herzensheiland,\nhab ich mir als Herrn erseh\'n,\nder du treu schon hier auf Erden\nmich lehrst sel‘ge Wege geh\'n.\r\nEinzig Dich meine ich,\nliebster Heiland, einzig Dich!\r\nEinzig Dich kennt meine Seele\nals der wahren Freude Grund;\nhab ich Dich, so steh ich sicher\nin dem ew‘gen Friedensbund.\r\nEinzig Dich und keinen andern\nsucht und will mein Herz fortan;\nDich zu haben, zu genießen,\ngeb\' ich alles gern daran.\r\nEinzig Dich, der mich errettet,\nmöcht\' von Angesicht ich schau\'n;\naufwärts schwing\' ich mich im Glauben,\nDich zu seh\'n auf Salems Au\'n.'),
(9, '0362', 'El shaddai, el shaddai, El-elyon na adonai, Age to Age You\'re still the Same, by the Power of the Name', 'El shaddai, el shaddai,\nEl-elyon na adonai,\nage to age You\'re still the same,\nby the power of the name.\nEl shaddai, el shaddai,\nErkamka na adonai,\nwe will praise and lift You high,\nEl shaddai.\r\nThrough Your love and through the ram,\nYou saved the son of abraham,\nthrough the power of Your hand,\nturned the sea into dry land.\nTo the outcast on her knees,\nYou were the God who really sees,\nand by Your might,\nYou set your children free.\r\nThrough the years You\'ve made it clear,\nthat the time of christ was near,\nthough the people couldn\'t see\nwhat Messiah ought to be.\nThough Your word contained the plan,\nthey just could not understand,\nYour most awesome work was done,\nthrough the frailty of Your son.\r\nEl shaddai, el shaddai,\nEl-elyon na adonai,\nage to age You\'re still the same,\nby the power of the name.\nEl shaddai, el shaddai,\nErkamka na adonai,\nI will praise You \'till I die,\nEl shaddai.', NULL),
(9, '0363', 'Er erlöste mich von meinen Sünden   (Chorus)', NULL, 'Er erlöste mich von meinen Sünden\nund machte mich frei.\nEr erlöste mich, Halleluja!\nHalleluja, Preis dem Herrn!'),
(9, '0364', 'Er führet mich der Jugend gleich  -  He leadeth me, o blessed Thought   (Er führt mich treu, Er führt mich fein)', 'He leadeth me, o blessed thought!\nO words with heav’nly comfort fraught!\nWhate’er I do, where’er I be\nstill ’tis God’s hand that leadeth me.\r\nHe leadeth me, He leadeth me,\nby His own hand He leadeth me.\nHis faithful foll’wer I would be,\nfor by His hand He leadeth me.\r\nSometimes ’mid scenes of deepest gloom,\nsometimes where Eden’s bowers bloom,\nby waters still, o’er troubled sea,\nstill ’tis His hand that leadeth me.\r\nLord, I would place my hand in Thine,\nnor ever murmur nor repine.\nContent, whatever lot I see,\nsince ’tis my God that leadeth me.\r\nAnd when my task on earth is done,\nwhen by Thy grace the vict’ry’s won,\ne’en death’s cold wave I will not flee,\nsince God through Jordan leadeth me.', 'Er führet mich der Jugend gleich,\no Himmelswort, an Trostgold reich!\nAuf jeden Pfad, in jedem Land,\nerhält und führt mich Gottes Hand!\r\nEr führt mich treu, Er führt mich fein\nan Seiner Hand tagaus, tagein.\nSein wahrer Jünger möcht ich sein;\ndenn nur mein Herr führt treu und fein.\r\nDurch kalte Nebel, trübe Nacht,\ndurch Gärten, wo der Sommer lacht,\nauf Wogen wild, am grünen Strand,\nführt mich, es führt mich Gottes Hand!\r\nSchließ\' meine Hand in Deine fest\no Herr, dass sie Dich nimmer lässt.\nIn Kreuz und Leid lass sprechen mich:\nHalt Ihm nur still, Er leitet dich!\r\nWenn hier mein Werk beendigt ist\nund Sieg mir winkt durch Jesus Christ,\ndurch Todesgrau\'n auf sich\'rer Bahn\nführt Seine Hand mich himmelan.'),
(9, '0365', 'Er gibt dir mehr Gnade, wenn Sorgen sich mehren  -  He giveth more Grace, when the Burdens grow greater   (Seine Liebe ist unendlich, Seine Gnade unermesslich)', 'He giveth more grace, when the burdens grow greater,\nHe sendeth more strength, when the labors increase.\nTo added affliction, He added His mercy.\nto multiplied trials, His multiplied peace.\r\nHis love has no limit, His grace has no measure,\nHis power has no boundary, known unto men.\nFor out of His infinite riches in Jesus.\nHe giveth, and giveth, and giveth again.\r\nWhen we have exhaused our store of endurance.\nWhen our strength has failed, ere the day is half done.\nWhen we reach the end of our horded resourses,\nour Father\'s full giving is only begun.\r\nWhen Satan assails and temptations grow stronger,\nand often we feel it is too much to bear.\nIn weakness we learn of an infinite Power.\nHis grace is sufficient, our Father does care.\r\nCommunion with Him, oh, what blessed enjoyment!\nForgiven, our sins, by the Blood of His cross.\nNew power receiving for strength in His service,\nHis grace is sufficient to purge all the dross.', 'Er gibt dir mehr Gnade, wenn Sorgen sich mehren,\nEr schenkt dir mehr Kraft, wenn die Arbeit dich drängt.\nVermehrt sich der Kummer, mehrt sich Sein Erbarmen,\nmit härterer Prüfung mehr Frieden Er schenkt.\r\nSeine Liebe ist unendlich, Seine Gnade unermesslich,\nSeine Kraft, Seine Weisheit unbegreiflich sie sind.\nUnergründlich ist der Reichtum den wir haben in Jesus,\ndavon gibt Er und gibt Er und gibt dir stets mehr.\r\nWenn wir unser Leben fast nicht mehr ertragen,\nwenn wir ganz erschöpft, eh die Arbeit getan.\nsind wir ganz am Ende mit unseren Kräften,\ndann soll\'n wir erfahren, dass Er helfen kann.\r\nWenn glaubend wir beten, will Er uns erhören,\nwenn wir Ihm vertrau\'n, werden Wunder wir seh\'n.\nWenn wir Ihm gehorchen, wird den Segen Er mehren,\nwenn wir Ihn hier lieben, werden wir Ihn einst seh\'n.\r\nGemeinschaft mit Ihm, welch gesegneter Genuss!\nUns\'re Sünden vergeben, durch\'s Blut am Kreuz.\nNeue Kraft empfangen für den Dienst mit Ihm,\nSeine Gnad\' ausreichend, um alles zu reinigen.'),
(9, '0366', 'Er hat die ganze Welt in Seiner Hand  -  He\'s got the whole World in His Hand', 'He\'s got the whole world in His hands,\nHe\'s got the whole world in His hands,\nHe\'s got the whole world in His hands,\nHe\'s got the whole world in His hands.\r\nHe\'s got you and me brother in His hands,\nHe\'s got you and me sister in His hands,\nHe\'s got you and me brother in His hands,\nHe\'s got the whole world in His hands.\r\nHe\'s got my father and my mother in His hands,\nHe\'s got my brother and my sister in His hands,\nHe\'s got you and me, in His hands,\nHe\'s got  the whole wide world in His hands.\r\nHe\'s got the little bitty baby in His hands,\nHe\'s got the little bitty baby in His hands,\nHe\'s got the little bitty baby in His hands,\nHe\'s got the whole world in His hands.\r\nHe\'s got everybody here in His hands,\nHe\'s got everybody here in His hands,\nHe\'s got everybody here in His hands,\nHe\'s got the whole world in His hands.', 'Er hat die ganze Welt in Seiner Hand,\nEr hat die ganze Welt in Seiner Hand,\nEr hat die ganze Welt in Seiner Hand,\nEr hat die ganze Welt in Seiner Hand.\r\nEr hat mich und dich, Bruder, in Seiner Hand,\nEr hat mich und dich, Schwester, in Seiner Hand,\nEr hat Vater und Mutter in Seiner Hand,\nEr hat die ganze Welt in Seiner Hand.\r\n\r\n\r\n'),
(9, '0367', 'Er hat mich frei gemacht   (Chorus)', NULL, 'Er hat mich frei gemacht, hat Riegel gesprengt,\nhat mich erlöst und heimwärts gelenkt.\nIhn darf ich schauen in Herrlichkeit,\nJesus, den Herrn, der mich hat befreit.'),
(9, '0368', 'Er hat mich so geliebt; Er hat mich Freund genannt; Das macht mein Herz so froh; Drum schenk ich Ihm mein Herz; Drum lieb ich Ihn so sehr   (5 Chorusse)', NULL, 'Er hat mich so geliebt!\nEr hat mich so geliebt!\nEr starb für mich auf Golgatha,\nEr hat mich so geliebt!\r\nEr hat mich Freund genannt,\nEr hat mich Freund genannt,\nEr starb für mich auf Golgatha,\nEr hat mich Freund genannt.\r\nDas macht mein Herz so froh,\ndas macht mein Herz so froh,\nEr starb für mich auf Golgatha,\ndas macht mein Herz so froh.\r\nD\'rum schenk\' ich Ihm mein Herz,\nd\'rum schenk\' ich Ihm mein Herz,\nEr starb für mich auf Golgatha,\nd\'rum schenk\' ich Ihm mein Herz.\r\nD\'rum lieb\' ich Ihn so sehr,\nd\'rum lieb\' ich Ihn so sehr,\nEr starb für mich auf Golgatha,\nd\'rum lieb\' ich Ihn so sehr.'),
(9, '0369', 'Er ist der Erlöser, Jesus Gottes Sohn   (Danke lieber Vater, Du gabst uns Deinen Sohn)', NULL, 'Er ist der Erlöser,\nJesus Gottes Sohn;\nGottes Lamm erwählt zu tragen\nunserer Sünde Lohn.\r\nDanke lieber Vater,\nDu gabst uns Deinen Sohn.\nDein Geist gibt uns die Kraft zu dienen,\nbis Er wiederkommt.\r\nJesus mein Erlöser,\nhöchster aller Namen,\nGottes Lamm erwählt zu tragen\nunserer Sünde Lohn.\r\nEinst werd\' ich Ihn sehen\nin der Herrlichkeit.\nMeinem König werd\' ich dienen,\nbis in alle Ewigkeit.'),
(9, '0370', 'Er ist der Felsen meiner Rettung, sein Banner über mir ist Lieb\'  -  Jesus is the Rock of my SalvationHis Banner over me is Love', 'Jesus is the Rock of my salvation,\nHis banner over me is love.\nJesus is the Rock of my salvation,\nHis banner over me is love.\nJesus is the Rock of my salvation,\nHis banner over me is love,\nHis banner over me, is love.\r\nHe forgave me all my sins,\nHis banner over me is love.\nHe forgave me all my sins,\nHis banner over me is love.\nHe forgave me all my sins,\nHis banner over me is love,\nHis banner over me is love.\r\nHe gives me the living water,\nHis banner over me is love.\nHe gives me the living water,\nHis banner over me is love.\nHe gives me the living water,\nHis banner over me is love,\nHis banner over me is love.\r\nI love You and You love me,\nHis banner over me is love.\nI love You and You love me,\nHis banner over me is love.\nI love You and You love me,\nHis banner over me is love,\nHis banner over me, is love.\r\nHe leads me through all of life,\nHis banner over me is love.\nHe leads me through all of life,\nHis banner over me is love.\nHe leads me through all of life,\nHis banner over me is love,\nHis banner over me is love.', 'Er ist der Felsen meiner Rettung,\nSein Banner über mir ist Lieb\'.\nEr ist der Felsen meiner Rettung,\nSein Banner über mir ist Lieb\'.\nEr ist der Felsen meiner Rettung,\nSein Banner über mir ist Lieb\',\nSein Banner über mir ist Liebe.\r\nEr vergab mir meine Sünden,\nSein Banner über mir ist Lieb\'.\nEr vergab mir meine Sünden,\nSein Banner über mir ist Lieb\'.\nEr vergab mir meine Sünden,\nSein Banner über mir ist Lieb\',\nSein Banner über mir ist Liebe.\r\nEr gibt mir das Lebenswasser,\nSein Banner über mir ist Lieb\'.\nEr gibt mir das Lebenswasser,\nSein Banner über mir ist Lieb\'.\nEr gibt mir das Lebenswasser,\nSein Banner über mir ist Lieb\',\nSein Banner über mir ist Liebe.\r\nEr liebt mich und ich lieb\' Ihn,\nSein Banner über mir ist Lieb\'.\nEr liebt mich und ich lieb\' Ihn,\nSein Banner über mir ist Lieb\'.\nEr liebt mich und ich lieb\' Ihn,\nSein Banner über mir ist Lieb\',\nSein Banner über mir ist Liebe.\r\nEr führt mich durchs ganze Leben,\nSein Banner über mir ist Lieb\'.\nEr führt mich durchs ganze Leben,\nSein Banner über mir ist Lieb\'.\nEr führt mich durchs ganze Leben,\nSein Banner über mir ist Lieb\',\nSein Banner über mir ist Liebe.'),
(9, '0371', 'Er ist der König meines Herzens', NULL, 'Er ist der König meines Herzens,\nmein Jesus, mein Jesus.\nEr ist der König meines Herzens,\nalles will ich für Ihn tun.\nJesus, Jesus, Jesus, Jesus.\nEr ist der König meines Herzens,\nalles will ich für Ihn tun.\r\nEr ist der Retter meiner Seele,\nmein Jesus, mein Jesus.\nEr ist der Retter meiner Seele,\ndenn Er starb am Kreuz für mich.\nJesus, Jesus, Jesus, Jesus.\nEr ist der Retter meiner Seele,\ndenn Er starb am Kreuz für mich.\r\nEr tauft mit Heil\'gem Geist und Feuer,\nmein Jesus, mein Jesus.\nEr tauft mit Heil\'gem Geist und Feuer,\nja Er tauft mit Heil\'gem Geist.\nJesus, Jesus, Jesus, Jesus.\nEr tauft mit Heil\'gem Geist und Feuer,\nja Er tauft mit Heil\'gem Geist.'),
(9, '0372', 'Er ist Herr, auferstanden von den Toten  -  He is Lord, He is risen from the dead   (Chorus)', 'He is Lord, He is Lord.\nHe is risen from the dead, and He is Lord.\nEvery knee shall bow, every tongue confess,\nthat Jesus Christ is Lord.', 'Er ist Herr, Er ist Herr.\nAuferstanden von den Toten und Er lebt.\nJedes Knie muss sich beugen, jede Zunge soll bekennen,\ndass Jesus ist der Herr.'),
(9, '0373', 'Er ist hier, Halleluja  -  He is here, Hallelujah   (2 Chorusse)', 'He is here, hallelujah!\nHe is here, Amen!\nHe is here, holy, holy,\nI will bless His holy name!\r\nHe is here, listen closely,\nhear Him calling out your name.\nHe is here you can touch Him,\nyou will never be the same.', 'Er ist hier, Halleluja!\nEr ist hier, Amen!\nEr ist hier, heilig, heilig,\nIch will ehren Seinen Nam\'!\r\nEr ist hier, darum höre,\nwie Er deinen Namen ruft.\nEr ist hier, komm, berühr\' Ihn,\ndu wirst nie derselbe mehr sein.'),
(9, '0374', 'Er ist mein Alles mir, mein Herr und Gott  -  He is my Everything, He is my all   (Chorus)', 'He is my everything, He is my all.\nHe is my everything, both great and small.\nHe gave Himself for me, made everything hew.\nHe is my everything, oh, how about you?', 'Er ist mein Alles mir, mein Herr und Gott;\nEr hat geholfen mir aus aller Not.\nEr gab sich selbst für mich, nun ist Er alles mir.\nEr ist mein Alles mir. Was ist Er dir?'),
(9, '0375', 'Er ist mein Alles, Er ist mein Alles mir  -  He\'s everything, He\'s everything to me   (Chorus)', 'He\'s everything, He\'s everything to me;\nHe\'s everything, He\'s everything to me;\nfor He\'s my father, my mother,\nmy sister and my brother,\nHe\'s everything to me.', 'Er ist mein Alles, ist mein Alles mir.\nEr ist mein Alles, ist mein Alles mir;\nEr ist mein Vater, meine Mutter,\nmeine Schwester und mein Bruder.\nEr ist mein Alles mir.'),
(9, '0376', 'Er ist was ich brauch ...  -  He\'s all I need ...   (6 Chorusse)', 'He\'s all I need,\nHe\'s all I need,\nJesus is all I need. (2x)\r\nI take You now,\nI take You now,\nJesus, I take You now. (2x)\r\nI worship You,\nI worship You,\nJesus, I worship You.\r\nI consecrate myself to You,\nI consecrate myself to You,\nJesus, I consecrate myself to You.\r\nYou live in me,\nYou live in me,\nJesus, You live in me. (2x)\r\nI rest in You,\nI rest in You,\nJesus, I rest in You. (2x)', 'Er ist, was ich brauch\',\nEr ist, was ich brauch\',\nJesus ist, was ich brauch\'. (2x)\r\nIch nehm\' Dich auf,\nich nehm\' Dich auf,\nJesus, ich nehm\' Dich auf. (2x)\r\nIch bete Dich an,\nich bete Dich an,\nJesus, ich bete Dich an. (2x)\r\nIch weihe mich Dir,\nich weihe mich Dir,\nJesus, Ich weihe mich Dir. (2x)\r\nDu lebst in mir,\nDu lebst in mir,\nJesus, du lebst in mir. (2x)\r\nIch ruh\' in Dir,\nich ruh\' in Dir,\nJesus, Ich ruh\' in Dir. (2x)'),
(9, '0377', 'Er kam zu mir als ich nicht kommen konnt\'  -  He came to me when I could not come   (Chorus)', 'He came to me, He came to me.\nWhen I could not come,\nto where He was, He came to me.\nThat\'s why He died on Calvary.\nWhen I could not come,\nto where He was, He came to me.', 'Er kam zu mir, Er kam zu mir,\nals ich nicht kommen konnt\',\ndort wo Er war, kam Er zu mir.\nDeshalb starb Er auf Golgatha.\nAls ich nicht kommen konnt\',\ndort wo Er war, kam Er zu mir.'),
(9, '0378', 'Er kann alles, Er kann alles, ich weiß, Er kann alles  -  He is able! He is able! Yes I know, He is able   [Jesu Name Band 2]', 'He is able! He is able!\nYes I know, He is able,\nI know my Lord is able\nto carry me through.\nHe heals the broken hearted,\nHe sets the captives free,\nHe makes the lame to walk again\nand makes the blind to see.', 'Er kann alles! Er kann alles!\nJa ich weiß, Er kann alles,\nIch weiß, dass Jesus mich\nbewahren kann.\nEr heilt zerbroch\'ne Herzen,\nGebund\'ne macht Er frei,\ndie Lahmen macht Er gehend,\ndas Leben schafft Er neu.'),
(9, '0379', 'Er lebt! Er lebt! Der Siegesheld, Er ist vom Grab erstanden', NULL, 'Er lebt! Er lebt, der Siegesheld!\nEr ist vom Grab erstanden\nund wird nicht ruh\'n, bis alle Welt\nist frei von Satans Banden.\r\nEr lebt! Er lebt! O zage nicht!\nEr muss sein Werk vollenden.\nOb alles wankt und alles bricht:\nVertraue seinen Händen!\r\nEr lebt! Er lebt! Dein Jesus lebt!\nD\'rum bist du wohl geborgen.\nBei Tag und Nacht ist er bestrebt,\ndich reichlich zu versorgen.\r\nEr lebt! Er lebt! Im ew’gen Licht,\num stets für dich zu beten\nund dich vor Gottes Angesicht\nals Priester zu vertreten.\r\nEr lebt! Er lebt! So ruhe still\nin diesem festen Glauben,\ndass alles geht, wie er es will,\ntrotz aller Feinde Schnauben.\r\nEr lebt! Er lebt! Ich ruf’ es laut\nund will es froh verkünden.\nEr lebt! Er lebt! Und wer ihm traut,\nwird’s stets bestätigt finden.'),
(9, '0380', 'Er lebt, Er lebt, mein Herr und Heiland lebt', '\r\nHe lives, He lives, Christ Jesus lives today.\nHe walks with me and talks with me,\nalong life\'s narrow way.\nHe lives, He lives salvation to impart!\nYou ask me how I know He lives!\nHe lives within my heart.', 'Er lebt, Er lebt, mein Herr und Heiland lebt!\nAls Siegesfürst von Golgatha ist Er den Seinen nah.\nEr lebt, Er lebt und bald erweist Er sich,\nals Herr und König aller Welt.\nEr lebt, mit Ihm auch ich.\r\nEr lebt, Er lebt! Mein Jesus lebt auch heut\'!\nEr geht mit mir, Er spricht mit mir, Er führt mich allezeit.\nEr lebt, er lebt, gibt Heil und Sieg schon hier.\nDu fragst, wie weißt du\'s, dass Er lebt?\nEr lebt im Herzen mir.'),
(9, '0381', 'Er segnet mich  - I am blessed   (Chorus)', 'I am blessed, I am blessed,\nevery day that I live I am blessed.\nWhen I wake up in the morning,\nwhen I lay my head to rest.\nI am blessed, I am blessed.', 'Er segnet mich, Er segnet mich,\njeden Tag, den ich lebe, segnet Er.\nWenn ich aufwache am Morgen,\nwenn ich abends geh\' zur Ruh\'.\nSegnet Er, segnet Er.'),
(9, '0382', 'Er sorget für mich  -  He careth for me   (2 Chorusse)', 'He careth for me, He careth for me.\nThrough sunshine  or shadow,\nHe careth for me.\r\nHe careth for you, He careth for you.\nThrough sunshine or shadow,\nHe careth for you.', 'Er sorget für mich, Er sorget für mich.\nBei Sonn\'schein, bei Schatten,\nsorgt Er ja für mich.\r\nEr sorget für Dich, Er sorget für Dich.\nBei Sonn\'schein, bei Schatten,\nsorgt Er ja für Dich.'),
(9, '0383', 'Er sorgt für mich', NULL, 'Er sorgt für mich,\nEr sorgt für mich,\ndarum werf ich die\nSorge auf Ihn.\r\nGott,  mein Vater,\nmein Vater sorgt für mich!\nGott,  mein Vater,\nmein Vater sorgt für mich!\r\nGott, der mich sieht,\nwas auch geschieht,\nDeine Hilfe ist mir gewiss! (2x)'),
(9, '0384', 'Er wird mich erfüllen, dass ich überfließe   (Chorus)', NULL, 'Er wird mich erfüllen, dass ich überfließe.\nJesus ruft mich: "Komm zu Mir,\nGeistesfeuer schenk\' Ich dir!"\nEr wird mich erfüllen, dass ich überfließe,\nmit dem Heil\'gen Geist und Kraft.'),
(9, '0385', 'Erdenlust hielt mich gebunden  -  Once my Way was dark and dreary   (Worte sagens nie, wie ich Ihn liebe)', 'Once my way was dark and dreary,\nfor my heart was full of sin,\nbut the sky is bright and cheery,\nsince the fullness of His love came in.\r\nI can never tell how much I love Him,\nI can never tell His love for me.\nFor it passeth human measure,\nlike a deep unfathomed sea.\n\'Tis redeeming love in Christ my Saviour,\nin my soul the heavenly joys begin.\nAnd I live for Jesus only\nsince the fullness of His love shone in.\r\nThere is grace for all the lowly,\ngrace to keep the trusting soul.\nPow’r to cleanse and make me holy,\nJesus shall my yielded life control.\r\nLet me spread abroad the story,\nother souls to Jesus win.\nFor the cross is now my glory,\nsince the fullness of His love came in.', 'Erdenlust hielt mich gebunden,\nSündennacht hielt mich umhüllt,\nbis der Heiland mich gefunden\nund mit Seiner Liebe ganz erfüllt.\r\nWorte sagen\'s nie, wie ich Ihn liebe,\nnoch wie Er mich liebte je und je!\nEs ist höher als die Berge,\ntiefer als die tiefste See!\nDie Erlöserliebe meines Heilands\nhat mit Himmelsfreude mich gestillt,\nund für Jesus leb\' ich einzig,\nseit mich Seine Liebe ganz erfüllt.\r\nJesus hat für jeden Gnade,\nder sich gänzlich Ihm ergibt.\nEr gibt Heiligung und Freude dem,\nder Ihn vor allem andern liebt.\r\nAllen Menschen, die in Sünden\nund in Dunkel noch gehüllt,\nwill ich Jesu Kreuz verkünden,\nweil mich Seine Liebe ganz erfüllt.'),
(9, '0386', 'Erforsche mich, Jesus, mein Licht, durchleuchte mein Innerstes mir', NULL, 'Erforsche mich, Jesus, mein Licht,\ndurchleuchte mein Innerstes mir!\nMein eig\'nes Bemühen taugt nicht;\n||: ich nahe mich willig,\nich nahe mich willig,\nich nahe mich Dir! :||\r\nWas soll mir die Welt und ihr Spiel?\nSie gab weder Trost mir noch Ruh.\nIch habe ein höheres Ziel:\n||: Mein Kleinod, o Jesus,\nmein Kleinod, o Jesus,\nmein Kleinod bist Du! :||\r\nIch gebe mein Liebstes Dir her;\nmein Alles auf Erden sei Dein!\nWas frag ich nach Irdischem mehr?\n||: Du selbst, o Herr Jesus,\nDu selbst, o Herr Jesus,\nDu selbst bist ja mein! :||\r\nIm Glauben erfasse ich Dich;\nich weiß es und traue Dir\'s zu.\nDu reinigst und heiligest mich.\n||: Du kannst mich erretten,\nDu willst stets erretten,\nallmächtig bist Du! :||\r\nDir, Jesus, sei Lob und sei Ehr\'!\nDu bist meine Kraft, meine Ruh\'.\nDu hältst mich, was will ich noch mehr?\n||: Du kannst mich bewahren,\nDu willst stets bewahren,\nallmächtig bist Du! :||'),
(9, '0387', 'Erfüll mich Herr, mit dem Feuer deines Geistes  -  Consume me Lord, with the Fire of Your Spirit   (Chorus)', 'Consume me Lord , with the fire of Your Spirit.\nConsume me Lord, make me more like Thee.\nBreak me Lord,\nand bless the broken pieces of my life.\nLet me be used, Lord, by You.', 'Erfüll mich Herr, mit dem Feuer deines Geistes!\nErfüll mich Herr, und mach mich so wie Du!\nForm mich Herr, in die Liebe deines Geistes ganz hinein,\nNutze mich mehr, Herr, für Dich.'),
(9, '0388', 'Erlöst bin ich, darf es wohl rühmen  -  Redeemed, how I love to proclaim it   (Erlöst, erlöst, erlöst durch des Heilandes Blut)', 'Redeemed - how I love to proclaim it!\nRedeemed by the blood of the Lamb.\nRedeemed through His infinite mercy,\nHis child, and forever, I am.\r\nRedeemed, redeemed,\nRedeemed by the blood of the Lamb.\nRedeemed, redeemed,\nHis child, and forever, I am.\r\nRedeemed and so happy in Jesus,\nno language my rapture can tell.\nI know that the light of His presence,\nwith me doth continually dwell.\r\nI think of my blessed Redeemer,\nI think of Him all the day long.\nI sing, for I cannot be silent.\nHis love is the theme of my song.\r\nI know I shall see in His beauty,\nthe King in whose way I delight.\nWho lovingly guardeth my footsteps,\nand giveth me songs in the night.\r\n', 'Erlöst bin ich, darf es wohl rühmen,\nerlöst durch des Heilandes Blut,\nerlöst durch Sein ewg\'es Erbarmen;\nwie hab ich\'s bei Jesu so gut!\r\nErlöst, erlöst,\nerlöst durch des Heilandes Blut!\nErlöst, erlöst,\nwie hab ich\'s bei Jesu so gut!\r\nErlöst bin ich, selig in Jesu;\nich finde nicht Worte dafür,\nwie süß Seine himmlische Nähe,\nwie groß Seine Liebe zu mir!\r\nStets denk ich an meinen Erlöser\nmit innigstem, seligstem Drang;\nund wie mein Herz voll Seiner Liebe,\ngeht über mein Mund im Gesang!\r\nEinst werd\' ich als König Ihn sehen!\nSein Dienst ist schon hier meine Freud!\nEr höret mein kindliches Flehen,\nmacht fest mich und siegreich im Streit!\r\nUnd hab ich dann treulich gekämpfet,\nvollendet in Ihm meinen Lauf,\nhab Glauben ich Jesu gehalten,\nnimmt Er mich gekrönt zu sich auf!'),
(9, '0389', 'Erlöst, sieben Siegel sind geöffnet', NULL, 'Erlöst! Sieben Siegel sind geöffnet.\nErlöst! Sieben Donnerstimmen rufen.\nErlöst! Auch mein Name ist im Buch.\nErlöst! Schon bevor die Schöpfung war.'),
(9, '0390', 'Erschaffe mir ein reines Herz  -  Create in me a clean Heart   (Psalm 51, 10-19)', 'Create in me a clean heart, oh God,\nand renew a right spirit within me.\nCreate in me a clean heart, oh God,\nand renew a right spirit within me.\r\nCast me not away from Thy presence, oh Lord,\nand take not Thy Holy Spirit from me.\nRestore unto me the joy of Thy salvation,\nand renew a right spirit within me.', 'Erschaffe mir ein reines Herz, o Gott!\nUnd erneu\'re in mir einen rechten Geist.\nErschaffe mir ein reines Herz, o Gott!\nUnd erneu\'re in mir einen rechten Geist.\r\nVerwirf mich nicht von Deinem Angesicht, o Herr,\nund nimm Deinen Heil\'gen Geist nicht von mir!\nLass mir wiederkehren, die Freude Deines Heiles,\nund erneu\'re in mir einen rechten Geist.'),
(9, '0391', 'Erscheinen meines Gottes Wege mir seltsam, rätselhaft und schwer', NULL, 'Erscheinen meines Gottes Wege\nmir seltsam, rätselhaft und schwer,\nund geh\'n die Wünsche, die ich hege,\nstill unter in der Sorgen Meer,\nwill trüb und still der Tag verrinnen,\nder mir nur Schmerzen und Qual gebracht,\ndann darf ich mich auf eins besinnen:\ndass Gott nie einen Fehler macht.\r\nWenn über ungelösten Fragen\nmein Herz verzweiflungsvoll erbebt,\nan Gottes Liebe will verzagen,\nweil sich der Unverstand erhebt:\nDann darf ich all mein müdes Sehnen\nin Gottes Rechte legen sacht\nund leise sprechen unter Tränen,\ndass Gott nie einen Fehler macht.\r\nWenn mir zu hoch des Herrn Gedanken,\nzu tief der Brunnen Seiner Huld,\nwenn alle Stützen haltlos wanken,\ndie Kraft mir fehlt und die Geduld;\nwenn gar mein Blick kein Ziel mehr findet\nin langer, tränenvoller Nacht,\nein Glaubensfunke dennoch kündet,\ndass Gott nie einen Fehler macht.\r\nD\'rum still, mein Herz, und lass vergehen,\nwas irdisch und vergänglich heißt.\nIm Lichte droben wirst du sehen,\ndass gut die Wege, die Er weist.\nUnd müsstest du dein Liebstes missen,\nund ging\'s durch kalte, finst\'re Nacht:\nHalt fest an diesem sel\'gen Wissen,\ndass Gott nie einen Fehler macht.'),
(9, '0392', 'Erstaunlich\' Gnad, sei allezeit mein Lobgesang  -  Amazing Grace, shall always be my Song of Praise   (So heb ich meine Augen auf nach Golgatha)', 'Amazing grace, shall always be my song of praise.\nFor it was grace, that brought me liberty.\nI do not know, just why He came to love me so.\nHe looked beyond my foult and saw my need.\r\nI shall forever lift my eyes to Calvery,\nto view the cross where Jesus died for me.\nHow marvellous the grace that cought my falling soul.\nHe looked beyond my fault and saw me need.\r\n\r\n\r\n', 'Erstaunlich\' Gnad\' sei allezeit mein Lobgesang,\ndenn es war Gnade, die mich freigekauft.\nIch weiß nicht, wie es kam dass er mich so geliebt,\nsah meine Fehler nicht, nur meine Not.\r\nSo heb\' ich meine Augen auf nach Golgatha,\nhinauf zum Kreuz, wo es für mich geschah.\nHerrliche Gnad\', die meine Seele zu sich rief.\nEr sah die Fehler nicht, nur meine Not.\r\nErstaunliche Gnad\' ist heute auch bereit für dich,\ndieselbe Liebe streckt sich aus nach dir.\nIn Seiner Nähe bleiben darfst du ewiglich.\nEr ruft dich heut\', so wie\'s geschah bei mir.\r\nNur Gottes Gnade brachte mich aus Finsternis\nhinein ins Licht, wo deutlich ich nun seh\'.\nIch ruf\' es von den Bergen, in den Tälern,\nEr sah die Fehler nicht, nur meine Not.\r\nUnd auch für heute such\' ich Deine Gnade Herr,\nund hoffe, dass Du segnest all mein Tun.\nUnd wenn der Sand der Zeit verrinnet um mich her,\ngewähre, dass mein Aug\' nie von Dir weicht!'),
(9, '0393', 'Erstaunliche Gnad, wie süß der Klang  -  Amazing grace, how sweet the Sound', 'Amazing grace! How sweet the sound,\nthat saved a wretch like me!\nI once was lost but now I\'m found,\nwas blind but now I see.\r\n\'Twas grace that taught my heart to fear,\nand grace my fears relieved;\nhow precious did that grace appear\nthe our I first believed.\r\nThrough many dangers, toils and snares,\nI have already come;\n\'tis grace that brought me safe this far,\nand grace will lead me home.\r\nWhen we\'ve been there ten thousend years,\nbright shining as the sun;\nwe\'ve no less days to sing God\'s praise\nthan when we first begun.\r\nPraise God, praise God, praise God, praise God,\npraise God, praise God, praise God.\nPraise God, praise God, praise God, praise God,\npraise God, praise God, praise God.', 'Erstaunliche Gnad\', wie süß der Klang,\nsie hat errettet mich.\nVerloren einst ich war, doch Jesus kam,\nwar blind, doch jetzt sehe ich.\r\nDie Gnade lehrte Gottesfurcht,\ndie and\'re Furcht verschwand.\nWie kostbar mir die Gnad\' erschien,\nals ich zum Glauben fand.\r\nDurch Leid, Gefahren, Müh\' und Not,\nbin durchgekommen ich.\nNur Gnade brachte mich so weit,\nund heim wird sie bringen mich.\r\nWenn wir sind dort zehntausend Jahr\',\nhellleuchtend wie die Sonn\'.\nDie Ewigkeit reicht niemals aus,\nzu preisen diese Gnad\'.\r\nPreis Gott, preis Gott, preis Gott, preis Gott,\npreis Gott, preis Gott, preis Gott.\nPreis Gott, preis Gott, preis Gott, preis Gott,\npreis Gott, preis Gott, preis Gott.'),
(9, '0394', 'Es bleibt mir stets vor Augen stehn, was ich im Geist geschaut   (O wie sehnt sich mein Herz da hinein)', NULL, 'Es bleibt mir stets vor Augen steh\'n,\nwas ich im Geist geschaut.\nIch durfte Zion vor mir seh\'n,\ngeschmückt als eine Braut.\r\nO wie sehnt sich mein Herz da hinein!\nJa, es ist mein Verlangen allein,\nin Jerusalem droben zu sein.\nGott ist da! Gott ist da!\r\nEs war so wunderbar für mich,\nwas ich im Geist geseh\'n.\nDie Sel\'gen riefen mich zu sich;\nich sah sie winkend steh\'n.\r\nDie Stadt lag da im Himmelsglanz,\nvoll Licht und Herrlichkeit.\nDie Welt war mir verschwunden ganz;\ndas Herz ward mir so weit.\r\nSonst liebte ich, was irdisch heißt;\nmein Schatz ist droben jetzt.\nIch bin ja durch den Heilgen Geist\nins Himmelreich versetzt.\r\nJerusalem, sei mir gegrüßt!\nDu bist die Heimat mir;\nund meine Pilgerfahrt versüßt\nein gläub\'ger Blick nach Dir.'),
(9, '0395', 'Es eilt die Zeit die Stunden fliehn   (Komm eh der letzte Tag versinkt, schon ist der Abend nah)', NULL, 'Es eilt die Zeit die Stunden flieh\'n,\nund niemand hält sie auf.\nAuch diene Jahre geh\'n dahin\nwie schneller Wogen Lauf.\r\nKomm\' eh der letzte Tag versinkt,\nschon ist der Abend nah,\nals helles Licht im Dunkel blinkt\ndas Kreuz von Golgatha,\ndas Kreuz von Golgatha.\r\nWie trügt die Welt mit falscher Pracht\ndoch den verlor\'nen Sohn,\nsie hat ihn arm und krank gemacht,\nund Undank ist ihr Lohn.\r\nDer Heiland wartet mit Geduld,\nDer dich unendlich liebt.\nEr ist\'s, Der alle deine Schuld\ndurch Seinen Tod vergibt.\r\nDein Sündenleid kennt Jesus schon,\nEr gab dafür Sein Blut.\nO, glaub\' an Ihn, den Gottessohn,\nund es wird alles gut\r\nKomm, eh der letzte Tag versinkt,\ndie Rettung ist dir nah!\nDir, lieber Freund, Erlösung bringt\ndas Kreuz von Golgatha,\ndas Kreuz von Golgatha.'),
(9, '0396', 'Es erglänzt uns schon nahe ein Land  -  There\'s a Land that is fairer than Day   (Bald, ja bald, o wie schön)', 'There\'s a land that is fairer than day,\nand by faith we can see it afar.\nFor the Father waits over the way,\nto prepare us a dwelling place there.\r\nIn the sweet by and by,\nwe shall meet on that beautiful shore!\nIn the sweet by and by,\nwe shall meet on that beautiful shore.\r\nWe shall sing on that beautiful shore,\nthe melodious songs of the blest.\nAnd our spirits shall sorrow no more,\nnot a sigh for the blessing of rest.\r\nTo our bountiful Father above,\nwe will offer our tribute of praise.\nFor the glorious gift of His love,\nand the blessings that hallow our days.', 'Es erglänzt uns schon nahe ein Land,\nunser Glaubensaug\' kann es schon seh\'n,\nund von Jesus geführt an der Hand,\nwerden wir als Sein Volk dort eingeh\'n.\r\nBald, ja bald, o wie schön,\nwerden wir uns dort droben dann seh\'n!\nBald, ja bald, o wie schön,\nwerden wir auch dort jubelnd eingeh\'n!\r\nDort singt alles in Wonne und Glück,\njauchzet selig dem Heilande zu.\nAlle Sorgen, die weichen zurück,\ndort ist himmlische, ewige Ruh\'.\r\nDort ist jene vollkommene Schar,\ndie entflammt von dem Heiligen Geist.\nIn Anbetung vor Gottes Altar,\nSeine Liebe im Sohne hoch preist.'),
(9, '0397', 'Es erschallt ein Ruf weit über Meer und Land  -  There\'s a Call comes ringing over the restless Wave   (Sendet Licht, des Wortes helles Licht)', 'There\'s a call comes ringing o\'er the restless wave.\nSend the light! Send the light!\nThere are souls to rescue, there are souls to save.\nSend the light! Send the light!\r\nSend the light, the blessed gospel light,\nlet it shine from shore to shore!\nSend the light, and let its radiant beams\nlight the world forevermore.\r\nWe have heard the Macedonian call today:\nSend the light! Send the light!\nAnd a golden offering at the cross we lay.\nSend the light! Send the light!\r\nLet us pray that grace may everywhere abound.\nSend the light! Send the light!\nAnd a Christ-like spirit everywhere be found.\nSend the light! Send the light!\r\nLet us not grow weary in the work of love.\nSend the light! Send the light!\nLet us gather jewels for a crown above.\nSend the light! Send the light!', 'Es erschallt ein Ruf weit über Meer und Land:\nSendet Licht! Sendet Licht!\nReicht verlor\'nen Seelen eine Retterhand!\nSendet Licht! Sendet Licht!\r\nSendet Licht, des Wortes helles Licht,\ndass es scheint in alle Welt!\nSendet Licht, das jede Nacht durchbricht\nund das Dunkel rings erhellt.\r\nMacedoniens Ruf ertönet weit und breit:\nSendet Licht! Sendet Licht!\nHabt ein golden\' Opfer für den Herrn bereit!\nSendet Licht! Sendet Licht!\r\nUm das Heil in Christo lasst uns gläubig fleh\'n.\nSendet Licht! Sendet Licht!\nDass die Geisteswinde jedes Land durchweh\'n!\nSendet Licht! Sendet Licht!\r\nLasst uns nie ermatten in dem Werk des Herrn.\nSendet Licht! Sendet Licht!\nDenn uns winkt die Krone und der Lohn von fern:\nSendet Licht! Sendet Licht!'),
(9, '0398', 'Es geht nach Haus, zum Vaterhaus  -  We’re going home, no more to roam', 'We’re going home, no more to roam,\nno more to sin and sorrow.\nNo more to wear the brow of care,\nwe’re going home tomorrow.\nWe’re going home, we’re going home tomorrow,\nwe’re going home, we’re going home tomorrow.\r\nFor weary feet awaits a street\nof wondrous pave and golden.\nFor hearts that ache, the angels wake\nthe story, sweet and olden.\nWe’re going home, we’re going home tomorrow,\nwe’re going home, we’re going home tomorrow.\r\nFor those who sleep, and those who weep,\nabove the portals narrow,\nthe mansions rise beyond the skies—\nWe’re going home tomorrow.\nWe’re going home, we’re going home tomorrow,\nwe’re going home, we’re going home tomorrow.\r\nOh, joyful song! Oh, ransomed throng!\nWhere sin no more shall sever.\nOur king to see, and, oh, to be\nwith Him at home forever!\nWe’re going home, we’re going home tomorrow,\nwe’re going home, we’re going home tomorrow.', 'Es geht nach Haus, zum Vaterhaus,\nwer weiß, vielleicht schon morgen;\nvorbei, mein Herz, ist dann der Schmerz\nund weg die Sünd\' und Sorgen.\nEs geht nach Haus, zum Vaterhaus,\nwer weiß, vielleicht schon morgen!\r\nDu müdes Kind, die Straßen sind\ndort golden, rein und sonnig,\nund ew\'ge Freud\' vertreibt dein Leid\nund Lieder, süß und wonnig.\nEs geht nach Haus, zum Vaterhaus,\nwer weiß, vielleicht schon morgen!\r\nDie gläubig fleh\'n, mit Tränen säh\'n,\ndie sind im Herrn geborgen.\nIns Heim so traut, das Gott gebaut,\nzieh\'n wir vielleicht schon morgen!\nEs geht nach Haus, zum Vaterhaus,\nwer weiß, vielleicht schon morgen!\r\nO Gnadenpfort\', o sel\'ger Ort!\nWo uns darf nichts mehr schaden;\nda wird viel Freud\' und Herrlichkeit\ndem, der zum Mahl geladen.\nEs geht nach Haus, zum Vaterhaus,\nwer weiß, vielleicht schon morgen.'),
(9, '0399', 'Es gibt ein Land, wo keine Sorgen   (Oh herrliches Land, einst darf ich sehen)', NULL, 'Es gibt ein Land, wo keine Sorgen,\nwo keine Not und Angst wird sein.\nIn diesem Land bin ich geborgen\nfür alle Zeit, ein Bürger werd\' ich sein.\r\nOh herrliches Land, einst darf ich sehen\ndich Himmelslicht am gold\'nen Strand,\nmit all` den Heil`gen werd\' ich stehen, zu\npreisen dich vor Gottes Angesicht.\r\nWenn ich auch wand\'le nur auf Erden\nvom Feind bedroht und oft geplagt,\nja Jesus soll mir alles werden,\nblick ich auf Ihn getrost und unverzagt.\r\nWillst du nicht mit zu diesem Lande,\nwo Jesus wohnt in Herrlichkeit.\nNur wer erlöst von jedem Bande,\nwird bei Ihm sein für Zeit und Ewigkeit.'),
(9, '0400', 'Es gibt eine Gnade vollkommen und frei', NULL, 'Es gibt eine Gnade vollkommen und frei,\nsie tilget die Sünde, wie groß sie auch sei.\nDurch Rettung des Sünders verherrlicht sie sich.\nIm Opfer des Lammes ist Gnade für dich.\nGnade für dich, Gnade für dich,\nim Opfer des Lammes ist Gnade für dich.\r\nEs gibt einen Frieden im Dunkel der Zeit,\nin Krankheit und Armut, Versuchung und Streit.\nWie heilender Balsam erweiset er sich.\nIn Jesu Gemeinschaft ist Frieden für dich.\nFrieden für dich, Frieden für dich,\nin Jesu Gemeinschaft ist Frieden für dich.\r\nEs gibt eine Kraft, die bei Tag und bei Nacht\nuns schirmet und träget und siegreich uns macht.\nIn unserer Schwachheit vollendet sie sich.\nDie Kraft deines Heilands genügt auch für dich.\nKraft auch für dich, Kraft auch für dich,\ndie Kraft deines Heilands genügt auch für dich.');
INSERT INTO song_list (LISTID, NUM, NAME, TEXT_EN, TEXT_DE) VALUES
(9, '0401', 'Es gibt eine Heimat im himmlischen Licht   (O nein, denn ich kenne den Heiland so gut)', NULL, 'Es gibt eine Heimat im himmlischen Licht,\nbereitet vom Heilande mein.\nUnd wenn Er mich rufet, so weiß ich gewiss:\nIch werde kein Fremdling dort sein.\r\nO nein, denn ich kenne den Heiland so gut,\nEr ist ja auf Erden schon mein.\nUnd geh\' in den Himmel ich ein durch Sein Blut,\nso werd\' ich kein Fremdling dort sein.\r\nIch weiß, ob auch Menschen mich selten versteh\'n,\nob Freunde mich lassen allein,\nwenn meinen Erlöser ich droben werd\' seh\'n,\nso werd\' ich kein Fremdling dort sein.\r\nDort sind meine Lieben am goldenen Strand,\numflossen vom himmlischen Schein.\nMit ihnen dort wandle auch ich Hand in Hand.\nIch werde kein Fremdling dort sein.\r\nO Fremdling, beim Heilande findest du Ruh\',\nEr wäschet von Sünde dich rein!\nKomm heute zu Ihm, und dann singest auch du:\nIch werde kein Fremdling dort sein.'),
(9, '0402', 'Es gibt einen Ort für alle Müden  -  There\'s a Place for all the Weak and Weary   (In dem Obersaal mit Jesus, sitz zu Jesu Füßen ich)', 'There\'s a place for all the weak and weary.\nA place where all may find real peace.\nIn the upper room with Jesus,\nall our cares and heartaches cease.\r\nIn the upper room with Jesus,\nsitting at his nail scarred feet.\nOh, oh, what rich and full\ncommunion, fellowship divine and sweet!\r\nThere is cooling water for the weary.\nThere\'s a balm for every broken heart.\nAnd there\'s rest for all the heavy-laden.\nHis peace to you He will impart.', 'Es gibt ein Ort für alle Müden,\neinen Ort, wo jeder findet Ruh\'.\nDort im Obersaal zu sein mit Jesus,\nHerzeleid und Kummer flieht.\r\nIn dem Obersaal mit Jesus,\nsitz\' zu Jesu Füßen ich.\nOh oh, welch sel\'ge Gemeinschaft!\nDort zu sein mit Ihm vereint.\r\nDort gibt\'s frisches Wasser für die Schwachen,\nBalsam gibt es dort für\'s kranke Herz,\ndort gibt\'s Ruh\' für alle Schwerbelad\'nen.\nSeinen Frieden teilt er dort mit uns.'),
(9, '0403', 'Es gibt jemand, der deine Lasten kennt', NULL, 'Es gibt jemand, der deine Lasten kennt,\njemand, der dich Sein Kind nennt,\njemand, der nie dich lässt allein.\nDenn Er trug am Kreuze deine Last,\ndie du selbst getragen hast,\nund Er wird immer bei dir sein.\r\nEs ist Jesus, der deine Lasten kennt,\nJesus, der dich Sein Kind nennt,\nJesus, der nie dich lässt allein.\nDenn Er trug am Kreuze deine Last,\ndie du selbst getragen hast,\nund Er wird immer bei dir sein.'),
(9, '0404', 'Es gibt Zweifler die versuchen Gottes Wort zu verdrehn  -  Some Doubters are trying God\'s Word to revise   (Lass es einfach so stehn, Gottes gesegnetes Wort)', 'Some doubters are trying God\'s Word to revise.\nJust leave it alone, just leave it alone.\nNo longer this line or that passage they prize,\ndon\'t change it just leave it alone.\r\nJust leave it alone, \'tis God\'s blessed Word,\nwhose Son did for evil atone.\nEach Word and each line tells of goodness divine;\ndon\'t change it just leave it alone!\r\nThis message is food revealed by the Word,\njust leave it alone, just leave it alone.\nGod\'s voice through His prophet is what we have heard,\ndon\'t change it just leave it alone.\r\nThe warning He\'s given so who will give heed?\nJust leave it alone, just leave it alone.\nGod\'s simple, plain message is all that we need,\ndon\'t change it just leave it alone.\r\nIt\'s light is the same as in ages gone by,\njust leave it alone, just leave it alone.\nAnd still it\'s great Giver is reigning on high\',\ndon\'t change it just leave it alone.', 'Es gibt Zweifler die versuchen Gottes Wort zu verdreh\'n.\nLass es einfach so steh\'n, lass es einfach so steh\'n.\nNicht länger diese Zeile oder Stelle sie nehm\'n,\ndoch ändre\'s nicht lass es so steh\'n.\r\nLass es einfach so steh\'n, Gott\'s gesegnetes Wort,\ndessen Sohn für das Böse uns Versöhnung gab.\nJedes Wort, jede Zeil\' spricht von göttlicher Güt\'.\nDoch ändre\'s nicht, lass es so steh\'n!\r\nDiese Botschaft ist die Speis\', die Offenbarung des Wort\'s,\nlass es einfach so steh\'n, lass es einfach so steh\'n.\nGottes Stimm\' durch Sein\' Propheten, die wir haben gehört,\ndoch ändre\'s nicht lass es so steh\'n.\r\nDie Warnung die Er gab, wer will noch schenken Gehör?\nLass es einfach so steh\'n, lass es einfach so steh\'n.\nGottes einfache Botschaft, ja was wollen wir mehr,\ndoch ändre\'s nicht, lass es so steh\'n.\r\n'),
(9, '0405', 'Es harrt die Braut so lange schon, o Herr auf Dein Erscheinen', NULL, 'Es harrt die Braut so lange schon,\no Herr, auf Dein Erscheinen,\nwann willst Du kommen, Gottessohn,\nzu stillen all ihr Weinen\ndurch Deiner Nähe Seligkeit?\nWann bringst Du die Erquickungszeit?\n||: O komme bald, Herr Jesus! :||\r\nZwar bist Du schon zu jeder Stund\'\nin Deiner Jünger Mitte,\nsprichst Frieden uns aus Deinem Mund,\nerhörest Lob und Bitte.\nDoch, Heiland, ganz genügt\'s uns nicht,\nwir möchten schau\'n Dein Angesicht\n||: o komme bald, Herr Jesus! :||\r\nEs schmerzt uns sehr der Feinde Spott,\ndie Deinen Namen schmähen,\ndie Dich, Du wunderbarer Gott,\nnicht lieben, noch verstehen.\nKomm, zeig den Völkern, weit und breit,\nDein Reich und Deine Herrlichkeit\n||: o komme bald, Herr Jesus! :||\r\nO lass uns wachen spät und früh,\nlass unsre Lampen brennen!\nDein heil\'ges Öl uns mangle nie,\nlass nichts von Dir uns trennen,\ndamit, wenn dann der Ruf erschallt\n"Der Bräut\'gam kommt!" es widerhallt:\n||: o komme bald, Herr Jesus! :||\r\nWir sehnen uns, mit Dir zu sein\nbei Deiner Hochzeitsfreude;\no Jesus, sieh, wir harren Dein,\ngeschmückt in Deinem Kleide!\nWir schauen freudig himmelwärts,\nund immer lauter ruft das Herz:\n||: o komme bald, Herr Jesus! :||'),
(9, '0406', 'Es hat durch\'s Kreuz uns Heil gebracht unser großer Erlöser  -  Christ has for Sin atonement made, what a wonderful Saviour   (O, ein großer Erlöser ist Jesus, mein Jesus)', 'Christ has for sin atonement made,\nwhat a wonderful Saviour!\nWe are redeemed, the price is paid,\nwhat a wonderful Saviour!\r\nWhat a wonderful Saviour is Jesus, my Jesus!\nWhat a wonderful Saviour is Jesus, my Lord!\r\nI praise Him for the cleansing blood,\nwhat a wonderful Saviour!\nThat reconciled my soul to God,\nwhat a wonderful Saviour!\r\nHe cleansed my heart from all its sin,\nwhat a wonderful Saviour!\nAnd now He reigns and rules therein,\nwhat a wonderful Saviour!\r\nHe walks beside me in the way,\nwhat a wonderful Saviour!\nAnd keeps me faithful day by day,\nwhat a wonderful Saviour!\r\nHe gives me overcoming pow\'r,\nwhat a wonderful Saviour!\nAnd triumph in each trying hour,\nwhat a wonderful Saviour!\r\nTo Him I’ve given all my heart,\nwhat a wonderful Saviour!\nThe world shall never share a part,\nwhat a wonderful Saviour!', 'Es hat durch\'s Kreuz uns Heil gebracht,\nunser großer Erlöser!\nBefreit hat uns aus Sündennacht,\nunser großer Erlöser!\r\nO, ein großer Erlöser ist Jesus, mein Jesus!\nO, ein großer Erlöser ist Jesus, mein Herr!\r\nPreis Dir für Dein Versöhnungsblut,\nunser großer Erlöser!\nDas Gnadenwunder an uns tut,\nunser großer Erlöser!\r\nVon Sünden machst das Herz Du rein,\nunser großer Erlöser!\nBewahr, regier es nur allein,\nunser großer Erlöser!\r\nDu ziehst mit uns durch\'s Leben hin,\nunser großer Erlöser!\nBehütest uns vor eitlem Sinn,\nunser große Erlöser!\r\nUns Schwachen gibt Er Siegeskraft,\nunser großer Erlöser!\nDie uns im Kampf Triumph verschafft,\nunser großer Erlöser!\r\nD\'rum freudig wir das Herz Dir weih\'n,\nunserm großer Erlöser!\nDu bist der Herr und Du allein,\nunser großer Erlöser!'),
(9, '0407', 'Es ist Dir gesagt, o Mensch, was gut ist   (Chorus)', NULL, 'Es ist dir gesagt, o Mensch, was gut ist\nund was der Herr von dir verlangt:\nGottes Wort halten und Liebe üben\nund demütig sein vor deinem Gott.'),
(9, '0408', 'Es ist ein Born, draus heilges Blut  -  There is a Fountain filled with Blood   (Es quillt für mich dies teure Blut, das glaub und fasse ich)', NULL, 'Es ist ein Born, d\'raus heil\'ges Blut\nfür arme Sünder quillt,\nein Born, der lauter Wunder tut\nund jeden Kummer stillt!\r\nEs quillt für mich dies teure Blut,\ndas glaub\' und fasse ich!\nEs macht auch meinen Schaden gut,\ndenn Christus starb für mich!\r\nDer Schächer fand den Wunderquell,\nden Jesu Gnad\' ihm wies,\nund dadurch ging er rein und hell\nmit Ihm ins Paradies.\r\nO Gotteslamm, Dein teures Blut\nhat noch die gleiche Kraft!\nGieß\' aus des Geistes Feuerglut,\ndie neue Menschen schafft!\r\nAuch ich war einst in Sündennot,\nda half mir Jesu Blut;\nd\'rum jauchz\' ich auch bis in den Tod,\nob dieser Gnadenflut.\r\nDies Blut sei all mein Leben lang\ndie Quelle meiner Lust,\ndas bleib mein ew\'ger Lobgesang\nan meines Heilands Brust!'),
(9, '0409', 'Es ist ein Wunder, o ja ein Wunder', NULL, 'Ich bin erlöst und bin Sein Kind.\nEr heilte mich und nahm hinweg all meine Sünd\'.\nMein Herz ist froh, es lobt und preist.\nGott sandte Seinen Heil\'gen Geist.\r\nEs ist ein Wunder, o ja ein Wunder.\nEs ist ein Wunder, dass der Heiland uns so liebt.\nEs ist ein Wunder, o ja ein Wunder.\nEs ist ein Wunder, dass Er Heil und Leben gibt.\r\nIch fand das Glück, das wahre Glück,\nund möchte niemals mehr zur Welt und Sünd\' zurück.\nNie mehr zurück, nie mehr zurück!\nIn Jesus fand ich all mein Glück.\r\nO Sünder komm, nimm Jesus an,\ndamit an dir der Herr ein Wunder tuen kann.\nEr heilt dein Herz, dein müdes Herz,\nund dann führt er Dich himmelwärts.'),
(9, '0410', 'Es ist einer gekommen, zu sterben für mich  -  There was One who was willing to die in my stead   (Sie sind dort an dem Kreuz, sie sind fort durch das Kreuz)', 'There was One who was willing to die in my stead,\nthat a soul so unworthy might live.\nAnd the path to the cross He was willing to tread,\nall the sins of my life to forgive.\r\nThey are nailed to the cross,\nthey are nailed to the cross,\no how much He was willing to bear!\nWith what anguish and loss, Jesus went to the cross!\nBut He carried my sins with Him there.\r\nHe is tender and loving and patient with me,\nwhile He cleanses my heart of its dross.\nBut "there\'s no condemnation," I know I am free,\nfor my sins are all nailed to the cross.\r\nI will cling to my Saviour and never depart;\nI will joyfully journey each day.\nWith a song on my lips and a song in my heart,\nthat my sins have been taken away.\r\n', 'Es ist Einer gekommen zu sterben für mich,\ndarum sei Er mir ewig gegrüßt!\nAn dem Kreuze nahm Er meine Sünden auf Sich,\nja, Er hat dort für alle gebüßt.\r\nSie sind dort an dem Kreuz,\nsie sind fort durch das Kreuz,\ndenn sie sanken mit Jesus ins Grab.\nO wie selig erfreut\'s: Jesus hing an dem Kreuz,\nund so nahm Er die Sünden uns ab.\r\nWill der Herr mit uns rechten in Seinem Gericht,\no wer könnte vor Ihm dann besteh\'n?\nDoch bereust du die Sünden und bringst sie ans Licht,\nja dann darfst du am Kreuze sie seh\'n.\r\nÜberlasse dich Jesu, vertrau Ihm allein,\ndenn Er starb ja dir, Sünder, zugut.\nAch, es mögen der Sünden unzählige sein,\nsie sind alle getilgt durch Sein Blut.\r\nEs ist einer am Kreuze gestorben für dich,\nund da ist für dich Friede gemacht.\nSieh, Er nahm deine Sünden und opferte Sich,\ndadurch ist dir Erlösung gebracht.'),
(9, '0411', 'Es ist etwas geschehen, ich kann\'s nun verstehen: ein Wunder', NULL, 'Es ist etwas geschehen, ich kann\'s nun verstehen: ein Wunder.\nIch sehe an mir das Leben aus Dir: ein Wunder.\nEs ist mir als hätt\' ich den Himmel in mir: ein Wunder.\nWas nie ich gedacht, geschah über Nacht: ein Wunder.\r\nHerr, Du bist mir nah, weil etwas geschah: ein Wunder.\nDenn Du liebst mich sehr, was will ich noch mehr: ein Wunder.\nEs ist mir als hätt\' ich den Himmel in mir: ein Wunder.\nDu hast über Nacht ein Feuer entfacht: ein Wunder.\r\nJetzt leb\' ich in Dir, und Du lebst in mir: ein Wunder.\nDas Alte verging, an dem ich so hing: ein Wunder.\nEs ist mir als hätt\' ich den Himmel in mir: ein Wunder.\nWas nie ich gedacht, Du hast es vollbracht: ein Wunder.\r\nNun sprichst Du durch mich, zu verherrlichen Dich, ein Wunder.\nDie Menschen dann seh\'n,:Dich auf Erden geh\'n, ein Wunder.\nIch weiß es, es ist nun der Himmel in mir: ein Wunder.\nDein Wort hat\'s gesagt, Du hast\'s offenbart: ein Wunder.'),
(9, '0412', 'Es ist Herrlichkeit mit Ihm zu gehn  -  It is Glory just to walk with Him', 'It is glory just to walk with Him whose blood has ransomed me.\nIt is rapture for my soul each day.\nIt is joy divine to feel Him near where\'er my path may be.\nBless the Lord, it\'s glory all the way!\r\nIt is glory just to walk with Him,\nit is glory just to walk with Him.\nHe will guide my steps aright\nthrough the day and through the night.\nIt is glory just to walk with Him.\r\nIt is glory when the shadows fall, to know that He is near.\nOh, what joy to simply trust and pray!\nIt is glory to abide in Him when skies above are clear.\nYes, with Him, it\'s glory all the way!\r\n\r\n\'Twill be glory when I walk with Him on heaven\'s golden shore,\nnever from His side again to stray.\nTwill be glory, wondrous glory with the Saviour evermore,\neverlasting glory all the way!\r\n', 'Es ist Herrlichkeit mit Ihm zu geh\'n, der mich hat frei gemacht\nes ist sel\'ge Lust für mich allezeit.\nWelche Wonne hat mir Seine Nähe und sein Heil gebracht\npreist den Herrn für diese Herrlichkeit.\r\nEs ist Herrlichkeit mit Ihm zu geh\'n,\nes ist Herrlichkeit mit Ihm zu geh\'n.\nDenn Er führt mich überall,\nsei\'s auf Berge, sei\'s durchs Tal.\nEs ist Herrlichkeit mit Ihm zu geh\'n.\r\nEs ist Herrlichkeit zu wissen, Er ist nahe in der Nacht,\ngläubig stütz\' ich mich auf seine Gnad\'.\nEs ist Herrlichkeit in Jesus, wenn die Sonne am Himmel lacht;\nEr bewahrt mich auf dem Lebenspfad.\r\nSeine Herrlichkeit, sie wohnt in mir,\nSeine Herrlichkeit, sie wohnt in mir.\nDenn Er führt mich überall,\nsei\'s auf Berge, sei\'s durchs Tal.\nSeine Herrlichkeit, sie wohnt in mir.\r\nEs ist Herrlichkeit zu wandeln einst mit Ihm im Himmelsland,\nniemals weichen mehr von Seiner Seit.\nEs wird herrlich sein, zu gehen mit dem Heiland Hand in Hand.\nO wunderbare Herrlichkeit!\r\nSeine Herrlichkeit, das ist Sein Wort.\nVoller Wunder ist der heil\'ge Ort.\nBleib\' nur dort bis sich\'s erfüllt,\nwas allein den Hunger stillt.\nSeine Herrlichkeit, das ist Sein Wort.'),
(9, '0413', 'Es ist kein Geheimnis, was Gott vermag  -  It is no Secret what Gott can do   (4 Strophen)', 'It is no secret what God can do,\nwhat He\'s done for others, He\'ll do for you.\nWith arms wide open, He\'ll pardon you,\nit is no secret what God can do.\r\nIt is no secret, I believe the Word,\nmy eyes were opened, my heart was stirred.\nI recognized Him the first I heard,\nthe prophet brings us the spoken Word.\r\nIt is no secret, where I have been,\nI met the prophet and he took me in.\nWith my heart wide open, the Light shone in,\nit is no secret I follow him.\r\nIt is no secret, of who he is,\nmore than a prophet, I\'m convinced of this.\nThe seventh angel, a Son of man,\nthe elijah promised in God\'s great plan.', 'Es ist kein Geheimnis, was Gott vermag.\nWas Er tat für and\'re, auch für dich Er tut.\nMit off\'nen Armen lädt Er dich ein.\nEs ist kein Geheimnis, was Gott vermag.\r\nEs ist kein Geheimnis, ich glaub\' dem Wort,\ndie Augen geöffnet, mein Herz wurd\' angerührt.\nIch erkannte Ihn, als ich es erstmals Mal hört\',\nder Prophet bringt uns, das gesproch\'ne Wort.\r\nEs ist kein Geheimnis, wo ich gewesen bin,\nich traf den Propheten, und Jesus nahm mich hin.\nMit weit off\'nem Herzen, leuchtet das Licht hinein,\nes ist kein Geheimnis, dass ich bin Sein.\r\nEs ist kein Geheimnis, welcher er ist,\nmehr als ein Prophet, das weiß ich ganz gewiss.\nDer siebte Engel, ein Menschensohn,\nin der Hand von Jesus, stand vor Gottes Thron.'),
(9, '0414', 'Es ist Kraft / Sieg / Heilung / Salbung   (4 Chorusse)', 'There is power, power, wonder-working power\nin the blood of the Lamb.\nThere is power, power wonder-working power\nin the precious blood of the Lamb.\r\n\r\n\r\n', 'Es ist Kraft, Kraft, wunderbare Kraft\nin dem Blut, in dem Blut.\nEs ist Kraft, Kraft, wunderbare Kraft\nin dem Blute des Heilands allein.\r\nEs ist Sieg, Sieg, wunderbarer Sieg\nIn dem Blut, in dem Blut.\nEs ist Sieg, Sieg, wunderbarer Sieg\nIn dem Blute des Heilands allein\r\nEs ist Heilung, Heilung,\nwunderbare Heilung.\nIn dem Blut, in dem Blut.\nEs ist Heilung, wunderbare Heilung\nin dem Blute des Heilands allein.\r\nEs ist Salbung, Salbung,\nwunderbare Salbung.\nIn dem Blut, in dem Blut.\nEs ist Salbung, Salbung,\nwunderbare Salbung.\nIn dem Blute des Heilands allein.'),
(9, '0415', 'Es ist Kraft, Kraft, es ist göttliche Reinheit   (Chorus)', 'It\'s power, power, it\'s purity divine, and victory over sin.\nIt\'s power, power, it\'s power of the Holy Ghost.', 'Es ist Kraft, Kraft, es ist göttliche Reinheit und Sieg über die Sünde.\nEs ist Kraft, Kraft, es ist die Kraft des Heiligen Geistes.'),
(9, '0416', 'Es ist nicht wichtig wie gut und fromm   (Lasst uns wandeln drum ganz nah mit Ihm, ganz in Seiner Lieb)', NULL, 'Es ist nicht wichtig, wie gut und fromm,\nwie rein und heilig wir hier schon.\nWenn es der Herr nicht persönlich in uns ist,\nnützt uns das äußere Heilige nichts.\r\nLasst uns wandeln d\'rum ganz nah mit Ihm, ganz in Seiner Lieb\'.\nDenn Er ist da, der Bräutigam und sehnt sich auch nach Dir.\r\nEs ist nicht wichtig, wenn du auch weißt,\nalle Geheimnisse der Abendzeit.\nWenn nicht der Herr auch persönlich mit uns spricht,\nnützt uns das tiefste Geheimnis auch nichts.\r\nEs ist nicht wichtig, wie viel du hast Glauben,\nder selbst auch Berge versetzt.\nEs zählt nur eins und darauf last uns bau\'n:\nGlaube aus der Liebe und aus dem Vertrau\'n.\r\nEs ist nur Lieb\'sgehorsam allein,\nJesus mein Herr ich will mich Dir weih\'n.\nSo oft im Leben hab\' ich versagt,\nbin nicht gewandelt mit Dir in der Tat.'),
(9, '0417', 'Es ist niemals ein Tag so traurig, es ist nie eine Nacht so lang  -  There is never a Day so dreary, there is never a Night so long   (Herrlicher, herrlicher Jesus)', 'There is never a day so dreary,\nthere is never a night so long,\nbut the soul that is trusting Jesus\nwill somewhere find a song.\r\nWonderful, wonderful Jesus!\nIn the heart He implanteth a song,\na song of deliverance, of courage, of strength,\nin the heart He implanteth a song.\r\nThere is never a cross so heavy,\nthere is never a weight of woe,\nbut that Jesus will help to carry,\nbecause He loveth so.\r\nThere is never a care or burden,\nthere is never a grief or loss,\nbut that Jesus in love will lighten\nwhen carried to the cross.\r\nThere is never a guilty sinner,\nthere is never a wandering one,\nbut that God can in mercy pardon\nthrough Jesus Christ, His Son.', 'Es ist niemals ein Tag so traurig,\nes ist nie eine Nacht so lang,\ndass die Seele, die trauet auf Jesus,\nnicht fänd einen Lobgesang.\r\nHerrlicher, herrlicher Jesus!\nIn das Herz legt er frohen Gesang,\nein Lied der Befreiung, des Mutes, der Kraft,\ntief im Herzen drin weckt Er Gesang.\r\nEs ist niemals ein Kreuz zu drückend,\nnie das Weh und die Last zu schwer,\ndass nicht Jesus gern hülfe sie tragen,\ndenn Er liebet ja so sehr.\r\nNie zu hart drücket Sorge, Bürde,\nnie zu tief quälet Schmerz, Verlust,\ndie in Lieb Er nicht auf sich würd\' nehmen;\nEr wandelt das Kreuz in Lust.\r\nNie zu schuldig ein armer Sünder\nNie zu weit weg ein Wand\'rer ist,\ndass nicht gerne Gott ihm wollt vergeben\nin Seinem Sohn Jesus Christ.'),
(9, '0418', 'Es ist noch Raum! Sein Haus ist noch nicht voll', NULL, 'Es ist noch Raum!\nSein Haus ist noch nicht voll,\ndie Tische sind noch leer.\nDa ist der Platz, wo jeder sitzen soll,\nihr Gäste, kommet her!\nLasst eure toten Eitelkeiten!\nGott lässt euch soviel Heil bereiten!\nEs ist noch Raum, es ist noch Raum!\r\nEs ist noch Raum! Ach wären Augen da!\nO tiefer Liebesgrund!\nDa schaut hinein und singt Halleluja,\nund tut\'s einander kund.\nRühmt doch das mächtige Erbarmen,\ndas euch umfasst mit Liebesarmen!\nEs ist noch Raum, es ist noch Raum!\r\nEs ist noch Raum! Es ist ihm nicht genug,\ndass viele selig sind.\nEr zöge gern durch Seinen Gnadenzug\nein jedes Menschenkind.\nEr ruft mit lautem Liebesschalle:\n"Mein Herz umfasst euch Sünder alle!"\nEs ist noch Raum, es ist noch Raum!\r\nEs ist noch Raum:\nO bleib nicht draußen steh\'n,\nGeladener des Herrn!\nSo oft du kommst, zu Seinem Mal zu geh\'n,\nempfängt Er dich so gern.\nWer ausbleibt, den wird er verfluchen,\nwer aber kommt, Ihn zu besuchen,\nfür den ist Raum, für den ist Raum!'),
(9, '0419', 'Es ist schon lange her, kam zu uns einst der Herr  -  In a Manger long ago, I know it\'s really so   (Oh ja, ich lieb den Mann von Galilä / Oh, I love that Mman from Galilee)', 'In a manger long ago, I know it\'s really so,\na babe was born to save men from their sin.\nJohn saw Him on the shore, the Lamb forevermore,\noh, Christ, the Crucified of Calvary.\r\nOh, I love that man from Galilee,\nfor He\'s done so very much for me.\nHe\'s forgiven all my sins, placed the Holy Ghost within;\noh, I love that man from Galilee.\r\nThe publican went to pray in the temple there one day,\nhe cried: "Oh, Lord, be merciful to me!"\nHe was forgiven of every sin, and a deep peace placed within,\nhe said: "Come see this man from Galilee."\r\nThe lame was made to walk, the dumb was made to talk,\nthat power was spoken with love upon the sea.\nThe blind was made to see, I know it could only be\nthe mercy of that man from Galilee.\r\nThe woman at the well, He all her sins did tell,\nhow five husbands she had at that time,\nshe was forgiven of every sin, and a deep peace came within\nthen she cried: "Come see that man from Galilee!"\r\nNicodemus came by night, to know the way of right,\nhe asked the Son of man what must I do.\nThese words He said to him: "Ye must be born again,"\nby the Spirit of that man from Galilee.\r\n\r\n\r\nDown on my knees, I found my Jesus,\ndown on my knees, I found the Lord.\nNot on a mountain, nor in a valley,\nbut on my knees, I found the Lord.', 'Es ist schon lange her, kam zu uns einst der Herr,\nals kleines Kind kam Er auf diese Welt.\nZu retten kam Er uns, es war die größte Stund\';\ngekreuzigt wurde Er auf Golgatha.\r\nOh ja, ich lieb\' den Mann von Galilä,\ndenn Er hat so viel für mich getan;\nEr vergab mir meine Sünd\', gab mir den Heil\'gen Geist,\noh, ich lieb\' den Herrn von Galilä.\r\nIm Tempel betete der Zöllner dort zu Gott.\nEr schrie: "O Herr, erbarm\' dich meiner hier."\nDie Sünde wurd\' getilgt, mit Fried\' wurd\' er erfüllt,\ndurch die Liebe von dem Herrn aus Galilä.\r\nDer Lahme konnte geh\'n, der Taube nun versteh\'n;\nmit Liebe sprach er Worte aus der Kraft.\nDer Blinde konnte seh\'n, nur dieses konnt\' gescheh\'n\ndurch die Gnade von dem Herrn aus Galilä.\r\nAm Brunnen war die Frau, der Herr sah sie genau.\nEr sagte ihr die Sünden alle dort.\nVergebung ward bereit, sie war voll Dankbarkeit\nund sie rief: "Kommt seht den Mann von Galilä".\r\n\r\nSein Kommen ist sehr nah, wir freu\'n uns immerdar.\nEr wird uns holen in die bess\'re Welt.\nBereitet ist uns dort, ein wunderbarer Ort.\nJa, wie lieben diesen Herrn von Galilä.\r\nDie Verwandlung steht bevor, wir preisen bald im Chor;\nwie unaussprechlich herrlich wird das sein.\nEs geht nun bald nach Haus, beendet ist der Lauf,\no wie liebt uns dieser Herr von Galilä.\r\n(Auf meinen Knien fand ich Jesus,\nauf meinen Knien fand ich den Herrn.\nNicht auf einem Berg, nicht in einem Tal,\naber auf meinen Knien fand ich Jesus.)'),
(9, '0420', 'Es ist schon vollbracht  -  It\'s already done   (Chorus)', 'It\'s already done,\nit\'s already done,\nthe victory is won,\nthe battle is over,\nit\'s already done.\r\nI\'m already healed\ni\'m already healed\nthe victory is won,\nthe battle is over,\ni\'m already healed\r\nMy family is sealed\nmy family is sealed\nthe victory is won,\nthe battle is over,\nmy family is sealed', 'Es ist schon vollbracht,\nes ist schon vollbracht,\nEr hat den Sieg gebracht,\nder Kampf ist vorüber,\nes ist schon vollbracht.\r\nIch bin bereits geheilt\nich bin bereits geheilt,\nEr hat den Sieg gebracht,\nder Kampf ist vorüber,\nIch bin bereits geheilt.\r\nMeine Familie ist versiegelt\nmeine Familie ist versiegelt,\nEr hat den Sieg gebracht,\nder Kampf ist vorüber,\nmeine Familie ist vergsiegelt.'),
(9, '0421', 'Es ist so gut, so gut, miteinander zu singen und preisen', NULL, 'Es ist so gut, so gut,\nmiteinander zu singen und preisen,\nso gut, so gut,\nmiteinander zu singen und preisen.\nUnbegreiflich, was geschehen,\ndass wir dürfen Jesus sehen.\nEs ist so gut, so gut, zu preisen Ihn,\nJesu Namen.'),
(9, '0422', 'Es kann kein Freund so wie Jesus lieben  -  There\'s not a Friend like the lowly Jesus   (Jesus kennt unsres Herzens Tiefen)', 'There\'s not a friend like the lowly Jesus -\nNo, not one! no, not one!\nNone else could heal all our soul\'s diseases -\nNo, not one! no, not one!\r\nJesus knows all about our struggles,\nHe will guide till the day is done.\nThere\'s not a friend like the lowly Jesus --\nNo, not one! no, not one!\r\nThere\'s not an hour that he is not near us -\nNo, not one! no, not one!\nNo night so dark but His love can cheer us -\nNo, not one! no, not one!\r\nNo friend like him is so high and holy -\nNo, not one! no, not one!\nAnd yet no friend is so meek and lowly -\nNo, not one! no, not one!\r\nWas e\'er a gift like the Saviour given?\nNo, not one! no, not one!\nWill he refuse us a home in heaven?\nNo, not one! no, not one!', 'Es kann kein Freund so wie Jesus lieben,\nkeiner, nein, keiner, nein!\nNiemand in Not ist so treu geblieben,\nkeiner, nein, keiner, nein!\r\nJesus kennt uns\'res Herzens Tiefen,\nleitet so treulich uns aus und ein.\nEs kann kein Freund so wie Jesus lieben,\nkeiner nein, keiner nein!\r\nEs ist kein Tag, wo er uns nicht nah’ ist,\nkeiner, nein, keiner, nein!\nund keine Nacht, in der er nicht da ist,\nkeiner, nein, keiner, nein!\r\nWer ward schon je von dem Freund verlassen?\nkeiner, nein, keiner, nein!\nWer sucht vergeblich sein Kleid zu fassen?\nkeiner, nein, keiner, nein!\r\nBibt\'s hier ein Glück wie ich\'s in Ihm habe?\nkeines nein, keines, nein.\nSel\'gere Heimat und Himmelsgabe?\nkeine, nein, keine, nein!'),
(9, '0423', 'Es kommt der Tag wo Christus wiederkommen wird', NULL, 'Es kommt der Tag, wo Christus wiederkommen wird.\nEs kommt der Tag, wo Er Sein Volk nach Hause führt.\nHalt aus, du kleine Schar, dein Retter ist ja nah.\r\nErhebe froh dein Haupt und sprich: "Halleluja".\nEr kommt in Herrlichkeit, wir seh\'n Ihn weit und breit.\nEs kommt der Bräutigam, holt heim die Braut.\r\nD\'rum irrt und täuscht euch nicht!\nDer Geist des Herrn, Er spricht:\n"Mein Volk, sei auf der Wacht,\nes wird bald Nacht." (2x)\r\nEs kommt der Sturm des Zorns auf diese böse Welt.\nDer Grimm des Herrn wie Donner auf die Frevler fällt.\nWie eine Windsbraut eilt Sein Schwert durch nah und fern.\r\nOh Weh\' der Welt am großen Rachetag des Herrn!\nEs kommt die Zeit, wo Gott bestraft für Hohn und Spott,\nwo vor dem Richterthron du stehst allein.\r\nDann wird zu spät es sein für alle\nEwigkeit. Komm, komm, oh,\nkomme doch, es ist noch Zeit. (2x)\r\nEs kommt die Zeit der Ewigkeit im Paradies.\nEs kommt die Zeit, die uns Sein Wort schon lang verhieß.\nDort wird der Jubel sein des Bräut\'gams und der Braut.\r\nDas neu\' Jerusalem hat Gott für uns erbaut.\nEs kommt die Zeit der Freud\', die uns der Herr bereit\'.\nWo die erlöste Schar fern von Gefahr.\r\nWo keine Träne rinnt, wo man\nnicht Trübsal find\'t, dort ist mein\nHeimatland, im Paradies. (2x)'),
(9, '0424', 'Es kommt ein Tag, ein großer Tag  -  There\'s a great Day coming   (Bist du bereit? Bist du bereit?)', 'There\'s a great day coming, a great day coming,\nthere\'s a great day coming by and by,\nwhen the saints and the sinners\nshall be parted right and left.\nAre you ready for that day to come?\r\nAre you ready? Are you ready?\nare you ready for the judgment day?\nAre you ready? Are you ready?\nfor the judgment day?\r\nThere\'s a bright day coming, a bright day coming.\nThere\'s a bright day coming by and by,\nbut its brightness shall only come\nto them that love the Lord.\nAre you ready for that day to come?\r\nThere\'s a sad day coming, a sad day coming,\nthere\'s a sad day coming by and by.\nWhen the sinner shall hear His doom,\n"Depart, I know ye not!"\nAre you ready for that day to come?', 'Es kommt ein Tag, ein großer Tag,\nja es kommt ein Tag schon sehr bald,\nwo die Heil\'gen von den Sündern\nEr wird scheiden auf dem Thron.\nBist du bereit für den großen Tag?\r\nBist du bereit? Bist du bereit?\nBist du bereit für den großen Tag?\nBist du bereit für den großen Tag?\r\nEs kommt ein Tag, ein heller Tag,\nja es kommt ein Tag schon sehr bald.\nDoch der helle Tag wird kommen nur für den,\nder liebt den Herrn.\nBist du bereit für den großen Tag?\r\nEs kommt ein Tag, ein bitt\'rer Tag,\nja es kommt ein Tag schon sehr bald,\nwo der Sünder hört sein Urteil:\n"Geh hinweg, Ich kenne dich nicht!"\nBist du bereit für den großen Tag?'),
(9, '0425', 'Es pilgert durch die Lande erlöst die selge Schar', NULL, 'Es pilgert durch die Lande\nerlöst die sel\'ge Schar,\nin ihren Reih\'n tönt leise\nein Lied, gar wunderbar.\nEs klingt im Land der Tränen\nwie lauter Jubelklang,\nes singt trotz tiefem Sehnen\nvon Sieg der Lobgesang.\r\nEs ist das Lied vom Lamme,\ndas herrlich neue Lied,\ndas von dem Kreuzesstamme\ndurch Ewigkeiten zieht,\ndas Lied von Jesu Wunden,\nvon Jesu Sieg und Macht,\nwie Er ein Heil gefunden,\ndas hier schon selig macht.\r\nUnd wo sich Seelen finden,\ndie einen stimmen\'s an,\ndas ew\'ge Lied vom Lamme,\nvon dem, was Er getan;\ndie andern singen\'s weiter,\nes braucht der Worte nicht,\nsie kennen sich am Liede,\nam leuchtenden Gesicht.\r\nO sel\'ges Lied vom Lamme,\nwann singen wir\'s beim Herrn?\nWann wirst Du wieder kommen,\nDu heller Morgenstern?\nO sammle bald die Deinen,\nja, Herr, mach uns bereit,\nzu singen Dir, dem Lamme,\nin alle Ewigkeit.'),
(9, '0426', 'Es quillt dort eine Quelle von Golgatha herab   (Sieh! Golgathas Quelle fließet)', '\r\nCalvary\'s stream is flowing,\nCalvary\'s stream is flowing,\nflowing so free for you and me.\nCalvary\'s stream is flowing.\r\n\r\n', 'Es quillt dort eine Quelle von Golgatha herab,\nihr Wasser ist so helle, und Heil sie jedem gab,\nder auf die Stimme hörte, wenn rief der Gottessohn:\n"Komm, Sünder, zu der Quelle, o komm zum Gnadenthron!"\r\nSieh! Golgathas Quelle fließet,\nGolgathas Quelle fließet,\nfließet so frei für dich und mich,\nGolgathas Quelle fließet!\r\nWenn dich der Sünde Ketten bedrücken hart und schwer,\ndein Heiland kann dich retten, denn Reinigung gibt Er,\ndein Heiland, der dich waschet von aller Sünde rein!\nO blicke nur zum Kreuze, dann ist der Friede dein!\r\nUnd diese Quell\' des Lebens für dich sie fließet frei!\nO lass Ihn nicht vergebens sich bieten dir mit Treu!\nWenn Jesus wird dein Retter, Sein Wille deine Freud,\ndann wirst als Kind und Erbe Ihn preisen du noch heut\'!'),
(9, '0427', 'Es schaut bei Nacht und Tage, Dein holdes Bild mich an   (Mein Gott, ich bin entschieden)', NULL, 'Es schaut bei Nacht und Tage\nDein holdes Bild mich an\nund legt mir vor die Frage,\nob ich Dich lassen kann.\r\nMein Gott, ich bin entschieden,\nauf ewig bin ich Dein,\nich kann ja ohne Frieden\nund ohne Dich nicht sein.\r\nDie Freuden hier auf Erden\nsah ich wie Schaum vergeh\'n,\nsie konnten mir nichts werden,\nDein Kreuz nur blieb mir steh\'n.\r\nOft habe ich gejammert,\nwenn Satans List mich schlug.\nJetzt hab ich den umklammert,\nder meine Sünden trug.\r\nNun steht bei Nacht und Tage\nDein Bild im Herzen mir,\ndass ich es jedem sage,\nwie gut es ist bei Dir.'),
(9, '0428', 'Es schlugen Sünderhände Ihn an des Kreuzes Pfahl   (Er lebt, Er lebt, seht nur, Sein Grab ist leer)', NULL, 'Er lebt, Er lebt, seht nur, Sein Grab ist leer!\nEr lebt, Er lebt, erstanden ist der Herr!\nEr lebt, Er lebt, in ew\'ger Herrlichkeit\nund führt Sein Volk zur Seligkeit.\r\nEs schlugen Sünderhände Ihn an des Kreuzes Pfahl,\nwo unsrer Sünden Menge Ihm machte Angst und Qual.\nEs rann von Seiner Stirne der kalte Todesschweiß.\nEr hat\'s vollbracht! Gott Lob und Preis!\r\nUm Seinen Leib bat Joseph, der nahm vom Kreuz Ihn ab\nund legte wohlverwahret Ihn in sein Felsengrab.\nDoch sieh, die Ostersonne durchbrach die Wolkenschicht!\nGott sprach\'s mit Macht "Es werde Licht!"\r\nDie Jünger kamen frühe zur off\'nen Grabestür.\nDa sprach des Herren Engel "Der Meister ist nicht hier.\nEr ist ja auferstanden, verkündigt\'s jedermann!\nGlaubt und erkennt, was Gott getan!"\r\nMaria weint voll Trauer, sie möcht\' den Meister seh\'n;\nda sieht mit heil\'gem Schauer sie, Jesus vor sich steh\'n!\nO seliges Entzücken, "Rabbuni!" ruft sie aus.\nAuch wir seh\'n Ihn im Vaterhaus!'),
(9, '0429', 'Es sind der Gaben auf Erden viel', NULL, 'Es sind der Gaben auf Erden viel\';\nnur Jesus haben führt uns zum Ziel.\nMein Herz ist fröhlich und freuet sich in Dir,\nmein Heiland, ich hab ja Dich.\r\nDurch Aufwärtsblicken zu jeder Zeit\nlern\' ich mich schicken in Freud\' und Leid.\nIch will nicht sorgen, Du sorgst für mich, Herr,\nheut\' und morgen, ich hab ja Dich.\r\nIn Deine Hände leg ich mich hin,\nDu weißt, Herr Jesus, wie schwach ich bin.\nDu führst die Deinen, Herr, seliglich,\ngeht\'s auch durch Weinen, ich hab ja Dich.\r\nDu bist mein Frieden, Du bist mein Heil,\nin Tod und Leben mein bestes Teil.\nDie beste Gabe, Herr, habe ich,\nauch über\'m Grabe, ich hab ja Dich.\r\nSo zieh ich fröhlich den schmalen Pfad;\ndas macht mich selig, dass ich Dich hab.\nDein Auge siehet und leitet mich\ndurchs ganze Leben, ich hab ja Dich.'),
(9, '0430', 'Es steht ein Leuchtturm, scheint in dunkler Nacht  -  There\'s a lighthouse on a hillside that over looks life\'s Sea   (Ich danke Gott für den Leuchtturm)', 'There\'s a lighthouse on a hillside\nthat over looks life\'s sea.\nWhen I\'m tossed it sends out a light,\na light that I might see.\nAnd the light that shines in darkness\nnow will safely lead me home.\nIf it wasn\'t for the lighthouse\nmy ship would sail no more.\r\nAnd I thank God for the Lighthouse,\nI owe my life to Him.\nFor Jesus is the Lighthouse,\nand from the rocks of sin\nhe has shown His light around me,\nthat I might  clealy see.\nIf it wasn\'t for the Lighthouse,\nwhere would this ship be?\r\nEverybody who lives around us\nsays tear that lighthouse down.\nYou know the bigs ships\nthey don\'t sail this way anymore,\nain\'t in it standing around.\nBut then my mind goes back\nto the stormy night when just in time,\nI saw the light.\nOh light from that old lighthouse,\nthat stands up there on the hill.\r\n', 'Es steht ein Leuchtturm, scheint in dunkler Nacht,\nwenn die Winde um uns weh\'n.\nEr hilft denen, die auf Ihn hinschau\'n,\nden rechten Weg zu geh\'n.\nWenn Er mich führt, dann fährt mein Schifflein\nin den Friedenshafen ein.\nWenn Sein Licht dir nicht mehr leuchtet,\nwo wird dann deine Seele sein?\r\nIch danke Gott für den Leuchtturm\nund Sein Licht, das für mich scheint.\nGottes Wort ist mein Leuchtturm;\nund bis wir ganz vereint, scheint Sein Licht,\num mich zu führen zum Hafen Seiner Ruh\'.\nDarum schau ich auf den Leuchtturm;\nsag mein Freund, auf wen schaust du?\r\nDie großen Schiffe schau\'n, nicht mehr auf Ihn,\nsie vertrauen nur auf sich, und sie sagen;\n"Ja, wir kennen den Weg, überwinden sicherlich."\nDoch wenn die Winde weh\'n, die Strömung zieht,\nschwindet eigne Kraft dahin.\nIch will lieber auf Ihn schauen,\nbis in dem Hafen ich einst bin.\r\nJa, auf den Klippen dieser Erdenzeit schimmert\nmanches trübe Licht:\nMenschen lehren Traditionen sind\'s, und kluger Menschen Sicht.\nAber die Seele, die das Leben sucht,\nbraucht das offenbarte Wort;\nalles andre, führt zum Schiffbruch,\nund niemals  zum Ruheort.'),
(9, '0431', 'Es wandert draußen der Heimat entwandt (Lukas 15, 11-24)', NULL, 'Es wandert draußen der Heimat entwandt,\nein Sohn, verblendet von eitlem Tand.\nSein Herz ist umnachtet, sein Sinn ist verwirrt,\ner hat sich vom Vater verloren, verirrt,\ner hat sich vom Vater verloren, verirrt.\r\nSo zieht er umher von Ort zu Ort\nund sucht sein Glück bald da, bald dort.\nGar schnell ist sein Alles verzehrt und verprasst,\nwer ist’s, den nicht Mitleid ergreift und erfasst,\nwer ist’s, den nicht Mitleid ergreift und erfasst!\r\nDoch sieh, Erbarmen ist nicht hier,\nihm öffnet sich nirgends zum Trost eine Tür;\nso sitzt er traurig am Trebertrog\nund klagt, wie so sehr ihn die Welt betrog,\nund klagt, wie so sehr ihn die Welt betrog.\r\nDa zuckt ein Gedanke durch seinen Sinn,\nzum Vaterhaus drängt er ihn mächtig hin.\n"ich will", spricht der Jüngling, "zum Vater geh\'n;\nich habe gesündigt, das muss ich gesteh\'n,\nich habe gesündigt, das muss ich gesteh\'n."\r\nZur Heimat zieht er die Straße entlang,\neinen Tränenstrom netzt seine magere Wang’.\nSo fleht er zum Vater, der zu ihm gekehrt.\nMein Vater, vergib mir, ich bin’s wohl nicht wert.\nMein Vater, vergib mir, ich bin’s wohl nicht wert.\r\nDa sieh, das Vaterherz jauchzet vor Lust:\n"Mein Sohn! Mein Sohn!", zieht ihn an die Brust,\ndenn dieser sein Sohn, war verloren und tot,\nnun ist er lebendig! Gelobt sei Gott,\nnun ist er lebendig! Gelobt sei Gott.'),
(9, '0432', 'Es wird Licht sein in der Abendzeit  -  It shall be Light in the Evening Time   (Durch den Wasserweg scheinet heut das Licht)', 'It shall be light in the evening time,\nThe path to glory you will surely find;\nThru the water way, It is the light today,\nBuried in the precious Name of Jesus.\nYoung and old, repent of all your sin,\nThe Holy Ghost will surely enter in;\nThe evening Light has come,\nIt is a fact that God and Christ are one.', 'Es wird Licht sein in der Abendzeit;\nDu wirst finden in die Herrlichkeit.\nDurch den Wasserweg scheinet heut\' das Licht,\nbegraben in dem teuren Nam\' von Jesus.\nJung und alt, bekennet eure Sünd\';\nDer Heil\'ge Geist wird kommen dann hinein.\nDas Abendlicht es kam,\nja, es ist wahr, Christus und Gott sind eins.'),
(9, '0433', 'Etwas tief im Herzen, das ich kann nicht verstehn   (Etwas in mir zieht mich zu Dir)', NULL, 'Etwas tief im Herzen,\ndas ich kann nicht versteh\'n.\nIch kann es nie erklären,\nwas mir durch Jesus gescheh\'n.\r\nEtwas in mir zieht mich zu Dir,\nweg von der Welt voll Sünd\'.\nEtwas in mir zieht mich heimwärts,\ndort darf ich Jesus dann seh\'n.\r\nEtwas in mir gibt Freude,\netwas in mir gibt Mut,\netwas sagt: "Schwing\' dich höher,\nbei Mir hast du es so gut."\r\nEtwas in mir ist ewig,\netwas in mir stirbt nie.\nMag auch der Leib vergehen,\nJesus in mir bleibt besteh\'n.'),
(9, '0434', 'Etwas zieht mich zu Dir, klopft an die Herzenstür  -  There\'s a Voice calling me, from an old rugged Tree   (Herr, was immer es braucht um Dir näher zu leben)', 'There\'s a voice calling me, from an old rugged tree\nand He whispers: Draw closer to me.\nLeave this world far behind,\nthere are new heights to climb,\nand a new place in Me you will find.\nand He whispers: Draw closer to me.\nLeave this world far behind,\nthere are new heights to climb,\nand a new place in Me you will find.\r\nAnd whatever it takes to draw closer to You, Lord,\nthat\'s what I\'ll be willing to do.\nAnd whatever it takes for my will to break,\nthat\'s what I\'ll be willing to do.\r\nTake my houses and lands,\ntake my dreams and my plans,\nI place my who life in Your hands.\nAnd if you call me someday to a land far away,\nLord, I\'ll go and Your will obey.\r\n\r\n', 'Etwas zieht mich zu Dir, klopft an die Herzenstür,\nes flüstert: "Lass dich ziehen von Mir!\nDenn für dich ist bereit ein gewaschenes Kleid\nund am Ende ein unsterblicher Leib."\r\nHerr, was immer es braucht um Dir näher zu leben,\nlass es geschehen in mir!\nUnd was immer es braucht, Dir mehr ähnlich zu werden,\nes geschehe, denn wie Du will ich sein.\r\nNimm, was ich einst geliebt, und der Seele nichts gibt.\nich lege es heute auf den Altar.\njeder Traum, jedes Ziel, führt in  finst\'rer Mächte Spiel,\nmög\' verbrennen was auf Erden noch hält.\r\nNimm den Reichtum dieser Welt und die Lust nach Gut und Geld,\nMenschenehre die ich einst gesucht.\nSelbst verachtet zu sein, in der Welt ganz allein,\nmacht mich heut\' reich, denn wie Du will ich sein.\r\nIch lass fahren die Welt und was vor Augen sie mir stellt.\nDu, mein Jesus, sollst mein Alles mir sein.\nUnd was noch nötig ist, dass mein Stolz ganz zerbricht,\nes geschehe, denn wie Du will ich sein.'),
(9, '0435', 'Euer Herz erschrecke nicht', NULL, 'Vor der ungewissen Zukunft: Gott vertrauen!\nIn den ausweglosen Lagen: Gott vertrauen!\nAn den hoffnungslosen Tagen: Gott vertrauen!\nIn den angsterfüllten Stunden: Gott vertrauen!\r\nWorte, die das Fürchten lehren,\nKrisen, die die Angst vermehren,\nMauern, die die Sicht verbauen,\nPläne, die wir nicht durchschauen.\nMenschen, die uns Angst einjagen,\nNöte, die sich überschlagen,\nDramen, die uns sprachlos machen,\nSorgen, die zu schaffen machen.\r\nEuer Herz erschrecke nicht,\nglaubt an Gott und glaubt an mich.\nEuer Herz erschrecke nicht,\nglaubt an Gott und glaubt an mich.\r\nAufbruch in das Unbekannte,\nSchatten wirft das Ungeplante,\nAbschied, der uns endlos schwerfällt,\nZweifel, der das Herz zutiefst quält.\nFehler, die man nie verzieh\'n kriegt,\nSchuld, die schon so lang zurückliegt,\nHoffnung auf den neuen Anfang,\nÄngste, weil er so oft misslang.'),
(9, '0436', 'Euer Herz werde nicht bestürzt   (Joh. 14, 1+6)', NULL, 'Euer Herz werde nicht bestürzt,\nihr glaubt an Gott, glaubet auch an mich.(2x)\r\nDu bist der Weg, Du bist die Wahrheit,\nDu bist das Leben. (2x)\r\nUnd niemand kommt zum Vater\nnur durch dich, Jesus,\nniemand kommt zum Vater\nnur durch Dich. (2x)'),
(9, '0437', 'Even so, come Lord Jesus come  -  Ja, komm, Herr Jesus, komm', 'Even so, come Lord Jesus come.\nEven so, take your bride away,\nhow my soul, longs to be with you my Lord.\nEven so, even so, come Lord Jesus come.', 'Ja, komm, Herr Jesus, komm.\nJa, nimm deine Braut hinweg,\noh, wie sehnt sich meine Seele, bei dir zu sein, mein Herr.\nJa, ja, komm, Herr Jesus, komm.'),
(9, '0438', 'Every Eye shall see, every Ear shall hear   (And He will plant His beautiful Feet upon this Mountain)', 'Every eye shall see, every ear shall hear,\nthe sound of angels, when He comes, when He comes.\nEvery knee shall bow, every tongue shall confess\nthat He is Lord, when He comes, when He comes.\r\nAnd He will plant His beautiful feet upon this mountain.\nAnd the dead of all the ages, who believed on Him shall rise.\nAnd I\'ll be one, I\'ll be one in the first resurrection,\nwhen He comes, when He comes, when He comes.\r\nEveryone then will know that it\'s Him, really Him,\nthe One and Only, when He comes, when He comes.\nGlorified and transformed, I\'ll arise at His call,\nI\'ll be ready, when He comes, when He comes.', NULL),
(9, '0439', 'Every Praise', 'Every praise is to our God\nEvery word of worship with one accord\nEvery praise every praise is to our God\nSing hallelujah to our God\nGlory hallelujah is due our God\nEvery praise every praise is to our God\r\nGod my Savior\nGod my Healer\nGod my Deliverer\nYes He is, yes He is', '(Jedes Lob gebührt unserem Gott\nJedes Wort der Anbetung in Einklang\nJedes Lob, jedes Lob gebührt unserem Gott\nSingt Halleluja zu unserem Gott\nEhre, Halleluja, gebührt unserem Gott\nJedes Lob, jedes Lob gebührt unserem Gott)\r\nGott mein Erlöser\nGott mein Heiler\nGott mein Befreier\nJa, er ist, ja er ist'),
(9, '0440', 'Every promise / Mein Mein / Sieg ist mein', 'Every promise in the book is mine,\nEvery chapter, every verse, every line.\nI am trusting in His love divine,\nEvery promise in the book is mine.\r\nMine, mine, mine, Jesus is mine.\nMine, mine, mine, Jesus is mine.\nJesus is my saviour day by day,\nmine, mine, mine, Jesus is mine.\r\nVictory is mine! Victory is mine!\nVictory today is mine!\nI told satan: "Get thee behind!"\nVictory today is mine!\r\nJoy is mine! Joy is mine!\nJoy today is mine!\nI told satan: "Get thee behind!"\nJoy today is mine!', 'Jede Verheißung in dem Buch ist mein;\njedes Kapitel, Vers und Zeile vereint.\nIch vertraue Seiner Lieb\' allein.\nJede Verheißung in dem Buch ist mein.\r\nMein, mein, mein, Jesus ist mein.\nMein, mein, mein, Jesus ist mein.\nJesus ist mein Retter Tag für Tag,\nmein, mein, mein, Jesus ist mein.\r\nSieg ist mein, Sieg ist mein,\nSieg ist heute mein.\nSatan ist besiegt, glaub es und er flieht,\nSieg ist heute mein!\r\nFreude ist mein, Freude ist mein,\nFreude ist heute mein.\nSatan ist besiegt, glaub es und er flieht,\nFreude ist heute mein!'),
(9, '0441', 'Ewger Fels, Du Hort der Deinen, birg Du mich  -  In Thy Cleft, o Rock of Ages, hide Thou me', 'In Thy cleft, o Rock of Ages, hide Thou me.\nWhen the fitful tempest rages, hide Thou me.\nWhere no mortal arm can sever\nfrom my heart Thy love forever.\nHide me, o Thou Rock of Ages, safe in Thee.\r\nFrom the snare of sinful pleasure, hide Thou me.\nThou, my soul’s eternal treasure, hide Thou me.\nWhen the world its power is wielding,\nand my heart is almost yielding.\nHide me, O Thou Rock of Ages, safe in Thee.\r\nIn the lonely night of sorrow, hide Thou me.\nTill in glory dawns the morrow, hide Thou me.\nIn the shadows that enfold me,\nlet thy gentle hands uphold me.\nHide me, O Thou Rock of Ages, safe in Thee.', 'Ew\'ger Fels, Du Hort der Deinen, birg\' Du mich!\nDein ist all mein Denken, Meinen, birg\' Du mich!\nWeder Freude soll noch Leiden\nmich von Deiner Liebe scheiden.\nO, Du ew\'ger Hort der Deinen, birg\' Du mich!\r\nWill die Welt mich Dir entreißen, birg\' Du mich!\nWenn der Sünde Lüste gleißen, birg\' Du mich!\nDroht der Feind von allen Seiten,\nwill mein müder Fuß fast gleiten,\ndann, Du ew\'ger Hort der Deinen, birg\' Du mich!\r\nIn der dunklen Nächte Kummer, birg\' Du mich!\nScheuchen Tränen mir den Schlummer, birg\' Du mich!\nBis die Finsternis verziehet und der ew\'ge Morgen glühet,\no, Du ew\'ger Hort der Deinen, birg\' Du mich!'),
(9, '0442', 'Ewiger Vater, Herrscher und König   (Chorus)', NULL, 'Ewiger Vater, Herrscher und König,\nSchöpfer der ganzen Welt, allmächtiger Gott.\nDu bist der Heilige, vollkommen Reine,\nHerr über alles, und doch nennst Du mich "Freund".'),
(9, '0443', 'Ewigkeit', NULL, 'Ich sehne mich nach einem Ort\nWo alles Leid ein Ende hat\nDenn was ich mit den Augen seh\nKann meine Seele nicht verstehn\nIch weiß: Du hast den besten Plan\nAuf den ich mich verlassen kann\nAuf jedem noch so schweren Weg\nSchau ich auf das, was nie vergeht\r\nDie Ewigkeit ist mein Zuhause\nDu hast sie mir ins Herz gelegt\nAuch wenn ich sterben werde, weiß ich\nDass meine Seele ewig lebt\nUnd diese Hoffnung wird mich tragen\nBis ich Dir gegenüber steh\r\nIch weiß: ich bin nur zu Besuch\nDenn wahre Heimat gibst nur Du\nAls Bürger deines Himmelreichs\nWerd ich für immer bei Dir sein\r\nMit Fokus auf die Ewigkeit\nLeb ich für das, was ewig bleibt\nDas Ziel vor Augen, Tag für Tag\nBis ich den Lauf vollendet hab'),
(9, '0444', 'Faith in the Father and Faith in the Son, Faith in the Holy Ghost, these three are One   (Chorus)', 'Faith in the Father and faith in the Son,\nfaith in the Holy Ghost, these three are One.\nDemons will tremble, and sinners awake,\nfaith in Jehovah can anything shake.', NULL),
(9, '0445', 'Faith of our Fathers living still   (Faith of our Fathers, holy Faith)', 'Faith of our fathers! living still\nIn spite of dungeon, fire and sword;\nOh how our hearts beat high with joy\nWhene\'er we hear that glorious word\r\nFaith of our fathers, holy faith!\nWe will be true to thee till death!\r\nOur fathers, chained in prisons dark,\nWere still in heart and conscience free:\nHow sweet would be their children\'s fate,\nIf they, like them, could die for Thee!\r\nFaith of our fathers! we will love\nBoth friend and foe in all our strife;\nAnd preach Thee, too,\nAs love knows how,\nBy kindly words and virtuous life!', NULL),
(9, '0446', 'Faithful to the End', 'When I\'m feeling afraid, full of uncertainty\nWhen the plans that I\'ve made all fall apart\nWhen the future\'s unclear, and all that I can do is wait\nThere is a promise echoing in my heart\r\nHe will be faithful to the end\nHe will provide time and time again\nHe will be faithful, so faithful to the end\nAnd he will be there when all else fades\nHis love is stronger than my pain\nHe will be faithful, so faithful to the end\r\nThere is grace I can\'t measure\nMercy I don\'t deserve\nThere\'s forgiveness that\'s endless for me\nOh, what a blessed assurance\nTo know how deeply I\'m loved\nAnd I\'m always reminded, that he will be all I need\nAll I need', NULL),
(9, '0447', 'Fass meine Hand, ich bin so schwach und hilflos  -  Hold Thou my Hand, so weak I am and helpless', 'Hold thou my hand! so weak I am, and helpless,\nI dare not take one step without thy aid.\nHold thou my hand! for then, O loving Saviour,\nno dread of ill shall make my soul afraid.\r\nHold thou my hand! and closer, closer draw me,\nto thy dear self, my hope, my joy, my all.\nHold thou my hand, lest haply I should wander,\nand, missing thee, my trembling feet should fall.\r\nHold thou my hand! the way is dark before me,\nwithout the sunlight of thy face divine.\nBut when by faith I catch its radiant glory,\nwhat heights of joy, what rapturous songs are mine.\r\nHold thou my hand! that when I reach the margin,\nof that lone river thou didst cross for me.\nA heavenly light may flash across its waters,\nand every wave like crystal bright shall be.', 'Fass meine Hand! Ich bin so schwach und hilflos,\ndass keinen Schritt ich wage ohne Dich.\nFass meine Hand, und dann, o lieber Heiland,\nkann Furcht vor Leiden nicht mehr ängstigen mich!\r\nFass meine Hand und zieh mich näher zu Dir,\ndenn Deinem Herzen möchte nah ich sein!\nFass meine Hand, ich möchte anders irren\nvom g\'raden Wege, ginge ich allein!\r\nFass meine Hand! Der Weg liegt dunkel vor mir,\nwenn mir Dein Angesicht nicht zugewandt.\nWenn Himmelslicht den finster\'n Pfad erhellet,\no Wonne, dann zu geh\'n an Deiner Hand!\r\nFass meine Hand! Und wenn am Todesjordan,\nden Du für mich durchkreuzt, ich einst werd\' steh\'n,\nlass Himmelslicht von Deinem Thron mir leuchten,\nlass auch im Schreckenstal mich furchtlos geh\'n!'),
(9, '0448', 'Father God I wonder how I managed to exist', 'Father God I wonder how I managed to exist\nwithout the knowledge of Your parenthood,\nand Your loving care.\nBut now I am Your child\nI am adopted in Your family,\nand I can never be alone, \'cause\nFather God You\'re there beside me.\r\nI will sing Your praises,\nI will sing Your praises,\nI will sing Your praises forevermore\nI will sing Your praises,\nI will sing Your praises,\nI will sing Your praises forevermore', NULL),
(9, '0449', 'Father I see that you are drawing a Line in the Sand   (Let the Worshippers arise, let the Sons and the Daughters sing)', 'Father I see that you are drawing a line in the sand.\nAnd I want to be standing on your side, holding your hand.\nSo let your kingdom come, let it live in me,\nthis is my prayer, this is my plea.\r\nLet the worshippers arise,\nlet the sons and the daughters sing,\nI\'m surrendering my all,\nI surrender to the King. (2x)\r\nFather I hear it growing louder,\nthe song of your redeemed.\nAs the saints of every nation\nare awakening to sing.\nFrom our hearts there comes an anthem,\noh, hear the heavens ring.\nThis is our song, a song to our King!', '\r\nDie Anbeter sollen sich erheben. \nLasst die Söhne und Töchter singen. \nIch übergebe alles.  Ich weihe mich dem König.\r\n'),
(9, '0450', 'Father in heaven, how we love You   (Blessed be the Lord God Almighty)', 'Father in heaven, how we love you.\nWe lift your Name in all the earth.\nMay your kingdom, be established in our praises,\nas your people declare your mighty works.\r\nBlessed be the Lord God Almighty\nWho was and is and is to come.\nBlessed be the Lord God Almighty\nWho reigns forevermore.\r\nFather of mercy, be exalted.\nMay Jesus name be lifted high.\nFor the sacrifice of love, has won my pardon\nand his resurrection power, gives me life.', NULL),
(9, '0451', 'Father of Live, seated on Your throne of Grace', 'Father of life, seated on Your throne of grace,\nit\'s only by Your mercy we are saved.\nLord, You have said if we call upon Your Name\nwe and our families will be saved.\r\nSo we cry out Your Name, El Shaddai, God of grace,\nLord Most High, Jesus Christ.\nWe rely on Your grace, Adonai, crowned in praise,\nLord Most High, Jesus Christ.\r\nFather of love never failing to forgive,\neach moment is a gift from You to live.\nWe\'re only here to tell the world about Your Grace,\nuntil the day that You take us all away.', '(Vater des Lebens, sitzend auf Deinem Thron der Gnade,\nnur durch Deine Gnade sind wir gerettet.\nHerr, Du hast gesagt, wenn wir Deinen Namen anrufen\nwerden wir und unsere Familien gerettet werden.)\r\nSo rufen wir Deinen Namen an, El Schaddai, Gott der Gnade,\nHerr, der Höchste, Jesus Christus.\nWir vertrauen auf Deine Gnade, Adonai, gekrönt mit Preis,\nHerr, der Höchste, Jesus Christus.\r\nVater der Liebe, der nie versagt, zu vergeben,\njeder Augenblick ist ein Geschenk von Dir zum Leben.\nWir sind nur hier, um der Welt von Deiner Gnade zu erzählen,\nbis zu dem Tag, an dem Du uns alle hinwegnimmst.'),
(9, '0452', 'Father, You are the Source of our Love   (Chorus)', 'Father, You are the source of our love,\nJesus, You are the source of our joy,\nSpirit, You are the source of our peace.\nOh Lord, we live to do Your will,\nYour will, Your will, Your will, Your will, Your will,\noh Lord, we live to do Your will.', NULL),
(9, '0453', 'Fels der Ewigkeiten, Welten durch Dich stehn', NULL, 'Fels der Ewigkeiten, Welten durch Dich steh\'n,\nFels im Meer der Zeiten, Hort im Sturmes weh\'n.\nFels, der in den Gluten öder Wüste hier\nsprudelt Lebensfluten: Fels, Dich preisen wir!\r\nStern an dunklen Tagen, wenn die Sonne flieht,\nDu lässt nicht verzagen den, der auf Dich sieht.\nStern, Du machst so helle unsre Wege hier;\nunsrer Hoffnung Quelle, Stern, Dich preisen wir!\r\nJesus will fürs Leben Fels und Stern dir sein;\ndu brauchst nie zu beben, nie bist du allein.\nAuf dem Felsen stehen, schauend auf den Stern,\nheißt, als Sieger gehen in der Kraft des Herrn.'),
(9, '0454', 'Fels der Heils geöffnet mir  -  Rock of Ages cleft for me', 'Rock of Ages, cleft for me,\nlet me hide myself in Thee.\nLet the water and the blood,\nfrom Thy wounded side which flowed,\nbe of sin the double cure,\nsave from wrath and make me pure.\r\nCould my tears forever flow,\ncould my zeal no languor know.\nThese for sin could not atone,\nThou must save, and Thou alone.\nIn my hand no price I bring,\nsimply to Thy cross I cling.\r\nNothing in my hand I bring,\nsimply to the cross I cling.\nNaked, come to thee for dress,\nhelpless, look to thee for grace.\nFoul, I to the fountain fly,\nwash me, Saviour, or I die.\r\nWhile I draw this fleeting breath,\nwhen my eyes shall close in death.\nWhen I rise to worlds unknown,\nand behold Thee on Thy throne.\nRock of Ages, cleft for me,\nlet me hide myself in Thee.', 'Fels des Heils, geöffnet mir,\nbirg mich, ewger Hort, in Dir!\nLass das Wasser und das Blut,\nDeiner Seite heilge Flut,\nmir das Heil sein, das frei macht\nvon der Sünden Schuld und Macht!\r\nDem, was Dein Gesetze spricht,\nkann mein Werk genügen nicht.\nMag ich ringen, wie ich will,\nfließen auch der Tränen viel,\ntilgt das doch nicht meine Schuld,\nHerr, mir hilft nur Deine Huld!\r\nDa ich denn nichts bringen kann,\nschmieg ich an Dein Kreuz mich an;\nnackt und bloß, o kleid mich doch!\nHilflos, ach, erbarm Dich noch!\nUnrein, Herr, flieh ich zu Dir!\nWasche mich, sonst sterb ich hier!\r\nJetzt, da ich noch leb im Licht,\nwenn mein Aug im Tode bricht,\nwenn durchs finstre Tal ich geh,\nwenn ich vor dem Richter steh,\nFels des Heils, geöffnet mir,\nbirg mich, ewger Hort, in Dir!'),
(9, '0455', 'Fest und treu wie Daniel war  -  Standing by a Purpose true   (Bleibe fest, wie Daniel)   [Jesu Name Band 1]', 'Standing by a purpose true,\nheeding God\'s command,\nhonor them, the faithful few!\nAll hail to Daniel\'s band!\r\nDare to be a Daniel,\ndare to stand alone!\nDare to have a purpose firm,\ndare to make it known!\r\nMany mighty men are lost,\ndaring not to stand,\nwho for God had been a host\nby joining Daniel\'s band.\r\nMany giants, great and tall,\nstalking through the land,\nheadlong to the earth would fall,\nif met by Daniel\'s band.\r\nHold the gospel banner high,\non to vict\'ry grand.\nSatan and his host defy,\nand shout for Daniel\'s band.', 'Fest und treu, wie Daniel war\nnach des Herrn Gebot,\nsei der Kinder Gottes Schar\nin der größten Not.\r\nBleibe fest, wie Daniel,\nstehst du auch allein;\nwag\' es treu vor aller Welt,\nGottes Kind zu sein!\r\nStarke Männer voller Licht\nmögen nicht besteh\'n,\nwagen Gott zu Ehren nicht\nin den Tod zu geh\'n.\r\nDoch wer stets wie Daniel dort\nfest am Herrn sich hält,\nkann im Glauben an sein Wort\nwidersteh\'n der Welt.\r\nTragt denn Christi Banner hoch\nin dem heil\'gen Krieg!\nSatan kommt zu Falle doch!\nUnser ist der Sieg!'),
(9, '0456', 'Feuer, Feuer, Feuer, Feuer, fall auf mich  -  Fire, fire, fire, fire fall on me   (Chorus)', 'Fire, fire, fire, fire fall on me.\nFire, fire, fire, fire fall on me.\nAs in the day of Pentecost,\nfire fall on me.\nAs in the day of Pentecost,\nfire fall on me.', 'Feuer, Feuer, Feuer, Feuer, fall\' auf mich!\nFeuer, Feuer, Feuer, Feuer, fall\' auf mich!\nWie es am Tag zu Pfingsten war,\nFeuer, fall\' auf mich!\nWie es am Tag zu Pfingsten war,\nFeuer, fall\' auf mich!'),
(9, '0457', 'Finstere Wolken steigen drohend im Sturm empor', NULL, 'Finstere Wolken steigen drohend im Sturm empor,\nrings brechen Feindesmächte wild zum Kampf hervor!\nSchau nicht der Feinde Toben, schau nicht die dunkle Nacht;\ndurch alle Wolken siegend strahlt des Heilands Macht.\r\nSieh nicht die dunklen Fluten, schon ist dein Moses nah.\nSieh nicht die trotz\'gen Mauern, sieh auf Josua!\nTraue dem ew\'gen Führer, harre nur kurze Zeit;\nbald wird die Nacht verschwinden, bald ist Herrlichkeit.\r\nSchon ward der Sieg errungen, denke an Golgatha!\nSchon ward der Kopf der Schlange längst zertreten da.\nUnd mit zertretenem Kopfe unter des Heilands Fuß\nkann dir der Feind nicht schaden, alles schwinden muss!\r\nChristus, dem Auferstand\'nen, nahet der Teufel nicht;\nall seine Macht ist Lüge, längst ward er besiegt!\nNur, wo noch Furcht und Zweifel, wächst ihm ein neuer Mut.\nSchaue allein auf Jesus und des Lammes Blut!\r\nTragen wir Schmach, Verfolgung, droben sind sie nicht mehr.\nLeiden um Jesu willen: Nichts ist herrlicher!\nLasst d\'rum die Fahne fliegen, auf denn zum letzten Streit!\nSinget die Siegeslieder bis in Ewigkeit!'),
(9, '0458', 'Finstre Nacht rings um uns her, Wetterleuchten schreckt uns sehr  -  We are often tossed and driv’n on the restless Sea of Time   (Dann vergeht, wenn der Morgen kommt)', 'We are often tossed and driven on the restless sea of time,\nsombre skies and howling tempest oft succeed a bright sunshine.\nIn that land of perfect day, when the mists have rolled away,\nwe will understand it better by and by.\r\nBy and by when the morning comes,\nwhen all the saints of God are gathered home,\nwe will tell the story how we overcome,\nfor we\'ll understand it better by and by.\r\nWe are often destitute of the things that life demands,\nwant of food and want of shelter, thirsty hills and barren lands.\nWe are trusting in the Lord, and according to the Word,\nwe will understand it better by and by.\r\nTrials dark on every hand, and we cannot understand,\nall the ways that God would lead us to that blessed promised land;\nbut He guides us with His eye and we\'ll follow till we die,\nfor we\'ll understand it better by and by.', 'Finst\'re Nacht rings um uns her, Wetterleuchten schreckt uns sehr.\nMüde Hände tasten hilflos in der Dunkelheit umher.\nDoch der Herr im Himmel wacht, bringt uns sicher durch die Nacht,\nbis der neue Morgen uns das Licht gebracht.\r\nDann vergeht, wenn der Morgen kommt,\nalles Fragen, das noch vor uns steht.\nDann wird klar, was dunkel um uns türmte sich,\nwenn der neue Morgen helles Licht gebracht.\r\nWir sind oftmals sehr geplagt, unser Herz ist schnell verzagt,\nviele Fragen keine Antwort, statt zu glauben wird geklagt.\nUnd stürmt es hier mit Macht, doch wir schreiten durch die Nacht,\nbis der neue Morgen uns das Licht gebracht.\r\nTiefe Wege sind zu geh\'n, manches Leid nicht zu versteh\'n,\nja, in diesem Prüfungsfeuer kann der Tapf\'re nur besteh\'n.\nAuf, wir müssen durch die Nacht, beten, glauben geben acht,\nbis der neue Morgen uns das Licht gebracht.'),
(9, '0459', 'Folg\' nicht der Versuchung, die Sünde betrügt  -  Yield not to Temptation, for Yielding is Sin   (Fleh zum Heiland, Er hört dich)', 'Yield not to temptation, for yielding is sin.\nEach vict’ry will help you, some other to win.\nFight valiantly onward, evil passions subdue.\nLook ever to Jesus, He will carry you through.\r\nAsk the Saviour to help you,\ncomfort, strengthen and keep you.\nHe is willing to aid you,\nHe will carry you through.\r\nShun evil companions, bad language disdain.\nGod’s name hold in rev’rence, nor take it in vain.\nBe thoughtful and earnest, kindhearted and true.\nLook ever to Jesus, He will carry you through.\r\nTo him that o’ercometh, God giveth a crown.\nThrough faith we will conquer, though often cast down.\nHe who is our Saviour, our strength will renew.\nLook ever to Jesus, He will carry you through.', 'Folg\' nicht der Versuchung, die Sünde betrügt!\nLausch\' einmal dem Locken, bald bist du besiegt.\nO Bruder, sei tapfer, die Leidenschaft brich;\nschau immer auf Jesus, Er rettet auch dich!\r\nFleh\' zum Heiland, Er hört dich,\ntröstet, warnet und stärkt dich;\nauf den Heiland verlass dich!\nJesus rettet auch dich!\r\nFlieh schlechte Gesellschaft, hass\' böses Gespräch;\nleicht wirst du gezogen vom richtigen Weg!\nWas rein ist, das liebe; was wahr ist, das sprich;\nschau immer auf Jesus, Er rettet auch dich!\r\nWer hier überwindet, trägt drüben die Kron\'.\nWas macht uns die Feindschaft? Was kümmert uns Hohn?\nD\'rum fliehe der Sünde, Gott gibt dir den Sieg;\nschau immer auf Jesus, Er rettet auch dich!'),
(9, '0460', 'For many Years now Satan has tried to stop us', 'For many years now Satan has tried to stop us,\nbut the Bride of Jesus, yes, She\'s still alive.\nLike a mighty army, she keeps pressing onward.\nWinning every battle, for the Lord\'s on Her side.\r\nWe\'ve got the power in the Name of Jesus,\nwe\'ve got the power in the Name of the Lord.\nTho Satan rages, we shall not be defeated.\nWe\'ve got the power in the Name of the Lord.\r\nGive me your hand, let us agree together.\nThen let all of our enemies stumble at our feet.\nFor whatever we bind on earth, shall be bound in heaven,\nat the Name of Jesus, demons have to flee.', NULL),
(9, '0461', 'Fort fort mein Herz zum Himmel', NULL, 'Fort, fort, mein Herz, zum Himmel\nfort, fort zum Himmel zu.\nIn diesem Weltgetümmel\nist für dich keine Ruh.\nWo Gottes Lämmlein weidet,\nist eine Stätt bereitet,\nda, da ist deine Ruh.\nFort, fort, zum Himmel zu.\r\nFühlst du dich noch gebunden,\nentreiß dich nur beherzt.\nDas Lamm hat überwunden,\nwas seine Seele schmerzt.\nWie schwingt es Seine Fahne\ndort auf dem Siegesplane.\nDa blühet deine Ruh.\nFort, fort, zum Himmel zu.\r\nEs eilet mit Erbarmen\nder Vater selbst zu dir,\nwill ewig dich umarmen,\nsetzt dich zur Pracht und Zier,\nschenkt dir die reine Seide,\nGerechtigkeit zum Kleide,\ndas bringet selge Ruh.\nFort, fort zum Himmel zu.\r\nO Lamm auf Zions Hügel.\nWie herrlich siehst Du aus.\nO hätt ich Adlers Flügel.\nIch flög noch heut nach Haus,\nwo mit Triumph und Prangen\nin ewig süßer Ruh.\nFort, fort, zum Himmel zu.\r\nJedoch soll mein Verlangen\nin Deinem Willen ruhn,\nmein Herz soll an Dir hangen\nund , was Du sagest, tun.\nIch will hier wartend stehen.\nBis mich Dein Mund heißt gehen,\nfort, fort, zu Deiner Ruh.\nFort, fort, zum Himmel zu.'),
(9, '0462', 'Four Days Journey by the Way of the Grave   (We are waiting for the Resurrection)', 'Four days journey\nby the way of the grave.\nFour days journey\ntill he heard The Voice\r\nWe are waiting for the resurrection,\nmy brother it might be today.\nWe are yearning for the translation\nthat sudden secret going away.\nWe are longing for the rapture\ndon\'t be left behind in the twinkle of an eye.\r\nHe was quickened from the earth,\npoisoned by the sting of death,\nSaints that fell asleep.\nBelieving, trusting and waiting on that voice,\nthat cried out \'Lazarus come forth!\'\r\nMy Easter seal,\nmy Jesus is so real.\nAs long as He lives\nin my soul He reigns,\ndeath has no sting.\r\nIt\'s conquered so the Bride is believing\nin the resurrection.\nThat morning hearing will recognize the voice\nthat cried out \'Lazarus come forth!', NULL),
(9, '0463', 'Frei vom Gesetz, o glückliches Leben  -  Free from the Law, o happy Condition   (Ein für alle Mal Sünder, ergreif es)', 'Free from the law, o happy condition,\nJesus hath bled, and there is remission.\nCursed by the law and bruised by the fall,\ngrace hath redeemed us once for all.\r\nOnce for all, O sinner, receive it,\nonce for all, O friend, now believe it.\nCling to the cross, the burden will fall,\nChrist hath redeemed us once for all.\r\nNow we are free, there\'s no condemnation,\nJesus provides a perfect salvation.\n"Come unto Me," O hear His sweet call,\ncome, and He saves us once for all.\r\n"Children of God," O glorious calling,\nsurely His grace will keep us from falling.\nPassing from death to life at His call,\nblessed salvation once for all.', 'Frei vom Gesetz, o glückliches Leben!\nDenn bei dem Herrn ist vieles vergeben!\nChristus erlöst uns gänzlich vom Fall!\nSein Blut gilt ein für alle Mal!\r\nEin für alle Mal Sünder, ergreif\' es!\nEin für alle Mal, Bruder, o glaub es!\nChristus erlöst uns gänzlich vom Fall!\nSein Blut gilt ein für alle Mal!\r\nIn Christus Jesus gibt\'s kein Verdammen!\nAlle Verheißung ist in Ihm Amen.\n"Kommet zu Mir!" so ruft Er mit Schall.\nSein Wort gilt ein für alle Mal!\r\nKinder des Höchsten, ihr seid berufen,\neuch zu erfreu\'n auf höheren Stufen!\nVolle Erlösung sei eure Wahl!\nChristus starb ein für alle Mal!'),
(9, '0464', 'Frei von der Weltlust betrüglichem Schein - Gone from my heart, the world and on its charms', 'Gone from my heart, the world and on its charms;\nnow, through the blood I\'m saved from all alarms.\nDown at the cross my heart is bendinglow,\nthe precious blood of Jesus cleanses white as snow.\r\nI love Him, I love Him,\nbecause He first loved me.\nAnd purchased my salvation\non Calvary`s tree.\r\nOnce I was lost, and \'way down deep in sin;\nonce was a slave to passions fierce within;\nonce was afraid to trust a loving God;\nbut now I\'m cleansed from every stain through Jesus\' blood.\r\nOnce I was bound, but now I am set free;\nonce I was blind, but now the light I see;\nonce I was dead, but now in Christ I live;\nto tell the world around the peace that He does give.', 'Frei von der Weltlust betrüglichem Schein,\nfrei von der Sünde mit all ihrem Pein,\nfrei durch die Gnade, das eine ich seh\':\nDas teure Blut des Heilands wäscht mich weiß wie Schnee.\r\nIch lieb\' Ihn, ich lieb\' Ihn,\nEr liebte mich zuerst.\nUnd brachte mir Erlösung\nauf Golgatha.\r\nEinst war verwirrt ich auf Pfaden der Sünd\'.\nEinst war versklavt ich, verarmt und ganz blind.\nIch konnt\' nicht glauben, dass Gott ist so gut,\nbis abgewaschen ward die Sünd\' durch Jesu Blut.\r\nIch war gebunden und tot in der Sünd\'.\nNun bin ich frei und ein Gottes Kind,\nwiedergeboren bezeuge ich frei,\ndass Jesus jetzt mein Heiland und Retter sei.'),
(9, '0465', 'Freude klingt in meinem Herz  -  I\'ve got the Joybells in my Heart   (Chorus)', 'I\'ve got the joybells in my heart,\nI\'ve got the joybells in my heart.\nI\'ll sing His praises through all the ages.\nI\'ve got the joybells in my heart.', 'Freude klingt in meinem Herz.\nFreude klingt in meinem Herz.\nIch darf Ihn preisen durch alle Zeiten.\nWelche Freud\' erklingt in mir.'),
(9, '0466', 'Freudig singend gehe ich meinen Pilgerpfad  -  As I journey through the Land, singing as I go   (O ich möchte schauen)', 'As I journey through the land, singing as I go,\npointing souls to Calvary, to the crimson flow.\nMany arrows pierce my soul from without within.\nBut my Lord leads me on, through Him I must win.\r\nOh, I want to see Him, look upon His face.\nThere to sing forever of His saving grace.\nOn the streets of glory let me lift my voice,\ncares all past, home at last, ever to rejoice.\r\nWhen I service for my Lord, dark may be the night,\nbut I\'ll cling more close to Him, He will give me light.\nSatan\'s snares may vex my soul, turn my thoughts aside,\nbut my Lord goes ahead, leads whate\' er betide.\r\nWhen in valleys low I look toward the mountain height,\nand behold my Saviour there, leading in the fight.\nWith a tender hand outstretched toward the valley low,\nguiding me, I can see, as I onward go.\r\nWhen before me billows rise from the mighty deep,\nthe my Lord directs my bark, He doth safely keep.\nAnd He leads me gently on through this world below,\nHe\'s a real friend to me, oh, I love Him so.', 'Freudig singend gehe ich meinen Pilgerpfad.\nSeelen zeig\' ich Golgatha, Gottes Lieb\' und Gnad\'.\nSchwirren Pfeile um mich her, bleibt doch ruhig mein Herz,\ndenn der Herr führet mich siegend himmelwärts.\r\nO ich möchte schauen, den, der für mich starb!\nAllzeit jubeln, preisen Seine Rettertat!\nMöcht\' auf goldnen Straßen singen hell und klar.\nNach dem Streit Herrlichkeit, Freude immerdar.\r\nWenn im Dienste für den Herrn dunkel ist die Nacht.\nHalte ich mich nur an Ihn und die Sonne lacht.\nSatan stellet Schlingen mir, um zu fällen mich,\ndoch der Herr geht voran, nichts brauch\' fürchten ich.\r\nWird es dunkel um mich her, blick\' ich auf zur Höh\'.\nEs flieh\'n Zweifel, Sorg\' und Not, wenn ich Ihn nur seh\'!\nSicher leitet mich Sein Arm, und das macht mich froh.\nWahrer Freund ist Er mir, o ich lieb\' Ihn so!\r\nWenn sich vor mir die Wogen erheben von der mächtigen Tiefe,\nlenkt mein Herr meine Barke, Er hält sie sicher.\nUnd er führt mich sanft durch diese Welt hier unten,\nWahrer Freund ist Er mir, o ich lieb\' Ihn so!'),
(9, '0467', 'Freund warum so viele Sorgen   (O, leg sie ab, die schwere Last, die du so lang getragen hast)', NULL, 'Freund, warum so viele Sorgen?\nSag, woher die schwere Last,\ndie du trägst vom frühen Morgen\nbis hinein in späte Nacht?\r\nO leg\' sie ab, die schwere Last,\ndie du so lang getragen hast.\nJesus gibt Ruh\', o glaub es nur.\nSein Blut gab Er für dich und mich.\r\nIst es nicht der Lohn der Sünde,\nder dich plaget und dich quält?\nNirgends kannst du Ruhe finden,\nsag, mein Freund, wo es dir fehlt.\r\nJesus will die Schuld fort nehmen,\nist sie auch blutrot und schwer.\new\'ges Leben will er geben,\nkomm zu Ihm Er liebt dich sehr.\r\nEwig glücklich kannst du werden,\nund wie fröhlich kannst du sein,\nglaube nur du kannst auf Erden\nschon ein Kind des Königs sein.\r\n1928 Liederkarte Musikverlag Hänßler\n- Freund warum so viele Sorgen\n- Georg Panzer'),
(9, '0468', 'Freund wir ziehn ins Heimatland   (Ja, dort ists schön, so herrlich schön)', NULL, 'Freund, wir zieh\'n ins Heimatland. Willst du mit?\nSelig ist\'s an Jesu Hand. Willst du nicht auch mit?\nWas die Welt dir bieten kann ist nur Schein.\nDenk, was Jesus hat getan, wie er um dich weint.\r\nJa, dort ist\'s schön, so herrlich schön.\nWillst du nicht mit mir heimwärts zieh\'n?\nJa, dort ist\'s schön, so herrlich schön.\nWillst du nicht mit, versuch\'s, \'s ist herrlich, herrlich schön.\r\nGib all\' deine Sünde dran, die dich drückt,\nselig man hier leben kann, Jesus nur erquickt.\nScheint auch dornenvoll der Pfad, o, wie wohl\nist\'s dem, der das Kreuz hier trägt, o, wie ist mir wohl.\r\nDroben wandelt sich in Freud\' alles Leid,\noh, welch frohe Seligkeit, mit dem Herrn vereint.\nMöcht\' doch niemand fehlen dort, Seele komm.\nHeut\' entrinn\' dem ew\'gen Tod, komm zum Gnadenthron.'),
(9, '0469', 'Fried\' wie ein Strom, Liebe ohne Grenzen  -  Peace like a River, Love like a Mountain   (Chorus)', 'Peace like a river, love like a mountain.\nThe wind of Your Spirit is blowing everywhere.\nJoy like a fountain, healing stream of life.\n(: Come, Holy Spirit, let Your fire fall. :)', 'Fried\' wie ein Strom, Liebe ohne Grenzen.\nDer Wind Deines Geistes bewegt sich unter uns.\nFreud\' aus der Quelle, ew\'ger Lebensstrom.\n(: Komm, Heil\'ger Geist, lass Dein Feuer fall\'n. :)'),
(9, '0470', 'Friede in Jesus so tief wie ein Strom', NULL, 'Friede in Jesus so tief wie ein Strom,\nRuhe in Ihm wie im himmlischen Dom,\nStille in Gott der ja alles doch lenkt,\nFriede viele höher als jemand es denkt.\nTrost in dem Leid, Stille beim Streit:\nDas ist der Friede den Jesus uns schenkt.\r\nKlare Gewissheit geheiligt zu sein,\nfrei von der Sünde mit all ihrer Pein,\nKraft aus der Höhe der alles gelingt,\ndie in Versuchung den Sieg stets erringt.\nFrohsinn in Not, Leben statt Tod:\nDas schafft der Friede den Jesus dir bringt.\r\nSanftmut, das Zorn dich nicht immer erregt,\nLangmut, die Unbill mit Freuden erträgt,\nMitleid das milde Barmherzigkeit lehrt,\nDemut die andre von Herzensgrund ehrt.\nFreude in Gott, Duldung beim Spott:\nDas liegt im Frieden den Jesus beschert.\r\nFriede in Jesus reicht alles dir dar,\nmacht dich gehorsam, geduldig und wahr.\nUnschuld und Keuschheit wird dann deine Zier,\nTreue und Einfalt wirkt Jesus in dir!\nWähle allein, Ihm dich zu weih\'n,\ndann macht der Heiland dich selig schon hier!'),
(9, '0471', 'Friedefürst, Wunderrat, Gnadenvoll, Gottes Sohn', NULL, 'Friedefürst, Wunderrat, Gnadenvoll, Gottes Sohn.\nHerr der Herrn, starker Held, König und Gott von Ewigkeit.\nIch erhebe Dich, Herr, ich erhebe Dich.\nDie Schöpfung ruft Dir zu:\n"So herrlich bist nur Du!"\nIch erhebe Dich, Herr, ich erhebe Dich,\nmein Jesus, ich erhebe Dich!'),
(9, '0472', 'Frieden, dem Strom gleich! O Herr kann es sein?  -   Peace like a River! O Lord, can it bee?   (Frieden, gleich des Stromes Flut)', 'Peace like a River! O Lord, can it bee?\nWonderful blessings are waiting for me?\nOft I rejoice when some clear sparkling rill,\ncomes from the fountain my spirit to fill.\nNow will it seem in its fulness to me\ncoming at floodtide, like waves of the sea.\r\nPeace, peace, like a rivers flow,\npeace, peace, my spirit shall know.\r\nPeace like a River! Thy word must be true,\nwhat Thou hast promised, Thou surely wilt do.\nIf I but list to Thy loving command,\nif I but follow Thy dear beck\'ning hand.\nPeace like a river my spirit shall feel,\njoy without measure Thy love shall reveal.\r\nPeace like a river that never runs dry!\nWhy drink at pools when the fountain is nigh?\nRiver of crystal from under the throne,\nwater the sweetest the ever was known.\nFree for the poorest, the Saviour has said,\ncome to the fountain, the price has been paid.\r\nPeace like a River! its waves like the sea!\nO grant this wonderful blessing to me.\nBroaden the way, that the water may flow,\ndeepen the channel thro\' wich it must go.\nBanish what ever may stand in the way,\nPeace like a River is flowing today.', 'Frieden, dem Strom gleich! O Herr kann es sein?\nSegnungen, wunderbar, warten sie mein?\nWie hat mich oft schon das Bächlein entzückt,\nwenn es die dürstende Seele erquickt;\nwas wird es sein, wenn das Meer sich erschließt\nund sich die Fülle wie Wasser ergießt!\r\nFrieden, gleich des Stromes Flut,\nFrieden aus des Lammes Blut.\r\nFrieden, dem Strom gleich! Dir, Herr, kann ich trau\'n,\nwas Du verheißen, das werde ich schau\'n.\nLausch\' ich nur willig dem göttlichen Wort,\nfolg\' ich dem Wink Deiner Hand nur sofort,\nkommt wie ein Strom, Herr, Dein Friede ins Herz,\nwandelt in Freude ohn\' Maßen den Schmerz.\r\nFrieden, dem Strom gleich! Kein Mangel ist da;\nwarum zur Lache? Die Quelle ist nah.\nKlar wie Kristall fließt sie nieder vom Thron,\nwer immer Durst hat, der trinke davon.\nKeiner geht leer aus, ob arm oder reich,\nJesus verkündet: Ich zahlte für euch.\r\nFrieden, dem Strom gleich, wie Wellen im Meer!\nGieß\' ihn hernieder ins Herz mir, o Herr!\nBahne den Weg für die göttliche Flut,\ngrabe nur tief, Herr, o grabe nur gut.\nWas ihn behindert, das schlage entzwei,\nmach Deinem Frieden den Zugang ganz frei!'),
(9, '0473', 'Frisch von dem Thron des Lammes  -  Fresh from the Throne of Glory   (Strom des Lebens, nicht vergebens sehn ich mich nach Dir)', 'Fresh from the throne of glory,\nbright in its crystal gleam.\nBursts out the living Fountain,\nswells on the living Stream.\r\nHoly River, I would ever draw my life from thee.\nMighty River, I will never cease to sing of thee.\r\nStream full of life and gladness,\nspring of all health and peace.\nNo harps by thee hang silent,\nnor happy voices cease.\r\nRiver of God, I greet thee,\nnow not afar, but near.\nMy soul to thy still waters\nhastes in its thirsting here.\r\nJesus, the healing Fountain,\nfresh from the throne above,\nThou art the living water,\nThou art the stream of love.', 'Frisch von dem Thron des Lammes,\nlauter wie ein Kristall,\nfließet der Strom des Lebens,\nheilbringend überall.\r\nStrom des Lebens, nicht vergebens seh\'n ich mich nach Dir.\nStrom des Lebens, nicht vergebens seh\'n ich mich nach Dir.\r\nO welche Wonn\' und Freude\nist uns bei Dir bereit.\nDort wird die Harfe tönen,\nJubel in Ewigkeit!\r\nStrom des lebend\'gen Wassers,\nsei mir gegrüßt von fern,\nhier schon im Land der Hoffnung\ntrink ich von Dir so gern.\r\n'),
(9, '0474', 'Fröhlich pilgern wir unsrer Heimat zu   (Einer ist\'s, der nie uns lässt in Kampf und Streit)', NULL, 'Fröhlich pilgern wir unsrer Heimat zu\nauf dem guten alten Weg;\nalles Zweifeln, Fragen kommt hier zur Ruh\'\nauf dem guten alten Weg.\r\nEiner ist\'s, der nie uns lässt in Kampf und Streit,\nder im Leid uns Freude schenkt und Tapferkeit,\nEiner, dessen Freundschaft unser höchster Lohn:\nJesus, der Gottessohn.\r\nUnseres Fußes Leuchte ist Gottes Wort\nauf dem guten alten Weg;\nalle Macht der Finsternis treibt es fort\nauf dem guten alten Weg.\r\nOft ist still und einsam es um uns her\nauf dem guten alten Weg;\ndenn es wird gar vielen zu bang und schwer\nauf dem guten alten Weg.\r\nWohl ist manche Trübsal hier unser Teil\nauf dem guten alten Weg;\ndoch am Ende winkt uns das ew\'ge Heil\nauf dem guten alten Weg.'),
(9, '0475', 'Fröhlich singt heut mein Herz, singt vor Lust und Wonne   (Wunderbar, wunderbar, Jesus ist der Herr)', NULL, 'Fröhlich singt heut\' mein Herz, singt vor Lust und Wonne.\nJesus ist Heiland mir, Leben, Licht und Sonne.\nEr vergab meine Schuld, Frieden wohnt im Herzen.\nJesus Christ ist wunderbar, heilte alle Schmerzen.\r\nWunderbar, wunderbar, Jesus ist der Herr.\nWunderrat, starker Gott, Friedefürst ist Er.\nRettet mich, schützet mich vor der Sünde Macht.\nWunderbar ist Jesus, der mir Sieg gebracht!\r\nEinst als Knecht meiner Sünd\' war ich voller Sorgen.\nJetzt bin ich frei und rein und in Ihm geborgen.\nAlle Schuld, alle Sünd\' hat Er mir vergeben.\nSein bin ich in Ewigkeit, darf stets mit Ihm leben.\r\nDurch den Herrn hab\' ich nun Heil und reiche Gnade.\nTag für Tag führt Er mich auf dem schmalen Pfade.\nWie beglückt mich all\'zeit Seine sel\'ge Nähe,\nseit Er mich mit starkem Arm hob aus Angst und Wehe!'),
(9, '0476', 'Fröhlich zieh ich meine Straße hier durch dieses Pilgertal', NULL, 'Fröhlich zieh ich meine Straße hier durch dieses Pilgertal;\nmeinen Herrn ich nimmer lasse, er beschirmt mich überall.\nMag manch wilder Sturm auch toben, der mich zu verderben droht,\ngläubig blicke ich nach oben, bin getrost in Not und Tod.\r\nJesus starb am Kreuzesstamme, trug dort alle Sünden Schuld.\nAch wie glüht in heii\'ger Flamme doch sein Herz voll Lieb und Huld!\nD\'rum hab\' ich mich ihm ergeben, in ihm sich mein Herze freut,\nohne ihn könnt ich nicht leben, ich bin sein in Ewigkeit.\r\nHeil fand ich in Jesu Wunden, bin von Sünd\' gewaschen rein;\nFried\' und Ruh\' hab ich gefunden, d\'rum kann ich so fröhlich sein.\nMag die Welt mich gleich auch hassen, willig trag\' ich Christi Schmach;\nbis ich werd\' im Tod erblassen, folg\' ich meinem Heiland nach.\r\nWillst auch du so glücklich werden, armes, friedeleeres Herz?\nLass die Treber dieser Erden, die dir bringen Leid und Schmerz!\nJesus nur kann recht beglücken, füllt dein Herz mit sel\'ger Lust,\nwill dich laben und erquicken, o so komm an seine Brust!'),
(9, '0477', 'Fühl mich so viel besser  -  Feeling so much better   (Lasst uns doch reden über den guten Weg)', 'Feeling so much better\ntalking about this good old way,\nFeeling so much better\ntalking about the Lord.\r\nLet\'s go on, let\'s go on\ntalking about this good old way,\nLet\'s go on, let\'s go on\ntalking about the  Lord.\r\nThe devil he don\'t like it,\ntalking about this good old way.\nThe devil he don\'t like it,\nTalking about the Lord.', 'Fühl mich so viel besser,\nredend über den guten Weg.\nFühl mich so viel besser,\nredend über den Herrn.\r\nLasst uns doch, lasst uns doch\nreden über den guten Weg.\nLasst uns doch, lasst uns doch\nreden über den Herrn.\r\nDer Teufel hört\'s nicht gerne,\nreden über den guten Weg.\nDer Teufel hört\'s nicht gerne,\nreden über den Herrn.'),
(9, '0478', 'Führ mich, o mein Heiland, führ mich  -  Guide me, o my Saviour, guide me   (Führ mich! Führ mich! Steh mir bei in Freud und Leid)', 'Guide me, o my Saviour, guide me!\nLet me clasp Thy hand!\nChoose my path, and guide my footsteps\nto the heav’nly land.\r\nGuide me, o my Saviour, guide!\nKeep me close to Thee!\nGuide me, O my Saviour, guide!\nKeep me close to Thee!\r\nGuide me, o my Saviour, guide me!\nHold my wayward heart,\nclasp me closer to Thy bosom,\nnevermore to part.\r\nGuide me, o my Saviour, guide me!\nLet me hear Thy voice,\nin the light or thro’ the shadow.\nMake my soul rejoice.', 'Führ\' mich, o mein Heiland, führ\' mich,\nhalt\' Dein Kind mit starker Hand.\nAbend wird\'s, die Schatten wachsen,\nund es geht durch fremdes Land.\r\nFühr\' mich! Führ\' mich!\nSteh\' mir bei in Freud\' und Leid!\nAll mein Denken sei Dein Eigen,\nall mein Wollen Dir geweiht!\r\nFühr\' mich, o mein Heiland, führ\' mich,\nwenn der Feind mir Schlingen legt\nund die Leidenschaft der Sünde\nsich mir heiß im Herzen regt.\r\nFühr\' mich, o mein Heiland, führ\' mich,\nbis mein Geist bei Dir erwacht,\nwo mich sel\'ge Freunde grüßen\nund der ew\'ge Morgen lacht.'),
(9, '0479', 'Führe Du uns o Jehova, pilgernd durch der Wüste Sand  -  Guide me o my great Redeemer, Pilgrim through this barren Land', 'Guide me, O my great Redeemer,\npilgrim through this barren land.\nI am weak, but you are mighty,\nhold me with your powerful hand.\nBread of heaven, bread of heaven,\nfeed me now and evermore.\r\nOpen now the crystal fountain,\nwhere the healing waters flow.\nLet the fire and cloudy pillar\nlead me all my journey through.\nStrong Deliverer, strong Deliverer,\never be my strength and shield.\r\nWhen I tread the verge of Jordan,\nbid my anxious fears subside.\nDeath of death, and hell\'s Destruction,\nland me safe on Canaan\'s side.\nSongs of praises, songs of praises\nI will ever sing to You.', 'Führe Du uns, o Jehova,\npilgernd durch der Wüste Sand!\nWir sind schwach, doch Du bist mächtig,\ntrage uns mit starker Hand.\nHimmelsmanna, Himmelsmanna,\nspeise Du dein mattes Volk!\r\nÖffne Du den ew\'gen Felsen,\nd\'raus das Lebenswasser fließt,\nschütz\' uns mit der Feuersäule,\nwenn der Feind uns rings umschließt!\nGroßer Retter, großer Retter,\nsei Du unser Schild und Hort!\r\nSteh\'n wir an des Jordans Ufer,\nmach\' uns durch den Strom die Bahn,\ndass Dein müdes Volk kann kommen\nins verheiß\'ne Kanaan!\nDankeslieder, Dankeslieder\nsteigen dann zu Dir empor!'),
(9, '0480', 'Führe uns, Heiland, an liebender Hand   (Jesus, deck mit Deinem Blute uns zu)', NULL, 'Führe uns, Heiland, an liebender Hand\ndurch dieses Leben zum himmlischen Land.\nSchütze uns Schwache und Mut uns zusprich!\nNimmermehr lassen wir Dich!\r\nJesus, deck mit Deinem Blute uns zu,\ndass Satan nimmermehr Schaden uns tu.\nNimmer, o nimmermehr lassen wir Dich,\nnimmermehr lassen wir Dich!\r\nOb auch der Himmel in Dunkel gehüllt,\nob Stürme brausen, der Donner laut brüllt,\nund selbst der Abgrund bewegete sich:\nnimmermehr lassen wir Dich!\r\nHerr, wir sind schwach noch, sei Du unsre Kraft,\ndie uns in Kämpfen den Sieg stets verschafft;\nDu bist ja unser, wir Dein ewiglich!\nNimmermehr lassen wir Dich!'),
(9, '0481', 'Füll mich jetzt  -  Fill me now   (Chorus)', 'Fill me now, fill me now,\nJesus come and fill me now.\nFill me with Your Holy Spirit,\ncome, oh, come and fill me now.', 'Füll mich jetzt, füll mich jetzt,\nJesus, komm und füll mich jetzt.\nFüll mich mit dem Heil\'gen Geist,\nHerr, komm, o, komm und füll mich jetzt'),
(9, '0482', 'Für mich gingst Du nach Golgatha   (Herr Deine Liebe ist so groß, dass ich sie nie begreifen kann)', NULL, 'Für mich gingst Du nach Golgatha,\nfür mich hast Du das Kreuz getragen,\nfür mich ertrugst Du Spott und Hohn,\nfür mich hast Du dich lassen schlagen.\r\nHerr Deine Liebe ist so groß, dass ich sie nie begreifen kann,\ndoch danken will ich Dir dafür.\nHerr Deine Liebe ist so groß, dass ich sie nie begreifen kann.\nIch bete Dich an.\r\nFür mich trugst Du die Dornenkron`,\nfür mich warst Du von Gott verlassen.\nAuf Dir lag alle Schuld der Welt,\nauch meine Schuld; ich kann`s nicht fassen.\r\nHerr Jesus Christus, alle Schuld\nhast Du für immer mir vergeben.\nDu hast mich froh und frei gemacht,\nDu schenkst mir neues, ew\'ges Leben.'),
(9, '0483', 'Fürcht ich, dass mein Glaube weicht  -  When I fear my Faith will fail   (Jesus hält mich fest / He will hold me fast)   [Original Ada Habershon + Pfingsjubel]', 'When I fear my faith will fail,\nChrist will hold me fast.\nWhen the tempter would prevail,\nHe can hold me fast!\r\nHe will hold me fast,\nHe will hold me fast.\nFor my Saviour loves me so,\nHe will hold me fast.\r\nI could never keep my hold,\nHe must hold me fast.\nFor my love is often cold,\nHe must hold me fast.\r\nI am precious in His sight,\nHe will hold me fast.\nThose He saves are His delight,\nHe will hold me fast.\r\nHe\'ll not let my soul be lost,\nChrist will hold me fast.\nBought by Him at such a cost,\nHe will hold me fast.', 'Fürcht\' ich, dass mein Glaube weicht,\nJesus hält mich fest;\nwenn Versuchung mich umschleicht,\nJesus hält mich fest!\r\nJa, Er hält mich fest,\nJesus hält mich fest;\ndenn mein Heiland hat mich lieb,\nd\'rum hält Er mich fest.\r\nIch kann nicht alleine geh\'n,\nJesus hält mich fest;\nkann vor Gott in nichts besteh\'n,\ndoch hält Er mich fest.\r\nWeil er teuer mich erwarb,\nd\'rum hält Er mich fest;\nweil am Kreuz Er für mich starb,\nhält Er treu mich fest.\r\nIch kann nicht verloren sein,\nJesus hält mich fest;\nbis ich geh zum Himmel ein,\nhält Er selbst mich fest.'),
(9, '0484', 'Fürchte dich nicht länger, sieh Ich bin mit dir  -  Fear not, I am with thee   (Nein, niemals allein)', '"Fear not, I am with thee", blessed golden ray,\nlike a star of glory, lighting up my way!\nThrough the clouds of midnight, this bright promise shone:\n"I will never leave thee, never will leave thee alone."\r\n[: No, never alone,\nno, never alone.\nHe promised never to leave me,\nnever to leave me alone. :]\r\nRoses fade around me, lilies bloom and die.\nEarthly sunbeams vanish, radiant still the sky!\nJesus, Henna-flower, blooming for His own.\nJesus, heaven\'s sunshine, never will leave me alone.\r\nSteps unseen before me, hidden dangers near.\nNearer still my Saviour, whispering, "Be of cheer".\nJoys, like birds of springtime, to my heart have flown,\nsinging all so sweetly, "He will not leave me alone."', 'Fürchte dich nicht länger, sieh, Ich bin mit dir!\nDas ist meine Leuchte auf dem Wege hier.\nDurch die Wolken funkelt der Verheißung Licht:\n"Siehe, Ich bin bei dir, und Ich verlasse dich nicht!"\r\n[: Nein, niemals allein!\nNein, niemals allein!\nSo hat der Herr mir verheißen,\nniemals lässt Er mich allein! :]\r\nLilien mögen welken,  Rosenduft verweh\'n,\nSonne sich verdunkeln, dennoch bleibt es steh\'n:\nJesus, meine Wonne, Er mein Sonnenschein,\nwird mich nie verlassen, Er lässt mich nimmer allein.\r\nIst der Pfad auch dunkel, droht manch Übel mir,\nhör ich Ihn doch sagen: "Kind ich bin bei dir!"\nDroben werd\' ich schauen Jesu Angesicht,\njubelnd Wird´s dann tönen: nein, Er verließ mich hier nicht!'),
(9, '0485', 'Fürchte dich nicht, was auch geschieht  -  Be not dismayed whate’er betide   (Gott sorgt für dich, Sein Kind,Freundlich und treu)', 'Be not dismayed whate’er betide,\nGod will take care of you.\nBeneath His wings of love abide,\nGod will take care of you.\r\nGod will take care of you,\nthrough every day, o’er all the way.\nHe will take care of you,\nGod will take care of you.\r\nThrough days of toil when heart doth fail,\nGod will take care of you.\nWhen dangers fierce your path assail,\nGod will take care of you.\r\nAll you may need He will provide,\nGod will take care of you.\nNothing you ask will be denied,\nGod will take care of you.\r\nNo matter what may be the test,\nGod will take care of you.\nLean, weary one, upon His breast,\nGod will take care of you.', 'Fürchte dich nicht, was auch geschieht,\nGott sorgt für dich, Sein Kind;\nSein liebend Auge auf dich sieht,\nGott sorgt für dich, Sein Kind.\r\nGott sorgt für dich, Sein Kind,\nFreundlich und treu;\njeden Tag neu sorgt Er für dich, Sein Kind,\nsorgt Er für dich, Sein Kind!\r\nWenn dir im Leid der Mut entsinkt,\nGott sorgt für dich, Sein Kind;\nWenn dich Gefahr und Not umringt,\nGott sorgt für dich, Sein Kind.\r\nWas du bedarfst, das gibt Er dir,\nGott sorgt für dich, Sein Kind;\nKomm nur im Glauben für und für,\nGott sorgt für dich, Sein Kind.\r\nOb auch die Prüfung lange währt,\nGott sorgt für dich, Sein Kind;\nBald nimmt Er dir, was dich beschwert,\nGott sorgt für dich, Sein Kind.'),
(9, '0486', 'Fürchte nichts kleine Herd\'  -  Fear not little Flock   (Glaube nur, glaube nur! Alles ist möglich drum glaube nur)', 'Fear not little flock, from the cross to the throne,\nfrom death into life He went for His own.\nAll power in earth, all power above,\nis given to Him for the flock of His love.\r\nOnly believe, only believe, all things are possible, only believe.\nOnly believe, only believe, all things are possible, only believe.\r\nFear not little flock, He goeth ahead.\nYour Shepherd selecteth the path you must tread.\nThe waters of Marah He\'ll sweeten for thee,\nHe drank all the bitter in Gethesmane.\r\nFear not little flock, whatever your lot.\nHe enters all rooms "The doors being shut."\nHe never forsakes, He never is gone.\nSo count on His presence in darkness and dawn.', 'Fürchte nichts, kleine Herd\', von dem Kreuze zum Thron,\nvon dem Tode zum Leben ging einst Gottes Sohn.\nAlle Macht in der Welt der Vater Ihm gab,\nfür die Schar Seiner Kinder, die innig er liebt.\r\nGlaube nur, glaube nur! Alles ist möglich d\'rum glaube nur!\nGlaube nur, glaube nur! Alles ist möglich d\'rum glaube nur!\r\nFürchte nichts kleine Herd\', Er geht ja voran.\nDein Hirte zeigt dir, wo dein Fuß gehen kann.\nDie Wasser von Mara macht süß Er, d\'rum geh.\nEr trank ja das Bitt\'re in Gethsemane.\r\nFürchte nichts, kleine Herd\' was immer dein Los,\nEr hilft dir aus Not, sie sein klein oder groß.\nEr wird dich nicht lassen, o gib nur recht acht,\nund dich nicht verlassen bei Tag und bei Nacht.'),
(9, '0487', 'Ganz für Jesus, ganz für Jesus   (Ganz für Jesus, ganz für Jesus)', NULL, 'Ganz für Jesus, ganz für Jesus!\nAlles sei dem Herrn gebracht.\nAll mein Denken, Tun und Treiben,\njede Stunde Tag und Nacht.\r\nGanz für Jesus, ganz für Jesus!\nJede Stunde, Tag und Nacht.\nGanz für Jesus, ganz für Jesus,\no, wie das uns selig macht!\r\nMöcht\' mit Herz und Hand ihm dienen,\nwandeln nur, wohin er geht.\nMeinem Heiland lasst mich folgen,\nwill Ihn preisen früh und spät.\r\nSeit ich Jesus einst gefunden,\nsteht er vor mir, einzig schön.\nIhn alleine sucht mein Auge,\nseit ich Ihn am Kreuz geseh\'n.\r\nO welch Wunder, mein Erlöser,\naller Himmel König Du.\nSchenkst mir Armem Deine Liebe,\ndeckest mich mit Flügeln zu!'),
(9, '0488', 'Gar süß ist die Kunde von Jesus  -  O sweet is the Story of Jesus   (O herrliche, herrliche Kunde)', 'O sweet is the story of Jesus,\nthe wonderful Saviour of men.\nWho suffered and died for the sinner,\nI\'ll tell it again and again!\r\nO wonderful, wonderful story,\nthe dearest that ever was told.\nI\'ll repeat it in glory,\nthe wonderful story,\nwhere I shall His beauty behold.\r\nHe came from the brightest of glory,\nHis blood as a ransom He gave.\nTo purchase eternal redemption,\nand, o He is mighty to save!\r\nHis mercy flows on like a river,\nHis love is unmeasured and free.\nHis grace is forever sufficient,\nit reaches and purifies me.', 'Gar süß ist die Kunde von Jesus,\ndem herrlichen Heiland der Welt.\nFür weit, weit verlorene Sünder\nhat Er sich zum Bürgen gestellt.\r\nO herrliche, herrliche Kunde,\ndie herrlichste, die ich vernahm.\nEinst mit himmlischen Zungen\nwird droben gesungen\ndie Kunde von Jesus, dem Lamm!\r\nEr kam aus den himmlischen Höhen,\nSein Blut gab Er freiwillig her,\num eine Erlösung zu finden!\nJa mächtig zu retten ist Er!\r\nEr hat die Versöhnung vollendet,\nein Gnadenstrom fließt durch die Zeit;\nich komme und nehme im Glauben\ndie Gnade, die Jesus mir beut.'),
(9, '0489', 'Gefunden ist der Hafen nun  -  My Soul at last a Rest hath found   (O ewger Felsen, öffne Dich)', 'My soul at last a rest hath found,\na rest that will not fail.\nA sure and certain anchorage ground\nin Christ within the vail.\r\nO Rock of Ages cleft for me,\nin Thee my soul securely hide.\nMy tower of strength, I fly to Thee,\nand safely there abide.\r\nI’ll hide me in this refuge strong,\nfrom every stormy blast.\nAnd sit and sing until the waves\nof wrath are over-past.\r\nYe comfortless and tempest-tossed,\nby sins and woes opprest.\nYe tempted, troubled, ruined, lost,\ncome find in Christ your rest.\r\nYe thirsty, from this smitten Rock,\nlife’s crystal waters spring.\nThere hide from every stormy shock,\nand rest, and drink, and sing.', 'Gefunden ist der Hafen nun,\nhier werf\' ich Anker aus,\nhier kann mein leckes Schifflein ruh\'n,\nhier bin ich recht zu Haus.\r\nO ew\'ger Felsen, öffne Dich,\nbei Dir ist Ruh\' im Sturm der Zeit.\nMein starker Hort, ach birg Du mich,\nfür Zeit und Ewigkeit.\r\nWenn draußen wild der Sturmwind weht,\nist\'s doch im Hafen still;\ndie Woge, die dort donnernd geht,\ntreibt hier ihr sanftes Spiel.\r\nIhr, die des Lebens Sturm gejagt,\ndie Sünd\' und Weh bedrängt,\nihr, die ihr hilflos ringt und klagt,\nzum Friedenshafen lenkt!\r\nGespalten ist ein Felsen hier,\nd\'raus Lebenswasser quillt,\nda ruht und trinkt und jauchzt auch ihr;\ndas Sehnen ist gestillt.'),
(9, '0490', 'Geh aus, verlass dein Vaterland   (O Seele, gehe doch noch heut)', NULL, 'Geh aus, verlass dein Vaterland\nund deines Vaters Haus!\nDein Herz sei Jesu zugewandt,\nnach Ihm nur schaue aus!\r\nO Seele, gehe doch noch heut\'\nzur engen Pforte ein,\ndu wirst für Zeit und Ewigkeit\ndann wohlgeborgen sein!\r\nGeh aus, verlass die Sündenstadt,\nverweil\' in Sodom nicht.\nAuch kehre nicht, wie Lots Weib tat,\nzurück dein Angesicht!\r\nGeh aus, verlass die schnöde Welt,\neh dich die Flut verschlingt.\nEs ist die Arche dir bestellt,\ndie Heil und Rettung bringt.\r\nGeh aus, verlass den breiten Pfad,\ner beut nur Elend dar;\nund bleib nicht in der Sünder Rat,\nnoch in der Spötter Schar.\r\nGeh aus, geh aus, lass alles steh\'n,\nwas dich nur hindern kann.\nGeh aus, um selig einzugeh\'n\ndereinst in Kanaan.'),
(9, '0491', 'Geh früh, dich zu erquicken, geh in der Jugend Zier', NULL, 'Geh früh\', dich zu erquicken,\ngeh in der Jugend Zier,\nund kaufe dich zu schmücken,\nder Wahrheit Perle, dir!\nJa, diesen Schatz vom Himmel\nhalt fest in Herz und Hand,\ndass er im Weltgetümmel\ndir nimmer werd\' entwandt!\r\nGeh hin, solang die Sonne\ndir scheinet klar und hell,\ngeh hin, in Freud und Wonne,\nes kommt die Nacht so schnell!\nGib alles andre gerne\nfür dieses eine her.\nWas helfen Ordenssterne,\nwas Weltlust, Gut und Ehr\'?\r\nGeh hin, eh írd\'sche Sorgen\ndir nah\'n mit schwerer Pein.\nVerschieb\' es nicht auf morgen,\nheut\' kauf die Wahrheit ein.\nGedenke deines Gottes\nin deiner Jugendzeit.\nTrotz Kreuzesschmach und Spottes,\nsei Ihm dein Herz geweiht!'),
(9, '0492', 'Geh und ruf es von den Bergen  -  Go and shout it from the Mountains   (Chorus)', 'Go and shout it from the mountains,\nshout it into every town!\nGo and shout it from the mountains,\nwhat Jesus did for you!', 'Geh und ruf es von den Bergen,\nruf es hinein in jede Stadt!\nGeh und ruf es von den Bergen,\nwas Jesus für dich tat!'),
(9, '0493', 'Geh, trockne die Tränen, sorg nicht wie die Welt  -  Go bury thy Sorrow, the World hath its share', 'Go bury thy sorrow, the world hath its share.\nGo bury it deeply, go hide it with care.\nGo think of it calmly when curtained by night.\nGo tell it to Jesus, and all will be right.\r\nGo tell it to Jesus, He knoweth thy grief.\nGo tell it to Jesus, He\'ll send thee relief.\nGo gather the sunshine, He sheds on the way.\nHe\'ll lighten thy burden, go, weary one, pray.\r\nHearts growing a weary with heavier woe,\nnow droop \'mid the darkness: Go comfort them, go!\nGo bury thy sorrows, let others be blest.\nGo give them the sunshine, tell Jesus the rest.', 'Geh\', trockne die Tränen, sorg\' nicht wie die Welt!\nSag Jesu dein Sehnen, Er gibt, was dir fehlt!\nWenn Nacht dich umhüllet, bleib ruhig, mein Herz!\nGlaub Jesus, der stillet dir jeglichen Schmerz!\r\nEr kennt deine Sorgen, o blicke auf Ihn!\nEin herrlicher Morgen wird bald dir erblüh\'n!\nSchon steiget die Sonne am Himmel dir auf;\nBet\', so wird voll Wonne sich lichten dein Lauf!\r\nWeißt du dann noch Seelen in ähnlichem Leid,\ngeh, um zu erzählen, was dich hat befreit.\nO bete mit ihnen, ruf an Jesu Blut,\nbis Hilfe erschienen und alles ist gut!'),
(9, '0494', 'Gehe nicht vorbei, o Heiland  -  Pass me not, oh gentle Saviour   (Heiland, Heiland, hör des Herzens Schrei)', 'Pass me not, o gentle Saviour,\nhear my humble cry.\nWhile on others Thou art calling,\ndo not pass me by.\r\nSaviour, Saviour,\nhear my humble cry.\nWhile on others Thou art calling,\ndo not pass me by.\r\nLet me at Thy throne of mercy,\nfind a sweet relief.\nKneeling there in deep contrition,\nhelp my unbelief.\r\nTrusting only in Thy merit,\nwould I seek Thy face.\nHeal my wounded, broken spirit,\nsave me by Thy grace.\r\nThou the spring of all my comfort,\nmore than life to me.\nWhom have I on earth beside Thee?\nWhom in heav\'n but Thee?', 'Gehe nicht vorbei, o Heiland,\nhör\' des Herzens Schrei,\nda Du andern Gnad\' erzeigest,\ngehe nicht vorbei!\r\nHeiland, Heiland,\nhör\' des Herzens Schrei,\nda Du andern Gnad\' erzeigest,\ngehe nicht vorbei!\r\nGib mir an dem Thron der Gnade,\nRuh\' von meinem Schmerz.\nSieh, hier knie\' ich tief in Buße,\ntröste doch mein Herz.\r\nNur zu Dir steht mein Verlangen,\nFels der Ewigkeit.\nBei Dir bin ich Armer sicher,\njetzt und allezeit.\r\nDu bist ja des Trostes Quelle,\nSündern bringst Du Heil.\nSei der Friede meines Herzens,\nwerd\' mein ganzes Teil!'),
(9, '0495', 'Geist Gottes sei willkommen - Holy Spirit Thou art welcome in this place', 'Holy Spirit, Thou art welcome in this place,\nHoly Spirit, Thou art welcome in this place.\nOmnipotent Father of mercy and grace.\nThou art welcome in this place.\r\nLord in Thy presence there\'s healing divine,\nno other power can save, Lord, but Thine.\nHoly Spirit Thou art welcome in this place,\nThou art welcome in this place.\r\nFill all the hungry, and empty within,\nrestore us, oh Father, revive us again.\nHoly Spirit, Thou art welcome in this place,\nThou art welcome in this place.', 'Geist Gottes sei willkommen hier bei uns\nGeist Gottes sei willkommen hier bei uns\nAllmächtiger Vater voll Gnade und Huld\nSei willkommen hier bei uns\r\n\r\n'),
(9, '0496', 'Geliebte, lasst uns lieben einander  -  Beloved, let us love one another', 'Beloved, let us love one another,\nfor love is of God,\nand everyone that loveth is born of God,\nand knoweth God.\nHe that loveth not, knoweth not God,\nfor God is love.\nBeloved, let us love one another.', 'Geliebte, lasst uns lieben einander;\ndenn Gott ist Lieb\',\nund jeder, der Gott liebt,\nist gebor\'n aus Gott\nund kennet Gott.\nAber ohne Lieb\' kennst du Gott nicht,\ndenn Gott ist Lieb\'.\nGeliebte, lasst uns lieben einander!'),
(9, '0497', 'Gemeinschaft in Dir meinem Zufluchtsort', 'Shut in with God in the secret place,\nthere in the Spirit beholding His face,\ngaining new power to run in the race,\nI love to be shut in with God.\r\n\r\n', 'Gemeinschaft in Dir, meinem Zufluchtsort,\nim neuen Namen, dem Bergungsort!\nFluten der Liebe, o salbe Dein Wort!\nO ich sehn\' mich nach Gemeinschaft mit Dir!\r\nGemeinschaft in Dir, ein geweihter Raum!\nIn Deinem Geiste Dein Angesicht schau\'n.\nDeiner Dynamik ohne Grenzen vertrau\'n.\nOh, ich sehn\' mich nach Gemeinschaft mit Dir!\r\nGemeinschaft in Dir, bitte, neig\' dich zu mir!\nÜbernatürlicher, sei mein Panier!\nEngel des Bundes, o nimm Du mich hier!\nO ich sehn\' mich nach Gemeinschaft mit Dir!'),
(9, '0498', 'Gesegnet sei das Band  -  Blest be the Tie that binds', 'Blest be the tie that binds\nour hearts in Christian love.\nThe fellowship of kindred minds\nis like to that above.\r\nBefore our Father\'s throne\nwe pour our ardent prayers.\nOur fears, our hopes, our aims are one.\nOur comforts and our cares.\r\nWe share our mutual woes,\nour mutual burdens bear.\nAnd often for each other flows\nthe sympathizing tear.\r\nWhen we asunder part,\nit gives us inward pain.\nBut we shall still be joined in heart,\nand hope to meet again.', 'Gesegnet sei das Band,\ndas uns im Herrn vereint;\ngeknüpft von Christi Liebeshand,\nbleibt\'s fest, bis Er erscheint.\r\nVor unsres Vaters Thron\nsteigt ernstlich unser Flehn,\nin Leid und Freud ein Herz, ein Geist;\nso klingt\'s dem Vater schön.\r\nWir tragen jede Last\nmit Schwergeprüften gern.\nDes Mitleids Tränen fließen\noft vereint vor unserm Herrn.\r\nUnd scheiden wir allhier,\nso gibt\'s uns tiefen Schmerz.\nDoch bleiben wir im Geist vereint\nund pilgern himmelwärts.'),
(9, '0499', 'Gestern durfte ich erfahrendeine Gnade Schritt für Schritt', NULL, 'Gestern durfte ich erfahren\nDeine Gnade Schritt für Schritt,\ngab es überall Gefahren,\nDu gingst mit, Du gingst mit.\r\nHeute werde ich verspüren\nDeine Gegenwart so nah,\ndenn ich weiß, Du wirst mich führen,\nDu bist da, Du bist da.\r\nMorgen willst Du mit mir gehen,\nwas auch immer kommen mag,\nDeine Hilfe werd\' ich sehen\njeden Tag, jeden Tag.\r\nEwig ziehst Du Deine treuen\nSegenshände nicht zurück.\nJa, ich darf mich jubelnd freuen,\ndas ist Glück, das ist Glück.'),
(9, '0500', 'Get right Church and let\'s go home   (2 Chorusse)', 'Get right church and let\'s go home,\nGet right church and let\'s go home,\nGet right church, get right church,\nGet right church and let\'s go home.\r\nI\'m going home on the mornin\' train,\nI\'m going home on the mornin\' train,\nI\'m going home, I\'m going home,\nI\'m going home on the mornin\' train.', NULL),
(9, '0501', 'Gib dich heute ganz gefangen   (... befreit, von der Sünde Tod und Leid)', NULL, 'Gib dich heute ganz gefangen\nin des lieben Heilands Hand.\nBleib nicht an der Sünde hangen,\ndie dich hält mit ihrem Band.\nJesus hat dich ganz befreit,\r\nvon der Sünde Tod und Leid.\nGlaube jetzt, Er hat\'s getan,\nund fang gleich zu danken an.\r\nHalb erlöst sein ist vom Übel,\ndas genügt der Seele nicht.\nVolles Heil lehrt unsre Bibel,\nund Gott hält, was Er verspricht.\nJesus hat auch dich befreit,\r\nFrag nicht: Wird es mir gelingen,\nfrei von Sünd einherzugehn?\nNicht dein Kämpfen, nicht dein Ringen,\nJesus selbst wird es versehn!\nJesus hat auch dich befreit,\r\nGanze Lösung, volle Scheidung\nvon dem, was nicht ist aus Gott,\ndas sei deines Glaubens Losung,\nund vorbei ist alle Not.\nJesus hat auch dich befreit,\r\nHalleluja, Dir, mein Heiland!\nNimm mich hin, ich bin ganz Dein!\nNicht mehr halb nur, so wie weiland,\nganz erlöst! Ich geh drauf ein.\nJesus hat mich ganz befreit,\r\nvon der Sünde Tod und Leid.\nJa, ich glaub, Er hat\'s getan!\nHalleluja Ihm fortan!'),
(9, '0502', 'Gib doch das Bestes dem Meister  -  Give of your Best to the Master', 'Give of your best to the Master,\ngive of the strength of your youth.\nThrow your soul’s fresh, glowing ardor,\ninto the battle for truth.\nJesus has set the example,\ndauntless was He, young and brave.\nGive Him your loyal devotion,\ngive Him the best that you have.\r\nGive of your best to the Master,\ngive Him first place in your heart.\nGive Him first place in your service,\nconsecrate every part.\nGive, and to you will be given,\nGod His beloved Son gave.\nGratefully seeking to serve Him,\ngive Him the best that you have.\r\nGive of your best to the Master,\nnaught else is worthy His love.\nHe gave Himself for your ransom,\ngave up His glory above.\nLaid down His life without murmur,\nyou from sin’s ruin to save.\nGive Him your heart’s adoration,\ngive Him the best that you have.', 'Gib doch das Beste dem Meister,\ngib ihm der Jugendkraft Glut.\nEile, dich völlig zu weihen,\nihm, der so viel für dich tut.\nWie einst dein Herr und dein Meister\nwirke für Gott ohne Rast.\nGib ihm in heiliger Liebe alles,\nwas immer du hast!\r\nGib doch das Beste dem Meister,\nstell ihm in allem voran.\nRäum\' ihm den Thron ein im Herzen,\nlohn\'s ihm, was er dir getan.\nGib, und es wird dir gegeben,\ngib es mit freudigem Sinn.\nJesus gab für dich sein Leben:\ngib nun dein alles ihm hin.\r\nGib doch das Beste dem Meister,\nhab doch von Herzen ihn lieb.\nGab er sich einst doch zum Opfer,\nweil seine Liebe ihn trieb.\nGab sich in heil\'gem Gehorsam.\nRetten, das war ja sein Plan.\nGib daher Jesus das Beste;\ndenk doch was er einst getan!'),
(9, '0503', 'Gib mir dein Herz, ruft der Vater herab  -  Give Me thy Heart, says the Father above   (Gib Mir dein Herz, gib Mir dein Herz)', '"Give Me thy heart," says the Father above,\nno gift so precious to Him as our love.\nSoftly He whispers, wherever thou art,\n"Gratefully trust Me, and give Me thy heart."\r\n"Give Me thy heart, give Me thy heart,"\nhear the soft whisper, wherever thou art.\nFrom this dark world He would draw thee apart,\nSpeaking so tenderly, "Give Me thy heart."\r\n"Give Me thy heart,” says the Saviour of men,\ncalling in mercy again and again.\n"Turn now from sin, and from evil depart,\nhave I not died for thee? Give Me thy heart."\r\n"Give Me thy heart," says the Spirit divine,\n"All that thou hast, to My keeping resign.\nGrace more abounding is Mine to impart,\nmake full surrender and give Me thy heart."', '"Gib mir dein Herz", ruft der Vater herab.\nKöstlich\'re Gabe Ihm niemand je gab.\nLeise nun flüstert Er hier allerwärts:\n"Dankbar vertrau Mir und gib Mir dein Herz."\r\n"Gib Mir dein Herz, gib Mir dein Herz",\nhöre es flüstern, ringsum, allerwärts;\naus dunklem Elend Er zieht himmelwärts,\nrufet so inniglich: "Gib Mir dein Herz."\r\n"Gib mir dein Herz", ist des Heilandes Wort,\nhört, wie so gnädig Er sagt\'s immerfort:\n"Lass doch die Sünde, sei nicht hart wie Erz."\nIhm, der am Kreuze starb, gib Ihm dein Herz.\r\n"Gib mir dein Herz", sagt der Heilige Geist,\n"Lass dich nicht fesseln, was irdisch noch heißt;\nGnade befreit dich von Sünde und Schmerz,\nschenk\' Mir dein Alles, o, gib Mir dein Herz."'),
(9, '0504', 'Gib mir ein Herz zu Deinem Preis   (Gib mir ein Herz zu Deinem Preis)', NULL, 'Gib mir ein Herz zu Deinem Preis,\nein Herz, befreit von Sünd\',\nein Herz, befreit von Sünd\',\ndass ich ganz sicher bin und weiß,\nich bin ein Gotteskind.\r\nGib mir ein Herz wie Deins,\ngib mir ein Herz wie Deins,\nvoll der heiligsten Triebe,\nvoller Glauben und Liebe,\ngib mir ein Herz wie Deins!\r\nEin wahres und ein treues Herz,\ndas glaubet, hofft und liebt,\ndas glaubet, hofft und liebt,\ndas Mitleid fühlt mit andrer Schmerz,\nim Dienen gern sich übt!\r\nEin Herz, erneuert ganz und gar\nin Sinn und Tat und Wort,\nin Sinn und Tat und Wort,\nein Herz wie Deins, o Jesus, war,\nDu, unser Heil und Hort!\r\nGib mir ein solches Herz wie Deins,\nich bitt\'s zu Deiner Ehr\',\nich bitt\'s zu Deiner Ehr\',\ndas immer weiß mit Dir sich eins,\nnichts wünsch\' ich weiter mehr!'),
(9, '0505', 'Gib mir Öl in mein Lamp hilf mir leuchten  -  Give me Oil in my Lamp keep me burning   (2 Chorusse)', 'Give me oil in my lamp keep me burning,\ngive me oil in my lamp I pray.\nGive me oil in my lamp keep me burning,\nkeep me burning \'til the break of day.\r\nSing Hosannah! Sing Hosannah!\nSing Hosannah to the King of Kings!\nSing Hosannah! Sing Hosannah!\nSing Hosannah to the King!', 'Gib mir Öl in mein\' Lamp\', hilf mir leuchten,\ngib mir Öl in mein\' Lamp\', ich fleh\'.\nGib mir Öl in mein\' Lamp\', hilf mir leuchten,\nhilf mir leuchten, bis der Tag anbricht.\r\nSing Hosianna, sing Hosianna,\nsing Hosianna, unser\'m König, unser\'m Herrn.\nSing Hosianna, sing Hosianna,\nsing Hosianna unser\'m Herrn.'),
(9, '0506', 'Give me a double Portion   (Chorus)', 'Give me a double portion, that\'s what I need!\nMore of the spirit that\'s living in me.\nI\'m gonna keep asking until I receive,\na double portion, that\'s what I need!', NULL),
(9, '0507', 'Glaube einfach jeden Tag  -  Simply trusting every Day   (Glauben will ich, Herr, mein Gott)', 'Simply trusting every day,\ntrusting through a stormy way.\nEven when my faith is small,\ntrusting Jesus, that is all.\r\nTrusting as the moments fly,\ntrusting as the days go by.\nTrusting Him whate’er befall,\ntrusting Jesus, that is all.\r\nBrightly doth His Spirit shine\ninto this poor heart of mine.\nWhile He leads I cannot fall,\ntrusting Jesus, that is all.\r\nSinging if my way is clear,\npraying if the path be drear.\nIf in danger for Him call.\ntrusting Jesus, that is all.\r\nTrusting Him while life shall last,\ntrusting Him till earth be past.\nTill within the jasper wall,\ntrusting Jesus, that is all.', 'Glaube einfach jeden Tag,\nglaube, ob\'s auch stürmen mag.\nGlaub\' erst recht auf dunkler Spur,\nJesus spricht ja: "Glaube nur!"\r\nGlauben will ich, Herr, mein Gott,\nglauben fest bis in den Tod,\nbis zum Schau\'n auf Zions Flur.\nJesus spricht ja: "Glaube nur!"\r\nO, wie strahlt Sein Geist so rein\nin mein armes Herz hinein!\nD\'rum vertrau ich Seiner Kur,\nJesus spricht ja: "Glaube nur!"\r\nFroh wall ich im Sonnenstrahl,\nbetend in dem Schattental,\nmich schreckt keine Kreatur,\nJesus spricht ja: "Glaube nur!"\r\nIch glaub jeden Augenblick,\nglaub\' in Nöten wie im Glück,\ngeht\'s auch wider die Natur,\nJesus spricht ja: "Glaube nur!"'),
(9, '0508', 'Glaube nur  -  Only believe   (3 Chorusse)', 'Only believe, only believe,\nall things are possible, only believe.\nOnly believe, only believe,\nall things are possible, only believe.\r\nJesus is here, Jesus is here,\nall things are possible, Jesus is here.\nJesus is here, Jesus is here,\nall things are possible, Jesus is here\r\nLord, I believe, Lord, I believe,\nall things are possible, Lord, I believe.\nLord, I believe, Lord, I believe,\nall things are possible, Lord, I believe.', 'Glaube nur, glaube nur!\nAlles ist möglich, d\'rum glaube nur!\nGlaube nur, glaube nur!\nAlles ist möglich, d\'rum glaube nur!\r\nJesus ist hier, Jesus ist hier.\nAlles ist möglich, weil Jesus ist hier.\nJesus ist hier, Jesus ist hier.\nAlles ist möglich, weil Jesus ist hier.\r\nJetzt glaube ich, jetzt glaube ich.\nAlles ist möglich, denn jetzt glaube ich.\nJetzt glaube ich, jetzt glaube ich.\nAlles ist möglich, denn jetzt glaube ich.'),
(9, '0509', 'Glaube, glaube und vertraue   (Chorus)', NULL, 'Glaube, glaube und vertraue,\nglaube wider allen Schein!\nGlaube, glaube und vertraue,\nglaube und der Sieg ist dein!'),
(9, '0510', 'Glaubet dem Herrn  -  Have Faith in God   (Chorus)', 'Have faith in God,\nhave faith in God,\nhave faith in God for the answer,\nhave faith in God!', 'Glaubet dem Herrn,\nglaubet dem Herrn,\nglaubet dem Herrn für die Antwort,\noh, glaubet dem HErrn!'),
(9, '0511', 'Gleich wie die schimmernden Sterne verblassen  -  Fading away like the Stars of the Morning   (Eines bestehet, nimmer vergehet)', 'Fading away like the stars of the morning,\nlosing their light in the glorious sun.\nThus would we pass from the earth and its toiling,\nonly remembered by what we have done.\r\nOnly remembered, only remembered,\nonly remembered by what we have done.\nThus would we pass from the earth and its toiling,\nonly remembered by what we have done.\r\nShall we be miss\'d though by others succeeded,\nreaping the fields we in springtime have sown?\nNo, for the sowers may pass from their labors,\nonly remembered by what they have done.\r\nOnly the truth that in life we have spoken,\nonly the seed that on earth we have sown.\nThese shall pass onward when we are forgotten,\nfruits of the harvest and what we have done.\r\nOh, when the Saviour shall make up His jewels,\nwhen the bright crowns of rejoicing are won.\nThen shall His weary and faithful disciples,\nall be remembered by what they have done.', 'Gleich wie die schimmernden Sterne verblassen,\nstrahlet der leuchtende Morgen sie an,\nwirst du die Welt und ihr Tagwerk verlassen.\nEines besteht: was du liebend getan!\r\nEines bestehet, nimmer vergehet,\nnimmer vergehet, was du liebend getan.\nWirst du die Welt und ihr Tagwerk verlassen,\nnimmer vergeht, was du liebend getan.\r\nWo du im Lenze gepflanzt und gesäet,\nwirst du gewisslich die Ernte empfah\'n.\nSchnell sind des Sämannes Spuren verwehet,\neines besteht: was du liebend getan.\r\nHast du für Gott und die Wahrheit gestrebet,\nwacker gekämpft wider Sünde und Wahn,\nwirst du vergessen, doch bleibet und lebet,\nreifet zur Frucht, was du liebend getan.\r\nHimmlische Gaben - wer mag sie ermessen?\nwerden die Treuen vom König empfah\'n.\nKeinem der Seinen wird Jesus vergessen,\nwas er im Leben hat liebend getan.'),
(9, '0512', 'Glory Hallelujah, I shall not be moved   (I shall not be, I shall not be moved)', 'Glory Hallelujah, I shall not be moved.\nAnchored in Jehovah, I shall not be moved.\nJust like a tree that\'s planted by the waters,\nI shall not be moved.\r\nI shall not be, I shall not be moved,\nI shall not be, I shall not be moved,\njust like a tree that\'s planted by the waters,\nI shall not be moved.\r\nIn His love abiding, I shall not be moved.\nAnd in Him confiding, I shall not be moved.\nJust like a tree that\'s planted by the waters,\nI shall not be moved.\r\nThough all hell assail me, I shall not be moved.\nJesus will not fail me, I shall not be moved.\nJust like a tree that\'s planted by the water,\nI shall not be moved.\r\nThough the tempest rages, I shall not be moved.\nOn the Rock of Ages, I shall not be moved.\nJust like a tree that\'s planted by the waters,\nI shall not be moved.', NULL),
(9, '0513', 'Glory, glory, Halleluja, seit ich frei von Lasten bin  -  Glory, glory, Hallelujah, since I laid my Burdens down   (2 Chorusse)', 'Glory, glory, hallelujah,\nsince I laid my burdens down.\nGlory, glory, hallelujah,\nsince I laid my burdens down.\r\nI feel so much better,\nsince I laid my burdens down.\nYes I feel so much better,\nsince I laid my burdens down.', 'Glory, glory, Halleluja,\nseit ich frei von Lasten bin!\nGlory, glory, Halleluja,\nseit ich frei von Lasten bin!\r\nBin so glücklich, ja so glücklich,\nseit ich frei von Lasten bin.\nBin so glücklich, ja so glücklich,\nseit ich frei von Lasten bin!'),
(9, '0514', 'Glückselig der Mann   (Psalm 1, 1-3)', NULL, 'Glückselig der Mann,\nder nicht wandelt im Rate der Gottlosen,\nder nicht geht auf dem Wege der Sünder\nund der nicht sitzt im Kreis der Spötter.\nAber am Worte des Herrn\nsein Wohlgefallen hat\nund der darüber nachdenkt\nbei Tag und Nacht.\r\nUnd er ist wie ein Baum\ngepflanzt an Wasserströmen,\nder seine Frucht bringt\nzu seiner Zeit\nund dessen Laub niemals verwelkt.\nAlles gelingt ihm.'),
(9, '0515', 'Gnade allein', NULL, 'Gar nichts, was ich hab\'\nNichts was ich selbst tat\nKein Verdienst, kein Geld\nWär\' genug\nDenn keine Fähigkeit\nBringt mich dort hinein\nNichts auf dieser Welt\nWär\' genug\nWär\' genug\r\nWenn wir dann vor den Toren stehen\nUnd die Engel hören\n"Kommt und tretet ein!"\nWerden wir noch viel mehr verstehen\nDass dafür nichts genügt\nAußer Gnade allein\r\nFür den Eintritt dort\nBraucht es nur ein Wort\nGar nichts andres sonst\nWär genug\nWär genug\nJesus ganz allein\nHat den Preis bezahlt\nDankbar will ich sein\nEwiglich\r\nJesus ganz allein\nHat den Preis bezahlt\nDankbar will ich sein\nEwiglich\nTraue nur auf Ihn\nAuch dich trägt Er hindurch\nSei mit Ihm vereint\nEwiglich\nEwiglich'),
(9, '0516', 'Gnade hat mich befreit   (Chorus)', NULL, 'Gnade hat mich befreit,\nGottes Gnade hat mich erneut.\nIch war gebunden meine Seele in Pein;\naber Gnade hat mich befreit.'),
(9, '0517', 'Gnade muss es sein, Gnade ganz allein', NULL, 'Gnade muss es sein,\nGnade ganz allein!\nAlles andre geht in Stücke,\nist nur eine schlechte Krücke,\nGnade hält allein,\nGnade muss es sein.\r\nAller eigne Wert\nnur den Hochmut nährt.\nAlles, was ich selbst erworben,\nhat die Sünde ganz verdorben.\nGnade muss es sein,\nGnade ganz allein.\r\nWenn zu herb der Schmerz,\nund schier bricht das Herz,\nwenn im Tal es düster dunkelt,\nschau ich auf; trotz allem funkelt\nmir der Gnade Schein;\nGnade muss es sein.\r\nAlso Gnad allein,\nGnade muss es sein,\nGnad zum Bleiben, Gnad zum Gehen,\nGnad, getrost beim Herrn zu stehen,\nnichts als Gnad allein.\nGnade muss es sein.'),
(9, '0518', 'Gnade schrieb mein Leben neu  -  Mercy rewrote my life   (Chorus)', 'Mercy rewrote my life,\nGod`s mercy rewrote my life.\nI should have fallen, my soul cast down,\nbut mercy rewrote my life.', 'Gnade, schrieb mein Leben neu,\nGottes Gnade, schrieb mein Leben neu.\nIch wäre gefallen, meine Seele verlor\'n,\ndoch Gnade schrieb mein Leben neu.'),
(9, '0519', 'Gnade so herrlich und wunderbar  -  Marvellous Grace of our loving God   (Gnade, Gnade, anstatt Gericht Jesu Lieb und Huld)', 'Marvellous grace of our loving God,\ngrace that exceeds our sin and our guilt.\nYonder on Calvary\'s mount outpoured,\nthere where the blood of the lamb was split\r\nGrace, grace, God\'s grace\ngrace that will pardon and cleans within.\nGrace, grace, God\'s grace,\nGrace that is greater than all our sin.\r\nSin and dispair like the sea wavens cold,\nthreaten the soul with infinite loss.\nGrace that is greater, yes, grace untold,\npoints to the refuge, the mighty cross.\r\nDark is the stain that we cannot hide,\nwhat can avail to wash it away?\nLook, there is flowing a crimson tide,\nwhiter than snow you may be tonight.\r\nMarvellous, infinite, matchless grace,\nfreely bestored on all who believe.\nYou that are longing to see his face,\nwill you this moment His grace receive?', 'Gnade so herrlich und wunderbar,\nbietet sich jedem auf Golgatha dar.\nHerrliche Gnad\' ist bereit für dich,\nd\'rum nimm sie an, dann wird alles gut.\r\nGnade, Gnade\nanstatt Gericht Jesu Lieb\' und Huld.\nGnade, Gnade,\nGnade viel größer als meine Schuld.\r\nLeidest als Sünder du große Pein,\nwillst du nicht ewig verloren sein?\nHerrliche Gnad\' ist bereit für dich.\nSuch\' diese Zuflucht und zögre nicht.\r\nKomm eilend vor Jesu Angesicht,\nEr macht dich frei und alles wird Licht.\nHerrliche Gnad\' ist bereit für dich\nund Seine Gnade heilt jedes Weh\'.\r\nGnade so herrlich und  wunderbar,\nreichlich geschenket, Halleluja!\nHerrliche Gnade, welch großer Lohn,\nbringt uns schon bald vor den Königsthron.'),
(9, '0520', 'Go tell it on the Mountain, over the hills and everywhere', 'Go tell it on the mountain,\nover the hills and everywhere.\nGo tell it on the mountain,\nour Jesus Christ is born.\r\nThe angels were rejoicing,\nthe shepherds went around:\n"Our God does signs and wonders,\nMessiah we have found!"\r\nMy God has made me able,\nHe gave us Light to see,\nHe once was in a stable,\nbut now in you and me!', NULL),
(9, '0521', 'God is moving by His Spirit  -  Gott bewegt sich durch seinen Geist   (Chorus)', 'God is moving by His Spirit\nmoving through all the earth.\nSigns and wonders when God moveth,\nmove, o Lord, in me.', 'Gott bewegt sich durch seinen Geist\nund bewegt sich über die ganze Erde.\nZeichen und Wunder, wenn Gott sich bewegt,\nbewege dich, o Herr, in mir.'),
(9, '0522', 'God is not a Man that He should lie  -  Gott ist nicht ein Mensch, dass Er lüge   (4. Mose 23, Vers 19+20)', 'God is not a man that He should lie,\nneither the son of man\nthat He should repent.\nHath He said, and shall He not do it?\nOr hath He spoken,\nand shall He not make it good?\r\nBehold I have received\nCommandment to bless.\nAnd He hath blessed,\nand I cannot reverse it.\nFor God is not a man, that He should lie,\nneither the son of man\nthat He should repent.', 'Gott ist nicht ein Mensch, dass Er lüge,\nnoch ein Menschenkind dass Ihn etwas gereue.\nHat Er gesprochen und wird Er\'s nicht tun?\nOder hat Er geredet, und Er wird es nicht halten?\r\nSiehe, zu segnen bin ich hergebracht,\nEr hat gesegnet und ich kann es nicht wenden.\nDenn Gott ist nicht ein Mensch, dass Er lüge,\nnoch ein Menschenkind dass Ihn etwas gereue.'),
(9, '0523', 'God will work it out', 'Before I knew my name,  before I drew a breath\nHe was making ways for me\nNow and everyday,  in each and every step\nHe is making ways for me\nWhen my heart is full of doubt\nFeels like faith is running out\nI\'ve come too far to turn around\nI know\r\nGod will work it out\nGod will work it out\nOne thing I know\nOne thing I\'ve found\nGod will work it out\r\nPushing past the fear, fighting to relief\nHe is making ways for me\nAnd He won\'t let me down, never ever leave\nHe\'s still making ways for me\nWhen my heart is full of doubt\nIt feels like faith is running out\nI\'ve come too far to turn back \'round\nI know\r\nBe still my soul\nBe still and know\nLean in, take hold\nIn God alone\nBe still my soul\nBe still and know\nLean in, take hold\r\nHe\'s working right now\nHe\'s working right now\nHe\'s working right now\nHe\'s working right now\n...\nI believe His work\r\nOne thing I know\nOne thing I\'ve found\nGod is working now', NULL),
(9, '0524', 'God\'s abiding Peace is in my Soul today   (It is mine, mine, blessed be His Name)', 'God’s abiding peace is in my soul today,\nyes, I feel it now, yes, I feel it now.\nHe has taken all my doubts and fears away,\nthough I cannot tell you how.\r\nIt is mine, mine, blessed be His Name!\nHe has given peace, perfect peace to me.\nIt is mine, mine, blessed be His Name!\nMine for all eternity!\r\nHe has wrought in me a sweet and perfect rest,\nin my raptured heart I can feel it now.\nHe each passing moment keeps me saved and blest,\nfloods with light my heart and brow.\r\nHe has given me a never failing joy,\noh, I have it now! oh, I have it now!\nTo His praise I will my ransomed pow’rs employ,\nand renew my grateful vow.\r\nOh, the love of God is comforting my soul,\nfor His love is mine, yes, His love is mine!\nWaves of joy and gladness o’er my spirit roll,\nthrilling me with life divine.', NULL),
(9, '0525', 'God\'s rich in mercy, God\'s rich in mercy. Sending His Son, we were undone', 'God\'s rich in mercy, God\'s rich in mercy.\nSending His Son, we were undone,\nGod\'s rich in mercy. God\'s rich in grace,\nGod\'s rich in love,\nsent us the best from heaven above.\nSaying to all the world today:\n"God\'s rich in mercy, God\'s rich in mercy."', NULL),
(9, '0526', 'Going Home', 'I\'m on a heavenly journey,\nbut I\'m not alone,\nthere are many here with me,\nand we\'re going Home.\nAnd though this world\'s gone and broken,\nGod\'s Word has been spoken,\nand He makes ev\'rything right\nfor a heavenly flight!\r\nGoing Home,\nGoing Home,\nGoing Home,\nGoing Home,\neach daughter, each son\nwill not be alone,\nfor we\'re going Home!\r\nWe are the last generation,\nbut that\'s not the end,\nthere\'ll come a great Revelation\nof Jesus, our Friend,\nfor the Heavens will open\nto those who are hoping,\nthat Jesus will come\nto take His bride Home!', NULL),
(9, '0527', 'Goodbye World, I stay no longer with you', 'Goodbye world,\nI stay no longer with you,\nGoodbye pleasures of sin,\nI stay no longer with you.\nI made up my mind to go God\'s way\nthe rest of my life.\nI made up my mind to go God\'s way\nthe rest of my life.', 'Lebe wohl, Welt, ich bleibe nicht länger bei dir\nLebt wohl, Vergnügen der Sünde, ich bleibe nicht länger bei euch\nIch habe entschieden, Gottes Weg zu gehen\nDen Rest meines Lebens'),
(9, '0528', 'Gott bahnt dir den Weg  -  God will make a Way', 'God will make a way, where there seems to be no way.\nHe works in ways we cannot see, He will make a way for me.\nHe will be my guide, hold me closely to his side.\nWith love & strength, for each new day, He will make a way.\nHe will make a way. (2x)\r\nBy a roadway in the wilderness He\'ll lead me.\nRivers in the desert will I see.\nHeaven & earth will fade,\nbut his word will still remain\nand He will do something new today.\r\nWith love and strength for each new day\nHe will make a way,\nHe will make a way.', 'Gott bahnt dir den Weg, wo du keinen Weg mehr siehst,\nauch wenn es uns verborgen bleibt, Jesus führt uns allezeit.\nEr wird mein Führer sein, hält mich nah\' an Seiner Seit\',\nmit Lieb\' und Kraft für jeden Tag, bahnt Er mir den Weg.\nBahnt Er mir den Weg. (2x)\r\nAuf Wegen der Wildniss wird Er mich leiten,\nFlüsse werde ich dort dann seh\'n.\nHimmel und Erd\' vergeh\'n,\naber sein Wort bleibt doch besteh\'n,\nund Er wird tun, neue Dinge, heut\'.\r\nMit Lieb\' und Kraft für jeden Tag,\nbahnt Er mir den Weg,\nbahnt Er mir den Weg.'),
(9, '0529', 'Gott bewegt sich, Gott bewegt sich  -   God is moving, God is moving   (Chorus)', 'God is moving, God is moving,\nis moving all over the earth.\nSigns and wonders, where God\nis moving, moving all over the earth.', 'Gott bewegt sich, Gott bewegt sich,\nbewegt sich weit über die Welt.\nZeichen und Wunder, wo Gottes Bewegung;\nbewegt sich weit über  die Welt.'),
(9, '0530', 'Gott hat die Fülle, was immer dich quält   (Gott hat die Fülle und was dein Begehr)', NULL, 'Gott hat die Fülle, was immer dich quält,\ngeh nur und klag Ihm dein Leid;\nbete ohn\' Unterlass, sag, was dir fehlt,\nEr hält dir Hilfe bereit.\r\nGott hat die Fülle und was dein Begehr\',\nkomm nur mit fröhlichem Mut;\nGott hat die Fülle, o sorg\' dich nicht mehr,\nkomm nur, und alles ist gut.\r\nGott hat die Fülle, o flieh\' an Sein Herz,\nkomm nur, ob früh oder spät;\ntrau den Verheißungen, sag Ihm den Schmerz,\nGott erhört sicher Gebet.\r\nGott hat die Fülle, Er rüstet mit Kraft,\nmacht dir das Leben Beschwer\',\nWeisheit und Gnade der Herr in dir schafft,\nkomm nur und zweifle nicht mehr.\r\nGott hat die Fülle, ob mühsam der Pfad,\nhalte ein wenig nur aus.\nGott führt die Seinen mit ewiger Gnad\',\nund bringt dich sicher nach Haus.'),
(9, '0531', 'Gott hat immer einen Weg', NULL, 'Manchmal kannst du nicht mehr weitergehen,\nmanchmal kannst du keinen Ausweg sehen,\ndoch da ist dein Gott, Er kennt deine Not,\nwie Er hilft, das wirst du bald verstehen!\r\nGott hat immer einen Weg,\nauch wenn du ihn nicht siehst,\ndann liegt das nur daran,\ndass du ein Mensch bist!\nGott hat immer einen Weg,\nEr öffnet jede Tür,\nEr bahnt den Weg vor dir,\ndamit du darauf gehst!\r\nGott kennt deine Nöte und dein Sehnen,\nund Er kennt auch alle deine Tränen,\nbleib\' Ihm einfach treu, Er kommt bald herbei,\nwird dich sicher in die Freiheit führen!\r\nAuf Ihn hoffen ist niemals vergebens,\ndenn Er ist der König deines Lebens,\nhat schon oft mit Macht Hilfe dir gebracht,\nwird es immer wieder für dich tun!'),
(9, '0532', 'Gott hat uns verheißen: "Am Abend wird es Licht sein!"   (Er wird alles wiedererstatten, was uns ging verloren)', NULL, 'Gott hat uns verheißen: "Am Abend wird es Licht sein!"\nDieses Licht, es scheinet für Seine kleine Braut.\nUnd wir werden sehen heut\' unsere Verheißung\nund Ihm dafür danken, dass sie sich erfüllt.\r\nEr wird alles wiedererstatten, was uns ging verloren,\nwird Er uns wieder schenken, die Verheißung hat Er uns gegeben.\nEr gibt auch den Glauben und es wird gescheh\'n.\r\nGott hat mir verheißen: "Ich will dir wieder geben!"\nAlles, was verloren, hat Er gegeben neu.\nAuch wir Er uns führen hinein in Seine Ruhe,\nund wir dürfen heißen Kinder uns\'res Herr.\r\nEr wird sich vermählen mit Seiner Braut auf Erden,\nbeide werden eins sein, auch ich gehör\' dazu.\nBald wird Er erscheinen in großer Kraft und Ehre,\nwir werden verwandelt, ewig bei Ihm sein.'),
(9, '0533', 'Gott ist die Liebe, lässt mich erlösen  -  God loves me dearly, grants me Salvation   (Drum sag ich noch einmal: Gott ist die Liebe)', 'God loves me dearly,\ngrants me salvation,\nGod loves me dearly,\nHe loves even me.\r\nTherefore I\'ll say again:\nGod loves me dearly,\nGod loves me dearly,\nHe loves even me.\r\nI was in slav\'ry,\nsin, death, and darkness;\nGod\'s love was working\nto make me free.\r\n\r\nHe sent forth Jesus,\nmy dear Redeemer,\nHe sent forth Jesus\nand set me free.\r\n\r\n\r\nI shall inherit\nEternal Pleasure,\nthrough Christ inherit\nEternal Rest.\r\nNow I will praise You,\nO love Eternal;\nnow I will praise You\nall my life long.', 'Gott ist die Liebe,\nlässt mich erlösen;\nGott ist die Liebe,\ner liebt auch mich.\r\nD\'rum sag ich noch einmal:\nGott ist die Liebe,\nGott ist die Liebe,\nEr liebt auch mich.\r\nIch lag in Banden\nder schnöden Sünde,\nich lag in Banden\nund konnt\' nicht los.\r\nIch lag im Tode,\ndes Teufels Schrecken;\nIch lag im Tode,\nder Sünden Sold.\r\nEr sandte Jesum,\nden treuen Heiland;\nEr sandte Jesum\nund macht mich los.\r\nDu heilst, o Liebe,\nall meinen Jammer;\nDu stillst, o Liebe,\nmein tiefstes Weh!\r\nDu füllst mit Freuden\ndie matte Seele;\nDu füllst mit Frieden\nmein armes Herz.\r\nDu lässt mich erben\ndie ew\'ge Freude,\ndu lässt mich erben\ndie ew\'ge Ruh!\r\nDich will ich preisen,\nDu ewge Liebe,\nDich will ich loben,\nsolang ich bin!'),
(9, '0534', 'Gott ist gegenwärtig! Lasset uns anbeten', NULL, 'Gott ist gegenwärtig!\nLasset uns anbeten\nund in Ehrfurcht vor Ihn treten!\nGott ist in der Mitte!\nAlles in uns schweige\nund sich innigst vor Ihm beuge!\nWer Ihn kennt, wer Ihn nennt:\nSchlag die Augen nieder,\nkommt, ergebt euch wieder!\r\nGott ist gegenwärtig,\ndem die Cherubinen\nTag und Nacht gebücket dienen.\n"Heilig, heilig!" singen\nalle Engelchöre,\ngeben sie dem Herrn die Ehre.\nHerr, vernimm unsre Stimm,\nda auch wir Geringen\nunsre Opfer bringen!\r\nWir entsagen willig\nallen Eitelkeiten,\naller Erdenlust und Freuden;\nda liegt unser Wille, Seele,\nLeib und Leben\nDir zum Eigentum ergeben!\nDu allein sollst es sein,\nunser Gott und Herre;\nDir gebührt die Ehre.\r\nDu durchdringest alles;\nlass Dein schönstes Lichte,\nHerr, berühren mein Gesichte!\nWie die zarten Blumen\nwillig sich entfalten\nund der Sonne stille halten,\ndass ich so still und froh\nDeine Strahlen fasse\nund Dich wirken lasse!\r\nMache mich einfältig,\ninnig abgeschieden,\nsanft, und gib mir stillen Frieden,\nmach mich reines Herzens,\ndass ich Deine Klarheit\nschauen kann in Geist und Wahrheit,\ndass mein Herz überwärts\nwie ein Adler schwebe\nund in Dir nur lebe!\r\nHerr, komm in mir wohnen,\ndass mein Geist auf Erden\nDir ein Heiligtum mög werden!\nKomm, Du nahes Wesen,\nDich in mir verkläre,\ndass ich Dich stets lieb und ehre;\nwo ich geh, sitz und steh,\nlass mich Dich erblicken\nund vor Dir mich bücken!'),
(9, '0535', 'Gott ist gut allezeit  -  God is good all the Time', 'God is good all the time,\nHe put a song of praise in this heart of mine.\nGod is good all the time,\nthrough the darkest night, His light will shine.\nGod is good, God is good all the time!\r\nIf you\'re walking through the valley\nand there are shadows all around,\ndo not fear, He will guide you.\nHe will keep you safe and sound,\nHe has promised to never leave you,\nor forsake you, and His word is true.', 'Gott ist gut allezeit,\nich singe Ihm ein Lied voller Dankbarkeit.\nGott ist gut allezeit,\nund Sein Licht vertreibt meine Dunkelheit.\nGott ist gut, Gott ist gut allezeit!\r\nWenn du einmal durch ein Tal gehst\nund es sind Schatten um dich her,\nfürchte nichts, denn Er führt dich.\nEr erhält dich auf dem Weg,\ndenn dein Gott hat dir versprochen,\ndass Er dich nie mehr verlassen wird.'),
(9, '0536', 'Gott ist immer für uns, wer kann uns noch schaden?   (Denn ich bin gewiss, dass weder Tod noch Leben, mich von Ihm scheiden kann)', NULL, 'Gott ist immer für uns, wer kann uns noch schaden?\nEr hat Seinen Sohn nicht verschont.\nEr hat Ihn uns gegeben, auf dass wir sollen leben\nals freie Menschen auf der Erd\'.\r\n||: Denn ich bin gewiss,\ndass weder Tod noch Leben,mich von Ihm scheiden kann,\nja, dass nichts und niemand mehr\nmich kann scheiden von dem Herrn. :||\r\nTraurigkeit und Ängste, Hunger und Verfolgung,\nkann mich das den scheiden von Ihm?\nIn der Not in Sorgen, weiß ich mich geborgen.\nImmer will ich hören Seine Stimm\'.\r\nAuch vor Satans Mächten, Welten und Kräften,\nbraucht mir nicht mehr bange zu sein.\nDenn durch die große Liebe des Heilands Jesus Christus,\nhab\' ich überwunden die Pein.'),
(9, '0537', 'Gott ist mein Hort, er birgt mich gut  -  The Lord\'s our Rock, in Him we hide   (Ja Jesus will ich traun, denn Er ist mein Fels)', 'The Lord\'s our Rock, in Him we hide,\na shelter in the time of storm.\nSecure whatever ill betide,\na shelter in the time of storm.\r\nO Jesus is a Rock in a weary land,\na weary land, a weary land.\nO Jesus is a Rock in a weary land,\na shelter in the time of storm.\r\nA shade by day, defense by night,\na shelter in the time of storm.\nNo fears alarm, no foes affright,\na shelter in the time of storm.\r\nThe raging storms may round us beat,\na shelter in the time of storm.\nWe\'ll never leave our safe retreat,\na shelter in the time of storm.\r\nO Rock divine, O Refuge dear,\na shelter in the time of storm.\nBe Thou our helper ever near,\na shelter in the time of storm.', 'Gott ist mein Hort, er birgt mich gut,\nein starker Fels im wilden Sturm!\nFest steht Er, braust auch hoch die Flut,\nein starker Fels im wilden Sturm!\r\nJa Jesus will ich trau\'n, denn Er ist mein Fels,\nEr ist mein Fels, Er ist mein Fels!\nJa, Jesus will ich traun\', denn Er ist mein Fels,\nein starker Fels im wilden Sturm.\r\nIm Sonnenbrand ein kühler Schutz,\nein starker Fels im wilden Sturm!\nBei Nacht dem stärksten Feind ein Trutz,\nein starker Fels im wilden Sturm!\r\nWenn er gebeut, wird still das Meer,\nein starker Fels im wilden Sturm!\nIch fürchte nichts, mich schützt der Herr,\nein starker Fels im wilden Sturm!\r\nO lieber Fels, o Heiland mein.\nO starker Fels im wilden Sturm!\nIch flieh zu Dir, Du birgst mich fein,\ndu starker Fels im wilden Sturm!'),
(9, '0538', 'Gott ist mein Schöpfer, Er schuf mein Herz  -  I have a Maker, He formed my Heart   (He knows my name)', 'I have a maker.\nHe formed my heart.\nBefore even time began\nMy life was in His hands.\r\nHe knows my name.\nHe knows my every thought.\nHe sees each tear that falls\nAnd hears me when I call.\r\nI have a father.\nHe calls me His own.\nHe\'ll never leave me\nNo matter where I go.', 'Gott ist mein Schöpfer\nEr schuf mein Herz\nbevor selbst die Zeit begann\nhielt Er mich in der Hand.\r\nEr kennt mein Herz\nEr weiß, was mich bewegt,\nEr, der die Tränen zählt,\nlässt mich niemals allein.\r\nGott ist mein Vater\nEr nennt mich Sein Kind\nwas auch das Leben bringt\nmein Gott wird bei mir sein.'),
(9, '0539', 'Gott ist nicht tot Er ist lebendig  -  God\'s not dead, He\'s alive', 'God\'s not dead, He\'s alive,\nGod\'s not dead, He\'s alive,\nGod\'s not dead, He\'s alive.\nI can feel Him in my hands,\nI can feel Him in my feet,\nI can feel Him in my heart,\nI feel Him all over me.', 'Gott ist nicht tot, er ist lebendig!\nGott ist nicht tot, er ist lebendig!\nGott ist nicht tot, er ist lebendig!\nFühl\' Ihn in meinen Händen,\nFühl\' Ihn in meinen Füßen,\nFühl\' Ihn in meinem Herzen,\nich fühle Ihn ganz über mir!'),
(9, '0540', 'Gott kann tun', 'God can do anything,\nanything, anything.\nGod can do\nanything for you.\nHe\'s the Alpha, the Omega,\nthe Beginning and the End.\nGod can do\nanything for you.', 'Gott kann tun, alles tun,\nalles tun, alles tun.\nGott kann tun,\nalles tun, für dich.\nEr ist Alpha und Omega,\nEr der Anfang und das End\'.\nGott kann tun,\nalles tun, für dich.'),
(9, '0541', 'Gott kanns tun noch einmal  -  God can do it again', 'God can do it again\nand again and again.\nThere\'s no reason to doubt,\nGod can do it again.\nYesterday and the day before,\nHe is always the same.\nThere\'s no reason to doubt,\nGod can do it again.', 'Gott kann\'s tun noch einmal,\nnoch einmal, noch einmal.\nKeinen Zweifel gibt\'s da,\nGott kann\'s tun noch einmal.\nGestern war\'s und tags zuvor,\nimmer gleich ist der Herr.\nKeinen Zweifel gibt\'s da,\nGott kann\'s tun noch einmal.'),
(9, '0542', 'Gott liebet dich, Gott liebet dich. Wie war dir doch Sein Herz gewogen', NULL, 'Gott liebet dich, Gott liebet dich!\nWie war dir doch Sein Herz gewogen,\ndass es den Sohn vom Thron ans Kreuz gezogen.\nSieh, alle deine Schuld nahm Er auf Sich!\nGott liebet dich, Gott liebet dich!\r\nEr liebet mich, Er liebet mich!\nFürwahr, Er ist für mich gestorben,\nhat mich mit Seinem teuren Blut erworben.\nAch, jetzt, o Heiland, erst erkenn\' ich Dich:\nDu liebest mich, Du liebest mich!\r\nIch liebe Dich, ich liebe Dich,\nmein Herze sei nur Dir verschrieben,\nich will Dich, treue Liebe, wieder lieben, o Herr,\nDu weißt es wohl: Dein Kind bin ich\nund liebe Dich, und liebe Dich!\r\nDu liebest mich, und ich lieb Dich,\nDein Bund bleibt fest zu allen Zeiten,\nund wer will mich von Deiner Liebe scheiden?\nIch weiß, mit ew\'ger Gnade krönst Du mich!\nDu liebest mich, und ich lieb Dich!'),
(9, '0543', 'Gott mit euch bis wir uns wiedersehn  -  God be with you till we meet again   (Auf Wiedersehn, Wiedersehn)', 'God be with you till we meet again!\nBy His counsels guide, uphold you,\nwith His sheep securely fold you.\nGod be with you till we meet again!\r\nTill we meet! Till we meet!\nTill we meet at Jesus\' feet.\nTill we meet! Till we meet!\nGod be with you \'til we meet again!\r\nGod be with you till we meet again!\n\'Neath His wings securely hide you,\ndaily manna still provide you.\nGod be with you till we meet again!\r\nGod be with you till we meet again!\nWhen life\'s perils thick confound you,\nput His arms unfailing round you.\nGod be with you till we meet again!\r\nGod be with you till we meet again!\nKeep love\'s banner floating o\'er you,\nsmite death\'s threat\'ning wave before you.\nGod be with you till we meet again!', 'Gott mit euch bis wir uns wiederseh\'n!\nÜbergebt nun eure Wege\nSeiner treuen Hirtenpflege.\nGott mit euch, bis wir uns wiederseh\'n!\r\nAuf Wiederseh\'n, Wiederseh\'n,\nhier auf Erden oder dort im Licht!\nAuf Wiederseh\'n, Wiederseh\'n!\nUnser Hüter schläft noch schlummert nicht.\r\nGott mit euch, bis wir uns wiederseh\'n!\nGottes Auge wird euch leiten\nund durch Freud und Leid begleiten.\nGott mit euch, bis wir uns wiederseh\'n!\r\nGott mit euch, bis wir uns wiederseh\'n!\nSollte Not und Schmerz euch schrecken,\nmög\' Sein Flügel euch bedecken.\nGott mit euch, bis wir uns wiederseh\'n!\r\nGott mit euch, bis wir uns wiederseh\'n!\nSeine Gnade, Huld und Treue\nGrüß euch alle Tage neue:\nGott mit euch, bis wir uns wiederseh\'n!'),
(9, '0544', 'Gott sandte uns seinen Propheten  -  God sent to us His mighty Prophet   (Jesus Christus ist Derselbe gestern, heut, in Ewigkeit)', 'God sent to us His mighty prophet\nwith the spoken Word.\nThe pillar of fire came down,\nand vindicated His word.\r\nJesus Christ is still the same,\nyesterday, eternally.\nJust believe and you shall see Him,\nJesus is the same today. (2x)\r\nGod leads His people out of Babel,\nas He did long time ago.\nCome out of their midst\nand obey the word this hour!\r\nHear the crying of the eagle:\n"You my people be prepared!"\nFor the Lord, He is soon coming,\nsoon eternity begins.', 'Gott sandte uns Seinen Propheten\nmit dem gesprochenen Wort.\nDie Feuersäule kam hernieder,\nund sie bestätigte Sein Wort.\r\nJesus Christus ist Derselbe\ngestern, heut\', in Ewigkeit!\nGlaube nur und du wirst sehen,\nJesus ist Derselbe heut\'! (2x)\r\nGott führt Sein Volk heraus aus Babel,\nso wie Er\'s tat vor langer Zeit.\nKommt heraus aus Ihrer Mitte\nund befolgt das Wort der Zeit.\r\nHör den Schrei des großen Adlers:\n"Ihr, Mein Volk, macht euch bereit!"\nDenn der Herr, Er wird bald kommen,\nbald beginnt die Ewigkeit.'),
(9, '0545', 'Gott sitzt am Webstuhl meines Lebens, und Seine Hand die Fäden hält', NULL, 'Gott sitzt am Webstuhl meines Lebens,\nund Seine Hand die Fäden hält.\nEr schafft und wirket nicht vergebens,\nwenn Ihm ein Muster wohl gefällt.\nMir will es manchmal seltsam dünken,\nwie Er die Fäden so verwirrt.\nDoch niemals seine Arme sinken,\nwenn Er das Weberschifflein führt.\r\nManch raue Fäden lässt er gleiten,\ndurch seine liebe Vaterhand.\nEr weiß aus allem zu bereiten,\nfür mich des Himmels Lichtgewand.\nAuch dunkle Fäden eingebunden,\nflicht Er in das Gewebe ein.\nDas sind des Lebens trübe Stunden,\ndann schweige ich und harre Sein.\r\nUnd stille ich am Webstuhl stehe,\nwenn Er auch dunkle Fäden spinnt.\nDen gold\'nen Faden ich nur sehe,\nund freu\' mich dessen wie ein Kind.\nDenn ob es helle oder trübe,\naus allem glänzet doch hervor,\nder gold\'ne Faden Seiner Liebe,\nder mich zu Seinem Kind erkor.\r\nUnd ist der letzte Tag zerronnen,\nmein Sterbetag von Gott gewollt,\ndann ist der Webstuhl abgesponnen,\nund alles glänzt wie lauter Gold.\nDann sing ich mit den Engelchören,\nnach letzter durchgekämpfter Nacht.\nDem großen Meister dann zu Ehren,\n"Ja, Du hast alles wohl gemacht!"'),
(9, '0546', 'Gott wird dich tragen, drum sei nicht verzagt  - God will take care of you, be not afraid   (Gott wird dich tragen mit Händen so lind)', 'God will take care of you, be not afraid,\nHe is your safeguard through sunshine and shade.\nTenderly watching and keeping His own,\nHe will not leave you to wander alone.\r\nGod will take care of you still to the end,\noh, what a Father, Redeemer, and Friend!\nJesus will answer whenever you call,\nHe will take care of you, trust Him for all.\r\nGod will take care of you, through all the day,\nshielding your footsteps, directing your way.\nHe is your shepherd, protector, and guide,\nleading His children where still waters glide.\r\nGod will take care of you long as you live,\ngranting you blessings no other can give.\nHe will take care of you when time is past,\nsafe to His kingdom will bring you at last.', 'Gott wird dich tragen, d\'rum sei nicht verzagt,\ntreu ist der Hüter, der über dich wacht.\nStark ist der Arm, der dein Leben gelenkt,\nGott ist ein Gott, der der Seinen gedenkt.\r\nGott wird dich tragen mit Händen so lind.\nEr hat dich lieb wie ein Vater sein Kind.\nDas steht im Glauben wie Felsen so fest:\nGott ist ein Gott, der dich nimmer verlässt.\r\nGott wird dich tragen, wenn einsam du gehst,\nGott wird dich hören, wenn weinend du flehst.\nGlaub\' es, wie bang dir der Morgen auch graut,\nGott ist ein Gott, dem man täglich vertraut.\r\nGott wird dich tragen durch Tage der Not;\nGott wird dir beisteh\'n in Alter und Tod.\nFest steht das Wort, ob auch alles zerstäubt,\nGott ist ein Gott, der in Ewigkeit bleibt.'),
(9, '0547', 'Gottes Geist wirkt noch einmal   (Kommt zum Mahl ihr Gäste alles ist bereit)', NULL, 'Gottes Geist wirkt noch einmal,\nGottes Geist wirkt noch einmal,\nGottes Geist wirkt noch einmal auf der Erd\'.\nZu erfüllen jedes Wort, überall an jedem Ort,\nGottes Geist wirkt noch einmal auf der Erd\'.\r\nKommt zum Mahl ihr Gäste alles ist bereit,\nin des Königs Hochzeitssaal, voll Herrlichkeit.\nEr, der viele schon gespeist\nund auch jetzt uns Heil verheißt,\nruft auch dich voll Lieb\' und Huld:\n"Komm zum Mahl!"\r\nGottes Geist wirkt jetzt in mir,\nGottes Geist wirkt jetzt in mir,\nGottes Geist wirkt jetzt in mir noch einmal.\nDie Verheißung sich erfüllt,\nalles Sehnen wird gestillt.\nGottes Geist wirkt jetzt in mir noch einmal.'),
(9, '0548', 'Gottes schneeweiße Taube naht  -  On the Wings of a snow-white Dove   (Chorus)', 'On the wings of a snow-white dove,\nGod sends His pure, sweet love,\nA sign from above,\nOn the wings of a dove.', 'Gottes schneeweiße Taube naht,\nzu dir vom Thron der Gnad\'\nschwebt Liebe so zart,\nauf den Flügeln der Gnad\'.'),
(9, '0549', 'Gottes Verheißungen bleiben, sie wanken ewig nicht   (Himmel und Erd mag brennen)', NULL, 'Gottes Verheißungen bleiben,\nsie wanken ewig nicht.\nBlutend hat Jesus besiegelt,\nwas Er im Wort verspricht.\r\nHimmel und Erd\' mag brennen,\nHügel und Berg verschwinden;\ndoch, wer da glaubt, wird finden,\nGottes Wort bleibt stets wahr.\r\nRichte den Blick nur nach oben,\nwie einstens Abraham!\nWährend die Sterne du zählest,\nGlaubensmut reichlich naht.\r\nGlaube, wenn alles auch dunkel,\nwenn gleich das Herz dir bricht!\nNur ein paar Stunden es währet,\ndann strahlt das Sonnenlicht.\r\nGlaube trotz aller Verfolgung!\nIn deiner Trübsalsglut\nwandelt dein Herr, der Sohn Gottes,\nund Er macht alles gut.\r\nGlaube, wenn Freunde versagen!\nEiner bleibt dennoch treu!\nJesus, dein Freund, wird dich tragen,\nstärket dich täglich neu.\r\nGlaube in all deinen Nöten,\nbald geht es himmelwärts!\nDort wirst in Wahrheit du schauen,\nwas hier geglaubt dein Herz.'),
(9, '0550', 'Göttliche Liebe, so groß und unermesslich weit   (Wunderbar, wunderbar, wunderbar, o Liebe Gottes, so groß)', NULL, 'Göttliche Liebe, so groß und unermesslich weit,\nLiebe, so wunderbar groß, bleibet in Ewigkeit.\nGott ist im Fleische erschienen, Menschen mit sich zu versühnen,\nihnen zum Leben zu dienen. O Liebe Gottes, so groß!\r\nWunderbar, wunderbar, wunderbar, o Liebe Gottes, so groß!\r\nGöttliche Liebe, so groß! Herz, bleib ihr ja nicht fern!\nLiebe, so wunderbar groß, ist auch für dich im Herrn.\nKrippe und Kreuz dir verkünden: Jesus macht frei dich von Sünden,\nlässt neues Leben dich finden. O Liebe Gottes, so groß!\r\nGöttliche Liebe, so groß, sie wendet alle Not.\nLiebe, so wunderbar groß, gibt uns nicht mehr dem Tod.\nKetten des Satans zerspringen, Sklaven zur Freiheit durchdringen\nund Jesu Blut laut besingen. O Liebe Gottes, so groß!\r\nGöttliche Liebe, so groß! Komm, Seele, bete an!\nLiebe, so wunderbar groß, führt uns ja himmelan.\nGibt sich uns ganz zu genießen, lässt Geist und Kraft auf uns fließen,\nwird uns einst droben begrüßen. O Liebe Gottes, so groß!'),
(9, '0551', 'Grad jetzt dank ich Dir  -  In Moments like these   (Wir singen: Ich lieb Dich, Herr)', 'In moments like these, I sing out a song,\nI sing out a love song for Jesus.\nIn moments like these, I lift up my hands,\nI lift up my hands to the Lord.\r\nSinging: I love You Lord.\nSinging: I love You Lord.\nSinging: I love You o Lord,\nI love You Lord.', 'Grad jetzt dank\' ich Dir und singe ein Lied,\nich singe ein Lied nur für Dich.\nGrad jetzt dank\' ich Dir, ich heb\' meine Hand,\nich heb\' meine Hände zu Dir.\r\nWir singen: "Ich lieb\' Dich, Herr".\nWir singen: "Ich lieb\' Dich, Herr".\nWir singen: "Ich liebe Dich, o Herr,\nich liebe Dich".'),
(9, '0552', 'Grad wenn mein Herz entmutigt  -  Just when I am disheartened   (Die Gnade des Herrn reicht aus für mich)', 'Just when I am disheartened, just when with cares oppressed,\njust when my way is darkest, just when I am distressed.\nThen is my Saviour near me, He knows my every care.\nJesus will never leave me, He helps my burdens bear.\r\nHis grace is enough for me,\nHis grace is enough for me.\nThrough sorrow and pain,\nthrough loss or gain,\nHis grace is enough for me.\r\nJust when my hopes are vanished, just when my friends forsake,\njust when the fight is thickest, just when with fear I shake.\nThen comes a still small whisper: "Fear not, My child, I’m near."\nJesus brings peace and comfort, I love His voice to hear.\r\nJust when my tears are flowing, just when with anguish bent,\njust when temptation’s hardest, just when with sadness rent.\nThen comes a thought of comfort: I know my Father knows.\nJesus has grace sufficient, to conquer all my foes.', 'Grad wenn mein Herz entmutigt, von Sorgen hart bedrängt,\ngrad wenn mein Weg recht dunkel und mir die Brust beengt,\ndann ist mir Jesus nahe, Er weiß was mir gebricht;\nEr wird mich nie verlassen, nein, Er versäumt mich nicht.\r\nDie Gnade des Herrn reicht aus für mich,\ndie Gnade des Herrn reicht aus für mich.\nIn Sorge und Leid, in Schmerz und Freud\'\ngenüget mir Seine Gnad\'.\r\nGrad wenn die Hoffnung fliehet und Freunde wandeln sich,\ngrad wenn der Kampf recht heftig und Furcht erschüttert mich.\ndann hör ich leise flüstern: "Fürchte dich nicht, mein Kind!"\nUnd in des Meisters Worten Ruhe und Trost ich find\'.\r\nGrad wenn die Tränen fließen, wenn Seelenschmerz mich beugt,\nwenn die Versuchung dränget, voll Trauer ist das Heut\',\ndann tröstet mich das Wissen: Mein Vater droben wacht!\nUnd ich lass mir genügen an meines Gottes Gnad\'.'),
(9, '0553', 'Graves Into Garden', 'I searched the world\nBut it couldn\'t fill me\nMan\'s empty praise\nAnd treasures that fade\nare never enough\nThen You came along\nAnd put me back together\nAnd every desire is now satisfied Here in Your love\r\nOh, there\'s nothing better than You There\'s nothing better than You Lord, there\'s nothing\nNothing is better than You\r\nI\'m not afraid\nTo show You my weakness\nMy failures and flaws\nLord, You\'ve seen them all\nAnd You still call me friend\n\'Cause the God of the mountain\nIs the God of the valley\nThere\'s not a place Your mercy and grace Won\'t find me again\r\nYou turn mourning to dancing You give beauty for ashes You turn shame into glory You\'re the only one who can\r\nYou turn graves into gardens You turn bones into armies You turn seas into highways You\'re the only one who can You\'re the only one who can', 'Ich durchsuchte die Welt\nAber sie konnte mich nicht erfüllen Die leere Anbetung der Menschen Und Schätze, die vergehen\nsind niemals genug\nDann bist Du gekommen\nUnd fügtest mich wieder zusammen Und jedes Verlangen ist nun gestillt Hier in deiner Liebe\r\n(Oh, es gibt nichts Besseres als Dich Da ist nichts besser als Du\nHerr, da ist nichts,  Nichts ist besser als Du)\r\nIch habe keine Angst\nDir meine Schwäche zu zeigen\nMein Versagen und meine Mängel\nHerr, Du hast sie alle gesehen\nUnd immer noch nennst Du mich Freund Denn der Gott des Berges Ist der Gott des Tales\nEs gibt keinen Ort, an dem deine Barmherzigkeit und Gnade\nmich nicht wiederfinden\r\nDu verwandelst Trauer in Tanz Du gibst Schönheit für Asche\nDu verwandelst Scham in Ruhm Du bist der Einzige, der das kann\r\nDu verwandelst Gräber in Gärten Du verwandelst Knochen in Armeen Du verwandelst Meere in Straßen Du bist der Einzige, der das kann Du bist der Einzige, der das kann'),
(9, '0554', 'Greater than all my Sin', 'Greater than all my sin\nis the blood that still cleanses me\nis the blood that still sets me free\nto praise Him\nI know the bloods applied\nI\'m walking on newness of life\nI cannot fall, for it\'s greater than all\nthe blood of the lamb', 'Größer als all meine Sünde ist das Blut dass mich reinigt\ndas Blut das mich immer noch frei macht,  Ihn zu preisen\nIch weiß das Blut ist angewandt,  Ich wandel in der\nErneuerung des Lebens\nIch kann nicht fallen, denn es ist größer als alles\ndas Blut des Lammes..'),
(9, '0555', 'Großer Gott wir loben Dich  -  Holy God, we praise thy Name', 'Holy God, we praise thy name,\nLord of all, we bow before thee!\nAll on earth Thy scepter claim,\nall in heav\'n above adore thee.\nInfinite thy vast domain,\neverlasting is thy reign.\r\nHark, the loud celestial hymn,\nangel choirs above are raising.\nCherubim and seraphim,\nin unceasing chorus praising,\nfill the heav’ns with sweet accord:\nHoly, holy, holy Lord.\r\n\r\n\r\n', 'Großer Gott, wir loben Dich!\nHerr, wir preisen Deine Stärke.\nVor Dir neigt die Erde sich\nund bewundert Deine Werke.\nWie Du warst vor aller Zeit, so\nbleibst Du in Ewigkeit.\r\nAlles, was Dich preisen kann,\nCherubim und Seraphinen,\nstimmen Dir ein Loblied an.\nAlle Engel, die Dir dienen,\nrufen Dir in sel\'ger Ruh\'\n"Heilig, heilig, heilig" zu.\r\nHeilig, Herr, Gott Zebaoth,\nheilig, Herr der Kriegesheere.\nStarker Helfer in der Not!\nHimmel, Erde, Luft und Meere\nsind erfüllt von Deinem Ruhm.\nAlles ist Dein Eigentum.\r\nSieh Dein Volk in Gnaden an,\nhilf uns, segne, Herr, Dein  Erbe.\nLeit\' es auf der rechten Bahn,\ndass der Feind es nicht verderbe.\nGib, dass es im Aufersteh\'n\nfrei Dein Antlitz möge seh\'n.\r\nHerr, erbarm\', erbarme Dich!\nAuf uns komme, Herr, Dein Segen!\nDeine Güte zeige sich,\nallen der Verheißung wegen.\nAuf Dich hoffen wir allein,\nlass uns nicht verloren sein.'),
(9, '0556', 'Güte von Gott / Goodness of God', 'I love You, Lord\nFor Your mercy never fails me\nAll my days, I\'ve been held in Your hands\nFrom the moment that I wake up\nUntil I lay my head\nOh, I will sing of the goodness of God\r\nAnd all my life You have been faithful\nAnd all my life You have been so, so good\nWith every breath that I am able\nOh, I will sing of the goodness of God\r\nI love Your voice\nYou have led me through the fire\nIn the darkest night\nYou are close like no other\nI\'ve known You as a Father\nI\'ve known You as a Friend\nAnd I have lived in the goodness of God\r\n\'Cause Your goodness is running after\nIt\'s running after me\nYour goodness is running after\nIt\'s running after me\nWith my life laid down\nI\'m surrendered now\nI give You everything\n\'Cause Your goodness is running after\nIt\'s running after me', 'Ich lieb dich, Herr\nNie verlässt mich deine Gnade\nJeden Tag\nHältst du mich in der Hand\nVom Moment wenn ich erwache\nBis ich mich schlafen leg\nSing ich von deiner Güte, mein Gott\r\nMein ganzes Leben bist du treu, Herr\nMein ganzes Leben bist du so, so gut\nSolang ich kann, so lang ich atme\nSing ich von deiner Güte, mein Gott\r\nIch lieb dein Wort\nDu führst mich auch durch das Feuer\nIn tiefster Nacht\nBist du nah wie kein andrer\nIch kenne dich als Vater\nIch kenne dich als Freund\nIch leb\' in deiner Güte,  mein Gott\r\n||:Deine Güte, sie jagt mir nach\nSie jagt mir immer nach:||\nAlles was ich bin\nLeg ich vor dich hin\nIch gebe alles dir\nDeine Güte, sie jagt mir nach\nSie jagt mir immer nach'),
(9, '0557', 'Hab Dank aus vollem Herzen  -  Give Thanks with a greatful Heart', 'Give thanks with a greatful heart,\ngive thanks to the Holy One.\nGive thanks because He\'s given\nJesus Christ, His Son. (2x)\r\nAnd now let the weak say\nI am strong, let the poor say I am rich,\nbecause of what the Lord has done for us.  (2x)\nGive thanks.... give thanks.', 'Hab\' Dank aus vollem Herzen,\nHab\' Dank, Du Heiliger,\nHab\' Dank, denn du gabst uns\nJesus Christ, Deinen Sohn (2x)\r\nIn Ihm, sag ich Schwacher,\nich bin stark, sag ich Armer,\nich bin reich,\nwegen allem, was Du für mich getan (2x)'),
(9, '0558', 'Habt ihr gehört den Gnadenruf zu unsers Heilands Hochzeitsmahl   (O hör den Ruf: "Mach dich bereit")', NULL, 'Habt ihr gehört den Gnadenruf\nzu unser\'s Heilands Hochzeitsmahl?\nEr ladet alle freundlich ein zum Fest\nim ew\'gen Freudensaal.\r\nO hör den Ruf: "Mach dich bereit!"\nBald kommt der Herr in Herrlichkeit.\nVielleicht kommt Er in diesem Jahr;\nd\'rum mach dich auf zu geh\'n mit Ihm zum Hochzeitsmahl.\r\nHin eilt die Zeit, der Tag ist nah,\nwo der Posaunenton erschallt.\nSchmück\' deine Lampe! Kaufe Öl!\nDer Geist spricht ja: "Der Herr kommt bald."\r\nD\'rum seid den klugen Jungfrau\'n gleich,\nerfüllt mit heil\'gem Liebessinn;\nund wachet, wartend Tag für Tag,\nbis Er uns ruft zur Hochzeit hin.\r\nDu hast in uns, o Herr, geweckt\nein heißes Sehnen hin zu Dir;\nund wo noch Flecken, Runzeln sind,\nda läutre uns, so flehen wir!\r\nSchnell eilt die Zeit! Mach uns bereit,\nHerr, für Dein Komm\'n in Herrlichkeit;\ndass wenn Du kommst in diesem Jahr,\nwir alle jubelnd geh\'n mit Dir zum Hochzeitsmahl.'),
(9, '0559', 'Habt ihr treulich gesuchet die Schafe  -  Have you sought for the sheep that have wandered', 'Have you sought for the sheep that have wandered,\nfar away on the dark mountains cold?\nHave you gone, like the tender Shepherd,\nto bring them again to the fold?\nHave you followed their weary footsteps?\nAnd the wild desert waste have you crossed,\nnor lingered till safe home returning,\nyou have gathered the sheep that were lost?\r\nHave you been to the sad and the lonely,\nwhose burdens are heavy to bear?\nHave you carried the name of Jesus,\nand tenderly breathed it in prayer?\nHave you told of the great salvation\nHe died on the cross to secure?\nHave you asked them to trust in the Saviour,\nwhose love shall forever endure?\r\nHave you knelt by the sick and the dying,\nthe message of mercy to tell?\nHave you stood by the trembling captive\nalone in his dark prison cell?\nHave you pointed the lost to Jesus,\nand urged them on Him to believe?\nHave you told of the life everlasting,\nthat all, if they will, may receive?\r\nIf to Jesus you answer these questions,\nand to Him have been faithful and true,\nthen behold, in the mansions yonder\nare crowns of rejoicing for you.\nAnd there from the King eternal\nyour welcome and greeting shall be,\ninasmuch as ’twas done for My brethren,\neven so it was done unto Me.', 'Habt ihr treulich gesuchet die Schafe,\ndie auf felsigem Pfade verirrt,\nmit nie rastender Hirtentreue,\nwie Jesus uns sucht, unser Hirt\'?\nSeid der Spur ihr gefolgt im Tale,\ndurch der Schluchten unheimliche Nacht,\nbis ihr matt, doch mit jauchzendem Herzen\neuer Schaf zu der Hürde gebracht?\r\nHabt die einsamen, trauernden Herzen\nihr mit tröstender Liebe besucht,\nwo vereint im Gebet gebeuget,\nden Kummer zu Jesu ihr trugt?\nHabt zu Jesus die Sünderherzen\nund zum Kreuz ihr die Blicke gelenkt,\nbis die Tränen der Freude geflossen\nund das Lamm ihnen Frieden geschenkt?\r\nHabt zur Wohnung der darbenden Armen\nihr die Gabe der Liebe gebracht?\nHabt ihr oftmals, im Geiste Jesu,\nam Bette der Kranken gewacht?\nHobt die Blumen ihr auf am Wege,\ndie zertreten schon lagen im Staub?\nHabt ihr Jesu zum Kreuz sie gewunden\nund der Hölle entrissen den Raum?\r\nEinst wird sammeln der König am Throne\naller Völker unzählbare Schar;\nwelch ein Lohn wird dem Knechte werden,\nder treu in der Liebe hier war!\nO welch Glück, wenn sich huldvoll neiget\nDeines Heilands Antlitz zu dir:\nWas du tat\'st an dem ärmsten der Brüder,\nhast zugleich du getan, auch an Mir!'),
(9, '0560', 'Habt ihrs gehört von Jesus dem Meister  -  Ye are the Temples, Jesus hath spoken   (Hat euch erfüllt, seit ihr geglaubt, der werte Heilge Geist?)', 'Ye are the temples, Jesus hath spoken,\ntemples of God’s holy Spirit divine.\nHave ye receiv’d Him, bidden Him enter,\nmake His abode in that poor heart of thine?\r\nHave ye receiv’d, since ye believ’d,\nthe blessed Holy Ghost?\nHe who has promis’d, gift of the Father,\nhave ye receiv’d the Holy Ghost?\r\nHe who has pardon’d surely will cleanse thee,\nall of the dross of thy nature refine.\nCleans’d from all sin, His power will enter,\nfill you and thrill you with power divine.\r\nShowers of mercy, fulness of blessing,\never the Spirit’s indwelling attend.\n’Tis this enduement, power of service,\nfruits for your labor He surely will send.\r\nWeary of wand’ring, come into Canaan,\nfeast on the fullness and fat of the land.\nFeed on the manna, dwell in the sunshine,\nled by His Spirit and kept by His hand.', 'Habt ihr\'s gehört von Jesus, dem Meister,\nBrüder, dass Tempel des Geistes ihr seid?\nHabt ihr empfangen, bittend im Glauben,\nIhn, der zu kommen, zu bleiben bereit?\r\nHat euch erfüllt, seit ihr geglaubt,\nder werte Heil\'ge Geist?\nEr, der verheißen Gaben des Vaters,\nhat euch erfüllt der Heil\'ge Geist?\r\nDer uns vergeben, reinigt uns völlig,\nmacht von den Schlacken des Alten uns frei.\nWenn wir gereinigt, wird uns erfüllen\nKraft aus der Höhe, die alles macht neu.\r\nStröme der Gnade, Fülle des Segens\nspendet der Geist, wenn im Herzen er thront.\nAusrüstung bringt Er, Kraft um zu dienen,\nFrucht für die Arbeit, wo bleibend Er wohnt.\r\nMüde vom Wandern gehe im Glauben\nein in die Ruhe, in Kanaans Land.\nDort ist Erquickung, dort scheint die Sonne,\nleitet Sein Geist und beschirmt Seine Hand.'),
(9, '0561', 'Halleluja Amen  -  Hallelujah Amen   (Chorus)', 'Hallelujah... (hallelujah)\nAmen... (Amen)                (3x)\nGlory unto the Lord.', 'Halleluja... (halleluja)\nAmen... (Amen)                (3x)\nEhre sei dem Herrn.'),
(9, '0562', 'Halleluja bin erlöst durch das Blut   (Chorus)', NULL, 'Halleluja, halleluja, bin erlöst durch das Blut!\nHalleluja, halleluja, wie hab ich\'s so gut!\nHalleluja, halleluja, der Heiland ist mein!\nHalleluja, wie schön ist\'s, gerettet zu sein.'),
(9, '0563', 'Halleluja Jesus Christ macht alles neu   (Chorus)', NULL, 'Halleluja, Jesus Christ macht alles neu, das alte Leben ist vorbei.\nHalleluja, Jesus Christ macht alles neu, das alte Leben ist vorbei.\nDurch wunderbares Handeln kann Er dich ganz verwandeln,\nmein Leben, das einst Wüstensand verwandelt Er in Gartenland.\nHalleluja, Jesus Christ macht alles neu, das alte Leben ist vorbei.'),
(9, '0564', 'Halleluja singe ich, auch wenn der Feind versuchet mich  -  Hallelujah anyhow, don\'t let the Devil get you down   (Chorus)', 'Hallelujah anyhow, don\'t let the devil get you down.\nWhen old troubbles come your way,\nhold your head up high and say: Hallelujah anyhow!', 'Halleluja, singe ich, wenn der Feind auch plaget mich.\nMutig will ich weitergeh\'n nur auf die Verheißung seh\'n.\nHalleluja, singe ich.'),
(9, '0565', 'Halleluja tönt\'s in meinem Herzen   (Ewig klingt\'s im Herzen mir das Halleluja für und für)', NULL, 'Halleluja, tönt\'s in meinem Herzen,\nHalleluja, schalt\'s bei Tag und Nacht.\nHalleluja, klingt\'s durch Freud und Schmerzen,\nHalleluja, Jesus hat\'s vollbracht.\r\nEwig klingt\'s im Herzen mir\ndas Halleluja für und für.\nDurch Jesu Blut ward mir zuteil,\nHalleluja das volle Heil.\r\nHalleluja, Licht ist nun mein Leben,\nHalleluja, Herr Du kamst zu mir.\nHalleluja, alles wirst Du geben,\nHalleluja, nimm mein Herz dafür!\r\nHalleluja, Herr Du heilst die Wunden,\nHalleluja, Du hilfst stark und treu.\nHalleluja, Herr Du lässt gesunden,\nHalleluja, Freude schenkst Du neu.\r\nHalleluja, sicher darf ich schreiten,\nHalleluja, froh durch\'s Erdenland.\nHalleluja, Du wirst mich begleiten,\nHalleluja, Du hältst meine Hand.\r\nHalleluja, Du gabst neues Leben,\nHalleluja, Geist von Deinem Geist.\nHalleluja, Herr ich spür\' Dein Weben,\nHalleluja, Herz und Mund Dich preist.\r\nHalleluja, jauchzend will ich singen,\nHalleluja, hört es weit und breit.\nHalleluja, jubelnd soll es klingen,\nHalleluja, bis in Ewigkeit.'),
(9, '0566', 'Halleluja! Der Heiland lebt; Er ist vom Tod erstanden', NULL, 'Halleluja! Der Heiland lebt;\nEr ist vom Tod erstanden.\nDie Höllenmacht des Teufels bebt;\ngesprengt sind alle Banden.\nNun ist die finst\'re Nacht vorbei,\nder Zutritt zu dem Vater frei.\nHalleluja, der Heiland lebt!\r\nHalleluja! Der Heiland siegt;\nes glänzet Seine Krone.\nBis alles Ihm zu Füßen liegt,\nsitzt er auf Seinem Throne.\nIhm dient des Himmels ganzes Heer;\nDenn Ihm gebührt Lob, Preis und Ehr\'.\nHalleluja, der Heiland siegt!\r\nHalleluja! Der Heiland liebt;\nEr liebt Seine Kinder.\nO hört\'s wie Er so gern vergibt\nund annimmt arme Sünder!\nEr hat ein Mahl für uns bereit\nund ladet ein zu dieser Zeit.\nHalleluja, der Heiland liebt!\r\nHalleluja! Der Heiland ist da,\nEr weilt im Kreis der Seinen,\nist allen bis ans Ende nah,\nden Großen und den Kleinen;\nEr führt sie durch das dunkle Tal\nin seinen schönen Himmelsaal.\nHalleluja, der Heiland ist da!'),
(9, '0567', 'Halleluja! Lobet Gott in seinem Heiligtum   (Alles was Odem hat, lobet den Herrn)   (Psalm 150)', NULL, 'Halleluja! Lobet Gott in seinem Heiligtum,\nlobet Ihn in der Feste Seiner Macht.\nLobet Ihn für seine Taten, lobet Ihn,\nlobet Ihn in seiner großen Herrlichkeit.\r\nAlles was Odem hat, lobet den Herrn,\nHalleluja.\nAlles was Odem hat, lobet den Herrn,\nHalleluja.\r\nLobet Ihn mit den Posaunen, lobet Ihn,\nlobet Ihn mit Psalter und mit Harfen.\nLobet Ihn mit Pauken und mit Reigen,\nlobet Ihn mit Saiten und mit Pfeifen.\r\nLobet Ihn mit hellen Zimbeln, lobet Ihn\nlobet Ihn mit wohlkingenden Zimbeln.'),
(9, '0568', 'Halleluja, ... Jesus liebt dich; Er kommt wieder; Danke Jesus; Jesus ruft dich; Es geht heimwärts; Sieh der Bräut\'gam   (6 Chorusse)', 'Halleluja, Halleluja.\nHalleluja, Halleluja! (2x)\r\n\r\nEr kommt wieder,\nEr kommt wieder.\nEr kommt wieder,\nEr kommt wieder! (2x)\r\nDanke, Jesus,\ndanke, Jesus.\nDanke, Jesus,\ndanke, Jesus! (2x)\r\n\r\n\r\n', '\r\nJesus liebt dich,\nJesus liebt dich.\nJesus liebt dich,\nJesus liebt dich! (2x)\r\n\r\n\r\nJesus ruft dich,\nJesus ruft dich.\nJesus ruft dich,\nJesus ruft dich! (2x)\r\nEs geht heimwärts,\nes geht heimwärts.\nEs geht heimwärts,\nes geht heimwärts! (2x)\r\nSieh, der Bräut\'gam,\nsieh der Bräut\'gam.\nSieh, der Bräut\'gam,\nsieh der Bräut\'gam! (2x)'),
(9, '0569', 'Halleluja, auferstanden ist der Herr, der starke Held  -  Hallelujah, He is risen! Jesus is gone up on high', 'Hallelujah, He is risen! Jesus is gone up on high!\nBurst the bars of death asunder, angels shout and men reply.\nHe is risen, He is risen, living now no more to die.\nHe is risen, He is risen, living now no more to die.\r\nHallelujah, He is risen! Our exalted Head to be.\nSends the witness of the Spirit that our advocate is He.\nHe is risen, He is risen, justified in Him are we.\nHe is risen, He is risen, justified in Him are we.\r\nHallelujah, He is risen! Death for aye hath lost his sting,\nChrist, Himself the Resurrection, from the grave His own will bring.\nHe is risen, He is risen, living Lord and coming King.\nHe is risen, He is risen, living Lord and coming King.', 'Halleluja, auferstanden ist der Herr, der starke Held!\nEr entstieg des Grabes Banden, hat des Feindes Macht gefällt.\nAuferstanden ist mein Jesus, preiset ihn in aller Welt!\nAuferstanden ist mein Jesus, preiset ihn in aller Welt!\r\nHalleluja, auferstanden ist der Herr, der unser Haupt!\nUnd nun sendet er den Tröster Jeglichem, der an Ihn glaubt.\nAuferstanden ist mein Jesus, niemand ist, der Ihn mir raubt!\nAuferstanden ist mein Jesus, niemand ist, der Ihn mir raubt!\r\nHalleluja, auferstanden ist der Herr, Heil Seiner Macht!\nMit Sich führt Er nun die Seinen auch aus Tod und Grabesmacht.\nAuferstand\'ner Herr und König, Dir sei ewig Lob gebracht!\nAuferstand\'ner Herr und König, Dir sei ewig Lob gebracht!'),
(9, '0570', 'Halleluja, denn der Bräutigam kommt', NULL, 'Halleluja, Halleluja, Halleluja, Halleluja,\nHalleluja, Halleluja, Halleluja, Halleluja,\nHalleluja, denn der Bräutigam,\nder Bräutigam, Er kommt!\r\nSeid wachsam, seid wachsam,\nall ihr Frommen,\nseid wachsam, seid wachsam,\nall ihr Frommen,\nseid wachsam, seid wachsam,\nall ihr Frommen, denn der Bräutigam,\nder Bräutigam, Er kommt!\r\nLieber Jesus,\nerfüll\' mich mit dem Geist,\nlieber Jesus,\nerfüll\' mich mit dem Geist,\nlieber Jesus,\nerfüll\' mich mit dem Geist,\ndenn der Bräutigam,\nder Bräutigam, Er kommt!'),
(9, '0571', 'Halleluja, Halleluja, preiset den Herrn', '\r\n\r\n\r\nJesus lebt, Jesus lebt,\nJesus lebt, Jesus lebet,\nlobet, preiset Ihn. (2x)', 'Hallelu, Hallelu\nHallelu, Halleluja!\nPreiset den Herrn (2x)\r\nPreiset den Herrn, Halleluja!\nPreiset den Herrn, Halleluja!\nPreiset den Herrn, Halleluja!\nPreiset den Herrn!\r\nLobet ihn, lobet Ihn,\nlobet ihn, lobet Ihn, ja,\nlobet den Herrn. (2x)\r\n'),
(9, '0572', 'Halleluja, Preis dem Lamm  -  Hallelujah, praise the Lamb   (Chorus)', 'Hallelujah, praise the lamb!\nHallelujah, praise the lamb!\nMy heart sings His praise again,\nHallelujah, praise the lamb!', 'Halleluja, Preis dem Lamm!\nHalleluja, Preis dem Lamm!\nImmer wieder singt mein Herz,\nHalleluja, Preis dem Lamm!'),
(9, '0573', 'Hallelujah I\'m gonna sing all about it   (Chorus)', 'Hallelujah, I\'m gonna sing all about it.\nHallelujah, I\'m gonna shout all about it.\nHallelujah, can\'t live without it, praise God.\nNow I\'m living in a new creation,\nnow I\'m drinking from the well of salvation,\nnow there is no condemnation, praise God!', NULL),
(9, '0574', 'Hallelujah, what a Thought! Jesus full Salvation brought   (Victory,  yes, victory; Hallelujah I am free)', 'Hallelujah, what a thought!\nJesus full salvation brought,\nVictory, victory.\nLet the powers of sin assail,\nHeaven\'s grace can never fail,\nVictory, victory.\r\nVictory,  yes, victory;\nHallelujah! I am free\nJesus gives me victory.\nGlory, glory, Hallelujah\nHe is all in all to me.\r\nI am trusting in the Lord,\nI am standing on His word,\nVictory, victory.\nI have peace and joy within,\nSince my life is free from sin,\nVictory, victory.\r\nShout your freedom everywhere,\nHis eternal peace declare,\nVictory, victory.\nLet us sing it here below,\nIn the face of every foe,\nVictory, victory.\r\nWe will sing it on that shore,\nWhen this fleeting life is o\'er,\nVictory, victory.\nSing it here, ye ransomed throng,\nStart the everlasting song:\nVictory, victory.', NULL),
(9, '0575', 'Halt fest auf allen Wegen am teuren Gotteswort   (Das Wort kann Kraft dir geben, ist deines Weges Licht)', NULL, 'Halt fest auf allen Wegen,\nam teuren Gotteswort,\nes bringt dir reichen Segen,\nund ist ein sich\'rer Hort.\r\nDas Wort kann Kraft dir geben,\nist deines Weges Licht,\ndas Wort ist Geist und Leben,\ndas Wort vergehet nicht.\r\nNicht Gold und nicht Juwelen\nsind diesem Schatze gleich,\nes stillt den Durst der Seelen\nund macht die Ärmsten reich.\r\nEs wird die Jugend schützen,\nlehrt sie unsträflich sein,\ndie Schwachen wird es stützen,\nBetrübten Trost verleih\'n.\r\nEs rettet die Verlor\'nen,\nVerirrte ruft es heim,\nes ist dem Gottgebor\'nen\nwie lauter Honigseim.\r\nHalt fest zu allen Zeiten\nam teuren Gotteswort!\nEs wird dich sicher leiten\nzur off\'nen Himmelspfort\'.'),
(9, '0576', 'Halt mich treu, Herr Jesus, halt mich treu  -  Keep me true, Lord Jesus, keep me true   (Chorus)', 'Keep me true, Lord Jesus, keep me true,\nkeep me true, Lord Jesus, keep me true.\nThere\'s a race that i must ran,\nthere are victories  to be won.\nGive me power, every hour, to be true.', 'Halt mich treu, Herr Jesus, halt mich treu.\nHalt mich treu, Herr Jesus, halt mich treu.\nEinen Lauf hab\' ich zu geh\'n,\nmanchen Kampf noch zu besteh\'n.\nGib mir Kraft, die es schafft, halt mich treu!'),
(9, '0577', 'Halte ein und überlege, Sünder, o wo willst du hin   (Kehre um zu dem Erbarmer, dem Befreier Jesus Christ)', NULL, 'Halte ein und überlege,\nSünder, o wo willst du hin?\nDir graut selbst vor deinem Wege,\ndenn ein Abgrund endet ihn.\r\nKehre um zu dem Erbarmer,\ndem Befreier Jesus Christ!\nEr verstößt dich nicht, du Armer,\nkomm zu Ihm, so wie du bist!\r\nLang genug hast du gerungen,\nstets gebunden, stets beengt;\nhast den Feind doch nicht bezwungen\nund die Kette nicht gesprengt.\r\nO, das ist ein andres Leben,\nwenn man weiß: Ich bin befreit,\nmeine Sünden sind vergeben,\nmeinem Herrn bin ich geweiht.\r\nKomm! Der Herr hat Himmelsgaben\nfür die Seele, die Ihn liebt.\nKomm! Auch du kannst alles haben,\nwas Er hier den Seinen gibt!\r\nKannst du selbst dich nicht bewahren,\nnimm Ihn auf in Herz und Haus,\nund auch du wirst es erfahren:\nEine Kraft geht von Ihm aus.\r\nKomm und wirf dich vor Ihm nieder,\num, befreit aus deiner Haft,\ndann zu Seiner Ehre wieder\naufzusteh\'n in Seiner Kraft!'),
(9, '0578', 'Halte still, denn Gott wird für dich sorgen   (Schau hinweg, ja, schau hinweg auf Jesus)', NULL, 'Halte still, denn Gott wird für dich sorgen,\nhalte still, denn Gott wird bei dir sein,\nhalte still, und denke nicht an morgen,\nhalte still, Gott lässt dich nicht allein!\r\nSchau hinweg, ja, schau hinweg auf Jesus,\nEr, der immer schon die Seinen trug,\nschau hinweg, hinweg von deinen Sorgen,\nweil Sein Auge liebend auf dir ruht,\nSeine Hilfe, die ist uns genug!\r\nEs war Er, der zwei  Millionen Menschen\nwie ein Adler aus Ägypten trug,\nspeiste sie, gab Wasser aus dem Felsen,\nund als Vater macht\' Er alles gut.\r\nIch seh\' Jesus an dem Ufer stehen:\n"Kinder, habt ihr Essen?", Er dort spricht,\nich seh\' Seine Jünger zu Ihm kommen,\nseh\' sie speisen mit Ihm Brot und Fisch.\r\nSpürst du nicht, wie Er in Seiner Liebe\nwie ein Vater Sorge um uns trägt,\nEr ist immer noch "Jehova-Jireh"\nund "El Shaddai", den uns\'re Not bewegt.'),
(9, '0579', 'Hand in Hand mit Jesus kann ich sicher gehn  -  Anywhere with Jesus I can safely go   (Hand in Hand mit dem Herrn kann mir nichts geschehn)', 'Anywhere with Jesus I can safely go.\nAnywhere He leads me in this world below.\nAnywhere without Him dearest joys would fade.\nAnywhere with Jesus I am not afraid.\r\nAnywhere! anywhere! Fear I cannot know.\nAnywhere with Jesus I can safely go.\r\nAnywhere with Jesus I am not alone,\nother friends may fail me, He is still my own.\nThough His hand may lead me over dreary ways,\nanywhere with Jesus is a house of praise.\r\nAnywhere with Jesus I can go to sleep,\nwhen the dark’ning shadows round about me creep,\nknowing I shall waken nevermore to roam.\nAnywhere with Jesus will be home, sweet home.\r\n', 'Hand in Hand mit Jesus kann ich sicher geh\'n,\nwird Er doch im Leben alles recht verseh\'n.\nAber ohne Jesus seufzt mein Herz und klagt:\nHand in Hand mit Jesus bin ich unverzagt.\r\nHand in Hand mit dem Herrn kann mir nichts gescheh\'n.\nHand in Hand mit Jesus werd\' ich sicher geh\'n.\r\nHand in Hand mit Jesus bin ich nie allein.\nFreunde mögen scheiden, Er bleibt ewig mein.\nWenn Er mich auch manchmal in die Wüste bringt,\nHand in Hand mit Jesus jauchzt mein Herz und singt.\r\nHand in Hand Jesus geh ich ein zur Ruh\',\nschließen meine Augen sich im Tode zu.\nWenn ich dann erwache, werd\' ich bei Ihm sein.\nHand in Hand mit Jesus geht\'s zum Himmel ein.\r\nHand in Hand mit Jesus droben auf dem Thron.\nMühsam war die Arbeit, herrlich ist der Lohn.\nKöstlich ist\'s, zu ruhen nach dem Erdenleid,\nHand in Hand mit Jesus, in der Ewigkeit.'),
(9, '0580', 'Happy to be in this Place, happy to feel Your warm Embrace', 'Happy to be in this place,\nhappy to feel Your warm embrace,\nhappy to be in this place again. (2x)\r\nWe come worshipping You\nlonging to see You,\nknowing that You\'re always near.\nWe come worshipping You\nlonging to be with You,\nknowing that You will be here.\r\nKnowing that you will be here.\nKnowing that you will be here.', NULL),
(9, '0581', 'Harre meine Seele, harre des Herrn', NULL, 'Harre meine Seele, harre des Herrn!\nAlles Ihm befehle, hilft Er doch so gern!\nSei unverzagt, bald der Morgen tagt,\nund ein neuer Frühling  folgt dem Winter nach!\nIn allen Stürmen, in aller Not\nwird Er dich beschirmen, der treue Gott.\r\nHarre meine Seele, harre des Herrn!\nAlles Ihm befehle, hilft Er doch so gern!\nWenn alles bricht, Gott verlässt uns nicht;\ngrößer als der Helfer ist die Not ja nicht.\nEwige Treue, Retter in Not,\nrett’ auch meine Seele, Du treuer Gott!\r\nHarre meine Seele, harre des Herrn!\nAlles Ihm befehle, hilft Er doch so gern!\nBald höret auf unser Pilgerlauf\nund die Klagen schweigen, Jesus nimmt uns auf.\nNach allen Leiden, nach aller Not\nFolgen ew\'ge Freuden; gelobt sei Gott!'),
(9, '0582', 'Hast du dich früh dem Herrn geweiht   (Drum blicke nur hinauf zu deinem Herrn)', NULL, 'Hast du dich früh dem Herrn geweiht,\nwird schön dein Leben sein,\ndenn die versäumte Gnadenzeit,\nholt man nicht wieder ein!\r\nD\'rum blicke nur hinauf zu deinem Herrn,\ndenn schnell vergeht die Zeit,\nJesus gibt dir auch heute noch so gern,\nFried\', Freud\' und Seligkeit.\r\nSehnt sich dein Herz nach Glück und Heil,\nsuch\'s nur bei Jesus Christ\',\nein ganzer Himmel ist dein Teil,\nwenn du Sein Eigen bist.\r\nWo man die Frühlingssaat verträumt,\nwird keine Ernte sein,\nwas bei der Aussaat wird versäumt,\nholt man im Herbst nicht ein!'),
(9, '0583', 'Hast du dich je verlorn in dem Geiste von Jesus', NULL, 'Hast du dich je verlor\'n im Geiste von Jesus?\nSprachst du mit dem, der in dir wohnt?\nDann steh\'n dir alle Geheimnisse offen,\nhörst du Seine Stimme, die zu dir spricht:\n"Dein Werk ist Mein Werk, was du sprichst bin Ich!\nIch bin\'s, der in dir Unmögliches wirkt!"'),
(9, '0584', 'Hast du eine Sorgenlast, die dir raubet Fried und Rast', NULL, 'Hast du eine Sorgenlast,\ndie dir raubet Fried\' und Rast,\nJesu Herz dir offen steht:\nMach aus Sorgen ein Gebet!\r\nGlühet tief in deiner Brust\nirdischer Hoffnung süße Lust,\nachte fein, wo Jesus geht,\nwerde stille im Gebet!\r\nBist du traurig und allein,\ndrückt dich bitt\'re Seelenpein,\ndein Erbarmer dich versteht;\nsuche Tröstung im Gebet!\r\nDroht des Feindes Macht und List,\nflieh zu dem, der Sieger ist,\nund von Seiner Majestät\nziehe Kraft an im Gebet!\r\nWillst du Jesu Diener sein,\nsorg\' im stillen Kämmerlein,\ndass Sein Geist dich rein umweht,\nhole Weisung im Gebet!\r\nWas dein Herze auch bewegt,\nob sich Schmerz, ob Wonne regt,\nflieh zu Jesus früh und spät,\nmach aus allem ein Gebet!'),
(9, '0585', 'Hast du heute schon danke gesagt', NULL, 'Hast du heute schon danke gesagt\nFür so viel schöne Sachen?\nHast du heute schon danke gesagt,\nGott will Dir Freude machen!\r\nZum Wohnen ein Haus,\nZum Schlafen ein Bett,\nDie Freunde zum Spielen sind so nett.\r\nUnd weißt du auch schon,\nDass Jesus dich mag,\nDass er mit dir geht von Tag zu Tag.\r\nDas Brot auf dem Tisch,\nDie Milch in dem Krug\nUnd Kleider, die haben wir genug.'),
(9, '0586', 'Hast du heute schon Danke gesagt', NULL, 'Hast du heute schon Danke gesagt\nfür soviel schöne Sachen?\nHast du heute schon Danke gesagt?\nGott will dir Freude machen !\r\nZum Wohnen ein Haus,\nzum Schlafen ein Bett,\nzum Spielen die Freunde\nsind ja so nett. Ja!\r\nDas Brot auf dem Tisch,\ndie Milch in dem Krug\nund Kleider die haben\nwir auch genug. Ja!\r\nUnd weißt du auch schon,\ndass Jesus dich mag,\ndass Er mit uns geht\nvon Tag zu Tag? Ja!'),
(9, '0587', 'Hast du im Leben auch viel Versuchung  -  Tempted and tried we’re oft made to wonder   (Es kommt der Tag, dann wird Sonne scheinen)', 'Tempted and tried we’re oft made to wonder\nwhy it should be thus all the day long.\nWhile there are others living about us,\nnever molested tho\' in the wrong.\r\nFarther along we’ll know all about it,\nfarther along we’ll understand why.\nCheer up, my brother, live in the sunshine,\nwe’ll understand it all by and by.\r\nWhen death has come and taken our loved ones,\nit leaves our home so lonely and drear.\nThen do we wonder why others prosper,\nliving so wicked year after year.\r\nFaithful till death said our loving Master,\na few more days to labor and wait.\nToils of the road will then seem as nothing,\nas we sweep thru the beautiful gate.\r\nWhen we see Jesus coming in glory,\nwhen He comes from His home in the sky.\nThen we shall meet Him in that bright mansion,\nwe\'ll understand it all by and by.', 'Hast du im Leben auch viel Versuchung,\nquält dich der Feind bei Tag und bei Nacht.\nDu siehst wie and\'re in Freuden leben\nund jedem immer die Sonne lacht.\r\nEs kommt der Tag, dann wird Sonne scheinen,\ndann wirst im Licht dein Leben du seh\'n;\ndoch liebes Herz, du brauchst ja nicht weinen,\ndroben bei Jesus wirst du\'s versteh\'n.\r\nKommt dann der Tod und nimmt dir die Lieben\nund du bist plötzlich so ganz allein.\nAnd\'re sie haben Reichtum und Ehre,\nnur du trägst Sorgen, tagaus, tagein.\r\nTreu bis zum Tode, sagt unser Meister,\nnur noch ein Weilchen wirken für Ihn.\nAlle Probleme werden verschwinden,\nwenn wir auf ewig sind dann bei Ihm.\r\nWenn wir dann sehen unseren Jesus,\nwenn Er erscheint in Wolken so hell,\nwir werden treffen unseren Meister,\nund dann verstehen wieso, warum.'),
(9, '0588', 'Hast du je erfahren Jesu Retterkraft  -  Have you been to Jesus for the cleansing Power   (Bist du rein durch das Blut)   (6 Strophen)   [Nieste]', 'Have you been to Jesus for the cleansing power?\nAre you washed in the blood of the Lamb?\nAre you fully trusting in His grace this hour?\nAre you washed in the blood of the Lamb?\r\nAre you washed in the blood,\nin the soul cleansing blood of the Lamb?\nAre your garments spotless? Are they white as snow?\nAre you washed in the blood of the Lamb?\r\nAre you walking daily by the Saviour\'s side?\nAre you washed in the blood of the Lamb?\nDo you rest each moment in the Crucified?\nAre you washed in the blood of the Lamb?\r\nWhen the Bridegroom cometh will your robes be white?\nAre you washed in the blood of the Lamb?\nWill your soul be ready for the mansions bright,\nAnd be washed in the blood of the Lamb?\r\nLay aside the garments that are stained with sin,\nand be washed in the blood of the Lamb.\nThere\'s a fountain flowing for the soul unclean,\no be washed in the blood of the Lamb!\r\n\r\n', 'Hast du je erfahren Jesu Retterkraft?\nBist du rein durch des Heilandes Blut?\nUnd vertraust du völlig Seiner Gnadenmacht?\nBist du rein durch des Heilandes Blut?\r\nBist du rein durch das Blut,\nbist du rein durch des Heilandes Blut?\nIst dein Kleid schon helle, ist es weiß wie Schnee?\nBist du rein durch des Heilandes Blut?\r\nWandelst jeden Tag du an des Heiland\'s Seit\'?\nBist du rein durch des Heilandes Blut?\nRuhst in Ihm du jeden Augenblick der Zeit?\nBist du rein durch des Heilandes Blut?\r\nWenn der Bräut\'gam kommt, ist dann dein Kleid schneeweiß?\nBist du rein durch des Heilandes Blut?\nIst dein Herz bereit für Seine Herrlichkeit?\nBist du rein durch des Heilandes Blut?\r\nLege ab die Kleider, so von Sünd\' befleckt,\nwerde rein durch des Heilandes Blut!\nFlieh zur Quelle, die all deinen Schaden deckt,\nund sei rein durch des Heilandes Blut!\r\nHältst du treulich wachend bei dem Kreuze stand?\nBist du rein durch des Heilandes Blut?\nGehst du kindlich gläubig stets an Jesu Hand?\nBist du rein durch des Heilandes Blut?\r\nSo entsag\' der Sünde, lieb den Herrn allein,\nwerde rein durch des Heilandes Blut!\nSieh der Brunnen fließet, tauch\' dich tief hinein,\nwerde rein durch des Heilandes Blut!'),
(9, '0589', 'Hast du je schon gehört, wie die Sonne aufging   (Große Dinge, die tut Gott auf Seine Weise)', NULL, 'Hast du je schon gehört, wie die Sonne aufging,\nhast du je schon gehört, wie der Tag neu anfing,\nhast du je schon gehört, wie die Erde sich dreht,\nja und wie sich die Erde bewegt?\r\nGroße Dinge, die tut Gott auf Seine Weise,\nGottes große Dinge, sie geschehen leise.\nGroße Dinge, die tut Gott auf Seine Weise,\nGottes große Dinge, sie geschehen leise.\r\nHast du je schon gehört, wie der Frühling begann,\nhast du je schon gehört, wie das Leben wiederkam?\nStaunend stands du davor, ja und doch traf dein Ohr\nnicht ein einziger, einziger Ton.\r\nHast du Jesus geseh\'n wie auf Erden Er war?\nHast du Jesus geseh\'n auf dem Weg nach Golgatha?\nWie ein Lamm war Er still, sprach nur:\n"Vater, erfüll\' Deinen Willen, oh Vater in Mir!"\r\nWeißt du noch als das Lamm das letzte Siegel brach,\nja dann war in dem Himmel die große Stille da.\nJetzt kommst du in die Ruh\'\nund dann flüstert dir Gott Seine großen Geheimnisse zu.\r\nBald, ja bald, Jesus kommt! Weißt du noch was Er sprach?\nBald, ja bald, Jesus kommt wie ein Dieb in der Nacht.\nJa, die Welt wird nichts hören, ja sie lässt sich nicht stören\ndurch das Kommen, das Kommen des Herrn.'),
(9, '0590', 'Hast du Jesu Ruf vernommen  -  Hark, the Voice of Jesus crying   (Hast du Jesu Ruf vernommen: Wer will heut zur Arbeit gehn)', 'Hark, the voice of Jesus crying,\n"Who will go and work today?\nFields are ripe and harvests waiting,\nwho will bear the sheaves away?"\nLong and loud the Master calls us,\nrich reward He offers free.\nWho will answer, gladly saying,\n"Here am I, send me, send me"?\r\nHark, the voice of Jesus crying,\n"Who will go and work today?\nFields are ripe and harvests waiting,\nwho will bear the sheaves away?"\r\nIf you cannot cross the ocean,\nand the distant lands explore,\nyou can find the lost around you,\nyou can help them at your door.\nIf you cannot give your thousands,\nyou can give the widow\'s mite;\nwhat you truly give for Jesus,\nwill be precious in His sight.\r\nIf you cannot be the watchman\nstanding high on Zion\'s wall,\npointing out the path to heaven,\noff\'ring life and peace to all.\nWith your pray\'rs and with your bounties\nyou can do what heav\'n demands.\nYou can be like faithful Aaron,\nholding up the prophet\'s hands.\r\nLet none hear you idly saying,\n"There is nothing I can do,"\nwhile the lost of earth are dying,\nand the Master calls for you.\nTake the task He gives you gladly,\nlet His work your pleasure be.\nAnswer quickly when He calls you,\n"Here am I, send me, send me."', 'Hast du Jesu Ruf vernommen:\n"Wer will heut\' zur Arbeit geh\'n?\nSeht, die Ernte ist gekommen,\nreif im Feld die Ähren steh\'n."\nAllen gilt des Meisters Frage,\nDer einst lohnt in Ewigkeit;\no wer ist, der zu Ihm sage:\n"Sende mich, ich bin bereit!"?\r\nHast du Jesu Ruf vernommen:\n"Wer will heut\' zur Arbeit geh\'n?\nSeht, die Ernte ist gekommen,\nreif im Feld die Ähren steh\'n."\r\nKannst du nicht das Meer durcheilen,\narmen Heiden zugewand:\nAuch bei uns noch viele weilen,\ndenen Jesu nicht bekannt.\nKannst du wenig nur verwenden,\nsollt es nur ein Scherflein sein:\nAuch die kleinste deiner Spenden\nist dem Heiland nicht zu klein.\r\nKannst du nicht mit heil\'gem Feuer\nreden, wie einst Paulus tat:\nSagen kannst du, wie dein treuer\nHeiland dich erlöset hat.\nKannst du nicht die Sünder rühren,\ndass sie dem Gericht entflieh\'n:\nKleine Kindlein kannst du führen\nzu dem Kinderfreunde hin.\r\nWer du bist, o lass dich werben!\nWehe, wer den Ruf verwarf,\nwährend Seelen rings verderben\nund der Meister dein bedarf!\nGanz dem Herrn dich hinzugeben,\nsei dir Lust und Seligkeit.\nSag Ihm ohne Widerstreben:\nSende mich, ich bin bereit!"'),
(9, '0591', 'Hast du keinen Raum für Jesus  -  Have you any Room for Jesus   (Wer will ganz sich Jesu weihen)', 'Have you any room for Jesus,\nHe who bore your load of sin?\nAs He knocks and asks admission,\nsinner, will you let Him in?\r\nRoom for Jesus, King of Glory!\nHasten now, His Word obey.\nSwing the heart’s door widely open.\nBid Him enter while you may.\r\nRoom for pleasure, room for business.\nBut for Christ, the Crucified,\nnot a place that He can enter,\nin the heart for which He died?\r\nHave you any room for Jesus,\nas in grace He calls again?\nOh, today is time accepted,\nt’morrow you may call in vain.\r\nRoom and time now give to Jesus,\nsoon will pass God’s day of grace.\nSoon your heart left cold and silent,\nand your Saviour’s pleading cease.', 'Hast du keinen Raum für Jesus?\nSieh, Er will dein Heiland sein!\nHorch, Er klopft an deiner Türe!\nSünder, lässt du Ihn nicht ein?\r\nWer will ganz sich Jesu weihen?\nWer tut auf des Herzens Tür?\nSeele, du wirst\'s nie bereuen,\nlass Ihn ein, Er schenkt sich dir!\r\nRaum hast du für eitle Dinge,\nnur für deinen Jesum nicht!\nAch willst du dich Dem verschließen,\nDem um dich das Herze bricht?\r\nHast du keine Zeit für Jesus,\nDer vor deiner Türe steht?\nBrauche doch dein sel\'ges Heute,\nmorgen schon mag\'s sein zu spät!\r\nGib dein Alles hin an Jesus,\ndenn die Gnadenzeit eilt sehr;\nkäme des Gerichtes Stunde,\nträfe dich das Urteil schwer!'),
(9, '0592', 'Have you been baptized into the Body   (Are you in the church, triumphant)', 'Have you been baptized into the Body?\nBaptized with the Holy Ghost;\nThere is but one way to enter in it,\nJust as they did on Pentecost.\r\nAre you in the church, triumphant?\nAre you in the Saviour\'s Bride?\nCome and be baptized into the Body,\nAnd forevermore abide.\r\nThere is but one Church, Bride or Body,\nAnd into it we\'re all baptized;\nBy the one, true, promised Holy Spirit;\nThough by the world we\'re all despised.\r\nEvery creed has claimed to be the Body,\nBut the "plumb line" proved untrue\nAll their dreams, for God has so determined\nTo bring His Son\'s true Bride to view.\r\nMany thought that they were in the Body,\n\'Till the Holy Ghost had come;\nWhen the Word of God was opened to them,\nThey entered in, and yet there\'s room.\r\nThose who died before the Holy Spirit\nCame upon us from on high,\nMay, by faith with Saints of old departed,\nArise to meet Him in the sky.\r\nWhen the Bridegroom comes, will you be ready;\nAnd your vessel all filled and bright?\nYou will be among the foolish virgins\nIf you do not walk in the light.', NULL),
(9, '0593', 'Have Your Way Holy Spirit and fill our Hearts', 'Have Your way, have Your way.\nHoly Spirit fill our hearts\nand have Your way.\nAs we wait, and as we pray.\nSpeak Your word into our hearts\nand have Your way', '(Habe deinen Weg, Habe deinen Weg\nHeiliger Geist erfülle unsere Herzen\nund habe deinen Weg.\nWährend wir warten, und während wir beten.\nSprich dein Wort zu unseren Herzen\nund habe deinen Weg)'),
(9, '0594', 'Hält dein Anker fest, in des Lebens Sturm  -  Will your Anchor hold in the Storms of Life   (Ja, unser Anker hält ewig fest)', 'Will your anchor hold in the storms of life,\nwhen the clouds unfold their wings of strife?\nWhen the strong tides lift and the cables strain,\nwill your anchor drift, or firm remain?\r\nWe have an anchor that keeps the soul\nsteadfast and sure while the billows roll.\nFastened to the Rock which cannot move,\ngrounded firm and deep in the Saviour’s love.\r\nIt is safely moored, ’twill the storm withstand,\nfor ’tis well secured by the Saviour’s hand.\nAnd the cables, passed from His heart to mine,\ncan defy that blast, through strength divine.\r\nIt will surely hold in the straits of fear,\nwhen the breakers have told that the reef is near.\nThough the tempest rave and the wild winds blow,\nnot an angry wave shall our bark o’erflow.\r\nWhen our eyes behold through the gath’ring night\nthe city of gold, our harbor bright,\nwe shall anchor fast by the heav’nly shore,\nwith the storms all past forevermore.', 'Hält dein Anker fest, in des Lebens Sturm,\nwenn die Wolken droh\'n, Finsternis ringsum?\nWenn die Flut sich hebt und das Tau sich spannt,\ntreibt dein Anker weg, oder hält er stand?\r\nJa, unser Anker hält ewig fest!\nob Wellen droh\'n, und der Sturmwind bläst.\nSicher in dem Fels, verborgen tief,\nist gegründet er, in des Heilands Lieb\'.\r\nJa, der Anker hält, denn des Meisters Hand\nhat in Seiner Macht alles dran gewandt.\nWenn die Strömung zieht, scharf die Kette strafft,\nbleibt gesichert er doch in Gottes Kraft.\r\nJa, der Anker hält auch in Furcht und Not,\nwenn der Strudel hier und das Riff dort droht.\nOb der Mast sich biegt und das Schanzkleid bricht:\nNein, die Flut verschlingt, doch das Fahrzeug nicht.\r\nWenn dem Auge dann durch die finst\'re Nacht\neinst das helle Licht aus dem Hafen lacht,\nwerfen Anker wir an dem ew\'gen Strand,\nwo kein Sturm uns trifft, in des Vaters Land.'),
(9, '0595', 'Hätte ich mehr von Jesus nur  -  More about Jesus would I know   (Mehr, mehr von dem Heiland)', 'More about Jesus would I know,\nmore of His grace to others show.\nMore of his saving fullness see,\nmore of His love who died for me.\r\nMore, more about Jesus,\nmore, more about Jesus.\nMore of His saving fullness see,\nmore of His love who died for me.\r\nMore about Jesus let me learn,\nmore of his holy will discern.\nSpirit of God, my teacher be,\nshowing the things of Christ to me.\r\nMore about Jesus in His Word,\nholding communion with my Lord.\nHearing his voice in ev\'ry line,\nmaking each faithful saying mine.\r\nMore about Jesus on his throne,\nriches in glory all His own.\nMore if His kingdom\'s sure increase,\nmore of His coming, Prince of peace.', 'Hätte ich mehr von Jesus nur!\nFolgte ich mehr des Heilands Spur!\nKennte ich mehr des Heilands Huld,\nmehr Seine Liebe und Geduld!\r\nMehr, mehr von dem Heiland!\nMehr, mehr von dem Heiland!\nMehr möcht\' ich seh\'n das stille Lamm,\nmehr möcht\' ich steh\'n am Kreuzesstamm.\r\nMehr von dem Heiland möcht\' ich seh\'n\nund Seinen zarten Wink versteh\'n.\nOhne Ihn bin ich arm und leer,\nEr nur allein ist mein Begehr.\r\nMehr von dem Heiland hätt\' ich gern,\num zu erkennen Ihn, den Herrn,\nmehr von des Heilgen Geistes Kraft,\ndie Jesu Leben in uns schafft!\r\nMehr von dem Heiland, bis zuletzt\nEr mich ins Vaterhaus versetzt!\nO welches Glück, wenn dort im Licht\nich Ihn darf schau\'n von Angesicht!'),
(9, '0596', 'He became me, so that I might become Him by Grace   (Chorus)', 'He became me,\nso that I might become Him by grace.\nHe became me,\nso that I might become Him by grace.\nFor He took my place,\nso that I through His love could take His.\nHe became me,\nso that I might become Him by grace.', '(Er wurde wie ich,\nso dass ich durch Gnade wie Er werden kann.\nEr wurde wie ich,\nso dass ich durch Gnade wie Er werden kann.\nDenn Er nahm meinen Platz ein,\ndamit ich durch Seine Liebe Seinen einnehmen konnte.\nEr wurde wie ich,\nso dass ich durch Gnade wie Er werden kann.)'),
(9, '0597', 'He came down! He came down on the great Ohio River', 'He came down! He came down!\nOn the great Ohio River,\nHe came down.\nTo lead His Bride,\nthrough His perfect Word,\nback to the Tree of Life.\nOh, rest little Bride, rest,\nfor He came down.\r\nHe is here! He is here!\nPraise and joy for evermore,\nfor He is here.\nThe Message of the prophet was\nto declare \'The Lord is here!\'\nOh, rest little Bride, rest,\nfor He is here.\r\nAll is well, all is well,\nI have heard the message\n"Shalom" and all is well.\nThere is a place\nof perfect rest\nbehind the inner veil.\nSo, rest, little Bride,\nrest, for all is well!', NULL),
(9, '0598', 'He counts the stars one and all   (He knows my name)', 'He counts the stars one and all,\nHe knows how much sand is on the shore,\nHe sees every sparrow that falls.\nHe made the mountains and the seas,\nHe\'s in control of everything,\nof all creatures great and small.\r\nHe knows my name,\nevery step that I take\nevery move that I make,\nevery tear that I cry\nand He knows my name.\nWhen I\'m overwhelmed by the pain\nand can\'t see the light of day,\nI know I\'ll be just fine,\n\'cause He knows my name.\r\nI don\'t know what tomorrow will bring,\nI can\'t tell you what\'s in store,\nI don\'t know a lot of things.\nI don\'t have all the answers\nto the questions of life,\nbut I know in whom I believe.', NULL),
(9, '0599', 'He gives me satisfying Peace   (Chorus)', 'He gives me satisfying peace, this wonderful Saviour.\nHe gives me joys that never cease, this wonderful Lord.\n\'Tis only Jesus who can bless with everlasting happiness,\nand he\'s my Saviour this wonderful Lord.', NULL),
(9, '0600', 'He is alive and well   (Chorus)', 'He is alive and well,\nliving in me to tell\nthe world that He is the same.\nHe is the same yesterday,\ntoday and for ever.\nJesus is alive and well.', NULL);
INSERT INTO song_list (LISTID, NUM, NAME, TEXT_EN, TEXT_DE) VALUES
(9, '0601', 'He is Jehovah, God of creation ... the great I AM   (Sing hallelujah, sing hallelujah)', 'He is Jehovah, God of creation.\nHe is Jehovah, Lord God Almighty.\nThe balm of Gilead, the Rock of Ages.\nHe is Jehovah, the God that healeth thee.\r\nSing hallelujah, sing hallelujah,\nsing hallelujah, sing hallelujah.\nHe is Jehovah, Lord God Almighty.\nHe is Jehovah, the God that healeth thee\r\nHe is the great I AM, the God of Abraham.\nJehovah Shalom, the God of peace I AM.\nThe God of Israel, the everlasting One.\nHe is Jehovah, the God that healeth thee.\r\nHe\'s your provider, Jehovah Jireh.\nGod of Salvation, God of Messiah.\nThe Son He sent to you, He testified of Him.\nHe is Jehovah, the God that healeth thee.', NULL),
(9, '0602', 'He is our Peace   (2 Chorusse)', 'He is our peace\nwho has broken down every wall,\nHe is our peace, He is our peace.\nHe is our peace\nwho has broken down every wall,\nHe is our peace, He is our peace.\r\nCast all you cares on Him,\nfor He cares for you,\nHe is our peace, He is our peace.\nCast all you cares on Him,\nfor He cares for you,\nHe is our peace, He is our peace.', '(ER ist unser Friede, der jede Mauer durchbrochen hat\nER ist unser Friede)\r\nWirf alle deine Sorgen auf IHN\ndenn ER sorgt für dich\nER ist unser Friede'),
(9, '0603', 'He left the Splendour of Heaven   (If that isn\'t love, the Ocean is dry)', 'He left the splendour of Heaven,\nknowing His destiny\nwas the lonely hill of Calvary\nwhere He laid down His life for me.\r\nIf that isn\'t love,\nthe ocean is dry,\nthere\'s no stars in the sky,\nand the sparrow can\'t fly.\r\nIf that isn\'t love,\nthen heaven\'s a myth,\nthere\'s no feeling like this,\nif that isn\'t love.\r\nEven in death He remembered\nthe thief hanging by His side.\nHe spoke with love and compassion,\nthen He took Him to paradise.', NULL),
(9, '0604', 'He paid the Debt He did not owe', 'He paid the debt He did not owe,\nI owed a debt I could not pay,\nI needed someone to wash my sins away\nand now I sing a brandnew song.\nAmazing grace all day long,\nChrist Jesus paid the debt that I could never pay.\r\nHe paid the debt at Calvary,\nHe cleansed my soul and set me free,\nI\'m glad that Jesus did all my sins erase,\nI now can sing a brandnew song.\nAmazing grace all day long,\nChrist Jesus paid the debt that I could never pay.\r\nOne day He\'s coming back for me\nto live with Him eternally.\nWon\'t it be glory to see Him on that day!\nI then will sing a brandnew song.\nAmazing grace all day long,\nChrist Jesus paid the debt that I could never pay.', 'Er bezahlte die Schulden, die er nicht schuldete,\nIch schuldete eine Schuld, die ich nicht bezahlen konnte,\nIch brauchte jemanden, der meine Sünden wegwäscht\nund jetzt singe ich ein neues Lied.\nErstaunliche Gnade, den ganzen Tag lang,\nChristus Jesus bezahlte die Schuld, die ich nie bezahlen konnte.\r\nEr hat die Schuld auf Golgatha bezahlt,\nEr hat meine Seele gereinigt und mich frei gemacht,\nIch bin froh, dass Jesus alle meine Sünden getilgt hat,\nIch kann jetzt ein neues Lied singen.\nErstaunliche Gnade, den ganzen Tag lang,\nChristus Jesus bezahlte die Schuld, die ich nie bezahlen konnte.\r\nEines Tages wird er zu mir zurückkommen\num mit Ihm ewig zu leben.\nWird es nicht herrlich sein, ihn an diesem Tag zu sehen!\nDann werde ich ein ganz neues Lied singen.\nErstaunliche Gnade, den ganzen Tag lang,\nChristus Jesus bezahlte die Schuld, die ich nie bezahlen konnte.'),
(9, '0605', 'He that dwelleth in the secret Place   (Psalm 91)', 'He that dwelleth in the secret place,\nof the most high,\nshall abide under the shadow\nof the Almighty.\nI will say of the Lord,\nHe is my refuge and my fortress,\nmy God, in Him will I trust.\r\nHe shall cover thee with His feathers,\nand under His wings shalt thou trust.\nHis truth shall be thy shield, and buckler.\nHe that dwelleth in the secret place,\nof the most high,\nshall abide under the shadow,\nof the Almighty.', NULL),
(9, '0606', 'He wasn\'t looking at me   (Chorus)', 'He wasn\'t looking at me, when He took me in.\nHe wasn\'t looking at my heart, that was black by sin.\nHe was looking at the blood flowing rich and free,\nThat precious blood, that covers me.', 'Er schaute nicht auf mich, als Er mich hinein brachte\nEr schaute nicht auf mein Herz das schwarz von Sünde war\nEr schaute aus das Blut, das reich und frei floss\ndas kostbare Blut, daas mich bedeckt'),
(9, '0607', 'He\'s Alive and Well', 'He\'s alive and well\nliving in me to tell\nThe world, that He is the Same\nHe\'s the same yesterday\nToday and Foreever\nJesus is alive and well\r\nThe Same Jesus Who died\nOn the cross crucified\nHe\'s alive in our hearts today\nResurrected agian\nIn a body without sin\nPraise God He\'s alive and well', '(Er ist lebendig und gut\nEr lebt in mir und sagt\nDer Welt, dass er derselbe ist\nEr ist derselbe gestern\nHeute und in Ewigkeit\nJesus ist lebendig und wohlauf)\r\nDerselbe Jesus, der gestorben ist\nAm Kreuz gekreuzigt\nEr ist heute in unseren Herzen lebendig\nWieder auferstanden\nIn einem Körper ohne Sünde\nGelobt sei Gott, er lebt und ist gesund'),
(9, '0608', 'He\'s God', 'When I come into His presence\nI humble myself,\nlift up both my hands,\nand I began to worship Him,\nI worship Him.\r\nFor all He\'s done for me,\nredeemed and set me free,\nand because, just because He\'s God.\r\nWhen I come into His presence\nI humble myself,\nremembering what He\'s done,\nthe victories He\'s won,\nso I\'ll praise Him,\nI\'ll praise Him.', 'Wenn ich in Seine Gegenwart komme\ndemütige ich mich,\nerhebe meine beiden Hände,\nund fange an, ihn anzubeten,\nIch bete Ihn an.\r\nFür alles, was er für mich getan hat,\nmich erlöst und befreit hat,\nund weil, einfach weil er Gott ist.\r\nWenn ich in Seine Gegenwart komme\ndemütige ich mich,\nund erinnere mich daran, was Er getan hat,\ndie Siege, die er errungen hat,\nso werde ich Ihn preisen,\nIch werde Ihn loben.'),
(9, '0609', 'He\'s got it all in Control', 'He\'s got it all in control.\nHe\'s got it all in control.\nHe\'s put that reassurance\nway down in my soul.\nHe\'s got it all in control.\r\nI\'ve put my life in His hands.\nI\'ve put my life in His hands.\nSo every road I walk down,\nI\'m sure is in His plan.\n\'Cause I\'ve put my life in His hands.\r\nHe holds the stars in the sky.\nHe holds the land back from the sea.\nIf He can do all of that,\nsurely He can take care\nof you and me!\r\nMy father knows what I need\nMy father knows what I need\nIn everything I go through\nHe knows whats best for me\nMy father knows what I need', '(ER hat alles unter Kontrolle\nER legte diese Sicherheit tief in meine Seele...)\r\n(Ich habe mein Leben in Seine Hand gelegt\nJeder Weg den ich gehe ist sicher in Seinem Plan...)\r\nER hält die Sterne am Himmel\nER trennt das Land von der See\nWenn ER all dieses tun kann, kann ER sicher für\ndich und mich sorgen\r\nMein Vater weiß, was ich brauche\nIn allem was ich durchmache\nEr weiß, was das Beste für mich ist...'),
(9, '0610', 'Heal me oh Lord', 'Heal me Oh Lord\nAnd I will be healed\nSave me and I will be saved\nHeal me Oh Lord\nAnd I will be healed\nFor You are the One I praise\nYou are the One I praise', '(Heile mich, oh Herr\nUnd ich werde geheilt\nRette mich und ich werde gerettet\nHeile mich, oh Herr\nUnd ich werde geheilt\nDenn Du bist derjenige, den ich lobe\nDu bist derjenige, den ich lobe )'),
(9, '0611', 'Healer of the Broken Pieces', 'Nothing compares,  Lord,\nTo knowing You\nAnd seeing what\nThe grace of God can do\nYou faithfully sought me\nAnd called me Your own\nThen made a way to bring\nMy wandering heart back home\r\nHealer of the broken pieces\nYou touched my heart and mage it new\nNow my whole life I surrender\nLay it down before the Mender\nLord,  I give my heart to You\nLove that sought before I knew You\nHas brought me near to where You are Now live to praise You\nEver may I praise You\nHealer of my heart\r\nYou are the Healer,  Healer of my heart\nThe Maker and the God of all we are\nI was the broken vessel in Your hands\nBut You looked beyond the hurt\nAnd made me whole again', NULL),
(9, '0612', 'Healing Is Here', 'Healing is here , healing is here\nHealing is here and I receive it\nHealing is here , healing is here\nHealing is here and I believe it\r\nI reach my hands to the heavens\nI lift my eyes where my help comes from\nI look to You my rock my healer\nI trust in You\r\nFreedom is here , freedom here\nFreedom is here and I receive it\nFreedom is here , freedom is here\nfreedom is here and I believe it\r\nSickness can′t stay any longer\nYour perfect love is casting out fear\nYou are the God of all power\nAnd it is Your will that my life is healed\r\nDepression can′t stay any longer\nYour perfect love is casting out fear\nYou are the God of all power\nAnd it is Your will that my life is healed\r\nTroubles can′t stay any longer\nYour perfect love is casting out fear\nYou are the God of all power\nAnd it is Your will that my life is healed\r\nI reach my hands to the heavens\nI lift my eyes where my help comes from\nI look to You my rock my healer\nI trust in You\r\nJesus is here , Jesus is here\nJesus is here and I believe it\nJesus is here , Jesus is here\nJesus is here and I Jesus it', '(Heilung ist hier, Heilung ist hier\nHeilung ist hier und ich empfange sie\nHeilung ist hier, Heilung ist hier\nDie Heilung ist hier und ich glaube)\r\nIch strecke meine Hände zum Himmel\nIch erhebe meine Augen, woher meine Hilfe herkommt\nIch schaue zu Dir mein Fels mein Heiler\nIch vertraue auf Dich\r\n(Freiheit ist hier, Freiheit ist hier\nFreiheit ist hier und ich empfange sie\nFreiheit ist hier, Freiheit ist hier\nDie Freiheit ist hier und ich glaube)\r\nDie Krankheit kann nicht länger bleiben\nDeine vollkommene Liebe vertreibt die Angst\nDu bist der Gott aller Macht\nUnd es ist Dein Wille, dass mein Leben geheilt wird\r\nDie Depression kann nicht länger bleiben\nDeine vollkommene Liebe vertreibt die Angst\nDu bist der Gott aller Macht\nUnd es ist Dein Wille, dass mein Leben geheilt wird\r\nDie Probleme können nicht länger bleiben\nDeine vollkommene Liebe vertreibt die Angst\nDu bist der Gott aller Macht\nUnd es ist Dein Wille, dass mein Leben geheilt wird\r\nIch strecke meine Hände zum Himmel\nIch erhebe meine Augen, woher meine Hilfe herkommt\nIch schaue zu Dir mein Fels mein Heiler\nIch vertraue auf Dich\r\n(Jesus ist hier, Jesus ist hier\nJesus ist hier und ich empfange sie\nJesus ist hier, Jesus ist hier\nJesus ist hier und ich glaube)'),
(9, '0613', 'Hear the blessed Saviour calling the oppressed   (Come unto Me, I will give you Rest)', 'Hear the blessed Saviour calling the oppressed,\n"Oh ye heavy-laden, come to Me and rest.\nCome, no longer tarry, I your load will bear,\nbring Me ev\'ry burden, bring Me ev\'ry care."\r\nCome unto Me, I will give you rest,\ntake My yoke upon you, Hear Me and be blest.\nI am meek and lowly, come and trust My might.\nCome, My yoke is easy, and My burden\'s light.\r\nAre you disappointed, wand\'ring here and there,\ndragging chains of doubt and loaded down with care?\nDo unholy feelings struggle in your breast?\nBring your case to Jesus, He will give you rest.\r\nStumbling on the mountains dark with sin and shame,\nstumbling tow\'rd the pit of hell\'s consuming flame.\nBy the pow\'rs of sin deluded and oppressed,\nHear the tender Shepherd, "come to Me and rest."\r\nHave you by temptation often conquered been,\nhas a sense of weakness brought distress within?\nChrist will sanctify you, if you\'ll claim His best,\nin the Holy Spirit, He will give you rest.', NULL),
(9, '0614', 'Heavenly Father, I am overcome with gratitude to Thee   (Help me raise her with Love. Teach her Respect)   (New Parents Prayer)', 'Heavenly father, I am overcome with gratitude to Thee.\nFor giving us this child who humbles me.\nI hold her tiny hand in mine.\nThankful tears come in my eyes.\nThis blessing\'s such a great responsibility.\nAs my weakness feel magnified, I ask for strength to do what\'s right.\r\nHelp me raise her with love. Teach her respect.\nI\'ll read Thy words of truth to her and pray Thou will protect\nHer from all fear. Fill her with hope.\nLet me know when to support her and let go.\nHelp me raise her with love.\r\nHeavenly father, as our precious child is falling fast asleep, I\nsense your angels guard us lovingly.\nThough I\'m weary and so tired, I am strengthened by her smile.\nLet me live my life to show my love to Thee.\nAs I learn to purity my heart, let me lead my child to where Thou art.', NULL),
(9, '0615', 'Heb dich auf und schwebe in das Sonnenlicht', NULL, 'Heb\' dich auf und schwebe in das Sonnenlicht,\ngebrauche deine Schwingen: Lobpreis und Gebet!\nFlieg\', flieg\', Adler, höher in die Luft!\nAlles sieht so anders aus, wenn du fliegst.\r\nWeil du ein Adler bist, werde dir bewusst,\ngebrauche deine Schwingen und erheb\' die Brust.\nBrich hinein in den Heil\'gen Geist\nund du wirst erkennen was Fliegen heißt.\r\nDein Zuhause ist ja nicht der Hühnerstall,\nd\'rum flieg doch etwas höher und hinein in\'s All!\nGehe höher, gehe in das Wort,\nund dann bist du bald an jenem sel\'gen Ort.'),
(9, '0616', 'Hebt mich höher, hebt mich höher aus der Sünde dunkler Nacht  -  Rais me higher, raise me higher out of Sins dark gloomy Sea', 'Rais me higher, raise me higher\nout of sins dark gloomy sea.\nTo the Saviour bring me nigher,\nwho was crucified for me.\nCome ye angels spread your bright wings,\nbear me to Golghata\'s height.\nMan\'s redemption there was finished,\nlet me see the wondrous sight.\r\nRaise me higher, raise me higher,\nfrom the tires and pain of woe.\nEver nigher, ever nigher,\nsorrows flames around me glow.\nCome ye angels spread your bright wings,\nbear me up tu Tabor\'s hight,\nlet me see the Saviour glory\ngrief shall vanish at the sight.\r\nRaise me higher, raise me higher,\nfrom this vain world\'s empty glare.\nTo Mount Zion bring me nigher,\nto the light and glory there.\nCome ye angels spread your bright wings,\nbear me to the land of rest,\nopen wide the pearly portals,\nbear me to my Saviours breast.', 'Hebt mich höher, hebt mich höher\naus der Sünde dunkler Nacht!\nRücket mich dem Heiland näher,\nder am Kreuz für mich vollbracht!\nEngel kommt, schwingt eure Flügel,\ntragt mich hin nach Golgatha,\ndass ich seh\' auf jenem Hügel,\nwas für Sünder dort geschah!\r\nHebt mich höher, hebt mich höher\naus der Schmerzen trüber Flut!\nImmer weher, immer weher\ntut des Leidens Feuersglut!\nEngel kommt, schwingt eure Flügel,\ntragt mich hin auf Tabors Höh\'n,\nwo auf dem Verklärungshügel\nalle Schmerzen schnell vergeh\'n.\r\nHebt mich höher, hebt mich höher\naus der armen Erdenwelt,\nimmer näher, immer näher\nzu des Himmels Lichtgezelt!\nEngel kommt, schwingt eure Flügel\nund hebt mich zum Herrn empor,\ntragt mich hin zu Zions Hügel,\nöffnet mir das Perlentor!'),
(9, '0617', 'Heil\'ge steht ein für das Licht  -  All ye Saints of Light proclaim   (Wir wandeln im Licht, herrlichen Licht)', 'All ye saints of light proclaim.\nJesus, the light of the world.\nLife and mercy in His name,\nJesus, the light of the world.\r\nWe\'ll walk in the light, beautiful light,\ncome where the dewdrops of mercy are bright.\nShine all around us by day and by night,\nJesus, the light of the world.\r\nHear the Saviour\'s earnest call,\nJesus, the light of the world.\nSend the Gospel truth to all,\nJesus, the light of the world.\r\nWhy not seek Him then today,\nJesus, the light of the world.\nGo with truth the narrow way,\nJesus, the light of the world.\r\nCome, confess Him as your King,\nJesus, the light of the world.\nThen the bells of heaven will ring,\nJesus, the light of the world.', 'Heil\'ge steht ein für das Licht!\nJesus, das Licht dieser Welt.\nGnad\' und Leben ist\'s für dich,\nJesus das Licht dieser Welt\r\nWir wandeln im Licht, herrlichen Licht,\nkomm wo der Tau seiner Gnade sich bricht.\nGanz um uns leuchtet bei Tag und bei Nacht,\nJesus, das Licht dieser Welt.\r\nHör wie Jesus zu uns spricht!\nJesus, das Licht dieser Welt.\n"Zege allen Gottes Licht!"\nJesus, das Licht dieser Welt.\r\nSuch\' den Herrn so lange es geht!\nJesus, das Licht dieser Welt.\nFolg\' Ihm auf dem schmalen Weg!\nJesus, das Licht dieser Welt.\r\nKomm, bekenne Jesus Christ\'!\nJesus, das Licht dieser Welt.\nUnd das Er dein König ist;\nJesus, das Licht dieser Welt.'),
(9, '0618', 'Heil\'ger Geist Gabe von oben', NULL, 'Heil\'ger Geist, Gabe von oben,\nmächtige göttliche Kraft,\ngib uns ein herrliches Loben,\ndas Du selbst in uns schaffst!\r\nKomm wie ein Brausen auf alle,\nschenk\' neue Freude uns ein!\nLass uns von Deinem Schalle\nneu aufgeweckt sein!\r\nSchenke zu m Dienst neue Salbung,\nlass Jesu\' Antlitz uns seh\'n!\nGib eine Geisteserquickung,\nTröster aus Himmelshöh\'n!\r\nHerr, lass vor Dir uns hintreten,\narm in uns selber und schwach!\nHör unser aller ernst\' Beten,\nund uns voll Geistes mach\'!\r\nHerr, wir sind hier nun beisammen,\nbeten voll Inbrunst zu Dir:\nLass Deine göttliche Flammen\nauf jeden fallen hier.'),
(9, '0619', 'Heiland, führe Du Dein Kind  -  Saviour, lead me lest I stray   (Führe, führe, führe mich durch Nacht zum Licht)', 'Saviour, lead me lest I, stray,\ngently lead me all the way.\nI am safe when by thy side,\nI would in thy love abide.\r\nLead me, lead me.\nSaviour, lead me lest I stray.\nGently down the stream of time,\nlead me, Saviour, all the way.\r\nThou the refuge of my soul,\nwhen life’s stormy billows roll.\nI am safe when thou art nigh,\nall my hopes on thee rely.\r\nSaviour, lead me, then at last,\nwhen the storm of life is past,\nto the land of endless day,\nwhere all tears are wiped away.', 'Heiland, führe Du Dein Kind;\nDeine Hand ist stark und lind,\nmeine Burg, mein Fels, mein Licht,\nJesus, meine Zuversicht!\r\nFühre, führe, führe mich\ndurch Nacht zum Licht,\nund wenn alles wankt und bricht,\nbleib Du meine Zuversicht.\r\nDroht der Feind, bist Du mein Hort;\ntost der Sturm, bist Du mein Port;\nalles, alles bist Du mir! Jesu,\no ich traue Dir!\r\nD\'rum, so nimm denn meine Hand,\nführ\' mich bis ins Vaterland.\nHeiter folg\' ich Schritt für Schritt,\ndenn mein Jesus geht ja mit.'),
(9, '0620', 'Heilge Liebe, unaussprechlich, Freude aus den Himmelshöhn  -  Love divine, all Loves excelling, joy of Heav’n', 'Love divine, all loves excelling,\njoy of heav’n, to earth come down,\nfix in us Thy humble dwelling,\nall Thy faithful mercies crown.\nJesus, Thou art all compassion,\npure, unbounded love Thou art.\nVisit us with Thy salvation;\nenter ev\'ry trembling heart.\r\nBreathe, o breathe Thy loving Spirit\ninto ev’ry troubled breast.\nLet us all in Thee inherit,\nlet us find the promised rest.\nTake away the love of sinning,\nAlpha and Omega be.\nEnd of faith, as its beginning,\nset our hearts at liberty.\r\nCome, Almighty, to deliver,\nlet us all Thy life receive.\nSuddenly return, and never,\nnevermore they temples leave.\nThee we would be always blessing,\nserve Thee as Thy hosts above,\npray, and praise Thee without ceasing,\nglory in Thy perfect love.\r\nFinish, then, Thy new creation,\ntrue and spotless let us be.\nLet us see Thy great salvation\nperfectly restored in Thee.\nChanged from glory into glory,\ntill in heav’n we take our place,\ntill we cast our crowns before Thee,\nlost in wonder, love and praise.', 'Heil\'ge Liebe, unaussprechlich,\nFreude aus den Himmelshöh\'n,\nkomm und wirke in uns mächtig,\nDeine Gottesgnade krön\'.\nJesus, Du bist das Erbarmen,\nunbegrenzte, reine Lieb\'.\nDecke uns mit Deinen Armen,\nunsern Herzen Ruhe gib.\r\nHauche Du den Geist der Liebe\nden verzagten Herzen ein.\nWeck\' in uns des Geistes Triebe,\nführ\' zur Sabbatruh\' uns ein.\nNimm von uns die Lust zur Sünde,\nAlpha und Omega sei,\nunsres Glaubens Grund und Ende,\nmache unsre Herzen frei.\r\nKomm, allmächtiger Befreier,\ngib uns, was Du bist, was Dein.\nKomm zu uns, wir harren Deiner,\nzieh in Deinen Tempel ein.\nO wie werden wir Dich rühmen,\ndienend mit der ober\'n Schar,\nDich, Herr, preisen ohn\' Ermüden,\nwelche Liebe wunderbar!\r\nO vollende Deine Schöpfung,\nmach uns fleckenlos und rein.\nGib uns völlige Erlösung,\nganz erneuert lass uns sein.\nUnd wenn wir verklärt in Wahrheit\nvor dem Thron in Klarheit knien,\nlegen staunend wir die Kronen,\nHerr, zu Deinen Füßen hin.'),
(9, '0621', 'Heilges Wort das bewahrt  -  Holy Words long preserved', 'Holy words long preserved\nfor our walk in this world.\nThe resound with God\'s own heart\noh let the ancient words impart.\r\nWords of life, words of hope.\nGive us strength, help us cope.\nIn this world,where e\'er we roam.\nAcient words will guide us home.\r\nAncient words ever true\nchanging me and changing you.\nWe have come with open hearts\noh let the ancient words impart.\r\nHoly words of our faith\nhanded down to this age.\nCame to us through sacrifice\nheed the faithful words of Christ.\r\nHoly words long preserved\nfor our walk in this word.\nThe resound with Gods own heart\nO let the ancient words impart.\r\nWord of God, ever true,\nchanging me, changing you.\nWe have come with open hearts,\noh, let the word of God impart.', 'Heil\'ges Wort, das bewahrt\nden, der sich im Glauben naht.\nAus dem Herzen Gottes spricht\nGottes Wort, das Abendlicht.\r\nHeil\'ges Wort dich bewegt\nwenn Sein Geist es dir belebt,\nspricht zum Samen tief in dir,\nChristus klopft an deine Tür.\r\nEw\'ges Wort, wahr und rein,\nlässet mich Dir ähnlich sein.\nHeut\' ich komm, mein Herz bereit,\nsprich zu mir in dieser Zeit.\r\nHeil\'ges Wort in jeder Zeit,\nmachst Du Deine Braut bereit.\nHast für sie stets einen Stern,\nDeine Stimme hört sie gern.\r\nHeil\'ges Wort das erstrahlt,\nwenn Dein Geist dem Wort sich naht.\nFührst Dein Volk im Abdenlicht,\nbis der neue Tag anbricht.\r\nWort Gottes, immer wahr,\nverändert mich, verändert dich.\nWir sind mit offenen Herzen gekommen,\nlass das Wort Gottes vermitteln.'),
(9, '0622', 'Heilig, heilig ist der Herr  -  Holy, holy is the Lord   (Chorus)', 'Holy, holy is the Lord,\nholy, holy is the Lord,\nFor the Lamb was worthy\nto open the book,\nholy is the Lord.', 'Heilig, heilig ist der Herr,\nheilig, heilig ist der Herr.\nDenn das Lamm war würdig\nzu öffnen das Buch,\nheilig ist der Herr.'),
(9, '0623', 'Heilig, heilig, heilig ist der Herr! Jauchzt ihm, ihr Völker  -  Holy, holy, holy is the Lord! Sing, o ye People, gladly adore Him   (Heilig, heilig, heilig ist der Herr)', 'Holy, holy, holy is the Lord!\nSing, O ye people, gladly adore Him.\nLet the mountains tremble at His word,\nlet the hills be joyful before Him.\nMighty in wisdom, boundless in mercy,\ngreat is Jehovah, King over all.\r\nHoly, holy, holy is the Lord!\nLet the hills be joyful before Him.\r\nPraise Him, praise Him! shout aloud for joy,\nwatchman of Zion, herald the story.\nSin and death His kingdom shall destroy,\nall the earth shall sing of His glory.\nPraise Him ye angels, ye who behold Him,\nrobed in His splendor, matchless, divine.\r\nKing Eternal, blessed be His name!\nSo may His children gladly adore Him.\nWhen in heav\'n we join the happy strain,\nwhen we cast our bright crowns before Him.\nThere in His likeness joyful awaking,\nthere we shall see Him, there we shall sing.', 'Heilig, heilig, heilig ist der Herr!\nJauchzt Ihm, ihr Völker, rühmt Seinen Namen.\nBebt, ihr Berge! Brause laut, o Meer!\nRuft dazu, ihr Hügel, das Amen.\nGnädig und gütig, mächtig und weise,\ngroß ist Jehova, Herrscher der Welt!\r\nHeilig, heilig, heilig ist der Herr!\nRuft dazu, ihr Hügel, das Amen.\r\nLobt Ihn! Preist Ihn! Gebt die Herzen hin!\nWächter auf Zion, frei es verkündet!\nLasst das Wort mit heil\'gem Feuer glüh\'n,\nam Altar die Fackel entzündet.\nPreist Ihn ihr Engel, strahlende Helden,\ntausendmal tausend, betet Ihn an!\r\nHeilig! Ewig! Licht ist Sein Gewand!\nHerr ist Jehova! Wer kann Ihm gleichen?\nEr bleibt Sieger, stark ist Seine Hand!\nTod und Sünde muss vor Ihm weichen.\nWenn wir erwachen in Seinem Bilde,\nschauen auch wir Ihn, jauchzen Ihm zu.'),
(9, '0624', 'Heilig, heilig, heilig, Du großer Gott,', 'Holy, holy holy, Lord God of Hosts!\nHoly, holy holy, Lord God of Hosts!\nHeav\'n and earth are full of Thee!\nHeav\'n and earth are praising Thee,\nO Lord most high!', 'Heilig, heilig, heilig, Du großer Gott,\nHeilig, heilig, heilig, Du großer Gott,\nHimmel und Erd\' sind voll von Dir,\nDeine Größe preisen wir,\nDu höchster Gott.'),
(9, '0625', 'Heilig, heilig, heilig, Gott Ewig-Vater  -  Holy, holy, holy! Lord God Almighty!', 'Holy, holy, holy! Lord God Almighty!\nEarly in the morning our song shall rise to Thee.\nHoly, holy, holy, merciful and mighty!\nGod in three Persons, blessed Trinity!\r\nHoly, holy, holy! Lord God Almighty!\nEarly in the morning our song shall rise to Thee.\nHoly, holy, holy, merciful and mighty!\nGod in three Persons, blessed Trinity!\r\nHoly, holy, holy! Though the darkness hide Thee,\nthough the eye of sinful man Thy glory may not see.\nOnly Thou art holy; there is none beside Thee,\nperfect in pow’r, in love, and purity.\r\nHoly, holy, holy! Lord God Almighty!\nAll Thy works shall praise Thy Name, in earth, and sky, and sea.\nHoly, holy, holy; merciful and mighty!\nGod in three Persons, blessed Trinity!', 'Heilig, heilig, heilig, Gott Ewig-Vater!\nHör, wie Deiner Kinder Lied Dich Ew\'ger, staunend preist.\nHeilig, heilig, heilig, gnädig und allmächtig!\nHerr Gott, Jehova, Vater, Sohn und Geist.\r\nHeilig, heilig, heilig! Heilige anbeten.\nVor Dir legt die Kronen hin der Überwinder Schar.\nCherubim und Seraphim preisend vor Dich treten,\nder war und ist und sein wird immerdar.\r\nHeilig, heilig, heilig! Ob Dich Nacht verhüllet,\nob auch sündig Menschenaug\' nicht schaut die Herrlichkeit.\nDu allein bist heilig, der die Welt erfüllet,\nglorreich in Liebe. Kraft und Heiligkeit.\r\nHeilig, heilig, heilig! Gott Ewig-Vater!\nDeiner Schöpfung Wunderpracht, Herr, Deinen Namen preist.\nHeilig heilig, heilig, gnädig und allmächtig,\nHerr Gott, Jehova, Vater, Sohn und Geist.'),
(9, '0626', 'Heilig, heilig, heilig, Gott ist allmächtig  -  Holy, holy, holy, Lord God Almighty', 'Holy, holy,\nholy, holy,\nholy, holy, Lord God Almighty.\nAnd we lift our hearts before you\nas a token of our love.\nHoly, holy,\nholy, holy.\r\nHalleluja, Halleluja,\nHalleluja, Halleluja,\nHalleluja, Halleluja Lord God Almighty.\nAnd we lift our hearts before you\nas a token of our love.\nHalleluja, Halleluja.\nHalleluja, Halleluja,\r\nHosianna, Hosianna,\nHosianna, Hosianna,\nHosianna, Hosianna, Lord God Almighty.\nAnd we lift our hearts before you\nas a token of our love.\nHosianna, Hosianna,\nHosianna, Hosianna.\r\nMaranatha, Maranatha,\nMaranatha, Maranatha,\nMaranatha, Maranatha, Lord God Almighty.\nAnd we lift our hearts before you\nas a token of our love.\nMaranatha, Maranatha,\nMaranatha, Maranatha.', 'Heilig, heilig,\nheilig, heilig,\nHeilig, heilig.\nGott ist allmächtig.\nUnd als Liebeszeichen\nheben wir die Hände empor.\nHeilig, heilig,\nheilig, heilig.\r\nHalleluja, Halleluja,\nHalleluja, Halleluja,\nHalleluja, Halleluja.\nGott ist allmächtig.\nUnd als Liebeszeichen\nheben wir die Hände empor.\nHalleluja, Halleluja,\nHalleluja, Halleluja.\r\nHosianna, Hosianna,\nHosianna, Hosianna,\nHosianna, Hosianna.\nGott ist allmächtig.\nUnd als Liebeszeichen\nheben wir die Hände empor.\nHosianna, Hosianna,\nHosianna, Hosianna.\r\nMaranatha, Maranatha,\nMaranatha, Maranatha,\nMaranatha, Maranatha.\nGott ist allmächtig.\nUnd als Liebeszeichen\nheben wir die Hände empor.\nMaranatha, Maranatha,\nMaranatha, Maranatha.'),
(9, '0627', 'Heiliger Geist, nun Deine Flügel breite', NULL, 'Heiliger Geist, nun Deine Flügel breite,\nwo sich die Deinen sammeln zum Gebet;\nkomm, offenbare uns den Heiland heute,\ndass Er verklärt vor unserer Seele steht.\r\nHeiliger Geist, verscheuche jede Wolke,\nschenk\' uns in Jesu Namen frohen Mut;\nDein hold Gedächtnis weck\' in Seinem Worte,\ndass neu entflammt des Zeugeneifers Glut.\r\nHeiliger Geist, heut\' in den Herzen walte,\nheiligend, tröstend, Führer, Rat und Freund;\ndass Jesu Leben sich in uns gestalte\nund Seine Klarheit leuchtend in uns scheint.'),
(9, '0628', 'Heim zu Gott führt mich nur der Weg dort am Kreuz  -  I must needs go Home by the Way of the Cross   (Der Weg dort am Kreuz führt heim)', 'I must needs go home by the way of the cross,\nthere’s no other way but this.\nI shall ne’er get sight of the Gates of Light,\nif the way of the cross I miss.\r\nThe way of the cross leads home,\nthe way of the cross leads home.\nIt is sweet to know, as I onward go,\nthe way of the cross leads home.\r\nI must needs go on in the blood-sprinkled way,\nthe path that the Saviour trod.\nIf I ever climb to the heights sublime,\nwhere the soul is at home with God.\r\nThen I bid farewell to the way of the world,\nto walk in it nevermore.\nFor my Lord says, "Come," and I seek my home,\nwhere He waits at the open door.', 'Heim zu Gott führt mich nur der Weg dort am Kreuz,\nes gibt keinen ander\'n Weg.\nUnd es schauet nicht jenes Land im Licht,\nwer den Weg zum Kreuz nicht geht.\r\nDer Weg dort am Kreuz führt heim,\nder Weg dort am Kreuz führt heim.\nDort mir Gott verzieh, ich vergesse es nie.\nDer Weg dort am Kreuz führt heim.\r\nIch muss geh\'n den Weg, der zum Kreuze mich führt,\nwo Jesus vergoss Sein Blut\nwill ich dort einsteh\'n, wo ich Ihn werd\' seh\'n,\nwo das Herz in der Gnade ruht.\r\nDarum fahret hin, alle Wege der Welt,\nich lass euren Glanz und Schein!\nSeit Er rief: "Kommt her!" wünsch\' ich sonst nichts mehr,\newig möchte bei Ihm ich sein.'),
(9, '0629', 'Her mit dem Rettungsseil! Eilt, es tut Not  -  Throw out the Life-Line across the dark Wave   (Wirf ihm das Seil zu! Wirf ihm das Seil zu)', 'Throw out the Life-Line across the dark wave!\nThere is a brother whom someone should save--\nSomebody’s brother! O who then will dare\nto throw out the Life-Line, his peril to share?\r\nThrow out the Life-Line! Throw out the Life-Line!\nSomeone is drifting away!\nThrow out the Life-Line! Throw out the Life-Line!\nSomeone is sinking today.\r\nThrow out the Life-Line with hand quick and strong -\nwhy do you tarry, why linger so long?\nSee, he is sinking! O hasten today,\nand out with the Life-Boat! away, then, away!\r\nThrow out the Life-Line to danger-fraught men,\nsinking in anguish where you’ve never been.\nWinds of temptation and billows of woe\nwill soon hurl them out where the dark waters flow.\r\nSoon will the season of rescue be o’er,\nsoon will they drift to eternity’s shore.\nHaste then, my brother - no time for delay,\nbut throw out the Life-Line and save them today.', 'Her mit dem Rettungsseil, eilt, es tut Not!\nDort in den Wogen er ringt mit dem Tod!\nIst\'s nicht dein Bruder? O zaudre nicht mehr!\nAuf, trag\' ihm das Seil zu durchs tosende Meer!\r\nWirf ihm das Seil zu! Wirf ihm das Seil zu!\nNoch mit den Wogen er ringt!\nWirf ihm das Seil zu! Wirf ihm das Seil zu!\nEhe dein Bruder versinkt.\r\nWirf ihm das Seil zu mit sicherer Hand!\nAch, warum stehst du noch zaudernd am Strand?\nSieh, er versinket, hinaus mit dem Boot!\nJetzt, jetzt, durch die Brandung! Entreiß\' ihn dem Tod.\r\nAuf, Brüder, werfet das Rettungsseil aus!\nSünder verderben im Wogengebraus.\nSünde ist stark und Versuchung ist groß;\nschon fasst sie die Strömung; bald heißt\'s: rettungslos!"\r\nNoch gilt\'s zu retten; die Arbeit bald ruht,\nbald ringst im Tode auch du mit der Flut.\nDann rufst im schwellenden Jordan auch du:\n"Wirf mir, o mein Heiland, das Rettungsseil zu!"'),
(9, '0630', 'Herbei, o ihr Gläubigen  -  Oh come, all ye Faithful   (O lasset uns anbeten, o lasset uns anbeten)', 'Oh come, all ye faithful,\njoyful and triumphant.\nOh come ye, O come ye to Bethlehem.\nCome and behold Him, born the King of angels.\r\nOh come, let us adore Him, oh come, let us adore Him,\noh come, let us adore Him, Christ, the Lord.\r\nTrue God of true God,\nlight of light eternal,\nour lowly nature He hath not abhorred.\nBorn of a woman, here in flesh appearing.\r\nSing, choirs of angels,\nsing in exultation,\noh sing, all ye citizens of heav\'n above.\nGlory to God, all glory in the highest.\r\nYea, Lord, we greet Thee,\nborn this happy morning,\nJesus, to Thee be all glory giv\'n.\nWord  of the Father, now in flesh appearing.', 'Herbei, o ihr Gläubigen,\nfröhlich triumphierend,\no kommet, o kommet nach Bethlehem!\nSehet das Kindlein, uns zum Heil geboren!\r\nO lasset uns anbeten, o lasset uns anbeten,\no lasset uns anbeten den König!\r\nDu König der Ehren,\nHerrscher der Heerscharen\ndu ruhst in der Krippe, im Erdental.\nGott, wahrer Gott, von Ewigkeit geboren!\r\nKommt, singt dem Herren,\no ihr Engelchöre,\nfrohlocket, frohlocket, ihr Seligen:\nEhre sei Gott im Himmel und auf Erden!\r\nDir, der du bist heute\nMensch für uns geboren,\no Jesu, sei Ehre und Preis und Ruhm!\nDir, Fleisch geword\'nes Wort des ew’gen Vaters!'),
(9, '0631', 'Here comes Jesus! Oh hail King Jesus!   (2 Chorusse)', 'Here comes Jesus! Oh hail King Jesus!\nGive Him glory and honour and power!\nKing Jesus!\r\nTo His majesty, we lift up holy hands.\nLord we love You, we praise You, adore You!\nHallelujah!', NULL),
(9, '0632', 'Here is Love vast as the Ocean', 'Here is love vast as the ocean\nloving kindness as the flood,\nwhen the prince of life our ransom\nshed for us his precious blood.\nWho his love will not remember?\nWho can cease to sing his praise?\nHe can never be forgotten\nthroughout Heavens eternal day.\r\nOn the mount of crucifixion\nfountains opened deep and wide,\nthrough the floodgates of Gods mercy\nflowed a vast and gracious tide.\nGrace and love like mighty rivers\npoured incessant from above.\nHeavens peace and perfect justice\nkissed a guilty world in love.\r\nLet us all his love accepting,\nlove him ever all your days.\nLet us seek his kingdom only\nand our lives be to his praise.\nHe alone shall be our glory,\nnothing in the world we see.\nHe has cleansed and sanctified us,\nHe himself has set us free.\r\nIn his truth he does direct me\nby his spirit through his word,\nand his grace my need is meeting\nas I trust in him my Lord.\nAll his fullness he is pouring\nin his love and power in me,\nwithout measure,\nfull and boundless\nas I yield myself to Thee.', NULL),
(9, '0633', 'Here so many are taking Vacation   (When I take my Vacation in Heaven)', 'Here so many are taking vacation,\nto the mountains, the lake or the sea,\nwhere they rest from their cares and their worries,\nwhat a wonderful time that must be!\nBut it seems not my lot to be like them,\nI must toil thru the heat and the cold,\nseeking out the lost sheep on the mountains,\nbringing wanderers back to the fold.\r\nWhen I take my vacation in heaven,\nwhat a wonderful time that will be,\nhearing concerts by heavenly chorus,\nand the face of my Saviour I\'ll see.\nSitting down by the banks of the river,\n\'neath the shade of the ever green tree,\nI shall rest from my burdens forever,\nwon\'t you spend your vacation with me.\r\nNow some day I shall take my vacation\nto the city John tells us about,\nwith its foundation walls all so precious,\nwhere from gladness of heart I shall shout!\nOh, no sights ever witnessed by mortals\ncan compare with the glories up there.\nI shall spend my vacation with Jesus,\nin the place He went on to prepare.\r\nThere the weather will always be perfect,\nnot a cloud shall sweep over the sky;\nand no earthquakes or cyclones shall threaten.\nin the land of the "Sweet by and by".\nSoon there\'s going to be an excursion,\nI am booked for a ride in the air,\nyou\'re invited to share my vacation\nand the feast with our Bridegroom to share.\r\nHere on earth when we take our vacation,\nwe return to our homes by and by.\nWhen I take my vacation in heaven,\nin those mansions of gold in the sky,\nI shall dwell with my Saviour forever,\nwith Him sit on His heavenly throne.\nAll the days will be one, long vacation,\nwhen my Saviour takes me to His home.', NULL),
(9, '0634', 'Here we are', 'And here we are\nLifting our hands to you\nHere we are\nGiving you thanks for all you do\nAnd as we praise\nAnd worship your Holy name\nYou are here\nDwelling within our praise\r\nFor every answered prayer\nOh yeah, for always being there\nFor love that hears us when we call\nFor arms that lift us when we fall, oh yeah\nOh, you have always been\nRight beside us, leading us all along the way\nAnd we made it through (we made it through)\nBecause of you\r\nFor days we cannot see (for days we cannot see)\nFor all that\'s yet to be (so much is yet to be)\nThe trials we may have to face\nWhen we\'ll be leaning on your grace, oh yes\nIt will be your strengt, (yes, it will) that saves us\nYour love that makes us strong\nAnd through it all (through it all)\nWe\'ll sing this song, oh', 'Und hier sind wir\nWir heben unsere Hände zu dir\nHier sind wir\nWir danken dir für alles, was du tust\nUnd während wir deinen\nund deinen heiligen Namen anbeten\nDu bist hier\nWohnst in unserem Lobpreis\r\nFür jedes erhörte Gebet\nOh ja, dafür, dass wir immer da sind\nFür die Liebe, die uns hört, wenn wir rufen\nFür Arme, die uns aufheben, wenn wir fallen, oh ja\nOh, du warst immer\nDirekt neben uns, führst uns den ganzen Weg entlang\nUnd wir haben es geschafft (wir haben es geschafft)\nWegen dir\r\nFür Tage, die wir nicht sehen können (für Tage, die wir nicht sehen können)\nFür alles, was noch sein wird (so vieles wird noch sein)\nDie Prüfungen, die wir vielleicht zu bestehen haben\nWenn wir uns auf deine Gnade stützen werden, oh ja\nEs wird deine Stärke sein, (ja, das wird sie) die uns rettet\nDeine Liebe, die uns stark macht\nUnd durch alles hindurch (durch alles hindurch)\nwerden wir dieses Lied singen, oh'),
(9, '0635', 'Herr bereit mich, zu einem heil\'gen Tempel  -  Lord prepare me, to be a Sanctuary   (Chorus)', 'Lord, prepare me,\nto be a sanctuary,\npure and holy, tried and true.\nWith thanksgiving\nI want to be a living\nsanctuary for you.', 'Herr bereit mich\nzu einem heil\'gen Tempel,\nrein und heilig, geprüft und treu.\nVoller Leben\nwill ich den Dank Dir geben,\nals ein Tempel für Dich.'),
(9, '0636', 'Herr Dein Wort ist meines Fußes Leuchte', NULL, 'Herr, Dein Wort ist meines Fußes Leuchte\nein stetes Licht auf meinem Weg.\nNicht nur gestern, sondern auch heute\nzeigt mir Dein Wort den Weg, den ich geh\'n soll.\r\nDenn in Christus liegen verborgen\nalle Schätze der Weisheit und Erkenntnis.\nGestern, heute und morgen\nist Jesus da, Er führt und leitet mich.'),
(9, '0637', 'Herr Deine Güte ist besser als Leben  -  Thy loving Kindness is better than Life', 'Thy loving kindness is better than life.\nThy loving kindness is better than life.\nMy lips shall praise Thee,\nThus will I bless Thee.\nI will lift up my hands in Thy name.\r\nI lift my hands Lord, unto Thy name.\nI lift my hands Lord, unto Thy name.\nMy lips shall praise Thee,\nThus will I bless Thee.\nI will lift up my hands in Thy name.\r\n\r\n', 'Herr, Deine Güte ist besser als Leben.\nHerr, Deine Güte währt ewiglich!\nMein Mund soll Dich preisen,\nDu wirst mich segnen.\nIch heb\' auf meine Hände im Gebet.\r\nIch heb\' auf meine Hände im Gebet.\nIch heb\' auf meine Hände im Gebet.\nMein Mund soll Dich preisen,\nDu wirst mich segnen.\nIch heb\' auf meine Hände im Gebet.\r\nHerr, meine Freude\nist, wenn ich Dich lobe.\nHerr, meine Wonne\nbist Du ganz allein.\nMein Mund soll Dich preisen,\nDu wirst mich segnen,\nweil ich bei Dir Zuflucht hab.\r\nIch verlang\', oh Herr, nach Dir.\nIch verlang\', oh Herr, nach Dir.\nMein Mund soll Dich preisen,\nDu wirst mich segnen.\nIch verlang\', oh Herr, nach Dir.'),
(9, '0638', 'Herr Deine Liebe sie ist so groß   (Ich blick auf Jesus, das Gotteslamm)', NULL, 'Herr, Deine Liebe sie ist so groß,\nvon meiner Sünde band\'st Du mich los.\nDas macht mich glücklich, so froh und frei,\nich kann bezeugen, alles wurd\' neu.\r\nIch blick auf Jesus, das Gotteslamm,\ndas mich erlöst hat am Kreuzesstamm.\nIm Glauben schau\' ich nach Golgatha,\num Ihm zu danken, was dort geschah.\r\nIm Glauben richt\' ich den Blick auf Ihn,\nund Gottes Gnade kommt dann zu mir.\nDenn in dem Anschau\'n des Gottesheld\'s,\nwerd\' ich verwandelt ganz in Sein Bild.\r\nDas Buch ist offen, der Weg ist frei,\nIhm zu begegnen, Er macht dich neu.\nDas alte Leben verschwindet ganz,\nwenn Er dich führen und dein Herr sein kann.\r\nGottes Charakter kommt jetzt hervor.\nIn Prüfungszeiten formt Er den Ton;\nbis in Sein Bildnis wir sind geformt\nund Er uns heim holt als Seine Braut.'),
(9, '0639', 'Herr ich komm zu Dir, suche die Veränderung  -  Lord, I come to You, let my Heart be changed, renewed   (Halt mich fest, ganz fest in Deiner Liebe)', 'Lord, I come to You, let my heart be changed, renewed,\nflowing from the grace, that I’ve found in You.\nLord I’ve come to You, the weaknesses  I see in me,\nwill be stripped away, by the power of Your love.\r\nHold me close, let Your love surround me,\nbring me near, draw me to your side,\nand as I wait I’ll rise up like the eagle,\nand I will sour with You, Your spirit leads me on\nin the power of Your love.\r\nLord unveil my  eyes, let me see You face to face,\nthe knowledge of Your love, as You live in me.\nLord renew my  mind, as Your will unfolds in my live\nin living every day, by the power of your love.', 'Herr ich komm zu Dir, suche die Veränderung,\ndie Deine Gnade schafft, mit der Du mich führst.\nDu nimmst die Schwäche fort, nimmst weg was Dir im Wege steht,\nHerr Du erneuerst mich, durch die Kraft Deiner Liebe.\r\nHalt mich fest, ganz fest in Deiner Liebe,\ndass ich Herr, nahe bei Dir bleib,\nDu machst mich still, ich gleite wie ein Adler,\nmit Dir empor mein Gott, durch deinen Geist berührt,\nin der Kraft deiner Liebe.\r\nHerr ich  möchte gern, ganz in Deiner Nähe sein,\nich weiß das Du mich liebst, und Du siegst in mir.\nHerr Du erneuerst mich, Dein Wille prägt sich mir tief ein,\nich lebe jeden Tag, in der Kraft Deiner Liebe.'),
(9, '0640', 'Herr ich will Dich preisen, meine Hände zu Dir heben  -  I Just want to praise You, lift my Hands to You', 'I just want to praise You, lift my hands and say: "I love You".\nYou are everything to me and I exalt Your Holy Name on high.\nI just want to praise You, lift my hands and say: "I love You".\nYou are everything to me.\nAnd I exalt Your Holy Name, I exalt Your Holy Name,\nI exalt Your Holy Name on high.', 'Herr, ich will Dich preisen, meine Hände zu Dir heben,\nDu, Herr, bist mein alles, heilig ist Dein Name, höchster Gott.\nHerr, ich will Dich preisen, meine Hände zu Dir heben,\nDu, Herr, bist mein alles.\nHeilig ist Dein Name, heilig ist Dein Name,\nheilig ist Dein Name, höchster Gott.'),
(9, '0641', 'Herr Jesus, ich wäre so gerne ganz heil  -  Lord Jesus, I long to be perfectly Whole   (O wasche mich, mache mich weißer als Schnee)   [Pfingstjubel]', 'Lord Jesus, I long to be perfectly whole.\nI want Thee forever to ransom my soul.\nBreak down ev\'ry idol, cast out ev\'ry foe:\nNow wash me, and I shall be whiter than snow.\r\nWhiter than snow, yes, whiter than snow.\nNow wash me, and I shall be whiter than snow.\r\nDear Jesus, let nothing unholy remain,\napply Thine own blood, and extract ev\'ry stain.\nTo have this blest washing I all things forego,\nnow wash me, and I shall be whiter than snow.\r\nDear Jesus, come down from Thy throne in the skies,\nand help me to make a complete sacrifice.\nI give up myself, and whatever I know,\nnow wash me, and I shall be whiter than snow.\r\nDear Jesus, Thou seest I patiently wait,\ncome now, and within me a new heart create.\nTo those who have sought Thee thou never saidst, no,\nnow wash me, and I shall be whiter than snow.\r\nDear Jesus, for this I most humbly entreat,\nI wait blessed Lord, at thy crucified feet.\nBy faith, for my cleansing, I see thy blood flow,\nnow wash me, and I shall be whiter than snow.\r\nThe blessing by faith I receive from above,\no glory! my soul is made perfect in love.\nMy prayer has prevailed, and this moment I know\nthe blood is applied, I am whiter than snow.', 'Herr Jesu, ich wäre so gerne ganz heil\nund hätte Dich gerne zum bleibenden Teil!\nDie Götzen zerbrich und die Bande zerreiß;\no wasche mich, mache wie Schnee mich so weiß.\r\nSo weiß wie den Schnee, ja, weißer als Schnee;\no wasche mich, mache mich weißer als Schnee!\r\nHerr Jesu, lass gar nichts Unreines in mir,\nentsündige mich, dass ich heilig sei Dir!\nIch gebe Dir gerne mein alles zum Preis,\no wasche mich, mache wie Schnee mich so weiß.\r\nHerr Jesu, o komme Du selber zu mir\nund heil‘ge zum völligen Opfer mich Dir!\nIch bringe Dir, was ich nur habe und weiß,\no wasche mich, mache wie Schnee mich so weiß.\r\nHerr Jesu, Du siehst es, still harre ich Dein,\no schaffe ein Herz in mir heilig und rein!\nDie Fleh\'nden erhören, das dient Dir zum Preis,\no wasche mich, mache wie Schnee mich so weiß.\r\nHerr Jesu, hier liege zu Füßen ich Dir!\nDein Blut macht ja rein. Herr, ich flehe allhier:\nKomm, zeig Deine Huld, Deine Allmacht beweis!\nO wasche mich, mache wie Schnee mich so weiß.\r\nIm Glauben empfang ich den Segen von Dir.\nDu schaffst ein gereinigtes Herze in mir,\nDu hast mich erhöret, mein Heiland, ich weiß,\nDu hast mich gewaschen wie Schnee nun so weiß.'),
(9, '0642', 'Herr wir kommen anzubeten  -  Lord we come to You in Worship   (El, Elah, Elohim, Herr wie beten wir Dich an)', 'Lord we come to You in worship\nno matter what the circumstance.\nNo matter what the situation\nWe will lift up holy hands.\r\nEl Elah Elohim\nHow we long to worship You.\nEl Elah Elohim\nHow we long to worship You.\r\nHere we are in Satan\'s Eden,\nSatan comes to beat us down,\nbut with Your Spirit here before us,\nin righteousness we\'ll rise and shine.\r\n', 'Herr wir kommen anzubeten,\nganz gleich was um uns her geschieht.\nGanz gleich was uns bewegt im Leben,\nsingen wir Dir unser Lied:\r\nEl, Elah, Elohim,\nHerr wie beten wir Dich an.\nEl, Elah, Elohim,\nHerr wie beten wir Dich an.\r\nHerr, wir sind in dunklen Zeiten,\nSatan lässt das Kämpfen nicht,\ndoch wenn Dich Deine Kinder preisen,\nhebst Du uns, Herr, in Dein Licht!\r\nHerr, Du bist von Ewigkeiten,\nunausschöpflich bist Du, Gott,\nund Dein Strom des ew\'gen Lebens\nstillet alle uns\'re Not!'),
(9, '0643', 'Herr wohin sonst', NULL, 'Herr, wohin sonst sollten wir gehen?\nWo auf der Welt fänden wir Glück?\nNiemand,  kein Mensch kann uns so viel geben wie du.\nDu führst uns zum Leben zurück.\nNur du,  nur du schenkst uns Lebensglück.\r\nAus deinem Mund höre ich das schönste Liebeslied.\nAn deinem Ohr darf ich sagen, was die Seele fühlt.\nAn deiner Hand kann ich fallen, und du hältst mich fest.\nAn deinem Tisch wird mein Hunger gestillt.'),
(9, '0644', 'Herr, beuge mich wie Du das Korn', NULL, 'Herr, beuge mich, wie Du das Korn,\ndas goldne, beugst im Morgenhauch.\nVor Deines Heil\'gen Geistes Weh\'n,\nda beuge mich in Demut auch.\r\nUnd wenn das trotzig\' Herz sich wehrt,\ndem Geist zu folgen, wenn Er wirkt,\nso komm im Feuer, Kraft des Herrn,\nverbrenne, was sich Dir verbirgt!\r\nWie sich die Welle vor dem Sturm\ntief beuget, beuge mich vor Dir,\nund wie am Ufer sie zerschellt,\ngib im Zerbrechen Segen mir!\r\nHerr, beuge mich! Wie Du den Lauf\nder Ströme hältst in Deiner Hand,\nso leite Ströme Deiner Kraft\ndahin, wo jetzt noch dürres Land!\r\nWie sich die Rebe beugt und fügt,\nwie es der Gärtner haben will,\ngib, dass ich nichts mehr suche selbst,\nnein, Dir mich beuge froh und still!\r\nHerr, beuge mich! Mach aus dem Ton,\nder doch zu nichts sonst für Dich wert,\nein Dir gebräuchliches Gefäß,\ndas Dich gebeugt, zerbrochen ehrt!'),
(9, '0645', 'Herr, Dein Wort, die edle Gabe, diesen Schatz erhalte mir', NULL, 'Herr, Dein Wort, die edle Gabe,\ndiesen Schatz erhalte mir!\nDenn ich zieh es alles Habe\nund den größten Reichtum für.\nWenn Dein Wort nicht mehr soll gelten,\nworauf soll der Glaube ruhn?\nMir ist\'s nicht um tausend Welten,\naber um Dein Wort zu tun.\r\nHalleluja, Ja und Amen!\nHerr, Du wolltest auf mich seh\'n,\ndass ich mög\' in Deinem Namen\nfest bei Deinem Worte stehn!\nLass mich eifrig sein beflissen,\nDir zu dienen früh und spat,\nund mich stets zu Deinen Füßen\nsetzen, wie Maria tat!'),
(9, '0646', 'Herr, der Höchste bist Du  -  Lord most high, oh Lord most high', 'Lord most high,\noh, Lord most high,\nYou are the King of Glory,\nforever pure and holy,\nLord most high!\nHallelujah! Oh, Hallelujah!\nWe come before (within) Your throne.\nTo worship You alone, Hallelujah!', 'Herr, der Höchste bist Du,\no, Herr, der Höchste bist Du,\nBist König der Herrlichkeit,\newig rein, voll Heiligkeit.\nHerr, der Höchste bist Du!\nHalleluja! O, allelujah!\nWir kommen zu Deinem Thron.\nAnbeten den Menschensohn, Halleluja!'),
(9, '0647', 'Herr, Du bist so kostbar für mich  -  Lord You are so precios to me   (2 Chorusse)', 'Lord You are so precious to me.\nLord You are so precious to me.\nAnd I love You, yes I love You,\nbecause You first loved me.\r\nLord You are so gracious to me.\nLord You are so gracious to me.\nAnd I love You, yes I love You,\nbecause You first loved me.', 'Herr, Du bist so kostbar für mich.\nHerr, Du bist so kostbar für mich.\nUnd ich liebe Dich, ja, ich liebe Dich,\nweil Du mich zuerst geliebt.\r\nHerr, Du bist so gnädig zu mir.\nHerr, Du bist so gnädig zu mir.\nUnd ich liebe Dich, ja, ich liebe Dich,\nweil Du mich zuerst geliebt.'),
(9, '0648', 'Herr, Du bist so reich an Liebe und Güte   (Psalm 51)', NULL, 'Herr, Du bist so reich\nan Liebe und Güte,\ndarum komm ich zu Dir\nund wage zu bitten: Herr, vergib\',\nwas ich Falsches tat\nund wasche mich rein,\nvon aller Schuld, die mich quält,\nund mach mich doch wieder froh.'),
(9, '0649', 'Herr, Du hast Großes an uns hier getan   (Herrlichkeit Dir, Jesus, allein)', NULL, 'Herr, Du hast Großes an uns hier getan!\nJubelnd im Staube wir beten Dich an;\npreisen die Macht Deiner Gnade vereint,\nDu unsrer Seele getreuester Freund!\r\nHerrlichkeit Dir, Jesus, allein!\nHerrlichkeit Dir, Jesus, allein!\nAlles, was Odem hat, stimme mit ein:\nHerrlichkeit Jesu, ja, Jesu allein!\r\nDu, Deiner Kinder gekrönetes Haupt,\nzeigst ohne Hülle Dich jedem, der glaubt;\nwandelst im Kreise der Deinen allhier,\ndass jeder selig Dich nahe verspür\'!\r\nKönig der Herzen, Du hast uns erkauft\nund uns mit Geist und mit Feuer getauft.\nNimm uns denn alle mit Leib und mit Seel\',\nDein sind wir ewig, Immanuel!\r\nZieh durch die Lande, o Heiland der Welt!\nBeuge, was Dir sich entgegen noch stellt!\nWecke die schlafenden Sünder in Eil\',\nDein Schmerzenslohn werde voll Dir zuteil!\r\nDas wird allein, Herrlichkeit sein,\ndas wird allein, Herrlichkeit sein.\nWenn frei von Weh ich Sein Angesicht seh\',\nwenn frei von Weh ich Sein Angesicht seh\','),
(9, '0650', 'Herr, Du kennst meinen Weg und Du ebnest die Bahn   (Dass Du mich einstimmen lässt in Deinen Jubel)', NULL, 'Herr, Du kennst meinen Weg,\nund Du ebnest die Bahn,\nund Du führst mich den Weg durch die Wüste.\r\nDass Du mich einstimmen lässt\nin Deinen Jubel, o Herr,\nDeiner Engel und himmlischen Heere,\ndas erhebt meine Seele zu Dir, o mein Gott,\ngroßer König Lob sei Dir und Ehre.\r\nUnd Du reichst mir das Brot,\nund Du reichst mir den Wein\nund bleibst selbst, Herr, mein Begleiter.\r\nUnd Du sendest den Geist,\nund Du machst mich ganz neu\nund erfüllst mich mit Deinem Frieden.\r\nUnd nun zeig mir den Weg,\nund nun führ\' mich die Bahn,\nDeine Liebe zu verkünden.\r\nGib mir selber das Wort,\nöffne Du mir das Herz,\nDeine Liebe, Herr, zu schenken.\r\nUnd ich dank\' Dir, mein Gott,\nund ich preise Dich, Herr,\nund ich schenke Dir mein Leben.'),
(9, '0651', 'Herr, halt mein Herz von Tag zu Tag  -  Lord keep my Soul from Day to Day   (Unter dem Blut, dem teuren Blut)   [Bieselsberg]', 'Lord, keep my soul from day to day,\nunder the blood, under the blood.\nTake doubt and fear and sin away,\nunder the precious blood.\r\nUnder the blood, the precious blood,\nunder the cleansing, healing flood.\nKeep me, Saviour, from day to day,\nunder the precious blood.\r\nThe sinner\'s refuge here alone,\nunder the blood, under the blood.\nHere Jesus makes salvation known,\nunder the precious blood.\r\nSweet peace abides within the heart,\nunder the blood ,under the blood.\nAnd gifts divine their joy impart,\nunder the precious blood.\r\nThe Holy Spirit, hour by hour,\nunder the blood, under the blood.\nExerts His sanctifying power,\nunder the precious blood.', 'Herr, halt mein Herz von Tag zu Tag\nunter dem Blut, unter dem Blut.\nNimm Zweifel, Furcht und Sünd\' mir ab\nunter dem teuren Blut.\r\nUnter dem Blut, dem teuren Blut,\nunter des vollen Heiles Flut.\nHerr bewahre mich Tag für Tag\nunter dem teuren Blut.\r\nDes Sünders Zuflucht ist allein\nunter dem Blut, unter dem Blut.\nNur Jesus gibt ein volles Heil,\nunter dem teuren Blut.\r\nHerr, mit Dir selbst mein Herze still\nunter dem Blut, unter dem Blut.\nWirk\' in mir Deines Willens Füll\'\nunter dem teuren Blut.\r\nDein Heil\'ger Geist wirkt Tag und Nacht\nunter dem Blut, unter dem Blut.\nUnd heiligt mich durch Seine Macht\nunter dem teuren Blut.'),
(9, '0652', 'Herr, hier bring ich mein Alles  -  My Body, Soul and Spirit, Jesus, I give to Thee   (Entzünde jetzt Dein Opfer)', 'My body, soul and spirit,\nJesus, I give to thee,\na consecrated offering,\nThine evermore to be.\r\nMy all is on the altar,\nI’m waiting for the fire.\nWaiting, waiting, waiting,\nI’m waiting for the fire.\r\nO Jesus, mighty Saviour,\nI trust in thy great name.\nI look for thy salvation,\nThy promise now I claim.\r\nO let the fire, descending\njust now upon my soul.\nConsume my humble offering,\nand cleanse and make me whole!\r\nI’m thine, O blessèd Jesus,\nwashed by thy precious blood.\nNow seal me by thy Spirit\na sacrifice to God.', 'Herr, hier bring ich mein Alles:\nLeib, Seel\' und Geist Dir dar,\no Du, mein Hoherpriester,\nnimm hin mich ganz und gar!\r\nEntzünde jetzt Dein Opfer;\nsieh, Herr, hier warte ich,\nwarte, warte, warte,\no tauf\' mit Feuer mich!\r\nO mächtiger Erlöser,\nDu ew\'ger Gnadenhort,\nich wart\' auf Dich im Glauben\nund traue auf Dein Wort!\r\nGieß\' aus des Geistes Flammen,\no Gott, füll\' mich mit Dir!\nIch seufze nach Erlösung;\nDein Wort verheißt es mir.\r\nMit Deinem Blut gewaschen,\nbin ich nun, Herr, ganz Dein.\nLass durch den Geist versiegelt,\nmich Dein auf ewig sein!'),
(9, '0653', 'Herr, ich bleibe nicht dort steh\'n  -  Take me past the outer Court   (Deine Gegenwart, Herr, will ich sehen)', 'Take me past the outer court into Thy Holy Place,\npast the brazen altar, Lord I wanna see Your Face.\nPass me by the crowds of people, the priests who sing Your praise.\nLord I hunger and  thirst for Your righteousness\nand it\'s only found in one place.\r\nTake me in to the Holy of Holies,\nTake me in by the Blood of the Lamb.\nTake me in to the Holy of Holies,\nTake the coal, cleanse my lips, here I am.\r\nIn the outer court I\'m justified, in the Holy Place made clean,\nBut in the Holy of Holies is the Holy Ghost Itself.\nThe mighty Presence of Jehovah and I a prisoner of love,\nLord help me so You can rise me a capstone of love.', 'Herr, ich bleibe nicht dort steh\'n,\nwo die Anbeter sind,\nwill auch nicht dort bleiben,\nwo der Priester Opfer bringt,\nja, und auch den Leuchter Gottes,\nden lasse ich zurück,\nich hungere nach Deiner Gegenwart,\nHerr, nur das hab\' ich im Blick.\r\nDeine Gegenwart, Herr, will ich sehen,\nDeine Gegenwart, Herr, will ich spür\'n,\nDeine Gegenwart in meinem Leben,\nHerr, Dein Feuer soll mich heut\' berühr\'n.\r\nJesus, Du hast viele Gaben, denn Du, Herr, bist so gut,\ndoch ich will mehr haben, denn das ist mir nicht genug,\nja, den Geber aller Gaben, Dich selber suche ich,\nja, Du, die Person auf dem Herzensthron,\noh Herr, erfülle mich!'),
(9, '0654', 'Herr, ich hör von gnäd\'gen Regen, die Du ausgießt mildiglich  -  Lord, I hear of Show\'rs of Blessing, Thou art scatt\'ring full and free', 'Lord, I hear of show\'rs of blessing,\nThou art scatt\'ring full and free!\nShowers the thirsty land refreshing,\nlet some portion fall on me.\nEven me, even me!\nLet some portion fall on me.\r\nPass me not, o gracious Father!\nSinful though my heart may be.\nThou might\'st pass me, but the rather\nlet Thy mercy light on me.\nEven me, even me!\nLet Thy mercy light on me.\r\nPass me not, o tender Saviour!\nLet me love and cling to Thee.\nI am longing for Thy favor,\nwhilst Thou\'rt calling, oh, call me.\nEven me, even me!\nWhilst Thou\'rt calling, oh, call me.\r\nPass me not, O mighty Spirit!\nThou canst make the blind to see.\nWitnesser of Jesus\' merit,\nspeak the word of power to me.\nEven me, even me!\nSpeak the word of power to me.\r\nPass me not! this lost one bringing,\n\'tis but one more, Lord, for Thee!\nAll my heart to Thee is springing.\nBlessing others, oh, bless me.\nEven me, even me!\nBlessing others, oh, bless me.', 'Herr, ich hör von gnäd\'gen Regen,\ndie Du ausgießt mildiglich,\nRegen, die das Land bewegen;\nsende Tropfen auch auf mich!\nAuch auf mich, auch auf mich!\nSende Tropfen auch auf mich!\r\nVater, willst vorbei Du gehen\nan mir, der ich arm und siech?\nNein, o hör mein heißes Flehen,\nblick\' in Gnaden auch auf mich!\nAuch auf mich, auch auf mich!\nBlick\' in Gnaden auch auf mich!\r\nJesu, willst Du nicht erbarmen\nüber meine Seele Dich?\nJa, Du willst, o hilf mir Armen,\nwasche, reinige auch mich!\nJa auch mich, ja auch mich!\nWasche, reinige auch mich!\r\nHeil\'ger Geist, willst Du nicht rühren\nauch mein Herze kräftiglich?\nDu nur kannst zum Himmel führen,\ngieße Deine Kraft in mich!\nAuch in mich, auch in mich!\nGieße Deine Kraft in mich!\r\nHerr, Du segnest ja so gerne,\nbinde mich nur fest an Dich.\nHerr, Du segnest nah und ferne:\nsegne mich, Dein Kind, auch mich!\nJa auch mich, ja auch mich!\nSegne mich, Dein Kind, auch mich!'),
(9, '0655', 'Herr, mein Heiland und mein Hirte  -  Thou, my everlasting Portion   (Dir nach, Dir nach)   [Pfingstjubel]', 'Thou, my everlasting portion,\nmore than friend or life to me.\nAll along my pilgrim journey,\nSaviour, let me walk with Thee.\nClose to Thee, close to Thee,\nClose to Thee close to Thee;\nAll along my pilgrim journey,\nSaviour, let me walk with Thee.\r\nNot for ease or worldly pleasure,\nnor for fame my prayer shall be.\nGladly will I toil and suffer,\nonly let me walk with Thee.\nClose to Thee, close to Thee,\nClose to Thee, close to Thee;\nGladly will I toil and suffer,\nonly let me walk with Thee.\r\nLead me through the vale of shadows,\nbear me o\'er life\'s fitful sea.\nThen the gate of life eternal,\nmay I enter, Lord with Thee.\nClose to Thee, close to Thee,\nClose to Thee, close to Thee;\nThen the gate of life eternal,\nMay I enter, Lord with Thee.\r\n', 'Herr, mein Heiland und mein Hirte,\nder des Lebens Bahn mir brach,\nich bin Dein von ganzem Herzen,\nDir nur will ich folgen nach!\nDir nach! Dir nach!\nDir nach! Dir nach!\nIch bin Dein von ganzem Herzen,\nDir nur will ich folgen nach!\r\nDu bist meine Sonn\' in Freuden,\nDu mein Trost in Ungemach.\nSeh\' ich Deines Fußes Spuren,\no da will ich folgen nach!\nDir nach! Dir nach!\nDir nach! Dir nach!\nSeh\' ich Deines Fußes Spuren,\no da will ich folgen nach!\r\nFühr\' mich durch dies Erdentale,\nhalt mein Herze treu und wach,\nbis Du kommst, dann hin zum Throne,\nlass mich froh Dir folgen nach!\nDir nach! Dir nach!\nDir nach! Dir nach!\nDurch die Schmach zur Ehrenkrone,\nHerr, Dir will ich folgen nach!\r\nNimm mich hin zu Deinem Dienste,\ntue, was Dein Mund versprach,\ngeh voran, Du großer Meister,\nso will ich Dir folgen nach!\nDir nach! Dir nach!\nDir nach! Dir nach!\nGeh voran, Du großer Meister,\nso will ich Dir folgen nach!'),
(9, '0656', 'Herr, mit Inbrunst bitten wir nicht ein irdisch Gut von Dir   (Sieh wir wollen, Herr, du weißt, wandeln nur nach Deinem Geist)', NULL, 'Herr, mit Inbrunst bitten wir\nnicht ein irdisch Gut von Dir,\nnichts, womit man eitel prangt,\nnichts, wonach die Welt verlangt.\r\nSieh wir wollen, Herr, du weißt,\nwandeln nur nach Deinem Geist;\nnichts soll Seinem sanften Weh\'n\nhemmend mehr im Wege steh\'n!\nNimm, o nimm, Du allein,\nbleibend unsre Herzen ein!\r\nNicht das Fleisch, der Geist allein\nsoll in uns der Herrscher sein,\nund wir wollen lauschen still,\nwenn Er mit uns reden will.\r\nEr allein bestimme nun\nunser Denken, Reden, Tun\nalso, dass sich kein Gebiet\nSeinem Einfluss mehr entzieht.\r\nUnter Deines Geistes Zucht\nreife still die Geistesfrucht;\njeder müsse an uns seh\'n\ndas, was in uns ist gescheh\'n.\r\nWelche Gnade liegt darin,\nganz zu tun nach Deinem Sinn,\nals Dein Werkzeug dazusteh\'n,\nsich von Dir gebraucht zu seh\'n.'),
(9, '0657', 'Herr, weil mich festhält Deine starke Hand, vertrau ich still', NULL, 'Herr, weil mich festhält Deine starke Hand,\nvertrau ich still.\nWeil Du voll Liebe Dich zu mir gewandt,\nvertrau ich still.\nDu machst mich stark, Du gibst mir frohen Mut.\nIch preise Dich: Dein Wille, Herr, ist gut.\r\nHerr, weil ich weiß, dass Du mein Retter bist,\nvertrau ich still.\nWeil Du für mich das Lamm geworden bist,\nvertrau ich still.\nWeil ich durch Dich dem Tod entrissen ward,\npräg\' tief in mir, Herr, Deine Lammesart.\r\nHerr, weil Du jeden Weg nun mit mir gehst,\nvertrau ich still.\nWeil Du zu meiner Rechten helfend stehst,\nvertrau ich still.\nDroht mir der Feind, so schau ich hin auf Dich,\nein Bergungsort bist Du, oh, Herr, für mich.\r\nIst auch die Zukunft meinem Blick verhüllt,\nvertrau ich still.\nSeitdem ich weiß, dass sich Dein Plan erfüllt,\nvertrau ich still.\nSeh\' ich nicht mehr als nur den nächsten Schritt,\nmir ist\'s genug! Mein Herr geht selber mit.'),
(9, '0658', 'Herr, wir loben Deine Gnade  -  How I praise Thee, precious Saviour   (Nur Gefäße, heilger Meister)', 'How I praise Thee, precious Saviour,\nthat Thy love laid hold of me.\nThou hast saved and cleansed and filled me\nthat I might Thy channel be.\r\nChannels only, blessed Master,\nbut with all thy wondrous power.\nFlowing through me, thou canst use me\nevery day and every hour.\r\nJust a channel full of blessing,\nto the thirsty hearts around.\nTo tell out Thy full salvation,\nall Thy loving message sound.\r\nEmptied that Thou shouldest fill me,\na clean vessel in Thy hand.\nWith no pow’r but as Thou givest\ngraciously with each command.\r\nWitnessing Thy pow’r to save me,\nsetting free from self and sin.\nThou who boughtest to possess me,\nin Thy fullness, Lord, come in.\r\nJesus, fill now with Thy Spirit\nhearts that full surrender know.\nThat the streams of living water\nfrom our inner self may flow.', 'Herr, wir loben Deine Gnade,\ndie uns ganz für Dich gewann,\nrettend, rein\'gend und erfüllend,\nuns Dir bräuchlich machen kann.\r\nNur Gefäße, heil\'ger Meister,\ndoch gefüllt mit Deiner Kraft,\nlass für uns und durch uns strömen\nLeben, das Dein Geist uns schafft!\r\nNur Gefäße, doch von Segen\nfür die Durstgen  rings umher,\nlass uns sein, geliebter Heiland,\nmach dazu uns täglich mehr!\r\nLeer, damit Du ganz uns füllest\nals Gefäße Deiner Hand,\nund mit keinem andern Siegel\nals nur dem "von Dir gesandt".\r\nVon der Rettermacht zu zeugen,\ndie von Sünden uns befreit,\ndazu sind wir ausgesondert,\ndazu hast Du uns geweiht.\r\nJesus, füll\' mit Deinem Geiste\njedes Herz, das völlig Dein,\nlass den Strom lebend\'gen Wassers\nbei und durch uns mächtig sein!'),
(9, '0659', 'Herr, wir preisen Dich  -  Lord, we praise You   (3 Chorusse)', 'Lord, we praise You,\nLord, we praise You,\nLord, we praise You,\nwe praise You, Lord.\r\nLord, we thank You,\nLord, we thank You,\nLord, we thank You,\nwe thank You, Lord.\r\nLord, we praise You,\nLord, we praise You,\nLord, we praise You,\nwe praise You, Lord.', 'Herr, wir preisen,\nHerr, wir preisen,\nHerr, wir preisen,\nwir preisen Dich.\r\nHerr wir danken,\nHerr wir danken,\nHerr wir danken,\nwir danken Dir.\r\nHerr wir loben,\nHerr wir loben,\nHerr wir loben,\nwir loben Dich.'),
(9, '0660', 'Herr, wohin sollen wir gehen', NULL, 'CHORUS\nHerr, wohin sollen wir gehen,\nDu hast Worte des ewigen Lebens,\nund wir haben erkannt, haben erkannt:\nDu bist Christus!\r\nKeiner muss rätseln und raten,\ndenn Deine Worte und Taten\nsind für uns sichtbar geschehen,\nganz deutlich können wir sehen:\r\nAuch wenn in unseren Tagen\nMenschen nur zweifeln und fragen\nund jetzt den Glauben verlassen,\nweil sie die Wahrheit verpassen...\r\nAuch, wenn sich Menschen abwenden,\nmeinen, was Bess\'res zu finden:\nNirgendwo sonst kann es geben,\nwas wir hier bei Dir erleben!\r\nWir sind von Dir eingeladen,\nseh\'n Deinen Tisch, Deine Gaben,\ndürfen von Deinem Wort essen,\nund die Welt um uns vergessen...'),
(9, '0661', 'Herrlich wogt das goldne Ährenfeld  -  See the shining Fields of waving Grain   (Jesus ruft auch mich und dich)', 'See the shining fields of waving grain,\nSee the harvest fields so white!\nOverspreading ev\'ry hill and plain,\nSee the harvest fields so white!\r\nThere is work each may do,\nwork for me, work for you.\nAnd the lab\'rers are so very few\nin the harvest fields so white!\r\nHear the Saviour, as he calleth thee\nto the harvest fields so white!\n"Come and labor earnestly for me\nin the harvest fields so white!"\r\nHaste! the Master\'s urgent call obey,\nsee the harvest fields so white!\nQuickly join the reaper\'s ranks today\nin the harvest fields so white!', 'Herrlich wogt das goldne Ährenfeld,\nsieh die Ernte reif und weiß!\nGottes Acker ist die weite Welt;\nsieh die Ernte reif und weiß!\r\nJesus ruft auch mich und dich;\nEr belohnt uns königlich!\nDarum wirken wir auf Sein Geheiß\nin der Ernte reif und weiß.\r\nHör auf Jesus, denn Er ruft auch dich\nin die Ernte reif und weiß:\n"Komm herbei und wirke treu für Mich\nin der Ernte reif und weiß!\r\nEile, denn der Meister ladet ein\nin die Ernte reif und weiß!\nTritt noch heute in der Schnitter Reih\'n,\nin die Ernte reif und weiß!'),
(9, '0662', 'Herrliche Botschaft der Liebe, sag sie mir noch einmal  -  Wonderful Story of Love, tell it to me again   (Wunderbar wunderbar! Botschaft der Liebe, Botschaft für dich und für mich)', 'Wonderful story of love,\ntell it to me again.\nWonderful story of love,\nwake the immortal strain.\nAngels with rapture announce it,\nshepherds with wonder receive it.\nSinner, O won’t you believe it?\nWonderful story of love!\r\nWonderful! Wonderful!\nWonderful story, Wonderful story of love! (2x)\r\nWonderful story of love,\nthough you are far away.\nWonderful story of love,\nstill He doth call today.\nCalling from Calvary’s mountain,\ndown from the crystal bright fountain.\nE’en from the dawn of creation,\nwonderful story of love!\r\nWonderful story of love,\nJesus provides a rest.\nWonderful story of love,\nfor all the pure and blest.\nRest in those mansions above us,\nwith those who’ve gone on before us.\nSinging the rapturous chorus,\nWonderful story of love!', 'Herrliche Botschaft der Liebe,\nsag sie mir noch einmal.\nHerrliche Botschaft der Liebe,\nan eine Welt voll Qual.\nEngel entzückt sie verkünden,\nHirten erstaunt lauschen ihr.\nUnd du gebund\'ner in Sünden,\nhör diese Botschaft gilt dir.\r\nWunderbar wunderbar! Botschaft der Liebe,\nBotschaft für dich und für mich. (2x)\r\nHerrliche Botschaft der Liebe,\nGott hat den Sohn gesandt.\nHerrliche Botschaft der Liebe,\nHölle und Tod gebannt.\nSterbend auf Golgatha\'s Höhen,\nopfert sich selbst für und für,\nließ er uns Gnade erstehen,\nhör diese Botschaft gilt dir.\r\nHerrliche Botschaft der Liebe,\nLabsal im Todestal.\nHerrliche Botschaft der Liebe,\nöffnet den Himmelssaal.\nJubelnd und rauschend dort tönet,\ntausendmal schöner als hier,\nGott ist mit Menschen versöhnet,\nhör diese Botschaft gilt dir.'),
(9, '0663', 'Herrliche Kleider rein, herrlich die Heimat mein  -  Beautiful Robes so white, beautiful Land of Light   (Herrliches Kleid, herrliches Land)', 'Beautiful robes so white! Beautiful land of light!\nBeautiful home so bright, where there shall come no night.\nBeautiful crown I\'ll wear, shining with stars o\'er there,\nyonder in mansions fair, gather us there.\r\nBeautiful robes, beautiful land,\nBeautiful home, beautiful band!\nBeautiful crown, shining so fair!\nBeautiful mansion bright gather us there.\r\nBeautiful tho\'t to me, we shall forever be,\nThine in eternity, when from this world we\'re free.\nFree from its toil and care, heavenly joys to share.\nLet me cross over there, this is my pray\'r.\r\nBeautiful things on high, over in yonder sky,\nthus I shall leave this shore, Counting my treasures o\'er.\nWhere we shall never die, carry me by and by.\nNever to sorrow more, heavenly shore.', 'Herrliche Kleider rein! Herrlich die Heimat mein!\nHerrlich das Land wird sein, herrlich der Lichtesschein,\nwohin kein Dunkel dringt! Dort mir die Krone winkt,\nsternengeziert sie bringt Jesus, mein Herr.\r\nHerrliches Kleid, herrliches Land,\nherrliches Heim! Liebe das Band!\nHerrlich die Kron\' im Lichtesschein!\nHerrliche Wohnungen nehmen wir ein!\r\nHerrlicher Hoffnungsstern, dem ich nun folge gern\nin meine Heimat fern zu meinem treuen Herrn,\ndass ich, von allem frei, ewig dort glücklich sei!\nHöre, Herr, meinen Schrei und steh mir bei!\r\nHerrliche Himmelslust füllt uns schon hier die Brust;\ndoch sind wir uns bewusst und sind auch stets getrost,\ndass in der Ewigkeit herrliche Seligkeit,\nvöllige Herrlichkeit uns ist bereit.'),
(9, '0664', 'Herrliche Stunden an Jesu Seite das ist mein Leben heut   (O komm doch heut, o komm doch heut)', NULL, 'Herrliche Stunden an Jesu Seite, das ist mein Leben heut\',\neinstmals da hielt mich Satan gebunden, jetzt juble ich voll Freud\'.\nUnd mit dem Heiland in meinem Leben, so zieh ich himmelan.\nOb Stürme toben, ich blick nach oben, Jesus geht mir voran.\r\nO komm doch heut\', o komm doch heut\', zu deinem Heiland,\nzu deinem Heiland komm doch heut\'. (2x)\r\nStunden der Gnade, Stunden des Segens, Jesus uns täglich gibt.\nSind rau und steinig manchmal die Pfade, ich weiß das Er mich liebt.\nD\'rum will ich wandern an Seiner Seite heimwärts ins bess\'re Land.\nEngel sie singen und Palmen schwingen, warten am gold\'nen Strand.\r\nStunden verrinnen, Jahre vergehen, es naht die Ewigkeit,\nwillst du ein neues Leben beginnen, Freund o dann komm noch heut\'.\nBeug\' dich vor Jesus, sag Ihm die Sünde und alles was dich drückt.\nEr wird dir geben ewiges leben und du bist hoch beglückt.'),
(9, '0665', 'Herrlicher Jesus, Ihn werden wir seh\'n  -  Glorious Jesus, ever shall see   (Bald sind wir zu Hause, bald sind wir daheim)', 'Glorious Jesus, ever shall see,\nheartaches have ended, those beautiful streets.\nno pain, no war; original fore.\nIt is so glorious to know, that we\'re nearing the shore.\r\nWe\'re nearing the shore, we\'re nearing the shore.\nTroubles soon will be over, we\'ll suffer no more.\nTrials all passed, victory at last.\nOh it\'s so wonderful to be nearing the shore.\r\nWe\'ll see the lighthouse, Jesus divine.\nHe will say: "Welcome, children of mine.\nCome in and rest, it\'s land possessed."\nOh, it\'s so wonderful, to be nearing the shore.', 'Herrlicher Jesus, Ihn werden wir seh\'n,\nder Kummer vorüber, am himmlischen Strand.\nKein Schmerz, kein Krieg, nur das Original.\nEs ist so wunderbar, bald sind wir zu Haus\'.\r\nBald sind wir zu Hause, bald sind wir daheim.\nDie Sorgen verschwinden, das Leid ist vorbe.\nVersuchung vorüber, Sieg ist dann mein.\nEs ist so wunderbar, bald sind wir daheim.\r\nDort seh\'n wir den Leuchtturm, Jesus, Ihn selbst.\nEr sagt: "Willkommen, Kinder des Herrn.\nKommet und ruht im verheiß\'nen Land."\nEs ist so wunderbar, bald sind wir zu Haus\'.'),
(9, '0666', 'Herrlicher Tag', NULL, 'Einst, als im Himmel der strahlendste Tag war\nHerrschte auf Erden die dunkelste Nacht\nDa wurde Jesus als Mensch geboren\nEr hat uns Gnade und Wahrheit gebracht\nDas Wort wurde Fleisch und das Licht wohnte bei uns\nEs scheint in der Nacht\r\nFür uns geboren, für uns gestorben\nEr nahm die Sünde der Welt mit ins Grab\nAm dritten Tag ist er auferstanden\nEinst wird er kommen, welch herrlicher Tag\nWelch herrlicher Tag\r\nDann führten sie ihn hinauf um zu sterben\nAns Holz genagelt, das Kreuz aufgestellt\nDer Mann der Schmerzen verachtet, verstoßen, er trug die Sünde\nDer Heiland der Welt\nDie heilenden Hände sind weit ausgebreitet für unsere Schuld\r\nAm dritten Tag hielt das Grab ihn nicht länger\nWeg war der Stein und die Grabkammer leer\nEr ist auferstanden, den Tod überwunden\nEr fuhr auf zum Himmel, der siegreiche Herr\nEr gab neues Leben\nDie Schuld ist vergeben, mein Retter ist er\r\nOh bald wird der Tag seiner Wiederkunft kommen\nBald werden wir ihn in Herrlichkeit sehen\nEr wird die Seinen dann ganz zu sich nehmen\nStaunend werd ich vor ihm stehen'),
(9, '0667', 'Herrliches Golgatha, herrliches Golgatha   (Chorus)', NULL, 'Herrliches Golgatha,\nherrliches Golgatha!\nMeine Sünd\' ist vergeben,\nmeine Schuld ist bezahlt,\nherrliches Golgatha!'),
(9, '0668', 'Herrliches, liebliches Zion, Stätte der selgen Ruh  -  Beautiful valley of Eden, sweet is thy Noontide calm   (Herrliches, liebliches Zion, Heimat dir eil ich zu)', 'Beautiful valley of Eden!\nSweet is thy noontide calm.\nOver the hearts of the weary,\nbreathing thy waves of balm.\r\nBeautiful valley of Eden,\nhome of the pure and blest.\nHow often amid the wild billows,\nI dream of thy rest, sweet rest!\r\nOver the heart of the mourner\nshineth thy golden day.\nWafting the songs of the angels\ndown from the far away.\r\nThere is the home of my Saviour,\nthere, with the blood-washed throng.\nOver the highlands of glory\nrolleth the great new song.', 'Herrliches, liebliches Zion,\nStätte der sel\'gen Ruh\',\nflößest verwundeten Herzen\nheilenden Balsam zu.\r\nHerrliches, liebliches Zion,\nHeimat dir eil\' ich zu.\nWie oft sing ich sehnend hier unten\nvon deiner so sel\'gen Ruh\'!\r\nHier geht umnachteten Seelen\ngolden die Sonne auf.\nHier schließt mit himmlischen Chören\nselig der Pilgerlauf.\r\nDa ist der Thron meines Heilands,\nwo jedes Herz erglüht,\nwenn durch die Ewigkeit rauschet\nherrlich das neue Lied.'),
(9, '0669', 'Herrscher der Ewigkeit, König der Zeit', NULL, 'Herrscher der Ewigkeit, König der Zeit,\nSchöpfer des Weltenalls,Licht ist Dein Kleid.\nDu, den kein sterblich Aug\' je noch geseh\'n,\nhör unsern Lobgesang, hör unser Fleh\'n!\r\nHerrlich und wunderbar ist Deine Macht.\nAuf dein allmächtig Wort floh einst die Nacht,\nflammte der Sterne Licht unzählig auf,\nnahm durch den Weltenraum es seinen Lauf.\r\nHimmel und Erde jauchzt, Vater, Dir zu;\nbist doch im Weltenall Herrscher nur Du.\nRühmet der Engel Heer, was Du getan,\no so nimm unser Lied gnädig auch an!'),
(9, '0670', 'Herz und Herz vereint zusammen sucht in Gottes Herzen Ruh', NULL, 'Herz und Herz vereint zusammen sucht in Gottes Herzen Ruh\',\nlasset eure Liebesflammen lodern auf den Heiland zu.\nEr das Haupt, wir Seine Glieder; Er das Licht, und wir der Schein;\nEr der Meister, wir die Brüder; Er ist unser, wir sind Sein.\r\nKommt, ach kommt, Ihr Gnadenkinder, und erneuert euren Bund,\nschwöret unserm Überwinder Lieb und Treu aus Herzensgrund.\nUnd wenn eurer Liebeskette Festigkeit und Stärke fehlt,\no, so flehet um die Wette, bis sie Jesus wieder stählt.\r\nAch, Du holder Freund vereine Deine Dir geweihte Schar,\ndass sie es so herzlich meine, wie\'s Dein letzter Wille war.\nJa, verbinde in der Wahrheit, die Du selbst im Wesen bist,\nalles, was von Deiner Klarheit in der Tat erleuchtet ist.\r\nLiebe, hast Du es geboten, dass man Liebe üben soll,\no so mache doch die toten, trägen Geister lebensvoll!\nZünde an die Liebesflamme, dass ein jeder sehen kann:\n"Wir als die von einem Stamme, stehen auch für einen Mann."\r\nLass uns so vereinigt werden, wie Du mit dem Vater bist.\nBis schon hier auf dieser Erden kein getrenntes Glied mehr ist;\nund allein von deinem Brennen nehme unser Licht den Schein.\nAlso wird die Welt erkennen, dass wir Deine Jünger sein.'),
(9, '0671', 'Heute will dich Jesus fragen: Bist du ganz für mich bereit   (Wag es mit Jesus, was deine Not auch sei)', NULL, 'Heute will dich Jesus fragen:\nBist du ganz für mich bereit?\nDu verlierst dich sonst im Jagen\nnach den Gütern dieser Zeit.\r\nWag\' es mit Jesus, was deine Not auch sei.\nWag\' es mit Jesus, Er macht dich frei!\nWag\' es mit Jesus, Er macht dich frei!\r\nRühmst dich deiner Kraft und Gaben,\nnur dich selbst bezwingst du nicht.\nMut muss man bei Jesus haben,\nMenschenfurcht führt zum Verzicht.\r\nLass dich nicht von Menschen leiten,\nMenschen sind wie Laub im Wind.\nJesus schafft Persönlichkeiten,\ndie das Salz der Erde sind.\r\nEinmal fällt die Maskerade,\ndie du vor der Welt beziehs.,\nWenn du durch Gericht und Gnade\ndich im Lichte Gottes siehst.'),
(9, '0672', 'Hier auf dem Lebensmeere die Wogen toben wild  -  Upon life\'s boundles Ocean where mighty Billows roll   (Verankert in Jesus)', 'Upon life\'s boundless ocean where mighty billows roll,\nI\'ve fixed my hope in Jesus, blest anchor of my soul.\nWhen trials fierce assail me as storms are gathering o\'er.\nI rest upon His mercy and trust Him more.\r\nI\'ve anchored in Jesus, the storms of life I\'ll brave.\nI\'ve anchored in Jesus, I fear no wind or wave.\nI\'ve anchored in Jesus, for He hath pow\'r to save.\nI\'ve anchored in the Rock of Ages.\r\nHe keeps my soul from evil and gives me blessed peace.\nHis voice hath stilled the waters and bid their tumult cease.\nMy pilot and deliv\'rer, To Him I all confide.\nFor always when I need Him, He\'s at my side,\r\nHe is my Friend and Saviour, in Him my anchor\'s cast.\nHe drives away my sorrows and shields me from the blast.\nBy faith I\'m looking upward Beyond life\'s troubled sea.\nThere I behold a haven prepared for me.', 'Hier auf dem Lebensmeere die Wogen toben wild.\nMein Hoffen ist auf Jesus, mein Anker und mein Schild.\nWenn Stürme mich umtosen, die Prüfung bitterschwer,\nvertrau\' ich seiner Gnade und fürcht\' nichts mehr.\r\nVerankert in Jesus, ich bin in Sicherheit.\nVerankert in Jesus, von Furcht und Pein befreit.\nVerankert in Jesus für Zeit und Ewigkeit.\nVerankert bin ich in dem Felsen.\r\nEr schützt die Seel\' vom Übel, den Frieden Er mir schenkt,\ngebietet Wind und Wellen, wie wunderbar Er\'s lenkt.\nMein Führer und Befreier, ich trau\' Ihm alles zu,\nin allen meinen Nöten schenkt Er mir Ruh\'.\r\nEr ist mein Freund und Heiland, mein Anker in Ihm ruht,\nEr treibt hinweg die Sorgen und schützt mich vor der Flut.\nIm Glauben seh\' ich jenseits des Lebens rauher See,\nden Hafen meiner Ruhe in Sel\'ger Höh\'.'),
(9, '0673', 'Hier bin ich, Herr, hier bin ich  -  Here I am, Lord, here I am   (Chorus)', 'Here I am, Lord, here I am.\nI give all myself to You, here I am.\nHere I am, Lord, here I am.\nFill me with Thy Holy Ghost\nand here I am.', 'Hier bin ich, Herr, hier bin ich.\nIch übergeb\' mich Dir, Herr Jesus, hier bin ich.\nHier bin ich, Herr, hier bin ich,\nfülle mich mit Deinem Geist,\nHerr hier bin ich.'),
(9, '0674', 'Hier bin ich, klein vor Deiner Herrlichkeit (Majestät)  -  Here I am, humbled by Your Majesty   (Majestät, Majestät, verändert bin ich für alle Zeit)', 'Here I am, humbled by Your Majesty,\ncovered by Your Grace so free.\nHere I am, knowing I\'m a sinful man,\ncovered by the blood of the Lamb.\nNow I\'ve found, the greatest love of all is mine,\nsince You laid down Your Life,\nthe greatest Sacrifice.\r\nMajesty, Majesty,\nYour Grace has found me just as I am,\nempty handed, but alive in Your hands.\r\nHere I am, humbled by the Love that You give,\nforgiven so that I can forgive.\nHere I stand, knowing that I\'m Your desire,\nsanctified by Glory and Fire.\nNow I\'ve found, the greatest love of all is mine,\nsince You laid down Your Life,\nthe greatest Sacrifice.\r\nMajesty, Majesty,\nforever I am changed by Your Love,\nin the presence of Your Majesty.', 'Hier bin ich, klein vor Deiner Herrlichkeit,\nDeine Gnade hat mich befreit!\nHier bin ich, kenne meine Sünde gut,\ndoch Du machst mich rein durch Dein Blut.\nIch fand ja, die allergrößte Liebe da,\nwo Du Dein Leben gabst,\ndas größte Opfer warst.\r\nMajestät, Majestät,\nich bin, wie Deine Gnade mich fand,\nleer und dennoch leb\' ich in Deiner Hand.\r\nHier bin ich, demütig weil Du mich liebst,\nvergeben kann ich, weil Du vergibst.\nHier bin ich, weiß nur Dich verlangt nach mir,\ngeheiligt durch das Feuer in Dir.\nIch fand ja, die allergrößte Liebe da,\nwo Du Dein Leben gabst,\ndas größte Opfer warst.\r\nMajestät, Majestät,\nverändert bin ich für alle Zeit,\nin der Nähe Deiner Herrlichkeit.'),
(9, '0675', 'Hier hast du meine beiden Hände', NULL, 'Hier hast du meine beiden Hände,\nich kann ja nichts aus eig\'ner Kraft!\nDu weißt den Weg, Du weißt das Ende,\nbring du mich durch die Pilgerschaft.\r\nAch, leite mich mit Deinen Augen\nauf jeden Schritt im dunklen Tal!\nWie gar nichts meine Kräfte taugen,\nich fühl\' es täglich tausendmal.\r\nIch müsste ja vor Angst verzagen,\nwüsst\' ich nicht, dass Du mit mir gehst,\ndass Deine Schultern für mich tragen,\nund dass im Kampf Du bei mir stehst.\r\nIch bitte nur, das bis zum Ende\ndu mich in Dein Erbarmen hüllst.\nHier hast Du meine beiden Hände,\nnun mache mit mir, was Du willst!'),
(9, '0676', 'Hier ist mein Herz! mein Gott, ich geb es Dir', NULL, 'Hier ist mein Herz!\nMein Gott, ich geb\' es Dir,\nDir, der es gnädig schuf.\n"Nimm es der Welt,\nmein Kind, und gib es Mir!"\nDas ist an mich Dein Ruf.\nHier ist das Opfer meiner Liebe;\nich weih es Dir aus treuem Triebe;\n||: hier ist mein Herz! :||\r\nHier ist mein Herz!\nO nimm es gnädig an,\nob ihm gleich viel gebricht.\nIch geb\' es Dir,\nso gut ich\'s geben kann.\nVerschmäh\' die Gabe nicht!\nEs ist mit böser Lust beflecket,\nmit Sünd\' erfüllt, mit Schuld bedecket,\n||: mein sündig Herz! :||\r\nHier ist mein Herz!\nEs sucht in Christo Heil,\nes naht zum Kreuze hin\nund spricht: "O Herr,\nDu bist mein Gut und Teil,\nDein Tod ist mein Gewinn!"\nEs hat in des Erlösers Wunden\nTrost, Ruh\' und Seligkeit gefunden\n||: mein gläubig Herz! :||'),
(9, '0677', 'Hier sind wir vor dem Herrn, heil\'ge Hände heben wir  -  Here we are in Your Presence, lifting holy hands to You   (Chorus)', 'Here we are in Your Presence,\nlifting holy hands to You.\nHere we are praising Jesus,\nfor the things He\'s brought us through.\r\nI don\'t have the words to tell You how I feel,\nI just don\'t know what I can say.\nI\'m not worthy to speak Your Holy Name,\nyet You tell me You love me just the same.\r\nI never thought that it could be this way,\nand I never thought I\'d be the one.\nBut You found me dying in my sin,\nand You looked at me with love that took me in.\r\nHere we are in Your Presence,\nlifting holy hands to You.\nHere we are praising Jesus,\nfor the things He\'s brought us through,\nfor the things He\'s brought us through.', 'Hier sind wir vor dem Herrn,\nheil\'ge Hände heben wir,\nhier sind wir, preisen Jesus,\ndenn aus Gnade leben wir.\r\nMir fehlen die Worte, um Dir zu sagen, was ich fühle,\nich weiß einfach nicht, was ich sagen kann.\nIch bin nicht würdig, Deinen heiligen Namen auszusprechen,\nund doch sagst Du mir, dass Du mich trotzdem liebst.\r\nIch hätte nie gedacht, dass es so sein könnte,\nund ich hätte nie gedacht, dass ich derjenige sein würde.\nAber Du fand\'st mich sterbend in meiner Sünde,\nund Du sahst mich mit Liebe an, die mich aufnahm.\r\nHier sind wir vor dem Herrn,\nheil\'ge Hände heben wir,\nhier sind wir, preisen Jesus,\ndenn aus Gnade leben wir,\ndenn aus Gnade leben wir.'),
(9, '0678', 'Himmel und Erde werden vergeh\'n, Du aber bleibst   (Psalm 102, 27)', NULL, 'Himmel und Erde werden vergeh\'n,\nwerden alt, werden und nicht besteh\'n,\nDu wechselst sie, Herr, wie ein Gewand,\nwirst sie verwandeln mit Deiner Hand...\r\nDu aber bleibst\nimmer Derselbe\nund Deine Zeit,\nsie hat kein Ende,\newig bist Du,\nwirst nie vergehen,\nund wer Dich kennt,\nder kennt das Leben!\r\nDu hast den Grund dieser Erde gelegt,\naus Dir kommt alles, was heute lebt,\nDu bist das Leben, dem keines gleicht,\nnichts hier auf Erden in uns\'rer Zeit...\r\nHerr, Du kamst zu uns in uns\'re Nacht,\nund hast Dein Leben zu uns gebracht,\ndas gibt uns Frieden, wenn man auch sieht,\ndas unser äuß\'rer Mensch doch vergeht...\r\nWas uns belastet, kann nicht besteh\'n,\nwird mit dem Staub der Geschichte vergeh\'n.\nWarum dann sorgen, warum das Leid?\nDie Last von heute geht mit der Zeit...'),
(9, '0679', 'Himmlischer Vater, ich bete Dich an  -  Heavenly Father, I appreciate You', 'Heavenly Father, I appreciate you,\nHeavenly Father, I appreciate you,\nI love you, adore you,\nI bow down before you,\nHeavenly Father, I appreciate you.', 'Himmlischer Vater, ich bete Dich an.\nHimmlischer Vater, ich bete Dich an.\nIch lieb\' Dich und ehr\' Dich,\nknie vor Dir nieder.\nHimmlischer Vater, ich bete Dich an.'),
(9, '0680', 'Hinter den Vorhang zu gehn  -  Just beyond the Vail   (3 Chorusse)', 'Just beyond the veil,\nI long to see Your face,\nJust to see the beauty there,\njust beyond the veil.\r\nBeautiful You are,\nBeautiful You are,\nBeautiful You are, You are.\nBeautiful You are.\r\nYou\'re the Prince of Peace,\nYou\'re the Prince of Peace,\nYou\'re the Prince of Peace, You are.\nYou\'re the Prince of Peace.', 'Hinter den Vorhang zu geh\'n,\nDeine Schönheit zu seh\'n,\nauf Dein Angesicht zu schau\'n;\ndas ist\'s, wonach ich mich seh\'n.\r\nWunderschön bist Du,\nWunderschön bist Du!\nLass mich heute vor Dir steh\'n,\nDeine Schönheit zu seh\'n.\r\n'),
(9, '0681', 'His heart was broken, mine was mended   (His Life for mine, His Life for mine)', 'His heart was broken, mine was mended,\nHe became sin, now I am clean,\nthe cross he carried bore my burden,\nthe nails that held Him set me free.\r\nHis life for mine, His life for mine,\nhow could it ever be?\nThat He would die, God\'s son would die,\nto save a wretch like me.\nWhat love divine,\nHe gave His life for mine.\r\nHis scars of suffering brought me healing,\nHe spilled His blood to fill my soul,\nHis crown of thorns made me royalty,\nHis sorrow gave me joy untold.\r\nHe was despised and rejected,\nstripped of his garment and oppressed.\nI am loved and accepted,\nand I wear a robe of righteousness.', NULL),
(9, '0682', 'His mercy is more', 'What love could remember no wrongs we have done\nOmniscient, all knowing, He counts not their sum\nThrown into a sea without bottom or shore\nOur sins they are many, His mercy is more\r\nPraise the Lord, His mercy is more\nStronger than darkness, new every morn\nOur sins they are many, His mercy is more\r\nWhat patience would wait as we constantly roam\nWhat Father, so tender, is calling us home\nHe welcomes the weakest, the vilest, the poor\nOur sins they are many, His mercy is more\r\nWhat riches of kindness He lavished on us\nHis blood was the payment, His life was the cost\nWe stood \'neath a debt we could never afford\nOur sins they are many, His mercy is more', 'Welche Liebe könnte sich keiner unserer Fehler erinnern\nAllwissend, zählt Er sie doch nicht\nGeworfen in ein Meer ohne Boden und Ufer\nUnsere Sünden waren viele,  Seine Gnade ist mehr\r\nPreis den Herrn,  Seine Gnade ist mehr\nStärker als Dunkelheit,  neu jeden Morgen\nUnsere Sünden sind viele,  Seine Gnade ist mehr\r\nWelche Geduld würde warten während wir immer umherirren\nWelcher Vater, so sanft, ruft uns nach Hause\nEr empfängt die Schwächsten, die Gemeinsten die Armen\nUnsere Sünden sind viele, Seine Gnade ist mehr\r\nWelche Reichtümer der Freundlichkeit verschwendet Er an uns\nSein Blut war die Bezahlung, Sein Leben der Preis\nWir standen mit einer Schuld die wir niemals bezahlen konnten\nUnsere Sünden sind viele,  Seine Gnade ist mehr'),
(9, '0683', 'Holy forever', 'A thousand generations falling down in worship\nTo sing the song of ages to the Lamb\nAnd all who\'ve gone before us and all who will believe\nWill sing the song of ages to the Lamb\r\nYour name is the highest Your name is the greatest\nYour name stands above them all\nAll thrones and dominions All powers and positions\nYour name stands above them all\r\nAnd the angels cry holy All creation cries holy\nYou are lifted high, holy Holy forever\nHear Your people sing holy To the King of kings, holy\nYou will always be holy Holy forever\r\nIf you\'ve been forgiven and if you\'ve been redeemed\nSing the song forever to the Lamb\nIf you walk in freedom and if you bear His name\nSing the song forever to the Lamb\nWe\'ll sing the song forever and amen', 'tausend Generationen fallen nieder in Anbetung\nSingen das Lied von Zeiten her für das Lamm\nAlle die vor uns gegangen sind und alle die glauben werden\nSingen das Lied von Zeiten her für das Lamm\r\nDein Name ist der höchste, Dein Name ist der gerößte\nDein Name steht über Ihnen allen\nAlle Throne und Herrschaften, alle Kräfte und Positionen \nDein Name steht über ihnen allen\r\nUnd die Engel rufen Heilig\nDie ganze Schöpfung ruft Heilig\nDu bist hoch erhoben, Heilig Heilig für immer\nHöre dein Volk singen Heilig für den König der Könige Heilig\nDu wirst immer sein Heilig, Heilig für immer\r\n'),
(9, '0684', 'Holy Holy Holy are you Lord', 'Holy, holy, holy are You Lord\nHoly, holy, holy are You Lord\nThe Elders and Angels bow\nThe redeemed worship You now\nHoly, holy, holy are You Lord', NULL),
(9, '0685', 'Holy Spirit come and fill me   (Chorus)', 'Holy Spirit come and fill me,\nwhile I am waiting for You.\nI am broken, I am thirsting,\nI am longing for You.', 'O Geist Gottes, komm und füll mich,\nHERR, ich warte auf Dich\nDenn ich dürste, denn ich sehn mich,\nHERR, ich warte auf Dich'),
(9, '0686', 'Holy Spirit come and seal us know   (Chorus)', 'Holy Spirit, Holy Spirit,\ncome and seal us know.\nHoly Spirit, Holy Spirit,\ncome and seal us know.\nIn Your image and your likeness\nwe\'ll become Your living Word.\nHoly Spirit, Holy Spirit.\ncome and seal us know.', NULL),
(9, '0687', 'Holy Spirit move me now   (Chorus)', 'Holy Spirit move me now,\nmake my life whole again.\nSpirit move over me,\nspirit move over me.', NULL),
(9, '0688', 'Holy Spirit rain down', 'Holy Spirit, rain down, rain down,\noh Comforter and Friend.\nHow we need Your touch again.\nHoly Spirit, rain down, rain down\r\nLet Your power fall,\nlet Your voice be heard.\nCome and change our hearts\nas we stand on Your Word.\r\nHoly Spirit, rain down.\r\nNo eye has seen, no ear has heard,\nno mind can know what God has in store.\nSo open up heaven, open it wide\nover Your church and over our lives.', NULL),
(9, '0689', 'Holy Spirit, how I love You   (2 Chorusse)', 'Holy Spirit, how I love You.\nHoly Spirit, flood my soul.\nHoly Spirit, take me over.\nHoly Spirit, lead me on.\r\nYou\'re the strength that helps me in my weakness,\nYou\'re the Friend who comes to walk beside.\nYou\'re the peace that passes understanding,\nas You reign in my life.', NULL),
(9, '0690', 'Holy, Holy, Holy, Lord God of Hosts   (Chorus)', 'Holy, Holy, Holy, Lord God of hosts.\nHeaven and earth are full of Thee,\nHeaven and earth are praising Thee,\nO Lord Most High.', NULL),
(9, '0691', 'Horch ich höre fern von hier ein Kampfgeschrei  -  Far away the Noise of Strife upon my Ear is falling   (Ich wohne auf dem Berge, der in reinen Lüften liegt)', 'Far away the noise of strife upon my ear is falling,\nthen I know the sins of earth beset on every hand.\nDoubt and fear and things of earth in vain to me are calling,\nnone of these shall move me from Beulah Land.\r\nI\'m living on the mountain underneath a cloudless sky.\nI\'m drinking at the fountain that never shall run dry.\nI\'m feasting on the manna from a bountiful supply.\nFor I am dwelling in Beulah land\r\nFar below the storm of doubt upon the world is beating,\nsons of men in battle long the enemy withstand.\nSafe am I within the castle of God’s word retreating,\nnothing then can reach me, ’tis Beulah Land.\r\nLet the stormy breezes blow, their cry cannot alarm me,\nI am safely sheltered here, protected by God’s hand.\nHere the sun is always shining, here there’s naught can harm me,\nI am safe forever in Beulah Land.\r\nViewing here the works of God, I sink in contemplation,\nhearing now His blessed voice, I see the way is planned.\nDwelling in the spirit, here I learn of full salvation,\ngladly will I tarry in Beulah Land.', 'Horch ich höre fern von hier ein Kampfgeschrei erschallen,\nund ich weiß dass Sünd\' und Not mir droh\'n von Satans Hand.\nFurcht und Zweifel mögen mich auf Erden leicht befallen,\ndoch sie zieh\'n mich nimmer vom Wonneland.\r\nIch wohne, auf dem Berge, der in reinen Lüften liegt,\nich trinke von der Quelle, die nimmermehr versiegt.\nPreis Gott ich esse, von dem Manna, das der Herr mir täglich gibt.\nGottlob ich wohne im Wonneland.\r\nBrausen auch des Zweifels Stürme über alle Lande,\nbieten wir doch fest und gläubig Trotz und Widerstand.\nIn dem festen Schloss des Herrn wir sichre Zuflucht fanden,\nund nichts kann uns schaden im Wonneland.\r\nMögen Stürme wütend droh\'n, sie können uns nicht schrecken,\nwir sind wohl geborgen hier, beschirmt von Gottes Hand.\nGottes Sonne sehen wir durch alle Wolken brechen,\nund wir wohnen sicher im Wonneland.\r\n'),
(9, '0692', 'Horch, dein Heiland lässt dich laden, komm, komm und sieh  -  Hear the Gospel Invitation, come, come and see   (Lasst die Botschaft weithin schallen)', 'Hear the Gospel Invitation:\nCome, come and see.\nTake a full and free Salvation:\nCome, com and see.\r\nSend abroad the proclamation,\nsing the somg to every nation,\nJesus Christ and His Salvation;\ncome, come and see.\r\nCome and see, \'ts Jesus calling,\ncome, come and see.\nCome and see the shadows are falling,\ncome, come and see.\r\nEre the paths of life grow dreary,\ncome, come and see.\nHeavy laden, weak and weary,\ncome, come and see.\r\nWe have found Him and the glory,\ncome, come and see.\nCome and help to sing the story,\ncome, come and see.', 'Horch, dein Heiland lässt dich laden:\nKomm, komm und sieh.\nZu dem Hochzeitsmahl der Gnaden,\nkomm, komm und sieh.\r\nLasst die Botschaft weithin schallen,\nBerg und Tal lasst widerhallen:\n"Gott vergibt den Sündern allen.\nKomm, komm und sieh!"\r\nSagt\'s den Kleinen, sagt\'s den Großen:\nKomm, komm und sieh!\nKeiner wird hinaus gestoßen,\nkomm, komm und sieh!\r\nKomm, eh dich die Nacht ereilet,\nkomm, komm und sieh!\nJesus rettet, Jesus heilet,\nkomm, komm und sieh!\r\nGott will dir viel Gnad\' erweisen,\nkomm, komm und sieh!\nDich an Seinem Tische speisen,\nkomm, komm und sieh!'),
(9, '0693', 'Horch, die Stimme ew\'ger Liebe schallt von Golgatha mit Macht   (Halleluja, Halleluja, Jesus ruft: Es ist vollbracht)', NULL, 'Horch, die Stimme ew\'ger Liebe\nschallt von Golgatha mit Macht!\nAch, dass dich\'s zum Heiland triebe,\nWelt, hab auf die Kunde acht!\r\nHalleluja, Halleluja,\nJesus ruft: "Es ist vollbracht!"\nAmen.\r\nO, wie weckt\'s im Herzen Wonne!\nHier ist, was uns selig macht;\ndenn vom Kreuz scheint uns die Sonne,\ndie vertreibt der Sünde Nacht.\r\nJubiliert, ihr Engelchöre;\nstimmt in unser Loblied ein!\nArmes Sünderherz, o höre:\nselig, selig sollst du sein!'),
(9, '0694', 'Horch, es klopfet für und für! Wer steht draußen vor der Tür  -  Knocking, knocking, who is there? Waiting, waiting, o how fair', 'Knocking, knocking, who is there?\nWaiting, waiting, O how fair!\n\'Tis a Pilgrim, strange and kingly,\nnever such was seen before.\nAh! my soul, for such a wonder\nwilt thou not undo the door?\r\nKnocking, knocking, still He\'s there,\nwaiting, waiting, wondrous fair.\nBut the door is hard to open,\nfor the weeds and ivy vine\nwith their dark and clinging tendrils\never round the hinges twice.\r\nKnocking, knocking what! still there?\nWaiting, waiting, grand and fair.\nYea, the wounded hand still knocketh,\nand beneath the thorn-wreath\'d hair\nbeam the patient eyes, so tender,\nof thy Saviour waiting there.\nWilt thou keep him waiting there?', 'Horch, es klopfet für und für!\nWer steht draußen vor der Tür?\nO, ein Gast ist\'s sondergleichen,\nden die Liebe zu dir trieb!\nAch, mein Herz, lass dich erweichen,\ntu\' Ihm auf und hab Ihn lieb!\r\nHorch, es klopfet stets aufs neu!\nWer mag warten so voll Treu?\nO, dein Herr ist\'s, hoch erhaben;\nwelch ein Glück ist\'s, Sein zu sein!\nSieh, Er kommt mit Himmelsgaben;\ntu\' Ihm auf und lass Ihn ein!\r\nHorch, es klopfet! Hör es doch!\nImmer steht Er draußen noch!\nO, dein Heiland ist\'s voll Gnaden,\nder da klopft an deiner Tür!\nEr will dich zur Hochzeit laden,\ntu\' Ihm auf, Er schenkt sich dir!'),
(9, '0695', 'Horch, es tönt ein Ruf auf Erden weit und breit   (O die Ströme rauschen mächtig schon herab)', NULL, 'Horch, es tönt ein Ruf auf Erden weit und breit,\nund es kehrt zurück die sel\'ge Pfingstenzeit\nfür das Volk des Herrn, das gänzlich Ihm sich weiht\nin der finster\'n Mitternacht.\r\nO die Ströme rauschen mächtig schon herab,\nund der Geist ist da, die edle Gottesgab.\nJa, der Ruf erschallt rings in der Christenheit:\n"Sieh, der Bräutgam kommt, macht euch bereit!"\r\nPfingsten kehrt zurück für jede gläub\'ge Seel\',\ndass es ihr nicht mangle an dem heil\'gen Öl,\ntreu zu wandeln nach des Heilandes Befehl\nin der finster\'n Mitternacht.\r\nSieh, das Feuer fällt herab auf den Altar,\nwie es einst an jenem ersten Pfingsten war,\nfindet sich vor Gott einmütig eine Schar\nin der finster\'n Mitternacht.\r\nPfingsten schafft den einen heil\'gen Leib dem Herrn,\nund es leuchtet auf der helle Morgenstern,\nja der Tag des Heil\'s ist wahrlich nicht mehr fern,\nbald entflieht die Mitternacht.\r\nJedem, der an die Verheißung einfach glaubt\nund sich willig zur Verfügung hält dem Haupt,\nwird durch Satans List die Krone nicht geraubt\nin der finster\'n Mitternacht.'),
(9, '0696', 'Hosianna, Hosianna in der Höhe  -  Hosannah, Hosannah in the Highest', ':/: Hosannah, Hosannah,\nHosannah in the highest! :/:\nLord, we lift up Your Name\nwith hearts full of praise\nBe exalted, oh Lord, our God!\nGlory to the King of Kings\r\n:/: Glory, Glory, Glory to\nthe King of Kings! :/:\nLord we lift up Your Name\nwith hearts full of Praise\nBe exalted, oh Lord, our God!\nGlory to the King of Kings!', ':/:Hosianna, Hosianna,\nHosianna in der Höhe. :/:\nDu bist König und Herr,\ndu regierst mit Macht,\nDeine Herrlichkeit ist offenbar.\nHosianna in der Höhe.\r\n:/: Ehre, Ehre,\nEhre sei dem König allein. :/:\nDu bist König und Herr,\ndu regierst mit Macht,\ndeine Herrlichkeit ist offenbar.\nEhre sei dem König!'),
(9, '0697', 'How can I get into the new Jerusaem   (2 Chorusse)', 'How can I get into the new Jerusalem?\nOnly if You take me there.\nHow can I get into the new Jerusalem?\nOnly if You take me there.\r\nGive me Your perfect will\nand give me Your Spirit\nand then You will take me there.\nGive me Your perfect will\nand give me Your Spirit\nand then You will take me there.', NULL),
(9, '0698', 'How can I say Thanks for the Things You have done for me   (To God be the Glory)', 'How can I say thanks for the things\nYou have done for me?\nThings so undeserved yet You gave,\nto prove Your love for me.\nThe voices of a million angels\ncould not express my gratitude.\nAll that I am, and ever hope to be\nI owe it all to Thee.\r\nTo God be the glory,\nto God be the glory,\nto God be the glory,\nfor the things He has done.\nWith His Blood He has saved me,\nwith His Pow\'r He has raised me,\nto God be the glory\nfor the things He has done.\r\nJust let me live my life and\nlet it be pleasing Lord to Thee.\nAnd if I gain any praise\nlet it go to Calvary.\nWith His blood He has saved me,\nwith His power He has rased me.\nTo God be the glory\nfor the things He has done.', NULL),
(9, '0699', 'How He Loves', 'He is jealous for me\nLove\'s like a hurricane, I am a tree\nBending beneath the weight of His wind and mercy\nWhen all of a sudden\nI am unaware of these afflictions eclipsed by glory\nAnd I realize just how beautiful You are\nAnd how great Your affections are for me\r\nAnd oh, how He loves us, oh\nOh, how He loves us\nHow He loves us all\r\nAnd He is jealous for me\nLove\'s like a hurricane, I am a tree\nBending beneath the weight of his wind and mercy\nWhen all of a sudden\nI am unaware of these afflictions eclipsed by glory\nAnd I realize just how beautiful You are\nAnd how great Your affections are for me\r\nAnd, oh, how He loves us, oh\nOh, how He loves us\nHow He loves us all\r\nHe loves us\nOh, how He loves us\nOh, how He loves us\nOh, how He loves\r\nAnd we are His portion and He is our prize\nDrawn to redemption by the grace in His eyes\nIf His grace is an ocean, we\'re all sinking\nAnd heaven meets earth like an unforeseen bliss\nAnd my heart turns violently inside of my chest\nI don\'t have time to maintain these regrets\nWhen I think about, the way...\r\nYes, He loves us\nOh, how He loves us\nOh, how He loves us\nOh, how He loves\nYes, He loves us\nOh, how He loves us\nOh, how He loves us\nOh, how He loves', NULL),
(9, '0700', 'How to reach the Masses, Men of every Birth   (Lift Him up, lift Him up)', 'How to reach the masses, men of\nevery birth? For an answer Jesus gave\na key, "And I, if I be lifted up from the\nearth, Will draw all men unto me."\r\nLift Him up, lift Him up,\nStill He speaks from eternity,\n"And I, if I be lifted up from the earth,\nWill draw all men unto me."\r\nO the world is hungry for the living\nbread, Lift the Saviour up for them to\nsee; Trust Him, and do not doubt the\nwords that He said, "I\'ll draw all men\nunto me."\r\nDon\'t exalt the preacher, don\'t exalt\nthe pew, Preach the Gospel simple,\nfull and free; Prove Him and you will\nfind that promise is true, "I\'ll draw all\nmen unto me."\r\nLift Him up by living as a Christian\nought, Let the world in you the\nSaviour see, Then men will gladly\nfollow Him who once taught, "I\'ll\ndraw all men unto me."', NULL),
(9, '0701', 'Hör auf zu grübeln! Jesus lebt! Ja, Jesus lebt   (Lass ab! Lass ab, betrübtes Herz)', NULL, 'Hör auf zu grübeln! Jesus lebt! Ja, Jesus lebt,\nder dich aus allen Ängsten hebt.\nSein Wort ist wahr, glaub, was Er spricht,\nund deut\'le daran länger nicht!\nDie Weisheit alle Rätsel löst\ndem Geist, der sich vor Gott entblößt.\r\nLass ab! Lass ab, betrübtes Herz!\nDein eig\'nes Wesen schafft nur Schmerz.\nDein Licht ist lauter Finsternis.\nNur Jesus macht den Gang gewiss.\r\nHör auf zu denken! Himmelhoch, ja himmelhoch\ngeh\'n die Gedanken Gottes doch.\nDie tiefste Einfalt wandelt nur\nauf ihrer unerforschten Spur.\nEin Kind, einfältig, arm und klein,\ngeht frei in Gottes Tiefen ein.\r\nHör auf zu sorgen! Gottes Treu, ja Gottes Treu\nist alle Morgen ewig neu.\nVor Ihm im klaren Spiegel steht\nein jedes Ding, das dich angeht.\nD\'um werde alle Sorgen los,\nwie klein sie sind, wie schwer, wie groß.\r\nHör auf zu ringen, \'s ist vollbracht, ja \'s ist vollbracht!\nDu schaffst es nie mit deiner Macht.\nDes Bußkampfs finst\'re Wurzel heißt:\n"Ihr widerstrebt dem Heilgen Geist!"\nWer in die Ruhe kommen will,\nder halte fein dem Geiste still.\r\nLass ab von allem eignen Tun, ja eignen Tun!\nDu darfst in Christi Grabe ruh\'n.\nDa endet alle finst\'re Pein,\nman geht zum ew\'gen Sabbat ein.\nHier fällt die Auferstehungskraft,\ndie völlig neue Menschen schafft.'),
(9, '0702', 'Hör das Weinen der Gefangnen  -  Hear the Cries of the Shakled', 'Hear the Cries of the Shakled from the onset of time\nfor the chains of defeat there\'s n key.\nSee the tears of the broken, the cries of the slaves\n"Is there no one worthy to set us free?"\r\nThen the crying is stilled as the chorus rings out,\nthe shakled released from their chains.\nAnd thousands of voices are swelling the song:\n"Worthy the Lamb that was slain."\r\nWorthy, worthy, worthy the Lamb of God.\nHoly, holy, holy is the Lamb of God!\nJesus, Jesus, Jesus is the Lamb of God!\r\nThen all the archangels, the saints of all time,\nholding their crowns in their hands,\nfall down before Him, joining the song:\n"Worthy, worthy the Lamb."', 'Hör das Weinen der Gefang\'nen\ndie da warten schon lang auf Befreiung aus den Ketten der Sünd\'.\nSieh\' die Tränen des Johannes, als keiner würdig war.\n"Ist denn niemand, der uns befreien kann?"\r\nDoch auf einmal ward es stille. Dann ein Jubel erklang.\nVon den Ketten die Gefang\'nen sind frei.\nViele tausend Stimmen, sie sangen das Lied:\n"Es ist würdig das blutende Lamm!"\r\nWürdig, würdig, würdig, ist das Gotteslamm!\nHeilig, heilig, heilig ist das Gotteslamm!\nJesus, Jesus, Jesus ist das Gotteslamm!\r\nUnd dann alle Seine Engel und die siegreiche Schar\nvor dem Thron auf die Knie niederfall\'n,\nund gemeinsam im Chor sie stimmen dann an:\n"Es ist würdig das blutende Lamm!"'),
(9, '0703', 'Hör den Herrn der Ernte freundlich rufen  -  Hear the Lord of Harvest sweetly calling   (Rede, Herr, sprich zu mir)', 'Hear the Lord of harvest sweetly calling,\n"Who will go and work for Me today?\nWho will bring to Me the lost and dying?\nWho will point them to the narrow way?"\r\nSpeak, my Lord, speak my Lord,\nspeak, and I\'ll be quick to answer Thee;\nspeak, my Lord, speak, my Lord,\nspeak, and I will answer, "Lord, send me."\r\nWhen the coal of fire touched the prophet,\nmaking him as pure as pure can be.\nWhen the voice of God, said "Who\'ll go for us?"\nThen he answered, "Here I am, send me."\r\nMillions now in sin and shame are dying;\nlisten to their sad and bitter cry;\nhasten, brother, hasten to the rescue;\nquickly answer, "Master, here am I."\r\nSoon the time for reaping will be over;\nsoon we\'ll gather for the harvest home;\nmay the Lord of harvest smile upon us,\nmay we hear His blessed, "Child, well done."', 'Hör den Herrn der Ernte freundlich rufen:\n"Wer will geh\'n, ein Werk für mich zu tun?\nWer will die Verlor\'nen zu mir führen,\ndas erlöst bei mir sie ewig ruh\'n?"\r\nRede, Herr, sprich zu mir!\nSprich und ich will schnell gehorchen Dir!\nRede, Herr, sprich zu mir!\nSende mich, ich folge, hier bin ich.\r\nAls die Glut des Knechtes Mund berührte,\nward er rein und alles Böse wich.\nGottes Geist fragt: "Wer will sein mein Bote?"\nUnd Jesaja sprach: "Herr, sende mich!"\r\nSiehst du nicht in Angst Millionen sterben?\nHörst du, wie sie klagen bitterlich?\nEile, Bruder, eile, sie zu retten!\nSprich auch du: "Oh, Meister, sende mich!"\r\nBald ist uns\'re Erntezeit vorüber.\nBald nimmt dich die ew\'ge Heimat auf.\nAch, dass Jesu Aug\' dann froh dich grüßte:\n"Treu hast du vollendet deinen Lauf!"'),
(9, '0704', 'Hör es, o hör es und eile heran, frei ist zum Kreuze der Weg', NULL, 'Hör es, o hör es und eil\' heran,\nfrei ist zum Kreuze der Weg.\nJesus brach selber im Tod die Bahn,\nfrei ist zum Kreuze der Weg.\nBring deine Bürde, bring deine Last,\nkomm, was du immer zu tragen hast!\nSelig wer\'s glaubet und wer\'s erfasst,\nfrei ist zum Kreuze der Weg!\r\nO warum zauderst und fragst du noch,\nfrei ist zum Kreuze der Weg.\nKomm, wie du bist, Er zerbricht dein Joch,\nfrei ist zum Kreuze der Weg.\nIst auch dein Herze noch kalt und tot,\nist deine Sünde gleich blutig rot,\nhier ist Errettung von aller Not,\nfrei ist zum Kreuze der Weg!\r\nLass nur dein Wenn du dein Aber sein,\nfrei ist zum Kreuze der Weg.\nKomm und vertraue dem Herrn allein,\nfrei ist zum Kreuze der Weg.\nJesus, ich bringe Dir Lob und Preis,\nFreude durchglüht meine Seele heiß,\ndass ich\'s erfahren hab, dass ich\'s weiß:\nfrei ist zum Kreuze der Weg!'),
(9, '0705', 'Hör, Herr, mein Flehn   (Chorus)', NULL, 'Hör, Herr, mein Fleh\'n:\nLass mich Dein Zeuge sein.\nGib mir die Kraft,\nDir treu zu sein.'),
(9, '0706', 'Höre Bruder Schwester bist du fertig wenn der Herr erscheint   (Maranatha, Halleluja)', NULL, 'Höre Bruder Schwester bist du fertig wenn der Herr erscheint?\nist dein Wandel in dem Himmel, bist Du bald mit Ihm vereint?\nWenn dann alles hin gesunken, du die Augen aufwärts hebst,\nund zur nächt\'gen Stunde Christus vor dir steht.\r\nMaranatha, Halleluja,\nMaranatha, Halleluja,\nMaranatha, Halleluja.\nJesus kommt und dann beginnt der Hochzeitstag.\r\nSchaust du nach des Heilands Kommen, hälst du dich für Ihn bereit?\nHat die Welt durch Dich vernommen, das der König nicht mehr weit?\nSieht man dich für Ihn beschäftigt oder stehst du müßig nur?\nZwölfe schlägt schon bald das großen Königs Uhr.\r\nAuf des Heilands Kommen weisen auch die Zeichen dieser Zeit,\nund auch ich will Ihn mit preisen bis in alle Ewigkeit.\nHeller soll mein Kleid erscheinen wenn ich Ihm entgegen geh\',\nsag mein Freund wirst du mit mir den König seh\'n?'),
(9, '0707', 'Höre des Bräutigams Stimme: Siehe Ich komme bald', NULL, 'Höre des Bräutigams Stimme: Siehe Ich komme bald!\nAch, dass die Jungfrauen wachten, wenn Jesu Ruf erschallt!\nBrennt deine Lampe, hast Öl du genug?\nSchrecklich ist ja der Betrug (der Betrug),\nwenn man nicht Öl hat genug!\r\nGut ist\'s, auf Jesus zu warten, wachend und wirkend für Ihn,\nwirklich bereit auf sein Kommen, als wenn Er heut noch erschien;\nFlehst du in Wahrheit:Herr Jesus komm bald!\nSchrecklich zu wem Er einst spricht (Er einst sprich):\nWeiche, ich kenne dich nicht!\r\nHerrlich, ja herrlich für alle, die von Ihm werden entrückt,\ndie durch die Erstauferstehung, werden von Jesus beglückt!\nSelig und heilig, wer teil daran hat! Selig für alle Zeit (alle Zeit),\nselig in Ewigkeit!'),
(9, '0708', 'Hörst du nicht den Herren rufen: Wer will unser Diener sein', NULL, 'Hörst du nicht den Herren rufen: Wer will unser Diener sein?\nGroß und reif ist rings die Ernte, doch der Schnitter Zahl ist klein.\nReichen Lohn verheißt der Meister, laut ruft alle Er zu Sich,\nwer will kommen, wer will sagen: Hier bin ich sende mich, sende mich!\nHier bin ich sende mich, sende mich!\r\nKannst du nicht das Meer durchschiffen als ein Heidenmissionar,\nkannst du hier auch Heiden finden, hilft nur dieser treu und wahr!\nKannst du Tausende nicht geben für das große Werk des Herrn,\nJesus freut das kleinste Scherflein, gib nur, was du gibst recht gern!\nGib nur, was du gibst recht gern!\r\nKannst du nicht wie Engel reden, nicht wie Paulus pred\'gen dort,\nkannst du doch von Jesus zeugen, wie Er ist der Sünder Hort!\nKannst du Starke nicht gewinnen, bleiben Alte von dir fern,\no, so führe kleine Kinder in die Arme unser\'s Herrn!\nIn die Arme unser\'s Herrn!\r\nD\'rum so sag nie mehr so träge: Es gibt nichts für mich zu tun!\nWährend Tausende hinsterben und der Herr dich rufet nun.\nNimm das Pfund, das dir gegeben, wuchre damit emsiglich,\nfolg\' dem Herrn und sprich mit Freuden:\nHier bin ich sende mich, sende mich!\nHier bin ich sende mich, sende mich!'),
(9, '0709', 'Hört es ihr Lieben und lernet ein Wort (Jesus errettet mich jetzt)', NULL, 'Hört es ihr Lieben und lernet ein Wort,\ndas euch zum Segen gesetzt.\nSprecht es mir nach, und dann sagt’s weiter fort:\n„Jesus errettet mich jetzt!“\r\nJesus errettet mich jetzt,\nJesus errettet mich jetzt.\nJa, Jesus errettet mich allezeit,\nJesus errettet mich jetzt!\r\nSind eure Sünden gleich blutrot und schwer,\nist das Gewissen verletzt.\nO so sprecht gläubig (vergesst es nicht mehr):\n„Jesus errettet mich jetzt!“\r\nWenn euch die Welt mit Versuchung anficht,\nSatan euch nachstellt und hetzt.\nSo wiederholt es und fürchtet euch nicht:\n„Jesus errettet mich jetzt!“\r\nWenn euch die Träne der Trübsal und Not,\nbrennend die Wange benetzt.\nSagt nur ganz ruhig im Aufblick zu Gott:\n„Jesus errettet mich jetzt!“\r\nKommt ihr dann hin zu dem finsteren Tal,\no so sprecht jubelnd zuletzt:\nNun geht’s zur Herrlichkeit, freut euch zumal,\n„Jesus errettet mich jetzt!“'),
(9, '0710', 'Hört ihr des Hirten Stimm so bang  -  Hark! \'tis the Shepherd\'s Voice I hear   (Bringt sie heim, bringt sie heim)', 'Hark! \'tis the Shepherd\'s voice I hear,\nout in the desert dark and drear,\ncalling the sheep who\'ve gone astray,\nfar from the Shepherd\'s fold away.\r\nBring them in, bring them in,\nbring them in from the fields of sin,\nbring them in, bring them in,\nbring the wand\'ring ones to Jesus.\r\nWho\'ll go and help this Shephard kind,\nhelp Him the wand\'ring ones to find?\nWho\'ll bring the lost ones to the fold,\nwhere they\'ll be sheltered from the cold?\r\nOut in the dessert hear their cry,\nout on the montains wild and high,\nHark! \'tis the Master speaks to thee:\n"Go find My sheep where\'er the be."', 'Hört ihr des Hirten Stimm\' so bang\',\nwie sie durch Berg\' und Wüsten drang?\nSchafe, die von der Herd\' verirrt,\nsucht immer noch der treue Hirt\'.\r\nBringt sie heim, bringt sie heim!\nBringt sie heim vom Land der Sünd\' und Pein!\nBringt sie heim, bringt sie heim!\nBringt die Irrenden zu Jesus!\r\nKommt doch, so ruft der treue Hirt\',\nhelft Mir zu suchen, was verirrt.\nBringt sie heim zur Herde dann,\nwo sie kein Schaden treffen kann.\r\nHörst du ihr banges Jammern nicht dort,\nwo die Dornen steh\'n so dicht?\nHör, wie der Hirt\' so dringend fleht:\nSucht Meine Schafe, eh\'s zu spät!'),
(9, '0711', 'Hört, die Himmelsglocken schallen  -  The Gospel Bells are ringing   (Glockenklang, Engelsang, laut erschalle weit und breit)', 'The Gospel bells are ringing,\nover land, from sea to sea.\nBlessed news of free salvation\ndo they offer you and me.\nFor God so loved the world\nthat His only Son He gave.\nWhosoe’er believeth in Him\neverlasting life shall have.\r\nGospel bells, how they ring,\nover land from sea to sea.\nGospel bells freely bring,\nblessed news to you and me.\r\nThe Gospel bells invite us\nto a feast prepared for all.\nDo not slight the invitation,\nnor reject the gracious call.\nI am the Bread of life,\neat of Me, thou hungry soul.\nTho’ your sins be red as crimson,\nthey shall be as white as wool.\r\nThe Gospel bells give warning,\nas they sound from day to day,\nof the fate which doth await them,\nwho forever will delay.\nEscape ye, for thy life,\ntarry not in all the plain,\nnor behind thee look, oh, never,\nlest thou be consumed in pain.\r\nThe Gospel bells are joyful,\nas they echo far and wide,\nbearing notes of perfect pardon,\nthro’ a Saviour crucified.\nGood tidings of great joy\nto all people do I bring.\nUnto you is born a Saviour,\nwhich is Christ the Lord and King.', 'Hört, die Himmelsglocken schallen\ndurch die Lande weit und breit!\nLaut verkünden sie uns allen\neine gnadenreiche Zeit.\nGottes Liebe sei gepriesen,\ndass er Seinen Sohn uns gab!\nWer Ihm glaubt, darf froh genießen\nLeben über Tod und Grab.\r\nGlockenklang, Engelsang,\nlaut erschalle weit und breit!\nWort vom Sohn, süßer Ton!\nJetzt ist\'s angenehme Zeit!\r\nHört, die Himmelsglocken laden\nzu des Königs Hochzeitsmahl!\nHier ist Heil für jeden Schaden,\nRaum für Sünder ohne Zahl,\nJesus ist das Brot des Lebens.\nSeelen, die ihr müd\' und matt:\nKommt! Ihr glaubet nicht vergebens;\nweil, wer Ihn hat, alles hat.\r\nHört, die Himmelsglocken warnen:\nTräge kommen leicht zu spät!\nLasst euch nicht vom Feind umgarnen;\nsorgt, dass keins verloren geht.\nRingt, noch steht die Pforte offen;\nsie ist eng, der Weg ist schmal;\ndrin ist Glaube, Liebe, Hoffen;\ndraußen herrscht nur ew\'ge Qual.\r\nHört, die Himmelsglocken läuten!\nNun bricht an das Jubeljahr.\nGottes Kinder, jauchzt mit Freuden\nmit der Sel\'gen großen Schar!\nBald wird unser König kommen;\nseht, von ferne naht Er schon!\nSeid getreu, ihr lieben Frommen,\ndass ihr erbt des Lebens Kron\'.'),
(9, '0712', 'Hört, Jesus ruft: "Kommt alle her"   (O welch ein lieblich Los)', NULL, 'Hört, Jesus ruft: "Kommt alle her!\nIch führ\' euch an der Hand!\nGeht\'s hier auch durch manch Trübsalsmeer,\ngeht\'s doch zum sel\'gen Land!\nIhr Menschenkinder, kommt herzu,\nIch führe euch zur ew\'gen Ruh\'!\nDort jubiliert die sel\'ge Schar\nund jauchzet immerdar!"\r\nO welch ein lieblich Los!\nWelch ein Los! Welch ein Los!\nO welch ein lieblich Los\nfind\'t man in Jesu Schoß!\r\nO hört, wie es in Zion klingt,\nwenn Sünder Buße tun!\nDie ganze Schar der Sel\'gen singt,\nda kann kein Engel ruh\'n;\nda preiset alles Jesu Blut,\ndas immer noch solch Wunder tut;\nda rühmet alles Gottes Macht,\ndie Sünder selig macht.\r\nWenn dann am Tag der Ewigkeit\nder Heiland milde spricht:\n"Kommt her, ererbt die Herrlichkeit\nbeim Vater in dem Licht!"\nDa wird der Mund voll Lachens sein,\nder ganze Himmel stimmt mit ein:\n"Ja, Großes hat", so heißt es dann,\n"der Herr an uns getan!"\r\nO welch ein lieblich Los!\nWelch ein Los! Welch ein Los!\nO welch ein lieblich Los\nfind\'t man in Jesu Schoß!\nDort sind die Heilgen ohne Zahl,\nvereint beim Herrn am Hochzeitsmahl\nund singen laut: Viktoria,\ndem Lamm, Halleluja!'),
(9, '0713', 'Humble yourself before the Lord   (2 Chorusse)', 'Humble yourself before the Lord\nHe will lift you up     (2x)\n(He will lift you)\r\nHe will lift you up!  (He will lift you!)\nHe will lift you up!  (If you only!)\nHumble yourself before the Lord,\nHe will lift you up!', NULL),
(9, '0714', 'Hymn of Heaven', 'How I long to breathe the air of Heaven\nWhere pain is gone and mercy fills the streets\nTo look upon the One who bled to save me\nAnd walk with Him for all eternity\r\nThere will be a day when all will bow before Him\nThere will be a day when death will be no more\nStanding face to face with He who died and rose again\nHoly, holy is the Lord\r\nAnd every prayer we prayed in desperation\nThe songs of faith we sang through doubt and fear\nIn the end, we\'ll see that it was worth it\nWhen He returns to wipe away our tears\r\nAnd on that day, we join the resurrection\nAnd stand beside the heroes of the faith\nWith one voice, a thousand generations\nSing, "Worthy is the Lamb who was slain"\r\nSo let it be today we shout the hymn of Heaven\nWith angels and the saints, we raise a mighty roar\nGlory to our God who gave us life beyond the grave\nHoly, holy is the Lord', NULL),
(9, '0715', 'I am covered', 'I am covered, covered\nCovered by His blood\nWalking by faith\nLiving in love\nI am covered, covered\nCovered by His blood\nJesus has rescued me', NULL),
(9, '0716', 'I am redeeemed, bought with a Price   (2 Chorusse)', 'I am redeemed, bought with a price.\nJesus has changed my whole life.\nIf anybody ask you just who I am,\ntell them I am redeemed.\r\nWhere there was hate, love now abounds.\nWhere there was strife, peace now reigns.\nI\'m walking with my Saviour, I\'m a child of the King,\nall because I am redeemed.', NULL),
(9, '0717', 'I am resting on the finished work  -  Ich ruhe heute auf dem vollendeten Werk von Jesus Christus   (I am free, my new day has come)', 'I am resting on the finished work\nof Jesus Christ today,\nall circumstances will be gone,\nthe Word of God will still remain!\nNo sickness, fear, no guilt or sin\ncan have control and worry me,\nthe keys of faith are in my hands,\nand I am bound for Victory!\r\nI am free, my new day has come,\nnow I can be who I truly am.\nI am free, Covered by His Blood!\nAll things are possible with God!\nAll things are possible with God!\r\nA great commission from my Lord\nI have now received.\nThe prince of power of the air\nwill never have a part in me.\nAs amateur creator\nI can change the atmosphere around,\nI use the chain of circumstance\nfor any spirits to be bound!\r\nI know that Jesus "the I AM"\nis the same today,\nthe prophet came to show the life\nthe bride must have It on display.\nThe hour has come for Christ in us\nto be completely glorified,\nI want the Spirit to be free\nto do the greater works in me!', 'Ich ruhe heute auf dem vollendeten Werk von Jesus Christus,\nes werden alle Umstände verschwunden sein,\naber das Wort Gottes wird bleiben!\nKeine Krankheit, Angst, keine Schuld oder Sünde kann die Kontrolle haben und mich beunruhigen,\ndie Schlüssel des Glaubens sind in meinen Händen, und ich bin zum Sieg bestimmt!\r\nIch bin frei, mein neuer Tag ist gekommen,\njetzt kann ich sein, wer ich wirklich bin.\nIch bin frei, bedeckt mit Seinem Blut!\nAlle Dinge sind möglich mit Gott!\nAlle Dinge sind möglich mit Gott!\r\nEinen großen Auftrag von meinem Herrn habe ich jetzt erhalten.\nDer Fürst der Macht der Lüfte wird nie einen Anteil an mir haben.\nAls Amateurschöpfer kann ich die Atmosphäre um mich herum verändern,\nich benutze die Ketten der Umstände, um alle Geister zu binden!\r\nIch weiß, dass Jesus "der ICH BIN" heut\' derselbe ist,\nder Prophet kam, um das Leben zu zeigen, das die Braut haben muss, es wird zur Schau gestellt.\nDie Stunde ist gekommen, dass Christus in uns vollständig verherrlicht wird,\nIch möchte, dass der Geist frei ist, um die größeren Werke in mir zu tun!'),
(9, '0718', 'I am so homesick and blue, and I want to see Jesus  -  Ich habe so viel Heimweh und bin so traurig, und ich möchte Jesus sehen    (Beyond the Curtain of Time / Hinter dem Vorhang der Zeit)', 'I am so homesick and blue and I want to see Jesus,\nI would like to hear those sweet harbor bells chime.\nIt would brighten my path and would vanish all fear,\nLord, let me look past the curtain of time.\r\nLord, let me look past the curtain of sorrows and fear,\nlet me view that sunny bright clime.\nIt would strengthen my faith and would banish all fear,\nLord, let me look past the curtain of time.', 'Ich habe so Heimweh und bin traurig, und ich möchte Jesus sehen,\nich würde gerne die süßen Hafenglocken läuten hören.\nEs würde meinen Weg erhellen und alle Angst verschwinden lassen,\nHerr, lass mich hinter den Vorhang der Zeit schauen.\r\nHerr, lass mich hinter den Vorhang der Sorgen und Ängste schauen,\nlass mich in das sonnige, helle Land schauen.\nEs würde meinen Glauben stärken und alle Angst vertreiben,\nHerr, lass mich hinter den Vorhang der Zeit schauen.'),
(9, '0719', 'I AM that spoke to Moses in the burning Bush of Fire   (Oh, who do you say I am)', 'I AM that spoke to Moses\nin the burning bush of fire.\nI AM the God of Abraham,\nthe Bright and Morning Star.\nI AM the Rose of Sharon,\nfrom beginning whence I came.\nI AM the whole creation,\nand Jesus is My Name.\r\nOh, who do you say I am,\nand whence do you say I came.\nDo you know the Father,\nand can you tell His Name?\nIn Jesus dwells the fulness\nof the Godhead, don\'t you see.\nJesus is the great I AM,\nand the Lord of Lords is He.\r\nI AM was before old Abraham,\n"He rejoiced to see My day."\nWhen Jesus spoke these precious words,\nthey stoned Him right away.\n"Why do you stone Me?"\nJesus said, in a holy, sweet command.\n"Because you say you\'re the great I AM,\nwe believe you\'re just a man."\r\nIt was on the Day of Pentecost,\noh, how the fire did fall.\nThe Holy Ghost descended\nand filled them one and all.\nThen Peter told the multitude,\n"Repent of all your sins."\nAbout three thousand souls were buried\nin Jesus\' precious Name.', NULL),
(9, '0720', 'I am the Lord that healeth thee', 'I am the Lord that healeth thee,\nI am the Lord that healeth thee;\nJehovah Rapha is My Name:\nFor I am the Lord that healeth thee.\r\nI am the Lord that healeth thee,\nI am the Lord that healeth thee;\nSickness must flee at My command:\nFor I am the Lord that healeth thee.\r\nI am the Lord that healeth thee,\nI am the Lord that healeth thee;\nThe prayer of faith shall banish disease:\nFor I am the Lord that healeth thee.\r\nI am the Lord that healeth thee,\nI am the Lord that healeth thee;\nMy name is still as ointment poured forth:\nFor I am the Lord that healeth thee.\r\nI am the Lord that healeth thee,\nI am the Lord that healeth thee;\nCome and be free from all your pains:\nFor I am the Lord that healeth thee.', NULL),
(9, '0721', 'I am under the Rock   (Chorus)', 'I am under the Rock, the Rock is higher than I.\nJehovah hide me, I am under the Rock.\nGo tell my enemy, I am under the Rock.\nJehovah hide me, I am under the Rock.', NULL),
(9, '0722', 'I am watching for the Coming of the glad Millenial Day   (Oh, our Lord is coming back to Earth again)', 'I am watching for the coming of the glad millennial day,\nwhen our blessed Lord shall come\nand catch his waiting Bride away;\noh, my heart is filled with rapture as I labour, watch and pray,\nfor  the Lord is coming back to earth again.\r\nOh, our Lord is coming back to earth again,\nyes, our Lord is coming back to earth again;\nSatan will be bound a thousand years,\nwe\'ll have no tempter then,\nafter Jesus shall come back to earth again.\r\nJesus\' coming back will be the answer to earth\'s sorrowing cry,\nfor the knowledge of the Lord shall fill the earth and sea and sky;\nGod shall take away all sickness And the sufferer\'s tears will dry,\nwhen our Saviour shall come back to earth again.\r\nYes, the ransomed of the Lord shall come to Zion then with joy,\nand in all His holy mountain nothing hurts or shall destroy;\nperfect peace shall reign in every heart, and love without alloy,\nAfter Jesus shall come back to earth again.\r\nThen the sin and sorrow, pain and death\nof this dark world shall cease,\nin a glorious reign with Jesus of a thousand years of peace;\nAll the earth is groaning, crying for that day of sweet release,\nFor our Jesus to come back to earth again.', NULL),
(9, '0723', 'I belong to Jesus, what blessed Mystery  -  Ich gehöre Jesus, welch wunderbarer Stand', 'I belong to Jesus\nwhat blessed mystery,\nthe vilest of all sinners now\nforgiven and redeemed.\nOh, the depths of darkness\nHis love would reach down through.\nTo cover me with mercy\nand hide me in His wounds.\r\nOh, Hallelujah.\nOh, bless His name.\nTen thousand years will just\nbegin my song of praise.\nOh, Hallelujah,\nsing it again.\nI belong to Jesus,\nI belong to Him.\r\nI belong to Jesus,\nthe cross that once was mine\nbecame the curse that He would bear\nand give to me new life.\nI am His forever,\nforever He is mine.\nMy freedom bought and paid for\nby His blood divine.\r\nI belong to Jesus\no hasten now the day,\nthat I behold Your glory\nand look upon Your face.\nRobed in holy splendor\nlike thunder we will stand.\nThe voice of every saint declaring:\nWorthy is the Lamb!', '(Ich gehöre Jesus\no welch sel\'ger Stand,\ndem übelsten aller Sünder\nwurde vergeben und erlöst.\nOh, die Tiefen der Dunkelheit\ndurch die Seine Liebe hinab reicht.\nUm mich mit Gnade zu bedecken\nund mich in seinen Wunden zu verbergen.)\r\nOh, Halleluja.\nOh, gesegnet sei Sein Nam\'.\nZehntausend Jahre sind erst\nder Beginn meines Lobpreises.\nOh, Halleluja,\nsing es noch mal.\nIch gehöre Jesus,\nich gehöre Ihm.\r\n(Ich gehöre Jesus,\ndas Kreuz, das einst mein\'s war\nwurd\' zum Fluch den Er trug,\nEr mir neues Leben schenkt.\nIch bin für immer Sein,\nEr ist für immer mein.\nMeine Freiheit erkauft und bezahlt\ndurch Sein göttliches Blut.)\r\n(Ich gehöre Jesus\no komme doch du Tag,\nan dem ich Deine Herrlichkeit seh\'\nund in Dein Antlitz schau\'.\nGekleidet in heil\'ger Pracht,\nwie Donner wir dann steh\'n.\nDie Stimme jedes Heil\'gen spricht:\nWürdig ist das Lamm!)'),
(9, '0724', 'I builded on the Rock, on the Rock of God   (I hold not the Rock, but the Rock holds me)', 'I builded on the Rock, on the Rock of God,\nbuilded on the Rock,Christ Jesus.\nI dug down deep and builded on the Rock,\nbuilded on the Rock of God.\r\nI hold not the Rock, but the Rock holds me,\nthe Rock holds me, the Rock holds me.\nI rest on the Rock, and the Rock holds me,\nresting on the Rock of God.\r\nWhy should I fear when the winds sweep by?\nBuilded on the Rock, Christ Jesus.\nOr shaken be when The waves roll high?\nBuilded on the Rock of God.\r\nHush, raging billows at His command,\nbuilded of the Rock, Christ Jesus.\nOh, peace be still \'neath His loving hand!\nBuilded on the Rock of God.\r\nPraise God for our foundation sure!\nbuilded on the Rock, Christ Jesus.\nNo storms can harm our house secure,\nbuilded on the Rock of God.', NULL),
(9, '0725', 'I can run through a Troop and leap over a Wall', 'I can run through a troop, and leap over a wall.\nHalleluja, halleluja!\nHe\'s my rock and my shield, He gives power to all.\nHalleluja, halleluja.\nI am free from condemnation, Jesus is the Rock of my salvation.\nI can run through a troop and leap over a wall.\nHalleluja, halleluja!', 'Ich kann durch ein Dickicht rennen und über eine Mauer springen\nER ist mein Fels und mein Schild,  ER gibt jedem Kraft\nHalleluja Halleluja\nIch bin frei von Verklagung, Jesus ist der Fels meines Heils\nIch kann durch ein Dickicht rennen und über eine Mauer springen\nHalleluja Halleluja'),
(9, '0726', 'I cast my mind to Calvary', 'I cast my mind to Calvary,\nWhere Jesus bled and died for me,\nI see His wounds, His hands, His feet.\nMy Saviour on that cursed tree.\r\nHis body bound and drenched in tears,\nThey laid Him down in Joseph\'s tomb,\nThe entrance sealed by heavy stone,\nMessiah still and all alone!\r\nO praise the Name of the Lord our God!\nO praise His Name forevermore!\nFor endless days we will sing Your praise,\nOh Lord,  oh Lord,  our God!\r\nThen on the third at break of dawn,\nThe Son of heaven rose again,\nO trampled death, where is your sting?\nThe angels sing for Christ my King!\r\nHe shall return in robes of white,\nThe blazing sun shall pierce the night,\nAnd I will rise among the saints.\nMy gaze transfixed on Jesus\' face!', 'Ich denk zurück an Golgatha,\nWo Jesus Blut und Leben gab,\nich seh durchbohrt die Gnadenhand,\nMein Retter dort, am Kreuzesstamm.\r\nEr starb für uns, weil Er uns liebt,\nIn Josephs Grab wurd\' Er gelegt,\nDie Tür versperrt mit schwerem Stein,\nMessias ist nur Er allein!\r\nO preist den Herrn,  Jesus,  unser Gott,\nO preist den Namen ewiglich,\nFür alle Zeit singen wir für Dich,\nOh Herr,  oh Herr,  mein Gott\r\nAm dritten Tag, im Morgenrot,\nErhob Er sich als Herr und Gott,\nDie Todesmacht hat Er besiegt,\nWelch eine Kraft! Der Feind, er flieht!\r\nEr kommt zurück in heller Pracht,\nSein Sonnenglanz durchdringt die Nacht,\nWie Er werd ich nun auferstehn,\nUm Jesus selbst einmal zu sehn!'),
(9, '0727', 'I choose to worship', 'When my heart is broken, when my life is empty,\nI can’t see your face, I can’t hear your voice,\nWhen I’m feeling helpless, wand’ring in the darkness,\nSurrounded by fear and defeat,\nI have a choice to make, no matter what comes my way\r\nI choose to worship, I choose to praise\nI choose to lift up the name above all names\nI choose surrender, I choose to believe\nFor all that you’ve done and for all you will be, I choose to worship\r\nEven in the fire, even in the valley\nI can have joy, I can have peace\nYou are always with me, never will forsake me,\nYour presence is all that I need,\nI have a choice to make, with all that I am I proclaim,\r\nThough we are pressed, on every side, Praise is our weapon, and we’ll win this fight Let the church rise up and say (we will say)\r\nWe choose to worship, we choose to praise\nWe choose to lift up the name above all names\nWe choose surrender, we choose to believe\nFor all that you’ve done and for all you will be,\nWe choose to worship, we choose to praise\nWe choose to lift up the name above all names\nWe choose surrender, we choose to believe\nFor all that you’ve done and for all you will be,\nWe choose to worship', 'Wenn mein Herz gebrochen ist, wenn mein Leben leer ist,\nIch kann dein Gesicht nicht sehen, ich kann deine Stimme nicht hören, Wenn ich mich hilflos fühle, wandle in der Dunkelheit,\nUmgeben von Angst und Niederlage,\nIch muss eine Wahl treffen, egal was auf mich zukommt\r\nIch wähle anzubeten, ich wähle zu preisen\nIch entscheide mich dafür, den Namen über alle Namen zu erheben\nIch entscheide mich für Hingabe, ich entscheide mich zu glauben\nFür alles, was du getan hast und für alles, was du sein wirst, entscheide ich mich für die Anbetung\r\nSelbst im Feuer, sogar im Tal\nIch kann Freude haben, ich kann Frieden haben\nDu bist immer bei mir, wirst mich nie verlassen,\nDeine Anwesenheit ist alles was ich brauche,\nIch muss eine Wahl treffen, mit allem, was ich bin, verkünde ich,\r\nObwohl wir von allen Seiten bedrängt werden, ist Lob unsere Waffe und wir werden diesen Kampf gewinnen  Lass die Gemeinde aufstehen und sagen (wir werden sagen)\r\n'),
(9, '0728', 'I come to the Cross seeking Mercy and Grace', 'I come to the cross seeking mercy and grace.\nI come to the cross, where You died in my place.\nOut of my weakness and into Your strength.\nHumbly I come to the cross.\r\nYour arms are open, You call me by name.\nYou welcome this child that was lost.\nYou paid the price for my guilt and my shame.\nJesus I come, Jesus I come,\nJesus I come to the cross.', NULL),
(9, '0729', 'I command my Hands to prais the Lord   (I command my Body, my Feet, my Soul)', 'I command my hands\nto praise the Lord. (4x)\r\nHands, praise the Lord.\nHands, praise the Lord.\nHands, praise the Lord.\nHands, praise the Lord.\r\nI command my body\nto praise the Lord. (4x)\r\nBody, praise the Lord.\nBody, praise the Lord.\nBody, praise the Lord.\nBody, praise the Lord.\r\nI command my feet\nto praise the Lord. (4x)\r\nFeet, praise the Lord.\nFeet, praise the Lord.\nFeet, praise the Lord.\nFeet, praise the Lord.\r\nI command my soul\nto praise the Lord. (4x)\r\nSoul, praise the Lord.\nSoul, praise the Lord.\nSoul, praise the Lord.\nSoul, praise the Lord.\r\nHands, praise the Lord.\nHands, praise the Lord.\r\nFeet praise the Lord.\nFeet praise the Lord.\r\nLips, praise the Lord.\nLips, praise the Lord.\r\nBody, praise the Lord.\nBody, praise the Lord.\r\nSoul, praise the Lord.\nSoul, praise the Lord.', NULL),
(9, '0730', 'I don\'t know why Jesus loved me  -  Ich weiß nicht, warum Jesus mich geliebt hat', 'I don\'t know why Jesus loved me.\nI don\'t know why He cared.\nI don\'t know why He sacrificed His life.\nOh, but I\'m glad, so glad He did.\r\nWhere would I be if Jesus didn\'t love me?\nWhere would I be if Jesus didn\'t care?\nWhere would I be if He hadn\'t sacrificed His life?\nOh, but I\'m glad, so glad He did.\r\nHe left His mighty throne in glory,\nto bring to us redemption\'s story.\nThen He died but He rose again.\nJust for you and me.\nOh,  and I\'m glad, so glad He did.', 'Ich weiß nicht, warum Jesus mich geliebt hat.\nIch weiß nicht, warum es Ihn interessierte.\nIch weiß nicht, warum er sein Leben geopfert hat.\nOh, aber ich bin froh, so froh, dass er es tat.\r\nWo wäre ich, wenn Jesus mich nicht liebte?\nWo wäre ich, wenn Jesus sich nicht kümmern würde?\nWo wäre ich, wenn Er nicht sein Leben geopfert hätte?\nOh, aber ich bin froh, so froh, dass Er es getan hat.\r\nEr verließ seinen mächtigen Thron in Herrlichkeit,\num uns die Geschichte der Erlösung zu bringen.\nDann starb Er, aber Er stand wieder auf.\nFür dich und für mich.\nOh,  und ich bin froh, so froh, dass Er es tat.'),
(9, '0731', 'I dreamed I went to that City called "Glory"   (Then I bowed on my Knees and cried: "Holy, Holy, Holy")', 'I dreamed I went to that city called "Glory", so bright and so fair,\nwhen I entered the gate I cried "Holy",\nthe angels all met me there;\nthey showed me from mansion to mansion,\nand oh, the sights I saw,\nbut I said: "I want to see Jesus,\nthe One who died for all."\r\nThen I bowed on my knees and cried:\n"Holy, Holy, Holy".\nI clapped my hands and said:\n"Glory, glory to the Son of God."\r\nI thought when I entered that city,\nmy friends knew me well,\nthey showed me all through heaven,\nthe scenes are too num\'rous to tell;\nthey showed me Abraham, Isaac, Jacob,\nMark, Luke and Timothy,\nbut I said: "I want to give praise, to the One who died for me."\r\nI thought when I saw my Saviour: Oh! Glory to God!\nI just fell right down before Him,\nsinging: "Praise to the name of the Lord!"\nI bowed down and worshipped Jehovah,\nmy friend of Calvary,\nfor I wanted to give praise to Jesus,\nfor saving a sinner like me.', NULL),
(9, '0732', 'I dreamed that the great Judgment Morning had dawned   (And, oh, what a weeping and wailing)', 'I dreamed that the great judgment morning\nhad dawned, and the trumpet had blown;\nI dreamed that the nations had gathered\nto judgment before the white throne;\nfrom the throne came a bright shining angel\nand stood on the land and the sea,\nand swore with his hand raised to heaven,\nthat time was no longer to be.\r\nAnd, oh, what a weeping and wailing,\nas the lost were told of their fate;\nthey cried for the rocks and the mountains,\nthey prayed, but their prayers were too late.\r\nThe rich man was there, but his money\nhad melted and vanished away;\na pauper he stood in the judgment,\nhis debts were too heavy to pay;\nthe great man was there, but his greatness,\nwhen death came, was left far behind.\nThe angel that opened the records,\nnot a trace of his greatness could find.\r\nThe widow was there with the orphans,\nGod heard and remembered their cries;\nno sorrow in heaven forever,\nGod wiped all the tears from their eyes;\nthe gambler was there and the drunkard,\nand the man that had sold them the drink,\nwith the people who gave him the license,\ntogether in hell they did sink.\r\nThe moral man came to the judgement,\nbut his self-righteous rags would not do;\nthe men who had crucified Jesus\nhas passed off as moral men, too;\nthe soul that had put off salvation,\n"Not tonight; I\'ll get saved by and by,\nno time now to think of religion!"\nat last they had found time to die.', NULL),
(9, '0733', 'I feel like going on, though Trials come on every Hand   (6 Chorusse)', 'I feel like going on,\nI feel like going on.\nThough trials come on every hand,\nI feel like going on.\r\nI feel like moving on,\nI feel like moving on.\nThough trials come on every hand,\nI feel like moving on.\r\nI feel like praising Him,\nI feel like praising Him.\nThough trials come on every hand,\nI feel like praising Him.\r\nI feel like serving Him,\nI feel like serving Him.\nThough trials come on every hand,\nI feel like serving Him.\r\nI feel like pressing on,\nI feel like pressing on.\nThough trials come on every hand,\nI feel like pressing on.\r\nI feel like thanking Him,\nI feel like thanking Him.\nThough trials come on every hand,\nI feel like thanking Him.', NULL),
(9, '0734', 'I get so thrilled with Jesus every Moment of the Day', 'I get so thrilled with Jesus\nevery moment of the day.\nI get so thrilled with Jesus\nHe\'s the Truth, the Life, the Way.\nI get so thrilled with Jesus\nHe satisfies my longing soul.\nI get so thrilled with Jesus\nHe\'s the One who makes me whole.', NULL),
(9, '0735', 'I give my mind', 'I give my mind\nCompletely to You, Lord\nFill me with Your thoughts,\nAnd make it all brand new\nChange my life\nLet me live in all that\'s true\nI just want to think like You\r\nTake me and hold me\nTeach me to be still\nLead me and guide me\nShow me Your perfect will\r\nSearch me and cleanse me\nPurify my heart\nChange me, transform me\nIn Your image let me stand\r\nBreak me and mold me\nTill I be like You\nReveal me Your pure Word\nLet Your light shine through me.', 'Ich gebe meine Gesinnung ganz Dir Herr\nFülle mich mit Deinen Gedanken und mache alles neu\nVerändere mein Leben, lass mich in der Wahrheit leben\nIch möchte nur denken wie Du\r\nNimm mich und halte mich, lehre mich ruhig zu sein\nFühre und Leite mich, zeige mir Deinen vollkommenen Willen\r\n\r\n'),
(9, '0736', 'I give myself away', 'I give myself away,\nI give myself away,\nso You can use me.\nI give myself away,\nI give myself away,\nso You can use me.\r\nHere I am.\nHere I stand.\nLord, my life is in your hands.\nLord, I’m longing to see\nyour desires revealed in me.\r\nTake my heart.\nTake my life.\nAs a living sacrifice.\nAll my dreams, all my plans,\nLord I place them in your hands.\r\nMy Life is not my own\nTo you I belong\nI give myself, I give myself to you 2x', '(Ich gebe mich selbst auf,\nIch gebe mich selbst auf,\ndamit Du mich gebrauchen kannst.\nIch gebe mich selbst auf,\nich gebe mich selbst auf,\ndamit Du mich gebrauchen kannst.)\r\nHier bin ich.\nHier stehe ich.\nHerr, mein Leben liegt in deinen Händen.\nHerr, ich sehne mich danach zu sehen\ndeine Wünsche in mir offenbart werden.\r\nNimm mein Herz.\nNimm mein Leben.\nAls ein lebendiges Opfer.\nAll meine Träume, all meine Pläne,\nHerr, ich lege sie in deine Hände.\r\nMein Leben gehört nicht mir\nDir gehöre Ich\nIch geb\' mich, Ich geb\' mich Dir hin.2x'),
(9, '0737', 'I got my Mind made up   (Chorus)', 'I got my mind made up,\nand I won\'t turn back,\n\'Cause I want to see my Jesus\nsome day.\nI got my mind made up,\nand I won\'t turn back,\n\'Cause I want to see my Jesus\nsome day.', NULL),
(9, '0738', 'I have a longing in my heart for Jesus   (Sehnsucht, Sehnsucht nach Jesus)', 'I have a longing in my heart for Jesus,\nI have a longing in my heart for Him.\nAlthough I know His presence lingers near me,\nI have a longing just to see His face.\r\nLonging, longing for Jesus.\nI have a longing in my heart for Him.\nJust to be near Him, to feel His presence,\nI have a longing in my heart for Him.\r\nI have a longing just to walk with Jesus,\nI have a longing just to hold His hand.\nTo know He\'s there forever near to guide me,\nto know His love will never let me go.\r\nTo you who do not know this man named Jesus,\nyou\'ve never lived or found life\'s greatest joy.\nOh, won\'t you now take Him as Lord and Saviour,\nand know the fullness of His matchless love?', '\r\nSehnsucht, Sehnsucht nach Jesus.\nIch hab\' ein Sehnen in dem Herz nach Dir.\nLass mich Dir nahen, Dich zu erleben,\nich hab\' ein Sehnen in dem Herz nach Dir.\r\n\r\n'),
(9, '0739', 'I have a loving Saviour, oh what a Christ have I   (And this is why I love Him)', 'I have a loving Saviour,\noh what a Christ have I.\nTo leave His home in Glory\nto come to earth to die.\nI think of Him so tender,\nso loving and so kind.\nHe gave His life for sinners,\nmy Saviour crucified.\r\nAnd this is why I love Him,\nbecause He first loved me.\nTo purchase my redemption,\nHe hung upon a tree.\nAt last He cried "Tis finished",\nHe hung His head and died.\nOh what a sight for sinners,\nmy Jesus crucified.\r\nThey mocked Him\nand they scoffed Him,\nwith thorns they crowned His head.\nAs a lamb unto the slaughter\nMy Saviour! -  He was led.\nThe soldier\'s cruel dagger\nwas thrust into His side.\nOh what a sight for sinners,\nmy Saviour crucified.\r\nI have a risen Saviour,\nHe means so much to me.\nI\'m longing for His coming,\nHis blessed face to see.\nI pray I may prove faithful\nand in His Word abide.\nAnd one day I shall se Him,\nmy Saviour crucified.', NULL),
(9, '0740', 'I have a Revival in my Soul   (Chorus)', 'I have a revival in my soul,\nI have a revival in my soul.\nI\'m redeemed by the Blood of the Lamb.\nI have a revival in my soul.', NULL),
(9, '0741', 'I have a Song I love to sing   (since I have been redeemed)', 'I have a song I love to sing,\nsince I have been redeemed.\nOf my Redeemer, Saviour, King,\nsince I have been redeemed.\r\nSince I have been redeemed,\nsince I have been redeemed.\nI will glory in His name;\nSince I have been redeemed,\nI will glory in my Saviour\'s name.\r\nI have a Christ that satisfies,\nsince I have been redeemed.\nTo do His will my highest prize,\nsince I have been redeemed.\r\nI have a witness bright and clear,\nsince I have been redeemed.\nDispelling ev\'ry doubt and fear,\nsince I have been redeemed.\r\nI have a home prepared for me,\nsince I have been redeemed.\nWhere I shall dwell eternally,\nsince I have been redeemed.', NULL),
(9, '0742', 'I have crossed the riven Veil   (Chorus)', 'I have crossed the riven veil\nwhere the glory never fails,\nHalleluja, Halleluja.\nI have crossed the riven veil\nwhere the glory never fails,\nFor I\'m living in the presence of the King.', NULL),
(9, '0743', 'I have found His Grace is all complete   (It is Joy unspeakable and full of Glory)', 'I have found His grace Is all complete,\nHe supplieth every need.\nWhile I sit and learn at Jesus\' feet,\nI am free, yes free indeed.\r\nIt is joy unspeakable and full of glory,\nfull of glory, full of glory.\nIt is joy unspeakable and full of glory,\noh, the half has never yet been told.\r\nI have found the pleasure I once craved,\nit is joy and peace within.\nWhat a wondrous blessing! I am saved,\nfrom the awful guilt of sin.\r\nI have found that hope so bright and clear,\nliving in the realm of grace.\nOh, the Saviour\'s presence is so near,\nI can see His smiling face.\r\nI have found the joy no tongue can tell,\nhow its waves of glory roll!\nIt is like a great o\'erflowing well,\nspringing up within my soul.', NULL),
(9, '0744', 'I have heard how Christians long ago   (I pledge allegiance to the Lamb)', 'I pledge allegiance to the Lamb,\nwith all my strength, with all I am.\nI will see to wander His commands.\nI pledge allegiance to the Lamb.\r\nI have heard how Christians long ago,\nwe\'re brought before a tirans thrown.\nThey were told that he would spare their lives,\nif they would renounce the name of Christ.\r\nBut one by one, they chose to die.\nThe Son of God they would not deny,\nlike the great and gently pride saints,\nI can almost here their voices sing:\r\nNow the years have come, and the years have gone.\nBut the cause of Jesus, still goes on.\nNow the time has come, to count the cost,\nto reject His Word, to embrace the cross.\r\nAnd one by one let us give our lives,\nfor the One who died to give us live.\nTill the trumpet sounds on that final day,\nlet us proudly stand, and boldly say.\r\nTo the Lamb of God, who bored my pain,\nwho took my place, who whore my shame.\nI will seek to wander His commands,\nI pledge allegiance to the Lamb.', NULL),
(9, '0745', 'I have heard, but now I see', 'I have heard, but now I see\nwhat my Jesus spoke to me,\nYou may say: "How can this be?"\nI\'ve heard from my theophany!\nI\'ve heard from my theophany!\r\nWord of God, oh, word of God,\nspoken to me by my Lord,\nall the doubts will fall from me,\nI\'ve heard from my theophany!\nI\'ve heard from my theophany!\r\nNot a demon will stop me,\nall the devils have to flee,\nI know I\'ll have the victory,\nI\'ve heard from my theophany!\nI\'ve heard from my theophany!', NULL),
(9, '0746', 'I have lived a life of sin in this world I\'m living in   (Across the Bridge there\'ll be no Sorrow)', 'I have lived a life of sin in this world I\'m living in.\nI have done forbidden things I shouldn\'t do.\nI asked a beggar along the way, if he could tell me where to stay.\nWhere I could find real happiness and love that\'s true.\r\nAcross the bridge there\'ll be no sorrow,\nacross the bridge there\'ll be no pain.\nThe Son will shine across the river,\nand we\'ll never be unhappy again.\r\nFollow the footsteps of the King till you hear the voices ring.\nThey\'ll be singing out the glory of the land.\nThe river Jordan will be near, the sound of trumpets you will hear.\nAnd you\'ll behold the most precious place ever known to man.', NULL),
(9, '0747', 'I just wanna be where You are', 'I just wanna be where You are,\ndwelling daily in Your Presence.\nI don\'t want to worship from afar,\ndraw me close to where You are.\r\nI wanna be where You are,\ndwelling in Your Presence,\nfeasting at Your table,\nsurrounded by Your Glory.\nIn Your Presence that\'s\nwhere I always want to be,\nI just want to be with You.', NULL),
(9, '0748', 'I just want the Dove to lead this Eagle', 'I just want the Dove to lead this eagle,\nI just want the Dove to lead this eagle home.\nFor I know the Dove is here, He has come to lead God\'s eagles.\nAnd I know He will guide me,aAnd keep me in His Word.\r\nI just want to follow the way You will lead me,\nI just want to follow, the way that You will go.\nFor I know You will lead me, in the footprints that You have left.\nAnd I know that You will guide me, and keep me in this path.\r\nI just love that Dove, for He is my Lord.\nI just love that Dove, for He is has been my guide.\nHe has brought me up seven steps to a perfect Faith I\'ve never known.\nNow He\'ll send me with His Word, as He rides this trail again.', NULL),
(9, '0749', 'I keep falling in love with Him', 'I keep falling in love with Him,\nfalling in love with Him,\nover and over again. (2x)\r\nIt gets sweeter and sweeter as the days go by.\nOh, what a love between my Lord and I.\nI keep falling in love with Him,\nover and over and over and over again.', NULL),
(9, '0750', 'I know my Redeemer lives   (Chorus)', 'I know my Redeemer lives,\nI know my Redeemer lives,\nlet all creation testify.\nLet this life within me cry,\nI know my Redeemer lives.', 'Ich weiß, dass mein Erlöser lebt,\nIch weiß, dass mein Erlöser lebt,\ndie ganze Schöpfung soll es bezeugen.\nLass dieses Leben in mir schreien,\nIch weiß, dass mein Erlöser lebt.'),
(9, '0751', 'I know what it\'s like to think of things I\'ve done  -  Ich weiß, wie es ist, an Dinge zu denken, die ich getan habe   (He has forgiven me)', 'I know what it\'s like to think of things I\'ve done\nand want to run and hide my head in shame.\nI know what it\'s like to really hurt someone\nand feel no sense of sorrow at their pain.\nBut I know what it\'s like to have enough of my disgrace\nand find because of Jesus\' blood my sins can be erased.\r\nHe has forgiven me,\nmy sins have been washed from His Memory,\nby the Blood of the Lamb of Calvary\nHe has forgiven me.\r\nDo you know what it\'s like for God to be your friend?\nTo talk to Him with nothing in between?\nDo you know what it\'s like when the day comes to an end,\nto sleep in peace because your heart is clean?\nDo you know what it\'s like when the accuser comes your way?\nTo look him squarely in the eye with confidence and say:', 'Ich weiß, wie es ist, an Dinge zu denken, die ich getan habe\nund weglaufen zu wollen und meinen Kopf in Schande zu verstecken.\nIch weiß, wie es ist, jemanden wirklich zu verletzen\nund kein Gefühl der Trauer über seinen Schmerz zu empfinden.\nAber ich weiß wie es ist, genug von meiner Schande zu haben\nund zu erfahren, dass durch das Blut Jesu meine Sünden getilgt werden können.\r\nEr hat mir verziehen,\nmeine Sünden sind aus Seinem Gedächtnis ausgewaschen worden.\ndurch das Blut des Lammes von Golgatha\nhat er mir vergeben.\r\nWeißt du wie es für Gott ist, dein Freund zu sein?\nMit Ihm zu reden, ohne dass etwas dazwischen kommt?\nWeißt du wie es ist, wenn der Tag zu Ende geht,\nin Frieden zu schlafen, weil dein Herz rein ist?\nWeißt du wie es ist, wenn der Ankläger auf dich zukommt?\nIhm vertrauensvoll in die Augen zu schauen und zu sagen:'),
(9, '0752', 'I look and see earth\'s sorrowing Picture, the Hoarding Mobs for selfish Gain   (The end is here, it\'s now at hand, the Bride is gathering; the World is failing)', 'I look and see earth\'s sorrowing picture,\nthe hoarding mobs for selfish gain.\nTheir toil of hand for ease and comfort,\ncan they not see, their doom is sealed, it\'s all in vain.\r\nThe end is here, it\'s now at hand,\nthe Bride is gathering; the world is failing.\nIsrael\'s awaking, nations are breaking,\nour prophet taught us, we believe the end is here.\r\nSirs, this is the time, our prophet spoke of!\nThe angel came with a shout.\nThe mountain shook as His voice cried out:\n"Time is no more", loud and clear the shout went forth.\r\nHave you considered the end-time message?\nHave you considered Maleachi 4?\nRevelation 10:7 and St. Luke 17\nproclaims this message now, and then forevermore.', NULL),
(9, '0753', 'I love Him better every Day   (Chorus)', 'I  love Him better every day,\nI love Him better every day.\nClose by His side, I will abide,\nI love Him better every day.', NULL),
(9, '0754', 'I love Him for He is mine   (2 Chorusse)', 'I love Him for He is mine,\nI love Him for He is divine,\nI\'ve loved Him forever it seems,\nthis Jesus, the Nazarene.\r\nI wonder just where I\'d be\nif not for the Nazarene,\nI know I\'d be still in my sins,\no blessed be the Nazarene.', NULL),
(9, '0755', 'I love that thrill that I feel', 'I love that thrill that I feel,\nwhen I get together with\nGod\'s wonderful people. (2x)\r\nWhat a joy just to see all their happy faces,\npraising the Lord in heavenly places.\nI love that thrill that I feel,\nwhen I get together with\nGod\'s wonderful people.', NULL),
(9, '0756', 'I love You Lord, today   (Chorus)', 'I love You, I love You,\nI love You Lord, today.\nBecause You care for me,\nin such a special way,\nand yes I praise You, I lift You up,\nI magnify Your Name.\nThat\'s why my heart,\nis filled with praise.', 'Ich liebe Dich, ich liebe Dich,\nIch liebe Dich, Herr, heute.\nDenn Du sorgst für mich,\nauf so eine besondere Art und Weise,\nund ja, ich preise Dich, ich erhebe Dich,\nIch verherrliche Deinen Namen.\nDas ist der Grund, warum mein Herz,\nmit Lob erfüllt.'),
(9, '0757', 'I need You Lord (4 Chorusse)', 'I need You Lord,\nI need You Lord, right now.\nI need You Lord,\nI need You Lord, right now.\nI lift my hands,\nand bow my knees,\nand worship at your throne.\nI need You Lord,\nI need You Lord, right now.\r\nWe need You Lord,\nwe need You Lord, right now.\nWe need You Lord,\nwe need You Lord, right now.\nWe lift our hands,\nand bow our knees,\nand worship at your throne.\nWe need You Lord,\nwe need You Lord, right now.', 'Ich brauche Dich Herr, grade jetzt.)\n(Ich erhebe meine Hände und beuge meine Knie\nund bete an vor Deinem Thron.\r\nWir brauchen Dich Herr, grade jetzt.)\n(Wir erheben unsere Hände und beugen unsere Knie\nund beten an vor Deinem Thron.'),
(9, '0758', 'I read of how they beat Him, and of how they plucked His Face   (That Joy was you, and you were worth every Stripe)', 'I read of how they beat Him, and of how they plucked His face.\nThen I asked my Lord, how could you stand to suffer such disgrace?\nYou\'re the very source of life, and yet You chose to die.\r\nThat joy was you, and you were worth every stripe.\nLong before I made the world, I had you on my mind.\nYou are everything I hoped for, and I think it\'s time you knew.\nThe joy set before me -- That joy was you.\r\nHow could you let them do it? Then I heard His sweet reply,\nfor the joy set before me,  I endured the cross.\nThen I asked my Lord what sort of joy could justify the cost?\nOh, Lord, what kind of happiness could be worth the blood you shed?\nThen my Saviour smiled at me and said:\r\nI know you feel unworthy, my love\'s hard to comprehend.\nAnd so I\'ll try to tell you in a way you\'ll understand.\nWhen a man\'s in love, he would give his life,\nif he thought that he could save his children or his wife.\r\nAnd if I had to choose, I\'d do it all again,\nfor the love of God far exceeds the love of man.\nThe joy I set before me was a spotless bride.\nDo you know how much I\'ve longed to have you by my side?', NULL),
(9, '0759', 'I remember when my Burdens rolled away   (Rolled away, rolled away, I am happy since my Burdens rolled away)', 'I remember when my burdens rolled away.\nI had carried them for years, night and day.\nWhen I sought the blessed Lord, and I took Him at His Word,\nthen at once all my burdens rolled away.\r\nRolled away, rolled away,\nI am happy since my burdens rolled away.\nRolled away, rolled away,\nI am happy since my burdens rolled away.\r\nI remember when my burdens rolled away.\nThat I feared would never leave night or day.\nJesus showed to me the loss, so I left them at the cross.\nI was glad when my burdens rolled away.\r\nI am singing since my burdens rolled away.\nThere\'s a song within my heart night and day.\nI am living for my King, And with joy I shout and sing.\nHalleluja! all my burdens rolled away.', NULL),
(9, '0760', 'I say yes Lord, yes   (2 Chorusse)', 'I say yes, Lord, yes\nTo Your will and to Your way\nI say yes, Lord, yes\nI will trust You and obey.\r\nWhen Your spirit speaks to me\nWith my whole heart I\'ll agree\nAnd my answer will be:\nYes, Lord Yes!', NULL),
(9, '0761', 'I sing praises to Your Name, oh Lord   (2 Chorusse)', 'I sing praises to Your Name, oh Lord,\npraises to Your Name, oh Lord.\nFor Your Name is great\nand greatly to be praised.      (2x)\r\nI give glory to Your Name, oh Lord,\nglory to Your Name, oh Lord,\nfor Your Name is great\nand greatly to be praised.      (2x)\r\nThere is healing in Your Name, oh Lord,\nhealing in Your Name, oh Lord.\nFor Your Name is great\nand greatly to be praised.      (2x)', NULL),
(9, '0762', 'I speak Jesus', 'I just wanna speak the name of Jesus\nOver every heart and every mind\n\'Cause I know there is peace within Your presence\nI speak Jesus\r\nI just wanna speak the name of Jesus\n\'Til every dark addiction starts to break\nDeclaring there is hope and there is freedom\nI speak Jesus\r\n\'Cause Your name is power\nYour name is healing\nYour name is life\nBreak every stronghold\nShine through the shadows\nBurn like a fire\r\nI just wanna speak the name of Jesus\nOver fear and all anxiety\nTo every soul held captive by depression\nI speak Jesus\r\nShout Jesus from the mountains\nJesus in the streets\nJesus in the darkness over every enemy\nJesus for my family\nI speak the holy name\nJesus', 'Ich sprech aus den heilgen Namen Jesus\nüber jede Seele,  jedes Herz.\nIch weiss genau, bei Dir herrscht tiefer Friede.\nIch sag Jesus\r\nIch sprech aus den heilgen Namen Jesus\nIch hör nicht auf,  bis jede Kette bricht.\nIch proklamiere Hoffnung echte Freiheit.\nIch sag Jesus.\r\nDu bist das Leben,\ndu bist der Heiler,\ndu bist Kraft.\nSpreng jede Festung,\nbrenn wie ein Feuer,\nstrahl in der Nacht.\r\nIch sprech aus den heilgen Namen Jesus\nüber Furcht und über jede Angst,\nzu jedem Herzen voller Depressionen.\nIch sag Jesus\r\nRuft Jesus von den Bergen,\nJesus in die Stadt,\nJesus in das Dunkel, über jeden bösen Feind,\nfür meine Familie.\nIch sprech das heilge Wort Jesus.'),
(9, '0763', 'I thank the Lord, I\'m homeward bound   (He is the same today)', 'I thank the Lord, I\'m homeward bound,\nsomeday I\'ll leave the earth.\nOh soon will now the rapture come\nand that\'s all sorrow\'s worth.\nThe Lord\'s mercy has set me free,\nthe Blood has been applied.\nWith Christ I go in charity\n\'cause in Him I abide.\r\nHe is the same today,\nHe is the same today,\nby Him there is no change at all,\nHe is the same today.\r\nThe gentile days are numbered now,\nGod\'s wrath is really nigh.\nManmade laws cause pain and sorrow,\nGod\'s day comes by and by.\nSin is increasing everywhere,\nthe measure \'s almost full.\nBut God\'s prophet restored all things,\nshowing us the third pull.\r\nWhen I read Matthew twenty-four\nand see what happens now.\nThen I see the end is at the door,\nthat ends the bride\'s sorrow.\nThe Lord again deals with the Jews\nwhen the Bride is gone away.\nSo now there \'s just a short time left,\nfor this last gentile day.', NULL),
(9, '0764', 'I wandered so aimless, Life filled with Sin   (I saw the light, I saw the light)', 'I wandered so aimless, life filled with sin,\nI wouldn\'t let my dear saviour in.\nThen Jesus came like a stranger in the night.\nPraise the Lord, I saw the light.\r\nI saw the light, I saw the light,\nno more in darkness, no more in night.\nNow I\'m so happy, no sorrows inside.\nPraise the Lord, I saw the light.\r\nJust like a blind man I wandered allone,\nworries and fears I claimed for my own.\nThen like the blind man that God gave back his sight.\nPraise the Lord, I saw the light.\r\nI was a fool to wander and stray,\nstraight is the gate and narrow the way.\nNow I have traded the wrong for the right.\nPraise the Lord, I saw the light.', NULL),
(9, '0765', 'I wanna be more like you Jesus', 'I wanna be more like you Jesus\nI wanna be more like you\nI wanna be a vessel you work through\nI wanna be more like you\nI wanna be more like you Jesus\nI wanna be more like you\nI wanna be a vessel you work through\nI wanna be more like you', NULL),
(9, '0766', 'I want to do Thy Will, oh Lord   (Chorus)', 'I want to do Thy will, oh Lord,\nI want to do Thy will, oh Lord.\nTake me, break me,\nmould me and make me.\nI want to do Thy will, oh Lord.', NULL),
(9, '0767', 'I want what you want', 'I want what you want for me dear lord.\nWhatever, wherever it may be.\nCause I know that you know what\'s best, my lord.\nII: I want what you want for me :II', NULL),
(9, '0768', 'I want you to know that a few Years ago   (Don\'t worry, when Things go wrong)', 'I want you to know, that a few years ago\nI thought, things were going well.\nBut Satan came in to interrupt my plans\nand that\'s when things began to fail.\nBut He told me: "Keep on living right,\nkeep walking in the light,\ndon\'t worry, it will be allright."\r\nDon\'t worry, when things go wrong.\nGod will help you if you go on.\nKeep on living right,\nkeep walking in the light.\nDon\'t worry, it will be allright.\r\nMy health seemed to fail, I wasn\'t feeling well\nand I tried so hard to carry on.\nWell, I lost my appetite and I couldn\'t sleep at night,\nwell, sometimes I was left all alone.\nBut He told me: "Keep on living right,\nkeep walking in the light,\ndon\'t worry, it will be allright."\r\nI want you to know, Jesus loves me so,\nno matter what others have in mind,\nwell, He took me by my hand,\nHe said:"Child, understand,\nI\'ll be yours and you be mine."\nAnd He told me:\n"Keep on living right,\nkeep walking in the light,\ndon\'t worry, it will be allright."', NULL),
(9, '0769', 'I was glad when they said unto me: Let us go into the House of the Lord   (Chorus)   (Psalm 122,1)', 'I was glad when they said unto me,\nI was glad when they said unto me,\nI was glad when they said unto me:\n"Let us go into the House of the Lord."', NULL),
(9, '0770', 'I was in Sin and Prison oh, so dark and cold   (Jesus gab mir Gnade  -  Jesus signed my Pardon)', 'I was in sin and prison\noh, so dark and cold,\nlike a lost sheep wandering\nfrom God\'s eternal fold.\nThen the door wung open\nand He spoke to me:\n"I have signed your pardon,\nnow you may go free"\r\nJesus signed my pardon,\nthis I surely know.\nHe took my place on Calvary,\nnow I don\'t have to go.\nAll my life I give Him,\nHe gave His for me.\nWhen He signed my pardon,\nthere at Calvary.\r\nWhen my Saviour led me\nfrom that awful place,\nI could hear the saints\nthey sing: Amazing grace.\nNow I know, I\'m pardoned\nfrom my sin and shame\nand I\'ll join them, singing:\nGlory to his name.\r\nSinner friend that\'s wandering\nfrom that blessed fold,\nJesus died for you\nto save your sinsick soul.\nNo more in satan\'s prison\ndo you now belong.\nCan\'t you hear Him calling:\n"Now you may come home".', '\r\nJesus gab mir Gnade,\ndas weiß ich genau.\nEr ging für mich nach Golgatha,\nich brauche nicht zu geh\'n.\nIch geb\' Ihm mein Leben,\nEr gab Seins für mich,\nals Er mich begnadigte auf Golgatha.\r\n\r\n'),
(9, '0771', 'I will arise and go forth in the Name of the Lord of Hosts', 'I will arise and go forth\nin the Name of the Lord of hosts.\nFor He has conquered every foe,\nby His Word, by His Word.\nI will declare that He is Lord\nand in Him I am not ashamed.\nFor He has conquered every foe,\nby His Word.\r\nSo with the high praises of God\nin our mouth.\nAnd the two edged sword\nin our hand.\nWe\'ll march right up into victory,\nright into Canaan Land!', NULL),
(9, '0772', 'I will comfort them and make them rejoice   (For He will turn our Mourning into Joy)', 'I will comfort them\nand make them rejoice\nfrom their sorrow, says the Lord. (2x)\r\nFor He will turn our mourning into joy,\nfor He will turn our mourning into joy,\ninto joy!\r\nHe will gather us,\ntherefore we shall come,\npraise the goodness of our Lord. (2x)\r\nThen shall we rejoice\nwith great joy and dance\nboth young men and old together. (2x)', NULL),
(9, '0773', 'I will dwell in the secret place of the Most High   (Psalm 91)', 'I will dwell in the secret place of the Most High\nI will stay in the shadow of Your wings\r\nFor Lord, You are my refuge\nMy tower of strength.\nMy hope is in You\nsecure, I stand.\r\nYou will deliver me,\nYour truth will be my shield.\nJesus, You cover me,\nin Your love, no fear prevails.\r\nNo evil, no terror, no arrow, no plague\nshall ever come near me.\nFor You are my safety, my hiding place\nJesus, I trust in You.\nJesus, I trust in You.\nJesus, I trust in You.\nJesus, I trust in You.', NULL),
(9, '0774', 'I will give Him Glory, I will give Him Praises   (Chorus)', 'I will give Him glory, I will give Him praises,\nI will shine the light deep into the night,\nI will give Him glory.\nI will give Him glory, I will give Him praises,\nEvery song I sing, I just wanna bring\nglory to my King.', NULL),
(9, '0775', 'I will praise the Lord   (Chorus)', 'I will praise the Lord,\nI will praise the Lord.\nNo matter what tomorrow brings,\nwhat it has in store.\nI will praise the Lord.', NULL),
(9, '0776', 'I will serve Thee, because I love Thee   (Chorus)', 'I will serve Thee, because I love Thee,\nYou have given life to me.\nI was nothing before you found me,\nYou have given life to me.\nHeartaches, broken pieces,\nruined lives are why you died on Calvary.\nYour touch is what I long for,\nYou have given life to me.', NULL),
(9, '0777', 'I will sing', 'Lord, You seem so far away\nA million miles or more,\nIt feels today\nAnd though I haven\'t lost my faith\nI must confess right now\nThat it\'s hard for me to pray\nBut I don\'t know what to say\nAnd I don\'t know where to start\nBut as You give the grace\nWith all that\'s in my heart\r\nI will sing I will praise,\nEven in my darkest hour\nThrough the sorrow and the pain\nI will sing I will praise,\nLift my hands to honor You\nBecause Your word is true,\nI will sing\r\nLord it\'s hard for me to see\nAll the thoughts and plans\nYou have for me\nBut I will put my trust in You\nKnowing that you died\nTo set me free\nBut I don\'t know what to say\nAnd I don\'t know where to start\nBut as you give the grace\nWith all that\'s in my heart', NULL),
(9, '0778', 'I will sing of the Mercies of the Lord forever   (Psalm 89, 1)', 'I will sing of the mercies of the Lord forever,\nI will sing, I will sing.\nI will sing of the mercies of the Lord forever,\nI will sing of the mercies of the Lord.\r\nWith my mouth shall I make known\nThy faithfulness, Thy faithfulness.\nWith my mouth shall I make known\nThy faithfulness to all generations.\nI will sing of the mercies  of the Lord forever,\nI will sing of the mercies of the Lord.', '(Ich werde immer von der Gnade des Herrn singen)\r\n(Mit meinem Mund mache ich bekannt\nDeine Treue\nMit meinem Mund mache ich bekannt\nDeine Treue an alle Generationen)'),
(9, '0779', 'I will trust my Saviour Jesus', 'I will trust my Saviour Jesus,\nwhen my darkest doubts befall.\nTrust Him when to simply trust Him,\nseems the hardest thing of all.\r\nI will trust my Saviour Jesus,\ntrust Him when my strength is small.\nFor I know the shield of Jesus,\nis the safest place of all.\r\nJesus, only Jesus\nhelp me trust you more and more.\nJesus, only Jesus\nmay my heart be ever yours.\r\nI will trust my Saviour Jesus\nHe has said, His way is best.\nFor I know the path He’s chosen\nleads to everlasting rest.\r\nOh on that cross, how it was seen\nI can go now ever trusting in the One who died for me.\nWhat could I bring for your gift is complete\nso I trust you, simply trust you, Lord, with every part of me.', NULL),
(9, '0780', 'I will worship you, (I will worship you)', 'I will worship you, (I will worship you)\nWorship and adore you\nI will worship you, (I will worship you)\nLay my life before you\r\nI\'ll bow my head before your glory\nWorship at your feet\nAnd I\'ll declare that you are worthy\nI\'ll set my eyes on you alone and\r\nI will lift my hands to you saying\n"Father I love you, Father I need you"\nI will lift my voice and sing\nI will sing of your glory, the glory of my king', NULL),
(9, '0781', 'I wrote a letter to my Lord, I didn\'t know where to start   (I wanna be Yours forever, Yours forever, Lord)', 'I wrote a letter to my Lord,\nI didn\'t know where to start.\nThere was so much to thank Him for,\nthat swelled within my heart.\nI thanked Him for the love inside,\nthat I didn\'t have before.\nAnd at the end I signed it:\nI\'ll be Yours forever more.\r\nI wanna be Yours forever,\nYours forever, Lord,\nI wanna be Yours forever\nYours forever, Yours forever,\nYours forever more.\r\nA few days later in Sunday school,\nwe learned John 3:16.\nIt told of everlasting life,\nif only we\'d believe.\nNow everlasting means forever,\nand I began to see.\nGod\'s Word was a letter to my heart,\nHe\'d written back to me.', 'Ich schrieb einen Brief an meinen Herrn,\nIch wusste nicht, wo ich anfangen sollte.\nEs gab so viel, wofür ich ihm danken konnte,\ndas in meinem Herzen wuchs.\nIch dankte ihm für die Liebe in mir,\ndie ich vorher nicht hatte.\nUnd am Ende unterschrieb ich es:\nIch werde für immer der Deine sein.\r\nIch will für immer Dein sein,\nFür immer Dein, Herr,\nIch will für immer Dein sein\nFür immer dein, für immer dein,\nDeins für immer.\r\nEin paar Tage später in der Sonntagsschule,\nlernten wir Johannes 3,16.\nDort ist vom ewigen Leben die Rede,\nwenn wir nur glauben würden.\nNun bedeutet "ewig" "für immer",\nund ich begann zu verstehen.\nGottes Wort war ein Brief an mein Herz,\nEr hatte mir zurückgeschrieben.'),
(9, '0782', 'I\'m a Pilgrim and a Stranger wand\'ring through this World of Sin   (When the saints go marching in)', 'I\'m a pilgrim and a stranger\nWand\'ring through this world of sin,\nOn my way to that fair city,\nWhen the Saints go marching in.\r\nWhen the saints go marching in,\nWhen the saints go marching in,\nLord, I want to be in that number\nWhen the saints go marching in.\r\nOh, I know I\'ll see my Saviour\nif my life is free from sin,\nheaven\'s doors will open for me\nwhen the Saints go marching in.\r\nWhen we gather \'round the throne\nAnd the gates are closed within,\nI\'ll be shouting "Glory, Glory"\nWhen the Saints go marching in.\r\nI\'m waiting for the chariot\nTo swing low and I\'ll step in,\nOn the clouds I\'ll ride to Heaven\nWhen the Saints go marching in.', NULL),
(9, '0783', 'I\'m coming to Jesus for Rest   (I believe Jesus saves)', 'I\'m coming to Jesus for rest,\nrest, such as the purified know.\nMy soul is athirst to be blest,\nto be washed and made whiter than snow.\r\nI believe Jesus saves,\nand His blood washes whiter than snow.\nI believe Jesus saves,\nand His blood washes whiter than snow.\r\nIn coming, my sin I deplore,\nmy weakness and poverty show.\nI long to be saved evermore,\nto be washed and made whiter than snow.\r\nTo Jesus I give up my all,\nevery treasure and idol I know.\nFor His fullness of blessing I call,\ntill His blood washes whiter than snow.', NULL),
(9, '0784', 'I\'m covered, covered by His Blood   (Chorus)', 'I\'m covered, covered,\ncovered by his blood,\nwalking by faith, living in love.\nI\'m covered, covered,\ncovered by his blood,\nJesus has rescued me.', NULL),
(9, '0785', 'I\'m depending on You, Lord, take me through   (6 Chorusse)', 'I\'m depending on You, Lord,\nTake me through. (3x)\nTake me through Lord!\nTake me through.\r\nI wanna go home, Lord.\nTake me through! (3x)\nTake me through, Lord!\nTake me through!\r\nOn bending knees, Lord.\nTake me through! (3x)\nTake me through, Lord!\nTake me through!\r\nSometimes I get weary, Lord.\nTake me through! (3x)\nTake me through, Lord!\nTake me through!\r\nI\'m Your child, Lord.\nTake me through! (3x)\nTake me through, Lord!\nTake me through!\r\nLord, I\'m striving for adoption,\nJustification just won\'t do...', NULL),
(9, '0786', 'I\'m gonna stay right under His Blood   (2 Chorusse)', 'I\'m gonna stay right under His Blood,\nI\'m gonna stay right under His Blood,\nI\'m gonna stay right under His Blood,\nWhere the devil can do me no harm.\r\nNo harm, no harm, no harm,\nNo harm, no harm, no harm.\nWhere the devil can do me no harm.', NULL),
(9, '0787', 'I\'m happy today with Jesus my Lord   (Chorus)', 'I\'m happy today, I\'m happy today.\nWith Jesus my Lord, I\'m happy today.\nHe took all my sins away from me\nand that\'s why I\'m happy today.', NULL),
(9, '0788', 'I\'m in that Number robed in white', '\r\nI\'m in that  number,\nthat blood-washed number,\nI\'m in that number robed in white.\nI\'m in that number,\nthat blood-washed number,\nI\'m in that number robed in white.\r\nJohn saw that number,\nThe blood-washed number,\nJohn saw that number robed in white;\nJohn saw that number,\nThat blood-washed number,\nJohn saw that number robed in white.', 'I\'m in that number, I\'m in that number,\nI\'m in that number robed in white;\nI\'m in that number, I\'m in that number,\nI\'m in that number robed in white.\r\n\r\n'),
(9, '0789', 'I\'m in the Way, the bright and shining Way   (I\'m in the Glory-Land Way)', 'I\'m in the way,\nThe bright and shining way,\nI\'m in the glory-land way;\nTelling the world\nThat Jesus saves today,\nYes, I\'m in the glory-land way.\r\nI\'m in the glory-land way\nI\'m in the glory-land way;\nHeaven is nearer,\nAnd the way groweth clearer,\nFor I\'m in the glory-land way.\r\nList to the call,\nThe gospel call today,\nGet in the glory-land way;\nWand\'rers, come home,\nOh, hasten to obey,\nAnd get in the glory-land way.\r\nOnward I go,\nRejoicing in His love,\nI\'m in the glory-land way;\nSoon I shall see Him\nIn that home above,\nOh, I\'m in the glory-land way.', NULL),
(9, '0790', 'I\'m loving You more every Day   (Chorus)', 'I\'m loving You more every day,\nloving You more every day.\nThe more I know You I want to show You,\nI\'m loving You more every day.', NULL),
(9, '0791', 'I\'m quickened, changed, translated', 'I\'m quickened, changed, translated\nby the Power of the Holy Ghost.\nAnd I\'m waiting for this outward\nto be changed and taken of the earth.\nHis Power now is moving\nand it\'s deep inside of me.\nAs I look into the mirror\nI know it\'s Him I see.', NULL),
(9, '0792', 'I\'m reaching out to You my Lord', 'I\'m reaching out to You dear Lord,\nI\'m reaching out to You.\nI know Your arm is not too short,\nand it can reach me too.\nAnd as I pray and press my way\ninto Your kingdom true.\nI long to be more like You,\njust by reaching out to You.', NULL),
(9, '0793', 'I\'m running for my Life', 'I\'m running for my life,\nI\'m running for my life,\nI\'m running for my life,\nevery day I\'m running for my life.\nIf anybody asks you,\nwhat\'s the matter with me,\ntell them I\'m saved and sanctified,\nHoly Ghost filled and water baptized;\nI\'ve got Jesus on the inside,\nand I\'m running for my life.\r\nWon\'t you come on home with me,\nwon\'t you come on\nHome with me,\nwon\'t you come on home with me, saint,\nwon\'t you come on home with me.\nIf anybody asks you,\nwhat\'s the matter with me,\ntell them I\'ve got the Original Seed,\ngoing in my theophany, step on in eternity,\nwon\'t you come on home with me.', NULL),
(9, '0794', 'I\'m so glad that the Lord brought me out', 'I\'m so glad that the Lord brought me out,\nI\'m so glad that the Lord brought me out.\nIf it had not been for Jesus, oh where would I be?\nI\'m so glad that the Lord brought me out.\r\nI\'ve been happy since the Lord  brought me out,\nI\'ve been happy since the Lord brought me out.\nIf it had not been for Jesus, oh where would I be?\nI\'m so glad that the Lord brought me out.\r\nI\'ve been shouting since the Lord  brought me out,\nI\'ve been shouting since the Lord  brought me out.\nIf it had not been for Jesus, oh where would I be?\nI\'m so glad that the Lord brought me out.\r\nI\'ve been singing since the Lord brought me out,\nI\'ve been singing since the Lord brought me ou.\nIf it had not been for Jesus, oh where would I be?\nI\'m so glad that the Lord brought me out.\r\nAren\'t you glad that the Lord brought you out?\nAren\'t you glad that the Lord brought you out?\nIf it had not been for Jesus, oh where would I be?\nI\'m so glad that the Lord brought me out.', NULL),
(9, '0795', 'I\'ve been changed', 'I\'ve been changed\nhealed,  freed,  delivered\nI\'ve found joy,  peace\ngrace and favor\r\nAnd right now is the moment\nToday is the day\nI\'ve been changed\nI\'ve been changed\nAnd I have waited for this moment to come\nAnd I won\'t let it pass me by\r\nI won\'t go back,  can\'t go back,\nto the way it used to be\nBefore your presence came\nand changed me\nI won\'t go back,  I can\'t go back,\nto the way it used to be\nBefore your presence came\nand changed me\r\nAll my shame,  guilt,  sins\nforgiven\nNo more chains,  fear\nMy past is over', NULL),
(9, '0796', 'I\'ve been on Mount Pisgah\'s lofty Height   (O the Fire is burning, yes, \'tis brightly burning in my Soul)', 'I\'ve been on Mount Pisgah\'s lofty height,\nAnd I\'ve satisfied my longing heart\'s desire;\nFor I caught a glimpse of glory bright,\nAnd my soul is burning with the fire.\r\nO the fire is burning,\nyes, \'tis brightly burning,\nO \'tis burning, burning in my soul;\nO the fire is burning,\nyes, \'tis brightly burning,\nO \'tis burning, burning in my soul.\r\nI will walk with Jesus, bless His name,\nAnd to be like Him I ev\'ry day aspire;\nFor His love is like a heav\'nly flame,\nAnd my soul is burning with the fire.\r\nI my all upon the altar lay,\nAs I to my closet lovingly retire;\nAnd the flame consumes while\nthere I pray,\nAnd my soul is burning with the fire.\r\nBy faith\'s eye I scan the ocean\'s foam,\nAnd beyond I see the haven I desire;\nThere I view the beacon lights of home,\nAnd my soul is burning with the fire.', NULL),
(9, '0797', 'I\'ve cast my heavy Burdens down on Canaan\'s happy Shore   (Living on the Shore, I\'m living on the Shore)', 'I\'ve cast my heavy burdens down on Canaan\'s happy shore,\nI\'m living where the healing waters flow.\nI\'ll wander in the wilderness of doubt and sin no more.\nI\'m living where the healing waters flow.\r\nLiving on the shore, I\'m living on the shore,\nI\'m living where the healing waters flow.\nLiving on the shore, I\'m living on the shore,\nI\'m living where the healing waters flow.\r\nWith Israel\'s trusting children I\'m rejoicing on my way,\nI\'m living where the healing waters flow.\nThe cloudy, fiery pillar is my guiding light today,\nI\'m living where the healing waters flow.\r\nMy hung\'ring soul is satisfied with manna from above,\nI\'m living where the healing waters flow,\nNo more I thirst, the rock I\'ve found,\nthat fount of endless love;\nI\'m living where the healing waters flow.\r\nI\'m singing "Halleluja,"\nsafely anchored in my soul,\nI\'m living where the healing waters flow,\nI\'m resting on his promises;\nthe blood has made me whole.\nI\'m living where the healing waters flow.', NULL),
(9, '0798', 'I\'ve come to worship You   (2 Chorusse)', 'I\'ve come to worship You (4x)\nfor You are so worthy, oh God (3x)\nfor You shed Your Blood, Your Blood.\r\nI sing: "Halleluja!" (4x)\nLord, You created me to worship You (2x)\nSo in Your Spirit, Lord, I worship You,\nand in Truth,in Truth.', NULL),
(9, '0799', 'I\'ve found a Friend who is all to me   (Saved by His Pow\'r divine)', 'I\'ve found a friend who is all to me,\nHis love is ever true.\nI love to tell how He lifted me,\nand what His grace can do for you.\r\nSaved by His pow\'r divine,\nsaved to new life sublime!\nLife now is sweet\nand my joy is complete,\nfor I\'m saved, saved, saved!\r\nHe saves me from ev\'ry sin and harm,\nsecures my soul each day.\nI\'m leaning strong on His mighty arm,\nI know He\'ll guide me all the way.\r\nWhen poor and needy and all alone,\nin love He said to me:\n"Come unto Me and I\'ll lead you home,\nto live with Me eternally.', NULL),
(9, '0800', 'I\'ve found the happy Side of Life', 'I\'ve found the happy side of life,\nI\'ve found the happy side of life,\nwith Jesus as my Saviour I\'ve found a way.\nRollin along, singing a song,\nevery single passing day.\nI\'ve found the happy side of life,\nI\'ve found the happy side of life,\nwith Jesus as my Saviour I\'ve found a way.\nI\'ve found the happy side of...\nI\'ve found the happy side of...\nI\'ve found the happy side of life.', NULL);
INSERT INTO song_list (LISTID, NUM, NAME, TEXT_EN, TEXT_DE) VALUES
(9, '0801', 'I\'ve got a Father over yonder', 'I\'ve got a Father over yonder,\nI\'ve got a Father over yonder,\nI\'ve got a Father over yonder,\non the other shore.\r\nSome bright day I\'ll go and see Him,\nsome bright day I\'ll go and see Him,\nsome bright day I\'ll go and see Him,\non the other shore.\r\nWon\'t that be a happy meeting!\nWon\'t that be a happy meeting!\nWon\'t that be a happy meeting!\nOn the other shore.\r\nThat bright day may be tomorrow,\nthat bright day may be tomorrow,\nthat bright day may be tomorrow,\non the other shore.', NULL),
(9, '0802', 'I\'ve got my Mind made up   (Chorus)', 'I\'ve got my mind made up to serve the Lord,\nI\'ve got my mind made up to serve the Lord,\nI\'ve got my mind made up to serve the Lord,\nLord I\'ve got my mind made up.', NULL),
(9, '0803', 'I\'ve got so much to thank Him for   (Chorus)', 'I\'ve got, so much to thank Him for,\nSo much to praise Him for,\nYou see, He has been so good to me.\nWhen I think, of what He\'s done,\nAnd where He\'s brought me from,\nI\'ve got so much to thank Him for.', NULL),
(9, '0804', 'I\'ve got something that the World can\'t give and the World can\'t take it away', 'I\'ve got something that the world can\'t give,\nand the world can\'t take it away.\nI\'ve got something that the world can\'t give\nand it keeps me day by day.\nI\'ve got something worth talking about,\nit makes me sing and it makes me shout.\nI\'ve got something that the world can\'t give\nand the world can\'t take it away.', NULL),
(9, '0805', 'I\'ve got the Holy Ghost down in my Soul', 'I\'ve got the Holy Ghost down in my soul,\njust like the Bible said.\nI\'ve got the Holy Ghost down in my soul,\njust like the Bible said.\nI\'ve got the Holy Ghost down in my soul,\njust like the Bible said.\r\nI\'ve been to the water and I\'ve been baptised,\nmy soul got happy and I feel alright.\nI\'ve put my hands on the Gospel plough,\nand I wouldn\'t take nothing for my journey back now.\nJust like the Bible,\njust like the Bible,\njust like the Bible said.', NULL),
(9, '0806', 'I\'ve seen the Light\'ning flashing and heard the Thunder roll   (No, never alone / Nein, niemals allein)', 'I\'ve seen the light\'ning flashing,\nand heard the thunder roll.\nI\'ve felt sin\'s breakers dashing,\ntrying to conquer my soul.\nI\'ve heard the voice of my Saviour,\ntelling me still to fight on.\nHe promised never to leave me,\nnever to leave me alone.\r\nNo, never alone! No, never alone!\nHe promised never to leave me,\nnever to leave me alone.\nNo, never alone! No, never alone!\nHe promised never to leave me,\nnever to leave me alone.\r\nThe world\'s fierce winds are blowing,\ntemptations sharp and keen.\nI feel a peace in knowing.\nmy Saviour stands between.\nHe stands to shield me from danger,\nwhen earthly friends are gone.\nHe promised never to leave me,\nnever to leave me alone.\r\nWhen in affliction\'s valley,\nI\'m treading the road of care.\nMy Saviour helps me to carry,\nmy cross when heavy to bear.\nMy feet, entangled with briars,\nready to cast me down.\nMy Saviour whispers His promise,\n"I never will leave thee alone."\r\nHe died for me on the mountain,\nfor me they pierced His side.\nFor me He opened the fountain,\nthe crimson, cleansing tide.\nFor me He\'s waiting in glory,\nseated upon His throne.\nHe promised never to leave me,\nnever to leave me alone.', '\r\nNein, niemals allein! Nein, niemals allein!\nSo hat der Herr mir verheißen,\nniemals lässt Er mich allein!\nNein, niemals allein! Nein, niemals allein!\nSo hat der Herr mir verheißen,\nniemals lässt Er mich allein!\r\n\r\n\r\n'),
(9, '0807', 'I\'ve wandered far away from God, now I\'m coming home   (Coming home, coming home, nevermore to roam)', 'I\'ve wandered far away from God,\nnow I\'m coming home.\nThe paths of sin too long I\'ve trod,\nLord, I\'m coming home.\r\nComing home, coming home,\nnevermore to roam.\nOpen wide Thine arms of love,\nLord, I\'m coming home.\r\nI\'ve wasted many precious years,\nnow I\'m coming home.\nI now repent with bitter tears,\nLord, I\'m coming home.\r\nI\'ve tired of sin and straying, Lord,\nnow I\'m coming home.\nI\'ll trust Thy love, believe Thy word,\nLord, I\'m coming home.\r\nMy soul is sick, my heart is sore,\nnow I\'m coming home.\nMy strength renew, my hope restore,\nLord, I\'m coming home.\r\nMy only hope, my only plea,\nnow I\'m coming home.\nThat Jesus died, and died for me,\nLord, I\'m coming home.\r\nI need His cleansing blood, I know,\nnow I\'m coming home.\nOh, wash me whiter than the snow,\nLord, I\'m coming home.', NULL),
(9, '0808', 'Ich bete an die Macht der Liebe  -  O Power of Love, all else transcending', 'O power of love, all else transcending\nin Jesus present evermore,\nI worship Thee, in homage bending\nThy name to honor and adore.\nYea, let my soul, in deep devotion,\nbathe in love\'s mighty boundless ocean.\r\nThou art my rest, no earthly treasure\ncan satisfy my yearning heart,\nand naught can give to me the pleasure\nI find in Thee, my chosen part,\nThy love, so tender, so possessing,\nis joy to me, and every blessing.\r\n\r\n\r\nTo Thee my heart and life be given,\nThou art in truth my highest good.\nFor me Thy sacred side was riven,\nFor me was shed Thy precious blood.\nO Thou who art the world\'s salvation,\nbe Thine my love and adoration.\r\n\r\n\r\n', 'Ich bete an die Macht der Liebe,\ndie sich in Jesu offenbart;\nich geb\' mich hin dem freien Triebe,\nmit dem ich Wurm geliebet ward;\nich will, anstatt an mich zu denken,\nins Meer der Liebe mich versenken.\r\nWie bist Du mir so sehr gewogen,\nund wie verlangt Dein Herz nach mir!\nDurch Liebe sanft und stark gezogen,\nneigt sich mein Alles auch zu Dir.\nDu traute Liebe gutes Wesen,\nDu hast mich, ich hab Dich erlesen.\r\nIch fühl\'s, Du bist\'s, Dich muss ich haben,\nich fühl\'s, ich muss für Dich nur sein.\nNicht im Geschöpf, nicht in den Gaben,\nmein Ruh\'platz ist in Dir allein;\nhier ist die Ruh, hier ist Vergnügen,\nd\'rum folg\' ich Deinen sel\'gen Zügen.\r\nIch liebt und lebte recht im Zwange,\nals ich mir lebte ohne Dich;\nich wollte Dich nicht, ach, so lange,\ndoch liebtest Du und suchtest mich.\nO wenn doch dies der Sünder wüsste,\nsein Herz wohl bald Dich lieben müsste!\r\nFür Dich ist ewig Herz und Leben,\nErlöser, Du mein einzig Gut.\nDu hast für mich Dich hingegeben\nzum Heil durch Dein Erlösungsblut.\nO Heil des schweren, tiefen Falles,\nfür Dich ist ewig Herz und alles!\r\nO Jesus, dass Dein Name bliebe\nim Grunde, drück\' ihn tief hinein!\nMöcht\' Deine süße Jesusliebe\nin Herz und Sinn gepräget sein!\nIn Wort und Werk, in allem Wesen\nsei Jesus und sonst nichts zu lesen.\r\nIn diesem teuren Jesusnamen\ndas Vaterherze öffnet sich;\nein Brunn\' der Liebe, Fried\' und Freude\nquillt nun so nah, so mildiglich.\nMein Gott, wenn\'s doch der Sünder wüsste,\nsein Herz wohl bald Dich lieben müsste.\r\nLob sei dem hohen Jesusnamen,\nin dem der Liebe Quell entspringt,\nvon dem hier alle Bächlein kamen,\naus dem die sel\'ge Schar dort trinkt.\nWie beugen sie sich ohne Ende!\nWie falten sie die frohen Hände!'),
(9, '0809', 'Ich bete Dich an, allmächtger Gott  -  I worship You, almighty God   (Chorus)', 'I worship You,\nAlmighty God, there is none like You.\nI worship You, oh Prince of Peace,\nthat is what I want to do.\nI give You praise,\nfor You are my righteousness.\nI worship You, Almighty God,\nthere is none like You.', 'Ich bet\' Dich an,\nallmächt\'ger Gott, keiner ist wie Du.\nIch bet\' Dich an, o Friedefürst,\ndas ist, was ich möchte tun.\nIch preise Dich,\nDu bist mir Gerechtigkeit.\nIch bet\' Dich an, allmächt\'ger Gott,\nkeiner ist wie Du.'),
(9, '0810', 'Ich bete um ein neues Erleben, Herr mit Dir (Herr, in dieser Zeit wo die Hölle voll Wut) - Chrous', NULL, 'Herr, in dieser Zeit, wo die Hölle voll Wut,\nund die Sünde Fallen mir stellt.\nDa bewahre Du mich doch unter dem Blut,\nlass mich sein ein Licht in der Welt.\r\nIch bete um ein neues Erleben, Herr mit Dir;\ndurch Dich nur kann ein Sieger ich sein.\nUnd gib mir Deine Kraft, offenbare neu Dich mir.\nHüll\' mich in Deine Gnade ganz ein.\r\nHerr, Du sahst wie untreu auch ich manchmal war.\nTief beschämt vor Dir ich nun steh\'.\nHerr, ich bring\' mein Leben aufs Neue Dir dar;\nall mein Versagen ich seh\'.\r\nFühr\' zur ersten Liebe, oh Herr, mich zurück.\nGib mir ein zerbrochenes Herz.\nReiß von allem Irdischen los meinen Sinn.\nFühr\' mich auf dem Weg himmelwärts.'),
(9, '0811', 'Ich bin beglückt von Jesus, der mir Großes hat getan   (Chorus)', NULL, 'Ich bin beglückt von Jesus, der mir Großes hat getan.\nIch bin beglückt von Jesus, Er ist das Licht auf meiner Bahn.\nIch bin beglückt von Jesus, für jeden neuen Augenblick.\nIch bin beglückt von Jesus, ich möchte niemals mehr zurück!'),
(9, '0812', 'Ich bin da zu ehren ja, ehren Deinen Nam  -  I just came to glorify, glorify Your name   (Chorus)', 'I just came to glorify, glorify Your name.\nI just came to glorify, glorify Your name.\nYou are the sweetest name I know,\nI\'ll tell it, everywhere I go,\nI came to glorify, glorify Your name.', 'Ich bin da zu ehren, ja, ehren Deinen Nam\'.\nIch bin da zu ehren, ja, ehren Deinen Nam\'.\nDu bist der schönste Name mir,\nwo immer ich geh\', erzähl\' ich von Dir.\nIch komm\' zu ehren, ja, ehren Deinen Nam\'.'),
(9, '0813', 'Ich bin dein Gott, Ich geb dir Ruh; Ich kämpf für Dich; Ich liebe dich   (3 Chorusse)', '\r\n\r\n\r\nI am the God that healeth thee,\nI am the Lord your healer.\nI\'ve sent my Word and I healed your disease,\nI am the Lord your Healer.', 'Ich bin dein Gott, ich geb\' dir Ruh\',\nich bin der Herr, dein Friede.\nWirf doch auf mich deine Sorge, deine Last.\nIch bin der Herr, dein Friede.\r\nIch bin dein Gott, ich kämpf\' für dich.\nIch bin der Herr, dein Banner.\nBlick auf zu mir, und ich führe deinen Kampf.\nIch bin der Herr, dein Banner.\r\nIch bin dein Gott, ich liebe dich.\nIch bin der Herr, dein Löser.\nIch ging ans Kreuz, und ich kaufte dich zurück.\nIch bin der Herr, dein Löser.\r\nIch bin dein Gott, ich heile Dich,\nIch bin der Herr, dein Heiler.\nIch gab mein Wort, und ich tue, was ich sag.\nIch bin der Herr, dein Heiler.'),
(9, '0814', 'Ich bin Dein, o Herr, ich vernahm Dein Wort  -  I am Thine, o Lord, I have heard Thy Voice   (Zieh mich näher, näher, treuer Herr)', 'I am Thine, O Lord, I have heard Thy voice,\nAnd it told Thy love to me;\nBut I long to rise in the arms of faith,\nAnd be closer drawn to Thee.\r\nDraw me nearer, nearer blessed Lord,\nTo the cross where Thou hast died;\nDraw me nearer, nearer, nearer blessed Lord,\nTo Thy precious, bleeding side.\r\nConsecrate me now to Thy service, Lord,\nBy the pow’r of grace divine;\nLet my soul look up with a steadfast hope,\nAnd my will be lost in Thine.\r\nOh, the pure delight of a single hour\nThat before Thy throne I spend,\nWhen I kneel in prayer, and with Thee, my God\nI commune as friend with friend!\r\nThere are depths of love that I cannot know\ntill I cross the narrow sea.\nThere are heights of joy that I may not reach,\ntill I rest in peace of Thee.', 'Ich bin Dein, o Herr, ich vernahm Dein Wort,\nDeine Liebe wohnt in mir,\ndoch es fühlt mein Herz noch immerfort,\nes bedarf noch mehr von Dir.\r\nZieh mich näher, näher, treuer Herr,\nan das Kreuz, woran Du starbst!\nZieh mich näher, näher, treuer Herr,\nan Dein treues Jesuherz!\r\nIch bin Dein, o Herr, und mein Wille soll\nganz in Deinem Willen ruh\'n.\nHerr, in Deinem Dienst lass mich glaubensvoll\nnur nach Deinem Willen tun.\r\nO die heil\'ge Zeit einer einz\'gen Stund\',\nknieend an dem Thron verbracht!\nO, da mach ich meine Gedanken kund,\nwie der Freund dem Freund es macht.\r\nLiebestiefen gibt\'s, die kein Herz ermisst,\ndas nicht Jesus Dir recht nah;\nFreudenhöhen gibt\'s , die kein Aug\' erreicht,\ndas nicht, Herr Dein Antlitz sah.'),
(9, '0815', 'Ich bin durch die Welt gegangen', NULL, 'Ich bin durch die Welt gegangen,\nund die Welt ist schön und groß,\nund doch zieht ein heiß Verlangen\nmich weit von der Erde los.\r\nIch habe die Menschen gesehen,\nund die suchen spät und früh;\nsie schaffen, sie kommen und gehen,\nund ihr Leben ist Arbeit und Müh\'.\r\nSie suchen, was sie nicht finden\nin Liebe und Ehre und Glück,\nund sie kommen belastet mit Sünden\nund unbefriedigt zurück.\r\nEs ist eine Ruh\' vorhanden\nfür das arme, müde Herz,\nsagt es laut in allen Landen:\nHier ist gestillt aller Schmerz.\r\nEs ist eine Ruh\' gefunden\nfür alle, fern und nah:\nIn des Gotteslammes Wunden,\nam Kreuze auf Golgatha.'),
(9, '0816', 'Ich bin ein Pilger nach Zions Höhn, mein Leben, mein Alles ist Jesus   (Jesus, Jesus! Mein Leben, mein Alles ist Jesus)', NULL, 'Ich bin ein Pilger nach Zions Höh\'n,\nmein Leben, mein Alles ist Jesus!\nO sel\'ge Heimat, wie strahlst du schön!\nMein Leben, mein Alles ist Jesus!\r\nJesus, Jesus!\nMein Leben, mein Alles ist Jesus!\r\nO, welch ein Wandeln im Himmelslicht!\nMein Leben, mein Alles ist Jesus!\nDie Welt, sie ahnt und versteht es nicht,\nmein Leben, mein Alles ist Jesus!\r\nOb Sturm rings tobet, ob Wolken dräun,\nmein Leben, mein Alles ist Jesus!\nBei Ihm wohnt Friede und Sonnenschein;\nmein Leben, mein Alles ist Jesus!\r\nEinst sing ich droben im sel\'gen Chor:\nMein Leben, mein Alles ist Jesus!\nIhr goldnen Gassen, ihr Perlentor:\nMein Leben, mein Alles ist Jesus!'),
(9, '0817', 'Ich bin eine neue Schöpfung', NULL, 'Ich bin eine neue Schöpfung, neue Schöpfung,\ndas Alte ist vergangen, alles wurde neu.\nIch bin eine neue Schöpfung, neue Schöpfung,\ndas Alte ist vergangen, das Alte ist vergangen,\nalles wurde neu.\r\nOh Jesus Christus, Heiland,\nmein Erlöser, Du hast Dein Blut\ngegeben, einst auf Golgatha.\nIch preise Deine Gnade,\nDeine Liebe, und bitt\' Dich, Herr,\nmein Heiland, bleibend in mir wohn\'.'),
(9, '0818', 'Ich bin entschieden vorwärts zu gehen  -  I am resolved no longer to linger   (Ich will zu Ihm eilen, eilen so ganz befreit)', 'I am resolved no longer to linger,\ncharmed by the world\'s delight.\nThings that are higher, things that are nobler,\nthese have allured my sight.\r\nI will hasten to Him,\nhasten so glad and free.\nJesus, greatest, highest,\nI will come to Thee.\r\nI am resolved to go to the Saviour,\nleaving my sin and strife.\nHe is the true one, He is the just one,\nHe has the words of life.\r\nI am resolvd to follow the Saviour,\nfaithful and true each day.\nHeed what He sayeth, do what he willeth,\nhe is the living way.\r\nI am resolved to enter the kingdom,\nleaving teh paths of sin.\nFriends may oppose me, foes may beset me,\nstill will I enter in.\r\nI am resolved, and who will go with me?\nCome, friends, without delay.\ntaught by the Bible, led by the Spirit,\nwe\'ll walk the heavenly way.', 'Ich bin entschieden vorwärts zu gehen,\nlasse die Welt zurück.\nDinge die höher, Dinge die schöner\nhabe ich jetzt im Blick.\r\nIch will zu Ihm eilen,\neilen so ganz befreit,\nwill nicht mehr verweilen\nbei Dingen dieser Zeit.\r\nIch will jetzt gehen zu meinem Heiland,\nwerfe die Sünde fort.\nEr, der mein Alles, Er, der mein Leben,\nEr hat das Lebenswort.\r\nIch bin entschieden, Jesus zu folgen,\nimmer wahrhaft und treu.,\nwill ich auf Ihn hören, tun seinen Willen,\nwas auch immer sei.\r\nIch will ganz sicher das Ziel erreiche,\ndas soll mein Streben sein!\nMan mag mich hassen und mich verlassen,\nich dränge dort hinein.\r\nIch will jetzt gehen, wer will es wagen,\nFreunde, so kommt doch mit.\nMöge sein Geist uns reinigen, füllen,\nführen bei jedem Schritt.'),
(9, '0819', 'Ich bin entschieden, zu folgen Jesus  -  I have decided, to follow Jesus', 'I have decided, to follow Jesus,\nI have decided, to follow Jesus,\nI have decided, to follow Jesus,\nNo turning back, no turning back!\r\nThe world behind me, the Cross before me,\nthe world behind me, the Cross before me,\nthe world behind me, the Cross before me.\nNo turning back, no turning back!\r\nThough none go with me, I still will follow,\nthough none go with me, I still will follow,\nthough none go with me, I still will follow,\nno turning back, no turning back.', 'Ich bin entschieden, zu folgen Jesus,\nich bin entschieden, zu folgen Jesus,\nich bin entschieden, zu folgen Jesus.\nNiemals zurück, niemals zurück!\r\nDie Welt liegt hinter mir, das Kreuz steht vor mir,\ndie Welt liegt hinter mir, das Kreuz steht vor mir,\ndie Welt liegt hinter mir, das Kreuz steht vor mir.\nNiemals zurück, niemals zurück!\r\nWenn niemand mit mir geht, doch ich will folgen,\nwenn niemand mit mir geht, doch ich will folgen,\nwenn niemand mit mir geht, doch ich will folgen.\nNiemals zurück, niemals zurück!'),
(9, '0820', 'Ich bin erlöst durch des Lammes Blut  -  I\'ve been redeemed, by the Blood of the Lamb', 'I\'ve been redeemed, by the blood of the Lamb,\nI\'ve been redeemed, by the blood of the Lamb,\nI\'ve been redeemed, by the blood of the Lamb,\nsaved and sanctified I am!\nAll of my sins are under the blood,\nI\'ve been redeemed.\r\nThe devil\'s  mad and I\'m so glad,\nthe devil\'s  mad and I\'m so glad,\nthe devil\'s  mad and I\'m so glad,\nhe lost a sinner that he thought he had.\nAll of my sins are under the blood, I\'ve been redeemed.\r\nYou can talk about me all that you please,\nyou can talk about me all that you please,\nyou can talk about me all that you please,\nI talk about you down on my knees.\nAll of my sins are under the blood, I\'ve been redeemed.\r\nAnd that\'s not all there\'s more besides,\nand that\'s not all there\'s more besides,\nand that\'s not all there\'s more besides,\nI\'ve been to the river and I have been baptized.\nAll of my sins are under the blood, I\'ve been redeemed.', 'Ich bin erlöst, durch des Lammes Blut,\nich bin erlöst, durch des Lammes Blut,\nich bin erlöst, durch des Lammes Blut,\nlos- und freigekauft bin ich!\nAlle meine Sünden sind unter dem Blut, ich bin erlöst.\r\nD\'rum ist Satan bös\',  glücklich bin ich,\nd\'rum ist Satan bös\',  glücklich bin ich,\nd\'rum ist Satan bös\',  glücklich bin ich,\naus seiner Hand verlor er mich.\nAlle meine Sünden sind unter dem Blut, ich bin erlöst.\r\nRed\' nur über mich soviel Du willst,\nred\' nur über mich soviel Du willst,\nred\' nur über mich soviel Du willst,\nich red\' über Dich auf meinen Knien.\nAlle meine Sünden sind unter dem Blut, ich bin erlöst.\r\nDa gibt\'s noch mehr, das reicht noch nicht,\nda gibt\'s noch mehr, das reicht noch nicht,\nda gibt\'s noch mehr, das reicht noch nicht,\nich war am Fluss, getauft bin ich.\nAlle meine Sünden sind unter dem Blut, ich bin erlöst.'),
(9, '0821', 'Ich bin erlöst! Wort voll Frieden und Macht   (Ich bin erlöst! Erlöst durch den Herrn)', NULL, 'Ich bin erlöst! Wort voll Frieden und Macht!\nVöllig erlöst! Jesu Blut hat\'s vollbracht.\nNichts, nichts mehr bleibt zur Erlösung zu tun,\nals glauben, nehmen und danken und ruh\'n.\r\nIch bin erlöst! Erlöst durch den Herrn!\nVöllig erlöst! Völlig erlöst!\nIch bin erlöst! Anbetung dem Lamm,\ndas mich erlöst am Kreuz!\r\nIch bin erlöst; denn bezahlt hat die Schuld\nblutend das Lamm; o der göttlichen Huld!\nHat sie vergeben, versenkt in das Meer,\nSein Kind nennt Gott mich, was will ich noch mehr?\r\nIch bin erlöst, vom Gesetze befreit,\nmit Ihm gekreuzigt, Gott völlig geweiht.\nMein Leib, mein Leben, mein Alles ist Sein,\nund Halleluja! Sein Leben ist mein!\r\nIch bin erlöst, meine Seele lobpreist;\nin alle Wahrheit mich leitet Sein Geist,\nbis Christi Reichtum mir gänzlich enthüllt\nund überströmend Sein Geist mich erfüllt.'),
(9, '0822', 'Ich bin erlöst, es darf kein Feind mehr nahn', NULL, 'Ich bin erlöst, es darf kein Feind mehr nah\'n,\ner ist besiegt, gericht\'.\nIch bin erlöst, gen Himmel geht die Bahn,\nmich hält die Erde nicht.\nIch bin an Christi Kreuz geschlagen,\nEr hat die Schuld hinweg getragen,\nich bin erlöst, ich bin erlöst!\r\nIch bin erlöst, es ist für immer hin,\nwas einst mir Adam gab.\nEs starb am Kreuz, was ich gewesen bin,\nund sank in Jesu Grab.\nAls Christus stieg aus Todesbanden,\nda bin ich auch mit auferstanden.\nIch bin erlöst, ich bin erlöst!\r\n"Ich bin erlöst!" So ruft des Lammes Braut\nund jubelt himmelan.\nIhr Engel kommt, o staunet nur und schaut,\nwas Jesu Blut getan!\nVor Anbeginn der Welt erlesen,\nwerd\' ich verwandelt in Sein Wesen,\nin Jesu Bild, in Jesu Bild.\r\nIch bin erlöst! Und bin mit Ihm vereint,\nmit Ihm auf Gottes Thron.\nDes Himmels Glanz auf meinem Antlitz scheint,\nDein Bild, o Gottessohn.\nBald wird die ganze Welt es sehen,\nsieht mich auf Deinem Throne stehen,\nerlöst für Dich, erlöst für Dich!'),
(9, '0823', 'Ich bin froh ich gehöre Jesus  -  I am glad I belong to Jesus   (Preis dem Herrn, Halleluja)', 'I am glad I belong to Jesus,\nI am glad I belong to Jesus,\nI am glad I belong to Jesus,\nHallelujah Praise the Lord!\r\nPraise the Lord, Hallelujah,\nPraise the Lord, Hallelujah,\nPraise the Lord, Hallelujah,\nPraise the Lord, Hallelujah,\nPraise the Lord, Hallelujah,\nPraise the Lord, Hallelujah,\nHallelujah Prais the Lord.\r\nWhat the world needs today is Jesus,\nwhat the world needs today is Jesus,\nwhat the world needs today is Jesus,\nHe alone can set it free.', 'Ich bin froh, ich gehöre Jesus,\nich bin froh, ich gehöre Jesus,\nich bin froh, ich gehöre Jesus,\nHalleluja, Preis dem Herrn!\r\nPreis dem Herrn, Halleluja,\nPreis dem Herrn, Halleluja,\nPreis dem Herrn, Halleluja,\nPreis dem Herrn, Halleluja,\nPreis dem Herrn, Halleluja,\nPreis dem Herrn, Halleluja,\nHalleluja, Preis dem Herrn!\r\nWas die Welt heute braucht ist Jesus,\nwas die Welt heute braucht ist Jesus,\nwas die Welt heute braucht ist Jesus,\nEr allein kann sie befrei\'n.'),
(9, '0824', 'Ich bin gekommenum den Herrn anzubeten   (Chorus)', NULL, 'Ich bin gekommen, um den Herrn anzubeten,\nschaue auf Ihn und Seine Gnad\',\nich bin gekommen, um den Herrn zu erheben,\nweil Er nur Gutes an mir tat.'),
(9, '0825', 'Ich bin gewiss, nichts kann mich scheiden von meinem Heiland Jesus Christ', NULL, 'Ich bin gewiss, nichts kann mich scheiden\nvon meinem Heiland Jesus Christ;\nnicht Angst, nicht Trübsal oder Leiden,\n|: weil Er die ew\'ge Liebe ist. :|\r\nIch bin gewiss, Er ist gestorben,\ndamit ich selig werden kann,\nSein Blut hat Freiheit mir erworben\n|: von Sündendienst und Sündenbann! :|\r\nIch bin gewiss, Er herrscht dort droben,\nund leitet mich durch Seinen Geist,\nEr hat mich an Sein Herz gehoben\n|: und wünscht, dass Ihn mein Wandel preist. :|\r\nIch bin gewiss, um Jesu willen\nund nicht, weil je ich\'s selbst verdien\',\nwird alles selig sich erfüllen,\n|:  warum auf Erden Er erschien. :|\r\nIch bin gewiss! O sel\'ges Wissen,\nwie beugst Du mich so tief hinab!\nUnd doch könnt ich Dich niemals missen,\n|: weil ich in Dir mein Leben hab\'. :|'),
(9, '0826', 'Ich bin glücklich in dem Dienste meines Herrn  -  I am happy in the Service of the King   (In dem Dienste meines Herrn, meine Gaben weih ich gern)', 'I am happy in the service of the King,\nI am happy, oh, so happy.\nI have peace and joy that nothing else can bring,\nin the service of the King.\r\nIn the service of the King\nevery talent I will bring.\nI have peace and joy and blessing\nin the service of the King.\r\nI am happy in the service of the King,\nI am happy, oh, so happy.\nThro\' the sunshine and the shadow I can sing,\nin the service of the King.\r\nI am happy in the service of the King,\nI am happy, oh, so happy.\nAll that I possess to Him I gladly bring,\nin the service of the King.\r\nI am happy in the service of the King,\nI am happy, oh, so happy.\nTo His guiding hand forever I will cling,\nin the service of the King.', 'Ich bin glücklich in dem Dienste meines Herrn,\nich bin glücklich, o so glücklich.\nIch hab Fried\' und Freude, darum steh ich gern\nin dem Dienste meines Herrn.\r\nIn dem Dienste meines Herrn\nmeine Gaben weih ich gern.\nIch habe Friede, Freud und Segen\nin dem Dienste meines Herrn.\r\nIch bin glücklich in dem Dienste meines Herrn,\nich bin glücklich, o so glücklich.\nDenn in Trübsal leuchtet mir ein Hoffnungsstern\nIn dem Dienste meines Herrn.\r\nIch bin glücklich in dem Dienste meines Herrn,\nich bin glücklich, o so glücklich.\nAlles, was ich habe, bringe ich Ihm gern\nin dem Dienste meines Herrn.\r\nIch bin glücklich i n dem Dienste meines Herrn,\nich bin glücklich, o so glücklich.\nSeine führ\'nde Hand mag ich gern,\nin dem Dienste meines Herrn.'),
(9, '0827', 'Ich bin im Land voll Korn und Wein  -  I\'ve reached the Land of Corn and Wine   (O Himmelsland, o Himmelsland)', 'I\'ve reached the land of corn and wine\nand all its riches freely mine.\nHere shines undimmed one blissful day,\nfor all my night has passed away.\r\nOh Beulah Land, sweet Beulah Land.\nAs on Thy highest mount I stand.\nI look away across the sea,\nwhere mansions are prepared for me.\nAnd view the shining glory-shore,\nmy heaven, my home forevermore!\r\nMy Saviour comes and walks with me,\nand sweet communion here have we.\nHe gently leads me by the hand,\nfor this is heaven\'s borderland.\r\nA sweet perfume upon the breeze,\nis borne from ever vernal trees.\nAnd flow\'rs, that never fading grow,\nwhere streams of life forever flow.\r\nThe zephyrs seem to float to me,\nsweet sounds of heaven\'s melody.\nAs angels with the white-robed throng\njoin in the sweet Redemption song.', 'Ich bin im Land voll Korn und Wein,\nund all sein Reichtum er ist mein.\nHier strahlt ein ungetrübter Tag\nhier ist vergangen meine Nacht.\r\nO Himmelsland, o Himmelsland,\ndas heute ich im Glauben fand.\nich steh und schaue über\'s Meer,\nwo alles macht bereit der Herr,\nund sehe: Bald ist schon bereit\ndas Himmelsheim in Ewigkeit.\r\nMein Heiland kommt und geht mit mir,\nja, welch\' Gemeinschaft hab\' ich hier,\nsanft leitet Er mich bei der Hand,\no herrlich ist dies\' Himmelsland.\r\nWelch\' Wohlgeruch der Wind hier trägt,\nder durch den Baum des Lebens weht.\nUnd Blumen steh\'n an Ufern schön\ndes Wassers , das wird nie vergeh\'n.\r\nUnd Engel kommen mir jetzt nah,\nvom Land, das ich im Geiste sah,\nso herrlich singen sie ein Lied,\nvon jener Stadt, die nie vergeht.'),
(9, '0828', 'Ich bin jung und ich bin frei von der Sündensklaverei   (Ja, jung zu sein ist schön doch, gerettet sein ist schöner noch)', NULL, 'Ich bin jung und ich bin frei von der Sündensklaverei,\nfreudig folg\' ich dem Herrn Jesus Christ.\nUnd ich wandre mit der Schar,\ndie zur Heimat zieht fürwahr;\ndort wo ew\'ge Herrlichkeit ist.\r\nJa, jung zu sein ist schön doch,\ngerettet sein ist schöner noch.\nGerettet sein und jung zu gleich\nnichts macht so glücklich und so reich.\r\nIch bin jung und froh bereit,\nGott zu dienen allezeit\nmit den Gaben, die Er mir verlieh\'n.\nWill gewinnen viele noch,\nbin ein Streiter Christi doch;\ndarf im Kampf nimmer weichen und fliehn.\r\nIch bin jung und, ja ich weiß,\ndass der Kampf oft schwer und heiß\nund für Jesus zu Leiden es gilt.\nAber Er wird mit mir geh\'n\nund mir treu zur Seite steh\'n,\ndenn Sein Wort Er gewisslich erfüllt.\r\nIch bin jung, das bist du auch,\nund mit Sehnsucht lauschest du,\nmöchtest gern glücklich sein so wie ich.\nKomm auch du zum Heiland heut,\nEr von Sünden dich befreit.\nGlaub es doch, Jesus liebet auch dich.'),
(9, '0829', 'Ich bin schwach doch Du bist stark  -  I am weak but Thou art Strong   (Immer näher, Herr, zu Dir)', 'I am weak but Thou art strong,\nJesus keep me from all wrong;\nI\'ll be satisfied as long,\nas I walk let me walk close to Thee.\r\nJust a closer walk with Thee,\ngrant it, Jesus, is my plea;\nDaily walking close to Thee,\nlet it be, dear Lord, let it be.\r\nThru this world of toil and snares,\nif I falter, Lord, who cares?\nWho with me my burden shares?\nNone but Thee, dear Lord, none but Thee.\r\nWhen my feeble life is o\'er,\ntime for me will be no more;\nGuide me gently, safely o\'er,\nto Thy kingdom shore, to Thy shore.', 'Ich bin schwach, doch Du bist stark,\nJesus halt\' mich in der Gnad\',\ndas ich geh\' auf Deinem Pfad\',\ndas ich geh\' treuer Herr, nur mit Dir.\r\nImmer näher, Herr, zu Dir,\nist mein Flehen stets allhier,\ntäglich wandeln nur mit Dir,\ndas gewähr\', oh Herr, bitten wir.\r\nIn der Welt voll Sorg\' und Tod,\nwer ist da der hilft aus Not?\nWer gibt Fried\' und neuen Mut?\nDu allein, Jesus, Herr, Du allein.\r\nWenn mein Leben hier vorbei,\nbin ganz sicher das Er treu,\nführt Er mich zum gol\'dnen Strand,\nPreis sei Ihm, ins verheißene Land.'),
(9, '0830', 'Ich bin so froh für den Trost den Gott gibt  -  I am so glad that our Father in Heav\'n   (Ich bin so froh, mein Jesus liebt mich)', 'I am so glad that our Father in heav\'n\ntells of His love in the Book He has giv\'n.\nWonderful things in the Bible I see,\nthis is the dearest, that Jesus loves me.\r\nI am so glad that Jesus loves me,\nJesus loves me, Jesus loves me.\nI am so glad that Jesus loves me,\nJesus loves even me.\r\nThough I forget Him and wander away,\nstill He doth love me wherever I stray.\nBack to His dear loving arms would I flee,\nwhen I remember that Jesus loves me.\r\nO if there\'s only one song I can sing,\nwhen in His beauty I see the great King.\nThis shall my song in eternity be:\n"O what a wonder, that Jesus loves me!"\r\nJesus loves me, and I know I love Him,\nlove brought Him down my poor soul to redeem.\nYes, it was love made Him die on the tree,\noh, I am certain that Jesus loves me!\r\nIf one should ask of me, how can I tell?\nGlory to Jesus, I know very well!\nGod’s Holy Spirit with mine doth agree,\nconstantly witnessing Jesus loves me.\r\nIn this assurance I find sweetest rest,\ntrusting in Jesus, I know I am blessed.\nSatan, dismayed, from my soul now doth flee,\nwhen I just tell Him that Jesus loves me.', 'Ich bin so froh für den Trost, den Gott gibt,\ndass Er unendlich und herzlich uns liebt.\nManch Wunderding in der Bibel find\' ich!\nDoch keins wie dieses: Mein Jesus liebt mich!\r\nIch bin so froh, mein Jesus liebt mich!\nJesus liebt mich! Jesus liebt mich!\nIch bin so froh, mein Jesus liebt mich!\nJesus liebt mich, Ja, mich!\r\nHab ich mich von Ihm, dem Treuen, gewand\'t,\nmich in manch Torheit und Elend verrannt,\neilt mein Herz, dass es sich in Ihm verkriech\',\nwenn ich darf hören: Mein Jesus liebt mich!\r\nDies ist mein einer und liebster Gesang,\ntausendfach halle und schalle sein Klang,\nbis jedes Herz davon jubelt in sich;\nO welch ein Wunder: Mein Jesus liebt mich!\r\nJesus liebt mich und ich weiß, ich lieb Ihn,\nEr stieg vom Throne, mich zu sich zu zieh\'n,\nmich zu erlösen Er sterbend verblich!\nD\'rum ist\'s gewisslich: Mein Jesus liebt mich!\r\nMöcht\' jemand fragen, woher ich dies weiß,\nrühm\' ich\'s mit Freuden, dem Heiland zum Preis.\nSanft sagt es in mir so wunderbarlich\nSein Geist beständig: Mein Heiland liebt mich!\r\nMit diesem Zeugnis strömt Segen mir zu.\nJesu vertrauen ist himmlische Ruh\',\nSatan muss weichen mit tödlichem Stich,\nwenn ich ihm sage: Mein Jesus liebt mich!'),
(9, '0831', 'Ich bin so froh Herr, dass ich bin Dein  -  So glad I\'m yours Lord   (2 Chorusse)', 'So glad I\'m Yours Lord, so glad I\'m Yours,\nso glad Your mercy, has followed me,\nso glad You found me, and set me free,\nso glad I\'m Yours Lord, so glad I\'m Yours.\r\nSo glad I\'m Yours Lord, so glad I\'m Yours,\nso glad Your mercy, has followed me,\nYou make me free from sin and pure,\nso glad I\'m Yours Lord, so glad I\'m Yours.', 'Ich bin so froh Herr, dass ich bin Dein,\nich darf aus Gnaden, Dein Eigen sein,\nDu gibst die Fülle des Segens mir,\noh, Herr, mein Heiland, ich danke Dir.\r\nIch bin so froh, Herr, dass ich bin Dein,\nich darf aus Gnaden Dein Eigen sein.\nDu machst von Sünde mich frei und rein,\nich bin so froh, Herr, dass ich bin Dein.'),
(9, '0832', 'Ich bin so froh, dass der Vater im Licht  -  I am so glad that our Father in Heav\'n   (Ich bin so froh, dass Jesus mich liebt)   [Siegesklänge]', 'I am so glad that our Father in heav\'n\ntells of His love in the Book He has giv\'n.\nWonderful things in the Bible I see -\nthis is the dearest, that Jesus loves me.\r\nI am so glad that Jesus loves me,\nJesus loves me, Jesus loves me.\nI am so glad that Jesus loves me,\nJesus loves even me.\r\nThough I forget Him and wander away,\nstill He doth love me wherever I stray.\nBack to His dear loving arms would I flee\nwhen I remember that Jesus loves me.\r\nO if there\'s only one song I can sing\nwhen in His beauty I see the great King.\nThis shall my song in eternity be:\n"O what a wonder, that Jesus loves me!"\r\nJesus loves me, and I know I love Him,\nlove brought Him down My poor soul to redeem.\nYes, it was love made Him die on the tree.\nOh, I am certain that Jesus loves me!\r\nIf one should ask of me, how can I tell?\nGlory to Jesus, I know very well!\nGod\'s Holy Spirit with mine doth agree,\nconstantly witnessing Jesus loves me.\r\nIn this assurance I find sweetest rest,\ntrusting in Jesus, I know I am blessed.\nSatan, dismayed, from my soul now doth flee,\nwhen I just tell him that Jesus loves me.', 'Ich bin so froh, dass der Vater im Licht\nzu uns im Worte so liebevoll spricht!\nManch edlen Schatz in der Bibel es gibt;\ndies ist der größte, dass Jesus mich liebt.\r\nIch bin so froh, dass Jesus mich liebt,\nJesus mich liebt, Jesus mich liebt.\nIch bin so froh, dass Jesus mich liebt,\nJesus mich ewig liebt.\r\nOb ich auch irrend mich von ihm gewandt,\nzog er mich wieder mit liebender Hand.\nStets eil\' ich hin zu ihm, den ich betrübt,\nwenn ich dran denke, dass Jesus mich liebt.\r\nWerd\' ich den Heiland im Himmel einst seh\'n,\nvor seinem Throne in Herrlichkeit steh\'n,\nsing ich das Lied, das schon hier ich geübt,\nvon seiner Gnade, dass Jesus mich liebt.\r\n\r\n\r\n'),
(9, '0833', 'Ich bin zufrieden, mit dem was ich habe   (Mein Heim ist droben, gleich hinter den Sternen)', NULL, 'Ich bin zufrieden, mit dem was ich habe,\nnicht Gold und Silber sind mir anvertraut.\nIm Himmel droben hab ich eine Wohnung,\nvon Silbermauern und Gold erbaut.\r\nMein Heim ist droben, gleich hinter den Sternen,\nim Land des Lebens wir altern nicht mehr.\nDort sind nicht Tränen, vollkommen ist alles,\nin diesem Lande weint niemand mehr.\r\nIn Not geübet, in schwerer Versuchung,\nfind ich als Ruh\'ort, gleich Jakob den Stein,\nmein fester Wohnort ist niemals hier unten,\nim Land der Sel\'gen bin ich daheim.\r\nIch glaub nicht ängstlich von Unruh\' gefangen,\nich bin nicht arm noch von Missmut gebeugt.\nIch bin ein Pilger zur himmlischen Heimat,\ndort winkt die Krone und ew\'ge Freud\'!'),
(9, '0834', 'Ich blicke voll Beugung und Staunen  -  I stand all bewildered with Wonder   (Sein Kreuz bedeckt meine Schuld)', 'I stand all bewildered with wonder,\nand gaze on the ocean of love.\nAnd over its waves to my spirit,\ncomes peace like a heavenly dove.\r\nThe cross now covers my sins,\nthe past is under the blood.\nI’m trusting in Jesus for all,\nmy will is the will of my God.\r\nI struggled and wrestled to win it,\nthe blessing that setteth me free.\nBut, when I had ceased from my struggling,\nHis peace Jesus gave unto me.\r\nHe laid his hand on me and healed me,\nand bade me be every whit whole.\nI touched but the hem of his garment,\nand glory came thrilling my soul.\r\nThe Prince of my peace is now passing,\nthe light of his face is on me.\nBut listen, beloved, he speaketh:\nMy peace I will give unto thee.', 'Ich blicke voll Beugung und Staunen,\nhinein in das Meer Seiner Gnad\',\nund lausche der Botschaft des Friedens,\ndie Er mir verkündiget hat.\r\nSein Kreuz bedeckt meine Schuld,\nSein Blut macht hell mich und rein.\nMein Wille gehört meinem Gott,\nich traue auf Jesum allein.\r\nWie lang hab ich müh\'voll gerungen,\ngeseufzt unter Sünde und Schmerz,\ndoch als ich mich Ihm überlassen,\nda strömte Sein Fried\' in mein Herz.\r\nSanft hat Seine Hand mich berühret,\nEr sprach: "O mein Kind, du bist heil!"\nIch fasste den Saum Seines Kleides,\nda ward Seine Kraft mir zuteil.\r\nDer Fürst meines Friedens ist nahe,\nSein Antlitz ruht strahlend auf mir;\no horcht Seiner Stimme, sie rufet:\n"Den Frieden verleihe Ich dir!"'),
(9, '0835', 'Ich brauch Dich allezeit, Du gnadenreicher Herr  -  I need Thee every Hour, most gracious Lord   (Ich brauch Dich, o ich brauch Dich)', 'I need Thee every hour,\nmost gracious Lord.\nNo tender voice like Thine\ncan peace afford.\r\nI need Thee, oh, I need Thee,\nevery hour I need Thee!\nOh, bless me now, my Saviour,\nI come to Thee!\r\n\r\nI need Thee every hour,\nin joy or pain.\nCome quickly and abide,\nor life is vain.\r\nI need Thee every hour,\nmost holy one.\nOh, make me Thine indeed,\nThou blessed Son.\r\n', 'Ich brauch Dich allezeit,\nDu gnadenreicher Herr.\nDein Name ist mein Hort,\nDein Blut mein Freudenmeer.\r\nIch brauch Dich,\no ich brauch Dich,\nJesus, ja, ich brauch Dich,\nich muss Dich immer haben,\nHerr, segne mich!\r\nIch brauch Dich allezeit,\no Jesus, steh mir bei,\ndass ich bis in den Tod\nDir bleibe stets getreu.\r\nIch brauch Dich allezeit,\nin Freude wie in Leid;\nDu bist mein Sonn\' und Schild\njetzt und in Ewigkeit.\r\nIch brauch Dich allezeit,\nführ\' mich nur, wie Du willst;\nich harre auf Dein Wort,\nbis Du es ganz erfüllst.\r\nIch brauch Dich allezeit,\nHerr Jesus, Gottes Sohn;\nmit Dir ererb ich einst\ndes ew\'gen Lebens Kron\'.'),
(9, '0836', 'Ich brauch dich mehr, mehr als je zuvor  -  I need You more, more than yesterday   (Chorus)', 'I need You more, more than yesterday,\nI need You more, more than words can say.\nI need You more, than ever before,\nI need You Lord, I need You Lord.\r\nMore than the air I breathe\nMore than the song I sing\nMore than the next heartbeat, more than anything\nLord as time goes by, I\'ll be by Your side\n\'cause I never wanna go back to my old life', 'Ich brauch Dich mehr, mehr als je zuvor,\nich brauch Dich Herr, unbeschreiblich mehr.\nIch brauch Dich mehr, als jemals zuvor,\nich brauch Dich Herr, ich brauch Dich Herr.\r\nMehr als zu atmen Herr\nmehr als mein schönstes Lied\nmehr als dass mein Herz schlägt, mehr als alles Herr\nMein ganzes Leben lang\nmöchte ich bei Dir sein\nin mein altes Leben kehre ich niemals zurück'),
(9, '0837', 'Ich brauche Dich, geliebter Herr   (Ich brauch Dich, ja ich brauch Dich)', NULL, 'Ich brauche Dich, geliebter Herr,\nich brauche Deine heil\'ge Kraft,\nich brauch sie täglich mehr und mehr,\nweil sie ja alles in mir schafft.\r\nIch brauch Dich, ja ich brauch Dich,\nich brauch Dich täglich mehr und mehr.\nIn dunkler Nacht, im Sonnenschein\nsollst Du mein Freund und Führer sein.\r\nIch brauch Dich, wenn der Tag erwacht,\nund wenn sich spät die Sonne neigt,\nich brauch Dich in der dunklen Nacht,\nzu wandeln, wie Dein Geist mir\'s zeigt.\r\nIch brauche Deiner Liebe Macht,\nich brauche Deiner Gnade Halt,\nich brauch\'s, dass mir Dein Antlitz lacht,\nund dass mir Deine Stimme schallt.\r\nIch brauch Dich, wo ich geh und steh,\nich brauche Deines Kreuzes Hort,\nich brauch Dich in der Erde Weh\nund in der Herrlichkeit einst dort.'),
(9, '0838', 'Ich dachte an den Herrn und etwas zog mich an  -  At night I lay in Bed, and I begin to cry   (Ich fühle Ihn, wie Er mich zieht)   [Linn]', 'At night I lay in bed, and I begin to cry,\nand my mind just fails to know exactly why.\nI can\'t explain with tongue or pen, the spirit`s groanings deep within\nit must be God, here in my soul, cause I feel the pull.\r\nI feel the pull, I hear the call,\nand I know, His Spirit\'s moving me to give my all.\nHe speaks to me, and I agree,\nLord, please come and take control I feel the pull.\r\nI went to hear the Word and with each line and phrase,\nHe was drawing me to give a higher praise.\nThere\'s a deep call to the deep like a great magnet pulling me\nI know for sure that I\'ll reach the goal, cause I feel the pull.', 'Ich dachte an den Herrn und etwas zog mich an,\netwas war es, tiefer als dass ich\'s verstand.\nEtwas in mir zieht mich zu Ihm, oh wie ich mich nach Jesus seh\'n,\nGott muss es sein, Er ganz allein, denn ich fühl Ihn zieh\'n.\r\nIch fühle Ihn, wie Er mich zieht\nund Sein Geist bewegt mich, dass mein Herz Ihm alles gibt.\nEr spricht zu mir, dass Er mich liebt,\nund ich sage "Ja" zu Jesus, der mich liebt.\r\nMit jedem Wort, das Er in Liebe zu mir spricht,\nseh\' ich meinen Herrn in einem größ\'ren Licht,\nund wenn in mir Lobpreis beginnt, Worte, die unaussprechlich sind,\nweiß ich: Schon bald werd ich Ihn seh\'n, denn ich fühl\' Ihn zieh\'n!'),
(9, '0839', 'Ich danke meinem Gott von ganzem Herzen   (Psalm 9, 2-3 + 12)', NULL, 'Ich danke meinem Gott von ganzem Herzen!\nVon all Seinen Wundern will ich laut erzählen\nund loben Seinen Namen.\nIch danke meinem Gott von ganzem Herzen.\nIch freue mich und bin fröhlich, Herr, in Dir. Halleluja!\nIch freue mich und bin fröhlich, Herr, in Dir. Halleluja!\r\nKommt, stimmet ein ins Lob von ganzem Herzen!\nVerkündigt unter den Völkern Sein Tun\nund lobsinget Seinem Namen.\nKommt, stimmet ein ins Lob von ganzem Herzen,\ndenn unser Herr ist ein ewiger Gott. Halleluja!\nDenn unser Herr ist ein ewiger Gott. Halleluja!'),
(9, '0840', 'Ich darf im Glauben kommen und fassen Jesu Hand', NULL, 'Ich darf im Glauben kommen und fassen Jesu Hand,\ndarf Gottes Kind mich nennen, o sel\'ger Gnadenstand!\nDer Herr trug meine Sünde, das Opfer ist vollbracht!\nLob, Ehre, Preis, Anbetung dem Lamme, das geschlacht\'!\r\nNun muss ich auch nicht zagen und gar nicht seh\'n auf mich,\nder Schuldbrief ist zerrissen, am Kreuze bleibe ich.\nDa ist allein die Stätte, wo ich, befreit von Sünd\',\nnun einen völl\'gen Frieden im Blut des Lammes find.\r\nErfüll\' mich ganz, Herr Jesus, mit Deinem Sinn und Geist.\nDu gibst die Kraft von oben, weil es Dein Wort verheißt!\nIm Glauben will ich fassen und nehmen, was Du gibst,\nlaut preisen Deine Gnade und lieben, wie Du bist!'),
(9, '0841', 'Ich darf nun durch Gottes Gnade fröhlich meine Straße ziehn  -  I am going to a City where the Streets with Gold are laid   (Hier gibts Blumen zur Saison nur)', 'I am going to a city\nwhere the streets with gold are laid.\nWhere the tree of life is blooming\nand the roses never fade.\r\nHere they bloom but for a season,\nsoon their beauty is decayed.\nI am going to a city\nwhere the roses never fade.\r\nIn this world we have our troubles.\nSatan snares we must evade.\nWe\'ll be free from all temptations.\nWhere the roses never fade.\r\nLoved ones gone to be with Jesus\nin their robes of white arrayed.\nNow are waiting for my coming\nwhere the roses never fade.\r\n\r\n', 'Ich darf nun durch Gottes Gnade\nfröhlich meine Straße zieh\'n.\nJa ich pilg\'re zu dem Lande,\nwo die Rosen nie verblüh\'n.\r\nHier gibt\'s Blumen zur Saison nur,\nschnell welkt ihre Schönheit hin.\nDoch ich pilg\'re zu dem Lande,\nwo die Rosen nie verblüh\'n.\r\nDunkelheit und Schatten schwinden,\nseh\' das Morgenrot schon glüh\'n.\nEinen neuen Tag im Lande,\nwo die Rosen nie verblüh\'n.\r\nNäher an Dein Herz, Herr Jesus,\nich möcht\' dieser Welt entflieh\'n\nund in jenem Lande weilen,\nwo die Rosen nie verblüh\'n.\r\nO, wie herrlich wird es dort sein,\nin der Herrlichkeit bei Ihm!\nEwig werden wir uns freuen,\nwo die Rosen nie verblüh\'n.\r\nBald kommt unser König wieder,\ndieser Welt werd\' ich entflieh\'n\nund in jenem Land Ihn preisen,\nwo die Rosen nie verblüh\'n.'),
(9, '0842', 'Ich darfs glauben und wissen, meine Schuld ist bezahlt   (Halleluja, Halleluja, Du hast mich geliebet)', NULL, 'Ich darf\'s glauben und wissen:\nMeine Schuld ist bedeckt\nund die Handschrift zerrissen,\ndie mich lange geschreckt!\r\nHalleluja, Halleluja,\nDu hast mich geliebet;\nHalleluja, Halleluja\nsing ich Dir, o mein Gott!\r\nGottes Sohn gab Sein Leben\nals ein Lösegeld hin,\num mir Freiheit zu geben,\naus dem Tod mich zu ziehn!\r\nUnd nun folg\' ich dem Tilger\nmeiner Sünden beglückt\nals ein fröhlicher Pilger,\nden die Schuld nicht mehr drückt!\r\nAls Erlöster, Befreiter,\nbleib ich willig und gern\nein Verlobter, Geweihter,\nein Gebundner des Herrn!\r\nMeinem Retter zum Preise\nsing ich freudig fortan,\nund so geht meine Reise\nnun zum Himmel hinan!'),
(9, '0843', 'Ich denke nicht nach was der Morgen mir bringt  -  I care not Today what the Morrow may bring   (Im Glauben leb ich, auf Jesus ich schau)', 'I care not today what the morrow may bring,\nIf shadow or sunshine or rain.\nThe Lord I know ruleth o\'er everything,\nand all of my worry is vain.\r\nLiving by faith, in Jesus above,\ntrusting, confiding in His great love.\nFrom all harm safe In His sheltering arm,\nI\'m living by faith And I feel no alarm.\r\nThough tempest may blow and the stormclouds arise,\nobscuring the brightness of life, I\'m never alarmed.\nAt the overcast skies,\nthe Master looks on at the strife.\r\nI know that He safely will carry me through,\nno matter what evils betide.\nWhy should I then care, though the tempest may blow,\nif Jesus walks close to my side.\r\nOur Lord will return to this earth some sweet day,\nour troubles will then all be o\'er.\nThe Master so gently will lead us away,\nbeyond that blest heavenly shore.', 'Ich denke nicht nach, was der Norgen mir bringt,\nob Sonn\'schein, ob Regen, ob Sturm.\nIch weiß, mein Herr Jesus bringt sicher mich durch,\nmein Sorgen ist völlig umsonst.\r\nIm Glauben leb\' ich, auf Jesus ich schau\nund Seiner Gnad\' und Lieb\' ich vertrau.\nVor Schaden Er birgt mich mit schützender Hand.\nIm Glauben leb\' ich und fürchte mich nicht.\r\nIch weiß Er trägt sicher durch\'s Leben mich durch,\nwenn Wolken auch dunkeln die Sicht.\nAuch wenn Stürme toben, Er bleibt nah bei mir,\nWarum soll ich sorgen dann mich?\r\nVon Kriegen wir hören, was kommt auf uns zu?\nAuch Erdbeben sind hier und da.\nErschrecke doch nicht, denn all dies muss gescheh\'n.\nBlick auf, die Erlösung ist nah!\r\nUnser Herr kommt zurück, es wird bald gescheh\'n,\nall\' unsere Sorgen sind dann vorbei.\nDer Meister uns sanft heimführen wird,\nzu dem schönen himmlischen Heim.'),
(9, '0844', 'Ich dürstete im Wüstenland der Sünd und Schmach  -  I thirsted in the barren Land of Sin and Shame   (Trinke von dem Lebenswasser heute)', 'I thirsted in the barren land of sin and shame\nand nothing satisfying there I found.\nBut to the blessed cross of Christ one day I came\nwhere springs of living water did abound.\r\nDrinking at the springs of living water,\nhappy now am I my soul they satisfy.\nDrinking at the springs of living water\no wonderful and bountiful supply.\r\nHow sweet the living water from the hills of God.\nIt makes me glad and happy all the way.\nNow glory grace and blessing mark the path I\'ve trod.\nI\'m shouting hallelujah every day.\r\nO sinner won\'t you come today to Calvary\na fountain there is flowing deep and wide.\nThe Saviour now invites you to the water free,\nwhere thirsting spirits can be satisfied.', 'Ich dürstete im Wüstenland der Sünd\' und Schmach\nund nichts befriedigte mein Herze dort.\nDoch eines Tages kam ich zum Kreuze Christi hin,\nwo Lebenswasser floss so reich für mich.\r\nTrinke von dem Lebenswasser heute,\nerquicken wird es dich,, beglücken gerne dich.\nTrinke von dem Lebenswasser heute!\nO welch ein reicher Überfluss für dich!\r\nWie wunderbar das Lebenswasser für mich ist;\nes macht mich glücklich und zufrieden hier.\nAuf meinem Wege folgen mir jetzt Gnad\' und Ehr\',\nich singe "Halleluja" Jesus Dir.\r\nO Seele, willst du nicht noch heut\' nach Golgatha;\ndort fließet eine Quelle auch für dich.\nDer Heiland bietet dir umsonst aus Seiner Quell\'.\nWen dürstet, komme heut\' noch zu Ihm hin.'),
(9, '0845', 'Ich ergeb mich Dir   (Chorus)', NULL, 'Ich ergeb\' mich Dir,\nIch ergeb\' mich Dir,\nalles Dir, geliebter Heiland,\nalles geb\' ich Dir.'),
(9, '0846', 'Ich erhebe meine Hände zu Dir   (2 Chorusse)', NULL, 'Ich erhebe meine Hände zu Dir,\nich erhebe meine Hände zu Dir.\nDu allein verdienst allen Lob und Ehre.\nIch erhebe meine Hände zu Dir.\r\nIch preise Deinen heiligen Nam\',\nich preise Deinen heiligen Nam\'.\nDu allein verdienst allen Lob und Ehre.\nIch preise Deinen heiligen Nam\'.'),
(9, '0847', 'Ich finde Ruh in Jesus allein  -  Find Rest in my Soul in Christ alone   (2 Chorusse)', 'Find rest my soul in Christ alone.\nKnow His power in quietness and trust.\r\nWhen the oceans rise and thunders roar,\nI will soar with You above the storm.\nFather, You are King over the flood.\n(And) I will be still and know You are God.\n(And) I will be still and know You are God.', 'Ich finde Ruh\' in Jesus allein.\nEmpfange Kraft in Stille und Vertrau\'n.\r\nWenn die Meere toben, Donner groll\'n,\nfürchte ich mich nicht, denn Du bist da.\nHerr, Du bist mein Fels, Du stillst den Sturm.\nIch bin ganz ruhig, ich weiß: Du bist da,\nich bin ganz ruhig, ich weiß: Du bist da.'),
(9, '0848', 'Ich folge nur Jesus   (Chorus)', NULL, 'Ich folge nur Jesus, folg\' Ihm Schritt für Schritt\nund in Seiner Liebe find\' ich all mein Glück.\nKein Sorgen ums Morgen, ich leb\' nur im Heut\',\ndenn ich folge Jesus, jetzt und allezeit.'),
(9, '0849', 'Ich freu mich in Jesus   (Chorus)', NULL, 'Ich freu\' mich in Jesus, ich freu\' mich in Jesus,\ndenn Jesus ist mein Glück allein.\nIch freu\' mich in Jesus, ich freu\' mich in Jesus,\ner ist mein Sonnenschein.\nAuch in den Nöten des Lebens bin ich Ihm ergeben,\nEr ist mein Alles mir.\nIch freu\' mich in Jesus, ich freu\' mich in Jesus,\ner ist mein Sonnenschein.'),
(9, '0850', 'Ich fühle ein Heimweh nach einem Land  -  I\'m kind of Homesick for a Country   (Friedensland, ich sehne mich nach dir)', 'I\'m kind of homesick for a country\nTo which I\'ve never been before.\nNo sad goodbyes there will be spoken\nFor time won\'t matter anymore.\r\nBeulah land, I\'m longing for You\nAnd someday on thee I\'ll stand.\nThere my home shall be eternal.\nBeulah land, sweet Beulah land.\r\nI\'m looking out across the river.\nThat\'s where my faith shall end in sight.\nThere\'s just a few more days to labour.\nAnd I will take my heavenly flight.', 'Ich fühle ein Heimweh nach einem Land\nIn welchem ich noch nie gewesen bin.\nKein trauriger Abschied wird dort mehr gesprochen.\nWeil Zeit keine Rolle mehr spielen wird.\r\nGelobtes Land, ich sehne mich nach dir.\nUnd eines Tages werde ich in dir stehen.\nDort wird mein Heim ewig sein.\nGelobtes Land, süßes, gelobtes Land.\r\nIch schaue aus, über den Fluss.\nDort wird mein Glaube sichtbar enden.\nEs sind nur noch einige Tage der Arbeit.\nUnd dann werde ich meinen himmlischen Flug nehmen.'),
(9, '0851', 'Ich geb alle Ehre dem Herrn  -  I give all my worship to You', 'I give all my worship to You,\nI give all my worship to You,\nwhatever the cost or what others do,\nI give all my worship to You.\r\n\r\n\r\n', 'Ich geb\' alle Ehre dem Herrn,\nich geb\' alle Ehre dem Herrn.\nEs macht mir nichts aus was andere tun.\nIch geb\' alle Ehre dem Herrn.\r\nIch geb\' allen Lobpreis dem Herrn,\nich geb\' allen Lobpreis dem Herrn.\nEs macht mir nichts aus was andere tun.\nIch geb\' allen Lobpreis dem Herrn.\r\nIch leg\' alle Sorgen auf Ihn,\nich leg\' alle Sorgen auf Ihn.\nEs macht mir nichts aus was andere tun.\nIch leg\' alle Sorgen auf Ihn.\r\nIch bring\' alle Nöte dem Herrn,\nich bring\' alle Nöte dem Herrn.\nEs macht mir nichts aus was andere tun.\nIch bring\' alle Nöte dem Herrn.'),
(9, '0852', 'Ich geh hinauf in die Erstauferstehung  -  I\'m going up in the first Resurrection   (Chorus)', 'I\'m going up, I\'m going up I\'m going up in the first resurrection.\nI\'m going up, I\'m going up I\'m going up to meet the Lord.\nThey\'ll be coming from the East, coming from the West,\nComing from the North, They\'ll be coming from the South.\nI\'m going up, I\'m going up I\'m going up to meet the Lord.', 'Ich geh\' hinauf, ich geh\' hinauf, ich geh\' hinauf in der Erstauferstehung.\nIch geh\' hinauf, ich geh\' hinauf ich geh\' hinauf und treff\' den Herrn.\nUnd von Osten kommen sie, auch von Westen, aber wie,\naus dem Norden kommen sie und aus dem Süden, komm und sieh.\nIch geh\' hinauf, ich geh hinauf ich geh\' hinauf und treff\' den Herrn.'),
(9, '0853', 'Ich geh in den Garten allein  -  I come to the Garden alone   (Und Er geht mit mir, und Er spricht mit mir)', 'I come to the garden alone\nwhile the dew is still on the roses.\nAnd the voice I hear, falling on my ear\nthe Son of God discloses.\r\nAnd He walks with me,\nand He talks with me,\nand He tells me I am His own.\nAnd the joy we share as we tarry there\nnone other has ever known.\r\nHe speaks and the sound of His voice\nis so sweet, the birds hush their singing.\nAnd the melody that He gave to me\nwithin my heart is ringing.\r\nI\'d stay in the garden with Him\n\'tho the night around me be falling.\nBut He bids me go through the voice of woe.\nHis voice to me is callin.', 'Ich geh\' in den Garten allein,\nmeinem Heiland dort zu begegnen.\nSeine Stimme ich hör\', und ich freu\' mich sehr,\nmein Heiland will mich segnen.\r\nUnd Er geht mit mir, und Er spricht mit mir,\nund Er sagt mir, dass ich ganz Sein.\nUnd die Freude dort, die mir gibt Sein Wort,\nsie könnte nicht größer sein.\r\nSein Wort klingt so freundlich und so traut,\nwer es hört anbetet und schweiget.\nDiese Melodie, nie vergess\' ich sie,\nmein Herz vor Ihm sich neiget.\r\nGern blieb ich im Garten mit Ihm,\nbis der Abend rings mich umhüllte.\nDoch Er bittet: Geh, sieh\' der Menschen Weh!\nIch folge Seiner Stimme.'),
(9, '0854', 'Ich geh\' den schmalen Lebensweg, den Jesus selbst gebahnt   (Ich geh, ich geh den schmalen Lebensweg)', NULL, 'Ich geh\' den schmalen Lebensweg, den Jesus selbst gebahnt;\nden einz\'gen Weg, der sicher führt zum höh\'ren, bess\'ren Land.\r\nIch geh\', ich geh\' den schmalen Lebensweg.\nIch geh\', ich geh\' den schmalen Lebensweg.\r\nIch geh\' den schmalen Lebensweg, ob jeder untreu wird,\nden Weg, von dem geschrieben steht, dass selbst ein Tor nicht irrt.\r\nIch geh\' den schmalen Lebensweg, wenn auch verlassen hier,\nso bin ich dennoch nicht allein, mein Jesus bleibt bei mir.\r\nIch geh\' den schmalen Lebensweg durch Trübsal, Leid und Not;\ndurch Gottes Hilfe, Gnad\' und Kraft gehorsam bis zum Tod.\r\nIch geh\' den schmalen Lebensweg getreu durch Spott und Hohn,\nbis Jesus mich einst zu sich ruft, wo mir dann wird der Lohn.'),
(9, '0855', 'Ich gehe mit Jesus und folg Schritt für Schritt  -  I\'m following Jesus, one Step at a Time', 'I\'m following Jesus, one step at a time,\nI live for the moment, in His love divine.\nWhy think of tomorrow, just live for today,\nI\'m following Jesus, each step of the way.\r\nThe pathway is narrow, but He leads me on,\nI walk in His shadow, my fears are all gone.\nMy spirit grows stronger, each moment, each day,\nfor Jesus is leading each step of the way.\r\n', 'Ich gehe mit Jesus und folg\' Schritt für Schritt,\nnicht sorgend um Morgen, denn Er geht ja mit.\nSo bin ich geborgen bei Ihm Tag für Tag,\nschau vorwärts auf jesus und folge Ihm nach.\r\nDer Weg zwar ist schmal nur, doch führt er zum Ziel,\nund seit ich Ihm folge, die Angst von mir fiel.\nEr stärkt mir den Mut nun all\' Stunden und Tag\',\nweil Er mir voran geht, d\'rum folg ich Ihm nach.\r\nNie bin ich allein nun, denn viele geh\'n mit,\nwir haben Gemeinschaft und geh\'n Schritt für Schritt.\nWir singen und zeugen vom Herrn Tag für Tag.\nEr macht uns so fröhlich, d\'rum folg\' ich Ihm nach.'),
(9, '0856', 'Ich ging einher in Dunkelheit  -  I wandered in the Shades of Night   (Friede, Freude strahlt in meiner Seel)', 'I wandered in the shades of night,\ntill Jesus came to me.\nAnd with the sunlight of His love\nbid all my darkness flee.\r\nSunlight, sunlight in my soul today,\nsunlight, sunlight all along the way.\nSince the Saviour found me, took away my sin,\nI have had the sunlight of His love within.\r\nThough clouds may gather in the sky,\nand billows \'round me roll.\nHowever dark the world may be,\nI\'ve sunlight in my soul.\r\nSoon I shall see Him as He is,\nthe light that came to me.\nBehold the brightness of His face,\nthroughout eternity.', 'Ich ging einher in Dunkelheit,\neh Jesus ich gekannt,\nbis unter Seinem Gnadenlicht,\nich sel\'gen Frieden fand.\r\nFriede, Freude strahlt in meiner Seel\',\nJesu Liebe macht den Pfad mir hell.\nSeit der teure Heiland mir das Herz erneut,\nwandle ich im Lichte seiner Heiligkeit.\r\nGeh\' ich im Licht des Herrn umher,\nso winkt mir süße Ruh\'.\nNicht kümmert mich die Lust der Welt,\nich eil\' der Heimat zu.\r\nUnd ist das himmlisch\' Ziel erreicht,\nwerd\' ich in Klarheit schaun\',\nden König dem kein and\'rer gleicht,\nauf sel\'gen Himmelsau\'n.'),
(9, '0857', 'Ich glaube Gott! Es wird schon noch geschehen', NULL, 'Ich glaube Gott! Es wird schon noch geschehen,\nwas Er uns zugesagt.\nSein Wort bleibt fest, wird nimmermehr vergehen,\ndas macht mich unverzagt.\nWohl höhnt die Welt! Sie kann mich nicht verstehen.\nIch fürchte nicht den Spott:\nIch werde Jesus als den König sehen.\nIch glaube Gott, ich glaube Gott!\r\nIch glaube Gott! Soll ich nicht Ihm vertrauen,\nder mich so reich beglückt?\nAuf das, was doch vergeht, kann ich nicht bauen,\nweil es ja nur bedrückt.\nWohl höhnt die Welt! Mich zieht\'s zu Himmelsauen.\nIch fürchte nicht den Spott:\nIch werde Jesus als den König schauen.\nIch glaube Gott, ich glaube Gott!\r\nIch glaube Gott! Das dient zu meinem Frommen\nund macht das Herz mir still.\nDie hellste Freude ist in mir entglommen,\ndie nie mehr enden will.\nWohl höhnt die Welt! Das macht mich nicht beklommen.\nIch fürchte nicht den Spott: Ich sehe Jesus als den König kommen.\nIch glaube Gott, ich glaube Gott!\r\nIch glaube Gott! Was ist das für ein Segen,\nder mich so reich beglückt?\nGott ist mit mir auf allen meinen Wegen,\nwohin Sein Geist mich schickt.\nWohl höhnt die Welt! Das kann mich nicht erregen.\nIch fürchte nicht den Spott: Dem König Jesus gehe ich entgegen.\nIch glaube Gott, ich glaube Gott!'),
(9, '0858', 'Ich glaube Gott! Ich glaube Gott! Es soll gescheh\'n, so wie Er\'s gesagt  -  I believe God! I believe God! It shall be done, even as He said', 'I believe God! I believe God!\nIt shall be done, even as He said.\nTrust and obey, look up and say:\n"I believe, I believe God!"\r\nAnd if you want salvation now\nand the Holy Ghost and power,\njust trust and obey, believe it and say:\nI believe, I believe God.', 'Ich glaube Gott! Ich glaube Gott!\nEs soll gescheh\'n, so wie Er\'s gesagt.\nVertraue, gehorch\', schau\' auf und sag\':\n"Ich glaube, ich glaube Gott!"\r\nUnd wenn du jetzt Erlösung brauchst\nund Heil\'gen Geist und Kraft,\nvertrau\' gehorch\', glaub\' und sprich:\nIch glaube, ich glaube Gott.'),
(9, '0859', 'Ich hab Befreiung, o Preis sei Gott', NULL, 'Ich hab\' Befreiung, o Preis sei Gott,\nich hab\' Befreiung durch Sein Wort!\nDie Sündenketten zerbrochen,\nich hab\' Befreiung, o Preis sei Gott!\nUnd bei mir ist alles neu, ja alles ist neu.\nGlücklich bin ich, Er machte mich frei.\nEr führte mich zur Freiheit aus der Sklaverei.\nO, o, o, o, alles ist neu!'),
(9, '0860', 'Ich hab Dich nötig Herr, so nötig o Herr   (Chorus)', NULL, 'Ich hab\' Dich nötig, Herr, so nötig, o Herr!\nIch hab\' Dich nötig, Herr, so nötig, o Herr!\nNimm meine Rechte weg in dieser sündigen Welt\nund wirke Du in mir, was Dir nur gefällt.'),
(9, '0861', 'Ich hab einen Heiland, o betet Ihn an  -  I have a Redeemer, o worship His Name   (O ewige Liebe, die mir vergab)', 'I have a Redeemer, o worship His name,\nHe bore my transgressions, my sin and my shame,\nand in His own body on Calvary’s tree,\nHe took them upon Him that I might go free.\r\nOh, wonderful love that saved me from sin!\nOh, wonderful love that cleansed me within!\nHis Spirit bears witness that now I am saved.\nAll glory to Jesus, I’m saved, I’m saved, I’m saved!\r\nI have a Redeemer who calls me His own,\nHe bids me come boldly before His great throne.\nBecause I am pardoned and cleansed by His blood,\nand guiltless, tho’ living ’mid earth’s evil flood.\r\nYes, sweet are Thy mercies, O Saviour divine,\nin tender compassion Thou madest me Thine.\nWith Thee I will journey till life’s day is done,\nand all thro’ the ages give praise to the Son.', 'Ich hab\' einen Heiland, o betet Ihn an,\nIhn, der meine Sünde und Schuld auf sich nahm!\nAuf Golgatha gab Er Sein leben dahin,\ndamit ich hinfort kein Gebund\'ner mehr bin.\r\nO ewige Liebe, die mir vergab,\nall meine Lasten nahmst Du mir ab.\nDein Geist gibt mir Zeugnis, dass ich ewig Dein,\no herrlicher Heiland, bin Dein, bin ganz Dein!\r\nIch hab\' einen Heiland des Eigen\' ich bin;\nEr ladet mich freundlich zu Seinem Thron hin.\nObwohl ich noch leb\' in der Welt voller Sünd\'\nich all\'zeit Bewahrung und Gnad\' bei Ihm find\'.\r\nJa, groß ist die Gnade, die Du gibst allein.\nDurch Liebe und Mitleid darf Dein ich nun sein.\nMit Dir will ich pilgern durch\'s irdische Tal\nund ewig Dich preisen im himmlischen Saal.'),
(9, '0862', 'Ich hab einen herrlichen König, den einzig erkenne ich an  (Jesus, mein Heil, meine tiefe Ruh, Jesus, Dir jauchze ich selig zu)', NULL, 'Ich hab einen herrlichen König,\nden einzig erkenne ich an.\nIch will keinen andern auf Erden,\nund ständ\' ich allein auf dem Plan.\r\nJesus, mein Heil, meine tiefe Ruh\',\nJesus, Dir jauchze ich selig zu!\nIch hab einen herrlichen König\no Jesus, Jesus, nur Du!\r\nIch stell zur Verfügung mich gerne\ndem König, der königlich liebt,\nund tue mit Wonne den Willen\ndes Königs, der königlich gibt.\r\nIch traue den Worten des Königs\nund richte mich immer danach\nund folg\' Seiner siegenden Fahne,\nund geht\'s auch durch Schmerzen und Schmach.\r\nIch will, dass mein alles im Leben\ndem König sei untertan,\nund sehe mit sehnender Seele\nSein ewiges Königreich nah\'n.'),
(9, '0863', 'Ich hab einen Mittler und Fürsprecher droben  -  I have a Saviour, He’s pleading in Glory   (Ich will für dich beten, o lass dich doch retten)', 'I have a Saviour, He’s pleading in glory,\na dear, loving Saviour, though earth friends be few.\nAnd now He is watching in tenderness o’er me,\nand, oh, that my Saviour were your Saviour, too.\r\nFor you I am praying,\nfor you I am praying,\nfor you I am praying,\nI’m praying for you.\r\nI have a Father; to me He has given,\na hope for eternity, blessed and true.\nAnd soon will He call me to meet Him in heaven,\nbut, oh, that He’d let me bring you with me, too!\r\nI have a robe: ’tis resplendent in whiteness,\nawaiting in glory my wondering view.\nOh, when I receive it all shining in brightness,\ndear friend, could I see you receiving one, too!\r\nTo me has been given a peace like a river,\na peace that the friends of this world never knew.\nAnd Christ is the Author, and Christ is the Giver,\nand o that his peace might be given to you!\r\nWhen Jesus has found you, tell others the story,\nthat my loving Saviour is your Saviour too.\nThen pray that your Saviour may bring them to glory,\nand prayer will be answered \'twas answered for you!', 'Ich hab einen Mittler und Fürsprecher droben,\ndes Freundschaft und Liebe auf Erden nichts gleicht.\nAch, könnt ich die Huld dieses Heilands recht loben,\nwie würde dein Herz bald bewegt und erweicht!\r\nIch will für dich beten,\no lass dich doch retten!\nIch fleh\', Herr, zu Dir:\nSchenk Dich jedem allhier!\r\nIch hab einen Vater, des göttliche Güte\nmir eine lebendige Hoffnung verlieh.\nBald ruft Er mich heim, da ist ewiger Friede,\nfolg\' Ihm, dass auch dich Seine Lieb dorthin zieh!\r\nIch hab einen Schmuck, seht, welch himmlische Wonne,\nmein Heiland erwirkte und schenkte ihn mir,\ndies Kleid der Gerechtigkeit glänzt wie die Sonne,\nach, dass du, mein Freund, auch empfingst solche Zier!\r\nIch hab einen Frieden im Herzen verborgen,\nein Gut, wie die Welt es nicht kennt und nicht gibt.\nMein Heiland bewahrt mich, so bin ich geborgen,\nhast du auch dies Licht, das kein Dunkel mehr trübt?\r\nWohlan, wenn du Jesum, den Heiland, gefunden,\nso sag es auch andern und führ\' sie herzu.\nBis sie auch frohlockend die Gnade bekunden\nund lieben und danken und loben wie du.'),
(9, '0864', 'Ich hab Freude in meiner Seel\'  -  I\'ve got Joy deep down in my Soul   (Chorus)', 'I\'ve got joy deep down in my soul,\nI\'ve got joy deep down in my soul.\nI\'m redeemed by the Blood of the Lamb,\nI\'ve got joy deep down in my soul.', 'Ich hab\' Freude in meiner Seel\',\nIch hab\' Freude in meiner Seel\',\ndenn das Lamm hat mich völlig erlöst,\nich hab\' Freude in meiner Seel\'.'),
(9, '0865', 'Ich hab gehört von dem Land an dem goldenen Strand  -  I have heard of a Land on the far away Strand   (Niemals mehr alt)', 'I have heard of a land,\non the far away strand,\n\'tis a beautiful home of the soul.\nBuilt by Jesus on high,\nthere we never shall die,\n\'tis a land where we never grow old.\r\nNever grow old, never grow old,\nIn a land where we\'ll never grow old;\nNever grow old, never grow old,\nIn a land where we\'ll never grow old.\r\nIn that beautiful home,\nwhere we\'ll nevermore roam,\nwe shall be in the\nsweet by and by.\nHappy praise to the King,\nthrough eternity sing,\n\'tis a land where we never shall die.\r\nWhen our work here is done,\nand the life-crown is won,\nand our troubles and trials are o\'er.\nAll our sorrow will end,\nand our voices will blend,\nwith the loved ones who\'ve gone on before.', 'Ich hab\' gehört von dem Land,\nan dem goldenen Strand,\neinem herrlichen Ort für die Seel\'.\nJa, von Jesus erbaut,\nfür die liebliche Braut,\n\'s ist ein Land, wo wir nie werden alt.\r\nNiemals mehr alt, niemals mehr alt.\nIn diesem Land werden wir nie mehr alt.\nNiemals mehr alt, niemals mehr alt.\nIn diesem Land werden wir nie mehr alt.\r\nIn dem herrlichen Heim,\nsind wir nie mehr allein,\nes wird dort in der Herrlichkeit sein.\nDen König preisen wir dort,\nder uns gab hier Sein Wort.\nIn dem Land, wo der Tod ist ganz fort.\r\nWenn die Arbeit vollbracht,\nwird die Kron\' mir gebracht,\nalle Prüfungen sind dann vorbei.\nAlle Sorgen sind fort,\nund wir stimmen froh ein,\nmit den Lieben, die jetzt schon sind dort.'),
(9, '0866', 'Ich hab Seinem Wort geglaubt  -  I’ve believed the true Report   (Halleluja, Halleluja, fällt der Vorhang hinter mir)', 'I’ve believed the true report, Hallelujah to the Lamb!\nI have passed the outer court, O glory be to God!\nI am all on Jesus’ side, on the altar sanctified,\nTo the world and sin I’ve died, Hallelujah to the Lamb!\r\nHallelujah! Hallelujah!\nI have passed the riven veil,\nwhere the glories never fail,\nHallelujah! Hallelujah!\nI am living in the presence of the King.\r\nI’m a king and priest to God, Hallelujah to the Lamb!\nBy the cleansing of the blood, o glory be to God!\nBy the Spirit’s power and light, I am living day and night,\nin the holiest place so bright, Hallelujah to the Lamb!\r\nI have passed the outer veil, Hallelujah to the Lamb!\nWhich did once God’s light conceal, o glory be to God!\nBut the blood has brought me in to God’s holiness so clean,\nwhere there’s death to self and sin, Hallelujah to the Lamb!\r\nI’m within the holiest pale, Hallelujah to the Lamb!\nI have passed the inner veil, o glory be to God!\nI am sanctified to God by the power of the blood,\nnow the Lord is my abode, Hallelujah to the Lamb!', 'Ich hab\' Seinem Wort geglaubt, Halleluja, Preis dem Lamm!\nhab\' in\'s Heiligtum geschaut, o Ehre sei dem Herrn!\nIch bin ganz auf Jesu Seit\', bin als Opfer Ihm geweiht,\nvon der Welt und Sünd\' befreit, Halleluja , Preis dem Lamm!\r\nHalleluja, Halleluja!\nFällt der Vorhang hinter mir,\nhab\' ich Herrlichkeit bei Dir.\nHalleluja, Halleluja!\nDie Schechina-Herrlichkeit umhüllt mich ganz.\r\nSeit Sein Blut wusch mich ganz rein, Halleluja, Preis dem Lamm!\ndarf ein König ich heut\' sein, o Ehre sei dem Herrn!\nJa, durch Seines Geistes Licht, darf ich schau\'n Sein Angesicht,\nnah\' bei Ihm die Welt zerbricht, Halleluja, Preis dem Lamm!\r\nNicht im Vorhof mehr ich bin, Halleluja, Preis dem Lamm!\nheut\' darf ganz zu Ihm ich hin, o Ehre sei dem Herrn!\nIn Sein Haus hinein zu Sich, brachte durch sein Blut Er mich,\ndort ist tot das alte Ich, Halleluja, Preis dem Lamm!\r\nHinter mir der Vorhang fiel, Halleluja, Preis dem Lamm!\nGottes Licht, ich bin am Ziel, o Ehre sei dem Herrn!\nHeut\' ich selbst ein Tempel bin, dass ich leb\' hat einen Sinn,\nich gab mich Ihm völlig hin, Halleluja, Preis dem Lamm!'),
(9, '0867', 'Ich habe eingewilligt, mein Weg sei mir durchkreuzt', NULL, 'Ich habe eingewilligt, mein Weg sei mir durchkreuzt.\nEs werde nie gebilligt, wozu das Fleisch mich reizt!\nDurch Jesu Kreuz geschieden von meinem eignen Sinn,\nzieh ich in tiefem Frieden durchs Leben froh dahin.\r\nIm stillen Heiligtume schau ich anbetend an\nzu meines Jesu Ruhme, was Er an mir getan.\nIn heißem Liebeswerben hat Er sich dargebracht\nund hat auch mich zum Sterben dadurch bereit gemacht.\r\nO selger Geist von oben, Du machst mir\'s offenbar:\nMein Jesus ward erhoben für mich auf den Altar.\nAn Ihm darf ich nun hangen und mitgekreuzigt sein.\nGestillt ist alles Bangen, ich ging zur Ruhe ein.\r\nWas soll ich weiter sagen? Gott führt mich, wie Er will.\nIch will das Kreuz nachtragen dem Heiland selig, still.\nEs werde nie gebilligt, wozu das Fleisch mich reizt!\nIch habe eingewilligt: Mein Weg bleibt mir durchkreuzt.'),
(9, '0868', 'Ich habe Freude; Friede; Ruhe in meinem Herzen -  There is a Joy; Peace; Rest down in my Heart   (Ich bin so glücklich, unsagbar glücklich)   (3 Chorusse)', 'There is a joy, joy, joy, joy down in my heart,\ndown in my heart, down in my heart,\nThere is a joy, joy, joy, joy down in my heart,\nGlory to the Lord!\r\nI am so happy, so very happy,\nI have the love of Jesus in my heart!\nI am so happy, so very happy,\nI have the love of Jesus in my heart!\r\nThere is a peace, peace, peace, peace down in my heart,\ndown in my heart, down in my heart.\nThere is a peace, peace, peace, peace down in my heart,\nGlory to the Lord!\r\nThere is a rest, rest, rest, rest down in my heart,\ndown in my heart, down in my heart.\nThere is a rest, rest, rest, rest down in my heart,\nGlory to the Lord!', 'Ich habe Freude, Freude, Freude Freude in meinem Herzen,\nin meinem Herzen, in meinem Herz.\nIch habe Freude, Freude, Freude Freude in meinem Herzen,\nEhre sei dem Herrn!\r\nIch bin so glücklich, unsagbar glücklich,\ndenn Jesu Liebe macht das Herz so froh!\nIch bin so glücklich, unsagbar glücklich,\ndenn Jesu Liebe macht das Herz so froh!\r\nIch habe Friede, Friede, Friede, Friede in meinem Herzen,\nin meinem Herzen, in meinem Herz.\nIch habe Friede, Friede, Friede Friede in meinem Herzen,\nEhre sei dem Herrn!\r\nIch habe Ruhe, Ruhe, Ruhe, Ruhe in meinem Herzen,\nin meinem Herzen, in meinem Herz.\nIch habe Ruhe, Ruhe, Ruhe, Ruhe in meinem Herzen,\nEhre sei dem Herrn!'),
(9, '0869', 'Ich hatte von Dir nur vom Hörensagen vernommen   (Hiob 42, 5)', NULL, 'Ich hatte von Dir nur vom Hörensagen vernommen,\naber nun hat mein Auge Dich geseh\'n,\nnun hat mein Auge Dich geseh\'n,\nhat mein Auge Dich geseh\'n, oh, Herr!\nIch will Deinen Namen erheben allezeit,\ndenn nun hat mein Auge Dich geseh\'n,\nnun hat mein Auge Dich gesehen,\nhat mein Auge Dich geseh\'n, oh, Herr!'),
(9, '0870', 'Ich hör meinen Heiland rufen  -  I can hear my Saviour calling   (Wie Er führt will ich Ihm folgen)', 'I can hear my Saviour calling,\nI can hear my Saviour calling,\nI can hear my Saviour calling,\n"Take thy cross and follow, follow Me."\r\nWhere He leads me I will follow,\nwhere He leads me I will follow,\nwhere He leads me I will follow,\nI\'ll go with Him, with Him all the way.\r\nI\'ll go with Him through the garden,\nI\'ll go with Him through the garden,\nI\'ll go with Him through the garden,\nI\'ll go with Him, with Him all the way.\r\nHe will give me grace and glory,\nHe will give me grace and glory,\nHe will give me grace and glory,\nand go with me, with me all the way.\r\nGrace and glory will be with me,\nGrace and glory will be with me,\nGrace and glory will be with me,\nand go with me, with me all the way.', 'Ich hör meinen Heiland rufen,\nich hör meinen Heiland rufen,\nich hör meinen Heiland rufen:\n"Nimm dein Kreuz und folge, folge mir."\r\nWie Er führt will ich Ihm folgen,\nwie Er führt will ich Ihm folgen,\nwie Er führt will ich Ihm folgen,\ndenn Er führt mich, führt mich bis zum Ziel.\r\nIch geh\' mit Ihm durch den Garten,\nich geh\' mit Ihm durch den Garten,\nIch geh\' mit Ihm durch den Garten,\nich geh\' mit Ihm, mit Ihm bis zum Ziel.\r\nHerrlichkeit wird Er mir geben,\nHerrlichkeit wird Er mir geben,\nHerrlichkeit wird Er mir geben,\ndenn er führt mich, führt mich bis zum Ziel.\r\nHerrlichkeit wird bei mir bleiben,\nHerrlichkeit wird bei mir bleiben,\nHerrlichkeit wird bei mir bleiben,\nbei mir bleiben, bleiben bis zum Ziel.'),
(9, '0871', 'Ich hört des lieben Heilandes Wort  - I heard my loving Saviour say   (Komm, komm, komm zu der Quelle)', 'I heard my loving Saviour say,\nthere’s room at the fountain for me.\nCome wash the stains of sin away,\nthere’s room at the fountain for thee.\r\nRoom, room, yes, there is room,\nthere’s room at the fountain for thee.\nRoom, room, yes, there is room,\nthere’s room at the fountain for thee.\r\nI came to him my sins confessed,\nthere’s room at the fountain for me.\nWhen I gave up my heart was blest,\nthere’s room at the fountain for thee.\r\nI plung’d beneath the crimson tide,\nthere’s room at the fountain for me.\nAnd now by faith am sanctified,\nthere’s room at the fountain for thee.\r\nI found the crimson stream I know,\nthere’s room at the fountain for me.\nHis blood has wash’d me white as snow,\nthere’s room at the fountain for thee.\r\nHe cleans’d my heart from inbred sin,\nthere’s room at the fountain for me.\nAnd now he keeps me pure within,\nthere’s room at the fountain for thee.\r\nHis blood was shed but once for all,\nthere’s room at the fountain for me.\nO don’t reject sweet Mercy’s call,\nthere’s room at the fountain for thee.\r\nI’ll praise him while he gives me breath,\nthere’s room at the fountain for me.\nHe saved me from an awful death,\nthere’s room at the fountain for thee.\r\nWe’ll sing with all the saints above,\nthere’s room at the fountain for me.\nAnd praise him for redeeming love,\nthere’s room at the fountain for thee.', 'Ich hört\' des lieben Heilandes Wort:\n"Ja, komm zu der Quelle noch heut\'!\nJa, komm und wasche die Sünden fort,\nja, komm zu der Quelle noch heut\' !"\r\n"Komm, komm, komm zu der Quell\'!"\nIch bin an der Quelle noch heut\'.\n"Komm, komm, komm zu der Quell\'!"\nIch bin an der Quelle noch heut\'.\r\nAls ich dann meine Sünd\' bekannt,\nda wurde vom Herrn ich befreit.\nIn meinem Herz ich Gnade fand,\nund ich bin an der Quelle noch heut\'.\r\nIch taucht\' mich in die rote Flut\nund hab mich dem Herrn dort geweiht.\nJa, rein bin ich durch Jesu Blut\nund bin an der Quelle noch heut\'.\r\nNoch heut\' den Gnadenstrom ich seh\'\nund bin an der Quelle noch heut\'.\nSein Blut es wäscht mich weiß wie Schnee,\nich bin an der Quelle noch heut\'.\r\nEr wusch mein Herz von Sünden rein\nund jetzt preis ich Ihn allezeit!\nEr Selbst, das Leben, ist jetzt mein!\nich bin an der Quelle noch heut\'.\r\nSein Blut es floss auf Golgatha\nfür den, der die Sünde bereut.\nUnd bald schon mit der Heil\'gen Schar,\nsing ich Ihm ein Lied allezeit.\r\n\r\n'),
(9, '0872', 'Ich hörte Jesu Freundesruf: Komm her, beladnes Herz  -  I heard the Voice of Jesus say, come unto me and rest', 'I heard the voice of Jesus say,\n"Come unto me and rest.\nLay down, o weary one,\nlay down your head upon my breast."\nI came to Jesus as I was,\nso weary, worn, and sad.\nI found in him a resting place,\nand he has made me glad.\r\nI heard the voice of Jesus say,\n"Behold, I freely give\nthe living water, thirsty one,\nstoop down and drink and live."\nI came to Jesus, and I drank\nof that life-giving stream.\nMy thirst was quenched, my soul revived,\nand now I live in him.\r\nI heard the voice of Jesus say,\n"I am the dawning light.\nLook unto Me, your morn shall rise,\nand all your day be bright."\nI looked to Jesus, and I found\nin Him my star, my sun.\nAnd in that light of life I’ll walk\ntill trav’ling days are done.', 'Ich hörte Jesu Freundesruf:\n"Komm her, belad\'nes Herz,\nan meinem Herzen find\'st du Ruh\'\nfür allen deinen Schmerz."\nIch kam zu Ihm, so wie ich war,\nbeladen, krank und matt;\nda schenkte Er mir Fried\' und Ruh\'\naus freier Huld und Gnad\'!\r\nIch hörte Jesu Freundesruf:\n"Wer durstig ist, der komm,\nund wer kein Geld hat, trinke nur\numsonst vom Lebensstrom!"\nIch kam zu Jesus und ich trank\naus dieser heil\'gen Flut,\nda ward der Seele Durst gestillt,\nund leb\' ich durch sein Blut.\r\nIch hörte Jesu Freundesruf:\n"Ich bin das Licht der Welt;\nin Finsternis blick auf zu Mir,\nso wird dein Weg erhellt!"\nIch schaute auf und fand in Ihm\nden schönen Morgenstern,\nund wandle nun in Seinem Licht\nzur Heimat, zu dem Herrn.'),
(9, '0873', 'Ich kann, ich will, ich glaube jetzt  -  I can, I will, I do believe   (2 Chorusse)', 'I can, I will, I do believe,\nI can, I will, I do believe,\nI can, I will, I do believe,\nthat Jesus heals me now.\r\nI\'m trusting only in the Lord,\nI\'m trusting only in the Lord,\nI\'m trusting only in the Lord,\nthat Jesus heals me now.', 'Ich kann, ich will, ich glaube jetzt,\nich kann, ich will, ich glaube jetzt,\nich kann, ich will, ich glaube jetzt,\ndass Jesus mich jetzt heilt.\r\nIch traue einzig meinem Herrn,\nich traue einzig meinem Herrn,\nich traue einzig meinem Herrn,\ndass Jesus mich jetzt heilt.'),
(9, '0874', 'Ich kann, ich will, nicht mehr mir selber leben   (Siehe mein Verlangen, stille mein Verlangen)', NULL, 'Ich kann, ich will nicht mehr mir selber leben,\nmein stolzes Herz hat mich zu oft betört;\nDir, Jesus, Dir will ich mich übergeben,\nnimm an das Opfer, das voll und ganz Dir gehört!\r\nSiehe mein Verlangen,\nstille mein Verlangen!\nMein Heiland, nimm mich hin!\nIch bin Dein, nimm mich hin!\r\nVergib, vergib mein langes Widerstreben,\nDu siehst, dass ich jetzt ganz entschlossen bin!\nDir will ich alles weihen, alles geben,\nmein Leben, meine Liebe, ja, alles nimm hin!\r\nIch bin\'s nicht wert, dass Du Dich zu mir neigest,\nund dennoch glaub ich\'s, Herr, Du nimmst mich an.\nIch weiß, dass Du noch Größ\'res mir erzeigest\nals das, was Du bis hierher schon an mir getan.\r\nWelch Glück, ich darf nach Deinem Willen leben,\ndarf kindlich, freudig Dir gehorsam sein;\nwas Du verlangst, willst Du mir selber geben,\nwillst mir durch Deinen Geist und Dein Wort Kraft verleih\'n.\r\nDu kannst, Du willst mich, Herr, bei dem erhalten,\nwas Du mir gibst; ich bin und bleibe Dein.\nNein, meine Liebe soll nicht mehr erkalten,\nnur immer echter, tiefer, geheiligter sein.'),
(9, '0875', 'Ich kenne den, der Stürme stillt / I know the Master of the Wind (Mein Lebensboot fährt übers raue Meer - My Boat of life sails on a troubled Sea)', 'My boat of life sails on a troubled sea,\nand ever there\'s a wind in my sail.\nBut I have a friend, who watches over me,\nwhen the breeze turns into a gale.\r\nI know the Master of the wind,\nI know the Maker of the rain.\nHe can calm the storm\nand make the sun to shine again,\nI know the Master of the wind.\r\nSometimes I soar like an eagle through the sky,\nabove the peaks my soul can be found.\nAn unexpected storm may drive me from the heights,\nbrings me low, but never brings me down.', 'Mein Lebensboot fährt übers raue Meer,\nund immer, wenn der Wind ins Segel weht,\nso hab ich einen Freund, der mir zur Seite steht,\nwenn der Wind zum Sturm sich erhebt.\r\nIch kenne den, der Stürme stillt,\nder mich beschirmt, wenn Regen fällt,\nalles schweigt, wenn Jesus spricht\nund hell erstrahlt Sein Licht,\nich kenne den, der Stürme stillt.\r\nManchmal steig ich hoch wie ein Adler weit hinauf,\nam Gipfel bin ich frei und sorgenlos,\nund kommt ein starker Sturm, zieht er mich tief hinab,\ndoch niemals zieht er mich bis zum Grund.'),
(9, '0876', 'Ich komm zu preisen Seinen Nam  -  I came to glorify His Name   (Chorus)', 'I came to glorify His name,\nI came to glorify His name,\nI came to glorify the name of the Lord,\nI came to glorify His name.', 'Ich komm\' zu preisen Seinen Nam\',\nich komm\' zu preisen Seinen Nam\',\nich komm\' zu preisen diesen Namen des Herrn.\nIch komm\' zu preisen Seinen Nam\'.'),
(9, '0877', 'Ich lebe so frei wie der Fisch in dem Meer   (O volle Erlösung, so herrlich und frei)', NULL, 'Ich lebe so frei wie der Fisch in dem Meer,\ndie Gnade des Herrn gibt mir Kraft.\nDer Sünden und Sorgen unzähliges Heer\nsind ewig in Ihm abgeschafft.\r\nO volle Erlösung, so herrlich und frei\nvon Sünden und Schmerzen und Pein!\nDie Knechtschaft der Sünde ist ewig vorbei,\ndes Heilandes Leben ist mein.\r\nO herrlich Gnade, o seliger Stand:\nGemeinschaft mit Gott und dem Sohn.\nDie völlige Freude im Geiste ich fand,\nbin selig im Staubkleide schon.\r\nDie göttliche Liebe ist Balsam fürs Herz.\nSo wunderbar stillt sie mein Weh;\nsie heilt meine Krankheit und lindert den Schmerz,\nmacht weißer im Blut mich als Schnee.\r\nAm Kreuze ging Einer für uns in den Tod,\nauf Golgatha hat Er\'s vollbracht.\nErkauft hat das Lamm durch Sein Blut uns für Gott,\nzu Königen, Priestern gemacht.'),
(9, '0878', 'Ich lebte einst in Satans Macht   (O, der Heiland strahlt in meinem Herzen)', NULL, 'Ich lebte einst in Satans Macht\nund in Sünd\' und Gram dahin,\nals plötzlich in der finster\'n Nacht\nJesu strahlend Licht erschien.\r\nO, der Heiland strahlt in meinem Herzen\nnoch viel heller als der Sonne Licht!\nEs fliehen vor Ihm Sorg\' und Schmerzen,\nund der Sünden Kette bricht.\r\nDie Traurigkeit als täglich Brot,\nwar ich finst\'rer Mächte Spiel,\nals in der allergrößten Not\nJesu Lichtstrahl auf mich fiel.\r\nEinst sucht ich, denn mein Herz war leer,\nFreude noch in dieser Welt,\njetzt brauch ich keine Weltlust mehr,\nJesu Licht mein Herz erhellt.\r\nO singe, jauchze, Seele mein,\nGottes Sonne strahlt für dich,\nbald wirst du in der Sel\'gen Reih\'n\nfroh Ihn loben ewiglich!'),
(9, '0879', 'Ich lebte einst in Sündenschuld mein eignes Leben   (Nichts habe ich zu bringen, Herr)', NULL, 'Ich lebte einst in Sündenschuld\nmein eig\'nes Leben stolz,\nbis ich vor Ihm im Licht mich sah,\nerbärmlich, arm und bloß.\r\nNichts habe ich zu bringen, Herr,\nnur halten will ich mich\nan Deinem Kreuz, wo Du den Sieg\nerstritten hast auch für mich.\r\nUnd alles Gute das ich hab\'\nist mir geschenkt von Ihm.\nDurch Seine unverdiente Gnad\'\nbin ich was ich bin.\r\nAuch kann ich nie ein Christ hier sein\naus meiner eig\'nen Kraft.\nD\'rum rühm\' ich Jesus ganz allein,\nEr hat\'s für mich vollbracht!\r\nUnd wenn ich einst in Herrlichkeit\nmit euch und Ihm darf sein.\ndann sing\' ich dort so wie auch hier:\n"Nur Gnade brachte uns heim!"'),
(9, '0880', 'Ich leg in Zion einen Grundstein, einen Stein  -  I lay in Zion for a Foundation a Stone (Jesaja 28, 16)', 'I lay in Zion for a foundation a stone.\nI lay in Zion for a foundation a stone.\nA tried stone, a precious cornerstone,\na sure foundation, a sure foundation.\nA tried stone, a precious cornerstone.\nHe that believeth shall not make haste.', 'Ich leg\' in Zion einen Grundstein, einen Stein.\nIch leg\' in Zion einen Grundstein, einen Stein.\nEin bewährter Stein, ein kostbarer Eckstein,\nder fest gegründet, der fest gegründet ist.\nEin bewährter Stein, ein kostbarer Eckstein.\nWer glaubt, der wird nicht zuschanden sein.'),
(9, '0881', 'Ich lieb Dich Herr, keiner ist wie Du  -  I love You Lord, and I lift my Voice   (Chorus)', 'I love You Lord, and I lift my voice,\nto worship You, O my soul rejoice.\nTake joy my King in what You hear.\nLet me be a sweet, sweet sound in Your Ear.', 'Ich lieb\' Dich Herr, keiner ist wie Du,\nanbetend neigt sich mein Herz Dir zu.\nMein König, Gott, nimm dies Lied von mir.\nLass mich, Herr, ein Wohlklang sein vor Dir.'),
(9, '0882', 'Ich lieb Ihn (Chorus)', 'I love Him, I love Him,\nbecause He first loved me.\nAnd purchased my salvation\non Calvary`s tree.', 'Ich lieb\' Ihn, ich lieb\' Ihn,\nEr liebte mich zuerst.\nUnd brachte mir Erlösung\nauf Golgatha.'),
(9, '0883', 'Ich lieb Ihn viel zu sehr, um von Ihm zu gehen', 'I love Him too much, to fail Him now.\nI love Him too much, to break my vow.\nFor I´ve promised the Lord\nthat I will make it somehow.\nSo, I love Him too much, to fail Him now.\r\nWhen I first heard of Jesus,\nof His love and His grace,\nmy heart was overwhelmed\nto think a King would take my place.\nI cried: "Lord, I\'ll go with You every step of the way."\nThat\'s all I can do my dept to repay!\r\nWell, I told Him I loved Him,\nit was so easy to say,\nbut harder to prove\nwhen temptations came my way.\nFor my good I\'ve broken promises\nI counted them - but lost,\nwhen I caught a glimpse of true love\nhanging on a rugged cross.\r\nAnd now the years have drawn us closer\nmy love for Him has grown.\nEach step has brought me nearer\nto my eternal home.\nAnd I\'m just too close to heaven\nto turn back right now.\nHe said His grace would be sufficient,\nI\'m gonna make it somehow!', 'Ich lieb\' Ihn viel zu sehr, um von Ihm zu gehen.\nIch lieb\' Ihn viel zu sehr, ich muss zu Ihm steh\'n.\nIch versprach meinem Herrn,\nden ganzen Weg mit Ihm zu geh\'n,\ndenn ich lieb\' Ihn so sehr, ich muss zu Ihm steh\'n.\r\n\r\n\r\n'),
(9, '0884', 'Ich liebe den Herrn, denn Er hörte mein Flehn   (Lobt den Herrn, den Herrn der Ewigkeit)', NULL, 'Ich liebe den Herrn, denn Er hörte mein Fleh’n,\nEr neigte zu mir Sein Ohr.\nich lag in der Nacht, doch dann schrie ich zu Ihm,\nund schon brach Sein Licht hervor!\r\nLobt den Herrn, den Herrn der Ewigkeit.\nVoller Gnade und Barmherzigkeit.\nLobt den Herrn, der uns so gnädig ist,\nder Sein Volk aus Liebe nie vergisst!\r\nIn Kummer und Not aß ich täglich mein Brot,\nund Ängste umfingen mich,\nda rief ich zu Ihm, meinem Heiland und Gott,\nund Er kam und rettete mich!\r\nDu hast meine Seele lebendig gemacht,\nhast mich vor dem Sturz bewahrt,\nund all‘ meine Tränen, Herr, trocknest Du ab,\nund hilfst mir an jedem Tag!'),
(9, '0885', 'Ich liebe Dich/I love You, I love You, that\'s what Calvary said', 'In letters of crimson\nGod wrote His love\non a hillside so long, long ago.\nFor you and me our Jesus died\nand love\'s greatest story was told.\r\n"I love You, I love You",\nthat\'s what Calvary said.\n"I love You, I love You",\nI love You written in red.\r\nDown through the ages\nGod wrote his love,\nwith the same hands,\nthat suffered and bled.\nHe kept giving all that He had to give\na message so easily read.\r\nOh, precious is the flow,\nthat makes me white as snow.\nNo other fount I know,\nnothing but the blood of Jesus.', '\r\n"Ich liebe Dich, ich liebe Dich",\ndas heißt Golgatha,\n"ich liebe dich, ich liebe Dich",\nGott selber hat es gesagt.\r\n\r\n'),
(9, '0886', 'Ich liebe nur Jesus, nicht Güter und Geld  -  I\'d rather have Jesus than Silver or Gold   (Will nicht König sein über große Macht / Than to be the King of a vast Domain)', 'I\'d rather have Jesus than silver or gold,\nI\'d rather be His than have riches untold,\nI\'d rather have Jesus than houses or lands,\nI\'d rather be led by His nail pierced hand.\r\nThan to be the king of a vast domain\nor be held in sin\'s dread sway.\nI\'d rather have Jesus than anything,\nthis world affords today.\r\nI\'d rather have Jesus than men\'s applause,\nI\'d rather be faithful to His dear cause,\nI\'d rather have Jesus than worldwide fame,\nI\'d rather be true to His holy name\r\nHe\'s fairer than lilies of rarest bloom,\nHe\'s sweeter than honey from out the comb,\nHe\'s all that my hungering spirit needs,\nI\'d rather have Jesus and let Him lead.', 'Ich liebe nur Jesus, nicht Güter und Geld,\nich liebe nur Ihn, nicht den Reichtum der Welt,\nich liebe nur Jesus, nicht Häuser und Land,\nich liebe nur Ihn, dessen Lieb\' mich fand.\r\nWill nicht König sein über große Macht\nund gelegt in Sündenbann.\nIch liebe nur Jesus, nur Ihn allein,\nweil die Welt nichts bieten kann.\r\nIch liebe nur Jesus, nicht Menschenlob,\nich liebe nur Ihn der mich hoch erhob,\nich liebe nur Jesus, nicht Ehre der Welt,\nich liebe nur Ihn, dessen Gnad\' mich hält.\r\nIch liebe nur Jesus, der freundlich regiert,\nich liebe nur Ihn, dessen Treue mich führt,\nich liebe nur Jesus, des\' Freude mich füllt,\nich liebe nur Ihn, der die Seele stillt.'),
(9, '0887', 'Ich meinte wohl manchmal in meinem Sinn: Wenn ich nur das alles verstünd', NULL, 'Ich meinte wohl manchmal in meinem Sinn:\nWenn ich nur das alles verstünd,\nso wäre gewiss meine Knechtschaft dahin,\nso wär\' ich Dein glückliches Kind.\nIch forschte und sann, ich hörte und las,\nerkannte mit Lust dann dies und dann das.\nDoch blieb mir die Perle noch immer verwehrt,\nso heiß auch mein Herz sie begehrt.\nIch brauch zu verstehen Dich nicht.\nDer Glaube gibt besseres Licht.\nIch darf Dir vertrauen, Du herrlicher Herr,\nauch wenn ich verstehe Dich nicht.\r\nDa dacht\' ich, es läge am Willen vielleicht,\ndass stets mir noch fehle die Kraft.\nSo freue dich Seele, das Ziel ist erreicht,\nder redliche Wille es schafft.\nIch gab ihn dahin auf Gottes Altar\nund brachte gar oft zum Opfer ihn dar.\nDoch immer noch blieb mir die Perle verwehrt,\nso heiß auch mein Herz sie begehrt.\nDer Wille allein tut es nicht,\nwenn dir es an Glauben gebricht.\nIch muss Dir vertrauen, Du herrlicher Herr,\nsonst hilft all mein Wollen mir nicht.\r\nDann ward das Geheimnis der Vorsehung mir\nim göttlichen Lichte enthüllt.\nDa rief ich anbetend: Mein Gott, Du bist hier,\nnun ist meine Sehnsucht gestillt.\nIch wähnte Dich fern; doch warst Du stets nah.\nIn allem warst Du, was je mir geschah.\nDie Perle, sie blieb mir auch jetzt noch verwehrt,\nso heiß auch mein Herz sie begehrt.\nDas Gefühl Deiner Nähe tut\'s nicht,\ndas leichter als Scherben zerbricht.\nGefühle vergehen, wie Wolken verwehen.\nDer Glaube gibt ewiges Licht.\r\nNun weiß ich im Glauben: Du wohnest in mir,\ndie Quelle der Weisheit und Macht.\nSo lässt meine Seele vertrauend sich Dir,\nso ist sie zur Ruhe gebracht.\nDein Leben durchdringt den innersten Grund\nbeständig und hält die Seele gesund.\nNun wird mir die Perle nicht länger verwehrt,\nder Herr hat mein Flehen erhört.\nIm Glauben erfasse ich Dich.\nIm Glauben durchwohnest Du mich.\nWenn Wissen und Wollen und Fühlen zerbricht,\nder Herr bleibt mein ewiges Licht.'),
(9, '0888', 'Ich möchte es jedem verkünden   (Ich bin selig schon hier, ewig Anbetung Dir)', NULL, 'Ich möchte es jedem verkünden,\nwas Du für mich, Jesus, vollbracht.\nIch habe Vergebung der Sünden,\nErlösung von all ihrer Macht.\r\nIch bin selig schon hier;\newig Anbetung Dir!\nDu, Herr, bist mein Teil,\nDu gibst völliges Heil;\newig Anbetung Dir !\r\nIch bin jetzt so glücklich hienieden\nund blicke zur Welt nicht zurück;\nich habe, o Herr, Deinen Frieden,\nin Dir auch ein ewiges Glück.\r\nIch habe  den Himmel gefunden\nin Dir, o Herr Jesus, in Dir.\nNun kann meine Seele gesunden;\nDu wohnst ja, mein Heiland, in mir.'),
(9, '0889', 'Ich möchte mehr von Jesus, mehr und mehr und mehr  -  I want more of Jesus, more and more and more   (Chorus)', 'I want more of Jesus, more and more and more,\nI want more of Jesus, than I\'ve ever had befor.\nI wont more of His great love, so rich, so full and free.\nI want more of Jesus, so I\'ll give Him more of me.', 'Ich möchte mehr von Jesus, mehr und mehr und mehr,\nich möchte mehr von Jesus, das wünsche ich mir so sehr.\nIch möchte mehr von seiner Gnad\', von seinem Liebessinn.\nIch möchte mehr von Jesus, drum\' geb\' ich mich ihm hin.'),
(9, '0890', 'Ich möchte sein wo Du bist  -  I just wanna be where You are   (Ich möchte sein wo Du bist)', 'I just wanna be where You are,\ndwelling daily in Your presence\nI don\'t want to worship from afar,\ndraw me near to where You are\r\nI just wanna be where You are,\ndwelling daily in Your Presence.\nI don\'t want to worship from afar,\ndraw me close to where You are.\nI wanna be where You are,\ndwelling in Your Presence,\nfeasting at Your table,\nsurrounded by Your Glory.\nIn Your Presence that\'s\nwhere I always want to be,\nI just want to be with You.\r\nI just wanna be where You are,\nto enter boldly in Your presence\nI don\'t want to worship from afar,\ndraw me near to where You are\r\nOh, my God,\nYou are my strength and my song\nAnd when I\'m in Your presence\nThough I\'m weak You\'re always strong', '|: Herr ich möchte sein, wo Du bist,\nin Deiner Gegenwart verweilen!\nBring mich an den Ort wo Du bist!\nHerr ich möchte bei Dir sein! :|\r\nIch möchte sein wo Du bist\nHerr in deiner Nähe\nGemeinschaft mit Dir haben\nin Deinem Heiligtum!\nIn Deiner Nähe, in der ich immer möchte sein\nHerr ich möchte bei Dir sein!\r\n\r\n'),
(9, '0891', 'Ich möchte sein, wie Jesus mich möchte sehn - (Jesus liebte mich als ich nicht liebenswert war)', '\r\nI want to live the way He wants me to live.\nI want to give until there\'s just no more to give.\nI want to love, love \'til there\'s just no more love.\nFor I could never, ever outlove the Lord.\r\n\r\n', 'Jesus liebte mich als ich nicht liebenswert war,\nwo verirrt und tief unten im Schlamme ich war.\nSeine Hand zog heraus mich aus Hölle und Nacht.\nJesu Liebe hat alles vollbracht.\r\nIch möchte sein, wie Jesus mich möchte seh\'n,\nich möchte tun, was Er mich stets heißet zu tun.\nIch möchte warten in Liebe auf Jesus allein.\nGib mir Liebe, Dich zu sehen allein.\r\nBin nicht das, was ich früher war ohne Ihn;\nbin noch nicht, was ich heute gern wäre vor Ihm.\nJa, doch eines weiß ich, das ich werde sein\nwie die Lilie so fleckenlos rein.\r\nDiese Liebe, o schenke sie Du mir in\'s Herz;\nDich zu lieben, ist mehr als die ganze Welt wert.\nLass die Dinge, die groß sind, mir werden so klein.\nGib mir Liebe, Dich zu sehen allein!'),
(9, '0892', 'Ich muss Jesus bei mir haben  -  I must have the Saviour with me   (Dann erst fürchte ich kein Leid, Jesus führt mich allezeit)', 'I must have the Saviour with me,\nfor I dare not walk alone.\nI must feel His presence near me,\nand His arm around me thrown.\r\nThen my soul shall fear no ill.\nLet him lead me where he will,\nI will go without a murmur,\nand his footsteps follow still.\r\nI must have the Saviour with me,\nfor my faith at best is weak.\nHe can whisper words of comfort\nthat no other voice can speak.\r\nI must have the Saviour with me,\nand His eye the way must guide.\nTill I reach the vale of Jordan,\ntill I gain the other side.', 'Ich muss Jesus bei mir haben,\ndenn ich kann allein nicht geh\'n.\nIch muss Seine Näh\' verspüren,\nSeine Lieb\' muss mich umweh\'n.\r\nDann erst fürchte ich kein Leid,\nJesus führt mich allezeit.\nIch will folgen ohne Klagen,\nwill Ihm folgen allezeit.\r\nIch muss Jesus bei mir haben;\nsteil und rauh ist oft die Bahn.\nEr allein nur kann mich trösten,\nwie sonst niemand trösten kann.\r\nIch muss Jesus bei mir haben,\ndass Sein Auge auf mir ruht,\nbis ich komm\' zum Todesjordan,\nbis ich schreite durch die Flut.'),
(9, '0893', 'Ich nehm\' meine Harfe von dem Weidenbaum  -  I\'m taking my Harp down from off the willow Tree   (Chorus)', 'I\'m taking my harp down from off the willow tree.\nAnd now I am singing, the victory.\nMy past is forgiven, my home is in Heaven.\nAll sorrow is gone, the victory\'s won,\nand now I am free.', 'Ich nehm\' meine Harfe von dem Weidenbaum,\nund nun singe ich von dem Sieg allein.\nDie Schuld ist vergeben, mein Heim ist im Himmel,\ndie Sorgen sind fort, der Sieg ist nun mein,\nund nun bin ich frei.'),
(9, '0894', 'Ich preise den Herrn   (Chorus)', NULL, 'Ich preise den Herrn,\nIch preise den Herrn.\nPreis Gott, Er sorgt auch für mich.\nEr führt mich zu sich,\nwenn ich wandle mit Ihm.\nIch will singen und preisen den Herrn.'),
(9, '0895', 'Ich sag ja, ja, ja   -  I\'ll say yes, yes, yes   (Chorus)', 'I\'ll say yes, yes, yes.\nI\'ll say yes, yes, yes.\nI\'ll say yes, Lord.\nI\'ll say yes, Lord.\nI\'ll say yes, yes, yes.', 'Ich sag Ja, Ja, Ja.\nIch sag Ja, Ja, Ja.\nIch sag Ja, Herr.\nIch sag Ja, Herr.\nIch sag Ja, Ja, Ja.'),
(9, '0896', 'Ich sage Jesus all meine Sorgen  -  I must tell Jesus all of my Trials   (Ich sag es Jesus, ich sag es Jesus)', 'I must tell Jesus all of my trials,\nI cannot bear these burdens alone.\nIn my distress He kindly will help me,\nHe ever loves and cares for His own.\r\nI must tell Jesus! I must tell Jesus!\nI cannot bear my burdens alone.\nI must tell Jesus! I must tell Jesus!\nJesus can help me, Jesus alone.\r\nI must tell Jesus all of my troubles,\nHe is a kind, compassionate friend.\nIf I but ask Him, He will deliver,\nmake of my troubles quickly an end.\r\nTempted and tried, I need a great Saviour,\none who can help my burdens to bear.\nI must tell Jesus, I must tell Jesus,\nHe all my cares and sorrows will share.\r\nO how the world to evil allures me,\no how my heart is tempted to sin!\nI must tell Jesus, and He will help me\nover the world the vict\'ry to win.', 'Ich sage Jesus all meine Sorgen,\ndenn es versteht mich keiner wie Er.\nIn allen Nöten hilft Er mir gerne,\nimmer sorgt Er und liebt mich so sehr.\r\nIch sag\' es Jesus, ich sag\' es Jesus,\ndenn es versteht mich keiner wie Er.\nIch sag\' es Jesus, ich sag\' es Jesus,\nJesus kann helfen, Jesus nur Er!\r\nIch sage Jesus all mein Versagen,\ndenn Er fühlt mit mir und vergibt gern.\nWenn wir Ihn bitten von ganzem Herzen,\nschenkt Er Befreiung, macht alles neu.\r\nIn der Versuchung, Jesus ich brauch Dich,\nstarker Erlöser, Jesus mein Herr.\nIch sag es Jesus, ich sag es Jesus,\nEr sorgt für mich und bringt mich hindurch.\r\nLockt auch die Welt mit all ihrem Treiben\nund möcht\' mich ziehen vom Heiland fort.\nSag ich es Jesus und Er hilft gerne,\nschenkt Siegeskraft mir über die Welt.'),
(9, '0897', 'Ich sah Lieb, Gnade und Huld  -  I saw Love, Mercy and Grace   (Chorus)', 'I saw love, mercy and grace,\nI saw love, mercy and grace.\nI envisioned His beauty and looked on His face.\nI saw love, mercy and grace.', 'Ich sah Lieb\', Gnade und Huld,\nich sah Lieb\', Gnade und Huld.\nIch sah Seine Schönheit und schaute auf Ihn.\nIch sah Lieb\', Gnade und Huld.'),
(9, '0898', 'Ich sah Seine Hände durchbohrt für mich Sünder   (Chorus)', NULL, 'Ich sah Seine Hände durchbohrt für mich Sünder,\nich sah Seine Füße geheftet ans Kreuz,\ndann sah ich Sein Haupt und verwundete Seite;\nund nun lieb\' ich Jesus und Jesus liebt mich.'),
(9, '0899', 'Ich sing von meinem Jesus, der mich mit Gnade krönt', NULL, 'Ich sing von meinem Jesus, der mich mit Gnade krönt.\nIn Ihm wohnt alle Fülle, Er, Er hat mich versöhnt.\nIch sing von meinem Jesus, dem teuren Gotteslamm,\nder sich für mich gegeben und starb am Kreuzesstamm.\r\nIch sing von meinem Jesus und ruh\' an Seiner Brust.\nDa werd\' ich Seiner Liebe, mir inniglich bewusst.\nIch sing von meinem Jesus, bei aller Angst der Welt.\nIch sing von Seiner Gnade, die mich bei Ihm erhält.\r\nIch sing von meinem Jesus und strecke mich nach dem,\nwas droben ist im Himmel, im Neu-Jerusalem.\nUnd wenn einst meine Seele, aus Gnaden dort einzieht,\nso sing ich meinem Jesus ein neues, ew\'ges Lied.'),
(9, '0900', 'Ich singe Dir mit Herz und Mund  -  I\'ll praise Thee with my Heart and Tongue', 'I\'ll praise Thee with my heart and tongue,\no Lord, my soul\'s delight,\ndeclaring to the world in song\nThy glory, praise and might.\r\nThou art th\'eternal source of grace,\nthe fount of lasting bliss;\nfrom Thee unto the human race\nflows all true happiness.\r\n\r\n\r\nThy chastisements are nought but love;\nwhen we our sins confess,\nwe Thy forgiveness richly prove;\n\'tis Thy delight to bless.\r\n\r\nGod never yet mistake hath made\nin his vast government;\nand all he doth permit or aid\nis blest in the event.\r\nThen murmur not, but be resigned\nto His most holy will;\npeace, rest and comfort thou wilt find,\nmy soul, in being still.', 'Ich singe Dir mit Herz und Mund,\nHerr, meines Herzens Lust.\nIch sing und mach auf Erden kund,\nwas mir von Dir bewusst.\r\nIch weiß, dass Du der Brunn\' der Gnad\'\nund ew\'ge Quelle bist,\ndaraus uns alllen früh und spat\nviel Heil und Gutes fließt.\r\nWas sind wir doch?  Was haben wir\nauf dieser ganzen Erd\',\ndas uns, o Vater, nicht von Dir\nallein gegeben werd\'?\r\nDu nährest uns von Jahr zu Jahr,\nbleibst immer fromm und treu\nund stehst uns, wenn wir in Gefahr\ngeraten, treulich bei.\r\nDu strafst uns Sünder mit Geduld\nund schlägst nicht allzu sehr;\nja, endlich nimmst Du unsre Schuld\nund wirfst sie in das Meer.\r\nWohlauf, mein Herze, sing und spring\nund habe guten Mut!\nDein Gott, der Ursprung aller Ding,\nist selbst und bleibt dein Gut.\r\nEr hat noch niemals was verseh\'n\nin Seinem Regiment;\nnein, was Er tut und lässt gescheh\'n,\ndas nimmt ein gutes End\'.\r\nEi nun, so lass Ihn ferner tun\nund red\' Ihm nicht darein,\nso wirst du hier in Frieden ruh\'n\nund ewig selig sein.'),
(9, '0901', 'Ich sinke still und anbetend, vor Jesus dem König hin  -  I stand amazed in the Presence of Jesus the Nazarene   (O wie wunderbar, o wie wunderbar)   [Pfingstjubel]', 'I stand amazed in the presence\nof Jesus the Nazarene.\nAnd wonder how He could love me,\na sinner condemned, unclean.\r\nO how marvelous! O how wonderful!\nAnd my song shall ever be:\nO how marvelous! O how wonderful!\nIs my Saviour’s love for me!\r\nFor me it was in the garden,\nHe prayed: “Not my will, but Thine.”\nHe had no tears for His own griefs,\nbut sweat-drops of blood for mine.\r\nHe took my sins and my sorrows,\nHe made them His very own.\nHe bore the burden to Calv’ry,\nand suffered, and died alone.\r\nWhen with the ransomed in glory,\nHis face I at last shall see.\n’Twill be my joy through the ages,\nto sing of His love for me.', 'Ich sinke still und anbetend\nvor Jesus, dem König, hin;\nwie konnte Er mich nur lieben,\nder ich unrein, sündig bin!\r\nO wie wunderbar, o wie wunderbar,\nimmer wieder rüh\'m ich\'s neu,\no wie wunderbar, o wie wunderbar,\nist des Heilands Liebestreu!\r\nFür mich hat Jesus gebetet:\nNicht mein, nein, Dein Will gescheh\'!\nEr weinte nicht um Sich selber,\ndoch für mich trug Er das Weh.\r\nDen Fluch musst Er für mich tragen,\nEr ging in die Schmach, den Tod,\nfür mich, den schuldigen Sünder,\ntat Er es, der heilige Gott!\r\nWenn droben mit den Erlösten\nich einst seh\' Sein Angesicht,\nso preis ich laut Seine Liebe\nim ewigen Himmelslicht.'),
(9, '0902', 'Ich staune die nie zu begreifende Liebe an  -  I stand all amazed at the Love Jesus offers me   (O, das ist wunderbar, dass Jesus nach mir fragt)', 'I stand all amazed at the love Jesus offers me,\nconfused at the grace that so fully He proffers me.\nI tremble to know that for me He was crucified,\nthat for me, a sinner, He suffered, He bled, and died.\r\nO it is wonderful, that He should care for me,\nenough to die for me!\nO it is wonderful, wonderful to me.\r\nI marvel that He would descend from His throne divine\nTo rescue a soul so rebellious and proud as mine;\nThat He should extend His great love unto such as I -\nSufficient to own, to redeem and to justify.\r\nI think of His hands pierced and bleeding to pay the debt!\nSuch mercy, such love and devotion can I forget?\nNo, no! I will praise and adore at the mercy-seat,\nuntil at the glorified throne I kneel at His feet.', 'Ich staune die nie zu begreifende Liebe an,\ndie Gnade beschämt mich, die so viel für mich getan.\nIch zittre, bedenk\' ich, dass Jesus gekreuzigt ist,\nfür mich, für mich Sünder, für mich Er sich schlagen ließ.\r\nO, das ist wunderbar, dass Jesus nach mir fragt,\nhat Er Sein Leben doch für mich am Kreuz gewagt.\nWunderbar ist das!\r\nIch staune, dass Er aus dem Himmel hernieder kam,\nsich meines rebellischen Herzens so treu annahm,\nja dass Seine Liebe sich wirklich auf mich erstreckt,\nmich rettet, erlöset, mit Kleidern des Heil\'s bedeckt.\r\nIch schau Seine rettenden, blutenden Hände an!\nSein Opfer an meiner Statt nie ich vergessen kann!\nAnbetend will ich Ihn nun preisen am Gnadenthron,\nbis dass ich Ihn schaue, den herrlichen Gottessohn.'),
(9, '0903', 'Ich steh am stürm\'schen Jordanstrand  -  On Jordan\'s stormy Banks I stand   (Mich ziehts ins verheißne Land)', 'On Jordan\'s stormy banks I stand\nand cast a wishful eye.\nToward Canaan\'s fair and happy land\nwhere my possessions lie.\r\nI am bound for the promised land,\nI am bound for the promised land.\nOh, who will come and go with me?\nI am bound for the promised land.\r\nO\'er all those wide extended plains\nshines one eternal day.\nThere God the Son forever reigns,\nand scatters night away.\r\nNo chilling winds, nor pois\'nous breath,\ncan reach that healthful shore.\nSickness and sorrow, pain and death,\nare feared and felt no more.\r\nWhen shall I reach that happy place,\nand be forever blest!\nWhen shall I see my Father\'s face,\nand in His bosom rest!', 'Ich steh\' am stürm\'schen Jordanstrand\nund schau voll Sehnsucht aus.\nNach dem verheiß\'nen schönen Land,\ndenn dort ist mein Zuhaus.\r\nMich zieht\'s in\'s verheiß\'ne Land,\no mich zieht\'s  in\'s verheiß\'ne Land.\nHast du Sehnsucht auch dort hinzugeh\'n?\nMich zieht\'s in\'s verheiß\'ne Land.\r\nIn diesem wunderschönen Land\ndie Sonne immer scheint.\nDenn unser Herr ist Selbst das Licht\nund niemand dort mehr weint.\r\nNicht Krankheitsnot noch Todesangst\nwird dort zu finden sein.\nAuch Sorgen drücken mich nicht mehr,\nich bin nie mehr allein.\r\nWenn ich dann endlich dort eingeh\'\nin meines Vaters Haus.\nDann darf ich seh\'n Sein Angesicht\nund ruhe bei Ihm aus.'),
(9, '0904', 'Ich steh beglückt vor dem Heiland  -  I stand amazed in the Presence of Jesus the Nazarene   (O wie wunderbar, o wie gnadenreich)   [Siegesklänge]', 'I stand amazed in the presence\nof Jesus the Nazarene,\nAnd wonder how He could love me,\na sinner, condemned, unclean.\r\nO how marvelous! O how wonderful!\nAnd my song shall ever be:\nO how marvelous! O how wonderful!\nIs my Saviour’s love for me!\r\nFor me it was in the garden\nHe prayed: "Not My will, but Thine."\nHe had no tears for His own griefs,\nbut sweat drops of blood for mine.\r\nIn pity angels beheld Him,\nand came from the world of light.\nTo comfort Him in the sorrows,\nHe bore for my soul that night.\r\nWhen with the ransomed in glory\nHis face I at last shall see,\n’Twill be my joy through the ages\nTo sing of His love for me.', 'Ich steh\' beglückt vor dem Heiland\nund schau Ihn verwundert an.\nIch staune, wie Er mich Sünder\nvoll Flecken noch lieben kann.\r\nO wie wunderbar! O wie gnadenreich!\nSo sing ich schon selig hier.\nO wie wunderbar! O wie gnadenreich!\nist die Liebe Jesu mir!\r\nFür mich litt Er in dem Garten\nund flehte so tief betrübt.\nDer Sieg, den Er dort erstritten,\nmir Sünder den Frieden gibt.\r\nVoll Mitleid sah\'n Ihn die Engel,\nals betend Er niedersank.\nDoch bin ich heil, weil Er gerne\nden Kelch jener Leiden trank.\r\nWenn einst die Schar der Erlösten\nanbetend vor Jesus kniet,\ndann preis auch ich Seine Liebe\nund singe das neue Lied.'),
(9, '0905', 'Ich steh voll Ehrfurcht in der Gegenwart des Herrn  -  I stand in Awe within the Presence of the Lord   (Oh Herr, ich trau auf Dich)', 'I stand in awe within the presence of the Lord\nin whom the wisdom of the ages lies,\nfor whom the raging of the sea subsides\nthe living Sacrifice, the only Source of Life.\r\nMy Hope is in the Lord\nfrom this time on and evermore.\nO my Hope is in the Lord\nforevermore.\r\nHis tender mercies come with ev’ry rising sun\nto meet the sinner in his brokenness,\nto offer healing and forgiveness,\nand those who trust in Him\nwill find their hearts at rest.', 'Ich steh voll Ehrfurcht in der Gegenwart des Herrn,\nin Ihm ruht Weisheit, die kein Mensch begreift.\nAuf Sein Gebot beruhigt das Meer sich schnell,\nlebend\'ges Opferlamm, Er ist die Lebensquell\'.\r\nOh Herr, ich trau auf Dich,\nvon heute an und ewiglich,\nOh mein Herr, ich trau auf Dich\newiglich.\r\nSein Gnadenreichtum kommt mit jedem Sonnenstrahl\nund hilft dem Sünder tief in seiner Not.\nEr bietet Heilung und Vergebung an,\nund dem, der Ihm vertraut,\nschenkt er das Lebensbrot.'),
(9, '0906', 'Ich trau auf Dich o Herr   (Chorus)', NULL, 'Ich trau auf Dich, oh Herr.\nIch sage: "Du bist mein Gott."\nIn Deiner Hand steht meine Zeit,\nin Deiner Hand steht meine Zeit.\nGelobet sei der Herr,\ndenn Er hat wunderbar,\nSeine Liebe mir erwiesen\nund Güte mir gezeigt.'),
(9, '0907', 'Ich traue ganz meinem Herrn all mein Leben lang  -  I just keep trusting my Lord, as I walk along   (Solch ein treuer Freund)', 'I just keep trusting my Lord,\nas I walk along.\nI just keep trusting my Lord,\nas He gives me a song.\nThough the storm clouds darken the sky\nov\'r the heavenly trail.\nI just keep trusting my Lord\nHe will never fail.\r\nHe’s a faithful friend,\nsuch a faithful friend.\nI can count on him to the very end.\nThough the storm clouds darken the sky\nov\'r the heavenly trail.\nI just keep trusting my Lord,\nHe will never fail!\r\nI just keep trusting my Lord,\non the narrow way.\nI just keep trusting my Lord,\nas He leads each day.\nThough the road is weary at times,\nand I\'m sad and blue.\nI just keep trusting my Lord,\nhe will see me through!\r\nHe’s a faithful friend,\nsuch a faithful friend.\nHe is always there,\nwalking by my side.\nThough the road is weary at times,\nand I\'m sad and blue.\nI just keep trusting my Lord,\nhe will see me through!', 'Ich traue ganz meinem Herrn,\nall mein Leben lang,\nich traue ganz meinem Herrn,\ndies ist mein Gesang!\nOb auch Stürme gegen mich sind,\nGott bestimmt auch sie.\nIch traue ganz meinem Herrn,\nEr verlässt mich nie!\r\nSolch ein treuer Freund,\nja, ein treuer Freund,\nhat in Ewigkeit sich mit mir vereint!\nOb auch Stürme gegen mich sind,\nGott bestimmt auch sie.\nIch traue ganz meinem Herrn,\nEr verlässt mich nie!\r\n\r\n'),
(9, '0908', 'Ich trieb mit dem Strome dieses Lebens   (Ein Adler, Er rief aus den Himmeln)', NULL, 'Ich trieb mit dem Strome dieses Lebens\nund groß war die Lehre in mir.\nWas ich auch versucht\' war vergebens,\ndoch jemand hielt Ausschau nach mir.\nIch war weit entfernt von der Weide,\nein Schaf, ein ganz hilfloses Tier.\nSo war ich allein auf der reise,\ndoch jemand hielt Ausschau nach mir.\r\nEin Adler, Er rief aus den Himmeln\nder Same in mir wurde wach.\nIch sprach: "Herr, komm zu mir,\nich seh\'n mich nach Dir.\nSprich Du, und ich schwinge mich auf!"\r\nDas Wort Seiner Gnade ich hörte,\ndoch war kein Erkennen in mir.\nSein Wort war für mich noch versiegelt,\ndoch jemand hielt Ausschau nach mir.\nIm Hühnerhof war ich nicht glücklich,\nich wusste nicht, was steckt in mir.\nDoch ward alles klar augenblicklich,\nals jemand hielt Ausschau nach mir.\r\nMein Freund, bist auch du ganz am Boden,\nes geht dir genauso wie mir.\nDu brauchst nicht im Hühnerhof wohnen,\ndenn jemand hält Ausschau nach dir.\nSein Blut gab auch dir neues Leben,\nund Jesus wird kommen zu dir.\nLass dich heut\' zum Kreuz doch bewegen,\ndenn jemand hält Ausschau nach dir.\r\nEin Adler, Er ruft aus den Himmeln,\nder Same in dir wird heut\' wach.\nDu sagst: "Herr, komm zu mir,\nich sehn\' mich nach Dir.\nSprich Du, Herr, ich nehme Dich auf!"'),
(9, '0909', 'Ich und mein Haus - Me and my house (Ich schau auf die Welt um mich her)', 'In this world of darkness and sin,\nIn this world that I\'m living in\nI have made a definite choice:\nI will follow God and His Voice!\r\nYes, me and my house,\nMe and my house,\nWe will serve the Lord ( 2x)\r\nI can see a great promised land,\nI can see my mountain of faith,\nI will fight and on it I\'ll stand,\nFor I\'m walking by my Lord\'s Grace!\r\nI will keep my eyes in Calvary,\nWhere my Lord and Saviour died for me,\nI will keep my eyes on Calvary,\nI can hear His cry of Victory!\r\nYou can do whatever you want,\nEven doubt the things I believe,\nI\'ll have faith and I will go on,\nI will have a full victory!', 'Ich schau auf die Welt um mich her,\nFinsternis liegt auf ihr so schwer,\ndoch ich bleibe nicht in der Nacht,\nich hab‘ für mich selbst festgemacht:\r\nIch und mein Haus,\nich und mein Haus,\nwir dienen unserm Herrn! (2x)\r\nUnd weil ich mich Gott zugewandt,\nseh‘ ich mein verheißenes Land,\nhab‘ mein Erbteil fest jetzt im Blick,\nford’re es vom Feind mir zurück!\r\nIch heb‘ meinen Blick nach Golgatha,\nwo der allergrößte Sieg geschah,\nwo mein Jesus rief: "Es ist vollbracht!"\nwo Er siegte über jede Macht!\r\nUnd wenn and’re Gott nicht versteh’n,\nIhn anzweifeln und von Ihm geh’n -\nfür mich gibt es nur einen Weg:\nIch dräng‘ vorwärts in Gottes Sieg!'),
(9, '0910', 'Ich verlor bei Menschen Ehre seit ich floh von Welt und Sünd  -  I have lost my Reputation since I turned my back on Sin   (Ich falle auf überall, bin offenbar wo immer ich bin)', 'I have lost my reputation since I turned my back on sin.\nAnd a lot of friends went from me since I let my Saviour in.\nNow they pass me by unknown, when they once passed with a smile.\nNow they say I\'m very foolish, and they say I\'m out of style.\r\nI am marked, marked, marked, I am marked now wherever I go.\nI am marked, marked, marked, just what I am everyone seems to know.\nI am sealed, sealed, sealed, I am sealed by His Spirit Divine.\nO glory to God! Hallelujah! Amen! I am His, and I know he is mine.\r\nWell, they say my life is ruined, and my talent thrown away.\nAnd they cannot understand it, for I had such plans one day.\nBut I know what I surrendered when I promised I\'d go through.\nAnd I gained far more glory since God made me over new.', 'Ich verlor bei Menschen Ehre seit ich floh von Welt und Sünd\'.\nViele Freunde mich verließen, weil ich bin ein Gotteskind.\nFür sie wurd\' ich wie ein Fremder, damals noch so hoch geschätzt,\nund sie sagen ich wär\' töricht und aus dieser Welt versetzt.\r\nIch falle auf überall, bin offenbar wo immer ich bin.\nich falle auf überall, jeder sieht meinen anderen Sinn.\nVersiegelt für alle Zeit, versiegelt im Heiligen Geist.\nO Ehre sei Gott, Halleluja, Amen.\nIch bin sein und ich weiß, Er ist mein.\r\nGanz zerstört sei nun mein Leben und verspielt sei mein Talent.\nWie könnt ich denn nur verwerfen, was die Welt so wichtig nennt.\nDoch so gern ich Jesus weihe voller Freude alles dies,\ndenn ich erbe viel mehr Freude hier und dann im Paradies.'),
(9, '0911', 'Ich vermag all Dinge in Ihm, der mir Kraft gibt', NULL, 'Ich vermag alle Dinge\nin Ihm, der mir Kraft gibt,\nich vermag alle Dinge in Ihm.\nIch vermag alle Dinge,\nin Ihm, der mir Kraft gibt,\nich vermag alle Dinge in Ihm.\nIch vermag alle Dinge in Ihm,\nalles in Ihm, ja alles in Ihm.\nIch vermag alle Dinge in Ihm,\nich vermag alle Dinge in Ihm.'),
(9, '0912', 'Ich wandle den Hochweg der Herrlichkeit zu   (Ehre dem Lamm, Es hat mich befreit)', NULL, 'Ich wandle den Hochweg der Herrlichkeit zu,\nmich leitet Sein heiliger Geist.\nEr füllt mir die Seele mit himmlischer Ruh\',\ndass jubelnd den Heiland sie preist.\r\nEhre dem Lamm! Es hat mich befreit,\nwandle nun durch die Wüste der Zeit\nmit Singen und Jubeln zur Herrlichkeit,\nwo ewig den König ich schau!\r\nIch wandle den Hochweg der Herrlichkeit zu\nund rufe die Sünder herbei:\n"Der Heiland, Er liebt dich, o Sünder, auch du\nsollst wandeln so herrlich und frei!"\r\nIch wandle den Hochweg zur Herrlichkeit hin,\nmein Glück ruht in Ihm nur allein;\nund wenn ich daheim bei dem Vater einst bin,\nwie wird es da herrlich erst sein!'),
(9, '0913', 'Ich war fern von zu Haus, tief verstrickt im Sündgebraus', NULL, 'Ich war fern von zu Haus,\ntief verstrickt im Sündgebraus,\nganz verzweifelt und ohne Hoffnungslicht.\nWas die Welt mir auch bot\nSeelenfrieden gab sie nicht,\nund ich suchte bis mir Rettung ward.\r\nJesus bleibt wie Er war,\ngestern, heut\' und allezeit!\nSeine Liebe und Gnade bleibt besteh\'n!\nSein Wort hält Er gewiss\nEr treibt fort die Finsternis.\nGlaub\' es nur - Jesus rettet Dich!\r\nJetzt leb\' ich mit dem Herrn,\ndenn Er hat mich frei gemacht.\nMeine Sünden nahm Er ganz auf sich.\nNicht ich suchte Ihn,\nsondern Er suchte sein Kind.\nSeine Liebe ist grenzenlos und wahr!\r\nUnd auch heut\' sucht er doch\nnach Verirrten immer noch.\nHoffnung ist auch für Dich, lieber Freund!\nJesus ändert sich nicht!\nGlaub\' es nur, zweifle nicht!\nJesus liebt dich, Er wartet jetzt auf Dich!'),
(9, '0914', 'Ich war froh, als man sagte zu mir: "Lasst uns geh\'n zum Hause des Herrn!"  -  I was glad, when they said unto me: "Let us go to the House of the Lord!"', 'I was glad, when they said unto me:\n"Let us go to the House of the Lord!"\nI was glad, when they said unto me:\n"Let us go to the House of the Lord!"\r\n\r\n', 'Ich war froh, als man sagte zu mir:\n"Lasst uns geh\'n zum Hause des Herrn!"\nIch war froh, als man sagte zu mir:\n"Lasst uns geh\'n zum Hause des Herrn!"\r\nDenn dort ist Hilfe bereit\nfür Seele, Geist und Leib,\nein Licht der Ewigkeit\nfür den ganzen Menschen,\nich gehe hin, ich hör\' zu,\nich sage: "Herr, rede Du!",\nempfange Hilfe im Nu\nfür den ganzen Menschen!\r\nEs kommen Menschen hierher,\ndoch ist es Dein Haus, oh Herr,\nDu lässt die Herzen nicht leer\nnach Hause gehen!\nUnd was uns Segen verheißt\nund uns die Richtung heut\' weist,\ndas ist Dein Heiliger Geist\nim Haus des Herrn!'),
(9, '0915', 'Ich war verirrt, doch Herr Du fandst mich   (O Herr, ich danke, o Herr, ich danke)', NULL, 'Ich war verirrt, doch Herr, Du fand\'st mich,\nich war verirrt, doch Herr, Du fand\'st mich,\nich war verirrt, doch Herr, Du fand\'st mich,\nund ich danke Dir dafür allezeit.\r\nO Herr, ich danke, o Herr, ich danke,\nich danke Dir dafür allezeit.\nO Herr, ich danke, o Herr, ich danke,\nich danke Dir dafür allezeit.\r\nIn Krankheitsnot, o Herr, Du heilst mich,\nin Krankheitsnot, o Herr, Du heilst mich,\nin Krankheitsnot, o Herr, Du heilst mich,\nund ich danke Dir dafür allezeit.\r\nDurch Deinen Geist werd\' neu ich werden,\ndurch Deinen Geist werd\' neu ich werden,\ndurch Deinen Geist werd\' neu ich werden,\nund ich danke Dir dafür allezeit.\r\nDein Wort ist meines Fußes Leuchte,\nDein Wort ist meines Fußes Leuchte,\nDein Wort ist meines Fußes Leuchte,\nund ich danke Dir dafür allezeit.'),
(9, '0916', 'Ich weiß das Jesus zurück kommt an dem Morgen   (Chorus)', NULL, 'Ich weiß, dass Jesus zurück kommt an dem Morgen.\nIch weiß, dass Jesus zurück kommt auch für mich!\nIch weiß, Ich weiß, Ich weiß, Er kommt zurück am Morgen.\nIch weiß, Ich weiß, Ich weiß, Er kommt zurück für mich!'),
(9, '0917', 'Ich weiß der Herr hat einen Weg für mich  -  I know the Lord will make the Way for me   (2 Chorusse)', 'I know the Lord will make the way for me,\nI know the Lord will make the way for me.\nTrust Him firmly and do not doubt!\nHe will be my way and light.\nI know the Lord will make the way for me.', 'Ich weiß, der Herr hat einen Weg für mich,\nich weiß, der Herr hat einen Weg für mich.\nTrau Ihm nur und zweifle nicht!\nEr wird Weg mir sein und Licht.\nIch weiß, der Herr hat einen Weg für mich.'),
(9, '0918', 'Ich weiß einen Strom dessen herrliche Flut  -  Oh, have you not heard of that beautiful Stream   (O Seele, ich bitte dich: Komm / O seek that beautiful Stream)', 'Oh, have you not heard of that beautiful stream\nthat flows through the promised land?\nIts waters gleam bright in the heavenly light,\nand ripple o’er golden sand.\r\nO seek that beautiful stream,\no seek that beautiful stream.\nIts waters, so free, are flowing for thee,\no seek that beautiful stream.\r\nWith murmuring sound doth it wander along,\nthrough fields  of eternal green.\nWhere songs of the blest in their heaven of rest,\nfloat soft on the air serene.\r\nIts fountains are deep and its waters are pure,\nand sweet to the weary soul.\nIt flows from the throne of Jehovah alone!\nO come where its bright waves roll.\r\nThis beautiful stream is the river of life,\nit flows for all nations free!\nA balm for each wound in its water is found,\no sinner, it flows for thee!\r\nOh, will you not drink of this beautiful stream,\nand dwell on its peaceful shore?\nThe Spirit says: Come, all ye weary ones home,\nand wander in sin no more.', 'Ich weiß einen Strom, dessen herrliche Flut\nfließt wunderbar stille durch\'s Land.\nDoch strahlet und glänzt er wie feurige Glut,\nwem ist dieses Wasser bekannt?\r\nO Seele, ich bitte dich: Komm!\nUnd such diesen herrlichen Strom!\nSein Wasser fließt frei und mächtiglich,\no glaub\'s, es fließet für dich!\r\nWohin dieser Strom sich nur immer ergießt,\nda jubelt und jauchzet das Herz,\ndas nunmehr den köstlichsten Segen genießt,\nerlöset von Sorgen und Schmerz.\r\nDer Strom ist gar tief, und sein Wasser ist klar,\nes schmecket so lieblich und fein,\nes heilet die Kranken und stärkt wunderbar,\nja machet die Unreinsten rein.\r\nDas Wasser des Lebens, das ist diese Flut,\ndurch Jesum ergießet sie sich.\nSein kostbares, teures und heiliges Blut,\no Sünder, vergoss Er für dich.\r\nWen dürstet, der komme und trinke sich satt,\nso rufet der Geist und die Braut.\nNur wer in dem Strome gewaschen sich hat,\ndas Angesicht Gottes einst schaut.'),
(9, '0919', 'Ich weiß es war das Blut  -  I know it was the Blood', 'I know it was the blood,\nI know it was the blood,\nI know it was the blood for me.\nOne day when I was lost,\nHe died upon the Cross,\nI know it was the blood for me.\r\nHe\'s coming back again,\nHe\'s coming back again,\nHe\'s coming back again for me.\nOne day when I was lost,\nHe died upon the Cross,\nHe\'s coming back again for me.', 'Ich weiß, es war das Blut,\nich weiß, es war das Blut,\nich weiß, es war das Blut für mich!\nAls ich verloren war,\nstarb Er auf Golgatha.\nIch weiß, es war das Blut für mich!\r\nIch weiß, Er kommt zurück,\nich weiß, Er kommt zurück,\nich weiß, Er kommt zurück für mich!\nAls ich verloren war,\nstarb Er auf Golgatha.\nIch weiß, Er kommt zurück für mich!'),
(9, '0920', 'Ich weiß nicht, wann Christus, mein König, erscheint  -  I know not the Hour when my Lord will come', 'I know not the hour when my Lord will come\nto take me away to His own dear home.\nBut I know that His presence will lighten the gloom,\nand that will be glory for me.\nAnd that will be glory for me,\noh, that will be glory for me!\nBut I know that His presence will lighten the gloom,\nand that will be glory for me.\r\nI know not the song that the angels sing,\nI know not the sound of the harps’ glad ring.\nBut I know there’ll be mention of Jesus our King,\nand that will be music for me.\nAnd that will be music for me,\noh, that will be music for me!\nBut I know there’ll be mention of Jesus our King,\nand that will be music for me.\r\nI know not the form of my mansion fair,\nI know not the name that I then shall bear.\nBut I know that my Saviour will welcome me there,\nand that will be Heaven for me.\nAnd that will be Heaven for me,\noh, that will be Heaven for me.\nBut I know that my Saviour will welcome me there,\nand that will be Heaven for me.', 'Ich weiß nicht, wann Christus, mein König, erscheint,\nmich zu sich zu rufen, da niemand es meint.\nDoch ich weiß ja, der kommende Heiland ist mein,\nund das wird unendlich, unendlich mich freu\'n.\nO, das wird unendlich, unendlich mich freu\'n!\nO, das wird unendlich, unendlich mich freu\'n!\nDenn ich weiß ja, der kommende Heiland ist mein,\nund das wird unendlich, unendlich mich freu\'n.\r\nIch weiß nicht, wie droben der Engelchor singt,\nund wie dort das himmlische Saitenspiel klingt.\nDoch ich weiß, dort wird Jesus das A und O sein,\nund da stimm\' ich jubelnd mit ein.\nO, da stimm\' ich jubelnd mit ein!\nO, da stimm\' ich jubelnd mit ein!\nDenn ich weiß, dort wird Jesus das A und O sein,\nund da stimm\' ich jubelnd mit ein.\r\nIch weiß nicht, wie Gottes Behausungen sind,\nund weiß nicht, welch\' Namen Er gibt seinem Kind.\nDoch ich weiß, Er hat alles bereitet gar fein,\nund das soll genügend mir sein!\nO, das soll genügend mir sein!\nO, das soll genügend mir sein!\nDenn ich weiß, Er hat alles bereitet gar fein,\nund das soll genügend mir sein!'),
(9, '0921', 'Ich weiß nicht, warum Gottes Gnad  -  I know not why God\'s wondrous Grace   (Doch ich weiß ja, an wen ich glaube)', 'I know not why God\'s wondrous grace\nto me He hath made known,\nnor why, unworthy, Christ in love\nredeemed me for His own.\r\nBut I know whom I have believed,\nand am persuaded that He is able.\nTo keep that which I\'ve committed,\nunto Him against that day.\r\nI know not how this saving faith\nto me He did impart.\nNor how believing in His Word\nwrought peace within my heart.\r\nI know not how the Spirit moves,\nconvincing men of sin.\nRevealing Jesus through the Word,\ncreating faith in Him.\r\nI know not what of good or ill\nmay be reserved for me.\nOf weary ways or golden days,\nbefore His face I see.\r\nI know not when my Lord may come,\nat night or noonday fair.\nNor if I\'ll walk the vale with Him,\nor meet Him in the air.', 'Ich weiß nicht, warum Gottes Gnad\'\nmir je ward offenbar,\nnoch warum ich erlöset bin,\nder ich ein Sünder war.\r\nDoch ich weiß ja, an wen ich glaube,\nund Seiner Hand kann mich nichts entreißen.\nMein Erbteil wird Er mir wahren\nauf den Tag, da Er erscheint.\r\nIch weiß nicht, wie die Glaubenskraft\nmein Gott mir mitgeteilt,\nnoch wie der Glaube an Sein Wort\nden Seelenschmerz geheilt.\r\nIch weiß nicht, wie der Heil\'ge Geist\nmich Sünder  überzeugt,\nwie Jesus Er in mir verklärt\nund alle Not verscheucht.\r\nIch weiß nicht, wie viel Not und Leid\nder Herr mir zugedacht,\nwie Er mich führt durch Licht und Nacht,\nbis einst mein Lauf vollbracht.\r\nIch weiß nicht, wann der Herr erscheint,\nweiß weder Tag noch Stund\',\nob durch den Tod Er rufen wird,\nob durch des Engel Mund.'),
(9, '0922', 'Ich weiß nicht, was der Tag mir bringt   (Und so erwart ich froh und still)', NULL, 'Ich weiß nicht, was der Tag mir bringt;\ndoch soll mir\'s d\'rum nicht grau\'n,\ndenn meine Seele hat gelernt,\nDir, Jesus, zu vertrau\'n.\r\nUnd so erwart ich froh und still,\nwas, Herr, Dein Wille von mir will.\nGewiss, Du führst mich durch die Zeit\nauf sich\'rem Weg zur Herrlichkeit.\r\nIch weiß nicht, was der Tag mir bringt,\ndoch das ist mir bewusst:\nDein Wort, und was es mir verheißt,\nbleibt meines Herzens Lust.\r\nIch weiß nicht, was der Tag mir bringt,\nob Freude oder Harm;\nich ruh\' bei allem wie ein Kind\nin meines Vaters Arm.\r\nIch weiß nicht, was der Tag mir bringt;\nvielleicht, Herr, bringt er Dich.\nJa, Dich, den König, anzuschau\'n,\ndazu bereite mich!'),
(9, '0923', 'Ich weiß, dass mein Erlöser lebt   (Er lebt [Er lebt], Er lebt [Er lebt])', NULL, 'Ich weiß, dass mein Erlöser lebt,\nund bald auch mich zu sich erhebt\nin jenes Reich des Lichts.\nEr lebt und mit ihm lebe ich,\ndas weiß ich nun und ewiglich.\nDies Wissen raubt mir nichts.\r\nEr lebt, Er lebt ,\nich weiß, dass mein Erlöser lebt.\nEr lebt , Er lebt ,\nich weiß, dass mein Erlöser lebt.\r\nIch weiß, dass mein Erlöser lebt,\nund dieses Wissen mich belebt.\nEs macht mich stark im Streit\nWohin mein Weg auch immer führt,\nOb’s licht ob‘s dunkel künftig wird.\nDies weiß ich alle Zeit:\r\nIch weiß, dass mein Erlöser lebt,\nauch wenn die ganze Erde bebt.\nDas tröstet mich im Leid.\nUnd wenn ich einst die Augen schließ‘,\nSo weiß ich eines ganz gewiss,\nEr lebt in Ewigkeit!\r\nIch weiß, dass mein Erlöser lebt,\nauch wenn der Abend sich erhebt\nund bald die Nacht anbricht.\nIch bin hier unten nicht zuhaus,\nbin Fremdling hier und wandre aus,\nsing einst verklärt im Licht.'),
(9, '0924', 'Ich weiß, mein Heiland liebet mich allein aus freier Gnad', NULL, 'Ich weiß, mein Heiland liebet mich\nallein aus freier Gnad\',\nEr opferte sich williglich\nam Kreuz an meiner Statt.\r\nEs spricht für mich Sein teures Blut\nSein Tod und Aufersteh\'n;\nwas Er verdient, kommt mir zugut,\nhilft mir aus allen Weh\'n.\r\nIn Ihm hab ich den Felsengrund,\nworauf ich bau\' und trau,\nmit Gott steh ich hier so im Bund,\nbis ich Ihn droben schau.'),
(9, '0925', 'Ich will Dich ehren, Herr  -  I will bless Thee, oh Lord   (2 Chorusse)', 'I will bless Thee, oh Lord,\nI will bless Thee, oh Lord.\nWith a heart of thanksgiving,\nI will bless Thee, oh Lord.\r\nWith my hands lifted up,\nand my heart filled with praise.\nWith a heart of thanksgiving,\nI will bless Thee, oh Lord.', 'Ich will Dich ehren, Herr,\nich will Dich ehren, Herr,\nmit dem Herzen voller Dank\nwill ich Dich ehren, Herr.\r\nMit meinen Händen erhoben\nund mein Herz voller Freud\',\nmit dem Herzen voller Dank\nwill ich Dich ehren, Herr.'),
(9, '0926', 'Ich will dich lieben, meine Stärke', NULL, 'Ich will Dich lieben, meine Stärke,\nich will Dich lieben, meine Zier,\nich will Dich lieben mit dem Werke\nund immerwährender Begier;\nich will Dich lieben, schönstes Licht,\nbis mir das Herze bricht.\r\nIch will Dich lieben, o mein Leben,\nals meinen allerbesten Freund;\nich will Dich lieben und erheben,\nsolange mich Dein Glanz bescheint;\nich will Dich lieben, Gottes Lamm,\nals meinen Bräutigam.\r\nAch, dass ich Dich so spät erkannte,\nDu hochgelobte Schönheit Du,\ndass ich nicht eher mein Dich nannte,\nDu höchstes Gut und wahre Ruh\';\nes ist mir leid, ich bin betrübt,\ndass ich so spät geliebt.\r\nIch lief verirrt und war verblendet,\nich suchte Dich und fand Dich nicht;\nich hatte mich von Dir gewendet\nund liebte das geschaff\'ne Licht.\nNun aber ist’s durch Dich gescheh\'n,\ndass ich Dich hab erseh\'n.\r\nIch danke Dir, Du wahre Sonne,\ndass mir Dein Glanz hat Licht gebracht;\nich danke Dir, Du Himmelswonne,\ndass Du mich froh und frei gemacht;\nich danke Dir, Du güldner Mund,\ndass Du mich machst gesund.\r\nErhalte mich auf Deinen Stegen\nund lass mich nicht mehr irre geh\'n;\nlass meinen Fuß in Deinen Wegen\nnicht straucheln oder stille steh\'n;\nerleucht\' mir Leib und Seele ganz,\nDu starker Himmelsglanz.\r\nIch will Dich lieben, meine Krone,\nich will Dich lieben, meinen Gott,\nich will Dich lieben ohne Lohne\nauch in der allergrößten Not;\nich will Dich lieben, schönstes Licht,\nbis mir das Herze bricht.'),
(9, '0927', 'Ich will Dir danken, Herr, unter allen Erdenvölkern', NULL, 'Ich will Dir danken, Herr, unter allen Erdenvölkern.\nIch will Dir Loblieder singen unter den Menschen.\nDenn Deine Güte reicht soweit bis zu den Himmeln\nund Deine Treue, soweit die Wolken geh\'n.\nSei erhoben, o Gott, über den Himmel,\nDeine Herrlichkeit sei über alle Welt.\nSei erhoben, o Gott, über den Himmel,\nDeine Herrlichkeit sei über alle Welt.'),
(9, '0928', 'Ich will einziehn in sein Tor  -  I will enter in His Gates   (Psalm 100, 4; 118, 24)', 'I will enter His gates with thanksgiving in my heart,\nI will enter His courts with praise.\nI will say this is the day that the Lord has made,\nI will rejoice for He has made me glad.\r\nHe has made me glad,\nHe has made me glad,\nI will rejoice for He has made me glad.\nHe has made me glad,\nHe has made me glad,\nI will rejoice for He has made me glad.', 'Ich will einzieh\'n in Sein Tor mit dem Herzen voller Dank,\nich will treten in den Vorhof mit Preis,\ndenn ich weiß, dies ist der Tag, den der Herr gemacht.\nIch will mich freu\'n, Er hat mich froh gemacht.\r\nEr hat mich froh gemacht,\nEr hat mich froh gemacht,\nich will mich freu\'n, Er hat mich froh gemacht.\nEr hat mich froh gemacht,\nEr hat mich froh gemacht,\nich will mich freu\'n, Er hat mich froh gemacht.'),
(9, '0929', 'Ich will folgen, Jesus, Dir von Tag zu Tag  -  I have made my Choice to follow Christ each Day   (Herr, ich steh zu Deinem Dienst bereit)', 'I have made my choice to follow Christ each day,\nI am Thine for service, Lord.\nTho’ I sometimes falter on the thorny way,\nI am Thine for service, Lord.\r\nThine for service when the days are drear,\nThine for service when the skies are clear.\nYes, Thine for service thro’ the coming years,\nI am Thine for service, Lord.\r\nLet me idle not the precious hours away,\nI am Thine for service, Lord.\nAs Thy voice shall bid me, I will go or stay,\nI am Thine for service, Lord.\r\nI am Thine for service till the last glad hour\nshall have passed on earth from me.\nAnd I wake to service of a greater pow’r,\nthro’ a glad eternity.', 'Ich will folgen, Jesus, Dir von Tag zu Tag,\nDir nur dienen will ich, Herr!\nOb ich hin und wieder auch ermüden mag,\nDir nur dienen will ich, Herr!\r\nHerr, ich steh\' zu Deinem Dienst bereit,\nalle Kräfte hab\' ich Dir geweiht;\nja Dir in Zeit und alle Ewigkeit\nwill ich dienen, Herr, allein.\r\nLass mich nie vergeuden eine gold\'ne Stund\',\ndienend Dir, nur Dir, mein Herr,\nstets gewärtig des Befehls aus Deinem Mund,\nlebend Dir, nur Dir, mein Herr!\r\nDein im Dienste, bis mein letztes Stündlein schlägt,\nwenn Dein Wink mir Ruh\' gebeut,\nDir zu dienen dann mit einem bessern Dienst,\ndort in ew\'ger Seligkeit.'),
(9, '0930', 'Ich will preisen meinen Herrn  -  I just came to prais the Lord   (Chorus)', 'I just came to praise the Lord,\nI just came to praise the Lord,\nI just came to praise His holy name,\nI just came to praise the Lord.', 'Ich will preisen meinen Herrn,\nIch will preisen meinen Herrn,\nich will preisen Seinen heil\'gen Nam\',\nIch will preisen meinen Herrn.'),
(9, '0931', 'Ich will singen dem Herrn mein Leben lang', NULL, 'Ich will singen dem Herrn mein Leben lang,\nLoblieder bringen meinem Gott, so lange ich bin.\nEr ist so groß, jedes mal, wenn ich an Ihn denk,\nmacht es mich froh, macht es mich froh, froh in dem Herrn. :|:\nLobe den Herrn, meine Seel\', und alles, was in mir ist!\nLobe den Herrn, meine Seel\'!\nLobe den Herrn! :|:'),
(9, '0932', 'Ich will singen meinem Herrn, Ihm allein gebührt die Ehr\' -  I will sing unto Lord, He is worthy to be praised', 'I will sing unto the Lord,\nHe is worthy to be praised.\nI will sing unto the Lord,\nHe is worthy to be praised.\r\nHosanna, blessed be the Rock,\nblessed be the Rock of my salvation!\nHosanna, blessed be the Rock,\nblessed be the Rock of my salvation!\r\nOh, magnify the Lord with me,\nfor He is worthy to be praised.\nOh, magnify the Lord with me,\nfor He is worthy to be praised.\r\nGlory, glory to His name,\nHe lives and reigns forever.\nGlory, glory to His name,\nHe lives and reigns forever.\r\nJehova Jireh is His name,\nfor He provideth all my needs.\nJehova Jireh is His name,\nfor He provideth all my needs.', 'Ich will singen meinem Herrn,\nIhm allein gebührt die Ehr\'.\nIch will singen meinem Herrn,\nIhm allein gebührt die Ehr\'.\r\nHosianna, gepriesen sei der Fels,\ngepriesen sei der Fels meiner Erlösung!\nHosianna, gepriesen sei der Fels,\ngepriesen sei der Fels meiner Erlösung!\r\nOh, erhebt den Herrn mit mir,\nIhm allein gebührt die Ehr\'.\nOh, erhebt den Herrn mit mir,\nIhm allein gebührt die Ehr\'.\r\nRuhm, Ruhm Seinem Namen,\nEr lebt und regiert in Ewigkeit.\nRuhm, Ruhm Seinem Namen,\nEr lebt und regiert in Ewigkeit.\r\nJehova Jireh ist sein Name,\ner sorgt für alles, was ich brauch\'.\nJehova Jireh ist Sein Name,\ner sorgt für alles, was ich brauch\'.'),
(9, '0933', 'Ich will singen von der Gnade meines Herrn für immer', NULL, 'Ich will singen von der Gnade meines Herrn für immer, ewiglich, singe ich.\nIch will singen von der Gnade meines Herr.\nMit dem Mund, verkünde ich Deine Treue, deine Treue.\nMit dem Mund, verkünde ich Deine Treue bis in Ewigkeiten!\nIch will singen von der Gnade meines Herrn für immer,\nich will singen von der Gnade meines Herrn.'),
(9, '0934', 'Ich will streben nach dem Leben, wo ich selig bin', NULL, 'Ich will streben nach dem Leben, wo ich selig bin;\nich will ringen, einzudringen, bis dass ich\'s gewinn\'.\nHält man mich, so lauf ich fort; bin ich matt, so ruft das Wort:\nFortgerungen, durchgedrungen bis zum Kleinod hin!\r\nAls berufen zu den Stufen vor des Lammes Thron\nwill ich eilen; das Verweilen bringt oft bösen Lohn.\nWer auch läuft und läuft zu schlecht, der versäumt das Kronenrecht.\nWas dahinten, das mag schwinden; ich will nichts davon.\r\nJesus, richte mein Gesichte nur auf jenes Ziel;\nlenk\' die Schritte, stärk\' die Tritte, wenn ich Schwachheit fühl\'!\nLockt die Welt, so sprich mir zu, schmäht sie mich, so tröste Du;\nDeine Gnade füh\'r grade mich aus ihrem Spiel!\r\nDu musst ziehen, mein Bemühen ist zu mangelhaft.\nWo ihr\'s fehle, fühlt die Seele; aber Du hast Kraft,\nweil Dein Wort das Leben bringt und Dein Geist das Herz durchdringt.\nDort wird\'s tönen bei dem Krönen: Gott ist\'s, der es schafft!'),
(9, '0935', 'Ich will von meinem Jesus singen  -  I will sing of my Redeemer   (Singt, o singt von meinem Jesu)', 'I will sing of my Redeemer,\nand His wondrous love to me.\nOn the cruel cross He suffered,\nfrom the curse to set me free.\r\nSing, oh, sing of my Redeemer,\nwith His blood He purchased me.\nOn the cross He sealed my pardon,\npaid the debt, and made me free.\r\nI will tell the wondrous story,\nhow my lost estate to save.\nIn His boundless love and mercy,\nHe the ransom freely gave.\r\nI will praise my dear Redeemer,\nHis triumphant pow’r I’ll tell.\nHow the victory He giveth\nover sin, and death and hell.\r\nI will sing of my Redeemer,\nof His love of God so free.\nHe brought me from death to life\nthat I may be with Him for\'ver.', 'Ich will von meinem Jesus singen,\nvon Seiner Gnade, Lieb und Treu,\nvon Seinem bitter\'n Kreuzesleiden,\nvon Seiner Blutskraft, die macht frei.\r\nSingt, o singt von meinem Jesu,\nvon Seiner Gnade, Lieb und Treu,\nvon Seinem bitter\'n Kreuzesleiden,\nvon Seiner Blutskraft, die macht frei!\r\nIch will von Seinen Wunden rühmen,\nwie Er die Sünder selig macht;\nEr hat auch mir durch Sein Versühnen\nhimmlisches Licht und Heil gebracht.\r\nIch will den teuren Heiland preisen,\nSein Regiment ist ohne Fehl;\nEr hilft den Seinen völlig siegen\nüber die Sünde, Tod und Höll\'!\r\nIch will von meinem Heiland singen,\nvon Seiner Gotteslieb\' so frei.\nEr brachte mich vom Tod zum Leben,\ndas ich auf ewig bei Ihm sei.'),
(9, '0936', 'Ich wünsche mir kein Diadem noch Zepter   (Ich will mit Ihm gehen bis nach Golgatha)', NULL, 'Ich wünsche mir kein Diadem noch Zepter,\nder Erde Lust und Rum vermiss ich gern.\nIch möchte nur noch folgen dem Erlöser,\nverkünden seine Wunder nah und fern.\r\nIch will mit Ihm gehen bis nach Golgatha,\nich will bei Ihm stehen unter\'m Kreuze da.\nBis an\'s End\' mit Ihm vereint,\nwill ich dienen meinem Freund,\nich will mit Ihm gehen bis nach Golgatha.\r\nIch weiß das dieser Weg für Ihn nicht leicht war,\nhier floss Sein Blut hier ging Er in den Tod.\nIn namenloser Qual bringt Er den Preis dar,\ndoch dadurch ward das Kreuz der Weg zu Gott.\r\nIch kann nicht mehr zurück, die Liebe treibt mich,\nden Kelch voll Leid und Weh, ich neh\'m in an.\nDoch auch in meinen Tränen bin ich glücklich,\nweil Jesus wahren Frieden geben kann.\r\nIn Liebe will ich wirken, dulden streben,\nwill Seiner Gnade ganz mich anvertrau\'n.\nEinst werd\' ich, wenn vollendet ist mein Leben,\nverwandelt in Sein strahlend Antlitz schau\'n.'),
(9, '0937', 'If not for grace', 'Where would I be You only know\nI\'m Glad You see through eyes of love\nA hopeless case, an empty place\nIf not for Grace\r\nAmazing grace how sweet the sound\nI once was lost but now I\'m found\nA hopeless case, an empty place\nIf not for Grace\r\n(Precious Lord please take my hand\nLead me on let me stand\nA hopeless case, an empty place\nIf not for Grace)', 'Wo würde ich sein, das weißt nur Du\nIch bin froh, dass du mit den Augen der Liebe siehst\nEin hoffnungsloser Fall, ein leerer Ort\nWenn nicht für die Gnade\r\nErstaunliche Gnade, wie süß der Klang\nIch war einst verloren, aber jetzt bin ich gefunden\nEin hoffnungsloser Fall, ein leerer Ort\nWenn nicht für die Gnade\r\nKostbarer Herr, bitte nimm meine Hand\nFühre mich weiter, lass mich stehen\nEin hoffnungsloser Fall, ein leerer Ort\nWenn nicht für die Gnade'),
(9, '0938', 'If the same Spirit that raised Christ from the Dead dwells in you', 'If the same Spirit\nthat raised Christ from the dead\ndwells in you, dwells in you.\nIf that same spirit\nthat raised Christ from the dead\ndwells in you, dwells in you.\nIt will quicken your mortal body,\nif that Spirit dwells in you.\nIt will quicken your mortal body,\nif that Spirit dwells in you.', '(Wenn derselbe Geist \nder Christus von den Toten auferweckte\nin dir wohnt, in dir wohnt\nWird Er deinen sterblichen Leib erwecken\nWenn derselbe Geist in dir wohnt)'),
(9, '0939', 'If there are some Questionsin the Corners of your Mind   (Jesus is the Answer for the World today)', 'Jesus is the answer\nfor the world today,\nabove Him, there\'s no other,\nJesus is the way.    2x\r\nIf there are some questions\nin the corners of your mind,\ntraces of discouragement,\npeace you cannot find,\nreflections of your past\nseem to face you every day,\nthis one thing I know for sure:\nJesus is the way.\r\nKnow that you\'ve got mountains\nyou think you cannot climb.\nYour skies are dark and cloudy\nand you think the sun won\'t shine.\nI know that you\'ve got problems\nyou think you can\'t tunnel through.\nWhy don\'t you try my Jesus,\nfor He knows just what to do.', NULL),
(9, '0940', 'If you believe you shall receive', 'If you believe, you shall receive\nthere\'s not a trouble or care\nthe good Lord can\'t release.\nFor he is just the same today,\nall you\'ve got to do is trust,\npray and believe.\nYou must believe.', NULL),
(9, '0941', 'If you could see, what I once was   (I\'m just a Sinner, saved by Grace)', 'If you could see, what I once was.\nIf you could go with me,\nback to where, I started from,\nI know you would see,\na miracle of love that took me\nin Its sweet embrace.\nAnd mayby what, I am today,\njust an old sinner, saved by grace.\r\nI\'m just a sinner, saved by grace.\nWhen I stood condamed to death,\nHe took my place.\nNow I live and breath in freedom,\nwith each breath of life I take.\nLoved and forgiven,\nback with the living\nI\'m just a sinner, saved by grace.\r\nHow could I boast, on anything\nI\'ve ever seen or done.\nHow could I dare,\nto claim as mine,\nthe victories God has won.\nWhere would I be,\nwhen God not brought me gently to this place.\nI\'m here to say, I\'m nothing but,\na sinner, saved by grace.', NULL),
(9, '0942', 'If you want to be great in God\'s Kingdom, learn to be the Servant of all', 'If you want to be great in God\'s Kingdom,\nlearn to be the servant of all.\nIf you want to be great in God\'s Kingdom,\nlearn to be the servant of all,\nlearn to be the servant of all,\nlearn to be the servant of all.', NULL),
(9, '0943', 'If you\'re happy and you know it', 'If you\'re happy and you know it\nclap your hands\nIf you\'re happy and you know it\nclap your hands\nIf you\'re happy and you know it\nand you really want to show it\nIf you\'re happy and you know it\nclap your hands\r\nIf you\'re happy and you know it\nstamp your feet\nIf you\'re happy and you know it\nstamp your feet\nIf you\'re happy and you know it\nand you really want to show it\nIf you\'re happy and you know it\nstamp your feet', NULL),
(9, '0944', 'Ihr aufgehobnen Segenshände', NULL, 'Ihr aufgehob\'nen Segenshände\nvoll Heil, voll Wunderkraft des Herrn,\nihr wirkt und waltet bis ans Ende,\nuns ungeseh\'n, doch niemals fern.\nIm Segnen seid ihr aufgefahren,\nim Segnen kommt ihr einst zurück;\nauch in des Glaubens Zwischenjahren\nbleibt ihr der Seelen Trost und Glück.\r\nIhr segnet Christi Schar hienieden\nmit Freude, die ohn\' Ende währt;\nihr legt auf sie den hohen Frieden,\nden keine Welt uns sonst beschert.\nJa, segnend ruht ihr auf den Seinen,\ndies beugt und stärkt uns bis ins Grab;\nund wenn wir Sehnsuchtstränen weinen,\nso trocknet dies die Tränen ab.\r\nIhr zieht mit Gotteskraft die Herzen\nzu Ihm und an Sein Herz hinauf;\nihr stillt, ihr heilt die Seelenschmerzen,\nihr helft der Schwachheit mächtig auf.\nIhr brecht den Zwang, der Herzen kettet,\nihr fasst und stärkt des Pilgers Hand,\nihr hebt, ihr tragt und ihr errettet\nund führt uns bis ins Vaterland.\r\nEinst öffnet ihr die Himmelstore\nder treuen Erdenpilgerschar\nund reicht dem Überwinderchore\ndes ew\'gen Lebens Kronen dar.\nDann, dann mit jeder Gottesgabe,\nmit jedem Heil begabt durch euch,\njauchzt eurem goldnen Königsstabe\ndes weiten Himmels Königreich.'),
(9, '0945', 'Ihr Schnitter in der weißen Ernte  -  Ho, Reapers in the whitened Harvest   (Denn die da harren auf den Herrn, die kriegen neue Kraft)', 'Ho, reapers in the whitened harvest!\nOft feeble, faint and few;\nCome, wait upon the blessed Master,\nOur strength He will renew.\r\nFor they that wait upon the Lord shall renew their strength,\nthey shall mount up with wings, they shall mount up with wings as eagles.\nThey shall run and not be weary, they shall walk and not faint,\nThey shall run and not be weary, they shall walk and not faint,\nThey shall run and not be weary, shall walk and not faint.\r\nRejoice, for He is with us alway,\nLo, even to the end!\nLook up, take courage and go forward,\nAll needed grace He’ll send!\r\nToo oft aweary and discouraged,\nwe pour a sad complaint.\nBelieving in a living Saviour,\nwhy should we ever faint?', 'Ihr Schnitter in der weißen Ernte,\noft elend, schwach und klein,\nkommt wartet auf den treuen Meister,\nEr will euch Kraft verleih\'n.\r\nDenn die da harren auf den Herrn, die kriegen neue Kraft,\nsie fahren auf mit Flügeln, sie fahren auf mit Flügeln wie Adler.\nSie laufen ohne matt zu werden, wandeln ohn\' ermüden,\nsie laufen ohne matt zu werden, wandeln ohn\' ermüden,\nsie laufen ohne matt zu werden, und wandeln mühelos.\r\nFreut euch, denn Er ist immer mit uns,\nja sicher bis an\'s End\'.\nBlickt auf, seid mutig und geht vorwärts,\ndie nöt\'ge Kraft er spend\'t.\r\nIm Kreuz ist uns\'re Kraft verborgen,\nnimm sie nur gläubig an.\nGeh Schritt für Schritt und lass Ihn sorgen,\nEr führt auf sich\'rer Bahn.'),
(9, '0946', 'Ihr Streiter Zions schwingt die Fahn   (Und wenn der Kampf vorüber, werden wir gekrönt)', '\r\nAnd when the battle\'s over, we shall wear a crown!\nYes, we shall wear a crown! Yes, we shall wear a crown!\nAnd when the battle\'s over, we shall wear a crown\nin the new Jerusalem.\nWear a crown, wear a crown, wear a bright and shine crown,\nAnd when the battle\'s over, we shall wear a crown\nin the new Jerusalem.\r\n\r\n\r\n\r\n', 'Ihr Streiter Zions schwingt die Fahn\'\nund seid zum Kampf bereit!\nEilt vorwärts auf der Siegesbahn,\nseid tapfer in dem Streit!\r\nUnd wenn der Kampf vorüber, werden wir gekrönt,\nja, werden wir gekrönt, ja, werden wir gekrönt.\nUnd wenn der Kampf vorüber, werden wir gekrönt\nmit der goldenen Siegeskron\', Siegeskron\', Siegeskron\',\nmit der goldenen Siegeskron\'!\nUnd wenn der Kampf vorüber, werden wir gekrönt\nmit der goldenen Siegeskron!\r\nDie Kraft der Jugend braucht der Herr,\ndes Alters Rat und Tat.\nZu dringen in des Feindes Heer\nauf siegesreichem Pfad.\r\nHerbei, ihr jungen Kämpfer,\nzieht des Glaubens Panzer an.\nWo Liebe warm im Herzen glüht,\ngeht Christi Werk voran.\r\nZeigt sich der Feind auch keck und kühn,\nist scharf sein Schwert und Spieß.\nWenn unter Christi Kreuz wir zieh\'n\nist uns der Sieg gewiss.\r\nD\'rum auf, ihr Kämpfer, in den Krieg\nmit Mut, Entschlossenheit!\nAuf, auf! der Feldruf lautet: Sieg!\nSieg für die Ewigkeit!'),
(9, '0947', 'Im Geiste war einst ich am Meeresstrand  -  In Fancy I stood by the Shore, one day   (Und ich wusste, dass ich ewig Ihn liebe)', 'In fancy I stood by the shore, one day,\nof the beautiful murm’ring sea.\nI saw the great crowds as they thronged the way\nof the Stranger of Galilee.\nI saw how the man who was blind from birth,\nin a moment was made to see.\nThe lame was made whole by the matchless skill\nof the Stranger of Galilee.\r\nAnd I felt I could love Him forever,\nso gracious and tender was He!\nI claimed Him that day as my Saviour,\nthis Stranger of Galilee.\r\nHis look of compassion, His words of love,\nthey shall never forgotten be.\nWhen sin-sick and helpless He saw me there,\nthis Stranger of Galilee.\nHe showed me His hand and His riven side,\nand He whispered, "It was for thee!"\nMy burden fell off at the pierced feet\nof the Stranger from Galilee.\r\nCome, ye who are driven and tempest-tossed,\nand His gracious salvation see.\nHe’ll quiet life’s storms with His "Peace, be still!"\nthis Stranger of Galilee.\nHe bids me to go and the story tell,\nwhat He ever to you will be.\nIf only you let Him with you abide,\nthis Stranger of Galilee.', 'Im Geiste war einst ich am Meeresstrand,\nleise rauschten die Well\'n der See.\nIch eilte der drängenden Menge nach\nzum  Fremdling von Galilä.\nIch sah einen Mann, blind von Mutterleib,\nnur ein Wort und er konnte seh\'n.\nEin Lahmer geheilt durch die milde Hand\ndes Fremdlings von Galilä.\r\nUnd ich wusst\', dass ich ewig Ihn liebe.\nNoch heut\' ich vor Augen Ihn seh\'.\nIch schenkte mein Herz diese Stunde,\ndem Fremdling von Galilä.\r\nEin einziger Blick mir sein Herz gewann.\nSeine Liebe nahm all mein Weh,\nals sündig und hilflos ich zu ihm kam,\nzum Fremdling von Galilä.\nEr zeigt mir die Wunden und flüstert nah:\n"Auch für Dich war mein Kreuzesweh."\nDie Last mir entfiel, als ich bluten sah,\nden Fremdling von Galilä.\r\nOh, komm der Du müde und traurig bist,\nSein herrliches Heil nur sieh\'!\nOb Stürme auch toben,\nes macht sie still,\nder Fremdling von Galilä.\nUnd was auch Dein Herz sonst\nerheben lässt.\nEr ist Herr über Not und Weh\'.\nWo du Ihn nur einlässt den Kreuzesheld,\nden Fremdling von Galilä.'),
(9, '0948', 'Im Glauben gehen wir und nicht im Schauen', NULL, 'Im Glauben gehen wir und nicht im Schauen,\ndas Schwert des Geistes liegt in uns\'rer Hand.\nUnd das Wort Gottes führt uns immer weiter,\ndamit wir sicher geh\'n an Seiner Hand.\r\nIm Kampfe siegreich sein und nicht verzagen,\nweil Er den Sieg schon längst für uns errang.\nDer Heil\'ge Geist kennt keine Niederlagen,\nlasst uns im Glauben, nicht im Schauen geh\'n.\r\nIm Glauben beten wir zu unser\'m Vater\nund wissen, dass Er hört ein ernst Gebet.\nWir zweifeln nicht und ehren Ihn durch Glauben,\nweil Er ja hält, was Er im Wort verspricht.'),
(9, '0949', 'Im Glauben seh ich Jesus sterben  -  By Faith I view my Saviour dying', 'By faith I view my Saviour dying\non the tree, on the tree.\nTo ev\'ry sinner He is crying,\nlook to me, look to me.\nHe bids the guilty now draw near,\nrepent, believe, dismiss their fear.\nHark, hark! what precious words I hear:\nMercy\'s free, mercy\'s free.\r\nJesus, the Lord of life, hath spoken\npeace to me, peace to me.\nNow all my chains of sin are broken,\nI am free, I am free.\nSoon as I on His name believed,\nHis pard\'ning grace my soul received,\nand was from sin and death retrieved,\nmercy\'s free, mercy\'s free.\r\nThis precious truth, ye sinners hear it,\nmercy\'s free, mercy\'s free.\nYe ministers of God, declare it,\nmercy\'s free, mercy\'s free,\nVisit the heathen\'s dark abode,\nproclaim to all the love of God,\nand spread the glorious news abroad,\nmercy\'s free, mercy\'s free.\r\nLong as I live I\'ll still be crying,\nmercy\'s free, mercy\'s free.\nAnd thus shall be my theme when dying,\nmercy\'s free, mercy\'s free.\nAnd when the vale of death I\'ve passed,\nwhen lodged above the stormy blast,\nI\'ll sing while endless ages last,\nmercy\'s free, mercy\'s free.', 'Im Glauben seh\' ich Jesus sterben,\nmir zugut, mir zugut.\nSeh\' ihn durch Leiden Heil erwerben!\nTeures Blut, teures Blut!\nIhr Sünder, auf, hier winkt euch Licht,\no, glaubt an ihn und zaget nicht!\nHorcht, horcht, welch köstlich Wort Er spricht:\n"Freie Gnad! Freie Gnad!"\r\nAls ich geirrt in meinen Sünden,\ndacht\' Er mein, dacht\' Er mein?\nLieß Er auch mich noch Gnade finden?\nKann es sein, kann es sein?\nJa, Jesus hat an mich gedacht,\nhat Heil und Leben mir gebracht.\nMein Mund frohlockt, mein Herze lacht.\n"Freie Gnad\'! Freie Gnad\'!"\r\nWenn Sorge mich und Zweifel drücket,\nweiß Er Rat, weiß Er Rat.\nWas ist\'s, das meine Seel\' erquicket?\nFreie Gnad\'! Freie Gnad\'!\nO süßer Friede, holde Lust!\nWie wird so voll und frei die Brust!\nO, hätt\' ich\'s eher schon gewusst!\n"Freie Gnad\'! Freie Gnad\'!"\r\nDas sei mein Lied, solang ich lebe:\n"Freie Gnad\'! Freie Gnad\'!"\nMein letzter Atemzug erhebe:\n"Freie Gnad\'! Freie Gnad\'!"\nUnd weckt mich einst Posaunenton,\nund steh ich vor des Lammes Thron,\nso grüß\' ich damit Gottes Sohn:\n"Freie Gnad\'! Freie Gnad\'!"'),
(9, '0950', 'Im Himmel dort vor Gottes Thron  -  Before the Throne of God above', 'Before the throne of God above\nI have a strong and perfect plea,\na great High Priest whose name is Love,\nwho ever lives and pleads for me.\nMy name is graven on his hands,\nmy name is written on His heart.\nI know that while in heav\'n he stands,\n||: no tongue can bid me thence depart :||\r\nWhen Satan tempts me to despair\nand tells me of the guilt within,\nupward I look and see Him there\nwho made an end of all my sin.\nBecause the sinless Saviour died\nmy sinful soul is counted free.\nFor God the Just is satisfied,\n||: to look on Him and pardon me :||\r\nBehold him there! The risen Lamb,\nmy perfect, spotless righteousness.\nThe great unchangeable "I AM",\nthe King of glory and of grace!\nOne with Himself I cannot die,\nmy soul is purchased by his blood.\nMy life is hid with Christ on high,\n||: with Christ, my Saviour and my God :||', 'Im Himmel, dort vor Gottes Thron,\ntritt jemand anders für mich ein,\nder Hohepriester, Gottes Sohn,\nEr kann allein mein Mittler sein.\nMein Name steht in Seiner Hand,\nEr betet für mich immerfort.\nEr gibt den Geist als Unterpfand,\n||:mich kann nichts trennen mehr von Gott :||\r\nWenn Satan mich verklagen will\nund hält mir vor die Sündenlast,\nso schau ich auf zu meinem Herrn,\nder rief am Kreuz: Es ist vollbracht!\nVollkommen sündlos hing Er dort,\nnahm meine ganze Schuld auf sich.\nDer Zorn des Vaters ist nun fort,\n||: Er sieht den Sohn, begnadigt mich :||\r\nSieh auf das Lamm, das auferstand,\nJesus, meine Gerechtigkeit.\nAls der „ICH BIN“ ist Er bekannt,\nder König voller Herrlichkeit.\nMit Christus bin ich nun vereint,\nsei es im Leben oder Tod.\nIch werde ewig bei Ihm sein,\n||: Er ist mein Retter und mein Gott :||'),
(9, '0951', 'Im Himmel gibt es manches, was ich gerne möchte sehn  -  In heaven there are many Things I’m longing so to see   (Der Erste den ich seh soll Jesus sein)', 'In heaven there are many things I’m longing so to see,\nits beauties surely will my soul enthrall.\nBut when I’m ushered to the realms of blest eternity,\nI want to see my Saviour first of all!\r\nI want to see my Saviour first of all,\nbefore on any others I would call.\nAnd then for countless days on His dear face I’ll gaze,\nI want to see my Saviour first of all.\r\nI want to see those pearly gates those avenues of gold,\nI want to see each mansion\'s large and small.\nThe tree of life and crystal stream I\'m longing to behold,\nbut I want to see my Saviour first of all.\r\nI want to see my mother who is waiting on the shore,\nand many bygone days we will recall.\nI want to see each loved ones who had journeyed on before.\nBut I want to see my Saviour first of all.', 'Im Himmel gibt es manches, was ich gern möchte seh\'n,\nan Schönheit wird mein Herz sich dort erfreu\'n.\nUnd wenn ich einst in Ewigkeit zum Himmel werd\' eingeh\'n,\nder Erste, den ich seh\', soll Jesus sein.\r\nDer Erste, den ich seh\' soll Jesus sein,\nund dann erst alles and\'re mich erfreuen.\nAnbetend werd\' ich steh\'n vor dem, der alles gibt.\nIch sehe dann den Heiland, der mich liebt.\r\nIch sehe einst das Perlentor, es strahlt so hell und klar,\nich sehe einst das wunderschöne Heim.\nIch sehe einst den weißen Thron und auch die Engleschar.\nDer Erste, den ich seh\' soll Jesus sein.\r\nIch sehe einst die Lieben dort in jenem Himmelsland,\nund viele die mit mir dann ziehen heim.\nSo mancher wartet dort auf mich an jenem gold\'nem Strand.\nDer Erste, den ich seh\' soll Jesus sein.'),
(9, '0952', 'Im Sturme des Lebens, im Dunkel der Nacht  -  My Soul in sad Exile was out on Life\'s Sea   (Ich habe gefunden den Hafen der Ruh)', 'My soul in sad exile was out on life\'s sea,\nso burdened with sin and distressed.\nTill I heard a sweet voice saying,\n"Make Me your choice",\nand I entered the "Haven of Rest!"\r\nI\'ve anchored my soul in the haven of rest,\nI\'ll sail the wild seas no more.\nThe tempest may sweep o\'er the wild, stormy deep,\nin Jesus I\'m safe evermore.\r\nI yielded myself to His tender embrace,\nand faith taking hold of the Word.\nMy fetters fell off, and I anchored my soul,\nthe Haven of Rest is my Lord.\r\nThe song of my soul, since the Lord made me whole,\nhas been the old story, so blest.\nOf Jesus, who\'ll save whosoever will have\na home in the "Haven of Rest!"\r\n\r\nHow precious the thought that we all may recline,\nLike John, the beloved and blest.\nOn Jesus\' strong arm, where no tempest can harm.\nSecure in the "Haven of Rest!"\r\nOh, come to the Saviour, He patiently waits\nto save by His power divine.\nCome, anchor your soul in the haven of rest,\nand say, "My Beloved is mine."', 'Im Sturme des Lebens, im Dunkel der Nacht,\nso trieb ich im tosenden Meer.\nDa hörte ich Jesu holdseligen Ruf:\n"Ihr Müden, Belad\'nen kommt her!"\r\nIch habe gefunden den Hafen der Ruh\',\nich bin nun erlöst und befreit!\nOb ringsum es stürmt, in des Heilandes Arm,\nda ruh\' ich in Ewigkeit!\r\nEr zog mich empor an Sein liebendes Herz,\nda strömte mir köstliche Ruh\'.\nNun hab ich vergessen die Not und die Qual,\no Jesus, mein Alles bist Du!\r\nNun ruf ich\'s hinaus in die stürmende See:\nIhr Elenden, kommt doch herein!\nVon all eurer Mühsal, von all eurer Last\nwill hier euch der Heiland befrei\'n!\r\nEs winkt euch und wartet der Hafen der Ruh,\ndort seid ihr erlöst und befreit!\nOb ringsum es stürmt, in des Heilandes Arm,\nda ruht ihr in Ewigkeit!\r\nO lasst Ihn nicht warten, Er liebt euch, Er winkt,\nEr sehnt sich, o könnt ihr\'s versteh\'n?\nNach euch, ihr Verlor\'nen, um euch zu befrei\'n;\nihr sollt in die Ruhe eingeh\'n.\r\nUnd ist eure Sünde wie Blut auch so rot,\nder Herr macht von allem euch rein!\nO wascht nur die Kleider im Blute des Lamm\'s,\ndann geht ihr zur Herrlichkeit ein.'),
(9, '0953', 'Immanuel, Immanuel, Sein Name heißt Immanuel  -  Emmanuel, Emmanuel, His name is called Emmanuel   (Chorus)', 'Emmanuel, Emmanuel,\nHis name is called Emmanuel.\nHe\'s God with us, revealed in us.\nHis name is called Emmanuel.', 'Immanuel, Immanuel,\nSein Name heißt Immanuel.\nGott mit uns geoffenbart,\nSein Name heißt Immanuel.'),
(9, '0954', 'Immer mehr von Dir, immer mehr', NULL, 'Immer mehr von Dir, immer mehr.\nImmer mehr sein wie Du, immer mehr.\nImmer mehr Deine Worte versteh\'n,\nDeine Werke tun, o Herr immer mehr.\r\nDu bist ein Gott, der seine Kinder liebt,\nder als ein Vater ihr Verlangen sieht.\nNiemand und nichts kommt Dir jemals gleich, oh Herr.\nDu zeigst Dich uns als ewig treuer Freund\nund weißt genau wie unser Herz es meint.\nGib uns mehr von Dir, immer mehr.'),
(9, '0955', 'Immer mehr, immer mehr - Through it all', 'I\'ve had many tears and sorrows,\nI\'ve had questions for tomorrow,\nthere\'s been times I didn\'t know right from wrong.\nBut in every situation,\nGod gave me blessed consulation,\nthat my trials come to only make me strong.\r\nThrough it all, through it all,\nI\'ve learned to trust in Jesus,\nI\'ve learned to trust in God.\nThrough it all, through it all,\nI\'ve learned to depend upon His word.\r\nI\'ve been to lots of places,\nI\'ve seen a lot of faces,\nthere\'s been times I felt so all alone.\nBut in my lonely hours,\nyes, those precious lonely hours,\nJesus lets me know that I was His own\r\nI thank God for the mountains,\nand I thank Him for the valleys,\nI thank Him for the storms He brought me through.\nFor if I\'d never had a problem,\nI wouldn\'t know God could solve them,\nI\'d never know what faith in God could do.', 'Manchmal hab ich viele Sorgen,\ndenke viel nach über morgen,\nmanchmal scheint der Ausweg weit entfernt.\nDoch in allen Lebenslagen,\nund an allen trüben Tagen,\nhab‘ ich eine Sache immer mehr gelernt:\r\nImmer mehr, immer mehr,\nlern\' ich zu vertrauen\nJesus, meinem Gott.\nImmer mehr, immer mehr,\nsetz‘ ich mein Vertrauen auf Sein Wort!\r\nManchmal stand ich voll im Leben,\nwar von Freunden ich umgeben,\nmanchmal war ich einsam und allein.\nDoch gerad‘ in diesen Stunden\nhabe ich herausgefunden:\nJesus ist mein Freund und ich bin ewig Sein!\r\nIch danke Gott für alle Berge,\nich danke Gott für alle Täler,\nfür jeden Sturm, durch den Er mich gebracht.\nDenn in allen den Gefahren,\nhab ich nach und nach erfahren,\nwelche Rettung Gott durch Glauben möglich macht.'),
(9, '0956', 'In Christus ist mein ganzer Halt  -  In Christ alone, my Hope is found', 'In Christ alone, my hope is found,\nHe is my light, my strength, my song.\nThis cornerstone, this solid ground,\nfirm through the fiercest drought and storm.\nWhat heights of love, what depths of peace,\nwhen fears are stilled, when strivings cease!\nMy Comforter, my All in All,\nhere in the love of Christ I stand.\r\nIn Christ alone, who took on flesh,\nfullnes of God in helpless babe.\nThis gift of love and righteousness,\nscorned by the ones He came to save.\nTill on that cross as Jesus died,\nthe wrath of God was satisfied.\nFor every sin on Him was laid,\nhere in the death of Christ I live.\r\nThere in the ground His body lay,\nlight of the world by darkness slain.\nThen bursting forth in glorious day,\nup from the grave He rose again!\nAnd as He stands in victory,\nsin\'s curse has lost its grip on me.\nFor I am His and He is mine,\nbought with the precious blood of Christ.\r\nNo guilt in life, no fear in death,\nthis is the power of Christ in me.\nFrom life\'s first cry to final breaht,\nJeus commands my destiny.\nNo power of hell, no scheme of man,\ncan ever pluck me from His hand.\nTill He returns or calls me home,\nhere in the power of Christ I\'ll stand.', 'In Christus ist mein ganzer Halt.\nEr ist mein Licht, mein Heil, mein Lied,\nder Eckstein und der feste Grund,\nsicherer Halt in Sturm und Wind.\nWer liebt wie Er, stillt meine Angst,\nbringt Frieden mir mitten im Kampf?\nMein Trost ist Er in allem Leid.\nIn Seiner Liebe find\' ich Halt.\r\nDas ew\'ge Wort, als Mensch gebor\'n.\nGott offenbart in einem Kind.\nDer Herr der Welt, verlacht, verhöhnt\nund von den Seinen abgelehnt.\nDoch dort am Kreuz, wo Jesus starb\nund Gottes Zorn ein Ende fand,\ntrug Er die Schuld der ganzen Welt.\nDurch Seine Wunden bin ich heil.\r\nSie legten Ihn ins kühle Grab,\nDunkel umfing das Licht der Welt.\nDoch morgens früh am dritten Tag\nwurde die Nacht vom Licht erhellt.\nDer Tod besiegt, das Grab ist leer,\nder Fluch der Sünde ist nicht mehr,\ndenn ich bin Sein, und Er ist mein.\nMit seinem Blut macht Er mich rein.\r\nNun hat der Tod die Macht verlor\'n,\nich bin durch Christus neu gebor\'n.\nMein Leben liegt in Seiner Hand\nvom ersten Atemzuge an.\nUnd keine Macht in dieser Welt\nkann mich Ihm rauben, der mich hält,\nbis an das Ende dieser Zeit,\nwenn Er erscheint in Herrlichkeit.'),
(9, '0957', 'In dem Blut von Jesus Christ  -  In the Blood of Christ my Lord', '||: In the Blood of Christ my Lord,\nin the Blood of Christ my Lord,\nin the Blood of Christ my Lord\nwe have the victory. :||\nWe have the victory,\nwe have the victory.\nIn the Blood of Christ my Lord\nwe have the victory.', '||: In dem Blut von Jesus Christ,\nIn dem Blut von Jesus Christ,\nIn dem Blut von Jesus Christ,\nda haben wir den Sieg. :||\nDa haben wir den Sieg,\nda haben wir den Sieg,\nin dem Blut von Jesus Christ,\nda haben wir den Sieg.'),
(9, '0958', 'In dem Herzen glühet mir ein Glanz, strahlender als Sonnenlicht  -  There is Sunshine in my Soul today, more glorious and bright   (O Du Sonne, herrliche Sonne)', 'There is sunshine in my soul today,\nmore glorious and bright.\nThan glows in any earthly sky,\nfor Jesus is my light.\r\nO there\'s sunshine, blessed sunshine,\nwhen the peaceful, happy moments roll.\nWhen Jesus shows His smiling face,\nthere is sunshine in my soul.\r\nThere is music in my soul today,\na carol to my King.\nAnd Jesus, listening, can hear\nthe songs I cannot sing.\r\nThere is music in my soul today,\nfor when my Lord is near.\nThe dove of peace sings in my heart,\nthe flowers of grace appear.\r\nThere is gladness in my soul today,\nand hope and praise and love.\nFor blessings which He gives me now,\nfor joys "laid up" above.', 'In dem Herzen glühet mir ein Glanz,\nstrahlender als Sonnenlicht,\naus den Augen leuchtet er hervor\nvon Jesu Angesicht.\r\nO Du Sonne, herrliche Sonne,\nmeiner Seele wonnevolles Licht,\nlass mich jubelnd schau\'n in alle Ewigkeit\nmeines Jesu Angesicht.\r\nUnd es klingt und singt in meiner Brust,\nund es tönt empor zu Dir:\n"O mein König, mein Geliebter Du,\ngib neue Lieder mir!"\r\nNeuer Frühling blüht im Herzen mir,\ndenn der König ist uns nah.\nAlle Erdenmacht wird dann vergeh\'n,\nbald ist der Retter da!\r\nHeil\'ge Freude füllt die Seele mir,\nJesu Liebe, Fried\' und Ruh!\nUnd die Quelle aller Seligkeit,\nmein Jesus, das bist Du!'),
(9, '0959', 'In dem Herzen glüht ein Licht, das leuchtet immer   (Es ist Jesus, es ist Jesus)', NULL, 'In dem Herzen glüht ein Licht, das leuchtet immer.\nEs ist Jesus, es ist Jesus.\nAll das Dunkel dieser Welt vermag auch nimmer,\nauszulöschen dieses Licht in meinem Herz\'.\r\nEs ist Jesus! Es ist Jesus!\nLeuchten wird Er durch die Ewigkeiten fort.\nWenn die Sonne und der Mond schon längst verloschen,\nbleibt Er stets mein Licht in jenem Lande dort.\r\nWenn der Lebensabend naht, kennt Er die Sorgen.\nEs ist Jesus, es ist Jesus.\nUnter Seinem starken Arm bin ich geborgen,\nbis der Ew\'ge Tag in Seinem Reich anbricht.\r\nIn dem dunklen Tal des Todes Er begleitet.\nEs ist Jesus, es ist Jesus.\nHand in Hand mein treuer Herr mich sicher leitet;\nauch in dunkler Nacht ist mir der Heiland nah.'),
(9, '0960', 'In dem Himmel ists wunderschön   (Welche Hoffnung, so schön und süß)', NULL, 'In dem Himmel ist\'s wunderschön!\nO wie gerne möcht\' ich dort steh\'n,\nwo statt Kampf, Schmerz und Hohn\nmeiner wartet die Kron\',\nwo ich darf meinen Heiland seh\'n!\r\nWelche Hoffnung, so schön und süß,\nzu kommen ins Paradies!\nMein Jesus ist dort, bereit ist der Ort!\nAuch für mich, ja, ganz gewiss.\r\nIn dem Himmel ist\'s wunderschön!\nDort gibt\'s nimmermehr Todesweh\'n;\nalle Nacht ist vorbei,\ndenn die Sonne scheint frei\ndort in jenen so sel\'gen Höh\'n.\r\nIn dem Himmel ist\'s wunderschön!\nWo die Sel\'gen sich wiederseh\'n,\nwo sie geh\'n Hand in Hand\nam kristallenen Strand,\nwo die Lüfte des Freidens weh\'n.\r\nIn dem Himmel ist\'s wunderschön!\nD\'rum will ich nur um eines fleh\'n:\nO Herr, mach mich bereit,\nin gewasch\'nem Kleid\ndort in Zion einst einzugeh\'n!'),
(9, '0961', 'In dem Namen Jesus haben wir den Sieg  -  In the Name of Jesus we have the Victory', 'In the Name of Jesus, in the Name of Jesus\nwe have the victory.\nIn the Name of Jesus, in the Name of Jesus\ndemons will have to flee. (Halleluja)\nWhen we stand in Jesus Name, tell me who can stand before.\nIn the precious Name of Jesus we have the victory.', 'In dem Namen Jesus, in dem Namen Jesus,\nhaben wir den Sieg.\nIn dem Namen Jesus, in dem Namen Jesus,\nist Satans Macht besiegt.\nWeißt du wie der Herr dich liebt, weißt du, welches Heil Er gibt?\nIn dem teuren Namen Jesus ist uns der ganze Sieg.'),
(9, '0962', 'In den Tagen Jesu einst, Sein Blut hatte selbst die Kraft  -  In the misty Days of yore, Jesus’ precious blood had pow’r   (Ja das Blut verliert nie seine Kraft)', 'In the misty days of yore\nJesus’ precious blood had pow’r\ne’en the thief upon the cross to save.\nLike a bird his spirit flies\nto its home in Paradise,\nthro’ the pow’r of Calv’ry’s crimson wave.\r\nAnd the blood has never lost its pow’r,\nno, never, no, never.\nJesus’ blood avails for sin forever,\nand will never lose its pow’r.\r\nI was lost and stepped in guilt,\nbut the blood for sinners spilt\nwash’d away my sins and set me free.\nNow and evermore the same,\npraise, o praise his holy name!\nWill the cleansing stream availing be.\r\nGod in mercy asks you why,\nbrother sinner, will you die\nwhen such full redemption he provides?\nYou have but to look and live,\nlife eternal he will give,\nfor the pow’r of Calv’ry still abides.\r\nBring your burdens, come today,\nturn from all your sins away,\nHe can fully save and sanctify.\nFrom the wrath to come now flee,\nlet your name recorded be\nwith the blood-washed, and redeem’d on high.', 'In den Tagen Jesu einst,\nSein Blut hatte selbst die Kraft,\nauch zu retten dort den Dieb am Kreuz.\nWie ein Vogel flog er heim\nging in\'s Paradiese ein,\ndurch die Kraft des Blutes von Golgatha.\r\nJa das Blut verliert nie seine Kraft!\nNein niemals, nein niemals!\nJesu Blut vergossen für mich Sünder,\nes verliert nie seine Kraft.\r\nAuch ich war verloren in Sünd\',\nbis das Blut des Lammes kam\nund es wusch mich rein und weiß wie Schnee.\nNun bin ich frei, preis sei Gott,\ndieses Blut wäscht mich noch,\nund es hat auch heut\' dieselbe Kraft.\r\nGott fragt dich nun gnädiglich,\nBruder, warum willst du nicht\ndie Erlösung durch Sein Blut erfahr\'n.\nNimm es an und glaub doch nur,\nfolge treulich Seiner Spur,\nund du lebst bereits im Himmel hier.\r\nKomm doch heut\' und\nleg die Last bei Jesus ab,\nund Er reinigt, heiligt dein Herz.\nDann kommt Er in seiner Gnad\',\nwenn gehorsam Ihm du warst\nund füllt herrlich dich mit Heil\'gem Geist.'),
(9, '0963', 'In der stillen Nächte Stunden  -  In the silent Midnight Watches', 'In the silent midnight watches,\nstanding at your door,\ncalls the Saviour, pleading, knocking,\nnow as oft before.\nHe would enter with salvation,\nheart oppressed by sin!\nOpen now the door for Jesus,\nlet Him enter in!\r\nDeath will come some day, relentless,\ncome to every man.\nNone can heedlessly ignore him,\nnone his entry ban.\nJesus waits in mercy pleading,\nat the door today.\nHim, not death, the cruel reaper,\nyou can turn away.\r\nWhen you hear the Saviour knocking,\ncalling at your door.\nOh receive Him, let Him enter,\nand your soul restore!\nThen when breaks the golden morning,\nbright, eternal, fair.\nHe will open Heaven’s portals\nand receive you there.', 'In der stillen Nächte Stunden,\nhorch, was klopft in dir?\nHörst du\'s klopfen, immer klopfen?\nSprich, was ist es hier?\nSage nicht, es sei dein Pulsschlag,\nes muss tiefer sein:\nJesus ist\'s, dein Heiland klopfet,\nruft: "O lass mich ein!"\r\nSieh, der Tod kommt oft geschritten\nschnell zu arm und reich;\ndoch er fragt und klopft nicht lange,\ndringt hinein sogleich.\nAber Jesus wartet, wartet\nvor der Herzenstür;\nendlich geht Er traurig weiter,\no, dann wehe dir!\r\nDann wirst du einst draußen stehen,\nbittend: Lass mich ein!\nHänderingend wirst du flehen,\ndoch zu spät wird\'s sein.\nSchnöder Sünder, hast\'s vergessen,\nwer einst klopfte, wer?\nEr, der lang um dich geworben,\nkennt dich dann nicht mehr!'),
(9, '0964', 'In der Sünde wildem Meer  -  I was sinking deep in Sin   (Liebe mich hob, Liebe mich hob. Wo sonst kein Helfer war)', 'I was sinking deep in sin, far from the peaceful shore,\nvery deeply stained within, sinking to rise no more.\nBut the Master of the see heard my dispairing cry,\nfrom the waters lifted me, now safe I am.\r\nLove lifted me! Love lifted me!\nWhen nothing else could help, love lifted me!\nLove lifted me! Love lifted me!\nWhen nothing else could help, love lifted me!\r\nAll my heart to Him I give, ever to Him I cling.\nIn His blessed presence live, ever His praises sing.\nLove so mighty and so true, merits my soul best songs,\nfaithful loving service, too, to Him belongs.\r\nSouls in danger look above, Jesus completely saves.\nHe will lift you by His love, out of the angry waves.\nHe\'s the master of the sea, billows His will obey,\nHe your Saviour wants to be, be saved today.', 'In der Sünde wildem Meer kam ich in Angst und Not,\nfern vom sichern Uferstrand, droht mir der bitt\'re Tod.\nDoch des Meeres Meister hört, gnädig des Sünders Schrei,\nmich zu retten aus der Flut, eilt Er herbei.\r\nLiebe mich hob, Liebe mich hob. Wo sonst kein Helfer war,\nLiebe mich hob. Liebe mich hob, Liebe mich hob,\nwo sonst kein Helfer war, Liebe mich hob.\r\nFröhlich nun mein Lied erklingt in sel\'ger Sicherheit,\nIhm gehört mein Leben nun, in alle Ewigkeit.\nSolche Lieb\' und solche Treu hat es gewiss verdient,\ndass mein Herz Ihm froh und gern ergeben dient.\r\nSeele schau zu Ihm empor, der dir die Hilfe bringt,\nIhm gehorchen Wind und Meer, was Er auch tut, gelingt.\nFasse Seine starke Hand, lasse dir helfen gleich.\nEr trägt dich zum sichern Strand, zum Himmelreich.'),
(9, '0965', 'In des Jordans kühle Wellen stieg der Heiland einst hinab', NULL, 'In des Jordans kühle Wellen\nstieg der Heiland einst hinab;\nsehet, wie sie um Ihn schwellen,\nIhn bedeckend als ein Grab!\nSeht hier seine heiße Lieb\'\nzu den Sündern, die Ihn trieb,\ndass Er sank in Todesnöten,\nuns vom ew\'gen Tod zu retten!\r\nAus des Jordans Fluten wieder\nauf zum Licht Er sich erhebt,\nund vom Vater segnend nieder\nGeistes Fittich Ihn umschwebt.\nMit dem Herrn auch wir ersteh\'n\nund ins neue Leben geh\'n,\ntot der Schuld und frei von Banden,\nmitgestorben, miterstanden!\r\nD\'rum wohlan, ihr Gotteskinder,\nhat Er euch befreit vom Fluch?\nLiebt ihr euren Überwinder?\nFühlt ihr seines Geistes Zug?\nO, so traget seine Schmach!\nFolgt Ihm in die Fluten nach!\nWo das Haupt vorangegangen,\ndarf\'s den Gliedern nimmer bangen.'),
(9, '0966', 'In die Nacht der Welt hast Du uns gestellt   (Herr, wir bitten Komm und segne uns)', NULL, 'In die Nacht der Welt hast Du uns gestellt,\nDeine Freude auszubreiten.\nIn der Traurigkeit mitten in dem Leid,\nlass uns Deine Boten sein.\r\nHerr, wir bitten: Komm\' und segne uns,\nlege auf uns Deinen Frieden.\nSegnend halte Hände über uns.\nRühr\' uns an mit Deiner Kraft.\r\nIn die Schuld der Welt hast Du uns gestellt,\num vergebend zu ertragen,\ndass man uns verlacht, uns zu Feinden macht,\nDich und Deine Kraft verneint.\r\nIn den Streit der Welt hast Du uns gestellt,\nDeinen Frieden zu verkünden,\nder nur dort beginnt, wo man wie ein Kind,\nDeinem Wort Vertrauen schenkt.\r\nIn das Leid der Welt hast Du uns gestellt,\nDeine Liebe zu bezeugen.\nLass uns Gutes tun und nicht eher ruh\'n,\nbis wir Dich im Lichte seh\'n.'),
(9, '0967', 'In dieser letzten Gnadenzeit  -  In these, the closing Days of Time   (Der Herr kommt bald)   [Bieselsberg]', 'In these, the closing days of time,\nwhat joy the glorious hope affords.\nThat soon, oh, wondrous truth sublime!\nHe shall reign, King of Kings and Lord of Lords.\r\nHe\'s coming soon, He\'s coming soon,\nwith joy I welcome His returning.\nIt may be morn\', it may be night or noon,\npraise God, He\'s coming soon.\r\nThe signs around in earth and air,\nor painted on the starlit sky.\nGod\'s faithful witnesses declare\nthat the coming of the Saviour draweth nigh.\r\nThe dead in Christ who neath us lie,\nin countless numbers, all shall rise.\nWhen thro\' the portals of the sky\nHe shall come to prepare our paradise.\r\nAnd we who, living, yet remain,\ncaught up, shall meet our faithful Lord,\nThis hope we cherish not in vain,\nbut we comfort one another by this word.', 'In dieser letzten Gnadenzeit\nertönt die Botschaft laut und rein\nBald wird der Herr von dieser Welt\nseinen treuen Kinder zu sich holen heim.\r\nDer Herr kommt bald, der Herr kommt bald.\nmit Freude heiß\' ich ihn willkommen.\nOb morgens früh, ob in der Abendzeit,\nich weiß, der Herr kommt bald.\r\nAuf Land und Meer wir Zeichen seh\'n\nsie zeigen klar die letzte Zeit.\nUnd Gottes Geist bezeuget auch,\ndass das Kommen uns\'res Herrn ist nicht mehr weit.\r\nAls Überwinder aufersteh\'n die heiligen,\ndie entschlafen schon.\nund werden dann mit uns entrückt\nin den Himmelswolken hin zu Gottes Thron.\r\nD\'rum lasst uns wachen, beten nun,\nwir wissen weder Tag noch Stund\',\ndenn wie ein Dieb in dunkler Nacht,\nkommt der Herr und tut Sich Seiner Braut dann kund.'),
(9, '0968', 'In dieser Zeit brauchst du den Heiland  -  In Times like these you need a Saviour   (3 Strophen)   [Ruth Caye Jones]', 'In times like these you need a Saviour,\nin times like these you need an anchor.\nBe very sure, be very sure,\nyour anchor holds and grips the solid rock.\r\nThis rock is Jesus, Yes, He\'s the One,\nthis rock is Jesus, the only One.\nBe very sure, be very sure,\nyour anchor holds and grips the solid rock.\r\nIn times like these you need the Bible,\nin times like these oh be not idle.\nBe very sure, be very sure,\nyour anchor holds and grips the solid rock.\r\nIn times like these, I have a Saviour,\nin times like these, I have an anchor.\nI\'m very sure, I\'m very sure,\nmy anchor holds and grips the solid rock.', 'In dieser Zeit brauchst du den Heiland,\nin dieser Zeit brauchst du den Herrn.\nSei nur getrost, sei nur getrost,\nhier ist der Fels, auf dem dein Glaube ruht.\r\nDer Fels ist Jesus, nur Er allein!\nDer Fels ist Jesus, nur Er allein!\nSei nur getrost, sei nur getrost,\nder Anker hält, er ist am Felsen fest.\r\nIn dieser Zeit brauchst du die Bibel,\nin dieser Zeit, o sei nicht müßig!\nSei nur getrost, sei nur getrost,\nder Anker hält, er ist am Felsen fest.\r\nIn dieser Zeit hab ich den Heiland,\nin dieser Zeit hab ich den Anker.\nIch bin getrost, ich bin getrost,\nmein Anker hält, er ist am Felsen fest.'),
(9, '0969', 'In dir ist Freude in allem Leide  -  In thee is Gladness, amid all Sadness', 'In thee is gladness, amid all sadness,\nJesus, sunshine of my heart.\nBy thee are given the gifts of heaven,\nthou the true Redeemer art.\nOur souls thou makest, our bonds thou breakest;\nwho trusts thee surely hath built securely,\nand stands forever. Hallelujah!\nOur hearts are pining to see thy shining;\ndying or living, to thee are cleaving;\nnaught can us sever. Hallelujah!\r\nIf God be ours, we fear no powers,\nnot of earth or sin or death.\nGod sees and blesses in worst distresses,\nand can change them in a breath.\nWherefore the story tell of God\'s glory\nwith heart and voices; all heaven rejoices,\nsinging forever; Hallelujah!\nWe shout for gladness, triumph o\'er sadness,\nloving and praising, voices still raising\nglad hymns forever: Hallelujah!', 'In dir ist Freude in allem Leide,\no du süßer Jesu Christ!\nDurch dich wir haben himmlische Gaben,\ndu der wahre Heiland bist;\nhilfest von Schanden, rettest von Banden.\nWer dir vertrauet, hat wohl gebauet,\nwird ewig bleiben. Halleluja.\nZu deiner Güte steht unser G\'müte,\nan dir wir kleben im Tod und Leben;\nnichts kann uns scheiden. Halleluja.\r\nWenn wir dich haben, kann uns nicht schaden\nTeufel, Welt, Sünd\' oder Tod;\ndu hast\'s in Händen, kannst alles wenden,\nwie nur heißen mag die Not.\nD\'rum wir dich ehren, dein Lob vermehren\nmit hellem Schalle, freuen uns alle\nzu dieser Stunde. Halleluja.\nWir jubilieren und triumphieren,\nlieben und loben dein Macht dort droben\nmit Herz und Munde. Halleluja.'),
(9, '0970', 'In Dir, Herr Jesus, fand mein Herz, und nur in dir allein   (Es ist kein Name in der Welt, der mir Genüge gibt)', NULL, 'In Dir, Herr Jesus, fand mein Herz, und nur in dir allein,\nden langersehnten Friedenshort und Freude nach der Pein.\r\nEs ist kein Name in der Welt, der mir Genüge gibt,\nich finde meine Freude nur in Dem, der mich geliebt.\r\nIch sehnte mich nach Ruhm und Glück, fragt\' aber nicht nach Dir;\ndoch Deine Liebe fand mein Herz, und nun gehör\' ich Dir.\r\nDie leeren Brunnen dieser Welt, die machen niemand satt;\nnur wer Dein Lebenswasser trinkt, hier keinen Durst mehr hat.\r\nDu tatest mir die Augen auf, Du liebtest mich so treu,\nDu, Jesus, gabst Dein Leben mir und machtest alles neu.\r\nMein Herz ist voller Dank und Glück, ich juble\'s laut hinaus,\nbis ich einst sing das neue Lied bei Dir im Vaterhaus.'),
(9, '0971', 'In everything give Him Thanks   (2 Chorusse)', '\r\nIn the good times, praise His Name.\nIn the bad times, do the same.\nIn everything give the King of kings all the thanks.', 'In everything give Him thanks, give Him thanks.\nIn everything, give Him thanks.\r\n'),
(9, '0972', 'In finstrer Gruft Er lag, Jesus mein Heiland  -  Low in the Grave he lay, Jesus my Saviour   (Rollt ab den Stein, Jesus lebt)', 'Low in the grave he lay, Jesus my Saviour,\nwaiting the coming day, Jesus my Lord!\r\nUp from the grave he arose,\nwith a mighty triumph o\'er his foes.\nHe arose a victor from the dark domain,\nand he lives forever, with his saints to reign.\nHe arose! He arose! Hallelujah! Christ arose!\r\nVainly they watch his bed, Jesus my Saviour,\nvainly they seal the dead, Jesus my Lord!\r\nDeath cannot keep its prey, Jesus my Saviour,\nHe tore the bars away, Jesus my Lord!', 'In finstrer Gruft Er lag, Jesus, mein Heiland!\nKomm, Auferstehungstag! Jesus, mein Herr!\r\nRollt ab den Stein, Jesus lebt!\nAus dem Tode sich der Herr erhebt!\nJesus lebt! Es hielt Ihn nicht des Grabes Nacht,\ndenn der Lebensfürst bezwang des Todes Macht.\nJesus lebt! Halleluja! Jesus lebt.\r\nUmsonst steht dort die Wacht, Jesus, mein Heiland!\nUmsonst des Siegels Macht, Jesus, mein Herr!\r\nTod kann nicht halten Dich, Jesus, mein Heiland!\nEr alle Riegel bricht, Jesus, mein Herr!'),
(9, '0973', 'In my life Lord be glorified, be glorified   (3 Chorusse)', 'In my life Lord be glorified, be glorified.\nIn my life Lord be glorified today.\r\nIn my home Lord be glorified, be glorified.\nIn my home Lord be glorified today.\r\nIn my church Lord be glorified, be glorified.\nIn my church Lord be glorified today.', NULL),
(9, '0974', 'In nächtlicher Tiefe, bedroht vom Gericht   (Du bist mein Retter aus Qual und Nacht)', NULL, 'In nächtlicher Tiefe, bedroht vom Gericht,\nda lag ich gebunden, gar ferne vom Licht.\nDa rief ich zum Herrn, und Er hörte mein Schrein\nund trug mich empor zum gold\'nen Tagesschein.\r\nDu bist mein Retter aus Qual und Nacht,\nhast meinen Fuß auf den Fels gebracht.\nJubelnd verkünd\' ich des Heilands Macht:\nO Preis sei Dir, Halleluja!\nHalleluja, Halleluja!\nJesu Wort und Blut und Geist\nmein Herze fröhlich preist.\nHalleluja, Halleluja!\nJesus ist mein ew\'ger Ruhm, Halleluja!\r\nEr trug mich empor auf den Felsen nun,\nda darf ich verbleiben und ewiglich ruh\'n.\nEr schützt mich vor Sünde, bis einst Er erscheint,\nbis einst mit dem König sich die Braut vereint.\r\nEr gab mir ein Lied, o ein herrliches Lied.\nIch sing\'s alle Tage und werd\' nimmer müd\'.\nMein Leben, mein Denken, mein Alles ist Sein;\nEr ist mein König und ist ewig mein.\r\nDas Lied muss ich singen, es lässt mir nicht Ruh\'.\nO Himmel, o Erde, o höret mir zu!\nO hört es, Ihr Sünder und kommet zu Hauf:\n"Mein Heiland nimmt alle armen Sünder auf!"\r\nAuch ich war verloren und bin nun beglückt,\nEr hat mich mit Ring und mit Krone geschmückt.\nIch juble und preise und jauchze empor\nund sing mit den Heilgen bald im ew\'gen Chor!'),
(9, '0975', 'In starken Ketten, in großer Not  -  In prisoners\' Chains, with bleeding Stripes   (Ich preise Dich, ich preise Dich)', 'In prisoners\' chains, with bleeding stripes.\nPaul and Silas prayed that night.\nAnd in their pain began to sing,\nTheir chains were loosed, and they were free.\r\nI bless Your Name, I bless Your Name.\nI give You honor, I give You praise.\nYou are the Life, the Truth, the Way.\nI bless Your Name, I bless Your Name.\r\nSome midnight hour, if you should find,\nyou\'re in a prison in your mind.\nReach out and praise defy those chains,\nAnd they will fall in Jesus\' Name.\r\nWe bless Your Name, we bless Your Name.\nWe give You honor, we give You praise.\nYou are the Life, the Truth, the Way.\nWe bless Your Name, we bless Your Name.\nYou are the Life, the Truth, the Way.\nWe bless Your Name, we bless Your Name.', 'In starken Ketten, in großer Not,\nverfolgt, gefangen, für Gottes Wort.\nPaulus und Silas, sie lobten Gott,\nund plötzlich waren die Ketten fort.\r\nIch preise Dich, ich preise Dich.\nOh Du mein Leben erhältst auch mich,\nDu bist der Weg, Wahrheit und Licht,\nich preise Dich, ich preise Dich!\r\nBist Du gebunden, hast eine Last,\ntrübe Gedanken und keine Kraft.\nDann blicke auf und bete an,\ndann sieh\'st du, was dein Gott tun kann!\r\n'),
(9, '0976', 'In the Blood of Christ my Lord', 'In the Blood of Christ my Lord,\nin the Blood of Christ my Lord,\nin the Blood of Christ my Lord,\nwe have the victory.\nWe have the victory,\nwe have the victory.\nIn the Blood of Christ my Lord,\nwe have the victory.', NULL),
(9, '0977', 'In the presence of Jehovah - (In and out of situations, that tug-of-war at me)', 'In and out of situations, that tug-of-war at me.\nAll day long I struggle for answers that I need.\nBut then I come into Your presence, and all my questions become clear.\nAnd for this sacred moment, no doubts can interfere.\r\nIn the presence of Jehovah,\nGod Almighty, Prince of Peace.\nTroubles vanish, hearts are mended\nIn the presence of the King.\r\nThrough His love the Lord provided, a place for us to rest.\nA place to find the answers, in the hour of distress.\nNow there\'s never any reason, for you to give up in despair.\nJust slip away and breathe His name, for He will surely meet you there.', '\r\nHerr ich spüre, dass Du nah bist\nGott allmächtig, Friedefürst\nHerzen heilen, Schmerzen schwinden\nWenn du heut\' dein Volk berührst\r\n'),
(9, '0978', 'In these Days of Trials so near the End   (So just be faithful, believe His Word)', 'In these days of trials so near the end,\nwhen Christ from glory doth now descend.\nMen\'s hearts are failing and filled with fear,\nwe know the end time is surely here.\r\nSo just be faithful, believe His Word,\nstay with the message that you have heard.\nList\' to His prophet, his message heed;\nwalk in the light where His star doth lead.\r\nIn every church age a star did shine,\nto help God\'s people the truth to find.\nIn this last church age a star shines bright,\nso friend receive it, walk in the light.\r\nDo not be fearful or filled with dread,\nyour prophet sleepeth, he is not dead.\nThe Bride is waiting now for that voice,\nand in this hope we can now rejoice.\r\nHis Word of promise he gave the Bride,\nfrom his white charger the prophet cried.\n"Yet one more time shall I ride this trail."\nTHUS SAITH THE LORD can never fail.', NULL),
(9, '0979', 'In this World I\'ve tried most everything, and I\'m happy now to say   (I\'d rather be an old-time Christian)', 'In this world I\'ve tried most everything,\nand I\'m happy now to say\nthere is nothing like religion\nin the good old-fashioned way;\nI am walking in the old-time way,\nand I want the world to know\nthat I\'d rather be an old-time christian\nthan anything I know.\r\nI\'d rather be an old-time christian\nthan anything I know,\nthere\'s nothing like an old-time christian\nwith a christian love to show;\nI\'m walking in the grand old highway,\nand I\'m telling everywhere I go,\nthat I\'d rather be an old-time christian\nthan anything I know.\r\nThere are many things I\'d like to be\nas my journey I pursue,\nI have longed to be a leader\nlike a mortal man would do;\nI would like to be a millionaire,\nwith a million to bestow.\nBut I\'d rather be an old-time christian\nthan anything I know.\r\nAll the world is bright since I got right.\nNow I sing and pray and shout,\nall my burdens have been lifted\nsince the Saviour brought me out;\nI will tell the world both far and near\nas I travel here below,\nthat I\'d rather be an old-time christian\nthan anything I know.', NULL),
(9, '0980', 'In Your Presence that\'s where I am strong  -  In Deiner Gegenwart, da bin ich stark', 'In Your presence that\'s where I am strong,\nin Your presence oh Lord my God.\nIn Your presence that\'s where I belong,\nseeking Your face, touching Your grace,\nin the cleft of the rock,\nin Your presence, oh God.\r\nI want to go where the rivers cannot overflow me,\nwhere my feet are on the rock.\nI want to hide where the blazing fire cannot burn me\nin your presence, oh God.\r\nI want to hide where the flow of evil cannot reach me,\nwhere I am covered by your blood.\nAnd I want to be where the schemes of darkness cannot touch me,\nin Your presence, oh God.', 'Wenn Du nah bist, Herr, da bin ich stark,\nwenn Du nah bist, oh Herr, mein Gott,\nwenn Du nah bist, da gehör ich hin,\nsuch\' Dein Gesicht, Dein Gnadenlicht,\nauf dem Felsen steh\' ich,\nJesus, wenn Du nah\' bist.\r\nIch will dorthin, wo die Flüsse mich nicht überschwemmen können,\nwo meine Füße auf dem Felsen stehen.\nIch will mich verbergen, wo das lodernde Feuer mich nicht verbrennt,\nin deiner Gegenwart, oh Gott.\r\nIch möchte mich dort verstecken, wo der Strom des Bösen mich nicht erreichen kann,\nwo ich von deinem Blut bedeckt bin.\nUnd ich möchte dort sein, wo die Machenschaften der Finsternis mich nicht berühren können,\nin Deiner Gegenwart, oh Gott.'),
(9, '0981', 'Ins Lebensbuch geschrieben hat der Herr auch meinen Namen   (Ich weiß, ich weiß, Halleluja, ich weiß)', NULL, 'Ins Lebensbuch geschrieben hat\nder Herr auch meinen Namen.\nKein Zweifel plagt mich, keine Furcht.\nIch bin von Gottes Samen.\r\nIch weiß, ich weiß, Halleluja, ich weiß,\nmein Name steht geschrieben da!\r\nEinst stand ich in dem Sünderbuch\nmit schwarzer Schrift verzeichnet.\nDoch Jesu Blut durchstrich die Schrift,\nin Seine Händ\' mich zeichnet.\r\nDoch selbst nachdem die Schuld getilgt,\ngab\'s oft noch trübe Stunden.\nDoch seit ich ganz geheiligt bin,\nist Dunkelheit verschwunden.\r\nEs mögen Kinder dieser Welt\nnach Menschengunst noch streben.\nDoch ich bin froh! Mein Name steht\njetzt in dem Buch des Lebens.'),
(9, '0982', 'Into the chamber', 'Into the chamber\nbe free Holy Spirit.\nSpeak to me gently\nas I close the door.\nHeavenly Lover\nlet Thy Spirit cover.\nShekina unending\nis all I long for.', 'In die Kammer\nsei frei, Heiliger Geist.\nSprich sanft zu mir\nwährend ich die Tür schließe.\nHimmlischer Geliebter\nlass Deinen Geist mich bedecken.\nShekina unendlich\nist alles wonach ich mich sehne'),
(9, '0983', 'Into Thy presence we come   (Chorus)', 'Into Thy presence we come\nnot by the works we have done;\nBut by Thy grace\nand Thy grace alone\ninto Thy presence we come.', NULL),
(9, '0984', 'Is everybody happy, is everybody glad', 'Is everybody happy, is everybody glad,\nI don\'t want to see you looking weary,\nI don\'t want to see you looking sad,\nI just want to see you keep on smiling,\nfor Jesus is at the door,\nso keep on shouting halleluja,\ntill we meet on the golden shore.', NULL),
(9, '0985', 'Is he worthy', 'Do you feel the world is broken? (We do)\nDo you feel the shadows deepen? (We do)\nBut do you know that all the dark won\'t stop the light from getting through? (We do)\nDo you wish that you could see it all made new? (We do)\nIs all creation groaning? (It is)\nIs a new creation coming? (It is)\nIs the glory of the Lord to be the light within our midst? (It is)\nIs it good that we remind ourselves of this? (It is)\r\nIs anyone worthy? Is anyone whole?\nIs anyone able to break the seal and open the scroll?\nThe Lion of Judah who conquered the grave\nHe is David\'s root and the Lamb who died to ransom the slave\nIs He worthy? Is He worthy?\nOf all blessing and honor and glory\nIs He worthy of this?\nHe is\r\nDoes the Father truly love us? (He does)\nDoes the Spirit move among us? (He does)\nAnd does Jesus, our Messiah hold forever those He loves? (He does)\nDoes our God intend to dwell again with us? (He does)\r\nIs anyone worthy? Is anyone whole?\nIs anyone able to break the seal and open the scroll?\nThe Lion of Judah who conquered the grave\nHe is David\'s root and the Lamb who died to ransom the slave\nFrom every people and tribe\nEvery nation and tongue\nHe has made us a kingdom and priests to God\nTo reign with the Son\nIs He worthy? Is He worthy?\nOf all blessing and honor and glory\nIs He worthy? Is He worthy?\nIs He worthy of this?\nHe is! He is!\nIs He worthy? Is He worthy?\nHe is! He is!\nHe is worthy! He is worthy!\nHe is!', NULL),
(9, '0986', 'Ist da Lieb in Deinem Herzen, Liebe für den Herrn', NULL, 'Ist da Lieb in Deinem Herzen, Liebe für den Herrn?\nHast Du Deinen nächsten auch wie Dich selbst so gern?\nLieb Gott von ganzem Herzen, mit aller Kraft und von ganzer Seele,\ndenn er will Dir sein Dein Leben, Dir seine Liebe geben.\nIst das denn so schwer zu glauben?\nNimm Ihn, Gott ist die Liebe, denk daran!'),
(9, '0987', 'Ist dein Herz voll Sorgen und Schmerz  -  Days are filled with Sorrow and Care   (Lasten sie fallen auf Golgatha)', 'Days are filled with sorrow and care,\nhearts are lonely and drear.\nBurdens are lifted at Calvary,\nJesus is very near.\r\nBurdens are lifted at Calvary,\nCalvary, Calvary.\nBurdens are lifted at Calvary,\nJesus is very near.\r\nCast your care on Jesus today,\nleave your worry and fear.\nBurdens are lifted at Calvary,\nJesus is very near.\r\nTroubled soul, the Saviour can feel\nevery heartache and tear.\nBurdens are lifted at Calvary,\nJesus is very near.', 'Ist dein Herz voll Sorgen und Schmerz,\ndie bedrücken dein Herz?\nLasten, sie fallen auf Golgatha,\nJesus ist immer nah.\r\nLasten, sie fallen auf Golgatha,\nGolgatha, Golgatha.\nLasten, sie fallen auf Golgatha,\nJesus ist immer nah.\r\nEr hilft dir, vertraue auf Ihn,\ngib dich völlig Ihm hin.\nLasten, sie fallen auf Golgatha,\nJesus ist immer nah.\r\nAlle, die vertrauen auf Ihn\nbringt Er sicher an\'s Ziel.\nLasten, sie fallen auf Golgatha,\nJesus ist immer nah.'),
(9, '0988', 'Ist dein Leben ein Segen für andre  -  Is your Life a Channel of blessing   (Mach mich zum Segen für andere heut)   [Siegesklänge]', 'Is your life a channel of blessing?\nIs the love of God flowing through you?\nAre you telling the lost of the Saviour?\nAre you ready His service to do?\r\nMake me a channel of blessing today,\nmake me a channel of blessing, I pray.\nMy life possessing, my service blessing,\nmake me a channel of blessing today.\r\nIs your life a channel of blessing?\nAre you burdened for those that are lost?\nHave you urged upon those who are straying\nthe Saviour Who died on the cross?\r\nIs your life a channel of blessing?\nIs it a daily telling for Him?\nHave you spoken the Word of salvation\nto those who are dying in sin?\r\nWe cannot be channels of blessing,\nif our lives are not free from known sin.\nWe will barriers be and a hindrance\nto those we are trying to win.', 'Ist dein Leben ein Segen für and\'re?\nStrahlst du göttliche Liebe hinaus?\nKündest Sündern du Heil und Erlösung?\nFührst Verlorene heim du nach Haus?\r\nMach mich zum Segen für andere heut\',\nmach mich zum Segen zu jeglicher Zeit!\nNimm hin mein Leben; Dir ganz ergeben,\nmach mich zum Segen für andere heut\'!\r\nIst dein Leben ein Segen für and\'re?\nHilfst du anderen erleichtern die Last?\nHast du Balsam für blutende Herzen?\nZeigst du Müden die Stätte der Rast?\r\nIst dein Leben ein Segen für and\'re?\nBist du täglich und stündlich bereit,\nden Geringsten und Ärmsten zu dienen?\nBist ein Segen für andre du heut\'?\r\nO, wir werden nicht andern zum Segen,\nwenn die Sünde noch Raum in uns hat.\nSei dem Herrn darum völlig ergeben,\nso gebraucht dich die göttliche Gnad\'.'),
(9, '0989', 'Ist der Tag gleich trübe und wolkenschwer  -  There are Days so dark that I seek in vain   (O, zu fühlen des Heilands Hand)', 'There are days so dark that I seek in vain\nfor the face of my Friend divine.\nBut though darkness hide, He is there to guide\nby the touch of His hand on mine.\r\nOh, the touch of His hand on mine,\noh, the touch of His hand on mine!\nThere is grace and pow’r in the trying hour,\nin the touch of His hand on mine.\r\nThere are times, when tired of the toilsome road,\nthat for ways of the world I pine.\nBut He draws me back to the upward track\nby the touch of His hand on mine.\r\nWhen the way is dim, and I cannot see\nthrough the mist of His wise design.\nHow my glad heart yearns and my faith returns\nby the touch of His hand on mine.\r\nIn the last sad hour, as I stand alone\nwhere the powers of death combine.\nWhile the dark waves roll He will guide my soul\nby the touch of His hand on mine.', 'Ist der Tag gleich trübe und wolkenschwer,\nscheint Sein Antlitz mir abgewandt,\nob verhüllt Sein Licht, ich erschrecke nicht,\nfühl\' ich nur meines Heilands Hand.\r\nO, zu fühlen des Heilands Hand.\nAuch in schwerster Pein\nkann getrost ich sein,\nfühl\' ich nur meines Heilands Hand.\r\nWenn ich oft noch spüre den alten Zug\nhin zur Welt und zu ihrem Tand,\nhält mich doch Sein Rat auf dem schmalen Pfad,\nfühl\' ich nur meines Heilands Hand.\r\nWenn so oft der Weg, den ich wandeln soll,\nmir auch dunkel und unbekannt,\ndarf ich ohne Grau\'n Seine Leitung trau\'n,\nfühl\' ich nur meines Heilands Hand.\r\nWenn zuletzt vollbracht hier mein Pilgerlauf,\nund ich steh an des Jordans Strand,\ngeht\'s im Glaubensmut auch durch Todesflut,\nfühl\' ich nur meines Heilands Hand.'),
(9, '0990', 'Ist der Weg hier unten schmal und steinig auch  -  Tho\' the Way we journey may be often drear   (Ja wir solln den König sehn)', 'Tho\' the way we journey may be often drear,\nwe shall see the King some day.\nOn that blessed morning clouds will disappear,\nwe shall see the King some day.\r\nWe shall see the King some day,\nwe will shout and sing some day.\nGathered ’round the throne,\nwhen He shall call His own,\nwe shall see the King some day.\r\nAfter pain and anguish, after toil and care,\nwe shall see the King some day.\nThro\' the endless ages joy and blessing share,\nwe shall see the King some day.\r\nAfter foes are conquered, after battles won,\nwe shall see the King some day.\nAfter strife is over, after set of sun,\nwe shall see the King some day.\r\nThere with all the loved ones who have gone before,\nwe shall see the King some day;\nSorrow past forever, on that peaceful shore,\nwe shall see the King some day.', 'Ist der Weg hier unten schmal und steinig auch,\neinst soll\'n wir den König seh\'n,\nschnell verschwindet auch des letzten Schattens Hauch,\nwenn wir unsern König sehn.\r\nJa, wir soll\'n den König seh\'n,\njubelnd soll\'n wir vor Ihm steh\'n.\nDurch Sein Blut befreiet ewig alle Zeit,\nwerden wir den König seh\'n.\r\nNach des Lebens Mühe, Angst und Not und Pein,\nwerden wir den König seh\'n,\ndort, wo keine Trennung, ewig glücklich sein,\nund Ihn, unsern König seh\'n.\r\nWenn das Siegesbanner triumphierend weht,\nwerden wir den König seh\'n,\nwenn nach heißem Tag die Sonne untergeht,\nwerden wir den König seh\'n.\r\nDort mit allen Lieben, die uns schon voraus,\nwerden wir den König seh\'n,\nin den ew\'gen Hütten, wenn wir ganz zu Haus,\nwerden wir den König seh\'n.'),
(9, '0991', 'Ist er nah? Ist er nah? Wächter, sag, was siehst du da', NULL, 'Ist er nah? Ist er nah?\nWächter, sag, was siehst du da?\nIst der Gnadentag zu Ende?\nGeh\'n die Jahre schon zur Wende?\nSage, ist uns Jesus nah?\r\nKomme bald! Komme bald!\nHerr, das Glaubenslied erschallt.\nUnd in ungezählten Zungen,\nvon der Wächterschar gesungen,\ntönt\'s: "Herr Jesus, komme bald!"\r\nMorgenrot, Morgenrot,\nsteig empor aus Nacht und Not!\nPlötzlich wird es dann geschehen,\ndass ich Jesum werde sehen,\nüberwunden ist der Tod.\r\nKaum gedacht, kaum gedacht,\nwird dem Leid ein End\' gemacht.\nGestern noch verfolgt, verhöhnet;\nheute schon entrückt, gekrönet,\nsteh\'n wir da in Himmelspracht.\r\nO wie bald, o wie bald\nsiegt die göttliche Gewalt!\nSchon zerstöret Jesu Stärke\nSatans Reich und Satans Werke,\nbis bei Ihm das Loblied schallt.\r\nDarum still, darum still\nfüg\' ich mich, wie Gott es will;\nich will warten, wachen, beten,\ngern den Leidensweg betreten.\nEinz\'ger Weg zum ew\'gen Ziel!'),
(9, '0992', 'Ist Er nicht wunderbar  -  Isn\'t He wonderful', 'Isn\'t He wonderful,\nwonderful, wonderful?\nIsn\'t Jesus, my Lord, wonderful?\nEyes have seen, ears have heard,\nwhat\'s recorded in God\'s Word.\nIsn\'t Jesus, my Lord, wonderful?\r\n\r\n', 'Ist Er nicht wunderbar,\nist Er nicht wunderbar,\nist Er nicht wunderbar, unser Jesus?\nIhn gesehen, Ihn gehört,\nund in seinem Wort verklärt,\nist er nicht wunderbar, wunderbar?\r\nJa, Er ist wunderbar,\nja, Er ist wunderbar,\nja, Er ist wunderbar, unser Jesus!\nIhn gesehen, Ihn gehört\nund in Seinem Wort verklärt.\nJa, Er ist wunderbar, wunderbar!\r\nJa, Er bleibt wunderbar,\nja, Er bleibt wunderbar,\nja, Er bleibt wunderbar,unser Jesus!\nIhn gesehen, Ihn gehört\nund in Seinem Wort verklärt.\nJa, Er bleibt wunderbar, wunderbar!'),
(9, '0993', 'Ist es nicht herrlich, einfach nur ein Christ zu sein', NULL, 'Ist es nicht herrlich, einfach nur ein Christ zu sein,\ndu brauchst keinen frommen Schein und auch nichts Besond\'res sein.\nWenn Jesus Christus an der Innenseite wohnt,\ndann lebt in dir Gottes Sohn und dann kannst du in Ihm ruh\'n.\r\nIst es nicht herrlich, einfach nur ein Christ zu sein,\nund der Herr wird in dir groß und du selber wirst ganz klein.\nEs ist so herrlich, und weil Christus in dir ist\nbist du einfach nur ein Christ, das ist alles was du bist.\r\nEs ist so herrlich: Du bist einfach nur ein Christ,\nder sich selber gern vergisst, weil der Herr der Große ist.\nDu kämpfst jetzt nicht mehr, nicht für Ehre, nicht für Ruhm,\ndu bist ja Sein Eigentum, willst auch gar nichts and\'res tun.'),
(9, '0994', 'Ist getilgt die Sünde? Bist du heil und neu?  -  Have you been to Jesus for the cleansing Powr?   (Bist du rein durch das Blut)   [Pfingstjubel, 4 Strophen]', 'Have you been to Jesus for the cleansing pow\'r?\nAre you washed in the blood of the Lamb?\nAre you fully trusting in His grace this hour?\nAre you washed in the blood of the Lamb?\r\nAre you washed in the blood,\nIn the soul-cleansing blood of the Lamb?\nAre your garments spotless?\nAre they white as snow?\nAre you washed in the blood of the Lamb?\r\nAre you walking daily by the Saviour\'s side?\nAre you washed in the blood of the Lamb?\nDo you rest each moment in the Crucified?\nAre you washed in the blood of the Lamb?\r\nWhen the Bridegroom cometh, will your robes be white?\nPure and white in the blood of the Lamb?\nWill your soul be ready for the mansions bright,\nAnd be washed in the blood of the Lamb?\r\nLay aside the garments that are stained with sin,\nAnd be washed in the blood of the Lamb.\nThere\'s a fountain flowing for the soul unclean,\nOh, be washed in the blood of the Lamb.', 'Ist getilgt die Sünde? Bist Du heil und neu?\nBist Du rein durch des Heilandes Blut?\nBist Du neugeboren von der Knechtschaft frei?\nBist Du rein durch des Heilandes Blut?\r\nBist du rein durch das Blut,\nbist du rein durch des Heilandes Blut?\nIst dein Kleid schon helle,\nist es weiß wie Schnee?\nBist du rein durch des Heilandes Blut?\r\nHältst Du treulich wachend bei dem Kreuze stand?\nBist Du rein durch des Heilandes Blut?\nGehst Du kindlich gläubig stets an Jesu Hand?\nBist Du rein durch des Heilandes Blut?\r\nWenn der Bräut´gam kommet ist Dein Herz bereit?\nBist Du rein durch des Heilandes Blut?\nStehst im heil\'gen Schmuck Du und im weißen Kleid?\nBist Du rein durch des Heilandes Blut?\r\nSo entsag\' der Sünde, lieb den Herrn allein,\nwerde rein durch des Heilandes Blut!\nSieh, der Brunnen fließet, tauch\' Dich tief hinein!\nWerde rein durch des Heilandes Blut!'),
(9, '0995', 'Ist\'s wahr, dass Jesus starb für mich  -  Alas and did my Saviour bleed and did my Sov\'reign die   (An dem Kreuz, an dem Kreuz brach der Morgen mir an)   [Pfingstjubel]', 'Alas and did my Saviour bleed\nand did my sov\'reign die.\nWould He devote that sacred head\nfor such a worm as I.\r\nAt the cross, at the cross, where I first saw the light\nand the burden of my heart rolled away,\nit was there by Faith, I received my sight\nand now I am happy all the day.\r\nWas it for crimes that I have done,\nHe groaned upon the tree.\nAmazing pity grace unknown\nand love beyond degree.\r\nBut drops of grief cannot repay\nthe debt of love I owe.\nHere lord I give myself away\nit\'s all that I can do.', 'Ist\'s wahr, dass Jesus starb für mich\nund büßte meine Schuld?\nDass Gottes Sohn am Kreuz verblich?\nO, wundersame Huld!\r\nAn dem Kreuz, an dem Kreuz\nbrach der Morgen mir an,\nund des Blinden Auge ward aufgetan,\ndenn ins Herze ließ ich den Heiland ein,\nHosianna, nun ist der Friede mein!\r\nTrug meine Sünd das Gotteslamm?\nGalt mir Sein Schmerzensschrei?\nDann seh\' ich erst am Kreuzesstamm,\nwas Gottes Liebe sei.\r\nO Herr, mit Tränen kann ich nie\ndie Schuld Dir zahlen ab;\nso nimm mich, Jesus, selber an,\nist\'s alles, was ich hab.'),
(9, '0996', 'It is all over me and it\'s keeping me alive   (Chorus)', 'It is all over me and it\'s keeping me alive,\nkeeping me alive, keeping me alive.\nIt is all over me and it\'s keeping me alive,\nJesus, it\'s keeping me alive.', NULL),
(9, '0997', 'It is alright, it is alright, as long as I have my Lord beside me', 'It is alright, it is alright,\nAs long as I have my Lord beside me,\nIt\'s alright.\nAs long as I have His Hand to hold,\nAs long as He watches over my soul,\nAs long as I\'m under His control,\nIt is alright.', NULL),
(9, '0998', 'It is Grace, Grace, Grace to serve the Lord', 'It is grace, grace,\ngrace to serve the Lord\nIt is grace, grace,\ngrace to serve the Lord.\nIt is grace, grace to serve the Lord,\nIt is grace, grace to serve the Lord.\r\nWe\'ve come from far, far,\nfar to serve the Lord.\nWe\'ve come from far, far,\nfar to serve the Lord.\nWe\'ve come from far,\nfar to serve the Lord.\nWe\'ve come from far,\nfar to serve the Lord.\r\nWe\'ve come from far, far,\nfar to praise the Lord.\nWe\'ve come from far, far,\nfar to praise the Lord.\nWe\'ve come from far,\nfar to praise the Lord.\nWe\'ve come from far,\nfar to praise the Lord.', NULL),
(9, '0999', 'It is more than a Dream, it is true Reality   (Chorus)', 'It is more than a dream, it is true reality,\nThat Jesus gave His life for me on Calvary.\nCan\'t you see Him hanging there\nall alone on Calvary,\nAnd to me it\'s more than a dream.', NULL),
(9, '1000', 'It shall flow like a River, it shall fall like the Rain', 'It shall flow like a river,\nit shall fall like the rain,\nit shall rise as the dew in the morning\no\'er the plain;\nfor the knowledge of the Lord\nshall fill all the earth\nwhen the Spirit of the Lord shall fall.\r\nFlow, river, flow;\nflow, river, flow;\nflow out through the nations\nwherever man may go;\ncause life to spring forth,\nthat all men may know\nthat You\'re the river of the Spirit;\noh, flow, river, flow.', NULL);
INSERT INTO song_list (LISTID, NUM, NAME, TEXT_EN, TEXT_DE) VALUES
(9, '1001', 'It was 1909, in a lonely old Cabin', 'It was 1909, in a lonely old cabin,\nwhere a baby was born,\nwith a sign over him.\nThe pillar of Fire came down that day,\nand whirled into the window\nin the room where he laid.\nAs he grew a little older\nhis parents told him,\nabout the mysterious light\nthat came in.\r\nAlone and forsaken by faith and by man,\ntill an Angel came down,\nso he would understand,\nHe was God\'s chosen man!\r\nOne day he was resting\nbeneath an old old tree,\nwhen he noticed a whirlwind\nrustling the leaves.\nHe thought, nothing strange,\nbut when he started to go,\na big Voice came forth and here\'s what He spoke:\n"Don\'t drink, nor smoke,\ndefile your body in any way.\nI\'ve got a work for you later,\nI\'ll show you some day."\r\nAt the age of seven\nGod showed him a vision,\nabout a bridge being built,\nlater on was fulfilled.\nOn the Ohio river\nwhere the bridge now stands,\nthere the mysterious cloud\ncame down again.\nAs he baptized his seventeenth\nperson that day,\nthousands were there\nto witness that day.\r\nAbout the story I told you,\nI know there is more,\nhe was the fulfillment of Malachi 4.\nNow if there\'s a doubt in your mind,\nwhat you heard,\ndon\'t take it from me,\ncheck it out with the Word.\nWith an open heart,\nGod will show you that it\'s plain,\nThat William Branham\nis this man\'s name!', NULL),
(9, '1002', 'It was a Day in early Spring Time   (O get ready, the Evening Shadows fall)   (Eleazar\'s Camel Train)', '\'T was a day in early spring time\nby an ancient way-side well.\nEleazar paused to rest his camel train.\nHe had found a bride for Isaac\nand the evening shadows fell.\nAnd his weary journey had not been in vain.\r\nO get ready, the evening shadows fall,\ndon\'t you hear that "Eleazar" call.\nThere is going to be a wedding supper,\nour joys will soon begin.\nIn the evening, when the camel train comes in.\r\nSo he took the fair Rebecca,\ndecked in jewels rich and rare,\nback to Abraham and Isaac faraway.\nNow Rebecca loved her Isaac\nand he loved Rebecca fair,\noh, it must have been a happy wedding day!\r\nThe blessed Holy Spirit,\nthrough the prophet of this day,\nhas come down to earth to claim a worthy bride.\nFor our Isaac over yonder\nhas prepared His tents of love.\nAnd He wants His fair Rebecca by His side.\r\nWe\'ve left our kinfolks gladly,\nwe bade the world good-bye,\nfor we\'re going to a land beyond the sky.\nWe shall soon behold our Isaac\nin the blessed eternity,\nwhat a happy, happy meeting that will be.\r\nWe\'re on our camel journey\nto a land beyond the sky,\nwhere our Isaac waits to meet His happy bride.\nWhat a holy consummation,\nwhat a glorious jubilee!\nWhen we see the fair Rebecca by His side.\r\nThat will be a joyful meeting,\nwhen the camel train comes in,\nwhen Rebecca leaves her camel by the way.\nWe\'ll close our earthly journey\nwith a joyful noise and then\nthat will surely be a happy wedding day.', NULL),
(9, '1003', 'It\'s a Highway to Heaven', 'It\'s a highway to heaven\nnone can walk up there\nbut the pure in heart.\nIt\'s a highway to heaven\nwalking on the King\'s highway.\r\nMy way gets brighter, my load gets lighter\nWalking up the Kings highway\nThere\'s joy in knowing with him I\'m going\nWalking up the Kings highway\r\nI don\'t have to worry, I don\'t have to hurry\nI\'m walking up the Kings highway\nChrist walks besides me, angels to guide me\nWalking up the Kings highway\r\nIf you\'re not walking, start while I\'m talking\nI\'m walking up the Kings highway\nThere\'ll be a blessing, you\'ll be possessing\nI\'m walking up the Kings highway', NULL),
(9, '1004', 'It\'s almost Time for the Lord to come   (O, it must be the Breaking of the Day)', 'It\'s almost time for the Lord to come,\nI hear the people say;\nThe stars of heav\'n are growing dim:\nIt must be the breaking of the day.\r\nO, it must be the breaking of the day,\nO, it must be the breaking of the day;\nThe night is almost gone,\nThe day is coming on:\nO, it must be the breaking of the day.\r\nThe signs foretold in the sun and moon,\nIn earth and sea and sky,\nAloud proclaim to mortal men,\nThat the coming of the Master\ndraweth nigh.\r\nIt must be time for the waiting church\nTo cast her pride away,\nWith girded loins and burning lamps\nTo look for the breaking of the day.\r\nThere must be those in the field of sin,\nFar from the fold astray,\nWho once were happy in Jesus\' love,\nAnd looking for the breaking of the day.\r\nGo quickly out in the streets and lanes,\nAnd in the broad highway,\nAnd call the maimed, the halt and blind,\nTo be ready for the breaking of the day.', NULL),
(9, '1005', 'It\'s hard to take the first Step, when I don\'t know the Way   (Lead me Lord, I will follow)', 'It\'s hard to take the first step\nWhen I don\'t know the way\nEach turn is so uncertain\nI learn to walk by faith\nBut you gave me a promise\nThat you would never leave\nYou will lead and guide me\nLord, I do believe\r\nLead me Lord, I will follow\nLead me Lord, I will go\nYou have called me\nI will answer\nLead me Lord, I will go\r\nYour plans for me are perfect\nI never need to fear\nFor though in times I feel alone\nI know that You are near\nMy heart just wants to follow\nI\'m willing to obey\nTake my hand and lead me\nI\'ll follow all the way!', 'Es ist schwer, den ersten Schritt zu gehen,\nwenn ich den Weg nicht kenne.\nJeder weg ist so ungewiss.\nIch lerne im Glaube zu gehen.\nAber du hast mir versprochen, dass du\nniemals gehen wirst. Du wirst mich leiten\nund führen.  Herr, dass glaube ich.\r\nFühre mich Herr,  ich will folgen\nFühre mich Herr,  ich werde gehen\nDu hast mich gerufen\nIch möchte antworten\nFühre mich Herr,  ich werden gehen\r\nDeine Pläne für mich sind vollkommen.\nIch brauche mich niemals fürchten.\nObwohl ich mich manchmal einsam fühle,\nweiss ich das Du nahe bist.\nMein Herz möchte einfach folgen\nIch bin bereit zu gehorchen\nNimm meine Hand und führe mich\nIch folge den ganzen Weg.'),
(9, '1006', 'It\'s His Blood', 'It\'s His blood that cleanses Me\nIt\'s His blood that gives me life\nIt\'s His blood that took my place\nIn redeeming sacrifice\nAnd washes me, whiter than the snow\nthan the snow\nMy Jesus,  God\'s precious sacrifice', 'Es ist Sein Blut, das mich reinigt\nEs ist Sein Blut, das mir Leben gibt\nEs ist Sein Blut, das meinen Platz einnimmt\nIm erlösenden Opfer\nUnd wäscht mich, weißer als der Schnee\nals der Schnee\nMein Jesus,  Gottes kostbares Opfer'),
(9, '1007', 'It\'s Jesus I really want to see   (Chorus)', 'It\'s Jesus I really want to see (2x)\nThe more I see of this world\nthe less it means to me.\nFor it is Jesus I really want to see.', NULL),
(9, '1008', 'It\'s not the first Mile that you\'ll be judged by   (It\'s not the first Mile that\'s so important.)', 'It\'s not the first mile that you\'ll be judged by,\nfor you may stumble along the way.\nBut you\'ll grow stronger in faith and courage,\nas Jesus walks with you from day to day.\r\nIt\'s not the first mile that\'s so important.\nIt is the last mile, when day is done.\nAnd you\'ll see Jesus, in all His splendour,\nand He will have for you the crown you\'ve won.\r\nThere may be times when you\'ll have a burden,\nthat grows too heavy along the road.\nIf you will let Him, the blessed Saviour,\nHe\'ll be so glad to bear your heavy load.', NULL),
(9, '1009', 'It\'s soon be done all the Troubles and Trials - Bald sind vorbei all die Prüfungen und Leiden', 'It\'s soon be done all the troubles and trials,\nwhen I get home on the other side.\nI\'m gonna shake my hands with the elders,\nI\'m gonna tell all the people "Good morning",\nI\'m gonna sit down beside my Jesus,\nI\'m gonna sit down and rest a little while.', 'Bald sind vorbei all die Prüfungen und Leiden,\nwenn es heim geht auf die and\'re Seit\'.\nIch werd\' begrüßen all\' die Lieben,\nich sage allen "Guten Morgen",\nich werde sitzen neben Jesus,\nich sitze nieder und ruh\' ein wenig aus.'),
(9, '1010', 'It\'s the old Ship of Zion   (2 Chorusse)', 'It\'s the old ship of Zion,\nIt\'s the old ship of Zion,\nIt\'s the old ship of Zion,\nGet on board, get on board.\r\nIt has landed my old father,\nIt has landed my old father,\nIt has landed my old father,\nGet on board, get on board.', NULL),
(9, '1011', 'I’ve tried all I could, it seems like nothing did me any good   (O es ist Jesus  -  Oh it is Jesus)', 'Oh it is Jesus! Yes, it is Jesus,\nit is Jesus in my soul!\nFor I have touched the hem of His garment,\nand His blood has made me whole.\r\nI’ve tried all I could,\nit seems like nothing did me any good.\nThen I heard Jesus, he’s passing by,\nand I decided to give him a try.\r\nNothing like Jesus!\nNobody hears my problems,\nwhen I was crying, when I was blue.\nAll I did was touch the hem of his garment,\nand his blood has made me whole.', 'O es ist Jesus, ja, es ist Jesus,\no es ist Jesus nur allein!\nIch hab\' berührt, den Saum Seines Kleides\nund Sein Blut, es wusch mich rein.\r\n\r\n'),
(9, '1012', 'J-O-Y, joy, joy in the Holy Ghost   (2 Chorusse)', 'J-O-Y, joy, joy in the Holy Ghost!\nJ-O-Y, joy, joy in the Lord.\r\nDon\'t let nobody steal your joy,\ndon\'t let nobody steal your joy,\ndon\'t let nobody steal your joy.\nJoy in the Lord.', NULL),
(9, '1013', 'Ja das ist Freude, unaussprechliche Freude', NULL, 'Ja, das ist Freude, unaussprechliche Freude,\nin Jesus Christus geborgen zu sein.\nJa, das ist Freude, unaussprechliche Freude,\nin Jesus Christus geborgen zu sein.\r\nJa, das ist Frieden, unaussprechlicher Frieden,\nin Jesus Christus geborgen zu sein!\nJa, das ist Frieden, unaussprechlicher Frieden,\nin Jesus Christus geborgen zu sein!\r\nJa, das ist Segen, unaussprechlicher Segen,\nin Jesus Christus geborgen zu sein!\nJa, das ist Segen, unaussprechlicher Segen,\nin Jesus Christus geborgen zu sein!'),
(9, '1014', 'Ja dort im Himmel verschwinden Traurigkeit und Leid und alles Weh   (Chorus)', NULL, 'Ja, dort im Himmel, dort im Himmel, dort im Himmel,\nverschwinden Traurigkeit und Leid und alles Weh.\nWenn mit den Heiligen vereint und allen Engeln,\nmeinen Heiland ich dort seh\'.'),
(9, '1015', 'Ja ich treff dich an dem Morgen an dem herrlichen Fluss  -  I will meet you in the morning by the bright river side   (Ich treff dich an dem Morgen)', 'I will meet you in the morning by the bright riverside,\nwhen all sorrow has drifted away.\nI’ll be standing at the portals when the gates open wide,\nat the close of life’s long dreary day.\r\nI’ll meet you in the morning\nwith a how do you do.\nAnd we’ll sit down by the river\nand with rapture old acquaintance renew.\nYou’ll know me in the morning\nby the smile that I wear.\nWhen I meet you in the morning\nin that city that is built four square.\r\nI will meet you in the morning, in the sweet by and by,\nand exchange the old cross for a crown.\nThere will be no disappointments and nobody shall die,\nin that land, ne\'er the sun goeth down.\r\nI will meet you in the morning, at the end of the way,\non the streets of that city of gold.\nWhere we all can be together and be happy for aye,\nwhile the years and the ages shall roll.', 'Ja, ich treff\' dich an dem Morgen an dem herrlichen Fluss,\nwenn von Sorgen und Nöten wir frei.\nJa, ich treff\' dich an dem Tore, wenn es weit offen steht,\nwenn das irdische Leben vorbei.\r\nIch treff dich an dem Morgen,\nwelche Freud\' dich zu seh\'n,\nund wir sitzen an dem Ufer\nan dem Flusse der so herrlich schön.\nDu wirst mich erkennen,\nhast mich ewig erkannt.\nJa ich treff dich an dem Morgen,\nja dort drüben in der gold\'nen Stadt.\r\nJa, ich treff\' dich an dem Morgen drüben in Herrlichkeit,\nund dann tausch ich das Kreuz für die Kron\'.\nJa, dort gibt es keine Trauer, la, dort gibt\'s keinen Tod.\nIn dem Land wo erstrahlt uns der Sohn.\r\nJa, ich treff\' dich an dem Morgen, wenn die Reise vorbei,\nauf den Straßen der goldenen Stadt,\nwo wir fröhlich sind zusammen und glücklich vereint,\nwo Gemeinschaft kein Ende hat.'),
(9, '1016', 'Ja in Jesus sind wir Brüder und Schwestern  -  You will notice, we say \'Brother\' and \'Sister\' round here   (Ich bin froh, dass ich weiß, Gottes Eigen zu sein)', 'I\'m so glad, I\'m a part of The family of God,\nI\'ve been washed in the fountain, cleansed by His blood.\nJoint heirs with Jesus, as we travel this sod,\nfor I\'m part of the family, the family of God.\r\nYou will notice, we say \'brother\' and \'sister\' round here,\nit\'s because we\'re a family and these folks are so near.\nWhen one has a heart-ache, we all share the tears,\nand rejoice in each\'s victory in this family so dear.\r\nFrom the door of an orphanage to the house of a King,\nno longer an outcast, a new song I sing.\nFrom rags unto riches, from the weak to the strong.\nI\'m not worthy to be here, but praise God I belong.', 'Ich bin froh, dass ich weiß, Gottes Eigen zu sein.\nIn dem Blut meines Heilands wusch Er mich rein.\nMit Ihm verbunden, ich war vorher so fern.\nJetzt gehöre ich ewig zur Familie des Herrn.\r\nJa, in Jesus sind wir Brüder und Schwestern in Ihm.\nWir sind eine Familie und gemeinsam wir zieh\'n.\nDenn ist einer traurig, tragen alle sein Leid,\nselbst die Freude zu teilen, ist ein jeder bereit.\r\nAus dem Waisenhaus kam ich zu dem Königshof hin,\nnicht länger verstoßen, ich ein neues Lied sing.\nVom Bettler zum Reichen wurde ich durch Sein Heil.\nIch bin dessen nicht würdig, doch hab\' ich daran teil.'),
(9, '1017', 'Ja Jesus lebt', NULL, 'Der Herr ist auferstanden,\nEr ist wahrhaftig auferstanden,\nder Herr ist auferstanden\nund Er lebt!\nJa, Jesus lebt (3x)\nin Ewigkeit!'),
(9, '1018', 'Ja keiner ist größer als Jesus  -  There\'s no one like Jesus   (2 Chorusse)', 'There\'s no one, there\'s no one like Jesus\nThere\'s no one, there\'s no one like Him.\nThere\'s no one, there\'s no one like Jesus\nThere\'s no one, there\'s no one like Him.\r\nI\'ve searched all over, over, over\nI\'ve looked all over, over, over\nI\'ve run all over, over, over\nThere\'s no one, there\'s no one like Him.', 'Ja, keiner ist größer als Jesus,\nja, keiner ist größer als Er,\nja, keiner ist größer als Jesus,\nja, keiner ist größer als Er.\r\nIch sucht\' überall, überall, überall,\nich schaut\' überall, überall, überall.\nIch lief hin überall, überall, überall,\nes gibt niemand, ja niemand wie Ihn.'),
(9, '1019', 'Ja wir stehen, auf heilgem Grund (We are standing on holy ground) - Chorus', 'When I walked through the doors I sensed His presence\nand I knew, this was a place where love abounds.\nFor this is a temple, the God we love abides here.\nOh, we are standing in His presence on holy ground!\r\nWe are standing, on holy ground,\nand we know that there are angels all around.\nLet us praise, Jesus now,\nwe are standing in His presence on holy ground.\r\nIn His presence I know, there is joy beyond all measure.\nAnd at His feet, sweet peace of mind can still be found.\nFor when we have a need, He is still the answer.\nOh, reach out and claim it, for we are standing on holy ground!', '\r\nJa wir stehen, auf heil\'gem Grund\nund wir wissen um der Engel um uns herum.\nLasset uns preisen, Jesu Nam\'!\nStehend heut\' auf heil\'gem Grund in Seiner Gegenwart.\r\n'),
(9, '1020', 'Ja, da gibt es ein Land, das noch kein Aug gesehn  -  There’s a country far beyond the starry Sky   (In der Stadt, die der Herr hat bereit)', 'There’s a country far beyond the starry sky,\nthere’s a city where there never comes a night.\nIf we’re faithful we shall go there by and by,\n’tis the city where the Lamb is the light.\r\nIn that city where the Lamb is the light,\nthe city where there cometh no night.\nI’ve a mansion over there,\nand when free from toil and care,\nI am going where the Lamb is the light.\r\nHere we have our days of sunshine, but we know\nthat the sun which shines upon us now so bright\nwill be changed to clouds and rain until we go\nto the city where the Lamb is the light.\r\nThere the flowers bloom forever and the day\nshall be one eternal day without a night.\nAnd our tears shall be forever wiped away,\nin that city where the Lamb is the light.\r\nHere we have our disappointments all the while,\nand our fondest hopes but meet with bitter blight.\nTho’ by night we weep, the morning brings a smile,\nin that city where the Lamb is the light.\r\nThen let sunlight fade, let twilight bring its gloom,\nnot a shadow can my blissful soul affright.\nFor I know that up in Heaven there is room,\nin that city where the Lamb is the light.', 'Ja, da gibt es ein Land, das noch kein Aug geseh\'n,\neine ew\'ge Stadt, die nie mehr wird vergeh\'n.\nWenn wir treu sind wohnen wir in Ewigkeit\nin der Stadt, die der Herr hat bereit\'.\r\nIn der Stadt, die der Herr hat bereit\'\nund sein Licht erstrahlt allezeit.\nIch hab eine Wohnung dort,\nnur noch Freud\' an jenem Ort,\nin der Stadt, die der Herr hat bereit.\r\nHier auf Erden sehn wir manchen Sonnenschein,\ndoch auch Wolken und auch regen müssen sein,\ndoch dies ist vorbei, wenn wir in Ewigkeit\nseh\'n die Stadt, die der Herr hat bereit.\r\nJa, dort seh\'n wir ewiglich die Blumen blüh\'n,\nund kein Dunkel, keine Nacht soll\'n wir dort seh\'n.\nOhne Tränen sehen wir von Not befreit\ndie Stadt, die der Herr hat bereit\'.\r\nMüssen wir auch manchmal durch Enttäuschung geh\'n,\nmanches Mal trifft uns des Lebens Bitterkeit.\nAll das ist vergessen an dem Morgen schön\nin der Stadt, die der Herr hat bereit\'.\r\nMuss ich dann auf Erden geh\'n durch\'s finst\'re Tal,\nkann kein Schatten mich erschrecken allezeit.\ndenn ich weiß, dass ich dort eine Wohnung hab\',\nin der Stadt die der Herr bereit\'.'),
(9, '1021', 'Ja, da gibt\'s ein Land der Freude auf der ander\'n Jordanseite  -  There\'s a Land beyond the river, that we call the sweet forever   (Hörst du nicht schon all die Stimmen)', 'There’s a land beyond the river,\nthat we call the sweet forever,\nand we only reach that shore by faith’s decree.\nOne by one we’ll gain the portals,\nthere to dwell with the immortals,\nwhen they ring the golden bells for you and me.\r\nDon’t you hear the bells now ringing,\ndon’t you hear the angels singing?\n’Tis the glory hallelujah Jubilee.\nIn that far off sweet forever,\njust beyond the shining river,\nwhen they ring the golden bells for you and me.\r\nWe shall know no sin or sorrow,\nin that haven of tomorrow,\nwhen our barque shall sail beyond the silver sea.\nWe shall only know the blessing\nof our Father’s sweet caressing,\nwhen they ring the golden bells for you and me.\r\nWhen our days shall know their number,\nand in death we sweetly slumber,\nwhen the King commands the spirit to be free.\nNevermore with anguish laden,\nwe shall reach that lovely Aiden,\nwhen they ring the golden bells for you and me.', 'Ja, da gibt\'s ein Land der Freude\nauf der ander\'n Jordanseite\nund der Glaube trägt die Heiligen hinein.\nMancher ist schon hingegangen,\nwo nur Heil\'ge hingelangen,\nwelche Freude: Bald schon werden wir dort sein!\r\nHörst du nicht schon all die Stimmen,\ndie vom and\'ren Ufer klingen\nund sie singen Halleluja ewiglich.\nIn dem schönen ew\'gen Lande\nan dem herrlich gold\'nem Strande.\nO welch herrlichkeit erwartet dich und mich!\r\nDort gibt\'s nie mehr Sünd\' und Sorgen,\nauch kein Gestern und kein Morgen,\nnur noch Freude in dem Herzen ewiglich.\nFreude, dass wir zu Dem kamen,\nDer uns hier schon rief mit Namen.\nO welch Herrlichkeit erwartet dich und mich!\r\nWenn gezählt hier uns\'re Tage\nund wir liegen dann im Grabe\nund das ird\'sche Leben hinter uns verblich.\nJa dann treffen wir dort jeden,\nden Er rief in Gottes Eden.\nO welch Herrlichkeit erwartet dich und mich!'),
(9, '1022', 'Ja, das ist Gnade für mich   (Chorus)', NULL, 'Ja, das ist Gnade für mich,\nja, das ist Gnade für dich.\nJesus allein kann erretten.\nJa, das ist Gnade für dich.'),
(9, '1023', 'Ja, Deine Hand, Herr Jesus, zog mich aus Sünd\' und Not   (Hand die mich gesucht hat)', NULL, 'Ja, Deine Hand, Herr Jesus,\nzog mich aus Sünd\' und Not,\nerhöht mich auf den Felsen,\nwo kein Verderben droht.\nDie Hand am Kreuz durchbohrt für mich,\nhält mich geborgen ewiglich.\r\nHand die mich gesucht hat,\nBlut das ich erkauft hat,\nGnade, die mich wieder heim gebracht;\nLob und Preis sei Deiner Liebe Macht.\r\nDein Blut gabst Du, Herr Jesus,\nam Kreuz von Golgatha.\nEs tilgt die Schuld und decket\ndie Sünden ganz und gar.\nEs hat inmitten dieser Zeit\nmich Gott erkauft in Ewigkeit.\r\nDu hast durch Deine Gnade\nmein Leben reich gemacht,\naus Leid und Nacht und Sünde\nmich in Dein Licht gebracht.\nD\'rum preis ich Dich, Herr Jesus Christ,\nweil Deine Lieb\' unendlich ist.\r\nNun darf ich selig leben\nvor Seinem Angesicht.\nUnd Seine Wunderwege\nhier schau\'n in Seinem Licht.\nZum Preise Seiner Herrlichkeit\ndünkt mir zu kurz die Ewigkeit.'),
(9, '1024', 'Ja, es gibt eine Stadt, die erbauet von Gold   (Dort die Sonn ewig scheint, dort kein Auge mehr weint)', NULL, 'Ja, es gibt eine Stadt, die erbauet von Gold,\nund kein Mund je beschrieben sie hat!\nWo die Sonne scheint ewig und wo nichts verwelkt,\nin der herrlichen goldenen Stadt.\r\nDort die Sonn\' ewig scheint,\ndort kein Auge mehr weint,\nund wir freu\'n uns an Jesu Liebe und Gnad\',\nin der herrlichen goldenen Stadt.\r\nAll die Seelen, die wir einst geführt zu Deinem Kreuz\nund die Jesus gerettet hier hat,\njedes Lamm, das zur Herde zurück gebracht,\nfinden wir in der goldenen Stadt.\r\nDann erschallt dort im Chore das herrliche Lied,\nwie der Heiland befreiet uns hat,\nund die Harfen erklingen so rein und so hell\nin der herrlichen goldenen Stadt.'),
(9, '1025', 'Ja, Gott ist gut  -  Yes, God is good   (5 Chorusse)', 'Yes, God is good, yes, God is good,\nyes, God is good, He\'s so good to me.\r\nI love Him so, I love Him so,\nI love Him so, He\'s so good to me.\r\nPraise to His name, praise to His nName,\nPraise to His name, He\'s so good to me.\r\nStand on the word, stand on the word,\nstand on the word, He\'s so good to me.\r\nGod answers prayer, God answers prayer,\nGod answers prayer, He\'s so good to me.', 'Ja, Gott ist gut, ja, Gott ist gut,\nja, Gott ist gut, Er ist gut zu mir.\r\nIch lieb\' Ihn so, ich lieb\' Ihn so,\nich lieb\' Ihn so, Er ist gut zu mir.\r\nPreist Seinen Nam\', preist Seinen Nam\',\npreist Seinen Nam\', Er ist gut zu mir.\r\nSteh\' auf dem Wort, steh\' auf dem Wort,\nsteh\' auf dem Wort, Er ist gut zu mir.\r\nGott hört Gebet, Gott hört Gebet,\nGott hört Gebet, Er ist gut zu mir.'),
(9, '1026', 'Ja, ich treff dich an dem Morgen in dem Osttor werd\' ich steh\'n  -  I will meet you in the Morning just inside the eastern Gate   (Ja, ich treff dich an dem Morgen)', 'I will meet you in the morning,\njust inside the Eastern Gate.\nThen be ready, faithful pilgrim,\nlest with you it be too late.\r\nI will meet you in the morning,\nI will meet you in the morning,\njust inside the Eastern Gate over there;\nI will meet you in the morning,\nI will meet you in the morning,\nI will meet you in the morning over there.\r\nIf you hasten off to glory,\nlinger near the Eastern Gate.\nFor I\'m coming in the morning,\nsyou\'ll not have long to wait.\r\nKeep your lamps all trimmed and burning,\nfor the Bridegroom watch and wait.\nHe\'ll be with us at the meeting,\njust inside the Eastern Gate.\r\nO the joys of that glad meeting\nwith the saints who for us wait.\nWhat a blessed, happy meeting,\njust inside the Eastern Gate.', 'Ja, ich treff\' dich an dem Morgen,\nin dem Osttor werd\' ich steh\'n.\nSei bereit, du treuer Pilger,\nbald schon wird\'s nach Hause gehen.\r\nJa, ich treff\' dich an dem Morgen,\nja, ich treff\' dich an dem Morgen,\nin dem Osttor werden wir uns einmal seh\'n.\nJa, ich treff\' dich an dem Morgen,\nja, ich treff\' dich an dem Morgen,\nin dem Osttor werden wir uns einmal seh\'n.\r\nWenn zur Herrlichkeit du eingehst,\nbleib doch an dem Osttor steh\'n,\ndenn ich komme an dem Morgen,\nwenn wir an dem Osttor steh\'n.\r\nHalt die Lampe rein und klar,\nhalte Ausschau wart\' auf Ihn!\nDenn der Bräutigam wird bei uns sein,\nwenn wir an dem Osttor steh\'n.\r\nO, was ist das für ein Treffen,\nall die Heiligen sind dort.\nWelch ein Segen bei dem Treffen,\ndas wir haben an dem Tor.'),
(9, '1027', 'Ja, wenn der Wind des Geistes weht   (Komm mit, steig ein und bleib nicht einfach sitzen)', NULL, 'Ja, wenn der Wind des Geistes weht\nund heut\' das Wasser sich bewegt,\ndann sage doch, dann sage doch:\n"Bestimmt meint Jesus heut\' auch mich!"\r\nKomm mit, steig ein und bleib\' nicht einfach sitzen!\nDer Herr kann heut\' für Sein Kind etwas tun.\nKomm mit, steig ein! Heut\' kann sich alles ändern,\ndenn Jesus wartet auf dich lange schon.\r\nUnd wenn dich grad\' die Not bedrängt,\ndas Leben dir nur Sorgen bringt,\nvielleicht gibt dir ein Augenblick\ndie Freude an dem Herrn zurück.\r\nUnd wenn du dort an deinem Platz\nso lange nichts empfangen hast,\ndann solltest du nicht resignier\'n,\nder Herr kann heute dich berühr\'n.'),
(9, '1028', 'Ja, wir sind auf dem richtigen Weg   (4 Chorusse)', NULL, 'Ja, wir sind auf dem richtigen Weg,\nja, wir sind auf dem richtigen Weg,\ndem Weg in die himmlische Stadt,\nja, wir sind auf dem richtigen Weg!\r\nJa, wir sehen die himmlische Stadt,\nja, wir sehen die himmlische Stadt,\nGottes lebendige Stadt,\nja, wir sehen die himmlische Stadt!\r\nJa, Himmel und Erde vereint,\nja, Himmel und Erde vereint,\nein Geist regiert diese Stadt,\nja, Himmel und Erde vereint!\r\nJa, die Tugenden Gottes in mir,\nja, die Tugenden Gottes in mir,\nSündenverlangen ist weg,\nja, die Tugenden Gottes in mir!'),
(9, '1029', 'Jahre lebte ich in Nichtigkeit  -  Years I spent in Vanity and Pride   (Gnade wurde mir am Kreuz geschenkt)', 'Years I spent in vanity and pride\nCaring not my Lord was crucified\nKnowing not it was for me He died\non Calvary\r\nMercy there was great, and grace was free,\nPardon there was multiplied to me.\nThere my burdened soul found liberty\nat Calvary\r\nBy God\'s Word at last my sin I learned,\nthen I trembled at the law I\'d spurned,\ntill my guilty soul imploring turned\nto Calvary.\r\nNow I\'ve given to Jesus everything,\nnow I gladly own Him as my King,\nnow my raptured soul can only sing\nof Calvary.', 'Jahre lebte ich in Nichtigkeit,\nJesus suchte ich zu keiner Zeit,\numzukehren war ich nicht bereit\nnach Golgatha.\r\nGnade wurde mir am Kreuz geschenkt.\nGnade, die heut\' meine Schritte lenkt.\nGnade, herrlich nur und wunderbar,\ndank Golgatha!\r\nLiebe hat mich dann zum Kreuz gelenkt.\nBuße hat mir Jesus auch geschenkt.\nFriede kam, als ich die Gnade sah\nauf Golgatha.\r\nHeute dank ich Jesus jeden Tag,\ndanke täglich, dass Er für mich starb.\nFrieden hat heut, wer die Gnade sah\nauf Golgatha.'),
(9, '1030', 'Jauchzet, ihr Himmel, frohlocket, ihr Engel in Chören', NULL, 'Jauchzet, ihr Himmel, frohlocket, ihr Engel in Chören,\nsinget dem Herren, dem Heiland der Menschen, zu Ehren!\nSehet doch da: Gott will so freundlich und nah\nzu den Verlornen sich kehren.\r\nJauchzet, ihr Himmel, frohlocket, ihr Enden der Erden!\nGott und der Sünder, die sollen zu Freunden nun werden.\nFriede und Freud wird uns verkündiget heut;\nfreuet euch, Hirten und Herden!\r\nSehet dies Wunder, wie tief sich der Höchste hier beuget;\nsehet die Liebe, die endlich als Liebe sich zeiget!\nGott wird ein Kind, träget und hebet die Sünd;\nalles anbetet und schweiget.\r\nGott ist im Fleische: wer kann dies Geheimnis verstehen?\nHier ist die Pforte des Lebens nun offen zu sehen.\nGehet hinein, eins mit dem Kinde zu sein,\ndie ihr zum Vater wollt gehen.\r\nHast Du denn, Höchster, auch meiner noch wollen gedenken?\nDu willst dich selber, Dein Herze der Liebe, mir schenken.\nSollt nicht mein Sinn innigst sich freuen darin\nund sich in Demut versenken?\r\nKönig der Ehren, aus Liebe geworden zum Kinde,\ndem ich auch wieder mein Herze in Liebe verbinde:\nDu sollst es sein, den ich erwähle allein;\newig entsag ich der Sünde.\r\nTreuer Immanuel, werd\' auch in mir nun geboren,\nkomm doch, mein Heiland, denn ohne Dich bin ich verloren!\nWohne in mir, mache ganz eins mich mit Dir,\nder Du mich liebend erkoren.'),
(9, '1031', 'Jede Stunde jeden Tag, sorgt Gott der Herr für mich  -  Every Hour, every Day, the Lord God cares for me   (Chorus)', 'Every hour, every day, the Lord God cares for me.\nEvery hour, every day, He preserv me from sin.\nEvery hour, every day He walks with me.\nEvery hour, every day Jesus is everything to me.', 'Jede Stunde, jeden Tag sorgt Gott, der Herr für mich.\nJede Stunde, jeden Tag bewahrt vor Sünd\' Er mich.\nJede Stunde, jeden Tag geht Er mit mir.\nJede Stunde, jeden Tag ist Jesus alles mir.'),
(9, '1032', 'Jede Verheißung in dem Buch ist mein  -  Every Promise in the Book is mein   (Chorus)', 'Every promise in the book is mine,\nEvery chapter, every verse, every line.\nI am trusting in His love divine,\nEvery promise in the book is mine.', 'Jede Verheißung in dem Buch ist mein;\njedes Kapitel, Vers und Zeile vereint.\nIch vertraue Seiner Lieb\' allein.\nJede Verheißung in dem Buch ist mein.'),
(9, '1033', 'Jeder Tag mit Jesus  -  Every Day with Jesus   (Chorus)', 'Every day with Jesus, is sweeter than the day before.\nEvery day with Jesus, I love Him more and more.\nJesus loves and keeps me, He\'s the One I\'m waiting for.\nEvery day with Jesus, is sweeter than the day before.', 'Jeder Tag mit Jesus, ist schöner als der Tag vorher.\nJeder Tag mit Jesus, ich lieb\' Ihn mehr und mehr.\nJesus liebt und führt mich, ich lebe nur zu Seiner Ehr\',\njeder Tag mit Jesus, ist schöner als der Tag vorher.'),
(9, '1034', 'Jehovah Jireh, my Provider', 'Jehovah-Jireh, my provider,\nYou are more than enough for me.\nJehovah-Rapha, You\'re my healer\nby Your stripes I am set free.\nJehovah- Shamma, You are with me\nYou supply all my needs.\nYou are more than enough, more than enough,\nYou are more than enough for me.\r\nJehovah-Nissi, You\'re my victory\nYou are more than enough for me.\nJehovah-Tsidkeno, my righteousness\nall You are I now can be.\nJehovah-Ra-ah, You\'re my sheperd\nShalom, You are my peace.\nYou are more than enough, more than enough,\nYou are more than enough for me.', 'Jehovah-Jireh, mein Versorger,\nDu bist mehr als genug für mich.\nJehovah-Rapha, Du bist mein Heiler\ndurch Deine Striemen bin ich frei geworden.\nJehovah-Schamma, Du bist bei mir\nDu erfüllst alle meine Bedürfnisse.\nDu bist mehr als genug, mehr als genug,\nDu bist mehr als genug für mich.\r\nJehovah-Nissi, Du bist mein Sieg\nDu bist mehr als genug für mich.\nJehova-Tsidkeno, meine Gerechtigkeit\nalles, was Du bist, kann ich jetzt sein.\nJehovah-Ra-ah, Du bist mein Hirte\nShalom, Du bist mein Friede.\nDu bist mehr als genug, mehr als genug,\nDu bist mehr als genug für mich.'),
(9, '1035', 'Jerusalem von Golde, wo Milch und Honig fließt  -  Jerusalem the Golden, with Milk and Honey blest', 'Jerusalem the golden, with milk and honey blest,\nbeneath your contemplation sink heart and voice oppressed.\nI know not, o I know not, what joys await us there,\nwhat radiancy of glory, what bliss beyond compare.\r\nThey stand, those halls of Zion, all jubilant with song,\nand bright with many an angel, and all the martyr throng.\nThe Prince is ever in them, the daylight is serene,\nthe pastures of the blessed are decked in glorious sheen.\r\nThere is the throne of David, and there, from care released,\nthe song of them that triumph, the shout of them that feast.\nAnd they who with their Leader have conquered in the fight,\nforever and forever are clad in robes of white.\r\nO sweet and blessed country, the home of God\'s elect!\nO sweet and blessed country that eager hearts expect!\nJesus, in mercy bring us to that dear land of rest,\nwho are, with God the Father and Spirit, ever blest.', 'Jerusalem von Golde, wo Milch und Honig fließt,\ndu Königsstadt, du holde, mein sehnend Aug dich grüßt!\nIch weiß nicht, welche Wonne, welch heilg\'e Freude harrt,\nwo Gott der Seinen Sonne und ihre Leuchte ward.\r\nDort schimmern Zions Hallen, dort schallt des Lammes Lied,\nund Engel strahlend wallen und Bruderliebe glüht.\nDort tönt am weißen Throne der Festeslieder Klang,\nes glänzt die Siegeskrone, es steigt Triumphgesang.\r\nUnd wer hier mit gestritten, trägt dort des Sieges Kleid,\nund wer hier mit gelitten, ruht aus von seinem Leid.\nVersiegt sind dort die Tränen, verstummt das Wehgeschrei,\ngestillt ist alles Sehnen, und jedes Herz ist frei.\r\nO, Heimat der Erlösten! O Stadt der Hoffnung du!\nDu wirst uns Müden trösten in ew\'ger Sabbatsruh.\nDu, der Du uns geladen und uns erlöset hast,\no Jesu, bring aus Gnaden auch mich zu jener Rast.'),
(9, '1036', 'Jerusalem, du hochgebaute Stadt', NULL, 'Jerusalem, du hochgebaute Stadt,\nwollt Gott, ich wär\' in dir!\nMein sehnlich Herz so groß Verlangen hat\nund ist nicht mehr bei mir.\nWeit über Berg und Tale,\nweit über flaches Feld,\nschwingt es sich über alle,\nund eilt aus dieser Welt.\r\nWas für ein Volk, was für ein edle Schar\nkommt dort gezogen schon?\nWas in der Welt von Auserwählten war,\nseh\' ich, die beste Kron\',\ndie Jesus mir, der Herre,\nentgegen hat gesandt,\nda ich noch war so ferne\nin meinem Tränenland.\r\nPropheten groß und Patriarchen hoch,\nauch Christen insgemein,\ndie weiland dort trugen des Kreuzes Joch\nund der Tyrannen Pein,\nschau ich in Ehren schweben,\nin Freiheit überall,\nmit Klarheit hell umgeben,\nmit sonnenlichtem Strahl.\r\nWenn dann zuletzt ich angelanget bin\nim schönen Paradeis,\nvon höchster Freud erfüllet wird der Sinn,\nder Mund von Lob und Preis.\nDas Halleluja reine singt man in Heiligkeit,\ndas Hosianna feine ohn\' End\' in Ewigkeit.'),
(9, '1037', 'Jesu Blut und Seine Wunden, das ist meine Arzenei   (Seine Lieb will ich verkünden)', NULL, 'Jesu Blut und Seine Wunden,\ndas ist meine Arzenei,\nda hab ich mein Heil gefunden,\ndass ich nun geborgen sei.\r\nSeine Lieb will ich verkünden,\nsie ist Leben und Gewinn,\nalles andre mag entschwinden,\nwenn ich nur in Jesu bin!\r\nJesus trug mit treuem Herzen\nunsre Schuld und ward ein Fluch.\nEr nahm auf sich unsre Schmerzen,\nals man Ihn ans Fluchholz schlug.\r\nKann wohl Liebe dich erweichen?\nKannst du Treue noch versteh\'n?\nO dann müsst das Kreuzeszeichen\nauch durch deine Seele geh\'n.\r\nLass doch nicht dein Herz berücken\nvon der Welt und ihrer Lust!\nJesus nur kann dich beglücken,\nkomm und eil\' an Seine Brust.'),
(9, '1038', 'Jesu Kreuz ist all mein Rühmen  -  In the Cross of Christ I glory', 'In the cross of Christ I glory,\ntowering o\'er the wrecks of time.\nAall the light of sacred story,\ngathers round its head sublime.\r\nWhen the woes of life o\'ertake me,\nhopes deceive, and fears annoy.\nNever shall the cross forsake me,\nlo! it glows with peace and joy.\r\nWhen the sun of bliss is beaming\nlight and love upon my way.\nFrom the cross the radiance streaming\nadds more luster to the day.\r\nBane and blessing, pain and pleasure,\nby the cross are sanctified.\nPeace is there that knows no measure,\njoys that through all time abide.', 'Jesu Kreuz ist all mein Rühmen;\ndahin geht der Seele Zug.\nHell von Gottes Licht umstrahlet,\nragt es ob der Jahre Flug.\r\nOft des Lebens Last mich drücket,\nHoffnung trügt und Furcht mich schreckt;\nschaut zum Kreuz das müde Auge,\nwird die Hoffnung neu erweckt.\r\nWenn das Lebensglück mir strahlet,\nLieb und Freundschaft hold mich führt,\nfällt vom Kreuz ein Strahl der Freude,\nder das Glück noch schöner ziert.\r\nWeh und Wonne, Freud und Trauer\nheiligt mir des Kreuzes Glanz,\nhüllt mich in den Schmuck des Heil\'s,\nkrönt mich mit des Siegers Kranz.'),
(9, '1039', 'Jesu Name nie verklinget, ewiglich bleibt er besteh\'n  -  Never fades the Name of Jesus, nor is dimmed by passing Time   (Jesu Name ist mir teuer)', 'Never fades the name of Jesus,\nnor is dimmed by passing time.\nJesus\' name is everlasting,\nfor its meaning is sublime.\nJesus\' name brings joy and gladness,\ndaily sending forth new life.\nIn his name there\'s power to gather\nsouls of men from ways of strife.\r\nHow I love the name of Jesus,\nHe has set my heart aflame!\nI have found a great salvation,\nthrough the merits of his name.\r\nNever fades the name of Jesus,\nnor is dimmed by passing time.\nJesus\' name is everlasting,\nfor its meaning is sublime.\nJesus\' name brings joy and gladness,\ndaily sending forth new life.\nIn his name there\'s power to gather,\nsouls of men from ways of strife.\r\nIn the night his dear name shineth\nlike a lighthouse evermore.\nGuiding lonely shipwrecked seamen\nsafely to salvation\'s shore.\nWhen the sun\'s last rays are fading,\ninto darkness spread his fame.\nTill the ransomed hosts in Heaven\nsing the praises of his name.', 'Jesu Name nie verklinget,\newiglich bleibt er besteh\'n.\nJesu Name Ruhe bringet,\nFried\' und Freude wunderschön.\nAllen Menschen gilt Sein Segen,\nallen, die in Sündennot.\nEr ruft sie von bösen Wegen,\nführt die Seele hin zu Gott.\r\nJesu Name ist mir teuer,\nheiß ist mir das Herz entbrannt.\nDank sei Dir, oh, mein Befreier,\ndenn durch Dich ich Rettung fand.\r\nJesu Name soll erstrahlen\nweithin über Land und Meer.\nTrost und Hoffnung gibt Er allen,\nrühmt Ihn laut zu Seiner Ehr\'.\nVor dem Namen Jesu schwindet,\nalles, was den Herrn betrübt.\nSünd\' und Unrecht überwindet,\nwer den Namen Jesu liebt.\r\nJesu Name leuchtet helle\nund Sein Glanz vergehet nicht.\nJesu Name bringt der Seele\nselbst in tiefer Nacht ein Licht.\nMag auch einst die Welt versinken,\nmag vergeh\'n der Sonne Schein.\nJesu Nam\' wird weiter klingen,\nunvergänglich wird Er sein.'),
(9, '1040', 'Jesu Tisch ist wohl bereit  -  Jesus has a Table spread   (Kommt zum Mahl  ihr Gäste alles ist bereit)', 'Jesus has a table spread where the saints of God are fed,\nHe invites His chosen people "Come and dine".\nWith His manna He doth feed and supplies our every need.\nO, \'tis sweet to sup with Jesus all the time!\r\n"Come and dine", the Master calleth, "Come and dine",\nyou may feast at Jesus\' table all the time.\nHe who fed the multitude, turned the water into wine,\nto the hungry calleth now, "come and dine".\r\nThe disciples came to land, thus obeying Christ\'s command,\nfor the Master called to them, "Come and dine".\nThere they found their hearts\' desire, bread and fish upon the fire.\nThus He satisfies the hungry every time.\r\nSoon the Lamb will take His bride to be ever at His side,\nall the host of heaven will assembled be.\nO, \'twill be a glorious sight, all the saints in spotless white.\nAnd with Jesus they will feast eternally.', 'Jesu Tisch ist wohl bereit für die Seinen allezeit.\nFreundlich ruft Er nun: "Kommt her zum Hochzeitsmahl!"\nManna schenkt Er, Himmelsbrot, macht uns frei aus aller Not.\nOh, wie köstlich hat\'s die auserwählte Zahl.\r\nKommt zum Mahl  ihr Gäste alles ist bereit,\nin des Königs Hochzeitssaal voll Herrlichkeit.\nEr der viele schon gespeist und auch jetzt uns Heil verheißt,\nruft auch dich voll Lieb\' und Huld: "Komm zum Mahl!"\r\nSeinen Jüngern auf dem Meer ruft der Meister: "Eilet her,\nesset mit mir von der Mahlzeit, uns bereit."\nAls sie kamen an den Strand, da war Brot und Fisch zur Hand.\nKöstlich ist\'s mit Ihm zu speisen allezeit.\r\nBald holt Jesus Seine Braut zu der Heimat, hoch erbaut.\nSieh, die Scharen sich dort sammeln ohne Zahl!\nWas wird das für Wonne sein, wenn die Sel\'gen, weiß und rein,\nwerden weilen mit dem Herrn beim Hochzeitsmahl!'),
(9, '1041', 'Jesus be the Lord of all   (2 Chorusse)', 'Jesus, be the Lord of all,\nJesus, be the Lord of all,\nJesus, be the Lord of all,\nthe kingdoms of my heart.\r\nJesus, I surrender all,\nJesus, I surrender all,\nJesus, I surrender all,\nthe kingdoms of my heart.', NULL),
(9, '1042', 'Jesus Christ the Lord, opened up the Way to Glory   (Jesus opened up the Way to heaven\'s Gate)', 'Jesus Christ the Lord opened up the way to glory,\nwhen He died to save us from our ruined state.\nAnd He asks that we shall go tell the world the story,\nhow His blood will save them from their awful fate.\r\nJesus opened up the way to heaven\'s gate,\nwhen He died on the cross to redeem all the los.;\nHe prepared the road that leads to His abode,\n\'Tis a road, marked by blood but it leads us home to God.\r\nAnd the way is marked by the foot-prints of the Saviour,\nwith His blood He made it, made it plain and straight.\nIf you walk that way, it will lead you into heaven,\nlead you safely into glory\'s golden gate.\r\nSinner, will you come and join in this heav\'nly journey,\nwalk the bloody pathway that the Saviour trod.\nThen when life is over and all the sheaves are garnered,\nyou will meet the Saviour and be not afraid.', NULL),
(9, '1043', 'Jesus Christus heißt die Botschaft   (Name über alle Namen, darin alles Heil besteht)', NULL, 'Jesus Christus heißt die Botschaft,\ndie wir tragen durch das Land.\nSeele, ist dir dieser Name\ndurch den Geist wohl schon bekannt?\r\nName über alle Namen,\ndarin alles Heil besteht!\nGegenwärtiger Erlöser,\nKönig, Priester und Prophet!\r\nJesus ist das Heil der Sünder,\ndie Versöhnung aller Schuld.\nDurch Ihn sind wir Gotteskinder,\nerben statt des Zornes Huld!\r\nJesus hat uns ganz geheiligt\nDurch Sein Blut auf Golgatha.\nDaran bist auch du beteiligt:\nPreis Ihn, Halleluja.\r\nJesus ist der Arzt der Kranken,\nder noch heute sich erweist.\nLerne glauben ohne Wanken,\nwas Sein Wort so klar verheißt.\r\nJesus ward uns auch gegeben,\ndass Er unsre Weisheit sei.\nGlaube nur, so wird dein Leben\nVon den dunklen Rätseln frei!\r\nJesus tauft mit Geist und Feuer\njeden, der es nur begehrt.\nwar der Preis auch noch so teuer:\ndurch Sein Blut wird es gewährt.\r\nJesus Christ wird bald erscheinen,\nheimzuholen Seine Braut,\nganz mit ihr Sich zu vereinen dort,\nwo sie Ihn ewig schaut.'),
(9, '1044', 'Jesus Christus herrscht als König', NULL, 'Jesus Christus herrscht als König;\nalles wird Ihm untertänig,\nalles legt Ihm Gott zu Fuß.\nJede Zunge soll bekennen,\nJesus sei der Herr zu nennen,\ndem man Ehre geben muss,\ndem man Ehre geben muss.\r\nNur in Ihm, o Wundergaben,\nkönnen wir Erlösung haben,\ndie Erlösung durch sein Blut!\nHört\'s, das Leben ist erschienen,\nund ein ewiges Versühnen\nkommt in Jesu uns zugut,\nkommt in Jesu uns zugut!\r\nGebt, ihr Sünder, Ihm die Herzen!\nKlagt, ihr Kranken, Ihm die Schmerzen!\nSagt, ihr Armen, Ihm die Not!\nEr kann alle Wunden heilen,\nReichtum weiß er auszuteilen,\nLeben schenkt er nach dem Tod,\nLeben schenkt er nach dem Tod!\r\nEil, es ist nicht Zeit zum Schämen!\nWillst du Gnade? Du sollst nehmen!\nWillst du leben? Es soll sein!\nWillst du erben? Du wirst sehen!\nSoll der Wunsch aufs höchste gehen:\nWillst du Jesum? Er ist dein!\nWillst du Jesum? Er ist dein!\r\nJauchz Ihm, Menge heil\'ger Knechte!\nRühmt, vollendete Gerechte,\nund du Schar, die Palmen trägt,\nund du Blutvolk in der Krone,\nund du Chor vor Seinem Throne,\nder die Gottesharfen schlägt,\nder die Gottesharfen schlägt!\r\nIch auch auf der tiefsten Stufen,\nich will glauben, reden, rufen,\nob ich schon noch Pilgrim bin:\n"Jesus Christus herrscht als König,\nalles sei Ihm untertänig!\nEhret, liebet, lobet Ihn!\nEhret, liebet, lobet Ihn!"'),
(9, '1045', 'Jesus Christus ist so gut zu mir', NULL, 'Jesus Christus ist so gut zu mir,\nJesus Christus ist so gut zu mir,\nJesus Christus ist so gut zu mir,\njeden Tag neu.\nSo gut, Er gibt den Frieden mir,\nso gut, Er gibt die Freude mir,\nso gut, Er gibt die Liebe mir,\njeden Tag neu.\r\nGottes Liebe ist so wunderbar,\nGottes Liebe ist so wunderbar,\nGottes Liebe ist so wunderbar,\nso wunderbar groß.\nSo hoch, was kann höher sein,\nso tief, was kann tiefer sein,\nso weit, was kann weiter sein,\nso wunderbar groß.\r\nDie Liebe Jesu ist so wunderbar,\nDie Liebe Jesu ist so wunderbar,\nDie Liebe Jesu ist so wunderbar,\nso wunderbar groß.\nSie ist so hoch, du kommst nicht über sie\nso tief, du kommst nicht unter sie,\nso weit, du kommst nicht \'rum um sie,\nso wunderbar groß.'),
(9, '1046', 'Jesus Christus lebt  -  Jesus is alive   (Chorus)', 'Jesus is alive, Jesus is alive!\nHis is the blood that ransomed me.\nHis is the pow\'r that set me free,\nHis is the life that is given to me,\nfor Jesus is alive.', 'Jesus Christus lebt, Jesus Christus lebt.\nSein Blut, es macht mich völlig rein.\nSein Geist gibt Kraft und Sieg allein,\nlässt mich Überwinder sein,\ndenn Jesus Christus lebt.'),
(9, '1047', 'Jesus Christus starb für mich, Jesus Christus starb für dich', NULL, 'Jesus Christus starb für mich,\nJesus Christus starb für dich.\nFür die ganze Welt starb er am Kreuz.\nEr nahm unsre Schuld auf sich.\r\nJesus ist der Weg für mich.\nJesus ist der Weg für dich.\nJesus ist der Weg zum Vaterhaus.\nEr nahm unsre Schuld auf sich.\r\nHerr, ich danke dir, dass du mich liebst.\nDeine Gnade gilt auch mir.\nDanke, Herr, dass du die Schuld vergibst.\nIch will leben, Herr, mit dir.\r\nJesus Christus, er ruft mich.\nJesus Christus, er ruft dich.\nMach dich auf und folge Jesus nach.\nEr nahm unsre Schuld auf sich.\r\nHerr, ich danke dir, dass du mich liebst.\nDeine Gnade gilt auch mir.\nDanke, Herr, dass du die Schuld vergibst.\nIch will leben, Herr, mit dir.'),
(9, '1048', 'Jesus Dir nur will ich singen   (Ehre, Ehre, Preis, Anbetung)', NULL, 'Jesus Dir nur will ich singen,\nder Du mich von Sünd\' befreit.\nDir das neue Lied darbringen,\nHerz und Mund sei Dir geweiht.\r\nEhre, Ehre, Preis, Anbetung\nsei Dir jetzt und alle Zeit.\nUnser\'m großen Welterlöser\nLob und Dank in Ewigkeit.\r\nVolle Freiheit von den Sünden\ndurch den Tod am Kreuzesstamm,\nkonnt\' mein müdes Herze finden,\ndenn Er ward das Opferlamm.\r\nEinst wird helle Jubel schallen,\nin dem wunderbaren Land.\nWo erlöste Scharen wallen,\nlobend dort am gold\'nen Strand.'),
(9, '1049', 'Jesus Du bist unaussprechlich herrlich Deinem Kind', NULL, 'Jesus, Du bist unaussprechlich\nherrlich Deinem Kind;\nGnad\' und Friede, Heil und Leben,\nHerr, in Dir ich find\'.\r\nJesus, wenn ich Dich nicht hätte,\nwär\' es finst\'re Nacht;\naber Deines Geistes Klarheit\nhat mir Licht gebracht.\r\nJesus, ohne Dich versänk\' ich\ntief in Sündennot;\ndoch nun bin ich frei geworden,\nHerr, durch Deinen Tod.\r\nLiebster Jesus, sieh, ich hülle\nmich in Dich hinein;\no da bin ich gut geborgen,\nkann ich sicher sein.\r\nKommt Versuchung, Satan, Sünde,\nwill ich stille sein,\nwill mich bergen hinter Jesum,\nhinter Ihm allein.\r\nUnd steht Jesus zwischen innen,\nbin ich aus dem Krieg;\ndenn schon längst erfocht mein Jesus\nüberall den Sieg.\r\nJesus, ja Du führst Dein Schäflein,\nwelches Dir vertraut;\nführst es sicher, führst es selig\nhin, wo Dich es schaut.'),
(9, '1050', 'Jesus Du seist gepriesen', NULL, 'Jesus, Du seist gepriesen,\nDu bist ja mein Herr und mein Gott!\nDu schenkst mir Kraft, neues Leben;\nich danke und bete Dich an.\nJesus, Jesus, Jesus,\nDu bist Gottes Sohn,\nJesus, Jesus, Jesus,\nich bete dich an.'),
(9, '1051', 'Jesus enttäuscht uns nie (Bist du einsam und betrübt  -  Earthly Friends may prove untrue)', 'Earthly friends may prove untrue,\ndoubts and fears assail.\nOne still loves and cares for you,\nOne who will not fail.\r\nJesus never fails,\nJesus never fails.\nHeav\'n and earth may pass away,\nbut Jesus never fails.\r\nThough the sky be dark and drear,\nfierce and strong the gail.\nJust remember he is near,\nand he will not fail.\r\nIn life\'s dark and bitter hour,\nlove will still prevail.\nTrust His everlasting pow\'r,\nJesu will not fail.', 'Bist du einsam und betrübt,\nfriedlos, von Furcht geplagt?\nEiner ist’s, der treu dich liebt,\neiner, der nie versagt.\r\nJesus enttäuscht uns nie,\nJesus enttäuscht uns nie.\nLass dein Zweifeln, komm und sieh:\nAuch dich enttäuscht Er nie!\r\nWenn der Himmel finster droht,\nSturmwind die Wolken jagt,\neiner lindert deine Not,\neiner, der nie versagt.\r\nWenn in bitt\'rer Prüfungszeit\nKummer am Herzen nagt,\ngeh zu ihm mit deinem Leid.\nEr hat noch nie versagt.'),
(9, '1052', 'Jesus Fels auf dem ich sicher steh', NULL, 'Ich bin so froh, dass\nich in diesen Zeiten\nmich auf die Zeit nicht\nmehr verlassen muss,\nmein Anker ist der\nFels der Ewigkeiten,\nder mich hält und\nder mich ewig trägt.\r\nJesus, Fels, auf dem ich sicher steh‘,\nJesus, fester Lebensgrund,\nJesus, den ich voller Hoffnung seh‘,\nJesus, Gottes Gnadenbund!\r\nWenn alles bricht,\nmein Felsen steht für ewig,\nwenn nichts mehr hält,\nmein Jesus hält mich fest,\nEr trägt mich weit, ich\nmuss nur in Ihm bleiben,\nEr, mein Gott, der\nniemals mich loslässt.\r\nUnd wenn ich dann\nnach diesem Erdenleben\nvor meinem Gott in\nHerrlichkeiten steh‘,\ndann werd‘i ich Ihm\nallein die Ehre geben,\nder mich trug den\nganzen, langen Weg!'),
(9, '1053', 'Jesus führt mich allerwegen  -  All the Way my Saviour leads me   [Rauschenbusch]', 'All the way my Saviour leads me,\nwhat have I to ask beside?\nCan I doubt His tender mercy,\nwho through life has been my Guide?\nHeav’nly peace, divinest comfort,\nhere by faith in Him to dwell!\nFor I know, whate’er befall me,\nJesus doeth all things well.\nFor I know, whate’er befall me,\nJesus doeth all things well.\r\nAll the way my Saviour leads me,\ncheers each winding path I tread.\nGives me grace for every trial,\nfeeds me with the living Bread.\nThough my weary steps may falter\nand my soul athirst may be.\nGushing from the Rock before me,\nLo! A spring of joy I see.\nGushing from the Rock before me,\nLo! A spring of joy I see.\r\nAll the way my Saviour leads me,\noh, the fullness of His love!\nPerfect rest to me is promised\nin my Father’s house above.\nWhen my spirit, clothed immortal,\nwings its flight to realms of day.\nThis my song through endless ages:\nJesus led me all the way.\nThis my song through endless ages:\nJesus led me all the way.', 'Jesus führt mich allerwegen.\nSeele, was verlangst du mehr?\nWillst an Seiner Gnad\' du zweifeln?\nO der treuste Hirt\' ist Er!\nSüße Ruh\' hat meine Seele,\nfolgt sie Jesus glaubensvoll.\nAuch im schwersten Leiden weiß ich:\nJesus machet alles wohl.\r\nJesus führt mich allerwegen.\ngibt mir Kraft in jeder Not,\nstützt mich treu im dunklen Tale,\nspeist mich mit dem Lebensbrot.\nWenn die müden Schritte straucheln,\nwenn verschmachten will die Seel\',\nsprudelt auch aus hartem Felsen\nauf sein Wort ein kühler Quell.\r\nJesus führt mich allerwegen.\nO, der Reichtum Seiner Gnad\'\nO, die Ruh, die bei dem Vater,\nEr auch mir bereitet hat!\nSchweb\' ich einst durch ew\'ge Fluren,\nmit des Siegers Schmuck geziert,\nwill ich das auf immer rühmen:\nJesus hat mich treu geführt!'),
(9, '1054', 'Jesus hat mein Leben erfasst  -  Jesus got a hold of my life   (Jesus hat mein Leben erfasst)', 'Sometimes I remember,\nhow I used to be living in sin.\nI tried to act happy and glad,\nbut I wasn\'t within.\nAnd I fooled a lot of friends of mine,\nthey thought I had a peace of mind,\nbut I never really did\ntill I opened and let Jesus in.\r\nJesus got a hold of my life\nand He won\'t let me go.\nJesus got into my heart,\nHe got into my soul.\nI used to be, oh so sad,\nbut now I\'m free and glad.\n\'Cause Jesus got a hold of my life\nand He won\'t let me go.\r\nAren\'t you just getting\ntired fooling around ?\nYou\'re trying to lead your life through life,\nbut you are not gaining ground.\nWell, won\'t you take the Lord today?\nJust ask Him in your heart to stay,\nand you\'ll find that love can be\nthe greatest thing that you ever found.', '\r\nJesus hat mein Leben erfasst,\nEr kam hinein in mein Herz.\nJesus hat mein Leben erfasst,\nEr kam hinein in mein Herz.\nEgal, was auch geschieht,\nich weiß, der Feind, er flieht.\nDenn Jesus hat mein Leben erfasst,\nEr kam hinein in mein Herz\r\n'),
(9, '1055', 'Jesus heilt', 'Are you tried of chasing pretty rainbows?\nAre you tired of spinning round and round?\nWrap up all the shattered dreams of your life\nAnd at the feet of Jesus lay them down\r\nGive them all, give them all\nGive them all to Jesus\nShattered dreams, wounded hearts, broken toys\nGive them all, give them all\nGive them all to Jesus\nAnd he will turn your sorrow into joy\r\nHe never said you\'d only see sunshine\nHe never said there\'d be no rain\nBut He has promised us a heart full of singing\nTo overcome the things that brought you pain', 'Bist du müde Träumen nachzujagen,\ndich mit eignen Plänen abzumühn?\nQuälen dich Probleme, Angst und Fragen?\nLeg deine Last zu Jesu Füßen hin.\r\nJesus heilt, Jesus heilt, Jesus heilt die Wunden,\nschenkt dir Kraft, neuen Mut und Lebenssinn!\nJesus heilt, Jesus heilt, Jesus heilt die Wunden,\nverwandelt auch dein Leben, glaube ihm!\r\nEr verspricht dir nicht nur Sonnentage,\nauch bleibst du vor Stürmen nicht verschohnt,\ndoch er hilft dir deine Lasten tragen,\nbei allem Schweren wirst du reich belohnt.'),
(9, '1056', 'Jesus heilte stets aus Gnaden jeden welcher nach Ihm rief   (Jesus heilt, Jesus heilt, immer noch erbarmt Er sich)', NULL, 'Jesus heilte stets aus Gnaden jeden welcher nach Ihm rief;\nnie war Ihm zu schlimm der Schaden, keine Wunde war zu tief.\nWen Er ansah und berührte, o, der ging geheilt nach Haus,\nweil er alsobald es spürte: Eine Kraft geht von Ihm aus.\r\nJesus heilt, Jesus heilt, immer noch erbarmt Er Sich.\nJesus heilt, Jesus heilt, Seine Gnade ist für dich.\r\nWenn dir Kraft und Frieden fehlen, Mut und Hoffnung dir versank,\nSeele, lass dir\'s nicht verhehlen, deine Sünde macht dich krank;\nund sie wird zum Tod dich führen, doch du darfst dich Jesu nah\'n.\nBitte Ihn, dich anzurühren, rühr\' auch Ihn im Glauben an.\r\nNicht die Krankheit nur vermindern wird der Herr für kurze Frist,\nnicht nur deinen Schaden lindern, bis er dir erträglich ist:\nNein, du wirst von Ihm bekommen Seine göttliche Natur;\nwen Er heilt, heilt Er vollkommen, nicht auf Augenblicke nur.\r\nWären noch so tief die Wunden, welche dir die Sünde schlug,\ndennoch kannst auch du gesunden, Jesu Kraft ist groß genug.\nWag\'s, dich Ihm zu übergeben willig, völlig, ungeteilt,\ndann hast du das ew\'ge Leben, wirst bis auf den Grund geheilt.'),
(9, '1057', 'Jesus heißt uns leuchten mit hellem Schein  -  Jesus bids us shine with a clear, pure Light', 'Jesus bids us shine with a clear, pure light,\nlike a little candle burning in the night.\nIn this world of darkness, we must shine,\nyou in your small corner, and I in mine.\r\nJesus bids us shine, first of all for Him,\nwell He sees and knows it if our light is dim.\nHe looks down from heaven, sees us shine,\nyou in your small corner, and I in mine.\r\nJesus bids us shine, then, for all around,\nmany kinds of darkness in this world abound.\nSin, and want, and sorrow, we must shine,\nyou in your small corner, and I in mine.\r\nJesus bids us shine, as we work for Him,\nbringing those that wander from the paths of sin.\nHe will ever help us, if we shine,\nyou in your small corner, and I in mine.', 'Jesus heißt uns leuchten mit hellem Schein,\nwie ein kleines Lämpchen, brennend klar und rein.\nChristen sollen leuchten in der dunklen Welt,\njedes an dem Plätzchen, wohin Gott es stellt.\r\nJesus heißt uns leuchten zuerst für Ihn,\nsicher weiß und merkt Er, ob wir für Ihn glüh\'n,\nob wir helle leuchten in der dunklen Welt,\njedes an dem Plätzchen, wohin Gott es stellt.\r\nJesus heißt uns leuchten auch um uns her\nin der Nacht und Sünde, in des Leidens Meer.\nSelig, wenn ein Lämpchen seinen Kreis erhellt,\nleuchtend an dem Plätzchen wohin Gott es stellt.\r\n'),
(9, '1058', 'Jesus hilft heute', NULL, 'Bist du in Nöten? Kannst du kaum beten?\nJesus hilft heute, wenn du ihn brauchst!\nNicht erst nach Tagen, nicht erst nach Jahren,\nJesus hilft heute, wenn du ihn brauchst.\r\nJesus hilft heute, Jesus hilft hier,\nwir sind nicht alleine, Er hilft dir und mir!\nSind wir voll Fragen, sind wir verletzt -\nJesus hilft heute, Jesus hilft jetzt!\r\nBist du voll Sorgen? Hast Angst vor morgen?\nJesus hilft heute, wenn du ihn brauchst!\nEr, der so treu ist, uns nicht vergisst,\nJesus hilft heute, wenn du ihn brauchst!\r\nEr hat den Tröster zu uns gesendet,\nJesus hilft heute, wenn du ihn brauchst!\nEr, der dein Schicksal wundervoll wendet,\nJesus hilft heute, wenn du ihn brauchst!\r\nDu brauchst nicht suchen in weiten Fernen,\nJesus hilft heute, wenn du ihn brauchst!\nEr ist dir nahe in deinem Herzen,\nJesus hilft heute, wenn du ihn brauchst!'),
(9, '1059', 'Jesus I\'ll never forget what You\'ve done for me', 'Jesus I\'ll never forget\nwhat You\'ve done for me.\nJesus, I\'ll never forget\nhow You set me free.\nJesus, I\'ll never forget\nhow You brought me ou.\nJesus I\'ll never forget, no, never.', NULL),
(9, '1060', 'Jesus ich hab Dich lieb, ich hab Dich lieb über alle Dinge   (Chorus)', NULL, 'Jesus, ich hab Dich lieb,\nich hab\' Dich lieb über alle Dinge.\nAlles in mir verlangt zu singen,\nJesus, ich hab\' Dich lieb!'),
(9, '1061', 'Jesus ich komm Dich zu preisen  -  Jeus, I just want to praise You   (3 Chorusse)', 'Jesus, I just want to praise You,\nJesus, I just want to praise You,\nJesus, I just want to praise You,\npraise You for being so good.\r\nJesus, I just want to thank You,\nJesus, I just want to thank You,\nJesus, I just want to thank You,\nthank You for being so good.\r\nJesus, we just want to tell You.\nJesus, we just want to tell You.\nJesus, we just want to tell You,\nwe love You for being so good.', 'Jesus, ich komm, Dich zu preisen,\nJesus, ich komm, Dich zu preisen,\nja, Jesus, ich komm, Dich zu preisen,\nweil Du so gut zu mir bist.\r\nJesus, ich komm, Dir zu danken,\nJesus, ich komm, Dir zu danken,\nja, Jesus, ich komm, Dir zu danken,\nweil Du so gut zu mir bist.\r\nJesus, wir möchten Dir sagen,\nJesus, wir möchten Dir sagen,\nja, Jesus, wir möchten Dir sagen,\ndas Du so gut zu uns bist.'),
(9, '1062', 'Jesus in mir, Jesus in mir   (Chorus)', NULL, 'Jesus in mir, Jesus in mir.\nSein Wort ist in mir geoffenbart.\nUnd wenn noch nicht voll sichtbar,\nso weiß ich ganz gewiss,\ndass Jesus in mir ew\'ges Leben ist.'),
(9, '1063', 'Jesus is alive, Jesus is alive   (Chorus)', 'Jesus is alive, Jesus is alive.\nSin and death must go,\nthey are conquered foe,\nfor Jesus is alive.', NULL),
(9, '1064', 'Jesus ist alles, alles mir  -  Jesus is all the World to me', 'Jesus is all the world to me,\nmy life, my joy, my all.\nHe is my strength from day to day,\nwithout Him I would fall.\nWhen I am sad, to Him I go,\nno other one can cheer me so.\nWhen I am sad, He makes me glad,\nHe\'s my friend.\r\nJesus is all the world to me,\nand true to Him I\'ll be.\nOh, how could I this friend deny,\nwhen He\'s so true to me?\nFollowing Him I know I\'m right,\nHe watches o\'er me day and night.\nFollowing Him by day and night,\nHe\'s my friend.\r\nJesus is all the world to me,\nI want no better friend.\nI trust Him now, I\'ll trust Him when\nlife\'s fleeting days shall end.\nBeautiful life with such a friend,\nbeautiful life that has no end.\nEternal life, eternal joy,\nHe\'s my friend.', 'Jesus ist alles, alles mir,\nmein Glück, mein Trost, mein Heil,\nist meine Kraft von Tag zu Tag\nund meiner Seele Teil.\nWenn ich betrübt und traurig bin,\nleg ich es Ihm zu Füßen hin.\nBin ich betrübt, Jesus mich liebt,\nEr ist mein Freund.\r\nJesus ist alles, alles mir,\nund soll es einzig sein,\nund Ihm will ich aufs Neue mich\nmit Leib und Seele weih\'n.\nEr soll es sein, der mich regiert,\nIhm will ich folgen, wie Er führt.\nDer mich regiert, gnädig mich führt,\nEr ist mein Freund.\r\nJesus ist alles, alles mir,\nEr stehet felsenfest.\nGeht auch mein Fuß durchs finst\'re Tal,\nEr nimmer mich verlässt.\nO, welch ein Glück, an Seiner Hand\npilgern zum ew\'gen Heimatland.\nAn Seiner Hand zum goldnen Strand,\nführt mein Freund.'),
(9, '1065', 'Jesus ist der Erlöser, Er hat uns von Sünde befreit   (Aus Liebe zu Gott)', NULL, 'Jesus ist der Erlöser,\nEr hat uns von Sünde befreit.\nEr hat Seine Liebe erwiesen,\nDu kannst nun ein Kind Gottes sein.\r\nAus Liebe zu Gott,\naus Liebe zu Gott:\nDein Herz übergib\' Ihm,\nlass Jesus einzieh\'n!\r\nJesus ist der Erretter,\nverlasse dich völlig auf Ihn.\nEr hat deine Sorgen getragen,\ndu brauchst nur in Ihm zu ruh\'n.'),
(9, '1066', 'Jesus ist der Herr', NULL, 'Heute leben wir\nam Ende aller Zeit,\nalles wird vergeh\'n,\nder Tag ist nicht mehr weit,\ndoch was alle diese\nDinge überstrahlt,\ndas ist Jesus, der\nsich uns ganz offenbart!\r\nJesus ist der Herr,\nganz alleine ER,\nniemand hier auf Erden\nist Ihm gleich,\nJesus ist der Herr,\nKönig ist nur Er!\nDer Himmel und mein Herz,\ndas ist Sein Reich!\r\nWenn es dunkler wird,\nviel heller strahlt Sein Licht,\nSeine Gnade ist\nviel größer als Gericht,\nwenn auch alles fällt,\nSein Wort vergeht doch nicht,\nund schon bald sind wir\nbei Ihm, in Seinem Licht!\r\nMancher hat uns schon\nso lange totgesagt,\nmancher hat den Glauben\nlang schon hinterfragt,\ndoch es bleibt dabei,\nund das ist unser Halt,\nJesus hat gesprochen:\n"Sieh, ich komme bald!"'),
(9, '1067', 'Jesus ist mein Retter, davon weich ich nicht   (Weichen, weichen, weichen kann ich nicht)   [Bieselsberg]', NULL, 'Jesus ist mein Retter, davon weich ich nicht!\nWenn ich bei Ihm bleibe, ist Sein Wort mein Licht.\nDenn wie ein Baum bin ich gepflanzt am Wasser,\nweichen kann ich nicht!\r\nWeichen, weichen, weichen kann ich nicht!\nStürme, Regen, gar nichts mich zerbricht.\nDenn wie ein Baum bin ich gepflanzt am Wasser,\nweichen kann ich nicht.\r\nWenn ich von Ihm trinke, bleibt mein Leben frisch,\nwenn ich von ihm trinke, bin ganz sicher ich.\nDenn wie ein Baum bin ich gepflanzt am Wasser,\nweichen kann ich nicht!\r\nWenn Sein Wort ich esse, gibt Er mir die Kraft,\nwenn Sein Wort ich esse, Er es in mir schafft.\nDenn wie ein Baum bin ich gepflanzt am Wasser,\nweichen kann ich nicht!\r\nWenn ich Ihm vertraue, richtet Er mich auf,\nwenn ich Ihm vertraue, führt Er meinen Lauf.\nDenn wie ein Baum bin ich gepflanzt am Wasser,\nweichen kann ich nicht!\r\nWenn ich in Ihm bleibe, werd\' ich auch besteh\'n,\nwenn ich in Ihm bleibe, die Entrückung seh\'n.\nDenn wie ein Baum bin ich gepflanzt am Wasser,\nweichen kann ich nicht!'),
(9, '1068', 'Jesus ist mein Retter, schwanken kann ich nicht  -  Jesus is my Saviour, I shall not be moved   (Schwanken, schwanken, schwanken kann ich nicht)', 'Jesus is my Saviour, I shall not be moved.\nIn His love and favour, I shall not be moved.\nJust like a tree that\'s planted by the waters,\nI shall not be moved.\r\nI shall not be moved, I shall not be moved.\nI shall not be moved, I shall not be moved.\nJust like a tree that\'s planted by the waters,\nI shall not be moved.\r\nIf I trust Him ever, I shall not be moved.\nHe will fail me never, I shall not be moved.\nJust like a tree that\'s planted by the waters,\nI shall not be moved.\r\nOn His word I\'m feeding, I shall not be moved.\nHe\'s the One that\'s leading, I shall not be moved.\nJust like a tree that\'s planted by the waters,\nI shall not be moved.\r\nHe is the vine and we the branches are,\nin His love I\'m hiding, I shall not be moved.\nJust like a tree that\'s planted by the waters,\nI shall not be moved.', 'Jesus ist mein Retter, schwanken kann ich nicht,\nwenn ich an Ihm bleibe, schwanken kann ich nicht,\ndenn wie ein Baum, bin ich gepflanzt am Wasser,\nschwanken kann ich nicht.\r\nSchwanken, schwanken, schwanken kann ich nicht,\nschwanken, schwanken, schwanken kann ich nicht,\ndenn wie ein Baum, bin ich gepflanzt am Wasser,\nschwanken kann ich nicht.\r\nWenn ich Ihm vertraue, schwanken kann ich nicht,\nlässt Er mich dann nimmer, schwanken kann ich nicht;\ndenn wie ein Baum, bin ich gepflanzt am Wasser,\nschwanken kann ich nicht.\r\nDurch sein Wort gestärket, schwanken kann ich nicht;\nEr Ist\'s der mich führet, schwanken kann ich nicht,\ndenn wie ein Baum, bin ich gepflanzt am Wasser,\nschwanken kann ich nicht.\r\nIch bin nur die Rebe, Er der Weinstock ist.\nWenn ich an Ihm bleibe, schwanken kann ich nicht,\ndenn wie ein Baum, bin ich gepflanzt am Wasser,\nschwanken kann ich nicht.'),
(9, '1069', 'Jesus ist Sieger', NULL, 'Als ich Ihn, als ich Ihn\ndort auf Golgatha sah,\nja, da war meine Seele voll Freud\',\nich erhob, ich erhob\nmeinen Gott voller Lob,\nund ich war von der Sünde befreit.\r\nJesus ist Sieger,\nEr siegte voll Macht,\nkein Feind kann vor Ihm besteh\'n,\nJesus ist Sieger,\nEr hat es vollbracht,\nich darf mit Ihm vorwärtsgeh\'n!\r\nWenn der Feind, wenn der Feind\nmeine Seele umringt,\nja, dann sag ich ihm das, was ich weiß:\ner ist längst, er ist längst\nschon durch Jesus besiegt,\nan dem Kreuz ist es für ihn vorbei!'),
(9, '1070', 'Jesus kam uns zu erlösen, preiset den Herrn', NULL, 'Jesus kam, uns zu erlösen, preiset den Herrn!\nEr zertrat die Macht des Bösen, preiset den Herrn!\nSünder, ihr habt nichts zu tun, als die Gnade zu erfassen\nund euch reinigen zu lassen, preiset den Herrn!\r\nSelber kann man\'s nicht erzwingen, preiset den Herrn!\nJesus nur kann es vollbringen, preiset den Herrn!\nEr nahm mir die Fesseln ab, hat dafür ein neues Leben,\nKraft und Frieden mir gegeben, preiset den Herrn!\r\nAllen ist das Heil erschienen, preiset den Herrn!\nKeiner muss dem Laster dienen, preiset dem Herrn!\nKeiner muss verloren gehn! Sagt es allen hier auf Erden:\n"Wer da will, kann selig werden!" Preiset den Herrn!'),
(9, '1071', 'Jesus kann alles verwandeln   (Alles verwandelt Er, alles verwandelt Er)', NULL, 'Jesus kann alles verwandeln!\nDurchs dunkle Wolkentor\nstrahlet die helle Sonne,\nwenn Er Sein Volk führt empor.\r\nAlles verwandelt Er, alles verwandelt Er,\ndenn alle Gewalt ist in seiner Hand,\nja alles verwandelt Er.\r\nJesus kann alles verwandeln!\nBalsam gibt Er für\'s Herz,\nstärket den müden Pilger,\nweist Ihm den Weg himmelwärts.\r\nJesus kann alles verwandeln!\nMacht jeden Schaden gut,\ntröstet betrübte Seelen,\nreinigt und heilt durch Sein Blut.\r\nJesus kann alles verwandeln!\nSiegt über Leid und Weh\',\nschenkt dir die Heilsgewissheit,\nfüllt dich mit Kraft aus der Höh\'.'),
(9, '1072', 'Jesus kommt wieder in Herrlichkeit  -  Jesus is coming to Earth again   (Herrlich, herrlich, Satan und Sünde fällt)', 'Jesus is coming to earth again,\nwhat if it were today?\nComing in power and love to reign,\nwhat if it were today?\nComing to claim His chosen Bride,\nall the redeemed and purified,\nover this whole earth scattered wide,\nwhat if it were today?\r\nGlory, glory!\nJoy to my heart \'twill bring.\nGlory, glory!\nWhen we shall crown Him King.\nGlory, glory!\nHaste to prepare the way.\nGlory, glory!\nJesus will come someday.\r\nSatan\'s dominion will then be o\'er,\no that it were today!\nSorrow and sighing shall be no more,\no that it were today!\nThen shall the dead in Christ arise,\ncaught up to meet Him in the skies.\nWhen shall these glories meet our eyes?\nWhat if it were today?\r\nFaithful and true would He find us here,\nif He should come today?\nWatching in gladness and not in fear,\nif He should come today?\nSigns of His coming multiply,\nmorning light breaks in eastern sky.\nWatch, for the time is drawing nigh,\nwhat if it were today?', 'Jesus kommt wieder in Herrlichkeit,\nwas, wenn es heute wär\'?\nFriede und Freude in Ewigkeit,\nwas, wenn es heute wär\'.\nJesus holt seine Erlösten heim,\ndie er im Blute gewaschen rein.\nChristusgemeinde, wann wird\'s sein?\nWas, wenn es heute wär?\r\nHerrlich, herrlich,\nSatan und Sünde fällt.\nHerrlich, herrlich,\nkrönt Ihn zum Herrn der Welt.\nHerrlich, herrlich,\nwachet und seid bereit!\nHerrlich, herrlich,\nbald ist des Königs Zeit!\r\nSatan und Sünde gebunden sind.\nAch, dass es heute wär\'!\nSeufzen und Klagen man nicht mehr find\'t,\nach, dass es heute wär\'!\nTote in Christus dann aufersteh\'n,\nIhm zu begegnen in Himmelshöh\'n.\nWunder wird unser Auge seh\'n,\nach, dass es heute wär\'!\r\nWeißt du, ob du mit dem Heiland gehst,\nwenn Er noch heute käm\'?\nOb du im Buche des Lebens stehst,\nwenn Er noch heute käm\'?\nJa, Er wird kommen, d\'rum sei bereit!\nWache und bete, schnell flieht die Zeit.\nWo wirst du sein in der Ewigkeit,\nwenn Er noch heute käm?'),
(9, '1073', 'Jesus kommt wieder, herrliche Zeit  -  Some glorious Morning Sorrow will cease   (Glorreicher Morgen, wenn Er erscheint)', 'Some glorious morning sorrow will cease,\nsome glorious morning all will be peace.\nHeartaches all ended, schooldays all done,\nheaven will open, Jesus will come.\r\nSome golden daybreak, Jesus will come.\nSome golden daybreak, battles all won.\nHe\'ll shout the victory, break through the blue.\nSome golden daybreak, for me, for you.\r\nSad hearts will gladden, all shall be bright.\ngood-bye forever to earth\'s dark night.\nChanged in a moment, like Him to be,\noh, glorious daybreak, Jesus I\'ll see.\r\nOh, what a meeting, there in the skies,\nno tears nor crying shall dim our eyes.\nLoved ones united eternally,\noh, what a daybreak that morn will be.', 'Jesus kommt wieder, herrliche Zeit!\nEr, der uns heimfand und uns befreit.\nIhm gebührt Ehre, Macht und Gewalt,\nöffne dich, Himmel, Jesus kommt bald!\r\nGlorreicher Morgen, wenn Er erscheint\nund all die Seinen mit sich vereint,\nwenn aus den Himmeln Sein Ruf erschallt.\nGlorreicher Morgen, der Herr kommt bald!\r\nTrauer muss weichen, Freude kehrt ein.\nPilger zum Himmel bald schon daheim.\nHerrlich verwandelt, Jesus Dir gleich,\nDir nur zu dienen in Deinem Reich.\r\nWas für ein Treffen wird es dort sein!\nKeiner mehr weinet, wir sind daheim.\nSind dann vereinigt in Ewigkeit,\no Halleluja, für alle Zeit!'),
(9, '1074', 'Jesus lässt dich nie allein, wenn Freunde auch dich oft verlassen', NULL, 'Jesus lässt dich nie allein,\nwenn Freunde auch dich oft verlassen.\nWenn kein Mensch in der Not zu dir steht,\nschenkt Er dir Geborgenheit,\ntiefen Frieden, wahre Freude\nwie ein Freund, der zu trösten versteht.\r\nSage alles nur Ihm, Er versteht deine Sorgen,\nwie schwarz auch die Wolken oft über dir steh\'n.\nIch sage alles, alles Ihm,\nEr ist bei mir heut\' und morgen,\nalle Tage, durch die ich noch geh.\r\nSage alles nur Ihm, Er versteht Deine Sorgen,\nwie schwarz auch die Wolken oft über dir steh\'n.\nIch bin froh, Sein Kind zu sein,\nich hab alles, brauch nicht sorgen.\nSeine Liebe und Treu\' mit mir geh\'n.'),
(9, '1075', 'Jesus lebet, Jesus siegt, Halleluja Amen', '\r\nJesus lebet, Jesus siegt.\nHalleluja! Amen.\r\n\r\n\r\n\r\n\r\n', 'Jesus lebet, Jesus siegt!\nHalleluja! Amen.\nSatan wütend stets bekriegt\nGottes heil\'gen Samen.\nVolk des Herrn, o sei getrost,\nwenn der Feind auch sehr erbost.\r\n\r\nEr verlor noch keine Schlacht\nund wird nie verlieren;\ndenn mit unbegrenzter Macht\nkann Er Kriege führen.\nUnter Seinem Kreuzpanier\nist der beste Platz allhier.\r\nStreiter Christi, frisch voran\nohne Furcht und Zagen.\nLängst gebrochen ist die Bahn,\nd\'rum darfst du es wagen.\nGottes Gnade reicht für dich,\nund du siegst ganz sicherlich.\r\nWird dir\'s auch im Kampfe heiß,\nlass den Mut nicht schwinden,\ndenn es gilt um jeden Preis\nstets zu überwinden!\nNur froh auf das Lamm geschaut\nund Ihm still und fest vertraut!\r\nKleines Häuflein, sei getreu\nin des Königs Kriegen.\nMache dich von allem frei,\nwas nicht hilft zum Siegen.\nHalt zusammen wie ein Mann,\ndass durch dich man sehen kann.\r\nHarre aus! Das End\' ist nah.\nBald erscheint die Stunde,\nwo ein froh Viktoria\ngeht von Mund zu Munde.\nEwig enden Kampf und Schmerz,\nselig jauchzt ein jedes Herz.'),
(9, '1076', 'Jesus lebt in mir, Jesus lebt in mir   (Chorus)', NULL, 'Jesus lebt in mir, Jesus lebt in mir.\nSünd\' und Tod müssen flieh\'n,\ndenn sie sind besiegt,\ndenn Jesus lebt in mir.'),
(9, '1077', 'Jesus liebt mich ganz gewiss  -  Jesus loves me this I know   (Ja, Jesus liebt mich)', 'Jesus loves me this I know,\nfor the bible tells me so.\nLittle ones to him belong,\nthey are weak, but he is strong.\r\nYes, Jesus loves me,\nyes, Jesus loves me,\nyes, Jesus loves me,\nthe Bible tells me so.\r\nJesus loves me he who died\nheaven\'s gate to open wide.\nHe will wash away my sin,\nlet his little child come in.\r\nJesus loves me! loves me still,\nthough I\'m very weak and ill.\nFrom His shining throne on high,\ncomes to watch me where I lie.\r\n', 'Jesus liebt mich, ganz gewiss,\ndenn die Bibel sagt mir dies.\nAlle Kinder groß und klein,\nlädt er herzlich zu sich ein.\r\nJa, Jesus liebt mich,\nja, Jesus liebt mich,\nja, Jesus liebt mich,\ndie Bibel sagt mir dies.\r\nJesus liebt mich, ja Er starb\nund das Heil Er mir erwarb.\nEr wusch mich von Sünden rein,\nführt mich einst zum Himmel ein.\r\nJesus liebt mich allezeit,\nauch wenn Schmerz und tiefes Leid\nmich befällt, Er treulich wacht\nund der Not ein Ende macht.\r\nJesus liebt mich, Er mein Hirt\',\nsicher mich, Sein Schäflein führt,\nwenn ich treu Ihm folge hier\nbin ich selig für und für.'),
(9, '1078', 'Jesus lover of my soul', 'Jesus, lover of my soul\nJesus, I will never let You go\nYou\'ve taken me from the miry clay\nSet my feet upon a rock\nAnd now I know\nI love You, I need You\nThough my world may fall\nI\'ll never let You go\nMy Savior, my closest friend\nI will worship You until the very end\nUntil the very end', 'Jesus, Liebe meines Lebens\nJesus, ich lass dich niemals los\nDu holtest mich aus der tiefsten Finsternis\nDu stelltest mich auf festen Grund\nund jetzt weiss ich \nIch lieb dich\nIch brauch dich\nAuch wenn die Welt vergeht\nIch lass dich niemals los\nMein Retter\nMein bester Freund\nIch verehre dich\nIn alle Ewigkeit'),
(9, '1079', 'Jesus nimmt die Sünder an', NULL, 'Jesus nimmt die Sünder an!\nSaget doch dies Trostwort allen,\nwelche von der rechten Bahn\nauf verkehrten Weg verfallen!\nHier ist, was sie retten kann:\nJesus nimmt die Sünder an!\r\nKeiner Gnade bin ich wert,\ndoch hat Er mit Seinem Worte\neidlich sich dazu erklärt.\nSehet nur, die Gnadenpforte\nist hier völlig aufgetan:\nJesus nimmt die Sünder an!\r\nWenn ein Schaf verloren ist,\nsuchet es ein treuer Hirte;\nJesus, der uns nie vergisst,\nsuchet treulich das Verirrte,\ndass es nicht verderben kann:\nJesus nimmt die Sünder an!\r\nKommet alle, kommet her,\nkommet, ihr betrübten Sünder!\nJesus rufet euch, und Er\nmacht aus Sündern Gottes Kinder.\nGlaubt es doch und denkt daran:\nJesus nimmt die Sünder an!\r\nIch Betrübter komme hier\nund bekenne meine Sünden,\nlass, mein Heiland, mich bei Dir\nGnade und Vergebung finden,\ndass dies Wort mich trösten kann:\nJesus nimmt die Sünder an!\r\nJesus nimmt die Sünder an!\nMich hat er auch angenommen\nund den Himmel aufgetan,\ndass ich selig zu Ihn kommen\nund auf den Trost sterben kann:\nJesus nimmt die Sünder an!'),
(9, '1080', 'Jesus nur alleine sei das Losungswort', NULL, 'Jesus nur alleine sei das Losungswort!\nNein, von meinem Heiland geh ich nicht mehr fort.\r\nEr gab mir die Kindschaft, nahm mich auf und an.\nO wie bin ich fröhlich, dass ich\'s glauben kann.\r\nMir ist\'s unbegreiflich und zu wunderbar\nnein, ich kann\'s nicht fassen, wie es möglich war!\r\nEinem solchen Armen welchem alles fehlt,\nhat Er sich zum sel\'gen Eigentum erwählt.\r\nDen, der Ihm bereitet manches Herzeleid,\nhat Er von dem ew\'gen Untergang befreit.\r\nDoch Er hat\'s nun einmal so mit mir gemacht,\nmich zum sel\'gen Leben aus dem Tod gebracht.\r\nKann nun Abba rufen, kann nun freudig ruhn\nin des Heilands Liebe; dabei bleibt es nun.\r\nDabei soll es bleiben, bis mein Auge bricht.\nAmen, Halleluja! Jesus lässt mich nicht!'),
(9, '1081', 'Jesus oh mein Jesus', NULL, 'Ich vertraue meinem Jesus,\nauch wenn dunkel ist die Nacht,\nwill Ihm trauen, auf Ihn schauen,\nauch wenn alles bersten mag.\r\nIch vertraue meinem Jesus,\nwenn die Kräfte schwinden wollen,\nEr bleibt meine Zufluchtsstätte,\nEr ist meine feste Burg.\r\nJesus, o mein Jesus,\nDir vertraue ich allein,\nJesus, o mein Jesus,\nDu mein Alles, Du bist mein.\r\nIch vertraue meinem Jesus,\nwelcher sagt: Ich bin der Weg,\nja, ich weiß dass ich am Ende\nSeine Herrlichkeit werde sehen.\r\nOh, an dem Kreuz, wo es geschah,\nich lege ab meine Bürde und belasse sie dort;\nWas könnte ich tun, es ist Gnade allein,\nDir vertraue ich, Dir vertraue ich,\nJesus Christus, Du bist mein.'),
(9, '1082', 'Jesus on the Inside, working on the outside', 'Jesus on the inside, working on the outside,\noh what a change in my life.\nJesus on the inside, working on the outside,\noh what a change in my life.\nJesus on the inside, working on the outside,\noh what a change in my life.\nOh, what a change in my life.', NULL),
(9, '1083', 'Jesus on the main line', 'Jesus on the main line, tell Him what you want,\nJesus on the main line, tell Him what you want.\nJesus on the main line, tell Him what you want.\nJesus on the main line now.\r\nIf you want your healing, tell Him what you want.\nIf you want your healing, tell Him what you want.\nIf you want your healing, tell Him what you want.\nJesus on the main line now.\r\nIf you want your loved ones saved, tell Him what you want.\nIf you want your loved ones saved, tell Him what you want.\nIf you want your loved ones saved, tell Him what you want.\nJesus on the main line now.\r\nIf you want the Holy Ghost, tell Him what you want.\nIf you want the Holy Ghost, tell Him what you want.\nIf you want the Holy Ghost, tell Him what you want.\nJesus on the main line now.', NULL),
(9, '1084', 'Jesus ruft freundlich Verlorne nach Haus  -  Jesus is tenderly calling thee home   (Jesus ruft heut, Jesus ruft heut)', 'Jesus is tenderly calling thee home,\ncalling today, calling today.\nWhy from the sunshine of love wilt thou roam\nFarther and farther away?\r\nCalling today,\nCalling today.\nJesus is calling,\niIs tenderly calling today.\r\nJesus is calling the weary to rest,\ncalling today, calling today.\nBring Him thy burden and thou shalt be blest,\nHe will not turn thee away.\r\nJesus is waiting, o come to Him now,\nwaiting today, waiting today;\nCome with thy sins,; at His feet lowly bow,\ncome and no longer delay.\r\nJesus is pleading, o list to His voice,\nhear Him today, hear Him today.\nThey who believe on His name shall rejoice,\nquickly arise and away.', 'Jesus ruft freundlich Verlor\'ne nach Haus,\nJesus ruft heut\', Jesus ruft heut\'.\nKomm aus dem Dunkel der Sünde heraus,\njetzt, wo Er Gnade dir beut!\r\nJesus ruft heut\', Jesus ruft heut\'.\nJesus, Er rufet.\nEr rufet so freundlich dich heut\'.\r\nJesus schenkt Müden Erquickung und Ruh\',\nschenket sie heut\', schenket sie heut\'.\nBring Ihm die Sorgen; o eile herzu!\nStillt Er doch gerne dein Leid!\r\nJesus harrt deiner, o Sünder, noch heut\',\nwartet noch heut\', wartet noch heut\'.\nHast du die Schuld deiner Sünde bereut?\nKomme, o Sünder, noch heut\'!\r\nJesus, Er locket und nötigt dich heut\',\nhör Ihn doch heut\', hör Ihn doch heut\'.\nWer an Ihn glaubet, hat Frieden und Freud.\nEile zum Retter noch heut\'!'),
(9, '1085', 'Jesus set me absolutely free   (Chorus)', 'Jesus set me absolutely free,\ndied on Calvary, gave me liberty,\nJesus set me absolutely free,\npraise His Holy Name.', NULL),
(9, '1086', 'Jesus sprengt jede Kette  -  Jesus breaks every Fetter   (7 Chorusse)', 'Jesus breaks every fetter,\nJesus breaks every fetter,\nJesus breaks every fetter,\nfor He sets me free!\r\nI will ever, ever praise Him,\nI will ever, ever praise Him,\nI will ever, ever praise Him,\nfor He sets me free!\r\nI will never doubt my Saviour,\nI will never doubt my Saviour,\nI will never doubt my Saviour,\nfor He cleanses me.\r\nI will rest on His promise,\nI will rest on His promise,\nI will rest on His promise,\nwhich is given to me.\r\nI will give God the glory,\nI will give God the glory,\nI will give God the glory,\nfor He set me free!\r\nI will sing Hallelujah,\nI will sing Hallelujah,\nI will sing Hallelujah,\nfor He set me free!\r\nOn the other side of Jordan,\nin the sweet fields of Eden,\nwhere the Tree of Life is blooming,\nthere is rest for me.', 'Jesus sprengt jede Kette,\nJesus sprengt jede Kette,\nJesus sprengt jede Kette,\ndenn Er macht mich frei.\r\nIch will Ihn immer preisen,\nich will Ihn immer preisen,\nich will Ihn immer preisen,\ndenn Er macht mich frei.\r\nIch will Ihn nicht anzweifeln,\nich will Ihn nicht anzweifeln,\nich will Ihn nicht anzweifeln,\ndenn Er reinigt mich.\r\nIch will ruh\'n in der Verheißung,\nich will ruh\'n in der Verheißung,\nich will ruh\'n in der Verheißung,\ndie mir gegeben ist.\r\nIch will Gott Ehre bringen,\nich will Gott Ehre bringen,\nich will Gott Ehre bringen,\ndenn Er macht mich frei.\r\nIch will Hallelujah singen,\nich will Hallelujah singen,\nich will Hallelujah singen,\ndenn er macht mich frei.\r\nAuf der and\'ren Jordanseite,\nauf der and\'ren Jordanseite,\nauf der and\'ren Jordanseite,\nda ist Ruh\' für mich.'),
(9, '1087', 'Jesus sucht das Verlorne, wer da will der komme heut   (Weit über die Lüfte hinaus, ist dein Zuhaus)', NULL, 'Jesus sucht das Verlor\'ne, wer da will der komme heut\'.\nAll deine Sünden nimmt Er dir ab,\nmacht dich ganz neu, Er macht alles neu,\nlass dich heut\' finden von diesem Herrn,\nEr hilft umsonst dir so gern.\r\nWeit über die Lüfte hinaus, ist dein Zuhaus,\nJesus Er liebt dich ja so sehr.\nViele sind dir schon voraus, sie ruhen aus,\nnur du allein irrst noch umher.\r\nJesus sucht das Verlor\'ne, wer da will der komme heut\'.\nEr will dir helfen, Er hat die Kraft,\nkomm aus dem Meer deiner Leidenschaft,\nschon triebt dein Schiff hinaus in die Welt,\nbis es am Felsen zerschellt.\r\nJesus sucht das Verlor\'ne, wer da will der komme heut\'.\nBlicke hinauf und sieh was geschah,\nan jenem Kreuz auf Golgatha,\nan deiner Stelle starb dort ein Lamm,\nfür uns\'re Sünden am Stamm.\r\nJesus sucht das Verlor\'ne, wer da will der komme heut\'.\nO komme heute jetzt ist deine Zeit,\nsie flieht es folgt dir die Ewigkeit,\nwarnende Stimmen schall\'n durch die Nacht,\nChristen und Sünder erwacht.'),
(9, '1088', 'Jesus sweet Jesus in me   (Chorus)', 'Jesus sweet Jesus in me.\nNo longer me but Thee.\nRessurection power,\nfill me this hour,\nJesus sweet Jesus in me.', NULL),
(9, '1089', 'Jesus to Calvary did go, His Love for Mankind to show   (Oh how He loves you and me)', 'Oh how He loves you and me.\nOh how He loves you and me.\nHe gave His Life, what more could He do\nOh how He loves You, Oh how He loves me.\nOh how He loves You and me.\r\nJesus to Calvary did go,\nHis love for mankind to show.\nAnd what He did there brought hope from despair.\nOh how He loves You, Oh how He loves me.\nOh how He loves You and me.', NULL),
(9, '1090', 'Jesus took my Burdens and rolled them in the Sea', 'Jesus took my burdens\nand rolled them in the sea,\nrolled them in the sea,\nrolled them in the sea.\nAnd now I have a peace\nthat He has given me.\nAll my sins and burdens\nHe rolled them in the sea.', NULL),
(9, '1091', 'Jesus trau ich Tag für Tag  -  Simply trusting every day   (Jesus trau ich in der Zeit, trau Ihm bis in Ewigkeit)', 'Simply trusting every day,\ntrusting through a stormy way.\nEven when my faith is small,\ntrusting Jesus, that is all.\r\nTrusting as the moments fly,\ntrusting as the days go by.\nTrusting Him whate’er befall,\ntrusting Jesus, that is all.\r\nBrightly doth His Spirit shine\ninto this poor heart of mine.\nWhile He leads I cannot fall,\ntrusting Jesus, that is all.\r\nSinging if my way is clear,\npraying if the path be drear.\nIf in danger for Him call,\ntrusting Jesus, that is all.\r\nTrusting Him while life shall last,\ntrusting Him till earth be past.\nTill within the jasper wall,\ntrusting Jesus, that is all.', 'Jesus trau\' ich Tag für Tag,\nwie der Sturm auch toben mag.\nIst der Glaube schwach und klein,\nJesus trau ich, Ihm allein!\r\nJesus trau ich in der Zeit,\ntrau Ihm bis in Ewigkeit.\nWenn die Trübsal bricht herein,\ntrau ich Jesus, Ihm allein!\r\nLieblich strahlet Gottes Schein\nin mein armes Herz hinein.\nWenn Er führet, geht es gut.\nJesus trau ich wohlgemut.\r\nFröhlich geht es himmelan,\nwenn man Ihm vertrauen kann.\nWillst du froh und selig sein,\ntraue Jesus, Ihm allein!\r\nJesus schenkt mir Seeleruh\',\nspricht mir Seinen Frieden zu,\nlässt die Freude völlig sein.\nDarum trau ich Ihm allein!'),
(9, '1092', 'Jesus we are here for You   (5 Chorusse)', 'Jesus we are here,\nJesus we are here,\nJesus we are here,\nwe are here, for You.\r\nFather we are here\nFather we are here,\nFather we are here,\nwe are here, for You.\r\nHoly Spirit we are here\nHoly Spirit we are here,\nHoly Spirit we are here,\nwe are here, for You.\r\nMaster we are here,\nMaster we are here,\nMaster we are here,\nwe are here, for You.\r\nMy Saviour we are here,\nMy Saviour we are here,\nMy Saviour we are here,\nwe are here,  for You.', NULL),
(9, '1093', 'Jesus What A Savior You Are', 'You are my strength when all my strength has ended\nYou are my hope when all my hope is gone\nYou are my joy when my world\'s filled with sorrow,\nyou\'re the peace in my tomorrow\nfor I know that you\'ll be there\r\nYou are my song when my melody has ended\nA light in the storm when I can\'t find my way\nYou are the one who gives my life a reason\nSomeone to believe in\nYou help me carry on\r\nJesus what a Saviour you are\nSaviour you are\nJesus what a Saviour you are\r\nYou are my rock when I need a place of refuge\nA hand reaching out when I stumble and fall\nYou are my all in every time and season\nYou are all I ever needed\nEvery time I call\r\nYou heard my cry\nYou answered my plea\nGave up your life\nGave me everything\nNow forever more\nI\'m devoted to you\nAnd that\'s why I sing my praise to you', NULL),
(9, '1094', 'Jesus your name is power', 'Jesus Your name is power,\nJesus, Your name is might\nJesus, Your name will break every stronghold\nJesus, Your name is life\r\nJesus, Your name is healing,\nJesus, Your name gives sight\nJesus, You name will free every captive\nJesus, Your name is life\r\nJesus, Your name is holy,\nJesus, Your name brings light\nJesus, Your name above every other\nJesus, Your name is life', NULL),
(9, '1095', 'Jesus zieh zum Kreuze mich  -  Jesus keep me near the Cross   (Hin zum Kreuz, hin zum Kreuz)', 'Jesus, keep me near the cross,\nthere a precious fountain.\nFree to all, a healing stream,\nflows from Calv\'ry\'s mountain\r\nIn the cross, in the cross,\nbe my glory ever,\ntill my ransomed soul shall find,\nrest beyond the river.\r\nNear the cross, a trembling soul,\nlove and mercy found me.\nThere the bright and morning star,\nshed His beams around me.\r\nNear the cross! O lamb of God,\nbring its scenes before me.\nHelp me walk from day to day,\nwith its shadow o\'er me.\r\nNear the cross! I\'ll watch and wait,\nhoping, trusting ever.\nTill I reach the golden strand,\njust beyond the river.', 'Jesus zieh zum Kreuze mich,\nwo die Quelle fließet,\ndie zum Heil der Sünder sich\ndort so frei ergießet.\r\nHin zum Kreuz, hin zum Kreuz,\nall mein Sehnen gehe,\nbis vor Gottes Throne ich\ntriumphierend stehe.\r\nZu dem Kreuz ich bebend kam,\nhilflos, schuldbeladen.\nAn dem blutbefleckten Stamm\nward ich frei von Schaden.\r\nNach dem Kreuze lass mich schau\'n,\nlass den Herrn mich sehen.\nIch will nur dem Opfer trau\'n,\ndas am Kreuz geschehen.\r\nVon dem Kreuze rühme ich,\nfür das Kreuz ich wage.\nUnd die Krone harrt auf mich,\nwenn das Kreuz ich trage.'),
(9, '1096', 'Jesus\' Name is so sweet   (2 Chorusse)', NULL, 'Jesus\' Name so sweet\nEmmanuel Name \'s so sweet,\nJesus\' Name so sweet,\nEmmanuel Name \'s so sweet,\r\nEvery time I talk about Jesus,\nJesus\' Name so sweet.\nEvery time I talk about Jesus,\nJesus\' Name so sweet.'),
(9, '1097', 'Jesus, alles sei Dein Eigen  -  All for Jesus! All for Jesus', 'All for Jesus! All for Jesus!\nAll my being’s ransomed pow\'rs,\nall my thoughts and words and doings,\nall my days and all my hours.\r\nSince my eyes were fixed on Jesus,\nI’ve lost sight of all beside.\nSo enchained my spirit’s vision,\nlooking at the Crucified.\r\nWorldlings prize their gems of beauty,\ncling to gilded toys of dust,\nboast of wealth and fame and pleasure;\nonly Jesus will I trust.\r\n\r\n\r\n', 'Jesus, alles sei Dein Eigen,\nLeib und Seele, Geist und Sinn!\nIch will ganz vor Dir mich beugen;\nnimm mein Herz, nimm alles hin!\r\nLass mein Aug auf Dich nur sehen,\nHand und Fuß lenk\' Dein Geheiß;\nund mein Mund soll Dich erhöhen,\nDir sei ewig Ruhm und Preis!\r\nNicht der Welt und ihren Lüsten\nkann ich fortan noch vertrau\'n.\nGeht\'s auf Rosen, geht\'s durch Wüsten,\nnur auf Gnade will ich bau\'n.\r\nSeit ich den am Kreuz erblicket,\nder Sein Blut für mich vergoss,\nist mein ganzes Herz entzücket\nJesus, Deine Lieb ist groß.\r\nO, wie fühl\' ich mich erwarmen!\nHerr, ich beuge mich vor Dir!\nSchließ\' mich ein in Dein Erbarmen,\nsei mir gnädig für und für!\r\nO, welch Wunder! Ich, ein Sünder,\ndarf nun ruh\'n in Jesu Schoß.\nJa, ich rühm\'s als Überwinder:\nSelig, selig ist mein Los.'),
(9, '1098', 'Jesus, dein Heiland, er rufet dir zu   (Hörst du den Heiland so inniglich flehn)', NULL, 'Jesus, dein Heiland, er rufet dir zu,\nhörst du Ihn fleh\'n, inniglich fleh\'n?\nAn Seinem Herzen ist Friede und Ruh\'.\nHör Ihn so inniglich fleh\'n.\r\nHörst du den Heiland so inniglich fleh\'n?\nOhne Ihn wirst du ja niemals besteh\'n.\nHier ist dein Retter aus himmlischen Höh\'n.\nHör Ihn so inniglich fleh\'n.\r\nLange schon ruft Er in großer Geduld,\nhörst du Ihn fleh\'n, inniglich fleh\'n?\nRufet dir zu mit unendlicher Huld,\nhör Ihn so inniglich fleh\'n.\r\nSchon siehst du nahen das ew\'ge Gericht,\nkannst du besteh\'n, vor Ihm besteh\'n?\nO dann wird\'s heißen: Ich kenne dich nicht!\nWie willst du vor Ihm besteh\'n?\r\nBald wird verstummen der Mahnruf des Herrn\nund auch Sein Fleh\'n, ja auch Sein Fleh\'n!\nDann werden Tausende stehen von fern,\nnimmer Sein Angesicht seh\'n.'),
(9, '1099', 'Jesus, der Herr, will mich brauchen, ein Sonnenstrahl zu sein  -  Jesus wants me for a Sunbeam, to shine for Him each Day   (Für Jesus, für Jesus will ich als Sonnenstrahl leuchten)', 'Jesus wants me for a sunbeam,\nto shine for Him each day.\nIn every way try to please Him,\nat home, at school, at play.\r\nA sunbeam, a sunbeam,\nJesus wants me for a sunbeam.\nA sunbeam, a sunbeam,\nI’ll be a sunbeam for Him.\r\nJesus wants me to be loving,\nand kind to all I see.\nShowing how pleasant and happy,\nHis little one can be.\r\nI will ask Jesus to help me\nto keep my heart from sin.\nEver reflecting His goodness,\nand always shine for Him.\r\nI’ll be a sunbeam for Jesus,\nI can if I but try.\nServing Him moment by moment,\nthen live for Him on high.', 'Jesus, der Herr, will mich brauchen,\nein Sonnenstrahl zu sein,\nder alle Tage hell leuchtet,\ndoch nur für Ihn allein.\r\nFür Jesus, für Jesus\nwill ich als Sonnenstrahl leuchten,\nFür Jesus, für Jesus\nwill ich ein Sonnenstrahl sein.\r\nJesus will freundlich mich sehen\nbei bei allem, was ich tu\',\ndenn bei dem Spiel, bei der Arbeit\nschaut mir der Heiland zu.\r\nJesus soll nur aus mir leuchten,\nich bitte Ihn darum,\ndass jeder mich gleich erkenne\nhier als sein Eigentum.\r\nJa, als ein Sonnenstrahl Jesu\nleb\' ich hier Tag für Tag,\nbis in den sonnigen Himmel\nEr heim mich holen mag.'),
(9, '1100', 'Jesus, der Name des Vaters,Gott, eingehüllt im Sohn   (Jesus ist Gott, Halleluja)', NULL, 'Jesus ist Gott, Halleluja,\nJesus ist Gott und Herr.\nJesus ist Gott, Halleluja,\nEr und sonst keiner mehr\r\nJesus, der Name des Vaters,\nGott, eingehüllt im Sohn,\nDu bist allein und kein andrer,\ndort auf dem Himmelsthron.\r\nJesus, wir wollen bekennen:\nDu bist mein alles mir,\nDu bist die Fülle der Gottheit,\newiger, einziger Herr.\r\nSanftmut und Demut Dein Wesen,\nund doch so königlich,\nstets bist Du uns nah gewesen\nund darum lieben wir Dich.'),
(9, '1101', 'Jesus, Du allein bist genug', NULL, 'Jesus, Du allein bist genug,\nDu bist alles für mich.\nJesus, öffne mein Herz,\nlass mich seh\'n und versteh\'n,\ndass Du mich liebst.\r\nKomm und fülle mein Herz,\ngib mir neu Deinen Geist.\nDu bist unser Gott der Heilung bringt,\nLicht des Lebens,\ndas das Dunkel durchbricht.'),
(9, '1102', 'Jesus, Du meine Sonne, Du meine Wonne, Du hast mich lieb   (Sehnsucht, zieh mich näher zu Jesus)', NULL, 'Jesus, Du meine Sonne, Du meine Wonne, Du hast mich lieb.\nFreuden in meinem Leben hast Du gegeben, o, welch ein Glück!\r\nHeimat im Licht dort oben, dich einst zu loben, darf ich hingeh\'n.\nWandeln auf goldnen Gassen, das zu erfassen ist wunderschön.\r\nSehnsucht, zieh mich näher zu Jesus,\nSehnsucht, bring mich näher nach Haus.\nSehnsucht, zieh mich näher zu Jesus,\nSehnsucht, bring mich näher nach Haus.\r\nJesus, Du musst mich ziehen, denn mein Bemühen, ist doch so klein.\nFließen auch manchmal Tränen, ist doch mein Sehnen, bei Dir zu sein.'),
(9, '1103', 'Jesus, geh voran auf der Lebensbahn', NULL, 'Jesus, geh voran auf der Lebensbahn!\nUnd wir wollen nicht verweilen,\nDir getreulich nachzueilen;\nführ uns an der Hand bis ins Vaterland.\r\nSoll\'s uns hart ergeh\'n, lass uns feste steh\'n,\nund auch in den schwersten Tagen,\nniemals über Lasten klagen.\nDenn durch Trübsal hier, geht der Weg zu Dir.\r\nRühret eigner Schmerz irgend unser Herz,\nkümmert uns ein fremdes Leiden,\no so gib Geduld zu beiden.\nRichte unsern Sinn, auf das Ende hin.\r\nOrdne unsern Gang, Jesu, lebenslang.\nFührst Du uns durch rauhe Wege,\ngib uns auch die nöt\'ge Pflege.\nTu\' uns nach dem Lauf Deine Türe auf.'),
(9, '1104', 'Jesus, He\'s the Waymaker   (I saw the Lord! I saw the Lord!)', 'Jesus, He\'s the waymaker,\nJesus, He\'s the waymaker,\nJesus, He\'s the waymaker,\none day He made a way, oh glory.\nWhen I was lost in sin,\nHe came and took me in.\nOne day, He made a way for me.\r\nI saw the Lord! I saw the Lord!\nAnd He was high and lifted up,\nand His train filled the temple.\nHe was high and lifted up\nand His train filled the temple.\nThe angels cried: "Holy!"\nThe angels cried: "Holy!"\nThe angels cried: "Holy is the Lord!"', NULL),
(9, '1105', 'Jesus, Heiland meiner Seele  -  Jesus, Lover of my Soul   (O wie gut ists, Dir vertrauen, Jesus, Dir ergeb ich mich)', 'Jesus, lover of my soul,\nlet me to thy bosom fly,\nwhile the nearer waters roll,\nwhile the tempest still is high.\r\n\r\nHide me, oh my Saviour, hide,\ntill the storm of life is past.\nSafe into the haven guide,\noh receive my soul at last!\r\nOther refuge have I none,\nhangs my helpless soul on Thee.\nLeave, ah! leave me not alone,\nstill support and comfort me.\r\nAll my trust on thee is stayed,\nall my help from thee I bring.\nCover my defenseless head\nwith the shadow of thy wing.\r\nPlenteous grace with thee is found,\ngrace to cover all my sin.\nLet the healing streams abound,\nmake and keep me pure within.\r\nThou of life the fountain art,\nfreely let me take of thee.\nSpring thou up within my heart,\nrise to all eternity.\r\n', 'Jesus, Heiland meiner Seele,\nlass an Deine Brust mich flieh\'n,\nda die Wasser näher rauschen\nund die Wetter höher zieh\'n.\r\nO wie gut ist\'s, Dir vertrauen,\nJesus, Dir ergeb\' ich mich!\nSelig, droben Dich zu schauen,\nDein zu bleiben ewiglich!\r\nBirg mich in den Lebensstürmen,\nbis vollendet ist mein Lauf;\nführe mich zum sichern Hafen,\nnimm dann meine Seele auf!\r\nAndre Zuflucht hab ich keine,\nzagend hoff\' ich nur auf Dich,\nlass, o lass mich nicht alleine,\nhebe, Herr, und stärke mich!\r\nNur zu Dir steht mein Vertrauen,\ndass kein Übel mich erschreckt;\nmit dem Schatten Deiner Flügel\nsei mein wehrlos Haupt bedeckt!\r\nGnad\' um Gnade, volle Sühnung\nsind in Dir, o Jesus, mein;\nlass die Heilung mich beströmen,\nnimm gereinigt mich hinein.\r\nDu bist ja des Lebens Quelle,\ndie den Durst auf ewig stillt.\nSei der Born in meinem Herzen,\nder zum ew\'gen Leben quillt!\r\nO wie gut ist\'s, Dir vertrauen,\nJesus, Dir ergeb\' ich mich!\nSelig, droben Dich zu schauen,\nDein zu bleiben ewiglich!'),
(9, '1106', 'Jesus, Heiland, steure Du, sicher mich dem Hafen zu  -  Jesus, Saviour, pilot me, over Life\'s tempestuous Sea', 'Jesus, Saviour, pilot me,\nover life\'s tempestuous sea.\nUnknown waves before me roll,\nhiding rocks and treach\'rous shoal.\nChart and compass come from Thee,\nJesus, Saviour, pilot me!\r\nAs a mother stills her child,\nThou canst hush the ocean wild.\nBoist\'rous waves obey Thy will\nwhen Thou say\'st to them, "Be still!"\nWondrous Sov\'reign of the sea,\nJesus, Saviour, pilot me!\r\nWhen at last I near the shore,\nand the fearful breakers roar.\n\'Twixt me and the peaceful rest,\nthen, while leaning on Thy breast,\nmay I hear Thee say to me,\n"Fear not - I will pilot thee!"', 'Jesus, Heiland, steure Du,\nsicher mich dem Hafen zu.\nFühre mich durch Sturmesnot,\nführe mich wo Klippe droht.\nSicher komme ich an\'s Land,\nhält das Steuer Deine Hand.\r\nTost der Wind und schäumt das Meer,\nsprich ein Wort, Du bist ihr Herr!\nSieh\' die Woge schweigt; der Wind\natmet wie ein schlummernd\' Kind.\nSturmesbrausen sinkt zur Ruh\'.\nJesus Heiland steu\'re Du.\r\nNah\' ich endlich mich dem Land,\nwo die Brandung bricht am Strand,\nbist Du dann, mein Heiland, nah\',\nbleibt mein Herze still auch da.\nMit der Hand am Steuer sprich:\nFürchte nichts Ich steure Dich.'),
(9, '1107', 'Jesus, höchster Name, teurer Erlöser, siegreicher Herr  -  Jesus, Name above all Names, beautiful Saviour, glorious Lord   (2 Chorusse)', 'Jesus, Name above all names,\nbeautiful Saviour, glorious Lord.\nEmmanuel, God is with us,\nblessed Redeemer, living Word.\r\nHe is the Prince of Peace and the Almighty God,\nadviser wonderful, Eternal Father,\nand the dominion rests on His shoulder,\nand there will be no end to his kingdom of peace.', 'Jesus, höchster Name,\nteurer Erlöser, siegreicher Herr.\nImmanuel, Gott ist mit uns,\nHerrlicher Heiland, lebendiges Wort.\r\nEr ist der Friedefürst und der allmächt\'ge Gott,\nRatgeber wunderbar, Ewiger Vater,\nund die Herrschaft ruht auf Seiner Schulter,\nund Seines Friedensreichs wird kein Ende sein.'),
(9, '1108', 'Jesus, I adore You', 'Jesus, I adore You,\nlay my life before You,\noh, how I love You.', 'Jesus, ich erhebe Dich,\nleg\' mein Leben vor Dich,\noh, wie sehr lieb ich Dich.'),
(9, '1109', 'Jesus, I need a Touch from You', 'Jesus, I need a touch from you,\n\'cause I am weary and tired.\nLord, won\'t you please lay your hands on my heart,\n\'cause I can\'t go on without you.\r\nThe things that I see, the things that I do,\nare making me weary and tired.\nThis world falls apart, all I need Lord is You.\nI just can\'t go on without you\r\nLord touch me, I open my door,\ntake seat at the throne of my heart.\nRestore your spirit, within me o Lord,\n\'cause I can\'t survive without you.\r\nThe victory You won, on Calvary,\nthe day You died on the cross.\nLet it become, reality, deep down in me,\nthat I am Yours eternally.', NULL),
(9, '1110', 'Jesus, in Deinem Namen ist die Kraft', NULL, 'Jesus, in Deinem Namen ist die Kraft,\nJesus, die selbst die Blinden sehend macht.\nDer Name Jesus ist erfüllt von Herrlichkeit,\nJesus, Gott von Ewigkeit.\r\nJesus, in Deinem Namen liegt das Heil.\nJesus, mein Lob wird Dir allein zuteil.\nOh, Jesus, Du bist die Gerechtigkeit,\nLeben in alle Ewigkeit.\r\nJesus, mein König, der bald wiederkehrt.\nJesus, mein Herz nur Dich allein begehrt.\nDem Namen Jesus singen wir für alle Zeit.\nJesus, Herr, der Herrlichkeit.'),
(9, '1111', 'Jesus, in Dir hab\' ich Ruhe, Freud in dem, was Du mir bist   (Jesus, Jesus, ja ich ruh in dem, was Du für mich bist)', NULL, 'Jesus, in Dir hab\' ich Ruhe, Freud\' in dem, was Du mir bist;\nDeines Herzens große Liebe mir so köstlich ist.\nTeurer Jesus, auf Dich blick ich, Deine Schönheit füllt mein Herz,\nDeine Gotteskraft verwandelt, heilet allen Schmerz.\r\nJesus, Jesus, ja ich ruh\' in dem, was Du für mich bist;\nTag für Tag mir Deine Liebe größer, schöner ist.\r\nDir vertrau\' ich, mein Herr Jesus, und ich schaue himmelwärts.\nDeine reine, treue Liebe bringt zur Ruh\' mein Herz.\nDu erfüllst mein tiefes Sehnen, kennest alle meine Not;\nDu umgibst mich stets mit Segen, wahre Lieb\' aus Gott.\r\nImmer lass Dein Antlitz leuchten, wenn ich wirke, vor Dir steh\'.\nBleibt Dein Lächeln mir, Herr Jesus, muss die Nacht vergeh\'n.\nLicht von meines Vaters Klarheit, Sonne Seines Angesicht\'s,\nhalte Du mich immer glaubend, betend, lass mich nicht!'),
(9, '1112', 'Jesus, Jesus, einzig Jesus, er soll unser alles sein  -  Jesus only is our Message, Jesus all our Theme shall be   (Einzig Jesus, einzig Jesus)', 'Jesus only is our message,\nJesus all our theme shall be.\nWe will lift up Jesus ever,\nJesus only will we see.\r\nJesus only, Jesus ever,\nJesus all in all we sing.\nSaviour, Sanctifier, and Healer,\nglorious Lord and coming King.\r\nJesus only is our Saviour,\nall our guilt He bore away.\nAll our righteousness He gives us,\nall our strength from day to day.\r\nJesus is our Sanctifier,\ncleansing us from self and sin.\nAnd with all His Spirit’s fullness,\nfilling all our hearts within.\r\nJesus only is our Healer,\nall our sicknesses He bare.\nAnd His risen life and fullness,\nall His members still may share.\r\nJesus only is our Power,\nHe the Gift of Pentecost.\nJesus, breathe Thy pow’r upon us,\nfill us with the Holy Ghost.\r\nAnd for Jesus we are waiting,\nlist’ning for the advent call.\nBut ’twill still be Jesus only,\nJesus ever, all in all.', 'Jesus, Jesus, einzig Jesus,\ner soll unser alles sein!\nEwig wollen wir ihn preisen,\neinzig Jesus nur allein!\r\nEinzig Jesus, einzig Jesus,\ner soll unser alles sein!\nRetter, Heiler und Befreier,\nHerr und König, er ist mein!\r\nJesus nur ist unser Retter,\nder für unsre Sünden starb.\nHeil, Gerechtigkeit und Stärke\ner uns allen dort erwarb.\r\nJesus nur ist der Befreier\nvon der Sünde und vom Ich.\nIn der Fülle seines Geistes\nschenkt er unsern Herzen sich.\r\nJesus nur ist unser Heiler,\nder für unsre Krankheit litt,\nteilt sein Auferstehungsleben\nallen seinen Dienern mit.\r\nJesus gibt des Geistes Gabe,\ndie zu Pfingsten er verheißt;\ndarum fleh\'n wir: Herr Jesus,\ntauf\' uns mit dem Heiligen Geist!\r\nUnd so warten wir auf Jesus,\nbis er kommt in Herrlichkeit.\nEr ist unser ein und alles\nhier und in der Ewigkeit.'),
(9, '1113', 'Jesus, Jesus, Jesus, da ist etwas in diesem Nam\'  -  Jesus, Jesus, Jesus, there\'s just something about that Name', 'Jesus, Jesus, Jesus,\nthere\'s just something about that Name.\nMaster, Saviour, Jesus!\nLike the fragrance afther the rain.\nJesus, Jesus, Jesus,\nlet all heaven and earth proclaim:\nKings and kingdoms will all pass away,\nbut there\'s something about that Name.', 'Jesus, Jesus, Jesus, da ist etwas in diesem Nam\'.\nMeister, Retter, Jesus!\nWie der Duft, der nach dem Regen kommt.\nJesus, Jesus, Jesus,\nruft es aus ihr Himmel und Erd\'.\nKönigreiche werden alle vergeh\'n,\ndenn da ist etwas in diesem Nam\'.'),
(9, '1114', 'Jesus, Jesus, Jesus, schönster Name mein   (3 Chorusse)', 'Jesus, Jesus, Jesus,\nsweetest name I know,\nfills my every longing,\nkeeps me singing as I go.\r\n\r\n', 'Jesus, Jesus, Jesus,\nschönster Name mein,\nstillst all mein Verlangen,\nfüllst mein Herz mit Sonnenschein.\r\nJesus, Jesus, Jesus,\nDu gibst Sieg und Ruh\',\njauchzet d\'rum mein Herze\nDir ein Halleluja zu.\r\nJesus, Jesus, Jesus,\nDu hast es vollbracht,\nhast in meinem Leben\nalles, alles neu gemacht.'),
(9, '1115', 'Jesus, mein Herr, wird immer mich lieben  -  Jesus, my Lord will love me forever   (Darum gehör\' ich Jesus, Jesus bin ich geweiht)', 'Jesus, my Lord will love me forever,\nfrom Him no pow\'r of evil can sever,\nHe gave His life to ransom my soul.\nNow I belong to Him.\r\nNow I belong to Jesus,\nJesus belongs to me,\nnot for the years of time alone,\nbut for eternity.\r\nOnce I was lost in sin\'s degradation,\nJesus came down to bring me salvation,\nlifted me up from sorrow and shame,\nNow I belong to Him.\r\nJoy floods my soul for Jesus has saved me,\nfreed me from sin that long had enslaved me,\nHis precious blood, He came to redeem,\nNow I belong to Him.', 'Jesus, mein Herr, wird immer mich lieben,\ndurch Sündennot bin ich zu Ihm getrieben,\nEr gab Sein Blut und kaufte mich los:\nDarum gehör\' ich Ihm!\r\nDarum gehör\' ich Jesus,\nJesus bin ich geweiht,\nnicht für die Erdenzeit allein,\nauch für die Ewigkeit.\r\nEinst lag ich tief in Sünde gebunden,\nJesus hat Heil und Erlösung gefunden,\nhob mich empor von Schande und Not:\nDarum gehör\' ich Ihm!\r\nJubelnde Freude füllt nun mein Leben,\nJesus hat Sieg und Kraft mir gegeben.\nSein kostbar Blut befreite mich ganz:\nDarum gehör\' ich Ihm!'),
(9, '1116', 'Jesus, mein König, führe mich den Weg nach Golgatha  -  King of my Life, I crown Thee now, Thine shall the Glory be', 'King of my life, I crown Thee now, Thine shall the glory be;\nLest I forget Thy thorn-crowned brow, lead me to Calvary.\nLest I forget Gethsemane, lest I forget Thine agony;\nLest I forget Thy love for me, lead me to Calvary.\r\nLet me like Mary, through the gloom, come with a gift to Thee;\nShow to me now the empty tomb, lead me to Calvary.\nLest I forget Gethsemane, lest I forget Thine agony;\nLest I forget Thy love for me, lead me to Calvary.', 'Jesus, mein König, führe mich den Weg nach Golgatha,\ndenn dort am Kreuze seh‘ ich Dich und was für mich geschah.\nDamit ich es erkennen kann, was Du, oh Herr, für mich getan,\nwas dort am Kreuz für mich geschah, füh\'r mich nach Golgatha.\r\nFüh\'r wie Maria mich zum Grab, lass mich den Morgen seh’n,\nwo ich nach Kreuz und Grab und Tod seh‘ Jesus aufersteh’n.\nDamit ich es erkennen kann, was Du, oh Herr, für mich getan,\nwas dort am Kreuz für mich geschah, füh\'r mich nach Golgatha.'),
(9, '1117', 'Jesus, meine Freude, meines Herzens Weide', NULL, 'Jesus, meine Freude, meines Herzens Weide,\nJesus, meine Zier!\nAch, wie lang, ach lange, ist dem Herzen bange\nund verlangt nach Dir!\nGotteslamm, mein Bräutigam, außer Dir soll mir auf Erden\nnichts sonst lieber werden.\r\nUnter Deinem Schirmen bin ich vor den Stürmen\naller Feinde frei.\nLass den Satan wittern, lass die Welt erschüttern:\nMir steht Jesus bei!\nOb es jetzt gleich kracht und blitzt, ob gleich Sünd\' und Hölle schrecken:\nJesus will mich decken.\r\nTrotz dem alten Drachen, Trotz dem Todesrachen,\nTrotz der Furcht dazu!\nTobe, Welt, und springe, ich steh hier und singe\nin gar sich\'rer Ruh\'.\nGottes Macht hält mich in acht, Erd\' und Abgrund müssen schweigen\nund vor Ihm sich neigen.\r\nWeg mit allen Schätzen! Du bist mein Ergötzen,\nJesus, meine Lust!\nWeg, ihr eitlen Ehren, ich mag euch nicht hören,\nbleibt mir unbewusst!\nElend, Not, Kreuz, Schmach und Tod soll mich, ob ich viel muss leiden,\nnicht von Jesus scheiden!\r\nWeicht, ihr Trauergeister, denn mein Freudenmeister,\nJesus, tritt herein.\nDenen, die Gott lieben, muss auch ihr Betrüben\nlauter Wonne sein.\nDuld\' ich schon hier Spott und Hohn,\ndennoch bleibst Du auch im Leide,\nJesus, meine Freude.'),
(9, '1118', 'Jesus, meiner Seele Freund, bleib, o bleib mir stets vereint', NULL, 'Jesus, meiner Seele Freund, bleib, o bleib mir stets vereint!\nIn Dir ruht mein Heil allein, sollst mir ewig alles sein!\nDass mein Herz Dich nie verlässt, halt es, Jesus, ewig fest,\ndass mein Herz Dich nie verlässt, halt es, Jesus, ewig fest!\r\nJesus, heller Morgenstern, Gotteslicht, sei mir nicht fern!\nDunkel ist\'s wo Du nicht bist, in Dir alle Klarheit ist!\nDass ich bleib auf rechter Bahn, führ\' mich, Heiland, himmelan,\ndass ich bleib auf rechter Bahn, führ\' mich, Heiland, himmelan!\r\nJesus, bleibe Du mein Hirt\', der sein Schäflein treulich führt,\nmich mit Lebenswasser tränkt, und mir Seinen Beistand schenkt.\nIn der Wüste, wie auf Au\'n, lass auf Deine Spur mich schau\'n,\nin der Wüste, wie auf Au\'n, lass auf Deine Spur mich schau\'n!\r\nJesus, großer Meister Du, das sei meine süße Ruh\',\ndass ich völlig Dir geweiht, treu Dir diene in der Zeit,\nbis ich darf im sel\'gen Licht schauen Dich von Angesicht,\nbis ich darf im sel\'gen Licht schauen Dich von Angesicht!'),
(9, '1119', 'Jesus, teurer Jesus  -  Jesus, all for Jesus', 'Jesus all for Jesus\nAll I am and have and ever hope to be\nJesus all for Jesus\nAll I am and have and ever hope to be\r\nAll of my ambitions hopes and plans,\nI surrender these into Your hands.\nAll of my ambitions hopes and plans,\nI surrender these into Your hands.\r\nFor it`s only in Your will that I am free.\nFor it`s only in Your will that I am free.\nJesus all for Jesus,\nAll I am and have and ever hope to be.', 'Jesus, teurer Jesus,\nalles was ich bin, bin ich durch dich.\nJesus, teurer Jesus,\nalles was ich bin, bin ich durch dich.\r\nAll mein Streben, Hoffen, Denken,\nsoll in deinem Will\'n stets erfunden sein.\nWas auch immer ich ersehne,\nes soll jederzeit Dir zur Ehre sein.\r\nWenn ich dich nur hab,\nwas brauch ich mehr o Herr?\nWenn ich dich nur hab,\nwas brauch ich mehr o Herr?\nJesus, teurer Jesus\nalles was ich bin, bin ich durch dich.'),
(9, '1120', 'Jesus, unser König ist der Sieger   (Chorus)', NULL, 'Jesus, unser König ist der Sieger,\nsiegt für uns mit mächtiger Hand,\nist für uns alles im Streite,\nführt uns ins himmlische Land.'),
(9, '1121', 'Jesus, von Dir will ich singen  -  O my heart sings today, sings for joy and gladness   (Wunderbar, wunderbar, Jesus ist der Herr)', 'O my heart sings today, sings for joy and gladness,\nJesus saves, satisfies, banishes my sadness.\nGuilt is gone, peace is mine, peace like to a river,\nJesus is wonderful, mighty to deliver.\r\nWonderful, wonderful, Jesus is to me,\nCounselor, Prince of Peace, Mighty God is He.\nSaving me, keeping me from all sin and shame,\nwonderful is my Redeemer, praise His name!\r\nOnce a slave, now I’m free, free from condemnation,\nJesus gives liberty and a full salvation.\nNow the sins of the past have been all forgiven,\nand my name is inscribed on the book of heaven.\r\nLiving here with my Lord in a holy union,\nday by day, all the way holding sweet communion.\nO what change grace hath wrought in my lowly station!\nSince my soul has received full and free salvation.', 'Jesus, von Dir will ich singen,\nein Herz voll Dankbarkeit bringen.\nÜberall will ich\'s erzählen,\nwas Du an mir hast getan,\nüberall will ich\'s erzählen,\nwas Du an mir hast getan.\r\nWunderbar, wunderbar, Jesus ist der Herr!\nWunderrat, starker Gott, Friedefürst ist Er.\nRettet mich, schützet mich  vor der Sünde Macht.\nWunderbar ist Jesus, der mir Sieg gebracht.\r\nIn mir war alles erkaltet,\nbis Gott mich ganz umgestaltet.\nSünde darf nicht mehr regieren,\ndenn nun ist Jesus mein Herr.\nSünde darf nicht mehr regieren,\ndenn nun ist Jesus mein Herr.\r\nFreund, dir will Jesus auch helfen,\nmöcht\' deine Hand gern\' ergreifen.\nGib Ihm doch dein ganzes Leben\nund du wirst glücklich und froh,\ngib Ihm doch dein ganzes Leben\nund du wirst glücklich und froh.'),
(9, '1122', 'Jesus, wie herrlich bist Du  -  Jesus, what a Wonder You are   (Chorus)', 'Jesus, what a wonder You are,\nYou are so gentle,\nso pure and so kind.\nYou shine like the morningstar,\nJesus what a wonder You are.', 'Jesus, wie herrlich bist Du,\nDu bist so freundlich,\nso rein und so sanft.\nDu scheinst wie der Morgenstern,\nJesus, wie herrlich bist Du!'),
(9, '1123', 'Jesus, wir erheben Dich, unser König bist Du', NULL, 'Jesus, wir erheben Dich,\nunser König bist Du.\nDu bist hier mitten unter uns;\nvoll Ehrfurcht stehen wir vor Dir.\nWir beten an vor Deinem Thron.\nWir beten an vor Deinem Thron.\nWir beten an vor Deinem Thron.\nKönig Jesus, die Herrschaft ist Dein.'),
(9, '1124', 'Jesus, wir sehen auf Dich. Deine Liebe, die will uns verändern', NULL, 'Jesus, wir sehen auf Dich.\nDeine Liebe, die will uns verändern,\nund in uns spiegelt sich Deine Herrlichkeit.\nJesus, wir sehen auf Dich.\r\nJesus, wir hören auf Dich.\nDu hast Worte des ewigen Lebens,\nund wir haben erkannt: Du bist Christus.\nJesus, wir hören auf Dich.\r\nJesus, wir warten auf Dich.\nDu wirst kommen nach Deiner Verheißung.\nAlle Menschen, sie werden Dich sehen.\nJesus, wir warten auf Dich.'),
(9, '1125', 'Jetzt ist der Heilge Geist uns nah   (Chorus)', NULL, 'Jetzt ist der Heil\'ge Geist uns nah,\nGott sandte Ihn, Halleluja!\nGnadenregen fallen\nauf die ausgestreute Saat.\nSpätregen Gott verheißen hat.'),
(9, '1126', 'Jetzt wo Dich Jesus locket, komm, Sünder, komm  -  While Jesus whispers to you, come, Sinner, come', 'While Jesus whispers to you,\ncome, sinner, come!\nWhile we are praying for you,\ncome, sinner come!\nNow is the time to own Him,\ncome, sinner, come!\nNow is the time to know Him,\ncome, sinner come!\r\nAre you too, heavy laden?\nCome, sinner, come!\nJesus will bear your burden,\ncome, sinner come!\nJesus will not deceive you,\ncome, sinner, come!\nJesus will now receive you,\ncome, sinner come!\r\nOh, hear His tender pleading,\ncome, sinner, come!\nCome and receive the blessing,\ncome, sinner come!\nWhile Jesus whispers to you,\ncome, sinner, come!\nWhile we are praying for you,\ncome, sinner come!', 'Jetzt, wo Dich Jesus locket,\nkomm, Sünder, komm!\nJetzt, wo wir für dich beten,\nkomm, Sünder, komm!\nJetzt musst du dich bekehren,\nkomm, Sünder, komm!\nJetzt gilt\'s, Ihn anzunehmen,\nkomm, Sünder, komm!\r\nBist du gar schwer beladen,\nkomm, Sünder, komm!\nJesus will deine Last\'n tragen,\nkomm, Sünder, komm!\nJesus allein kann helfen,\nkomm, Sünder, komm!\nSag Ihm nur deine Sünden,\nkomm, Sünder, komm!\r\nO hör Sein sanftes Rufen,\nkomm, Sünder, komm!\nKomm und nimm hin den Segen,\nkomm, Sünder, komm!\nJetzt, wo dich Freunde mahnen,\nkomm, Sünder, komm!\nJetzt, wo der Geist noch ziehet,\nkomm, Sünder, komm!'),
(9, '1127', 'Jetzt, o Vater, segne mich  -  Heav’nly Father, bless me now', 'Heav’nly Father, bless me now,\nat the cross of Christ I bow.\nTake my guilt and grief away,\nhear and heal me now, I pray.\nBless me now, bless me now,\nheav\'nly Father, bless me now.\r\nNow, O Lord! this very hour,\nsend Thy grace and show Thy power.\nWhile I rest upon Thy Word,\ncome, and bless me now, o Lord!\nBless me now, bless me now,\nheav\'nly Father, bless me now.\r\nNow, Jesus now, for Jesus\' sake,\nlift the clouds, and fetters break.\nWhile I look, and as I cry,\ntouch and cleanse me ere I die.\nBless me now, bless me now,\nheav\'nly Father, bless me now.\r\nNever did I so adore\nJesus Christ, Thy Son, before!\nNow the time! and the place!\nGracious Father, show Thy grace.\nBless me now, bless me now,\nheav\'nly Father, bless me now.', 'Jetzt, o Vater, segne mich!\nJesu Kreuz umschlinge ich.\nNimm hinweg all meine Schuld,\nheile mich in Deiner Huld!\nSegne mich, segne mich!\nJetzt, o Vater, segne mich!\r\nJetzt ist\'s angenehme Zeit!\nAlles, alles ist bereit!\nHerr, ich traue auf Dein Wort,\nsegne mich, Du treuer Hort!\nSegne mich, segne mich!\nJetzt, o Vater, segne mich!\r\nJetzt, um Christi willen, jetzt,\nda Dein Tisch mir ist gesetzt,\ngib mir Lebensbrot und Wein,\nmache mich von Sünden rein!\nSegne mich, segne mich!\nJetzt, o Vater, segne mich!\r\nNiemals habe ich so angebetet\nJesus Christus, Deinen Sohn, so sehr angebetet!\nJetzt ist die Zeit! und der Ort!\nGnädiger Vater, zeige Deine Gnade.\nSegne mich jetzt, segne mich jetzt,\nHimmlischer Vater, segne mich jetzt.'),
(9, '1128', 'Jetzt, wo noch im Jugendlenze alles uns umher erfreut   (Für die Sache unsers Meisters lasst uns wirken früh und spät)', NULL, 'Jetzt, wo noch im Jugendlenze\nalles uns umher erfreut,\nlasst ein jedes Herze sein,\ndem Dienst des Herrn geweiht.\r\nFür die Sache unser\'s Meisters\nlasst uns wirken früh und spät,\ndass nicht eh das Werk vollendet,\nunsere Sonne untergeht!\r\nLieben wir den Namen Jesus,\nlasst\'s uns zeigen durch die Tat;\nlasst uns wohltun und mitteilen\nund so folgen Seinen Rat!\r\nSchmerzen lindern, Seelen retten,\nZeit und Kraft dem Herren weih\'n,\ndas lasst ernstlich uns versuchen,\nsind wir auch noch schwach und klein!'),
(9, '1129', 'Jezus ik hou U', 'Jezus, ik hou van U,\n\'k Heb U lief Heer boven alle dingen.\nAl wat in mij is verlangt te zingen\nJezus, ik hou van U.', NULL),
(9, '1130', 'Jezus overwinnaar', 'Waar U verschijnt wordt alles nieuw\nWant U bevrijdt en geeft leven\nElke storm verstilt door de klank van uw stem\nAlles buigt voor Koning Jezus\r\n\r\nVoor eeuwig is Uw heerschappij\nUw troon staat onwankelbaar\nOngeëvenaarde kracht ligt in Uw grote naam\nJezus overwinnaar\r\nDe duisternis licht op door U\nDe duivel is door U verslagen\nDood waar is je macht\nWaar is je prikkel gebleven\nJezus leeft en ik zal leven\r\n\r\nNaam boven alle namen\nNaam boven alle namen\nNaam boven alle namen\nNaam boven alle namen\r\nKing of kings\nYou will reign on high\nForever and glorious\nNothing can withstand the power\nOf Your mighty name\nJesus, victorious', 'Wo Du erscheinst, wird alles neu\nDenn Du befreist und gibst Leben\nJeder Sturm wird durch den Klang Deiner Stimme zum Schweigen gebracht\nAlles verneigt sich vor König Jesus\r\nU bent de held die voor ons strijdt\nU baant de weg van overwinning\nElke vijand vlucht ieder bolwerk valt neer\nNaam boven alle namen hoogste Heer\nDu bist der Held, der für uns kämpft\nDu ebnest den Weg zum Sieg\nJeder Feind flieht, jede Festung fällt\nName über allen Namen höchster Herr\r\nEwig ist Deine Herrschaft\nDein Thron steht unerschütterlich\nUnerreichte Macht liegt in Deinem großen Namen\nJesus Sieger\r\n(Die Dunkelheit wird durch Dich erhellt\nDer Teufel wird durch Dich besiegt\nTod, wo ist deine Macht\nWo ist dein Sporn\nJesus lebt und ich werde leben)\r\nDe schepping knielt in diepst ontzag\nDe hemel juicht voor onze Koning\nEn de machten van de hel weten Wie er regeert\nNaam boven alle namen hoogste Heer\nDie Schöpfung kniet in tiefster Ehrfurcht\nDer Himmel jubelt über unseren König\nUnd die Mächte der Hölle wissen, wer regiert\nName über alle Namen höchster Herr\r\nDer Name über allen Namen\nName über allen Namen\nName über allen Namen\nName über allen Namen\r\nIn Ewigkeit bist du König, Herr\nDein Name wird niemals vergeh\'n.\nNichts kann widerstehen, Herr,\nder Macht in deinem Nam\'.\nJesus Überwinder.'),
(9, '1131', 'Johannes war im Geiste  -  John was in the Spirit   (In Ewigkeit, in Ewigkeit)', 'John was in the Spirit,\non the Lord\'s day.\nHe heard a voice from heaven,\nand this is what it said:\n"I\'m the Alpha and Omega\nThe beginning and the end;\nBehold I live forevermore."\r\nBehold I live, behold I live,\nBehold I live forevermore,\nBehold I live, behold I live,\nBehold I live forevermore.\r\nAmong the seven candle sticks,\nI saw the risen Lord.\nHis eyes were as a flame of fire,\nfrom his mouth a sword.\nAs the voice of many waters,\nsounded forth the living Word:\n"Behold, I live for ever more."', 'Johannes war im Geiste,\nwo er den König sah.\nEr fiel dem Herrn zu Füßen\nund hörte, was Er sprach:\n"Ich bin Alpha und Omega,\nder Anfang und das End\',\nund sieh\', ich leb\' in Ewigkeit."\r\nIn Ewigkeit, in Ewigkeit,\nund sieh\', ich leb\' in Ewigkeit.\nIn Ewigkeit, in Ewigkeit,\nund sieh\', ich leb\' in Ewigkeit.\r\nJohannes war im Geiste\nund schaute Jesus an,\nder hatte eine Botschaft\nfür jeden, der da kam,\nund auch du kannst sie heut\' hören,\nkommst du erst in den Geist:\n"Ja, sieh\', ich leb\' in Ewigkeit."'),
(9, '1132', 'John tells of a City, that he saw coming down   (I can almost see the Lights of that City)', 'John tells of a city,\nThat he saw coming down,\nWhere no sorrow or death will be known,\nThat someday we could go there\nThrough His marvelous grace,\nForever live in that heavenly home.\r\nI can almost see the lights of that city,\nI see them gathering, all around\nThe great white throne;\nWith faith in my Saviour,\nAnd His wonderful love,\nOh, I can almost see the lights of home.\r\nAnd sometimes when I\'m burdened,\nAnd my cross seems hard to bear.\nAnd old Satan, he tries to dim my view,\nWell I just look unto Jesus,\nHe is standing close by,\nThen once again,\nHis great light shines through.', NULL),
(9, '1133', 'Joy to the World the Lord is come, let Earth receive her King', 'Joy to the world the Lord is come, let earth receive her King.\nLet every heart prepare Him room, and heaven and nature sing,\nand heaven and nature sing.\nAnd heaven,\nand heaven and nature sing.\r\nJoy to the world! the Saviour reigns, let men their songs employ.\nWhile fields and floods, rocks, hills and plains, repeat the sounding joy.\nRepeat the sounding joy,\nrepeat, repeat the sounding joy.\r\nNo more let sins and sorrows grow, nor thorns infest the ground.\nHe comes to make His blessings flow far as the curse is found.\nFar as the curse is found,\nfar as, far as the curse is found.\r\nHe rules the world with truth and grace, and makes the nations prove.\nThe glories of His righteousness, and wonders of His love.\nAnd wonders of His love,\nand wonders, and wonders of His love.', NULL),
(9, '1134', 'Just any Day now our Lord is coming   (Chorus)', 'Just any day now our Lord is coming,\nHe\'ll be returning, for you and me.\nOh I\'ve been watching,\nand I\'ve been waiting.\nJust any day now, His face I\'ll see.', NULL),
(9, '1135', 'Just beyond the Jordan I see a Land   (Chorus)', 'Just beyond the Jordan I see a land,\na land not far from here on the golden strand.\nI have caught a climbs of my perfect body,\nmy theophany is calling me soon I\'ll be free.', NULL),
(9, '1136', 'Just give me Jesus and I′ll be all right', 'Just give me Jesus and I′ll be all right\nWith him I can make it walking beside\nI know my tomorrows are safe in his hand\nJust give me Jesus I know I can stand.\r\nSo many distractions seem to cloud my way\nAll the cares of life surrounding\ncan lead my heart astray\nWhen I cannot find the answers\nI know someone who can\nSo in the middle of my questions\nI reach for his hand\r\nWhen I take my eyes off Jesus\nAnd cofusion starts to win\nWhen my worries overwhelm me\nAnd the battle reaches in\nIn that moment I remember\nI know whose I am\nAnd when the enemy comes rushing\nI reach for his hand\r\nWe are servants of the king\nAnd our future is secure\nA crown of life is waiting\nFor all who will endure\nWhen I stand before my savior\nAnd he reaches out to me\nI\'ll lay all my crowns before him\nAnd fall to my knees and cry\r\nJesus, Jesus, how I trust him\nHow I\'ve proved him O′er and O\'er\nJesus, Jesus, precious Jesus\nO for grace to trust him more\nO for grace to trust him more', 'Gib mir einfach Jesus und ich werde in Ordnung sein\nMit ihm kann ich es schaffen, an seiner Seite zu gehen\nIch weiß, dass meine Zukunft sicher in seiner Hand ist\nGib mir Jesus und ich weiß, dass ich stehen kann.\r\nSo viele Ablenkungen scheinen meinen Weg zu trüben\nAll die Sorgen, die das Leben umgibt\nkönnen mein Herz in die Irre führen\nWenn ich die Antworten nicht finden kann\nkenne ich jemanden, der es kann\nSo in der Mitte meiner Fragen\ngreife ich nach seiner Hand\r\nWenn ich meine Augen von Jesus abwende\nUnd die Verwirrung beginnt zu siegen\nWenn meine Sorgen mich überwältigen\nUnd der Kampf mich erreicht\nIn diesem Moment erinnere ich mich\nIch weiß, wer ich bin\nUnd wenn der Feind kommt und stürmt\ngreife ich nach seiner Hand\r\nWir sind Diener des Königs\nUnd unsere Zukunft ist sicher\nEine Krone des Lebens wartet\nFür alle, die ausharren werden\nWenn ich vor meinem Retter stehe\nUnd er mir die Hand reicht\nlege ich alle meine Kronen vor ihm ab\nUnd auf meine Knie fallen und weinen\r\n(Jesus, Jesus, wie sehr ich Ihm vertraue!\nWie ich Ihn wieder und wieder bewiesen habe1\nJesus, Jesus, teurer Jesus!\nOh, Ihm um der Gnade willen mehr zu vertrauen!\nOh, Ihm um der Gnade willen mehr zu vertrauen!)'),
(9, '1137', 'Just suppose God searched through Heaven   (Had it not been for a Place called Mount Calvary)', 'Just suppose God searched through Heaven\nHe couldn\'t find one willing to be.\nThe supreme Sacrifice that was needed\nthat could buy Eternal Life for you and me.\r\nHad it not been for a place called mount Calvary.\nHad it not been for the old rugged cross.\nHad it not been for a man called Jesus.\nThen forever my soul would be lost.\r\nAnd I am glad He was willing to drink that bitter cup.\nEven though He prayed "Father let it pass from me."\nAnd I\'m so glad He never called Heavens Angels,\n"From my hands - pull the nails that torment me."', NULL),
(9, '1138', 'Just to be His Hand extended   (Chorus)', 'Just to be His hand extended\nreaching out to the oppressed.\nLet me touch Him, let me touch Jesus.\nSo that others may know and be blessed.', NULL),
(9, '1139', 'Justified, justified, you have not done it in the first place, justified.  (Chorus)', 'Justified, justified,\nYou have not done it\nin the first place, you\'re justified. (2x)\r\nI was sitting alone and wondering\nAbout what I’m supposed to do,\nI can’t deny the times I’ve made mistakes,\nI can’t hide from Him, He knew;\nBut I knew that deep within my soul\nI felt sorry, honest I do,\nSo I just cried and said, “Forgive me Lord,\nForgive me again, will you.”\r\nSo often I’m discouraged\nWhen I count the times I fall,\n‘Cause he promised I’d be victorious\nWhen I know I’m not at all;\nThen I heard an eagle scream,\nIts voice quickened my soul,\nHe said, “you’ve not done it in the first place, you’re justified.”\r\nHe looked at your perfect picture without blame, spot or wrinkle,\nHe didn’t look at you where you are now,\nHe looked from eternity,\nHe said you’re just trapped in that body,\nYou bypassed your theophany;\nYou have not done it in the first place, you’re justified.', '(Gerechtfertigt, gerechtfertigt,\nDu hast es nicht getan\nvon vornherein gerechtfertigt. )\r\nIch saß allein und fragte mich\nWas ich eigentlich tun soll,\nIch kann die Zeiten nicht leugnen, in denen ich Fehler gemacht habe, Ich kann mich nicht vor ihm verstecken, er wusste es;\nAber ich wusste, dass ich tief in meiner Seele\nIch fühlte mich traurig, ehrlich ich tue,\nAlso weinte ich einfach und sagte: "Vergib mir, Herr,\nVergib mir noch einmal, ja?"\r\nSo oft bin ich entmutigt\nWenn ich zähle, wie oft ich falle,\nDenn er versprach, ich würde siegreich sein\nobwohl ich weiß, dass ich es nicht bin;\nDann hörte ich den Schrei eines Adlers,\nSeine Stimme belebte meine Seele,\nEr sagte: "Du hast es gar nicht erst getan, du bist gerechtfertigt."\r\nEr betrachtete dein perfektes Bild ohne Tadel, Flecken oder Falten,Er sah dich nicht von dort aus an, wo du jetzt bist,\nEr schaute von der Ewigkeit her,\nEr sagte, du bist nur in diesem Körper gefangen,\nDu hast deine Theophanie umgangen;\nDu hast es gar nicht erst getan, du bist gerechtfertigt.'),
(9, '1140', 'Kann nimmermehr dich lassen, mein teures Bibelbuch  -  I’ll not give up the Bible, that precious Book divine   (Nimmermehr, nimmermehr lass ich von meiner Bibel)', 'I’ll not give up the Bible,\nthat precious book divine.\nFor glory gilds its pages,\nand truth adorns each line.\r\nI’ll never give up that holy book,\nI’ll never give up the Bible.\nI’ll never give up that holy book,\nthat precious book divine.\r\nWhen fate’s wild storms o’ercloud me,\nand loud the billows roar.\nMy chart shall be the Bible,\nto guide to Heav’n’s bright shore.\r\nThough foes may fight against me,\nand enemies combine.\nIts precepts still shall guide me,\nas light from Heav’n they shine.\r\n\r\n', 'Kann nimmermehr dich lassen,\nmein teures Bibelbuch,\nIch fand darin den Heiland,\nder meine Sünden trug.\r\nNimmermehr, nimmermehr\nlass ich von meiner Bibel.\nNimmermehr, nimmermehr\nlass ich mein Bibelbuch.\r\nIn Trübsal und Verfolgung,\nin Kummer, Leid und Schmerz.\nQuillt nur aus meiner Bibel,\nmir Trost ins wunde Herz.\r\nZielt mit dem gift’gen Pfeilen\nauf mich der Seelenfeind,\ngreif ich zu meiner Bibel,\nund Kreuzeslicht mir scheint.\r\nMuss bis aufs Blut ich ringen\nheiß in Gethsemane,\nso bringt mir meine Bibel\ndes Heilands Friedensnäh.\r\nD\'rum kann ich dich nicht lassen,\ngeliebtes Bibelbuch,\ndein Reichtum schenkt mir alles,\nwas immer ich auch such!'),
(9, '1141', 'Kannst du sehen, wie dein König mitten in der Gemeinde steht  -  Can you see Him as He stands therein the midst of the golden Lamps   (Würdig ist das Lamm)', 'Can you see Him as He stands there\nin the midst of the golden lamps?\nCan you see Him as He stands there\nwith the stars in His right hand?\r\nWorthy is the Lamb, worthy is the Lamb,\nsee Him as He stands  full of Power and Glory.\nWorthy is the Lamb, worthy is the Lamb.\nTake a look at Him, He\'s is ev\'rything!\r\nHe\'s the Alpha, the Omega,\nthe Betginning and the End,\nHe\'s the High King, He\'s the Eagle,\nHe\'s the Lion and the Lamb!\r\nHe\'s the Father, Son and Holy Ghost,\nHe Which was, is, and is to come,\nthe Almighty, Supreme Deity,\nmy Lord Jesus the All in All.', 'Kannst du sehen, wie dein König\nmitten in der Gemeinde steht,\nsieben Sterne, sieben Leuchter,\nderen Licht nur von Ihm ausgeht?\r\nWürdig ist das Lamm, würdig ist das Lamm,\nHerr, ich schau Dich an voller Macht und Herrlichkeit.\nWürdig ist das Lamm, würdig das Lamm.\nJesus, Gott und Herr, alles bist du mir.\r\nEr ist Alpha und Omega,\nEr, derselbe von Anfang an,\nHöchster König, großer Adler,\nEr, der Löwe und das Lamm!\r\nEr, der Vater, Sohn und Heil\'ger Geist,\nEr, der war und kommt und ist,\nder Allmächtige, Er, der Ewige,\ndu mein Alles Herr Jesus Christ.'),
(9, '1142', 'Keep your Mind stayed on Me   (Chorus)', 'Keep your mind stayed on Me,\nstayed on Me, faithfully.\nAnd I will give you perfect peace, sweet release,\nif you just keep your mind stayed on Me.', 'Halte deinen Sinn auf Mich gerichtet,\nbleibe auf Mich gerichtet, treu.\nUnd Ich werde dir vollkommenen Frieden geben, süße Befreiung,\nwenn du nur in deinem Sinn auf Mich gerichtet bleibst.'),
(9, '1143', 'Keiner ist wie Du  -  There is none like You', 'There is none like You,\nno one else can touch my heart like You do.\nI can search for all eternity long and find:\nThere is none like You.\r\nYour mercy flows like a river wide,\nand healing comes from Your hands.\nSuffering children are safe in Your arms.\nThere is none like You.\r\nI could search for all eternity long.\nThere is none like You.', 'Keiner ist wie Du!\nNiemand sonst berührt mein Herz so wie Du.\nWo auch immer ich noch suchte, o Herr, es bleibt:\nKeiner ist wie Du!\r\nErbarmen fließt wie ein weiter Strom,\nund Heilung strömt aus Deiner Hand.\nLeidende Kinder sind sicher bei Dir.\nKeiner ist wie Du!\r\nWo auch immer ich noch suchte, o Herr, es bleibt:\nKeiner ist wie Du!'),
(9, '1144', 'Keiner wird zuschanden, welcher Gottes harrt', NULL, 'Keiner wird zuschanden, welcher Gottes harrt;\nsollt ich sein der Erste, der zuschanden ward?\nNein, das ist unmöglich, Du getreuer Hort!\nEher fällt der Himmel, eh mich täuscht Dein Wort.\r\nDu hast zugesaget: wer da bittet, nimmt,\nwer da sucht, soll finden, was ihm Gott bestimmt;\nwer im festen Glauben mutig klopfet an,\ndem wird ohne Zweifel endlich aufgetan.\r\nNun so will ich\'s wagen, Herr, auf Dein Gebot,\nalle meine Sorgen, eign\' und fremde Not,\nall mein heimlich Grämen, alles, was mich quält,\nDir ans Herz zu legen, der die Tränen zählt.\r\nDu bist mein Erbarmer und mein bester Freund,\nmeines Lebens Sonne, die mir lacht und scheint,\nauch in finster\'n Nächten und durchs Todestal\nmir hinüberleuchtet zu des Lammes Mahl.'),
(9, '1145', 'Keiner, keiner ist wie Er   (Chorus)', NULL, 'Keiner, keiner ist wie Er,\ndenn in allem hilft der Herr!\nEr war versucht so wie wir,\ndoch immer siegte Er.'),
(9, '1146', 'Kennst du das Evangelium, wie Gott es selbst gesagt', NULL, 'Kennst du das Evangelium, wie Gott es selbst gesagt\nzu Seiner freien Gnade Ruhm in jener finster\'n Nacht?\nDie Feinde, die ihr heute seht, erblickt ihr nimmermehr,\nwenn ihr im Glauben vorwärts geht, hinein ins Rote Meer.\r\nIhr streitet nicht in dieser Nacht; das tut der Herr allein!\nEs hat das Lamm euch durchgebracht; ihr werdet stille sein.\nErschreckt nicht vor Ägyptens Macht und seinem ganzen Heer!\nEs findet, wenn der Morgen tagt, sein Grab im Roten Meer.\r\nSiehst du das Evangelium in diesem Wort so klar,\ndann bleibt dein Mund nicht länger stumm, er jauchzet immerdar.\nDer ganzen Hölle finst\'re Macht, der Sünden zahllos Heer,\ndie mir so viele Not gebracht, ertrank im Roten Meer.\r\nIch hab es freilich längst geseh\'n; doch durch des Teufels List\nließ ich den Trost mir stets entgeh\'n, weil es so einfach ist.\nDie Feinde, die ihr heute seht, erblicket ihr nicht mehr,\nnur wenn ihr gläubig vorwärts geht hinein ins Rote Meer.\r\nNun ist es endlich doch gescheh\'n in einer dunklen Nacht.\nIch ließ die „Wenn und Aber" geh\'n und hab es frisch gewagt.\nDie Feinde, die ich gestern sah, erblick\' ich nun nicht mehr.\nEs steht das Kreuz auf Golgatha: Ich fand das Rote Meer.'),
(9, '1147', 'Kennst du schon das Land voller Sonnenschein   (Komm, o komm zu dem, der mit Feuer tauft)', NULL, 'Kennst du schon das Land voller Sonnenschein,\nwo wie Ströme fließet der Friede dein,\nwo dir Glaubensmut strömt ins Herz hinein\nund des Heiligen Geistes Kraft?\r\nKomm, o komm zu dem, der mit Feuer tauft,\nzur Freiheit dich einst mit Blut erkauft!\nJesus will dich taufen mit Heil\'gem Geist,\nmit des Heiligen Geistes Kraft.\r\nGib dich ganz Ihm hin! Sieh, Er wirbt um dich.\nLass in Seinem Grab ruh\'n dein altes Ich.\nAuferstehungskraft strömt für dich und mich\nin dem Lande, das uns bereit.\r\nSieh, es winkt und strahlt, \'s ist dein Heimatland,\nwo du selig wandelst an Jesu Hand.\nDich zu segnen nur, ist Sein Herz entbrannt,\ndich zu taufen mit Seinem Geist.\r\nO, mein König, höre, o lass mich ein!\nMeine Sehnsucht ist, völlig gleich Dir sein,\nin Dein Bild verklärt, in das Wesen Dein,\nüberströmend mit Geist getauft!\r\nDarum taufe mich mit des Geistes Glut,\nmit Liebesmacht und mit Glaubensmut!\nWie zu Pfingsten taufe uns alle heut\'\nmit des Heiligen Geistes Kraft.'),
(9, '1148', 'Kennst du wohl den Brunnen der rinnt von dem Kreuze  -  Blessed be the Fountain of Blood   (Weißer denn der Schnee)', 'Blessed be the fountain of blood,\nto a world of sinners revealed.\nBlessed be the dear Son of God.\nOnly by His stripes we are healed.\nThough I\'ve wandered far from His fold,\nbringing to my heart pain and woe,\nwash me in the blood of the Lamb,\nand I shall be whiter than snow.\r\nWhiter than the snow,\nwhiter than the snow.\nWash me in the blood of the Lamb,\nand I shall be whiter than snow.\r\nThorny was the crown that He wore,\nand the cross His body o’ercame.\nGrievous were the sorrows He bore,\nbut He suffered thus not in vain.\nMay I to that Fountain be led,\nmade to cleanse my sins here below.\nWash me in the blood that He shed,\nand I shall be whiter than snow.\r\nFather, I have wandered from Thee,\noften has my heart gone astray.\nCrimson do my sins seem to me -\nwater cannot wash them away.\nJesus, to the Fountain of Thine,\nleaning on Thy promise, I go.\nCleanse me by Thy washing divine,\nand I shall be whiter than snow.', 'Kennst du wohl den Brunnen,\nder rinnt von dem Kreuze, wo Jesus starb?\nKennst du wohl das Lamm,\ndas gesühnt uns\'re Schuld und Heil uns erwarb?\nIst die Schuld wie Purpur so rot;\nhäuft sich gleich wie Berge das Weh;\nmächtig ist der Helfer in Not,\nSein Blut macht mich weißer denn Schnee.\r\nWeißer denn der Schnee,\nweißer denn der Schnee;\nmächtig ist der Helfer in Not,\nSein Blut macht uns weißer denn Schnee.\r\nBitter war am Kreuze Sein Schmerz,\nblut\'ge Dornen flocht man zur Kron\'.\nEinsam litt Sein liebendes Herz,\nnicht umsonst starb so Gottes Sohn.\nLass zu diesem Brunnen mich flieh\'n;\ndort allein die Rettung ich seh\';\nnimmer hilft mein eigen\' Bemüh\'n,\nSein Blut macht mich weißer denn Schnee.\r\nVon der Hürde fern und verirrt,\nsucht mein banges Herz längst nach Ruh\'.\nHole Du mich heim, oh mein Hirt\',\nmeiner Seele Friede bist Du!\nNur auf Deine Wunden ich schau;\ngläubig hier am Kreuze ich steh;\nnur auf Deine Gnade ich trau;\nDein Blut macht mich weißer denn Schnee.'),
(9, '1149', 'Kind Gottes, harre still und fein, wie dunkel auch dein Pfad  -  O child of God, wait patiently when dark thy Path may be', 'O child of God, wait patiently when dark thy path may be,\nand let thy faith lean trustingly on Him who cares for Thee.\nAnd though the clouds hang drearily upon the brow of night,\nyet in the morning joy will come, and fill thy soul with light.\r\nO child of God, He loveth thee, and thou art all His own,\nwith gentle hand He leadeth thee, thou dost not walk alone.\nAnd though thou watchest wearily the long and stormy night,\nyet in the morning joy will come, and fill thy soul with light.\r\nO child of God, how peacefully He calms thy fears to rest,\nand draws thee upward tenderly, where dwell the pure and blest.\nAnd He who bendeth silently above the gloom of night,\nwill take thee home where endless joy shall fill thy soul with light.', 'Kind Gottes, harre still und fein, wie dunkel auch dein Pfad,\nund lass es dem befohlen sein, der immer Wege hat.\nUnd ziehen dunkle Wetter auf und Wolken schwarz und dicht,\nfolg\' du nur ruhig deinem Lauf, am Morgen wird\'s doch Licht!\r\nKind Gottes, gib dich furchtlos hin, Sein Arm dich fest umschließt!\nDu darfst nun kindlich trau\'n auf Ihn, weil du Sein Eigen bist.\nUnd währt die Nacht auch noch so lang, Kind Gottes, zage nicht!\nHarr\' aus, trau Ihm und sei nicht bang: Am Morgen wird\'s doch Licht!\r\nKind Gottes, bist du Ihm geweiht und willst du ganz Ihm trau\'n,\ndann gibt Er dir Sein sanft Geleit auf grünen Friedensau\'n.\nD\'rum traue still und harre sacht,  einst glänzt Sein Angesicht!\nUnd eh\' du\'s merkst, ist hin die Nacht, und dann geht auf das Licht.'),
(9, '1150', 'King of my life I crown Thee now  -  König meines Lebens ich kröne Dich jetzt   (Lest I forget Gethsemane / Damit ich Gethsemane nicht vergesse)', 'King of my life I crown Thee now,\nThine shall the glory be.\nLest I forget Thy thorn-crowned brow,\nlead me to Calvary.\r\nLest I forget Gethsemane,\nLest I forget Thine agony,\nLest I forget Thy love for me,\nLead me to Calvary.\r\nShow me the tomb where Thou wast laid,\ntenderly mourned and wept.\nAngels in robes of light arrayed,\nguarded Thee whilst Thou slept.\r\nLet me, like Mary, through the gloom\ncome with a gift to Thee.\nShow to me now the empty tomb,\nlead me to Calvary.\r\nMay I be willing, Lord, to bear,\ndaily my cross for Thee.\nEven Thy cup of grief to share,\nThou hast borne all for me.\r\nFill me, oh Lord, with Thy desire,\nfor all who know not Thee.\nThen touch my lips with holy fire,\nto speak of Calvary.', 'König meines Lebens ich kröne Dich jetzt,\nDein soll die Herrlichkeit sein.\nDamit ich Deine dornengekrönte Stirn nicht vergesse,\nführe mich nach Golgatha.\r\nDamit ich Gethsemane nicht vergesse,\ndamit ich Deine Qualen nicht vergesse,\ndamit ich Deine Liebe zu mir nicht vergesse,\nführe mich nach Golgatha.\r\nZeigt mir das Grab, in das Du gelegt wurdest,\nzärtlich getrauert und geweint.\nEngel in lichte Gewänder gekleidet,\nbewachten Dich, während Du schliefst.\r\nLass mich, wie Maria, durch die Finsternis\nmit einer Gabe zu Dir kommen.\nZeig mir jetzt das leere Grab,\nführe mich nach Golgatha.\r\nMöge ich bereit sein, Herr,\ntäglich mein Kreuz für Dich zu tragen.\nAuch Deinen Kelch des Kummers zu teilen,\nDu hast alles für mich ertragen.\r\nErfülle mich, oh Herr, mit Deinem Verlangen,\nfür alle, die Dich nicht kennen.\nDann berühre meine Lippen mit heiligem Feuer,\num von Golgatha zu sprechen.'),
(9, '1151', 'Komm aus der Höhe, komm Geist der Herrn', NULL, 'Komm aus der Höhe, komm, Geist des Herrn!\nRausche und wehe, oh, bleib nicht fern.\nRausche und wehe, oh, bleib nicht fern.\r\nGöttliches Feuer, falle herab;\nDu bist uns teuer, himmlische Gab\';\nDu bist uns teuer, himmlische Gab\'!\r\nJesus, o höre, freundlich und mild,\nkomm und verkläre uns in Dein Bild!\nKomm und verkläre uns in Dein Bild!\r\nKomm, Geist, vertreibe Sünde und Schmerz,\nwohne und bleibe in aller Herz!\nWohne und bleibe in aller Herz!\r\nFüll\' uns hienieden mit Deinem Licht!\nFüll\' uns mit Frieden, wir bitten Dich!\nFüll\' uns mit Frieden, wir bitten Dich!\r\nAlle zusammen tauf\' aus der Höh\',\ndass heil\'ge Flammen an uns zu seh\'n,\ndass heil\'ge Flammen an uns zu seh\'n.'),
(9, '1152', 'Komm doch zur Quelle des Lebens  -  Come with thy Sins to the Fountain   (Eile dahin, warum verziehn)', 'Come with thy sins to the fountain,\ncome with thy burden of grief.\nBury them deep in its waters,\nthere thou wilt find a relief.\r\nHaste thee away, why wilt thou stay?\nRisk not thy soul on a moment’s delay.\nJesus is waiting to save thee,\nmis pleading today.\r\nCome as thou art to the fountain,\nJesus is waiting for thee.\nWhat though thy sins are like crimson,\nwhite as the snow they shall be.\r\nCome and be healed at the fountain,\nlist to the peace speaking voice.\nOver a sinner returning,\nnow let the angels rejoice.', 'Komm doch zur Quelle des Lebens,\ndurstig und müde und matt.\nKomm, denn es ist nicht vergebens,\nhier wirst du ruhig und satt.\r\nEile dahin! Warum verzieh\'n?\nEw\'ger Gewinn stehet hier auf dem Spiel.\nHier ist die Quelle des Lebens,\nhier ist dein einziges Ziel.\r\nKomm zu dem Born, dich zu laben,\ntauch\' dich im Glauben hinein.\nHier wird die Sünde begraben,\nhier wirst du selig und rein.\r\nKomm zu der heilenden Quelle,\ndir wird Genesung zuteil.\nSieh, wie sie sprudelt so helle,\ntrinke zum ewigen Heil.'),
(9, '1153', 'Komm heil\'ger Geist, ich brauch Dich - Come holy ghost we need you', 'Come like a spring in the desert,\ncome to the withered of soul.\nLord, let your sweet healing power\ntouch me and make me whole.\r\nCome Holy Spirit, I need Thee,\ncome, Holy Spirit, I pray.\nCome in Thy strength and Thy power,\ncome in Thine own gentle way.\r\nCome as a rest to the weary,\ncome as a balm to the sore.\nCome Lord as strength to my weakness,\nfill me with joy evermore.', 'Komm wie ein Quell in der Wüste,\nkomm zu den Verdorrten der Seel\'.\nHerr, lass\' deine süße Heilkraft\nberühr\'n mich und mache mich wohl.\r\nKomm, Heil\'ger Geist, ich brauch\' Dich.\nKomm, Heil\'ger Geist, ist mein Gebet.\nKomm zu Deinem Worte, es wartet auf Dich.\nKomm in Fülle und Kraft.\r\nKomm als Ruhe für die Müden,\nkomm als Balsam für die Wunden.\nKomm, Herr, und stärk\' meine Schwächen,\nerfüll\' mich mit ewiger Freud\'.'),
(9, '1154', 'Komm Heilger Geist und fache du Dein Himmelsfeuer an  -  Come, Holy Spirit, heav\'nly Dove, with all Thy quickening Powers', 'Come, Holy Spirit, heav\'nly Dove,\nwith all Thy quickening powers.\nKindle a flame of sacred love\nin these cold hearts of ours.\r\nO raise our thoughts from things below,\nfrom vanities and toys.\nThen shall we with fresh courage to\nto reach eternal joys.\r\nCome, Holy Spirit, heav\'nly Dove,\nwith all Thy quickening powers.\nCome, shed abroad a Saviour\'s love,\nand that shall kindle ours.', 'Komm, Heil\'ger Geist, und fache Du\nDein Himmelsfeuer an,\ndass auf dem Herzensaltar neu\ndie Flamme lodern kann!\r\nSo leblos, Herr, so müd\' und schlaff,\no wecke du uns bald!\nDenn deine Liebe ist so warm, d\noch unsre, ach so kalt.\r\nKomm, Heil\'ger Geist, und fache Du\nDein Himmelsfeuer an,\ndenn Jesu Liebe ganz allein\nuns neu beleben kann.'),
(9, '1155', 'Komm heim, komm heim! O du irrende Seel  -  Come home! Come home! You are weary at Heart   (O, verlornes Kind, komm heim)', 'Come home! come home!\nYou are weary at heart,\nfor the way has been dark,\nand so lonely and wild.\r\nO prodigal child!\nCome home! oh come home!\nCome, oh come home!\r\nCome home! come home!\nFor we watch and we wait,\nand we stand at the gate,\nwhile the shadows are piled.\r\nCome home! come home!\nFrom the sorrow and blame,\nfrom the sin and the shame,\nand the tempter that smiled.\r\nCome home! come home!\nThere is bread and to spare,\nand a warm welcome there,\nthen, to friends reconciled.', 'Komm heim, komm heim!\nO du irrende Seel\'!\nVon dem Vaterhaus fern\nglänzt dir nirgends ein Stern.\r\nO, verlor\'nes Kind!\nKomm heim, o komm heim!\nKomm, o komm heim!\r\nKomm heim, komm heim!\nLängst schon warten wir dein.\nLass in Reue und Schmerz\nendlich brechen dein Herz!\r\nKomm heim, komm heim\naus dem schrecklichen Land,\nwo der Finsternis Macht\ndir nur Jammer gebracht!\r\nKomm heim, komm heim!\nBei dem Vater ist\'s gut.\nFreundlich winkt Er dir zu,\nbeut Vergebung und Ruh\'.'),
(9, '1156', 'Komm her du sündenmüdes Herz -  Come every Soul by Sin oppressed   (Ihm allein vertrau von Herzen)', 'Come, every soul by sin oppressed,\nthere\'s mercy with the Lord.\nAnd He will surely give you rest,\nby trusting in His Word.\r\nOnly trust Him, only trust Him,\nonly trust Him now.\nHe will save you, He will save you,\nHe will save you now.\r\nFor Jesus shed His precious blood\nrich blessings to bestow.\nPlunge now into the crimson flood\nthat washes white as snow.\r\nYes, Jesus is the truth, the way,\nthat leads you into rest.\nBelieve in Him without delay\nand you are fully blessed.\r\nCome, then, and join this holy band,\nand on to glory go.\nTo dwell in that celestial land,\nwhere joys immortal flow.', 'Komm her, du sündenmüdes Herz,\ndein Heiland ruft dir zu.\nVertrau auf Ihn in deinem Schmerz,\nSein Wort verheißt dir Ruh\'!\r\nIhm allein vertrau von Herzen,\no vertrau Ihm jetzt!\nEr erlöst von Sünd\' und Schmerzen,\nEr erlöst dich jetzt!\r\nDer Herr vergoss Sein teures Blut\nzu unserm Heil allein.\nTauch\' dich in diese heil\'ge Flut,\nso wirst du völlig rein.\r\nJa, Jesus ist der eine Weg,\nder uns zum Vater führt.\nGlaub Ihm und wirf die Zweifel weg;\nEr ist\'s dem Ruhm gebührt.\r\nDes Heilands Lieb\', dies heil\'ge Band,\numschlingt dein Herz fortan.\nEr zieh\' dich ins gelobte Land,\nins sel\'ge Kanaan.'),
(9, '1157', 'Komm in mein Herz  -  Into my Heart (Chorus)', 'Into my heart, into my heart,\ncome into my heart, Lord Jesus.\nCome in today, come in to stay.\nCome into my heart, Lord Jesus.', 'Komm in mein Herz, komm in mein Herz!\nOh, komm in mein Herz, Herr Jesus!\nKomm ziehe ein, dann bin ich Dein.\nOh, komm in mein Herz, Herr Jesus!'),
(9, '1158', 'Komm in mein Herz treuer Heiland und Herr  -  Come to my Heart precious Jesus, my Lord   (Chorus)', 'Come to my heart,\nprecious Jesus, my Lord,\nhear me, oh Saviour divine!\nOpen the fountain and cleanse me, Lord.\nGive me a heart like Thine.', 'Komm in mein Herz,\ntreuer Heiland und Herr,\nhör meiner Seele Schrei!\nÖffne die Quelle und reinige mich, Herr.\nGib mir ein Herz wie Deins!'),
(9, '1159', 'Komm in unsere Mitte, o Herr   (2 Chorusse)', NULL, 'Komm in unsere Mitte,\no Herr, oh Herr, oh Herr!\n(2x)\r\nLass uns spüren,\ndass Du bei uns bist,\no Herr, wir bitten Dich!\nLass uns spüren,\ndass Du bei uns bist,\no Herr, wir danken Dir!'),
(9, '1160', 'Komm noch heut, komm noch heut   (Seliges Heut, heiliges Heut)', NULL, 'Komm noch heut\', komm noch heut\'!\nSeele, sage nicht mehr:\n"Morgen ist bessere Zeit!"\nHeute mahnt dich der Geist,\nheute ruft dich der Herr,\neile, und komme noch heut\'.\r\nSeliges Heut\'! Heiliges Heut\',\nda Gott uns Gnade anbeut.\nO sieh, alle Dinge\nsind wahrlich schon bereit,\nkomme zur Hochzeit noch heut\'.\r\nKomm noch heut\', komm noch heut\'!\nWie beschwert auch dein Herz;\nende den inneren Streit.\nJesus rettet dich heut\',\nJesus heilt deinen Schmerz;\nnahe dich Ihm doch noch heut\'.\r\nSieh, ich komm, teurer Herr,\nich vernahm Deinen Ruf;\nwillig ergeb\' ich mich Dir,\ndessen Wort einst das\nherrliche Weltall erschuf,\nschalte und walte in mir.\r\nSeliger Tag, glückliche Zeit,\nwenn sich ein Herz Jesu weiht.\nWenn gläubig es sich\nganz dem Heiland überlässt,\ndann kommt die goldene Zeit.\r\nWer da kommt, wer da kommt,\nder hat sonst nichts zu tun,\nals was der Herr ihm gebeut.\nJesus hat es vollbracht,\nund die Seele darf ruh\'n,\nvon jeder Bürde befreit.'),
(9, '1161', 'Komm und geh mit mir, zu des Vaters Haus  -  Come and go with me, to my Fathers House', 'Come and go with me to my Father\'s house,\nto my Father\'s House, to my Father\'s house.\nCome and go with me to my Father\'s house,\nwhere there\'s peace, peace, peace.\r\nJesus will be there, in my Father\'s house,\nin my Father\'s House, in my fathers house.\nJesus will be there, in my Father\'s house,\nwhere there\'s joy, joy, joy.\r\nI will see you there, in my Father\'s house,\nin my Father\'s House, in my fathers house.\nI will see you there, in my Father\'s house,\nwhere there\'s joy, joy, joy.\r\nThere\'ll be no sorrow ther,  in my Father\'s house,\nin my Father\'s House, in my fathers house.\nThere\'ll be no sorrow ther,  in my Father\'s house,\nther\'ll be joy, joy, joy.', 'Komm und geh\' mit mir, zu des Vater\'s Haus,\nzu des Vater\'s Haus, zu des Vater\'s Haus.\nKomm und geh\' mit mir zu des Vater\'s Haus\nda ist Fried\', Fried\', Fried\'.\r\nJesus ist der Weg zu des Vaters Haus,\nzu des Vaters Haus, ja zu Seinem Haus.\nJesus ist der Weg zu des Vaters Haus,\nda ist Freud\', Freud\', Freud\'.\r\nWerd\' ich dich dort seh\'n, in des Vaters Haus\nin des Vaters Haus, ja, in des Vaters Haus.\nWerd\' ich dich dort seh\'n, in des Vaters Haus,\nda ist Freud\', Freud\', Freud\'.\r\nDort ist keine Sorg\', in des Vaters Haus,\nin des Vaters Haus, in des Vaters Haus.\nDort ist keine Sorg\', in des Vaters Haus,\nda ist Freud\', Freud\', Freud\'.'),
(9, '1162', 'Komm zu dem Heiland, komme noch heut  -  Come to the Saviour, oh hear his Voice   (Herrlich, herrlich wird es einmal sein)', 'Come to the Saviour, make no delay,\nhere in his word he’s shown us the way.\nHerein our midst he’s standing today,\ntenderly saying: Come!\r\nJoyful, joyful will the meeting be,\nwhen from sin our hearts are pure and free.\nAnd we shall gather, Saviour, with Thee,\nin our eternal home.\r\nCome to the Saviour! Oh hear his voice!\nLet every heart leap forth and rejoice.\nAnd let us freely make him our choice,\ndo not delay, but come.\r\nThink once again, he’s with us today,\nheed now his blest commands, and obey.\nHear now his accents tenderly say:\nCome to your Saviour, come.', 'Komm zu dem Heiland, komme noch heut\'!\nFolg\' Seinem Wort, jetzt ist es noch Zeit!\nEr ist uns nah, zum Segnen bereit\nund ruft so freundlich: Komm!\r\nHerrlich, herrlich wird es einmal sein,\nwenn wir zieh\'n, von Sünde frei und rein,\nin das gelobte Kanaan ein!\nJesus, sieh her, ich komm!\r\nKomm, o mein Kind, und höre Sein Wort,\ngib Ihm dein Herz und folg\' Ihm sofort!\nEr ist ein sich\'rer, ewiger Hort;\nd\'rum mach dich auf und komm!\r\nGlaube nur fest; der Herr nimmt dich an!\nO fühlst du Ihn nicht jetzt dir schon nah\'n?\nMit Lieb und Gnad\' will Er dich umfahn.\nKomm nur, o Sünder, komm!'),
(9, '1163', 'Komm zu dem Wasser und trinke von mir - (Come to the water an trinketh from me)', 'You said you\'d come and share all my sorrows,\nYou said you\'d be there for all my tomorrows.\nI came to close to sending you away,\nbut just as You promised, You came here to stay.\nI just had to pray.\r\nAnd Jesus said: Come to the water and stand by my side.\nI know you are thirsty, you won\'t be denied.\nI felt ev\'ry teardrop, when in darkness you cried.\nAnd I strove to remind you, that for those tears I died.\r\nYour goodness so great, I can\'t understand.\nAnd, dear Lord, I know, that all this was planned.\nI know You\'re here now and always will be.\nYour love loosed my chains and in You I\'m free,\nbut Jesus why me?\r\nJesus, I give you my heart and my soul.\nI know that without You I\'d never be whole.\nSaviour, You opened all the right doors.\nAnd I thank You and praise You from earth\'s humble shores.\nTake me, I am Yours.', 'Du sagst Du kommst und teilst meine Sorgen,\nDu sagst Du bist da auch an jedem Morgen.\nIch meinte erst, das kann gar nicht sein,\ndoch was Du gesagt hast, das traf dann auch ein.\nDir trau ich allein.\r\nUnd Jesus sprach: Komm zu dem Wasser und trinke von mir,\nIch weiß du bist durstig, der Friede fehlt dir.\nIch zählte die Tränen, die des Nachts du geweint,\ndenk doch an Mein Sterben, Ich hab dich auch gemeint.\r\nNur Du bist so groß, ich kann\'s nicht verstehen.\nDein Plan ist so gut, den Du hast ersehen.\nDu weißt den Weg schon und bist mir nicht fern.\nDein Blut wäscht die Schuld, ich folge Dir gern,\ndem Retter und Herrn.\r\nJesus, Dir geb\' ich mein Gut und mein Leben.\nIch weiß ohne Dich, Herr, nützt mir gar kein Streben.\nHeiland Du selber löst alle Not.\nD\'rum dank\'\' ich und preis\' Dich von jetzt bis zum Tod.\nDein bin ich, mein Gott.'),
(9, '1164', 'Komm zum Kreuz mit deinen Lasten', NULL, 'Komm zum Kreuz mit deinen Lasten,\nmüder Pilger du!\nBei dem Kreuze kannst du rasten,\nda ist Ruh\'!\r\nUnter des Gerichtes Ruten\nsieh am Kreuzesstamm\nfür dich dulden und verbluten\nGottes Lamm!\r\nAn dem Kreuze trug der Reine\ndeiner Sünde Lohn.\nO wie liebt dich dieser Eine,\nGottes Sohn!\r\nDa stillt Er dir dein Verlangen,\nheilet deinen Schmerz;\nFrieden wirst du da empfangen,\nmüdes Herz!\r\nTrost, Vergebung, ew\'ges Leben\nfließt vom Kreuz dir zu;\nbei dem Kreuz wird dir gegeben\nHimmelsruh\'!'),
(9, '1165', 'Komm, du Sünder ohne Hoffnung  -  Come, ye sinners, lost and hopeless   (Und ich weiß, ja ich weiß, Jesu Blut macht auch den schlimmsten Sünder rein)', 'Come, ye sinners, lost and hopeless,\nJesus’ blood can make you free.\nFor He saved the worst among you,\nwhen He saved a wretch like me.\r\nAnd I know, yes, I know\nJesus’ blood can make the vilest sinner clean.\nAnd I know, yes, I know\nJesus’ blood can make the vilest sinner clean.\r\nTo the faint He giveth power,\nthrough the mountains makes a way.\nFindeth water in the desert,\nturns the night to golden day.\r\nIn temptation He is near thee,\nholds the pow’rs of hell at bay.\nGuides you to the path of safety,\ngives you grace for every day.\r\nHe will keep thee while the ages\nroll throughout eternity.\nThough earth hinders and hell rages,\nall must work for good to thee.', 'Komm, du Sünder ohne Hoffnung\nJesu Blut erlöst auch dich.\nEs floss für den schlimmsten Sünder,\ndenn es floss ja auch für mich.\r\nUnd ich weiß, ja ich weiß,\nJesu Blut macht auch den schlimmsten Sünder rein.\nUnd ich weiß, ja ich weiß,\nJesu Blut macht auch den schlimmsten Sünder rein.\r\nAll den Schwachen gibt er Kräfte,\ndurch die Nöte führt er dich,\ngibt dir Wasser in der Wüste,\nmacht die Nacht für dich zum Licht.\r\nIn Versuchung ist er nahe,\nvor dem Satan schützt er dich,\nführt dich auf dem schmalen Pfade,\ngibt dir Gnade ewiglich.\r\nEr hält dich für alle Zeiten,\nja für immer hält er dich!\nGegen dich mag alles streiten,\naber schaden kann\'s dir nicht!'),
(9, '1166', 'Kommt Brüder, steht nicht stille, o lasst uns vorwärts ziehn  -  Come Brethren, don\'t grow weary, but let us journey on   (In dem Himmel ist Ruh)', 'Come brethren, don\'t grow weary,\nbut let us journey on.\nThe passing scenes all tell us,\nthat death will surely come!\nThe moments will not tarry\nthis life will soon be gone.\nThese bodies soon will moulder,\nin the dark and weary tomb.\r\nThere is sweet rest in heaven,\nthere is sweet rest in heaven,\nthere is sweet rest, there is sweet rest,\nthere is sweet rest in heaven.\r\nLoved ons have gone before us,\nthe beckon us away.\nO\'er heavenly plains they\'re soaring,\nblest in eternal day.\nBut we are in the army,\nand dare not leave our post.\nWe\'il fight until we conquer,\nthe foe\'s most mighty host.\r\nOur captain\'s gone before us,\nHe kindly calls us home.\nTo yonder world of glory,\nand sweetly bids us come.\nThe world, the flesh and Satan,\nwill strive to hedge our way.\nBut we\'ll overcome these powers,\nif we hourly watch and pray.', 'Kommt, Brüder, steht nicht stille,\no, lasst uns vorwärts zieh\'n,\nseht nur, wie unser Leben\nso rastlos eilt dahin!\nDen Leib wird bald umfangen\nder Erde dunkles Grab.\nD\'rum weil\'s noch "Heute" heißet,\nergreift den Pilgerstab!\r\nIn dem Himmel ist Ruh\',\nin dem Himmel ist Ruh\'.\nIn dem Himmel, in dem Himmel,\nin dem Himmel ist Ruh\'.\r\nSchon sind viel unsrer Lieben\nim ober\'n Kanaan.\nSie haben überwunden\nund ruhen nun fortan,\nwir haben noch zu kämpfen,\nwie\'s uns verordnet ist.\nDoch werden wir auch siegen\nwie sie durch Jesus Christ.\r\nDer große Herr und König\ngeht uns voran im Streit.\nEr führt durch\'s Kreuz zur Krone,\ndurch Nacht zur Herrlichkeit.\nO, lasst uns auf Ihn seh\'n\nmit Wachsamkeit und Fleh\'n,\nbis wir als Überwinder\nin Zion auch eingeh\'n.'),
(9, '1167', 'Kommt stimmet alle jubelnd ein: Gott hat uns lieb  -  Come, let us All unite to sing, God is Love   (Gott hat uns lieb)', 'Come, let us all unite to sing, God is love.\nLet heav’n and earth their praises bring, God is love.\nLet ev\'ry soul from sin awake,\nlet ev’ry heart sweet music make,\nand sing with us for Jesus’ sake,\nfor God is love.\r\nGod is love!\nGod is love!\nCome, let us all unite to sing\nthat God is love.\r\nO tell to earth’s remotest bound, God is love.\nIn Christ we have redemption found, God is love.\nHis blood has washed our sins away,\nHis Spirit turned our night to day,\nand now we can rejoice to say\nthat God is love.\r\nHow happy is our portion here, God is love.\nThese promises our spirits cheer, God is love.\nGod is our sun and shield by day,\nour help, our hope, our strength and stay,\nand will be with us all the way:\nour God is love.', 'Kommt, stimmet alle jubelnd ein: Gott hat uns lieb!\nFreut euch in Seinem Gnadenschein! Gott hat uns lieb!\nDie ihr in Sünden schlaft, erwacht!\nSuchet, was euch nun selig macht!\nHin ist die bange Todesnacht!\nGott hat uns lieb!\r\nGott hat uns lieb!\nGott hat uns lieb!\nKommt, stimmet alle jubelnd ein:\nGott hat uns lieb!\r\nKündet\'s den Sündern überall: Gott hat uns lieb!\nEr kam vom Thron ins Erdental: Gott hat uns lieb!\nSehet, der Heiland ist nun da,\nder für uns starb auf Golgatha!\nWir sind erlöst, Halleluja!\nGott hat uns lieb.\r\nJubelt, die ihr euch Ihm geweiht: Gott hat uns lieb!\nSchmeckt Seine Güt\' und Freundlichkeit: Gott hat uns lieb!\nEr ist der Seinen Sonn\' und Schild\nund unsrer Lieb und Hoffnung Bild.\nEr ist\'s, der allen Kummer stillt.\nGott hat uns lieb!'),
(9, '1168', 'Kommt und seht Gottes Sohn. Kommt und seht die Liebe selbst', NULL, 'Kommt und seht Gottes Sohn. Kommt und seht die Liebe selbst.\nSeht den Königsmantel und den Dornenkranz.\nUnter Schmerz, unter Spott trägt Er selbst das schwere Kreuz\nund verlassen geht Er seinen Leidensweg.\r\nDein Tod hat uns befreit, die Gnade triumphiert\nund Dein Liebesstrom wäscht unsre Herzen rein.\nZur Sünde wurdest Du und warst doch ohne Schuld.\nEin Herz der Liebe ruft: "Vater vergib!".\r\nKommt und seht: unsre Schuld hat den Herrn am Kreuz durchbohrt,\nso viel tiefer als die Nägel seinen Leib.\nAll der Stolz, alles Leid, alles, was uns von Gott trennt\nund die Strafe lag auf Ihm zu unserem Heil.\r\nHerr des Himmels, als Kind gebor\'n, um aus Sünde zu befrei\'n.\nVoller Ehrfurcht beugen wir uns nun vor Dir.\nWeil du starbst, leben wir und Dein Opfer macht uns heil.\nDeine Auferstehungskraft gibt uns den Sieg.\r\nDein Tod hat uns befreit, die Gnade triumphiert\nund Dein Liebesstrom wäscht unsre Herzen rein.\nZur Sünde wurdest Du und warst doch ohne Schuld.\nEin Herz der Liebe ruft: "Vater vergib!".\nWir beten an das Lamm auf dem Thron.'),
(9, '1169', 'Kommt zu mir, die ihr mühselig und beladen seid', NULL, 'Kommt zu mir,\ndie ihr mühselig und beladen seid,\nkommt zu mir und ich gebe euch Ruh\'.\nNehmt mein Joch und lernet von mir,\ndenn ich bin sanftmütig und von Herzen\ndemütig. So werdet ihr finden\nRuhe für eure Seelen,\ndenn mein Joch ist sanft\nund meine Bürde ist leicht.'),
(9, '1170', 'Kommt, alles ist bereit! Hört das Wort!', NULL, 'Kommt, alles ist bereit! Hört das Wort!\nKommt, Heil und Seligkeit gibt es sofort.\nHier gibt es nicht nur Schein, alles soll euer sein.\nKommt, Jesus lädt euch ein, kommt Sünder, kommt!\r\nKommt zu dem Lebensquell, zu Jesus Christ,\nseht, wie so voll und hell das Wasser fließt.\nKeiner soll leer ausgeh\'n, keiner von ferne steh\'n,\nwer glaubt, wird Großes seh\'n. Kommt, Sünder, kommt!\r\nKommet zum Gnadenthron! Noch ist es Zeit.\nWer da will Heil im Sohn, der komme heut\'.\nSorgen und Traurigkeit, Schuld und dein Sündenleid,\nhier wird dein Herz befreit. Komm, Sünder, komm!'),
(9, '1171', 'Kommt, stimmt doch mit uns ein', NULL, 'Kommt, stimmt doch mit uns ein\nund lasst uns fröhlich sein,\ndenn Gott, der Herr, hat uns befreit.\nEr gab uns seine Kraft,\ndie neues Leben schafft,\npreist ihn in alle Ewigkeit.\r\nEr ist allein der Herr\nund ist sonst keiner mehr.\nDie Ehre gebt nur ihm allein.\nBedenkt, was er getan,\nbetet ihn dafür an,\nkommt, lasst uns seine Zeugen sein.\r\nSingt, lobt und jubelt laut!\nWer auf den Herrn vertraut,\nder baut sein Leben nicht auf Sand.\nEr, der die Welt regiert\nund seine Kinder führt,\nhält sie an seiner starken Hand.'),
(9, '1172', 'König ist Jesus allein, preist Ihn ihr Engel', NULL, 'König ist Jesus allein!\nPreist ihn, ihr Engel\nund rühmt ihn, ihr Menschen,\ndenn König ist Jesus allein.\nUnd er ist würdig,\nzu nehmen Kraft und Reichtum,\nWeisheit, Stärke und Ehre, Preis und Lob!\nKönig ist Jesus allein!\nPreist ihn, ihr Engel\nund rühmt ihn, ihr Menschen,\ndenn König ist Jesus allein.\r\nSieger ist Jesus allein!\nPreist ihn, ihr Engel\nund rühmt ihn, ihr Menschen,\ndenn Sieger ist Jesus allein.\nUnd er ist würdig,\nzu nehmen Kraft und Reichtum,\nWeisheit, Stärke und Ehre, Preis und Lob!\nSieger ist Jesus allein!\nPreist ihn, ihr Engel\nund rühmt ihn, ihr Menschen,\ndenn Sieger ist Jesus allein.\r\nRetter ist Jesus allein!\nPreist ihn, ihr Engel\nund rühmt ihn, ihr Menschen,\ndenn Retter ist Jesus allein.\nUnd er ist würdig,\nzu nehmen Kraft und Reichtum,\nWeisheit, Stärke und Ehre, Preis und Lob!\nRetter ist Jesus allein!\nPreist ihn, ihr Engel\nund rühmt ihn, ihr Menschen,\ndenn Retter ist Jesus allein.'),
(9, '1173', 'Krönt, krönt ihn, unsern Herrn, das Lamm auf Gottes Thron  -  Crown him with many Crowns, the Lamb upon His Throne', 'Crown Him with many crowns,\nthe Lamb upon His throne.\nHark! how the heavenly anthem drowns\nall music but its own.\nAwake, my soul, and sing\nof Him who died for thee,\nand hail Him as thy matchless king\nthrough all eternity.\r\nCrown him the Lord of love,\nbehold His hands and side,\nrich wounds, yet visible above,\nin beauty glorified.\nNo angels in the sky\ncan fully bear that sight,\nbut downward bends their burning eye\nat mysteries so bright.\r\nCrown Him the Lord of life,\nwho triumphed o\'er the grave,\nand rose victorious in the strife\nfor those He came to save.\nHis glories now we sing\nwho died and rose on high,\nwho died eternal life to bring,\nand lives that death may die.\r\nCrown him the Lord of years,\nthe potentate of time,\ncreator of the rolling spheres,\nineffably sublime.\nAll hail, Redeemer, hail!\nfor thou hast died for me;\nthy praise shall never, never fail\nthroughout eternity.', 'Krönt, krönt Ihn, unsern Herrn,\ndas Lamm auf Gottes Thron!\nGebt euer ganzes Leben hin\nfür Ihn, den Gottessohn!\nErwache, Herz, und sing\nvon dem, der für dich starb!\nAnbetung, Ruhm und Ehre bring\ndem, der dir Heil erwarb!\r\nKrönt, krönt Ihn, unsern Herrn,\nseht Seine Wunden an.\nSie strahlen Seine Liebe aus,\ndie niemand fassen kann.\nKein Engel kann sie schau\'n,\ner senkt den Blick davor\nund rühmet im Gebet das Lamm\nim hohen Himmelschor.\r\nKrönt, krönt ihn, unsern Herrn,\nder Frieden uns gebracht\nund dessen Zepter allem Streit\ndie Welt ein Ende macht.\nSein Reich bleibt ewiglich,\nob\'s jetzt nicht sichtbar ist,\nbekennen wird es jeder Mund,\ndass Christus König ist!\r\nKrönt, krönt ihn, unsern Herrn, d\nen Schöpfer aller Welt,\nder das Geschick der Völker\nrings in seinen Händen hält.\nHeil, Heil sei dir, o Herr!\nDu littst und starbst für mich!\nIch diene Dir, ich folge Dir,\nich preis Dich ewiglich!'),
(9, '1174', 'Kurz nur ist die Zeit, nah die Ewigkeit!   (Trau auf das was Gott verheißt)', NULL, 'Kurz nur ist die Zeit, nah die Ewigkeit!\nHast du dies bedacht?\nFlieh zu Gottes Sohn! Dir winkt ew\'ger Lohn!\nEr hat Himmelsmacht!\r\nTrau auf das, was Gott verheißt,\nstütze dich auf Seinen Geist.\nFürchte nichts was mag gescheh\'n,\nbald wirst du den König seh\'n.\r\nWenn du stille bist, Gott dir nahe ist!\nHöre, was er spricht!\nWarte mit Geduld, er schenkt Lieb und Huld\nzweifle daran nicht!\r\nWird es in dir hell, gib ihm Antwort schnell!\nSag: "Gott, her bin ich!"\nDir gehorch\' ich gern, folge meinem Herrn!\nStille füg\' ich mich!\r\nSei nun auf der Hut! Satans List und Wut\ndrohen dir mit Krieg.\nWenn du wachend bist, beten nicht vergisst,\nbleibt dir stets der Sieg!\r\nBald geht es nach Haus und wir ruhen aus!\nDann auf schmalen Pfad,\ntönt der laute Schrei: Bist du fertig, frei?\nSieh, dein Heiland naht!'),
(9, '1175', 'Lamm, das gelitten, und Löwe, der siegreich gerungen', NULL, 'Lamm, das gelitten, und Löwe, der siegreich gerungen!\nBlutendes Opfer und Held, der die Hölle bezwungen!\nBrechendes Herz, das sich aus irdischem Schmerz\nüber die Himmel geschwungen!\r\nDu hast in schauriger Tiefe das Höchste vollendet,\nGott in die Menschheit gehüllt, dass Dein Licht uns nicht blendet.\nWürdig bist Du, ruft Dir die Ewigkeit zu,\nPreises und Ruhms, der nicht endet!\r\nHimmlische Liebe, die Namen der Erde nicht nennen.\nFürst Deiner Welten, den einst alle Zungen bekennen.\nGingest Du nicht selbst in der Sünde Gericht,\nSünder entlassen zu können?\r\nÜber des Todes umnachteten, grau\'nvollen Klüften\nschwangst Du die Palme des Sieges in himmlischen Lüften.\nWer an Dich glaubt, trägt nun, von Hoffnung umlaubt,\newiges Leben aus Grüften.\r\nWahl voller Wunder! der einzige Reine von allen\neint sich mit Seelen, die sündig im Staube hier wallen,\nträgt ihre Schuld, hebt in unendlicher Huld\ndas, was am tiefsten gefallen!\r\nMenschensohn, Heiland, in dem sich das ew\'ge Erbarmen\nmilde zu eigen gegeben den schuldigen Armen,\nDir an der Brust darf nun in Leben und Lust\njeder Erstarrte erwarmen.\r\nLobe den Herrn, meine Seele, Er hat dir vergeben,\nheilt dein Gebrechen, legt in dich ein ewiges Leben;\nFrieden im Streit, Wonne im irdischen Leid\nweiß dir Dein Heiland zu geben.'),
(9, '1176', 'Lang irrt ich im Dunkel der Sünden umher  -  A long Time I wandered in Darkness and Sin', 'A long time I wandered in darkness and sin,\nand wondered if ever the light would shine in.\nI heard Christian friends speak of raptures divine,\nand I wished, how I wished, that their Saviour were mine.\nI wished He were mine, yes, I wished He were mine.\nI wished, how I wished, that their Saviour were mine.\r\nI heard the glad Gospel of good will to men,\nI read whosoever again and again.\nI said to my soul, can that promise be thine?\nand then began hoping that Jesus was mine.\nI hoped He was mine, yes, I hoped He was mine,\nand then began hoping that Jesus was mine.\r\nOh, mercy surprising! He saves even me!\nThy portion forever, He says, will I be.\nOn His Word I am resting, assurance divine:\nI am hoping no longer, I know He is mine.\nI know He is mine, yes, I know He is mine,\nI’m hoping no longer, I know He is mine.', 'Lang irrt ich im Dunkel der Sünden umher\nund hegte im stillen nach Licht doch Begehr\';\nIch wollte wie andre so gern selig sein,\nund wünschte von Herzen, der Heiland wär\' mein.\nO, wär\' Er doch mein auch, o, wär\' Er doch mein!\nIch wünschte von Herzen, der Heiland wär\' mein.\r\nIch hörte die Botschaft der Liebe des Herrn,\nich las die Verheißung für Sünder so gern;\nIch sprach: "Meine Seele, ist das nicht auch dein?"\nund fing an zu hoffen, der Heiland wär\' mein.\nO, wär\' Er doch mein auch, o, wär\' Er doch mein!\nIch fing an zu hoffen, der Heiland wär\' mein.\r\nO, Wunder der Gnade! Nun sage auch ich:\nDas Blut des Erlösers, es rettet auch mich;\nSein Wort flößt Gewissheit dem Ärmsten auch ein.\nIch hoffe nicht länger, ich weiß, Er ist mein.\nIch weiß, Er ist mein, ja, ich weiß Er ist mein!\nIch hoffe nicht länger, ich weiß, Er ist mein.'),
(9, '1177', 'Lang nach eines Lichtes Schimmer spähten wir in dunkler Nacht  -  Long in darkness we have waited, for the shining of the Light   (O, wo ist die starke Rechte)', 'Long in darkness we have waited,\nfor the shining of the light.\nLong have felt the things we hated,\nsink us still in deeper night.\r\nBlessèd Jesus, loving Saviour!\nTender, faithful, strong and true.\nBreak the fetters that have bound us,\nmake us in Thyself anew.\r\nNow, at last, the Light appeareth,\nJesus stands upon the shore.\nAnd with tender voice, He calleth,\ncome to Me and sin no more!\r\nNothing have we, but our weakness,\nnaught but sorrow, sin and care.\nAll within is loathsome vileness,\nall without is dark despair.\r\nAll our talents we have wasted,\nall Thy laws have disobeyed.\nBut Thy goodness now we’ve tasted,\nin Thy robes we stand arrayed.\r\n\r\nThou hast saved us - do Thou keep us,\nguide us by Thine eye divine.\nLet the Holy Spirit teach us,\nthat our light may ever shine.', 'Lang nach eines Lichtes Schimmer\nspähten wir in dunkler Nacht,\ndoch wir sanken tiefer immer\nin der Sünde finst\'re Macht.\r\nO, wo ist die starke Rechte,\nvoll von heil\'ger Gotteskraft,\ndie aus einem Sündenknechte\neinen neuen Menschen schafft?\r\nSiehe da, voll Huld und Gnaden\nkam der Heiland Jesus her.\nSprach: Ich heile deinen Schaden,\nkomm und sündige nicht mehr!\r\nUnsre Güter, unsre Gaben\nhatte Sündendienst verheert;\nMut und Hoffnung war begraben,\nunsre beste Kraft verzehrt.\r\nAch, was konnten wir Ihm geben,\nder so viel für uns getan!\nNichts als ein verarmtes Leben,\ndoch Er sah es gnädig an.\r\nUnd die Herzen, schuldbeklommen,\ndie wir Armen Ihm gebracht,\nhat Er liebreich angenommen\nund sie rein und still gemacht.\r\nHerr, mit Deinem Angesichte\nleite Du uns immerfort,\ndass sich unser Wandel richte\nnur nach Deinem Sinn und Wort!'),
(9, '1178', 'Lange her an einem Brunnen warn die Fraun zur Abendzeit  -  Long ago the Maids drew Water in the Evening Time   (Ja Gottes Licht in der Abendzeit weist dir den Weg in die Herrlichkeit)', 'Long ago the maids drew water in the evening time, they say.\nOne day Isaac sent his servant to stop Rebekah on her way.\n"My master sent me here to tell thee, see these jewels rich and rare,\nwouldst thou not his lovely bride be in that country over there?"\r\nIt shall be light in the evening time, the path to glory you will surely find,\nthru the water way, it is the light today, baptized in Jesus Name.\nYoung and old, repent of all your sin, the Holy Ghost will enter in.\nThe evening time has come, \'tis a fact that God and Christ are one.\r\nSo God\'s servants come to tell you of a Bridegroom in the sky,\nlooking for a holy people to be His bride soon, by and by.\nHe sends to us refreshing water in this wondrous latter day,\nthey who really will be raptured must go thru the water way.\r\nAre you on your way to ruin, cumbered with a load of care?\nSee the quick work God is doing that so His glory you may share.\nAt last the faith he once delivered to the saints, is ours today,\nto get in the church triumphant you must go the water way.\r\nHave you looked and often wondered why the power is slack today?\nWill you stay in that back number and go on the man-made way?\nOh, saints who never have been buried in the blessed name of God,\nlet the truth now sanctify you, it\'s the way apostles trod.', 'Lange her an einem Brunnen war\'n die Frau\'n zur Abendzeit,\nIsaak sandt\' Elieser und auch Rebekka war nicht weit.\n"Mein Herr schickt mich um dich zu suchen hat die Gaben mitgesandt.\nSag, willst Du nicht seine Braut sein drüben in dem ander\'n Land?"\r\nJa Gottes Licht in der Abendzeit weist dir den Weg in die Herrlichkeit.\nIn dem Wasserweg findest du das Licht, getauft in Jesu Nam\'.\nJung und Alt, wenn ihr euch Jesus weiht, kommt der Heil\'ge Geist zur Abendzeit.\nDas Abendlicht ist hier, und Er offenbart Sich dir und mir.\r\nSo hat Gottes Knecht gesprochen von dem Himmelsbräutigam,\nder da schaut nach einem Volke, das Er zur Braut Sich nehmen kann.\nEr sendet uns das Lebenswasser, ja an diesem dunklen Tag.\nWer die Erde will verlassen, der muss geh\'n den Wasserweg.\r\nBist du auf dem Weg beladen und mit Sorgen musst du geh\'n?\nSieh\', Gott tut Sein Werk in Eile, Er möchte dich verherrlicht seh\'n.\nDer Glaube, der ist für die Heil\'gen, dieser Glaube ist der Sieg.\nJa, willst du Ihn heut\' empfangen, musst du geh\'n den Wasserweg.\r\nHast du dich schon oft gefraget: Warum heut\' so klein die Kraft?\nBist du auf dem Weg gewandelt, ja, den ein Mensch sich selbst erdacht\'?\nO Heil\'ger, der noch nicht begraben in dem teuren Gottesnam\',\nkomm und geh\' den Weg der Wahrheit, der beginnt mit Jesu Nam\'!'),
(9, '1179', 'Lass das Buch leben in mir, Herr  -  Let the Book live in me, dear Lord   (Chorus)', 'Let the Book live in me, dear Lord,\nshow me myself within They Word.\nSanctify me and dwell in me,\nyes, let the Book live in me.', 'Lass das Buch leben in mir, Herr,\nzeig mir mich selbst in Deinem Wort.\nHeilige mich und wohne in mir,\nja, lass das Buch leben in mir.'),
(9, '1180', 'Lass das Reden meines Mundes   (2 Chorusse)', NULL, 'Lass das Reden meines Mundes\nund das Sinnen meines Herzens\nwohlgefällig, wohlgefällig sein vor Dir. (2x)\r\nHerr, mein Fels und mein Erlöser. (3x)\nHerr ich möchte, wohlgefällig sein vor Dir.'),
(9, '1181', 'Lass Dein Lebenswasser nun strömen durch mich  -  Let Your living Water flow over my Soul   (Chorus)', 'Let Your living water flow over my soul.\nLet Your Holy Spirit come and take control.\nIn every situation that has troubled my mind,\nall my cares and burden unto You I throw.\n|: Jesus, Jesus, Jesus. :|', 'Lass Dein Lebenswasser nun strömen durch mich.\nLass den Heil\'gen Geist jetzt kommen, nimm mich mit.\nJede Sorge, jede Last, die mich bedrückt,\nwerfe ich auf Dich, denn Du sorgst für mich.\n|: Jesus, Jesus, Jesus. :|'),
(9, '1182', 'Lass Deine Liebe durch mich strömen', NULL, 'Lass Deine Liebe durch mich strömen,\nlass Deine Liebe durch mich strömen,\nlass Deine Liebe, o Herr strömen\ndurch mich, ich bitte Dich.\nLass Deine Liebe durch mich strömen,\nlass Deine Liebe durch mich strömen,\nlass Deine Liebe, o Herr,\nströmen durch mich.\r\nLass Deinen Frieden durch mich strömen,\nlass Deinen Frieden durch mich strömen,\nlass Deinen Frieden, o Herr strömen\ndurch mich, ich bitte Dich.\nLass Deinen Frieden durch mich strömen,\nlass Deinen Frieden durch mich strömen,\nlass Deinen Frieden, o Herr,\nströmen durch mich.\r\nLass Deine Gnade durch mich strömen,\nlass Deine Gnade durch mich strömen,\nlass Deine Gnade, o Herr strömen\ndurch mich, ich bitte Dich.\nLass Deine Gnade durch mich strömen,\nlass Deine Gnade durch mich strömen,\nlass Deine Gnade, o Herr,\nströmen durch mich.\r\nLass Deine Ruhe durch mich strömen,\nlass Deine Ruhe durch mich strömen,\nlass Deine Ruhe, o Herr strömen\ndurch mich, ich bitte Dich.\nLass Deine Ruhe durch mich strömen,\nlass Deine Ruhe durch mich strömen,\nlass Deine Ruhe, o Herr,\nströmen durch mich.\r\nLass Deinen Segen durch mich strömen,\nlass Deinen Segen durch mich strömen,\nlass Deinen Segen, o Herr strömen\ndurch mich, ich bitte Dich.\nLass Deinen Segen durch mich strömen,\nlass Deinen Segen durch mich strömen,\nlass Deinen Segen, o Herr,\nströmen durch mich.'),
(9, '1183', 'Lass Deinen Geist nun auf uns alle fallen', NULL, 'Lass Deinen Geist nun auf uns alle fallen,\nwie in Jerusalem im ob\'ren Saal. :|\n|: Dasselbe Feuer send\' vom Himmel nieder\nauf uns in dieser Zeit der Sorg\' und Qual. :|:\r\nLass Deinen Geist nun auf uns alle fallen,\nwie einst Er fiel in des Kornelius Haus. :|\n|: Oh, tauf\' uns alle mit dem heil\'gen Feuer\nund aus dem Herzen treib all\' Furcht hinaus. :|:\r\nLass Deinen Geist nun auf uns alle fallen,\nwie einst, da Wunderzeichen viel geschah\'n. :|\n|: Wir warten betend im Verheißungssaale.\nKomm bald und lass uns Deine Kraft empfah\'n. :|:\r\nErwecke Deine Kinder, die da schlafen\nein\' Steinwurf weit von Dir am Kidronstrand.\nKomm zu uns wieder, wie Du früher tatest,\nund leg auf uns die durchgebohrte Hand.'),
(9, '1184', 'Lass die Lieblichkeit Jesu man sehn in mir  -  Let the Beauty of Jesus be seen in me', 'Let the beauty of Jesus be seen in me,\nAll His wonderful passion and purity;\nOh Thou Spirit divine,\nAll my nature refine,\nTill the beauty of Jesus is seen in me.\r\nLet the fruit of the Spirit be seen in me.\nGrant me grace all sufficient that I may be,\ntrue and faithful each day, every step of the way.\nPointing souls to the Saviour on Calvary.', 'Lass die Lieblichkeit Jesu man seh\'n in mir,\nSeine heilige Reinheit und Tugend Zier.\nOh, du Heiliger Geist,\nmach mich Christus nur gleich.\nbis die Lieblichkeit Jesu man seh\' in mir.\r\nLass die Frucht des Geistes an mir sichtbar werden.\nGewähre mir Gnade in Fülle, wahrhaftig und treu zu sein,\njeden Tag, bei jedem Schritt des Weges.\nSeelen auf den Erlöser auf Golgatha zu weisen.'),
(9, '1185', 'Lass du mich stille werden, mein Herr und Gott', NULL, 'Lass Du mich stille werden, mein Herr und Gott,\nnur Deine Stimme hören in Glück und Not,\nnur Deine Stimme hören in Glück und Not.\r\nBring alles eigne Wollen in mir zur Ruh\',\nund meines Lebens Fragen entscheide Du,\nund meines Lebens Fragen entscheide Du.\r\nWenn ich den Weg nicht finde in dunklem Streit,\nleucht\' mir mit ew\'gem Lichte durch diese Zeit,\nleucht\' mir mit ew\'gem Lichte durch diese Zeit.\r\nReich mir die Gnadenhände in meinem Lauf;\nzieh\' Blicke und Gedanken zu Dir hinauf,\nzieh\' Blicke und Gedanken zu Dir hinauf!\r\nBin ich in Deinem Bilde dereinst erwacht,\ndann rühm\' ich Deine Gnade: Du hast\'s vollbracht,\ndann rühm\' ich Deine Gnade: Du hast\'s vollbracht.'),
(9, '1186', 'Lass los und leg alles heut in Gottes Hand  -  Let go and let God have His wonderful Way   (Chorus)', 'Let go and let God have His wonderful way,\nlet go and let God have His way.\nYour sorrows will vanish, your night turn to day,\nlet go and let God have His way.', 'Lass los und leg alles heut\' in Gottes Hand,\nlass los und vertraue auf Ihn.\nDie Sorgen verschwinden, die Nacht ist vorbei,\nlass los und vertraue auf Ihn.'),
(9, '1187', 'Lass mein Leben sein eine Krippe für Dein Wort  -  Let Your Word be born in the Manger of my Heart   (Chorus)', 'Let Your Word be born, in the manger of my heart.\nLet it live in me, let it start.\nLive inside this house of clay, and mold it every day.\nLet Your Word be born in the manger of my heart.\r\nThere was a tiny, simple stable,\nOld, beaten, and worn;\nHardly a place\nFor a King to be born;\nHe didn\'t choose\nSome place special,\nTo reveal His Majesty;\nSo I know if I\'ll give Him control,\nHe\'ll be born in me.\r\nWell, outwardly I\'m nothing,\nNot much to behold,\nUnlikely the place\nfor His Word to unfold;\nBut if I\'ll just yield this vessel,\nAnd let Him have His way;\nFrom glory unto glory,\nHe\'ll change me day by day.', 'Lass mein Leben sein, eine Krippe für Dein Wort.\nLebe Du in mir und bleib bei mir.\nWohne Du in diesem Ton, und forme täglich mich.\nLass mein Leben sein eine Krippe für Dein Wort.\r\nEs gab einen winzigen, einfachen Stall.\nAlt, geschlagen und abgenutzt.\nKaum ein Ort, wo ein König geboren wird.\nEr hat nicht einen besonderen Ort gewählt\nSeine Majestät zu offenbaren.\nIch weiss wenn ich ihm die Kontrolle geben, wird er in mir geboren.\r\nVon aussen bin nichts, nicht besonders zu sehen.\nSehr wahrscheinlich nicht der Ort wo sein Wort sich entfaltet.\nAber wenn ich ihm dieses Gefäß einfach hingebe. Von Herrlichkeit zu Herrlichkeit,\nEr wird mich verändern Tag für Tag.'),
(9, '1188', 'Lass mich Dein sein und bleiben', NULL, 'Lass mich Dein sein und bleiben,\nDu treuer Gott und Herr!\nVon Dir lass nichts mich treiben,\nhalt mich bei Deiner Lehr\'!\nHerr, lass mich nur nicht wanken,\ngib mir Beständigkeit!\nDafür will ich Dir danken in alle Ewigkeit.'),
(9, '1189', 'Lass mich wandeln mit Jesus - Let me walk with You Jesus', 'Let me walk with you, Jesus,\ndon\'t ever leave me alone.\nFor without you I could never,\nno, never make heaven my home.\r\nYou found me when I was so lonely.\nYou found me when I was so blue.\nYou found me when no one could help me,\nwhen no one knew just what to do.\r\nI\'ve been on the mountain with Jesus,\nI\'ve been in the valley so low.\nAnd never one time has He failed me.\nTo Him with my troubles I go.', 'Lass mich wandeln mit Jesus,\noh, Herr, lass mich niemals allein.\nDenn ohne dich, oh, Herr Jesus,\nwird die Herrlichkeit niemals mein Heim.\r\nEr fand mich in tiefer Verzweiflung,\ner fand mich einsam, ohne Glück.\nEr fand mich als niemand konnt\' helfen,\nin Sünde und Welt ganz verstrickt.\r\nIch bin über Höhen gewandelt,\ndurch Täler der Tränen hindurch.\nUnd niemals hat er mich verlassen,\nnie hat seine Hand mich enttäuscht.'),
(9, '1190', 'Lass mich ziehn treuer Herr  -  Let me walk blessed Lord   (Füll mich neu jeden Tag mit Lieb)', 'Let me walk, blessed Lord,\nin the way Thou has gone,\nleading straight to the land above;\ngiving cheer everywhere\nto the sad and the lone,\nfill my way every day with love.\r\nFill my way every day with love,\nas I walk with the heavenly Dove,\nlet me go all the while\nwith a song and a smile,\nfill my way every day with love.\r\nKeep me close to the side\nof my Saviour and guide,\nlet me never in darkness rove;\nkeep my path free from wrath,\nand my soul satisfied,\nfill my way every day with love.\r\nSoon the race will be o\'er,\nand I\'ll travel no more,\nbut abide in my home above;\nlet me sing, blessed king,\nall the way to the shore,\nfill my way every day with love.', 'Lass mich zieh\'n, treuer Herr,\nauf dem Weg, den Du gingst,\nder da führt in das Land voll Fried\'.\nDass ich glaube Dein Wort\nund ich tu, was Du willst,\nfüll\' mich neu jeden Tag mit Lieb\'.\r\nFüll\' mich neu jeden Tag mit Lieb\',\ndass die Taube nie entflieht.\nLass mich geh\'n allezeit\nvoller Freud\' und Dankbarkeit.\nFüll\' mich neu jeden Tag mit Lieb\'.\r\nHalt mich nah an der Seit\'\nmeines Retters allezeit,\ndass ich nie mehr im Dunkel geh.\nHalt den Pfad frei von Plag\',\nmeine Seele bereit:\nFüll\' mich neu jeden Tag mit Lieb\'.\r\nBald vorbei ist mein Lauf,\nmeine Reise hört auf,\nund ich wohne im Heimatland.\nMöchte singen von Dir,\nnehm\' den Spott gern in Kauf.\nFüll\' mich neu jeden Tag mit Lieb\'.'),
(9, '1191', 'Lasst die Herzen immer fröhlich  -  Let our Hearts be always cheerful   (Immer fröhlich, immer fröhlich)', 'Let our hearts be always cheerful,\nwhy should murm\'ring enter there.\nWhen our kind and loving Father\nmakes us children of His care?\r\nAlways cheerful always cheerful,\nsunshine all around we see.\nFull of beauty is the path of duty,\ncheerful we may always be.\r\nWith His gentle hand to lead us,\nshould the pow\'rs of sin assail.\nHe has promised grace to help us,\nnever can His promise fail.\r\nWhen we turn aside from duty,\ncomes the pain of doing wrong.\nAnd a shadow, creeping o\'er us,\nchecks the rapture of our song.\r\nOh! the good are always happy,\nand their path is ever bright.\nLet us heed the blessed counsel,\nshun the wrong and love the right.', 'Lasst die Herzen immer fröhlich\nund mit Dank erfüllet sein,\ndenn der Vater in dem Himmel\nnennt uns Seine Kinderlein!\r\nImmer fröhlich, immer fröhlich,\nalle Tage Sonnenschein.\nVoller Schönheit ist der Weg des Lebens;\nfröhlich lasst uns immer sein!\r\nGott führt uns an Vaterhänden,\nschützet uns in Kampf und Streit,\nSeine Gnade ist\'s, die täglich\nKraft und Stärke uns verleiht.\r\nWenn wir uns von Ihm abwenden,\nwird es finster um uns her,\nunser Gang ist nicht mehr sicher\nund das Herz von Freuden leer.\r\nAber die Gerechten grünen,\nund ihr Pfad ist immer licht;\nlasst uns deshalb Jesu dienen,\nwill\'gen in die Sünde nicht!'),
(9, '1192', 'Lasst mich gehn, lasst mich gehn, dass ich Jesum möge sehn', NULL, 'Lasst mich geh\'n, lasst mich gehn,\ndass ich Jesum möge seh\'n!\nMeine Seel\' ist voll Verlangen,\nIhn auf ewig zu umfangen\nund vor Seinem Thron zu steh\'n!\r\nSüßes Licht, süßes Licht,\nSonne, die durch Wolken bricht,\no wann werd\' ich dahin kommen,\ndass ich dort mit allen Frommen\nschau Dein holdes Angesicht?\r\nAch, wie schön, ach, wie schön,\nist der Engel Lobgetön!\nHätt\' ich Flügel, hätt\' ich Flügel,\nflög ich über Tal und Hügel\nheute noch nach Zions Höh\'n.\r\nWie wird\'s sein, wie wird\'s sein,\nwenn ich zieh\' in Salem ein,\nin die Stadt der goldnen Gassen;\nHerr, mein Gott, ich kann\'s nicht fassen,\nwas das wird für Wonne sein!\r\nParadies, Paradies,\nwie ist deine Frucht so süß!\nUnter deinen Lebensbäumen\nwird uns sein, als ob wir träumen.\nBring uns, Herr, ins Paradies!'),
(9, '1193', 'Lasst uns miteinander singen, loben, preisen den Herrn   (Chorus)', NULL, 'Lasst uns miteinander, lasst uns miteinander,\nsingen, loben, preisen den Herrn.\nLasst es uns gemeinsam tun,\nsingen, loben, preisen den Herrn,\nsingen, loben, preisen den Herrn,\nsingen, loben, preisen den Herrn,\nsingen, loben, preisen den Herrn,\nsingen, loben, preisen den Herrn!'),
(9, '1194', 'Lasst uns reden von Jesus  -  Let\'s talk about Jesus   (6 Chorusse)', 'Let\'s talk about Jesus,\nthe King of Kings is He,\nthe Lord of lords supreme,\nthroughout eternity.\nThe Great I AM, the Way,\nthe Truth, the Life, the Door,\nlet\'s talk about Jesus more and more.\r\nLet\'s talk about Jesus,\nlet all the world proclaim.\nThe pow\'r and majesty\nof such a wondrous Name.\nThe Babe of Bethlehem,\nthe Bright and Morning Star,\nlet\'s sing His praises\nnear and far.\r\nLet\'s talk about Jesus,\nthe Bread of Life is He,\nThe Saviour of the world,\nthe Man of Galilee.\nThe Prophet, Priest and King,\nthe Mighty God is He,\nthe well of Living Water free.\r\nLet\'s talk about Jesus,\nthe Prince of Peace is He,\nthe Great Physician too,\ndown through all history.\nThe Lily pure and white,\nthe Rose of Sharon fair,\nthe Shepherd of such tender care.\r\nLet\'s talk about Jesus,\nthe Rock of Ages He,\nthe Lamb for sinners slain,\nthat man of Calvary.\nThe Great Emmanuel, the\nWord of God sublime,\nHe is our Bridegroom so divine.\r\nLet\'s talk about Jesus,\nHe is the Almighty God.\nHe brought salvation,\nto the world on Golgotha.\nHe is the great God,\nand Lord of Lords is He.\nLet\'s talk about Jesus\nmore and more.', 'Lasst uns reden von Jesus,\nKönig der Herrlichkeit,\nder allerhöchste Herr,\ndurch alle Ewigkeit,\nder ruft, "Ich bin der Herr,\nWahrheit, Leben und die Tür."\nGebt Jesus den Dank und Preis dafür.\r\nLasst uns reden von Jesus\nder ganzen Welt erklär\'n,\ndie Macht und Kraft von Ihm,\nlasst dies Wunder alle hör\'n.\nDas Kind von Bethlehem,\nleuchtender Morgenstern,\nlasst uns singen und preisen\nnah und fern.\r\nLasst uns reden von Jesus,\ndem wahren Lebensbrot,\nder Mann von Nazareth,\nder Retter aus der Not.\nKönig, Priester und Prophet,\nGott, Herr, Allmächtiger,\ndie Quelle für\'s Leben\nist nur Er.\r\nLasst uns reden von Jesus\nder Friedensfürst ist Er,\nauch unser  großer Arzt,\nimmer wieder, Bestätigter.\nDie Lilie weiß und rein,\nRose Sarons schön und wahr,\nGuter Hirte, Rat und Wunderbar.\r\nLasst uns reden von Jesus\ndem Fels der Ewigkeit,\ndies Lamm für Sünder starb,\nGolgatha war die Zeit.\nDer große "Gott mit uns"\nals "Das Wort" zu uns kam,\nEr unser himmlischer Bräutigam.\r\nLasst uns reden von Jesus,\nSein ist Gewalt und Macht.\nEr hat auf Golgatha,\ndas Heil der Welt gebracht.\nDer große Gott ist Er\nund aller Herren Herr,\nlasst uns reden von Jesus\nmehr und mehr.'),
(9, '1195', 'Laut rühmet Jesu Herrlichkeit  -  All hail the Pow\'r of Jesus\' Name', 'All hail the pow\'r of Jesus\' name!\nLet angels prostrate fall.\nBring forth the royal diadem,\nand crown Him Lord of all.\nBring forth the royal diadem,\nand crown Him Lord of all!\r\n\r\nYe seed of Israel\'s chosen race,\nye ransomed from the fall.\nHail Him, who saves you by His grace,\nand crown Him Lord of all.\nHail Him, who saves you by His grace,\nand crown Him Lord of all.\r\nSinners, whose love can ne\'er forget\nthe wormwood and the gall.\nGo spread your trophies at His feet,\nand crown Him Lord of all.\nGo spread your trophies at His feet,\nand crown Him Lord of all.\r\nLet every kindred, every tribe\non this terrestrial ball.\nTo Him all majesty ascribe,\nand crown Him Lord of all.\nTo Him all majesty ascribe,\nand crown Him Lord of all!\r\nOh, that with yonder sacred throng\nwe at His feet may fall!\nWe\'ll join the everlasting song,\nand crown Him Lord of all;\nWe\'ll join the everlasting song,\nand crown Him Lord of all!', 'Laut rühmet Jesu Herrlichkeit!\nIhn preist die Engelwelt, Ihn preist die Engelwelt.\nDie Krone bringt das Purpurkleid,\nund krönt Ihn, krönt Ihn, krönt Ihn,\nkrönt Ihn zum Herrscher aller Welt!\r\nKrönt Ihn, ihr Zeugen, die dem Lamm\nzur Schlachtung sich gestellt, zur Schlachtung sich gestellt;\nlobsinget dem Reis aus Jesses Stamm,\nund krönt Ihn, krönt Ihn, krönt Ihn,\nkrönt Ihn zum Herrscher aller Welt!\r\nErlöste Schar aus Israel, die treu zum König hält,\ndie treu zum König hält, lobsinget dem Immanuel,\nund krönt Ihn, krönt Ihn, krönt Ihn,\nkrönt Ihn zum Herrscher aller Welt!\r\nIhr Sünder aus der Völker Zahl,\neuch ruft der Siegesheld, euch ruft der Siegesheld.\nPreist Ihn für Seine Kreuzesqual,\nund krönt Ihn, krönt Ihn, krönt Ihn,\nkrönt Ihn zum Herrscher aller Welt!\r\nIhm dient in jedem Volk und Stamm,\nbis alles Ihm zufällt, bis alles Ihm zufällt.\nPreis und Anbetung bringt dem Lamm,\no krönt Ihn, krönt Ihn, krönt Ihn,\nkrönt Ihn zum Herrscher aller Welt!\r\nEinst singen wir das Lied der Braut\nim himmlischen Gezelt, im himmlischen Gezelt.\nDann tönt\'s durch alle Sphären laut:\no krönt Ihn, krönt Ihn, krönt Ihn,\nkrönt Ihn zum Herrscher aller Welt!'),
(9, '1196', 'Lebenswasser fließet', NULL, 'Lebenswasser fließet, fließet, fließet,\nLebenswasser fließet!\nIn den Fluten, da findest du Heil,\nin den Fluten, da findest du Heil.\nin den Fluten findest du ewiges Heil.\nDie Lebensflut ist Jesu Blut.\nIn den Fluten, da findest du Heil.'),
(9, '1197', 'Lehre mich glauben, Herr, lehre mich flehn', NULL, 'Lehre mich glauben, Herr, lehre mich fleh\'n!\nKindlich vertrauensvoll lehre mich fleh\'n!\nSegne, o Herr, dein Kind, dass es, von Lieb entzündt\',\nSeelen für dich gewinnt! Lehre mich fleh\'n!\r\nLehre mich glauben, Herr, lehre mich fleh\'n!\nZeig mir der Seelen Wert; lehre mich fleh\'n!\nHerr, o mein Heiland, gib Weisheit mir, Kraft und Lieb!\nIn deines Geistes Trieb lehre mich fleh\'n!\r\nLehre mich glauben, Herr, lehre mich fleh\'n!\nEilend die Zeit vergeht, lehre mich fleh\'n!\nSieh meine Schwachheit an, nimm mir des Kleinmuts Bann,\ndass ich obsiegen kann, lehre mich fleh\'n!\r\nLehre mich glauben, Herr, lehre mich fleh\'n!\nJesus, du kommst ja bald, lehre mich fleh\'n!\nO, dass du gnädig dann mein Werk kannst schauen an,\ndass ich bestehen kann, lehre mich fleh\'n!'),
(9, '1198', 'Lehre mich glauben, lehre mich lieben   (Glaube und Hoffnung und Liebe, die drei)', NULL, 'Lehre mich glauben, lehre mich lieben,\nauf dass die Ströme fließen von mir!\nLehre mich glauben, lehre mich lieben,\nauf dass ich Seelen kann führen zu Dir!\r\nGlaube und Hoffnung und Liebe, die drei;\naber die Liebe die größte sei!\nDarum so glaube und hoffe ich\ndass Du mit Liebe füllest mich.\r\nSanftmut und Demut, Friede und Freude\nist einer Brautseele Diadem;\nden Schmuck Er suchet, wenn einst erschallet:\nAuf, um dem Bräutgam entgegenzugehn!\r\nBald Er erscheinet, die Braut zu holen.\nWas wird Er suchen an dir und mir?\nNichts als Sein Wesen, und das ist Liebe!\nO Jesu, strahle Du wider in mir!'),
(9, '1199', 'Leise und inniglich mahnet der Heiland  -  Softly and tenderly Jesus is calling   (Komm heim, komm heim)', 'Softly and tenderly Jesus is calling,\ncalling for you and for me.\nSee on the portals He\'s waiting and watching.\nWatching for you and for me.\r\nCome home, come home,\nye who are weary, come home.\nEarnestly, tenderly, Jesus is calling,\ncalling, oh, sinner, come home!\r\nWhy should we tarry when Jesus is pleading,\npleading for you and for me?\nWhy should we linger and heed not His mercies,\nmercies for you and for me?\r\nTime is now fleeting, the moments are passing,\npassing from you and from me.\nShadows are gathering, death\'s night is coming,\ncoming for you and for me.\r\nOh! For the wonderful love He has promised,\npromised for you and for me.\nThough we have sinned, He has mercy and pardon,\npardon for you and for me.', 'Leise und inniglich mahnet der Heiland,\nruft die Verlor\'nen zum Heil,\nsteht vor der Türe des Herzens und wartet;\nöffne Ihm, Er ist dein Teil.\r\nKomm heim, komm heim.\nSeele, vernimm es, komm heim!\nHorch, wie dein Heiland dich flehentlich rufet;\ngib Ihm dein Herze, komm heim!\r\nKannst du noch warten? Ach, siehe, dein Heiland\nflehet so innig und warm,\nsuchet so emsig sein irrendes Schäflein;\nWarten bringt ewiglich Harm.\r\nFlüchtig sind hier unsre Stunden und Tage,\nbald ist die Arbeit getan.\nSieh, wie im Westen die Schatten sich mehren!\nBald bricht die Ewigkeit an.\r\nO welche Wunder der göttlichen Liebe,\ndie uns in Jesu erscheint!\nKennst du, mein Bruder, den Retter der Seelen?\nIst Er dein Heiland und Freund?'),
(9, '1200', 'Let everything within me, cry Holy   (3 Chorusse)', 'Let everything within me, cry Holy.\nLet everything within me, cry Holy.\nHoly, Holy, Holy is the Lamb that was slain.\r\nLet everything within me, cry Glory.\nLet everything within me, cry Glory.\nGlory, glory, glory to the Lamb that was slain.\r\nLet everything within me, cry Jesus.\nLet everything within me, cry Jesus.\nJesus, Jesus, Jesus is the Lamb that was slain.', NULL);
INSERT INTO song_list (LISTID, NUM, NAME, TEXT_EN, TEXT_DE) VALUES
(9, '1201', 'Let go of the old and lay hold on the new', 'Let, let go of the old,\nand lay, lay hold on the new,\nin laying it down a new life is found,\nthere a new life waits for you.\r\nCast your bread upon the waters,\nafter many days it shall return.\nIf you pour out your soul\nnot a part, but the whole,\na new life is there for you.\r\nIn saving your life, you will lose it,\nbut by losing your life, you will find it.\nDown in the ground that\'s where life is found,\nthere a new lif waits for you.', NULL),
(9, '1202', 'Let Him breathe on me   (Chorus)', 'Let Him breathe on me,\nlet Him breathe on me,\nlet the Holy Ghost now breathe on me. (2x)', NULL),
(9, '1203', 'Let not your Heart be troubled  -  Euer Herz erschrecke nicht   (Johannes 14, Vers 1+2)', 'Let not your heart be troubled,\nye believe in God, believe also in Me.\nIn My Father\'s house are many mansions.\nIf it were not so I would have told you.\r\nI go to prepare a place for you.\nAnd if I go and prepare a place for you,\nI will come again\nand receive you unto Myself,\nThat where I am, there ye may be also.', 'Euer Herz erschrecke nicht\nglaubt an Gott und glaubt an mich!\nIn Hause Meines Vaters sind viele Wohnungen.\nWenn es nicht so wäre, dann hätte Ich es euch gesagt.\r\n(Ich gehe hin um euch einen Platz vorzubereiten.\nUnd wenn ich hingehe und euch einen Platz vorbereitet habe,\ndann will ich wiederkommen und euch zu mir nehmen,\ndamit auch ihr seid, wo Ich bin.)'),
(9, '1204', 'Let the Lord have His Way in your Heart   (Chorus)', 'Let the Lord have His way  in your heart every day.\nThere\'s no rest, there\'s no peace \'til the Lord has His way.\nPlace your life in His hands, rest secure in His plans.\nLet the Lord, let the Lord have His way.', NULL),
(9, '1205', 'Let us go back to Church   (2 Chorusse)', 'Let us go back to church,\nLet us go back to church.\nJesus is coming back,\nLet us go back to church.\r\nWe have come to worship the Lord.\nWe have come to worship the Lord.\nWe have come back to church.\nWe have come to worship the Lord.', NULL),
(9, '1206', 'Let Your Anointing fill this Place   (Chorus)', '/: Let Your anointing fill this place :/ 4x\nCome down as we worship You,\ncome down as we praise Your name,\ncome down as we magnify.\nLet Your anointing fill this place.', NULL),
(9, '1207', 'Let Your Glory fall', 'Let Your glory fall\nWe are thirsty Lord\nHear us as we call\nFill us now\nLet Your glory fall\nLet Your glory fall\nLet Your glory fall\r\nEvery tongue and tribe\nGathered round Your throne\nWith one voice we cry\nHoly Lord\nEvery tongue and tribe\nEvery tongue and tribe\nEvery tongue and tribe\r\nGlory to the Lamb\nLamb upon the throne\nAll the saints proclaim\nJesus reigns\nJesus reigns\nJesus reigns\nJesus reigns\nGlory to the Lamb\nGlory to the Lamb\nGlory to the Lamb', NULL),
(9, '1208', 'Leuchtend strahl des Vaters Gnade  -  Brightly beams our Father\'s Mercy   (Lasst die Küstenfeuer brennen)', 'Brightly beams our Father\'s mercy,\nfrom His lighthouse evermore.\nBut to us He gives the keeping,\nof the lights along the shore.\r\nLet the lower lights be burning,\nsend a gleam across the wave.\nSome poor fainting, struggling seaman,\nyou may rescue, you may save.\r\n\r\nDark the night of sin has settled,\nLoud the angry billows roar.\nEager eyes are watching, longing,\nfor the lights along the shore.\r\n\r\nTrim your feeble lamp, my brother,\nsome poor sailor tempest tossed.\nTrying now to make the harbour,\nin the darkness may be lost.', 'Leuchtend strahlt des Vaters Gnade,\naus dem ober\'n Heimatland.\nDoch uns hat er anvertrauet,\nRettungslichter längs dem Strand.\r\nLasst die Küstenfeuer brennen,\nlasst sie leuchten weit hinaus.\nDenn sie zeigen manchem Schiffer\nsicherlich den Weg nach Haus.\r\nUnser Weg war fern vom Lichte,\nunser Herz in Schuld und Qual.\nDoch aus Jesu Angesichte\nleuchtete der Liebe Strahl.\r\nDunkel ist die Nacht der Sünde,\nschaurig klingt der Wogen Lied.\nManches Auge sucht voll Sehnsucht,\nob\'s am Strande Lichter sieht.\r\nJesus hat uns ausgesendet,\nwie der Vater Ihn gesandt.\nDass die Liebe Gottes strahle\nda, wo man Ihn nicht gekannt.\r\nLass dein Licht noch nicht verlöschen,\nsonst vielleicht zu dieser Stund\'.\nWeil es nicht den Hafen findet,\nsinkt ein Schifflein auf den Grund.'),
(9, '1209', 'Licht dieser Welt Du strahlst in unsrer Nacht auf  -  Light of the World you came down into darknes   (Ich will Dich anbeten, will mich vor Dir beugen)', 'Light of the world, You stepped down into darkness,\nopened my eyes, let me see.\nBeauty that made this heart adore You,\nhope of a life spent with You.\r\nAnd here I am to worship,\nHere I am to bow down,\nhere I am to say that You\'re my God.\nYou\'re altogether lovely,\naltogether worthy,\naltogether wonderful to me.\r\nKing of all days oh so highly exalted,\nglorious in heaven above.\nHumbly you came to the earth You created,\nall for love\'s sake became poor.\r\nI\'ll never know how much it cost,\nto see my sin upon that cross.\nI\'ll never know how much it cost,\nto see my sin upon that cross.', 'Licht dieser Welt, Du strahlst in uns\'rer Nacht auf,\nleuchtest den Weg, lässt mich seh\'n.\nHerr Deine Schönheit lässt mich anbeten,\newig werd\' ich vor Dir steh\'n.\r\nIch will Dich anbeten, will mich vor Dir beugen,\nwill Dir sagen, Du nur bist mein Gott.\nDenn Du allein bist herrlich, Du allein bist würdig,\nDu nur bist vollkommen gut zu mir.\r\nHerr aller Zeiten Du bist hoch erhaben,\nherrlich im Himmel erhöht.\nDoch voller Demut kamst Du auf die Erde,\nzeigst worin Liebe besteht.\r\nHerr nie begreife ich die Last,\ndie Du am Kreuz getragen hast.\nHerr nie begreife ich die Last,\ndie Du am Kreuz getragen hast.'),
(9, '1210', 'Licht nach dem Dunkel, Friede nach Streit  -  Light after Darkness, Gain after Loss', 'Light after darkness, gain after loss,\nstrength after weakness, crown after cross.\nSweet after bitter, hope after fears,\nhome after wandering, praise after tears.\r\nSheaves after sowing, sun after rain,\nsight after mystery, peace after pain.\nJoy after sorrow, calm after blast,\nrest after weariness, sweet rest at last.\r\nNear after distant, gleam after gloom,\nlove after loneliness, life after tomb.\nAfter long agony rapture of bliss,\nright was the pathway leading to this.', 'Licht nach dem Dunkel, Friede nach Streit,\nJubel nach Tränen, Wonne nach Leid,\nSonne nach Regen, Lust nach der Last,\nnach der Ermüdung selige Rast.\r\nFreude nach Trauer, Heilung nach Schmerz,\nnach dem Verluste Tröstung ins Herz.\nKraft nach der Schwachheit, Ruhm nach der Schmach,\nSturm muss sich legen, Stille darnach.\r\nRuhe nach Mühe, Ehre nach Hohn,\nnach den Beschwerden herrlicher Lohn.\nLabsal nach Trübsal, Krone nach Kreuz,\nSüßes nach Bitt\'rem, o wie erfreut\'s!'),
(9, '1211', 'Licht strahlt von ferne, Seemann, Hilfe ist nah  -  Light in the Darkness, Sailor, Day is at hand   (Auf, auf ans Land, Seemann, auf, auf ans Land)', 'Light in the darkness, sailor, day is at hand!\nsee o’er the foaming billows fair haven’s land,\ndrear was the voyage, sailor, now almost o’er,\nsafe within the life boat, sailor, pull for the shore.\r\nPull for the shore, sailor, pull for the shore!\nheed not the rolling waves, but bend to the oar.\nSafe in the life boat, sailor, cling to self no more!\nleave the poor old stranded wreck, and pull for the shore.\r\nTrust in the life boat, sailor, all else will fail.\nStronger the surges dash and fiercer the gale,\nheed not the stormy winds, though loudly they roar.\nWatch the bright and morning Star, and pull for the shore!\r\nBright gleams the morning, sailor, uplift the eye,\nclouds and darkness disappearing, glory is nigh!\nSafe in the life boat, sailor, sing evermore,\nglory, glory, hallelujah! pull for the shore.', 'Licht strahlt von ferne, Seemann, Hilfe ist nah.\nHorch! Durch des Sturms Gebraus tönt\'s: Rettung ist da!\nSchwer war des Schiffbruchs Leiden, heiß war der Stand,\nkomm ins Rettungsboot, o Seemann! Auf, auf ans Land!\r\nAuf, auf ans Land, Seemann, auf, auf ans Land!\nFürchte die Wellen nicht mehr! Halt fest die Hand!\nTrau deinem Retter, trau dem eignen ich nicht mehr!\nLass das alte, lecke Wrack versinken ins Meer!\r\nO, trau dem Rettungsboote, trau deinem Herrn!\nEr nur kann Seelen retten, Er tut es gern.\nLass nur das Wetter toben, pack\' Seine Hand;\nblick auf diesen Stern mit Freuden, Er führt an Land.\r\nSieh, wie der Morgen dämmert, heb\' auf den Blick;\nsiehe, wie Nacht und Dunkel weichen zurück!\nWohl dir im Rettungsboote, heb\' deine Hand;\nHalleluja! Jauchze fröhlich: auf, auf ans Land!'),
(9, '1212', 'Liebe tiefer als die Meere  -  Love deeper than the Seas   (Preis sei Ihm für diese Liebe)', 'Love, deeper than the seas,\nGrace, great as a flood,\nHe, the king of our soul\ngave for us His own blood!\r\nPraise be to Him for this love,\nPraise be to him for all time,\nunforgotten His Grace\nfor all eternity!\r\nOn the mountain where He hung on the cross,\nthe deep source opened,\nthrough the floodgates of His grace\nshe flowed out into the world.\r\nGreat waters, mighty floods\nare flowing down on us now,\nand a deep heavenly peace\nflows through us by His grace\'.', 'Liebe, tiefer als die Meere,\nGnade, groß wie eine Flut,\nEr, der König uns\'rer Seele\ngab für uns Sein eig\'nes Blut!\r\nPreis sei Ihm für diese Liebe,\nPreis sei Ihm für alle Zeit,\nunvergessen Seine Gnade\nbis in alle Ewigkeit!\r\nAuf dem Berg, wo Er am Kreuz hing,\nging die tiefe Quelle auf,\ndurch die Schleusen Seiner Gnade\nfloss sie in die Welt hinaus.\r\nGroße Wasser, mächt\'ge Fluten\nfließen jetzt auf uns herab,\nund ein tiefer Himmelsfriede\nströmt durch uns durch Seine Gnad\'.'),
(9, '1213', 'Liebster Jesus wir sind hier, Dich und Dein Wort anzuhören', NULL, 'Liebster Jesus, wir sind hier,\nDich und Dein Wort anzuhören.\nLenke Sinnen und Begier\nauf die süßen Himmelslehren,\ndass die Herzen von der Erden\nganz zu Dir gezogen werden!\r\nUnser Wissen und Verstand\nist mit Finsternis umhüllet,\nwo nicht Deines Geistes Hand\nuns mit hellem Licht erfüllet.\nGutes denken, tun und dichten\nmusst Du selbst in uns verrichten.\r\nO Du Glanz der Herrlichkeit,\nLicht vom Licht, aus Gott geboren,\nmach uns allesamt bereit,\nöffne Herzen, Mund und Ohren!\nUnser Bitten, Fleh\'n und Singen\nlass, Herr Jesus, wohlgelingen!'),
(9, '1214', 'Liebwerter, süßer Gotteswille, mein Ankergrund, mein sicheres Schloss   (O süßer, teurer Gotteswille)', NULL, 'Liebwerter, süßer Gotteswille,\nmein Ankergrund, mein sicheres Schloss,\ndes Geistes unverrückte Stille,\nich schmiege mich in Deinen Schoss.\r\nO süßer, teurer Gotteswille,\nschließ\' mich noch inniger an Dich,\nbis in des Heiligtumes Stille\nnur Du verfügest über mich!\r\nO Wille, der mich ganz verlanget,\nich geb\' mich Deiner Leitung hin.\nMein Herz an Deiner Brust stets hanget\nin still gelassenem Kindersinn.\r\nWenn Welt und Sünd\' und Teufel stürmen,\ngedenk\' ich nur: Gott will es so,\nEr wird dich stärken und beschirmen.\nSo werd\' ich mutig, still und froh.\r\nKann ich im Finstern Dich nicht sehen,\nso halt ich mich im Glauben still.\nDein Will wird doch in mir geschehen,\nwenn ich nichts aus mir selber will.\r\nO Gottes Wille, mein Verlangen,\nmein Brot in Mangel und in Pein,\no Gottes Will, nimm mich gefangen,\nso wird mein Wille frei und rein.'),
(9, '1215', 'Lies die Bibel, bet jeden Tag  -  Read your Bible, pray every Day   (Chorus)', 'Read your bible, pray every day, pray every day, pray every day.\nRead your the bible, pray every day, if you want to grow.\nIf you want to grow, if you want to grow,\nread your bible, pray every day, if you want to grow.', 'Lies die Bibel, bet\' jeden Tag, bet\' jeden Tag, bet\' jeden Tag.\nLies die Bibel, bet\' jeden Tag, wenn du wachsen willst,\nwenn du wachsen willst, wenn du wachsen willst.\nLies die Bibel, bet\' jeden Tag, wenn du wachsen willst.'),
(9, '1216', 'Life is a few Days of Trouble a wise Man once said', 'Life is a few days of trouble a wise man once said,\nBut I\'ll not complain, for I\'m sheltered, I\'m clothed, and I\'m fed.\nBut many\'s the trial my wants and my dreams put me through,\nAnd the only real peace that I have, dear Lord, is in You.\r\nThe only real peace that I have, dear Lord, is in You.\nThe only real peace that I have, dear Lord, is in You.\nWith all life\'s frustrations, I need You, I know I do.\n\'Cause the only real peace that I have, dear Lord, is in You.\r\nThe higher I\'ve soared in my dreams the harder I fall\nand sometimes I\'ve wondered if dreams are worth dreamin at all.\nBut my disappointments can\'t keep me blinded and blue.\nNot when I\'m reminded of sweet peace I have, Lord, in You.', NULL),
(9, '1217', 'Live in me Lord, live in me   (2 Chorusse)', 'Live in me Lord, live in me,\nhere\'s my heart Lord,\nlet it be, consecrated Lord to Thee,\ntake my life Lord, live in me.\r\nHallelujah I am free,\nChrist has given liberty.\nThe Holy Spirit is the key,\nHallelujah Christ in me.', NULL),
(9, '1218', 'Live, christian Live, live a Life of Holiness', 'Live a christian live, live a life of holiness.\nLive a christian live, live a life of holiness.\nIf you cannot testify live,\nIf you cannot preach you can live.\nFor you cannot hide from the eyes of the Lord,\nlive a christian live.', NULL),
(9, '1219', 'Lob und Dank, Gottes Kinder sagen immer Lob und Dank   (Chorus)', NULL, '||: Lob und Dank, Lob und Dank, Lob und Dank,\nGottes Kinder sagen immer: "Lob und Dank!" :||\nJedes Weh wurde gut, durch des Heilandes Blut.\nLob und Dank, Lob und Dank, Lob und Dank,\nGottes Kinder sagen immer: "Lob und Dank!"'),
(9, '1220', 'Lob\' den Herrn, meine Seele und was in mir ist, Seinen heiligen Namen   (Lob\' den Herrn, meine Seel)', NULL, 'Der dir alle deine Sünden vergibt\nund all\' deine Gebrechen heilt,\nder dein Leben vom Verderben erlöst.\nDer dir alle deine Sünden vergibt\nund all\' deine Gebrechen heilt,\nder dich krönt mit Gnade und Barmherzigkeit.\r\nLob\' den Herrn, meine Seel\'\nund was in mir ist, Seinen heiligen Namen.\nLob\' den Herrn, meine Seel\'\nund vergiss nicht, was Er dir Gutes getan hat.\r\nBarmherzig und gnädig ist Er,\ngeduldig und von großer Güte,\nder dein Leben vom Verderben erlöst.\nBarmherzig und gnädig ist Er,\ngeduldig und von großer Güte,\nder dich krönt mit Gnade und Barmherzigkeit.'),
(9, '1221', 'Lobe den Herren den mächtigen König der Ehren  -  Praise to the Lord, the Almighty, the King of Creation', 'Praise to the Lord, the Almighty, the King of creation!\nO my soul, praise him, for He is your health and salvation!\nCome, all who hear; now to His temple draw near,\njoin me in glad adoration.\r\nPraise to the Lord, above all things so wondrously reigning.\nSheltering you under His wings, and so gently sustaining!\nHave you not seen, all that is needful has been\nsent by His gracious ordaining?\r\nPraise to the Lord, Who will prosper your work and defend you.\nSurely His goodness and mercy shall daily attend you.\nPonder anew, what the Almighty can do,\nif with His love he befriends you.\r\nPraise to the Lord, who doth prosper thy work and defend thee.\nSurely His goodness and mercy here daily attend thee.\nPonder anew, what The Almighty can do,\nif with His love He befriend thee.\r\nPraise to the Lord! O let all that is in me adore Him!\nAll that has life and breath, come now with praises before Him.\nLet the Amen, sound from his people again,\ngladly forever adore Him.', 'Lobe den Herren, den mächtigen König der Ehren!\nLob ihn, o Seele, vereint mit den himmlischen Chören!\nKommet zu Hauf, Psalter und Harfe, wacht auf,\nlasset den Lobgesang hören!\r\nLobe den Herren, der alles so herrlich regieret,\nder wie auf Flügeln des Adlers dich sicher geführet,\nder dich erhält, wie es dir selber gefällt;\nhast du nicht dieses verspüret?\r\nLobe den Herren, der künstlich und fein dich bereitet,\nder dir Gesundheit verliehen, dich freundlich geleitet:\nIn wie viel Not hat nicht der gnädige Gott\nüber dir Flügel gebreitet!\r\nLobe den Herren, der deinen Stand sichtbar gesegnet,\nder aus dem Himmel mit Strömen der Liebe geregnet;\ndenke daran, was der Allmächtige kann,\nder dir mit Liebe begegnet!\r\nLobe den Herren, was in mir ist, lob\' Seinen Namen!\nAlles, was Odem hat, lobe mit Abrahams Samen!\nEr ist dein Licht; Seele vergiss es ja nicht,\nlob\' ihn in Ewigkeit! Amen.'),
(9, '1222', 'Lobe den Herren, o meine Seele', NULL, 'Lobe den Herren, o meine Seele!\nIch will Ihn loben bis in den Tod;\nweil ich noch Stunden auf Erden zähle,\nwill ich lobsingen meinem Gott.\nDer Leib und Seele gegeben hat,\nwerde gepriesen früh und spat.\nHalleluja, Halleluja.\r\nFürsten sind Menschen, vom Weib geboren,\nund kehren um zu ihrem Staub;\nihre Anschläge sind auch verloren,\nwenn nun das Grab nimmt seinen Raub.\nWeil denn kein Mensch uns helfen kann,\nrufe man Gott um Hilfe an.\nHalleluja, Halleluja.\r\nSelig, ja selig ist der zu nennen,\ndes Hilfe der Gott Jakobs ist,\nwelcher vom Glauben sich nicht lässt trennen\nund hofft getrost auf Jesus Christ.\nWer diesen Herrn zum Beistand hat,\nfindet am besten Rat und Tat.\nHalleluja, Halleluja.\r\nDieser hat Himmel, Meer und die Erden\nund was darinnen ist gemacht;\nalles muss pünktlich erfüllet werden,\nwas er uns einmal zugedacht.\nEr ist\'s, der Herrscher aller Welt,\nwelcher uns ewig Treue hält.\nHalleluja, Halleluja.\r\nZeigen sich welche, die Unrecht leiden,\nEr ist\'s, der ihnen Recht verschafft;\nHungrigen will er die Speise bereiten,\nwas ihnen dient zur Lebenskraft;\ndie hart Gebund\'nen macht er frei,\nund seine Gnad\' ist mancherlei.\nHalleluja, Halleluja.\r\nSehende Augen gibt Er den Blinden,\nerhebt, die tief gebeuget geh\'n;\nwo Er kann einige Fromme finden,\ndie lässt Er seine Liebe seh\'n.\nSein Aufsicht ist des Fremden Trutz,\nWitwen und Waisen hält er Schutz.\nHalleluja, Halleluja.\r\nAber der Gottesvergess\'nen Tritte\nkehrt Er mit starker Hand zurück,\ndass sie nur machen verkehrte Schritte\nund fallen selbst in ihren Strick.\nDer Herr ist König ewiglich;\nZion, dein Gott sorgt stets für dich.\nHalleluja, Halleluja.\r\nRühmet, ihr Menschen, den hohen Namen\ndes, der so große Wunder tut.\nAlles, was Odem hat, rufe Amen\nund bringe Lob mit frohem Mut.\nIhr Kinder Gottes, lobt und preist\nVater und Sohn und Heilgen Geist!\nHalleluja, Halleluja.'),
(9, '1223', 'Lobe den Herrn, meine Seele, und Seinen heiligen Namen   (Psalm 103)', NULL, 'Lobe den Herrn, meine Seele,\nund Seinen heiligen Namen.\nWas Er dir Gutes getan hat,\nSeele, vergiss es nicht, Amen.\nLobe, lobe den Herrn,\nlobe den Herrn, meine Seele.\nLobe, lobe den Herrn,\nlobe den Herrn, meine Seele.\r\nDer meine Sünden vergeben hat,\nDer mich von Krankheit gesund gemacht,\nDen will ich preisen mit Psalmen und Weisen,\nvon Herzen Ihm ewiglich singen:\r\nDer mich im Leiden getröstet hat,\nDer meinen Mund wieder fröhlich macht,\nDen will ich preisen mit Psalmen und Weisen,\nvon Herzen Ihm ewiglich singen:\r\nDer mich vom Tode errettet hat,\nDer mich behütet bei Tag und Nacht,\nDen will ich preisen mit Psalmen und Weisen,\nvon Herzen Ihm ewiglich singen:\r\nDer Erd\' und Himmel zusammenhält,\nunter Sein göttliches Jawort stellt,\nDen will ich preisen mit Psalmen und Weisen,\nvon Herzen Ihm ewiglich singen:'),
(9, '1224', 'Lobet den Herrn   (Chorus)', NULL, '||: Lobet den Herrn!\nDenn unser\'n Gott loben,\ndas ist ein köstlich Ding.\nSolch Lob ist lieblich und schön! :||'),
(9, '1225', 'Lobpreis und Anbetung', NULL, 'Lobpreis und Anbetung\nbringen wir heut\'\nunserem Gott (2x)\r\nDenn Er ist es wert,\ndass man Ihn ehrt,\nja, Er ist würdig,\nnur Er allein! (2x)'),
(9, '1226', 'Lobt den Herrn der mich erkauft  -  Oh, I praise the Lord who bought me   (Ja, ich preis\' Ihn, Halleluja)', 'Oh, I praise the Lord who bought me, hallelujah!\nI’m a happy pilgrim bound for glory land.\nI am singing, and I hope to sing forever,\nwhen before His throne eternal I shall stand.\r\nI will praise Him, hallelujah!\nI will praise Him more and more.\nIf I had ten thousand lives in which to praise Him\ni could not enough my blessed Lord adore.\r\nI will praise Him for salvation, hallelujah!\nRichest treasure human spirits ever found.\nOnce I wandered far away, was sad and lonely,\nbut I’m dwelling now where pleasures e’er abound.\r\nOh, I’ll never cease to praise Him, hallelujah!\nFor He gives me peace abounding every day.\nHe redeemed me from my sins and fully cleansed me,\nand I find His service sweeter all the way.\r\nI will praise the name of Jesus, hallelujah!\nI will praise Him for His mercies unto me.\nThen I’ll praise Him with the angels in the morning,\nwhen the face of my dear Saviour I shall see.\r\nOh, I praise Him for the strength He daily gives me,\nI am running now to gain that heav’nly prize.\nSoon with joy I’ll reach the goal of life immortal,\nand go sweeping through the gates of paradise.', 'Lobt den Herrn der mich erkauft, o Halleluja!\nich den schmalen Lebensweg nun freudig geh\'.\nJa, ich singe, hoffe immerdar zu singen,\nwenn ich vor dem ew\'gen Throne Gottes steh\'.\r\nJa, ich preis\' Ihn. Halleluja!\nWill Ihn preisen mehr und mehr.\nHätte ich zehntausend Leben, Ihn zu preisen,\nkönnt\' ich doch nie genug Ihn preisen hier.\r\nO ich preis\' Ihn für Erlösung, Halleluja!\nGrößter Reichtum, den der Menschensinn erkannt.\neinst war ich verirrt und war auf dem breiten Wege,\ndoch in Jesus Christus ew\'ges Heil ich fand.\r\nIch will immerdar Ihn preisen, Halleluja!\nFreud\' und Frieden Er gewährt mir allezeit.\nEr hat mich erlöst und hat mein Herz gereinigt,\nund in Seinem Dienst find\' ich Zufriedenheit.\r\nJesu Namen will ich preisen, Halleluja!\nUnd will rühmen Seine Gnade, die mein Teil.\nDenn dereinst am großen Auferstehungsmorgen\nseh\'n wir den, der uns erworben ew\'ges Heil.\r\nO ich preis Ihn für die Kraft, die Er verleihet,\nund dem vorgesteckten Ziel ich eile zu.\nBald ich gehe durch des Himmels schöne Pforte,\nwo ich ewiglich genieße süße Ruh\'."'),
(9, '1227', 'Lobt froh den Herrn ihr jugendlichen Chöre  -  Praise ye the Lord in simple, joyous Measure', 'Praise ye the Lord in simple, joyous measure;\nHe hears each word of children\'s praise and pleasure.\nPraise ye the Lord, praise ye the Lord!\r\nPraise ye the Lord, your youthful voices\nblending in sweet accord.\nPraise God with joy unending.\nPraise ye the Lord, praise ye the Lord!\r\nHis praise alone our hearts would render ever;\nup to His throne ascends our weak endeavour.\nAccept may He our earnest plea.\nPraise ye the Lord, praise ye the Lord!\r\n\r\nIn glory we our heav\'nly Father praising\nand happily new songs unnumbered raising,\nfor evermore, for evermore!', 'Lobt froh den Herrn, ihr jugendlichen Chöre!\nEr höret gern ein Lied zu Seiner Ehre.\nLobt froh den Herrn, lobt froh den Herrn!\r\nEs schallt empor zu Deinem Heiligtume\naus unserm Chor ein Lied zu Deinem Ruhme,\nDu, der sich Kinder auserkor\'.\nLobt froh den Herrn, lobt froh den Herrn!\r\nVom Preise voll, lass unser Herz Dir singen!\nDas Loblied soll zu Deinem Throne dringen,\ndas Lob, das unsrer Seel\' entquoll\'.\nLobt froh den Herrn, lobt froh den Herrn!\r\nWir stammeln hier; doch hörst Du unser Lallen\nund lässt es Dir in Gnaden wohlgefallen.\nDir jauchzen wir, Dir singen wir.\nLobt froh den Herrn, lobt froh den Herrn!\r\nEinst kommt die Zeit,\nwo wir auf tausend Weisen,\no Seligkeit! Dich, unsern Vater, preisen\nvon Ewigkeit zu Ewigkeit.'),
(9, '1228', 'Lobt in Seinem Heiligtume den, der große Wunder tut', '\r\nHalleluja, Halleluja,\nHalleluja, Amen.\r\n\r\n', 'Lobt in Seinem Heiligtume\nDen, der große Wunder tut,\nder zu seinem höchsten Ruhme\nbei erlösten Kindern ruht.\r\n\r\nLobet Ihn mit Freudentränen,\npreiset Ihn mit Harfenklang.\nLasst uns unsern König krönen,\nschalle Ihm, o Lobgesang.\r\nJauchzet Ihm mit ewger Freude,\ndie ihr Seinen Odem habt.\nRühmt, geschmückt im weißen Kleide,\nDen, der euch so hoch begabt.'),
(9, '1229', 'Lord have Mercy on us, come and heal our Land   (Chorus)', 'Lord have mercy on us, come and heal our land.\nCleanse with Your fire, heal with Your touch,\nhumble we bow and call upon You now.\nOh, Lord have mercy on us.', NULL),
(9, '1230', 'Lord I can feel Your Presence   (3 Chorusse)', 'Lord I can feel Your presence\nin this place.\nLord I can feel Your presence\nin this place.\r\nLord I can feel the anointing\nin this place.\nLord I can feel the anointing\nin this place.\r\nLord I can feel Your Spirit\nin this place.\nLord I can feel Your Spirit\nin this place.', NULL),
(9, '1231', 'Lord I want to be a Christian in my Heart   (2 Chorusse)', 'Lord I want to be a christian in my heart.\nLord I want to be a christian in my heart.\nIn my heart, in my heart.\nLord I want to be a christian in my heart.\r\nLord I want to be more holy...\nLord I want to be more holy...', NULL),
(9, '1232', 'Lord, I have started to walk in the Light   (I\'m going through, I\'m going through)', 'Lord, I have started to walk in the light,\nshining upon me from heaven so bright.\nI bade the world and its follies adieu,\nI\'ve started in Jesus and I\'m going through.\r\nI\'m going through, I\'m going through.\nI\'ll pay the price whatever others do,\nI\'ll take the way with the Lord\'s despised few,\nI\'m going through, Jesus, I\'m going through.\r\nOh, there are many who start in the race,\nbut with the light refuse to keep pace.\nOthers accept it because it is new,\nbut not very many expect to go through.\r\nI\'d rather walk with Jesus alone,\nhave for a pillow, like Jacob, a stone.\nLiving each moment with His face in view,\nthan shrink from my pathway and fail to go through.\r\nO brother, now will you take up the cross?\nGive up the world and count it as dross.\nSell all thou hast and give to the poor,\nthen go through with Jesus and those who endure.', '(Herr, ich habe begonnen im Licht zu wandeln,\ndas so hell vom Himmel auf mich scheint.\nIch habe der Welt und ihren Torheiten adieu gesagt,\nIch habe in Jesus angefangen und gehe hindurch.)\r\n(Ich gehe da durch, ja, ich gehe da durch.\nIch werde den Preis bezahlen, was auch immer andere tun,\nich werde den Weg mit den wenigen Verachteten des Herrn gehen,\nIch gehe da durch, Jesus, ich gehe da durch. )\r\n(Oh, es gibt viele, die im Rennen starten,\nsich aber weigern, mit dem Licht Schritt zu halten.\nAndere akzeptieren es, weil es neu ist,\naber nicht sehr viele erwarten, dass sie durchkommen.)\r\nIch will lieber mit Jesus allein gehen,\nwie Jakob einen Stein als Kopfkissen haben.\nJeden Augenblick mit Seinem Antlitz im Blick leben,\nals vor meinem Weg zurück zu schrecken und ihn nicht zu gehen.\r\nO Bruder, willst du nun das Kreuz auf dich nehmen?\nGib die Welt auf und zähle sie als Schlacke.\nVerkaufe alles, was du hast, und gib es den Armen,\ndann geh mit Jesus und denen, die ausharren, durch.'),
(9, '1233', 'Lord, I lift Your Name on high  -  Herr, ich erhebe Deinen Namen', 'Lord, I lift Your name on high.\nLord, I love to sing Your praises.\nI\'m so glad You\'re in my life.\nI\'m so glad You came to save us.\r\nYou came from Heaven to earth,\nto show the way,\nfrom the earth to the cross,\nmy debt to pay.\nfrom the cross to the grave,\nfrom the grave to the sky.\nLord, I lift Your name on high! (2x)', '(Herr, ich erhebe Deinen Namen.\nHerr, ich liebe es, Dein Loblied zu singen.\nIch bin so froh, dass Du in meinem Leben bist.\nIch bin so froh, dass Du gekommen bist, um uns zu retten.)\r\n(Du bist vom Himmel auf die Erde gekommen,\num den Weg zu zeigen,\nvon der Erde zum Kreuz,\num meine Schuld zu bezahlen.\nvom Kreuz zum Grab,\nvom Grab zum Himmel.\nHerr, ich erhebe Deinen Namen!) (2x)'),
(9, '1234', 'Lord, I need You right now    Herr, ich brauche Dich grad jetzt   (Chorus)', 'Lord, I need You right now,\nLord, I need You right now,\nI want all of my life\nin Your keeping somehow.\nLord, I need You right now.', '(Herr, ich brauche Dich grad jetzt,\nHerr, ich brauche Dich grad jetzt,\nIch will mein ganzes Leben\nirgendwie in Deine Obhut geben.\nHerr, ich brauche Dich grad jetzt.)'),
(9, '1235', 'Lord, I\'m coming now to Thee   (Chorus)', 'Lord, I\'m coming now to Thee,\nlay Thy nail scarred hand on me.\nLet Thy healing virtue flow\nand I shall be made whole.', NULL),
(9, '1236', 'Lord, my Desire, is to be like You   (Chorus)', 'Lord, my desire, is to be like You.\nI say the things You say, do the things You do.\nLet me hear Your still voice, through all the other noise,\nso that I can be, what You want me to be.', NULL),
(9, '1237', 'Lord, my Heart can grow so far away and cold  -  Herr, mein Herz kann so weit weg sein und kalt werden   (Lord I lift Your Name, Your holy Name)', 'Lord, my heart can grow so far away and cold,\nand yet for me Your love is still the same.\nLord, I bend my knee in awe and fear of Thee,\nmy head bowed down in rev\'rence to Your name.\r\nLord I lift Your name, Your holy name,\nJehovah God, Elohim.\nThe Great I AM, the Risen Lamb,\nmy Comforter and King.\r\nLord, my heart\'s desire is to be fillled with Spirit Fire,\nmy purpose is to worship You alone.\nOpen up my soul to worship and adore,\nto be a fragrance offered to Your throne.', 'Herr, mein Herz kann so weit weg sein und kalt werden,\nund doch ist für mich Deine Liebe noch dieselbe.\nHerr, ich beuge mein Knie in Ehrfurcht und Furcht vor Dir,\nmein Haupt niedergebeugt in Ehrfurcht vor Deinem Namen.\r\nHerr, ich erhebe Deinen Namen, Deinen heiligen Namen,\nJehovah Gott, Elohim.\nDer große ICH BIN, das auferstandene Lamm,\nmeinen Tröster und König.\r\nHerr, der Wunsch meines Herzens ist es, mit dem Feuer des Geistes erfüllt zu werden,\nmein Ziel ist es, Dich allein anzubeten.\nÖffne meine Seele zur Anbetung und Verehrung,\num ein Duft zu sein, der Deinem Thron dargebracht wird.'),
(9, '1238', 'Lord, You are El Elohim', 'Lord, You are El Elohim,\nthat\'s why I come unto You.\nLord, You are El Elohim, I worship You.\nShow me Your glory, show me who You are.\nShow me Your glory,\nI want to know You Lord.', NULL),
(9, '1239', 'Lord, You are more precious than Silver   (Chorus)', 'Lord, You are more precious than silver,\nLord, You are more costly than gold.\nLord, You are more beautiful than diamonds,\nand nothing I desire compares with You.', NULL),
(9, '1240', 'Lord, You\'re so good to me, Jesus', 'Lord, You\'re so good to me, Jesus,\nand set my captive heart free.\nYou suffered and died and rose to\nabide in me, You\'re so good to me.\r\nYou loved me, when I was unloveble,\nYou reach down and took my hand,\nYou pull me into this revelation\nand now I know who I am.\r\nAs I found out this new life you gave\nme, grace, grace is my cry.\nYou\'re love is really amazing, I will\nWorship You, Lord, God, most high.', NULL),
(9, '1241', 'Love the Lord, your God, with all your Heart', 'Love the Lord, your God, with all your heart,\nand all your soul, and all your mind.\nAnd love all mankind, as you would love yourself.\r\nLove the Lord, your God, with all your heart,\nand all your soul, and mind and all mankind.\r\nWe\'ve got christian lives to live,\nwe\'ve got Jesus Christ to give,\nwe\'ve got nothing to hide,\nbecause in Him we\'ll abide.\nLove the Lord...', NULL),
(9, '1242', 'Mach dir keine Sorgen wie es um die Braut steht   (Da ist ein Weg für die Braut und er ist schon gebahnt)', NULL, 'Mach dir keine Sorgen,\nwie es um die Braut steht.\nDenk doch, dass an jedem Morgen\nder Bräutigam mit ihr geht!\r\nDa ist ein Weg für die Braut und er ist schon gebahnt.\nDa ist ein Weg für die Braut und er fängt beim Kreuze an.\nDa ist ein Weg für die Braut, auf dem sie nur gehen kann,\ndoch sie geht ihn bis zum Ziel.\r\nBraut, du brauchst nur folgen!\nAlles ist schon getan.\nWirst du Gottes Weg wählen,\ndann geht der Herr dir voran.\r\nO welch große Freude,\no welch großer Sieg!\nJa, die Braut wird nicht fallen,\nweil ihr der Herr die Kraft gibt!'),
(9, '1243', 'Mach mich allezeit ganz für Dich bereit  -  Make my Life to be like a Melody   (Dass Jesus in mir lebt, gib mir dazu die Freud)   [Jesu Name Band 2]', 'Make my life to be like a melody,\never sounding on the message of the Cross.\r\nSaviour let me be like a melody,\never singing out through days of gain or loss.\r\nWith Jesus in the heart, no discord can arise,\nHe can make the saddest heard to harmonise.\nMake my life to be like a melody,\never sounding on the message of the Cross.', 'Mach mich allezeit ganz für Dich bereit,\ndass ich singe von der Liebe meines Herrn.\r\nAlle Schüchternheit fliehet mit der Zeit,\nwenn ich singe von der Liebe meines Herrn.\r\nDass Jesus in mir lebt, gib mir dazu die Freud\';\ndenn Sein Heil\'ger Geist vertreibt die Ängstlichkeit.\nMach mich allezeit ganz für Dich bereit,\ndass ich singe von der Liebe meines Herrn.'),
(9, '1244', 'Mach mich ähnlich Dir  -  Make me more like Thee   (Chorus)', 'Make me more like Thee,\nJesus, make me more like Thee.\nGive me a heart that\'s filled with love,\nand make me more like Thee.', 'Mach mich ähnlich Dir,\nJesus, mach mich ähnlich Dir.\nGib mir ein Herz erfüllt mit Lieb\'\nund mach mich ähnlich dir.'),
(9, '1245', 'Mach mich zum Werkzeug Deiner Lieb  -  Make me a Channel of your Peace   (Das ist heute mein Gebet, o Herr)', 'Make me a channel of your peace,\nwhere there is despair in life, let me bring hope.\nWhere there is darkness only light,\nand where there\'s sadness ever joy.\r\nMaster, grant that I may never seek,\nso much to be consoled as to console.\nTo be understood as to understand,\nto be loved as to love with all my soul.\r\nMake me a channel of your peace,\nit is in pardoning that we are pardoned.\nIn giving to all men that we receive,\nand in dying that we\'re born to eternal life.\r\nMake me a channel of your peace,\nwhere there is hatred let me bring your love.\nWhere there is injury your pardon, Lord,\nand where there\'s doubt true faith in You.\r\n', 'Mach mich zum Werkzeug Deiner Lieb\',\nwo Hass ist lass mich bringen Deine Güt\',\nwo Streit ist, Deinen Frieden tief und süß,\nwo Zweifel, Deinen Glauben, der siegt.\r\nDas ist heute mein Gebet, o Herr,\nzu trösten und selbst nicht getröstet sein,\nzu verstehen und selbst nicht verstanden sein,\nzu lieben, wenn auch nicht geliebt zu sein.\r\nMach mich zum Werkzeug Deiner Lieb\',\nin Dunkelheit lass bringen mich Dein Licht,\nwo Trauer, möchte ich bringen Deine Freud\',\nwo Schmerzen, lind\'re Du die Not.\r\nMach mich zum Werkzeug Deiner Lieb\',\nVerirrten möchte ich bringen Deinen Fried\',\nVerzagten Deine Gegenwart so süß.\nMach mich zum Werkzeug Deiner Lieb\' und Treu.\r\nMach mich zum Werkzeug Deiner Lieb\',\nfür Jesus leben ist mein Sehnen heut\',\nfür and\'re leben, ew\'ges Leben ist.\nO Herr, ich weihe mich ganz heut\'.'),
(9, '1246', 'Mache mich stille, das, Herr ist mein Flehn   (O lass mich ganz, ganz stille sein)', NULL, 'Mache mich stille, das, Herr ist mein Fleh\'n,\nstille, die Wunder im Wort zu seh\'n;\nstille, zu lauschen der Sprache Dein,\nstill, um mit Dir gern alleine zu sein!\r\nO lass mich ganz, ganz stille sein,\ngeliebter Herr und Heiland mein;\nbereit mich für die Ewigkeit\nin Deiner heil\'gen Einsamkeit!\r\nMache mich stille, wenn Schweres mir droht,\nstille in dem Wissen: Du kennst die Not!\nStill im Vertrauen auf deine Macht,\nstill in der Liebe die über mich wacht!\r\nMache mich stille im Warten und Ruh\'n,\nstille im Schaffen, im Kämpfen, Tun,\nstille vor anderer Glück und Leid,\nstille und betend zu helfen breit!\r\nMache mich stille ganz innerlich still,\nbis ich, was Du  willst, von Herzen will,\nbis Du so groß bist und ich so klein,\ndass Du mir alles in allem kannst sein!'),
(9, '1247', 'Made for more', 'I know who I am \'cause I know who You are\nThe cross of salvation was only the start\nI am chosen, free and forgiven\nI have a future and it\'s worth the living\r\nI wasn\'t made to be tending a grave\nI was called by name\nBorn and raised, back to life again\nI was made for more\nSo why would I make a bed in my shame\nWhen a fountain of grace is running my way\nI know I am Yours\nAnd I was made for more\r\nI know who I am \'cause I know who You are\nThe cross of salvation was only the start. \nI am chosen, free and forgiven \nI have a future and it\'s worth the living\r\nHalleluja\nYou called out my name\nSo I\'ll sing out Your praise\nHallelujah\nYou buried my past\nAnd I\'m not going back', 'Ich weiß, wer ich bin, weil ich weiß, wer Du bist\nDas Kreuz der Erlösung war nur der Anfang\nIch bin auserwählt, frei und vergeben\nIch habe eine Zukunft und sie ist es wert zu leben\r\nIch wurde nicht geschaffen, um ein Grab zu hüten\nIch wurde beim Namen gerufen\nGeboren und auferweckt, wieder zum Leben erweckt\nIch wurde für mehr geschaffen\nWarum also sollte ich ein Bett in meiner Schande machen\nWenn ein Brunnen der Gnade meinen Weg fließt\nIch weiß, ich bin Dein\nUnd ich wurde für mehr geschaffen\r\nIch weiß, wer ich bin, weil ich weiß, wer Du bist\nDas Kreuz der Erlösung war nur der Anfang. \nIch bin auserwählt, frei und vergeben \nIch habe eine Zukunft und sie ist es wert zu leben\r\nHalleluja\nDu hast meinen Namen gerufen\nSo singe ich Dein Lob\nHalleluja\nDu hast meine Vergangenheit begraben\nUnd ich gehe nicht zurück'),
(9, '1248', 'Mag Erdenfreude fliehn, Jesus ist mein', NULL, 'Mag Erdenfreude fliehn, Jesus ist mein!\nIch will mit Jesu ziehn, Jesus ist mein!\nIst auch kein Freund mir nah,\nist doch mein Jesus da.\nUnd ewig bleibt es wahr: Jesus ist mein!\r\nIch geh nicht mehr zurück, Jesus ist mein!\nIhm dienen ist mein Glück, Jesus ist mein!\nVon Welt und Sünde fern,\nleb\' ich nur meinem Herrn.\nEr ist mein Hoffnungsstern, Jesus ist mein!\r\nFahr hin, o Eitelkeit, Jesus ist mein!\nIhm bin ich ganz geweiht, Jesus ist mein!\nWas früher mein Gewinn,\ngeb\' ich jetzt gerne hin,\ndenn ich hab Jesu Sinn, Jesus ist mein!\r\nFahr hin, was sterben soll, Jesus ist mein!\nBei Jesu ist mir wohl, Jesus ist mein!\nMich schrecket kein Gericht;\nbald, bald im ew\'gen Licht\nschau ich Sein Angesicht. Jesus ist mein!'),
(9, '1249', 'Majestät, preist Seine Majestät  -  Majesty, worship His Majesty   (2 Chorusse)', 'Majesty, worship His majesty,\nunto Jesus be glory, honour and praise.\nMajesty, kingdom, authority,\nflow from His throne unto His own, His anthem rise.\r\nSo exalt, lift up on high the name of Jesus.\nMagnify, come glorify Christ Jesus the King.\nMajesty, worship His majesty,\nJesus who died, now glorified, King of all Kings.', 'Majestät, preist Seine Majestät,\nJesus Christus sei Lob und Ehre gebracht.\nMajestät, Herrschaft und Heiligkeit,\nfließen vom Thron von Gottes Sohn, in Seiner Macht.\r\nDarum auf, lobet den höchsten Namen Jesus.\nEr allein wird König sein für alle Zeit.\nMajestät, preist Seine Majestät,\nJesus ist Herr, keiner als Er, betet Ihn an.'),
(9, '1250', 'Make a joyful Noise unto the Lord   (2 Chorusse)', 'Make a joyful noise unto the Lord,\nall ye, all ye lands.\nServe the Lord with gladness.\nCome before His presence with singing.\r\nHalleluja, glory halleluja! (4x)\nHalleluja, glory halleluja! (4x)', NULL),
(9, '1251', 'Make my Life a Prayer to you', 'Make my life a prayer to You\nI wanna do what you want me to\nNo empty words and no white lies\nNo token prayers no compromise\r\nI wanna shine the light You gave\nThrough Your Son You sent to save us\nFrom ourselves and our despair\nIt comforts me to know You\'re really there\r\nWell I wanna thank you know\nFor being patient with me\nOh it\'s so hard to see\nWhen my eyes are on me\nI guess I\'ll have to trust\nAnd just believe what You say\nOh you\'re coming again\nComing to take me away\r\nI wanna die and let You give\nYour life to me so I might live\nAnd share the hope You gave me\nThe love that set me free\r\nI wanna tell the world out there\nYou\'re not some fable or fairy tale\nThat I\'ve made up inside my head\nYou\'re God the Son and You\'ve risen from the dead\r\nI wanna die and let You give\nYour life to me so I might live\nAnd share the hope You gave me\nThe love that set me free', 'Mach mein Leben zu einem Gebet vor Dir\nIch will tun, was du willst\nKeine leeren Worte und keine Notlügen\nKeine symbolischen Gebete, keine Kompromisse\r\nIch möchte das Licht erstrahlen lassen, das du gegeben hast\nDurch deinen Sohn, denn du gesandt hast, um uns zu retten\nVon uns selbst und unserer Verzweiflung\nEs tröstet mich zu wissen, dass Du wirklich da bist\r\nNun, ich möchte dir danken,\nDafür, dass du geduldig mit mir bist\nOh, es ist so schwer zu sehen\nWenn meine Augen auf mich gerichtet sind\nIch denke, ich muss vertrauen\nUnd einfach glauben, was du sagst\nDu kommst wieder\num mich mitzunehmen\r\nIch möchte sterben und Dein Leben empfangen,\nWelches du für mich geben hast, damit ich leben kann\nUnd die Hoffnung teilen, die du mir gegeben hast\nDie Liebe, die mich befreit hat\r\nIch will es der Welt da draußen sagen\nDu bist keine Fabel oder Märchen\nWelches ich mir in meinem Kopf ausgedacht habe.\nDu bist Gott der Sohn und du bist von den Toten auferstanden\r\nIch möchte sterben und Dein Leben empfangen,\nWelches du für mich geben hast, damit ich leben kann\nUnd die Hoffnung teilen, die du mir gegeben hast\nDie Liebe, die mich befreit hat'),
(9, '1252', 'Man erzählte mir froh von dem Himmel   (Halleluja! Ganz laut will ich singen)   [Singet dem Herrn]', NULL, 'Man erzählte mir froh von dem Himmel,\nvon der herrlichen Stadt hoch dort droben;\nwo Erlöste dann singen und loben,\nund einmal, bald einmal bin ich da.\r\nHalleluja! Ganz laut will ich singen;\nja ich bin auf dem Wege zum Himmel.\nUnd in mir ist ein fröhliches Klingen,\ndenn ich weiß, bald, ja, bald bin ich da.\r\nUnd ich hört\' von der Stadt ohne Sorgen,\nohne Leiden und Not, ohne Tränen.\nJa, dorthin geht ein fröhliches Sehnen,\nund einmal, bald einmal bin ich da.\r\nWeißt du auch von dem Ort voller Freude?\nKennst du den, der erlöset von Leiden?\nKennst du den, der im Elend dich sah?\nSingst auch du: "Bald einmal bin ich da!"?'),
(9, '1253', 'Man hat mir erzählt von der Liebe  -  They tell me of love\'s sweet old Story   (Oh, sag mir erneut Seinen Nam)', 'They tell me of love\'s sweet old story,\nthey tell me of a wonderful name.\nIt thrills my soul with its glory,\nit burns in my heart like a flame.\nThey say He\'s the one that so loved me,\nthat in Heaven He could not remain.\nHe came down to seek and to save me,\noh, tell me His name again.\r\nOh, tell me His name again\nand sing me the sweet refrain.\nOf Him who in love, came down from above,\nto die on the cross in shame.\nThis story my heart has been stirred,\nthe sweetest I\'ve ever heard.\nIt banishes fear, it brings hope and cheer,\noh tell me His name again.\r\nThey say He was born in a manger,\nthat there was no room in the inn.\nAnd in His own world was a stranger,\nbut loved us in spite of our sins.\nThey said that His path led to Calvary,\nand one day He died there in shame.\nHe gave His great life a ransom,\noh, tell me His name again.\r\nThey call Him the sweet Rose of Sharon,\nthey call Him the lily so fair.\nThey call Him the great rock of ages,\nthey call Him the bright morning star.\nHe\'s a prophet, a priest, and redeemer,\nthe king of all kings He now reigns.\nHe\'s coming in power and glory,\noh, tell me His name again.', 'Man hat mir erzählt von der Liebe,\ndie Gott legte in diesen Nam\'.\nEr schrieb Ihn mir auf meine Seele,\nund Er hat mein Herz ganz entflammt.\nMan sagt mir, dass Er mich so liebte,\ndass Er zu mir vom Himmel kam.\nEr kam, mich zu suchen und retten,\noh, sag\' mir erneut Seinen Nam\'!\r\nOh, sag mir erneut Seinen Nam\',\noh, was für ein lieblicher Klang.\nVon Ihm, der aus Lieb\' den Himmel verließ,\nund für mich das Kreuz auf sich nahm.\nMein Herz ist davon so bewegt,\ndas Schönste, was ich je erlebt.\nIch fürcht\' mich nicht mehr, und freu mich so sehr,\noh, sag mir erneut Seinen Nam\'!\r\nMan sagt, Er fand nur eine Krippe,\ndie Herberge bot keinen Raum.\nEr war für die Seinen ein Fremder,\nSein Volk, das erkannte Ihn kaum.\nDoch liebt\' Er uns trotz uns\'rer Sünden,\nnach Golgatha führte Sein Pfad.\nIn Ihm kann man Freiheit dort finden,\noh, sag mir erneut Seinen Nam\'!\r\nMan nennt Ihn die Rose von Saron,\nman nennt Ihn die Lilie so schön.\nMan nennt Ihn den Fels aller Zeiten,\nden Morgenstern, hell anzuseh\'n.\nMein Priester, mein Gott, mein Erlöser,\nmein König, ich bete Ihn an.\nBald kommt Er voll Macht und voll Ehre,\noh, sag\' mir erneut Seinen Nam\'!'),
(9, '1254', 'Manches Herz will fast ermüden, denn die Tage eilen hin  -  There are lonely Hearts to cherish, while the Days are going by   (Eilen hin, eilen hin)', 'There are lonely hearts to cherish,\nwhile the days are going by.\nThere are weary souls who perish,\nwhile the days are going by.\nIf a smile we can renew,\nas our journey we pursue.\nO, the good we all may do,\nwhile the days are going by!\r\nGoing by, going by,\ngoing by, going by.\nO, the good we all may do,\nwhile the days are going by!\r\nThere\'s no time for idle scorning,\nwhile the days are going by.\nLet your face be like the morning,\nwhile the days are going by.\nFor the world is full of sighs,\nfull of sad and weeping eyes.\nHelp your fallen brother rise,\nwhile the days are going by.\r\nAll the loving links that bind us,\nwhile the days are going by.\nOne by one we leave behind us,\nwhile the days are going by.\nBut the seeds of good we sow,\nboth in shade and shine will grow.\nAnd will keep our hearts aglow,\nwhile the days are going by.', 'Manches Herz will fast ermüden,\ndenn die Tage eilen hin.\nManche Seele seufzt nach Frieden,\ndenn die Tage eilen hin.\nKannst ein Lächeln du erneu\'n,\nnur ein Kinderherz erfreu\'n.\nHalt nichts Gutes für zu klein,\ndenn die Tage eilen hin.\r\nEilen hin, eilen hin,\neilen hin, eilen hin.\nWie viel Gutes kannst du tun!\nSieh, die Tage eilen hin.\r\nLass das Trauern, lass das Zagen,\ndenn die Tage eilen hin.\nGroßes gilt\'s für Gott zu wagen,\ndenn die Tage eilen hin.\nVoll von Unrecht ist die Welt,\ntritt nur vor als Gottes Held.\nRette, wo ein Bruder fällt,\ndenn die Tage eilen hin.\r\nWenn die Liebe Kränze windet,\ndenk: die Tage eilen hin!\nLohn es ihr, eh sie verschwindet,\ndenn die Tage eilen hin.\nLass das Herz voll Liebe sein,\nlass die Hände Segen streu\'n.\nMach die Welt voll Sonnenschein,\ndenn die Tage eilen hin.'),
(9, '1255', 'Many baffled Birds in vain will wave one Wing   (Rise and soar into the Sunlight Rays)', 'Many baffled birds in vain will wave one wing.\nDrooping prayers they pray but rarely shout and sing.\nRound and round these earth-bound birds go, in a maze.\nFor they fail to stretch the other wing in praise.\r\nRise and soar into the sunlight rays.\nUsing both your wings of prayer and praise.\nMount like eagles, higher in the sky.\nAnd you\'ll find things look so different when you fly.\r\nExercise your wings oh Christians, pray and praise.\nWe shall have the best revival these last days!\nGlide aloft and spread the message glad and strong.\nSee ten thousand angels swarm and swell with song.\r\nRise and soar in the sunlight rays,\nusing both,\nyour wings of prayer and praise.\nMount like eagles,\nhigher in the sky,\nand you\'ll find,\nthings look so different when you fly.', NULL),
(9, '1256', 'Many times in my childhood when weve traveled so far', 'Many times in my childhood when we\'d traveled so far,\nby nightfall how weary I\'d grown.\nFathers arms would slip around me and gently he\'d say:\n"My child we\'re going home".\r\nGoing home, I\'m going home,\nthere is nothing to hold me here.\nFor I\'ve caught a glimpse of the heavenly land,\npraise God, I\'m going home.\r\nNow the twilight is fading and the day soon shall end,\nLord, I get homesick, the farther I roam.\nBut my Father has led me each step of the way,\nand now we\'re going home.', NULL),
(9, '1257', 'Marching on in the Light of God   (A Robe of white, a Crown of gold)', 'Marching on in the light of God,\nMarching on, I am marching on;\nUp the path that the Master trod,\nMarching, marching on.\r\nA robe of white, a crown of gold,\nA harp, a home, a mansion fair,\nA victor\'s palm, a joy untold,\nAre mine when I get there.\r\nMarching on thro\' the hosts of sin,\nMarching on, I am marching on;\nVict\'ry\'s mine, while I\'ve Christ within,\nMarching, marching on.\r\nMarching on while the skeptics sneer,\nMarching on, I am marching on;\nPerfect love casteth out all fear,\nMarching, marching on.\r\nMarching on with the flag unfurled,\nMarching on, I am marching on;\nPreaching Christ to the dying world,\nMarching, marching on.', NULL),
(9, '1258', 'Mächtig tobt des Sturmes Brausen um ein kleines Schiff  -  Fierce and wild the Storm is raginground a helpless Bark   (Mut, blickt auf den Retter, höret, was Er spricht)', 'Fierce and wild the storm is raging\nround a helpless bark,\non to doom ’tis swiftly driving,\no’er the waters dark!\r\nJoy, behold the Saviour,\njoy, the message hear,\n"I’ll stand by until the morning,\nI’ve come to save you, do not fear."\nYes, I’ll stand by until the morning,\nI’ve come to save you, do not fear.\r\nWeary, helpless, hopeless seamen\nfainting on the deck.\nWith what joy they hail their Saviour,\nas He hails their wreck!\r\nOn a wild and stormy ocean,\nsinking ’neath the wave.\nSouls that perish heed the message,\nChrist has come to save!\r\nDaring death thy soul to rescue,\nHe in love has come.\nLeave the wreck and in Him trusting,\nthou shalt reach thy home!', 'Mächtig tobt des Sturmes Brausen\num ein kleines Schiff,\nhilflos hin und her geworfen,\ndroht ihm manches Riff.\r\nMut, blickt auf den Retter,\nhöret, was Er spricht:\nIch bin bei euch alle Tage,\nIch helfe euch, verzaget nicht!\nJa, Ich bin bei euch alle Tage;\nIch helfe euch, verzaget nicht!\r\nAuf dem Decke steht die Mannschaft\nohne Macht und Wehr.\nAlles schreit jetzt zu dem Retter\nund da half der Herr.\r\nAuf des Lebens Ozeane,\nwo manch\' Sturm uns droht,\nbeut uns eine frohe Botschaft\nHeil in jeder Not.\r\nJesus kam, uns zu erretten\naus der Welt Gebraus,\nlass dein Wrack, trau Seinem Walten,\nEr führt dich nach Haus.'),
(9, '1259', 'Mächtige Ströme des Segens  -  There shall be Showers of Blessing   (Mächtige Ströme des Segens)   [Siegesklänge]', 'There shall be showers of blessing,\nthis is the promise of love.\nThere shall be seasons refreshing,\nsent from the Saviour above.\r\nShowers of blessing,\nshowers of blessing we need.\nMercy drops round us are falling,\nbut for the showers we plead.\r\nThere shall be showers of blessing,\nprecious reviving again.\nOver the hills and the valleys,\nsound of abundance of rain.\r\nThere shall be showers of blessing,\nsend them upon us, O Lord.\nGrant to us now a refreshing,\ncome and now honor Thy Word.\r\nThere shall be showers of blessing,\no that today they might fall.\nNow as to God we\'re confessing,\nnow, as on Jesus we call.\r\nThere shall be showers of blessing,\nIf we but trust and obey;\nThere shall be seasons refreshing,\nIf we let God have His way.', 'Mächtige Ströme des Segens!\nDiese Verheißung Er gab.\nZeiten der ew\'gen Erquickung\nsendet der Heiland herab.\r\nMächtige Ströme des Segens!\nStröme Dein Wort uns verheißt.\nHerr, Deine Gnade ist köstlich,\nsend\' uns in Strömen den Geist!\r\nMächtige Ströme des Segens!\nSo nur wird Jesus geehrt,\nwenn auf den Hügeln und Eb\'nen\nKunde vom Segen man hört.\r\nMächtige Ströme des Segens!\nStröme des Segens sind Dein!\nGib uns die Zeit der Erquickung,\nlöse Dein Wort uns jetzt ein!\r\nMächtige Ströme des Segens!\nSende sie, Herr, uns noch heut\',\njetzt, wo wir vor Dir uns beugen,\njetzt, wo die Herzen bereit.\r\nMächtige Ströme des Segens\nhören wir rauschen von fern.\nÜber die Gläub\'gen und Sünder\nkommt die Verheißung des Herrn!'),
(9, '1260', 'Mehr als jemals zuvor, Herr ich lieb Dich  -  More than ever before, Lord I love You   (Mehr als jemals zuvor, Herr, ich lieb Dich)', 'I love You, Lord, I love You now,\nbut much more now then before.\nYou\'re all I\'ve found in this poor world,\nYou became my dearest friend.\nAnd with each day, You bring on my way,\njoy I\'ve never known before.\nAnd on a long way I would have to say,\nI lean upon You more and more.\r\nMore than ever before, Lord I love You.\nMore than ever before, Lord I need You.\nMore than ever before, I want to tell You,\nI love You now, more than ever before.\r\nYou know it\'s true that I love You,\nmore than words could ever show.\nBut forgive me, Lord, for all the times,\nwenn I haven\'t loved You so.\nFor You mean everything to me,\nYour presence I adore.\nI want to live each day in such a way\nYou know I love You more and more.', 'Herr Jesus Christ, ich liebe Dich\nweit mehr als je zuvor.\nAuf dieser Welt mich gar nichts hält,\nDu bist mein bester Freund.\nMit jedem Tag, wird meine Freude\ngrößer als vorher.\nAuf lange Sicht muss sagen ich,\nich stütz\' mich auf Dich mehr und mehr.\r\nMehr als jemals zuvor, Herr, ich lieb\' Dich.\nMehr als jemals zuvor, Herr, ich brauch\' Dich.\nMehr als jemals zuvor möcht\' ich Dir sagen,\nich lieb\' Dich heut\' mehr als jemals zuvor.\r\nMein Herr, Du weißt, ich liebe Dich,\nin Worten nicht zu sagen.\nEs tut mir leid, wo\'s nicht so war\nan vielen trüben Tagen.\nUnd Du bist alles was ich brauch\',\nAnbetung Dir, o Herr.\nAn jedem Tag möcht\' lernen ich\nDich lieben mehr und mehr.'),
(9, '1261', 'Mehr Frömmigkeit gib mir, mehr Eifer dazu  -  More Holiness give me, more Striving within', 'More holiness give me, more striving within.\nMore patience in suff\'ring, more sorrow for sin.\nMore faith in my Saviour, more sense of His care.\nMore joy in His service, more purpose in prayer.\r\nMore gratitude give me, more trust in the Lord.\nMore pride in His glory, more hope in His word.\nMore tears for His sorrows, more pain at His grief.\nMore meekness in trial, more praise for relief.\r\nMore purity give me, more strength to o’ercome.\nMore freedom from earth-stains, more longings for home.\nMore fit for the kingdom, more used would I be.\nMore blessèd and holy, more, Saviour, like Thee.', 'Mehr Frömmigkeit gib mir, mehr Eifer dazu!\nMehr Leid über Sünde, mehr Frieden und Ruh\',\nmehr Glauben an Jesus, mehr Acht auf Sein Teil,\nmehr Lust, Dir zu dienen, mehr Leben und Heil.\r\nMehr Dankbarkeit gib mir, mehr Treue, o Gott!\nMehr Herz, Dich zu lieben, mehr Hoffnung in Not!\nMehr Tränen des Mitleids, mehr Teilnahm am Schmerz,\nmehr Sanftmut und Milde, mehr Demut in\'s Herz!\r\nMehr Reinheit, Herr, gib mir, mehr Kraft aus der Höh\',\nmehr Freiheit vom Eitlem, mehr himmlisch\' Heimweh!\nMehr Mut für die Wahrheit, mehr Frucht, die Dich preist,\nmehr göttliche Klarheit, mehr Herr, Deinen Geist!'),
(9, '1262', 'Mehr lieben möcht ich Dich, hör mein Gebet  -  More Love to Thee, o Christ, more Love to Thee', 'More love to Thee, O Christ, more love to Thee!\nHear Thou the prayer I make on bended knee.\nThis is my earnest plea: More love, o Christ, to Thee,\nmore love to Thee, more love to Thee!\r\nOnce earthly joy I craved, sought peace and rest.\nNow Thee alone I seek, give what is best.\nThis all my prayer shall be: More love, o Christ, to Thee,\nmore love to Thee, more love to Thee!\r\nThen shall my latest breath whisper Thy praise.\nThis be the parting cry my heart shall raise.\nThis still its prayer shall be: More love, oO Christ, to Thee,\nmore love to Thee, more love to Thee!\r\n\r\n', 'Mehr lieben möcht\' ich Dich, hör mein Gebet!\nIch flehe inniglich, ruf früh und spät:\nMehr lieben möcht\' ich Dich, mehr lieben, Heiland, Dich,\nmehr lieben Dich, mehr lieben Dich.\r\nEinst sucht ich außer Dir mein Glück und Teil;\ndoch gabst Du, Jesus, mir Dein volles Heil.\nDas ist mehr lieben Dich, mehr lieben, Heiland, Dich,\nmehr lieben Dich, mehr lieben Dich.\r\nDrückt mich auch Kummer hier, schmerzt Kreuzespein,\nsoll dies doch für und für mein Wahlspruch sein:\nMehr lieben will ich Dich, mehr lieben, Heiland, Dich,\nmehr lieben Dich, mehr lieben Dich.\r\nUnd wenn mein Herze ringt in großer Not,\nwenn Satan auf mich dringt bis an den Tod;\nich will doch lieben Dich, mehr lieben, Heiland, Dich,\nmehr lieben Dich, mehr lieben Dich.\r\nEndigt sich dann mein Lauf in dieser Zeit,\nkomm ich zu Dir hinauf, o welche Freud!\nDort werd\' ich lieben Dich, mehr lieben, Heiland, Dich,\nmehr lieben Dich, mehr lieben Dich!'),
(9, '1263', 'Mehr und mehr will ich preisen meinen Herrn   (Chorus)', NULL, 'Mehr und mehr, will ich ihn preisen meinen Herrn.\nMehr und mehr will ich anbeten meinen Herrn.\nMehr und mehr will ich danken meinem Herrn,\nund mein Leben auf ewig ihm weih\'n.'),
(9, '1264', 'Mehr von Dir, mehr von DirI (have searched all around in the Husks that abound)', 'More of You, more of You,\nI\'ve had it all but what I need is more of You.\nOf things I had my fill, but yet I hunger still.\nEmpty and bare, Lord hear my prayer for more of You.\r\nI have searched all around in the husks that abound,\nbut I find no nourishment there.\nNow my strength’s almost gone and I feel the pull of despair.\nBut my thirst drives me on, as I stumble along,\nover ground, so barren and dry.\nBut the streams just ahead, living water,\n“Lord fill me!” I cry.\r\nI’m not trying to find just some new frame of mind\nthat will change my old point of view.\nFor I’ve been through it all, deep inside nothing’s changed, I’m not new.\nI’m not seeking a gift or emotional lift.\nBut one thing I’m longing to do,\nis to lift up my cup and let you fill it up,\nwith just you.', 'Mehr von Dir, mehr von Dir!\nIch brauch\' sonst nichts, doch was ich brauch\', ist mehr von Dir.\nDie Dinge dieser Welt, die einst mein Herz erfüllt,\nbrauch\' ich nicht mehr, Jesus mein Herr, gib mehr von Dir!\r\nIch habe überall in den Schalen, die es gibt, gesucht,\naber ich finde dort keine Nahrung.\nJetzt ist meine Kraft fast weg und ich fühle den Sog der Verzweiflung.\nDoch mein Durst treibt mich weiter, während ich weiterstolpere,\nüber einen Boden, der so unfruchtbar und trocken ist.\nAber die Bäche, die vor mir liegen, sind lebendiges Wasser,\n"Herr, fülle mich!" Ich rufe.\r\nIch versuche nicht, nur eine neue Geisteshaltung zu finden\ndie meine alte Sichtweise ändert.\nDenn ich habe alles schon durchgemacht, tief im Innern hat sich nichts geändert, ich bin nicht neu.\nIch suche nicht nach einem Geschenk oder einem emotionalen Auftrieb.\naber eine Sache, nach der ich mich sehne,\nist, meinen Kelch zu heben und ihn von dir füllen zu lassen,\nnur mit dir.'),
(9, '1265', 'Mein Glaube blickt auf Dich, Du Lamm das starb für mich  -  My Faith looks up to Thee, Thou Lamb of Calvary', 'My faith looks up to Thee,\nThou Lamb of Calvary,\nSaviour divine!\nNow hear me while I pray,\ntake all my guilt away,\noh let me from this day\nbe wholly Thine!\r\nWhile life\'s dark maze I tread,\nand griefs around me spread,\nbe Thou my Guide.\nBid darkness turn to day,\nwipe sorrow\'s tears away.\nNor let me ever stray\nfrom Thee aside.\r\nWhen ends life\'s transient dream,\nwhen death\'s cold, sullen stream\nshall o\'er me roll.\nBlest Saviour, then, in love,\nfear and distrust remove.\nO bear me safe above,\na ransomed soul!\r\nMay Thy rich grace impart\nstrength to my fainting heart,\nmy zeal inspire.\nAs Thou hast died for me,\noh may my love to Thee,\npure, warm, and changeless be,\na living fire!', 'Mein Glaube blickt auf Dich,\nDu Lamm, das starb für mich,\nErlöser mein!\nHöre mich, wenn ich fleh\',\nDu Retter in der Höh\',\nlass mich wohin ich geh,\nzum Segen sein!\r\nWenn mich die Wolke deckt\nund Nacht und Tod mich schreckt,\nder Sturmwind tost,\nmach Du das Dunkel licht,\nzeig mir Dein Angesicht.\nJa, Herr, verlass mich nicht\nsei Du mein Trost!\r\nWenn dann mein Lauf vollbracht,\nDu mich Herr frei gemacht,\nkomm ich zu Dir.\nDarf vor dem Throne steh\'n\nund Dich, den König , seh\'n,\nwo Dich mein Lobgetön\npreist für und für!\r\nMöge Deine reiche Gnade meinem ohnmächtigen Herzen Kraft\nverleihen und meinen Eifer beflügeln. Wie Du für mich gestorben bist,\noh möge meine Liebe zu Dir, rein, warm und unveränderlich,\nein lebendiges Feuer sein!'),
(9, '1266', 'Mein Glaube fest sich bauen kann  -  My Hope is built on nothing less   (Wer diesem Felsen fest vertraut)', 'My hope is built on nothing less\nthan Jesus’ blood and righteousness.\nI dare not trust the sweetest frame,\nbut wholly lean on Jesus’ name.\r\nOn Christ, the solid Rock, I stand,\nall other ground is sinking sand,\nall other ground is sinking sand.\r\nWhen darkness veils His lovely face,\nI rest on His unchanging grace.\nIn every high and stormy gale,\nmy anchor holds within the veil.\r\nHis oath, His covenant, His blood,\nsupport me in the whelming flood.\nWhen all around my soul gives way,\nHe then is all my hope and stay.\r\nWhen He shall come with trumpet sound,\noh, may I then in Him be found.\nDressed in His righteousness alone,\nfaultless to stand before the throne.', 'Mein Glaube fest sich bauen kann\nauf das, was Gott für mich getan.\nEin froh\' Gefühl gar bald zerstäubt;\nChristus, der ew\'ge Felsen, bleibt.\r\nWer diesem Felsen fest vertraut,\nder hat auf keinen Sand gebaut,\nder hat auf keinen Sand gebaut.\r\nIst auch verhüllt Sein Angesicht,\ndes Heilands Gnade wanket nicht.\nWenn auch der Sturmwind um mich bläst,\nder Fels hält meinen Anker fest.\r\nSein Eid, Sein Bund, Sein teures Blut\nbeschützen mich zur Zeit der Flut.\nWenn alles ringsum untergeht,\nder ew\'ge Felsen sicher steht.\r\nKommt zum Gerichte Gottes Sohn\nund weckt die Welt Posaunenton,\ndann sei des Herrn Gerechtigkeit\nallein mein Schmuck und Ehrenkleid.'),
(9, '1267', 'Mein Gott ist unendlich, die Gnade so reichlich  -  His Love has no Limit, His Grace has no Measure   (Chorus)', 'His love has no limit, His grace has no measure,\nHis Pow\'r has no boundary known  unto men.\nFor out of His infinite riches in Jesus,\nHe giveth and giveth and giveth again!', 'Mein Gott ist unendlich, die Gnade so reichlich,\ndie Liebe unfassbar, die Er uns erweist.\nDenn aus Seiner Fülle gibt Er uns so reichlich,\nEr gibt uns und gibt uns und gibt uns auf\'s Neu\'.'),
(9, '1268', 'Mein Gott kann tun, alles tun  -  My God can do anything   (Chorus)', 'My God can do anything,\nanything, anything,\nmy God can do anything.\nHe made the earth and all therein,\nHe saved my soul from every sin,\nmy God can do anything.', 'Mein Gott kann tun, alles tun,\nalles tun, alles tun,\nmein Gott kann einfach alles tun.\nEr schuf die Welt und Er schuf mich,\nund Er starb am Kreuz für dich.\nJa, mein Gott kann einfach alles tun.'),
(9, '1269', 'Mein Heiland ruft mir zu, deine Kraft ist klein  -  I hear the Saviour say, thy Strength is small   (Jesu Opfertod tilget all mein Weh)   [Gospel Hymns Band 1]', 'I hear the Saviour say,\n"Thy strength indeed is small,\nChild of weakness, watch and pray,\nfind in Me thine all in all."\r\nJesus paid it all,\nall to Him I owe.\nSin had left a crimson stain,\nHe washed it white as snow.\r\nLord, now indeed I find\nThy pow\'r and Thine alone,\ncan change the leper\'s spots,\nand melt the heart of stone.\r\nFor nothing good have I\nwhere-by Thy grace to claim.\nI\'ll wash my garments white\nin the blood of Calv\'ry\'s Lamb.\r\n\r\nAnd when, before the throne,\nI stand in Him complete.\n"Jesus died my soul to save,"\nmy lips shall still repeat.', 'Mein Heiland ruft mir zu:\nKind, deine Kraft ist klein;\nin Mir nur find\'st du Ruh,\nIch will dir alles sein.\r\nJesu Opfertod\ntilget all mein Weh;\nmeine Schuld, wie Blut so rot,\nwird weiß so wie der Schnee.\r\nO, Herr, Dein teures Blut\nwäscht meine Flecken rein;\nDu bist\'s, der Wunder tut,\nja, der erweicht den Stein.\r\nNichts Gutes ist in mir,\ndas Deine Gnad\' verdient;\nmein Heil steht nur in Dir,\nder mich mit Gott versühnt.\r\nWenn einst zur letzten Stund\'\nmein Geist sich reißt von hier,\nso jauchzt mein froher Mund:\nMein Jesus steht bei mir!\r\nUnd wenn vor Seinem Thron\nvollendet dann ich bin,\nleg ich die Ehrenkron\'\nzu seinen Füßen hin.'),
(9, '1270', 'Mein Herr befreite Daniel   -  My Lord delivered Daniel   (Chorus)', 'My Lord delivered Daniel,\nMy Lord delivered Daniel,\nMy Lord delivered Daniel,\nand my Lord delivered me.', 'Mein Herr befreite Daniel,\nMein Herr befreite Daniel,\nMein Herr befreite Daniel,\nmein Herr befreit auch mich.'),
(9, '1271', 'Mein Herr hat Kleider so köstlich fein  -  My Lord has Garments so wondrous fine   (Aus den Palästen von Elfenbein  / Out of the ivory Palaces)', 'My Lord has garments so wondrous fine,\nand myrrh their texture fills.\nIts fragrance reached to this heart of mine,\nwith joy my being thrills.\r\nOut of the ivory palaces,\ninto a world of woe.\nOnly His great eternal love\nmade my Saviour go.\r\nHis life had also its sorrows sore,\nfor aloes had a part.\nAnd when I think of the cross He bore,\nmy eyes with teardrops start.\r\nIn garments glorious he will come,\nto open wide the door.\nand I shall enter my heavenly home,\nto dwell forevermore.', 'Mein Herr hat Kleider so köstlich fein,\nvon Myrrhe duften sie.\nIhr Glanz durchströmte das Herze mein,\ndas vergess\' ich nie.\r\nAus den Palästen von Elfenbein,\nin eine Welt voll Schmerz,\nging mein Heiland aus Lieb allein.\nPreis ewig Ihn mein Herz.\r\nVoll tiefer Leiden Dein Leben war,\nwär\' ich wie Du gesinnt.\nUnd denke ich an Dein Kreuz fürwahr,\nvon Tränen mein Auge rinnt.\r\nIm Kleid der Herrlichkeit kommst Du bald,\nzu öffnen mir die Tür.\nUnd ich, verwandelt in Lichtgestalt,\nbin ewig dann bei Dir.'),
(9, '1272', 'Mein Herz es jauchzt und jubiliert, es geht ja bald nach Haus   (Ich werde einmal droben sein)', NULL, 'Mein Herz es jauchzt und jubiliert,\nes geht ja bald nach Haus\',\nmein Heim, das ist die Ewigkeit,\ngar bald ruh\' ich dort aus.\r\nIch werde einmal droben sein,\nerlöst, befreit, von Sünden rein.\nVergessen ist die Erdenpein,\noh, selig, dort zu sein.\r\nO, Heimat in der Himmelshöh\',\ndu Land voll Herrlichkeit.\nIm weißen Kleid ich dort einst steh\',\nich wünscht\' es wär\' noch heut\'.\r\nDort wird der Mund voll Lachens sein,\ndie Zunge voll von Ruhm.\nAuch ich stimm\' dann im Jubel ein,\nich als Sein Eigentum.\r\nUns keine Abschiedsstunde schlägt,\ndas Leid und Weh ist aus.\nZum Heiland jetzt mein Sehnen geht:\n"Komm bald! Ich möcht\' nach Haus\'!"'),
(9, '1273', 'Mein Herz es singt wenn ich darüber nachdenk\'  -  My Heart can sing when I pause to remember   (Doch bis dahin, mein Herz wird weiter singen)', 'My heart can sing when I pause to remember,\na heartache here is but a stepping stone,\nalong the trail That\'s winding always upward.\nThis troubled world iIs not my final home.\r\nMy heart will go on singing, until then,\nwith joy I\'ll carry on.\nUntil the day mine eyes behold the city,\nuntil the day God calls me home.\r\nThe things of earth will dim and lose their value,\nif we recall, they\'re borrowed for awhile.\nAnd things of earth that cause the heart to tremble,\nremember there, will only bring a smile.\r\nThis weary world with all its toil and struggle,\nmay take its toll of misery and strife.\nThe soul of man is like a waiting eagle,\nwhen it\'s released it\'s destined for the sky.', 'Mein Herz, es singt, wenn ich darüber nachdenk\',\ndie Qualen hier sind nur ein Meilenstein auf meinem Pfad,\nder himmelwärts mich leitet.\nDie Welt hier ist am Ende nicht mein Heim.\r\nDoch bis dahin, mein Herz wird weiter singen,\nbis dahin, mit Freude gehe ich.\nBis zu dem Tag, wenn ich die Stadt erblicke,\nbis zu dem Tag, wenn Gott mich ruft.\r\nDie Dinge hier verblassen und sind wertlos.\nwir wissen ja, wir nehmen sie nicht mit.\nDie Sorgen hier, die uns so sehr bedrücken,\nsind dann vorbei, wenn wir einst bei Ihm sind.\r\nDie Welt mit ihrer Müh\' und ihren Plagen,\nsie fordert Kummer, Elend, Kampf und Streit.\nDie Seele ist wie ein gefang\'ner Adler,\nwenn er befreit wird, schwingt er sich empor.'),
(9, '1274', 'Mein Herz singt ein Lied bei Tag und bei Nacht  -  My Heart sings a Song from Morning till Night   (Jesus, Jesus! Nichts klingt so süß wie Jesus)', 'My heart sings a song From morning till night.\nA song full of liberty, Love, and of light.\nA song of the Canaan-land, Happy and bright,\nand all of my song is Jesus.\r\nJesus, Jesus, All of my song is Jesus:\nFrom morning till night I sing with delight,\nJesus, my precious Jesus!\r\nMy heart hath a rest From sin and from fear.\nA rest from all doubting, Disappointment and care.\nA rest like the sky, Bending calm o\'er the year,—\nand all of my rest is Jesus.\r\n\r\nMy heart hath a light In the cloudiest day.\nA light which illumines Each moment my way.\nA light which will not let The little one stray,—\nand all of my light is Jesus.\r\nMy heart hath a Friend, All compassion and love,\nwhose speech falls a soft As the starlight above.\nA friend that abideth, And will not remove,\nand that dearest friend is Jesus.\r\n', 'Mein Herz singt ein Lied bei Tag und bei Nacht\nvon Friede und Freiheit und himmlischer Pracht,\nein Lied von der Liebe, die selig mich macht,\nund dieses mein Lied ist Jesus.\r\nJesus, Jesus! Nichts klingt so süß wie Jesus.\nWas immer ich tu, so sing ich dazu\nJesus, mein liebster Jesus!\r\nStatt knechtischer Furcht genieß\' ich nun Ruh\'\nvor Sünde und Anfechtung, Zweifeln dazu.\nBeladene Seele, o komme auch du,\ndie köstlichste Ruh\' ist Jesus.\r\nIch hab einen Schatz, so herrlich und frei,\nder niemals veraltet, dess\' Glanz immer neu,\nsein Wert ist unendlich, ich bleibe dabei,\nund dieser, mein Schatz, ist Jesus.\r\nMir strahlet ein Licht, wir trüb\'s hier sein mag,\ndas weist mich nach oben bei Nacht und bei Tag,\nbewahrt meine Seele vor Jammer und Klag,\nund dieses, mein Licht, ist Jesus.\r\nIch hab einen Freund, so liebreich und gut,\nder ist mein Berater, der stärkt meinen Mut,\nzu unsrer Erlösung vergoss Er Sein Blut,\nund dieser, mein Freund ist Jesus.\r\nIch habe ein Heim, das alles versüßt,\nin dem man, was kränket, vergibt und vergisst,\nwo ewige Wonne in Strömen mir fließt,\nund dieses, mein Heim, ist Jesus.'),
(9, '1275', 'Mein Herz verherrlicht Jesu Nam\'  -  My soul doth magnify the Lord   (Chorus)', 'My soul doth magnify the Lord,\nmy soul doth magnify the Lord\nand my spirit hath rejoiced in God my Saviour.\nFor He that is mighty hath done great things,\nand Holy is His Name.', 'Mein Herz verherrlicht Jesu Nam\',\nMein Herz verherrlicht Jesu Nam\',\nund mein Geist erfreut sich Deiner, Herr, mein Heiland.\nDenn Er ist so mächtig und tat Großes,\nund Heilig ist Sein Nam\'.'),
(9, '1276', 'Mein Herz war schwer beladen, ich lebte einst in der Sünd  -  Once my Heart was heavy , I was living in Sin   (Und Er heilte die Seele)', 'Once my heart was heavy,\nI was living in sin,\nbut then I found Jesus\nand He took me in.\r\nAnd He saved me, saved me,\nand from sin set me free.\nYes, He saved me,\n\'cause He loves me,\nyes, Jesus saved me.\r\nOnce I thought I\'d never\nfind a peace so fine,\nthen I gave my heart to Jesus,\nHe saved this soul of mine.\r\nSo if your heart is burdened,\nI\'ll tell you what to do,\njust put your trust in Jesus,\nand He will save you, too.', 'Mein Herz war schwer beladen,\nich lebte einst in der Sünd\',\ndoch fand mich der Herr Jesus,\nich war schon immer Sein Kind.\r\nUnd Er heilte die Seele,\nwie groß die Sünde auch sei,\nEr macht\' neu mich aus Liebe,\nja, Er setzte mich frei.\r\nIch dacht\', ich würd\' nie finden,\nden Frieden, welcher so tief,\nich gab mein Herz dem Herrn Jesus,\nmeine Seele heilt\' Er aus Lieb\'.\r\nSo, ist dein Herz beladen,\nich sag\' dir, was du dann tust.\nLeg allen Glauben in Jesus,\nSein Heil ist auch für dich gut.'),
(9, '1277', 'Mein Herz war verzagt, als ich ferne von Gott  -  My Heart was distressed ’neath Jehovah’s dread Frown   (Er brachte mich aus der Sünde Schlamm)', 'My heart was distressed ’neath Jehovah’s dread frown,\nand low in the pit where my sins dragged me down.\nI cried to the Lord from the deep miry clay,\nwho tenderly brought me out to golden day.\r\nHe brought me out of the miry clay,\nHe set my feet on the Rock to stay.\nHe puts a song in my soul today,\na song of praise, hallelujah!\r\nHe placed me upon the strong Rock by His side,\nmy steps were established and here I’ll abide.\nNo danger of falling while here I remain,\nbut stand by His grace until the crown I gain.\r\nHe gave me a song, ’twas a new song of praise,\nby day and by night its sweet notes I will raise.\nMy heart’s overflowing, I’m happy and free,\nI’ll praise my Redeemer, Who has rescued me.\r\nI’ll sing of His wonderful mercy to me,\nI’ll praise Him till all men His goodness shall see.\nI’ll sing of salvation at home and abroad,\ntill many shall hear the truth and trust in God.', 'Mein Herz war verzagt, als ich ferne von Gott,\nlag tief in der Grube in Sünde und Not.\nDa schrie ich zum Herrn aus der finsteren Nacht,\nbis gnädig Er mich zum gold\'nen Tag gebracht.\r\nEr brachte mich aus der Sünde Schlamm\nund stellte mich auf den Felsen dann,\ngab mir ein Lied, dass ich sing\' fortan\nund preise Ihn Halleluja!\r\nAuf sicheren Fels hat der Herr mich gestellt;\nmein Gang ist gewiss nun, weil Seine Hand hält.\nIch fürchte kein Fallen, die Liebe im Sohn\nhilft weit überwinden, bis ich trag\' die Kron\'.\r\nEr gab mir ein Lied, einen neuen Gesang;\nbei Tag und bei Nacht tönt der himmlische Klang.\nMein Herz fließet über in Glück und in Freud\'.\nIch preise den Heiland, der mich ganz erneut.\r\nIch sing\' von der Gnade, die an mir gescheh\'n,\nbis alle die Liebe des Heilandes seh\'n.\nIch will es verkünden, ob nah\' oder fern,\ndass viele es hören und Ihm folgen gern.'),
(9, '1278', 'Mein Herze lobt und preist  -  God sent His mighty Pow’r   (Der Liebe Feuer brennt)', 'God sent His mighty pow’r to this poor, sinful heart,\nto keep me ev’ry hour, and needful grace impart.\nAnd since His Spirit came, to take supreme control.\nThe love enkindled flame is burning in my soul.\r\n\'Tis burning in my soul, \'tis burning in my soul,\nthe fire of heavenly love is burning in my soul.\nThe Holy Spirit came, all glory to His name!\nThe fire of heavenly love is burning in my soul.\r\nBefore the cross I bow, upon the altar lay,\na willing off’ring now, my all from day to day.\nMy Saviour paid the price, my name He sweetly calls.\nUpon the sacrifice the fire from Heaven falls.\r\nNo good that I have done, His promise I embrace.\nAccepted in the Son, He saves me by His grace.\nAll glory be to God! Let hallelujahs roll.\nHis love is shed abroad, the fire is in my soul.\r\n', 'Mein Herze lobt und preist und rühmt Gott Tag und Nacht,\nEr sandte Seinen Geist auf mich in Kraft und Macht,\nund seit mein Herz den Quell beständgen Friedens kennt,\nder Liebe Feuer hell in meiner Seele brennt.\r\nDer Liebe Feuer brennt, der Liebe Feuer brennt,\nin meiner Seel\' der heil\'gen Liebe Feuer brennt.\nDer Heil\'ge Geist zog ein, zu Jesu Ehr allein.\nIn meiner Seel\' der heil\'gen Liebe Feuer brennt.\r\nDas Kreuz ist mein Panier! Was ich auch hab und bin,\ndas lege willig hier auf den Altar ich hin.\nErkauft hat mich mit Blut, der meinen Namen nennt,\nund dessen Liebesglut in meiner Seele brennt.\r\nMir bleibt kein eig\'ner Ruhm; nur Gnade rühme ich,\ndie frei zum Eigentum des Sohns erkoren mich.\nO rühmet Jesu Lieb\', bis jedes Herz sie kennt,\nund bis ihr heißer Trieb in jeder Seele brennt!\r\nO zünde, Geist des Herrn, so wie Du einst getan,\nnoch einmal nah und fern ein mächtig Feuer an.\nLass jedes Jüngers Herz in heißer Lieb erglüh\'n,\nund stell sie allerwärts der Welt zum Zeugnis hin!'),
(9, '1279', 'Mein himmlisch Heim ist hell und schön  -  My heavenly Home is bright and fair   (Ja ich möcht gern weiter ziehn)', 'My heavenly home is bright and fair,\nI feel like travelling on.\nNor pain, nor death can enter there,\nI feel like travelling on.\r\nYes, I feel like travelling on,\nI feel like travelling on.\nMy heavenly home is bright and fair,\nI feel like travelling on.\r\nLet others seek a home below,\nI feel like travelling on.\nWhich flames devour, or waves o\'erflow,\nI feel like travelling on.\r\nThe Lord has been so good to me,\nI feel like travelling on.\nUntil that blessed home I see,\nI feel like travelling on.\r\nJesus has been so good to me,\nI feel like travelling on.\nHe knocked on my heart\'s door,\nI feel like travelling on.', 'Mein himmlisch\' Heim ist hell und schön,\nich möcht\' gern weiter zieh\'n.\nKein Schmerz, kein Tod kann dort hinein,\nich möcht\' gern weiter zieh\'n.\r\nJa ich möcht\' gern weiter zieh\'n,\nja ich möcht\' gern weiter zieh\'n.\nMein himmlisch\' Heim ist hell und schön,\nja ich möcht\' gern weiter zieh\'n.\r\nLass and\'re suchen die Heimat hier,\nich möcht\' gern weiter zieh\'n,\ndas von Flamm\'n verzehrt oder Well\'n überspült,\nich möcht\' gern weiter zieh\'n.\r\nDer Herr, Er ist so gut zu mir,\nich möcht\' gern weiter zieh\'n.\nBis ich die gesegnete Heimat seh\',\nich möcht\' gern weiter zieh\'n.\r\nMein Jesus war so gut zu mir,\nich möcht\' gern\' weiterzieh\'n.\nEr klopfet an die Herzenstür,\nich möcht\' gern\' weiterzieh\'n.'),
(9, '1280', 'Mein ist der Heiland, vorbei sind die Klagen  -  I have a Saviour, He’s pleading in Glory   (Mein Heiland liebt alle)', 'I have a Saviour, He’s pleading in glory,\na dear, loving Saviour, tho\' earth-friends be few.\nAnd now He is watching in tenderness o’er me,\nand, o, that my Saviour were your Saviour, too!\r\nFor you I am praying,\nfor you I am praying,\nfor you I am praying,\nI’m praying for you.\r\nI have a Father; to me He has given\na hope for eternity, blessed and true.\nAnd soon will He call me to meet Him in heaven,\nbut, oh, that He’d let me bring you with me, too!\r\nI have a robe: ’tis resplendent in whiteness,\nawaiting in glory my wondering view.\nOh, when I receive it all shining in brightness,\ndear friend, could I see you receiving one, too!\r\nI have a peace; it is calm as a river,\na peace that the friends of this world never knew.\nMy Saviour alone is its author and giver,\nand o, could I know it was given for you.\r\n\r\nWhen Jesus has found you, tell others the story,\nthat my loving Saviour is your Saviour, too.\nThen pray that your Saviour may bring them to glory,\nand prayer will be answered, ’twas answered for you!', 'Mein ist der Heiland, vorbei sind die Klagen;\nin Ihm ist die Freude, in Ihm ist die Ruh\'!\nIch kann es nicht lassen, von Ihm dir zu sagen,\no komm, Ihn zu kennen, o komme auch du!\r\nMein Heiland liebt alle,\nEr opferte sich,\num dich auch zu retten,\nEr liebet auch dich!\r\nMein ist der Vater, ich darf Ihm vertrauen;\nich weiß es, mein Hoffen betrüget mich nicht,\neinst darf ich in Herrlichkeit ewig Ihn schauen,\no fände ich dich nur auch droben im Licht!\r\nMein ist der Himmel; ich darf einst empfangen\ndas Kleid des Erlösten, so hell und so rein;\nund, Bruder, auch du kannst das Kleinod erlangen,\nauch du kannst dereinst bei den Seligen sein!\r\nMein ist der Friede im stürmischen Leben;\ndie Schmerzen, die Leiden versüßet Er mir.\nDie Welt kennt ihn nimmer und kann ihn nicht geben;\ndoch willst du ihn haben, der Herr gibt ihn dir.\r\nMein ist nun alles, weil Jesus gestorben,\nund glaubst du an Jesum, so ist es auch dein!\nO, soll dir denn alles vergeblich erworben\nund du nun kein ewig Geretteter sein?\r\nWenn einst mein Heiland auch dein Herz gefunden,\ndann schweige nicht, Bruder, bezeuge es frei!\nDann rühme die Liebe, die dich überwunden,\nund locke noch andere Herzen herbei!'),
(9, '1281', 'Mein Jesus ist wunderbar   (2 Chorusse)', NULL, 'Mein Jesus ist wunderbar,\nmein Jesus ist wunderbar!\nDie Sonne, der Mond und der Sterne Schar\nsagen\'s laut: "Er ist wunderbar".\r\nIch weiß, Er ist wunderbar,\nich weiß, Er ist wunderbar!\nEr rettet, Er heilt, bewahrt und erquickt;\nja ich weiß, Er ist wunderbar!'),
(9, '1282', 'Mein Jesus liebt mich allezeit   (Er hat mich so geliebt)', '\r\nBecause He loved me so,\nbecause He loved me so,\nHe bled and died on Calvary,\nbecause He loved me so.\r\n\r\n', 'Mein Jesus liebt mich allezeit,\nein volles Heil hat er bereit;\nund sei es finster, sei es licht,\nmein Jesus Christ verlässt mich nicht.\r\nEr hat mich so geliebt!\nEr hat mich so geliebt!\nEr starb für mich auf Golgatha,\nEr hat mich so geliebt!\r\nMein Jesus hilft in jeder Not,\ner ist fürwahr ein guter Gott!\nEs eilt mein armes Herz ihm zu\nund findet bei ihm sel\'ge Ruh\'.\r\nMein Jesus macht von Sünden rein,\nund davon darf ich Zeuge sein.\nHalleluja! Er wohnt in mir,\nund ich bin glücklich für und für!'),
(9, '1283', 'Mein Jesus weiß, was ich heute brauch  -  My Jesus knows just what I need   (Chorus)', 'My Jesus knows just what I need,\noh yes He knows just what I need.\nHe satisfies and every need supplies,\nyes, He knows just what I need.', 'Mein Jesus weiß, was ich heut\' brauch\',\no ja, Er weiß was ich heut\' brauch\'.\nEr gibt mir Kraft und nimmt der Sorgen Last;\nja, Er weiß, was ich heut\' brauch\'.'),
(9, '1284', 'Mein Jesus, ich liebe Dich, ich weiß, Du bist mein  -  My Jesus, I love Thee, I know, Thou art mine', 'My Jesus, I love Thee, I know Thou art mine.\nFor Thee all the follies of sin I resign.\nMy gracious Redeemer, my Saviour art Thou:\nif ever I loved Thee, my Jesus, \'tis now.\r\nI love Thee because Thou has first loved me,\nand purchased my pardon on Calvary\'s tree.\nI love Thee for wearing the thorns on Thy brow:\nif ever I loved Thee, my Jesus, \'tis now.\r\nI\'ll love Thee in life, I will love Thee in death,\nand praise Thee as long as Thou lendest me breath.\nAnd say when the death dew lies cold on my brow:\nif ever I loved Thee, my Jesus, \'tis now.\r\nIn mansions of glory and endless delight,\nI\'ll ever adore Thee in heaven so bright.\nI\'ll sing with the glittering crown on my brow:\nif ever I loved Thee, my Jesus, \'tis now.', 'Mein Jesus, ich lieb\' Dich, ich weiß, Du bist mein.\nDie Lust dieser Welt kann mich nicht mehr erfreu\'n.\nNie hab\' Deine Freuden so hoch ich geschätzt,\nWenn je ich Dich liebte, mein Jesus, ist\'s jetzt.\r\nIch lieb\' Dich, weil Du mich zuerst hast geliebt,\nweil Dein Tod am Kreuze Erlösung mir gibt.\nIch lieb\' Dich, weil Dornen Dein Haupt einst verletzt.\nWenn je ich Dich liebte, mein Jesus, ist\'s jetzt.\r\nIch lieb\' Dich im Leben, ich lieb\' Dich im Tod.\nIch preis\' Dich, solange mir Odem schenkt Gott.\nIch sag\'s noch, bedeckt mich auch Angstschweiß zuletzt:\nWenn je ich Dich liebte, mein Jesus, ist\'s jetzt.\r\nVorm himmlischen Thron, wo die Sünde besiegt,\nvergess\' ich den Jammer, der hinter mir liegt,\nund sing\' in der Krone, mit Sternen besetzt:\nWenn je ich Dich liebte, mein Jesus, ist\'s jetzt.'),
(9, '1285', 'Mein Jesus, lieber hab ich Dich als alle Erdenlust  -  I know I love Thee better Lord, than any earthly Joy   (Mir ward die Hälfte nie gesagt)', 'I know I love Thee better, Lord\nthan any earthly joy.\nFor Thou hast given me the peace\nwhich nothing can destroy.\r\nThe half has never yet been told,\nof love so full and free.\nThe half has never yet been told,\nthe blood, it cleanseth me.\r\nI know that Thou art nearer still\nthan any earthly throng.\nAnd sweeter is the thought of Thee\nthan any lovely song.\r\nThou hast put gladness in my heart,\nthen may I well be glad.\nWithout the secret of Thy love,\nI could not but be sad.\r\nO Saviour, precious Saviour mine!\nWhat will Thy presence be,\nif such a life of joy can crown\nour walk on earth with Thee?', 'Mein Jesus, lieber hab ich Dich\nals alle Erdenlust,\nseit Du mein Freund geworden bist,\nwohnt Fried\' in meiner Brust.\r\nMir ward die Hälfte nie gesagt,\nvon solcher Lieb und Huld!\nMir ward die Hälfte nie gesagt!\nDas Blut macht rein von Schuld!\r\nWohl ward mir Menschenfreundschaft lieb,\ndoch lieb wie Deine nie;\nDein Name klingt so süß und traut\nwie alte Melodie.\r\nIn meinem Herzen wohnst Du still;\nmit Dir zog Freude ein.\nO hätt\' ich Deine Liebe nicht,\ndann müsst ich traurig sein.\r\nO Jesus, lieber Jesus mein,\nist\'s hier bei Dir so schön,\nwas wird\'s für Wonne droben sein,\nwenn wir Dein Antlitz seh\'n!'),
(9, '1286', 'Mein Jesus, mein Retter, keiner ist so wie Du  -  My Jesus, my Saviour, Lord, there is none like You', 'My Jesus, my Saviour, Lord, there is none like You.\nAll of my days, I want to praise,\nthe wonders of Your mighty love.\nMy comfort, my shelter,\ntower of refuge and strength,\nlet ev\'ry breath, all that I am,\nnever cease to worship You.\r\nShout to the Lord, all the earth, let us sing,\npower and majesty, praise to the King.\nMountains bow down and the seas will roar\nat the sound of Your name.\nI sing for joy at the work of Your hands,\nforever I\'ll love You, forever I\'ll stand,\nnothing compares to the promise I have in You.', 'Mein Jesus, mein Retter, keiner ist so wie Du.\nLobpreis sei Dir, jeden Tag mehr,\nfür Deine große Liebe, Herr.\nMein Tröster, mein Helfer,\nDu bist mir Zuflucht und Kraft.\nAlles in mir, beugt sich vor Dir,\nDu bist hoch erhoben Herr!\r\nRuft zu dem Herrn, alle Enden der Welt,\nEhre und Dank, dem, der alles erhält.\nHimmel und Erde, erhebt Ihn und singt,\nwenn sein Name erklingt.\nWir preisen Dich, Du hast Großes getan.\nWir kommen vor Dich und beten Dich an.\nDank sei Dir Herr, Du bist unvergleichlich gut.'),
(9, '1287', 'Mein Leben gab ich hin, vergoss am Kreuz mein Blut  -  I gave My life for thee, My precious Blood I shed', 'I gave My life for thee,\nMy precious blood I shed,\nthat thou might\'st ransomed be,\nand quickened from the dead.\n|: I gave, I gave My life for thee,\nwhat hast thou giv\'n for Me? :|\r\nMy Father\'s house of light,\nMy glory circled throne,\nI left for earthly night,\nfor wanderings sad and lone.\n|: I left, I left it all for thee,\nHast thou left aught for Me? :|\r\nI suffered much for thee,\nmore than thy tongue can tell,\nof bitt\'rest agony,\nto rescue thee from hell.\n|: I\'ve borne, I\'ve borne it all for thee,\nWhat hast thou borne for Me? :|\r\nAnd I have brought to thee,\ndown from My home above,\nsalvation full and free,\nMy pardon and My love.\n|: I bring, I bring rich gifts to thee,\nWhat hast thou brought to Me? :|', 'Mein Leben gab ich hin,\nvergoss am Kreuz Mein Blut,\nzu sühnen Gottes Zorn,\ndas tat Ich dir zugut.\n|: Mein Leben gab Ich hin für dich;\nund was gibst du für Mich? :|\r\nIch kam vom Land des Lichts,\nvon Meinem Ehrenthron,\nnahm an Mich Knechtsgestalt,\nVerachtung, Spott und Hohn.\n|: Das alles tat Ich nur für dich;\nsprich: Was tust du für Mich? :|\r\nIch trug die Dornenkron\',\nSchmerz, Marter, Angst und Not;\nIch trank den bitter\'n Kelch,\nGehorsam bis zum Tod.\n|: Das, Sünder, das litt Ich für dich;\nwas leidest du für Mich? :|\r\nNun biete Ich dir an\nVergebung aller Schuld,\nund Heil und Seligkeit\naus lauter Gnad\' und Huld.\n|: Das alles will Ich geben dir;\ngib Mir dein Herz dafür. :|'),
(9, '1288', 'Mein Leben war ein einzig Jagen nach dem Glück   (Das war der schönste Tag,den Gott mir jemals gab)', NULL, 'Mein Leben war ein einzig\' Jagen nach dem Glück,\nich wusste nichts von Gott und nichts von Golgatha.\nEin Teil des Lebenswegs lag hinter mir zurück,\nbis Gott mich suchte, und ich endlich sagte: "Ja!"\r\nDas war der schönste Tag,\nden Gott mir jemals gab,\nals Jesus in mein dunkles\nErdendasein kam.   (2x)\r\nIch sah viel von der Lust und Freude dieser Welt,\ndoch Reichtum, Ruhm und Ehre machte mich nicht frei.\nMein Herz sucht\' ruhelos nach Frieden, Seelenruh\',\nbis ich erkannte, dass mein Ruh\'platz Jesus ist.\r\nSo glücklich wie bei Jesus war mein Leben nie,\nEr gab mir alles, was mein Herz ersehnte je.\nUnd wenn ich heute denk\' den Lebensweg zurück,\nso weiß ich, Jesus brachte mir das höchste Glück!'),
(9, '1289', 'Mein Leib und Seele freuen sich Dein  -  O Lord, my Soul rejoiceth in Thee   (Liebe, wie groß! O Liebe, wie groß!)', 'O Lord, my soul rejoiceth in Thee,\nmy tongue Thy mercy is telling.\nI’ve found Thy love so precious to me,\nmy heart with its rapture is swelling.\r\nWonderful love! O wonderful love!\nI’ll sing of its fullness forever.\nI’ve found the way that leadeth above,\nThe way to the life giving river.\r\nI came to Thee o’er-burdened with care,\nmy guilt with sorrow confessing.\n‘Twas love, Thy love, that banished my fear,\nand gave me for sadness a blessing.\r\nTo Thee, my hope and refuge divine,\nmy faith is fervently clinging.\nAnd ev‘ry hour some token of love,\nnew joy to my spirit is bringing.\r\nI look beyond this valley of tears,\nwhere Thou, a mansion preparing.\nWilt call me home forever with Thee,\nthe bliss of the glorified sharing.', 'Mein Leib und Seele freuen sich Dein!\nIch will die Gnade verkünden!\nO Jesu, was kann köstlicher sein.\nAls Dir sich in Liebe verbinden?\r\nLiebe, wie groß! O Liebe, wie groß!\nDurchflute mein Herz und mein Leben!\nMir ward fürwahr ein liebliches Los,\nein herrliches Erbteil gegeben!\r\nIch kam zu Dir, von Schulden bedrückt,\nzum Kreuz ich reuig mich wandte;\nda hat mich Deine Liebe beglückt;\no wie meine Seele entbrannte!\r\nMein Heil, mein Hort, mein Hoffen bist Du,\nein Fels, da nistet die Taube!\nIn Deinem Schatten himmlische Ruh\'!\nWie rastet und stärkt sich der Glaube!\r\nO Tränental! O eilende Zeit!\nMein harrt die Wohnung dort oben.\nMein Jesus hält die Stätte bereit;\nDort will ich im Chore ihn loben.'),
(9, '1290', 'Mein Vater der Allmächtige  -  My father is omnipotent   (Es war ein Wunder schon, als Er die Sterne nahm)', 'My father is omnipotent,\nand that you can\'t deny,\na God of might and miracles,\n\'t is written in the sky.\r\nIt took a miracle to put the stars in place,\nit took a miracle to hang the world in space.\nBut when He saved my soul, cleansed and made me whole,\nit took a miracle of love and grace.\r\nThough here His glory has been shown\nwe can\'t fully see,\nthe wonders of His might, His throne;\n\'t will take eternity.\r\nThe Bible tells us of His power\nand wisdom all the way through,\nand every little bird and flower\nare testimonies, too.', 'Mein Vater, der Allmächtige,\nja niemand ist wie Er,\nein Gott der Wunder und der Macht,\nam Himmel kundgetan.\r\nEs war ein Wunder schon, als Er die Sterne nahm\nund auch die Welt im All, dort ihren Platz bekam.\nDoch als Er löste mich, machte mich frei und rein,\nwar es ein Wunder Seiner Lieb\' und Gnad\'.\r\nObwohl wir Ihn schon hier geseh\'n\nin Seiner Herrlichkeit,\nzu seh\'n die Wunder Seiner Macht,\nbraucht es die Ewigkeit.\r\nDie Bibel spricht von Seiner Kraft\nund Weisheit für und für,\nund jeder Vogel, jede Blum\'\nsind Zeugnisse schon hier.'),
(9, '1291', 'Mein Vater ist reich an Gütern und Geld  -  My Father is rich in Houses and Land   (Bin ein königlich Kind)   [Gebhardt]', 'My Father is rich in houses and land,\nHe holdeth the wealth of the world in His hands!\nOf rubies and diamonds, of silver and gold,\nHis coffers are full, He has riches untold.\r\nI\'m a child of the King!\nA child of the King!\nWith Jesus my Saviour,\nI\'m a child of the King!\r\nMy Father\'s own Son, the Saviour of men.\nOnce wandered o\'er earth as the poorest of them.\nBut now He is reigning forever on high.\nAnd will give me a home in heav\'n by and by.\r\nA tent or a cottage, why should I care?\nThey\'re building a palace for me over there!\nThough exiled from home, yet still I may sing.\nAll glory to God, I\'m a child of the King!', 'Mein Vater ist reich an Gütern und Geld,\nund Sein sind alle Reiche und Schätze der Welt.\nHat mächt\'ge Kammern voll Silber und Gold,\nIhm werde die Ehre des Höchsten gezollt!\r\nBin ein königlich Kind,\nein königlich Kind,\nmit Jesus dem Heiland,\nja ein königlich\' Kind.\r\nMein Vater, der gab aus Liebe vom Thron\nzum Heil aller Welt seinen einzigen Sohn.\nDer starb und stieg siegreich vom Grabe zur Höh\'\nund schuf mir die Heimat, wohin ich bald geh!\r\nUnd ob auch die ir\'dsche Hütte zerbricht,\nmein Vater ist reich, darum sorge ich nicht;\nmein wartet ein Heim, wo die Seligen sind;\npreist Gott, denn ich bin ja Sein königlich Kind!'),
(9, '1292', 'Mein Vater ist reich an Häusern und Land  -  My Father is rich in Houses and Lands   (Bin ein königlich Kind)   [Rauschenbusch]', 'My Father is rich in houses and lands,\nHe holdeth the wealth of the world in His hands!\nOf rubies and diamonds, of silver and gold.\nHis coffers are full, He has riches untold.\r\nI\'m a child of the King!\nA child of the King!\nWith Jesus my Saviour,\nI\'m a child of the King!\r\nMy Father\'s own Son, the Saviour of men.\nOnce wandered o\'er earth as the poorest of  them.\nBut now He is reigning forever on high.\nAnd will give me a home in heav\'n by and by.\r\nI once was an outcast, stranger on earth.\nA sinner by choice, an alien by birth!\nBut I\'ve been adopted, my name\'s written down.\nAn heir to a mansion, a robe, and a crown.\r\nA tent or a cottage, why should I care?\nThey\'re building a palace for me over there!\nThough exiled from home, yet still I may sing.\nAll glory to God, I\'m a child of the King!', 'Mein Vater ist reich an Häusern und Land,\nEr hält alle Schätze der Welt in der Hand.\nSein sind die Rubinen samt Silber und Gold,\nIhm werden die Ehren des Höchsten gezollt.\r\nBin ein königlich Kind,\nein königlich Kind,\nmit Jesus dem Heiland,\nja ein königlich\' Kind.\r\nMein Vater gab uns aus Liebe vom Thron\nzum Heil aller Welt Seinen einzigen Sohn.\nEr starb und stieg siegreich vom Grabe zur Höh\'\nund schuf mir die Heimat, zu der ich nun geh.\r\nEinst irrt\' ich als Fremdling traurig einher,\nin Sünden geboren, liebt\' Weltlust so sehr.\nJetzt bin ich gerettet, mein Name steht schon\nals Erbe im Himmel, bald trag\' ich die Kron\'!\r\nUnd ob auch die irdische Hülle zerbricht,\nmein Vater ist reich, darum sorge ich nicht.\nMein wartet ein Heim, wo die Seligen sind,\npreis Gott, denn ich bin ja ein königlich Kind!'),
(9, '1293', 'Mein Volk, das in vergangnen Tagen des Herren Banner fröhlich schwang', NULL, 'Mein Volk, das in vergang\'nen Tagen\ndes Herren Banner fröhlich schwang;\ndazu, von hohem Geist getragen,\nso himmlisch schöne Lieder sang,\nwo ist denn deiner Väter Glauben,\nihr\' feste Burg, ihr\' Waff\' und Wehr?\nDu ließt dein höchstes Gut dir rauben\nvon einem ganzen Höllenheer!\r\nMein Volk, das in verfloss\'nen Zeiten\nmit einer heiligen Geduld,\nverfolgt, erträgt die schwersten Leiden,\ngestützt auf Gottes Vaterhuld,\nkaum sahn wir dich dem Leid entrinnen,\nso warfst du dich zum Herrscher auf,\num schnell am Faden fortzuspinnen,\nwo Rom verlor den blut\'gen Lauf!\r\nMein Volk, das einstens protestierte\nvoll Kühnheit wider Trug und Wahn,\ndass schnell dein Geist, der lang\' verirrte,\nbetrat der Wahrheit lichte Bahn.\nIst jener Kampf denn schon beendet,\nim Geist besiegt der Lügner Rott\'?\nWeh\' dir, du hast dein Herz gewendet,\nbekämpfst das Licht nun selbst mit Spott!\r\nMein Volk, erwach\' aus deinem Schlummer\nund kehr\' zu deinem Herrn zurück,\nsonst trifft dich endlich schwerer Kummer,\nverscherz\' doch nicht dein eig\'nes Glück!\nFolg\' deiner Väter treuem Mahnen,\nnoch hast du hierzu Gnadenfrist.\nO schar\' dich eilends zu den Fahnen\ndes Siegesfürsten Jesus Christ.'),
(9, '1294', 'Mein Zelt ist abgeschlagen  -  My Tent is no more pitched', 'My tent is no more pitched\ndown there in Egyptland.\nYou won\'t see me no more there,\nI live in another land.\nHalleluja, Halleluja,\nHalleluja, Halleluja.\r\n', 'Mein Zelt ist abgeschlagen\ndort unten in  Ägyptenland.\nDu siehst mich nie mehr dort,\nich wohne im ander\'n Land.\nHalleluja, Halleluja,\nHallelujah, Hallelujah!\r\nIch bin der Sünde tot,\nentfloh\'n der Lust der Welt.\nIch bin so glücklich nun,\ndie Liebe Gottes hält.\nHallelujah, Hallelujah,\nHallelujah, Hallelujah!'),
(9, '1295', 'Mein, mein, mein, Jesus ist mein  -  Mine, mine, mine, Jesus is mine   (Chorus)', 'Mine, mine, mine, Jesus is mine.\nMine, mine, mine, Jesus is mine.\nJesus is my saviour day by day,\nmine, mine, mine, Jesus is mine.', 'Mein, mein, mein, Jesus ist mein.\nMein, mein, mein, Jesus ist mein.\nJesus ist mein Retter Tag für Tag,\nmein, mein, mein, Jesus ist mein.'),
(9, '1296', 'Meine Freude ist groß in dem Herrn  - I will greatly rejoice in the Lord   (So ist mein Gott, Er rettet mich)', 'I will greatly rejoice in the Lord,\nmy soul shall be joyful in my God,\nI will greatly rejoice in the Lord,\nmy soul shall be joyful in my God,\nfor He has clothed me, clothed me\nin the garments of salvation,\nand He has covered me, covered me\nwith the robe of righteousness!\r\nThis is our God, He will save us,\nwe will rejoice\nand be glad in His salvation! (2x)\nThis is our God...!', 'Meine Freude ist groß in dem Herrn,\nmeine Seele freut sich in meinem Gott,\nmeine Freude ist groß in dem Herrn,\nmeine Seele freut sich in meinem Gott,\ndenn Er bekleidet mich, bekleidet mich\nmit Gewändern der Erlösung,\nund Er bedeckt mich, bedeckt mich\nmit Kleidern Seines Heils!\r\nSo ist mein Gott, Er rettet mich,\nich freue mich\nund bin froh in der Erlösung! (2x)\nSo ist mein Gott …'),
(9, '1297', 'Meine Hände waren voll von Dingen, die mit Stolz ich einstmals nannte mein', NULL, 'Meine Hände waren voll von Dingen,\ndie mit Stolz ich einstmals nannte mein.\nEdlen Steinen gleich in gold\'nen Ringen,\nstrahlten sie mir zauberhaft und fein.\nAber Jesus nahm mir meine Hände,\nließ sie stille in den Seinen ruh\'n;\nmachte so der eitlen Lust ein Ende,\nalles fiel zu Seinen Füßen hin.\r\nMeine Hände waren alle Tage\nimmer unrein und mit Schuld befleckt.\nAch, umsonst war alle meine Plage,\nmeine Sünde war noch nicht bedeckt.\nAber Jesus nahm mir meine Hände,\nließ die meinen in den Seinen ruh\'n;\nmachte so der Unruh\' bald ein Ende,\ndurch Sein Blut war ich gereinigt nun.\r\nUngehorsam waren meine Hände,\nnur dem eig\'nen Willen untertan.\nGleich, als ob man so sein Leben fände,\no, wie rang ich da in stillem Wahn!\nAber Jesus nahm mir meine Hände,\nließ die Seinen auf den meinen ruh\'n;\nmachte so der Unruh\' bald ein Ende.\nO, wie süß ist der Gehorsam nun.'),
(9, '1298', 'Meine Heimat ist dort in der Höh\'  -  O think of the Home over there   (In der Höh, in der Höh)', 'O think of the home over there,\nby the side of the river of light,\nwhere the saints all immortal and fair,\nare robed in their garments of white.\r\nOver there, over there,\no think of the home over there.\nOver there, over there,\no think of the home over there.\r\nO think of the friends over there,\nwho before us the journey have trod.\nOf the song that they breathe on the air\nin their home in the palace of God.\r\nMy Saviour is now over there,\nwhere my kindred and friends are at rest.\nThen away from my sorrow and care\nlet me fly to the land of the blest.\r\nI’ll soon be at home over there,\nfor the end of my journey I see.\nMany dear to my heart over there\nare waiting and watching for me.', 'Meine Heimat ist dort in der Höh\',\nwo man nichts weiß von Trübsal und Weh\',\nwo die heil\'ge unzählbare Schar\njubelnd preiset das Lamm immerdar.\r\nIn der Höh\', in der Höh\',\nmeine Heimat ist dort in der Höh\'.\nIn der Höh\', in der Höh\',\nmeine Heimat ist dort in der Höh\'.\r\nViel\' Geliebte sind dort in der Höh\',\nwo ich sie einst verklärt wieder seh\',\nund dann bleiben wir immer vereint\ndort, wo ewig die Sonne uns scheint.\r\nHerr, ich freu\' mich, bis dort in der Höh\',\nich vor dir, meinem Heilande, steh\',\nzieh mich Dir nach, dass wo Du nun bist,\nauf dein Wort hin Dein Diener auch ist.\r\nJa, bald werd\' ich dort sein in der Höh\'!\nO mein Jesu, um eines ich fleh\',\nbring die Meinen doch alle mit mir\nzu der himmlischen Heimat zu Dir.'),
(9, '1299', 'Meine Hoffnung und meine Freude, meine Stärke, mein Licht  -  In the Lord I\'ll be ever thankful, in the Lord I will rejoice   (Chorus)', 'In the Lord I\'ll be ever thankful,\nin the Lord I will rejoice!\nLook to God, do not be afraid.\nLift up your voices, the Lord is near.\nLift up your voices, the Lord is near.', 'Meine Hoffnung und meine Freude,\nmeine Stärke, mein Licht,\nChristus, meine Zuversicht,\nauf dich vertrau\' ich und fürcht\' mich nicht,\nauf dich vertrau\' ich und fürcht\' mich nicht.'),
(9, '1300', 'Meine Seel irrte ab von dem himmlischen Pfad  -  Once my Soul was astray from the heavenly Way   (Er reichte Seine Hand nach mir)', 'Once my soul was astray from the heavenly way,\nand was wretched and vile as could be.\nBut my Saviour above, gave me peace, joy and love,\nwhen He reached down His hand for me.\r\nWhen He reached down His hand for me,\nwhen He reached down His hand for me.\nI was lost and undone, without God or His Son,\nwhen He reached down His hand for me.\r\nI was nearing despair, when He came to me there,\nand He showed me that I could be free.\nThen He lifted my feet, gave me glory complete,\nwhen He reached down His hand for me.\r\nHow my heart doth rejoice since I made Him my choice,\nfrom the tempest to Him now I flee.\nNow I lean on His arm I\'m secure from all harm,\nsince he reached down His hand for me.\r\nSince the Lord gave me peace, heavenly joys never cease,\nLord, I give all my life unto Thee.\nGuide my feet, hold my hand, grant with Thee I may stand,\nfor you reached down Your hand for me.', 'Meine Seel\' irrte ab, von dem himmlischen Pfad,\nwar erbärmlich, voll böser Begier\'.\nDoch mein Heiland, Er gab mir den Frieden und Gnad\',\nals Er reichte Seine Hand nach mir.\r\nEr reichte Seine Hand nach mir,\nEr reichte Seine Hand nach mir.\nWar verlor\'n, diente Fron,\nohne Gott\'s eig\'nem Sohn,\nals Er reichte Seine Hand nach mir.\r\nVerzweifelt war ich fort, als Er kam zu mir dort,\nbefreite mich von Sünden allhier.\nEr hob mich aus dem Staub, gab mir völligen Glaub\',\nals er reichte Seine Hand nach mir.\r\nNun mein Herz jubelt gern, seit ich nenne Ihn "Herrn",\ndenn die Botschaft ist jetzt mein Panier.\nLehnend auf Seinen Arm, bin geschützt ich vor Harm,\nseit Er reichte Seine Hand nach mir.\r\nWeil der Herr mir nicht fremd, hat die Freude kein End\',\nHerr, ich geb\' all mein Leben zu Dir.\nFühre mich an der Hand, bis ich sehe Dein Land,\ndenn Du reichtest Deine Hand nach mir.'),
(9, '1301', 'Meine Seele dürstet nach Gott   (Was betrübst du dich, meine Seele)', NULL, 'Meine Seele dürstet nach Gott,\nWann werd\' ich nur dahin kommen,\ndass das Angesicht Gottes ich schaue,\nder meine Freude ist.\nHalleluja, Halle-, Halleluja,\nHalleluja, Halleluja.\r\nWas betrübst du dich, meine Seele\nund bist so unruhig in mir?\nHarre auf Gott,\ndenn ich werde Ihm noch danken.\r\nAlle Tage sendet der Herr\nseine endlos große Güte,\nund des Nachts singe ich ihm und bete\nzu dem Gott, der mein Leben ist.\nHalleluja, Halle-, Halleluja,\nHalleluja, Halleluja.\r\nDeine Wahrheit und dein Licht\nsende mir, dass sie mich leiten\nund mich bringen zu deiner Wohnung.\nMein Gott, ich danke dir.\nHalleluja, Halle-, Halleluja,\nHalleluja, Halleluja.'),
(9, '1302', 'Meine Sünden sind vergeben, ich bin frei, ich bin frei   (Halleluja, Halleluja, Jesus starb für mich)', NULL, 'Meine Sünden sind vergeben;\nich bin frei, ich bin frei!\nChristus schenkte mir das Leben;\nich bin frei, ich bin frei!\r\nHalleluja, Halleluja,\nJesus starb für mich.\nHalleluja, Halleluja!\nIch bin frei, ich bin frei!\r\nAls ich lernte Ihm vertrauen,\nwurd\' ich frei, wurd\' ich frei!\nAls der Heil\'ge Geist mich füllte,\nblieb ich frei, blieb ich frei!\r\nLos von allen Sündenketten,\nbleib ich frei, bleib ich frei!\nDarf als Kind vor Gott hintreten;\nich bin frei, ich bin frei!'),
(9, '1303', 'Meine Vision, Herr, sei mir nur Dein Wort  -  Be Thou my Vision, o Lord of my Heart', 'Be Thou my vision, o Lord of my heart,\nnaught be all else to me, save that Thou art.\nThou my best thought, by day or by night,\nwaking or sleeping, thy presence my light.\r\nBe Thou my wisdom, be Thou my true word,\nI ever with Thee, and Thou with me Lord.\nBorn of Thy love, Thy child may I be,\nThou in me dwelling and I one with Thee.\r\nBe Thou my buckler, my sword for the fight,\nbe Thou my dignity, Thou my delight.\nThou my soul’s shelter, Thou my high tow’r,\nraise Thou me heav’nward, o pow’r of my pow’r.\r\nRiches I heed not, nor vain empty praise,\nThou mine inheritance, now and always.\nThou and Thou only, first in my heart,\nRuler of heaven, my treasure Thou art.\r\nHigh King of heaven, when vict’ry is won\nmay I reach heaven’s joys, o bright heav’n’s Sun!\nHeart of my heart, whatever befall,\nstill be my vision, o Ruler of all.', 'Meine Vision. Herr, sei mir nur Dein Wort,\nLicht meines Lebens, Herr, an jedem Ort!\nLass mich erkennen was Du wünschst von mir,\nwas ich heut\' habe, Herr, kommt nur von Dir.\r\nSei meine Weisheit und zeig mir den Weg,\nzeig\' wo dein Geist heut\' das Wasser bewegt!\nDu hast die Siegel gebrochen für mich,\nDu gibst mir Speise und rufst mich zu Tisch.\r\nSei Du im Kampfe mein Schild nur allein,\nSchwert Deines Wortes, Du sollst alles sein!\nDu hältst mich aufrecht und D machst mir Mut.\nin Satans Eden bewahrst Du mich gut.\r\nIch such nicht Schätze, nicht Reichtum und Ehr\',\ndenn was Du mir schenks,t das lieb\' ich viel mehr.\nIch bin ein Erbe, bin in Deiner Hand.\nDein sind die Himmel und Dein ist das Land.\r\nSo geh\' ich weiter zur himmlischen Stadt,\ndie mir mein König heut\' verheißen hat.\nMeine Vision ist: Nur Leben für Ihn!\n"Jesus mein König ich muss mir Dir zieh\'n!"'),
(9, '1304', 'Meine Zeit steht in Deinen Händen (Sorgen quälen und werden mir zu groß)', NULL, 'Meine Zeit steht in Deinen Händen,\nnun kann ich ruhig sein, ruhig sein in Dir.\nDu gibst Geborgenheit, Du kannst alles wenden,\nGib mir ein festes Herz, mach es fest in Dir.\r\nSorgen quälen und werden mir zu groß,\nmutlos frag ich: "Was wird morgen sein?"\nDoch Du liebst mich, Du lässt mich nicht los.\nVater, Du wirst bei mir sein.\r\nHast und Eile, Zeitnot und Betrieb\nnehmen mich gefangen, jagen mich.\nHerr, ich rufe: "Komm und mach mich frei!\nFühre Du mich Schritt für Schritt!"\r\nEs gibt Tage, die bleiben ohne Sinn.\nHilflos seh\' ich, wie die Zeit verrinnt.\nStunden, Tage, Jahre gehen hin,\nund ich frag, wo sie geblieben sind.'),
(9, '1305', 'Meinen Heiland höre ich, deine Kraft genüget nicht  -  I hear the Saviour say, thy Strength is small   (Jesus trug die Schuld / Jesus paid it all)   [Bieselsberg]', 'I hear the Saviour say:\n"Thy strength indeed is small,\nchild of weakness, watch and pray,\nfind in Me thine all in all."\r\nJesus paid it all.\nAll to Him I owe.\nSin had left a crimson stain,\nHe washed it white as snow.\r\nLord, now indeed I find,\nThy pow\'r and Thine alone,\ncan change the leper\'s spots,\nand melt the heart of stone.\r\nSince nothing good have I,\nwhereby Thy grace to claim,\ni\'ll wash my garments white,\nin the blood of Calv\'ry\'s Lamb.', 'Meinen Heiland höre ich:\n"Deine Kraft genüget nicht.\nKind von Schwachheit, schau auf mich,\nalles findest du in mir."\r\nJesus trug die Schuld,\nalles dank\' ich Ihm,\nSünde, die einst purpurrot,\nEr wusch sie weiß wie Schnee.\r\nHerr, nun weiß ich ganz gewiss,\nDeine Kraft ist es allein,\nsie kann heilen alle Sünd\'\nund sie nimmt das Herz aus Stein.\r\nWeil ich doch nichts bringen kann,\nist es Gnade nur allein,\nin dem Blut von Golgatha wasch\'\nich meine Kleider rein.'),
(9, '1306', 'Meines Herzens tiefste Sehnsucht und mein Hoffen   (Es ist Heil für dich in Jesu Blut und Wunden)', NULL, 'Meines Herzens tiefste Sehnsucht und mein Hoffen,\nfand Erfüllung, als ich einst zu JESUS kam.\nDort am Kreuz fand ich den Himmel für mich offen,\nfand Vergebung in dem teuren Gotteslamm!\r\nEs ist Heil für dich in Jesu Blut und Wunden,\nFrieden findest du am Kreuz von Golgatha!\nDenn auch ich hab dort das wahre Glück gefunden,\njubelnd preise ich den HERRN, Halleluja!\r\nNun hab ich für immer einen Freund gefunden,\ndem ich alles sage, was mich hier bedrückt.\nEr ist bei mir in des Lebens schwersten Stunden,\nSeine Gegenwart hat mich so oft beglückt!\r\nBald ist diese Gnadenzeit für dich zu Ende,\ndunkel drohend kommt gar schnell die Mitternacht!\nO noch heute dich zu Jesus Christus wende!\nBald erscheint Er in der Luft mit großer Pracht.'),
(9, '1307', 'Meister, es toben die Winde, die Wellen bedrohn uns sehr  -  Master, the Tempest is raging! The Billows are tossing high   (Er spricht: Wind und Meer, folg, wie ich es will)', 'Master, the tempest is raging!\nThe billows are tossing high!\nThe sky is o\'er-shadowed with blackness,\nno shelter or help is nigh.\n"Carest Thou not that we perish?"\nHow canst Thou lie asleep.\nWhen each moment so madly\nis threatening a grave in the angry deep?\r\n"The winds and the waves shall obey My will,\npeace, be still! Peace be still"\nWhether the wrath of the storm-tossed sea,\nor demons or men or whatever it be,\nno water can swallow the ship where lies\nthe Master of ocean and earth and skies.\nThey all shall sweetly obey My will. Peace, be still! Peace be still!\nThey all shall sweetly obey My will, peace, peace, be still!\r\nMaster, with anguish of spirit,\nI bow in grief today.\nThe depths of my sad heart are troubled,\no waken and save, I pray!\nTorrents of sin and of anguish\nsweep o\'er my sinking soul!\nAnd I perish! I perish, dear Master.\nO hasten and take control!\r\nMaster, the terror is over,\nthe elements sweetly rest.\nEarth\'s sun in the calm lake is mirrored,\nand heaven\'s within my breast.\nLinger, o blessed Redeemer,\nleave me alone no more.\nAnd with joy I shall make the blest harbor,\nand rest on the blissful shore.', 'Meister, es toben die Winde,\ndie Wellen bedroh\'n uns sehr;\nder Himmel umwölkt sich gar schaurig,\nwo nehmen wir Rettung her?\nFragst Du nicht, ob wir verderben,\nmerkst nicht, wie wir bedrängt?\nJeden Augenblick kann es geschehen,\nund wir sind im Tod versenkt!\r\nEr spricht: "Wind und Meer, folg\', wie ich es will!\nSchweig, sei still! Schweig, sei still!"\nOb es auch wüte, das stürmische Meer,\nob\'s Menschen, ob\'s Teufel sind oder was mehr,\ndas Schifflein bleibt sicher, wo Jesus Christ,\nder Herr aller Herren, der Meister ist.\nEs muss alles geh\'n, wie er es will. Schweig, schweig, sei still!\nEs muss alles geh\'n, wie er es will. Herz, schweig, sei still!\r\nMeister, voll Unruh im Herzen\nruf heute ich laut zu Dir.\nDie Tiefen sind in mir erreget,\nkomm, rette mich, hilf auch mir!\nStürme von schwerer Versuchung\ntreten an mich heran;\nich verderbe, o Herr, ich verderbe,\nhilf mir als mein Steuermann!\r\nMeister, der Sturm ist vorüber,\ndas tosende Meer nun schweigt,\nund hell scheint die herrliche Sonne,\ndie himmlische Gunst mir zeigt.\nO Du, mein großer Erretter,\nlass mich nicht mehr allein!\nDann gelange ich glücklich zum Hafen\nund werde geborgen sein.'),
(9, '1308', 'Merk, Seele, dir das große Wort', NULL, 'Merk, Seele, dir das große Wort:\nWenn Jesus winkt, so geh!\nWenn Er dich zieht, so eile fort!\nWenn Jesus hält, so steh!\r\nWenn Er dich reich macht, beuge dich!\nWenn Er dich liebt, so ruh\'!\nWenn Er dich aber schilt, so sprich:\n"Ich brauch\'s, Herr, schlage zu!"\r\nWenn Jesus in der Gnadenzeit\nsich da und dort verklärt,\nso freu\' dich der Barmherzigkeit,\ndie andern widerfährt!\r\nWenn Er dich aber brauchen will,\nso steig in Kraft empor!\nGebietet Jesus dir: "Sei still!"\nSo nimm auch du nichts vor!\r\nLeib, Seele ganz, das ganze Herz\ngehöre Jesu an;\nBei Schmach, bei Mangel und bei Schmerz\nsei es Ihm zugetan!'),
(9, '1309', 'Messiah is the King of Kings', 'Messiah is the King of kings,\nMessiah is the Lord of lords.\nMessiah is the King of kings,\nMessiah is the Lord of lords.\nHe is the King of kings,\nHe is the Lord of lords.\nMessiah is the King of kings,\nMessiah is the Lord of lords.', NULL),
(9, '1310', 'Mich verlangt nicht nach Schätzen, nicht nach Silber und Gold  -   Lord, I care not for Rriches, neither Silver nor Gold   (Dass mein Name dort steh)', 'Lord, I care not for riches, neither silver nor gold.\nI would make sure of Heaven, I would enter the fold.\nIn the book of thy Kingdom, with its pages so fair.\nTell me, Jesus, my Saviour, is my name written there?\r\nIs my name written there,\non the pages white and fair?\nIn the book of thy Kingdom,\nis my name written there?\r\nLord, my sins they are many, like the sands of the sea,\nbut Thy blood, o my Saviour, is sufficient for me.\nFor thy promise is written in bright letters that glow,\nthough your sins be as scarlet, I will make them like snow.\r\nO that beautiful city with its mansions of light,\nWith its glorified beings in pure garments of white;\nWhere no evil thing cometh to despoil what is fair;\nWhere the angels are watching, yes, my name is written there.\r\nYes, my name’s written there,\non the pages white and fair,\nin the book of thy Kingdom,\nyes, my name’s written there.', 'Mich verlangt nicht nach Schätzen, nicht nach Silber und Gold;\nmich verlanget zu wissen, ob mein Heiland mir hold.\nMeine Seele ist rastlos, nach Gewissheit sie fleht,\nob im Buche des Lebens wohl auch mein Name steht.\r\nDass mein Name dort steh!\nNur um dieses ich fleh\';\ndass im Buche des Lebens\ndoch auch mein Name steh!\r\nMeiner Sünden sind viele, wie der Sand an dem Strand,\ndoch ist mächtig zu helfen meines Heilandes Hand.\nWär\' auch blutrot die Sünde, soll sie werden wie Schnee,\ndarum komm ich und frage, ob mein Name dort steh.\r\nO Jerusalem droben, Stadt von Golde erbaut,\nvon dem ewigen König Ihm erkoren zur Braut!\nWo die Harfen Ihm rauschen, wo der Kummer vergeht!\nHalleluja, ich weiß es, dass mein Name dort steht.\r\n'),
(9, '1311', 'Mich ziehts ins verheißne Land', NULL, 'Mich zieht\'s ins verheiß\'ne Land,\no, mich zieht\'s ins verheiß\'ne Land.\nHast du Sehnsucht auch dort hinzugeh\'n?\nMich zieht`s ins verheiß\'ne Land.\r\nBin bestimmt für\'s verheißene Land,\nbin bestimmt für\'s verheißene Land.\nHast du Sehnsucht auch dort einzugeh\'n?\nBin bestimmt für\'s verheißene Land.'),
(9, '1312', 'Mine Eyes have seen the Glory of the Coming of the Lord  -  (Mein Auge sah die Ankunft unseres Herrn in ihrem Ruhm)   [Wikipedia]', 'Mine eyes have seen the glory of the coming of the Lord;\nHe is trampling out the vintage where the grapes of wrath are stored.\nHe hath loosed the fateful lightning of His terrible swift sword:\nHis truth is marching on.\r\nGlory! Glory, halleluja!\nGlory! Glory, halleluja!\nGlory! Glory, halleluja!\nHis Truth is marching on.\r\nI have seen Him in the watchfires of a hundred circling camps,\nthey have builded Him an altar in the evening dews and damps.\nI can read His righteous sentence by the dim and flaring lamps:\nHis day is marching on.\r\nI have read a fiery gospel writ in burnished rows of steel:\n“As ye deal with my contemners, so with you my grace shall deal."\nLet the Hero, born of woman, crush the serpent with his heel:\nSince God is marching on.”\r\nHe has sounded forth the trumpet, that shall never sound retreat,\nHe is sifting out the hearts of men before His judgment seat.\nOh be swift, my soul, to answer Him, be jubilant, my feet:\nOur God is marching on.\r\nIn the beauty of the lilies Christ was born across the sea,\nwith a glory in His bosom that transfigures you and me.\nAs He died to make men holy, let us die to make men free;\nWhile God is marching on.\r\nHe is coming like the glory of the morning on the wave,\nHe is wisdom to the mighty, He is honour to the brave.\nSo the world shall be His footstool, and the soul of wrong His slave:\nOur God is marching on.', '(Der deutsche Text ist eine Nachdichtung, ob singbar???)\nMein Auge sah die Ankunft unseres Herrn in ihrem Ruhm.\nEr stampfet aus die Kelter, wo des Zornes Früchte ruh\'n.\nSchon blitzt sein schrecklich schnelles Schwert, künd\'t Unheil bösem Tun:\nSeine Wahrheit schreitet voran.\r\nRühmt Ihn, rühmt Ihn, Halleluja!\nRühmt Ihn, rühmt Ihn, Halleluja!\nRühmt Ihn, rühmt Ihn, Halleluja!\nSeine Wahrheit schreitet voran.\r\nIn hunderten von Lagerfeuern sah ich Sein Gesicht,\nim Tau und Dunst des Abends ein Altar ward Ihm erricht’.\nSein Richterspruch erscheint vor mir im trüben Lampenlicht:\nSein Tag schreitet voran.\r\nIn glatten Stahl graviert die Botschaft klang wie Glockenton:\n„Kampf gegen die Verächter findet Meiner Gnade Lohn."\nEs zermalmt den Kopf der Schlange endlich nun der Menschensohn:\nDenn Gott schreitet voran.\r\nEr stieß in die Trompete, die zum Rückzug niemals ruft,\nnun richtet Er die Herzen, die erweckt Er aus der Gruft.\nSo eile, meine Seele, heb’ dich jubelnd in die Luft:\nUnser Gott schreitet voran.\r\nIn der Schönheit der Lilien Christ geboren dir und mir,\nwir, verklärt von Seinem Glanze, sammeln uns um Sein Panier.\nWie Er starb als unser Heiland, als Befreier sterben wir:\nUnd Gott schreitet voran.\r\nSein Kommen gleicht dem Strahlen morgendlicher Sonnenpracht,\nden Herrschern Weisheit und den Tapfer\'n Ehre Er vermacht.\nSein Reich auf unsrer Erde, es ist endlich nun vollbracht:\nUnser Gott marschiert voran.'),
(9, '1313', 'Mir ist Erbarmung wiederfahren', NULL, 'Mir ist Erbarmung widerfahren,\nErbarmung, deren ich nicht wert;\ndas zähl ich zu dem Wunderbaren,\nmein stolzes Herz hat\'s nie begehrt.\nNun weiß ich das und bin erfreut\nund rühme die Barmherzigkeit,\nund rühme die Barmherzigkeit.\r\nIch hatte nichts als Zorn verdienet\nund soll bei Gott in Gnaden sein;\nGott hat mich mit sich selbst versühnet\nund macht durchs Blut des Sohns mich rein.\nWo kam dies her? Warum geschieht\'s?\nErbarmung ist\'s und weiter nichts,\nErbarmung ist\'s und weiter nichts.\r\nDas muss ich Dir, mein Gott, bekennen,\ndas rühm\' ich, wenn ein Mensch mich fragt;\nich kann es nur Erbarmung nennen,\nso ist mein ganzes Herz gesagt.\nIch beuge mich und bin erfreut\nund rühme die Barmherzigkeit,\nund rühme die Barmherzigkeit.\r\nGott, der Du reich bist an Erbarmen,\nnimm Dein Erbarmen nicht von mir;\nund führe durch den Tod mich Armen,\ndurch meines Heilands Tod zu Dir.\nDa bin ich ewig recht erfreut\nund rühme die Barmherzigkeit,\nund rühme die Barmherzigkeit.'),
(9, '1314', 'Mit Glaubensflügeln flög ich gern   (Viele sind voraus und erwarten uns schon)', NULL, 'Mit Glaubensflügeln flög ich gern\nim raschen Flug dahin.\nWohl über Berge Tal und Höh\'n\nwo ich zu Hause bin.\r\nViele sind voraus und erwarten uns schon,\ndrüben an dem gold\'nen Strand.\nRuhen sich aus im weißen Gewand,\nund führen uns bald an der Hand.\nUnd uns ist so wohl und uns ist so wohl,\nauf dem Weg ins bess\'re Land.\nUnd uns ist so wohl, und uns ist so wohl,\nauf dem Weg ins bess\'re Land.\r\nDer Liebeszug ist erst gestillt,\nwenn ich den Schmerzensmann,\nden meine ganze Seele liebt,\nmit Augen sehen kann.\r\nUnd darf es noch nicht heute sein,\nso geht\'s wie Gott es will.\nMein Leben steht in IHM allein,\nEr führ\' es wie Er will.'),
(9, '1315', 'Mit Jesus geb ich alles in den Tod, Er ist ja mein Retter aus der Not  -  I left it all with Jesus long ago, all my Sins I brought Him and my Woe', 'I left it all with Jesus long ago,\nall my sins I brought him and my woe.\nWhen by faith I saw him on the tree,\nheard his loving whisper: ‘Tis for thee.\nFrom my heart the burden rolled away,\nHappy day!\r\nI leave it all with Jesus day by day.\nFaith can firmly trust him, come what may.\nHope has dropped her anchor, found her rest\nin the calm, sure haven of his breast.\nLove esteems it Heaven to abide,\nat his side.\r\nI leave it all with Jesus, for he knows\nhow to steal the bitter from life’s woes.\nHow to gild the teardrop with his smile,\nmake the desert garden bloom awhile.\nWhen my weakness leaneth on his might,\nall is light!\r\nO leave it all with Jesus, needy soul.\nTell not half the story, but the whole.\nWorlds on worlds are hanging on his hand,\nlife and death are waiting his command.\nYet his tender mercy makes thee room,\no come home!', 'Mit Jesus geb\' ich al!es in den Tod,\nEr ist ja mein Retter aus der Not.\nSeit ich Ihn am Kreuze hängen sah,\nist mein liebstes Plätzchen Golgatha.\nHier hab ich im Glauben, Fried\' und Freud\', sei\'ge Zeit,\nhier hab ich im Glauben Fried\' und Freud\', sei\'ge Zeit.\r\nMit Jesus geb\' ich alles, Er weiß wohl,\nwie Er mich, Sein Schäflein, führen soll.\nEr gibt Sonn\' und Regen auf die Au\'n,\nund lässt mich den Segen Gottes schau\'n.\nD\'rum will ich vertrauen Seiner Macht Tag und Nacht,\nd\'rum will ich vertrauen Seiner Macht Tag und Nacht.\r\nMit Jesus geb\' ich alles Tag für Tag;\nbin getrost, mag kommen, was da mag.\nEr ist meines Glaubens Ankergrund,\nSeiner Liebe Balsam macht gesund.\nUnd des Herzens Hoffnung trüget nicht in dem Licht,\nund des Herzens Hoffnung trüget nicht in dem Licht.\r\nMit Jesus gib dein alles, liebe Seel\',\nIhn, Sein Heil und Leben dir erwähl\'!\nWeltlust, Ehr\' und Freuden schnell vergeh\'n,\nGottes Lieb und Gnade, die besteh\'n.\nEil\' zu Seinem Herzen! Komm herzu, hier ist Ruh\',\neil\' zu Seinem Herzen! Komm herzu, hier ist Ruh\'!'),
(9, '1316', 'Mit Jesus gestorben im Tode sein  -  Dying with Jesus, by Death reckoned mine   (Stunde um Stunde hab in Ihm ich Ruh)', 'Dying with Jesus, by death reckoned mine,\nliving with Jesus, a new life divine,\nlooking to Jesus till glory doth shine,\nMoment by moment, O Lord, I am thine.\r\nMoment by moment I’m kept in His love,\nmoment by moment I’ve life from above,\nlooking to Jesus till glory doth shine,\nmoment by moment, O Lord, I am Thine.\r\n\r\nNever a trial that He is not there,\nnever a burden that He doth not bear,\nnever a sorrow that He doth not share,\nmoment by moment, I’m under His care.\r\nNever a heartache, and never a groan,\nnever a teardrop, and never a moan;\nnever a danger but there on the throne,\nmoment by moment He thinks of His own.\r\nNever a weakness that He doth not feel,\nnever a sickness that He cannot heal.\nMoment by moment, in woe or in weal,\nJesus my Saviour abides with me still.\r\n\r\n', 'Mit Jesus gestorben im Tode sein,\nmit Jesus lebend und für Ihn allein,\nwart ich auf Jesus, bis dass Er erschein\',\nStunde um Stunde, o Herr bin ich Dein.\r\nStunde um Stunde hab in Ihm ich Ruh\',\nfließt Seine Kraft und Sein Leben mir zu,\nwart ich auf Jesus, bis dass Er erschein\',\nStunde um Stunde, o Herr, bin ich Dein.\r\nNie einen Streit, wo die Wahrheit erliegt,\nnie einen Kampf, in dem Jesus nicht siegt.\nHell leuchtend strahlt Seiner Liebe Panier,\nStunde um Stunde ist Jesus bei mir.\r\nNiemals Versuchung, die vor Ihm nicht flieht,\nnie einen Kummer, den Jesus nicht sieht,\nnie eine Last mehr, Er nimmt sie auf Sich,\nStunde um Stunde sorgt Jesus für mich.\r\nNie eine Träne und nie einen Schmerz,\nnie einen Seufzer, der nicht trifft Sein Herz.\nNie in Gefahren, die fremd für Ihn sind,\nStunde um Stunde sorgt Er für Sein Kind.\r\nNie eine Freude, die Jesus nicht teilt,\nnie eine Krankheit die Er nicht auch heilt,\nStunde um Stunde in Lust und in Leid,\nträgt mich der Herr, dem mein Leben geweiht.\r\nBruder, was immer auch sei dein Geschick,\nkomm, und auch dir schenkt der Heiland dies Glück.\nStelle dich unter Sein rettendes Blut,\nStunde um Stunde, und alles wird gut.\r\nStunde um Stunde hast in Ihm du Ruh\',\nfließt Seine Kraft und Sein Leben dir zu,\nlass es fortan deine Losung nur sein:\n"Stunde um Stunde, o Herr, bin ich Dein."'),
(9, '1317', 'Mit uns ist Gott, mit uns ist Gott, wenn wir zum Kampfe ziehn   (Chorus)', NULL, 'Mit uns ist Gott, mit uns ist Gott,\nwenn wir zum Kampfe zieh\'n.\nMit uns ist Gott, mit uns ist Gott,\ndie Teufel müssen flieh\'n.\nWir zagen nicht, wenn alles bricht\nund sind wir in Gefahr:\nMit uns ist Gott, ob Hohn und Spott,\nEr hilft uns immerdar.'),
(9, '1318', 'Mitpilger mein auf der schmalen Bahn  -  Oh, Pilgrim bound for the heav\'nly Land   (Richte den Blick auf Jesus)', 'Oh, Pilgrim bound for the heav\'nly land,\nnever lose sight of Jesus.\nHe\'ll lead you gently with loving hand,\nnever lose sight of Jesus.\r\nNever lose sight of Jesus,\nnever lose sight of Jesus.\nDay and night He will lead you right,\nnever lose sight of Jesus.\r\nTho\' dark the pathway may seem ahead,\nnever lose sight of Jesus.\n"I will be with you," His word hath said,\nnever lose sight of Jesus.\r\nWhene\'er you\'re tempted to go astray,\nnever lose sight of Jesus.\nPress onward, upward, the narrow way,\nnever lose sight of Jesus.\r\nWhen death is knocking outside the door,\nnever lose sight of Jesus.\nTill safely landed on Canaan\'s shore,\nnever lose sight of Jesus.', 'Mitpilger mein auf der schmalen Bahn,\nrichte den Blick auf Jesus!\nEr führt dich sicher an Seiner Hand.\nRichte den Blick auf Jesus!\r\nRichte den Blick auf Jesus!\nRichte den Blick auf Jesus!\nTag und Nacht gibt Er auf dich acht.\nRichte den Blick auf Jesus!\r\nIst oft auch dunkel der steile Pfad,\nder dir zu geh\'n beschieden,\n"Ich bin mit dir", Er verheißen hat,\nschenket dir Trost und Frieden.\r\nWenn du versucht wirst, hier fehl zu geh\'n,\nwenn deine Kraft entschwindet,\neil\' vorwärts, ohne je still zu steh\'n:\nGott hat dir Sieg verkündet.\r\nUnd wenn der Tod dann klopft an bei dir,\nmusst du von hinnen scheiden,\nJesus führt dich durch die Himmelstür\nins Reich der ew\'gen Freuden.'),
(9, '1319', 'Mon seul appui', 'Mon seul appui, c’est l’Ami Céleste,\nJésus seul! Jésus seul!\nLes ans s’en vont, cet Ami me reste,\nJésus seul! Jésus seul!\r\nCet Ami connait mes alarmes,\nSon amour guérit ma douleur;\nSa main essuie toutes mes larmes,\nDoux Sauveur! Doux Sauveur!\r\nTout mon désir, c’est de Le connaitre,\nJésus seul! Jésus seul!\nEt que sa paix remplisse mon être,\nJésus seul! Jésus seul!\r\nDans le danger, toujours il me garde,\nJésus seul! Jésus seul!\nDans mes soucis, à Lui je regarde,\nJésus seul! Jésus seul!', 'Meine einzige Kraft ist der himmlische Freund\nJesus allein, Jesus allein\nDie Jahre vergehen, dieser Freund bleibt mir\nJesus allein, Jesus allein\r\nDieser Freund kennt meine Sorgen\nSeine Liebe heilt meinen Schmerz\nSeine Hand wischt alle meine Tränen weg\nsanftmütiger Retter,  Sanftmütiger Retter\r\nMein ganzer Wunsch ist Ihn zu kennen\nJesus allein,  Jesus allein\nUnd möge Sein Frieden mein Wesen erfüllen\nJesus allein,  Jesus allein\r\nIn Gefahr hält Er mich immer\nJesus allein,  Jesus allein\nIn meinen Sorgen schaue ich auf Ihn\nJesus allein,  Jesus allein'),
(9, '1320', 'More Love, more Power, more of You in my Life', 'More love, more power,\nmore of You in my life.\nMore love, more power,\nmore of You in my life.\r\nAnd I will worship You with all of my heart,\nand I will worship You with all of my mind,\nand I will worship You with all of my strength,\nfor You are my Lord, You are my Lord.\r\nAnd I will seek Your face with all of my heart,\nand I will seek Your face with all of my mind,\nand I will seek Your face with all of my strength,\nfor You are my Lord, You are my Lord.', NULL),
(9, '1321', 'More than anything', 'I lift my hands in total adoration unto You\nYou reign on the throne\nFor You are God and God alone\nBecause of You my cloudy days are gone\nI can sing to You this song\nI just want to say that I love You more than anything\r\nI lift my hands in total adoration unto You\nYou reign on the throne\nFor You are God and God alone\nBecause of You my cloudy days are gone\nI can sing to You this song\nI just want to say that I love You more than anything\r\nLove me in Your arms\nYou were my shelter from the storm\nWhen all my friends were gone\nYou were right there all along\nI\'ve never known a love like this before, oh\nI just want to say that I love You more than anything\r\nI love You Jesus\nI worship and adore You\nJust want to tell You\nLord, I love You more than anything', NULL),
(9, '1322', 'Möchtest Du Freud, echte Freud, wahrhafte Freud  -  If you want Joy, real Joy, wonderful Joy', 'If you want joy, real joy, wonderful joy,\nlet Jesus come into your heart.\nIf you want joy, real joy, wonderful joy,\nlet Jesus come into your heart.\nYour sins He’ll wash away,\nyour night He’ll turn to day,\nyour life He’ll make over anew.\nIf you want joy, real joy, wonderful joy,\nlet Jesus come into your heart.\r\n\r\n', 'Möchtest du Freud\', echte Freud\', wahrhafte Freud\',\nlass Jesus hinein in Dein Herz.\nMöchtest du Freud\', echte Freud\',wahrhafte Freud\',\nlass Jesus hinein in Dein Herz.\nDie Sünd\' nimmt Er Dir weg, schafft Licht auf dunklem Weg.\nDein Herz und Leben wandelt Er um, dass Er darinnen wohnt.\nMöchtest du Freud\', echte Freud\', wahrhafte Freud\',\nlass Jesus hinein in Dein Herz.\r\nMöchtest Du Glück, wahres Glück, ewiges Glück,\nlass Jesus dein Führer stets sein.\nMöchtest Du Glück, wahres Glück, ewiges Glück,\nlass Jesus dein Führer stets sein.\nEr wäscht das Herz dir rein, ist Licht und Sonnenschein\nauf deinem Lebensweg\nund wahrhaft wirst du glücklich sein.\nMöchtest Du Glück, wahres Glück, ewiges Glück,\nlass Jesus dein Führer stets sein.\r\nMöchtest du Ruh\', tiefe Ruh\', selige Ruh\',\nnur Jesus schenkt himmlische Ruh\'.\nMöchtest du Ruh\', tiefe Ruh\', selige Ruh\',\nnur Jesus schenkt himmlische Ruh\'.\nIn Unrast dieser Zeit, in Not und Herzeleid\nschenkt Jesus nur die selige Ruh\', jetzt und in Ewigkeit.\nMöchtest du Ruh\', tiefe Ruh\', selige Ruh\',\nnur Jesus schenkt himmlische Ruh\'.'),
(9, '1323', 'Möchtest du los sein vom Banne der Sünd  -  Would you be free from your Burden of Sin   (Es ist Kraft, Kraft, wunderbare Kraft)', 'Would you be free from your burden of sin?\nThere\'s power in the blood, power in the blood.\nWould you o\'er evil a victory win?\nThere\'s wonderful power in the blood.\r\nThere is power, power, wonder-working power\nin the blood of the Lamb.\nThere is power, power wonder-working power\nin the precious blood of the Lamb.\r\nWould you be free from your passion and pride?\nThere\'s power in the blood, power in the blood.\nCome for a cleansing to Calvary\'s tide.\nThere\'s wonderful power in the blood.\r\nWould you be whiter, much whiter than snow?\nThere\'s power in the blood, power in the blood.\nSin\'s stains are lost in its life-giving flow.\nThere\'s wonderful power in the blood.\r\nWould you do service for Jesus your King?\nThere\'s power in the blood, power in the blood.\nWould you live daily His praises to sing?\nThere\'s wonderful power in the blood.', 'Möchtest du los sein vom Banne der Sünd\'?\n\'s ist Kraft in dem Blut, Kraft in dem Blut.\nKomm, deine Seele den Frieden gewinnt,\ndenn Reinigungskraft hat das Blut!\r\nEs ist Kraft, Kraft, wunderbare Kraft\nin dem Blut, in dem Blut.\nEs ist Kraft, Kraft, Überwinderkraft\nin dem Blut des Heilands allein.\r\nMöchtest du frei von der Leidenschaft sein?\n\'s ist Kraft in dem Blut, Kraft in dem Blut.\nGolgathas Blut will zum Sieger dich weih\'n!\n\'s ist Sieg da für dich durch das Blut.\r\nMöchtest du rein sein, ja weißer als Schnee?\n\'s ist Kraft in dem Blut, Kraft in dem Blut.\nRein wäscht\'s von Flecken und nimmt jedes Weh!\nGanz rein wirst du sein durch das Blut.\r\nMöchtest du Jesu hier dienen so gern?\n\'s ist Kraft in dem Blut, Kraft in dem Blut.\nMöchtest du preisen den gnädigen Herrn?\nEs ist Kraft Stund\' um Stund\' in dem Blut!'),
(9, '1324', 'My dreams were shattered, all hope was gone   (Jesus ist alles, was ich brauch  -  Jesus is everything I need)', 'My dreams were shattered, all hope was gone.\nThere was no strength left in me to, carry on.\nThen I heard a voice so sweet whisper sweet peace to me.\nNow, that I know His name my life will never be the same for.\r\nJesus is everything I need,\nJesus, Jesus.\nJesus is life and breath to me,\nJesus, my Lord!', '\r\nJesus ist alles, was ich brauch\',\nJesus, Jesus.\nJesus ist Leben und Odem für mich,\nJesus, mein Herr!'),
(9, '1325', 'My Feet are on the Pathway', 'My feet are on the pathway,\nthe oil is on my head,\nI\'m drinking at the fountain,\nfeasting on the bread.\nMy mouth is filled with laughter,\nmy heart is filled with song.\nI\'ll praise my Saviour all day long.\r\nHalleluja! Halleluja!\nI\'ll praise my Saviour all day long.\nHalleluja! Halleluja!\nI\'ll praise my Saviour all day long.', NULL),
(9, '1326', 'My God is awesome, He can move Montains   (My God is awesome)', 'My God is awesome.\nHe can move mountains.\nKeep me in the valley.\nHide me from the rain.\nMy God is awesome.\nHeals me, when I\'m broken.\nGives strength, where I\'ve been weakened.\nForever He will reign. (2x)\r\nMy God is awesome, awesome, awesome, awesome\nMy God is awesome, awesome, awesome, awesome\r\nMy God is awesome.\nSaviour of the whole world.\nGiver of salvation.\nBy His stripes I am healed.\nMy God is awesome.\nToday I am forgiven.\nHis grace is, why I\'m living.\nPraise His holy name.\r\nMy God is awesome, awesome, awesome, awesome\nMy God is awesome, awesome, awesome, awesome\r\nHe\'s mighty\nHe\'s mighty\nHe\'s mighty\nHe\'s mighty\nAwesome, awesome.', NULL),
(9, '1327', 'My God makes me strong', 'I stand at the promised land\nand I hear my God speak:\n"My child, be of good courage,\nyou don\'t have to be weak!"\r\nMy God makes me strong (2x)\nMy trials are not too hard,\nand my way is not too long,\nfor my God makes me strong!\r\nMy God is a mighty God,\nHe helps me ev\'ry time,\nAnd He gave me a promise:\nI\'ll be not left behind.', 'Ich stehe am verheißenen Land\nund höre meinen Gott sprechen:\n"Mein Kind, sei guten Mutes,\ndu brauchst nicht schwach zu sein!"\r\nMein Gott macht mich stark,\nMeine Prüfungen sind nicht zu schwer,\nund mein Weg ist nicht zu weit,\ndenn mein Gott macht mich stark!\r\nMein Gott ist ein mächtiger Gott,\nEr hilft mir allezeit,\nUnd Er hat mir ein Versprechen gegeben:\nIch werde nicht zurückgelassen.'),
(9, '1328', 'My Heart will sing to You because of Your great Love', 'My heart will sing to You because of Your great love,\na love so rich so pure a love beyond compare.\nThe wilderness the barren place\nbecome a blessing in the warmth of Your embrace.\r\nWhen earthly wisdom dims the light of knowing You,\nor if my search for understanding clouds Your way.\nTo You I\'ll fly my hiding place,\nwhere revelation is beholding face to face.\r\nMay my heart sing You praise forever.\nMay my voice lift You Name, my God.\nMay my soul know no other treasure\nthan Your Love, than Your Love.', NULL),
(9, '1329', 'My Jesus is ever shining   (Chorus)', 'My Jesus is ever shining,\nmy Jesus is ever shining,\nmy Jesus is ever shining,\nmy Jesus is ever shining,\never shining, ever shining,\never shining, ever shining.', NULL),
(9, '1330', 'My Lord knows the Way through the Wilderness', 'My Lord knows the way through the wilderness,\nall I have to do is follow.\nMy Lord knows the way through the wilderness,\nall I have to do is follow.\r\nStrength for today is mine all the way,\nand all that I need for tomorrow.\nMy Lord knows the way through the wilderness,\nall I have to do is follow.', NULL),
(9, '1331', 'My Soul magnify the Lord   (Chorus)', 'My soul magnify the Lord\nand my spirit praise his name.\nEven death coul not hold him captive,\neven in the grave, Jesus is Lord.', NULL),
(9, '1332', 'My Soul says yes, yes, yes   (Chorus)', 'My soul says yes, yes, yes,\nmy soul says yes, yes, yes,\nmy soul says yes\nto the bleeding Lamb.\nMy soul says yes, yes, yes.', NULL),
(9, '1333', 'My Soul today is thirsting for living Streams divine   (Like a mighty Sea, like a mighty Sea)', 'My soul today is thirsting for living streams divine,\nto sweep from highest heaven to this poor heart of mine.\nI stand upon the promise, in Jesus\' name I plead,\noh send the gracious current to satisfy my need.\r\nLike a mighty sea, like a mighty sea,\nComes the love of Jesus, sweeping over me.\nThe waves of glory roll, the Saviour to extol,\ncomes the love of Jesus, sweeping o\'er my soul.\r\nI see the clouds arising, the mercy clouds of love,\nthat come to bring refreshing down from the throne above.\nThe earnest of the shower, just now to us is giv\'n,\nand now we wait, expecting the floods of grace from heav\'n.\r\nThe show\'rs of grace are falling, the tide is rolling in,\nthe flood-tide of salvation, with power to cleanse from sin.\nIt\'s surging thro\' my being and takes my sin away,\nit keeps me shouting glory! thro\' all the happy day.\r\nIt\'s coming, yes, it\'s coming, it\'s coming down this hour,\na torrent of salvation in saving cleansing pow\'r.\nI hear the billows surging, I see them mount and roll,\noh glory, halleluja! they\'re sweeping thro\' my soul.', NULL),
(9, '1334', 'Nahe ist die Zeit! Freund bist du bereit?   (Stell\' doch den Fuß im Glauben auf das Verheißungsland)', NULL, 'Nahe ist die Zeit! Freund bist du bereit,\nwenn Jesus wieder kommt?\nHeute ist noch Gnade, geh\' auf schmalem Pfade,\nin des Himmels Herrlichkeit.\r\nStell\' doch den Fuß im Glauben auf das Verheißungsland\nund es wird dir gehören.\nDenn das Wort des Vaters ist ja und Amen,\nEr hält was Er verspricht.\r\nAnfechtung und Not stellt der Feind entgegen,\ndoch in Jesus ist Sieg!\nIst dein Herz oft müde,zweifle nicht am Wege!\nJesus überwand für dich!\r\nJesus schenkt dir Heil, leben wird zuteil,\no glaube doch fest daran.\nAuch für deine Schmerzen gilt das Wort "Vollbracht!"\nDank dafür auch in der Nacht.'),
(9, '1335', 'Nationen zerbrechen und Israel erwach  -  Nations are breaking, Israel\'s awaking   (Der Tag der Erlösung ist nah)', 'Nations are breaking, Israel\'s awaking,\nthe signs that the prophets foretold;\nthe gentile days numbered,\nwith horrors encumbered\neternity soon will unfold.\r\nThe day of redemption is near,\nmen\'s heart are failing for fear;\nbe filled with the Spirit, your lamps trimmed and clear,\nlook up, your redemption is near.\r\nThe fig tree is growing - Jerusalem\'s restoring,\nher national life, long dethroned.\nToday she is calling, her latter rain\'s falling,\n"Return, oh, dispersed, to your own".\r\nHeaven\'s powers are shaking and many are mistaking\nGod\'s meaning to be of the sky.\nGod\'s church is the power that\'s shaking this hour,\nthe day of redemption is nigh.\r\nFalse prophets are lying, God\'s truth they\'re denying\nthat Jesus the Christ is our God.\nThrough this generation spurns God\'s revelation,\nwe\'ll walk where the apostles have trod.', 'Nationen zerbrechen und Israel erwacht,\nwie Propheten es lang schon geseh\'n.\nDie Zeit geht zu Ende, für die Heiden mit Schrecken.\nIn die Ewigkeit wir bald schon geh\'n.\r\nDer Tag der Erlösung ist nah\'.\nMenschenherzen verzagen vor Furcht.\nSei gefüllt mit dem Geist, deine Lampe geputzt!\nDer Tag der Erlösung ist nah\'.\r\nDer Feigenbaum trägt Blätter - Israel ein Staat,\nzurück kehrt Sein Volk das zerstreut.\nIn Zions Erweckung, ihr Spätregen fällt:\nIn ihr Erbteil zurück kehrt sein Volk..\r\nEr schüttelt den Weizen und viele geh\'n fehl,\nzu erkennen, was heut\' Gottes Plan.\nDoch Gottes Gemeinde, sie hat seine Kraft und sie weiß,\ndie Erlösung ist nah.\r\nFalsche Propheten erscheinen, die Wahrheit zu verneinen,\ndass Jesus Christ\' ist unser Gott.\nDoch durch diese Generation geht Gottes Offenbarung\nund Sein Leben lebt Er in uns fort.'),
(9, '1336', 'Näher, mein Gott zu Dir, näher zu Dir  -  Nearer, my God to Thee, nearer to Thee', 'Nearer, my God, to thee, nearer to thee!\nE\'en though it be a cross that raiseth me,\nstill all my song shall be, nearer, my God, to thee:\nnearer, my God, to thee, nearer to thee!\r\nThough like the wanderer, the sun gone down,\ndarkness be over me, my rest a stone,\nyet in my dreams I\'d be nearer, my God, to thee:\nnearer, my God, to thee, nearer to thee!\r\nThere let the way appear, steps unto heaven;\nall that thou sendest me, in mercy given,\nangels to beckon me nearer, my God, to thee.\nNearer, my God, to thee, nearer to thee!\r\nThen, with my waking thoughts bright with thy praise,\nout of my stony griefs Bethel I\'ll raise;\nso by my woes to be nearer, my God, to thee.\nNearer, my God, to thee, nearer to thee!\r\nOr if, on joyful wing cleaving the sky,\nsun, moon, and stars forgot, upward I fly,\nstill all my song shall be,\nnearer, my God, to thee.\nNearer, my God, to thee, nearer to thee!', 'Näher, mein Gott zu Dir, näher zu Dir!\nDrückt mich auch Kummer hier, drohet man mir,\nsoll doch trotz Kreuz und Pein dies meine Losung sein:\nNäher, mein Gott zu Dir, näher zu Dir.\r\nBricht mir wie Jakob dort Nacht auch herein,\nfind\' ich zum Ruheort nur einen Stein,\nist auch im Traume hier mein Sehnen für und für:\nNäher, mein Gott zu Dir, näher zu Dir.\r\nGeht auch die schmale Bahn aufwärts gar steil,\nführt sie doch himmelan zu unser\'m Heil.\nEngel, so licht und schön, winken aus sel\'gen Höh\'n.\nNäher, mein Gott zu Dir, näher zu Dir.\r\nIst dann die Nacht vorbei, leuchtet die Sonn\',\nweih ich mich Dir aufs neu vor Deinem Thron.\nBaue mein Bethel Dir und jauchz\' mit Freuden hier:\nNäher, mein Gott zu Dir, näher zu Dir.\r\nIst mir auch ganz verhüllt Dein Weg allhier,\nwird nur mein Wunsch erfüllt: Näher zu Dir!\nSchließt dann mein Pilgerlauf, schwing\' ich mich freudig auf:\nNäher, mein Gott zu Dir, näher zu Dir.'),
(9, '1337', 'Näher, noch näher, fest an Dein Herz  -  Nearer, still nearer, close to Thy Heart', 'Nearer, still nearer, close to Thy heart,\ndraw me, my Saviour, so precious thou art.\nFold me, oh fold me close to Thy breast.\nShelter me safe in that haven of rest,\nshelter me safe in that haven of rest.\r\nNearer, still nearer, nothing I bring,\nnaught as an off\'ring to Jesus, my King,\nonly my sinful, now contrite heart.\nGrant me the cleansing thy blood doth impart,\ngrant me the cleansing thy blood doth impart.\r\nNearer, still nearer, Lord, to be Thine,\nsin with its follies I gladly resign,\nall of its pleasures, pomp, and its pride.\nGive me but Jesus, my Lord, crucified,\ngive me but Jesus, my Lord, crucified.\r\nNearer, still nearer, while life shall last,\ntill safe in glory my anchor is cast.\nThrough endless ages, ever to be.\nNearer, my Saviour, still nearer to Thee,\nnearer, my Saviour, still nearer to Thee.', 'Näher, noch näher, fest an Dein Herz\nziehe mich, Jesus, durch Freude und Schmerz!\nBirg mich aus Gnaden in Deinem Zelt,\nschirme und schütze mich, Heiland der Welt!\nSchirme und schütze mich, Heiland der Welt!\r\nNäher, noch näher! Nichts hab ich hier,\nnichts, was als Opfer, Herr, tauget vor Dir.\nAch, nur ein sünd\'ges Herze ist mein.\nJesus, mein König, o wasche mich rein!\nJesus, mein König, o wasche mich rein!\r\nNäher, noch näher! Ganz in den Tod\ngebe ich willig, mein Heiland und Gott,\nwas Deinen Segen hemmte in mir:\nWeltliche Freuden und irdische Zier,\nweltliche Freuden und irdische Zier.\r\nNäher, noch näher, völl\'ger und frei,\nbis alles eigene Ringen vorbei,\nbis all mein Leben Dein Abglanz ist\nund Du, Herr Jesus, mein alles mir bist!\nUnd Du, Herr Jesus, mein alles mir bist!'),
(9, '1338', 'Nebel rings umher, ich sehe Dich nicht mehr  -  Whenn I feel afraid, think I\'ve lost my Way   (Dein Wort ist ein Licht auf meinem Weg / Thy Word is a Lamp unto my Feet)', 'Thy Word is a Lamp unto my feet\nand a light unto my path.\nThy Word is a lamp unto my feet\nand a light unto my path.\r\nWhenn I feel afraid\nthink I\'ve lost my way,\nstill You\'re there right beside me.\nNothing will I feer,\nas long as You are near,\nso please be near me to the End.\r\nI will not forget\nYour love for me and yet\nmy heart forever is wondering.\nJesus be my guide,\nhold me to Your side\nand I will love You to the end.', 'Dein Wort, ist ein Licht auf meinem Weg,\nwenn ich durch das Dunkel geh\'.\nDein Wort, ist ein Licht auf meinem Weg,\nlässt mich Deine Hilfe sehn\'.\r\nNebel rings umher,\nich sehe Dich nicht mehr,\nwie finde ich den Weg?\nDein Wort ist das Licht,\ndas durch den Nebel bricht,\nDu führst mich an Deiner Hand.\r\nTränen wischst Du fort,\ntröstest durch Dein Wort,\nKraft zum Leben gibst Du mir.\nWie ein weites Meer\nist Dein Wort, oh, Herr,\nunergründlich tief und reich.'),
(9, '1339', 'Nehme dein Kreuz und folge Jesus  -  Take up your Cross and follow Jesus   (Chorus)', 'Take up your cross and follow Jesus,\ntake up your cross every day.\nDon\'t be ashamed to say that you know Him.\nCount  the cost, then take up your cross and follow Him.', 'Nehme dein Kreuz und folge Jesus.\nTrage dein Kreuz jeden Tag.\nSchäme dich nicht, Ihn zu bekennen.\nNehme dein Kreuz, trage es gern und folge Ihm.'),
(9, '1340', 'Nehmt die Harfen von den Weiden', NULL, 'Nehmt die Harfen von den Weiden,\nsingt und jauchzet, jubelt laut!\nHalleluja, sagt\'s den Heiden:\n"Frei von Sünd\' ist Jesu Braut!\nJesus hat den Sieg erworben\nüber Teufel, Sünd und Tod,\ndenn Er ist für uns gestorben.\nHalleluja, preiset Gott!"\r\nJesus will dich herrlich schmücken\nmit den Kräften aus der Höh,\nEr will dich zu Sich entrücken,\ndass die Braut den König seh\'.\nSinget, jauchzet, Gottes Kinder,\nHalleluja, rühmt den Herrn,\nin Ihm seid ihr Überwinder;\nglaubet nur und dient Ihm gern.\r\nNur der Glaube kann\'s erleben,\nwas die Kraft des Herrn vollbringt;\nSieg um Sieg wird ihm gegeben,\ndass das Herz voll Jubel singt:\n"Jesus, Jesus, sei gepriesen,\nDu, mein König, Du, mein Gott!\nHast der Hölle mich entrissen,\nmich befreit von aller Not."\r\nJauchzet, Schwestern, jauchzet, Brüder,\npreiset Ihn, den Herrn der Welt!\nSinget Ihm das Lied der Lieder,\nDer den größten Feind gefällt.\nO, der Himmel ist nun offen,\nJesus selbst ist ja die Tür,\nJesus stillt der Seele Hoffen.\nRühmt und preist Ihn für und für!'),
(9, '1341', 'Neuer Morgen neue Gnade', NULL, 'In der Frühe bin ich aufgewacht\nVon deinem Sonnenschein\nSein Strahlen hat mich wach gemacht\nUm mich am neuen Tag zu freu\'n\r\nNeuer Morgen, neue Gnade\nNeue Stunden, neu geschenkte Tage\nDiese Jahre sind deine Gaben\nWir danken dir, dass wir sie haben\r\nIn der Frühe kommen wir zusamm\'n\nUm dir die Ehr\' zu bring\'n\nOh Herr, nimm unser Loblied an\nWas wir von Herzen grade sing\'n'),
(9, '1342', 'Neunundneunzig der Schafe lagen schon  -  There were ninety and nine that safely lay', 'There were ninety and nine that safely lay\nin the shelter of the fold,\nbut one was out on the hills away,\nfar off from the gates of gold —\naway on the mountains wild and bare,\naway from the tender Shepherd\'s care,\naway from the tender Shepherd\'s care.\r\n"Lord, thou hast here thy ninety and nine;\nare they not enough for thee?"\nBut the Shepherd made answer:\n"This of mine has wandered away from me,\nand although the road be rough and steep,\nI go to the desert to find my sheep,\nI go to the desert to find my sheep."\r\nBut none of the ransomed ever knew\nhow deep were the waters crossed;\nnor how dark was the night that the Lord passed thro\'\nere he found his sheep that was lost.\nOut in the desert he heard its cry —\nsick and helpless, and ready to die,\nsick and helpless, and ready to die.\r\n"Lord, whence are those blood-drops all the way\nthat mark out the mountain\'s track?"\n"They were shed for one who had gone astray\nere the Shepherd could bring him back."\n"Lord, whence are thy hands so rent and torn?"\n"They\'re pierced tonight by many a thorn,\nthey\'re pierced tonight by many a thorn."\r\nBut all thro\' the mountains, thunder-riv\'n,\nand up from the rocky steep,\nthere arose a glad cry to the gate of heav\'n,\n"Rejoice! I have found my sheep!"\nAnd the angels echoed around the throne,\n"Rejoice, for the Lord brings back his own!\nRejoice, for the Lord brings back his own!"', 'Neunundneunzig der Schafe lagen schon\nauf des Himmels Weide dort;\ndoch eins war fern und gar weit entfloh\'n,\nja weit von dem Himmel fort,\nweit weg im Gebirge wild und rauh\',\nweit weg von des Hirten sel\'ger Au,\nweit weg von des Hirten sel\'ger Au.\r\nNeunundneunzig, o Hirte, hast ja Du,\nsind sie nicht genug für Dich?\nDer Hirte spricht: Ich hab keine Ruh\',\nich seh\'n nach dem einen mich;\nund sei auch der Weg gar rauh und steil:\nIch suche mein Schaf und bringe ihm Heil,\nich suche mein Schaf und bringe ihm Heil.\r\nDoch keiner dort oben wusst\' es je,\nin welch tiefe Kluft er ging,\nnoch wie bitter und schwer\nwar das Todesweh,\ndas den Hirten für uns umfing.\nIn der Wüste, wo sonst keine Retter war,\nda fand Er Sein Schaf verschmachtet gar,\nda fand Er Sein Schaf verschmachtet gar.\r\nWoher kommen die Tropfen rotes Blut,\ndie man sieht den Weg entlang?\nEs floss vom Hirten, dem Schaf zugut,\nes ward ihm so heiß und bang.\nO Hirte, wie wund ist Deine Hand.\nDu hast so viel Schmerzen drangewandt,\nDu hast so viel Schmerzen drangewandt.\r\nUnd über die Berge schallt es hoch,\naus der Tiefe ruft\'s empor:\n"O freuet euch, freuet euch, freut euch doch,\ngefunden ist, was ich verlor!"\nUnd die Engel, sie stimmen ein Loblied an:\nGelobt sei der Herr, der solches getan!\nGelobt sei der Herr, der solches getan!'),
(9, '1343', 'Never failed me yet, never failed me yet   (Chorus)', 'Never failed me yet, never failed me yet.\nJesus\' love never failed me yet.\nThis one thing I know, that where e\'er I go,\nJesus\' love never failed me yet.', NULL),
(9, '1344', 'Nicht ferne vom Reiche Gottes und doch noch in Fluch und Pein?  -  Not far, not far from the Kingdom, yet in the Shadow of Sin   (Wie wenige dringen hinein)', 'Not far, not far from the kingdom,\nyet in the shadow of sin.\nHow many are coming and going!\nHow few there are entering in!\r\nHow few there are entering in!\nHow few there are entering in!\nHow many are coming and going!\nHow few there are entering in!\r\nNot far, not far from the Kingdom,\nwhere voices whisper and wait.\nToo timid to enter in boldly,\nso linger still outside the gate.\r\nNot far, not far from the Kingdom,\n\'Tis only a little space.\nBut oh, you may still be for ever,\nshut out from yon heavenly place!', 'Nicht ferne vom Reiche Gottes\nund doch noch in Fluch und Pein?\nBerufen hat Gott, ach, so viele,\ndoch wenige dringen hinein.\r\nWie wenige dringen hinein!\nWie wenige dringen hinein!\nEs sind wohl gar viele berufen,\ndoch wenige dringen hinein.\r\nNicht ferne vom Reiche Gottes!\nDie Stimme im Herzen spricht:\n"Was stehst du im Finsteren draußen?\nDort drinnen ist Freude und Licht."\r\nNicht ferne vom Reiche Gottes!\nWeit offen die Tür noch steht.\nDoch wird einst die Türe geschlossen,\ndann ist es auf ewig zu spät.'),
(9, '1345', 'Nicht im lauten Beten, nicht im Sang', NULL, 'Nicht im lauten Beten, nicht im Sang,\nauch nicht in der Predigt, Orgelklang,\nauch nicht in den Heilgen, hör es hier:\nAlle meine Quellen sind in Dir!\r\nNicht in den Gefühlen, dich ich hab,\nauch nicht in den Freuden, Deiner Gab,\nlaut in meinem Herzen tönt es hier:\nAlle meine Quellen sind in Dir!\r\nAlle meine Wünsche kennest Du,\nalle meine Unruh stillest Du,\nalle meine Sehnsucht sag ich Dir:\nAlle meine Quellen sind in Dir!\r\nO Du mein Geliebter, Du bist mein,\nkann es auch im Himmel schöner sein,\nwenn ich mit den Heilgen jubilier\':\nAlle meine Quellen sind in Dir!\r\nBist Du nicht mein Schatten vor der Glut?\nBist Du nicht mein Schutz in Sturmeswut?\nAuch in dürrer Wüste sing ich Dir:\nAlle meine Quellen sind in Dir!\r\nDie gewalt\'gen Feinde toben sehr;\ndoch stets gabst Du Deinem Namen Ehr\'!\nAn Dich glaube ich und triumphier\':\nAlle meine Quellen sind in Dir!\r\nO Du meine sichre, stolze Ruh\',\nmeine Burg und Festung, Jesus Du!\nO wie bin ich selig dort und hier:\nAlle meine Quellen sind in Dir!'),
(9, '1346', 'Nicht mehr mein, ich bin erlöset, Jesus starb auch mir zugut  -  Not my own, but saved by Jesus, who redeemed me by his Blood   (Nicht mehr mein, nicht mehr mein)', 'Not my own, but saved by Jesus,\nwho redeemed me by his blood.\nGladly I accept the message:\nI belong to Christ the Lord.\r\nNot my own, not my own,\nSaviour, I belong to thee.\nAll I have and all I hope for,\nThine for all eternity.\r\nNot my own; to Christ my Saviour,\nI, believing, trust my soul.\nEverything to him committed,\nwhile eternal ages roll.\r\nNot my own; my time, my talents,\nfreely all to Christ I bring.\nTo be used in joyful service,\nfor the glory of my King.\r\nNot my own; the Lord accepts me,\none among the ransomed throng.\nWho in Heaven shall see his glory,\nand to Jesus Christ belong.', 'Nicht mehr mein, ich bin erlöset,\nJesus starb auch mir zugut.\nFroh ich hörte diese Botschaft:\nEr erlöst mich durch Sein Blut.\r\nNicht mehr mein, nicht mehr mein,\nich bin Dein und bleibe Dein!\nWas ich hab, worauf ich hoffe,\nich bin Dein in Ewigkeit!\r\nNicht mehr mein, nur meinem Heiland\ngeb\' ich gern mein Herze hin;\nalles hab ich ihm vertrauet,\nich nicht mehr mein eigen bin.\r\nNicht mehr mein, die Zeit und Gaben\ngerne bring ich Jesu dar.\nZum Gebrauch kann Er sie haben,\nIhm zum Dienst sind sie fürwahr.\r\nNicht mehr mein, bin angenommen\nunter der Erlösten Zahl,\nin dem Himmel angekommen,\npreisend Ihn im Hochzeitssaal!'),
(9, '1347', 'Nichts habe ich, was nicht frei ich empfing  -  Naught have I gotten but what I received   (Einer, den Gottes Gnade fand)', 'Naught have I gotten but what I received,\nGrace hath bestowed it since I have believed!\nBoasting excluded, pride I abase:\nI’m only a sinner, saved by grace!\r\nOnly a sinner saved by grace!\nonly a sinner saved by grace!\nThis is my story, to God be the glory:\nI’m only a sinner saved by grace!\r\nOnce I was foolish, and sin ruled my heart,\ncausing my footsteps from God to depart.\nJesus hath found me, happy my case.\nI now am a sinner, saved by grace!\r\nTears unavailing, no merit had I,\nmercy had saved me, or else I must die.\nSin had alarmed me, fearing God’s face,\nbut now I’m a sinner saved by grace!\r\nSuffer a sinner whose heart overflows,\nloving his Saviour to tell what he knows.\nOnce more to tell it would I embrace:\nI’m only a sinner saved by grace!', 'Nichts habe ich, was nicht frei ich empfing,\ndurch Gottes Gnade bin ich was ich bin!\nRühmen sei fern, doch das sei bekannt:\nIch bin einer, den die Gnade fand.\r\nEiner, den Gottes Gnade fand!\neiner, den Gottes Gnade fand!\nAn mir erwiesen, sei laut sie gepriesen:\nIch bin einer, den die Gnade fand!\r\nEinst war ich arm und in Sünden verstrickt,\ndem Gott der Gnade so sehr fern gerückt.\nDoch Jesus kam und griff meine Hand.\nIch bin einer den die Gnade fand!\r\nNicht meine Tränen je haben`s gemacht,\nnur Sein Erbarmen hat alles vollbracht!\nSündenvergiftet, einst abgewandt,\nbin ich einer, den die Gnade fand!\r\nLass mich\'s dir sagen mit strahlendem Blick,\nmein Herz fließt über vor Freude und Glück;\nnoch einmal ruf ich\'s laut über\'s Land:\nIch bin einer, den die Gnade fand.'),
(9, '1348', 'Nichts, nichts kannst du tun zur Erlösung', NULL, 'Nichts, nichts kannst du tun zur Erlösung,\nsie ist ja vollbracht, sie ist dein;\ndu sollst sie nur glauben und nehmen,\num ewig errettet zu sein.\nNichts, nichts kannst du tun zur Vergebung,\ndenn Gnade, die wird nicht verdient;\nGerechtigkeit ist dir erworben\nvon dem, der die Sünde gesühnt.\r\nNichts, nichts kannst du tun fürs schneeweiße,\nim Blute gewaschene Kleid;\nnur lass dich im Glauben drein kleiden,\nso ziert dich vor Gott Heiligkeit.\nNichts, nichts kannst du tun für die Wohnung,\ndie Gott uns in Salem erbaut;\nnur komm, weil ja alles bereitet,\nso rufet der Geist und die Braut.\r\nNichts, nichts kannst du tun für den Himmel,\ndas selige Herrlichkeitsreich.\n"Ererbt es, denn Ich und der Vater",\nspricht Jesus, "Wir schenken es euch!"\nNichts, nichts kannst du tun zu der Würde,\nzu tragen die goldene Kron\';\nleg die dir aus Gnaden geschenkte\nnur demütig nieder am Thron!'),
(9, '1349', 'Nie allein, nie allein! Jesus lässt mich nie allein', NULL, 'Nie allein, nie allein! Jesus lässt mich nie allein.\nNiemals fern, niemals fern von der Liebe meines Herrn!\nNichts kann mir schaden, ich werd\' getragen\nvon dem Herrn bei Tag und Nacht.\nNie allein, nie allein! Jesus will mein Heiland sein.'),
(9, '1350', 'Nie mehr will ich von Dir gehen', NULL, 'Nie mehr will ich von Dir gehen,\nJesus, nein, nie mehr zurück!\nImmer tiefer darf ich sehen:\nDu allein schaffst Heil und Glück.\nJa, an Dir nur will ich hangen\nbis zu Deiner Wiederkehr\nund nichts anderes verlangen,\nnein, nie mehr, nein, nie mehr!\r\nNie mehr will ich Dir entfliehen;\ngib nur Gnade mir dazu.\nAlles hast Du mir verziehen:\nHerr, mein Gott, wer ist wie Du?\nDir von Herzensgrund zu danken,\nsei mein Sinnen und Begehr\'.\nGib mir\'s, dass ich nie mög\' wanken,\nnein, nie mehr, nein, nie mehr!\r\nNie mehr will ich Dich betrüben\ndurch verkehrten Eigensinn.\nTreulich möchte ich mich üben,\ndass ich stets gehorsam bin.\nLass mich Deinen Willen wissen;\nmach mich von mir selber leer!\nNie mehr möchte ich Dich missen,\nnein, nie mehr, nein, nie mehr!\r\nNie mehr will ich übersehen\neinen Wink von Deiner Hand.\nLehr\' mich nur, Ihn zu verstehen,\nmach mir Deinen Weg bekannt.\nAllem kann ich froh entsagen,\nDein Gebot ist mir nicht schwer:\nNach der Welt will ich nicht fragen,\nnein, nie mehr, nein nie mehr!\r\nNie mehr! Dabei soll es bleiben.\nNie mehr lasse ich von Dir.\nMöge mich Dein Geist nur treiben,\nsei  Du immer nahe mir.\nGeht es gleich durch Tod und Leiden,\nHerr,  Dein Rat ist hoch und hehr:\nNein, von Dir soll nichts mich scheiden,\nnein, nie mehr, nein nie mehr!'),
(9, '1351', 'Nie verbleicht der Name Jesus   (O ich lieb den Namen Jesu)', NULL, 'Nie verbleicht der Name Jesus,\nEr steht fest zu jeder Zeit.\nNiemand Diesen kann zerstören;\nEr besteht in Ewigkeit.\nEwig soll Er sich verbreiten;\nHeil und Sieg in jeder Not.\nEr allein kann sicher leiten\nalle Seelen heim zu Gott.\r\nO ich lieb\' den Namen Jesus,\nder mein ganzes Herz gewann.\nIn dem Namen Jesus fand ich\nHeilung, Freiheit von der Sünde Bann.\r\nHerrlich klingt der Name Jesus\nüber Meer und über Land.\nIn dem großen Namen Jesus\nTrost und Ruhe ich hier fand.\nDurch den Namen weicht die Bosheit,\nHass und Neid verschwinden dann;\nden Gefang\'nen gibt Er Freiheit,\nPreis dem teuren Gotteslamm.\r\nWie das Licht vom Leuchtturm funkelt\ndieser Name Jesus hell,\nzeigt den Weg dem armen Seemann\nzu dem sich\'ren Hafen schnell.\nWenn der Sonne Schein verschwunden,\ndieser Name leuchtet schön,\njubelnd alle Überwinder\nvor dem Throne Gottes steh\'n.'),
(9, '1352', 'Nieder zu Erden, um ein Mensch zu werden  -  Down from His Glory, ever living Story   (Ihn will ich lieben, will Ihn anbeten)', 'Down from His glory, ever living story,\nmy God and Saviour came, and Jesus was His Name.\nBorn in a manger, to His own a stranger,\na Man of sorrows, tears and agony.\r\nOh how I love Him, how I adore Him,\nmy breath, my sunshine, my all in all.\nThe great Creator became my Saviour,\nand all God\'s fullness dwelleth in Him.\r\nWhat condescension, bringing us redemption,\nthat in the dead of night, not one faint hope in sight.\nGod, gracious, tender, laid aside His splendor,\nstooping to woo, to win, to save my soul.\r\nWithout reluctance, flesh and blood His substance,\nHe took the form of man, Revealed the hidden plan.\nOh glorious mystery, Sacrifice of Calvary,\nand now I know Thou wert  the great "I AM."', 'Nieder zu Erden, um ein Mensch zu werden,\nkam der allmächt\'ge Gott, zu enden unsre Not.\nEr ward verstoßen und sein Blut vergossen.\nEr ward gehorsam bis zum bitter\'n Tod.\r\nIhn will ich lieben, will Ihn anbeten,\nmein Licht, mein Leben, mein ganzes Heil.\nDer große Schöpfer ward mein Erlöser,\nund Gottes Gnade ward mir zuteil.\r\nAuf welchen Wegen kommt uns Gott entgegen,\ndass er in finst\'rer Nacht uns wieder hoffen macht.\nFreundlich und gnädig, aller Pracht entledigt,\nklopft Er, erlösungbringend an mein Herz.\r\nOhne zu klagen, ließ Er sich zerschlagen,\ngab Er Sein Leben hin, auf dass Er uns gewinn\'.\nWer kann\'s erfassen: Gott sich selbst verlassen!\nNun weiß ich, Du bist\'s der da spricht: "ICH BIN".'),
(9, '1353', 'Niemand anders als Jesus, niemand anders als Er   (Chorus)', NULL, 'Niemand anders als Jesus, niemand anders als Er,\nkann mich erlösen, von Sünd\', nur Er.\nIn allen Sorgen, ist Er stets bei mir,\nniemand anders als Jesus, niemand anders als Er.'),
(9, '1354', 'Nimm den Namen Jesus mit dir  -  Take the Name of Jesus with you   (Teurer Nam\', o wie süß)', 'Take the name of Jesus with you,\nchild of sorrow and of woe.\nIt will joy and comfort give you,\ntake it then where\'er you go.\r\nPrecious name, oh how sweet!\nHope of earth and joy of heaven.\nPrecious name, oh how sweet!\nHope of earth and joy of heaven.\r\nTake the name of Jesus ever,\nas protection ev\'rywhere.\nIf temptations \'round you gather,\nbreathe that holy name in prayer.\r\nOh, the precious name of Jesus,\nhow it thrills our souls with joy.\nAll the favor of the Father,\nin this name we may enjoy.\r\nAt the name of Jesus bowing,\nwhen in heaven we shall meet.\nKing of kings, we\'ll gladly crown him,\nwhen our journey is complete.', 'Nimm den Namen Jesus mit dir,\nKind von Sorge und von Schmerz.\nEr wird Freud\' und Trost dir geben.\nNimm Ihn mit, wohin du gehst!\r\nTeurer Nam\', o wie süß!\nHoffnung hier und Freud\' im Himmel.\nTeurer Nam\', o wie süß!\nHoffnung hier und Freud\' im Himmel.\r\nNimm den Namen Jesus immer\nals ein Schild vor jedem Feind.\nWenn Versuchungen dir nahen,\nflüst\'re diesen heil\'gen Nam\'!\r\nO, der teure Name Jesus!\nWie füllt Er die Seel\' mit Freud\',\nwenn Er uns in Seine Arme nimmt\nund wir Ihn preisen dort!\r\nIn dem Namen Jesus werden\nbeugen alle Knie sich.\nUnsern König wir dort krönen,\nwenn die Reise ist zu End\'!'),
(9, '1355', 'Nimm Du mich ganz hin, o Gottes Sohn  -  Have Thine own way, Lord', 'Have Thine own way, Lord! Have Thine own way!\nThou art the potter, I am the clay.\nMould me and make me, after Thy will,\nwhile I am waiting, yielded and still.\r\nHave Thine own way, Lord! Have Thine own way!\nSearch me and try me, Master, today!\nWhiter than snow, Lord, wash me just now,\nas in Thy presence, humbly I bow.\r\nHave Thine own way, Lord! Have Thine own way!\nWounded and weary, help me, I pray!\nPower, all power, surely is Thine!\nTouch me and heal me, Saviour divine.\r\n', 'Nimm Du mich ganz hin, o Gottes Sohn!\nDu bist der Töpfer, ich bin der Ton.\nMach aus mir etwas, nach Deinem Sinn,\nwährend ich harre, nimm mich ganz hin!\r\nNimm Du mich ganz hin, o Gottes Sohn!\nPrüfe, erforsch\' mich, am Gnadenthron.\nWeißer denn Schnee, Herr, wasche mich rein,\ndass ich Dein eigen ewig mag sein!\r\nNimm Du mich ganz hin, o Gottes Sohn!\nMit Deinem Geiste jetzt in mir wohn\'.\nSei in dem Herzen König allein,\nlass alle sehen, dass ich ganz Dein.\r\nUnd mag zerbrechen die ganze Welt,\nso darf ich sprechen: "Wie\'s Gott gefällt."\nIch bin geborgen, o sel\'ger Stand\nheut\' und auch morgen in Gottes Hand.'),
(9, '1356', 'Nimm mein Leben! Jesus Dir, übergeb ich\'s für und für  -  Take my Life and let it be', 'Take my life and let it be\nconsecrated, Lord, to thee.\nTake my moments and my days\nlet them flow in endless praise.\r\nTake my hands and let them move\nat the impulse of thy love.\nTake my feet and let them be\nswift and beautiful for thee.\r\nTake my voice and let me sing\nalways, only, for my King.\nTake my lips and let them be\nfilled with messages from thee.\r\nTake my silver and my gold,\nnot a mite would I withhold.\nTake my intellect and use\nevery power as thou shalt choose.\r\nTake my will and make it thine,\nit shall be no longer mine.\nTake my heart it is thine own\nit shall be thy royal throne.\r\nTake my love; my Lord, I pour\nat thy feet its treasure store.\nTake myself, and I will be\never, only, all for thee.', 'Nimm mein Leben! Jesus, Dir\nübergeb\' ich\'s für und für.\nNimm Besitz von meiner Zeit,\njede Stund\' sei Dir geweiht!\r\nNimm Du meine Hände an,\nzeig mir, wie ich dienen kann;\nnimm die Füße, mach sie flink,\nDir zu folgen auf den Wink!\r\nNimm die Stimme, lehre mich\nreden, singen nur für Dich;\nnimm, o Herr, die Lippen mein,\nlege Deine Worte drein!\r\nNimm mein Gold und Silber hin,\nlehr\' mich tun nach Deinem Sinn;\nnimm die Kräfte, den Verstand\nganz in Deine Meisterhand!\r\nNimm, Herr, meinen Willen Du,\ndass er still in Deinem ruh\',\nnimm mein Herz, mach hier es schon\nDir zum Tempel und zum Thron!\r\nNimm Du meiner Liebe Füll\',\nJesus, all mein Sehnen still;\nnimm mich selbst und lass mich sein\newig, einzig, völlig Dein!'),
(9, '1357', 'Nimm mich bei der Hand Vater, Du bist meine Ruh', NULL, 'Nimm mich bei der Hand, Vater, Du bist meine Ruh\',\nbist des Lebens Zuflucht, Vater, winkst mir gnädig zu.\nHalt mich, wenn ich sinke, gib mir festen Stand,\nlass mich nie das Ziel verfehlen, nimm mich bei der Hand.\nNimm mich bei der Hand, Vater,\nnimm mich bei der Hand, Vater,\nlass mich nie das Ziel verfehlen,\nnimm mich bei der Hand.\r\nReich mir Deine Hand, Vater, in der dunklen Welt,\nsei mein Leitstern immer, Vater, der den Weg erhellt.\nHerr, Dill ich folgen, bis zum Heimatland,\ndeine Liebe wird mich leiten, nimm mich bei der Hand.\nNimm mich bei der Hand, Vater,\nnimm mich bei der Hand, Vater,\ndeine Liebe wird mich leiten,\nnimm mich bei der Hand.\r\nNimm mich bei der Hand, Vater, führ\' mich heim zu Dir,\nschenk\' mir Deine Gnade Vater, wenn ich scheid\' von hier.\nLass mich bei Dir ruhen, los vom Erdentand,\nführ mich heim zu Dir, o Vater, nimm mich bei der Hand.\nNimm mich bei der Hand, Vater,\nnimm mich bei der Hand, Vater,\nführ mich heim zu Dir o Vater,\nnimm mich bei der Hand.'),
(9, '1358', 'Nimm mich gefangen, Herr, denn dann erst bin ich frei  -   Make me a Captive, Lord, and then I shall be free', 'Make me a captive, Lord,\nand then I shall be free.\nForce me to render up my sword\nand I shall conqueror be.\nI sink in life\'s alarms\nwhen by myself I stand.\nImprison me within Thine arms,\nand strong shall be my hand.\r\nMy heart is weak and poor\nuntil it master find.\nIt has no spring of action sure,\nit varies with the wind.\nIt cannot freely move,\ntill Thou hast wrought its chain.\nEnslave it with Thy matchless love,\nand deathless it shall reign.\r\nMy pow\'r is faint and low\ntill I have learned to serve.\nIt lacks the needed fire to glow,\nit lacks the breeze to nerve.\nIt cannot drive the world\nuntil itself be driv\'n.\nIts flag can only be unfurled\nwhen Thou shalt breathe from heav\'n.\r\nMy will is not my own\ntill Thou hast made it Thine.\nIf it would reach a monarch\'s throne,\nit must its crown resign.\nIt only stands unbent\namid the clashing strife.\nWhen on Thy bosom it has leant,\nand found in Thee its life.', 'Nimm mich gefangen, Herr,\ndenn dann erst bin ich frei,\nentwinde meiner Hand die Wehr,\nauf dass ich Sieger sei!\nIch falle doch im Kampf,\nkämpf\' ich in eig\'ner Kraft,\ndoch hält Dein Arm umfangen mich,\nbist Du\'s, der alles schafft.\r\nMein Herz ist arm und schwach,\ndie letzte Kraft verrinnt,\nkann nicht gewisse Tritte tun\nund wechselt mit dem Wind.\nBrich seiner Ketten Last\nfür Zeit und Ewigkeit,\ndenn ganz von Deiner Lieb erfasst,\nHerr, überwind\' ich weit!\r\nVergeblich ohne Dich ist,\nwas mein Dienst erstrebt:\nGib mir das Feuer, das entflammt\nden Hauch, der neu belebt!\nDie Welt bleibt unbewegt,\nwenn nicht Dein Geist uns treibt\nund über unser Leben klar,\nHerr, Deinen Namen schreibt.\r\nMein Wille ist nicht rein,\neh\' er nicht Dir geweiht;\nder Weg zum Throne führt\nallein durch eigne Niedrigkeit.\nDer nur bleibt unbesiegt\nund hält im Streite stand,\nder, fest an Dein Herz angeschmiegt,\nin Dir sein Leben fand.'),
(9, '1359', 'Nimm o Herr meine Hand  -  Precious Lord take my Hand', 'Precious Lord take my hand,\nlead me on let me stand,\nI am tired, I am weak, I am worn,\nThry the storm thru the night,\nlead me on to the Light.\nTake my hand precious Lord,\nlead me home.\r\nWhen my way grows drear,\nprecious Lord linger near,\nWhen my life is almost gone,\nHear my cry, hear my call,\nhold my hand lest I fall,\nTake my hand, precious Lord,\nlead me home.\r\nWhen the darkness appears\nand the night draws near,\nand the day is past and gone,\nat the river I stand, geode my feet,\nhold my hand:\nTake my hand, precious Lord,\nLead me home.', 'Nimm, o Herr, meine Hand,\nführe mich unverwandt,\nich bin hilflos, müde und matt.\nFühr\' durch Sturm und durch Nacht\nmich zum Licht Deiner Pracht,\nnimm, o Herr, meine Hand,\nführ\' mich heim.\r\nDrohet Unheil mir,\nist mein Heiland bei mir,\nWenn mein Lebensmut entflieht,\nhör mein Schrei\'n, hör mein Fleh\'n,\nnur mit dir will ich geh\'n,\nnimm, o Herr, meine Hand,\nführ\' mich heim.\r\nKommt die Dunkelheit\nund die Nacht ist nicht weit\nund der Tag ist für mich getan,\nsteh\' am Jordan ich dann,\nführe mich an der Hand,\nnimm, o Herr, meine Hand,\nführ\' mich heim.'),
(9, '1360', 'Nimm Zeit dir zur Andacht und Ruh zum Gebet  -  Take Time to be holy, speak oft with thy Lord', 'Take time to be holy, speak oft with thy Lord,\nabide in Him always, and feed on His Word.\nMake friends of God’s children, help those who are weak,\nforgetting in nothing His blessing to seek.\r\nTake time to be holy, the world rushes on,\nspend much time in secret, with Jesus alone.\nBy looking to Jesus, like Him thou shalt be,\nthy friends in thy conduct His likeness shall see.\r\nTake time to be holy, let Him be thy Guide,\nand run not before Him, whatever betide.\nIn joy or in sorrow, still follow the Lord,\nand, looking to Jesus, still trust in His Word.\r\nTake time to be holy, be calm in thy soul,\neach thought and each motive beneath His control.\nThus led by His Spirit to fountains of love,\nthou soon shalt be fitted for service above.', 'Nimm Zeit dir zur Andacht und Ruh’ zum Gebet,\nvergiss nicht die Bibel vor Menschengered\'.\nVerlass die Gemeinschaft der Heiligen nicht,\nzu all\' deinen Schritten bei Gott suche Licht.\r\nNimm Zeit dir zur Andacht, die Welt lässt dich leer,\nallein in der Kammer mit Jesus verkehr.\nSein Licht, Seine Gnade umstrahlt dich dann mild,\nin dir nimmt Gestalt an des Heilandes Bild.\r\nNimm Zeit dir zur Andacht, dein Werk überleg\',\nund laufe nicht hastig, zeigt Gott keinen Weg.\nTu froh und zufrieden die Arbeit für heut’,\nso fehlt dir auch morgen nicht Gottes Geleit.\r\nNimm Zeit dir zur Andacht, in Freud\' und in Weh\'\nblick auf und sprich stille: "Dein Wille gescheh\'!"\nDann wächst dir Sein Friede, Sein Geist dich erfüllt,\nder Brunnen des Lebens im Herzen dir quillt.'),
(9, '1361', 'No longer slaves - Meine Furcht Sie regiert nicht mehr', 'You unravel me, with a melody,\nYou surround me with a song,\nof deliverance, from my enemies,\ntill all my fears are gone.\r\nI\'m no longer a slave to fear,\nI am a child of God.\nI\'m no longer a slave to fear,\nI am a child of God.\r\nFrom my mothers womb\nYou have chosen me,\nlove has called my name.\nI\'ve been born again,\ninto your family,\nYour blood flows through my veins.\r\nYou split the sea\nso I could walk right through it,\nall my fears were drowned in perfect love.\nYou rescued me\nso I could stand and sing,\nI am a child of God.\r\nLord, You come to me\nand You speak to me\nwords so loving, words so kind.\nI can hear You say:\n"I call you my child!"\nAnd I leave my fears behind.', 'Du befreist mich, Herr, durch ein Lied von Dir,\nder Gesang gibt mir die Kraft\nder Befreiung, Herr, von dem Feind, oh Herr,\nund die Ketten fallen ab!\r\nMeine Furcht, sie regiert nicht mehr,\nich bin Dein Kind, oh Herr!\nMeine Furcht, sie regiert nicht mehr,\nich bin Dein Kind, oh Herr!\r\nSchon von Ewigkeit\nhast Du mich erwählt,\nund zogst mich zu Dir hin.\nDurch Dein Blut befreit,\ndurch den Geist gebor\'n,\nweiß ich heute, wer ich bin!\r\nDu reißt die Mauern ein,\ndie mich umgeben,\nDu bahnst mir Wege durch das Meer,\ndie Liebe trieb die Furcht\naus meinem Leben\nund ich sing für Dich, Herr!\r\nHerr, Du kommst zu mir\nund Du sprichst zu mir\nWorte voller Lieblichkeit.\nVöllig unverdient\nnennst Du mich dein Kind\nund machst mich in Dir ganz frei!'),
(9, '1362', 'No one knew how alone I was feeling   (I’m amazed that You love me)', 'No one knew how alone I was feeling\nand the emptiness I tried so hard to hide.\nThrough I laughed and said my life was fine without You.\r\nI’m amazed that You love me.\nI’m amazed how You care.\nThrough Your precious blood,\nI’ve found pardon.\nAnd my sins are washed.\nThey’re all washed away.\nAll my sins are washed away.\r\nI was covering up the secret tears I cried.\nThen, one day someone told me of Your mercy,\nand the love You showed on a hill called Calvary.\nThere you died and purchased my redemption,\nwhen you broke sin’s power and set my spirit free.\r\nIt’s true there have been days when I’ve failed You.\nLord, You know the many times I’ve gone astray.\nBut I’ve learned that Your love is stronger than my weakness,\nand you ear is open every time I pray.\nNo one else has ever cared for me like You, Lord.\nOther friends could never be as close to me.\nI’m not afraid to face the problems of tomorrow,\nknowing, You are everything I’ll ever need.', NULL),
(9, '1363', 'No! He never changes   (2 Chorusse)', 'No! He never changes!\nJesus is the same every day! (2x)\r\nHe\'s a mighty God!\nHe\'s a mighty God!\nJesus is a mighty God!\nEverybody bow before Him,\nHe\'s a mighty God!\nEverybody bow before Him,\nHe\'s a mighty God!', NULL),
(9, '1364', 'Noah er trieb einst auf den Fluten dahin  -  Noah had drifted on the floods many days   (On the Wings of a snow-white Dove)', 'Noah had drifted on the floods many days.\nHe searched for land in various ways.\nTroubles he had some, but not from above,\nGod gave him His sign on the wings of a dove.\r\nOn the wings of a snow-white dove.\nGod sends down His pure, sweet love.\nA sign from above, on the wings of a dove.\r\nJesus, our Saviour came to earth one day;\nHe was born in a stable, In a manger of hay;\nthough here rejected, but not from above,\nGod gave us His sign, on the wings of a dove.\r\nThough I have suffered in many a way,\nI cried for healing both night and day;\nfaith wasn\'t forgotten By the Father above,\nHe gave me His sign on the wings of a dove.', 'Noah, er trieb einst auf den Fluten dahin.\nhielt Ausschau nach Land nicht einfach für ihn.\nManch Sorgen er hatte, doch gab er nicht auf.\nEin Zeichen von Gott auf den Flügeln der Taub\'.\r\nAuf den Flügeln der schneeweißen Taub\'\nsandte Gott Seine Liebe herab,\nGott gab ihm ein Zeichen, auf den Flügeln der Taub\'.\r\nJesus, mein Retter, kam herab einst zur Erd\',\ngeboren im Stalle, uns teuer und wert.\nDoch war Er verachtet, vom Volk ohne Glaub\',\nGott gab Ihm sein Zeichen auf den Flügeln der Taub\'.\r\nSo hab ich gelitten, bekam manchen Schlag.\nIch flehte um Heilung, bei Nacht und bei Tag.\nVon Gott nicht vergessen mein standhafter Glaub\'.\nEr gab mir Sein Zeichen auf den Flügeln der Taub\'.'),
(9, '1365', 'Nobody but You, Lord   (Chorus)', 'Nobody but you, Lord, nobody but you,\ncan keep me happy, can keep me true.\nAll through life\'s journey\nYou\'ll carry me through,\nnobody but you, Lord, nobody but you.', NULL),
(9, '1366', 'Noch einmal gibt mir Jesus gnädiglich  -  Once more, my Soul, thy Saviour, thro’ the Word   (Ich will, ich will, ich will)', 'Once more, my soul, thy Saviour, thro’ the Word,\nis offered full and free.\nAnd now, O Lord, I must, I must decide:\nShall I accept of Thee?\r\nI will! I will! I will!\nGod helping me, I will, o Lord, be Thine!\nThy precious blood was shed to purchase me,\nI will be wholly Thine!\r\nBy grace I will Thy mercy now receive,\nThy love my heart hath won.\nOn Thee, o Christ, I will, I will believe,\nand trust in Thee alone!\r\nThou knowest, Lord, how very weak I am,\nand how I fear to stray.\nFor strength to serve I look to Thee alone,\nthe strength Thou must supply.\r\nAnd now, O Lord, give all with us to-day\nthe grace to join our song.\nAnd from the heart to gladly with us say:\n"I will to Christ belong!"\r\nTo all who came, when Thou wast here below\nand said, “O Lord, wilt Thou?”\nTo them, “I will!” was ever Thy reply.\nWe rest upon it now.', 'Noch einmal gibt mir Jesus gnädiglich\nein volles, freies Heil!\nO Herr, ich weiß, ich muss entscheiden mich,\nwill ich solch sel\'gen Teil!\r\nIch will, ich will, ich will, ich will, ich will!\nGott, steh mir bei, ich will Dein eigen sein!\nDein Blut, o Jesus, macht mich völlig rein,\nich bin auf ewig Dein!\r\nMit Deiner Gnad\' ergreif\' ich Deine Hand!\nDein Lieben, Herr, zog mich!\nIch glaub an Dich, o Jesu, unverwandt\nund trau allein auf Dich!\r\nDu weißt, o Herr, wie ich so elend bin,\nin mir ist keine Kraft;\no hilf mir nur, dass ich Dir treulich dien\'!\nGib deiner Rebe Saft!\r\nHilf allen hier! Dir tön\' das neue Lied!\nEs schalle hell und rein,\nwenn jedes Herz in Lieb\nzu Dir erglüht und spricht: Herr, ich bin Dein!\r\n„O Herr, willst Du?" So sprach manch zagend Herz\n„Willst Du? Du kannst es tun!"\n„Ich will!" sprachst Du, und fort war aller Schmerz;\nwir dürfen in Dir ruh\'n!'),
(9, '1367', 'Noch gibt es viel Herzen die es nicht verstehn  -  We find many People who can\'t understand   (Das macht, dass so froh ich kann sein)', 'We find many people who can\'t understand,\nWhy we are so happy and free;\nWe\'ve crossed over Jordan to Canaan\'s fair land,\nAnd this is like Heaven to me.\r\nOh this is like Heaven to me. (Praise God!)\nYes, this is like Heaven to me.\nI\'ve crossed over Jordan to Canaan\'s fair land,\nAnd this is like Heaven to me.\r\nOh, when I get happy, I sing and I shout,\nThe devil don\'t believe It, I see;\nBut I\'m filled with the Spirit, there isn\'t a doubt,\nAnd that\'s what\'s the matter with me.\r\n', 'Noch gibt es viel Herzen, die es nicht versteh\'n,\nwarum wir so froh können sein.\nWir freu\'n uns, dass bald wir den Herrn werden seh\'n,\nin göttlichem Glanze und Schein.\r\nDas macht, dass so froh ich kann sein. ( Preis Gott! )\nDas macht, dass so froh ich kann sein;\nes kommt ja mein Heiland und holet mich heim,\ndas macht dass so froh ich kann sein.\r\nUnd wenn ich dann froh bin dann sing\' ich und jauchz\';\nder Teufel er glaubt\'s nicht, das stimmt.\nGefüllt mit dem Geiste, kein Zweifel mehr da;\nkein Mensch dann die Freude mir nimmt.\r\nSo wirst auch du glücklich, du jubelst und preist,\nGott gibt dieses Glück gern auch dir!\nEr füllt dich beständig mit Heiligem Geist,\ndann bist du im Himmel schon hier.'),
(9, '1368', 'Not by might', 'No not by might\nNor even power\nBut by Your Spirit O Lord\nHealer of hearts\nBinder of wounds\nLives that are lost, restore\nFlow through this land\n\'Til every man\nPraises Your name\nOnce more', 'Nicht durch Macht oder Kraft\nsondern durch Deinen Geist Oh Herr\nHeiler der Herzen, Verbinder der Wunden\nerstatte verlorene Leben, fließe durch dieses Land\nBis jeder Mensch Deinen Namen noch einmal preist'),
(9, '1369', 'Not by Might, nor by Power', 'Not by might, nor by power,\nbut by my Spirit saith the Lord.\nNot by might, nor by power,\nbut by my Spirit saith the Lord.\nThis mountain shall be removed.\nThis mountain shall be removed.\nThis mountain shall be removed,\nby my Spirit saith the Lord.', NULL),
(9, '1370', 'Not my Father, not my Mother, but me, o Lord   (It\'s me, it\'s me, it\'s me, oh Lord)', 'It\'s me, it\'s me, it\'s me, oh Lord,\nstanding in the need of prayer.\nIt\'s me, it\'s me, it\'s me, oh Lord,\nstanding in the need of prayer.\r\nNot my father, not my mother,\nbut me, oh Lord,\nstanding in the need of prayer.\nNot my brother, not my sister,\nbut me, oh Lord,\nstanding in the need of prayer.\r\nNot my friends, not my kids,\nbut me, oh Lord,\nstanding in the need of prayer.\nNot the saints, not the sinners,\nbut me, oh Lord,\nstanding in the need of prayer.\r\nNot the teachers, not the preachers,\nbut me, oh Lord,\nstanding in the need of prayer.\nNot the deacons, not the elders,\nbut me, oh Lord,\nstanding in the need of prayer.', NULL),
(9, '1371', 'Not what I wish to be   (Chorus)', 'Not what I wish to be,\nNor where I wish to go,\nfor who am I that I should choose my way?\nThe Lord shall choose for me,\n\'tis better far I know.\nSo let Him bid me go or stay.', NULL),
(9, '1372', 'Nothing between my Soul and the Saviour   (Nothing between my Soul and the Saviour)', 'Nothing between my soul and the Saviour,\nnaught of this worlds delusive dreams.\nI have renounced all sinful pleasure,\nJesus is mine, there\'s nothing between.\r\nNothing between my soul and the Saviour,\nso that His blessed face may be seen.\nNothing preventing the least of His favour,\nkeep the way clear! Let nothing between.\r\nNothing between like worldly pleasure,\nhabits of life, though harmless they seem.\nMust not my heart from Him ever sever,\nHe is my all, there\'s nothing between.\r\nNothing between, like pride or station,\nself or friends shall not intervene.\nThough it may cost me much tribulation,\nI am resolved, there\'s nothing between.\r\nNothing between, e\'en many hard trials,\nthough the whole world against me convene.\nWatching with prayer and much self-denial,\nI\'ll triumph at last, with nothing between.', NULL),
(9, '1373', 'Now, many Times I\'ve bowed beneath a heavy Load   (Oh, yes the Answer is on the way, yes, I know)', 'Oh, yes the answer is on the way, yes, I know\nJesus said it, I believe it, and it is so\nOur heavenly father knows the need before we pray\nAnd we can rest asure, the answer is on the way\r\nNow, many times I\'ve bowed beneath a heavy load\nBended knees to God a prayer I prayed\nYes, I kneeld there on the floor\nHe reminds me just once more\nThat the answer is already on the way\r\nIf there is a special need within your life my friend\nAnd you\'re seeking for an answer every day\nIf by faith you start believing\nMighty soon you receiving\nFor the answer is already on the way', NULL),
(9, '1374', 'Nun aufwärts froh den Blick gewandt', NULL, 'Nun aufwärts froh den Blick gewandt\nund vorwärts fest den Schritt!\nWir geh\'n an unser\'s Meisters Hand,\nund unser Herr geht mit.\r\nVergesset, was dahinten liegt\nund euer\'n Weg beschwert;\nwas ewig euer Herz vergnügt,\nist wohl des Opfers wert.\r\nUnd was euch noch gefangen hält,\no werft es von euch ab!\nBegraben sei die ganze Welt\nfür euch in Christi Grab.\r\nSo steigt ihr frei mit Ihm hinan\nzu lichten Himmelshöh\'n.\nEr uns vorauf, Er bricht uns Bahn,\nwer will Ihm widersteh\'n?\r\nD\'rum aufwärts froh den Blick gewandt\nund vorwärts fest den Schritt!\nWir geh\'n an unser\'s Meisters Hand,\nund unser Herr geht mit.'),
(9, '1375', 'Nun danket alle Gott, mit Herzen, Mund und Händen  -  Now thank we all our God, with Heart and Hands and Voices', 'Now thank we all our God,\nwith heart and hands and voices,\nwho wondrous things has done,\nin whom his world rejoices.\nWho from our mothers\' arms,\nhas blessed us on our way,\nwith countless gifts of love,\nand still is ours today.\r\nO may this bounteous God,\nthrough all our life be near us,\nwith ever joyful hearts,\nand blessed peace to cheer us.\nTo keep us in his grace,\nand guide us when perplexed,\nand free us from all ills,\nof this world in the next.\r\nAll praise and thanks to God,\nthe Father now be given,\nthe Son and Spirit blest,\nwho reign in highest heaven.\nThe one eternal God,\nwhom heaven and earth adore,\nfor thus it was, is now,\nand shall be evermore.', 'Nun danket alle Gott\nmit Herzen, Mund und Händen,\nder große Dinge tut\nan uns und allen Enden.\nDer uns von Mutterleib\nund Kindesbeinen an\nunzählig viel zugut\nund noch jetzt hat getan.\r\nDer ewigreiche Gott,\nwoll\' uns bei unserm Leben,\nein immer fröhlich Herz,\nund edlen Frieden geben.\nUnd uns in Seiner Gnad\',\nerhalten fort und fort,\nund uns aus aller Not\nerlösen hier und dort.\r\nLob, Ehr\' und Preis sei Gott,\ndem Vater und dem Sohne,\nund dem, der beiden gleich,\nim höchsten Himmelsthrone.\nIhm, dem ein\'gen Gott,\nals der im Anfang war,\nund ist und bleiben wird,\nwie jetzt, so immerdar.'),
(9, '1376', 'Nun ist die Zeit der Gnade, volle Versöhnung da   (Dir, Gotteslamm, sei Ehre! Dein Opfer ist vollbracht!)', NULL, 'Nun ist die Zeit der Gnade, volle Versöhnung da!\nAn unsrer Stelle büßte Jesus auf Golgatha.\nZahllose Scharen eilen freudig der Heimat zu.\nSie haben Heil gefunden, Frieden und Seelenruh\'.\r\nDir, Gotteslamm, sei Ehre! Dein Opfer ist vollbracht!\nVon unsrer Schuld und Sünde hast Du uns frei gemacht.\nWir sind ein Volk von Priestern, Kön\'ge in Deinem reich;\nnirgends ein Nam\' auf Erden ist Herr, dem deinen gleich.\r\nNun ist der Thron der Gnade, mit Opferblut besprengt ,\nund der vergeb\'nen Sünden Gott nimmermehr gedenkt.\nDes Heilands Liebessonne Guten und bösen scheint.\nDas Volk des neuen Bundes ist durch sein Blut vereint.\r\nKomm du, verirrt und hilflos! Für dich ist Rettung da!\nWas dir die Welt nicht bietet, find\'st du auf Golgatha:\nFrieden für Zweifelsfragen, Heilung für jeden Schmerz,\nKraft um das Kreuz zu tragen, Liebe für\'s leere Herz.'),
(9, '1377', 'Nun ist es geschehen! Ich bin nicht mehr mein', NULL, 'Nun ist es geschehen! Ich bin nicht mehr mein.\nDes Herrn will ich immer und ewiglich sein!\nEr hat mich erschaffen, Er hat mich erkauft,\nauf Seinen Tod bin ich, welch Gnade, getauft.\r\nNun ist es geschehen! Die Freiheit ist hin,\nweil ich ein Gebund\'ner Immanuels bin.\nWas Freiheit? Ich war ein gefesselter Knecht\nder Welt und des Satans; nun komm ich zurecht.\r\nNun ist es geschehen! Der Herr ist mein Heil,\nmein Führer auf Erden, im Himmel mein Teil.\nEr schalte und walte mit Unglück und Glück,\nso bin ich zufrieden und geh nicht zurück.\r\nNun ist es geschehen! O seliger Bund!\nIch weihe dem Heiland Herz, Lippen und Mund\nzum Reden und Schweigen nach Seinem Geheiß,\nzum Beten und Singen, dem Vater zum Preis.\r\nNun ist es geschehen! Nun leb\' ich in Dir;\nmein Licht und mein Leben, ach, bleibe bei mir!\nSo folg\' ich als Jünger Dir immerdar nach,\ndurch Süßes und Bitt\'res, durch Ehre und Schmach.\r\nNun ist es geschehen! Mein Heiland, es gilt!\nIn Deine Hand hab ich mich gänzlich gestellt!\nDir leb\' ich, Dir sterb\' ich, Dir bleib ich getreu;\nja, Dein bin ich, Jesu! Es bleibe dabei!'),
(9, '1378', 'Nun preiset alle Gottes Barmherzigkeit', NULL, 'Nun preiset alle Gottes Barmherzigkeit!\nLobt Ihn mit Schalle, ihr Christen weit und breit.\nEr lässt dich freundlich zu sich laden;\nfreue dich, Israel, Seiner Gnaden!\nFreue dich, Israel, Seiner Gnaden!\r\nDer Herr regieret über die ganze Welt.\nWas sich nur rühret, alles zu Fuß Ihm fällt.\nViel tausend Engel Ihn umschweben,\nPsalter und Harfe Ihm Ehre geben,\nPsalter und Harfe Ihm Ehre geben.\r\nWohlauf, ihr Heiden lasset das Trauern sein,\nzu grünen Weiden stellet euch willig ein;\nda lässt Er uns Sein Wort verkünden,\nmachet uns ledig von allen Sünden,\nmachet uns ledig von allen Sünden.\r\nEr gibet Speise reichlich und überall,\nnach Vaterweise sättigt Er allzumal;\nEr schaffet früh und späten Regen,\nfüllet uns alle mit Seinem Segen,\nfüllet uns alle mit Seinem Segen.\r\nD\'rum preis und ehre Seine Barmherzigkeit,\nSein Lob vermehre du, ganze Christenheit!\nUnd soll hinfort kein Unfall schaden,\nfreue dich, Israel, Seiner Gnaden!\nFreue dich, Israel, Seiner Gnaden!'),
(9, '1379', 'Nun ruhen alle Wälder  -  Now rest beneath night\'s Shadow', 'Now rest beneath night\'s shadow\nthe woodland, field, and meadow,\nthe world in slumber lies.\nBut thou, my heart, awake thee,\nto prayer and song betake thee,\nlet praise to thy Creator rise.\r\nThe radiant sun hath vanished,\nits golden rays are banished\nby night, the foe of day.\nBut Christ, the sun of gladness,\ndispelling all my sadness,\nwithin my heart holds constant sway.\r\nThe rule of day is over\nand shining jewels cover,\nthe heaven\'s boundless blue.\nThus I shall shine in heaven,\nwhere crowns of gold are given\nto all who faithful prove and true.\r\n\r\n', 'Nun ruhen alle Wälder,\nVieh, Menschen, Städt\' und Felder,\nes schläft die ganze Welt.\nIhr aber meine Sinnen,\nauf, auf, ihr sollt beginnen,\nwas eurem Schöpfer wohlgefällt.\r\nWo bist du Sonne blieben?\nDie Nacht hat dich vertrieben,\ndie Nacht, des Tages Feind.\nFahr hin, ein andre Sonne,\nmein Jesus, meine Wonne,\ngar hell in meinem Herzen scheint!\r\nDer Tag ist nun vergangen,\ndie güldnen Sternlein prangen\nam blauen Himmelssaal.\nAlso werd\' ich auch stehen,\nwann mich wird heißen gehen\nmein Gott aus diesem Jammertal.\r\nBreit aus die Flügel beide,\no Jesu meine Freude,\nund nimm Dein Küchlein ein!\nWill Satan mich verschlingen,\nso lass die Englein singen:\nDies Kind soll unverletzet sein!\r\nAuch euch, ihr meine Lieben,\nsoll heute nicht betrüben\nein Unfall noch Gefahr!\nGott lass euch ruhig schlafen,\nstell euch die güldnen Waffen\nums Bett und seiner Engel Schar!'),
(9, '1380', 'Nun stellt die Klagen ein und lasst uns fröhlich sein   (Der Heilge Geist ist da)', NULL, 'Nun stellt die Klagen ein\nund lasst uns fröhlich sein!\nHin ist die dunkle Nacht;\nder goldne Tag erwacht.\nEs steigt der Jubelchor\nzum Himmel hoch empor:\r\nDer Heil\'ge Geist ist da!\nDer Tröster, Er ist nah;\nder Heil\'ge Geist ist da!\nDie Nacht ist nun dahin,\nder Tag des Heils erschien,\nder Heil\'ge Geist ist da!\r\nIm Sturmwind tut sich kund\nder neue Gnadenbund.\nAufflammt ein Feuermeer:\nJehova fährt einher.\nIn neuen Zungen zieht\ndurchs Land das neue Lied:\r\nDas hat das Lamm vollbracht,\nSein ist Gewalt und Macht.\nO betet Jesum an,\nSein Blut hat das getan.\nSein wunderbares Heil\nwird heute uns zuteil:\r\nMacht dies den Sündern kund!\nEs geh von Mund zu Mund.\nIhr Engel, tragt es fort,\nsagt es von Ort zu Ort!\nO ladet alle ein!\nVernehmt es groß und klein:\r\nIhr Kerker, öffnet euch;\nerzittre Satans Reich!\nDer König kommt herbei,\nGefang\'ne, ihr seid frei!\nIhr Toten, stehet auf!\nNichts hemmt der Gnade Lauf.\r\nIhr Wächter, haltet Wacht,\nbald ist es Mitternacht!\nDer große Tag erscheint,\nder uns mit Ihm vereint.\nDurch alle Himmel zieht\nalsdann das Jubellied:'),
(9, '1381', 'Nur das Leben von Jesus Christ  -  It\'s the life behind the Name   (Chorus)', 'It\'s the life behind the Name,\nthat makes the demons tremble.\nIt\'s the life behind the Name,\nthat makes the proud heart humble.\nIt was God Who devised the plan,\nthat in all things like a man,\nHe would live, so He could give,\nto us the life behind the Name.', 'Nur das Leben von Jesus Christ,\ndas lässt den Teufel beben,\nnur das Leben, das Jesus gibt,\ndas wahre, ew\'ge Leben.\nGott hatte einen Plan,\nEr nahm die Menschen an.\nEr wohnt in dir, Er wohnt in mir.\nDas ist der Himmel heut\' schon hier!'),
(9, '1382', 'Nur der Erlöste ist glücklich und frei  -  Who but the Christian is happy and free   (Jesus mein Jesus hat Heil mir gebracht)', 'Who but the Christian is happy and free,\nfilled with the glory of God?\nNone in creation so happy as He,\nwashed and redeemed in the wonderful blood.\r\nJesus, the one who my sorrows hath healed,\nThou are the one who my spirit hath sealed.\nOnly Thy glory from heaven revealed,\nonly Thy favor can happiness yield.\r\nWho but the ransomed can ever rejoice,\nover the billows of time?\nGrace all abounding and hope’s gentle voice,\ngladden their spirits that never repine.\r\nHow can a mortal in fetters of sin,\ntaste of a freedom divine?\nOnly where Jesus is dwelling within,\ncomfort and liberty truly may shine.\r\nTell me not then of the pleasures that sting,\ncoiled under roses of pride.\nNone but the holy and innocent sing,\nout of a bosom where pleasures abide.', 'Nur der Erlöste ist glücklich und frei,\nfriedlich in Jesus er ruht,\nniemand auf Erden so glücklich wie er,\nvöllig erlöst durch des Heilandes Blut.\r\nJesus mein Jesus hat Heil mir gebracht,\nJesus allein hat mich glücklich gemacht.\nEwiges leben Herr schenktest Du mir,\ndurch Deine Gnade bin glücklich ich hier.\r\nNur der Erlöste kann immer sich freu\'n,\nsoll\'s auch durch Trübsale geh\'n.\nGnade die Fülle und Hoffnung sind sein,\ndie ihn ermutigen feste zu steh\'n.\r\nWie kann ein Mensch der gebunden in Sünd\',\nschmecken das göttliche Heil.\nDen nur, dem Jeusus ins Herze zog ein,\nvöllige Freiheit und Trost wird zuteil.\r\nSaget mir nichts von den Lüsten der Welt,\ndie in sich bergen den Tod.\nDie da heilig und unschuldig sind,\nhaben die ewigen Freuden in Gott.'),
(9, '1383', 'Nur ein Schritt aus der Nacht zum Licht   (Nur ein Schritt, alles ist bereit)', NULL, 'Nur ein Schritt aus der Nacht zum Licht,\nwie durch Wolken die Sonne bricht.\nNur ein Schritt, Seele, fürchte dich nicht,\nChristus, der Retter, ist da.\r\nNur ein Schritt, alles ist bereit,\nnur ein Schritt endet Angst und Streit.\nNur ein Schritt, komm, o komm noch heut,\nChristus, der Retter, ist da.\r\nNur ein Schritt, denn es ist vollbracht;\ntritt heraus aus der dunklen Nacht.\nSieh, der ewige Morgen tagt,\nChristus, der Retter, ist da.\r\nNur ein Schritt, o dein Heil ist nah,\nlängst vollendet auf Golgatha;\nglaub\'s und singe: Halleluja,\nChristus, der Retter, ist da.\r\nNur ein Schritt aus dir selbst in Ihn,\ndann muss Satan und Sünde flieh\'n.\nNeu wird alles, das Alte fällt hin,\nChristus, der Retter ist da.\r\nNur ein Schritt, ach vernimm doch dies,\nsonst verlierst du dein Paradies.\nGlaubst du nicht, was dir Gott verhieß,\nist kein Erretter sonst da.\r\nNur ein Schritt - du betörtes Herz!\nNichts vertreibt deinen Sündenschmerz,\nals nur das Ruhen an Gottes Herz;\nglaube; so steht alles da.\r\nNur ein Schritt, Seele, glaub es doch;\nnur ein Schritt aus dem Sündenjoch.\nNur ein Schritt, o komm heute noch.\nChristus, der Retter, ist da.'),
(9, '1384', 'Nur einmal machst du die Reise, lass eine gute Spur zurück', NULL, 'Nur einmal machst du diese Reise,\nlass eine gute Spur zurück,\nleb\' deinem Gott zu Lob und Preise,\nfür Ihn geh freudig zeugend jeden Augenblick.\nLeb\' so, dass niemand dich einst verklage,\ndort vor des großen Heilandes Thron.\nLeb\' nur in Treue, ganz unverzaget,\ntrage geduldig Spott und Hohn.\r\nLeb\' so,dass wirklich du im Leben\nein helles Licht für Jesus bist.\ndas Jeder muss dir Zeugnis geben,\ndu sei\'st ein guter, treuer, wahrer, echter Christ.\nWenn sie auch gleich den Weg nicht gehen,\nden schmalen Weg, den der Herr bereit\'.\nWie oft ließ\'t selbst du den Heiland stehen,\ndenk nur wie oft dich Gott gemahnt.\r\nNur einmal lebst du in dieser Weise,\nnur kurze Zeit in diesem Leib.\nNur einmal machst du diese Reise\ndurch diese Welt voll Furcht und Leid zur Ewigkeit.\nD\'rum leb\' ein Leben ganz Ihm ergeben,\ndenn du weißt niemals  den letzten Tag.\nD\'rum hinterlasse nur Segensspuren,\ndass and\'re finden das Himmelreich.\r\nLeb so, dass wenn dein lauf vollendet,\nvorüber deine Erdenzeit,\ndie Menschen mit denen du lebtest,\nder Herr sie auch errettet hat und sie befreit.\nleb\' du für Gott in jeder Weise,\ndenk\' daran jeden Augenblick,\ndass du nur einmal machst diese Reise,\nlass eine gute Spur zurück.'),
(9, '1385', 'Nur Jesu Blut, das wäscht mich weiß   (O das Blut, so teuer mir, schützt vor Sünd\' mich für und für)', NULL, 'Nur Jesu Blut, das wäscht mich weiß,\ndas macht mein Herze rein,\ngibt mir das Zeugnis Seines Geist\'s,\ndass ich auf ewig Sein.\r\nO das Blut, so teuer mir,\nschützt vor Sünd\' mich für und für,\nlöst von Furcht und Zweifelspein.\nDas teure Blut macht frei und rein!\r\nNur Jesu Blut, das scheucht hinweg\ndes Satans finst\'re Macht,\nes öffnet uns den Lebensweg,\nder führet aus der Nacht.\r\nNur Jesu Blut, das lässt uns ein\nzur schönen Heimat dort,\nder Blutstrom, herrlich, reich und rein,\nist unser sich\'rer Hort.'),
(9, '1386', 'Nur mit Jesus will ich Pilger wandern', NULL, 'Nur mit Jesus will ich Pilger wandern,\nnur mit Ihm geh\' froh ich ein und aus.\nWeg und Ziel find\' ich bei keinem andern,\nEr allein bringt Heil in Herz und Haus,\nEr allein bringt Heil in Herz und Haus.\r\nBerg und Tal und Feld und Wald und Meere,\nfroh durchwall ich sie an Seiner Hand.\nWenn der Herr nicht mein Begleiter wäre,\nfänd\' ich nie das wahre Vaterland,\nfänd\' ich nie das wahre Vaterland.\r\nEr ist Schutz, wenn ich mich niederlege,\nEr mein Hort, wenn früh ich stehe auf.\nEr mein Rater auf dem Scheidewege,\nund mein Trost bei rauhem Pilgerlauf,\nund mein Trost bei rauhem Pilgerlauf.\r\nBei dem Herrn will ich stets Einkehr halten,\nEr sei Speis\' und Trank und Freude mir.\nSeine Gnade will ich lassen walten,\nIhm befehl\' ich Leib und Seele hier,\nIhm befehl\' ich Leib und Seele hier.\r\nBis es Abend wird für mich hernieden\nund Er ruft zur ew\'gen Heimat hin,\nbis mit Ihm ich gehe ein zum Frieden,\nwo Sein sel\'ger Himmelsgast ich bin,\nwo Sein sel\'ger Himmelsgast ich bin.'),
(9, '1387', 'Nur Sein Kleid hatte sie berührt   (Christ, der Helfer, Er heilte dich)', NULL, 'Nur Sein Kleid hatte sie berührt,\nleise nur mit des Glaubens Hand.\nDoch der Helfer hat wohl es gespürt,\nhat sich zur Kranken gewandt.\r\nChrist, der Helfer, Er heilte dich,\nals Er starb! Glaub es festiglich!\nAll deine Krankheit nahm Er auf sich,\ntrug sie hinweg auf das Kreuz, auf das Kreuz.\r\nTrag\'s nicht länger; Er hat\'s getan,\nplag\' dich länger nicht, komm und ruh\'!\nDarfst Ihm fröhlich im Glauben nun nah\'n;\ndu auch bist frei, ja auch du!\r\nSieh das Lamm in des Leidens Qual,\nsieh, Er litt ja für dich, für dich!\nTrug die Schuld, deine Leiden ja all,\nheilte in Ewigkeit dich!\r\nNur ein Blick zu dem Kreuze hin\nmacht gesund dich und alles weicht.\nSchau auf dich nicht, o schau nur auf Ihn;\nalles der Glaube erreicht.\r\nOhne Fühlen und ohne Seh\'n\nnimm\'s im Glauben, so ist\'s gescheh\'n.\nAuf dem Felsen des Worts sollst du steh\'n,\npreisend durchs Leben dann geh\'n.'),
(9, '1388', 'O bleibe Herr, der Abend bricht herein  -  Abide with me: fast falls the Eventide', 'Abide with me: fast falls the eventide,\nthe darkness deepens, Lord, with me abide.\nWhen other helpers fail and comforts flee,\nhelp of the helpless, o abide with me.\r\nSwift to its close ebbs out life\'s little day,\nearth\'s joys grow dim, its glories pass away.\nChange and decay in all around I see.\nO thou who changest not, abide with me.\r\nI need thy presence every passing hour.\nWhat but thy grace can foil the tempter\'s power?\nWho like thyself my guide and strength can be?\nThrough cloud and sunshine, O abide with me.\r\nI fear no foe with thee at hand to bless,\nills have no weight, and tears no bitterness.\nWhere is death\'s sting? Where, grave, thy victory?\nI triumph still, if thou abide with me.\r\nHold thou thy cross before my closing eyes.\nShine through the gloom and point me to the skies.\nHeaven\'s morning breaks and earth\'s vain shadows flee,\nin life, in death, O Lord, abide with me.', 'O bleibe, Herr, der Abend bricht herein,\nbald ist es Nacht; o lass mich nicht allein!\nWenn alles flieht, wenn jede Stütze bricht,\nDu, der Verlass\'nen Hort, verlass mich nicht!\r\nNicht einen Blick, ein flüchtig Wort der Huld\nbitt\' ich; nein, gütig, herzlich, voll Geduld\nund, wie Dein Mund den Jüngern es verspricht\nauf immerdar, Herr, komm, verlass mich nicht!\r\nKomm als der Arzt, der unsre Krankheit heilt,\nals milder Freund, der allen Kummer teilt,\nkomm nicht gar schrecklich wie zum Weltgericht,\nnein, als Erlöser komm, verlass mich nicht!\r\nHab ich nur Dich, so macht kein Feind mir bang,\nsüß sind die Tränen, leicht der Trübsal Drang;\nja, wenn des Todes Stachel mich anficht,\nder Sieg ist mein, verläss\'st nur Du mich nicht!\r\nUnd bricht mein Aug, so halt Dein Kreuz mir für,\nweis\' durch das Dunkel mir des Himmels Tür;\ndie Schatten flieh\'n, auf strahlt Dein ewig Licht,\nin Tod und Leben, Herr, verlass mich nicht!'),
(9, '1389', 'O das Blut von Jesus  -  Oh the Blood of Jesus   (Chorus)', 'Oh the Blood of Jesus,\nprecious Blood of Jesus.\nOh the Blood of Jesus,\nit washes white as snow.', 'O, das Blut von Jesus,\no, das Blut von Jesus,\no, das Blut von Jesus,\nes wäscht mich weiß wie Schnee!'),
(9, '1390', 'O das ist wunderbar  -  What a wonderful thing   (Chorus)', 'What a wonderful thing,\nwhat a wonderful thing,\nto be free from sin\nand have peace within.\nTo be made a joint heir,\nwith Jesus my King.\nWhat a wonderful, wonderful thing.', 'O das ist wunderbar,\ndas ist wunderbar,\nbin errettet von Sünd\',\nhabe Frieden, bin Sein Kind.\nUnd ich erbe mit Ihm,\nmit König Jesus darf ich geh\'n,\no das ist wunderbar, wunderbar.'),
(9, '1391', 'O dass ich tausend Zungen hätte und einen tausendfachen Mund', NULL, 'O dass ich tausend Zungen hätte\nund einen tausendfachen Mund,\nso stimmt ich damit um die Wette\naus allertiefstem Herzensgrund\nein Loblied nach dem andern an\nvon dem, was Gott an mir getan.\r\nO dass doch meine Stimme schallte\nbis dahin, wo die Sonne steht!\nO, dass mein Blut mit Jauchzen wallte,\nso lang es noch im Laufe geht!\nAch, wär\' ein jeder Puls ein Dank\nund jeder Odem ein Gesang!\r\nWas schweigt ihr denn, ihr meine Kräfte?\nAuf, auf, braucht allen euren Fleiß\nund stehet munter im Geschäfte\nzu Gottes, meines Herren, Preis!\nMein Leib und Seele, schicke dich\nund lobe Gott herzinniglich.\r\nDir sei, o allerliebster Vater,\nunendlich Lob für Leib und Geist,\nfür alles, mildester Berater,\nwas Deine Güte mir erweist,\nwas Du in Deiner ganzen Welt\nzu meinem Nutzen hast bestellt.\r\nMein treu\'ster Jesus, sei gepriesen,\ndass Dein erbarmungsvolles Herz\nsich mir so hilfreich hat erwiesen\nund mich durch Blut und Todesschmerz\nvon aller Teufel Grausamkeit\nzu Deinem Eigentum befreit.\r\nAuch Dir sei ewig Ruhm und Ehre,\no heilig werter Gottesgeist,\nfür Deines Trostes süße Lehre,\ndie mich ein Kind des Lebens heißt.\nAch, wo was Gut\'s von mir geschieht,\ndas wirket nur Dein göttlich Licht.\r\nAch, nimm das arme Lob auf Erden,\nmein Gott, in allen Gnaden hin.\nIm Himmel soll es besser werden,\nwenn ich bei Deinen Engeln bin.\nDa sing ich Dir im höher\'n Chor\nviel tausend Halleluja vor.'),
(9, '1392', 'O dass mein Herz ein Altar wär voll Räuch\'werk des Gebets', NULL, 'O dass mein Herz ein Altar wär\'\nvoll Räuch\'werk des Gebets;\no dass ich Dank und Preis und Ehr\'\ndem Lamm darbrächt\' stets,\ndem Lamm darbrächt\' stets!\r\nWüsst\' ich von diesem Lamme nichts,\nso wär\'s um mich gescheh\'n;\nund ach, am Tage des Gerichts\nmüsst\' ich zur Linken steh\'n,\nmüsst\' ich zur Linken steh\'n!\r\nDoch wohl uns, dieses Lämmlein trug\ndie Sünden aller Welt.\nFür alle wurde es ein Fluch\nund zahlt\' das Lösegeld,\nund zahlt\' das Lösegeld.\r\nEin Lösegeld, das ewig gilt,\ngenug für alle tut,\ndas aller Sünde Jammer stillt:\nDas Lös\'geld ist Sein Blut,\ndas Lös\'geld ist Sein Blut.\r\nGottlob! Es hat auch mich erkauft,\nHalleluja! auch mich.\nIn Seinen Tod bin ich getauft,\nich armes Würmlein, ich\nich armes Würmlein, ich.\r\nWo sind die Sündenschulden all\'?\nIm Meer des Bluts ertränkt;\nich weiß, dass Gott von ihrer Zahl\nnicht einer mehr gedenkt,\nnicht eines mehr gedenkt.\r\nO nein, ich bin Ihm lieb und wert\nin dem erwürgten Lamm,\nich habe, was mein Herz begehrt;\nEr ist mein Bräutigam,\nEr ist mein Bräutigam.\r\nSo fürcht\' ich weder Not noch Tod,\ntrotz allen Feinden nun!\nIn Seinen heil\'gen Wunden rot\nkann ich fein sicher ruh\'n,\nkann ich fein sicher ruh\'n.\r\nMein Herz frohlockt, es jauchzt mein Mund,\nmir ist so wohl zumut;\nund fragst du nach der Freude Grund:\nEs ist des Lammes Blut,\nes ist des Lammes Blut.'),
(9, '1393', 'O die tiefe Liebe Jesu  -  Oh the deep, deep Love of Jesus', 'Oh the deep, deep love of Jesus,\nvast, unmeasured, boundless free.\nRolling as a mighty ocean,\nin its fullness over me.\nUnderneath me, all around me,\nis the current of Your love.\nLeading onward, leading homeward\nto Your glorious rest above.\r\nOh the deep, deep love of Jesus,\nspread His praise from shore to shore.\nHow He came to pay our ransom,\nthrough the saving cross He bore.\nHow He watches o’er His loved ones,\ntThose He died to make His own.\nHow for them He’s interceding,\npleading now before the throne.\r\nOh the deep, deep love of Jesus,\nfar surpassing all the rest.\nIt’s an ocean full of blessing,\nin the midst of every test.\nOh the deep, deep love of Jesus,\nmighty Saviour, precious friend.\nYou will bring us home to glory,\nwhere Your love will never end.', 'O, die tiefe Liebe Jesu!\nFrei, unfassbar, mächtiglich\nrollet gleich dem weiten Meere\nvoll und segnend über mich.\nRings ergießt sich und umschließt mich\nSeiner Liebe reicher Strom,\nführt mich vorwärts, führt mich aufwärts\nbis zur Ruh\' im Himmelsdom.\r\nO, die tiefe Liebe Jesu!\nSei gerühmt von Ort zu Ort;\nwie Er liebet, immer liebet\nohne Wandel fort und fort!\nWie er uns so reich beschenket,\nda er starb als Menschensohn,\nwie Er unser stets gedenket\nauch noch droben vor dem Thron.\r\nO, die tiefe Liebe Jesu!\nNiemand liebt so, Herr, wie Du!\nSie ist mir ein Meer von Segen\nund ein Port zu süßer Ruh\'!\nO die tiefe Liebe Jesu\nist des Himmels Himmel mir.\nSie erhebt zu Herrlichkeiten,\ndenn sie hebt mich, Herr, zu Dir!'),
(9, '1394', 'O dies Verheißungswort, tröstlich und süß  -  Sweet are the Promises, kind is the Word   (Führe mich, ich folge, folge Dir im Glauben nach)', 'Sweet are the promises, kind is the word.\nDearer far than any message man ever heard.\nPure was the mind of Christ, sinless I see.\nHe the great example is, and pattern for me.\r\nWhere He leads I\'ll follow,\nfollow all the way.\nWhere He leads I\'ll follow,\nfollow Jesus ev\'ry day.\r\nSweet is the tender love Jesus hath shown,\nsweeter far than any love that mortals have known.\nKind to the erring one, faithful is He.\nHe the great example is and pattern for me.\r\nList to His loving words, "Come unto Me!"\nWeary, heavy laden, there is sweet rest for thee.\nTrust in His promises, faithful and sure.\nLean upon the Saviour, and thy soul is secure.', 'O, dies Verheißungswort, tröstlich und süß,\nköstlicher als alles, was die Welt mir verhieß.\nSündlos war Jesu Herz, heilig und rein,\nd\'rum sei Er mein Heiland und mein Vorbild allein.\r\nFühre mich, ich folge, folge Dir im Glauben nach,\nJesus Führe mich, ich folge, folge Dir im Glauben nach,\n​Dir, o Jesus, Tag für Tag.\r\nSüß Seiner Liebesglut göttliches Band,\nsüßer als die Liebe, die ein Herz je empfand!\nAlle Verlorenen ladet Er ein,\nEr, mein treuer Heiland und mein Vorbild allein.\r\nHört auf Sein freundlich\' Wort: "Kommt her zu Mir,\nmüde und belad\'ne Seelen, Ruhe ist hier!"\nBringt eure Sündenlast, Er will befrei\'n,\neuer Heil und Zufluchtsort ist Jesus allein.'),
(9, '1395', 'O drückten Jesu Todesmienen sich meiner Seel auf ewig ein', NULL, 'O drückten Jesu Todesmienen\nsich meiner Seel\' auf ewig ein!\nO möchte stündlich sein Versühnen\nin meinem Herzen kräftig sein!\nDenn ach, was hab ich Ihm zu danken!\nFür meine Sünden floss sein Blut;\ndas heilet mich, den Armen, Kranken,\nund kommt mir ewiglich zu gut.\r\nEin  Glaubensblick auf Jesu Leiden\ngib auch dem schwächsten Herzen Mut.\nDie Quelle wahrer Geistesfreuden\nist Sein vergoss\'nes teures Blut.\nWenn Seine Kraft das Herz durchfließet,\nSein Leben unsern Geist durchdringt,\nwenn Seine Huld die Seel umschließet,\nund ihr Sein Trostwort Frieden bringt.\r\nFür mich starb Jesus; meine Sünden\nsind\'s, die Ihn in den Tod versenkt.\nD\'rum lässt Er Gnade mir verkünden,\ndie mich mit Lebenswasser tränkt.\nO Strom der Liebe, klar und helle,\nmein Herz soll offen steh\'n für Dich;\nO unerschöpfte Friedensquelle,\nergieß ohn\' Ende Dich in mich.\r\nHerr Jesus, nimm für Deine Schmerzen\nmich Armen an, so wie ich bin!\nIch setze Dir in meinem Herzen\nein Denkmal Deiner Liebe hin,\ndie Dich für mich in Tod getrieben,\ndich mich aus meinem Jammer riss.\nIch will Dich innig wieder lieben;\nDu nimmst es an, ich bin\'s gewiss.'),
(9, '1396', 'O Du Lamm Gottes, Du hast auf Golgatha herrlich gesieget. Amen, Halleluja', NULL, 'O Du Lamm Gottes, Du hast auf Golgatha\nherrlich gesieget. Amen, Halleluja!\nDu hast erworben Heil für die ganze Welt\nund hast aufs völligste gezahlt das Lösegeld.\nDu riefst mit lauter Stimm\' durchs Todes Nacht:\n"Es ist vollbracht! Es ist vollbracht!"\r\nO Wort des Lebens, hier kann mein Glaube ruh\'n;\nauf diesen Felsen kann ich mich gründen nun.\nEwig vollkommen ist unser\'s Gottes Heil;\nnimm es, o Sünder, an, so wird dir\'s ganz zuteil.\nNichts kannst du machen mehr, Er hat\'s gemacht:\nEs ist vollbracht! Es ist vollbracht!\r\nO Wort des Sieges! Wenn mir der Satan naht,\nblick ich zum Helden, der ihn zertreten hat.\nIn Jesu Wunden bin ich erlöst und frei,\nSein lauter Todesruf ist nun mein Siegesschrei.\nNicht soll mich fesseln mehr des Feindes Macht:\nEs ist vollbracht! Es ist vollbracht!\r\nJesus, mein Heiland, Dir sag ich Preis und Dank!\nO Überwinder, hör meinen Lobgesang!\nIn Deine Gnade hüll\' ich mich tief hinein,\nin Deinem teuren Blut bin ich gerecht und rein.\nEhr\' sei dem Lamm, das rief, da es geschlacht\':\n"Es ist vollbracht! Es ist vollbracht!"'),
(9, '1397', 'O Du mein Trost und süßes Hoffen, lass mich nicht länger meiner Pein', NULL, 'O Du mein Trost und süßes Hoffen,\nlass mich nicht länger meiner Pein,\nmein Herz und Seele sind Dir offen,\no Jesu, ziehe bei mir ein!\nDu Himmelslust, Du Erdenwonne,\nDu Gott und Mensch, Du Morgenglanz,\nach komm, Du teure Gnadensonne,\ndurchleuchte meine Seele ganz!\r\nO dass Du doch mein Herz Dir machtest\nzu Deiner Krippe, Kindlein hehr,\nund in ihm schlummertest und wachtest,\nals wenn es Deine Wiege wär\'!\nDann wär\' in Wahrheit mir gegeben\nein selig Ende meiner Pein;\nach Herr, dass Du in mir kannst leben,\nwoll\' erst in mir geboren sein!\r\nO Heiland, stille mein Verlangen\nmit Deines Kommens Seligkeit;\nvoll Demut will ich Dich empfangen,\nmein Herz und Seele sind bereit,\nmein Denken, Herr, und all mein Sinnen\nganz Deinem teuren Dienst zu weih\'n,\no lass mich Deinen Trost gewinnen,\no Jesus, ziehe bei mir ein!'),
(9, '1398', 'O Ehre sei Gott, Er hob mich empor  -  Oh glory to God, He lifted me up   (2 Chorusse)', 'Oh glory to God He lifted me up,\nHe lifted me up I know.\nHe reached down His hand\nAnd He lifted me up\nAnd that\'s why I love Him so.\r\nI love Him more and more.\nI love Him more and more.\nAnd when I stand upon the other shore\nI\'ll praise Him more and more.', 'O Ehre sei Gott, Er hob mich empor,\nEr hob mich empor, weiß ich.\nEr reichte die Hand und hob mich empor.\nUnd darum lieb\' ich Ihn so.\r\n'),
(9, '1399', 'O glorious Victory that Day He set me free   (Who I am, Lord, who I am)', 'O glorious victory\nthat day He set me free,\nand He made my heart His very throne.\nMy life is no longer mine,\nI\'m a prisoner of love divine,\nand now I live to praise His name.\r\nWho I am, Lord, who I am,\nI can see now, who I am.\nA part of my Saviour,\na part of His Word.\nIt\'s a revelation (It\'s predestination)\nof who I am.\r\nOn Calvary He died\nto redeem His lost Bride,\nthe King of Kings\nbecame my Saviour.\nThis is God\'s great mystery\nof love expressed to me,\nthat Christ and I\nmight be made one!', NULL),
(9, '1400', 'O Gott, Dir sei Ehre, der Großes getan  -  To God be the Glory, great Things He hath done   (Preist den Herrn, preist den Herrn)', 'To God be the glory, great things He hath done,\nso loved He the world that He gave us His Son.\nWho yielded His life an atonement for sin,\nand opened the life gate that all may go in.\r\nPraise the Lord, praise the Lord,\nlet the earth hear His voice.\nPraise the Lord, praise the Lord,\nlet the people rejoice.\nOh, come to the Father, through Jesus the Son,\nand give Him the glory, great things He hath done.\r\nOh, perfect redemption, the purchase of blood,\nto every believer the promise of God.\nThe vilest offender who truly believes,\nthat moment from Jesus a pardon receives.\r\nGreat things He hath taught us, great things He hath done,\nand great our rejoicing through Jesus the Son.\nBut purer, and higher, and greater will be,\nour wonder, our transport when Jesus we see.', 'O Gott, Dir sei Ehre der Großes getan!\nDu liebtest die Welt, nahmst der Sünder Dich an!\nDein Sohn hat sein Leben zum Opfer geweiht.\nDer Himmel steht offen zur ewigen Freud\'.\r\nPreist den Herrn! preist den Herrn!\nErde hör\' diesen Schall!\nPreist den Herrn! Preist den Herrn!\nVölker freuet euch all\'!\nO kommt zu dem Vater! In Jesus wir nah\'n,\nund gebt Ihm die Ehre, der Großes getan!\r\nO große Erlösung, erkauft durch sein Blut!\nDem Sünder, der glaubt, kommt sie heute zugut!\nDie volle Vergebung wird jedem zuteil,\nder Jesum erfasset, das göttliche Heil.\r\nWie groß ist Sein Lieben! Wie groß ist sein Tun!\nWie groß uns\'re Freude, in Jesus zu ruh\'n!\nDoch größer und reiner und höher wird\'s sein,\nwenn jubelnd und schauend wir droben zieh\'n ein.');
INSERT INTO song_list (LISTID, NUM, NAME, TEXT_EN, TEXT_DE) VALUES
(9, '1401', 'O Gott, sei gelobt für die Liebe im Sohn  -  We praise Thee, o God, for the Son of Thy Love   (Halleluja sei gepriesen)', 'We praise Thee, o God, for the Son of Thy love,\nfor Jesus who died and is now gone above.\r\nHallelujah! Thine the glory,\nHallelujah! Amen.\nHallelujah! Thine the glory,\nrevive us again.\r\nWe praise Thee, oh God, for Thy spirit of light,\nwho has shown us our Saviour, and scattered our night.\r\nAll glory and praise to the Lamb that was slain,\nwho has borne all our sins and has cleansed ev\'ry stain.', 'O Gott, sei gelobt für die Liebe im Sohn,\nder mit Blut uns erkauft und dann aufstieg zum Thron!\r\nHalleluja, sei gepriesen,\nHalleluja, Amen.\nHalleluja, sei gepriesen,\nHerr, segne uns jetzt!\r\nO Gott, sei gelobt für den Heiligen Geist,\nder zum Heiland uns führt und dann himmelwärts weist!\r\nLob, Ehre und Preis sei für immer gebracht,\nDir, dem Lamm, das von Sünde uns selig macht!'),
(9, '1402', 'O Heiland lass mich gehn mit Dir  -  O Master let me walk with Thee', 'O Master, let me walk with Thee,\nin lowly paths of service free.\nTell me Thy secret; help me bear\nthe strain of toil, the fret of care.\r\nHelp me the slow of heart to move\nby some clear, winning word of love.\nTeach me the wayward feet to stay,\nand guide them in the homeward way.\r\nTeach me Thy patience; still with Thee\nin closer, dearer, company,\nin work that keeps faith sweet and strong,\nin trust that triumphs over wrong.\r\nIn hope that sends a shining ray,\nfar down the future’s broad’ning way,\nin peace that only Thou canst give,\nwith Thee, O Master, let me live.', 'O Heiland lass mich geh\'n mit Dir\nden sel\'gen Pfad des Dienstes hier.\nWeih\' mich in Dein Geheimnis ein,\nlass mich im Kampf stets ruhig sein.\r\nHilf mir durch Deiner Liebe Glut,\nverzagten Herzen machen Mut.\nLehr\' mich, die Seelen, die verirrt,\nzu Dir zu führen guter Hirt\'.\r\nDeine Geduld, Herr, lehre mich,\nbinde mich fester nur an Dich,\ngib meinem Glauben Mut und Kraft,\nzu überwinden Satans Macht.\r\nDie Hoffnung ist mein helles Licht,\nich weiß den Weg und irre nicht,\nund Deinen Frieden gibst Du mir,\nso darf ich leben, Herr, mit Dir.'),
(9, '1403', 'O Herr ich liebe Dich, Jesus ich liebe Dich', NULL, 'O Herr ich liebe Dich, Jesus ich liebe Dich.\nMeine Sonne bist Du Tag für Tag. Ich liebe Dich.\nDu mein Stern in der Nacht, dunkelster Nacht,\nDu hast alles für mich wieder gut gemacht.\nMeines Lebens Quell bist du allein. Ich liebe Dich.'),
(9, '1404', 'O Herr, verweile bei uns und führ uns allezeit', NULL, 'O Herr, verweile bei uns und führ\' uns allezeit\nauf Deinen weisen Wegen bis in die Ewigkeit!\r\nErzeig\' der Welt ein Wunder! Schaff Einigkeit, o Herr,\nweltweit bei Deinen Kindern; den Frieden uns bescher\'!\r\nLass sein uns eines Sinnes! Die Liebe senk\' ins Herz!\nDie Sanftmut, Demut schenk\' uns und führ\' uns himmelwärts!\r\nErgieß\' auf alle wieder, Herr, Deinen Strom der Gnad\'\nund lehr\' uns Dich zu ehren, durch\'s Wort und durch die Tat!'),
(9, '1405', 'O herrlicher Retter, mein König, mein Herr  -  A wonderful Saviour is Jesus my Lord   (Im Schatten des Felsens, da ist es gar traut)   [Pfingstjubel]', 'A wonderful Saviour is Jesus my Lord,\na wonderful Saviour to me.\nHe hideth my soul in the cleft of the rock,\nwhere rivers of pleasure I see.\r\nHe hideth my soul in the cleft of the rock,\nthat shadows a dry, thirsty land.\nHe hideth my life in the depths of His love,\nand covers me there with His hand,\nand covers me there with His hand.\r\nA wonderful Saviour is Jesus my Lord,\nHe taketh my burden away.\nHe holdeth me up and I shall not be moved,\nHe giveth me strength as my day.\r\nWith numberless blessings each moment He crowns,\nand filled with His fullness divine.\nI sing in my rapture, oh, glory to God,\nfor such a Redeemer as mine.\r\nWhen clothed with His brightness transported I rise\nto meet Him in clouds of the sky.\nHis perfect salvation, His wonderful love,\nI’ll shout with the millions on high.', 'O herrlicher Retter, mein König, mein Herr,\noh, Jesus, Du Heiland der Welt!\nMit Strömen der Freude erfüllst Du das Herz\nund birgst mich in Deinem Gezelt.\r\nIm Schatten des Felsens, da ist es gar traut\',\nbrennt heiß in der Wüste die Glut.\nO ewige Liebe, in Deinem Gezelt,\nwie ruht da die Seele so gut!\nWie ruht da die Seele so gut!\r\nO Jesus, mein Heiland, wie bist Du so treu.\nDu hast mir die Freiheit verschafft.\nEs stützt mich und trägt Deine helfende Hand\nund füllt mir die Seele mit Kraft.\r\nMit Freudenöl hast Du das Haupt mir gesalbt\nund schenkst mir den Becher voll ein.\nIch singe und preise und juble empor,\ndass solch ein Erlöser ist mein!\r\nUnd wenn ich in Wolken des Himmels entrückt,\nempor in die Herrlichkeit geh,\ndann rühme ich jubelnd die ewige Lieb\'\nund preise Dich, Gott, in der Höh\'!'),
(9, '1406', 'O Herz sei still und denke an den Tag   (O blick auf Golgatha, zum Kreuz auf Golgatha)', NULL, 'O Herz, sei still und denke an den Tag,\nals an dem Kreuz dein Heiland für dich starb,\nals an dem Holz den Fluch Er auf Sich nahm\nund ew\'ges Heil für dich und mich erwarb.\r\nO blick auf Golgatha, zum Kreuz auf Golgatha,\nwo Jesus starb am blut\'gen Kreuzesstamm.\nO blick auf Golgatha, zum Kreuz auf Golgatha,\nwo Er die Sünden von uns allen nahm.\r\nO sieh die Menschen, die beim Kreuze steh\'n,\nauch du und ich, wir sind dort mitgezählt.\nEs ist um uns\'re Sündenschuld gescheh\'n,\nda Gottes Sohn am Kreuze ward gequält.\r\nNoch heut\' wie einst steh\'n viele vor dem Kreuz.\nSie lehnen ab Den, Der für sie dort starb.\nDoch öffne du in Liebe Ihm dein Herz,\nnimm an das Heil, das Er dir dort erwarb.'),
(9, '1407', 'O hört das wunderbare Wort, das Evangelium', NULL, 'O hört das wunderbare Wort, das Evangelium,\nund sagt es immer weiter fort zu Gottes Preis und Ruhm!\nDas Wort vom Kreuz ist Gotteskraft,\ndie lauter Gnadenwunder schafft;\ndringt dir dies Wort durch Mark und Bein,\nwirst du noch heut\' gerettet sein.\r\n"Es ward die Welt, die Gott verhöhnt, mit Ihm zur selben Stund\',\nals sie Ihn kreuzigte, versöhnt", so spricht des Höchsten Mund.\nO Golgatha, o Golgatha!\nWer fasst, was einst für uns geschah?\nHier rang die Liebe mit dem Zorn\nund öffnete den Gnadenborn!\r\nKomm, sieh, was nie ein Auge sah, komm, blicke dich gesund!\nFür mich, für dich hängt Jesus da, für uns schlug man Ihn wund.\nO Seele, sieh, o Seele, sieh!\nVergiss die große Liebe nie!\nEs stirbt der Sünde Zauberreiz\ndurch einen Glaubensblick aufs Kreuz.\r\nAch sieh das teure Gotteslamm, es gab Sich dir zugut!\nTritt nah herzu zum Kreuzesstamm und schau das teure Blut.\nDas Blut, das Blut, das Blut allein\nmacht uns von allen Sünden rein.\nEs löst der Sünden größten Schmerz\nund öffnet Gottes Vaterherz!'),
(9, '1408', 'O ich hab einen treuen Heiland   (An das Kreuz schlug man Ihn für mich)', NULL, 'O ich hab einen treuen Heiland,\nder für mich einst Sein Leben gab.\nHat am Kreuz dort Sein Blut vergossen,\nalle Sünden nahm Er mir ab.\r\nAn das Kreuz schlug man Ihn für mich!\nAn das Kreuz schlug man Ihn für mich!\nAls am Kreuz Er verblich, starb Er für mich.\nAn das Kreuz schlug man Ihn für mich.\r\nGern verließ Er den Thron des Himmels,\nnach des Vaters so weisen Rat.\nDort in Bethlehems Stall geboren,\ntrat Er dann auf den Dornenpfad.\r\nFür mich schlug man tiefe Wunden,\nmeine Sorgen nahm Er auf Sich.\nWard von Krankheit und Schmerz betroffen,\nduldet alles für mich und dich.'),
(9, '1409', 'O ich liebe Ihn, ja ich liebe Ihn   (Chorus)', NULL, 'O ich liebe Ihn! Ja, ich liebe Ihn,\nweil Er blutend für mich starb.\nO ich liebe Ihn! Ja, ich liebe Ihn,\nder am Kreuz mir Heil erwarb.'),
(9, '1410', 'O ich weiß ein Land hinterm Wolkenmeer so weit   (Wunderschönes Land, o ich sehne mich hier fort)', NULL, 'O ich weiß ein Land hinterm Wolkenmeer so weit,\neinen schönen Strand in der größten Herrlichkeit.\nO ich sehne mich nach Jerusalem so sehr,\nwo es gibt kein Scheiden mehr.\r\nWunderschönes Land, o ich sehne mich hier fort.\nAn dem klaren Strand, liebe Freunde warten dort.\nOftmals hör\' ich schon, wenn mein Herz ist schwer und bang,\nihren freud\'gen Willkommensang.\r\nDieser Erden Sorgen sind endlich bald vorbei.\nIn des Vaters Haus sind wir alle froh und frei.\nAch, mein Sehnen geht von der Erde Müh\' und Last,\nnach dem Land der süßen Rast.\r\nO ich schau\' im Glauben das wundervolle Land.\nO welch Glück für mich, wenn ich steh\' am gold\'nen Strand.\nIch will eilen vorwärts durch Trübsal und Gefahr,\nPreis sei Gott, bald bin ich da.'),
(9, '1411', 'O Jesus, ich wär\' so gern\' heilig und rein  -  Lord Jesus, I long to be perfectly whole   (Weißer als Schnee, ja weißer als Schnee)   [Siegesklänge]', 'Lord Jesus, I long to be perfectly whole,\nI want Thee forever to ransom my soul.\nBreak down ev\'ry idol, cast out ev\'ry foe,\nnow wash me, and I shall be whiter than snow.\r\nWhiter than snow, yes, whiter than snow.\nNow wash me, and I shall be whiter than snow.\r\nLord Jesus, for this I most humbly entreat,\nI wait, blessed Lord, at Thy crucified feet.\nBy faith, for my cleansing I see Thy blood flow,\nnow wash me, and I shall be whiter than snow.\r\n\r\nLord Jesus, Thou knowest I patiently wait,\ncome now, and within me a new heart create.\nTo those who have sought Thee, Thou never said "No:"\nnow wash me, and I shall be whiter than snow.\r\n', 'O Jesus, ich wär\' so gern\' heilig und rein;\nach wohntest und throntest Du in mir allein!\nZerbrich jeden Götzen und ende mein Weh!\nO, wasch\' mich im Blute jetzt weißer als Schnee!\r\nWeißer als Schnee, ja weißer als Schnee.\nO, wasch\' mich im Blute jetzt weißer als Schnee!\r\nO Jesus, lass nichts von der Sünde zurück!\nVollführe Dein Werk und vollende mein Glück,\ndass ich Dich verklärt in mir finde und seh\'.\nO, wasch\' mich im Blute jetzt weißer als Schnee!\r\nO Jesus, ich bring Dir als Opfer und Gab\nmein alles, was irgend ich bin oder hab.\nAch komm, mich zu segnen aus himmlischer Höh\',\nund wasch\' mich im Blute jetzt weißer als Schnee!\r\nO Jesus, ich warte voll Sehnsucht auf Dich;\nkomm eilend, erneure und heilige mich!\nDu willst nicht, dass einer getäuscht von Dir geh\'!\nAch wasch\' mich im Blute jetzt weißer als Schnee!\r\nO Jesus, ich fass Dich im Glauben beim Wort!\n"Sei rein", sprichst Du deutlich zu mir, o mein Hort!\nMein Herz ist so stille und klar wie die See;\ngewaschen im Blute, ist\'s weißer als Schnee.'),
(9, '1412', 'O Jesus, mein Jesus, mein Herz zu Dir nimm   (Herr, schenk mir die Kraft, Herr, rede zu mir)', NULL, 'O Jesus, mein Jesus, mein Herz zu Dir nimm,\nerrette mich ganz von dem eigenen Sinn,\nso dass es wird Himmel auf Erden schon hier,\nzu teilen die Schmerzen und Freuden mit Dir!\r\nHerr, schenk\' mir die Kraft! Herr, rede zu mir.\nHerr, hilf mir das Kreuz zu tragen mit Dir!\nHerr, schenk\' mir die Kraft, Herr, rede zu mir,\nHerr, hilf mir das Kreuz zu tragen mit Dir.\r\nDring\' tief in mein Herz, Herr, ich flehe zu Dir\nund sende von oben die Kraft auch zu mir,\ndass ernster und tiefer ich beugen mich kann,\nmich opfern und leben für Dich Gottes Lamm.\r\nIch will nicht mehr bitten um Kronen und Reich.\nIch flehe, mein Jesus, oh, mache mich Dir gleich,\ndass leiden ich kann hier, mein Jesus, für Dich,\nDu bist ja vom Tod auferstanden für mich!\r\nIch sehne mich sehr nach dem ewigen Glück.\nO, möchte nicht etwas mich halten zurück,\ndenn schön ist die Hoffnung des Himmels für mich.\nIch weiß ja, mein Jesus, ich finde dort Dich.'),
(9, '1413', 'O kein Freund der mich liebt wie Jesus   (Kein Freund, der mich liebt wie Jesus)', NULL, 'Oh kein Freund, der mich liebt wie Jesus,\nwenn des Lebens Stürme mich bedroh\'n;\nEr erquickt das wunde Herz,\nEr gibt Kraft im tiefsten Schmerz;\noh kein Freund, der mich liebt wie Jesus!\r\nKein Freund, der mich liebt wie Jesus,\nkein Freund, der mich liebt wie Jesus,\nEr vernimmt dein heißes Fleh\'n,\nund Er eilt, dir beizusteh\'n;\noh kein Freund, der mich liebt wie Jesus!\r\nWelchen Freund fand ich einst in Jesus,\nDer das Herz mit Trost und Frieden füllt;\nhält Er mich mit starkem Arm,\nfürcht\' ich weder Leid noch Harm;\noh kein Freund, der mich liebt wie Jesus!\r\nGeht mein Fuß auch im finster\'n Tale,\nwo die eis\'ge Flut des Jordan rollt;\nkeine Schrecken fürcht\' ich dann,\ndenn mein Heiland ist mir nah;\noh kein Freund, der mich liebt wie Jesus!\r\nWenn wir endlich die Heimat schauen\nmit den Lieben, die voran geeilt,\npreisen wir Ihn immerdar\nmit der bluterkauften Schar;\noh kein Freund, der mich liebt wie Jesus!'),
(9, '1414', 'O komm doch mit mir nach Golgatha', NULL, 'O komm doch mit mir nach Golgatha\nund sieh was am Kreuze für dich dort geschah.\nDort leidet Er Schmerzen und betet für dich,\nvon Menschen veracht\', verhöhnt und verlacht,\nstarb der Herr für dich.\r\nO komm doch mit mir nach Golgatha,\nder Heiland und Retter der Welt blutet da.\nUnd von diesem Mann den du so veracht\',\ntönt am Kreuze das Wort, es ist vollbracht,\ndas tat Er für dich.\r\nO komm doch mit mir nach Golgatha,\ndenn da ist der Himmel auf Erden dir nah.\nO sieh deine Sünden nahm Jesus auf sich,\nals am Kreuz Er als Heiland in Schmerzen verblich.\nDas tat Er für dich.'),
(9, '1415', 'O komm zu dem Heiland und glaube an Ihn  -  O come to the Saviour, believe in His Name   (Ja, es gibt Gnade für dich)', 'O, come to the Saviour, believe in His Name,\nand ask Him your heart to renew.\nHe waits to be gracious, o turn not away,\nfor now there is pardon for you.\r\nYes, there is pardon for you,\nyes, there is pardon for you.\nFor Jesus has died to redeem you,\nand offers full pardon to you.\r\nThe way of transgression that leads unto death,\no why will you longer pursue?\nHow can you reject the sweet message of love,\nthat offers full pardon for you?\r\nBe warned of your danger, escape to the cross,\nyour only salvation is there.\nBelieve, and that moment the Spirit of grace\nwill answer your penitent prayer.', 'O komm zu dem Heiland und glaube an Ihn,\nund bitt\' Ihn: "O heile auch mich!"\nEr wartet schon lange, dich zu Sich zu zieh\'n;\no sieh, es gibt Gnade für dich!\r\nJa, es gibt Gnade für dich!\nJa, es gibt Gnade für dich!\nDein Jesus, Er starb, dich zu retten;\nd\'rum sieh, es gibt Gnade für dich!\r\nWas willst du noch länger den Sündenweg geh\'n,\nder führet zum Tod und Gericht!?\nWarum denn der Liebe des Herrn widersteh\'n,\nda Er dir doch Gnade verspricht?\r\nO fliehe zum Kreuz deines Heilandes hin,\nsonst sinkst du in ewige Nacht!\nO glaube an Jesum in kindlichem Sinn,\nEr hat auch für dich einst vollbracht!'),
(9, '1416', 'O komm zu dem Heiland und schenk Ihm dein Herz   (Noch ist ja die köstliche Gnadenzeit)', NULL, 'O komm zu dem Heiland und schenk\' Ihm dein Herz\nund sage Ihm all deinen Jammer und Schmerz!\nO, komm doch und sag es Ihm ganz unverzagt,\nwas dich in der Seele bedrücket und plagt!\nO, klag Ihm dein ganzes Herzeleid!\r\nNoch ist ja die köstliche Gnadenzeit!\nO, komm zu dem Heiland der Sünder!\r\nWas stehst du noch zweifelnd? O, komm doch heran!\nWahrhaftig, der Heiland nimmt gerne dich an!\nO, komm doch und zögere länger nicht mehr,\nund wär\' deine Sünde gleich tief wie das Meer\nund hoch wie ein Berg dein Herzeleid!\r\nO komm, auch für dich floss Sein kostbares Blut!\nAuch dir kommt Sein Leiden und Sterben zugut!\nBeladener Sünder, o eile herzu,\nbei Ihm find\'st du Frieden, bei Ihm find\'st du Ruh!\nBei Jesus weicht jedes Herzeleid.\r\nEs schwindet die Zeit und bald ist es zu spät!\nWer weiß es, wie lange der Ruf noch ergeht.\nDer Ruf deines Heilands, der nach dir verlangt,\nder gerne dich rettet, den\'s heiß um dich bangt.\nEr schauet nach dir voll Herzeleid.'),
(9, '1417', 'O Land der Ruh, ich wart auf dich  -  O Land of Rest, for thee I sigh   (Ans Werk bis Jesus kommt)', 'O land of rest, for thee I sigh!\nWhen will the moment come\nwhen I shall lay my armor by\nand dwell in peace at home?\r\nWe\'ll work till Jesus comes,\nwe\'ll work till Jesus comes,\nwe\'ll work till Jesus comes\nand we\'ll be gathered home.\r\n\r\nTo Jesus Christ I fled for rest;\nHe bade me cease to roam.\nAnd lean for comfort on His breast\ntill He conducts me home.\r\nI sought at once my Saviour\'s side\nno more my steps to roam.\nWith Him I\'ll brave death\'s chilling tide,\nand reach my heavenly home.', 'O Land der Ruh\', ich wart auf dich!\nWann wird der Tag wohl sein?\nWenn ich die Waffen niederleg\',\nund geh in Frieden ein.\r\nAns Werk bis Jesus kommt,\nans Werk bis Jesus kommt,\nans Werk bis Jesus kommt\nund dann geht es nach Haus.\r\nEinst suchte ich den Frieden nur\nund Ruh\' in dieser Welt.\nDoch als ich dann zu Jesus fand,\nward ich zum Werk bestellt.\r\nBei Jesus fand ich endlich Ruh\',\nvon meiner Wanderschaft und\ntäglich gibt Er Speise mir,\nund für den Weg die Kraft.\r\nSeit dem ich meinen Jesus fand,\nsind meine Schritte fest\nund sogar noch im Tod weiß ich,\ndass Er mich nie verlässt.'),
(9, '1418', 'O lass den Geist nicht von dir fliehn  -  Oh, do not let the Word depart   (Warum nicht heut)', 'Oh, do not let the Word depart,\nand close thine eyes against the light.\nPoor sinner, harden not your heart,\nbe saved, oh, tonight.\r\nOh, why not tonight?\nOh, why not tonight?\nWilt thou be saved?\nThen why not tonight?\r\nTomorrow’s sun may never rise\nto bless thy long-deluded sight.\nThis is the time, oh, then be wise,\nbe saved, oh, tonight.\r\nOur Lord in pity lingers still,\nand wilt thou thus His love requite?\nRenounce at once thy stubborn will,\nbe saved, oh, tonight.\r\nOur blessed Lord refuses none\nwho would to Him their souls unite.\nBelieve on Him, the work is done,\nbe saved, oh, tonight.', 'O lass den Geist nicht von dir flieh\'n,\nschau nicht zurück zur Eitelkeit!\nDu weißt, du musst zum Heiland flieh\'n,\nwann willst du\'s tun? Warum nicht heut\'?\r\nWarum nicht heut\'?\nWarum nicht heut\'?\nWann willst du\'s tun?\nWarum nicht heut\'?\r\nWer weiß, wie bald dein Leben schließt!\nO eile doch bei guter Zeit\nzum Brunn\', da ew\'ges Leben fließt.\nWann willst du\'s tun? Warum nicht heut\'?\r\nWas beut\' die Welt für Freude dir?\nIhr Spielwerk ist Vergänglichkeit.\nGott spricht: Dring\' durch die off\'ne Tür!\nWann willst du\'s tun? Warum nicht heut\'?\r\nDer Heiland nimmt die Sünder an.\nEr führt auch dich zur Seligkeit,\ndich zieht\'s auf Seine schmale Bahn,\nwann folgest du? Warum nicht heut\'?'),
(9, '1419', 'O lass den Sohn des Höchsten wirken   (Jesus, oh Jesus, gib uns Deinen Geist)', NULL, 'O lass den Sohn des Höchsten wirken,\ndurch den Geist und Seine Kraft,\nnimm Ihn auf, Er bringt Zufriedenheit ins Herz.\nO gib Ihm alles, was dich festhält,\ndann führt Er dich jeden Tag\nund Sein Geist wird in dir bleiben ewiglich.\r\nJesus, oh Jesus,\ngib uns Deinen Geist. (2x)\r\nO komm und sing dies Lied voll Freude,\nkomm und bring Ihm deinen Dank.\nHeb\' die Hände auf und preise Seinen Nam\'.\nBring Ihm doch alle deine Sorgen,\nbring Ihm alles, was dich quält,\nin Ihm wirst du alles finden, was dir fehlt.'),
(9, '1420', 'O lasset uns anbeten  -  Oh come, let us adore Him   (5 Chorusse)', 'Oh come, let us adore Him,\noh come, let us adore Him,\noh come, let us adore Him,\nChrist, the Lord.\r\nI\'ll give you all the glory,\nI\'ll give you all the glory,\nI\'ll give you all the glory,\nmy Lord and God.\r\nFor You are my redeemer,\nfor You are my redeemer,\nfor You are my redeemer,\nmy Lord Jesus.\r\nFor He alone is worthy,\nfor He alone is worthy,\nfor He alone is worthy,\no Lamb of God.\r\nIn Him there is no failure,\nin Him there is no failure,\nin Him there is no failure,\nChrist the Lord.', 'O lasset uns anbeten,\nO lasset uns anbeten,\nO lasset uns anbeten,\nden König.\r\nIch gebe Dir die Ehre,\nIch gebe Dir die Ehre,\nIch gebe Dir die Ehre,\nmein Herr und Gott.\r\nDenn Du bist mein Erlöser,\nDenn Du bist mein Erlöser,\nDenn Du bist mein Erlöser,\nmein Herr Jesus.\r\nNur Du allein bist würdig,\nNur Du allein bist würdig,\nNur Du allein bist würdig,\no Gotteslamm.\r\nIn Ihm gibt\'s kein Versagen,\nin Ihm gibt\'s kein Versagen,\nin Ihm gibt\'s kein Versagen,\nChristus der Herr.'),
(9, '1421', 'O lasst uns mit Jauchzen erheben   (Gelobt sei Gott, gelobt sei der Herr unser Heil)', NULL, 'O lasst uns mit Jauchzen erheben\nden Schöpfer und Herrscher der Welt,\nden Herrn, von des Güte wir leben,\ndes Allmacht uns trägt und erhält!\r\nGelobt sei Gott, gelobt sei der Herr unser Heil!\nWir trau\'n auf Ihn, Er ist unser Gut, unser Teil!\r\nIhm, Ihm gehört Himmel und Erde,\nja, Ihm ist kein anderer gleich.\nUnd wir sind das Volk Seiner Herde,\nberufen, zu erben Sein Reich.\r\nVoll Liebe hat stets Er gewaltet\nund über uns freundlich gewacht,\nhat lieblich das Los uns gestaltet\nund hier uns schon glücklich gemacht.\r\nUnd hat Seine Hand uns geschlagen,\nso hatte Er dennoch uns lieb.\nUnd gab es auch Lasten zu tragen,\ndie Hoffnung der Herrlichkeit blieb.\r\nIhm, der uns durch Jesus versöhnet,\nder uns aus dem Staube erhob und uns mit\nBarmherzigkeit krönet, Ihm,\nIhm gebührt Ehre und Lob.\r\nO lasst uns mit jubelnden Chören\nIhm stets unser Loblied erneu\'n.\nPreist Ihn, alle Welt soll es hören,\ndass wir unsres Gottes uns freu\'n.'),
(9, '1422', 'O lehre mich wandeln wie Henoch mit Gott   (O Herrlichkeitsweg, mein Jesus Du selbst bist nun Überwinder in mir)', NULL, 'O lehre mich wandeln wie Henoch mit Gott,\nmein Heiland, bei Tag und bei Nacht,\nzu ruhen in Deiner glückseligen Näh\',\ngetragen von göttlicher Macht.\r\nO Herrlichkeitsweg, mein Jesus Du selbst\nbist nun Überwinder in mir.\nDu wandelst und lebst, Du streitest und siegst,\no ewig Anbetung sei Dir!\r\nBefreit von der Sünde, befreit von der Furcht,\nder Vater, Er lächelt mir zu.\nO Wunder der Gnade, mein Retter, mein Herr,\nDu hast es vollbracht, o nur Du!\r\nGelöst von der Erde, gekreuzigt der Welt,\nein Werkzeug des Herrn nur allein,\nnichts wissen und streben, nichts wollen und tun,\nals Ihm nur zur Ehre zu sein.\r\nO Anbetung Dir, Deinem Namen die Ehr,\nso lange hier währet die Zeit;\nich ruhe und staune und bete Dich an\nund schaue Dich in Ewigkeit.'),
(9, '1423', 'O Liebe, goldner Sonnenschein   (O Gotteslieb, so voll und frei, von alters her und immer neu)', NULL, 'O Liebe, goldner Sonnenschein für\'s arme Menschenherz,\nstrahlst du nur hell in mich hinein, versüßt ist jeder Schmerz.\nDas Dunkel weicht, die Nacht entflieht,\nwenn warm die Sonne scheint,\nund Freud und Lebenswonne zieht hinein ins Herz, das weint.\r\nO Gotteslieb\', so voll und frei,\nvon alters her und immer neu,\nsie quillt für mich, sie quillt für dich\nund zieht uns alle hin zu sich.\r\nAls von der Lieb am Kreuzespfahl in meine Sündennacht\neindrang der helle Sonnenstrahl, bin ich für Gott erwacht.\nSeitdem ich weiß, wer mich geliebt bis in den Tod so heiß,\nmein Herz sich Ihm zu eigen gibt zu Seines Namens Preis!\r\nDie Sonne, die mir scheinet hell, mir Lebenswonne beut,\nist Jesus, mein Immanuel, nur Er in Ewigkeit!\nIhm singe ich mein Jubellied schon hier im Trännental\nund ewig, wenn mein Aug\' Ihn sieht, in Seinem Himmelssaal.'),
(9, '1424', 'O magnify the Lord with me', 'O magnify the Lord with me,\nblessed Lamb of Calvary.\nFor His grace so rich and free,\nmagnify the Lord with me. (hallelujah)\nMagnify the Lord with me,\nblessed Lamb of Calvary,\nJesus gives the victory,\no magnify the Lord with me.', NULL),
(9, '1425', 'O mein Bruder kennst du schon den Heiland   (6 Strophen, deutsche Fassung)', NULL, 'O mein Bruder, kennst du schon den Heiland\nder dich liebt ganz inniglich?\nDieser Fels der Ewigkeiten\ntrieft von Honigseim für dich.\nEs ist Honig in dem Felsen, Bruder,\nes ist Honig in dem Fels für dich,\nlass das Blut deine Schuld bedecken,\nso ist Honig in dem Fels für dich.\r\nDürstet denn nicht deine arme Seele?\nSie ist krank und matt und siech.\nAus dem Felsen fließet Wasser,\nLebensflut für mich und dich.\nEs ist Wasser in dem Felsen, Bruder,\nes ist Wasser in dem Fels für dich.\nSchlage nur mit dem Stab des Glaubens,\ndann ist Wasser in dem Fels für dich.\r\nHungerst du wohl nach dem Brot des Lebens,\ndas der Herr uns einst verhieß,\nHimmelsspeise birgt der Felsen,\nsüße Frucht vom Paradies.\nEs ist Speise in dem Felsen, Bruder,\nes ist Speise in dem Fels für dich,\nsuche nur in der Morgenfrühe,\nes ist Speise in dem Fels für dich.\r\nHat die Sonne dich verbrannt am Wege,\ndich verletzt ihr heißer Stich?\nLagre dich am Fels der Wüste,\nda ist Schatten auch für dich.\nEs ist Schatten an dem Felsen, Bruder,\nes ist Schatten an dem Fels für dich,\nlass nur ab von den eignen Wegen,\nso ist Schatten an dem Fels für dich.\r\nIst dein Herze kalt und matt und öde,\nohne Liebe, ohne Licht?\nNah dich Christo, deinem Felsen,\nFeuer ist im Fels für dich.\nEs ist Feuer in dem Felsen, Bruder,\nes ist Feuer in dem Fels für dich.\nBringe endlich ein ganzes Opfer,\nso ist Feuer in dem Fels für dich.\r\nFehlt dir immer noch das Beste, Bruder?\nHat das Glück verlassen dich?\nO vernimm die frohe Kunde,\nes ist Hoffnung auch für dich.\nEs ist alles für dich da im Felsen,\nes ist alles in dem Fels für dich.\nKannst du nur ganz dich selbst verlieren,\nso ist alles in dem Fels für dich.'),
(9, '1426', 'O mein Bruder kennst du schon den Heiland  -  O my Brother, do You know the Saviour   (Es ist Honig in dem Fels, mein Bruder)   (4 Strophen, Original)', 'O my brother, do you know the Saviour,\nwho is wondrous, kind and true?\nHe\'s the Rock of your salvation!\nThere\'s Honey in the Rock for you.\r\nOh, there\'s Honey in the Rock, my brother,\nthere\'s Honey in the Rock for you.\nLeave your sins for the blood to cover,\nthere\'s Honey in the Rock for you.\r\nHave you tasted that the Lord is gracious?\nDo you walk in the way that\'s new?\nHave you drank from the living Fountain?\nThere\'s Honey in the Rock for you.\r\nDo you pray unto God the Father,\n"what wilt thou have me to do?"\nNever fear He will surely answer,\nthere\'s Honey in the Rock for you.\r\nThen go out through the streets and byways,\npreach the word to the many or few.\nSay to every fallen brother,\n"There\'s Honey in the Rock for you".', 'O mein Bruder kennst du schon den Heiland,\nder so freundlich ist und treu?\nEr der Fels des ew\'gen Heiles,\nhat Honig für dich täglich neu.\r\nEs ist Honig in dem Fels, mein Bruder,\nes ist Honig in dem Fels für dich.\nLass das Blut deine Schuld bedecken,\nes ist Honig in dem Fels für dich.\r\nHast\' gefunden du die Gnade Jesu,\nwandelst du in Seinem Licht?\nTrinkst du von der Lebensquelle,\nvom Honig in dem Fels für dich.\r\nBetest gläubig du zu Gott, dem Vater:\nHerr was willst Du dass ich tu\'?\nEr wird ganz gewiss dich führen,\nund Honig in dem Fels find\'st du.\r\nDann geh\' hin zu dem verirrten Bruder,\nder noch ohne Jesus Christ.\nSag ihm, dass noch wahre Freude\nund Honig in dem Felsen ist.'),
(9, '1427', 'O mein Herze brennt in Liebe dir zu sagen  -  I would love to tell you what I think of Jesus   (Niemand sorgt für mich so treu wie Jesus)', 'I would love to tell you what I think of Jesus,\nsince I found in Him a friend so strong and true.\nI would tell you how He changed my life completely,\nHe did something that no other friend could do.\r\nNo one ever cared for me like Jesus.\nThere\'s no other friend so kind as He.\nNo one else could take the sin and darkness from me.\nO how much He cared for me.\r\nAll my life was full of sin when Jesus found me.\nAll my heart was full of misery and woe.\nJesus placed His strong and loving arms around me.\nAnd He led me in the way I ought to go.\r\nEv\'ry day He comes to me with new assurance.\nMore and more I understand His words of love.\nBut I\'ll never know just why He came to save me.\nTill someday I see His blessed face above.', 'O mein Herze brennt in Liebe, dir zu sagen,\nwas mein Jesus für mich ist, seit ich Ihn fand.\nEr ist mir ein Freund in allen Lebenslagen,\nmachte frei mein Leben, das die Sünde band.\r\nNiemand sorgt für mich so treu wie Jesus,\nnie auf Erden war ein Freund wie Er!\nEr allein nur konnte Sünd\' und Nacht mir nehmen,\nja, Er liebt und sorgt so sehr.\r\nTief im Sündensumpf versunken fand mich Jesus,\nals mein Herze lag in Banden und in Weh,\nsanft ergriff mich Seine Hand und stellt\' mich sicher\nauf den festen, g\'raden Weg, den ich nun geh.\r\nJeden Tag beglückt Er mich mit neuer Freude,\nimmer besser darf ich Seine Lieb\' versteh\'n.\nDoch die Größe Seiner mächt\'gen Kreuzesliebe\nbleibt unfassbar mir, bis Ihn mein Aug\' wird seh\'n.'),
(9, '1428', 'O mein Jesus Du bist\'s wert, dass man Dich im Staube ehrt   (Von der Erde reiß mich los)', NULL, 'O, mein Jesus Du bist´s wert,\ndass man Dich im Staube ehrt!\nDass man Dich beständig lobt und ehrt!\nNiemand ist so gut wie Du;\nmeine Seele jauchzt Dir zu,\nmeine Seele jauchzt Dir fröhlich zu!\r\nVon der Erde reiß mich los,\nmache meinen Glauben groß.\nGib mir einen treuen Sinn,\nnimm mich ganz, mein Jesu, hin!\r\nDeine Hand hat mich gemacht,\nwunderbar ans Licht gebracht,\nwunderbar ans helle Licht gebracht.\nUnd Dein Blut hat mich erlöst,\ndass ich ewig sei getröst\'t,\ndass ich nun auf ewig sei getröst\'t.\r\nHuldreich blickest Du mich an,\nsagst mir, dass ich kommen kann,\nsagst mir, dass ich zu dir kommen kann.\nUnd dass Du der Sündenschuld\nnicht gedenkst nach Deiner Huld,\nnicht gedenkst nach Deiner Gnad´ und Huld.'),
(9, '1429', 'O mich ziehts nach jenen Höhen, wo die ewge Liebe thront', NULL, 'O mich zieht\'s nach jenen Höhen,\nwo die ew\'ge Liebe thront,\nwo die Friedenslüfte wehen\nund die Treue wird belohnt.\nLasst mich gehen, lasst mich eilen,\nnach der Heimat will ich hin!\nHier kann ich nicht länger weilen,\nnach der Heimat lasst mich zieh\'n!\r\nAch, nur heim geht mein Verlangen,\nErdenlust hält mich nicht auf,\nan dem Heiland will ich hangen,\nbis vollendet ist mein Lauf.\nO, du süße Freud und Wonne\nin dem schönen Vaterhaus,\nwo die holde Gnadensonne\nsendet ihre Strahlen aus.\r\nSchön\'res kann es doch nichts geben,\nals der Himmel mir verspricht,\nd\'rum zieht\'s mich nach jenem Leben,\nin das Land, wo Ruh\' und Licht.\nSüße Ahnung, sel\'ges Hoffen\nvon der sel\'gen Ewigkeit,\nja, mir ist der Himmel offen,\nschon bereit das weiße Kleid!'),
(9, '1430', 'O nimm mich wie ich bin   (Chorus)', NULL, 'O, nimm mich, wie ich bin!\nO, nimm mich, wie ich bin!\nDu starbst für mich,\nd\'rum komme ich,\no, nimm mich, wie ich bin!'),
(9, '1431', 'O schaue zum Kreuze des Herrn   (O leben, ja leben sollst du)', NULL, 'O schaue zum Kreuze des Herrn:\nEr hängt dort im Blute für dich!\nDie Sünden vergibt er dir gern,\ndie Schuld nahm Er liebreich auf sich.\r\nO leben, ja leben sollst du,\nin Jesu Blut findest du Ruh\',\ndort findest du Ruh\';\no eile zum Kreuze hinzu!\r\nDu bist ja verwundet und krank,\ndie Sünde ist mächtig in dir.\nO warte nun länger nicht mehr,\ndein Arzt, dein Erretter ist hier!\r\nJetzt ist noch die Gnadenzeit da,\ndoch allzu bald ist sie entfloh\'n.\nOh suche die Rettung doch ja,\nnoch findest du Leben im Sohn!\r\nO blicke im Glauben empor:\nAm Kreuz hängt er blutig für dich!\nAch komm, Seele, tritt jetzt hervor\nUnd ruf : "Heiland, hier hast du mich!"'),
(9, '1432', 'O Seele, komm eilend zum Kreuze   (O kommet doch alle zum Kreuze)', NULL, 'O Seele, komm eilend zum Kreuze!\nEs ladet der Heiland dich ein;\nhier fließet der Born Seiner Gnade\nso herrlich für groß und für klein.\r\nO kommet doch alle zum Kreuze,\nzum Kreuze nur eilet hinzu!\nSo gibt euch der Heiland noch heute,\nnoch heute die selige Ruh\'!\r\nO suche Vergebung und Frieden\nbeim Kreuz für dein trauriges Herz!\nDein Jesus beglückt schon hienieden\nund heilet dir jeglichen Schmerz.\r\nO suche Erlösung von Sünden\nam Kreuz durch des Heilandes Blut.\nDa sollst du das volle Heil finden,\ndies köstliche, himmlische Gut.\r\nO selige Hoffnung des Lebens,\nder Herrlichkeit droben beim Herrn!\nWir kommen zum Kreuz nicht vergebens,\nschon schimmert die Krone von fern.'),
(9, '1433', 'O sel\'ge Stunden im Gebet  -  Sweet Hour of Prayer, sweet Hour of Prayer   [Siegesklänge]', 'Sweet hour of prayer, sweet hour of prayer,\nthat calls me from a world of care,\nand bids me at my Father\'s throne,\nmake all my wants and wishes known.\nIn seasons of distress and grief,\nmy soul has often found relief,\nand oft escaped the tempter\'s snare\nBy thy return, sweet hour of prayer.\r\nSweet hour of prayer, sweet hour of prayer,\nthe joy I feel, the bliss I share,\nof those whose anxious spirits burn,\nwith strong desires for Thy return!\nWith such I hasten to the place\nwhere God, my Saviour, shows His face,\nand gladly take my station there,\nand wait for thee, sweet hour of prayer.\r\nSweet hour of prayer, sweet hour of prayer,\nThy wings shall my petition bear,\nto Him whose truth and faithfulness,\nengage the waiting soul to bless.\nAnd since He bids me seek His face,\nbelieve His word and trust His grace,\ni\'ll cast on Him my every care,\nand wait for thee, sweet hour of prayer.', 'O, sel\'ge Stunden im Gebet,\nwo alle Not der Welt vergeht,\nda knie\' ich an des Vaters Thron,\nEr kennt von fern mein Wünschen schon.\nIn tiefem Gram, in Trübsalszeit\nhat für Sein Kind Er Hilf\' bereit.\nEr des Versuchers Plan zerschlägt,\nwenn ich verharre im Gebet.\r\nO, sel\'ge Stunden im Gebet,\nwo Wonne uns und Glück umweht,\nwo unser Geist von Sehnsucht brennt\nund das Verlangen nach Ihm kennt.\nO, lasst uns eilen in Sein Licht,\nwo Er uns zeigt Sein Angesicht,\nund warten fröhlich früh und spät\nund Seiner harren im Gebet.\r\nO, sel\'ge Stunden im Gebet!\nEs dringt zu Ihm, was wir gefleht.\nDes Heilands Güt\' und Freundlichkeit\nden Wartenden Sein Heil verleiht.\nWeil Er mich heißt, auf Ihn zu schau\'n,\nder Gnade und dem Wort zu trau\'n,\nwerf\' ich auf Ihn, was mich bewegt\nund harre Seiner im Gebet.'),
(9, '1434', 'O selig, in Christo verborgen zu sein   (O Jesus, mein Herz ist mit Sehnsucht erfüllt)', NULL, 'O selig, in Christo verborgen zu sein,\nvon Ketten der Sünde befreit.\nZur völligen Ruhe führt Jesus uns ein,\nverschwunden ist Sorge und Leid.\r\nO Jesus, mein Herz ist mit Sehnsucht erfüllt;\nes schaut Dir entgegen die Braut.\nVerkläre mich völlig und ganz in Dein Bild,\nbis jubelnd mein Auge Dich schaut,\nbis jubelnd mein Auge Dich schaut.\r\nO Heiland, Du hast durch Dein Blut mich erkauft,\ndamit ich Dein Eigentum sei.\nDu hast mit dem Heiligen Geist mich getauft,\nDu machest mich glücklich und frei.\r\nD\'rum preise ich, Herr, dieses kostbare Blut,\ndas all meine Schulden bedeckt.\nDa bin ich geborgen in sicherer Hut,\nob Satan auch drohet und schreckt.\r\nO gib Deinen Geist uns mit Kraft und mit Macht,\no gib eine offene Tür.\nLass schwinden die Nebel, lass weichen die Nacht,\nund tritt Du als Sieger herfür.\r\nO siege, Du König, bis alles besiegt,\nrüst\' aus eine siegreiche Schar,\nbis dass alle Welt zu den Füßen Dir liegt\nund bringet Dir Huldigung dar.'),
(9, '1435', 'O tragt die Kunde fort, erzählt\'s von Ort zu Ort  -  O spread the Tidings \'round, wherever Man is found   (Der Heilge Geist ist da)', 'O spread the tidings \'round, wherever man is found,\nwherever human hearts and human woes abound.\nLet ev\'ry Christian tongue proclaim the joyful sound:\nThe Comforter has come!\r\nThe Comforter has come, the Comforter has come!\nThe Holy Ghost from heav\'n, the Father\'s promise giv\'n.\nO spread the tidings \'round, wherever man is found;\nThe Comforter has come!\r\nThe long, long night is past, the morning breaks at last,\nand hushed the dreadful wail and fury of the blast.\nAs o\'er the golden hills the day advances fast:\nThe Comforter has come!\r\nLo, the great King of kings, with healing in His wings,\nto ev\'ry captive soul a full deliverance brings.\nAnd through the vacant cells the song of triumph rings:\nThe Comforter has come!\r\nO boundless love divine! How shall this tongue of mine,\nto wond\'ring mortals tell the matchless grace divine.\nThat I, a child of hell, should in His image shine:\nThe Comforter has come!', 'O tragt die Kunde fort, erzählt\'s von Ort zu Ort,\nwo noch ein Menschenherz in Sünde seufzt und Schmerz.\nEs soll die Jüngerschar die Wahrheit machen klar:\nDer Heil\'ge Geist ist da!\r\nDer Heil\'ge Geist ist da! Der Heil\'ge Geist ist da!\nVom Himmel kam Er her, des Vates Gab\' ist Er.\nO tragt die Kunde fort, erzählt\'s von Ort zu Ort:\nDer Heil\'ge Geist ist da!\r\nDie lange Nacht ist hin, der neue Tag erschien,\nvorbei ist alle Not, es leuchtet Morgenrot.\nauf Erden wird es licht, die Gnadenzeit anbricht:\nDer Heil\'ge Geist ist da.\r\nO seht, des Königs Macht hat Heilung uns gebracht,\nGefang\'ne sollen\'s seh\'n, Befreiung ist gescheh\'n.\nUnd durch die Lande rings das Siegeslied erklingt:\nDer Heil\'ge Geist ist da!\r\nO Liebe, heilig, frei, dass ich Dein Zeuge sei,\ndie Gnad\' ich rühmen kann, die mich für Dich gewann.\nDie mich aus Sünd\' und Not bis an Dein Herz erhob:\nDer Heil\'ge Geist ist da!'),
(9, '1436', 'O welch ein Tag so groß und frei  -  Oh, happy Day, that fixed my Choice   (O welch ein Tag, herrlicher Tag)', 'Oh, happy day, that fixed my choice,\non Thee, my Saviour and my God!\nWell may this glowing heart rejoice,\nand tell its raptures all abroad.\r\nHappy day, happy day,\nwhen Jesus washed my sins away!\nHe taught me how to watch and pray,\nand live rejoicing every day\nHappy day, happy day,\nwhen Jesus washed my sins away.\r\nOh, happy bond, that seals my vows,\nto Him who merits all my love!\nLet cheerful anthems fill His house,\nwhile to that sacred shrine I move.\r\n\'Tis done, the great transaction\'s done.\nI am my Lord\'s, and He is mine.\nHe drew me, and I followed on,\ncharmed to confess the voice divine.\r\n', 'O welch ein Tag so groß und frei\nals Jesus macht mein Leben neu.\nDie große Freude die ich hab,\nist, dass Er mir die Schuld vergab.\r\nO welch ein Tag, herrlicher Tag,\nals Jesus wusch die Sünd\' mir ab!\nFrei und erlöst, glücklich bin ich,\nall meine Schuld nahm Er auf sich.\nO welch ein Tag, herrlicher Tag,\nals Jesus wusch die Sünd\' mir ab!\r\nSeit Jesus macht mein Leben heil,\nnehm\' ich an Seiner Freude teil.\nEr macht mich froh, o welches Glück,\nich möchte niemals mehr zurück!\r\nNun will ich stets ruhen in Ihm,\nrichten den Blick auf Jesus hin.\nO lass mich niemals von Dir geh\'n,\nall\'zeit auf Deiner Seite steh\'n.\r\nO welche Gnad\', die Er uns gab,\nElia kam zu uns herab,\nbrachte zurück das reine Wort,\nwelches uns bringt zur Heimat dort.'),
(9, '1437', 'O welch eine süße Melodie  -  There\'s within my Heart a Melody   (Jesus, Jesus, Jesus, schönster Name mein)', 'There\'s within my heart a melody;\nJesus whispers sweet and low,\n"Fear not, I am with you, peace, be still,"\nin all of life\'s ebb and flow.\r\nJesus, Jesus, Jesus,\nsweetest name I know,\nfills my every longing,\nkeeps me singing as I go.\r\nAll my life was wrecked by sin and strife,\ndiscord filled my heart with pain.\nJesus swept across the broken strings,\nstirred the slumbering chords again.\r\nThough sometimes He leads through waters deep,\ntrials fall across the way.\nThough sometimes the path seems rough and steep,\nsee His footprints all the way.\r\nFeasting on the riches of His grace,\nresting \'neath His sheltering wing,\nalways looking on His smiling face,\nthat is why I shout and sing.\r\nSoon He\'s coming back to welcome me\nfar beyond the starry sky.\nI shall wing my flight to worlds unknown,\nI shall reign with Him on high.', 'O, welch eine süße Melodie\nlegte Jesus mir ins Herz!\nFürchte dich nicht, Ich bin stets bei dir\nin des Lebens Freud\' und Schmerz.\r\nJesus, Jesus, Jesus,\nschönster Name mein,\nstillst all mein Verlangen,\nfüllst mein Herz mit Sonnenschein!\r\nEinst war es die Sünde,\ndie ins Herz brachte Missklang mir und Not.\nDoch mein Heiland heilte meinen Schmerz,\nschenkte mir ein Lied von Gott.\r\nGeht mein Weg durch tiefe Wasser auch,\nscheint er dornenvoll und steil.\nDarf ich doch dem Heiland froh vertrau\'n,\nSeine Führung ist mein Heil.\r\nFreudig darf ich ruh\'n in Seiner Gnad\',\nfinde bei Ihm Schutz und Halt,\nschau\' allzeit Sein freundlich Angesicht,\njauchzend drum mein Lied erschallt.\r\nBald kommt Jesus wieder\nund wird mich grüßen in der Herrlichkeit!\nFreudig darf ich Ihm entgegengeh\'n,\nwerde bei Ihm sein all\'zeit.'),
(9, '1438', 'O welch Gnade dass Jesus mein König mich erlöst hat von Sünde und Pein   (Welche Gnad, tiefe Gnad)', NULL, 'O welch Gnade, dass Jesus, mein König,\nmich erlöst hat von Sünde und Pein.\nO welch Gnade, nun darf ich für ewig\nin Ihm ruh\'n und Sein Eigentum sein.\r\nWelche Gnad\', tiefe Gnad\',\ndass mein Jesus mir das Heil erworben hat,\nwelche Gnad\', tiefe Gnad\',\newig währet diese wunderbare Gnad\'.\r\nDiese Welt kann mich nicht mehr betören\nmit Vergnügen und lockendem Schein.\nWelche Gnad\', ich darf Jesus gehören,\nEr ist mein und ich weiß, ich bin Sein.\r\nJesus tauft mich mit Geist und mit Feuer,\ndass ich siegreich im Kampf kann besteh\'n.\nGottes Wort, das mir lieb ist und teuer,\nweist den Weg mir zu himmlischen Höh\'n.\r\nHab den Lauf ich vollendet auf Erden,\nleuchtet Er mir durchs finstere Tal,\ndarf im Himmel die Krone dann erben\nund erscheinen dort zum Hochzeitsmahl.'),
(9, '1439', 'O welch selge Lust trag ich in der Brust  -  What a Fellowship, what a Joy divine   (Ruhend, ruhend, quälender Angst und Sorge fern)   [Westertimke]', 'What a fellowship, what a joy divine,\nLeaning on the everlasting arms;\nWhat a blessedness, what a peace is mine,\nLeaning on the everlasting arms.\r\nLeaning, leaning,\nSafe and secure from all alarms;\nLeaning, leaning,\nLeaning on the everlasting arms.\r\nOh, how sweet to walk in this pilgrim way,\nLeaning on the everlasting arms;\nOh, how bright the path grows from day to day,\nLeaning on the everlasting arms.\r\nWhat have I to dread, what have I to fear,\nLeaning on the Everlasting Arms!\nI have peace complete with my Lord so near,\nLeaning on the Everlasting Arms!\r\n', 'O welch\' sel\'ge Lust trag\' ich in der Brust,\nruhend in den Armen meines Herrn!\nAller Sündenschmerz floh mein banges Herz,\nruhend in den Armen meines Herrn!\r\nRuhend, ruhend,\nquälender Angst und Sorge fern.\nRuhend, ruhend,\nruhend in den Armen meines Herrn.\r\nAuf der schmalen Bahn geht es himmelan,\nruhend in den Armen meines Herrn!\nLicht ist nun mein Pfad bis zur goldnen Stadt,\nruhend in den Armen meines Herrn!\r\nOb Gefahr auch droht, hat\'s doch keine Not,\nruhend in den Armen meines Herrn!\n"Jesus, treuer Hort!" sei mein Losungswort,\nruhend in den Armen meines Herrn!\r\nBricht die Nacht herein, bin ich nicht allein,\nruhend in den Armen meines Herrn.\nBebt mein schwacher Mut,\ntrau ich auf sein Blut,\nruhend in den Armen meines Herrn.'),
(9, '1440', 'O welch Wunder hat Gott in mir gnädig vollbracht  -  What a wonderful Change in my Life   (Seit Jesus im Herzen mir wohnt)   [Pfingstjubel]', 'What a wonderful change in my life has been wrought,\nsince Jesus came into my heart!\nI have light in my soul for which long I had sought,\nsince Jesus came into my heart!\r\nSince Jesus came into my heart,\nsince Jesus came into my heart,\nfloods of joy o\'er my soul like the sea billows roll,\nsince Jesus came into my heart.\r\nI have ceased from my wand’ring and going astray,\nsince Jesus came into my heart.\nAnd my sins which were many are all washed away,\nsince Jesus came into my heart.\r\nI’m possessed of a hope that is steadfast and sure,\nsince Jesus came into my heart.\nAnd no dark clouds of doubt now my pathway obscure,\nsince Jesus came into my heart.\r\nThere’s a light in the valley of death now for me,\nsince Jesus came into my heart.\nAnd the gates of the City beyond I can see,\nsince Jesus came into my heart.\r\nI shall go there to dwell in that City I know,\nsince Jesus came into my heart.\nAnd I’m happy, so happy as onward I go,\nsince Jesus came into my heart.', 'O welch Wunder hat Gott in mir gnädig vollbracht,\nseit Jesus im Herzen mir wohnt!\nAlles Sehnen gestillt, und vorbei ist die Nacht,\nseit Jesus im Herzen mir wohnt!\r\nSeit Jesus im Herzen mir wohnt,\nseit Jesus im Herzen mir wohnt,\nhab ich Frieden und Freud,\no welch seliges Heut\',\nseit Jesus im Herzen mir wohnt!\r\nAuf dem Felsen des Heil\'s meine Seele nun ruht,\nseit Jesus im Herzen mit wohnt;\nalle Schuld ist bedeckt durch das heilige Blut,\nseit Jesus im Herzen mir wohnt!\r\nNach dem Tag seiner Zukunft schau freudig ich aus,\nseit Jesus im Herzen mir wohnt,\nbin ein Fremdling hier unten und droben zu Haus,\nseit Jesus im Herzen mir wohnt!\r\nSelbst die Schatten des Todes, sie schrecken mich nicht,\nseit Jesus im Herzen mir wohnt.\nO Jerusalem droben, wie glänzet dein Licht,\nseit Jesus im Herzen mir wohnt!\r\nUnd den Streiter erwartet die himmlische Kron,\nseit Jesus im Herzen mir wohnt,\nnach der Pilgerschaft droben ein ewiger Lohn,\nseit Jesus im Herzen mir wohnt!'),
(9, '1441', 'O wende dich zu Jesus hin, zu Ihm, zu Ihm allein', NULL, 'O wende dich zu Jesus hin,\nzu Ihm, zu Ihm allein!\nDann bringt dein Leben dir Gewinn,\nund du wirst glücklich sein.\r\nAch, hänge an die Welt dich nicht,\nnoch keinem gab sie Glück;\nzu Jesus kehr dein Angesicht\nund blicke nie zurück!\r\nDu kannst ja niemals glücklich sein,\nbleibst du dem Heiland fern.\nO Herz, geh doch zum Frieden ein,\nnimm Jesus als den Herrn!\r\nWohl singt die Welt von Glück und Glanz,\nvon Reichtum, Ehre, Pracht.\nWas hilft\'s? Es wird der Totenkranz\ngar bald für dich gemacht.\r\nDann hast du hier umsonst gelebt,\nverloren war die Zeit,\ndu hast nach falschem Glück gestrebt\nfür alle Ewigkeit.\r\nUnd wenn die Sterbestunde schlägt,\nso ist dein Glück ein Spott,\ndenn keiner von den Engeln trägt\ndich hin zu deinem Gott\r\nDann ist dein Sterben kein Gewinn,\nes bringt dir ew’ge Pein!\nD\'rum wende dich zu Jesus hin,\nzu Ihm, zu Ihm allein!'),
(9, '1442', 'O wenn dich dürstet, komme, trink von der Lebensflut   (Komm nur zur Quelle, sie fließet dir zugut)', NULL, 'O wenn dich dürstet, komme,\ntrink von der Lebensflut!\nWo du auch sonst getrunken hast,\nnichts stillte des Durstes Glut.\nWo du auch sonst getrunken hast,\nnichts stillte des Durstes Glut.\r\nKomm nur zur Quelle!\nSie fließet dir zugut.\nKomm, trink nur, so gibt dir Jesus\nKraft und Glaubensmut.\r\nAm Quell hat sich gelabet\nschon mancher Wandersmann.\nWelch sel\'ger Trost: Der Born vom Kreuz\nmir niemals versiegen kann!\nWelch sel\'ger Trost: Der Born vom Kreuz\nmir niemals versiegen kann!\r\nTrink immer wieder, Seele,\ndass deine Kraft sich mehrt!\nDu schwingst mit Macht dann in dem Kampf\ndes Glaubens das Geistesschwert.\nDu schwingst mit Macht dann in dem Kampf\ndes Glaubens das Geistesschwert.\r\nWenn dann dein Lauf vollendet,\ndie Ruhe winket süß,\nwirst trinken du vom Lebensborn\nbei Gott in dem Paradies!\nWirst trinken du vom Lebensborn\nbei Gott in dem Paradies.'),
(9, '1443', 'O wenn die Heilgen einmarschiern  -  O when the saints go marching in', 'Oh, when the saints go marching in,\noh, when the saints go marching in,\ndear Lord, I want to be in that number,\nwhen the saints go marching in.\r\nAnd when the book is opened now,\nand when the book is opened now,\ndear Lord, I want to be in that number,\nwhen the saints go marching in\r\nAnd when the world becomes new again,\nand when the world becomes new again,\ndear Lord, I want to be in that number,\nwhen the saints go marching in.\r\nAnd when you sing: "Halleluja!",\nand when you sing, "Halleluja!",\ndear Lord, I want to be in that number,\nwhen the saints go marching in.\r\nOh when they crown Him Lord of all,\noh when they crown Him Lord of all,\ndear Lord, I want to be in that number,\nwhen they crown Him Lord of all.', 'O wenn die Heil\'gen einmarschier\'n,\nja wenn die Heil\'gen einmarschier\'n,\no dann lass mich auch dabei sein,\nwenn die Heil\'gen einmarschier\'n.\r\nUnd wenn das Buch geöffnet wird,\nund wenn das Buch geöffnet wird,\nja dann lass mich auch dabei sein,\nwenn das Buch geöffnet wird.\r\nUnd wenn die Welt wird wieder neu,\nund wenn die Welt wird wieder neu,\nja dann lass mich auch dabei sein,\nwenn die Welt wird wieder neu.\r\nUnd wenn man singt: "Hallelujah!",\nund wenn man singt: "Hallelujah!",\nja dann lass mich auch dabei sein,\nwenn man singt: "Hallelujah!".\r\nUnd wenn der Herr wird dann gekrönt,\nund wenn der Herr wird dann gekrönt,\nja dann lass mich auch dabei sein,\nwenn der Herr wird dann gekrönt.'),
(9, '1444', 'O wie ernst und wie so wichtig ist doch diese letzte Zeit   (Ja, der Heiland wird bald kommen)', NULL, 'O wie ernst und wie so wichtig ist doch diese letzte Zeit,\nda die Völker, tief im Schlafe, jagen nach der Eitelkeit.\nSeht, schon geht der Tag zu Ende und die Abendzeit ist da;\nder Herr wird bald erscheinen mit der hei\'gen Engelschar.\r\nJa, der Heiland wird bald kommen, ja, der Heiland wird bald kommen,\nkommen mit den Engeln in des Vaters großer Herrlichkeit.\nUnd dann werden alle Frommen, und dann werden alle Frommen\nbei dem Herrn sein allezeit, bei dem Herrn sein allezeit.\r\nWährend wir in Zion stehen auf der Wahrheit ew\'gem Grund,\nwird zerstört das große Babel, wie\'s gesagt aus Gottes Mund.\nHeil\'ge Boten laut verkünden, heben hoch des Herrn Panier:\n"Der Heiland kommt bald wieder, ja, Er ist schon vor der Tür!"\r\nBald wird kommen unser König von dem hehren Himmelsthron,\num zu richten alle Völker, gebend jedem seinen Lohn.\nAllen Heil\'gen der getreue Richter dann die Krone gibt.\nO, alle Ehre unserm Heiland, der uns so geliebt!'),
(9, '1445', 'O wie herrlich ist die Kunde  -  Oh, how sweet the glorious Message   (Gestern, heute und für immer)   [Siegesklänge]', 'Oh, how sweet the glorious message simple faith may claim,\nYesterday, today, forever, Jesus is the same.\nStill He loves to save the sinful, heal the sick and lame,\ncheer the mourner, still the tempest glory to His name!\r\nYesterday, today, forever, Jesus is the same,\nall may change, but Jesus never glory to His name!\nGlory to His name! Glory to His name!\nAll may change, but Jesus never glory to His name!\r\nHe who pardoned erring Peter, never need\'st thou fear;\nHe that came to faithless Thomas, all thy doubt will clear.\nHe who let the loved disciple on His bosom rest,\nbids thee still, with love as tender, lean upon His breast.\r\n(He who once walked on rough waves on the sea,\ncan still temptation today, as in Galilee.\nHe who wrestled bleeding and wept in Gethsemane,\nDrinks with us the cup of sorrow, will never leave us.)\r\nAs of old He walked to Emmaus with them to abide;\nso through all life\'s way He walketh, ever near our side.\nSoon again we shall behold Him, hasten, Lord, the day!\nBut \'twill still be "this same Jesus", as He went away.', 'Oh wie herrlich ist die Kunde, nimm sie gläubig an:\nGestern, heute und für immer Jesus helfen kann.\nJa, Er liebt und rettet Sünder, heilt die Kranken gern.\nTrocknet Tränen, stillt die Stürme - Ehre sei dem Herrn!\r\nGestern, heute und für immer, bleibt unwandelbar\nJesus Christus stets derselbe, der Er ewig war;\nEhre sei dem Herrn! Ehre sei dem Herrn!\nAlles wechselt, Jesus nimmer - Ehre sei dem Herrn!\r\nDer dem Petrus hat vergeben, spricht:" O fürcht\' dich nicht!"\nDer dem Thomas nahm die Zweifel, hilft auch dir zum Licht.\nWie Er seinen Jüngern gab an Seinem Herzen Ruh\',\nruft Er jetzt mit zarter Liebe: "Komm auch du herzu!"\r\nEr, der über rauhe Wellen ging einst auf dem Meer,\nkann auch heut\' Versuchung stillen wie in Galilä\'.\nEr, der blutend rang und weinte in Gethsemane,\ntrinkt mit uns den Kelch der Trübsal, wird nie von uns geh\'n.\r\nWie nach Emmaus Er walte, teilte aus das Brot,\nkennt Er auf des Lebens Straßen alle uns\'re Not.\nDoch bald sehen wir Ihn wieder; Herr, den Tag uns bring\'!\nUnd es ist derselbe Jesus, der einst von uns ging.'),
(9, '1446', 'O wie ist mein Herz voll Lob und Dank, wenn ich an Seine Liebe denke', NULL, 'O wie ist mein Herz voll Lob und Dank,\nwenn ich an Seine Liebe denke.\nAlle meine Sünden trug Er ja,\nans Kreuz von Golgatha.\nEr ist nun ein Hoherpriester mir,\nbleibt mein Helfer für und für.\nO wie ist mein Herz voll Lob und Dank,\nich singe, Jesus, Dir.'),
(9, '1447', 'O wie kostbar ist die Kunde, die mein Herz erfüllt', NULL, 'O wie kostbar ist die Kunde, die mein Herz erfüllt,\ndie im Wechsel jeder Stunde all mein Sehnen stillt:\nGestern, heute und für immer bleibt unwandelbar\nJesus Christus stets derselbe, der Er ewig war!\nWer kann dies Geheimnis fassen, das doch Wahrheit ist?\nHeute noch auf unsern Straßen wandelt Jesus Christ,\nwandelt Jesus Christ, wandelt Jesus Christ!\nHeute noch auf unsern Straßen wandelt Jesus Christ.\r\nWie die silberhelle Quelle unerschöpflich fließt,\nwie im Meere Well\' auf Welle unabsehbar ist,\nso ergießt sich Gottes Fülle ewig durch den Sohn\nals ein mächt\'ger Strom des Lebens von des Höchsten Thron.\nKannst du dies Geheimnis fassen, das doch Wahrheit ist,\ndass der Strom der goldenen Gassen dir zu Füßen fließt,\ndir zu Füßen fließt, dir zu Füßen fließt,\ndass der Strom der goldnen Gassen dir zu Füßen fließt?\r\nWie im lichten Strahl die Sonne aller Welt sich schenkt\nund mit einem Strom der Wonne ihre Kinder tränkt,\nalso gibt sich Jesu Liebe frei im jedes Herz,\nweckt des ew\'gen Frühlings Triebe, heilt der Sünde Schmerz.\nHast du diesen Schatz gefunden, sag es weiter fort:\nJesus dringt durch alle Stunden, wohnt an jedem Ort.\nSag es weiter fort, sag es weiter fort.\nJesus dringt durch alle Stunden, wohnt an jedem Ort.\r\nGottes Stimme, die vor Zeiten uns das Heil verhieß,\nals sich Adam ließ verleiten einst im Paradies,\ndiese Stimme tönt noch immer durch die Zeiten fort,\nlockt so innig, schweiget nimmer, ruft an jedem Ort.\nJa, die ew\'ge Weisheit ladet alle zu sich ein.\nWer in diesem Quell sich badet, wird gesund und rein,\nwird gesund und rein, wird gesund und rein.\nJa, die ew\'ge Weisheit ladet alle zu sich ein.\r\nSage an, kennst du die Stätte, wo der König wohnt,\nwo Er gerne mit dir red\'te, wo Er ewig thront?\nSeele, suche nicht im Fernen, was dir liegt so nah,\nnicht erst über jenen Sternen! Er ist ja schon da!\nNur die Einfalt kann es fassen, die sich selbst vergisst.\nAuf des Herzens stillen Straßen wandelt Jesus Christ,\nwandelt Jesus Christ, wandelt Jesus Christ.\nWer Ihn dort will ganz umfassen, alles sonst vergisst.'),
(9, '1448', 'O wie köstlich ist\'s zu wissen, Jesus Christus Er ist mein   (Nah bei Jesus, nah bei Jesus, Himmelsluft uns da umweht)', NULL, 'O wie köstlich ist\'s zu wissen:\nJesus Christus, Er ist mein.\nDer den Schuldbrief hat zerrissen,\nsoll mein ein und alles sein!\r\nNah bei Jesus, nah bei Jesus,\nHimmelsluft uns da umweht,\nwenn vor Seinem Angesichte\nstill wir harren im Gebet.\r\nNäher an Dein Heilandsherze,\nsei die Losung Tag für Tag;\nvölliger Dir hingegeben,\nob auch komme, was da mag.\r\nO, Du mein geliebter Heiland\nmach vom eignen Ich mich frei,\ndass mein Wirken und mein Streben\nDeines Lebens Abglanz sei.'),
(9, '1449', 'O wie süß die teure Botschaft  -  Oh, how sweet the glorious Message   (Gestern, heute und für immer)   [Westertimke]', 'Oh, how sweet the glorious message, simple faith may claim;\nYesterday, today, forever, Jesus is the same.\nStill He loves to save the sinful, heal the sick and lame;\nCheer the mourner, still the tempest. Glory to His name!\r\nYesterday, today, forever, Jesus is the same,\nall may change, but Jesus never! Glory to His name,\nGlory to His name, Glory to his name;\nAll may change but Jesus never! Glory to His name.\r\nHe who was the friend of sinners seeks the lost one now;\nSinner, come, and at His footstool penitently bow.\nHe who said, “I’ll not condemn thee, go and sin no more,”\nspeaks to thee that word of pardon as in days of yore.\r\nOft on earth He healed the suff’rer by His mighty hand.\nStill our sicknesses and sorrows go at His command.\nHe who gave His healing virtue to a woman’s touch,\nto the faith that claims His fullness still will give as much.\r\n\r\nHe who pardoned erring Peter, never need\'st thou fear;\nHe that came to faithless Thomas, all thy doubt will clear.\nHe who let the loved disciple on His bosom rest,\nbids thee still, with love as tender, lean upon His breast.\r\nAs of old He walked to Emmaus with them to abide;\nso through all life\'s way He walketh, ever near our side.\nSoon again we shall behold Him, hasten, Lord, the day!\nBut \'twill still be "this same Jesus", as He went away.\r\nHe who \'mid the raging billows, walked upon the sea;\nstill can hush our wildest tempest, as on Galilee.\nHe who wept and prayed in anguish, in Gethsemane,\ndrinks with us each cup of trembling, in our agony.', 'O wie süß die teure Botschaft dem, der glauben kann,\ngestern, heute und für immer, gleich bleibt Gottes Lamm.\nHeut\' noch rettet er den Sünder, heilt die Kranken gern;\nstärkt, die traurig, stillt die Stürme. Ehre sei dem Herrn!\r\nGestern, heute und für immer  gleich bleibt Gottes Lamm!\nAlles wechselt, Jesus nimmer! Ehre sei dem Herrn.\nEhre sei dem Herrn. Ehre sei dem Herrn.\nAlles wechselt, Jesus nimmer! Ehre sei dem Herrn.\r\nEr der einst der Freund der Sünder, heute sucht Er dich;\nSünder fall\' zu seinen Füßen, büßend beug\' dein ich.\nEr sprach einst: "Ich nicht verdamme, sündige nicht mehr."\nEr vergibt dir deine Sünde, heut\' wie stets vorher.\r\nOft auf Erden heilt Er Kranke mit allmächt\'ger Hand.\nHeut\' noch weichen Sorg\' und Krankheit, Er ist\'s der sie bannt.\nEr, der jene Kranke heilte, die nur streift\' Sein Kleid,\ndem der gläubig Ihm vertrauet, schenkt Er Sich noch heut\'.\r\nWie vor alters bei den Jüngern kehrt Er heute ein;\nwandelt mit uns, wo wir gehen, lässt uns nie allein.\nBald wird unser Aug\' Ihn schauen, den, der für uns starb!\nHeute noch derselbe Jesus, der uns Heil erwarb.\r\nDer dem Petrus hat vergeben, spricht:" O fürcht\' dich nicht!"\nDer dem Thomas nahm die Zweifel, hilft auch dir zum Licht.\nWie Er seinen Jüngern gab an Seinem Herzen Ruh\',\nruft Er jetzt mit zarter Liebe: "Komm auch du herzu!"\r\nWie nach Emmaus Er walte, teilte aus das Brot,\nkennt Er auf des Lebens Straßen alle uns\'re Not.\nDoch bald sehen wir Ihn wieder; Herr, den Tag uns bring\'!\nUnd es ist derselbe Jesus, der einst von uns ging.\r\n'),
(9, '1450', 'O wie wunderbar ist Jesu Blut   (Chorus)', NULL, 'O wie wunderbar ist Jesu Blut,\no wunderbar ist Jesu Blut!\nDie himmlische Macht brach\nentzwei des Bösen Kraft,\nO wie wunderbar ist Jesu Blut!'),
(9, '1451', 'O wo sind die Schnitter im Erntefeld  -  O where are the Reapers that garner in   (Wo sind die Schnitter? O, wer hilft mit?)', 'O where are the reapers that garner in\nthe sheaves of the good from the fields of sin?\nWith sickles of truth must the work be done,\nand no one may rest till the "harvest home."\r\nWhere are the reapers? O who will come\nand share in the glory of the "harvest home"?\nO, who will help us to garner in\nthe sheaves of good from the fields of sin?\r\nGo out in the highways and search them all,\nthe wheat may be there, though the weeds are tall.\nThen search in the highway, and pass none by,\nbather from all for the home on high.\r\nThe fields all are rip\'ning, and far and wide\nthe world now is waiting the harvest tide.\nBut reapers are few, and the work is great,\nand much will be lost should the harvest wait.\r\nSo come with your sickles, ye sons of men,\nand gather together the golden grain.\nToil on till the Lord of the harvest come,\nthen share ye his joy in the "harvest home."', 'O wo sind die Schnitter im Erntefeld?\nWer sammelt die Garben dem Herrn der Welt?\nDie Wahrheit soll unsere Sichel sein,\nund keiner darf ruh\'n. Holt die Graben ein!\r\nWo sind die Schnitter? O, wer hilft mit?\nWer jubelt im Fest und singt das Erntelied?\nWer steht im Dienste des Herrn der Welt\nUnd sammelt Graben im Erntefeld?\r\nAn Hecken und Zäunen recht sorgsam geht,\nim üppigen Unkraut oft Weizen steht.\nAuf, schneidet mit Fleiß d\'rum und sammelt ein,\ndenn voll muss die Scheuer des Meisters sein.\r\nDer Weizen ist reif und zur Ernt\' bereit;\nes harret das Feld; es ist Erntezeit,\ndoch wenige nur an die Arbeit geh\'n,\ndie Schnitter vereinzelt im Felde steh\'n.\r\nD\'rum schwinget die Sichel nur früh und spat\nund sammelt dem Herrn seine goldne Saat.\nEinst ziehen wir heim, von der Arbeit müd\',\ndann singen wir jubelnd das Erntelied.'),
(9, '1452', 'O wunderbar süß ist die Botschaft  -  O wonderful Words of the Gospel   (O glaub es und trau Seiner Gnade)', 'Oh wonderful words of the gospel,\noh wonderful message they bring.\nProclaiming a blessed redemption\nThro’ Jesus our Saviour and king.\r\nBelieve, oh, believe in His mercy,\nthat flows like a fountain so free.\nBelieve, and receive the redemption,\nHe offers to you and to me.\r\nHe came from the throne of His glory,\nand left the bright mansions above.\nThe world to redeem from its bondage,\nso great His compassion and love.\r\nOh come to this wonderful Saviour,\ncome weary and sorrow-oppressed.\nBehold on the cross how He suffered,\nthat you in His kingdom might rest.\r\nThere’s no other refuge but Jesus,\nno shelter where lost ones may fly.\nAnd now, while He’s tenderly calling:\nOh “turn ye,” “for why will ye die?”', 'O wunderbar süß ist die Botschaft!\nSo traut und so herzlich sie klingt;\nverkündigt die ew\'ge Erlösung,\ndie Jesus, der Heiland, uns bringt.\r\nO glaub es und trau Seiner Gnade!\nSie fließt wie ein Strom auch für dich.\nO glaub\'s uns nimm an die Erlösung;\nsie gilt ja für dich und für mich.\r\nEr stieg von dem himmlischen Throne,\nverließ Seine Heimat voll Pracht,\nzu brechen die Fesseln der Knechtschaft,\nzu bringen das Licht in die Nacht.\r\nO komm zu dem mächtigen Heiland!\nMühselig, beladen, komm her!\nSieh, wie Er am Kreuze gelitten;\nvertrau Ihm und zweifle nicht mehr.\r\nKein andrer als Jesus kann helfen;\nes gibt ja kein anderes Heil.\nNoch steht Er geduldig und wartet;\no komm und empfange dein Teil!'),
(9, '1453', 'O, das Blut, Gnadenflut, Er hat schon bezahlt  -  O the Blood, Crimson love, Price of Life\'s Demand   (O das Blut des Lammes reinigt mich / O the Blood of Jesus washes me)', 'O the blood, crimson love,\nprice of life\'s demand.\nShameful sin, placed on Him,\nthe Hope of every man.\r\nO the blood of Jesus washes me,\no the blood of Jesus shed for me.\nWhat a sacrifice, that saved my life,\nyes, the blood it is my victory.\r\nSavior Son, Holy One,\nslain so I can live.\nSee the Lamb, the great I Am,\nwho takes away my sin.\r\nO the blood of the Lamb,\no the blood of the Lamb,\no the blood of the Lamb,\nthe precious blood of the Lamb.\nWhat a sacrifice, that saved my life,\nyes, the blood it is my victory.\r\nO what love, no greater love,\ngrace, how can it be.\nThat in my sin yes, even then,\nHe shed His blood for me.\r\nO the blood of Jesus washes me,\no the blood of Jesus shed for me.\nWhat a sacrifice, that saved my life,\nyes, the blood it is my victory.\r\nWhat can wash away my sin?\nNothing but the blood of Jesus.', 'O, das Blut, Gnadenflut,\nEr hat schon bezahlt.\nNahm für mich die Schuld auf sich,\ndie Hoffnung für die Welt.\r\nO das Blut des Lammes reinigt mich,\no das Blut des Lammes floss für mich.\nWelch ein Opfer das mir Leben gab,\nja das Blut, es wurde mir zum Sieg.\r\nGottes Sohn, Gnadenthron,\nstarb, damit ich leb\'.\nSeht das Lamm auf dem Thron,\ndas alle Schuld mir nahm.\r\nO welch kostbares Blut,\no welch kostbares Blut,\no welch kostbares Blut,\no welch kostbares Blut.\nWelch ein Opfer das mir Leben gab.\nJa, das Blut, es wurde mir zum Sieg!\r\nLiebe, die nie größer war,\nzeigt, was Gnade heißt.\nIn tiefer Schuld, dem Tode nah\',\nda spricht Sein Blut mich frei!\r\nO das Blut des Lammes reinigt mich,\no das Blut des Lammes floss für mich.\nWelch ein Opfer das mir Leben gab,\nja das Blut, es wurde mir zum Sieg.\r\nWas wäscht mich von Sünden rein?\nNur das Blut des Lammes Jesus!'),
(9, '1454', 'O, das teure Blut, das Jesus einst am Kreuz vergoss   (Ja, das teure Blut des Heilands fließet heut noch frei)', NULL, 'O, das teure Blut, das Jesus\neinst am Kreuz vergoss,\nmacht von allen Satansbanden\nfrei und los.\r\nJa, das teure Blut des Heilands\nfließet heut\' noch frei,\nmacht, wohin es sich ergießet,\nalles neu.\r\nSieh, das Blut des Sohnes Gottes\nlöst von jedem Bann,\nund auch du darfst es erfahren,\nwas es kann.\r\nSind die Sünden hoch wie Berge,\nmeerestief ihr Weh,\nJesu Blut wäscht jeden Flecken\nweiß wie Schnee.\r\nTeures Blut, das uns erlöste,\nunsrer Seele Preis,\nschaffest, dass ich mich errettet,\nsicher weiß.\r\nIn das Heiligtum des Höchsten\ntreten frei wir ein,\ndenn das Blut des Gotteslammes\nmacht uns rein.'),
(9, '1455', 'O, die Macht von Golgatha ist immer, immer Sieger   (Chorus)', NULL, 'O, die Macht von Golgatha\nist immer, immer Sieger.\nO, die Macht von Golgatha,\nnichts kann ihr widersteh\'n.'),
(9, '1456', 'O, gebt Jesus Ehre   (4 Chorusse)', NULL, 'O, gebt Jesus Ehre,\no, gebt Jesus Ehre,\nder uns mit Seinem Blut erkauft,\no, gebt dem Heiland Ehre!\r\nO, gebt Jesus Ehre,\no, gebt Jesus Ehre,\nder uns mit Geist und Feuer tauft,\no, gebt dem Heiland Ehre!\r\nO, gebt Jesus Ehre,\no, gebt Jesus Ehre,\nbei Ihm ist Leiden Herrlichkeit,\no, gebt dem Heiland Ehre!\r\nO, gebt Jesus Ehre,\no, gebt Jesus Ehre,\ngeht glaubend\ndurch die finst\'re Nacht,\no, gebt dem Heiland Ehre!'),
(9, '1457', 'O, Herr, gieß\' aus, aus, aus  -  It\'s coming down, down, down', 'It\'s coming down, down, down,\nit\'s coming down, down, down.\nAnd the Spirit of the Lord,\nis coming down.\nWhen the saints began to pray,\nfor the Lord to have His way,\nthen the glory of the Lord,\nis coming down.', 'O, Herr, gieß\' aus, aus, aus!\nO, Herr, gieß\' aus, aus, aus!\nUnd der Heil\'ge Geist des Herrn,\nEr fließt herab.\nWenn die Heil\'gen ernstlich fleh\'n,\nwird noch Mächtiges gescheh\'n\nund der Heil\'ge Geist des Herrn,\nEr fließt herab.'),
(9, '1458', 'O, herrlich ist das Leben, Gott hat mir vergeben   (Wunderbar mit Jesus zu gehen)', NULL, 'O, herrlich ist das Leben, Gott hat mir vergeben.\nEr hat mich erlöst aus der Vergangenheit.\nJeder soll es wissen, Er hat mich befreit,\nhell ist meine Zukunft allezeit.\r\nWunderbar mit Jesus zu gehen.\nWunderbar mit Jesus nur zu geh\'n.\nGlücklich ist mein Leben allezeit,\nweil mir schon vergeben: Das ist Herrlichkeit.\r\nFort sind alle Klagen und die alten Plagen\nsind versenkt ganz tief in die Vergessenheit.\nHerrlich ist mein Leben, denn die Last ist hin\nund nun hat die Zukunft einen Sinn.'),
(9, '1459', 'O, ich liebe diesen Jesus, denn Er nahm mir meine Schuld   (Chorus)', NULL, 'O, ich liebe diesen Jesus, denn Er nahm mir meine Schuld!\nO, ich liebe diesen Jesus voller Gnad\' und Huld!\nPreis der wunderbaren Liebe, die Ihn trieb nach Golgatha.\nEr gewann mein Herz für sich als ich die Liebe sah.'),
(9, '1460', 'O, in den Armen Jesu, an der geliebten Brust  -  Safe in the Arms of Jesus, safe on His gentle Breast   (O in den Armen Jesu, an der geliebten Brust)', 'Safe in the arms of Jesus, safe on His gentle breast,\nthere by His love o’ershaded, sweetly my soul shall rest.\nHark! ’tis the voice of angels, borne in a song to me,\nover the fields of glory, over the jasper sea.\r\nSafe in the arms of Jesus,\nsafe on His gentle breast,\nthere by His love o’ershaded,\nsweetly my soul shall rest.\r\nSafe in the arms of Jesus, safe from corroding care,\nsafe from the world’s temptations, sin cannot harm me there.\nFree from the blight of sorrow, free from my doubts and fears.\nOnly a few more trials, only a few more tears!\r\nJesus, my heart’s dear refuge, Jesus has died for me,\nfirm on the Rock of Ages, ever my trust shall be.\nHere let me wait with patience, wait till the night is o’er,\nwait till I see the morning break on the golden shore.', 'O, in den Armen Jesu, an der geliebten Brust\nlässt es sich herrlich ruhen, selig in Lieb und Lust.\nHorch, wie\'s herüber tönet vom von dem kristallen Meer,\nwo in des Himmels Auen jauchzet der Sel\'gen Heer!\r\nO, in den Armen Jesu,\nan der geliebten Brust\nlässt es sich herrlich ruhen,\nselig in Lieb und Lust.\r\nJa, in den Armen Jesu quält keine Sorge mehr,\nfrei von der Welt und Sünden, freut man sich hoch und hehr.\nFrei von den Seelenschmerzen, frei von der Zweifel Pein,\nkann man sich allerwege in seinem Heiland freu\'n.\r\nJesus, mein Hort und Heiland, dank Dir, Du starbst für mich,\neinzig auf diesen Felsen bau\' und vertraue ich.\nStille will ich nun warten, bis mir der Tag anbricht,\nwo ich dein Antlitz schaue droben im ew\'gen Licht.'),
(9, '1461', 'O, Jesu Nam, du klingst so süß in jedes Gläubgen Ohr  -  How sweet the Name of Jesus sounds in a Believer\'s Ear', 'How sweet the name of Jesus sounds\nin a believer\'s ear!\nIt soothes our sorrows, heals our wounds,\nand drives away our fear.\r\nIt makes the wounded spirit whole\nand calms the troubled breast.\n\'Tis manna to the hungry soul,\nand to the weary, rest.\r\nDear Name! the rock on which I build,\nmy shield and hiding place.\nMy never-failing treasure, filled\nwith boundless stores of grace!\r\nO Jesus, shepherd, guardian, friend,\nmy Prophet, Priest, and King.\nMy Lord, my Life, my Way, my End,\naccept the praise I bring.', 'O, Jesu Nam\', du klingst so süß\nin jedes Gläub\'gen Ohr!\nDu bringst uns nah das Paradies\nund hebst das Herz empor!\r\nVerwund\'te Herzen heilest Du,\nbist jedes Müden Kraft,\nDu gibst den Schwerbelad\'nen Ruh\',\nund Mut zur Ritterschaft.\r\nMein sich\'rer Fels in wilder Flut,\nmein ein\'ger Bergungsort,\nmein Schutz bei graus\'ger Stürme Wut,\nmein letzter Ruheort.\r\nMein Herr und König, Freund und Hirt\',\nmein Priester und Prophet,\nmein Weg und Ziel, wenn ich verirrt,\nmein Heil, sei hoch erhöht!'),
(9, '1462', 'O, lass den Tau des Himmels falln  -  Oh, let the Dew of Heaven fall   (Chorus)', 'Oh, let the dew of heaven fall upon my thirsty soul.\nOh, let the dew of heaven fall on me.\nBlessed Holy Spirit come and take complete control.\nOh, let the dew of heaven fall on me.', 'O, lass den Tau des Himmels fall\'n auf meine müde Seel\'.\nO, lass den Tau des Himmels fall\'n auf mich.\nGesegneter Geist Gottes, allein Dir gehöre ich.\nO, lass den Tau des Himmels fall\'n auf mich.'),
(9, '1463', 'O, ruf Mich an, so will der Herr dich weisen', NULL, '"O ruf Mich an!"\nSo will der Herr dich weisen.\n"O ruf Mich an in jeder Not!\nIch will dich retten,\nund du sollst Mich preisen:\nO ruf Mich an! Ich bin dein Gott;\nIch will dich retten,\nund du sollst mich preisen,\no ruf Mich an! Ich bin dein Gott."\r\nO ruf Ihn an,\neh dir der Feind der Seelen\nein Leid getan, ein Leid getan.\nStatt dich mit Furcht\nund Zweifel müd\' zu quälen,\no ruf Ihn an, o ruf Ihn an!\nStatt dich mit Furcht\nund Zweifel müd\' zu quälen,\no ruf Ihn an, o ruf Ihn an!\r\nO ruf Ihn an,\ndu tust es nie vergebens;\nSein Liebesplan, Sein Liebesplan\nbestimmt auch dich\nzum Erben ew\'gen Lebens,\no ruf Ihn an, o ruf Ihn an!\nBestimmt auch dich\nzum Erben ew\'gen Lebens:\nO ruf Ihn an, o ruf Ihn an!\r\nNur Er allein,\nnur Jesus kann befreien\nvom Sündenbann, vom Sündenbann,\nEr will dein Leben heilen\nund erneuen.\nO ruf Ihn an, o ruf Ihn an!\nEr will dein Leben heilen\nund erneuen.\nO ruf Ihn an, o ruf Ihn an!\r\nEr ist bereit,\nSich dir zu offenbaren,\nbegehrst du Ihn, begehrst du Ihn,\ndu sollst der Gnade\nHerrlichkeit erfahren:\nO huld\'ge Ihm, o huld\'ge Ihm!\nDu sollst der Gnade\nHerrlichkeit erfahren;\noh huld\'ge Ihm, o huld\'ge Ihm!'),
(9, '1464', 'O, welchen treuen Erlöser ich in meinem Heilande fand   (Gnade machte frei, Gnade machte frei. Meine Seele jauchzt Halleluja)', NULL, 'O, welchen treuen Erlöser\nich in meinem Heilande fand.\nLobpreis erfüllt meine Seele,\nmeiner Sünden gedenkt Er nicht mehr.\r\nGnade machte frei.\nGnade machte frei.\nMeine Seele jauchzt: "Halleluja!"\nGnade machte frei.\r\nStröme von Licht und von Gnade\nerfüllen mein Herz mehr und mehr.\nIch weiß, meine Sünd\' ist vergeben\ndurchs Blut meines Heiland\'s und Herrn.\r\nNichts kann von Jesus mich scheiden,\ndurch Seinen Geist wohnt Er in mir.\nIn Ihm bin ich sicher geborgen\nin Stunden von Sorge und Schmerz.\r\nIch bin nicht gerettet durch Werke,\nauch nicht durch mein Schluchzen und Schrei\'n.\nNoch durch mein Mühen und Kämpfen -\ndoch nur durch die Gnade allein.'),
(9, '1465', 'O, wie bin ich glücklich, seit ich Ihn gefunden   (Jesus nur allein, Jesus nur allein)', NULL, 'O, wie bin ich glücklich, seit ich Ihn gefunden;\nnun bin ich für immer, ja für immer Sein.\nHatte mich die Sünde noch so hart gebunden,\nEr kam mich zu retten, Er gedachte mein.\nUnd in Liebe goss Er Öl in meine Wunden!\nAch, das dank ich Jesu, Jesu nur allein.\r\nJesus nur allein, Jesus nur allein\nkann uns alles geben, Jesus nur allein!\nJesus nur allein, Jesus nur allein\nbringt uns Heil und Leben, Jesus nur allein!\r\nWelch ein neues Leben will der Herr dir geben,\nSein Blut macht dich völlig von der Sünde rein!\nAls der wahre Weinstock nährt Er Seine Reben,\nwirkt die Frucht des Geistes in uns zart und fein.\nWillst du da nicht gläubig deinen Blick erheben?\nO, vertraue Jesu, Jesu nur allein!\r\nLass den Kummer schwinden, höre auf zu klagen,\nSeele, die Erlösung bricht ja voll herein!\nSieh, dein Heiland will dich in den Armen tragen,\nEr wird von dir nehmen alle Angst und Pein.\nHerz, in Seinem Namen kannst du alles wagen,\nüberlass\' dich kindlich Jesu nur allein!\r\nJesu hingegeben, wirst du alles haben,\nda kann deine Seele still und selig sein;\nund dann wird dein Heiland dich gar reichlich laben,\ngießt Er doch ins Herz dir Himmelssonnenschein.\nJa, die ganze Fülle aller Seiner Gaben\nwill dir Jesus geben, Jesus nur allein.'),
(9, '1466', 'O, wie lieb ich Dich, Du hast mich Kind genannt   (2 Chorusse)', NULL, 'O, wie lieb ich Dich,\nDu hast mich Kind genannt!\nO, wie lieb ich Dich,\nDu hast mich Kind genannt!\r\nDeine Hand berührte mich so zart,\nDein Ohr vernahm mein Schrei\'n.\nDeinen Namen preis ich allezeit,\nmein Leben, Herr, ist Dein.'),
(9, '1467', 'O, wie wunderbar wurde mein Leben erneut  -  What a wonderful Change in my Life   (Seit Jesus im Herzen mir wohnt)   [Nieste]', 'What a wonderful change in my life has been wrought,\nsince Jesus came into my heart!\nI have light in my soul for which long I had sought,\nsince Jesus came into my heart!\r\nSince Jesus came into my heart,\nsince Jesus came into my heart,\nfloods of joy o\'er my soul\nlike the sea billows roll,\nsince Jesus came into my heart.\r\nI have ceased from my wandering and going astray,\nsince Jesus came into my heart!\nAnd my sins, which were many, are all washed away,\nsince Jesus came into my heart!\r\nI`m possessed of a hope that is steadfast and sure,\nsince Jesus came into my heart!\nAnd no dark clouds of doubt now my pathway obscure,\nsince Jesus came into my heart!\r\nThere`s a light in the valley of death now for me,\nsince Jesus came into my heart!\nAnd the gates of the City beyond I can see,\nsince Jesus came into my heart!\r\nI shall go there to dwell in that City, I know,\nsince Jesus came into my heart!\nAnd I`m happy, so happy, as onward I go,\nsince Jesus came into my heart!', 'O, wie wunderbar wurde mein Leben erneut,\nseit Jesus zog ein in mein Herz.\nWas ich lange gesucht, meine Seel\' nun erfreut,\nseit Jesus zog ein in mein Herz.\r\nSeit Jesus zog ein in mein Herz,\nseit Jesus zog ein in mein Herz,\nhab\' ich Frieden und Freud\',\no, welch seliges Heut\',\nseit Jesus zog ein in mein Herz.\r\nAlles Suchen und Wandern ist völlig vorbei,\nseit Jesus zog ein in mein Herz.\nJesu Blut tilgt\' die Sünde und wusch mich ganz rein,\nseit Jesus zog ein in mein Herz.\r\nEs erfüllt mich die Hoffnung, die Heimat ich seh\',\nseit Jesus zog ein in mein Herz.\nUnd kein Zweifel verdunkelt den Pfad, den ich geh\',\nseit Jesus zog ein in mein Herz.\r\nHimmlisch\' Licht leitet mich durch das Tränental heim,\nseit Jesus zog ein in mein Herz.\nLeuchtend seh\' ich die Tore, durch die ich zieh\' ein,\nseit Jesus zog ein in mein Herz.\r\nJa, ich weiß, ich werd\' sein in der goldenen Stadt,\nseit Jesus zog ein in mein Herz.\nO wie macht es mich glücklich, was Gott an mir tat,\nseit Jesus zog ein in mein Herz.'),
(9, '1468', 'Ob die Sonne morgen scheinet  -  I don\'t know about Tomorrow   (Was mir morgen schon begegnet)', 'I don\'t know about tomorrow,\nI just live from day to day,\nI don\'t borrow from ist sunshine,\nfor its skies may turn to gray.\nI don\'t worry o\'er the future,\nfor I know what Jesus said,\nand today I\'ll walk beside Him,\nfor He knows what is ahead.\r\nMany things about tomorrow.\nI don\'t seem to understand.\nBut I know who holds tomorrow,\nand I know who holds my hand.\r\nEv\'ry step is getting brighter,\nas the golden stairs I climb.\nEv\'ry burden\'s getting lighter,\nev\'ry cloud is silver lined.\nThere the sun is always shining,\nthere no tear will dim the eye,\nat the ending of the rainbow,\nwhere the mountains touch the sky.\r\nI don\'t know about tomorrow,\nit may bring me poverty.\nBut the One who feeds the sparrow,\nis the One who stands by me.\nAnd the path that be my portion,\nmay be through the flame or flood,\nbut His presence goes before me,\nand I\'m covered with His blood.', 'Ob die Sonne morgen scheinet,\nob der Himmel grau und trüb\',\nob mein Herze lacht ob\'s weinet,\nich halt\' fest an Jesu Lieb\'.\nWenn die Zukunft auch verborgen,\nist Sein Wort mir doch bekannt;\nEr trägt alle meine Sorgen,\nund Er führt mich an der Hand.\r\nWas mir morgen schon begegnet,\nahn\' ich nicht, kann`s nicht erseh\'n.\nDoch der heut\' mich reich gesegnet,\nwird auch morgen mit mir geh\'n.\r\nAuf dem gold\'nen Weg zum Leben\nwird die Bürde sanft und leicht.\nHinter Wolken, die da schweben,\nglänzt das Licht das nimmer weicht.\nÜber Bergen hoch erhaben,\nüber\'m Regenbogen weit,\nstrahlt die schönste aller Gaben,\nEr die Sonn\' der Herrlichkeit.\r\nWas die Seele auch beweget,\nmag es Not und Armut sein.\nDer den Sperling nährt und pfleget,\nlässt mich nimmermehr allein.\nAuf dem Pfad, den Er bereitet,\nsei\'s durch Feuer oder Flut,\nfolg\' ich Ihm, Der mich geleitet,\nund mich deckt mit Seinem Blut.'),
(9, '1469', 'Ob drunten in dem Tale, wo oft Gefahr mir droht  -  It may be in the Valley, where countless Dangers hide   (Mein Jesus, Er ist mir so nah)', 'It may be in the valley, where countless dangers hide.\nIt may be in the sunshine that I, in peace, abide.\nBut this one thing I know - if it be dark or fair,\nif Jesus is with me, I’ll go anywhere!\r\nIf Jesus goes with me, I’ll go anywhere!\n’Tis heaven to me, where’er I may be, if He is there!\nI count it a privilege here, His cross to bear,\nif Jesus goes with me, I’ll go anywhere!\r\nIt may be I must carry the blessed Word of life\nacross the burning deserts to those in sinful strife.\nAnd though it be my lot to bear my colors there,\nif Jesus goes with me, I’ll go anywhere!\r\nBut if it be my portion to bear my cross at home,\nwhile others bear their burdens beyond the billow’s foam,\nI’ll prove my faith in Him - confess His judgments fair,\nif Jesus stays with me, I’ll stay anywhere!\r\nIt is not mine to question the judgment of my Lord,\nIt is but mine to follow the leadings of His Word;\nBut if to go or stay, or whether here or there,\nI’ll be, with my Saviour, content anywhere!', 'Ob drunten in dem Tale, wo oft Gefahr mir droht,\nob droben auf den Bergen, im sonn\'gen Abendrot,\ndas eine bleibt mein Trost, wohin ich immer wall\':\nBei Ihm, meinem Heiland, ist\'s gut überall.\r\nMein  Jesus, Er ist mir so nah, überall.\nIch halt\' mich an Ihn und sollt\' ich auch zieh\'n ins dunkle Tal.\nIch folg\' Ihm, wohin Er mich führt, nach Seiner Wahl.\nWenn Jesus mich leitet, ist\'s gut, überall.\r\nOb draußen in der Ferne, wo ich es künden soll,\ndass Gott die Menschen suchet und rettet liebevoll,\ndas eine bleibt mein Trost, wohin ich immer wall\':\nBei Ihm, meinem Heiland, ist\'s gut überall.\r\nOb drinnen, wenn die Sorge in meine Kammer schleicht\nund frohe Lust dem Kummer in stiller Wehmut weicht,\ndann fleh\' ich glaubensvoll: bewahr\' mich vor dem Fall.\nBei Dir, meinem Heiland, ist\'s gut überall.\r\nEs ist nicht an mir, das Urteil meines Herrn in Frage zu stellen,\nes gebührt mir, den Führungen seines Wortes zu folgen.\nDoch ob ich gehe oder bleibe, ob hier oder dort,\nIch bin mit meinem Heiland, überall zufrieden!'),
(9, '1470', 'Ob sich Wolken um mich türmen  -  What tho\' Clouds are hov\'ring o\'er me', 'What tho\' clouds are hov\'ring o\'er me,\nand I seem to walk alone.\nLonging \'mid my cares and crosses,\nfor the joys that now are flown.\nIf I\'ve Jesus, "Jesus only,"\nthen my sky will have a gem.\nHe\'s a Sun of brightest splendor,\nand the Star of Bethlehem.\r\nWhat tho\' all my earthly journey\nbringeth naught but weary hours.\nAnd, in grasping for life\'s roses,\nthorns I find instead of flow\'rs.\nIf I\'ve Jesus, "Jesus only,"\nI possess a cluster rare.\nHe\'s the "Lily of the Valley,"\nand the "Rose of Sharon" fair.\r\nWhat tho\' all my heart is yearning\nfor the lov\'d of long ago.\nBitter lessons sadly learning\nfrom the shadowy page of woe.\nIf I\'ve Jesus, "Jesus only,"\nHe\'ll be with me to the end.\nAnd, unseen by mortal vision,\nangel bands will o\'er me bend.\r\nWhen I soar to realms of glory,\nand an entrance I await.\nIf I\'ve followed "Jesus only!"\nwide will ope the pearly gate.\nWhen I join the heav\'nly chorus,\nand the angel hosts I see.\nPrecious Jesus, "Jesus only,"\nwill my theme of rapture be.', 'Ob sich Wolken um mich türmen,\nund ich fühle mich allein,\nsehne mich, von Not und Sorgen\neinmal frei, ganz frei zu sein.\nHab ich Jesum, einzig Jesum,\ntrag\' ich doch ein Diadem,\nEr strahlt heller als die Sonne,\nEr, der Stern von Bethlehem.\r\nOb ich alle Erdentage\nhier auch unterm Kreuze steh\',\nund wenn and\'re Rosen brechen,\nselber nichts als Dornen seh\'.\nHab ich Jesum, einzig Jesum,\nist die schönste Blüte mein,\nRose Sarons, weiße Lilie,\nDu bist mein, und ich bin Dein.\r\nSchau ich auch mit heißem Sehnen\ndenen nach, die ich geliebt,\nschmeckt der Kelch auch oftmals bitter,\nden Gott mir zu trinken gibt.\nHab ich Jesum, einzig Jesum,\nfehlt mir dennoch, dennoch nichts,\nüber allen Erdenschatten\nlebe ich im Reich des Lichts.\r\nNah ich einst den Perlentoren,\nwartend, droben einzugeh\'n,\nwenn ich flüstre: "Einzig Jesus"\nwerden sie mir offen steh\'n.\nUnd auch durch das Lied des Lammes\ndort mit Engeln im Verein,\nklingt es: Jesus, einzig Jesus.\nJesus bleibt mein Ruhm allein.'),
(9, '1471', 'Ob so oder anders, der Herr mich regiert  -  In some way or other the Lord will provide   (Herr, Dir wir wolln vertraun, denn Du wirsts versehn)', 'In some way or other the Lord will provide,\nit may not be my way, it may not be thy way,\nand yet in his own way, "the Lord will provide."\r\n\r\nAt some time or other the Lord will provide.\nIt may not be my time, it may not be thy time,\nand yet in his own time, "The Lord will provide."\r\nDespond then no longer, the Lord will provide.\nAnd this be the token no word he hath spoken\nwas ever yet broken, "the Lord will provide."\r\nMarch on, then, right boldly; the sea shall divide.\nThe path shall be glorious, with shoutings victorious\nwe\'ll join in the chorus, "the Lord will provide."', 'Ob so oder anders, der Herr mich regiert,\nso gilt nur Sein Wille, ich halte Ihm stille;\ndenn Er führt zum Ziele, wo\'s herrlich sein wird!\r\nHerr, Dir wir woll\'n vertrau\'n, denn Du wirst\'s verseh\'n,\nbis wir droben Dich schau\'n in himmlischen Höhn!\r\nOb jetzt oder später mich rufet der Herr,\nmag\'s andre erschrecken, Sein Stab und Sein Stecken\nwird stets mich wohl decken, wer wollte noch mehr?\r\nWer mag hier noch zagen? Der Herr wird\'s verseh\'n!\nSein Wort kann nicht trügen, die Wahrheit nicht lügen,\no sel\'ges Entzücken den Heiland versteh\'n.\r\nD\'rum vorwärts und geht\'s auch durchs finstere Tal,\ndurch wogende Meere, durch feindliche Speere,\nzum seligen Heere im himmlischen Saal!'),
(9, '1472', 'Of Jesus Love I\'m singing I praise Him every Day   (All in All, All in All)', 'Of Jesus Love I\'m singing\nI praise Him every day.\nHe is my All in All, All in All.\nHe frees my soul from bondage\nHe takes my guilt away.\nJesus is my All in All.\r\nAll in All, All in All,\na strenght in times of weariness,\na light when shadows fall.\nAll in All, All in All,\nJesus is my All in All.\r\nHe\'s patient and so tender,\nso loving and so kind.\nHe is my All in All, All in All.\nAnother friend so faithful\nmy soul will never find..\nJesus is my All in All.\r\nIn time of need no other\nto me can prove so deer.\nHe is my All in All, All in All.\nHe hears me tho\' I wisper,\nto help me He is near.\nJesus is my All in All.', NULL),
(9, '1473', 'Offen steht Jesu erbarmendes Herze   (Hör wie Er ruft, o komm wie du bist)', NULL, 'Offen steht Jesu erbarmendes Herze,\nSeele, es stehet auch offen für dich!\nDu brauchst nicht länger verschmachten im Schmerze,\ndenn auch für dich er am Kreuze verblich.\r\nHör, wie Er ruft, o komm, wie du bist,\ngib Ihm dein trauriges Herz, wie es ist!\nRettung von Sünde, Friede und Freude,\nfindest du nur bei dem Herrn Jesus Christ!\r\nVolle Erlösung hat er uns erworben,\nda unsre Sünden am Kreuze er trug.\nFür die Verurteilten ist er gestorben,\nGott ist versöhnt! Ist das nicht genug?\r\nKommt denn, ihr Seelen, ihr Sünder kommt alle,\nnehmet hier doppelt für jedes Vergeh\'n.\nBrachte uns Adam auch alle zu Falle,\nist auch für alle Erlösung gescheh\'n.\r\nKomm zu dem Heiland, dem Fels aller Seelen,\nall sein Verdienst darfst du nehmen als dein.\nDank nur, du brauchst dich nicht länger zu quälen,\ner will im Himmel dich schreiben als Sein.'),
(9, '1474', 'Oft gedenken wir der ersten Zeiten   (Gib Erweckung Herr, wie einst vor Zeiten)', NULL, 'Oft gedenken wir der ersten Zeiten,\nwo das Geistesfeuer fiel herab.\nWo im Kampf und Streit nach allen Seiten,\nJesus Seinem Volk den Sieg stets gab.\r\nGib Erweckung Herr, wie einst vor Zeiten,\ngroße Wunder Jesus, lass gescheh\'n!\nEhe Du Dein Volk wirst heimwärts leiten,\nlass die Welt Dein volles Heil noch seh\'n.\r\nKeine schöne Kirche und Altäre,\nin den Häusern beugten sie die Knie\'.\nKeine toten Formen,  Menschenlehre,\nsondern Gottes Kraft erfüllte sie.\r\nHerr, noch einmal stärk\' auch unsre Hände,\njetzt zur Zeit der finster\'n Mitternacht.\nGeistesfeuer, Geistesregen sende,\noffenbare neu Herr, Deine Macht.\r\nBald ist diese Gnadenzeit zu Ende,\nin den Wolken Jesus dann erscheint.\nSchnell von aller Weltlust dich jetzt wende,\nzögerst du noch bis die Zeit versäumt?'),
(9, '1475', 'Oft scheint der Tag sehr lang  -  Oft\' times the Day seems long   (Es wird so herrlich sein, wenn wir Ihn sehen)', 'Oft\' times the day seems long, our trials hard to bear.\nWe\'re tempted to complain, to murmur and despair.\nBut Christ will soon appear to catch His bride away.\nAll tears forever over, in God\'s eternal day.\r\nIt will be worth it all when we see Jesus.\nLife\'s trials will seem so small when we see Christ.\nOne glimpse of His dear face all sorrow will erase,\nso bravely run the race till we see Christ.\r\nSo bravely run the race till we see Christ.\nSometimes the sky looks dark with not a ray of light.\nWe\'re tossed and driven on, no human help in sight.\nBut there\'s one in heaven who knows our deepest care.\nLet Jesus solve your problem just go to Him in prayer.\r\nLife\'s days will soon be o\'er, all storms forever past.\nWe\'ll cross the great divide to glory safe at last.\nWe\'ll share the joys of heav\'n, a harp, a home, a crown.\nThe tempter will be banished, we\'ll lay our burden down.', 'Oft scheint der Tag sehr lang, die Prüfung viel zu schwer.\nDie Last sie drückt auf dich, wir murren, klagen sehr.\nDoch Jesus kommt sehr bald, die Braut zu holen heim.\nDann wischt Er ab die Tränen, an jenem großen Tag.\r\nEs wird so herrlich sein, wenn wir Ihn sehen,\ndes Lebens Alltagslast verschwindet ganz.\nEin Blick von meinem Herrn, die Sorgen gleich aufhör\'n,\nd\'rum halte tapfer aus, bis wir Ihn seh\'n.\r\nOft ist es dunkle Nacht, kein Lichtstrahl ist zu seh\'n.\nWir sind verzweifelt dann, kein Mensch hört unser Fleh\'n.\nDoch einer, Er ist da, sieht tief in unser Herz,\nja wenn Du zu Ihm betest, löst Jesus dein Problem.\r\nBald ist hier ausgekämpft, wir ruh\'n dann aus beim Herrn.\nIn seiner Herrlichkeit wird Freude immer sein.\nEin ew\'ger Jubelsang, der Tag ist nicht mehr fern,\nder feind , er ist besieget, wir sind vereint beim Herrn.'),
(9, '1476', 'Oh give thanks to the Lord   (Chorus)', 'Oh give thanks to the Lord,\nfor His love it never will end.\nOh give thanks to the Lord,\nfor His love it never will end.', NULL),
(9, '1477', 'Oh I love to hear His Voice', 'Oh I love to hear His voice,\nsaying: You belong to Me,\nyou are not your own.\nWith a price you\'re bought,\nand you\'re Mine eternally.\nAnd I love to hear Him say:\nI have saved you by My grace.\nAnd when I get to glory,\nit will then be grander still,\nfor I shall see His face.', 'Oh, ich liebe es Seine Stimme zu hören,\ndie sagt: Du gehörst Mir,\ndu bist nicht dein eigen.\nMit einem Preis bist du gekauft,\nund du bist auf ewig Mein.\nUnd ich liebe es, Ihn sagen zu hören:\nIch habe dich durch Meine Gnade gerettet.\nUnd wenn ich in die Herrlichkeit komme,\ndann wird es noch großartiger sein,\ndenn ich werde Sein Angesicht sehen.'),
(9, '1478', 'Oh it is Jesus I really want to see   (Chorus)', 'Oh it\'s Jesus I really want to see,\nYes it\'s Jesus I really want to see.\nThe more I see of this world\nthe less it means to me\nand it\'s Jesus I really want to see.', NULL),
(9, '1479', 'Oh little Town of Bethlehem', 'Oh little town of Bethlehem,\nhow still we see thee lie.\nAbove thy deep and dreamless sleep\nthe silent stars go by.\nYet in thy dark streets shineth\nthe everlasting Light.\nThe hopes and fears of all the years\nare met in thee tonight.\r\nFor Christ is born of Mary,\nand gathered all above.\nWhile mortals sleep, the angels keep\ntheir watch of wond\'ring love.\nO morning stars, together\nproclaim the holy birth.\nAnd praises sing to God the King,\nand peace to men on earth.\r\nHow silently, how silently,\nthe wondrous gift is giv\'n!\nSo God imparts to human hearts\nthe blessings of His heav\'n.\nNo ear may hear His coming,\nbut in this world of sin,\nwhere meek souls will receive Him still,\nthe dear Christ enters in.\r\nOh holy Child of Bethlehem,\ndescend on us, we pray.\nCast out our sin, and enter in,\nbe born in us today.\nWe hear the holy angels\nthe great glad tidings tell.\nOh come to us, abide with us,\nour Lord Emmanuel.', NULL),
(9, '1480', 'Oh Lord, You\'re beautiful', 'Oh Lord, You\'re beautiful,\nYour face is all I seek,\nfor when Your eyes are on this child,\nYour grace abounds to me.\r\nOh, I want to take Your word\nand shine it all around,\nbut first help me to live it, Lord !\nAnd when I\'m doing well,\nhelp me to never seek a crown,\nfor my reward is giving glory to You.\r\nOh Lord, please light the fire\nthat once burned bright and clear.\nReplace the lamp of my first love,\nthat burned with holy fear.', NULL),
(9, '1481', 'Oh the Judgment Day is coming what an awful Day it will be   (Oh, my loving Brother, when the World\'s on Fire)', 'Oh the judgment day is coming,\nwhat an awful day \'twill be.\nChrist forever is my refuge,\nrock of ages cleft for me.\r\nOh, my loving brother, when the world\'s on fire,\ndon\'t you want God\'s bosom to be your pillow.\nHide me over in the rock of ages,\nrock of ages cleft for me.\r\nAt the sounding of the trumpet,\nat the dawning of the day.\nWorldly pleasures with their treasures,\nShall forever pass away.\r\nPoor lost sinners will be crying,\nfor the home they\'ll never see.\nBut the ransomed will be singing\nrock of ages, cleft for me.', NULL),
(9, '1482', 'Oh to be like Thee, blessed Redeemer   (Oh to be like Thee, oh to be like Thee)', 'Oh to be like Thee, blessed Redeemer,\nThis is my constant longing and prayer.\nGladly I\'ll forfeit, all of earth\'s treasures,\nJesus, Thy perfect Likeness to wear.\r\nOh to be like Thee, oh to be like Thee,\nBlessed Redeemer, pure as Thou art.\nCome in Thy sweetness, come in Thy fullness;\nStamp Thine own image ceep on my heart.\r\nOh to be like Thee, Full of compassion,\nloving, forgiving, Tender and kind.\nHelping the helpless, cheering the fainting,\nseeking the wandering sinner to find.\r\nOh to be like Thee, lowly in spirit,\nholy and harmless, patient and brave.\nMeekly enduring cruel reproaches,\nwilling to suffer, others to save.\r\nOh to be like Thee, Lord, I am coming,\nnow to receive th\' anointing divine.\nAll that I am and have I am bringing,\nLord, from this moment all shall be Thine.\r\nOh to be like Thee, While I am pleading,\npour out Thy Spirit, fill with Thy love.\nMake me a temple meet for Thy dwelling,\nfit me for life and heaven above.', NULL),
(9, '1483', 'Oh what a blessing, how can I express it   (I am adopted, oh wonderful Love)', 'Oh what a blessing, how can I express it?\nOut of the fullness of rapture I sing.\nNow by the Father received and adopted,\nI am a child and an heir of a king.\r\nI am adopted, oh wonderful love,\nheir to a heritage purchased above.\nTell it, my soul, and joyfully sing,\nI am a child and an heir of a king.\r\nOh what a Father, how tenderly gracious,\noh what a Saviour to make me His care.\nTho’ I have slighted, rejected, and grieved Him,\nstill He permits me His kingdom to share.\r\nOh the unsearchable riches He giveth,\nriches increasing from day unto day.\nTreasures in value all others excelling,\ntreasures that never will rust nor decay.\r\nWhen I have finished the work He appoints me,\nwhen I have ended my journey below.\nThen to my Father and Jesus my Saviour,\nhome to a beautiful palace I go.', NULL),
(9, '1484', 'Oh! Now I see the crimson Wave  -  Oh! Nun sehe ich die Gnadenflut   (The cleansing Stream I see)', 'Oh! now I see the crimson wave,\nThe fountain deep and wide;\nJesus, my Lord, mighty to save\nPoints to His wounded side.\r\nThe cleansing stream, I see, I see!\nI plunge, and oh, it cleanseth me!\nOh! praise the Lord, it cleanseth me,\nIt cleanseth me, yes, cleanseth me!\r\nI see the new creation rise,\nI hear the speaking blood,\nIt speaks! polluted nature dies!\nSinks \'neath the cleansing flood.\r\nI rise to walk in heav\'n\'s own light\nAbove the world and sin,\nWith heart made pure, and\ngarments white,\nAnd Christ enthroned within.\r\nAmazing grace! \'tis heav\'n below\nTo feel the blood applied,\nAnd Jesus, only Jesus know,\nMy Jesus crucified.', NULL),
(9, '1485', 'Oh, how He loves you and me   (Chorus)', 'Oh, how He loves you and me. (2x)\nHe gave His all,\nwhat else could He do.\nOh, how He loves you. (2x)\nOh, how He loves you and me.', NULL),
(9, '1486', 'Oh, how I love Jesus   (9 Chorusse)', 'Oh, how I love Jesus,\nOh, how I love Jesus,\nOh, how I love Jesus,\nbecause He first loved me.\r\nTo me He is so wonderful,\nto me He is so wonderful,\nto me He is so wonderful,\nbecause He first loved me.\r\nHow can you reject Him?\nHow can you reject Him?\nHow can you reject Him?\nHe shed His blood for you.\r\nWill you not love Jesus?\nWill you not love Jesus?\nWill you not love Jesus,\nwhen first He loved e\'en you?\r\nCome while He is waiting,\ncome while He is waiting,\ncome while He is waiting,e\nere He may turn from thee.\r\nCall now upon Jesus,\ncall now upon Jesus,\ncall now upon Jesus,\nHe waits to hear you cry.\r\nNow Jesus will save you,\nnow Jesus will save you,\nnow Jesus will save you,\nbelieve and you are free.\r\nGo tell it to others,\ngo tell it to others,\ngo tell it to others,\nthat He can save them too.\r\nSing hallelujah,\nsing hallelujah,\nsing hallelujah,\nto Jesus, Lord and King.', NULL),
(9, '1487', 'Oh, I know the Time is near, where Everything that I hold dear', 'Oh, I know the time is near,\nwhere everything that I hold dear\nwill lay before the holy consuming fire.\nAll my words and all my deeds\nand every prayer said on my knees\nwill lay before the holy consuming fire.\r\nAll I want to see is Jesus,\nall I want to see is him in me.\nAll I want to see is Jesus\nshining through me.\r\nAnd hear him say "Well done,\nmy precious one,\nWell done, well done,\nmy faithful one".', 'Ich weiß die Zeit ist nahe\nwo alles was ich liebe\nvor Deinem verzehrendem Feuer liegen wird\nAlle meine Worte und Taten\nJedes Gebet dass ich auf Knien sprach\nWird vor Deinem verzehrenden Feuer liegen\r\n(Alles was ich sehen will ist Jesus\nAlles was ich sehen will ist Ihn in mir\nAlles was ich sehen will ist Jesus\ndurch mich scheinend)\r\nUnd Ihn sagen hören "wohl getan"\nmein Kostbarer\nWohl getan, mein Treuer'),
(9, '1488', 'Oh, Oh, Oh, He\'s done so much for me', 'Oh, oh, oh, He\'s done so much for me!\nOh, oh, oh, He\'s done so much for me!\nOh, oh, oh, He\'s done so much for me!\nI never shall forget\nwhat He has done for me.\r\nHe brought me out the miry clay,\nthat\'s what He\'s done for me.\nHe brought me out the miry clay,\nthat\'s what He\'s done for me.\nHe brought me out the miry clay,\nthat\'s what He\'s done for me.\nI never shall forget what He has done for me.', NULL),
(9, '1489', 'Oh, predestinated Bride, won\'t you come stand by My Side', 'Oh, predestinated bride, won\'t you come stand by My side.\nYou\'ve run the race, you\'ve kept the faith,\ncome home.\nCan\'t you hear the prophet say: "Stay in line. Don\'t ever stray."\nOh, little bride, it\'s eveningtime,\ncome home.', NULL),
(9, '1490', 'Oh, the Joy of Sins forgiv\'n   (Where the healing waters flow)', 'Oh, the joy of sins forgiv\'n,\nOh, the bliss the blood-washed know,\nOh, the peace akin to heav\'n,\nWhere the healing waters flow.\r\nWhere the healing waters flow\nWhere the joys celestial glow,\nOh, there\'s peace and rest and love,\nWhere the healing waters flow!\r\nNow with Jesus crucified,\nAt his feet I\'m resting low;\nLet me evermore abide\nWhere the healing waters flow.\r\nOh, this precious perfect love!\nHow it keeps the heart aglow,\nStreaming from the fount above,\nWhere the healing waters flow.\r\nOh, to lean on Jesus\' breast,\nWhile the tempests come and go!\nHere is blessed peace and rest,\nWhere the healing waters flow.\r\nCleansed from ev\'ry sin and stain,\nWhiter than the driven snow,\nNow I sing my sweet refrain,\nWhere the healing waters flow.', NULL),
(9, '1491', 'Oh, to see the Dawn, of the darkest Day  -  (Oh, die Dämmerung des dunkelsten Tages zu sehen)   (This, the pow\'r of the Cross)', 'Oh, to see the dawn\nof the darkest day,\nChrist on the road to Calvary.\nTried by sinful men,\ntorn and beaten, then\nnailed to a cross of wood.\r\nThis, the pow\'r of the cross,\nChrist became sin for us.\nTook the blame, bore the wrath\nwe stand forgiven at the cross.\r\nOh, to see the pain\nwritten on Your face,\nbearing the awesome weight of sin.\nEv\'ry bitter thought,\nev\'ry evil deed\ncrowning Your bloodstained brow.\r\nNow the daylight flees,\nnow the ground beneath\nquakes as its Maker bows His head.\nCurtain torn in two,\ndead are raised to life,\n"Finished!" the vict\'ry cry.\r\nOh, to see my name\nwritten in the wounds,\nfor through Your suffering I am free.\nDeath is crushed to death,\nlife is mine to live,\nwon through Your selfless love.\r\nThis, the pow\'r of the cross:\nSon of God slain for us.\nWhat a love! What a cost!\nWe stand forgiven at the cross.', 'Welch ein dunkler Tag brach dort damals an,\nals Christus ging den Leidensweg.\nWie wurde er versucht, geschlagen und verhöhnt,\ngekreuzigt auf Golgatha.\r\nIn dem Kreuz liegt die Kraft,\nChristus wird zum Fluch gemacht.\nGottes Zorn nimmt er auf sich.\nUns ist vergeben durch das Kreuz.\r\nSieh doch seinen Schmerz auf dem Angesicht,\nals alle Sünde auf ihm lag.\nJedes schlechte Wort, jede böse Tat\nkrönte sein Haupt voll Blut.\r\nDas Licht verliert den Schein, und die Erde bebt,\nals Gottes Sohn am Kreuz dort stirbt.\nDer Vorhang reißt entzwei, Tote stehen auf.\nSein Sieg ist jetzt vollbracht.\r\nJa, mein Name steht in der durchbohrten Hand.\nEr litt für mich, nun bin ich frei.\nDer Tod ist jetzt besiegt und Leben mir geschenkt\ndurch Jesu Tat am Kreuz.\r\nIn dem Kreuz liegt die Kraft.\nChristus litt an unsrer statt,\nstarb für uns, welch ein Preis!\nUns ist vergeben durch das Kreuz.'),
(9, '1492', 'Oh, victory in Jesus, my savior forever', 'I heard an old, old story, how a Saviour came from glory,\nhow he gave His life on Calvary to safe a wretch like me.\nI heard about His groaning, of His precious blood\'s atoning,\nthen I repented of my sins and won the victory.\r\nOh, victory in Jesus, my Saviour forever,\nHe sought me and bought me with His redeeming blood.\nHe loved me ere I knew Him, and all my love is due Him,\nHe plunged me to victory, beneath the cleansing flood.\r\nI heard about His healing, of His cleansing pow\'r revealing,\nhow he made the lame to walk again and caused the blind to see.\nAnd then I cried: "Dear Jesus, come and heal my broken spirit",\nand somehow Jesus came and brought to me the victory.\r\nI heard about a mansion He has built for me in glory,\nand I heard about the streets of gold  beyond the crystal sea.\nAbout the angels singing, and the old redemption story,\nand some sweet day I\'ll sing up there the song of victory.', 'Ich hörte von dem Heiland der vom Himmel herab kam,\nwie Er am Kreuz auf Golgatha Sein Leben gab für mich.\nIch hört\' von Seinem Stöhnen, mit Gott mich zu versöhnen.\nIch übergab mich völlig Ihm, ließ Fried und Freud einzieh\'n.\r\nIch hab den Sieg in Jesus, meinem Heiland, für immer!\nEr suchte und erkaufte mich mit Seinem teuren Blut.\nEr liebte mich, eh\' ich kannte Ihn, meine Liebe geb\' ich ganz Ihm.\nEr brachte den Sieg mir in dieser reinen Flut.\r\nIch hörte von der Heilung, wunderbarer Befreiung,\nwie Er die Lahmen gehend macht und auch die Blinden seh\'n.\nDa rief ich voller Schmert:" heil\' mein zerb\'rochnes Herz!"\nUnd souveräne Gnade mir den Sieg bereitet hat.\r\nIch hörte von dem sel\'gen Ort, den der Braut Er bereitet dort.\nDie Straßen sind von feinem Gold, das Meer Kristall und klar.\nDie Engel werden singen, dem Lamm Anbetung bringen!\nErlösungsgnade ist mein Lied und bleibt es immerfort.'),
(9, '1493', 'Oh, what precious Love the Father had for Adam\'s fallen Race   (Chorus)', 'Oh, what precious love the Father had\nfor Adam\'s fallen race.\nGave His only Son to suffer,\nand redeem us by His Grace.', NULL),
(9, '1494', 'Oh, won\'t you watch with me one Hour', 'Oh, won\'t you watch with me one hour,\nwhile I go yonder, while I go yonder?\nOh, won\'t you watch with me one hour,\nwhile I go yonder and pray?\nI\'m overcoming, I\'m overcoming,\nI\'m overcoming, I\'m overcoming.\nFor I love Jesus, He\'s my Saviour,\nand He smiles and He loves me too.', NULL),
(9, '1495', 'Ohne Jesus kann ich nichts tun', NULL, 'Ohne Jesus kann ich nichts tuen,\nohne Jesus bin ich arm und leer,\nohne Jesus kann ich nur treiben,\nwie ein Schiff auf hoher See.\r\nDoch mit Jesus kann ich stets siegen,\ndurch die Stürme bin ich nie allein.\nWenn Er steuert, dann läuft mein Schifflein\nin den Friedenshafen ein.'),
(9, '1496', 'Ohne Weg, ohne Licht, ohne Hilfe  -  A pilgrim was I and a-wand\'ring   (Seine Güte und Gnade und seine große Treu)', 'A pilgrim was I and a-wand\'ring,\nin the cold night of sin I did roam.\nWhen Jesus the kind Shepherd found me,\nand now I am on my way home.\r\nSurely goodness and mercy shall follow me,\nall the days, all the days of my life.\nSurely goodness and mercy shall follow me,\nall the days all the days of my life.\r\nHe restoreth my soul when I\'m weary,\nHe giveth me strength day by day.\nHe leads me beside the still waters,\nHe guards me each step of the wa.y\r\nWhen I walk thro\' the dark lonesome valley,\nmy Saviour will walk with me there.\nAnd safely His great hand will lead me,\nto the mansions He\'s gone to prepare\r\nTherefore I\'ll praise Him and extol Him without fear,\ndaily bringing Him honor, praise and thanks.\nHis goodness and mercy and his great faithfulness,\nshall follow me all the days of my life.', 'Ohne Weg, ohne Licht, ohne Hilfe,\nwar in dunkelster Nacht ich verirrt,\nbis der Herr voll Erbarmen mich suchte,\nund Er ist nun mein guter Hirt\'.\r\nSeine Güte und Gnade und seine große Treu,\nwerden folgen mir mein Leben lang.\nSeine Güte und Gnade und seine große Treu,\nwerden folgen mir mein Leben lang.\r\nWollen Sorgen und Kummer mich drücken,\nist verzagt und entmutigt mein Herz,\nwird mein Hirte aufs Neu mich erquicken,\nund heilen wird Er jeden Schmerz.\r\nMuss durchs finstere Tal ich auch wandern,\nder Herr wird dort nahe mir sein,\nmit starker Hand wird Er mich führen,\nja, ich werd\' Seiner Hilfe mich freu\'n.\r\nDarum will ich Ihn loben und rühmen ohne Scheu,\ntäglich bringen Ihm Ehr\', Preis und Dank.\nSeine Güte und Gnade und seine große Treu,\nwerden folgen mir mein Leben lang.'),
(9, '1497', 'On Calvary\'s Hill of Sorrow where Sins demands were paid   (I see a Crimson Stream of Blood)', 'On Calvary\'s hill of sorrow\nwhere sins demands were paid.\nAnd rays of hope for tomorrow\nacross our path were laid.\r\nI see a crimson stream of blood,\nit flows from Calvary.\nIt\'s waves which reach the throne of God,\nare sweeping over me.\r\nToday no condemnation,\nabides to turn away.\nMy soul from His salvation,\nHe\'s in my heart to stay.\r\nWhen gloom and sadness whisper,\nyou\'ve sinned, no use to pray.\nI look away to Jesus,\nand He tells me to say:\r\nAnd when we reach the portal,\nwhere life forever reigns.\nThe ransomed hosts grand final,\nwill be this glad refrain.', NULL),
(9, '1498', 'On the Top of Mount Zion is a City   (Oh, that City on Mount Zion)', 'On the top of Mount Zion is a city\nand the earth with glory it doth fill;\nI shall look on its beauty in the morning\nwhen I reach that city on the hill.\r\nOh, that city on Mount Zion,\ntho\' a pilgrim, yet I love thee still;\nI\'ll not leave thee, through the ages,\nwhen I reach that city on the hill.\r\nI\'m invited to come home to that city,\nfor the Word says, "Whosoever will,"\nand I\'ll find there a mansion for me waiting\nwhen I reach that city on the hill.\r\nDeath will never molest me in that city,\nnever leave me lying, cold and chill;\nand I\'ll enter to live up there forever\nwhen I reach that city on the hill.\r\nSo I\'ll stay here until my Saviour calls me,\ntrying daily to perform His will;\nthen He\'ll say unto me, "Well done" up yonder\nwhen I reach that city on the hill.', NULL),
(9, '1499', 'Once a Sinner far from Jesus, I was perishing with cold   (Oh, Glory be to Jesus, let the Hallelujah\'s roll)', 'Once a sinner far from Jesus,\nI was perishing with cold,\nbut the blessèd Savior heard me when I cried.\nThen He threw His robe around me,\nand He led me to His fold,\nand I’m living on the hallelujah side.\r\nOh, glory be to Jesus, let the hallelujahs roll,\nHelp me ring the Savior’s praises far and wide.\nFor I’ve opened up tow’rd heaven,\nall the windows of my soul,\nand I’m living on the hallelujah side.\r\nTho’ the world may sweep around me\nwith her dazzle and her dreams,\nyet I envy not her vanities and pride.\nFor my soul looks up to heaven,\nwhere the golden sunlight gleams,\nand I’m living on the hallelujah side.\r\nNot for all earth’s golden millions\nwould I leave this precious place,\ntho’ the tempter to persuade me oft has tried.\nFor I’m safe in God’s pavilion,\nhappy in His love and grace,\nand I’m living on the hallelujah side.\r\nHere the sun is always shining,\nhere the sky is always bright,\n’tis no place for gloomy Christians to abide.\nFor my soul is filled with music\nand my heart with great delight,\nand I’m living on the hallelujah side.\r\nAnd upon the streets of glory,\nwhen we reach the other shore,\nand have safely crossed the Jordan’s rolling tide.\nYou will find me shouting Glory\njust outside my mansion door,\nwhere I’m living on the hallelujah side.', NULL),
(9, '1500', 'Once I thought that love was meant for any one else but me   (Eines Tages hörte ich das Jesus lebt)   [Original]', 'Once I thought that love was meant for any one else but me.\nOnce I thought that no one knew the way.\nNow that only goes to show how wrong we all can be,\n\'cause now it seems He loves me more each day.\r\nHis love is warmer than the warmest sunshine, softer than a sigh.\nHis love is deeper than the deepest ocean, wider than the sky.\nHis love is brighter than the brightest star, that shines every night above.\nAnd there is nothing in this world that can ever change His love.\r\nSomething happened to my heart that day that I met Him,\nsomething that I never felt before.\nAnd that something is, that He has buried all my sins,\nand every day I know He loves me more.', NULL),
(9, '1501', 'Once like a Bird in Prison I dwelt   (He set me free, yes, He set me free)', 'Once like a bird In prison I dwelt.\nNo freedom from my sorrow I felt.\nThen Jesus came and listened to me,\nGlory to God, He set me free.\r\nHe set me free, yes, He set me free.\nHe broke the bonds of prison for me.\nI\'m glory bound my Jesus to see,\nGlory to God, He set me free.\r\nNow I am climbing higher each day,\nDarkness of night has drifted away.\nMy feet are planted on higher ground,\nGlory to God, I\'m homeward bound.\r\nGood-bye to sin and things that confound,\nNaught of this world shall turn me around,\nDaily I\'m working, I\'m praying too,\nGlory to God, I\'m going through.', NULL),
(9, '1502', 'One of them / Mein Gott lebt, mein Gott lebt', 'There are people almost everywhere,\nwhose hearts are all aflame,\nwith the fire that fell at Pentecost,\nwhich cleansed and made them clean.\nIt is burning now within my heart,\nall glory to His name!\nI\'m so glad that I can say I\'m one of them!\r\nOne of them, one of them,\nI\'m so glad that I can say\nI\'m one of them!\nOne of them, one of them,\nI\'m so glad that I can say\nI\'m one of them!\r\nThey were gathered in the upper room,\nall praying in His name.\nThey were baptized with the Holy Ghost,\nand power for service came.\nNow what He did for them that day\nHe\'ll do for you the same.\nI\'m so glad that I can say\nI\'m one of them!\r\nCome, my brother, seek this blessing\nthat will cleanse your heart from sin,\nthat will start the joy-bells ringing\nand will keep the soul aflame.\nIt is burning now within my heart,\nall glory to His name,\nI\'m so glad that I can say\nI\'m one of them!', 'Da sind Menschen auf der ganzen Welt,\ndie heut\' noch brennend sind\nfür den großen Gott, der zu uns kam\nund uns das Leben gibt.\nUnd sie haben dieses Zeugnis,\nund sie wissen\'s ganz bestimmt:\n"Ja, ich hab\' es selbst erlebt,\ndass mein Gott lebt!"\r\nMein Gott lebt, mein Gott lebt,\nja, ich hab\' es selbst erlebt,\ndass mein Gott lebt!\nMein Gott lebt, mein Gott lebt,\nja, ich hab\' es selbst erlebt,\ndass mein Gott lebt!\r\nJa, sie waren in dem Obersaal,\nmit abgeschloss\'nen Tür\'n,\nja, sie suchten ihren Heiland,\nund sie war\'n tief im Gebet,\ndoch als dann die Kraft von oben kam,\nda konnte jeder spür\'n:\n"Ja, ich hab\' es selbst erlebt,\ndass mein Gott lebt!"\r\nOh mein Bruder, such\' den Segen,\nden uns Gott noch heute gibt,\nder dein Herz mit Freude füllt\nund der das Wort in dir belebt,\nsuche deinen Gott, der sich auch noch\nvon uns heut\' finden lässt,\ndann kannst du auch sicher sagen:\n"Mein Gott lebt!"'),
(9, '1503', 'One Way, one Way to Heaven', 'One way, one way to heaven,\nhold up high your hand.\nFollow free and forgiven, children of the Lamb.\r\nTwo roads diverged in the middle of my life\nI heard a wise man say.\nI took the one less travelled by,\nand that\'s made the difference,\nevery night and every day.\nSo I say\r\nOne way, one way heaven,\nhold your head up high.\nOne way, free and forgiven\nchildren of the sky.', NULL),
(9, '1504', 'Only a Look at Jesus   (Only a Look, only a Look)', 'Only a look at Jesus.\nOh, soul bowed down with care.\nHe has promised to defend you.\nHe will all your burdens share.\r\nOnly a look, only a look,\ncan turn you away from sin.\nA look will give you salvation\neternal life to win\r\nOnly a look at Jesus.\nHe\'ll prove a constant friend.\nHe will bring you peace and comfort\nand go with you to the end.', NULL),
(9, '1505', 'Only Jesus', 'Make it count, leave a mark, build a name for yourself\nDream your dreams, chase your heart, above all else\nMake a name the world remembers\nBut all an empty world can sell is empty dreams\nI got lost in the light when it was up to me\nTo make a name the world remembers\nBut Jesus is the only name to remember\r\nAnd I, I don\'t want to leave a legacy\nI don\'t care if they remember me\nOnly Jesus\nAnd I, I\'ve only got one life to live\nI\'ll let every second point to Him\nOnly Jesus\r\nAll the kingdoms built, all the trophies won\nWill crumble into dust when it\'s said and done\n\'Cause all that really mattered\nDid I live the truth to the ones I love?\nWas my life the proof that there is only One\nWhose name will last forever?\r\nJesus is the only name\nJesus is the only name\nJesus is the only name to remember, oh\nJesus is the only name\nJesus is the only name\nJesus is the only name to remember', NULL),
(9, '1506', 'Only my Jesus', 'With whom shall I walk through these troubles\nWith whom shall I stand in the dark\nOh let it be only my Jesus\nAnd only the strength in His arms\r\nWith whom shall I face my tomorrows\nWith whom shall I conquer my fears\nOh let it be only my Jesus\nWho will not abandon me here\r\nI will sing, I will sing\nI will sing of His steadfast love\nI will sing, I will sing of only my Jesus\r\nTo whom shall the glory be given\nTo whom shall the whole of earth bow\nOh it will be only my Jesus\nWorthy to wear every crown\r\nOf whom shall i sing in the twillight\nAs my earthly breath starts to fade\nOh let it be only my Jesus\nStill on my tongue be His praise', '(Mit wem soll ich durch diese Schwierigkeiten gehen?\nMit wem soll ich in der Dunkelheit stehen?\nOh, lass es nur meinen Jesus sein\nUnd nur die Kraft in seinen Armen)\r\nMit wem soll ich meine Zukunft angehen?\nMit wem soll ich meine Ängste besiegen?\nOh lass es nur meinen Jesus sein\nDer mich hier nicht verlassen wird\r\nIch will singen, ich will singen\nIch werde von Seiner unerschütterlichen Liebe singen\nIch will singen, ich will singen von meinem Jesus allein\r\nWem soll die Ehre gegeben werden\nVor wem soll sich die ganze Erde verneigen?\nOh, es wird nur mein Jesus sein\nWürdig, jede Krone zu tragen\r\nVon wem soll ich singen in der Dämmerung\nWenn mein irdischer Atem zu schwinden beginnt\nOh lass es nur meinen Jesus sein\nNoch auf meiner Zunge sei sein Lob'),
(9, '1507', 'Only to be what He wants me to be', 'Only to be what He wants me to be\nevery moment of every day.\nYielded completely to Jesus alone,\nevery step of this pilgrim way.\nJust to be clay in the Potter\'s hand,\nready to do what His Word commands.\nOnly to be what He wants me to be,\nevery moment of every day.', NULL),
(9, '1508', 'Only You, Lord, only You   (Chorus)', 'Only You, Lord, only You.\nOnly You, Lord, only You.\nYou\'re the fountain, that I run to.\nOnly You, Lord, only You.', NULL),
(9, '1509', 'Open the eyes of my heart Lord', 'Open the eyes of my heart, Lord\nOpen the eyes of my heart\nI want to see You\nI want to see You\r\nTo see You high and lifted up\nShinin\' in the light of Your glory\nPour out Your power and love\nAs we sing holy, holy, holy\r\nHoly,  Holy,  Holy,\nHoly,  Holy,  Holy,\nHoly,  Holy,  Holy,\nI want to see You,', 'Öffne die Augen meines Herzens, Herr\nÖffne die Augen meines Herzens\nIch möchte Dich sehen\nIch möchte Dich sehen\r\nDich hoch und erhöht zu sehen\nGlänzend im Licht Deiner Herrlichkeit\nGieße Deine Kraft und Liebe aus\nWährend wir heilig, heilig, heilig singen\r\n'),
(9, '1510', 'Our God is an awesome God   (Chorus)', 'Our God is an awesome God,\nHe reigns from heaven above,\nwith wisdom pow\'r and love,\nour God is an awesome God.', NULL),
(9, '1511', 'Overcoming Power is what we have today   (Chorus)', 'Overcoming power\nis what we have today.\nOvercoming power\nto keep the devil away.\nOvercoming power\nso we\'ll become the Word.\nThat\'s when we\'ll leave this sinful earth\nand go to meet the Lord.', NULL),
(9, '1512', 'Overtake me with your glory', 'Overtake me with Your glory,\noverwhelme me, I am Yours Lord,\nI am thirsty, come and fill me,\nall I need is more of You.\nOvertake me, Overtake me.\r\nMy hands are empty Lord,\nmy heart is open for,\nwhatever You would pour into my life.\nI bring to you my all,\nas at your feet I fall,\nin answer to Your call, Lord I come.\r\nYour spirits floods my soul,\nYour presence makes me whole,\noh Father take control of all I am.\nLord my hearts one disire,\nis Your consuming fire,\nwhatever You require, Lord I yield.\r\nHoly Spirit, breath on me\nfill this temple, show Your glory.', NULL),
(9, '1513', 'Öffne die Augen mir, o Herr, zeige mir die Wahrheit immer mehr  -  Open my Eyes, that I may see, glimpses of Truth   (Stille , o Herr, wart ich auf Dich)   [Bieselsberg]', 'Open my eyes, that I may see,\nglimpses of truth Thou hast for me.\nPlace in my hands the wonderful key,\nthat shall unclasp, and set me free.\r\nSilently now I wait for Thee,\nready, my God, Thy will to see.\nOpen my eyes, illumine me,\nSpirit Divine!\r\nOpen my ears, that I may hear,\nvoices of truth Thou sendest clear.\nAnd while the wave-notes fall on my ear,\neverything false will disappear.\r\nOpen my mouth, and let me bear,\ngladly the warm truth everywhere.\nOpen my heart, and let me prepare,\nlove with Thy children thus to share.', 'Öffne die Augen mir , o Herr,\nzeig mir die Wahrheit immer mehr,\nöffne das Wort, ich möchte Dich sehn,\nmöcht\' Deine Wege in Liebe versteh\'n.\r\nStille , o Herr, wart\' ich auf Dich!\nTu\' Deinen Will\'n, verändere mich!\nÖffne die Augen mir, o Herr\nimmer mehr!\r\nÖffne die Ohren mir, o Herr,\ndass ich heut\' Deine Stimme hör\',\ndenn wo Dein Wort ist, dort bist auch Du.\nUnd in der Wahrheit finde ich Ruh\'.\r\nÖffne den Mund mir,\nleg\' hinein Worte der Wahrheit ganz allein!\nÖffne das Herz die Liebe vermehr\',\ndass ich die Brüder so lieb\' wie Dich, Herr!'),
(9, '1514', 'Öffne mein Auge, zeige mir Jesus, was Wahrheit ist bei Dir  -  Open my Eyes that I may see Glimpses of Truth Thou hast for me   [Pfingstjubel])', 'Open my eyes that I may see\nglimpses of truth thou hast for me.\nPlace in my hands the wonderful key\nthat shall unclasp and set me free.\nSilently now I wait for Thee,\nready, my God, Thy will to see.\nOpen my eyes, illumine me,\nSpirit divine!\r\nOpen my ears that I may hear\nvoices of truth Thou sendest clear,\nand while the wave notes fall on my ear,\nev’rything false will disappear.\nSilently now I wait for Thee,\nready, my God, Thy will to see.\nOpen my ears, illumine me,\nSpirit divine!\r\nOpen my mouth and let me bear\ngladly the warm truth ev’rywhere.\nOpen my heart and let me prepare\nlove with Thy children thus to share.\nSilently now I wait for Thee,\nready, my God, Thy will to see.\nOpen my mouth, illumine me,\nSpirit divine!', 'Öffne mein Auge, zeige mir,\nJesus, was Wahrheit ist bei Dir.\nDu hast den Schlüssel, welcher mir hier\nöffnet zu vollem Licht die Tür.\nSchweigend, Herr Jesus, harr\' ich Dein,\nnur, was Du willst, gescheh\' allein.\nÖffne mein Aug\', dass recht ich seh\',\nHerr, in der Höh\'!\r\nÖffne mein Ohr, dass hell und klar,\nes, Herr, vernimmt, was vor Dir wahr,\ndass, was nicht lauter, werd\' offenbar\nund von mir weiche immerdar.\nSchweigend, Herr Jesus, harr\' ich Dein,\nnur, was Du willst, gescheh\' allein.\nÖffne mein Ohr, dass es versteh\'\nHerr, in der Höh\'!\r\nÖffne den Mund dann, dass er trägt\nBotschaft, die du hineingelegt.\nÖffne mein Herz, dass eingeprägt\nihm sei die Liebe, die Du gehegt.\nSchweigend, Herr Jesus, harr\' ich Dein,\nnur, was Du willst, gescheh\' allein.\nDir zur Verfügung ganz ich steh,\nHerr, in der Höh\'!'),
(9, '1515', 'Öffne mir die Augen, ich will Jesus sehen  -  Open my Eyes Lord, I want to see Jesus   (Chorus)', 'Open my eyes, Lord, I want to see Jesus,\nto reach out and touch Him and say that I love Him.\nOpen my ears, Lord, and help me to listen.\nOpen my heart, Lord, I want to be Yours, Lord.', 'Öffne mir die Augen, ich will Jesus sehen,\nich will Ihn berühren, und sagen: Ich lieb\' Dich.\nÖffne mir die Ohren, und hilf mir zu hören.\nÖffne das Herz mir, ich will Dir gehören.'),
(9, '1516', 'Peace I leave with you  -  Frieden lasse ich euch   (Johannes 14, 27)', 'Peace I leave with you,\nMy peace I give unto you.\nNot as the world giveth,\ngive I unto you.\nLet not your heart be troubled,\nNeither let it be afraid.\nPeace I leave with you.', 'Frieden lasse ich euch,\nMeinen Frieden gebe ich euch.\nIch gebe euch nicht wie die Welt gibt.\nEuer Herz erschrecke sich nicht\nund fürchte sich nicht.'),
(9, '1517', 'Peter and John went to pray   (Silber und Gold hab ich nicht)', 'Peter and John went to pray,\nthey met a lame man on the way,\nhe ask them for alms,\nthey showed him their palms\nand this is what Peter then said:\r\nSilver and gold have I none,\nbut what I have, I give you:\n"In the name of Jesus Christ\nfrom Nazareth, stand up and walk."\nWalking and jumping and praising God,\nwalking and jumping and praising God.\n"In the name of Jesus Christ\nfrom Nazareth, stand up and walk."\r\nYou may have come here today,\nyour strenght gone to walk in the way,\nbut look to the word,\nit\'s in flesh now, you\'ve heard.\nIf you listen too, you\'ll hear it say:', '\r\nSilber und Gold hab\' ich nicht,\ndoch was ich hab\', geb\' ich Dir:\n"Im Namen von Jesus Christus,\nnimm Dein Bett, steh auf und geh."\nLaufen und springen und preisen Gott.\nLaufen und springen und preisen Gott.\n"Im Namen von Jesus Christus,\nnimm Dein Bett, steh auf und geh."\r\n'),
(9, '1518', 'Pleasing, let me be pleasing to You   (Chorus)', 'Pleasing,\nlet me be pleasing to You.\nMay everything that I do\nbe pleasing to You.\nPraying that everything I pursue\nBe pleasing oh Lord to You.', 'Gefallen,\nlass mich Dir wohlgefällig sein.\nMöge alles, was ich tue\nDir wohlgefällig sein.\nIch bete, dass alles, was ich tue\nDir wohlgefällig ist, oh Herr.'),
(9, '1519', 'Potter\'s Hand', 'Beautiful Lord, wonderful savior\nI know for sure, all of my days are held in Your hands\nCrafted into Your perfect plan\r\nYou gently call me, into Your presence\nGuiding me by, Your Holy Spirit\nTeach me dear Lord\nTo live all of my life through Your eyes\r\nI\'m captured by, Your Holy calling\nSet me apart\nI know You\'re drawing me to Yourself\nLead me Lord I pray\r\nTake me, and mold me\nUse me, fill me\nI give my life to the Potter\'s hands\nHold me, You guide me\nLead me, walk beside me\nI give my life to the Potter\'s hand', 'Wunderbarer Herr, wunderbarer Retter\nIch weiß mit Sicherheit, dass alle meine Tage in deinen Händen gehalten werden\nGeschaffen in deinen perfekten Plan\r\nDu rufst mich liebevoll in Deine Gegenwart\nFühre mich durch, Deinen Heiligen Geist\nLehre mich lieber Herr\nMein ganzes Leben durch Deine Augen zu leben\r\nIch bin gefangen von Deiner heiligen Berufung\nTrenne mich\nIch weiß, dass du mich zu dir ziehst\nFühre mich, Herr, ich bete\r\nNimm mich und forme mich\nBenutze mich, erfülle mich\nIch gebe mein Leben in die Hände des Töpfers\nHalt mich, Du leitest mich\nFühre mich, geh neben mir\nIch gebe mein Leben in die Hand des Töpfers'),
(9, '1520', 'Pour Your Spirit Out On Me', 'Lord,  I seek You, Help me find You\nHow I need Your touch\nFind my dry and Broken places\nThirsty for Your love\nLord, forgive me, If I\'ve wandered\nFar away from You\nYou are all I\'ve ever needed\nCome and make me new\r\nPour Your Spirit out on me\nFall just like the rain\nSaturate my thirsty soul\nCome and fall afresh on me\nFill my cup again\nHeal my heart and make me whole\nI need You now\nPour Your Spirit out', 'Herr ich suche Dich, hilf mir Dich zu finden\nWie brauche ich Deine Berührung\nMeine trockenen und gebrochenen Stellen\nWie brauche ich Deine Liebe\nHerr vergib mir wenn ich weit von dir gegangen bin\nDu bist alles was ich jemals brauche\nkomm und erneuere mich\r\nGieße Deinen Geist auf mich aus,\nfalle wie der Regen\nStille meine durstige Seele\nKomm und falle erneut auf mich,\nfülle mein Gefäß noch einmal\nHeile mein Herz und mache mich ganz\nIch brauche Dich jetzt\nGieß Deinen Geist aus'),
(9, '1521', 'Praise God for His wonderful Love   (Chorus)', 'Praise God for His wonderful love,\npraise God for His wonderful love.\nLet the earth rejoice and everybody sing,\npraise God, praise God for His wonderful love.', NULL),
(9, '1522', 'Praise the mighty name of Jesus', 'My troubled soul,\nWhy so weighed down?\nYou were not made to bear this heavy load\nCast all your burdens, upon the Lord\nJesus cares, He cares for you.\r\nJesus cares, He cares for you\nAnd all your worrying won\'t help you make it through\nCast all your burdens, upon the Lord\nAnd trust again, in the promise of His love.\r\nI will praise the mighty name of Jesus\nPraise the Lord, the Lifter of my head\nPraise the Rock of my Salvation\nAll my days are in His faithful hands.\r\nMy anxious heart\nWhy so upset?\nWhen trials come, how you so easily forget\nTo cast your burdens, upon the Lord\nJesus cares, He cares for you.', NULL),
(9, '1523', 'Prayer will sail across the Country, faster than a Train can run   (Don\'t forget the Family Prayer  -  Vergiss nicht das Familengebet)', 'Prayer will sail across the country,\nfaster than a train can run.\nPrayer will sail across the ocean,\nprayer can stop your wandering round.\r\nDon\'t forget the family prayer,\nJesus wants to meet you there.\nHe will take your every care,\noh, don\'t forget the family prayer.\r\nAt evening when you feel downhearted,\neverything\'s gone wrong all day.\nCall the family together,\nask them all to kneel and pray.\r\nWhen you gather around the fireside,\nwith the family all close by.\nThank the Lord for all your blessings\nas you pray to Him on high.', NULL),
(9, '1524', 'Precious Memories, unseen Angels   (Precious Memories, how they linger)', 'Precious memories, unseen angels,\nsent from somewhere to my soul.\nHow they linger, ever near me,\nand the sacred past unfold.\r\nPrecious memories, how they linger,\nhow they ever flood my soul.\nIn the stillness of the midnight,\nprecious, sacred scenes unfold.\r\nPrecious father, loving mother,\nfly across the lonely years.\nAnd old home scenes of my childhood,\nin fond memory appear.\r\nIn the stillness of the midnight,\nechoes from the past I hear.\nOld-time singing, gladness bringing,\nfrom that lovely land somewhere.\r\nAs I travel on life\'s pathway,\nknow not what the years may hold.\nAs I ponder, hope grows fonder,\nprecious memories flood my soul.\r\nPrecious memories of the prophet,\nflood my soul from day to day.\nI remember scenes so precious\nthat can never pass away.\r\nI\'ve heard the message and its signal\nthat day\'s end is near at hand.\nBut I remember that He promised\nHe\'d return for those who\'d stand.\r\nPrecious memories, glorious meetings\nacross this land from sea to sea.\nWhere I heard the prophet\'s message\nthat brought life and hope to me.\r\nPrecious memories in this storehouse\nwhere the food was laid away.\nWe\'ve returned to where he stored it,\nspiritual food against this day.', NULL),
(9, '1525', 'Preis den Herrn, meine Seel und alles, was in mir ist  -  Bless the Lord, oh my Soul, and all that is within me   (2 Chorusse)', 'Bless the Lord, oh my soul\nand all that is within me,\nbless His holy name! (2x)\r\nFor He has done great things,\nHe has done great things,\nHe has done great things,\nbless His holy name.', 'Preis den HERRN, meine Seel\'\nund alles, was in mir ist,\nSeinen heil\'gen Nam\'! (2x)\r\nDenn Großes tat Er mir,\ngroßes tat Er mir,\ngroßes tat Er mir,\npreis sei Seinem Nam\'!'),
(9, '1526', 'Preis Dir, Du ewiger, siegreicher, mächtiger Herrscher und Gott  -  Come, Thou Almighty King, help us Thy Name to sing', 'Come, Thou Almighty King, help us Thy name to sing,\nhelp us to praise.\nFather, all glorious, o\'er all victorious,\ncome and reign over us, Ancient of Days.\r\nCome, Thou Incarnate Word,\ngird on thy mighty sword, scatter Thy foes.\nLet thine almighty aid our sure defense be made,\nour souls on Thee be stayed,\nThy wonders show.\nHerr, komme bald!\r\nCome, Holy Comforter,\nThy sacred witness bear in this glad hour.\nThou who almighty art, now rule in ev\'ry heart,\nand ne\'er from us depart,\nSpirit of power.\r\nTo the great One in Three\neternal praises be, hence evermore.\nHis sov\'reign majesty may we in glory see,\nand to eternity\nlove and adore.', 'Preis Dir, Du ewiger, siegreicher, mächtiger\nHerrscher und Gott!\nVater in Ewigkeit, prächtig in Heiligkeit,\nLicht ist Dein strahlend Kleid,\nHelfer in Not!\r\nPreis Dir, Du starker Sohn,\nDein ist des Vaters Thron, Dein die Gewalt.\nKönig und Friedefürst, liebend Dein Volk Du führst,\nsiegreich Du kommen wirst,\r\nPreis, mächtiger Tröster, Dir,\nsehnen Dein harren wir, Dein Volk Dich preist.\nRüst\' uns zur Jüngerschaft, tröst\',\nwenn der Mut erschlafft, füll uns mit Deiner Kraft,\nHeiliger Geist.\r\nPreis Dir auf einem Thron,\nVater und Geist und Sohn, Dein sei die Ehr\'.\nWaltend in Schöpferpracht,\nrettend durch Liebesmacht,\nhältst Du für uns die Wacht,\nGott, unser Herr.'),
(9, '1527', 'Preis Gott, preis Gott, bin ein königlich Kind  -  Oh yes, oh yes, I\'m a Child of the King   (Chorus)', 'Oh yes, oh yes, I\'m a child of the King,\nHis royal blood now flows through my veins.\nAnd I who was wretched and vile now can sing:\nPraise God, praise God, I\'m a child of the King!', 'Preis Gott, preis Gott, bin ein königlich Kind!\nSein teures Blut, es fließt nun durch mich.\nUnd ich war so elend, doch nun singe ich.\nPreis Gott, preis Gott, bin ein königlich Kind!'),
(9, '1528', 'Preis sei Dir, mein teurer Heiland  -  Precious Saviour, Thou hast saved me   (Glory, glory, Jesus saves me)', 'Precious Saviour, Thou hast saved me,\nThine, and only Thine I am.\nOh! the cleansing blood has reached me!\nGlory, glory, to the Lamb!\r\nGlory, glory, Jesus saves me,\nglory, glory to the Lamb!\nOh! the cleansing blood has reached me!\nGlory, glory, to the Lamb!\r\nTrusting, trusting ev’ry moment.\nFeeling now the blood applied.\nLying at the cleansing fountain\nDwelling in my Saviour’s side.\r\nConsecrated to thy service,\nI will live and die to thee.\nI will witness to thy glory,\nof salvation full and free.\r\nYes, I will stand up for Jesus;\nHe has sweetly saved my soul,\nCleansed me from inbred corruption,\nSanctified, and made me whole.', 'Preis sei Dir, mein teurer Heiland,\ndass Du starbst am Kreuzesstamm!\nDurch Dein Blut erkauft, errettet;\nbin ich Dein, o Gotteslamm!\r\nPreis sei Dir, mein teurer Heiland,\ndass Du starbst am Kreuzesstamm!\nDurch Dein Blut erkauft, errettet;\nbin ich Dein, o Gotteslamm!\r\nJeden Augenblick vertrauend\nauf des Lammes teures Blut,\ntrink ich aus der Lebensquelle\nund verbleib in treuer Hut.\r\nHerr, Dir will ich fortan dienen\nlebend, sterbend, ewig treu,\nwill zu Deiner Ehr\' bezeugen,\nwie Dein Heil ist voll und frei.\r\nJesu, Du mein guter Hirte,\nführst mich an der Liebe Seil,\nund so darf ich stets erfahren\nDein vollkomm\'nes ew\'ges Heil.'),
(9, '1529', 'Preis! Anbetung   (3 Chorusse)', '\r\nSei gepriesen! Sei gepriesen!\nSei gepriesen! Sei gepriesen!\r\nHalleluja! Halleluja!\nHalleluja! Halleluja!', 'Preis! Anbetung! Preis! Anbetung!\nPreis! Anbetung! Preis! Anbetung!\r\n\r\n'),
(9, '1530', 'Preist den Namen Jesus, Er ist mein Fels  -  Praise the name of Jesus, He is my Rock', 'Praise the name of Jesus,\npraise the name of Jesus.\nHe is my rock, He is my fortress,\nHe is my deliverer, in Him shall I trust.\nPraise the name of Jesus!\r\nWe give Him all the glory,\nwe give Him all the glory\nKing of kings, Lord of lords,\nPrince of Peace.\nHe is worthy of praise.\nPraise the name of Jesus.', 'Preist den Namen Jesus,\npreist den Namen Jesus,\nEr ist mein Fels, Er ist meine Festung.\nEr ist mein Erlöser, auf Ihn will ich vertrau\'n.\nPreist den Namen Jesus!\r\n'),
(9, '1531', 'Preist Ihn! Preist Ihn! Jesus, den treuen Erlöser  -  Praise Him, praise Him! Jesus, our blessed Redeemer   (Preist Ihn! Preist Ihn! Preist Seinen heiligen Namen)', 'Praise Him, praise Him! Jesus, our blessed redeemer!\nSing, o earth, His wonderful love proclaim!\nHail Him, hail Him! Highest archangels in glory!\nStrength and honor give to His holy name!\nLike a shepherd, Jesus will guard His children.\nIn His arms he carries them all day long.\r\nPraise Him! Praise Him! tell of his excellent greatness.\nPraise Him! Praise Him! ever in  joyful song.\r\nPraise Him, praise Him! Jesus, our blessed redeemer!\nFor our sins, He suffered, and bled, and died.\nHe our rock, our hope of eternal salvation,\nhail Him, hail Him! Jesus, the crucified.\nSound His praises, Jesus who bore our sorrows,\nlove unbounded, wonderful, deep, and strong.\r\nPraise Him, praise Him! Jesus, our blessed redeemer!\nHeav’nly portals loud with hosannas ring!\nJesus, Saviour, reigneth forever and ever!\nCrown Him, crown Him! prophet, and priest, and king!\nChrist is coming, over the world victorious.\nPow’r and glory unto the Lord belong.', 'Preist Ihn! Preist Ihn! Jesus, den treuen Erlöser,\nrühmt und lobt Ihn alle mit frohem Schall!\nHeil Ihm! Heil Ihm! Jauchzet, ihr heiligen Engel!\nIhr Erlösten, preiset Ihn überall.\nWie ein Hirte führet Er Seine Schafe,\nund die Lämmer trägt Er an Seiner Brust.\r\nPreist Ihn! Preist Ihn!\nPreist Seinen heiligen Namen.\nRühmt und lobt Ihn alle mit frohem Schall.\r\nPreist Ihn! Preist Ihn! Rühmet den freundlichen Heiland,\nweil Er starb für Sünder auf Golgatha.\nLobt Ihn! Lobt Ihn! Lobt Seinen heiligen Namen:\nJesus, Jesus! Jauchzet: Halleluja!\nJe und je hat Jesus uns treu geliebet.\nO vergiss nicht, was Er an dir getan.\r\nPreist Ihn! Preist Ihn! Jesus, den großen Erretter.\nAuf, ihr Tore, lasset Ihn ziehen ein!\nEr ist Sieger, Hölle und Tod sind bezwungen!\nKrönt Ihn! Krönt Ihn! König ist Er allein!\nBald wird Er mit himmlischer Pracht erscheinen.\nSein ist Macht und ewige Herrlichkeit.'),
(9, '1532', 'Preist Ihn, Preist Ihn, preiset Ihn am Morgen  -  Praise Him, praise Him, praise Him in the Morning', 'Praise Him, praise Him,\npraise Him in the morning,\npraise Him in the noon-time,\npraise Him, praise Him,\npraise Him when the sun goes down.\r\n\r\nI like the old-time singing, shouting,\nI like the old-time way.\nI like the old-time singing, shouting,\npreaching, praying.\nI like the old-time way.\r\nI sing about my Saviour everywhere I go,\neverywhere I go, everywhere I go.\nI sing about my Saviour everywhere I go,\nfor there is joy, joy in my soul.\r\nSinging joy, joy in my soul,\nsinging joy, joy in my soul.\r\nI’m going there, nobody can stop me.\nWooh, I’m going there, don’t you want to go too?\nI’m going there, nobody can stop me\nI’m on my way, I’m going there. (2x)', 'Preist Ihn, preist Ihn,\npreiset Ihn am Morgen,\npreiset Ihn am Mittag.\nPreist Ihn, preist Ihn,\npreist Ihn, wenn der Tag sich neigt.\r\nIch liebe Gott zu singen, jauchzen.\nIch liebe Seinen Weg.\nIch liebe Gott zu singen,\njauchzen, loben, preisen.\nIch liebe Seinen Weg.\r\nIch lieb\' das echte Singen, Jauchzen,\nbin von der alten Art.\nIch lieb\' die geistgewirkte Herzenspredigt, Amen!\nBin von der alten Art!\r\n\r\n\r\n'),
(9, '1533', 'Preist mit mir den Gott der Stärke  -  I will praise the Lord my Glory   (Ich will loben den Herrn der Welt)', 'I will praise the Lord my glory,\nI will praise the Lord my light.\nHe my cloud by day to cover,\nHe my fire to guide by night.\r\nI will praise thee with my whole heart,\nwill praise thee, o Lord.\nI will be glad and rejoice in thee,\no Thou most high.\r\nI will praise the Lord my prophet,\nholy priest and righteous king,\nwith the angels who adore him,\n"Holy, holy, holy" I will sing.\r\nI will praise the Lord my Shepherd,\nKeeper, Pasture, Door and Fold.\nO’er the lonely hills he sought me,\nwhen the night was dark and cold.\r\nI will praise the Lord my Father,\nSaviour, Brother, Guide and Friend.\nHe thus far in life hath led me,\nHe will lead me to the end.\r\nI will love Him, I will trust Him,\nall the remnant of my days.\nAnd will sing thro’ endless ages,\nnaught but my Redeemer’s praise.', 'Preist mit mir den Gott der Stärke,\nder im Regimente sitzt.\nDer uns mit der Wolke führet,\nmit der Feuersäule schützt.\r\nIch will loben den Herrn der Welt,\nden Gott meines Heil\'s.\nIch will lobsingen dem Fels\nund Hüter Israels.\r\nPreist mit mir den Herrn Jehova,\nunsern König, Ihn allein,\njauchzet Ihm das dreimal Heilig\nin des Flammenthrones Schein.\r\nPreist mit mir den Gott der Liebe,\nSeines Volkes treuen Hirt\',\nder auf grüner Au uns weidet,\nder uns sucht, wenn wir verirrt.\r\nPreist mit mir den ew\'gen Vater,\nRetter, Führer, Helfer, Freund,\nder uns tausendmal bewiesen,\nwie so gut Er\'s mit uns meint.\r\nIch will preisen, ich will lieben,\nwill Ihm trauen Tag für Tag,\nwill Ihm dienen, freudig wirken,\nwas Sein Arm durch mich vermag.'),
(9, '1534', 'Preist mit uns den Herrn  -  Let\'s just praise the Lord', 'Let\'s just praise the Lord,\npraise the Lord.\nLet\'s just lift our hands toward heaven,\nand praise the Lord.\nLet\'s just praise the Lord,\npraise the Lord,\nLet\'s just lift our hands toward heaven,\nand praise the Lord.', 'Preist mit uns den Herrn,\npreist den Herrn,\nerhebt die Hände auf zum Himmel\nund preist den Herrn.\nPreist mit uns den Herrn,\npreist den Herrn,\nerhebt die Hände auf zum Himmel\nund preist den Herrn.'),
(9, '1535', 'Pres de la croix', '\r\nÀ la croix, à la croix\nSoit ma gloire à jamais.\nJusqu’à ce que mon âme\nTrouve pardon et repos\r\n\r\nPrès de la Croix, Ô Agneau\nApporte tes cènes\nAide-moi à marcher toujours\nAvec ton ombre sur moi.\r\nPrès de la Croix j’attendrai\nVeillant, croyant toujours\nJusqu’à ce que j’atteindrai\nL’autre rive dorée.', 'Près de la Croix garde-moi\nÔ fontaine précieuse\nGratuite et guérissante\nQui coule du Calvaire.\nBeim Kreuz bewahre mich\nO kostbarer Brunnen\nfrei und heilend\nDer von Golgatha fließt\r\n(Dem Kreuz, dem Kreuz\nSei mein Ruhm in Ewigkeit.\nBis meine Seele\nVergebung und Ruhe findet)\r\nPrès de la Croix, tout tremblant\nAmour, grâce je trouve.\nLà l’Étoile du matin\nRayonne autour de moi.\n(Beim Kreuz, ganz zitternd\nLiebe, Gnade finde ich.\nDort ist der Morgenstern\nstrahlt um mich herum.)\r\nBeim Kreuz, o Lamm\nBringe dein Abendmahl\nHilf mir, immer zu wandeln\nMit deinem Schatten über mir\r\n(Am Kreuz werde ich warten\nWachend, immer glaubend\nBis ich das Ziel erreiche\nam anderen goldene Ufer.)'),
(9, '1536', 'Presence of the Lord', 'There is nothing like the presence of the Lord\nThere is nothing like the presence of the Lord\nAnd as we seek His face\nHe is here in this place\nThere is nothing like the presence of the Lord\r\nThere is healing in the presence of the Lord\nThere is healing in the presence of the Lord\nAnd as we seek His face\nHe is here in this place\nThere is healing in the presence of the Lord\r\nThere is freedom in the presence of the Lord\nThere is freedom in the presence of the Lord\nAnd as we seek His face\nHe is here in this place\nThere is freedom in the presence of the Lord', 'Es gibt nichts wie die Gegenwart des Herrn\nWährend wir Sein Angesicht suchen\nist Er hier an diesem Ort\r\nEs gibt Heilung in der Gegenwart des Herrn\nWährend wir Sein Angesicht suchen\nist Er hier an diesem Ort\r\nDa ist Freiheit in der Gegenwart des Herrn\nWährend wir Sein Angesicht suchen\nist Er hier an diesem Ort'),
(9, '1537', 'Press along Saints press along', 'Press along saints press along\nin God\'s own way.\nPress along saints press along\nin God\'s own way.\nPersecutions you must bear\ntrials and crosses in your way.\nBut the hotter the battle\nthe sweeter the victory!', NULL),
(9, '1538', 'Press on until the Day   (2 Chorusse)', 'Press on until the day,\nPress on until the day,\nPress on until the day,\nLet us press on until the day.\r\nFaithful until the day,\nFaithful until the day,\nFaithful until the day,\nBe faithful until the day.', NULL),
(9, '1539', 'Prüf mich, o Gott, erforsche Du mein Herz  -  Search me, oh God, and know my Heart today', 'Search me, oh God, and know my heart today;\ntry me, oh Saviour, know my thoughts, I pray;\nsee if there be some wicked way in me;\ncleanse me from every sin and set me free.\r\nI praise Thee, Lord, for cleansing me from sin;\nfulfill Thy Word and make me pure within.\nFill me with fire, where once I burned with shame;\ngrant my desire to magnify Thy name.\r\nLord, take my life, and make it wholly Thine;\nfill my poor heart with Thy great love divine;\ntake all my will, my passion, self and pride;\nI now surrender, Lord, in me abide.\r\nOh Holy Ghost, revivel comes from Thee,\nsend a revival, start the work in me.\nThe Word declares Thou will supply our need;\nfor blessing now, oh Lord, I humbly plead.', 'Prüf\' mich, o Gott, erforsche Du mein Herz!\nSieh mich , o Heiland, flehe ich grad\' jetzt.\nSchau, ob in mir jetzt etwas Falsches sei.\nwasche mich rein von Sünd\' und mach mich frei.\r\nIch preise Dich, Du reinigst mich von Sünd\';\nerfüll` Dein Wort und mach mich rein zur Stund\'.\nFüll\' mich mit Feuer, wo einst in Sünd\' ich brannt\',\nstill\' mein Verlangen, Herr, lös\' mich vom Verstand!\r\nHerr, nimm mich an und mach mich völlig Dein;\ngöttliche Liebe, o komm ins Herze mein!\nNimm meinen Willen, die Leidenschaft, den Stolz,\nich übergeb\' mich ganz, Herr, bleib` bei mir.\r\nOh, Heil\'ger Geist, Erweckung kommt von Dir;\nsende Erweckung und beginn in mir!\nDein Wort verheißt, dass Du mein Retter bist.\nSegne mich jetzt, o Herr, ich bitte Dich!'),
(9, '1540', 'Put it under the Blood', 'Put it under the blood.\nPut it under the blood.\nEverything in your life,\nthat you can\'t make right.\nPut it under the blood.\r\nIf you want to be clean\nand have your spirit free,\nlet nothing remain inside.\nLeave Satan no place to\nhide. Bring it under the blood.\r\nIf there\'s a thing in your life\nthat you need to make right.\nIf He finds your heart right\nHe\'ll forgive you tonight.\nBring it under the blood.\r\nAnything that you bring\nrepent it down on your knees.\nIf he finds your heart right\nHe\'ll forgive you tonight.\nBring it under the blood.', NULL),
(9, '1541', 'Quell der Barmherzigkeit, Born aller Huld  -  Fountain of purity opened for Sin   (Weiß wie der Schnee, weiß wie der Schnee)', 'Fountain of purity opened for sin,\nhere may the penitent wash and be clean.\nJesus, Thou blessed Redeemer from woe,\nwash me and I shall be whiter than snow.\r\nWhiter than snow,\nwhiter than snow,\nwash me, Redeemer,\nand I shall be whiter than snow.\r\nThough I have labored again and again,\nall my self-cleansing is utterly vain.\nJesus, Redeemer from sorrow and woe,\nwash me and I shall be whiter than snow.\r\nWhiter than snow! nothing further I need,\nChrist is the Fountain; this only I plead.\nJesus, my Saviour, to Thee will I go,\nwash me and I shall be whiter than snow.\r\nCleanse Thou the thoughts of my heart, I implore,\nhelp me Thy light to reflect more and more.\nDaily in loving obedience to grow,\nwash me and I shall be whiter than snow.', 'Quell der Barmherzigkeit, Born aller Huld,\neinzige Rettung von Sünde und Schuld,\nJesus, Erlöser von Jammer und Weh,\nwasch\' mich und mache mich weiß wie der Schnee.\r\nWeiß wie der Schnee,\nweiß wie der Schnee,\nwasche mich, Heiland,\nso werde ich weiß wie der Schnee.\r\nRang ich auch lange, ich wurde nicht rein;\nrein wird ein Sünder durch Gnade allein;\nfrei ist und offen der Born, den ich seh\':\nJesus wasch\' Du mich so weiß wie der Schnee.\r\nWeiß wie der Schnee, Herr, die Quelle bist Du!\nReinheit und Heiligung, Friede und Ruh.\nAlles in Dir, d\'rum ich bittend hier steh:\nWasch\' mich und mache mich weiß wie der  Schnee.\r\n'),
(9, '1542', 'Quellen meiner Freude find\' ich nur im Wort des Herrn allein   (Freud am Herrn ist meine Stärke)', NULL, 'Quellen meiner Freude\nfind\' ich nur im Wort des Herrn allein;\ndadurch ist mein Leben glücklich,\nJesus deckt den Tisch mir fein.\nUnd mein Herz, es findet Nahrung,\nwird erfüllt von heiliger Erlösungsfreud\'!\nIch bin ständig selig, glücklich,\nsinge jubelnd stets erneut:\r\nFreud\' am Herrn ist meine Stärke,\no, welch Glück, so wunderbar!\nAlle Sünden sind vergeben,\nmeine Sach\' mit Gott ist klar!\nMeine Freude fließet über!\nEwig wird im Herzen froher Jubel sein.\nJedes Leiden ist vorüber!\nEwig darf ich selig, glücklich sein.\r\nEinst trank ich vom ird\'schen Brunnen,\ndoch mein Herz blieb freudeleer,\nund die Sünde in mir brannte\nwie ein weites Feuermeer.\nOb ich in der Welt gleich suchte,\nFrieden fand ich nicht, nur tiefe, bitt\'re Qual.\nDoch als ich den Herrn gefunden,\ntraf ich meine beste Wahl!\r\nMit den Scharen der Erlösten\npreis\' den Herrn ich für und für!\nNichts darf mir den Frieden rauben,\nbis ich steh\' vor der Himmelstür.\nDort schau\' ich dann meinen Heiland,\nder die Seinen führte sicher lebenslang.\nUnd aus lieberfülltem Herzen schallet\nsel\'ger noch mein Sang:'),
(9, '1543', 'Quiet me', 'Working daily for your cause\nThere is so little time to pause\nand to see you prayerfully\nGood intentions somehow fail\nEmpty promises prevail\nOh Lord am I too busy\nFor You to quiet me?\r\nQuiet me, let peaceful water flow\nLearn to be still my soul\nLet me hear,\nMy Jesus walking near,\nTouch me Lord and quiet me.\r\nSo many songs unsung\nAnd dreams not yet begun\nFor there is so much to do in so little time\nYet there is nothing that can replace\nAll the times i seek Your face\nOh Lord I want Your perfect will\nFor this life of mine.', 'Täglich für deine Sache arbeiten\nEs bleibt so wenig Zeit zum Innehalten\nund dich im Gebet zu sehen\nGute Absichten scheitern irgendwie\nLeere Versprechen überwiegen\nOh Herr, bin ich zu beschäftigt\ndass Du mich zur Ruhe bringen kannst?\r\nBring mich zur Ruhe, lass friedliches Wasser fließen\nLerne, still zu sein, meine Seele\nLass mich hören,\nMein Jesus wandelt nahe,\nBerühre mich, Herr, und mach mich ruhig.\r\nSo viele ungesungene Lieder\nUnd noch nicht begonnene Träume\nDenn es gibt so viel zu tun in so wenig Zeit\nDoch es gibt nichts, was ersetzen kann\nAll die Zeiten, in denen ich Dein Gesicht suche\nOh Herr, ich will Deinen vollkommenen Willen\nfür mein Leben.'),
(9, '1544', 'ready to leave', 'Some folks are building hopes down here and planning ahead\nso busy with their fortunes, they forgot what Jesus said:\nabout the wars and earthquakes and the fig tree\'s budding leaves.\nBut there\'s a group of people getting ready to leave!\r\nReady to leave in a twinkling of an eye,\nmaking investments in the bank up in the sky!\nI\'ve made preparations – not a reason to grieve.\nAre you in that number getting ready to leave?\r\nSinner, what\'s the reason for your needless delay?\nWhile you\'re hesitating, Christ could come just any day!\nHeed the Spirit\'s calling, make your way to Calvary,\nand get in that number getting ready to leave!', NULL),
(9, '1545', 'Real, real, real, real, Christ is so real to me', 'Real, real, real, real,\nChrist \'s so real to me.\nI love Him \'cause\nHe gave me the victory\nMany people doubt Him,\nBut I can\'t live without Him,\nThat is why I love Him so,\nHe\'s so real to me.', NULL),
(9, '1546', 'Regen des Segens soll fallen  -  There shall be Showers of Blessing   (Regen des Segens, Regen des Segens tut not)   [Pfingstjubel]', 'There shall be showers of blessing,\nthis is the promise of love.\nThere shall be seasons refreshing,\nsent from the Saviour above.\r\nShowers of blessing,\nshowers of blessing we need.\nMercydrops round us are falling,\nbut for the showers we plead.\r\nThere shall be showers of blessing,\nprecious reviving again.\nOver the hills and the valleys,\nsound of abundance of rain.\r\nThere shall be showers of blessing,\nsend them upon us, oh Lord.\nGrant to us now a refreshing,\ncome, and now honour Thy Word.\r\nThere shall be showers of blessing,\noh, that today they might fall,\nnow as to God we\'re confessing,\nnow as on Jesus we call!', '"Regen des Segens soll fallen",\nrufet des Ewigen Mund.\nZeiten der ew\'gen Erquickung\ntut die Verheißung uns kund.\r\nRegen des Segens,\nRegen des Segens tut not.\nTropfen der Gnade, sie fallen;\nsende die Ströme, o Gott!\r\nRegen des Segens soll fallen!\nDann, dann wird Jesus geehrt,\nund auf den Hügeln und Ebnen\nKunde von Regen man hört.\r\nRegen des Segens soll fallen!\nRegen des Segens sind Dein;\ngib uns die Zeit der Erquickung,\nlöse Dein Wort uns jetzt ein!\r\nRegen des Segens soll fallen!\nÖffne den Strömen die Tür,\njetzt, wo wir vor Dir uns beugen,\njetzt, wenn wir rufen zu Dir.'),
(9, '1547', 'Reinige mein Herz  -  Purify my Heart   (Feuer des Herrn, danach verlangt mein Herz)', 'Purify my heart,\nlet me be as gold\nand precious silver.\nPurify my heart,\nlet me be as gold,\npure gold.\r\nRefiner\'s fire,\nmy heart\'s one desire,\nis to be holy.\nSet apart for You, Lord,\nI choose to be holy.\nSet apart for You, my Master,\nready to do Your will.\r\nPurify my heart,\ncleanse me from within\nand make me holy.\nPurify my heart,\ncleanse me from my sin,\ndeep within.\r\nRefiner\'s fire,\nmy heart\'s one desire,\nis to be holy.\nSet apart for You, Lord,\nI choose to be holy.\nSet apart for You, my Master,\nready to do Your will.', 'Reinige mein Herz,\nmach mich rein wie Gold\nin Deinem Feuer.\nReinige mein Herz,\nmach mich rein wie Gold,\npures Gold.\r\nFeuer des Herrn,\ndanach verlangt mein Herz\nmach mich rein, (und) heilig.\nDir allein will ich dienen,\nmach mich rein, (und) heilig\nDir allein will ich dienen, mein Meister,\nund deinen Willen tun.\r\nReinige mein Herz,\nnimm, was mich trennt von dir\nund mach mich heilig.\nReinige mein Herz,\nnimm, was mich trennt von Dir, tief in mir.\r\nFeuer des Herrn,\ndanach verlangt mein Herz\nmach mich rein, (und) heilig.\nDir allein will ich dienen,\nmach mich rein, (und) heilig\nDir allein will ich dienen, mein Meister,\nund deinen Willen tun.'),
(9, '1548', 'Remember Daniel in the Lion\'s Den   (The Lord is my strenght, the Lord in His power)', 'Remember Daniel in the lion\'s den\nHe was there for he would not bow to men\nThere  is no doubt or denying\nGod shut up the mouth of the lion\nWhen he heard his servant cry!\r\nThe Lord is my strenght,\nthe Lord in His power\nis my strenght\nday by day\nand every hour - every day and every hour.\r\nRemember Paul and Silas in the jail!\nThey rejoiced for they knew God would not fail!\nThen around about midnight\nGod delivered them by his great might\nWhen he heard his children cry!', NULL),
(9, '1549', 'Remember me Almighty God   (2 Chorusse)', 'Remember me, Almighty God,\nremember me, Almighty God.\r\nSpeak now to me, Almighty One,\nspeak now to me, Almighty One.', NULL),
(9, '1550', 'Rettet die Irrenden, sucht die Verlornen  -  Rescue the Perishing, care for the Dying', 'Rescue the perishing, care for the dying,\nsnatch them in pity from sin and the grave.\nWeep o’er the erring one, lift up the fallen,\ntell them of Jesus, the mighty to save.\r\nRescue the perishing, care for the dying,\nJesus is merciful, Jesus will save.\r\nThough they are slighting Him, still He is waiting,\nwaiting the penitent child to receive.\nPlead with them earnestly, plead with them gently,\nHe will forgive if they only believe.\r\nDown in the human heart, crushed by the tempter,\nfeelings lie buried that grace can restore.\nTouched by a loving heart, wakened by kindness,\nchords that were broken will vibrate once more.\r\nRescue the perishing, duty demands it.\nStrength for thy labor the Lord will provide.\nBack to the narrow way patiently win them.\nTell the poor wand’rer a Saviour has died.', 'Rettet die Irrenden, sucht die Verlor\'nen,\nwarnt, wo das Locken der Sünde berückt;\nweint mit den Trauernden, hebt die Gefall\'nen,\nhelft, wo die Schuld eine Seele bedrückt.\r\nRettet die Irrenden, sucht die Verlor\'nen;\nJesus errettet sie, Jesus ist gut.\r\nViele vergessen Ihn, manche verachten;\nJesus harrt noch voll Erbarmen und Treu.\nRuft\'s ihnen freundlich zu, sagt\'s ihnen herzlich:\nJesus verlanget nur Glauben und Reu\'.\r\nTief in dem Herzensgrund lieget der Same,\nden in der Jugend die Liebe gestreut.\nUnter der Sünde Last lag er begraben,\nstrahlt ihn die Gnade an, sprosst er noch heut\'.\r\nRettet die Irrenden, Jesus gebeut es;\nMitleid und Liebe Er selber uns gibt.\nHin auf den schmalen Weg führt sie geduldig;\nsagt\'s ihnen tröstend, dass Jesus sie liebt.'),
(9, '1551', 'Revelation Song', 'Worthy is the Lamb who was slain\nHoly, holy, is He\nSing a new song, to Him who sits on\nHeaven\'s mercy seat\r\nHoly, Holy, Holy\nIs the Lord God Almighty\nWho was, and is, and is to come\nWith all creation I sing\nPraise to the King of kings\nYou are my everything\nAnd I will adore You\r\nClothed in rainbows, of living color\nFlashes of lightning, rolls of thunder\nBlessing and honor, strength and glory and power be\nTo You the only wise King\r\nFilled with wonder, awestruck wonder\nAt the mention of your name\nJesus your name is power\nBreath, and living water\nSuch a marvelous mystery', NULL),
(9, '1552', 'Revival in my Soul, revival in my Soul', 'Revival in my soul, revival in my soul.\nI\'ve got the hunger and desire\nfor the Holy Ghost and fire.\nGot it in my soul, got it in my soul.\r\nYou\'ve got to get in (get in), get out (get out)\nor get run over (get run over),\nYou\'ve got to get in (get in), get out (get out)\nor get run over (get run over).\nI\'ve got the hunger and desire\nfor the Holy Ghost and fire.\nGot it in my soul, got it in my soul.', NULL),
(9, '1553', 'Richte den Blick nur auf Jesus / Turn your Eyes upon Jesus - (O Herz bist du traurig und müde  -  Oh soul, are you weary and troubled?)', 'Oh, soul, are you weary and troubled?\nNo light in the darkness you see?\nThere\'s light for a look at the Saviour,\nAnd life more abundant and free!\r\nTurn your eyes upon Jesus,\nlook full in His wonderful face.\nAnd the things of earth\nwill grow strangely dim.\nIn the light of His glory and grace.\r\nThrough death into life everlasting\nHe passed, and we follow Him there.\nOver us sin no more hath dominion,\nfor more than conqu\'rors we are!\r\nHis Word shall not fail you, He promised,\nbelieve Him, and all will be wel.\nThen go to a world that is dying,\nHis perfect salvation to tell!', 'O Herz bist du traurig und müde?\nGehst einsam in Dunkel und Nacht?\nDa ist Licht wenn du schaust auf den Heiland,\nder volle Erlösung dir \'bracht.\r\nRichte den Blick nur auf Jesus,\nschau auf in Sein Antlitz so schön.\nUnd die Dinge der Welt\nwerden schwach und klein\nin dem Licht Seiner Gnade geseh\'n.\r\nSein Weg ging vom Tode zum Leben\nund wir folgen freudig und gern.\nDie Herrschaft der Sünd\' ist gebrochen\nwir sind Überwinder im Herrn.\r\nSein Wort geht nicht fehl Er verheißt es,\no glaub Ihm und alles wird gut!\nDann verkünd\' einer sterbenden Menschheit\ndie volle Erlösung im Blut.'),
(9, '1554', 'Ringen, Flehen, Beten   (Chorus)', NULL, '||: Ringen, Flehen, Beten,\nwie der Weg auch sein mag, :||\n||:wenn auch dornenvoll,\nwenn auch dornenvoll ||:'),
(9, '1555', 'Rufe zu Gott früh am Morgen  -  Whisper a Prayer in the Morning   [Jesu Name Band 2]', 'Whisper a prayer in the morning,\nwhisper a prayer at noon.\nWhisper a prayer in the evening.\nTo keep your heart in tune.\r\nGod answers prayer in the morning,\nGod answers prayer at noon.\nGod answers prayer in the evening,\nso keep your heart in tune.\r\nJesus may come in the morning,\nJesus may come at noon.\nJesus may come in the evening,\nso keep your heart in tune.', 'Rufe zu Gott früh am Morgen,\nbete am Mittag zu Ihm.\nSteh\' unter\'m kreuz auch am Abend.\nIm Beten da liebe Ihn.\r\nGott hört dein Beten am Morgen\nund auch zur Mittagsstund\'.\nGott nimmt beim Beten die Sorgen,\ntut Seinen Willen kund.\r\nJesus kann frühmorgens kommen\noder zur Mittagszeit.\nWarte auf Ihn auch am Abend,\nsei allezeit bereit.'),
(9, '1556', 'Ruft herein die armen Sünder, die Verirrten nah und fern  -  Call them in, the Poor, the Wretched, sin-stained Wanderers from the Fold', 'Call them in, the poor, the wretched,\nsin-stained wanderers from the fold.\nPeace and pardon freely offer!\nCan you weigh their worth with gold?\nCall them in! the weak, the weary,\nladen with the doom of sin.\nBid them come and rest in Jesus!\nHe is waiting: call them in!\r\nCall them in! the Jew, the Gentile,\nbid the stranger to the feast!\nCall them in! the rich, the noble,\nfrom the highest to the least.\nForth the Father runs to meet them,\nHe hath all their sorrows seen.\nRobe, and ring, and kiss of pardon,\nwait the lost ones: call them in!\r\n"Call them in", the broken-hearted,\ncowering \'neath the brand of shame.\nSpeak love\'s message low and tender,\n\'twas for sinners Jesus came.\nSee, the shadows lengthen round us,\nsoon the day dawn will begin.\nCan you leave them lost and lonely?\nChrist is coming, "Call them in."\r\n', 'Ruft herein die armen Sünder,\ndie Verirrten nah und fern.\nBietet an das Heil in Christus,\ndie Erlösung durch den Herrn!\nRuft herein die Armen, Schwachen,\ndie beschwert von Sünd\' und Pein.\nJesus will auch euch erquicken,\nja, Er wartet; kommt herein!\r\nRuft herein die Juden, Heiden;\nFremde, kommt zum Hochzeitsmahl!\nRuft herein die Reichen, Hohen,\nund der Armen große Zahl!\nSeht, der Vater eilt entgegen,\njedem will Er gern verzeih\'n.\nKleider, Ring und neue Schuhe\ngibt Er selbst, o kommt herein!\r\nRuft herein die tief Gefall\'nen,\nvoller Jammer, voller Scham;\nsagt auch ihnen von dem Retter,\nder für sie vom Himmel kam!\nJesu Wiederkehr beendet\nschon ganz bald die Gnadenzeit;\nkommt doch, ehe es zu spät\nist bis in alle Ewigkeit!\r\nRuft herein die lieben Kleinen,\ndie noch fern vom Heiland steh\'n!\nWartet nicht auf spät\'re Zeiten,\nheut\' sollt ihr zu Jesu geh\'n!\nFolget nur, wie Er euch führet;\nWer Ihm folgt, wird selig sein.\nKommt, ihr Blinden, Lahmen kommet.\nGlaubt, Er heilt euch, kommt herein!'),
(9, '1557', 'Rühmet mit mir Gottes Barmherzigkeit', NULL, 'Rühmet mit mir Gottes Barmherzigkeit,\nrühmet mit Schall, laut überall,\nund auf den Bergen und in den Gründen\nlasst uns Gottes Lob verkünden!\nUnd auf den Bergen und in den Gründen\nlasst uns Gottes Lob verkünden!'),
(9, '1558', 'Sad, broken-hearted, at an Alter I knelt   (Lernen zu ruhn, lernen zu ruhn  -  Learning to lean)', 'Sad, broken-hearted, at an alter I knelt.\nI found peace that was so serene.\nAnd all, that He asks, is a child like trust\nand a heart, that is learning, to lean.\r\nLearning to lean, learning to lean.\nI\'m learning to lean on Jesus.\nFinding more power than I\'d ever dreamed.\nI\'m learning to lean on Jesus.', '(Traurig, gebroch\'nen  Herzens am Altar ich kniete.\nIch fand Frieden, der so heiter war.\nUnd alles, was Er verlangt, ist kindliches Vertrauen\nund ein Herz, das lernt, sich anzulehnen)\r\nLernen zu ruh\'n, lernen zu ruh\'n.\nIch lerne zu ruh\'n in Jesus.\nBekomme mehr Kraft, als je ich gedacht.\nIch lerne zu ruh\'n in Jesus.'),
(9, '1559', 'Sag mir Wächter erscheint bald der Morgen  -  Tell me, Watchman, oh, what of the Morning   (Ja, wir werden dann alle am Morgen)', 'Tell me, watchman, oh, what of the morning\ndo you see as the mist clears away?\nWe behold in its splendor the dawning\nof a bright and glorious day.\r\nWe shall all gather home in the morning,\nwhen the mist from the hills clears away.\nAnd it seems I can see by the dawning,\nthat we’re nearing the end of the way.\r\nFrom the mountain of pure inspiration,\nsee the gleam of eternity rise.\nWith the holy in sweet convocation\nwe shall soon unite in praise.\r\n’Mid the rapturous glories of heaven,\non immortal and beautiful plane.\nAll the ransomed will joyfully gather,\nnevermore to part again.\r\nHallelujah! How blessed the meeting,\nwhen we gather with Jesus at home.\nIn the kingdom of love what a greeting\nof the saints around the throne!', 'Sag mir Wächter, erscheint bald der Morgen?\nIst das Dunkel der Nacht schier dahin?\nDenn wir seh\'n durch das Wort Seiner Wahrheit\nschon den ew\'gen Tag erblüh\'n.\r\nJa, wir werden dann alle am Morgen,\nwenn der Nebel für immer entfloh\'n,\nbei dem Herrn sein auf ewig geborgen,\nin dem Lichte vor Gottes Thron.\r\nDurch die göttliche Wahrheit vom Himmel\nscheinen Strahlen der Ewigkeit schon,\nwo die Heil\'gen in süßer Gemeinschaft\nIhn einst preisen vor dem Thron.\r\nEinst auf köstlichen, herrlichen Auen\nmit dem heiligen, himmlischen Heer\ndie Erlösten sich freudig versammeln,\num zu scheiden nimmermehr.\r\nHalleluja, wie groß wird die Freude,\nwenn mit Jesus vereint um den Thron\nwir im Reiche der Lieb\' uns begrüßen\nund empfangen unser\'n Lohn!'),
(9, '1560', 'Sag nicht nein, Gott ruft auch dich, sieht, wie es um dich steht', NULL, 'Sag nicht nein, Gott ruft auch dich, sieht, wie es um dich steht.\nSag nicht nein, wenn dir Sein Wort tief zu Herzen geht.\nSieh, Er liebt dich, nimmt deine Sünden und die Lasten dir fort.\nNeues Leben will Er geben. Komm und glaube Seinem Wort.\r\nSag nicht nein, denn deine Zeit liegt nicht in deiner Hand.\nSag nicht nein, die Zeit vergeht, wie die Spur im Sand.\nSieh, Er liebt dich, nimmt deine Sünden und die Lasten dir fort.\nNeues Leben will Er geben. Komm und glaube Seinem Wort.\r\nSag doch ja, Er liebt dich so und gab Sein Leben hin.\nSag doch ja, Er ist dein Ziel und des Lebens Sinn.\nSieh, Er liebt dich, nimmt deine Sünden und die Lasten dir fort.\nNeues Leben will Er geben. Komm und glaube Seinem Wort.'),
(9, '1561', 'Sag, kennst du wohl den wunderbaren Namen  -  Say, do you know the wondrous Name of Jesus   (Name über alle Namen: Jesus)', 'Say, do you know the wondrous Name of Jesus,\nGod in grace has given thee?\nHis name is praised and sung in ev\'ry nation,\nover ev\'ry land and sea.\r\nGreater than all names is that of Jesus,\nno greater name on earth is found.\nNo other name than His can give salvation,\nnowhereelse is solid ground.\r\nHis name shines brighter than all stars in heaven,\nover earthly plague and pain.\nIt raises hope an lights the flame of courage,\nwhere it has been weak and vain.\r\nIt\'s bringing heav\'nly peace to souls in torment,\ncomforting the troubled heart.\nIt bids the wind and waves return to silent,\nwhen the storms tear me a part.\r\nOnce all the other names have gon an withered,\nJesus\' name will still remain.\nEternaly His majesty and glory,\nwill forev\'r and ever reign.', 'Sag, kennst du wohl den wunderbaren Namen,\nuns zum Heil von Gott gesandt?\nSein Lob erklingt hinaus in alle Welten\nüber Meer und jedes Land.\r\nName über alle Namen: Jesus!\nKein Nam\' auf Erden ist so schön.\nIn keinem andern Namen ist Erlösung,\nnur in diesem Nam\' ist Heil.\r\nDer Name wie ein Morgenstern erstrahlet,\nüber Not und Nacht der Welt.\nEr schenket Mut und neue Hoffnungsflamme,\nwo sie glimmt so schwach und matt.\r\nDen Müden und Verzagenden hienieden,\nrings vom Untergang bedroht.\nBringt er den lang ersehnten Himmelsfrieden,\nund erlöst von Sünd\' und Tod.\r\nWenn alle andern Namen einst verbleichen,\nJesu Name ewig bleibt.\nSein Purpurglanz so wunderbar wird strahlen,\nbis in aller Ewigkeit.'),
(9, '1562', 'Sag, warum noch warten o Seele  -  Why do you wait, dear Brother   (Warum? Warum? Warum kommst du nicht herzu)', 'Why do you wait dear brother,\no why do you tarry so long?\nYour Saviour is waiting to give you\na place in His sanctified throng.\r\nWhy not, why not,\nwhy not come to Him now?\nWhy not, why not,\nwhy not come to Him now?\r\nWhat do you hope, dear brother,\nto gain by a further delay?\nThere’s no one to save you but Jesus,\nthere’s no other way but His way.\r\nDo you not feel, dear brother,\nHis Spirit now striving within?\nO why not accept His salvation,\nand throw off your burden of sin?\r\nWhy do you wait dear brother?\nthe harvest is passing away.\nYour Saviour is longing to bless you,\nthere\'s danger and death in delay.', 'Sag, warum noch warten, o Seele?\nSteh auf und komm eilend herzu!\nDein Heiland ruft dich schon so lange,\ngern schenkt Er dir Frieden und Ruh\'!\r\nWarum? Warum?\nWarum kommst du nicht herzu?\nWarum, warum\nwillst du nicht Frieden und Ruh?\r\nWas nützt dir dein Zögern, o Seele?\nDie Gnadenzeit eilet dahin!\nKein andrer als Jesus kann segnen.\nIhn haben ist ew\'ger Gewinn.\r\nFühlst du nicht im Herzen, o Seele,\ndes Geistes lebendigen Zug?\nWillst du nicht Erlösung von Sünde?\nO eile zu Jesu im Flug!\r\nSag, warum noch warten, o Seele?\nSchnell nahet dir Tod und Gericht!\nO komm, weil die Pforte noch offen\nund Jesu Blut jetzt für dich spricht!'),
(9, '1563', 'Sage doch Jesus all deine Sorgen  -  I must tell Jesus all of my trials   (Sag alles Jesus, bring Ihm die Fragen)   [Jesu Name Band 5]', 'I must tell Jesus all of my trials,\nI cannot bear these burdens alone.\nIn my distress He kindly will help me,\nHe ever loves and cares for His own.\r\nI must tell Jesus! I must tell Jesus!\nI cannot bear my burdens alone.\nI must tell Jesus! I must tell Jesus!\nJesus can help me, Jesus alone.\r\nI must tell Jesus all of my troubles,\nHe is a kind, compassionate friend.\nIf I but ask Him, He will deliver,\nmake of my troubles quickly an end.\r\nTempted and tried, I need a great Saviour,\none who can help my burdens to bear.\nI must tell Jesus, I must tell Jesus,\nHe all my cares and sorrows will share.', 'Sage doch Jesus all deine Sorgen,\ndenn es versteht dich niemand wie Er.\nEr sieht dein Heute und kennt dein Morgen,\nEr will dir helfen, allmächtig ist Er.\r\nSag\' alles Jesus, bring Ihm die Fragen,\nEr hat die Antwort für dich schon bereit.\nEr wird dich führen, die Last will Er tragen.\nEr bringt dich sicher durch diese Zeit.\r\nFühlst du dich auch von Menschen verlassen,\ndrückt dich Versagen, füllt Kummer dein Herz:\nEiner ist da, Seine Hand darfst du fassen.\nEr hat dich lieb, Er kennt deinen Schmerz.\r\nIn allen Dingen kannst du Ihm vertrauen,\nkein andrer Freund liebt dich so wie Er.\nOhne Bedenken kannst du auf Ihn bauen,\newig Derselbe ist Jesus, der Herr.'),
(9, '1564', 'Sagt an, vergoss der Herr Sein Blut und starb Er denn für mich  -  Alas! and did my Saviour bleed and did my Sovereign die   (Jesus starb für dich, Jesus starb für mich)   [Pfingstjubel]', 'Alas! and did my Saviour bleed,\nand did my Sovereign die!\nWould he devote that sacred head\nfor sinners such as I?\r\nJesus died for you,\nJesus died for me!\nYes, for us all died the Lord,\nthank God, He died for me!\r\nWas it for crimes that I have done,\nhe groaned upon the tree?\nAmazing pity! Grace unknown!\nAnd love beyond degree!\r\nWell might the sun in darkness hide,\nand shut its glories in,\nwhen God, the mighty maker, died\nfor his own creature\'s sin.\r\nThus might I hide my blushing face,\nwhile his dear cross appears.\nDissolve my heart in thankfulness,\nand melt mine eyes to tears.\r\nBut drops of tears can ne\'er repay\nthe debt of love I owe.\nHere, Lord, I give myself away,\n\'tis all that I can do.', 'Sagt an, vergoss der Herr Sein Blut,\nund starb Er denn für mich?\nNeigt Er Sein Haupt auch mir zugut,\nfür solchen Wurm wie ich?\r\nJesus starb für dich,\nJesus starb für mich!\nJa, für uns alle starb der Herr,\ngottlob, Er starb für mich!\r\nIst\'s wahr, litt Er für meine Schuld\nden Fluch am Kreuzesstamm?\nAch, mit solch wunderbarer Huld\nliebt mich dies Gotteslamm?\r\nWohl mocht\' die Sonn\' in Finsternis\nverwandeln ihren Schein,\nals Jesus jenen Schrei ausstieß\nin Seiner Todespein!\r\nVor Scham möcht\' ich mein Angesicht\nverhüllen allezeit\nund weinen, bis mein Auge bricht,\nvoll heißer Dankbarkeit!\r\nDoch löste dies nicht meinen Schmerz,\nzerflösse ich auch gar;\nHerr, heilen kannst nur Du mein Herz,\nd\'rum bring ich\'s Dir auch dar!'),
(9, '1565', 'Sagt es laut, dass Gott die Liebe  -  God is Love! His Word proclaims it   (Halleluja, welche Wahrheit, die kein Herz je ganz ermisst)', 'God is love! His Word proclaims it,\nday by day the truth we prove.\nHeav’n and earth with joy are telling,\never telling, God is love!\r\nHallelujah! tell the story,\nsung by angel choirs above.\nSounding forth the mighty chorus -\nGod is light, and God is love!\r\nGod is love! Oh, tell it gladly,\nhow the Saviour from above.\nCame to seek and save the lost ones,\nshowing thus the Father’s love.\r\nGod is love! Oh, boundless mercy;\nmay we all it fullness prove;\nTelling those who sit in darkness,\nGod is light, and God is love!', 'Sagt es laut, dass Gott die Liebe,\njeder Tag verkündet\'s neu.\nPracht der Erde, Glanz der Sterne,\nspricht, dass Gott die Liebe sei.\r\nHalleluja, welche Wahrheit,\ndie kein Herz je ganz ermisst,\ndoch in Jubelharmonien singt\'s,\ndass Gott die Liebe ist.\r\nSingt es froh, dass Gott die Liebe.\nSo hat er die Welt geliebt,\ndass, vom ew\'gen Tod zu retten,\ner den einz\'gen Sohn uns gibt.\r\nSelig Wort: "Gott ist die Liebe!"\nSelig, wer es selbst erfährt\nund mit Glauben, Zeugen, Lieben,\ndiesen Gott der Liebe ehrt.'),
(9, '1566', 'Said I found a Love that pardons   (2 Chorusse)', 'Said I found a love that pardons,\nsaid I found some stripes that heal.\nSaid I found strength for my weakness,\nand I found grace to cover all my sins.\r\nIt\'s in Jesus, all in Jesus,\nit\'s in Jesus, He\'s the One,\nHe is the Rock of Salvation,\nHe\'s the sound Foundation,\nit\'s in Jesus, He\'s the One.', NULL),
(9, '1567', 'Satan\'s like a roaring Lionroaming to\' and fro\'   (Greater is He that is in me)', 'Greater is He that is in me.\nGreater is He that is in me.\nGreater is He that is in me,\nthan he that\'s in the world.\r\nSatan\'s like a roaring lion\nroaming to\' and fro\'.\nSeeking whom he may devour,\nthe Bible tells me so.\nMany souls have been his prey\nto fall in some weak hour.\nGod has promised us today\nHis Overcoming Power.\r\nOn the day of Pentecost\na rushing mighty wind,\nblew into the upper room\nand baptised all of them\nwith a Power greater than\nany earthly foe.\nI\'m so glad I\'ve got it too.\nI\'m gonna let the whole world know.', 'Größer ist der, der in mir ist.\nGrößer ist Er, der in mir ist.\nGrößer ist Er, der in mir ist,\nals der, der in der Welt ist.\r\nSatan ist wie ein brüllender Löwe\nder hin und her streift.\nEr sucht, wen er verschlingen kann,\nso sagt es die Bibel.\nViele Seelen sind seine Beute gewesen\num in einer schwachen Stunde zu fallen.\nGott hat uns heute versprochen\nSeine Überwindungskraft.\r\nAm Tag von Pfingsten\nrauschte ein mächtiger Wind,\nin den oberen Raum wehte\nund taufte sie alle\nmit einer Kraft, die größer war\njeden irdischen Feind.\nIch bin so froh, dass ich sie auch bekommen habe.\nIch werde es die ganze Welt wissen lassen.'),
(9, '1568', 'Saved to the uttermost: I am the Lord\'s   (Saved, saved, saved to the uttermost)', 'Saved to the uttermost: I am the Lord\'s,\nJesus my Saviour salvation affords.\nGives me His Spirit a witness within,\nwhisp\'ring of pardon, and saving from sin.\r\nSaved, saved, saved to the uttermost,\nsaved, saved by power divine.\nSaved, saved, I\'m saved to the uttermost,\nJesus the Saviour is mine!\r\nSaved to the uttermost: Jesus is near,\nkeeping me safely, He casteth out fear.\nTrusting His promises now I am blest,\nleaning upon Him, how sweet is my rest.\r\nSaved to the uttermost: this I can say,\n"once all was darkness, but now it is day."\nBeautiful visions of glory I see,\nJesus in brightness revealed unto me.\r\nSaved to the uttermost: cheerfully sing,\nloud halleluja\'s to Jesus my King!\nRansomed and pardoned,redeemed by His blood,\ncleansed from unrighteousness, glory to God!', NULL),
(9, '1569', 'Schalle wieder im höhern Chor, herrliches Gotteswort  -  Sing them over again to me, wonderful Words of Life   (Herrliches Wort, herrliches Wort)', 'Sing them over again to me,\nwonderful words of Life.\nLet me more of their beauty see,\nwonderful words of Life.\nWords of life and beauty,\nteach me faith and duty:\r\nBeautiful words, wonderful words,\nwonderful words of Life.\nBeautiful words, wonderful words,\nwonderful words of life.\r\nChrist, the blessed One, gives to all,\nwonderful words of Life.\nSinner, list to the loving call,\nwonderful words of Life.\nAll so freely given,\nwooing us to heaven:\r\nSweetly echo the gospel call,\nwonderful words of Life.\nOffer pardon and peace to all,\nwonderful words of Life.\nJesus, only Saviour,\nsanctify forever:', 'Schalle wieder im höher\'n Chor,\nherrliches Gotteswort!\nKomm, beselige Herz und Ohr,\nherrliches Gotteswort!\nWort voll Geist und Leben,\nmach uns Dir ergeben!\r\nHerrliches Wort, herrliches Wort,\nherrliches Gotteswort!\nHerrliches Wort, herrliches Wort,\nherrliches Gotteswort!\r\nChristus bringt es uns allen nah,\nherrliches Gotteswort!\nSünder, hört es, für euch ist\'s da,\nherrliches Gotteswort!\nWer mit Schuld beladen,\nkomm zum Mahl der Gnaden!\r\nSüß ertönt froher Botschaft Schall,\nherrliches Gotteswort!\nBringt Erlösung ins Erdental,\nherrliches Gotteswort!\nHeiligend hienieden,\nführt\'s zum ew\'gen Frieden!'),
(9, '1570', 'Schallt ihr Himmelsglocken, Engel jubelt heut  -  Ring the bells of heaven, there is joy today   (Halleluja, Engel, jubiliert)', 'Ring the bells of heaven! There is joy today,\nfor a soul, returning from the wild!\nSee the Father meets him out upon the way,\nwelcoming His weary, wand\'ring child.\r\nGlory! Glory! How the angels sing;Glory!\nGlory! How the loud harps ring!\n\'Tis the ransomed army, like a mighty sea,\npealing forth the anthem of the free.\r\nRing the bells of heaven! There is joy today,\nfor the wand\'rer now is reconciled.\nYes, a soul is rescued from his sinful way,\nand is born anew a ransomed child.\r\nRing the bells of heaven! Spread the feast today!\nAngels, swell the glad triumphant strain!\nTell the joyful tidings, bear it far away!\nFor a precious soul is born again.', 'Schallt ihr Himmelsglocken, Engel jubelt heut\'!\nDenn ein irrend Herz ist heimgekehrt!\nSeht, wie sich der Vater seines Kindes freut,\nWie er es liebkost, umarmt und ehrt!\r\nHalleluja, Engel, jubiliert!\nHalleluja, Brüder triumphiert!\nAll der sel\'gen Geister unermesslich Heer,\nBringe heut\' lobpreisend Gott die Ehr\'!\r\nSchallt, ihr Himmelsglocken, welch ein Freudentag!\nFrei ist nun die Seel\', die Tod verdient!\nDer noch jüngst in Elend und Verderben lag,\nist erlöst, ist nun ein Gotteskind!\r\nSchallt ihr Himmelsglocken! Schwestern freuet euch;\nBrüder stimmt ein Loblied an mit Macht!\nTragt die frohe Kunde hin durch Gottes Reich:\nEine teure Seel\' ist heimgebracht!'),
(9, '1571', 'Schau ich zu jenem Kreuze hin  -  When I Survey the Wondrous Cross', 'When I survey the wondrous cross,\non which the Prince of glory died,\nmy richest gain I count but loss,\nand pour contempt on all my pride.\r\nForbid it, Lord, that I should boast,\nsave in the death of Christ, my God!\nAll the vain things that charm me most,\nI sacrifice them through his blood.\r\nSee, from his head, his hands, his feet,\nsorrow and love flow mingled down.\nDid e\'er such love and sorrow meet,\nor thorns compose so rich a crown?\r\nWere the whole realm of nature mine,\nthat were a present far too small.\nLove so amazing, so divine,\ndemands my soul, my life, my all.', 'Schau ich zu jenem Kreuze hin,\nwo einst der Friedensfürst verblich,\nfür Schaden acht ich, was Gewinn,\nwas einst mein Stolz, beschämet mich.\r\nHerr, lass in nichts mein Rühmen sein,\nnur in des Heilands Opfertod;\nfahr hin, o Welt, mit deinem Schein;\nbleib Jesu, Du, mein Herr und Gott.\r\nSieh, wie von Haupt und Fuß und Hand\nKummer und Liebe purpurn floss;\nheiß ist auch mir das Herz entbrannt,\nHerr, solche Liebe ist so groß.\r\nWär\' mein die Welt mit ihrem Glanz,\nwär\'s doch als Opfer viel zu klein;\nfür solche Liebe nimm mich ganz,\nich selbst will, Herr, das Opfer sein.'),
(9, '1572', 'Schau ich zurück wie hat mich Gott getragen   (Wenn Jesus kommt, wird mir die Sonne scheinen)', NULL, 'Schau ich zurück, wie hat mich Gott getragen,\nauf jedem Schritt begleitete Er mich.\nEr sorgt getreu in allen Lebenslagen\nund meine Schuld warf Er weit hinter Sich.\r\nWenn Jesus kommt, wird mir die Sonne scheinen,\nkeine Nacht, kein Tod wird dort mehr sein.\nWenn Jesus kommt, ist Freude bei den Seinen;\nbald sind wir dort, bei Ihm allein.\r\nSchau ich zurück, ich wollte oft verzagen,\nich hatte Angst, die Zukunft schreckte mich;\ndoch Er versprach, mich sicher durchzutragen\nbis an das Ziel: Mein Gott verlässt mich nicht.'),
(9, '1573', 'Scheint es im Haus des Vaters dir viel zu enge   (Jesus, Er reicht dir die Retterhand)', NULL, 'Scheint es im Haus des Vaters dir viel zu enge,\nbist du im Kreis der Deinen nicht mehr daheim.\nSuchst du dein Glück im Menschengedränge,\nwo\'s keinen Frieden gibt;\nEiner will dich zu Sich ziehen, Einer der dich liebt:\r\nJesus, Er reicht dir die Retterhand,\nJesus, Er ist dir so nah.\nEr ist die Tür für dich zum ew\'gen wahren Heimatland,\nweil Er für deine Sünden starb auf Golgatha.\r\nTreibt es dich fort, hinaus in des Lebens Weiten,\nlockt dich die Sehnsucht bis an das ferne Meer;\ndennoch wird Einer immer dich leiten,\nEiner, den du nicht siehst,\nja, Er wird dich stets umgeben, auch wenn du Ihm fliehst:\r\nBist Du enttäuscht, durch scheinbare Freud\' betrogen,\nhaben sich deine Freunde von dir gewandt;\nmutig bist Du des Weges gezogen?\njetzt ist betrübt dein Blick.\nMach\' dich auf und kehr noch heut\' zum Vaterhaus zurück!\r\nDu willst nach außen nur deine Not nicht zeigen.\nWeißt du denn nicht, wonach deine Seele schreit?\nNun sei nicht stolz, die Schuld zu verschweigen,\nbleibe nicht draußen steh\'n;\nsiehst du nicht den Vater dir voll Lieb entgegen geh\'n?'),
(9, '1574', 'Schmachbedeckt und müd der Sünden  -  Sad and weary with my Longing   (Alles geb ich hin für Jesus)', 'Sad and weary with my longing,\nfilled with shame, because of sin.\nAs I am in conscious weakness,\nhere I would salvation win.\r\nAll I have I leave for Jesus,\nI am counting it but dross,\nI am coming to the Master,\nI am clinging to the cross.\r\nO the joy of knowing Jesus,\nit is dawning on my soul.\nI am finding his salvation,\nand the pow’r that makes me whole.\r\nO refine me by thy spirit,\nmake my earthly life sublime,\nwith my heart a home for Jesus,\ntill I’m done with earth and time.', 'Schmachbedeckt und müd\' der Sünden,\nleg ich, Jesus, mich Dir hin,\no, lass mich Erlösung finden,\nsieh, wie schwach und matt ich bin!\r\nAlles geb\' ich hin für Jesus;\nweiche, Welt, mit deinem Reiz!\nIch will nichts als Jesus haben,\nHerr, so komme ich zum Kreuz.\r\nWelch ein Trost ist\'s, Dich zu kennen,\nmeiner Seele dämmert\'s schon.\nDich, den Herrn mein eigen nennen,\nbringt mit volles Heil zum Lohn.\r\nHeil\'ge Dir fortan mein Leben,\nläut\'re mich durch Deinen Geist!\nWohn\' in mir und hilf mir streben,\nbis mein Geist Dich droben preist!'),
(9, '1575', 'Schmecket und sehet, wie freundlich der Herr ist   (Chorus)', NULL, 'Schmecket und sehet, wie freundlich der Herr ist,\nSchmecket und sehet, wie freundlich der Herr ist! (2x)\nWohl dem, der auf Ihn traut,\nwohl dem, der auf Ihn traut! (2x)'),
(9, '1576', 'Schönster Herr Jesus, Herrscher aller Enden  -  Fairest Lord Jesus, Ruler of all Nature', 'Fairest Lord Jesus, Ruler of all nature,\no Thou of God and man the Son.\nThee will I cherish, Thee will I honor,\nThou, my soul’s glory, joy and crown.\r\nFair are the meadows, fairer still the woodlands,\nrobed in the blooming garb of spring.\nJesus is fairer, Jesus is purer,\nwho makes the woeful heart to sing.\r\nFair is the sunshine, fairer still the moonlight,\nand all the twinkling starry host.\nJesus shines brighter, Jesus shines purer,\nthan all the angels heav’n can boast.\r\nAll fairest beauty, heavenly and earthly,\nwondrously, Jesus, is found in Thee.\nNone can be nearer, fairer or dearer,\nthan Thou, my Saviour, art to me.', 'Schönster Herr Jesus, Herrscher aller Enden,\nGottes und Mariä Sohn!\nDich will ich lieben, Dich will ich ehren,\nDu meiner Seelen Freud und Kron.\r\nSchön sind die Wälder, schöner sind die Felder\nin der schönen Frühlingszeit.\nJesus ist schöner, Jesus ist reiner,\nder unser traurig Herz erfreut.\r\nSchön leucht\' der Monde, schöner leucht\' die Sonne,\nschön die Sternlein allzumal.\nJesus leucht\' schöner, Jesus leucht\' reiner\nals all die Engel im Himmelssaal.\r\nAlle die Schönheit, Himmels und der Erden\nist gefasst in Dir allein.\nNichts soll auf Erden mir lieber werden als Du,\no Jesus, Liebster mein.'),
(9, '1577', 'Seele, dein Heiland ist frei von den Banden   (Jesus, dein Heiland, ist Sieger und lebt)', NULL, 'Seele, dein Heiland ist frei von den Banden,\nglorreich und herrlich vom Tode erstanden.\nFreue dich, Seele, die Hölle erbebt!\r\nJesus, dein Heiland, ist Sieger und lebt!\nJesus, dein Heiland, ist Sieger und lebt!\r\nFreue dich, Seele, der Hölle Macht lieget!\nSünde und Satan und Tod sind besieget.\nDer im Triumphe dem Grab sich enthebt:\r\nFasse dich, Seele, sei tapfer im Streite!\nJesus ist mit dir und kämpft dir zur Seite.\nZage nicht, wenn auch der Tod dich umschwebt!'),
(9, '1578', 'Seele, die von Schmerz umnachtet   (Zage nie in dunkler Stunde, zweifle nie an Gottes Wort)', NULL, 'Seele, die von Schmerz umnachtet,\ntrau nur fest auf deinen Gott.\nEr will dich nur tüchtig machen\ndurch all diese Angst und Not.\r\nZage nie in dunkler Stunde,\nzweifle nie an Gottes Wort.\nWas Er spricht, geht in Erfüllung,\nGlaube, glaube immerfort!\r\nLass dich nur nicht überwinden\nvon des Satans finst\'rer Macht.\nSieh, des Heilands Wege gingen\neinstmals auch durch dunkle Nacht.\r\nWillst du ganz mit Jesus leben,\nmuss dein eig\'nes Ich vergeh\'n.\nWillst du nützlich für Ihn werden,\nwird dein Weg durch Sterben geh\'n.\r\nDarum lass die Zweifel fliehen,\nhalt dich nur an Jesus Christ.\nFür Sein Kind lässt Er geschehen\nnur, was gut und heilsam ist.'),
(9, '1579', 'Sehnst du dich jetzt, von Sünden frei zu sein  -  If you from Sin are longing to be free   (Blick auf des Gotteslamm)   [Siegesklänge]', 'If you from sin are longing to be free?\nLook to the Lamb of God.\nHe, to redeem you, died on Calvary.\nLook to the Lamb of God.\r\n\r\nLook to the Lamb of God.\nLook to the Lamb of God,\nfor He alone is able to save you.\nLook to the Lamb of God.\r\nWhen Satan tempts, and doubts and fears assail.\nLook to the Lamb of God.\nYou in His strength shall over all prevail.\nLook to the Lamb of God.\r\nAre you aweary, does the way seem long?\nLook to the Lamb of God.\nHis love will cheer and fill your heart with song.\nLook to the Lamb of God.\r\n\r\nFear not when shadows on your pathway fall.\nLook to the Lamb of God.\nIn joy or sorrow Christ is all in all.\nLook to the Lamb of God.', 'Sehnst du dich jetzt, von Sünden frei zu sein?\nBlick auf das Gotteslamm.\nEs starb am Kreuz für deine Schuld allein.\nBlich auf des Gotteslamm.\r\nBlick auf des Gotteslamm.\nBlick auf des Gotteslamm.\nJesus allein kann dich erretten.\nBlick auf des Gotteslamm.\r\n\r\nHält dich zurück die große Feindesmacht?\nBlick auf des Gotteslamm.\nJesus hat dennoch Rettung dir gebracht.\nBlick auf des Gotteslamm.\r\nBist du ermüdet von der Trübsalsglut?\nBlick auf des Gotteslamm.\nEs gibt dem Müden Kraft und frischen Mut.\nBlick auf des Gotteslamm.\r\nFürchte dich nicht wenn Todesschatten droh\'n.\nBlick auf des Gotteslamm.\nDroben erwartet dich der Heiland schon.\nBlick auf des Gotteslamm.\r\n'),
(9, '1580', 'Sehnst du dich nach Geistesfülle  -  Are you looking for the Fullnessof the blessing of the Lord   (Er wird dich erfüllen das du überfließest)', 'Are you looking for the fullness\nof the blessing of the lord\nin your heart and life today?\nClaim the promise of Your Father,\ncome according to His word,\nin the blessed old time way.\r\nHe will fill your heart today to overflowing,\nas the Lord commandeth you.\n"Bring your vessels, not a few."\nHe will fill your heart today to overflowing\nwith the Holy Ghost and pow\'r.\r\nBring your empty earthen vessels,\nclean thro\' Jesus\' precious blood,\ncome, ye needy, one and all.\nAnd in human consecration\nwait before the throne of God,\n\'Till the Holy Ghost shall fall.\r\nLike the cruse of oil unfailing\nis His grace forevermore,\nand His love unchanging still.\nAnd according to His promise\nwith the Holy Ghost and pow\'r,\nHe will ev\'ry vessel fill.', 'Sehnst du dich nach Geistesfülle,\njener Kraft der ersten Zeit,\ndie der Herr verheißen hat?\nZweifle nie an Gottes Wort,\nvertrau Ihn kindlich allezeit,\nwie\'s die Jünger einst getan.\r\nEr wird dich erfüllen das du überfließest.\nJesus ruft dich: Komm zu Mir,\nGeistesfülle schenk\' ich dir.\nEr will dich erfüllen, dass du überfließest,\nmit des Heil\'gen Geistes Kraft.\r\nNimm nur mit dir die Gefäße,\nRein\'gung gibt\'s in Jesu Blut\nkomm, ja komm, so tust du wohl.\nVor dem Throne beug\' dich nieder;\ndenn der Herr ist treu und gut.\nEr macht dich des Geistes voll.\r\nGottes Gnadenströme fließen\nvon der Höhe rein und klar.\nSie durchdringen Herz und Sinn.\nJesus gibt den Geist so gerne,\nwie es einst verheißen war;\nwende dich zu Ihm nur hin.'),
(9, '1581', 'Sei guten Mutes spricht Gott dort zu Josua  -  Be of good Courage, God spake unto Joshua   (Schaust du auf Ströme, die keiner zu zwingen meint)', '"Be of good courage", God spake unto Joshua,\nWhen o\'er the river God pointed the way;\nJordan uncrossable; Things seemed impossible,\nWaters divide as they march and obey.\r\nGot any rivers you think are uncrossable?\nGot any mountains you can\'t tunnel through?\nGod specializes in things thought impossible;\nAnd He will do what no other power can do.\r\nBattles to win! They would meet with their obstacles,\nJericho\'s walls, too, must fall to the ground.\nGod never failed; He stood back of His promises,\nWalls had to crumble as they marched around.\r\nGod is the Same and His Word is dependable,\nHe\'ll make a way through the waters for you;\nLife\'s situations by Him are amendable,\nMountains and hills He will part for you too.', '"Sei guten Mutes" spricht Gott dort zu Josua,\nheißt mit dem Volk durch den Jordan ihn geh\'n.\nUnmöglich scheint\'s, doch sie ziehen, und Gott ist da,\nteilet die Fluten, lässt Wunder gescheh\'n.\r\nSchaust du auf Ströme, die keiner zu zwingen meint?\nStehst du vor Bergen, die niemand durchbricht?\nGott tut so gerne, was uns ganz unmöglich scheint.\nEr nur vollbringt es, ein anderer nicht!\r\nSiege empfangen wir ohne zu kämpfen nicht.\nJericho sperret dem Volke die Bahn;\ndoch sie marschieren, und Gott hält was er verspricht.\nMauern zerbrechen, tritt Gott auf dem Plan.\r\nGott ist derselbe, Sein Wort ist unwandelbar,\nEr bahnt dir Wege im wogenden Meer.\nWas wir nicht meistern, Er wandelt es wunderbar.\nBerge versetzen das fällt Ihm nicht schwer.'),
(9, '1582', 'Sei mir gegrüßt, Herr Jesus Christ', NULL, 'Sei mir gegrüßt, Herr Jesus Christ;\nich danke innig Dir,\ndass Du für mich gestorben bist\nund mich noch liebst zu jeder Frist.\nGegrüßet seist Du mir!\nGegrüßet seist Du mir!\r\nAm Marterholze sah ich Dich;\nDu littest in Geduld.\nDort öffnete der Himmel sich;\nDu trugst der Sünde Last für mich.\nWie groß ist Deine Huld!\nWie groß ist Deine Huld!\r\nIn Dir fand ich ein selig Los.\nO Herr, wer ist Dir gleich?\nIch war so elend, nackt und bloß;\nnun ruhe ich in Deinem Schoß.\nDu machst den Armen reich,\nDu machst den Armen reich.\r\nIn Dir, mein Gott, ist Seligkeit.\nDie Knechtschaft ist vorbei.\nMir blüht so voll die Gnadenzeit\nmit Himmelslust nach so viel Leid.\nDu machst mich froh und frei,\nDu machst mich froh und frei.\r\nO Herr, ich rühme Dich allein.\nLob, Preis und Dank sei Dir!\nIch darf in Dir geheiligt sein,\nvon jeder Sünde frei und rein.\nMein Alles bist Du mir,\nmein Alles bist Du mir.\r\nNun liegt auf meinem Pilgerkleid\ndes Himmels Sonnenschein.\nSo pilgre ich zur Herrlichkeit;\nDu machst mich selbst dazu bereit;\nwie selig kann ich sein,\nwie selig kann ich sein!'),
(9, '1583', 'Sei still in der Gegenwart des Herrn', NULL, 'Sei still in der Gegenwart des Herrn!\nDer Heilige ist hier.\nKomm, beuge dich vor Ihm,\nin Ehrfurcht geb\' dich hin.\nEr starb für unsre Schuld.\nEr trägt uns in Geduld.\nSei still in der Gegenwart des Herrn!\nDer Heilige ist hier.\r\nSei still, denn die Herrlichkeit des Herrn\nerstrahlt nun über uns.\nSein heiliges Feuer brennt,\nEr, der die Herzen kennt.\nWir steh\'n in Seinem Licht,\nschau\'n in Sein Angesicht.\nSei still, denn die Herrlichkeit des Herrn\nerstrahlt nun über uns!\r\nSei still denn die Kraft- unsres Herrn\nberührt die Herzen nun.\nEr reinigt und Er heilt,\nnur Gnade ist Sein Tun.\nKein Ding ist Ihm zu schwer\ndenn Jesus ist der Herr.\nSei still, denn die Kraft- unsres Herrn\nberührt die Herze nun.'),
(9, '1584', 'Seid getrost, ihr Erlösten des Herrn  -  We shall meet in the Eden above   (In dies herrliche Land lasst uns ziehn Hand in Hand)', 'We shall meet in the Eden above,\nin that beautiful land of the blest.\nAll our trials and pains will be o’er,\nwhen we enter that mansion of rest.\r\nIn the beautiful, beautiful Eden above,\nin the beautiful, beautiful Eden above,\nall our trials and pains will be o’er,\nwhen we enter that mansion of rest.\r\nWhen we meet in the Eden above,\nwhen we enter that blissful abode,\nall the good who have passed on before,\nwe shall meet in the City of God.\r\nThe saints of all ages are there,\nthe prophets and martyrs of old.\nThe children whose voices on earth are still,\nnow sing in that city of gold.', 'Seid getrost, ihr Erlösten des Herrn!\nRingt hinan auf der heiligen Bahn!\nSeht, es leuchtet uns Bethlehems Stern,\nder führt sicher zum Himmel hinan!\r\nIn dies herrliche Land\nlasst uns zieh\'n Hand in Hand!\nJesu Liebe, die bringt uns hinein,\no, wie süß wird die Ruhe dort sein!\r\nBrüllt der Löwe gleich rings um uns her,\ngibt\'s auch Kampf und Versuchung und Schmerz.\nFürchtet nichts, denn uns schützet der Herr,\nder bringt sicher zur Ruhe das Herz!\r\nSeht die sel\'ge unzählbare Schar,\nder Propheten und Märtyrer Chor,\nall die Zeugen vor Gottes Altar\nwarten unser am himmlischen Tor.'),
(9, '1585', 'Seid ich ging um Dich zu suchen  -  Since I started out to find Thee   (Knüpfe, Herr, das Band stets fester)', 'Since I started out to find Thee,\nsince I to the cross did flee,\nevery bridge is burned behind me,\nI will never turn from Thee.\r\nStrengthen all the ties that bind me\ncloser, closer, Lord to Thee,\nevery bridge is burned behind me,\nThine I evermore will be.\r\nThou didst hear my plea so kindly,\nThou didst grant me so much grace,\nevery bridge is burned behind me;\nI will ne’er my steps retrace.\r\nCares of life perplex and grind me,\nyet I keep the narrow way,\nevery bridge is burned behind me,\nI from Thee will never stray.\r\nAll in All I ever find Thee,\nSaviour, Lover, Brother, Friend,\nevery bridge is burned behind me,\nI will serve Thee to the end.', 'Seit ich ging, um Dich zu suchen,\nseit ich unterm Kreuz Dich fand,\nist die Brücke abgebrochen,\ndie mich mit der Welt verband.\r\nKnüpfe, Herr, das Band stets fester,\ndas mich Dir verbunden hält.\nHinter mir sei keine Brücke,\ndie zurück führt in die Welt.\r\nDu erhörtest, Herr, mein Flehen,\nhell strahlt mir dein Gnadenschein,\nabgebrochen sind die Brücken\nhinter mir, ich bleibe Dein.\r\nWill mich Angst und Not bestürmen,\nhältst mich Du an Deiner Hand,\nabgebrochen sind die Brücken,\nvorwärts geht\'s ins Heimatland.\r\nDu bist alles mir in allem,\nRetter, Tröster, Herr und Freund,\nDeiner Liebe goldne Brücke\nist\'s, die so mich Dir vereint.'),
(9, '1586', 'Seid still und erkennt, dass Ich bin Gott  -  Be still and know that I am God   (3 Chorusse)', 'Be still and know that I am God.\nBe still and know that I am God.\nBe still and know that I am God.\r\nI am the Lord that healeth Thee.\nI am the Lord that healeth Thee.\nI am the Lord that healeth Thee.\r\nIn Thee oh Lord I put my trust.\nIn Thee oh Lord I put my trust.\nIn Thee oh Lord I put my trust.', 'Seid still und erkennt, dass Ich bin Gott.\nSeid still und erkennt, dass Ich bin Gott.\nSeid still und erkennt, dass Ich bin Gott.\r\nIch bin der Herr, dein Gott, der dich heilt.\nIch bin der Herr, dein Gott, der dich heilt.\nIch bin der Herr, dein Gott, der dich heilt.\r\nAuf Dich, o Herr, vertrauen wir.\nAuf Dich, o Herr, vertrauen wir.\nAuf Dich, o Herr, vertrauen wir.'),
(9, '1587', 'Sein Nam ist höher als alle andern  -  His Name is higher than any other   (Chorus)', 'His Name is higher than any other,\nHis Name is Jesus, His Name is Lord.\nHis Name is Wonderful, His Name is Counselor,\nHis Name is Prince of Peace, Almighty God.', 'Sein Nam\' ist höher, als alle andern,\nSein Nam\' ist Wunderbar und Starker Gott.\nSein Nam\' ist Friedefürst, Sein Nam\' heißt Rat,\nSein Nam\' ist Vater in Ewigkeit.'),
(9, '1588', 'Sein Nam\' heißt Wunderbar  -  His Name is Wonderful', 'His Name is Wonderful, His Name is Wonderful,\nHis Name is Wonderful, Jesus my Lord.\nHe is the mighty King, Master of everything,\nHis Name is Wonderful, Jesus my Lord.\nHe\'s the great Shepherd, the Rock of all ages,\nAlmighty God is He.\nBow down before Him, love and adore Him.\nHis Name is Wonderful, Jesus my Lord.', 'Sein Nam\' heißt "Wunderbar", Sein Nam\' heißt "Wunderbar",\nSein Nam\' heißt "Wunderbar", Jesus, mein Herr.\nEr, der Allmächtige, Schöpfer der ganzen Welt,\nSein Nam\' heißt "Wunderbar", Jesus, mein Herr.\nEr ist mein Hirte, Fels aller Zeiten,\nallmächtig ist der Herr.\nKniet vor Ihm nieder, singet Loblieder!\nSein Nam\' heißt "Wunderbar" Jesus, mein Herr.'),
(9, '1589', 'Sein Schaf kennt die Stimm und den Weg den Er nimmt  -  My Sheep know My Voice and the Path that I take   (Sein Schaf kennt die Stimme des Hirten so gern)', 'My sheep hear My voice and the path that I take,\nthey follow wherever I go.\nMy sheep know My voice and come at my call,\nbut a stranger’s voice do they not know.\r\nMy sheep know My voice and day by day\nthey abide in the fold and go not astray.\nThey love Me because I have made them my choice,\nand they follow My call for My sheep know My voice.\r\nMy sheep know My voice and the pastures of green,\nwhere I lead them so often to feed.\nMy sheep know My voice and the cool sparkling stream,\nwhere beside its still waters I lead.\r\nMy sheep know My voice and the valley of death,\nthrough which I shall lead them some day.\nBut no danger nor harm can touch one of them,\nfor I will be with them alway.', 'Sein Schaf kennt die Stimm\' und den Weg den Er nimmt,\nes folgt Ihm wohin Er\'s auch führt.\nSein Schaf kennt die Stimme und folgt Ihr so gern,\neiner fremden Stimm\' folgen sie nicht.\r\nSein Schaf kennt die Stimm\' des Hirten so gern\nund es folgt dieser Stimm\' Er sei nah oder fern.\nEs liebt Seinen Hirt\', der zuerst es geliebt,\nund es folgt Seinem Ruf, denn Sein Schaf kennt die Stimm\'.\r\nSein Schaf kennt die Stimm\' und es weiß ganz genau,\nEr führt es zur grünen Au\'.\nSein Schaf kennt die Stimm\' und den sprudelnden Quell,\nwo der Durst wird für immer gestillt.\r\nSein Schaf kennt die Stimm, auch wenn\'s dunkel hier wird\nführt der Hirte es sicher hindurch.\nD\'rum zögere nicht, gib doch schnell auf dein ich,\ndenn nur wenn du Ihm folgst irrst du nicht!'),
(9, '1590', 'Seine Gnade so vollkommen ist, sie stillt alle meine Not   (Welche Freude, unaussprechlich groß und herrlich)', NULL, 'Seine Gnade so vollkommen ist,\nsie stillt alle meine Not.\nZu den Füßen meines Jesu Christ\nich empfange Lebensbrot.\r\nWelche Freude, unaussprechlich groß und herrlich,\ngroß und herrlich, groß und herrlich,\nwelche Freude, unaussprechlich groß und herrlich.\nJa, die Hälfte ward mir nie gesagt.\r\nSucht ich einstens Glück, ich jetzt es find\',\nFreud und Friede ist es nun.\nWelch ein Segen: Bin befreit von Sünd\'.\nDarf in Ihm nun selig ruh\'n.\r\nJa, ich fand die Hoffnung, hell und klar,\nlebend in dem Gnadenlicht.\nOh, des Heilands Nähe ist so wahr,\nja, ich seh\' Sein Angesicht!\r\nDiese Freude die kein Mensch beschreibt,\nwie ein Lied der Herrlichkeit,\nwie die Quelle überfließend bleibt,\nsprudelt in der Seele heut\'.'),
(9, '1591', 'Seine Hand zog heraus mich aus Sünde   (Er starb für mich, Er starb für dich, auf Golgatha)', NULL, 'Er starb für mich, Er starb für dich,\nauf Golgatha.\nEr starb für mich, Er starb für dich,\nHalleluja.\r\nSeine Hand zog heraus mich aus Sünde,\nSeine Hand zog heraus mich aus Not.\nSeine Hand voller Liebe für Blinde\nführt mich liebend nach Hause zu Gott.\r\nDiese Hand ward geschlagen ans Kreuze,\ndiese Hand ward durchstochen für mich.\nDiese Hand musste leiden die Qualen,\ndass ich singen darf nun ewiglich.\r\nDiese Hand mit den Malen der Nägel,\nstreckt sich liebend nach dir heute aus.\nNimm die rettende Hand deines Heilands,\ndiese Hand führt dich sicher nach Haus.'),
(9, '1592', 'Seine Liebe in mir, Seine Freude in mir, Sein Friede in mir   (Chorus)', NULL, 'Seine Liebe in mir,\nSeine Freude in mir,\nSein Frieden in mir,\ndas macht mich so froh!\nIch wandle mit Ihm,\nich sitze mit Ihm,\nich schlafe mit Ihm\nund erwache mit Ihm.'),
(9, '1593', 'Seit ich erlöst von Sündenmacht  -  Since Christ my Soul from Sin set free   (O Halleluja, es ist vollbracht)', 'Since Christ my soul from sin set free,\nthis world has been a Heav\'n to me.\nAnd \'mid earth\'s sorrows and its woe,\n\'tis Heav\'n my Jesus here to know.\r\nOh hallelujah, yes, \'tis Heav\'n,\n\'tis Heav\'n to know my sins forgiv\'n.\nOn land or sea, what matters where?\nWhere Jesus is, \'tis Heaven there.\r\nOnce Heaven seemed a far-off place,\ntill Jesus showed His smiling face.\nNow it\'s begun within my soul,\n\'twill last while endless ages roll.\r\nWhat matters where on earth we dwell?\nOn mountain top, or in the dell?\nIn cottage, or a mansion fair.\nWhere Jesus is, \'tis Heaven there.', 'Seit ich erlöst von Sündenmacht,\nseit Jesus Freiheit mir gebracht,\nda frag\' ich nicht nach Erdenleid,\nmir strahlt des Himmels Herrlichkeit.\r\nO Halleluja, es ist vollbracht!\nMein Jesus hat mich frei gemacht!\nOb Land, ob Meer, ob Glück, ob Leid,\nwo Jesus ist, ist Herrlichkeit!\r\nSeit ich geseh\'n Sein Angesicht,\numleuchtet mich des Himmels Licht!\nNun ist mein Leben nicht mehr mein,\nin Ewigkeit, o Jesus, Dein!\r\nWas frage ich nach Tag und Zeit,\nnach Erdenlust und Erdenfreud\'?\nGeborgen in des Heilands Hut,\nvoll Himmelslust die Seele ruht!'),
(9, '1594', 'Seit ich in heilger Stunde mich, Jesus Dir geweiht', NULL, 'Seit ich in heil\'ger Stunde mich, Jesus, Dir geweiht,\nklingt mir im Herzensgrunde ein Loblied allezeit.\nOb Dunkel mich umhülle, was immer mich bewegt,\nDu hast der Freuden Fülle mir tief ins Herz gelegt.\nDu hast der Freuden Fülle mir tief ins Herz gelegt.\r\nSo lebt im Herzensgrunde bei mir stets Dank und Preis,\ndass ich in jeder Stunde Dich nur zu rühmen weiß.\nEs kann mir ja nichts fehlen, denn Du bist mir bekannt\nund hast als Freund der Seelen auch mich nun Freund genannt.\nUnd hast als Freund der Seelen auch mich nun Freund genannt.\r\nWeil mir die frohe Kunde von der Erlösung kam,\nbleibt mir im Herzengrunde Dein Lob gar wundersam.\nIch preise Deine Liebe, sie ist mir täglich neu\nund wenn mir sonst nichts bliebe, Du bleibst mir immer treu.\nUnd wenn mir sonst nichts bliebe, Du bleibst mir immer treu.\r\nDass nur mein Herz gesunde, gab\'st Du Dich hin für mich;\nd\'rum ehrt im Herzengrunde mein Dank Dich inniglich.\nMir ist das Licht gekommen nach finst\'rer Sündennacht:\nDu hast von mir genommen, was siech und elend macht.\nDu hast von mir genommen, was siech und elend macht.\r\nO Herr, von Herzensgrunde bet\' ich Dich heute an.\nHalt mich mit Dir im Bunde, dass ich nicht wanken kann.\nAch lehre mich, Dich loben noch mehr zu jeder Frist,\nbis einst mein Dank dort oben ganz ohne Ende ist.\nBis einst mein Dank dort oben ganz ohne Ende ist!'),
(9, '1595', 'Seit ich sah mein Nam in dem Buch der Erlöung  -  Since I saw my Name in the Book of Redemption   (Chorus)', 'Since I saw my Name in the book of redemption,\nsince I saw my Name in the book.\nI have communion now with Christ my redeemer,\nsince I saw my Name in the Book.', 'Seit ich sah mein\' Nam\' in dem Buch der Erlösung,\nseit ich sah mein\' Nam\' ich dem Buch.\nBin ich so froh für meinen Erlöser,\nseit ich sah mein\' Nam\' in dem Buch.'),
(9, '1596', 'Seit so vielen Jahren säen die Menschen Samen  -  Sowing in the Morning, sowing Seeds of Kindness   (Bringt die Garben ein)', 'Sowing in the morning, sowing seeds of kindness,\nsowing in the noontide and the dewy eve.\nWaiting for the harvest and the time of reaping,\nwe shall come rejoicing, bringing in the sheaves.\r\nBringing in the sheaves, bringing in the sheaves,\nwe shall come rejoicing, bringing in the sheaves.\nBringing in the sheaves, bringing in the sheaves,\nwe shall come rejoicing, bringing in the sheaves.\r\nSowing in the sunshine, sowing in the shadows,\nfearing neither clouds nor winter\'s chilling breeze.\nBy and by the harvest and the labour ended,\nwe shall come rejoicing, bringing in the sheaves.\r\nGoing forth with weeping, sowing for the Master,\nthough the loss sustained, our spirit often grieves.\nWhen our weeping\'s over, He will bid us welcome,\nwe shall come rejoicing, bringing in the sheaves.\r\n\r\n', 'Seit so vielen Jahren säen die Menschen Samen,\nja, das Wort des Herrn, so kostbar und so fein.\nBald schon ist die Ernte, bald schon wirst du hören,\nwie es oben tönet: "Bringt die Garben ein!"\r\nBringt die Garben ein, bringt die Garben ein,\no welch\' eine Freude.\nbringt die Garben ein, bringt die Garben ein!\r\nHast du schon vernommen, Abend ist gekommen,\nund der Engel schwor, das Zeit wird nicht mehr sein.\nViel wird nicht mehr fehlen, nur noch ein paar Seelen,\nbis der Meister rufet: "Bringt die Garben ein!"\r\nHerr, ich kann es sehen, etwas wird geschehen,\nHerr, ich bete, mach mich vor Dir klar und rein.\nIch will Dich nicht lassen, will Dich nicht verpassen,\nich will selber hören: "Bringt die Garben ein!"\r\nEinst da muss der Weizen in die Erde fallen,\ndenn der Herr Er wollte bleiben nicht allein.\nHat\'s gesät mit Tränen, dass wir zu Ihm kämen\nund mit Freuden hörten: "Bringt die Garben ein!"\r\nHerr, ich kann es sehen, die Sonne untergehen.\nMach\' mich jetzt bereit, denn bald zu spät wird\'s sei!\nIch seh\' meinen Heiland in dem Felde stehen,\nsehnt sich nach der Braut, ja bald führt Er sie heim!'),
(9, '1597', 'Selig ein Herz, das wie Schnee ist so rein  -  Oh, for a Heart that is whiter than Snow   (Selig ein Herz, weiß wie der Schnee)', 'Oh, for a heart that is whiter than snow,\nkept, ever kept ’neath the life-giving flow.\nCleansed from all passion, self-seeking and pride,\nwashed in the fountain of Calvary’s tide.\r\nOh, for a heart whiter than snow!\nSaviour divine, to whom else shall I go?\nThou who didst die, loving me so,\ngive me a heart that is whiter than snow!\r\nOh, for a heart that is whiter than snow!\ncalm in the peace that He loves to bestow.\nDaily refreshed by the heavenly dews,\nready for service whene’er He shall choose.\r\nOh, for a heart that is whiter than snow!\nwith the pure flame of the Spirit aglow.\nFilled with the love that is true and sincere,\nlove that is able to banish all fear.\r\nOh, for a heart that is whiter than snow!\nthen in His grace and His knowledge to grow,\ngrowing like Him who my pattern shall be,\ntill in His beauty my King I shall see.', 'Selig ein Herz, das wie Schnee ist so rein,\nBergung sich sucht unterm Kreuze allein,\ndas dort dort Erlösung von Sünde und Not\nReinigung fand in des Heilandes Tod.\r\nSelig ein Herz, weiß wie der Schnee!\nJesus, wer anders, heilt Sünde und Weh.\nDu, der Du starbst, liebst mich allein,\ngib mir ein Herz, das wie Schnee ist so rein.\r\nSelig ein Herz, das wie Schnee ist so rein!\nRuhend in Jesus kann selig es sein.\nTäglich erquickt sich\'s auf grünender Flur,\nfreut sich des Hirten und folgt Seiner Spur.\r\nSelig ein Herz, das wie Schnee ist so weiß,\nglühend für Jesus in Liebe so heiß,\nleuchtend für Ihn, dessen Liebe allein\nfrei uns gemacht von Verdammnis und Pein.\r\nSelig ein Herz, das wie Schnee ist so weiß,\nstark in der Gnade, dem Heiland zum Preis,\nähnlich dem Meister und wachsend wie Er,\nbis es Ihn schaut mit dem himmlischen Heer.'),
(9, '1598', 'Selig ist\'s, dem Herrn vertrauen  -  \'Tis so sweet to trust in Jesus   (Jesus, Jesus, Dir vertrau ich)', '\'Tis so sweet to trust in Jesus,\njust to take him at his word.\nJust to rest upon his promise,\njust to know, "Thus saith the Lord."\r\nJesus, Jesus, how I trust Him!\nHow I\'ve proved Him o\'er and o\'er!\nJesus, Jesus, precious Jesus!\nOh, for grace to trust Him more!\r\nOh, how sweet to trust in Jesus,\njust to trust His cleansing blood.\nJust in simple faith to plunge me\n\'neath the healing, cleansing flood!\r\nYes, \'tis sweet to trust in Jesus,\njust from sin and self to cease.\nJust from Jesus simply taking\nlife and rest, and joy and peace.\r\nI\'m so glad I learned to trust Him,\nprecious Jesus, Saviour, Friend.\nAnd I know that He is with me,\nWill be with me to the end.', 'Selig ist\'s, dem Herrn vertrauen,\nnimmt getrost Ihn nur beim Wort.\nGründe dich auf die Verheißung,\nwas Er sagt, gilt ewig fort.\r\nJesus, Jesus, Dir vertrau ich,\nDeine Treu hab ich erprobt.\nJesus, Jesus, Dir vertrau ich\newiglich, sei hochgelobt!\r\nSelig ist\'s, dem Herrn vertrauen,\nsich zu gründen auf Sein Blut.\nSich im Glauben einzutauchen\ntief in diese heil\'ge Flut.\r\nSelig ist\'s, dem Herrn vertrauen,\nfrei vom eignen schlimmen "Ich".\nNur aus Seiner Hand zu nehmen\nFried\' und Freude ewiglich.\r\nDank sei Dir, dass Du mich lehrtest,\nDir, Herr Jesus, zu vertrau\'n.\nIn Dir woll\'st Du mich bewahren,\nbis Dich meine Augen schau\'n.'),
(9, '1599', 'Selig, ja selig zu ruhen in Dir', NULL, 'Selig, ja selig zu ruhen in Dir,\nselig, ja selig zu ruhen in Dir,\nstets nur zu wandeln an Deiner Hand,\nglauben und schauen das Heimatland.\r\nSelig, ja selig zu ruhen in Dir,\nStröme des Friedens, Herr, schenkest Du mir,\nfroh darf ich wandeln an Deiner Hand,\nglauben und schauen das Heimatland.\r\nSelig, ja selig zu ruhen in Dir,\nbleibende Freude verheißest Du mir,\nall meine Sünden vergeben sind!\nVater, mein Vater, ich bin ja Dein Kind!\r\nSelig, ja selig zu ruhen in Dir,\nDu, Herr, weckst Jubelgesänge in mir.\nFrei bin ich, los von des Feindes Macht!\nJesus, mein Jesus, Dein Blut hat\'s vollbracht!\r\nHeilig, ja heilig, o Herr, darf ich sein!\nDu machst mein Leben wie Deines so rein,\nDu taufst mit Geist mich und Feuer nun.\nPreis Dir! Du lässt Deinen Geist auf mir ruh\'n!\r\nHerrlich, ja herrlich, o Jesus bist Du!\nGlückselig eilen die Deinen Dir zu,\nwenn Du uns rufst mit Posaunenschall,\nund wir Dir folgen zum Hochzeitssaal.'),
(9, '1600', 'Seliges Wissen, Jesus ist mein  -  Blessed assurance, Jesus is mine   (Das muss ich singen Jesus zur Ehr)', 'Blessed assurance, Jesus is mine,\noh, what a foretaste of glory divine!\nHeir of salvation, purchase of God,\nborn of His Spirit, washed in His blood.\r\nThis is my story, this is my song,\npraising my Saviour all the day long.\nThis is my story, this is my song,\npraising my Saviour all the day long.\r\nPerfect submission, perfect delight,\nvisions of rapture now burst on my sight.\nAngels descending, bring from above\nechoes of mercy, whispers of love.\r\nPerfect submission, all is at rest,\nI in my Saviour am happy and blest.\nWatching and waiting, looking above,\nfilled with His goodness, lost in His love.\r\nThis is my boast, my song of joy:\nPraise Thee my Jesus, all the day long.\nThis is my boast, my song of joy:\nPraise Thee my Jesus, all the day long.', 'Seliges Wissen: "Jesus ist mein",\nfüllt mir das Herz mit himmlischem Schein;\nwiedergeboren, frei von der Sünd\',\nunseres Gottes herrliches Kind.\r\nDas muss ich singen Jesus zur Ehr\',\nEr ist mein Rühmen, einzig nur Er,\nLicht mir und Leben, mein Sonnenschein,\no Du mein Alles, Du nur allein!\r\nZu Deinen Füßen, o Herrlichkeit!\nSeh\' ich den Himmel offen mir weit.\nFluten der Liebe, Ströme der Gnad\'\nrauschen herab den himmlischen Pfad.\r\nWachend und wartend blick ich empor,\nbis meine Seel\' in Ihm sich verlor.\nVon Seinem Wesen völlig erfüllt,\nwerd\' ich verwandelt ganz in sein Bild.\r\nDas ist mein Rühmen, mein Jubelsang:\nPreis Dir, mein Jesus, mein Leben lang.\nDas ist mein Rühmen, mein Jubelsang:\nPreis Dir, mein Jesus, mein Leben lang.');
INSERT INTO song_list (LISTID, NUM, NAME, TEXT_EN, TEXT_DE) VALUES
(9, '1601', 'Seligkeit ist den Herrn zu kennen  -  Happiness is to know the Saviour   (Die Freud ist mein, wenn auch Tränen werden sein)', 'Happiness is to know the Saviour,\nliving a life within His favour,\nhaving a change in my behaviour,\nhappiness is the Lord.\r\nReal joy is mine,\nno matter if the teardrops start.\nI\'ve found a secret,\nit\'s Jesus in my heart.\r\nHappiness is to be forgiven,\nliving a life that\'s worth the livin\',\ntaking a try that leads to Heaven,\nhappiness is the Lord.\r\nHappiness is a new creation,\nJesus and me in close relation,\nhaving a part in His salvation,\nhappiness is the Lord.', 'Seligkeit ist den Herrn zu kennen.\nLeben, begnadet im ew\'gen Leben.\nVerwandlung erleben, in meinem Benehmen,\nSeligkeit ist der Herr!\r\nDie Freud\' ist mein,\nwenn auch Tränen werden sein.\nIch fand dies Geheimnis, Jesus in mir allein.\r\nSeligkeit ist: Total vergeben,\nleben ein Leben, das lohnt zu leben,\nwandeln im Licht des ew\'gen Lebens,\nSeligkeit ist der Herr!\r\nSeligkeit ist die neue Schöpfung,\nJesus und ich in engster Verbindung,\nbin ich ein Teil in Seiner Erlösung,\nSeligkeit ist der Herr!'),
(9, '1602', 'Send die Kraft jetzt, o Herr', NULL, 'Send\' die Kraft jetzt, o Herr!\nSend\' die Kraft jetzt, o Herr!\nSend\' sie brausend und wogend\ngleich den Wellen im Meer.\nSende Fluten des Segens\ndurch die Lande allhier,\neine große Erweckung\nund beginn sie in mir.'),
(9, '1603', 'Send down the Rain', 'Send down the rain,\nsend down the rain,\nsend down the latter rain.\nSend down the rain,\nsend down the rain,\nSend down the latter rain.\r\nWe need the rain, Lord...\nWe need the rain, Lord...', NULL),
(9, '1604', 'Set my Spirit free, that I might worship Thee   (Chorus)', 'Set my spirit free, that I might worship Thee,\nset my spirit free, that I might prais Thy name.\nLet al bondage go, let Your deliverance flow.\nSet my spirit free, to worship Thee.', 'Befreie meinen Geist, damit ich Dich anbeten kann,\nbefreie meinen Geist, damit ich Deinen Namen preise.\nLass alle Fesseln los, lass Deine Erlösung fließen.\nBefreie meinen Geist, damit ich Dich anbeten kann.'),
(9, '1605', 'Set your Wings - (Du kannst zwei Wege gehen  -  There are two Roads you may take)', 'There are two roads you may take,\nOne by sight and one by faith.\nTake the word of god or what you see,\nWhat you believe is what will be.\r\nSet your wings to the winds of faith,\nYou can fly in a higher place.\nDo not struggle it\'s by grace,\nSet your wings to the winds of faith.\r\nWhat\'s your need and what\'s your cry,\nWhat\'s your mountain, much too high.\nSpeak the word of god and by and by ,\nit will move or you will fly.\r\nWatch the eagle in the sky,\nIt does not struggle it does not strive.\nFor the power that makes him rise,\nIs already in the sky.', '(Du kannst zwei Wege gehen,\nEinen durch Sehen, einen durch Glauben.\nNimm das Wort Gottes oder das was du siehst,\nWas du glaubst wird geschehen.)\r\nLege deine Flügel in den Wind des Glaubens.\nDu kannst an einem höheren Ort fliegen.\nKämpfe nicht, es ist durch Glauben,\nLege deine Flügel in den Wind des Glaubens.\r\n(Was ist deine Not und was ist dein Schrei,\nWas ist dein Berg, viel zu hoch.\nSprich das Wort Gottes und nach und nach,\nWird er weichen oder du wirst fliegen.)\r\nBeachte den Adler im Himmel,\nEr kämpft und müht sich nicht.\nDenn die Kraft die ihn erheben wird,\nIst bereits im Himmel.'),
(9, '1606', 'Shalom', 'Shalom, Shalom,\nPeace and good morning,\nHe is on the throne,\nShalom, Shalom,\nWe are almost home', NULL),
(9, '1607', 'Shine Your Light, shine Your Light   (2 Chorusse)', 'Shine Your light, shine Your light,\nshine Your light on me Jesus.\nShine Your light, shine Your light,\nshine Your light on me, Jesus.\r\nShine, shine, shine, shine,\nshine on me, Jesus.\nShine Your light, shine Your light,\nshine Your light on me, Jesus.', NULL),
(9, '1608', 'Sicher in Jesu Armen, sicher an seiner Brust  -  Safe in the Arms of Jesus, safe on His gentle Breast', 'Safe in the arms of Jesus, safe on His gentle breast,\nthere by His love o\'ershaded, sweetly my soul shall rest.\nHark! \'Tis the voice of angels, borne in a song to me,\nover the fields of glory, over the jasper sea.\r\nSafe in the arms of Jesus, safe from corroding care,\nsafe from the world\'s temptations sin cannot harm me there.\nFree from the blight of sorrow, free from my doubts and fears,\nonly a few more trials, only a few more tears!\r\nJesus, my heart\'s dear refuge, Jesus has died for me,\nfirm on the rock of ages, ever my trust shall be.\nHere let me wait with patience, wait till the night is o\'er,\nwait till I see the morning, break on the golden shore.', 'Sicher in Jesu Armen, sicher an Seiner Brust,\nruhend in Seiner Liebe, da find\' ich Himmelslust. ||\nMit holder Hirtenstimme ruft mir mein Heiland zu:\n"Lass ab vom eignen Ringen, an Meinem Herzen ruh\'!"\n(Wiederholen vom Versanfang bis ||)\r\nSicher in Jesu Armen, los von der Sorge Qual,\nsicher in der Versuchung durch Jesu Wundenmal! ||\nFrei von dem Druck des Kummers, frei von des Zweifels Pfad,\nnur noch ein wenig Prüfung, nur etwas Tränensaat!\n(Wiederholen vom Versanfang bis ||)\r\nJesus, des Herzens Zuflucht, Jesus, Du starbst für mich!\nSicher auf diesen Felsen stütz\' ich mich ewiglich. ||\nHier will ich stille warten, bis dass vergeht die Nacht,\nbis an dem goldnen Ufer leuchtend der Tag erwacht.\n(Wiederholen vom Versanfang bis ||)'),
(9, '1609', 'Sie banden Seine Hände, wo einst Er im Gebet  -  They bound the Hands of Jesus   (Er rief nicht nach zehntausend Engeln)', 'They bound the hands of Jesus in the garden where he prayed.\nThey led him thru the streets in shame.\nThey spat upon the saviour, so pure and free from sin,\nthey said, "crucify him: he\'s to blame!"\r\nHe could have called ten thousand angels\nto destroy the world and set him free.\nHe could have called ten thousand angels\nbut he died alone, for you and me.\r\nUpon his precious head they placed a crown of thorns.\nThey laughed and said, "Behold the king".\nThey struck him and they cursed him and mocked his holy name.\nAll alone he suffered everything.\r\nWhen they nailed him to the cross, his mother stood nearby,\nHe said, "Woman, behold thy son!"\nHe cried, "I thirst for water," but they gave him none to drink.\nThen the sinful work of man was done.\r\nTo the howling mob he yielded: he did not for mercy cry.\nThe cross of shame he took alone.\nAnd when he cried, "It’s finished," he gave himself to die.\nSalvation\'s wondrous plan was done.\r\nYou have heard the word, the rest is now up to you,\ndecide, there is still time for you!\nYes, Jesus is the life, only He has accomplished it.\nSo come to Him and get ready today!', 'Sie banden Seine Hände, wo einst Er im Gebet,\nund führten Ihn gefangen mit sich fort.\nSie schmähten den Erretter, der sündlos, rein und still:\n"Hinweg mit Ihm!", so rief das ganze Volk.\r\nEr rief nicht nach zehntausend Engeln,\nnahm keine Kraft, zu retten Sich.\nEr rief nicht nach Zehntausend Engeln,\nEr starb am Kreuz für dich und mich.\r\nSein Haupt es ward gekrönet mit Dornen und mit Schmach,\nsie spotteten und schlugen Ihn.\nSie rissen seine Kleider für Schläge Ihm vom Leib.\nDoch wie ein Lamm nahm Er dies\' alles hin.\r\nMaria war Ihm nahe, als einst am Kreuz Er hing\nsich selbst vergessend sorgte Er für sie.\nIm Kampf rief Er: "Mich dürstet!" und Essig man Ihm gab.\nEr nahm den Tod, der Sünde Lohn auf sich.\r\nDem Mob ganz ausgeliefert, Er nicht um Gnade bat,\nden Kreuzestod Er willig auf sich nahm.\n"Es ist vollbracht!" ausrufend, in Schmerzen Er verblich.\ndas Meisterwerk der Liebe war getan.\r\nDas Wort hast du vernommen, der Rest liegt jetzt bei dir,\nentscheide dich, es ist für dich noch Zeit!\nJa, Jesus ist das Leben, nur Er hat es vollbracht.\nSo komm zu Ihm und mach dich heut\' bereit!'),
(9, '1610', 'Sie jauchzet doch mit Freuden, die heilge Gottesstadt', NULL, 'Sie jauchzet doch mit Freuden, die heil\'ge Gottesstadt,\ndie sich durch Jesu Leiden vor nichts zu fürchten hat!\nDenn Gott ist bei ihr drinnen, Er hilft ihr früh und spät,\ndas macht die Furcht zerrinnen und stärket zum Gebet.\r\nLass andre wankend fragen, ob Gott ihr Vater sei?\nEin Christ kann mutig sagen, kann schwören wohl dabei:\n"Ich habe Heil gefunden, die Seligkeit ist mein;\ndurch meines Mittlers Wunden geh ich zum Himmel ein."\r\nEin wahrer Christ ist selig, der Christum recht erkennt,\nder seine Schuld unzählig und sich verloren nennt;\nder alles flieht und hasset, was nur dem Fleisch gefällt,\nder Jesum gläubig fasset und über alles hält.\r\nJa, selig sind die Christen, die ohne Falsch besteh\'n.\nO, dass es alle wüssten, die noch zur Hölle geh\'n!\nWer ist so reich und prächtig, so schön vergnügt und satt,\nso fröhlich, stark und mächtig, als wer den Glauben hat?\r\nBehalte, Welt, das Deine, das mit dem Tod zerfällt!\nIn Christi Gnadenscheine durchwall in diese Welt.\nWenn alle Reichtum darben, wenn Fürsten betteln geh\'n,\nwill ich mit Freudengarben in Zions Toren steh\'n!'),
(9, '1611', 'Sie kommen von Ost und West  -  They come from the East and West   (Sie kommen von stürm\'scher Flut)', 'They come from the east and west,\nthey come from the lands afar,\nto feast with the King, to dine as His guest,\nhow blessed these pilgrims are!\nBeholding His hallowed face\naglow with light divine.\nBlest partakers of His grace,\nas gems in His crown to shine.\r\nSince Jesus has set me free,\nI’m happy as heart can be.\nNo longer I bear the burden of care,\nHis yoke is so sweet to me.\nMy soul was as black as night,\nbut darkness as taken flight.\nNow I shout the victory,\nfor Jesus has set me free.\r\nI look on the great white throne,\nbefore it the ransom’d stand.\nNo longer are tears, no sorrow is known\nnor death in that goodly land.\nMy Saviour has gone before,\npreparing the way for me.\nSoon we’ll meet to part no more\nthrough time or eternity.\r\nThe gates of that holy place,\nstand open by night and day.\nOh look to the Lord who giveth more grace,\nwhose love has prepar’d the way.\nA home in those mansions fair,\nHis hand hath reserved for all.\nFor the wedding feast prepare,\nobeying the gracious call.\r\nOh, Jesus is coming soon,\nour trials will then be o\'er.\nWhat, if our Lord this moment,\nshould come for those who are free from sin?\nThen would it bring you joy,\nor sorrow and deep despair?\nWhen our Lord in Glory comes,\nwe\'ll meet Him up in the air.', 'Sie kommen von Ost und West,\nsie kommen von Süd und Nord,\nsie sitzen beim Mahl im himmlischen Saal\nund hören des Heilands Wort.\nSie schauen Sein Antlitz hold, sie trinken dort Seligkeit,\nsingen Jubellieder dort in alle Ewigkeit.\r\nSie kommen von stürm\'scher Flut,\nsie kommen vom dorn\'gen Pfad,\nsie kommen vom Berg,\nsie kommen vom Tal\nzum Ort, wo die Seele ruht!\nSie tragen das Hochzeitskleid; sie treffen den Bräutigam,\nder sie einst mit Blut erkauft\nam harten Kreuzesstamm.\r\nDa sammelt der Herr die Schar,\nerlöst von der Sorge Pein.\nNicht Sünde und Not, nicht Krankheit und Tod,\nnicht Nacht wird dort jemals sein.\nDas Alte, es ist vorbei, der Herr machte alles neu.\nLob und preis dem Lamm erklingt\nfür Seine Lieb und Treu.\r\nSchau hin in das off\'ne Buch,\ndeine Name schon lang dort steht.\nDurch Gnade wir seh\'n, was vormals gescheh\'n,\nund dies gibt uns frohen Mut.\nDie Heiligen harren Dein,\nmit Sehnsucht so lange schon,\nbis auch wir bereitet sind, zu steh\'n vor Gottes Thron.\r\n'),
(9, '1612', 'Sieg ist mein, Sieg ist heute mein  -  Victory is mine, Victory today is mine   (3 Chorusse)', 'Victory is mine! Victory is mine!\nVictory today is mine!\nI told satan: "Get thee behind!"\nVictory today is mine!\r\nJoy is mine! Joy is mine!\nJoy today is mine!\nI told satan: "Get thee behind!"\nJoy today is mine!\r\nPeace is mine! Peace is mine!\nPeace today is mine!\nI told satan: "Get thee behind!"\nPeace today is mine!', 'Sieg ist mein, Sieg ist mein,\nSieg ist heute mein.\nSatan ist besiegt, glaub es und er flieht,\nSieg ist heute mein!\r\nFreude ist mein, Freude ist mein,\nFreude ist heute mein.\nSatan ist besiegt, glaub es und er flieht,\nFreude ist heute mein!\r\nFriede ist mein, Friede ist mein,\nFriede ist heute mein.\nSatan ist besiegt, glaub es und er flieht,\nFriede ist heute mein!'),
(9, '1613', 'Siegreich wirst du triumphieren', NULL, 'Siegreich wirst du triumphieren,\nwenn auch noch so heiß die Schlacht,\nnur den Glauben nicht verlieren\nund nicht seh\'n auf Feindesmacht!\nNur den Blick aufs Kreuz gerichtet,\nwo der Sieg schon längst erkämpft,\nwo die Feinde sind geflüchtet\nund die finst\'re Macht gedämpft.\r\nSiegreich will ich vorwärts schreiten,\nob verwundet auch das Herz,\nob durch Fallen auch und Gleiten,\nob durch tiefen Seelenschmerz.\nDennoch muss es immer heißen:\n"Siegreich auf der Siegesbahn!"\nNichts kann mich von Jesus reißen.\nVorwärts aufwärts, himmelan!\r\nSiegreich immer fortgerungen,\nachtend nicht des Feindes Wehr!\nGlaubend, hoffend durchgedrungen!\nVor dem Glauben fliehet er.\nSiegreich einstens heimzukehren\naus dem heißen, schweren Strauß,\nbringt dem Streiter hohe Ehren,\nwenn er kommt ins Vaterhaus.\r\nD\'rum im Kampf nur nicht ermatten!\nGlaubend bleib am Kreuz ich steh\'n,\nfürchte nicht des Todes Schatten,\nmag auch alles untergeh\'n.\nSiegreich seh\' ich droben\nwinken leuchtend mir die Siegeskron\',\nunvergänglich, himmlisch blinken,\ndargereicht vom Gottessohn.'),
(9, '1614', 'Sieh hier bin ich, mein König, ich weihe mich Dir  -  Empty me of self, my gracious Lord   (Mach was klein Dir, mir klein, was Dir groß ist, mir groß)', 'Empty me of self, my gracious Lord,\ntake away all hindrance to Thy word.\nBring my will with Thine in sweet accord,\nfill me with Thy love.\r\nEmpty me of self, almighty Saviour,\nempty me of self and lift my heart above.\nFill me with Thy blessed Holy Spirit,\nfill me with Thy love.\r\nEmpty me of self, that Thou mayst see\nThine own holy likeness formed in me.\nConsecrated fully, Lord to Thee,\nfill me with Thy love.\r\nEmpty me of self, that I may give\nwitness to the faith by which I live.\nWitness to the blessings I receive,\nfill me with Thy love.\r\nEmpty me of self, that I may bring\nglad and ready service to my King.\nSweetest hallelujahs then I’ll sing,\nfill me with Thy love.', 'Sieh, hier bin ich, mein König, ich weihe mich Dir\nnimm, gebrauche mich, Herr, wie Du willst.\nAch, ich weiß nichts, was Wert hat, ist irgend an mir,\nnichts, wenn Du mich nicht selber erfüllst.\r\nMach was klein Dir, mir klein, was Dir groß ist, mir groß,\ndass ich folge Dir, Jesus, allein.\nMach vom eigenen Sinn, von mir selber mich los,\nlass ein brauchbares Werkzeug mich sein!\r\nSieh, hier bin ich, mein König, mein Herze das brennt,\nDir zu dienen, wo du es begehrst.\nGib, dass völlig Dein Geist vom Verlangen mich trennt,\nmir zu nehmen, was Du nicht gewährst!\r\nSieh, hier bin ich, mein König, und ist meine Hand\nnicht geschickt für den vordersten Streit,\nso verzäune die Lücken und bessre das Land\ndoch durch mich, denn ich bin in Dir geweiht.\r\nSieh, hier bin ich, mein König, ob niemand es weiß,\nwenn Dein Auge nur über mir wacht,\nwenn ich da, wo ich steh, tu\' nach Deinem Geheiß,\nbin ich glücklich bei Tag und bei Nacht.'),
(9, '1615', 'Sieh wie einst im fremden Land  -  Standing by a Purpose true   (O so machs wie Daniel)   [Gospel Hymns Band 1]', 'Standing by a purpose true,\nheeding God\'s command,\nhonor them, the faithful few!\nAll hail to Daniel\'s band!\r\nDare to be a Daniel!\nDare to stand alone!\nDare to have a purpose firm!\nDare to make it known!\r\nMany mighty men are lost,\ndaring not to stand,\nwho for God had been a host\nby joining Daniel\'s band.\r\nHold the gospel banner high,\non to vict\'ry grand.\nSatan and his host defy,\nand shout for Daniel\'s band.', 'Sieh, wie einst im fremden Land,\nfest bei Gottes Wort,\nDaniels kleines Häuflein stand\nsogar in Babel dort.\r\nO so mach\'s wie Daniel,\nstehe fest im Herrn!\nWag\' es mit getrostem Mut,\nzeuge für ihn gern!\r\nO, wie würd\' für Gottes Reich\nmancher noch ein Held,\nwürd\' er nur dem Daniel gleich,\nstatt dass er schmählich fällt.\r\nHebe Christi Fahne hoch,\nauf, die Zeit verrinnt!\nSatans Heer muss fliehen noch,\nund Daniels Schar gewinnt.'),
(9, '1616', 'Sieh, Gottes Lamm vergoss sein Blut an dem Kreuz', NULL, 'Sieh, Gottes Lamm vergoss sein Blut\nan dem Kreuz, an dem Kreuz!\nO glaub\'s, es starb auch dir zugut\nan dem Kreuz, an dem Kreuz!\nWohl tobt der Hölle finst\'re Macht,\ndoch horch dem Ruf: Es ist vollbracht!\nHeil dir, die Gnadensonne lacht a\nan dem Kreuz, an dem Kreuz!\r\nIch zeuge, wo ich geh und steh,\nvon dem Kreuz, von dem Kreuz!\nUnd bringe Ehr\' Gott in der Höh\'\nfür das Kreuz, für das Kreuz!\nMein Jubel schalle weit und breit\nin Zeit und alle Ewigkeit,\ndass Jesus mich vom Tod befreit\nan dem Kreuz, an dem Kreuz!\r\nAch, dass doch jeder Sünder dräng\'\nzu dem Kreuz, zu dem Kreuz!\nUnd jedes Christen Herze säng\'\nbei dem Kreuz, bei dem Kreuz!\nIhr Pred\'ger, hier sei euer Stand,\nwo, mit der Bibel in der Hand,\nihr preiset Jesus unverwandt,\nunterm Kreuz, unterm Kreuz!'),
(9, '1617', 'Sieh, wer steht vor deiner Tür? Lass den Heiland ein  -  There’s a Stranger at the Door, let Him in', 'There’s a Stranger at the door,\nlet Him in.\nHe has been there oft before,\nlet Him in.\nLet Him in, ere He is gone,\nlet Him in, the Holy One.\nJesus Christ, the Father’s Son,\nLet Him in.\r\nOpen now to Him your heart,\nlet Him in.\nIf you wait He will depart,\nlet Him in.\nLet Him in, He is your Friend.\nHe your soul will sure defend,\nHe will keep you to the end,\nlet Him in.\r\nHear you now His loving voice?\nLet Him in;\nNow, oh, now make Him your choice,\nLet Him in;\nHe is standing at your door,\nJoy to you He will restore,\nAnd His Name you will adore,\nLet Him in.\r\nNow admit the heav’nly Guest,\nlet Him in.\nHe will make for you a feast,\nlet Him in.\nHe will speak your sins forgiv’n,\nand when earth ties all are riv’n,\nHe will take you home to heav’n.\nLet Him in.', 'Sieh, wer steht vor deiner Tür?\nLass den Heiland ein! Lass den Heiland ein!\nOft schon klopfte Er bei dir!\nLass den Heiland ein! Lass den Heiland ein!\nLass verstreichen nicht die Frist,\nlass Ihn ein, der heilig ist,\nDeinen König, Jesus Christ!\nLass den Heiland ein! Lass den Heiland ein!\r\nÖffne Ihm doch jetzt dein Herz!\nLass den Heiland ein! Lass den Heiland ein!\nWenn du säumst, machst du Ihm Schmerz.\nLass den Heiland ein! Lass den Heiland ein!\nLass Ihn ein, Er ist dein Freund,\nder es stets so treu gemeint\nund Sich gern mit dir vereint.\nLass den Heiland ein! Lass den Heiland ein!\r\nHörst du Seine Liebesstimm\'?\nLass den Heiland ein! Lass den Heiland ein!\nO, so übergib dich Ihm!\nLass den Heiland ein! Lass den Heiland ein!\nEr steht bittend vor der Tür,\nwahre Freude schenkt Er dir,\ndass du ewig dankst dafür!\nLass den Heiland ein! Lass den Heiland ein!\r\nSchließ\' nicht aus des Himmels Gast!\nLass den Heiland ein! Lass den Heiland ein!\nDenn in Ihm allein ist Rast!\nLass den Heiland ein! Lass den Heiland ein!\nDer von Sünden frei dich spricht,\nund, wenn ird\'sche Fessel bricht,\nheim dich holt zum ew\'gen Licht.\nLass den Heiland ein! Lass den Heiland ein!'),
(9, '1618', 'Siehst du nicht meine Freude  -  Can\'t you see why I\'m happy', 'Can\'t you see why I\'m so happy?\nI\'ve accepted the Word of the Lord.\nThe revealed Word that was spoken\nby the prophet of Malachi four.', 'Siehst du nicht meine Freude?\nIch nahm an das Wort des Herrn.\nGeoffenbartes Wort gesprochen\nvom Propheten aus Maleachi vier.'),
(9, '1619', 'Sing it in the Valleys, shout it from the Mountain Tops', 'Sing it in the valleys,\nshout it from the mountain tops.\nJesus came to save us,\nand His saving never stops.\nHe is King of kings,\nand new life He brings,\nsing it in the valleys,\nshout it from the mountain tops,\n(Oh!) shout it from the mountain tops.\r\nJesus You are by my side,\nYou take all my fears.\nIf I only come to You,\nYou will heal the pain of years.\r\nYou have not deserted me,\nthough I go astray.\nJesus take me in Your arms,\nhelp me walk with You today.\r\nJesus, You are living now,\nJesus, I believe.\nJesus, take me, heart and soul,\nyours alone I want to be.', NULL),
(9, '1620', 'Sing mit mir ein Halleluja   Für die Ruhe in der Nacht ...', NULL, 'Sing mit mir ein Halleluja,\nsing mit mir ein Dankeschön.\nDenn im Danken da liegt Segen\nund im Danken preis ich Ihn.\r\nFür die Ruhe in der Nacht.\nFür die Sonne, die mir lacht.\nfür die Luft, die mir den Atem gibt.\r\nFür die Freunde, die ich hab\'.\nFür die Liebe jeden Tag,\ndie aus Seiner großen Gnade quillt.\r\nFür das Wunder, das geschah\',\ndort am Kreuz auf Golgatha,\nals Er starb, damit ich leben kann.\r\nDafür, dass Er auferstand\'\nund der Hölle Macht gebannt,\ndafür, dass Er mich hat froh gemacht.\r\nDafür, dass Er heut\' noch lebt\nund mir treu zur Seite steht.\nDafür, dass mich Seine Liebe trägt.'),
(9, '1621', 'Sing to the Lord with all of your Heart   (You are the Lord, the Saviour of all)', 'Sing to the Lord with all of your heart,\nsing of the glory that\'s due to His name.\nSing to the Lord with all of your soul,\njoin all of heaven and earth to proclaim.\r\nYou are the Lord, the Saviour of all,\nGod of creation, we praise You.\nWe sing the song that awaken the dawn,\nGod of creation we praise You.\r\nSing to the Lord with all of your mind,\nwith understanding give thanks to the King.\nSing to the Lord with all of your strength,\nliving your life as a praise offering.', NULL),
(9, '1622', 'Sing unto the Lord a new Song', 'Sing unto the Lord a new song\ndance and praise Him\nlift him higher.\nAll ye chosen generation\ndance and celebrate. (2x)\r\nIf we lift Him higher will draw\nus ever nearer closer to Him\nday by day.', NULL),
(9, '1623', 'Singe Amen, Amen, Amen  -  Singing Amen, Amen, Amen', 'Singing Amen, amen, amen.  (3x)\nSinging Amen.\r\nSinging Maranata, amen, amen.  (3x)\nSinging Maranatha.\r\nSinging Halleluja, amen, amen.  (3x)\nSinging haleluja.', 'Singe Amen, Amen, Amen,\nsinge Amen, Amen, Amen,\nsinge Amen, Amen, Amen,\nsinge Amen!\r\nMaranatha, Amen, Amen,\nMaranatha, Amen, Amen,\nMaranatha, Amen, Amen,\nMaranatha!\r\nHalleluja, Amen, Amen,\nHalleluja, Amen, Amen,\nHalleluja, Amen, Amen,\nHalleluja!'),
(9, '1624', 'Singe mir es noch einmal vor  -  Sing them over again to me   (Liebliches Wort, herrliches Wort)', 'Sing them over again to me,\nwonderful words of Life.\nLet me more of their beauty see,\nwonderful words of Life.\nWords of life and beauty,\nteach me faith and duty:\r\nBeautiful words, wonderful words,\nwonderful words of Life.\nBeautiful words, wonderful words,\nwonderful words of life.\r\nChrist, the blessed One, gives to all,\nwonderful words of Life.\nSinner, list to the loving call,\nwonderful words of Life.\nAll so freely given,\nwooing us to heaven:\r\nSweetly echo the gospel call,\nwonderful words of Life.\nOffer pardon and peace to all,\nwonderful words of Life.\nJesus, only Saviour,\nsanctify forever:', 'Singe mir es noch einmal vor,\nwunderbar Lebenswort.\nDas mir öffnet des Himmels Tor,\nwunderbar Lebenswort.\nWort des ew‘gen Lebens,\nschalle nicht vergebens:\r\nLiebliches Wort, herrliches Wort,\nliebliches Wort, herrliches Wort,\nwunderbar Lebenswort!\r\nJesus hat noch für jedermann\nwunderbar Lebenswort.\nDarum höre, wer hören kann,\nwunderbar Lebenswort.\nAlles ist gegeben,\nwas man braucht zum Leben!\r\nRastlos schalle dein heller Ton,\nwunderbar Lebenswort.\nSünder, führe zu Gottes Thron,\nwunderbar Lebenswort.\nAlle Welt vergehet,\nJesus bleibt erhöhet.'),
(9, '1625', 'Singet froh von Jesu heilger Liebe  -  Sing the wondrous Love of Jesus   (Wenn wir ziehn in den Himmel)   [Bieselsberg]', 'Sing the wondrous love of Jesus,\nsing his mercy and his grace.\nIn the mansions bright and blessed\nhe\'ll prepare for us a place.\r\nWhen we all get to heaven,\nwhat a day of rejoicing that will be!\nWhen we all see Jesus\nwe\'ll sing and shout the victory.\r\nWhile we walk the pilgrim pathway\nclouds will overspread the sky.\nBut when traveling days are over,\nnot a shadow, not a sigh.\r\nLet us then be true and faithful,\ntrusting, serving every day;\njust one glimpse of Him in glory\nwill the toils of life repay.\r\nOnward to the prize before us,\nsoon His beauty we\'ll behold.\nSoon the pearly gates will open,\nwe shall tread the streets of gold.', 'Singet froh von Jesu heil\'ger Liebe,\npreiset seine große Gütigkeit!\nIn dem schönen, lichten Himmel\nhat er uns ein Heim bereit\'t!\r\nWenn wir zieh\'n in den Himmel,\nwelch ein Tag voller Jubel wird das sein!\nWenn wir seh\'n den Heiland,\nwir singen Ehre Ihm allein!\r\nWährend wir auf Pilgerpfaden gehen,\nhüllen dunkle Wolken uns oft ein.\nDoch sind wir ans Ziel gekommen,\nleuchtet heller Sonnenschein.\r\nLasst uns treu und freudig Jesus dienen,\nvoll Vertrauen folgen Tag für Tag.\nWenn wir Ihn in Klarheit sehen\nfolgt die Herrlichkeit danach.\r\nVorwärts denn es winkt die Lebenskrone,\nbald wir Ihn in Seiner Schönheit seh\'n.\nOffen steh\'n die Perlentore\nund wir werden bei Ihm steh\'n.'),
(9, '1626', 'Singt dem Herrn ein neues Lied', NULL, 'Singt dem Herrn ein neues Lied\nSingt dem Herrn alle Welt\nSingt dem Herrn und preist seinen Namen\n(2x)\nBetet an den Herrn in heiliger Pracht\nDenn so groß ist der Herr in Stärke und Macht\nBetet an den Herrn in heiliger Pracht\nGebt dem Herrn alle Ehre und Macht'),
(9, '1627', 'Singt Halleluja unserm Herrn  -  Sing Hallelujah to the King  -  Chante Alléluia au Seigneur', 'Singt Hallelujah unserm Herrn,\nsingt Hallelujah unserm Herrn,\nsingt Hallelujah, singt Halleluja,\nsingt Hallelujah unserm Herrn!\nSing Halleluja to the King,\nsing Halleluja to the King,\nsing Halleluja, sing Hallelujah,\nsing Halleluja to the King.\nChante Alléluia au Seigneur,\nchante Alléluia au Seigneur,\nchante Alléluia, chante Alléluia,\nchante Alléluia au Seigneur.\r\nJesus died for us on the cross,\nJesus died for us on the cross,\nJesus died for us, Jesus died for us,\nJesus died for us on the cross,\r\nJesus is coming for his bride\nJesus is coming for his bride\nJesus is coming, Jesus is coming\nJesus is coming for his bride.', '\r\nJesus starb für uns an dem Kreuz,\nJesus starb für uns an dem Kreuz,\nJesus starb für uns, Jesus starb für uns,\nJesus starb für uns an dem Kreuz\r\nJesus kommt wieder für die Braut,\nJesus kommt wieder für die Braut,\nJesus kommt wieder, Jesus kommt wieder,\nJesus kommt wieder für die Braut.'),
(9, '1628', 'Singt unserm Herren, alle Welt, mit großer Dankbarkeit!', NULL, 'Singt unserm Herren, alle Welt, mit großer Dankbarkeit!\nDem, der uns schuf und uns erhält, sei Ehre alle Zeit.\nDem, der uns schuf und uns erhält, singt Lob mit Dankbarkeit.\r\nIhr Auserwählten, preiset Ihn, ihr Same Abrahams.\ndem, der uns Seine Gnade gab und hat erlöst uns ganz!\nDem, der uns Seine Gnade gab und hat erlöst von Sünd\' uns ganz.\r\nHerr, unser Lob ist schwach und arm, nimm es als Stückwerk an.\nBeschreiben kann kein Menschenwort, was Du für uns getan.\nWir loben Dich und sagen Dank, was Du, Herr, hast für uns getan.'),
(9, '1629', 'Sinners, run and hide your Face   (Crying "Holy" unto the Lord)', 'Crying "Holy" unto the Lord,\ncrying "Holy" unto the Lord,\nIf I could, I surely would\nstand on that rock where Moses stood.\r\nSinners, run and hide your face,\nsinners, run and hide your face.\nGo and run into the rocks and hide your face.\nThe rocks got no hiding place.\r\nLord, I ain\'t no sinner now,\nLord, I ain\'t no sinner now.\nI\'ve been to the river and I\'ve been baptized,\nand I ain\'t no sinner now.\r\nLord, I ain\'t no stranger now,\nLord, I ain\'t no stranger now.\nI\'ve been introduced to the Father and the Son\nand I ain\'t no stranger now,', NULL),
(9, '1630', 'Sitzend zu den Füßen Jesu  -  Sitting at the Feet of Jesus', 'Sitting at the feet of Jesus, oh, what words I hear Him say!\nHappy place! so near, so precious! May it find me there each day.\nSitting at the feet of Jesus, I would look upon the past.\nFor His love has been so gracious, it has won my heart at last.\r\nSitting at the feet of Jesus, where can mortal be more blest?\nThere I lay my sins and sorrows, and, when weary, find sweet rest.\nSitting at the feet of Jesus, there I love to weep and pray.\nWhile I from His fullness gather grace and comfort every day.\r\nBless me, O my Saviour, bless me, as I sit low at Thy feet.\nOh, look down in love upon me, let me see Thy face so sweet.\nGive me, Lord, the mind of Jesus, keep me holy as He is.\nMay I prove I’ve been with Jesus, who is all my righteousness.', 'Sitzend zu den Füßen Jesu, o welche Worte höre ich.\nSelger Ort, in Seiner Nähe lass mich weilen ewiglich.\nSitzend zu den Füßen Jesu, denk ich Seiner Führung nach.\nSeine Liebe unermesslich mir mein stolzes Herze brach.\r\nSitzend zu den Füßen Jesu, kann ein Mensch wohl sel\'ger sein?\nHier leg ab ich Sünd\' und Schmerzen, hier zog Gott ins Herze ein.\nGern sitz\' ich zu Jesu Füßen, klag Ihm alle meine Not,\nhier schenkt Er mir volles Leben, führet mich bis in den Tod.\r\nSegne mich, mein Jesus segne, da ich Dir zu Füßen lieg.\nSchau in Liebe auf mich nieder, gib mir allezeit den Sieg.\nGib mir, Herr, die wahre Demut, halt mich heilig, wie Du bist.\nLass mich wandeln Deine Wege, mit Dir, Heiland, Jesus Christ.'),
(9, '1631', 'So bin ich nun gekommen ins selige Tal  -  I have entered the Valley of Blessing so sweet   (O, kommet doch alle herein in dies Tal)', 'I have entered the valley of blessing so sweet,\nand Jesus abides with me there.\nAnd His Spirit and blood make my cleansing complete,\nand His perfect love casteth out fear.\r\nO, come to this valley of blessing so sweet,\nwhere Jesus will fullness bestow.\nO, believe, and receive, and confess Him,\nthat all His salvation may know.\r\nThere is peace in the valley of blessing so sweet,\nand plenty the land doth impart.\nAnd there\'s rest for the weary, worn traveler\'s feet,\nand there\'s joy for the sorrowing heart.\r\nThere is love in the valley of blessing so sweet,\nsuch as none but the blood-washed may feel.\nWhen heaven comes down redeemed spirits to greet,\nand Christ sets his covenant seal.\r\nThere\'s a song in the valley of blessing, so sweet,\nthat angels would fain join the strain.\nAs with rapturous praises we bow at His feet,\ncrying "Worthy the Lamb that was slain."', 'So bin ich nun gekommen ins selige Tal,\nwo mein Jesus bei mir auch verbleibt.\nWo Sein Blut mich befreit von jeglicher Qual\nund die Liebe die Furcht ganz vertreibt.\r\nO, kommet doch alle herein in dies Tal,\nwo Jesus mit Gnade uns tränkt,\nund ergreifet im Glauben zumal,\nwas Er uns voll Liebe hier schenkt.\r\nDa ist Frieden in diesem gesegneten Tal\nund das Land gibt der Früchte genug!\nDa ist Ruh\' für die Müden und Freude zumal\nfür das Herz, das des Kummers Last trug.\r\nDa ist Liebe in diesem gesegneten Tal,\nwie sie Jesus den Seinen nur gibt.\nWo die Seele durchglüht ist vom himmlischen Strahl\nund man liebt, wie der Heiland uns liebt.\r\nDa ertönet Gesang in dem seligen Tal,\nund es freu\'n sich die Engel darob.\nUnserm Lamm, das für uns hat erduldet die Qual,\nIhm sei ewiglich Ehre und Lob!'),
(9, '1632', 'So fürchte dich nun nicht, denn ich bin bei dir', NULL, 'So fürchte dich nun nicht,\ndenn ich bin bei dir,\nso fürchte dich nun nicht",\nso spricht dein Herr,\n"ich bin dein Retter und\nsonst keiner mehr,\nso fürchte dich nun nicht,\ndenn ich bin bei dir!"\r\n"Du, meine Braut, gehst mir\nnicht mehr aus dem Sinn,\nich liebe dich und geb\'\nfür dich Völker hin,\nich lasse dich heut\' seh\'n,\nwer ich wirklich bin,\ndenn du meine Braut, gehst mir\nnicht mehr aus dem Sinn!"\r\n"Ich trug den ganzen Weg\ndich bis hierher,\nwie schnell du doch vergisst,\ndass ich bin mit dir,\nich rufe dir heut\' zu:\nBraut, vertraue mir!\nIch trug den ganzen Weg\ndich bis hierher!"'),
(9, '1633', 'So groß ist der Herr, singt mit mir - How Great is Our God (Ein König voller Pracht, voll Weisheit und voll Macht  -  The Splendor of a King, clothed in Majesty)', 'The splendor of a King, clothed in majesty,\nlet all the earth rejoice, all the earth rejoice.\nHe wraps himself in light, and darkness tries to hide,\nand trembles at his voice, trembles at his voice.\r\nHow great is our God,\nsing with me how great is our God,\nall will see how great,\nhow great is our God.\r\nAge to age he stands, and time is in his hands,\nbeginning and the end, beginning and the end.\nThe Godhead – Three in One; Father, Spirit and Son,\nthe Lion and the Lamb, the Lion and the Lamb.\r\nName above all names\nWorthy of our praise\nMy heart will sing\nHow great is our God', 'Ein König voller Pracht,\nvoll Weisheit und voll Macht.\nDie Schöpfung betet an, die Schöpfung betet an.\nEr kleidet sich in Licht. Das Dunkel hält ihn nicht\nund flieht, sobald er spricht, und flieht, sobald er spricht.\r\nWie groß ist mein Gott,\nsing mit mir wie groß ist mein Gott,\njeder sieht wie groß,\nwie groß ist mein Gott.\r\nVon Anbeginn der Zeit bis in die Ewigkeit,\nbleibt er derselbe Gott, bleibt er derselbe Gott.\nJa, keiner ist Ihm gleich, voll Gnade ist Sein Reich,\nder König, der da kam als Löwe und als Lamm.\r\nSein Name sei erhöht,\ndenn er verdient das Lob.\nWir singen laut:\nSo groß ist der Herr.'),
(9, '1634', 'So I come to tell you He\'s alive', 'There is a blood that cost a life\nThat paid my way Death its price\nWhen it flowed down from the cross\nMy sins were gone, my sins forgot\r\nThere is a grave that tried to hide\nThis precious blood that gave me life\nIn three days He breathed again\nAnd rose to stand in my defense\r\nSo I come to tell you He\'s alive\nTo tell you that He dries\nEvery tear that falls\nSo I come to tell you that He saves\nTo shout and to proclaim\nThat He\'s coming back for you\r\nThere is a blood that sights the blind\nThat heals the sick, the lonely finds\nIt has the power to free the bound\nAs chains they fall upon the ground\r\nSo pour it out to cleanse my soul\nAnd let His liquid glory flow\nBecause He lives to make me whole\nI owe my life, I owe my all\r\nSo I come to tell you He\'s alive\nTo tell you that He dries\nEvery tear that falls\nSo I come to tell you that He saves\nTo shout and to proclaim\nThat He\'s coming back for you\r\nThis price, this blood\nThis price, this precious blood\nThis one He sacrificed to wash away my sin\nWhat can wash away my sin?\nNothing, nothing\r\nWhat can make me whole again?\nNothing but the blood, nothing but the blood\nWhat can wash away my sin?\nNothing, nothing', 'Dort ist ein Blut welches ein Leben kostet\nEs hat meinen Weg bezahlt, Tod war der Preis\nAls es vom Kreuze floss, waren meine Sünden bezahlt,\nMeine Sünden vergessen.\r\nDort war ein Grab welches versuchte verstecken,\nDieses kostbare Blut welches mir Leben gab,\nNach drei Tagen atmete er wieder\nAuferstanden, um für mich einzustehen\r\n\r\n\r\n\r\n\r\n\r\n'),
(9, '1635', 'So lieb und freundlich Jesus kam  -  In loving-kindness Jesus came   (Sinkendem Sand entriss Er mich)', 'In loving-kindness Jesus came\nmy soul in mercy to reclaim,\nand from the depths of sin and shame\nthrough grace He lifted me.\r\nFrom sinking sand He lifted me,\nwith tender hand He lifted me,\nfrom shades of night to plains of light,\nO praise His name, He lifted me!\r\nHe called me long before I heard,\nbefore my sinful heart was stirred,\nbut when I took Him at His word,\nforgiven, He lifted me.\r\nHis brow was pierced with many a thorn,\nHis hands by cruel nails were torn,\nwhen from my guilt and grief, forlorn,\nin love He lifted me.\r\nNow on a higher plane I dwell,\nand with my soul I know ’tis well;\nyet how or why I cannot tell\nHe should have lifted me.', 'So lieb und freundlich Jesus kam,\nsich meiner Seel\' so warm annahm,\nhob mich aus tiefer Sünd\' und Schand\'\nmit Seiner Gnadenhand.\r\nSinkendem Sand entriss Er mich,\nmit zarter Hand hob mich zu sich,\nempor aus Nacht zu vollem Licht,\nGott sei gelobt, zu vollem Licht!\r\nEr rief mich lang, eh ich\'s gehört,\nund eh\'s mein sünd\'ges Herz begehrt\'.\nDoch als ich Ihn beim Worte nahm,\nVergebung ich bekam.\r\nDie Dornenkron Sein Haupt umwand,\nder Nagel drang durch Seine Hand,\nals meine Schuld und Straf Er trug,\nin  Liebe nach mir frug.\r\nAuf höher\'m Grund, jetzt gnadenvoll,\nwohnt meine Seel\', sie weiß es wohl.;\nWarum und wie, weiß, wer Ihn fand,\nkennt Seine Retterhand.'),
(9, '1636', 'So manche Fragen ich nicht versteh   (Jesus, Er lebt, Er lebt in mir)', NULL, 'So manche Fragen ich nicht versteh,\nund es gibt Dinge, die ich nicht seh\'.\nDoch eines weiß ich, ja, ganz gewiss:\nGott, Er ist da und ist mir nah, wo ich auch geh\'.\r\nJesus, Er lebt! Er lebt in mir!\nJesus, Er lebt und durch\nSein Blut wusch Er mich hier.\nEr liebt mich so, des bin ich froh.\nWenn alles bebt, Jesus,\nEr lebt! Er lebt in mir!\r\nManche, sie zweifeln, sie sind besorgt\nund gehen stumm an mir vorbei.\nDoch ich bin glücklich, Gott geht mit mir.\nWenn ich verzag\', ruft Er mir zu:\n"Ich bin bei dir!"'),
(9, '1637', 'So nimm denn meine Hände und führe mich  -  O take my Hands, dear Father, and lead Thou me', 'O take my hands, dear Father, and lead Thou me,\ntill at my journey’s ending I dwell with Thee.\nAlone I cannot wander one single day,\nso do Thou guide my footsteps on life’s rough way.\r\nO cover with Thy mercy my poor, weak heart,\nlest I in joy or sorrow from Thee depart.\nPermit Thy child to linger here at Thy feet,\nThy goodness blindly trusting with faith complete.\r\nThough oft Thy power but faintly may stir my soul,\nwith Thee, my Light in darkness, I reach the goal.\nTake then my hands, dear Father, and lead Thou me,\ntill at my journey’s ending I dwell with Thee.', 'So nimm denn meine Hände und führe mich.\nBis an mein selig Ende und ewiglich!\nIch kann allein nicht gehen, nicht einen Schritt;\nwo Du wirst geh\'n und stehen, da nimm mich mit.\r\nIn Dein Erbarmen hülle mein schwaches Herz,\nund mach es gänzlich stille in Freud und Schmerz!\nLass ruh\'n zu Deinen Füßen Dein armes Kind!\nEs wird die Augen schließen und glauben blind.\r\nWenn ich auch gar nichts fühle von Deiner Macht,\nDu führst mich doch zum Ziele auch durch die Nacht.\nSo nimm denn meine Hände und führe mich\nbis an mein selig Ende und ewiglich!'),
(9, '1638', 'So sein wie Jesus, so sein wie Jesus / To be like Jesus', 'From Bethlehem\'s manger came forth a stranger -\nOn earth I long to be like Him.\nMy faithful Saviour, how rich His favor!\nOn earth I long to be like Him.\r\nTo be like Jesus, To be like Jesus,\non earth I long, to be like Him.\nAll thru life\'s journey, from earth to glory\nI only ask, to be like Him.\r\nSerene and holy, obedient, lowly -\nOn earth I long to be like Him.\nBy grace forgiven, an heir of heaven -\nOn earth I long to be like Him.', 'Als Lamm auf Erden, Retter zu werden -\nAuf Erden möcht\' ich sein wie Er.\nAm Kreuz zu geben Sein eig\'nes Leben -\nAuf Erden möcht\' ich sein wie Er.\r\nSo sein wie Jesus, so sein wie Jesus!\nOh, ich möchte, sein wie Er!\nDurch\'s ganze Leben, von hier zum Himmel\nmöcht\' ich sein, nur so wie Er.\r\nHimmlische Heere jauchzen Ihm die Ehre -\nAuf Erden möcht\' ich sein wie Er.\nAm Kreuz zerschunden, hat überwunden!\nAuf Erden möcht\' ich sein wie Er.'),
(9, '1639', 'So wie der Meister möcht ich immer sein  -  More like the Master I would ever be   (Nimm Du mein Herz, ich möchte Dein nur sein)', 'More like the Master I would ever be,\nmore of His meekness, more humility.\nMore zeal to labor, more courage to be true,\nmore consecration for work He bids me do.\r\nTake Thou my heart, I would be Thine alone,\ntake Thou my heart and make it all Thine own.\nPurge me from sin, O Lord, I now implore,\nwash me and keep me Thine forevermore.\r\nMore like the Master is my daily prayer,\nmore strength to carry crosses I must bear.\nMore earnest effort to bring His kingdom in,\nmore of His Spirit, the wanderer to win.\r\nMore like the Master I would live and grow,\nmore of His love to others I would show.\nMore self-denial, like His in Galilee,\nmore like the Master I long to ever be.', 'So wie der Meister möcht\' ich immer sein,\nmehr sanft und linde, mehr im Herzen klein.\nMehr eifrig wirken, mehr tätig sein für Ihn,\nin Seinem Dienste möcht ganz mein Herz erglüh\'n.\r\nNimm Du mein Herz, ich möchte Dein nur sein,\nnimm Du mein Herz, und mach es gänzlich Dein.\nTilg\' alle Schuld, o Herr ich bitte Dich,\nwasche mich rein und halt\' mich ewiglich.\r\nSo wie der Meister, ist mein täglich fleh\'n,\nmein Kreuz zu tragen, mehr auf Ihn zu seh\'n.\nmehr ernstes Mühen, für Jesus einzusteh\'n,\nmehr Seines Geistes, Verlor\'nen nachzugeh\'n.\r\nSo wie der Meister, ist mein Lebensziel,\nmehr Seine Lieb\', ich andern zeigen will.\nMehr selbstverleugnend, wie Er auf Erden war,\nin Treu\' und Liebe, wie Er unwandelbar.'),
(9, '1640', 'So wie ich bin, ohn alle Zier  -  Just as I am, without one Plea', 'Just as I am, without one plea,\nbut that thy blood was shed for me,\nand that thou bidd\'st me come to thee,\no Lamb of God, I come, I come.\r\nJust as I am, tho tossed about\nwith many a conflict, many a doubt,\nfightings and fears within, without,\no Lamb of God, I come! I come!\r\nJust as I am, tho tossed about\nwith many a conflict, many a doubt,\nfightings and fears within, without,\no Lamb of God, I come! I come!\r\nJust as I am, Thou wilt receive,\nwilt welcome, pardon, cleanse, relieve.\nBecause Thy promise I believe,\no Lamb of God, I come! I come!\r\n', 'So wie ich bin, ohn\' alle Zier,\nkomm durch Dein Blut ich, Herr, zu Dir.\nDu rufst: Belad\'ne, kommt zu Mir!\nSo komm\' ich Gotteslamm! Ich komm\'.\r\nSo wie ich bin, so arm und schlicht,\nweil mir\'s am Guten ganz gebricht,\nfleh\' ich zu Dir um Heil und Licht.\nSo komm\' ich Gotteslamm! Ich komm\'.\r\nSo wie ich bin, voll Reu\' und Leid,\nvoll Elend und Kleinmütigkeit,\nnur hoffend auf Barmherzigkeit,\nSo komm\' ich Gotteslamm! Ich komm\'.\r\nSo wie ich bin, nimmst Du mich auf,\nvergibst und reinigst, hilfst im Lauf;\nDu hast\'s gesagt, ich baue drauf,\nSo komm\' ich Gotteslamm! Ich komm\'.\r\nSo wie ich bin, Herr, Deine Lieb\ngibt frohen Mut und heil\'gen Trieb. /\nDass ich ganz Dein mög\' sein, das gib!\nSo komm\' ich Gotteslamm! Ich komm\'.'),
(9, '1641', 'So wie ich bin, zu Dir ich komm [so muss es sein]  -  Just as I am, without one Plea', 'Just as I am, and waiting not,\nto rid my soul of one dark blot.\nTo Thee whose blood can cleanse each spot,\no Lamb of God, I come, I come.\r\nJust as I am, though tossed about.\nWith many a conflict, many a doubt.\nFightings and fears within, without,\no Lamb of God, I come, I come.\r\nJust as I am, poor, wretched, blind,\nsight, riches, healing of the mind.\nYea, all I need in Thee to find,\no Lamb of God, I come, I come.\r\nJust as I am, Thou wilt receive,\nwilt welcome, pardon, cleanse, relieve.\nBecause Thy promise I believe,\no Lamb of God, I come, I come.\r\nJust as I am, Thy love unknown,\nhath broken every barrier down.\nNow, to be Thine, yea, Thine alone,\no Lamb of God, I come, I come.', 'So wie ich bin zu Dir ich komm\',\nnicht meine Kraft, nur Du allein!\nDein Blut wäscht mich von Sünden rein.\nO Gottes Lamm, ich komm\', ich komm\'.\r\nSo wie ich bin, vom Sturm gejagt,\nmit bangen Zweifeln oft geplagt,\nvom Feind bedroht und sehr verzagt.\nO Gottes Lamm, ich komm\', ich komm\'.\r\nSo wie ich bin, blind, arm und irr,\nsuch\' ich, was mir gebricht, bei Dir:\nLicht, Reichtum, Deiner Gnade Zier.\nO Gottes Lamm, ich komm\', ich komm\'.\r\nGrad\' wie ich bin nimmst Du mich an.\nDie Sündenschuld ist abgetan,\nweil ich auf Dein Wort trauen kann.\nO Gottes Lamm, ich komm\', ich komm\'.\r\nGrad\' wie ich bin, was mich noch hält,\nvor Deiner Lieb\' in Staub zerfällt.\nDir hab\' ich ewig mich vermählt.\nO, Gottes Lamm, ich komm\', ich komm\'.'),
(9, '1642', 'Solang mein Jesus lebt und Seine Kraft mich hebt', NULL, 'Solang mein Jesus lebt\nund Seine Kraft mich hebt,\nmuss Furcht und Sorge von mir flieh\'n,\nmein Herz in Lieb erglüh\'n.\r\nEr ist ein guter Hirt\',\nder treu sein Schäflein führt;\nEr weidet mich auf grüner Au,\ntränkt mich mit Himmelstau.\r\nWenn sich die Sonn\' verhüllt,\nder Löwe um mich brüllt,\nso weiß ich auch in finst\'rer Nacht,\ndass Jesus mich bewacht.\r\nUnd glitte je mein Fuß,\nbrächt\' mir die Welt Verdruss,\nso eilt ich schnell zu Jesu Herz,\nder heilte meinen Schmerz.\r\nD\'rum blick ich nur auf Ihn,\no seliger Gewinn!\nMein Jesus liebt mich ganz gewiss,\ndas ist mein Paradies!'),
(9, '1643', 'Sollt Jesus tragen nur ein Kreuz  -  Must Jesus bear the Cross alone', 'Must Jesus bear the cross alone,\nand all the world go free?\nNo, there\'s a cross for every one,\nand there\'s a cross for me.\r\nThe consecrated cross I\'ll bear,\ntill death shall set me free.\nAnd then go home my crown to wear,\nfor there\'s a crown for me.\r\nUpon the crystal pavement, down\nat Jesus\' pierced feet.\nWith joy I\'ll cast my golden crown,\nand His dear name repeat.\r\nOh precious cross! Oh glorious crown!\nOh resurrection day!\nYe angels from the stars come down\nAnd bear my soul away.\r\nThen carry your cross and overcome\nthrough Him what painful seems.\nRemember, Jesus carried the heavy cross,\nso you wear yours too.', 'Sollt Jesus tragen nur ein Kreuz\nund alle andern keins?\nEs gibt ein Kreuz für jedermann,\nund du und ich trag eins.\r\nDas gottgewollte Kreuz trag\' ich\nsolang ich hier noch bin,\nbald geh\' ich heim und trag\' die Kron\',\nwenn ich vollendet bin.\r\nZu Jesu Füßen leg\' ich dann\nvoll Freude meine kron\'\nund singe dann das neue Lied,\ndenn Er ist unser Lohn.\r\nO liebes Kreuz, o welche Kron\',\no Auferstehungstag!\nDie Engel holen mich hinauf,\ndenn ich bin seine Braut.\r\nD\'rum trag\' dein Kreuz und überwind\'\ndurch Ihn was schmerzlich scheint.\nDenk\', Jesus trug das schwere Kreuz,\nd\'rum trage du auch deins.'),
(9, '1644', 'Someone asked the Question, why do we sing   (I sing because I\'m happy)', 'Someone asked the question,\nwhy do we sing?\nWhen we lift our hands to Jesus.\nWhat do we really mean?\r\nI sing because I\'m happy,\nI sing because I\'m free.\nHis eye is on the sparrow\nthat\'s the reason why we sing.\r\nSomeone may be wondering,\nwhen we sing our song.\nAt times we\'re even crying\nand nothings even wrong.\r\nAnd if somebody asks you,\nwas it just a show?\nLift your hands and be a witness,\nand tell the whole world, No!\r\nAnd when we cross that river,\nto study war no more.\nWe will sing our songs to Jesus,\nthe Oone that we adore.', NULL),
(9, '1645', 'Someone\'s praying Lord, come by me   (Chorus)', 'Someone\'s praying Lord, come by me,\nsomeone\'s praying Lord, come by me.\nSomeone\'s praying Lord, come by me.\nOh, Lord, come by me.', NULL),
(9, '1646', 'Something beautiful, something good   (Chorus)', 'Something beautiful, something good!\nAll my confusion He understood.\nAll I had to offer Him was brokeness and strife,\nbut He made something beautiful of my life.', 'Etwas Schönes, etwas Gutes!\nAlle meine Verwirrung hat Er verstanden.\nAlles, was ich Ihm darbringen konnte,\nwar Zerbrochenheit und Hader,\ndoch Er machte etwas Schönes aus meinem Leben.'),
(9, '1647', 'Something keeps holding me - Jesus Er hält mich fest (Die Nöte dieser Welt, sie wurden schwerer  -  The Trials of this World were getting closer)', 'The trials of this world were getting closer,\nthe pull I felt was more than I could bear.\nAnd I was on the verge of just giving over,\nthe strength within myself just wasn’t there.\r\nSomething keeps holding me, every day I see,\nhelping me faithfully, to overcome my trials.\nGuiding me constantly, giving me victory,\nit\'s a reality, for Jesus keeps holding me.\r\nSatan laid before me his temptation,\nof his desire, to steal away my faith.\nBut I have found in time the revelation,\nthe strength I need, to keep me by His grace.', 'Die Nöte dieser Welt, sie wurden schwerer,\nes war viel mehr, als ich ertragen kann.\nDoch war es, als ich nicht mehr weiter wusste,\ndass Jesus kam und nahm mich bei der Hand.\r\nJesus Er hält mich fest, Er der mich nie verlässt,\nauch in dem größten Test lässt Er mich nie allein.\nEr führt mich jeden Tag, führt mich von Sieg zu Sieg,\nEr, der mein König ist, Er hält mich für immer fest.\r\nUnd wenn der Feind mit all seiner Versuchung,\nund Zweifeln meinen Glauben stören will.\nDann wart\' ich nur auf Gottes Offenbarung,\ndann wird in Jesus meine Seele still!'),
(9, '1648', 'Something more than Gold for the Master   (All He wants is you, no one else will do)', 'Something more than gold for the Master,\nsomething more than gifts to appease.\nThere is only one thing that you alone can bring,\nthere is only one gift that will please.\r\nAll He wants is you, no one else will do.\nNot just a part, He wants all of your heart.\nAll He wants is all of you, all He wants is you.\r\nNothing less than this can you offer,\nnothing less than this can you bring.\nIt is not just your songs, But for you alone He longs.\nNothing less can you give to your King.\r\nAll He wants is me, unreservedly.\nNot just a part, He wants all of my heart.\nAll He wants is all of me, all He wants is me.', NULL),
(9, '1649', 'Something more than may Yesterdays   (Chorus)', 'Something more than my yesterdays,\nmore than I had before.\nSomething more than wealth or fame.\nHe gave me some thing worth living for.', NULL),
(9, '1650', 'Sometimes Hallelujah, sometimes praise the Lord', 'Sometimes hallelujah,\nsometimes praise the Lord\nsometimes gently singing,\npraise the Lord in one accord.\nSometimes hallelujah,\nsometimes praise the Lord\nsometimes gently singing,\npraise the Lord in one accord.', NULL),
(9, '1651', 'Sonnenschein der Gnade Jesu macht mich fröhlich allezeit   (Wahre Freude ist bei Jesus)', NULL, 'Sonnenschein der Gnade Jesu\nmacht mich fröhlich allezeit.\nJeden Tag erleb\' ich\'s wieder,\nseit ich mich dem Herrn geweiht.\r\nWahre Freude ist bei Jesus,\nEr erfüllt die Seele mein.\nSo leb\' ich in Seiner Nähe,\nEr ist mein und ich bin Sein.\r\nWas mir fehlt, find\' ich bei Jesus,\nEr versorgt mich für und für.\nAuch für meine kleinsten Sorgen\nhat Er eine off\'ne Tür.\r\nGnadenreiche Nähe Jesu\nmacht mich stille allezeit.\nAuch im Sturm und trüben Tagen\nist zum Trösten Er bereit.\r\nWenn ich froh mein Lauf vollendet,\nruhe ich bei Jesus aus.\nFreud\' und ew\'ge Wonne spendet\nEr mir dann im Heimathaus.'),
(9, '1652', 'Souverän (Großer Gott, wir loben dich)', NULL, 'Wer du bist, was du tust\nWie du liebst lässt mich nur staunen, Herr\nWie du kämpfst, wie du führst\nWas du wirkst, ist immer souverän\r\nDu bist gut, du bist treu\nDeinem Wort vertrauen wir allein\nIn der Not bist du nah\nDu lässt uns nie mehr verloren sein\r\nGroßer Gott, wir loben dich\nHerr, wir preisen deine Stärke\nVor dir neigt die Erde sich\nUnd bewundert all deine Werke\r\nWie du warst vor aller Zeit\nSo bleibst du bis in Ewigkeit\nWie du warst vor aller Zeit\nSo bleibst du bis in Ewigkeit\nHeilig, heilig\nGroßer Gott, wir loben dich\nHeilig, heilig\nGroßer Gott, wir loben dich'),
(9, '1653', 'Sovereign over us', 'There is strength within the sorrow\nThere is beauty in our tears\nAnd you meet us in our mourning\nWith a love that cast out fear\nYou are working in our waiting\nYou\'re sanctifying us\nWhen beyond our understanding\nYou\'re teaching us to trust\r\nYou are wisdom unimagined\nWho could understand your ways\nReigning high above the heavens\nReaching down in endless grace\nYou\'re the lifter of the lowly\nCompassionate and kind\nYou surround and you uphold me\nAnd your promises are my delight\r\nYour plans are still to prosper\nYou have not forgotten us\nYou\'re with us in the fire and the flood\nYou\'re faithful forever\nPerfect in love\nYou are sovereign over us\r\nEven what the enemy means for evil\nYou turn it for our good\nYou turn it for our good and for your glory\nEven in the valley, you are faithful\nYou\'re working for our good\nYou\'re working for our good and for your glory', 'Da ist Kraft in Sorgen, Schönheit in unseren Tränen\nDU begegnest uns in unserem Stöhnen\nMit der Liebe die Furcht austreibt\nDU wirkst in unserem Warten,  Du heiligst uns\nWenn Du uns über unseren Verstand hinaus\nlehrst zu vertrauen\r\n(Du bist unvorstellbare Weisheit\nwer könnte Deine Wege verstehen\nHoch über den Himmeln regierend\nin endloser Gnade herabreichend\nDu erhebst die Niedrigen\nMitfühlend und freundlich\nDu umgibst und stützt mich\nDeine Verheißungen sind meine Freude\r\nDein Plan ist unser Wohlergehen\nDU hast uns nicht vergessen\nDu bist mit uns in Feuer und Flut\nDu bist für immer treu\nVollkommen in Liebe\nDu bist souverän über uns\r\nSogar was der Feind zum Bösen plante\nwendest Du zum Guten\nDu wendest es zum Guten und zu Deiner Herrlichkeit\nSogar im Tal  bist du treu\nDU wirkst zu unserem Guten\nDu wirkst zum Guten und zu Deiner Herrlichkeit'),
(9, '1654', 'Speak To The Mountains', 'Why would I worry when giants keepcalling my name?\nMy God is so much bigger than troubles I face\nWhy would I hunger for power or riches or fame?\nCause my God is so much better than all of these things\r\nSo I won\'t be shaken, I won\'t be moved\nMy God is faithful, His promise is true\nSo I speak to the mountains\n"Oh, it\'s time to move\nCause my God is bigger, better, stronger, greater than you"\r\nMy enemies scatter cause they know the battle is done\nMy God is stronger, the victory\'s already won\nHe died for my ransom and rose up on the third day\nCause my God is greater than death, hell, and the grave\r\nThere\'s no mountain too high,  no valley too low\nThere\'s no fear that I have,  He doesn\'t already know\nThere\'s no problem too big, There\'s no weapon too strong, There is nothing for God that\'s impossible (2x)\r\nI won\'t be shaken,  I won\'t be moved\nMy God is faithful,  His promise is true\nSo I speak to the mountains\n"Oh, it\'s time to move\nCause my God is bigger,  better,  stronger,  greater than you,\nCause my God is bigger,  better,  stronger,  greater than you."', 'Warum sollte ich mich sorgen, wenn Riesen meinen Namen rufen?\nMein Gott ist so viel größer,  als die Probleme,  die mir begegnen.\nWarum sollte ich trachten nach Macht,  Reichtum oder Ruhm?\nMein Gott ist so viel besser,  als alle diese Dinge\r\nSo werde ich nicht erschüttert, ich werde nicht bewegt\nMein Gott ist treu, Sein Versprechen ist wahr\nSo spreche ich zu den Bergen\n„Oh, es ist Zeit sich zu bewegen,\ndenn mein Gott ist größer, besser, stärker, mächtiger als du“\r\nMeine Feinde zerstreuen sich, weil sie wissen der Kampf ist beendet.\nMein Gott ist stärker, der Sieg ist bereits gewonnen\nEr starb für meine Erlösung und erwachte am dritten Tag.\nDenn mein Gott ist größer als der Tod, die Hölle und das Grab\r\nDa ist kein Berg zu hoch,  kein Tal zu tief\nDa ist keine Furcht,  die ich habe,  von der er nicht bereits weiß\nDa ist kein Problem zu groß,  Da ist keine Waffe zu stark,  Da ist nichts für Gott,  was unmöglich ist\r\nIch werde nicht erschüttert,  ich werde nicht bewegt\nMein Gott ist treu,  Sein Versprechen ist wahr\nSo spreche ich zu den Bergen\n„Oh,  es ist Zeit sich zu bewegen, denn mein Gott ist größer,  besser,  stärker, mächtiger als du,  denn mein Gott ist größer,  besser,  stärker,  mächtiger als du.“'),
(9, '1655', 'Special 18.02', NULL, 'Danke, dass du als sanftes Lamm gekommen bist,\nDu hattest eine solche Liebe, dass du für uns in die Tiefe sankst,\nDu hast den Leib des Sohnes dem Tod übergeben,\nDeine Seele ist mit den Sünden aller Menschen in die Hölle hinabgestiegen,\nUm uns alle nach oben zu heben.\r\nDanke, dass du mir zuhörst\nDu weißt, wenn ich seufze oder mein Herz schnell schlägt, weißt du alles,\nwas ich brauche, und wenn ich in Demut zu dir komme, sprichst du zu mir.\r\nDie Liebe Gottes, was kann damit verglichen werden?\nWenn schwere Zeiten kommen und Unglaube überall ist,\nhält uns nur die Liebe Gottes.\nNur Gottes Liebe hat uns durch alle Zeiten getragen, beschützt und bewahrt.\nWie könnte jemand ohne die Liebe Christi überleben?\r\nDanke für alles, was du gibst, für alles, was du versprochen hast.\nAll das ist mir so kostbar.\nIch möchte, dass sich die Natur und der Charakter Christi\nimmer mehr in mir manifestieren.'),
(9, '1656', 'Special Lisa', 'I am resting on the finished work\nOf Jesus Christ today,\nAll circumstances will be gone,\nThe Word of God will still remain!\nNo sickness, fear, no guilt or sin can have control and worry me,\nThe keys of faith are in my hands, and I am bound for Victory!\r\nA great commission from my Lord\nI have now received,\nThe prince of power of the air\nWill never have a part in me.\nAs amateur creator I\nCan change the atmosphere around,\nI use the chain of circumstance\nFor any spirits to be bound!\r\nI know that Jesus “the I AM” is the same today,\nThe prophet came to show the Life\nThe Bride must have It on display\nThe hour has come for Christ in us to be completely glorified,\nI want the Spirit to be free to do the greater works in me!\r\nI am free, My new day has come,\nNow I can be who I truly am,\nI am free, Covered by His Blood!\nAll things are possible with God!\nAll things are possible with God!', NULL),
(9, '1657', 'Spirit now melt and move   (Chorus)', 'Spirit now melt and move,\nall of our hearts with love.\nBreathe on us from above,\nwith old time power.', NULL),
(9, '1658', 'Spirit of God move', 'I lift my hands in surrender\nlaying all on the altar\nI don\'t want to pretend\nbut be sealed by Your hand\nI will take Your Word\nand I\'ll hide it in my heart\ntill every fiber of my being\nhas that desperate cry\r\nSpirit of God Move\nwrite Your Word in my heart\nfill my whole being\nconsume my life\nSpirit of God move\nan empty vessel I want to be\nso that You can come\nLord, and fill me\r\nI\'ve recognized Your Voice\nI\'ve understood the call\nhelp me not to faint\nbut stand and overcome\nLord I just want to please You\nthat\'s all I want to do\nso from my soul now\nI cry to You', NULL),
(9, '1659', 'Spirit of the living God, fall afresh on me   (Chorus)', 'Spirit of the living God, fall afresh on me.\nSpirit of the living God, fall afresh on me.\nBreak me, melt me, mould me, fill me.\nSpirit of the living God, fall afresh on me.', NULL),
(9, '1660', 'Spirit of Truth', 'Spirit of Truth,\nSpirit of Power,\nSpirit of Truth,\nHoly Fire. (2x)\r\nJesus, we open our hearts\nfor Your Presence,\nJesus, we open our hearts\nfor You! (2x)', NULL),
(9, '1661', 'Sprich das Wort und glaube   (Er, der in uns ist, Er, der größer ist)', NULL, 'Sprich das Wort und glaube, Jesus ist mit dir,\nEr, der Überwinder, will dein Helfer sein.\nSprich das Wort und glaube, denn dein Herr ist hier,\nEr hat Macht und wird auch Stärke dir verleih\'n!\r\nEr, der in uns ist, Er, der größer ist\nals der, der ist in der Welt,\nEr, der in uns ist, der Herr Jesus Christ,\nEr, der starke Gottesheld, Er, der starke Gottesheld.\r\nSprich das Wort und glaube und es wird gescheh\'n,\nder, der glaubt, wird heute Wunder Gottes seh\'n.\nSprich das Wort und glaube, ist dein Weg auch schwer,\ndenn dein Gott wird ändern alles um dich her!\r\nSprich das Wort und glaube, nimm aus Seiner Hand,\nwas Gott dir gegeben: gutes, weites Land!\nSprich das Wort und glaube - was im Wege steht,\nmuss vor dir vergehen, weil Er mit dir geht!'),
(9, '1662', 'Sprich, ist es wahr, dass sich ein Strom ergossen   (Er kann dich waschen, er kann dich heilen)', NULL, 'Sprich, ist es wahr, dass sich ein Strom ergossen\nzu heilen mich von meinem Sündenweh?\n[: Der aus den Wunden Jesu ist geflossen,\nund der mich wäscht so weiß wie Schnee? :]\r\nEr kann dich waschen, er kann dich heilen,\ner will vergeben all deine Schuld.\r\nDu liebe Seele, fühlst du deine Sünden,\ndrückt dich die Last der Schuld unendlich schwer,\n[: kannst du nicht Ruhe und nicht Frieden finden,\nso denk daran, es lebt der Herr! :]\r\nIn diesen Strom tauch\' dich mit deinen Leiden,\ndie lang getrag\'ne Last, wirf sie hinein,\n[: dann wird dich Gott auf Friedensauen weiden,\ndein Herz wird froh und glücklich sein. :]'),
(9, '1663', 'Sprich, o Herr, sprich Dein Wort zu uns  -  Speak, oh Lord, as we come to You', 'Speak, oh Lord, as we come to You\nto receive the food of Your Holy Word.\nTake Your truth, plant it deep in us,\nshape and fashion us in Your likeness,\nthat the light of Christ might be seen today\nIn our acts of love and our deeds of faith.\nSpeak, oh Lord, and fulfill in us\nall Your purposes for Your glory.\r\nTeach us, Lord, full obedience,\nholy reverence, true humility.\nTest our thoughts and our attitudes\nin the radiance of Your purity.\nCause our faith to rise; cause our eyes to see\nyour majestic love and authority.\nWords of pow\'r that can never fail\nlet their truth prevail over unbelief.\r\nSpeak, oh Lord, and renew our minds,\nhelp us grasp the heights of Your plans for us.\nTruths unchanged from the dawn of time\nthat will echo down through eternity.\nAnd by grace we\'ll stand on Your promises,\nand by faith we\'ll walk as You walk with us.\nSpeak, oh Lord, till Your bride is built\nand the earth is filled with Your glory.', 'Sprich, o Herr, sprich Dein Wort zu uns,\nes soll wahr und klar zu den Herzen gehn.\nSäe aus, pflanz\' es tief hinein,\nform\' und gieße uns in dein Ebenbild.\nMag das Licht des Herrn leuchten hell und weit,\nals ein Zeugnis Seiner Herrlichkeit.\nSprich, o Herr, und gebrauche uns,\nbringe Frucht hervor Dir zur Ehre.\r\nPrüfe uns in dem Licht des Worts,\ndas vollkommen gut und das Absolut.\nLehre uns, das was recht vor Dir,\neinen sanften Geist und Aufrichtigkeit.\nSchärfe uns den Blick für das rechte Tun,\ndass wir dienlich sind und im Glauben ruh\'n.\nLebensbrot ist Dein heil\'ges Wort,\nweise uns den Weg, der zum Ziele führt.\r\nEhre, Dank und Anbetung sei\nDeinem Namen, Herr, bis in Ewigkeit.\nWir sind hier, mache uns bereit\nfür Dein Kommen, Herr, in der Herrlichkeit.\nJa, den schmalen Weg wollen wir nun geh\'n,\nhilf uns, Jesus, nur auf dich zu seh\'n.\nWohin sollen wir denn geh\'n?\nDu allein hast Worte ew\'gen Lebens.'),
(9, '1664', 'Spuren im Sand', NULL, 'Einst im Traum sah ich mich geh\'n mit meinem Herrn\nSeite an Seit\' gingen wir an einem Strand.\nUnd mein Leben, es zog an mir vorbei\nund ich sah unsere Fußspuren im Sand.\r\nDoch ich erschrak, als ich zurückgeblickt,\nals ich bemerkte in den schwersten Lebenszeiten,\ndass eine Spur nur im Sand zu sehen war,\ngerad\' in den Prüfungszeiten.\r\nIch fragte: "Herr, wo warst du da?\nmusst\' ich alleine durch die dunklen Täler gehen,\nals die Not doch am allergrößten war?\nDas kann ich so nicht verstehen."\r\nDa antwortete Er:\n"Mein liebes Kind, ich liebe dich.\nIch bin bei dir auch an allen schweren Tagen.\nDort, wo du nur eine Spur gesehen hast,\nda hab ich dich getragen."'),
(9, '1665', 'Spürbar ist die Gegenwart unsres Herrn heut unter uns - (In the Midst of His Children the Lord said He would be)', 'In the midst of His children the Lord said He would be,\nit doesn’t take very many, it can be just two or three.\nAnd I feel that same sweet spirit that I’ve felt so many times before.\nSurely I can say I’ve been with the Lord.\r\nSurely the presence of the Lord is in this place,\nI can feel His mighty power and His grace.\nI can hear the rush of angel wings, I see glory on each face.\nSurely the presence of the Lord is in this place.\r\nThere’s a holy hush around us as His glory fills this place.\nI’ve touch the hem of His garment, I can almost see His face.\nAnd my heart is overflowing with the fullness of His joy.\nI know without a doubt that I’ve been with the Lord.', '\r\nSpürbar ist die Gegenwart uns\'res Herrn heut\' unter uns.\nIch kann spüren Seine Liebe, Seine Gnad\' und Seine Gunst.\nHör\' ich Engelsflügel rauschen und erstrahlt Dein Angesicht,\nja, dann weiß ich, der Herr ist hier und offenbart heute sich.\r\n'),
(9, '1666', 'Standing Somewhere in the Shadows', 'Standing somewhere in the shadows you\'ll find Jesus.\nHe\'s the Friend who always cares and understands.\nStanding somewhere in the shadows you will find Him,\nand you\'ll know Him by the nail prints in His hands.', NULL),
(9, '1667', 'Ständig vorwärts in dem Lichte  -  Travel along in the Sunshine', 'Travel along in the sunshine,\non the King\'s highway!\nTravel along, singing a song!\nFollow Jesus all the way!\nNever mind, what lies before you.\nNever mind, what others say or do.\nYou just travel along in the sunshine,\non the King\'s highway!', 'Ständig vorwärts in dem Lichte,\nauf dem Hochweg bleib!\nStändig vorwärts, Gesang in dem Herz!\nFolge Jesus allezeit!\nAchte nicht, was noch liegt vor dir.\nAchte nicht auf and\'re, was sie tun.\nGeh nur ständig vorwärts in dem Lichte,\nauf dem Hochweg bleib!'),
(9, '1668', 'Stehend auf dem Wort des Königs Jesus Christ  -  Standing on the Promises of Christ my King   (Gläubig steh ich, auf dem Worte)', 'Standing on the promises of Christ my King,\nthrough eternal ages let His praises ring.\nGlory in the highest I will shout and sing,\nstanding on the promises of God.\r\nStanding, standing,\nstanding on the promises of Christ my Saviour.\nStanding, standing,\nI\'m standing on the promises of God.\r\nStanding on the promises that cannot fail,\nwhen the howling storms of doubt and fear assail.\nBy the living Word of God I shall prevail,\nstanding on the promises of God.\r\nStanding on the promises of Christ the Lord,\nbound to Him eternally by love\'s strong cord.\nOvercoming daily with the Spirit\'s sword,\nstanding on the promises of God.\r\nStanding on the promises I cannot fall,\nlist\'ning every moment to the Spirit\'s call.\nResting in my Saviour, as my all in all,\nstanding on the promises of God.', 'Stehend auf dem Wort des Königs Jesus Christ,\nder in Ewigkeit des Preises würdig ist.\nRühm\' ich Ihn der mich befreit aus Satans List,\ndenn ich trau dem Worte meines Herrn.\r\nGläubig steh ich,\nauf dem Worte meines Heilands Jesus Christus.\nGläubig steh ich,\nauf dem Worte meines Heilands Jesus Christ.\r\nFest trau\' ich dem Wort des Herrn, das nimmer weicht,\nwenn in Not mich Zweifel oft und Furcht beschleicht.\nDoch durchs Wort des Herrn wird mir der Sieg so leicht,\nd\'rum trau ich dem Worte meines Herrn.\r\nSteh ich auf dem Worte, lässt der Geist mich sehn\',\nwelch ein völl\'ges Rettungswerk am Kreuz gescheh\'n,\nkann nun in der Freiheit meines Herrn besteh\'n,\nruhend auf dem Worte meines Herrn.\r\nTrauend auf dem Wort des Königs fall\' ich nicht,\nwenn ich stetig achte auf des Geistes Licht.\nDenn ich ruh\' in dem was mir Sein Mund verspricht.\nFest trau ich dem Worte meines Herrn.'),
(9, '1669', 'Steht auf, steht auf zum Streite, ihr Gotteskinder all  -  Stand up, stand up for Jesus ye Soldiers of the Cross   (Steht auf für Jesus, ihr gottgeweihten Reihn)', 'Stand up, stand up for Jesus ye soldiers of the cross.\nlift high his royal banner, it must not suffer loss.\nfrom vict\'ry unto vict\'ry his army he shall lead,\n\'til ev\'ry foe is vanquished, and Christ is Lord indeed.\r\n\r\nStand up, stand up for Jesus, the trumpet call obey,\nforth to the mighty conflict in this his glorious day.\nYe that are men now serve him against unnumbered foes,\nlet courage rise with danger, and strength to strength oppose.\r\nStand up, stand up for Jesus, the strife will not be long.\nThis day the noise of battle, the next the victor\'s song.\nTo him that overcometh a crown of life shall be.\nHe with the King of glory shall reign eternally.', 'Steht auf, steht auf zum Streite, ihr Gotteskinder all!\nWohlan, wohlan, noch heute folgt dem Posaunenschall!\nDes Königs Fahnen wehen, nun geht\'s zum heil\'gen Krieg;\nzu Jesus lasst uns stehen, er führt von Sieg zu Sieg.\r\nSteht auf für Jesus, ihr gottgeweihten Reih\'n,\nerhebt das Siegesbanner, denn Jesus ja Jesus wird Sieger sein!\r\nSteht auf, steht auf zum Streite! Des Feindes Macht ist groß;\nes stehet ihm zur Seite der Hölle finst\'rer Tross.\nDoch fürchtet nicht sein Toben, o fasset Glaubensmut,\nzieht an die Macht von oben; für euch floss Christi Blut.\r\nSteht auf, steht auf zum Streite! Hier ist Immanuel!\nDer Feind flieht in die Weite; errettet ist die Seel\'.\nDem Sieger winkt entgegen als sel\'ger Gnadenlohn\ndes Himmels Heil und Segen, des ew\'gen Lebens Kron\'.'),
(9, '1670', 'Steht mein Heiland mir zur Seit, falle ich nicht   (Jesus ist heut und ewiglich teurer als alle Welt für mich)', NULL, 'Steht mein Heiland mir zur Seit\',\nfalle ich nicht, falle ich nicht.\nWeiche, Welt! Er ist allezeit\nKraft mir und Licht, Kraft mir und Licht!\r\nJesus ist heut\' und ewiglich\nteurer als alle Welt für mich,\nseit ich Seinen Ruf gehört,\nlieb mir und wert, lieb mir wert.\r\nWenn Sein Schaf auf steilem Pfad\nSeiner begehrt, Seiner begehrt,\nist Er mir mit Rat und Tat\nteuer und wert, teuer und wert.\r\nBin ich auch ein Scherben noch,\nwertlos und klein, wertlos und klein.\nGießt Er Seinen Segen doch\nin mich hinein, in mich hinein.\r\nGrüßen am kristall\'nen Meer\nStimmen der Braut, Stimmen der Braut,\nJesu Stimme ist vielmehr\nhold mir und traut, hold mir und traut.'),
(9, '1671', 'Stern auf den ich schaue', NULL, 'Stern auf den ich schaue, Fels, auf dem ich steh\',\nFührer, dem ich traue, Stab, an dem ich geh\',\nBrot, von dem ich lebe, Quell, an dem ich ruh\',\nZiel, das ich erstrebe, alles, Herr, bist Du!\nZiel, das ich erstrebe, alles, Herr, bist Du!\r\nOhne Dich, wo käme Kraft und Mut mir her,\nohne Dich, wer nähme meine Bürde, wer?\nOhne Dich zerstieben, würde mir im Nu,\nGlauben, Hoffen, Lieben, alles, Herr, bist Du.\nGlauben, Hoffen, Lieben, alles, Herr, bist Du.\r\nD\'rum, so will ich wallen, meinen Pfad dahin,\nbis Posaunen schallen, und daheim ich bin.\nDann, mit neuem Singen, jauchz\' ich froh Dir zu:\nNichts hab ich zu bringen, alles, Herr, bist Du!\nNichts hab ich zu bringen, alles, Herr, bist Du!'),
(9, '1672', 'Stimmt an mit vollem Klang und preiset Gottes Sohn  -  Come, we that love the Lord and let are Joys be known   (Wir pilgern nach Zion)', 'Come, we that love the Lord,\nand let are Joys be known,\njoin in a song with sweet accord,\njoin in a song with sweet accord,\nand thus surround the throne,\nand thus surround the throne.\r\nWe\'re marching to Zion\nbeautiful, beautiful Zion.\nWe\'re marchring upwward to Zion.\nthe beautiful city of God.\r\nLet those refuse to sing\nwho never knew our God,\nbut children of the heavenly King,\nbat children of the heavenly King,\nmay speak their joys abroad,\nmay speak their joys abroad.\r\nThe hill of Zion yields,\na thousand sared sweets\nbefore we reach the heavenly fields,\nbefore we reach the heavenly fields,\nor walk the golden streets,\nor walk the golden streets.\r\nThen let our songs abound,\nand every tear be dry;\nwe\'re marching thru Emmanuels\'s ground,\nwe\'re marching thru Emmanuels\'s ground,\nto fairer worlds on high,\nto fairer Worlds on high.', 'Stimmt an mit vollem Klang\nund preiset Gottes Sohn,\nwir scharen uns mit Jubelsang,\nwir scharen uns mit Jubelsang,\num unsers Vaters Thron,\num unsers Vaters Thron.\r\nWir pilgern nach Zion!\nHerrliches liebliches Zion!\nJa, heimwärts geht es nach Zion,\nder herrlichen himmlischen Stadt!\r\nOh, liebeleeres Herz,\ndas hier noch schweigen will,\nkomm richt\' die Blicke himmelwärts,\nkomm richt\' die Blicke himmelwärts,\ndann bleibst auch Du nicht still,\ndann bleibst auch Du nicht still.\r\nOh, komm und wandere mit!\nWer mit uns Pilgern reist,\nwird eh sein Fuß die Stadt betritt,\nwird eh sein Fuß die Stadt betritt,\nmit Manna schon gespeist,\nmit Manna schon gespeist.\r\nD\'rum fröhlich jubiliert,\nund lass das Sorgen sein,\nein frohes Herz den Pilger ziert,\nein frohes Herz den Pilger ziert,\nbald geht\'s in Zion ein,\nbald geht\'s in Zion ein.'),
(9, '1673', 'Strahl\' auf mich, Herr, strahl\' auf mich  -  Shine on me, Lord, shine on me', 'Shine on me, Lord, shine on me,\nlet the light from the lighthouse shine on me.\nShine on me, Lord, shine on me,\nlet the light from the lighthouse shine on me.\r\nShine on me, Lord, shine on me.\nLet the word of this hour shine on me.\nShine on me, Lord, shine on me.\nLet the word of this hour shine on me.', 'Strahl\' auf mich, Herr, strahl\' auf mich!\nLass das Licht dieser Stunde strahl\'n auf mich.\nStrahl auf mich, Herr, strahl\' auf mich!\nLass das Licht dieser Stunde strahl\'n auf mich.\r\nStrahl\' auf mich, Herr, strahl\' auf mich!\nLass das Wort dieser Stunde strahl\'n auf mich.\nStrahl auf mich, Herr, strahl\' auf mich!\nLass das Wort dieser Stunde strahl\'n auf mich.'),
(9, '1674', 'Strebend zu wandeln des Heilandes Pfade  -  Trying to walk in the Steps of the Saviour   (Wie schön ist es, zu gehn an des Heilandes Seite)', 'Trying to walk in the steps of the Saviour,\ntrying to follow our Saviour and King.\nShaping our lives by His blessed example,\nhappy, how happy, the songs that we bring.\r\nHow beautiful to walk in the steps of the Saviour,\nstepping in the light, stepping in the light,\nhow beautiful to walk in the steps of the Saviour,\nled in paths of light\r\nPressing more closely to Him Who is leading,\nwhen we are tempted to turn from the way.\nTrusting the arm that is strong to defend us,\nhappy, how happy, our praises each day.\r\nWalking in footsteps of gentle forbearance,\nfootsteps of faithfulness, mercy, and love.\nLooking to Him for the grace freely promised,\nhappy, how happy, our journey above.\r\nTrying to walk in the steps of the Saviour,\nupward, still upward, we follow our Guide.\nWhen we shall see Him, "the King in His beauty,"\nhappy, how happy, our place at His side.', 'Strebend zu wandeln des Heilandes Pfade,\ntrachtend zu folgen, wo immer Er führt;\nnach Seinem Vorbild das Leben gestaltend,\nsingen wir fröhlich, weil Er uns regiert!\r\nWie schön ist es, zu geh\'n an des Heilandes Seite,\nwandelnd in dem Licht, wandelnd in dem Licht!\nWie schön ist es, zu geh\'n an des Heilandes Seite,\nwandelnd in dem Licht!\r\nWill die Versuchung uns schnöde verleiten,\nlehnen wir fester dem Führer uns an.\nSicher im Schutz Seines mächtigen Armes\nstimmen wir mutig ein Jubellied an!\r\nSchreitend auf Pfaden der kindlichen Demut,\nPfaden der innigen Liebe und Treu\';\nharrend der Gnade, die Er uns verheißen,\nsingen wir immer und wieder auf\'s Neu\'!\r\nStrebend dem himmlischen Ziele entgegen,\nwo uns die Krone zum Lohne bereit.\nDort wird zum Schauen, was hier wir geglaubet,\njubelnd und jauchzend in ewiger Freud\'!'),
(9, '1675', 'Streck dich aus, Ihn zu berühren, Dein Herr zieht vorbei  -   Reach out and touch the Lord as He goes by', 'Reach out and touch the Lord as He goes by.\nYou\'ll find He\'s not too busy to hear your heart\'s cry.\nHe\'s passing by this moment, your needs to supply.\nReach out and touch the Lord as He goes by.', 'Streck\' dich aus, Ihn zu berühren, Dein Herr zieht vorbei.\nEr will dir gerne helfen, Er hört deinen Schrei.\nEr ist hier in diesem Augenblick und macht alles neu.\nStreck\' dich aus, ihn zu berühren, dein Herr zieht vorbei.'),
(9, '1676', 'Stretch out Your Hand, and heal this Nation', 'Stretch out Your hand, and heal this nation.\nStretch out Your hand, and bring restoration.\nLet Your mercy overflow us like a never failing stream.\nBy the Blood of Jesus cleanse us, oh Lord, it\'s You we seek.\nCause Your face to shine upon us again.', NULL),
(9, '1677', 'Ström durch mich Heilger Geist, ström durch mich  -  Flow through me, Holy Spirit, flow through me', 'Flow through me, Holy Spirit, flow through me.\nFlow through me, Holy Spirit, flow through me.\nAs I lift my hands to worship and to magnify Thy Name.\nFlow through me, Holy Spirit, flow through me.', 'Ström\' durch mich Heil\'ger Geist, ström\' durch mich.\nStröm\' durch mich Heil\'ger Geist, ström\' durch mich.\nMeine Hände hoch erhoben, mach\' ich Deinen Namen groß.\nStröm\' durch mich, Heil\'ger Geist, ström\' durch mich.'),
(9, '1678', 'Ströme der Liebe, Fluten der Gnad   (Fließen herab, ja, fließen herab)', NULL, 'Ströme der Liebe, Fluten der Gnad\'\nfließen vom Himmel auf uns herab,\nfüllen die Herzen bis auf den Grund;\nKranke und Schwache werden gesund.\r\nFließen herab, ja, fließen herab,\nStröme der Gnade fließen herab,\nfüllen mein Herz mit Liebe und Gnad\',\nheilende Ströme fließen herab.\r\nFülle des Segens spendet Er frei;\noh, wenn dich dürstet, komme herbei!\nWasser des Lebens heut\' für dich fließt,\nheilende Ströme fließen herab.\r\nSieh dort den Heiland dornengekrönt,\noh, wie man Ihn verschmäht und verhöhnt.\nAus Jesu Herz strömt Wasser und Blut,\nfließt auch für dich und macht alles gut.\r\nWer zu Ihm kommt, empfängt freies Heil,\nSeine Verheißung wird uns zuteil.\nFülle und Kraft im Heiligen Geist,\nJesus, der Heiland, jedem verheißt.\r\nZeichen des Endes zeigen sich schon,\nbald werden steh\'n wir vor Seinem Thron.\nDort fließt der Strom kristallhell und klar,\nwir sind beim Heiland dann immerdar!'),
(9, '1679', 'Ströme des Segens, sende sie Herr   (Ströme des Segens erwarten wir von dir o Herr)', NULL, 'Ströme des Segens, sende sie Herr,\nfülle die Herzen mit neuem Geist von dir,\nSchenk\' neues Leben, das nie vergeht,\nFrieden so reich, gib, o Herr, im Gebet.\r\nStröme des Segens erwarten wir von dir o Herr\nbittende Herzen steh\'n heut\' vor dir.\nSchenke Erweckung persönlich auch mir,\nStröme des Segens, o Herr.\r\nRühr\' an die Herzen, durch deine Hand\nlass\' hell sie leuchten, dass Jesus wird bekannt.\nSchenk\' uns die Gnade, vor dir zu steh\'n,\nlass deine Wunder, o Herr, heut\' uns seh\'n!'),
(9, '1680', 'Suche vom Grabesrand Seelen zu retten   (Jesus hat alles für alle getan)', NULL, 'Suche vom Grabesrand Seelen zu retten!\nNimm der Verlornen in Liebe dich an!\nReiche die Bruderhand, löse die Ketten,\nführe Verirrte zu Jesu hinan!\nDu, der einst Rettung fand\'st, eile zu retten!\r\nJesus hat alles für alle getan!\r\nOb sie mit bitt\'rem Hohn einst Ihn verachtet,\nwenn sie nur glauben, nimmt Jesus sie an.\nDer in der Dornenkron für uns geschmachtet,\nwartet, ob reuig ein Herz sich will nah\'n.\nSagt, ob zum Menschensohn Seelen ihr brachtet!\r\nTief in des Herzens Schacht liegt oft gefangen,\nSehnsucht nach Rettung von Sünde und Wahn.\nWeckst du mit Liebesmacht dieses Verlangen,\nfindet es endlich zur Gnade die Bahn.\nDer in die Todesnacht für uns gegangen.\r\nScheint diese Pflicht dir schwer, nimm die Beschwerden!\nJesus gibt Kraft dir, o denke daran!\nRufe noch manche her, gläubig zu werden,\ntreu ihrem Heiland zu folgen fortan!\nDass man je mehr und mehr rühme auf Erden.'),
(9, '1681', 'Suchst vergebens du Glück, Zufriedenheit   (Meine Liebe reicht aus auch für dich)', NULL, 'Suchst vergebens du Glück, Zufriedenheit,\nhat nicht oft schon enttäuscht dich dein bester Freund.\nHör\' wie Jesus dann leise zu dir spricht:\n"Meine Liebe reicht aus auch für dich!"\r\n"Meine Liebe reicht aus auch für dich",\nJesus dein Herr zu dir spricht.\n"Denn mein Wort ist wahr, Ich bin stets dir nah.\nMeine Liebe reicht aus auch für dich!"\r\nIst die Last oft schwer und du kannst nicht mehr,\nversinkt dein Lebensmut in der Sorge Meer?\nHör\' wie Jesus dann leise zu dir spricht:\n"Meine Kraft reicht aus auch für Dich!"\r\nMeine Kraft reicht aus auch für dich,\nJesus, dein Herr, zu dir spricht.\nDenn Mein Wort ist wahr,\nIch bin stets dir nah,\nMeine Kraft reicht aus auch für dich.\r\nHast du oft versagt, deinen Herrn betrübt,\nund du fragst, ob Er dich auch jetzt noch liebt.\nHör\' wie Jesus dann leise zu dir spricht:\n"Meine Gnade reicht aus auch für Dich!"\r\n"Meine Gnade reicht aus auch für dich",\nJesus dein Herr zu dir spricht.\n"Denn mein Wort ist wahr,\nIch bin stets dir nah.\nMeine Gnade reicht aus auch für dich!"'),
(9, '1682', 'Surround me oh Lord', 'Surround me oh Lord\nSurround me oh Lord\nSurround me oh Lord\nLet Your presence fill this place', 'Umgib mich oh Herr\nund lass Deine Gegenwart diesen Ort füllen'),
(9, '1683', 'Sünde kann dort nicht hinein  -  Sin will never enter in', 'Sin will never enter in,\nsin will never enter in,\nsin will never enter in,\nwe are heaven bound,\nHeaven, heaven bound,\nheaven, heaven bound,\nheaven, heaven bound,\nwe are heaven bound.', 'Sünde kann dort nicht hinein,\nSünde kann dort nicht hinein,\nSünde kann dort nicht hinein,\nweil wir himmlisch sind.\nHimmlisch, himmlisch sind,\nhimmlisch, himmlisch sind,\nhimmlisch, himmlisch sind,\nweil wir himmlisch sind.'),
(9, '1684', 'Süß ist die Hoffnung, die mein Herz erfüllt  -  Sweet is the Hope that is thrilling my Soul   (Ich weiß, ich werd Jesus einst sehn)', 'Sweet is the hope that is thrilling my soul,\nI know I’ll see Jesus some day!\nThen what if the dark clouds of sin o’er me roll,\nI know I’ll see Jesus some day!\r\nI know I’ll see Jesus some day!\nI know I’ll see Jesus some day!\nWhat a joy it will be when His face I shall see.\nI know I’ll see Jesus some day!\r\nThough I must travel by faith, not by sight,\nI know I’ll see Jesus some day!\nNo evil can harm me, no foe can affright,\nI know I’ll see Jesus some day!\r\nDarkness is gath’ring, but hope shines within,\nI know I’ll see Jesus some day!\nWhat joy when He comes to wipe out ev’ry sin.\nI know I’ll see Jesus some day!', 'Süß ist die Hoffnung, die mein Herz erfüllt:\nIch weiß, ich werd\' Jesus einst seh\'n!\nWas macht\'s, wenn auch hier mich oft Dunkel umhüllt!\nIch weiß, ich werd\' Jesus einst seh\'n!\r\nIch weiß, ich werd\' Jesus einst seh\'n,\nich weiß, ich werd\' Jesus einst seh\'n!\nWelche Freude wird\'s sein, wenn von Sünde ich rein\ndas Angesicht Jesu darf seh\'n.\r\nWenn ich hier glauben muss, ohne zu schau\'n,\nweiß ich, ich werd\' Jesus einst seh\'n!\nKein Feind kann mir schaden, vor nichts darf mir grau\'n,\nich weiß, ich wer\' Jesus einst seh\'n!\r\nNcht bricht herein, doch füllt Hoffnung mein Herz,\nich weiß, ich werd\' Jesus einst seh\'n!\nWelch Glück wenn Er kommt und tilgt allen Schmerz.\nIch weiß, ich werd Jesus Ihn seh\'n!.'),
(9, '1685', 'Sweet Holy Spirit, sweet heavenly Dove', 'Sweet Holy Spirit, sweet heavenly Dove.\nStay right here with us, filling us with Your love.\nAnd for these blessings, we lift our hearts in praise.\nWithout a doubt we\'ll know, that we have been revived.\nWhen we shall leave this place.', NULL),
(9, '1686', 'Sweet Jesus, what a Wonder You are', 'Sweet Jesus, sweet Jesus,\nWhat a wonder you are,\nYou\'re brighter than the morning star;\nYou\'re fairer, much fairer,\nThan the lily that grows by the wayside,\nPrecious, more precious than gold;\nJust like the Rose of Sharon,\nYou\'re fairer than the fair,\nYou are all my heart and soul\'s desire,\nSweet Jesus, sweet Jesus,\nWhat a wonder you are,\nYou\'re precious, more precious than gold.', NULL),
(9, '1687', 'Tag für Tag', NULL, 'Tag für Tag in allen Lebenslagen\nFind ich Kraft für meine Arbeit hier\nGott ist da ich brauch nicht zu verzagen\nJeden Grund zur Sorge nimmt er mir\nDieser Herr will mir das Beste schenken\nSchickt mir Freude und auch tiefen Schmerz\nLiebevoll will er mich dadurch lenken\nGibt mir Ruh und Frieden in mein Herz\r\nJeden Tag steht er mir treu zur Seite\nSeine Gnade ist mir immer neu\nAuch wenn ich ihm manche Not bereite\nLiebt er mich und bleibt mir ständig treu\nSchutz und Weisung will er uns heut geben\nWill uns helfen stets mit seinem Rat\nEr verheißt nicht nur das wahre Leben\nSondern hält was er versprochen hat.\r\nHilf mir Herr in allen Glaubensproben\nZu vertrauen deinem Wort allein\nAuch in diesen Zeiten will ich loben\nWeil du mir die Kraft gibst stark zu sein\nHilf mir Herr wenn Lasten mich bedrücken\nSie zu nehmen stets aus deiner Hand\nLass mich immer frohen Mutes blicken\nHin zu dem von dir verheiß´nen Land'),
(9, '1688', 'Tag für Tag in allen Lebenslagen  -  Day by Day and with each passing Moment', 'Day by day and with each passing moment,\nstrength I find to meet my trials here.\nTrusting in my Father\'s wise bestowment,\nI\'ve no cause for worry or for fear.\nHe whose heart is kind beyond all measure,\ngives unto each day what he deems best.\nLovingly, its part of pain and pleasure,\nmingling toil with peace and rest.\r\nEv\'ry day the Lord himself is near me,\nwith a special mercy for each hour.\nAll my cares he gladly bears and cheers me,\nHe whose name is Counselor and Pow\'r.\nThe protection of his child and treasure\nis a charge that on himself he laid.\n"As your days, your strength shall be in measure",\nthis the pledge to me he made.\r\nHelp me then in ev\'ry tribulation\nSo to trust your promises, O Lord,\nThat I lose not faith\'s sweet consolation\nOffered me within your holy Word.\nHelp me, Lord, when, toil and trouble meeting,\nE\'er to take, as from a father\'s hand,\nOne by one, the days, the moments fleeting,\nTill I reach the promised land.', 'Tag für Tag in allen Lebenslagen\nfind\' ich Kraft für meine Arbeit hier.\nGott ist da, ich brauch\' nicht zu verzagen,\njeden Grund zur Sorge nimmt er mir.\nDieser Herr will mir das Beste schenken,\ngibt mir Freude und auch tiefen Schmerz.\nLiebevoll will er mich dadurch lenken,\ngibt mir Ruh\' und Frieden in mein Herz.\r\nJeden Tag, steht Er mir treu zur Seite,\nSeine Gnade ist mir immer neu.\nAuch wenn ich Ihm manche Not bereite,\nliebt Er mich und bleibt mir ständig treu.\nSchutz und Weisung will Er uns heut\' geben,\nwill uns helfen stets mit Seinem Rat.\nEr verheißt nicht nur das wahre Leben,\nsondern hält was Er versprochen hat.\r\nHilf mir, Herr, in allen Glaubensproben\nzu vertrauen Deinem Wort allein.\nAuch in diesen Zeiten will ich loben,\nweil Du mir die Kraft gibst stark zu sein.\nHilf mir, Herr, wenn Lasten mich bedrücken,\nsie zu nehmen stets aus Deiner Hand.\nLass mich immer frohen Mutes blicken\nhin zu dem von Dir verheiß\'nen Land.'),
(9, '1689', 'Talk about happy, I\'m so happy   (2 Chorusse)', 'Talk about happy, I\'m so happy,\nsince I laid my burdens down.\nTalk about happy, I\'m so happy,\nsince I laid my burdens down.\r\nI\'m gonna walk with, walk with Jesus,\nsince I laid my burdens down.\nI\'m gonna walk with, walk with Jesus,\nsince I laid my burdens down.', NULL),
(9, '1690', 'Taste and see that the Lord is good   (Chorus)', 'Taste and see that the Lord is good.\nTaste and see that the Lord is good.\nTaste and see that the Lord is good.\nBlessed is the man that trusteth in Him.\nTaste and see that the Lord is good.', NULL),
(9, '1691', 'Tell me the old, old Story   (Tell me the old, old Story)', 'Tell me the old, old story\nof unseen things above.\nOf Jesus and His glory,\nof Jesus and His love.\nTell me the story simply,\nas to a little child,\nfor I am weak and weary,\nand helpless and defiled.\r\nTell me the old, old story,\ntell me the old, old story,\ntell me the old, old story\nof Jesus and His love.\r\nTell me the story softly,\nthat I may take it in.\nThat wonderful redemption,\nGod\'s remedy for sin.\nTell me the story often,\nfor I forget so soon.\nThe early dew of morning,\nhas passed away at noon.\r\nTell me the same old story,\nwhen you have cause to fear.\nThat this world\'s empty glory,\nis costing me too dear.\nYes, and when that world\'s glory\nis dawning on my soul,\ntell  me the old, old story:\nChrist Jesus makes thee whole.', NULL),
(9, '1692', 'Teuer wert ist diese Botschaft  -  \'Tis a true and faithful Saying   (O teuerwerte Botschaft)', '\'Tis a true and faithful saying,\nJesus died for sinful men.\nThough we’ve told the story often,\nwe must tell it o’er again.\r\nOh, glad and glorious Gospel!\nWith joy we now proclaim.\nA full and free Salvation,\nthrough faith in Jesus’ name!\r\nHe has made a full atonement,\nnow His saving work is done.\nHe has satisfied the Father,\nWho accepts us in His Son.\r\nStill upon His hands the nail prints,\nand the scars upon His brow.\nOur Redeemer, Lord, and Saviour,\nin the glory standeth now.\r\nBut remember, the same Jesus\nin the clouds will come again.\nAnd with Him His blood-bought people\nevermore shall live and reign.', 'Teuer wert ist diese Botschaft,\ndass der Herr sein Leben gab.\nLasst mich\'s noch einmal erzählen\nwas ich oft erzählet hab.\r\nO teuerwerte Botschaft,\nwie bleibt sie immer neu.\nO glaubt an Jesu Namen,\nund werdet heil und frei!\r\nVoll und gültig ist Sein Opfer.\nWas zu tun war ist getan.\nOffen steht die Tür zum Vater.\nFrei nimmt Er die Sünder an.\r\nIn den Händen Nägelmale\nan der Stirn der Dornen Spur,\nin dem Schmuck der Liebe steht Er\nwie Er auf zum Vater fuhr.\r\nEinst erscheinet Er als König,\nder als Knecht zuvor erschien.\nDie das Kreuz Ihm nachgetragen,\ndann als Sieger mit Ihm zieh\'n.'),
(9, '1693', 'Teurer Heiland, Dein Blut diese heilige Flut, macht von Sünde mich helle und rein   (Christi Blut, floss vom Kreuz, floss vom Kreuz mir zugut)', NULL, 'Teurer Heiland, Dein Blut, diese heilige Flut,\nmacht von Sünde mich helle und rein.\nTilget all meine Schuld bringt auch mir Gottes Huld,\nund dies Blut ist mein Leben allein.\r\nChristi Blut, floss vom Kreuz, floss vom Kreuz mir zugut.\nD\'rum in meinem Gesang ist der seligste Klang:\nChristi Blut, floss vom Kreuz mir zugut.\r\nWenn mein Herze d\'ran denkt, dass es nun ist besprengt,\no wie jauchzt es und rühmt dieses Blut.\nKein Gericht nun mehr droht, und ob nahet der Tod,\nauch zum Sterben gibt\'s freudigen Mut.\r\nEinst in Salems Gefild\' wird mein Sehnen gestillt,\nund ich jauchze im höheren Chor.\nDoch auch dort im Gesang steigt als jubelnder Klang\nnur der Ruhm dieses Blutes empor.'),
(9, '1694', 'Thank God for you, for every Prayer that you pray', 'Thank God for you.\nThank God for you.\nFor every prayer that you pray\nand every kind word you say.\nThank God for you.\nThank God for you.\nMay the blessings of the Lord\nrest on you.', NULL),
(9, '1695', 'Thank You for Your Mercy, thank You for Your Grace', 'Thank You for Your mercy, thank You for Your grace.\nThank You for Your Blood that\'s made a way\nto come into Your presence and glorify Your Name.\nLord, I stand amazed at what I see.\r\nGreat is Your mercy t\'wards me, Your love and kindness t\'wards me.\nYour tender mercy I see, Day after day.\nForever faithful t\'wards me always providing for me.\nGreat is Your mercy t\'wards me, great is Your grace.\r\nYour promises are ageless, Your Love will never end.\nTo a thousand generations Your covenant will stand.\nShowing grace and mercy to those who fear Your name.\nEstablishing Your righteousness and praise.', NULL),
(9, '1696', 'Thank you Jesus   (3 Chorusse)', 'Thank You Jesus, thank You Jesus,\nthank You Jesus, thank You Jesus.\nThank You Jesus, thank You Jesus,\nthank You Jesus, thank You Jesus.\r\nHalleluja, Halleluja,\nHalleluja, Halleluja.\nHalleluja, Halleluja,\nHalleluja, Halleluja.\r\nJesus died for my salvation.\nJesus died for my salvation.\nJesus died for my salvation.\nJesus died for my salvation.', NULL),
(9, '1697', 'Thank you Jesus for the blood applied (Chorus)', 'I was a wretch,\nI remember who I was.\nI was lost, I was blind,\nI was running out of time.\nSin separated,\nthe breach was far too wide.\nBut from the far side of the chasm\nYou held me in your sight.\r\nSo You made a way\nacross the great divide.\nLeft behind, heavens throne\nto build it here inside.\nAnd there at the cross\nYou paid the debt I owed.\nBroke my chains, freed my soul.\nFor the first I had hope.\r\nThank You Jesus for the blood applied.\nThank You Jesus it has washed me white.\nThank You Jesus You have saved my life,\nbrought me from the darkness into glorious light.\r\nYou took my place,\nlaid inside my tomb of sin.\nYou were buried for three days\nand then You walked right out again.\nAnd now death has no sting\nand life has no end,\nfor I have been transformed\nby the blood of the lamb.\r\nThere is nothing stronger\nthen the wonder working power of the blood,\nthe blood!\nthat calls us sons and daughters.\nWe are ransomed by our father\nthrough the blood,\nthe blood. (2x)\r\nGlory to His name,\nglory to His name,\nthere to my heart was the blood aplied,\nglory to His name.', 'Ich denk‘ zurück,\nweiß genau noch, wer ich war,\nwar verlor’n, war so blind,\nwar dem Ende schon so nah.\nSchuld trennte mich\ndie Kluft war viel zu weit,\ndoch Deine gnadenvollen Augen\nsah’n mich aus der Ewigkeit.\r\nDu machtest Bahn,\nhobst die große Trennung auf,\nDu verließest Deinen Thron,\nbaust ihn dafür in mir auf.\nDort an dem Kreuz,\nbezahltest Du den Preis.\nBrachst die Ketten, gabst mir Hoffnung,\nhast die Seele ganz befreit.\r\nDanke, Jesus, Dein Blut floss für mich,\ndanke, Jesus, Dein Kreuz rettet mich.\nDanke, Jesus, frei und rein bin ich,\naus der Dunkelheit ziehst Du mich in Dein Licht.\r\nDu warst der Gott,\nder für mich Sein Leben gab,\ndoch noch länger als drei Tage\nhielten Dich nicht Tod und Grab.\nDu kamst hervor,\nund der Tod verlor die Macht,\nund ich bin ganz verwandelt,\ndenn Dein Blut ist voller Kraft!\r\nJesus, nichts ist größer\nals die wunderbare\nKraft in Deinem Blut,\nDeinem Blut!\nWir sind Deine Kinder,\ndie Erlösten uns’res Vaters\ndurch Dein Blut,\ndurch Dein Blut! (2x)\r\nEhre Seinem Nam\',\nEhre Seinem Nam\',\ndort an meinem Herz wurde das Blut angebracht,\nEhre seinem Nam\'.'),
(9, '1698', 'Thank You Jesus for the Things that You hav done for us', 'Thank You, Jesus!\nFor the things that You have done for us!\nThough I can\'t repay,\nthe love that You have given me,\nI thank You Lord!\r\nThank you, Jesus,\nfor the grace that You have given us.\nThough I can\'t repay\nbut from my heart, I´d like to say,\nI thank You, Lord.', 'Danke Jesus für die Dinge die DU für mich getan,\nObwohl ich Deine Liebe nicht zurückzahlen kann\ndanke ich Dir\r\nDanke Jesus, dür die Gnade die Du mir gegeben hast\nObwohl ich es nicht zurückzahlen kann,\ndoch von meinem Herzen möchte ich sagen: Ich liebe Dich'),
(9, '1699', 'Thank You Lord, I just wanna thank You', 'Thank You Lord,\nI just wanna thank You,\nI just wanna thank You.\nThank You Lord,\nI just wanna thank You,\nI just wanna thank You.\r\nI just wanna take a little time right now\nand thank the Lord for all He\'s done for me.\nI just wanna take a little time right now,\nand thank the Lord for all He\'s done for me.\r\nThank You Lord, thank You Lord.\nThank You Lord, thank You Lord.\r\nI just wanna take little time...\nI just wanna take little time...', NULL),
(9, '1700', 'Thanks, thanks, I give You thanks   (Chorus)', 'Thanks, thanks,\nI give You thanks\nfor all You\'ve done.\nI am so blessed,\nmy soul has found rest.\nOh Lord I give You thanks.', NULL),
(9, '1701', 'That sounds like Home to me', 'That sounds like home to me,\nlike where I want to be.\nThere\'ll be no tears\nto dim our eyes again.\nThe hills will echo with the story\nas we sing of His grace and glory.\nWhere the saints of God will be\nthat sounds like home to me.', NULL),
(9, '1702', 'That\'s how it\'s gonna be when Jesus comes', 'That\'s how it\'s gonna be\nwhen Jesus comes.\nThat\'s how it\'s gonna be\nwhen Jesus comes.\nThat\'s how it\'s gonna be\nwhen Jesus comes,\nHappiness, gladness and joy.\r\nNo more crying, no more sorrow,\nno more tears when Jesus comes.\nNo more crying, no more sorrow,\nno more tears when Jesus comes.', NULL),
(9, '1703', 'The Battle is the Lords', 'There is a Source\nIn times of need\nThat gives me hope\nAnd brings me peace\nIn every trial\nTru\' every test\nMy Savior stands in my defence\r\nSo when the road you walk\nLeaves you tired and worn\nAll your strength is gone\nAnd your heart feels torn\nRemember God is greater than the storm\nTake courage for the battle is the Lord\'s\r\nAnd when the water rise\nHe calls my name\nAnd bids me come out on the waves\nHe holds my hand\nLest I should falter\nAnd makes me stand upon the water', 'Ich finde Kraft\nzur Zeit der Not\ndie Hoffnung liegt\nin meinem Gott\nIn jedem Kampf\nin jedem Test\nsteht Er mir bei\nund hält mich fest.\r\nWenn du auf deinem Weg\ndeine Kraft verlierst,\nwenn dein Herz zerbricht\nund Du müde wirst\nvergiss nie, Gott ist auch im Sturm bei dir,\nsei mutig, denn es kämpft für dich der Herr.\r\nWenn sich die Flut erhebt,\nruft mich mein Herr\ngrösser ist Er\nals Sturm und Meer,\nhält meine Hand,\nwird nie versagen\nund selbst das Wasser\nwird mich noch tragen.'),
(9, '1704', 'The Church’s one Foundationis Jesus Christ our Lord.', 'The church’s one foundation\nis Jesus Christ, our Lord.\nWe are a new creation\nby water and the Word.\nFrom heav’n He came and taught us\nwhat perfect love can be.\nThrough life and death He sought us,\nand rose to set us free.\r\nThe church in ev’ry nation\nis one through all the earth.\nOur charter of salvation,\none God, one faith, one birth.\nOne name together blessing,\none holy food we share,\nto one hope ever pressing,\nat one in work and prayer.\r\nStill, schisms, tribulation,\nand hatred fuel our war.\nWe wait the consummation\nof peace forevermore.\nThe saints their watch are keeping,\ntheir cry goes up “How long?”\nAnd soon the night of weeping\nshall be the morn of song.\r\nYet we on earth have union\nwith God, the Three in One,\nand mystic, sweet communion\nwith those whose rest is won.\nOh, happy ones and holy!\nGod, give us grace that we,\nlike them, the meek and lowly,\nmay live eternally.', NULL),
(9, '1705', 'The circuit-rider Preacher went riding through the Land   (Leaning, leaning, leaning on the everlasting arm)', 'The circuit-rider preacher went riding through the land,\nwith a rifle on his shoulder and a bible in his hand.\nHe told the prairie people of a blessed promised land\nas he went riding, singing along.\r\nLeaning, leaning,\nleaning on the everlasting arm.\nLeaning, leaning,\nleaning on the everlasting arm.\r\nHe preached the coming judgment of fire and brimstone\nand a glorious, endless heaven of the justified alone.\nAs he rode across the mountains you could hear him sing this song,\nas he went riding on.', NULL),
(9, '1706', 'The cross', 'To some it\'s just an emblem a formality.\nIt\'s a symbol that\'s been used so frequently.\nMany blaspheme and despise.\nThough it\'s ancient, it abides.\nA shrine to death that stands for life to me.\r\nThere was a cross made for the Son of God at Calvary.\nTwo pieces of rough timber on a hill.\nThrough His hands and through His feet,\nHe took the nails for you and me.\nAngels watched as He died for the lost.\nThough He could have walked away He chose the cross.\r\nYou see why this old emblem is so dear to me.\nIt stood for suffering, yet it brought us peace.\nIt bridged the gap for me.\nOffered cleansing for our sins.\nAn icon that reminds us that we\'re free.\r\nGod forbid that I should ever let my memory fade.\nBut forever keep the cross in view for that\'s where I was saved.', 'Für einige ist es nur ein Emblem, eine Formalität\nEIn Symbol das so oft benutzt wurde\nVieel verspotten und verachten es\nObwohl es alt ist bleibt es bestehn\nEin Schrein des Todes das füer mich Leben bedeutet\r\nDort war ein Kreuz für den Sohn Gottes auf Golgatha\nZweit Stücke rauhes Holz auf einem Hügel\nDurch seine Hände und Füße\nNahm er die Nägel für dich und mich\nEngel schauten zu wie Er für die Verlorenen starb\nObwohl er hätte weggehen können erwählte Er das Kreuz\r\ndarum ist dieses alte  Emblem mit so kostbar\nEs stand für Leiden und brachte usn Frieden\nEs überbrückte die Kluft für mich\nGab Reinigung für unsere Sünden\nEin Zeichen dass uns daran erinnert dass wir frei sind\r\nGott lass moch niemals vergessen\nAber für immer das Kreuz vor Augen halten\ndenn dort wurde ich gerettet'),
(9, '1707', 'The disciples were praying for the Power to fall   (Shut in with God in the secret Place)', 'The disciples were praying for the power to fall.\nTen days they did tarry, on God they did call.\nThen God sent His spirit to baptize them all.\nFor they had been shut in with God.\r\nShut in with God in the secret place,\nthere in the Spirit beholding His face,\ngaining new power to run in the race,\nI love to be shut in with God.\r\nOf all pleasant places on land or on sea,\nthere’s no place on earth that is sweeter to me,\nthan to kneel at the feet of my Master and Lord,\nfor there, I’ll be shut in with God.\r\nThe pathway to Heaven, though rugged it may be,\nI’ll travel ‘til my precious Saviour I’ll see.\nThen the gates of that city will open for me,\nand there I’ll be shut in with God.', NULL),
(9, '1708', 'The Father has a plan   (Stand still und let God move, standing still is hard to do)', 'The Father has a plan, though it’s hard to see it now,\nyou feel you’re all alone, but He is there no doubt.\nWhen the storm around you rages, and you’re tossed to and fro,\nwhen you’re faced with life’s decisions,\nand not sure which way to go.\r\nStand still und let God move, standing still is hard to do!\nWhen you feel you have reached the end,\nHe’ll make a way for you, stand still and let Go move.\nThe answer will come, but only in His time.\nStand still and let God move, stand still and let God move.\r\nWhen the enemy surrounds you, and the walls are closing in.\nWhen the tide is swiftly rising, and you wounder where He’s been.\nFriend, there never was a moment, that His arms weren’t reaching out.\nYou can rest assured and be secured, God is moving right now.', 'Der Vater hat einen Plan, obwohl es jetzt schwer ist ihn zu sehen.\nDu fühlst, als wärest du ganz allein, aber kein Zweifel, Er ist da.\nWenn der Sturm um dich herum tobt, und du wirst hin und her geworfen. Wenn du mit Entscheidungen des Lebens konfrontiert wirst,\nund bist nicht sicher, welchen Weg du gehen sollst.\r\nDann steh still und lass Gott wirken, still zu stehen ist so schwer!\nWenn du fühlst, du kannst nicht mehr weiter, dann wird ER einen Weg für dich machen. Dann steh still und lass Gott wirken. Die Antwort wird kommen, aber zu Seiner Zeit! Steh still und lass Gott wirken.\r\n(Wenn der Feind um dich herum ist, und du bist von Mauern eingeschlossen. Wenn die Flut rasch ansteigt, und du fragst dich, wo Er gewesen ist. Freund, da war nie ein Moment, in dem Seine Arme sich nicht ausgestreckt haben. Du kannst versichert und sicher sein,\nGott bewegt sich grad jetzt.)'),
(9, '1709', 'The Fight is on, the Trumpet sound is ringing out   (The Fight is on, oh Christian Soldiers)', 'The fight is on, the trumpet sound is ringing out,\nThe cry "To arms" is heard afar and near;\nThe Lord of hosts is marching on to victory,\nThe triumph of the right will soon appear.\r\nThe fight is on, oh Christian soldiers,\nAnd face to face in stern array,\nWith armour gleaming, and colours streaming,\nThe right and wrong engage today;\nThe fight is on, but be not weary,\nBe strong and in his might hold fast;\nIf God be for us, his banner o\'er us,\nWe\'ll sing the victor\'s song at last.\r\nThe fight is on, arouse ye soldiers brave and true,\nJehovah leads, and vict\'ry will assure;\nGo buckle on the armor God has given you,\nAnd in his strength unto the end endure.\r\nThe Lord is leading on to certain victory,\nThe bow of promise spans the eastern sky;\nHis glorious name in every land shall honored be,\nThe morn will break, the dawn of peace is nigh.', NULL),
(9, '1710', 'The Grace of God it is so sweet   (Chorus)', 'The grace of God, it is so sweet.\nThe grace of God, it is so sweet.\nThe grace of God, it is so sweet.\nThe grace, the grace, the grace of God.', NULL),
(9, '1711', 'The Holy Ghost Power is moving just like a Magnet', 'The Holy Ghost power is moving\njust like a magnet.\nThe Holy Ghost power is moving\njust like a magnet.\nMoving here moving there\nJust as the days of Pentecost.\nThe Holy Ghost power is moving\njust like a magnet.\r\nThe Message of the hour is moving\njust like a magnet.\nThe Message of the hour is moving\njust like a magnet.\nMoving here moving there\nJust as the days of Pentecost.\nThe Message of the hour is moving\njust like a magnet.', NULL),
(9, '1712', 'The Hour of shaking is now at hand when many Builders will realize   (Nowe more than Conquerors we are)', 'The hour of shaking is now at hand,\nwhen many builders will realize,\nthey built on sinking sand.\nFor the stone that those builders refused,\nthey have rejected God\'s revelation of the Son of man.\nBut unto you He made a treasure\nand an anchor to your soul.\nAll the evil of this world you\'ve overcome.\r\nNowe more than conquerors we are\nthrough the power of Jesus\' Name.\nPriests and kings he has made us\nand forever we shall reign.\r\nMany pressures came outside and within\nand temptations did arise,\nto take a look unto the other side.\nBut by the grace of God we resisted sin\nand the devils were surprised.\nWe knew by  the Word of the Lord\nwe were tested and tried.\nBut unto you who look above\nthrough the windows of perfect love\nGod has sent to us His Son on the wings of a dove.\r\nAs the new ministry becomes reality\nnow men will see with their eyes\nthe Work of God expressed through His little Bride.\nEvery knee must bow, every tongue confess.\nMen\'s folly be made manifest.\nThe foolish man won\'t be able to understand.\nBut unto the wise who understand, great exploits are now at hand.\nFor Michael\'s feet are on the sea and on the land.', NULL),
(9, '1713', 'The Joy of the Lord is the Strength of His People   (Oh, the Joy of the Lord is my Strength and my Song)', 'The joy of the Lord is the strength of His people,\nthe sunshine that scatters their sadness and gloom.\nThe fountain that bursts in the desert of sorrow,\nand sheds o’er the wilderness, gladness and bloom.\r\nOh, the joy of the Lord is my strength and my song,\nour sorrow and sighing are o’er.\nWe’ll rejoice in the Lord,\nwe’ll rejoice in the Lord,\nwrejoice in the Lord evermore.\r\nThe joy of the Lord is our strength for life’s burdens,\nand gives to each duty a heavenly zest.\nIt sets to sweet music the task of the toiler,\nasoftens the couch of the laborer’s rest.\r\nThe joy of the Lord is our strength for life’s trials,\nand lifts the crushed heart above sorrow and care.\nLike the nightingale’s notes, it can sing in the darkness,\narejoice when the fig tree is fruitless and bare.\r\nThe joy of the Lord is the hope of our calling,\nand oh, for His coming, how fondly we pray!\nWhen we shall return with rejoicing to Zion,\nand sorrow and sighing shall vanish away.', NULL),
(9, '1714', 'The King is coming in Glory, to catch His Bride away   (The King is coming, Hallelujah! He\'s coming in the Air)', 'The King is coming in glory, to catch His bride away.\nIt may be in the morning it may be at mid-day.\nAt the even or midnight, the trump will sound so clear.\nThe dead in Christ, and we that live, His voice shall hear.\r\nThe King is coming, hallelujah! He\'s coming in the air.\nThe fig tree is budding, the signs are everywhere.\nThe saints are looking ever up-ward while jour\'ning on their way.\nHe\'s coming, halleluja! To catch his bride away.\r\nBehold! He cometh, and leaping and skipping o\'er the hills.\nLike the young roe, like the young hart, my soul with rapture thrills.\nThru the window He\'s looking, Thru the lattice-work is seen.\nThe winter\'s past, the rain is o\'er, the figs are green.\r\nThe King is coming , "Be ready," to meet Him on that day.\nWith your heart right, with your robes white.\nAnd in this holy way; like the light\'ning that flashes.\nIn the twinkling of an eye, or Lord shall come to claim His own,\nHe\'s drawing nigh.', NULL),
(9, '1715', 'The Law of the Lord is perfect, converting the soul   (Psalm 19)', 'The law of the Lord is perfect,\nConverting the soul:\nThe testimony of the Lord is sure,\nMaking wise the simple.\nMore to be desired are they than gold,\nYea, than much fine gold:\nSweeter also than honey\nand the honeycomb.\r\nThe statutes of the Lord are right,\nRejoicing the heart:\nThe commandment of the Lord is pure,\nEnlightening the eyes.\nMore to be desired are they than gold,\nYea, than much fine gold:\nSweeter also than honey\nand the honeycomb.\r\nThe fear of the Lord is clean,\nEnduring for ever:\nThe judgments of the Lord are true\nAnd righteous altogether.\nAnd in the keeping of them\nThere is great reward,\nThere is great reward.\nIn the keeping of them\nThere is great reward.', NULL),
(9, '1716', 'The Lion of Judah shal break every Chain   (Chorus)', 'The Lion of Judah shall break every chain,\nand give to us the victory again and again.\nThe Lion of Judah shall break every chain,\nand give to us the victory again and again.', NULL),
(9, '1717', 'The Lord is so good, the Lord is good', 'The Lord is so good, the Lord is good,\nThe Lord is so good, the Lord is good.\nHe gave us His Spirit, the Lord is good\nHe gave us His Spirit, the Lord is good\r\nWe praise our Lord, we praise our Lord,\nWe praise our Lord, we praise our Lord,\nHe sent us His Prophet, we praise our Lord.\nHe sent us His Prophet, we praise our Lord.\r\nWe thank our Lord, we thank our Lord,\nWe thank our Lord, we thank our Lord,\nHe gave us this Message, we thank our Lord.\nHe gave us this Message, we thank our Lord.', NULL),
(9, '1718', 'The Lord reigneth, the Lord reigneth', 'The Lord reigneth, the Lord reigneth.\nBlessed be the name of our God.\nThe Lord reigneth, the Lord reigneth.\nBlessed be the name of our God.\nLet the heavens be glad\nand the earth rejoice,\nlet men say among the nations:\nThe Lord reigneth, the Lord reigneth,\nblessed be the name of our God.', NULL),
(9, '1719', 'The Lord spoke to Moses and told him what to say   (Let the Death Angel pass, God\'s Bride\'s safe at last)', 'The Lord spoke to Moses and told him what to say\nto the children of Israel in Goshen that day.\nSlay the lamb, take the blood, strike the post of the door,\nfor I\'ll pass through Egypt this night and smite all the first born.\r\nLet the death angel pass, God\'s bride\'s safe at last\nin the token He gave that we should be saved.\nOh, halleluja and glory to God.\nThe blood\'s been applied, the spirit abides.\nLet the death angel pass.\r\nThe sweet Holy Spirit is the token today\nand those who are under it,\nGod said would be saved.\nOutside the token the lost would be found.\nSo if you want your loved ones saved\nyou better get them in now.', NULL),
(9, '1720', 'The mighty God is Jesus, the Prince of Peace is He   (It’s all in Him, it’s all in Him)', 'The Mighty God is Jesus, the Prince of Peace is He,\nthe Everlasting Father, the King eternally,\nthe wonderful in wisdom by whom all things were made.\nThe fullness of the Godhead in Jesus is display’d.\r\nIt’s all in Him, it’s all in Him,\nthe fullness of the Godhead is all in Him.\nIt’s all in Him, it’s all in Him,\nthe Mighty God is Jesus, and it’s all in Him!\r\nEmmanuel, God with us, Jehovah Lord of hosts,\nthe omnipresent Spirit who fills the universe,\ntAdvocate, the High Priest, the Lamb for sinners slain,\nThe Author of redemption, O glory to His name!\r\nThe Alpha and Omega, Beginning and the End,\nthe Living Word incarnate, the helpless sinner’s Friend.\nOur wisdom and perfection, our righteousness and pow’r.\nYea, all we need is Jesus, we find this very hour.\r\n\'Our God for whom we’ve waited\', will be the glad refrain\nof Israel recreated when Jesus comes again.\nLo! He will come and save us, our King and Priest to be,\nfor in Him dwells all fullness, and Lord of all is He!', NULL),
(9, '1721', 'The most precious Name is Jesus   (Chorus)', 'The most precious name is Jesus.\nThe most precious love is His own.\nThe most precious name is His name.\nThe most precious place is His presence.', NULL),
(9, '1722', 'The next Hand you shake could be the Hand of the Saviour', 'The next hand you shake\ncould be the hand of the Saviour.\nThe next step you take,\ncould be on streets of purest gold.\nOh your next meal we take\ncould be the marriage supper.\nAnd the next voice you hear\ncould be Him saying: "Well done!"', NULL),
(9, '1723', 'The noble Promise for the Bride was that soon, Jesus would come again   (Churches are still waiting that Jesus will come)', 'The noble promise for the Bride was\nthat soon, Jesus would come again.\nYes it\'s true that time is phasing out.\nSo, check the promise, He would come again.\nScoffers are scolding as in the days of Noah.\nDoubters are doubting as in the days of Gomorrah.\nBut the Son of Man has been revealed.\nAnd we know that we\'re at the end.\r\nChurches are still waiting that Jesus will come.\nThey are blind to see that Jesus is come.\nBut the Bride knows that Jesus is here.\nShe feels the power of the Third pull.\nIt\'s the Pillar of Fire\'s rapture round call.\nThe Seals are opened calling the roll.\nRejoice my brother/sister He\'s come again.\nLet\'s climb higher Jesus is come.\nWith the rapture Jesus is come.\nRejoice my brother/sister He\'s come again.\r\nBrother, don\'t give up; the world may keep back,\nas long as you know that He\'s come again.\nSigns and wonders in heaven and on earth,\ndon\'t you see, that He\'s come again.\nThe Prophet cried out with a loud voice\nSaying: "Look up, behold Christ!"\nIn 1963 He was seen on a cloud He came down.', NULL),
(9, '1724', 'The Promise', 'I never said that I would give you silver or gold\nOr that you would never feel the fire or shiver in the cold\nBut I did say you\'d never walk through this world alone\nAnd I did say, don\'t make this world your home\r\nI never said that fear wouldn\'t find you in the night\nOr that loneliness was something you\'d never have to fight\nBut I did say I\'d be right there by your side\nAnd I did say I\'ll always help you fight\r\nCause you know I made a promise that I intend to keep\nMy grace will be sufficient in every time of need\nAnd my love will be the anchor that you can hold onto\nThis is the promise, this is the promise I made to you\r\nI never said that friends would never turn their backs on you\nOr that the world around you wouldn\'t see you as a fool\nBut I did say like me you\'ll surely be despised\nAnd I did say my ways confound the wise\r\nI didn\'t say you\'d never taste the bitter kiss of death\nOr have to walk through chilly Jordan to enter into rest\nBut I did say I\'d be waiting right on the other side\nAnd I did say I\'ll dry every tear you cry\r\nCause you know I made a promise that I\'ve prepared a place\nAnd some day sooner than you think you\'ll see me face to face\nAnd you\'ll sing with the angels and a countless multitude\nThis is the promise, this is the promise I\'ve made to you\r\nSo just keep on walkin\', don\'t turn to the left or right\nAnd in the midst of darkness, let this be your light\nThat hell can\'t separate us and you\'re gonna make it through\nThis is the promise, this is the promise I\'ve made to you\nOh, this is the promise, this is the promise I\'ve made to you', 'Ich habe nie gesagt, dass ich dir Silber oder Gold geben würde\nOder dass du nie das Feuer spüren oder in der Kälte zittern würdest\nAber ich habe gesagt, du würdest nie allein durch diese Welt gehen\nUnd ich habe gesagt, mach diese Welt nicht zu deinem Zuhause\r\nIch habe nie gesagt, dass die Angst dich in der Nacht nicht finden würde\nOder dass Einsamkeit etwas ist, das du nie bekämpfen musst\nAber ich habe gesagt, dass ich immer an deiner Seite sein werde\nUnd ich habe gesagt, dass ich dir immer helfen werde zu kämpfen\r\nDenn du weißt, ich habe ein Versprechen gegeben, das ich zu halten gedenke\nMeine Gnade wird in jeder Zeit der Not ausreichend sein\nUnd meine Liebe wird der Anker sein, an dem du dich festhalten kannst\nDies ist das Versprechen, dies ist das Versprechen, das ich dir gegeben habe\r\nIch habe nie gesagt, dass Freunde sich nie von dir abwenden würden\nOder dass die Welt um dich herum dich nicht als Narr sehen würde\nAber ich habe gesagt, dass du wie ich verachtet werden wirst\nUnd ich habe gesagt, dass meine Wege die Weisen verwirren\r\nIch habe nicht gesagt, dass du nie den bitteren Kuss des Todes schmecken wirst\nOder dass du durch den kalten Jordan gehen musst, um zur Ruhe zu kommen\nAber ich sagte, ich würde auf der anderen Seite warten\nUnd ich habe gesagt, dass ich jede Träne trocknen werde, die du weinst\r\nDenn du weißt, dass ich ein Versprechen gegeben habe, dass ich einen Ort vorbereitet habe. Und eines Tages, früher als du denkst, wirst du mich von Angesicht zu Angesicht sehen. Und du wirst mit den Engeln und einer unzähligen Schar singen. Dies ist das Versprechen, dies ist das Versprechen, das ich dir gegeben habe\r\nAlso geh einfach weiter, dreh dich nicht nach links oder rechts\nUnd inmitten der Dunkelheit, lass dies dein Licht sein\nDass die Hölle uns nicht trennen kann und du es schaffen wirst\nDies ist das Versprechen, dies ist das Versprechen, das ich dir gegeben habe\nOh, dies ist das Versprechen, dies ist das Versprechen, das ich dir gegeben habe'),
(9, '1725', 'The Sands have been washed in the Footprints', 'The sands have been washed in the footprints\nOf the Stranger on Galilee\'s shore,\nAnd the voice that subdued the rough billows,\nWill be heard in Judea no more.\nBut the path of that lone Galilean\nwith joy I will follow today,\nAnd the toils of the road will seem nothing,\nWhen I get to the end of the way. (2x)\r\nThere are so many hills to climb upward,\nI often am longing for rest,\nBut He who appoints me my pathway,\nKnows just what is needful and best,\nI know in His word He hath promised\nThat my strength, "it shall be as my day."\nAnd the toils of the road will seem nothing,\nWhen I get to the end of the way. (2x)\r\nHe loves me too well to forsake me\nOr give me one trial too much,\nAll His people have been dearly purchased,\nAnd Satan can never claim such.\nBy and by I shall see Him and praise Him,\nin the city of unending day.\nAnd the toils of the road will seem nothing,\nWhen I get to the end of the way. (2x)\r\nWhen the last feeble step has been taken,\nAnd the gates of that city appear,\nAnd the beautiful songs of the angels\nfloat out on my listening ear.\nWhen all that now seems so mysterious\nWill be bright and as clear as the day.\nThen the toils of the road will seem nothing.\nWhen I get to the end of the way. (2x)', NULL),
(9, '1726', 'The Sheep of His Pasture have gathered', 'The sheep of His pasture have gathered\nto hear what the Shepherd would say.\nHis voice like the sound of slow waters,\ncame rippling through vessels of clay.\r\n\'Tis the voice that brought forth creation\nand set all the stars in array,\nand speaks words of Life and of wisdom,\nin the midst of His people today.\r\nThrough prophets,\nby precious blood purchased,\ncleansed and surrendered and filled.\nAnd set in the body for service,\nas the head of the body hath willed.', NULL),
(9, '1727', 'The Sun, it will never go down in that City', 'The sun, it will never go down in that city,\nthe sun, it will never go down.\nThe flowers are blooming forever,\nand the sun, it will never go down.\r\nI feel like traveling on, I do,\nI feel like traveling on;\nthe flowers are blooming forever,\nand the sun, it will never go down.\r\nI feel like shouting, sometimes I do.\nI feel like shouting, I do;\nthe flowers are blooming forever,\nand the sun, it will never go down.', NULL),
(9, '1728', 'The Voice of my Beloved   (It\'s manifesting Time)', 'The voice of my Beloved!\nBehold!  He quickly comes!\nSweeping over the mountains,\nover the hills He runs!\nI long to hear His voice!\nI long to hear Him say:\n"Arise, my love, my fair one,\ncome away".\r\nIt\'s manifesting time.\nThe fruits are on the vine.\nAnd the Lovely One\nis coming in plain view.\nOh, to cap God\'s chosen Bride,\nredemption draweth nigh.\nHe\'s that Lovely One,\nHe\'s coming in plain view!\r\nThe grapes are yours and mine,\nlittle foxes spoil the vine.\nFor the vineyard blossoms forth\nher harvest time!\nKeep your eyes on things above.\nDon\'t look at me or you.\nSee that Lovely One,\nHe\'s coming in plain view!\r\nIn the cleft of the rock,\nin the secret place so high!\n\'Til the daybreak and the shadows flee away!\nIn that mountain place,\na sweet smell is coming thro\'.\nHe\'s that Lovely One,\nHe\'s coming in plain view!', NULL),
(9, '1729', 'The Wind is blowing again, the wind is blowing again', 'The wind is blowing again, the wind is blowing again.\nAs of the days of Pentecost, the wind is blowing again.\nThe wind is blowing again, the wind is blowing again.\nAs of the days of Pentecost, the wind is blowing again.', NULL),
(9, '1730', 'The Words of Christ, good Teacher', 'The words of Christ, good Teacher\nare hidden in us, deep in our Hearts.\nAnd you and I are all the Letter of Christ.\nIt\'s read by the people on the earth.\nThe Great Book is our earthly life,\nand the wind of days turns the pages.\nThere are pains and sufferings, and bright joy\nshines as a ray of light on those pages.\nThere are fervent hearts, labours, our longings,\nquiet prayers and the cry of the soul.\nThese pages will tell of our life,\nthey are alive and they speak.\r\nPeople read the book of our life.\nThey want to see the Lord.\nIs the life of Christ well seen in us?\nAnd can their eyes read what\'s needed?\nChrist has written the Letter with His Love,\nwith His sacrifice, His Holy Blood.\nOh, if we had only such a life\nthat this precious writing would not be worn out!\nThis is a writing of the truth and deep faith,\npatience and unfailing love.\nMay all these feelings never fade in us\nthat people could recognize Christ.\r\nAnd you and I are all the letter of Christ.\nIt\'s read by the people on the earth.', NULL),
(9, '1731', 'The Years had left Scars, the Scars left Pain   (Beautiful! That\'s how Mercy saw me)', 'The years had left scars, the scars left pain,\nhow could He recognize me, I wasn\'t the same.\nI knew I should pay and I knew the price.\nFor justice and law demanded my life,\nyet his tender hart heard my desperate cry,\nand He saw my past thourgh mercifyl eyes.\r\nBeautiful! That\'s how mercy saw me,\nfor I was broken and so lost,\nmercy looked past my faults.\nJustice of God saw what I had done,\nmercy saw me thourhg the Son.\nNot what I was but what I could be,\nthat\'s how mercy saw me.\r\nWhatever you\'ve done you can\'t go too far,\nthat His eys of mercy can\'t see where you are.\nHe loves you too much to leave you alone,\nyou\'re flesh of His flesh and bone of His bone.\nYet His heart crys out for your heart today.\nSee yourself through His eys and you will say...', NULL),
(9, '1732', 'Then He\'ll say "Peace, Peace"', 'Then He\'ll say "Peace, peace,\nPeace unto my lovely Bride.\nShalom, Shalom,\nfor a new day has been broken.\nFrom this sick and dying world\nto God\'s life and immortality."\nAll we can hear from His Throne\nis "Good morning, good morning\nto my Bride."', NULL),
(9, '1733', 'There are no words to tell you how I love You', 'There are no words to tell you how I love You.\nThere are no words to even make a start.\nThere are no words worthy of Your Sacrifice.\nThere are no words, so Lord, I give my heart.\r\nThere are no words to tell you how I love You.\nThere are no words to even make a start.\nThere are no words worthy of Your Love to me.\nThere are no words, so  Lord, I give my heart.', NULL),
(9, '1734', 'There are so many People in the World today', 'There are so many people in the world today\nwho don\'t really know what true love is.\nMany have searched the whole wide world\nand still can\'t seem to find it. Love is patient, love is kind.\r\nTrue love can never be broken.\nLove endureth all things and love suffers long.\nLove is God and God is love, who is our King.\nSo how can we know true love without knowing Him.\r\nMany waters cannot quench love,\nneither can the floods drown it (4x)\nSo whoever God joins together,\nlet no man put asunder.\r\nTherefore shall a man leave mother and father\nand cleave unto his wife.\nThen they shall be no more twain but they shall be one.\nThen he\'ll love his bride as Christ the church Giving himself for it.\r\nFor no man yet hateth his flesh but loveth and cherished it.\nLove is God and God is love who is our King.\nSo how can we know true love without knowing Him.', NULL),
(9, '1735', 'There flows from Calvary a Stream   (What! never thirst again?)', 'There flows from Calvary a stream\nfor every sinner\'s pain.\nAnd he that drinketh, Jesus said,\nshall never thirst again.\r\nWhat! never thirst again?\nNo, never thirst again.\nWhat! Never thirst again?\nNo, never thirst again.\nFor he that drinketh, Jesus said,\nshall never, never thirst again.\r\nEarth\'s fountains fair, but mock our souls,\nlike desert phantoms lure.\nAnd they that drink, the fainter grow,\nthe keener thirst endure.\r\nThis stream from Calvary still flows,\nto bless and cleanse and heal.\nAnd he that drinketh, Jesus said,\nnew life and rest shall feel.\r\nOh, blessed stream of pure delight!\nOh, balm for ev\'ry pain!\nTo thee I haste, for Jesus said,\nI\'ll never thirst again.', NULL),
(9, '1736', 'There have been Names that I have loved to hear   (Jesus is the sweetest Name I know)', 'There have been names that I have loved to hear,\nbut never has there been a name so dear.\nTo this heart of mine, as the name divine,\nthe precious, precious name of Jesus.\r\nJesus is the sweetest Name I know,\nand He\'s just the same as His lovely name.\nThat\'s the reason why I love Him so,\nfor Jesus is the sweetest name I know.\r\nThere is no name in earth or Heav’n above,\nthat we should give such honor and such love.\nAs the blessed name, let us all acclaim,\nthat wondrous, glorious name of Jesus.\r\nAnd someday I shall see Him face to face.\nto thank and praise Him for His wondrous grace,\nwhich He gave to me, when He made me free,\nthe blessed Son of God called Jesus.', NULL),
(9, '1737', 'There is a Land of Milk and Honey   (And that\'s the reason we shout Hallelujah)', 'There is a land of milk and honey,\nthere is a land where we won\'t need money.\nThere is a land shining with jasper,\nThere we shall see our blessed Saviour.\r\nAnd that\'s the reason we shout Hallelujah.\nPraising our King across the river.\nThat shining river where the saints will gather.\nThere we shall see our blessed Messiah.\r\nElijah has come, he has done his work already,\nas John has said, the Bride has made ready.\nAnd now we are waiting for the coming of Jesus,\nfor that blessed day when the Lamb shall take us.\r\nOur hopes are bright, our lamps are burning,\nand day by day our hearts are yearning.\nThis is the evening He will come in the morning,\nthen we shall wait until the morning.', NULL),
(9, '1738', 'There is a Song in my Heart today, something I never had   (Oh say, but I\'m glad, I\'m glad)', 'There is a song in my heart today,\nsomething I never had.\nJesus has taken my sins away.\nOh say, but I\'m glad.\r\nOh say, but I\'m glad, I\'m glad,\noh say, but I\'m glad.\nJesus has come and my cup\'s overrun.\nOh say but I\'m glad.\r\nWonderful, marvelous love He brings,\nInto a heart that\'s sad.\nThrough darkest tunnels the soul just sings.\nOh say, but I\'m glad.\r\nWe have a fellowship rich and sweet.\nTongues can never relate.\nAbiding in Him is a real treat.\nOh say, but I\'m glad.\r\nWon\'t you come to Him with all your care,\nweary and worn and sad?\nYou too, will sing as His love you share.\nOh say, but I\'m glad.', NULL),
(9, '1739', 'There is no Satisfaction outside Salvation   (2 Chorusse)', 'There is no satisfaction outside\nsalvation, S-A-L-V-A-T-I-O-N;\nThere is no satisfaction outside\nsalvation, S-A-L-V-A-T-I-O-N.\r\nShout it out, loud and clear,\nS-A-L-V-A-T-I-O-N.\nShout it out, loud and clear,\nS-A-L-V-A-T-I-O-N.', NULL),
(9, '1740', 'There is none like You, oh Lord', 'There is none like You, oh Lord.\nYour glory fills the Heavens.\nThere is none like You, oh Lord.\nYour love endures, Your mercys flow,\nall that I need is in Your hands.\nThere is none like You.\nThere is none like You.', NULL),
(9, '1741', 'There is not one Whole in my Armour   (Chorus)', 'There is not one whole in my armour,\nJesus covered me well.\nI\'ll never fall, if I wear it all,\nsatans darts cannot prevail.', NULL),
(9, '1742', 'There is only one, Jesus Christ the Son   (He set me free on Calv\'rys Tree)', 'There is only one,\nJesus Christ the Son.\nOh, what have I done\nto deserve God\'s only Son.\r\nHe set me free on Calv\'rys Tree.\nAll would be lost if He had not\npaid the cost on the cross.\r\nThey pierced His side,\nthe truth they did deny.\n\'T was grace that set me free,\noh what He\'s done for me', NULL),
(9, '1743', 'There is Power in the Name of Jesus  -  Es ist Macht im Namen Jesu   (To break every Chain / Um jede Kette zu brechen)', 'There is power in the name of Jesus,\nthere is power in the name of Jesus,\nthere is power in the name of Jesus.\r\nTo break every chain, break every chain,\nbreak every chain, to break every chain,\nbreak every chain, break every chain.\r\nThere\'s an army rising up,\nthere\'s an army rising up,\nthere\'s an army rising up.\r\nAll sufficient sacrifice so freely given,\nsuch a price bought our redemtion.\nHeaven\'s gates swing wide.', '(Es ist Macht im Namen Jesu,\nes ist Macht im Namen Jesu,\nes ist Macht im Namen Jesu.)\r\n(Um jede Kette zu brechen, jede Kette zu brechen,\njede Kette zu brechen, um jede Kette zu brechen,\njede Kette zu brechen, jede Kette zu brechen.)\r\n(Es erhebt sich eine Armee,\nes erhebt sich eine Armee,\nes erhebt sich eine Armee.)\r\nAlle ausreichenden Opfer so frei gegeben,\nsolch ein Preis erkaufte unsere Erlösung.\nDie Tore des Himmels tun sich weit auf.'),
(9, '1744', 'There is something in my Soul which keeps the Shadows all away   (O the precious love of Jesus)', 'There is something in my Soul\nwhich keeps the shadows all away.\nIt is love, my Saviour\'s love!\nSomething lightens ev\'ry burden\ngive me gladness day by day,\nIt is love, my Saviour\'s love!\r\nO the precious love of Jesus,\nhow it thrills my ransomed soul!\nMore and more I\'ll sing its praises\nwhile the happy ages roll.\r\nWhen the tempter tries to win me\nsomething keeps me true and strong.\nIt is love, my Saviour\'s love!\nSomethings makes me life a blessing\nto the needy in the throung.\nIt is love, my Saviour\'s love!\r\nWhen misfortune overtaken me\nsomething calms my troubled breast.\nIt is love, my Saviour\'s love!\nSomething draws my soul to heaven,\nthat sweet land of peace and rest.\r\nSoul astray and bowed in sorrow,\nsomething waits for you today.\nIt is love, my Saviour\'s love!\nIt would give you peace and comfort,\nmake your burdens roll away.\nIt is love, my Saviour\'s love!', NULL),
(9, '1745', 'There stands a Rock on Shores of Time that rears to Heav\'n its Head sublime   (Some build their Hopes on the ever drifting Sand)', 'There stands a Rock on shores of time\nThat rears to heav\'n its head sublime;\nThat Rock is cleft, and they are blest\nWho find within this cleft a rest.\r\nSome build their hopes on the ever drifting sand.\nSome on their fame, or their treasure, or their land.\nMine\'s on a Rock that forever will stand,\nJesus, the "Rock of Ages."\r\nThat Rock\'s a cross, its arms outspread,\nCelestial glory bathes its head;\nTo its firm base my all I bring,\nAnd to the Rock of Ages cling.\r\nThat Rock\'s a tow\'r, whose lofty height,\nIllum\'d with heav\'n\'s unclouded light,\nOpes wide its gate beneath the dome\nWhere saints find rest with Christ at home.', NULL),
(9, '1746', 'There was a time of tenderness in me   (Move me with Your Message)', 'There was a time of tenderness in me,\nand with that tenderness came liberty.\nBut through the cares of life I built a shell\nthat harbored me from hurt but God as well.\r\nMove me with your message once again.\nIt\'s been so long since I have broke within.\nTake me back once more to Calvary,\nwhere one more time your message moves me.\r\nOur lives, they get so stale, they get so cold.\nHow often we are found in hardened molds.\nBut Lord, I recognize my need again.\nCome by Your Spirit, revive my soul again.', 'Da war eine Zeit der Sanftheit in mir,\nund durch die Sanftheit kam Freiheit.\nDoch durch die Sorgen des Lebens baute ich eine Hülle,\nwelche mich vor Verletzung verbarg, jedoch auch vor Gott\r\nBewege mich noch einmal mit deiner Botschaft,\nEs ist so lange her, dass ich innerlich zerbrach.\nBring mich noch einmal zurück zu Golgatha,\nwo mich deine Botschaft noch einmal bewegt.\r\nUnsere Leben werden so schal, sie werden so kalt,\nWie oft werden wir in verhärteten Formen gefunden.\nDoch Lord, wiederum erkenne ich meine Not,\nKomm‘ mit deinem Geist und belebe meine Seele erneut.'),
(9, '1747', 'There was a Time on Earth, when in the Book of Heaven   (Long ago, long ago, yes the old Account was settled long ago)', 'There was a time on earth, when in the book of heaven\nan old account was standing for sins yet unforgiven.\nMy name was at the top and many things below.\nI went unto the keeper and settled long ago.\r\nLong ago, long ago, yes the old account was settled long ago.\nAnd the record\'s clear today, for He washed my sins away,\nwhen the old account was settled long ago.\r\nThe old account was large and growing every day,\nfor I was always sinning, and never tried to pay.\nBut when I looked ahead and saw such pain and woe,\nI said that I would settle, I settled long ago.\r\nWhen at the judgment bar, I stand before my King,\nand He the book will open, He cannot find a thing.\nThen will my heart be glad, while tears of joy will flow.\nBecause I had it settled, and settled long ago.\r\nWhen in that happy home my Saviour\'s home above,\nI\'ll sing redemption\'s story, and praise Him for His love.\nI\'ll not forget that book, with pages white as snow.\nBecause I came and settled, and settled long ago.\r\nO sinner, seek the Lord, repent of all your sin.\nFor thus He hath commanded, if you would enter in.\nAnd then if you should live a hundred years below,\nup there you\'ll not regret it, you settled long ago.', NULL),
(9, '1748', 'There was Jesus', 'Every time I tried to make it on my own\nEvery time I tried to stand and start to fall\nAnd all those lonely roads that I have travelled on\nThere was Jesus\r\nWhen the life I built came crashing to the ground.\nWhen the friends I had were nowhere to be found.\nI couldn\'t see it then but I can see it now\nThere was Jesus\r\nIn the waiting, in the searching\nIn the healing and the hurting\nLike a blessing buried in the broken pieces.\nEvery minute, every moment\nWhere I\'ve been and where I\'m going\nEven when I didn\'t know it or couldn\'t see it\nThere was Jesus\r\nFor this man who needs amazing kind of grace\nFor forgiveness at a price I couldn\'t pay\nI\'m not perfect so I thank God every day\nThere was Jesus (There was Jesus)\r\nOn the mountain, in the valleys (There was Jesus)\nIn the shadows of the alleys (There was Jesus)\nIn the fire, in the flood (There was Jesus)\nAlways is and always was\nNo I never walk alone (Never walk alone)\nYou are always there\r\nIn the waiting, in the searching\nIn the healing and the hurting\nLike a blessing buried in the broken pieces\nEvery minute (Every minute), every moment (Every moment)\nWhere I\'ve been and where I\'m going\nEven when I didn\'t know it or couldn\'t see it', '(Jedes Mal habe ich versucht,  es selbst zu schaffen\nJedes Mal, wenn ich versuchte aufzustehen,  fing ich an zu fallen\nUnd all diese einsamen Wege,  auf denen ich gegangen bin\nDa war Jesus)\r\n(Als das Leben,  das ich aufgebaut hatte,  zusammenbrach.\nAls die Freunde,  die ich hatte,  nirgends zu finden waren.\nIch konnte es damals nicht sehen,  aber ich kann es jetzt sehen\nDa war Jesus)\r\n(Im Warten,  im Suchen\nIn der Heilung und im Schmerz\nWie ein Segen,  der in den Scherben vergraben ist.\nJede Minute,  jeden Augenblick\nWo ich war und wohin ich gehe\nAuch wenn ich es nicht wusste oder nicht sehen konnte\nDa war Jesus)\r\nFür diesen Mann, der erstaunliche Gnade braucht\nFür Vergebung zu einem Preis, den ich nicht bezahlen konnte\nIch bin nicht perfekt,  also danke ich Gott jeden Tag\nDa war Jesus (Da war Jesus)\r\nAuf dem Berg, in den Tälern (Da war Jesus)\nIn den Schatten der Gassen (Da war Jesus)\nIm Feuer,  in der Flut (Da war Jesus)\nImmer ist und immer war\nNein,  ich gehe nie alleine (gehe nie alleine)\nDu bist immer da\r\n(Im Warten,  im Suchen In der Heilung und im Schmerz\nWie ein Segen,  der in den Scherben vergraben ist.\nJede Minute,  jeden Augenblick\nWo ich war und wohin ich gehe\nAuch wenn ich es nicht wusste oder nicht sehen konnte\nDa war Jesus)'),
(9, '1749', 'There\'s a blessed Time that\'s coming, coming soon   (We shall see the King)', 'There\'s a blessed time that\'s coming, coming soon,\nit may be evening, morning or at noon,\nThe wedding of the bride, uited with the groom,\nwe shall see the King when he comes.\r\nWe shall see the King,\nwe shall see the King,\nwe shall see the King when He comes.\nHe is coming in pow\'r,\nwe\'ll hail the blessed hour,\nwe shall see the King when He comes.\r\nAre you ready should the Saviour call today?\nWould Jesus say, "Well done," or "Go away"?\nMy home is for the pure, the vile can never stay,\nwe shall see the King when comes.\r\nOh, my brother, are you ready for the call?\nTo crown your Saviour King and Lord of all?\nThe Kingdoms of this world shall soon before Him fall,\nwe shall see the King when He comes.', NULL),
(9, '1750', 'There\'s a Curtain that\'s drawn between Earth and Heaven   (Lord, let me look past the Curtain of Sorrows and Fear)', 'There\'s a curtain that\'s drawn between earth and heaven,\nand just beyond lies a beautiful clime.\nWhere the evils of this life no longer can touch me,\nLord, let me look past the curtain of time.\r\nLord, let me look past the curtain of sorrows and fear,\nlet me view that sunny bright clime.\nIt would strengthen my faith and would banish all fear,\nLord, let me look past the curtain of time.\r\nI\'m helpless, alone, and I want to see Jesus,\nand hear the sweet harbor bells chime.\nWhere my friends and dear loved ones are waiting for me,\nLord, let me look past the curtain of time.\r\nI\'m so homesick and blue, and I want to see Jesus,\nI would like to hear those sweet harbor bells chime.\nIt would brighten my path and would vanish all fear,\nLord, let me look past the curtain of time.', NULL),
(9, '1751', 'There\'s a Feeling in the Air that God is everywhere', 'There\'s a feeling in the air\nthat God is everywhere,\nand His resurrection power\nis moving in this hour,\nthat Jesus may be glorified.\r\nI will glorify the Name of the Lord,\nI will glorify His Name,\nand His resurrection power\nis moving in this hour,\nthat Jesus may be glorified.', NULL),
(9, '1752', 'There\'s a Fountain opened', 'There\'s a fountain opened\nin the house of David\nto you who would believe\nand there are streams of grace\nthat\'s flowing down from Calvary,\nCome now and receive.', NULL),
(9, '1753', 'There\'s a Fountain that is flowing from a Place called Calvary   (Have you been beneath the Fountain)', 'There\'s a fountain that is flowing\nFrom a place called Calvary\nThere is healing in it\'s waters\nThere is joy and victory\r\nHave you been beneath the fountain\nThere\'s no other place to go\nFlowing down from Calvary\'s mountain\nIt will wash you white as snow\r\nOther waters will be bitter\nThey just cannot satisfy\nBut this fountain flows forever\nAnd it never shall run dry', NULL),
(9, '1754', 'There\'s a holy and beautiful City, whose Builder and Ruler is God   (In that bright City, pearly white City)', 'There\'s a holy and beautiful city,\nwhose builder and ruler is God.\nJohn saw it descending from heaven\nwhen Patmos, in exile, he trod.\nIts high, massive wall is of jasper,\nthe city itself is pure gold.\nAnd when my frail tent here is folded,\nmine eyes shall its glory behold.\r\nIn that bright city, pearly white city,\nI have a mansion, a harp, and a crown.\nNow I am watching, waiting and longing,\nfor the white city John saw coming down.\r\nNo sin is allowed in that city,\nand nothing defiling nor mean.\nNo pain and no sickness can enter,\nno crape on the doorknob is seen.\nEarth\'s sorrows and cares are forgotten,\nno tempter is there to annoy.\nNo parting words ever are spoken,\nthere\'s nothing to hurt and destroy.\r\nNo heartaches are known in that city,\nno tears ever moisten the eye,\nthere\'s no disappointment in heaven,\nno envy and strife in the sky.\nThe saints are all sanctified wholly,\nthey live in sweet harmony there.\nMy heart is now set on that city,\nand some day its blessings I\'ll share.\r\nMy loved ones are gathering yonder,\nmy friends, too, are passing away.\nAnd soon I shall join their bright number,\nand dwell in eternity\'s day.\nThey\'re safe now in glory with Jesus,\ntheir trials and battles are pas.;\nThey overcome sin and the tempter,\nthey\'ve reached that fair city at last.', NULL),
(9, '1755', 'There\'s a River of Life flowing out from Me', 'There\'s a river of life flowing out from me,\nmakes the lame to walk, and the blind to see,\nopens prison doors, sets the captives free,\nthere\'s a river of life flowing out from me.\r\nSpring up oh well within my soul.\nSpring up oh well and make me whole,\nspring up oh well and\ngive to me that life - abundantly.', NULL),
(9, '1756', 'There\'s a Story in the Bibel of Elisha   (All is well, all is well. I have heard the message "Shalom" and all is well)', 'There\'s a story in the Bible of Elisha,\na Shunammite woman and her son.\nThe woman found favour with God\nand He gave her a son.\nWhile working in the field the little boy died.\nBut the woman\'s faith never failed,\neven in death she testified\nthat  - All is well! -\r\nAll is well, all is well.\nI have heard the message "Shalom" and all is well.\nThere is a place of perfect rest inside the inner veil.\nSo rest, little Bride, rest, for all is well.\r\nNow things have not worked out\nlike God\'s people thought.\nFor we\'re still here, to fight the\ngreatest battle ever fought.\nWe must have the faith of Abraham,\nknowing God\'s Word never fails.\nIf you trust in Him you will find\nthat  - All is well! -', NULL),
(9, '1757', 'There\'s been a Change in me since Jesus set me free.', 'There\'s been a change in me\nsince Jesus set me free.\nI\'ve been to Calvary I\'m born again.\nI cannot turn around\nmy feet are on solid ground.\nSomeday I\'ll wear a crown\noh what a change!', 'Da war eine Veränderung seit Jesus mich freigemacht hat\nIch war auf Golgatha,  bin von Neuem geboren\nIch kann nicht mehr zurück,  meine Füße stehen auf festem Grund\nEines Tages werde ich eine Krone tragen\nOh welche Veränderung'),
(9, '1758', 'There\'s no Disappointment in Heaven   (I\'m bound for that beautiful City)', 'There\'s no disappointment in heaven,\nno weariness, sorrow or pain.\nNo hearts that are bleeding and broken,\nno song with a minor refrain.\nThe clouds of our earthly horizon\nwill never appear in the sky,\nFor all will be sunshine and gladness,\nwith never a sob nor a sigh.\r\nI\'m bound for that beautiful city\nmyLord has prepared for His own.\nWhere all the redeemed of all ages\nsing "Glory!" around the white throne.\nSometimes I grow homesick for heaven,\nand the glories I there shall behold.\nWhat a joy that will be when my Saviour I see,\nin that beautiful city of gold!\r\nWe\'ll never pay rent for our mansion,\nthe taxes will never come due.\nOur garments will never grow threadbare,\nbut always be fadeless and new.\nWe\'ll never be hungry nor thirsty,\nnor languish in poverty there.\nFor all the rich bounties of heaven\nHis sanctified children will share.\r\nThere\'ll never be crape on the doorknob,\nno funeral train in the sky.\nNo graves on the hillsides of glory,\nfor there we shall nevermore die.\nThe old will be young there forever,\ntransformed in a moment of time.\nImmortal we\'ll stand in His likeness,\nthe stars and the sun to outshine.', NULL),
(9, '1759', 'There\'s no Rock like our God', 'There\'s no Rock like our God,\nThere\'s no Rock like our God,\nI can stand on Him,\nwhen my world falls apart,\nThere\'s no Rock like our God!\r\nJesus is the only Rock,\nJesus is the only Rock,\nHe\'s the Rock of time\nand eternity,\nJesus is the only Rock!\r\nI will place my feet on Him,\nI will place my feet on Him,\nHE\'s the All-in-all,\nHe will never fall,\nI will place my feet on Him!', NULL),
(9, '1760', 'There\'s nothing as precious as You Lord   (Chorus)', 'There\'s nothing as precious as You Lord,\nnothing as precious as You.\nNo one else is so dear to my heart,\nnothing as precious as You.', NULL),
(9, '1761', 'Therefore the Redeemed of the Lord shall return   (nach Jesaja 51,11)', 'Therefore the redeemed of the Lord shall return,\nand come with singing unto Zion.\nAnd everlasting joy shall be upon their head.\nTherefore the redeemed of the Lord shall return,\nand come with singing unto Zion.\nAnd everlasting joy shall be upon their head.\nThey shall obtain gladness and joy,\nand sorrow and mourning shall flee away.\nTherefore the redeemed of the Lord shall return,\nand come with singing unto Zion.\nAnd everlasting joy shall be upon their head.', NULL),
(9, '1762', 'They who know the Saviour shall in Him be strong    (Victory, Victory blessed Blood bought Victory)', 'They who know the Saviour shall in Him be strong,\nmighty in the conflict of the right ’gainst wrong.\nThis the blessed promise given in God’s Word,\ndoing wondrous exploits, they who know the Lord.\r\nVictory, victory blessed blood bought victory,\nvictory, victory, victory all the time.\nAs Jehovah liveth, strength divine He giveth,\nunto those who know Him victory all the time.\r\nIn the midst of battle be thou not dismayed,\nthough the pow’rs of darkness ’gainst thee are arrayed.\nGod, thy strength, is with thee, causing thee to stand,\nheaven’s allied armies wait at thy command.\r\nBrave to bear life’s testing, strong the foe to meet,\nwalking like a hero midst the furnace heat,\ndoing wondrous exploits with the Spirit’s sword,\nwinning souls for Jesus, praise, oh, praise the Lord!', NULL),
(9, '1763', 'Things are different now  -  Die Dinge sind jetzt anders', 'Things are different now,\nsomething happened to me,\nwhen I gave my heart to Jesus.\nThings are different now,\nI was changed, it must be,\nwhen I gave my heart to Him.\r\nThings I loved before have passed away.\nThings I love far more,\nhave come to stay.\nThings are different now,\nsomething happened that day,\nwhen I gave my heart to Him.', 'Die Dinge sind jetzt anders,\netwas ist mit mir passiert,\nals ich mein Herz an Jesus übergab.\nDie Dinge sind jetzt anders,\nich wurde verändert, das muss so sein,\nals ich Ihm mein Herz schenkte.\r\nDinge die ich früher geliebt habe, sind vergangen.\nDinge, die ich viel mehr liebe\nsind gekommen, um zu bleiben.\nDie Dinge sind jetzt anders,\nweil an jenem Tag etwas geschah,\nals ich Ihm mein Herz schenkte.'),
(9, '1764', 'Things change, Plans fail  -  Dinge ändern sich, Pläne scheitern   (Jesus will still be there / Jesus wird immer noch da sein)', 'Things change, plans fail\nyou look for love, on a grander scale.\nStorms rise, hopes fade\nand you place your bets, on another day.\nWhen the going gets tough,\nwhen the ride\'s too rough,\nwhen you\'re just not sure enough:\r\nJesus will still be there,\nHis love will never change.\nSure as a steady rain,\nJesus will still be there.\nWhen no one else is true,\nHe\'ll still be loving you.\nWhen it looks like you\'ve lost it all,\nand you haven\'t got a prayer.\nJesus will still be there.\r\nTime flies, hearts turn,\na little bit wiser from lessons learned.\nBut sometimes, weakness wins\nand you lose your foothold, once again.\nWhen the going gets tough,\nwhen the ride\'s too rough,\nwhen you\'re just not sure enough:', 'Dinge ändern sich, Pläne scheitern,\nman sucht die Liebe in größerem Maße.\nStürme ziehen auf, Hoffnungen verblassen\nund man setzt auf einen anderen Tag.\nWenn die Dinge hart werden,\nwenn die Fahrt zu rau ist,\nwenn man sich einfach nicht sicher genug ist:\r\nJesus wird immer noch da sein,\nSeine Liebe wird sich nie ändern.\nSicher wie ein stetiger Regen,\nwird Jesus immer noch da sein.\nWenn niemand sonst wahr ist,\nwird er dich immer noch lieben.\nWenn es so aussieht, als hättest du alles verloren,\nund du kein einziges Gebet mehr hast.\nJesus wird immer noch da sein.\r\nDie Zeit vergeht, die Herzen ändern sich,\nein bisschen weiser durch die gelernten Lektionen.\nAber manchmal siegt die Schwäche\nund man verliert den Halt, wieder einmal.\nWenn es schwierig wird,\nwenn die Fahrt zu rau ist,\nwenn man einfach nicht sicher genug ist:'),
(9, '1765', 'Think about His Love, think about His Goodness', 'Think about His Love,\nthink about His Goodness,\nthink about His Grace,\nthat brought us through.\r\nFor as high as the heavens above\nso great is the measure of our Fathers Love,\ngreat is the measure of our Fathers Love.', NULL),
(9, '1766', 'This is the Time, when true Worshipers will worship Him.', 'This is the time,\nwhen true worshipers will worship Him.\nThese are the days,\nwhen my fathers ways will belong to me.\nThis is the hour,\nwhen the Spirit comes to move again.\nAs we worship You  in spirit and in true.\r\nHoly, Holy, Holy is Your Name\nWorthy worthy, let all the earth proclaim.\nMighty, mighty, there is no one like You,\nand we worship You, in spirit and in true.', NULL),
(9, '1767', 'Thou Christ of burning, cleansing Flame', 'Thou Christ of burning, cleansing flame,\nsend the fire, send the fire, send the fire!\nThy blood bought gift today we claim,\nsend the fire, send the fire, send the fire!\nLook down and see this waiting host,\ngive us the promised Holy Ghost,\nwe want another Pentecost,\nsend the fire, send the fire, send the fire!\r\nGod of Elijah, hear our cry,\nsend the fire, send the fire, send the fire!\nHe\'ll make us fit to live or die,\nsend the fire, send the fire, send the fire!\nTo burn up every trace of sin,\nto bring the light and glory in,\nthe revolution now begin,\nsend the fire, send the fire, send the fire!\r\n\'Tis fire we want, for fire we plead,\nsend the fire, send the fire, send the fire!\nThe fire will meet our every need,\nsend the fire, send the fire, send the fire!\nFor strength to ever do the right,\nfor grace to conquer in the fight,\nfor power to walk in the world in white,\nsend the fire, send the fire, send the fire!', NULL),
(9, '1768', 'Through the Blood, we can come into His Presence   (Chorus)', 'Through the Blood, through the Blood,\nwe can come into His Presence\nthrough the Blood.\nJesus Christ has made a way,\nso we can come into His Presence,\nthrough the Blood.', NULL),
(9, '1769', 'Thy Name oh Lord, is pure and holy   (2 Chorusse)', 'Thy Name oh Lord,\nis pure and holy.\nThy Name oh Lord,\nis more precious then gold.\r\nBlessed be Thy Name,\nblessed be Thy Name,\nblessed be Thy Name oh Lord, my God.', NULL),
(9, '1770', 'Tief in meinem Herzen schreibe Herr Dein Wort   (Lass auf jedem Wege, Licht Dein Wort mir sein)', NULL, 'Tief in meinem Herzen\nschreibe, Herr, Dein Wort.\nTief in meinem Herzen\nsei es immerfort.\r\nLass auf jedem Wege,\nLicht Dein Wort mir sein.\nTief ins Herz mir lege,\nHerr, Dein Wort hinein.\r\nTief in meinem Herzen\nDein Wort Wunder schafft.\nTief in meinem Herzen\ngibt es neue Kraft.\r\nTief in meinem Herzen\njetzt und allezeit,\nsei Dein Wort geschrieben\nbis in Ewigkeit.'),
(9, '1771', 'Tief verborgen im Herzen erfahre ich heut einen Frieden  -  Far away in the Depths of my Spirit tonight   (Frieden wunderbar klar, den der Vater vom Himmel gesandt)', 'Far away in the depths of my spirit tonight\nrolls a melody sweeter than psalm.\nIn celestial-like strains it unceasingly falls\no’er my soul like an infinite calm.\r\nPeace, peace! wonderful peace,\ncoming down from the Father above.\nSweep over my spirit forever, I pray,\nin fathomless billows of love.\r\nWhat a treasure I have in this wonderful peace\nburied deep in the heart of my soul.\nSo secure that no power can mine it away\nwhile the years of eternity roll.\r\nI am resting tonight in this wonderful peace,\nresting sweetly in Jesus’ control.\nFor I’m kept from all danger by night and by day,\nand His glory is flooding my soul.\r\nAnd me thinks when I rise to that city of peace\nwhere the Author of peace I shall see.\nThat one strain of the song which the ransomed will sing\nin that heavenly kingdom shall be.\r\nAh! soul, are you here without comfort and rest,\nmarching down the rough pathway of time?\nMake Jesus your friend ere the shadows grow dark,\no accept this sweet peace so sublime!', 'Tief verborgen im Herzen erfahre ich heut\'\neinen Frieden so still wie der See.\nUnaufhörlich strömt diese Erquickung mir zu,\nweil den Weg des Gehorsams ich geh\'.\r\nFrieden wunderbar klar,\nden der Vater vom Himmel gesandt.\nDu umgibst meinen Geist und bleibst immer bei mir,\nweil den Friedefürst Jesus ich fand.\r\nDieser Friede erfüllt nun mein Denken und Tun.\nGottes Wort stets regier\' meinen Geist.\nDarum flieht alle Angst, weil in jeder Gefahr\nsich die Gegenwart Jesu erweist.\r\nWenn ich bald in die Stadt voller Frieden eingeh\',\nwo den Schöpfer des Friedens ich seh\',\njedes Leid und die Sorgen vergessen dann sind,\nwenn vor Jesus anbetend ich steh\'.\r\nUnd ich denke, wenn ich zu der Stadt des Friedens aufsteige\nwo ich den Urheber des Friedens sehen werde.\nDass eine Strophe des Liedes, das die Erlösten singen werden\nin jenem himmlischen Reich sein wird.\r\nAch, Seele, bist du hier ohne Trost und Rast,\nmarschierst du den rauen Pfad der Zeit entlang?\nMach Jesus zu deinem Freund, bevor die Schatten dunkel werden,\no nimm diesen süßen Frieden an, der so erhaben ist!'),
(9, '1772', 'Tiefe Freude, immerwährend, hat der Tröster uns gebracht  -  Joys are flowing like a River, since the Comforter has come   (Selge Glaubensruh! Heige Glaubensruh)', 'Joys are flowing like a river,\nsince the Comforter has come.\nHe abides with us forever,\nmakes the trusting heart His home.\r\nBlessed quietness, holy quietness,\nblest assurance in my soul!\nOn the stormy sea, Jesus speaks to me,\nand the billows cease to roll.\r\nEverything is turned to gladness,\nall around this glorious Guest.\nBanished unbelief and sadness,\nall is perfect peace and rest.\r\nLike the rain that falls from heaven,\nlike the sunlight from the sky.\nSo the Holy Spirit given,\nfalls upon us from on high.\r\nSee, a fruitful field is growing,\nblessed fruit of righteousness,\nand the streams of life are flowing\nin the lonely wilderness.\r\nWhat a wonderful salvation,\nwhere we always see His face!\nWhat a peaceful habitation!\nWhat a quiet resting place!', 'Tiefe Freude, immerwährend,\nhat der Tröster uns gebracht,\nder, den teuren Herrn verklärend\nin uns Wohnung hat gemacht.\r\nSel\'ge Glaubensruh\'! Hei\'ge Glaubensruh\'!\nja, in Ihm ist Sicherheit.\nSelbst auf stürm\'schen Meer ist mein Friede Er,\nmacht mich still in Sturm und Streit.\r\nKraft, Gesundheit, neues Leben\ndieser teure Geist verleiht,\nwill aus Traurigkeit uns heben\nund aus Ruhelosigkeit.\r\nWie der Regen aus der Wolke,\nwie der lichte Sonnenstrahl,\nalso kam zu Seinem Volke\nGottes Geist ins Erdental.\r\nUnd das Feld trägt, herrlich spießend,\nFrüchte der Gerechtigkeit;\nLebensströme, mächtig fließend,\ntränken Wüsten weit und breit.\r\nDer Erlösung reiche Fülle,\nist in Dir lebend\'ger Hort;\nja in Dir ist Sabbatstille,\nist ein ew\'ger Ruheort.'),
(9, '1773', 'Tiefer Friede ist gekommen seit ich wurde frei', NULL, 'Tiefer Friede ist gekommen, seit ich wurde frei!\nJesus hat mich hingenommen, steht mir ewig bei.\nEinst ein Unterliegen, jetzt ein sel\'ges Siegen!\nTiefer Friede ist gekommen, seit ich wurde frei!\r\nAuch der schnöden Lust zur Sünde ist der Tod gebracht,\nweil ich sie gekreuzigt finde durch des Heilands Macht.\nEinst so hart gekettet, jetzt so ganz gerettet!\nAuch der schnöden Lust zur Sünde ist der Tod gebracht.\r\nMich beglückt die süße Stille, die Er mir geschenkt.\nEinverstanden ist mein Wille, wie Er\'s immer lenkt.\nAlle meine Sachen wird Er selber machen.\nMich beglückt die süße Stille, die Er mir geschenkt.\r\nNicht mehr ich! Der Herr wird leben in mir Tag und Nacht.\nIch bin in den Tod gegeben, den Er mir gebracht;\nund Sein Auferstehen ist für mich geschehen.\nNicht mehr ich! Der Herr wird kleben in mir Tag und Nacht.'),
(9, '1774', 'Tiefer und tiefer, Herr, beug ich mich Dir  -  Lower and lower, dear Lord, at thy Feet   (Tiefer und tiefer, tiefer in Dich)', 'Lower and lower, dear Lord, at Thy feet,\nseeking Thy Spirit, Thy mercy so sweet.\nDown in our need, blessed Master, we fall,\nlower and lower be Thou all in all.\r\nLower and lower, down at Thy cross,\nall the world’s treasure counting but dross.\nDown at Thy feet, blessed Saviour, we fall,\nlower, still lower, Christ all in all!\r\nLower and lower, dear Saviour, we pray,\nlosing the self-life still more every day.\nWeak and unworthy, we’re looking above,\nempty us wholly; then fill us with love.\r\nLower and lower, yet higher we rise\nlifted in Jesus, led on to the skies.\nHumbly we follow the way of the cross,\nthen, crowns of glory, and gain for all loss.', 'Tiefer und tiefer, Herr, beug\' ich mich Dir,\ngib doch die Fülle der Gnadenkraft mir.\nMeister, im Staube vor Dir liege ich,\nwerde doch alles in allem für mich.\r\nTiefer und tiefer, tiefer in Dich,\nnichts von der Welt mehr begehre ich.\nDir, Herr, zu Füßen, da leg ich mich hin,\nChristus, mein Leben und mein Gewinn!\r\nTiefer und tiefer, so flehe ich, Herr,\ntöte das eigne Leben noch mehr,\nich bin nicht wert, dass Du meiner gedenkst,\naber ich weiß, dass Erhörung Du schenkst.\r\nTiefer und tiefer, denn höher hinan\nzu Dir, Herr Jesus, gelange ich dann;\ndemütig geh ich den Kreuzweg Dir nach,\nKrone und Herrlichkeit folget der Schmach.'),
(9, '1775', 'Tiefer, tiefer in die Liebe Jesu lass mich dringen ein  -  Deeper, deeper in the Love of Jesus, daily let me go   (Drum tiefer, Herr, ich fleh)', 'Deeper, deeper in the love of Jesus\ndaily let me go.\nHigher, higher in the school of wisdom,\nmore of grace to know.\r\nOh, deeper yet, I pray,\nand higher ev\'ry day.\nAnd wiser, blessed Lord,\nin Thy precious, holy word.\r\nDeeper, deeper! blessed Holy Spirit,\ntake me deeper still.\nTill my life is wholly lost in Jesus,\nand His perfect will.\r\nDeeper, deeper! tho\' it cost hard trials,\ndeeper let me go!\nRooted in the holy love of Jesus,\nlet me fruitful grow.\r\nDeeper, higher, ev\'ry day in Jesus,\ntill all conflict past.\nFinds me conqu’ror, and in His own image\nperfected at last.', 'Tiefer, tiefer in die Liebe Jesu\nlass mich dringen ein;\nhöher, höher vor des Heilands Throne\nmöcht\' ich mich erfreu\'n!\r\nD\'rum tiefer, Herr, ich fleh\',\nführ\' höher mich als je!\nErleuchte treuer Hort,\nmeine Seele durch Dein Wort!\r\nTiefer, tiefer, Heil\'ger Geist,\nDu Tröster, in des Lichtes Quell,\nwo der Seele Finsternis entschwindet,\nalles klar und hell!\r\nTiefer, tiefer in das Reich der Gnade,\nist der Kampf auch schwer!\nO, versenke Du mich, Herr,\nvollkommen in der Liebe Meer.\r\nTiefer, höher lass mich täglich\ndringen m der Seelen Heil,\nbis mir Gottes heil\'ge Gnadenfülle\newig wird zuteil!'),
(9, '1776', 'Till the Storm passes by', 'Out on the water, storms raging high\nThe waters around them, were troubled that night\nFear filled their hearts\nAnd they thought they would die\nThey failed to remember that the Master was nigh\r\nSo why should I worry?\nAnd why should I fear?\nThe very same Jesus\nHe stays always near\nHe lives in my heart\nAnd He hears when I cry\nI′ll call on His name, till the storm passes by\r\nWe read in the bible, how He walked with them\nBrought light to the darkness\nWhen the way grew so dim\nHow great it would be\nTo have His steps leading mine\nAnd to walk with the Master, all of the time\r\nHe spoke the word, and the winds all stood still\nEven the waters, they obeyed his will\nAnd He calmed the storms, just like He will mine\nIf I just remember, that He lives deep inside\r\nSo when trials come, and death is so nigh\nI just searched for the Master\nSaid He\'ll be there on time\nAnd when I′m in trouble, and my body is in pain\nAll I have to do is call on His name', 'Draußen auf dem Wasser toben Stürme hoch\nDie Gewässer um sie herum waren in dieser Nacht aufgewühlt\nAngst erfüllte ihre Herzen\nUnd sie dachten, sie würden sterben\nSie erinnerten sich nicht daran, dass der Meister in der Nähe war\r\nWarum sollte ich mir also Sorgen machen?\nUnd warum sollte ich Angst haben?\nDerselbe Jesus\nEr bleibt immer in der Nähe\nEr lebt in meinem Herzen\nUnd er hört, wenn ich weine\nIch werde Seinen Namen anrufen, bis der Sturm vorüber ist\r\nWir lesen in der Bibel, wie Er mit ihnen ging\nLicht ins Dunkel gebracht\nAls der Weg so dunkel wurde\nWie toll wäre es\nDass Seine Schritte meine führen\nUnd die ganze Zeit mit dem Meister zu gehen\r\nEr sprach das Wort, und alle Winde standen still Sogar die Wasser, sie gehorchten seinem Willen\nUnd Er beruhigte die Stürme, genauso wie Er es bei meinen tun wird\nWenn ich mich nur daran erinnere, dass er tief in mir lebt\r\nAlso, wenn Prüfungen kommen und der Tod so nah ist\nIch habe gerade nach dem Meister gesucht\nSagte, er wird pünktlich da sein\nUnd wenn ich in Schwierigkeiten bin und mein Körper Schmerzen hat\nAlles, was ich tun muss, ist, seinen Namen anzurufen'),
(9, '1777', 'Time after Time I went searching for Peace in some Void   (Er war da allezeit)', 'Time after time I went searching for peace in some void.\nI was trying to blame all my ills on this world.\nI was in surface relationships used me \'til I was done.\nIn and all of the while someone was begging To free me from sin.\r\nHe was there all the time,\nHe was there all the time,\nwaiting patiently in line,\nHe was there all the time.\r\nNever again will I look for a fake rainbow\'s end.\nNow that I have the answer My life is just starting to rhyme.\nSharing each new day with Him Is a cup of fresh wine.\nAnd oh what I missed, He\'s been waiting right there all the time.', '\r\nEr war da allezeit,\nEr war da allezeit,\nwar geduldig da in Lieb\',\nEr war da allezeit.\r\n'),
(9, '1778', 'To get a Touch from the Lord is so real   (Chorus)', 'To get a touch from the Lord is so real,\nto get a touch from the Lord is so real,\nif you draw nigh to Him, He will draw nigh to you,\nto get a touch from the Lord is so real.', NULL),
(9, '1779', 'To Him who sits on the Throne   (Chorus)', 'To Him Who sits on the throne and unto the Lamb,\nto Him Who sits on the throne and unto the Lamb.\nBe blessing, and honor and power forever,\nbe blessing, and honor and power forever.', NULL),
(9, '1780', 'To Jesus ev\'ry Day I find my Heart is closer drawn   (The Half cannot be fancied)', 'To Jesus ev\'ry day I find my heart is closer drawn.\nHe\'s fairer than the glory of the gold and purple dawn.\nHe\'s all my fancy pictures in its fairest dreams, and more.\nEach day He grows still sweeter than He was the day before.\r\nThe half cannot be fancied\nthis side the golden shore.\nOh, there He\'ll be still sweeter\nthan He ever was before.\r\nHis glory broke upon me when I saw Him from afar.\nHe\'s fairer than the lily, brighter than the morning star.\nHe fills and satisfies my longing spirit o\'er and o\'er.\nEach day He grows still sweeter than He was the day before.\r\nMy heart is sometimes heavy, but He comes with sweet relief.\nHe folds me to His bosom when I droop with blighting grief.\nI love the Christ who all my burdens in His body bore.\nEach day He grows still sweeter than He was the day before.', NULL),
(9, '1781', 'To me the Holy Ghost is giv\'n   (I\'ve Pentecost in my Soul)', 'To me the Holy Ghost is giv\'n,\nAn earnest of the joys of heaven.\nSince He has taken full control,\nI\'ve Pentecost in my soul.\r\nI\'ve Pentecost in my soul,\nI\'ve Pentecost in my soul,\nThe Spirit has come, has come to abide,\nI\'ve Pentecost in my soul.\r\nThe Spirit dwells my heart within,\nAnd breaks the pow\'r of pardoned sin.\nTho\' o\'er my head dark clouds may roll,\nI\'ve Pentecost in my soul.\r\nO holy rest! O peace sublime!\nHe reigns within me all the time.\nHe purifies and makes me whole\nI\'ve Pentecost in my soul.\r\nThen seek this Gift without delay,\nReceive the Holy Ghost today.\nYield all to His benign control,\nLet Pentecost fill your soul! O yes!', NULL),
(9, '1782', 'To the Harvest Field away we will gladly go today   (Gathering Sheaves, beautiful Sheaves)', 'To the harvest field away\nwe will gladly go today,\ngathering sheaves, beautiful sheaves.\nFrom the early dawn till night we will\nlabour with our might,\ngathering sheaves, beautiful sheaves.\r\nGathering sheaves, beautiful sheaves,\ngathering sheaves, beautiful sheaves,\npraise the Lord, we\'re on our way to\nthat land of endless day,\ngathering sheaves, beautiful sheaves.\r\nOn the mountain, hill or plain\nwe will harvest in the grain,\ngathering sheaves, beautiful sheaves.\nYes, we\'ll labour far and near, never\nfalter, never fear,\ngathering sheaves, beautiful sheaves.\r\nWe will sing and we will pray,\nand our Master\'s voice obey,\ngathering sheaves, beautiful sheaves.\nAs we go in foreign lands, doing what\nour Lord commands,\ngathering sheaves, beautiful sheaves.', NULL),
(9, '1783', 'Tochter Zion freue dich', NULL, 'Tochter Zion, freue dich!\nJauchze laut, Jerusalem!\nSieh, dein König kommt zu dir;\nja, Er kommt, der Friedefürst!\nTochter Zion, freue dich!\nJauchze laut, Jerusalem!\r\nHosianna, Davids Sohn,\nsei gesegnet Deinem Volk!\nGründe nun Dein ewig Reich!\nHosianna in der Höh!\nHosianna, Davids Sohn,\nsei gesegnet Deinem Volk!\r\nHosianna, Friedefürst,\nsei gegrüßet, König mild!\nEwig steht Dein Friedensthron,\nDu, des ewgen Vaters Kind!\nHosianna, Friedefürst,\nsei gegrüßet, König mild!'),
(9, '1784', 'Touched by a fire', 'Jesus blinded all my darkness\nHe sparked my heart within\nHis grace and mercy lit a passion\nConsumed my sin\nNow like a city on a hilltop\nI\'ll shine through the night\nI am a lamp made for His glory\nI will not hide\nI\'ve been touched by a fire\nSo let the world come and watch me burn\nShout it from the rooftops\nShout it til everyone has heard\nThis love will never be extinguished\nIt\'s alive and wild and free\nI\'m overtaken by his power\nHis spirit in me\nHis spirit in me\nHis spirit in me\nJesus has changed my life\nHis name be lifted high\nThis holy fire\'s burning inside of me\nI cannot hold it inside\nI cannot keep it quiet\nThis holy fire\'s burning inside of me', NULL),
(9, '1785', 'Trachtet zuerst nach dem Reiche des Herrn  -  Seek ye first the Kingdom of God   (Halleluja, Halleluja, Halleluja)', 'Seek ye first the Kingdom of God\nand His righteousness.\nAnd all these things shall be added unto you.\nHallelu\', hallelujah.\r\nHalleluja, Halleluja, Halleluja\nHallelu, Halleluja\r\nKnock, and the door shall be opened unto you,\nseek and you shall find.\nAsk and it shall be given unto you.\nHallelu\', hallelujah.\r\nMan shall not live by bread alone,\nbut by every Word.\nThat proceeds from the mouth of the Lord.\nHallelu\', hallelujah.\r\n\r\n\r\n', 'Trachtet zuerst nach dem Reiche des Herrn\nund Seiner Gerechtigkeit.\nSo wird Euch solches alles zufallen.\nHallelu\', Halleluja.\r\n\r\nBittet, so wird euch gegeben,\nsuchet, so werdet ihr finden.\nKlopfet an, so wird euch aufgetan.\nHallelu\', Halleluja.\r\nDer Mensch lebt nicht vom Brot allein,\nsondern von einem jedem Worte,\ndas aus dem Munde Gottes kommt.\nHallelu\', Halleluja.\r\nWer an Mich glaubt, wie die Bibel es sagt,\nvon dessen Leib werden fließen,\nStröme lebendigen Wassers.\nHallelu\', Halleluja.\r\nIhr werdet Kraft empfangen,\nwenn der Heilige Geist kommt.\nUnd werdet Meine Zeugen sein.\nHallelu\', Halleluja.\r\nJesus Du sprachst: "Ich bin das Licht,\nwer an Mich glaubt. der wird leben,\nselbst wenn er schon entschlafen ist."\nHallelu\', Halleluja.'),
(9, '1786', 'Trau auf den Herrn und zweifle nicht  -  Trust in the Lord and don’t despair   (Sing, wenn der Tag dir lacht)', 'Trust in the Lord and don’t despair,\nHe is a friend so true!\nNo matter what your troubles are,\nJesus will see you through.\r\nSing when the day is bright,\nSing through the darkest night,\nEvery day, all the way,\nLet us sing, sing, sing.\r\n\r\n\r\n', 'Trau auf den Herrn und zweif\'le nicht,\nEr ist dein Freund, so treu.\nWas immer dir zur Stund\' gebricht,\nEr bringt dich durch auf\'s Neu.\r\nSing, wenn der Tag dir lacht!\nSing auch in dunkler Nacht,\njeden Tag, wie\'s sein mag,\nsing, mein Herz, oh sing!\r\nGlaub Seinem Wort und zweifle nicht,\nEr lässt dich nie allein.\nSein treues Auge wacht für dich\nbei Nacht und Sonnenschein.\r\nSei nur getrost und freue dich,\nes liebt dich ja der Herr.\nHerrlichkeit ist bereit für dich\nund Gnade tief wie\'s Meer.\r\nEs ist so schön, dem Herrn vertrau\'n\nund Seiner Hände Tun,\nbeständig auf Sein Antlitz schau\'n,\nin Seiner Liebe ruh\'n!'),
(9, '1787', 'Traurig von ferne zehn Aussätz\'ge stehn  -  Wand’ring afar from the dwellings of Men   (Wo sind die Neun?)', 'Wand’ring afar from the dwellings of men,\nhear the sad cry of the lepers, the ten:\nJesus have mercy! brings healing divine,\none came to worship, but where are the nine?\r\nWhere are the nine?\nWhere are the nine?\nWere there not ten cleansed?\nWhere are the nine?\r\nLoudly the stranger sang praise to the Lord,\nknowing the cure had been wrought by His word.\nGratefully owning the Healer divine;\nJesus says tenderly, Where are the nine?\r\nWho is this Nazarene? Pharisees say,\nis He the Christ? Tell us plainly, we pray.\nMultitudes follow Him seeking a sign,\nshow them His mighty works - where are the nine?\r\nJesus on trial today we can see,\nthousands deridingly ask, Who is He?\nHow they’re rejecting Him, your Lord and mine!\nBring in the witnesses - where are the nine?', 'Traurig von ferne zehn Aussätz\'ge steh\'n,\n"Jesus, erbarme Dich"! bange sie fleh\'n.\nWunderbar macht Jesu Liebe sie rein;\nEiner kommt dankend, doch wo sind die Neun?\r\nWo sind die Neun?\nWo sind die Neun?\nWurden nicht zehn rein?\nWo sind die Neun?\r\nLaut pries der Fremdling die Gnade des Herrn,\ndankt Ihm als seinem Erretter so gern.\nWie? Gibt nur er Gott die Ehre allein?\nJesus fragt schmerzlich: "Wo sind denn die Neun"?\r\n"Ist dieser Christus?" so fragte man sich;\ngibt Er uns Zeichen, dann glaube auch ich!\nDoch auch das Größte ist ihnen zu klein,\nkaum glaubt Ihm einer und wo sind die Neun?\r\nTausenden fragen verächtlich noch jetzt:\nWer ist den dieser, zum Herrn uns gesetzt?\n"Jesus" Er ladet so freundlich euch ein!\nWenige kommen, o, wo sind die Neun?'),
(9, '1788', 'Treff ich dich wohl bei der Quelle  -  Will you meet me at the Fountain   (Ja, ich komm zur Lebensquelle)   [Siegesklänge]', 'Will you meet me at the fountain,\nwhen I reach the glory land.\nWill you meet me at the fountain,\nshall I clasp your friendly hand.\nOther friends will give me welcome,\nother loving voises cheer.\nThere\'ill be music at the fountain,\nwill you, will you meet me there?\r\nYes, I\'ll meet you at the fountain,\nat the fountain bright and fair.\nYes I\'ll meet you, oh, I\'ll meet you,\nat the fountain, yes, I\'ll meet you, meet you there.\r\nWill you meet me at the fountain,\nfore I\'m sure that I shall know.\nKindred souls and sweet communion\nmore than I have known below.\nAnd the chorus will be sweeter,\nwhen it bursts  upon my ear.\nAnd my heaven seem completer,\nif your happy voice I hear.\r\nWill you meet me at the fountain,\nI shall long to have you near.\nWhen I meet my loving Saviour,\nwhen his welcome words I hear.\nHe will meet me at the fountain,\nHis embraces I shall hear.\nThere\'ll be glory at the fountain,\nwill you, will you meet me there.', 'Treff ich dich wohl bei der Quelle\nin dem Land der Herrlichkeit?\nDürstet nicht auch deine Seele\nnach dem Born der Seligkeit?\nLauter Jubel wird erschallen\nbei der Quelle, licht und schön.\nDarf ich, wo die Sel\'gen wallen,\nnicht auch dich, ja dich dort seh\'n?\r\nJa, ich komm\' zur Lebensquelle,\nzu der Quelle, licht und schön.\nOh, wie freut sich meine Seele\nauf solch sel\'ges Wiederseh\'n!\r\nTreff ich dich wohl bei der Quelle?\nViel\' der Lieben sind schon dort,\ndie im hohem Licht erst helle\nich erkenn\' an jenem Ort.\nHimmlisch süß wird dann erklingen\nunsres Sanges Lobgetön.\nWillst auch du nicht darnach ringen,\ndass wir dort uns wiederseh\'n?\r\nTreffen wir uns bei der Quelle,\nbei dem Herrn im Vaterhaus?\nBeim Betreten seiner Schwelle\nblick\' ich sehnend nach dir aus.\nBei der Quelle strömt den Armen\nFülle hohem Lebens zu.\nSel\'ges Los in Jesu Armen!\nKomm auch du zu dieser Ruh\'!'),
(9, '1789', 'Treffen wir uns an dem Strome  -  Shall we gather at the River   (Ja, ich komm zur Lebensquelle)', 'Shall we gather at the river,\nwhere bright angel feet have trod.\nWith its crystal tide forever,\nflowing by the throne of God?\r\nYes, we\'ll gather at the river,\nthe beautiful, the beautiful river.\nGather with the saints at the river\nthat flows by the throne of God.\r\nOn the bosom of the river,\nwhere the Saviour-King we own.\nWe shall meet and sorrow never,\n\'neath the glory of the throne.\r\nOn the margin of the river,\nwashing up its silver spray,\nwe will walk and worship ever,\nall the happy, golden day.\r\nEre we reach the shining river,\nlay we every burden down.\nGrace our spirits will deliver,\nand provide a robe and crown.\r\nAt the smiling of the river,\nmirror of the Saviour\'s face.\nSaints whom death will never sever\nlift their songs of saving grace.\r\nSoon we\'ll reach the shining river,\nsoon our pilgrimage will cease.\nSoon our happy hearts will quiver\nwith the melody of peace.', 'Treffen wir uns an dem Strome\nvor Gottes Thron auf heiligem Grund?\nWerden wir uns dort begegnen,\num Ihn zu preisen wie aus einem Mund?\r\nJa ich komm zur Lebensquelle,\nzu der  Quelle licht und schön!\nO, wie freut sich meine Seele\nauf ein sel\'ges Wiederseh\'n!\r\nDort werden wir Ihn endlich sehen,\nder auf Erden uns mit Blut hat erkauft,\nwerden alle Wege verstehen,\nJesus danken, auf den wir vertraut.\r\nFreudengesang und lauter Jubel\nwird dort uns\'re Gemeinschaft sein.\nKeine Schatten und kein Dunkel,\ndenn das Lamm wird das Licht uns sein.\r\nJede Träne wird Er wischen\nfort von unserem Angesicht,\nalles Leid, es ist vergessen,\nund der Feind erreicht uns nicht.\r\nDort werden wir sie wiedersehen,\nalle, die Er vor uns durchgebracht.\nDie Gesichter strahlen in dem Lichte,\ndann vertreibt der ew\'ge Tag die Nacht.\r\nBald erreichen wir den herrlichen Fluss,\nbald ist unsere Pilgerreise zu Ende.\nBald erbeben unsere glücklichen Herzen,\nmit der Melodie des Friedens.'),
(9, '1790', 'Treuer Gott, unveränderlich  -  Faithful One, so unchanging', 'Faithful One, so unchanging,\nageless One, You\'re my rock of peace,\nLord of all, I depend on You.\nI call out to You, again and again,\nI call out to You, again and again.\r\nYou are my Rock in times of trouble,\nYou lift me up when I fall down.\nAll through the storm Your love is the anchor,\nmy hope is in You alone.', 'Treuer Gott, unveränderlich,\nStarker Fels, ich stell mich auf Dich,\nHerr der Herrn, nur Dich brauche ich,\nich rufe Dich an, Herr, an jedem Tag,\nich rufe Dich an, Herr, an jedem Tag.\r\nDu bist mein Fels in schweren Zeiten,\nDu hebst mich hoch auf Deinen Arm.\nIn jedem Sturm ruht in Dir mein Anker,\nich hoffe auf Dich allein!'),
(9, '1791', 'Trials here are sometimes many   (After all this Life is over)', 'Trials here are sometimes many,\nand oft times my feet grow weary,\n\'till It seems I almost stumble and fall.\nBut the tender hand that leads me,\nis the hand that keeps me steady,\nand gives me faith that I will make it after all\r\nAfter all this life is over,\nand my burdens have been lifted,\nand I stand upon the mountain top so tall.\nLooking over to that city,\nthat the Saviour is preparing,\ngives me faith that I can make it after all.\r\nBy myself I cannot make it,\nbut I know He\'s there to help me,\nHe will hear my cry and answer when I call.\nKeep on trusting and believing,\nare the words I hear Him whisper,\njust a few more days to labor after all.', NULL),
(9, '1792', 'Trostlos und leer ist ohne Dich die Welt  -  Living below in this old sinful World   (Wohin soll ich gehn, o wohin soll ich gehn)', 'Living below in this old sinful world,\nhardly a comfort can afford.\nStriving alone to face temptations sore,\nwhere could I go but to the Lord?\r\nWhere could I go, oh, where could I go?\nSeeking a refuge for my soul?\nNeeding a friend to help me in the end,\nwhere could I go but to the Lord?\r\nNeighbours are kind, I love them every one,\nwe get along in sweet accord;\nbut when my soul needs manna from above,\nwhere could I go but to the Lord?\r\nLife here is grand with friends I love so dear,\ncomfort I get from God\'s own word;\nyet when I face the chilling hand of death,\nwhere could I go but to the Lord?', 'Trostlos und leer ist ohne Dich die Welt,\nkaum eine Hoffnung gibt sie mir.\nBin ich allein, Versuchung mich befällt,\nsag mir, wohin soll ich geh\'n als Herr zu Dir?\r\nWohin soll ich geh\'n, o wohin soll ich geh\'n?\nLeben find\' ich allein bei Dir.\nIch wüsste nicht, wer mir sonst helfen kann,\nsag mir, wohin soll ich geh\'n als Herr zu Dir?\r\nFreunde hab\' ich, ich lieb\' sie alle sehr,\nsie waren gut und treu zu mir.\nDoch meine Seel\' braucht Manna noch viel mehr,\nsag mir, wohin soll ich geh\'n als Herr zu Dir?\r\nLeben ist schön mit Freunden die bei mir.\nTrost find ich nur in Gottes Wort.\nDoch wenn der Tod einst klopft an meine Tür,\nsag mir, wohin soll ich geh\'n als Herr zu Dir?'),
(9, '1793', 'Und löst sich hier das Rätsel nicht  -  Not now, but in the coming Years   (Drum trau auf Gott und harre aus)   [Pfingstjubel]', 'Not now, but in the coming years,\nit may be in the better land,\nwe’ll read the meaning of our tears,\nand there, sometime, we’ll understand.\r\nThen trust in God through all the days.\nFear not, for He doth hold thy hand.\nThough dark thy way, still sing and praise,\nsometime, sometime we’ll understand.\r\nWe’ll catch the broken thread again,\nand finish what we here began.\nHeav’n will the mysteries explain,\nand then, ah then, we’ll understand.\r\nWe’ll know why clouds instead of sun,\nwere over many a cherished plan.\nWhy song has ceased when scarce begun.\n’Tis there, sometime, we’ll understand.\r\nWhy what we long for most of all,\neludes so oft our eager hand.\nWhy hopes are crushed and castles fall,\nup there, sometime, we’ll understand.\r\nGod knows the way, He holds the key,\nHe guides us with unerring hand.\nSometime with tearless eyes we’ll see.\nYes, there, up there, we’ll understand.', 'Und löst sich hier das Rätsel nicht\nder Tränen all, die du geweint,\nim Land voll ew\'gem Sonnenlicht,\nda wirst du seh\'n, wie Er\'s gemeint.\r\nD\'rum trau auf Gott und harre aus,\nwie dunkel auch dein Weg dir scheint.\nEr endet doch im Vaterhaus,\ndann wirst du seh\'n, wie Er\'s gemeint.\r\nDa knüpft sich manch\' zerrissen\' Band,\nwas hier getrennt, wird neu vereint,\nund was kein Menschenherz verstand,\ndort wirst du seh\'n, wie Er\'s gemeint.\r\nOb über deinem Leben nie\ndes Glückes lichte Sonne scheint,\nnur düst\'re Wolken spät und früh,\neinst wirst du seh\'n, wie Er\'s gemeint.\r\nUnd ward dem Herzen Traum um Traum,\nder Seele Wunsch auf Wunsch verneint,\nentlaubt der Hoffnung grüner Baum,.\nEinst wirst du seh\'n, wie Er\'s gemeint.\r\nO murre nicht und frag nicht viel,\nEr ist und bleibt dein treu\'ster Freund,\nEr kennt den Weg, Er kennt das Ziel;\neinst wirst du seh\'n, wie Er\'s gemeint.'),
(9, '1794', 'Und scheinen die Wege auch seltsam, die Christus, Dein König dich führt   (O so wisse, dass Gott keine Fehler macht)', NULL, 'Und scheinen die Wege auch seltsam,\ndie Christus, Dein König, dich führt,\ndu musst es Ihm ganz überlassen,\nIhm, der dir dein Leben regiert.\r\nO so wisse, dass Gott keine Fehler macht,\no so wisse, dass Gott keine Fehler macht,\no so sag ich\'s dir wieder auf\'s neu:\nJesus ist treu.\r\nUnd kannst du es auch nicht verstehen,\nwarum Gott dir manches nicht ließ,\nim Ewigkeitslicht darfst du\'s wissen,\nim himmlischen Paradies.\r\nMusst Unrecht du manches erleiden,\nso denkst du, das ist nicht vom Herrn!\nDu murrst wider Gott gar und trauerst,\nund Er möcht\' dich läutern nur gern.\r\nUnd kannst du es auch nicht begreifen,\nwas du dir so anders gedacht,\nso richte den Blick nur auf Jesus,\nweil Er keinen Fehler macht.'),
(9, '1795', 'Under His Wings I am safely abiding   (Under His wings, under His wings)', 'Under His wings I am safely abiding,\nthough the night deepens and tempests are wild.\nStill I can trust Him, I know He will keep me.\nHe has redeemed me, and I am His child.\r\nUnder His wings, under His wings,\nwho from His love can sever?\nUnder His wings my soul shall abide,\nsafely abide forever.\r\nUnder His wings - what a refuge in sorrow!\nHow the heart yearningly turns to His rest!\nOften when earth has no balm for my healing,\nthere I find comfort, and there I am blest.\r\nUnder His wings - oh, what precious enjoyment!\nThere will I hide till life’s trials are o’er.\nSheltered, protected, no evil can harm me;\nresting in Jesus I’m safe evermore.', NULL),
(9, '1796', 'Unerschöpflich strömt die Quelle  -  When I saw the cleansing Fountain   (Ich will preisen, ich will preisen)', 'When I saw the cleansing fountain,\nopen wide for all my sin.\nI obeyed the Spirit’s wooing\nwhen He said, “Wilt thou be clean?”\r\nI will praise Him! I will praise Him!\npraise the Lamb for sinners slain.\nGive Him glory, all ye people,\nfor His blood can wash away each stain.\r\nTho\' the way seems straight and narrow,\nall I claimed was swept away.\nMy ambitions, plans and wishes,\nat my feet in ashes lay.\r\nBlessed be the name of Jesus!\nI’m so glad He took me in.\nHe’s forgiven my transgressions,\nHe has cleansed my heart from sin.\r\nThen God\'s fire upon the altar\nof my heart was set aflame.\nI shall never cease to praise Him,\nglory, glory to His name!', 'Unerschöpflich strömt die Quelle,\ndie mich reinigt von der Schuld.\nUnd ich öffne mich dem Geiste,\nder mir nachgeht mit Geduld.\r\nIch will preisen, ich will preisen\nGottes Lamm, das starb für mich!\nAlle Ehre dem Erlöser,\ndenn Sein Blut wusch rein von aller Sünd\'.\r\nGottes Wort macht mich zum Tempel,\nwo des Geistes Feuer brennt.\nImmer sei Ihm Dank und Ehre,\nder mich sanft beim Namen nennt.\r\nPreis dem teuren Namen Jesus!\nEr nahm auf, mich als Sein Kind.\nDessen bin ich immer fröhlich,\ndass hinweg Er nahm die Sünd\'.\r\nDann wurde das Feuer Gottes auf dem Altar\nmeines Herzens in Flammen gesetzt.\nIch werde nie aufhören, Ihn zu preisen,\nRuhm, Ruhm seinem Namen!'),
(9, '1797', 'Uns wird\'s verwandeln in einem Augenblck   (Chorus)', NULL, 'Uns wird\'s verwandeln in einem Augenblick,\nuns wird\'s verwandeln in einem Augenblick.\nDie Posaune ertönt; wer bereit ist, wird geh\'n.\nUns wird\'s verwandeln in einem Augenblick.'),
(9, '1798', 'Unser Himmlischer Vater, Heilig ist Dein Name', NULL, 'Unser Himmlischer Vater,\nheilig ist Dein Name,\nDein Reich komme,\nDein Wille geschehe.\r\nUnser tägliches Brot\ngib uns an diesem Tage\nund vergib uns,\nwie auch wir vergeben.\r\nDenn\nDein ist das Reich und die Kraft,\nDein ist die Herrlichkeit,\nin Ewigkeit, Amen! (2x)\r\nAmen, Amen!\nWie im Himmel,\nso auf Erden,\nAmen!'),
(9, '1799', 'Unser Leid hast Du getragen   (Durch Deine Wunden sind wir geheilt)', NULL, 'Unser Leid hast Du getragen,\nunsre Schmerzen unsre Schuld.\nHast all das auf Dich geladen\nund uns gerettet vor dem Tod.\r\nWir alle irrten umher wie Schafe,\nwir war\'n verloren auf uns\'rem Weg.\nUns\'re Schuld hat Dich getroffen,\nauf dass wir Gottes Gnade seh\'n.\r\nDurch Deine Wunden sind wir geheilt.\ndie Strafe lag auf Dir zu uns\'rem Frieden.\nDurch Deine Wunden sind wir jetzt frei,\nJesus wie sehr, wie sehr musst Du uns lieben.\r\nSo zerschunden und gemartert,\nDu hast den Mund nicht aufgetan.\nHast Dich gebeugt und stumm ertragen\nwas niemand von uns tragen kann.'),
(9, '1800', 'Unsern Ausgang segne Gott, unsern Eingang gleichermaßen', NULL, 'Unsern Ausgang segne Gott,\nunsern Eingang gleichermaßen!\nSegne unser täglich Brot,\nsegne unser Tun und Lassen!\nSegen uns mit sel\'gem Sterben\nund mach uns zu Himmelserben!');
INSERT INTO song_list (LISTID, NUM, NAME, TEXT_EN, TEXT_DE) VALUES
(9, '1801', 'Unter dem Kreuz wo auch mir zugut  -  Down at the Cross where my Saviour died   (Ehre sei dem Herrn)', 'Down at the cross where my Saviour died,\ndown where for cleansing from sin I cried,\nthere to my heart was the blood applied.\nGlory to His name!\r\nGlory to His name!\nGlory to His name!\nThere to my heart was the blood applied.\nGlory to His name!\r\nI am so wondrously saved from sin,\nJesus so sweetly abides within,\nthere at the cross where He took me in.\nGlory to His name!\r\nOh, precious fountain that saves from sin!\nI am so glad I have entered in,\nthere Jesus saves me and keeps me clean:\nGlory to His Name!\r\nCome to this fountain so rich and sweet,\ncast thy poor soul at the Saviour\'s feet,\nplunge in today and be made complete:\nGlory to His name!', 'Unter dem Kreuz, wo auch mir zugut\',\nströmet die köstliche Gnadenflut,\ndort fand ich Frieden in Jesu Blut.\nEhre sei dem Herrn!\r\nEhre sei dem Herrn!\nEhre sei dem Herrn!\nDort fand ich Frieden in Jesu Blut,\nEhre sei dem Herrn!\r\nIch bin aus Gnaden von Sünden rein,\nJesus, Er wohnet im Herzen mein;\ndort unterm Kreuz ward ich ewig Sein.\nEhre sei dem Herrn!\r\nHerrliche Quelle, die Sünder heilt!\nIch bin im Glauben und unverweilt\nin diese sühnende Flut geeilt.\nEhre sei dem Herrn!\r\nKommt zu der Quelle so reich und klar,\nbringt eure Seelen dem Heiland dar.\nDann singt ihr einst mit der sel\'gen Schar:\n"Ehre sei dem Herrn!"'),
(9, '1802', 'Unter Lilien jener Freuden sollst du weiden', NULL, 'Unter Lilien jener Freuden sollst du weiden,\nSeele, schwinge dich empor!\nWie ein Adler flieg behende,\nJesu Hände öffnen schon das Perlentor.\r\nLasst mich gehen, lasst mich laufen\nzu dem Haufen derer, die des Lammes Thron\nnebst, dem Chor der Seraphinen schon bedienen\nmit dem reinsten Jubelton!\r\nLöse, erstgeborner Bruder,\ndoch die Ruder meines Schiffleins;\nlass mich ein in den sichern Friedenshafen\nzu den Schafen, die der Furcht entrücket sein!\r\nO wie bald kannst Du es machen,\ndass mit Lachen unser Mund erfüllet sei!\nDu kannst durch des Todes Türen\nträumend führen und machst uns auf einmal frei.\r\nDu hast Sünd\' und Straf getragen.\nFurcht und Zagen muss nun ferne von mir geh\'n.\nTod, dein Stachel liegt darnieder;\nmeine Glieder werden fröhlich aufersteh\'n.\r\nHerzenslamm, Dich will ich loben hier\nund droben in der zartsten Liebsbegier.\nDu hast Dich zum ew\'gen Leben mir gegeben;\nhole mich, mein Lamm, zu Dir!'),
(9, '1803', 'Unter Seiner Flügel Schutz winkt mir süße Ruh  -  In the Shadow of His Wings there is Rest   (Süße Ruh, holder Fried, selge Freud)', 'In the shadow of His wings there is rest, sweet rest.\nThere is rest from care and labor,\nthere is rest for friend and neighbor.\nIn the shadow of His wings there is rest, sweet rest,\nin the shadow of His wings there is rest.\r\nThere is rest, there is peace, there is joy,\nin the shadow of His wings.\nThere is rest, there is peace, there is joy,\nin the shadow of His wings.\r\nIn the shadow of His wings there is peace, sweet peace,\npeace that passeth understanding,\npeace, sweet peace that knows no ending.\nIn the shadow of His wings there is peace, sweet peace,\nin the shadow of His wings there is peace.\r\nIn the shadow of His wings there is joy, glad joy,\nthere is joy to tell the story,\njoy exceeding, full of glory.\nIn the shadow of His wings there is joy, glad joy,\nin the shadow of His wings there is joy.', 'Unter Seiner Flügel Schutz winkt mir süße Ruh\'.\nDa ist Ruh\' von Müh\' und Sorgen,\no wie gut ist man geborgen!\nUnter Seiner Flügel Schutz winkt mir süße Ruh\';\nunter Seiner Flügel Schutz da ist Ruh\' (für mich).\r\nSüße Ruh\', holder Fried\', sel\'ge Freud\',\nunter Seiner Flügel Schutz.\nSüße Ruh\', holder Fried\', sel\'ge Freud\',\nunter Seiner Flügel Schutz.\r\nUnter Seiner Flügel Schutz wohnet holder Fried\',\nFriede den kein Zweifel störet,\nholder Fried\' der nie aufhöret.\nUnter Seiner Flügel Schutz wohnet holder Fried\',\nUnter Seiner Flügel Schutz da ist Fried\'.\r\nUnter Seiner Flügel Schutz lächelt sel\'ge Freud\',\nFreude groß und unaussprechlich,\nFreude, fest und unbeweglich.\nUnter Seiner Flügel Schutz lächelt sel\'ge Freud\',\nunter Seiner Flügel Schutz da ist Freud\'.'),
(9, '1804', 'Unterm Kreuz ist Friede, tiefe, tiefe Ruh', NULL, 'Unterm Kreuz ist Friede, tiefe, tiefe Ruh\',\nda strömt Jesu Gnade müden Seelen zu,\nda versiegt der Quelle bitt\'rer Tränenflut\nund von Sünden helle macht des Lammes Blut!\r\nUnterm Kreuz ist Friede, da floss Jesu Blut,\nseine Sünderliebe kommt auch mir zugut.\nWill der Feind mich schrecken, macht die Sünd\' mir Not,\nJesus will mich decken, mir bringt Sieg sein Tod.\r\nUnd fahr ich von hinnen, eile ich ihm zu.\nIn dem Himmeln drinnen bist es du, nur du,\ndem ich meine Krone leg zu Füßen hin,\nwo ewig ich wohne, stets bei Jesus bin.'),
(9, '1805', 'Unterm Schatten seiner Flügel bin ich sicher Jahr um Jahr', NULL, 'Unterm Schatten seiner Flügel bin ich sicher Jahr um Jahr.\nWeicht, ihr Berge, fallt, ihr Hügel – Jesus bleibt, was stets er war,\nbleibt mein Hirte, der mich weidet, Lebensquell, nach dem mich dürst\',\nStern, der mich gen Himmel leitet, Heiland, Retter, Friedefürst.\r\nArzt des Leibes und der Seele, meine Stärke, meine Kraft,\nTilger meiner Schuld und Fehle, Schöpfer, welcher neu mich schafft,\nTrost in allen Traurigkeiten, Kompass auf des Lebens Meer,\nheller Schein in Dunkelheiten und im Kampfe Schutz und Wehr.\r\nSchatten vor des Tages Hitze, Decke vor der Nächte Frost,\nLicht, wenn ich im Finster\'n sitze, Zuflucht, wenn das Wetter tost,\nFreistatt, drin ich wohl geborgen, Fels, auf dem mein Glaube ruht,\nTräger aller meiner Sorgen, sich\'rer Schutz und treue Hut.\r\nEinz\'ges Heil und Weg zum Vater, wunderbarer Helfersmann,\nmein allmächtiger Berater, wo kein Mensch mehr helfen kann.\nFreund, auf welchen ich mich lehne, Stab und Stecken meiner Hand,\new\'ge Ruh\', die ich ersehne, Führer nach dem Vaterland.\r\nFreude, Friede, ew\'ges Leben, Hoherpriester vor dem Thron,\nBürge, der sich dargegeben, Hoffnung, Schild und großer Lohn.\nEr, mein Glück und meine Wonne, meine höchste Seligkeit,\nmeines Lebens heit\'re Sonne, die mir strahlt in Ewigkeit.\r\nWenn ich leer bin – meine Fülle, bin ich arm – der Reichtum mein,\nin der Unruh – meine Stille, in der Nacht – mein heller Schein.\nD\'rum in seinen Liebesarmen darf ich ruhen immerdar,\nunterm Schatten seiner Flügel bin ich sicher Jahr um Jahr.'),
(9, '1806', 'Upon our Journey here below we meet with Pain and Loss   (When we\'re inside the Gates of Pearl)', 'Upon our journey here below\nwe meet with pain and loss.\nSometimes there is a crown of thorns,\nsometimes the heavy cross.\nThe dreary road to Calvary,\nthe bitter goad and sting.\nBut what\'s inside those gates of pearl\nwill be worth everything.\r\nWhen we\'re inside the gates of pearl,\nwe\'ll learn a lot of things.\nWe\'ll have a harp that\'s made of gold,\nperhaps a thousand strings.\nWe\'ll sing and shout and dance about,\nthe Lamb will dry our tears.\nWe\'ll have a grand homecoming week,\nthe first ten thousand years.\r\nThe shadows now begin to fall,\nthe time is drawing nigh.\nWhen Christ our Lord shall come again\nlike lightning from the sky.\nAnd while we wait and suffer here,\npraise God, we\'ll shout and sing.\nFor one glimpse through those gates\nof pearl will be worth everything.\r\nThe precious blood of God\'s own Son\nhas saved and sanctified.\nA wondrous people for His name\nand they are called the Bride.\nThough here neglected and despised,\none day the Lord will bring.\nHis chosen ones within the gates,\nand that\'s worth everything.', NULL),
(9, '1807', 'Über Berge und Höhn geht mein Sehnen   (Nimm, was Dir nicht gefällt doch von mir)', NULL, 'Über Berge und Höh\'n geht mein Sehnen,\nnach dem Land voller Frieden und Freud\'.\nFließen hier auch im Kampf manchmal Tränen,\nbald kommt Jesus, ach, wär\' es doch heut.\r\nNimm, was Dir nicht gefällt doch von mir.\nWie ich bin, HErr, so komm ich zu Dir.\nDurch Dein Blut wasch\' mich rein\nund voll Geistes lass mich sein.\nGib\' mir Gnad\' Dir zu leben allein.\r\nWillst\' den Heiland du droben einst schauen,\nmit den Heil\'gen im Himmel dich freu\'n?\nWillst du wandeln auf himmlischen Auen?\nDann lass heute dein Flehen doch sein:\r\nWill der Feind mit der Sünde dich fangen,\nauf den Weg des Verderbens dich zieh\'n?\nSind auch einige vom Herrn gegangen,\ndann bleib\' du Ihm doch treu, ja bitt\' Ihn:'),
(9, '1808', 'Überwunden durch das Blut, jauchzt ein siegend Heer   (Triumphierend brach das Lamm, Satans Macht entzwei)', NULL, '"Überwunden durch das Blut!"\njauchzt ein siegend\' Heer,\nvoll von heil\'ger Dankesglut,\nam kristall\'nen Meer.\r\nTriumphierend brach das Lamm\nSatans Macht entzwei.\nDurch das Blut am Kreuzesstamm\nsind wir alle frei.\r\nÜberwunden durch das Blut\nist die alte Schuld;\nJesus machte alles gut,\nblickt auf uns mit Huld.\r\nÜberwunden durch das Blut\nist der Sünde Macht;\ntrotz des Teufels List und Wut\nwird uns Sieg gebracht.\r\nÜberwunden durch das Blut\nwird der alte Feind.\nBald sind wir in sich\'rer Hut\nmit dem Herrn vereint.\r\nÜberwunden durch das Blut\nist die Todesmacht;\nJesus hat auch mir zugut\ndiesen Sieg vollbracht.'),
(9, '1809', 'Vater im Himmel', NULL, 'Aus der Tiefe meines Herzens\nSteigt ein Loblied auf zu dir\nZu dem Schöpfer aller Himmel\nZu dem Gott, der wohnt in mir\nDu hast mich erdacht geschaffen\nUnd geformt nach deinem Bild\nDurch die schwere Zeit getragen\nUnd mit deinem Geist erfüllt\r\nDu bist die Quelle\nDas Leben in Fülle\nVater im Himmel\nDu bist mir heilig\nVater für immer\nEhre ich dich\nVater, dein Name\nWerde geheiligt\nUnd dein Licht scheine durch mich\r\nDu hast mir genug gegeben\nAn deinen Tisch lädst du mich ein\nLehre mich bewusst zu lieben\nIn deiner Gegenwart zu sein\nDu hast mich so reich gesegnet\nIch darf an deinem Herzen ruh′n\nUnd was immer mir begegnet\nHat mit dir etwas zu tun'),
(9, '1810', 'Vater lass das Feuer falln  -  Father let the Fire fall   (Chorus)', 'Father, let the fire fall, Father, let the fire fall, let the fire fall,\nlet the fire fall, let the Pentecostal fire fall!', 'Vater lass das Feuer fall\'n, Vater lass das Feuer fall\'n,\nlass das Feuer fall\'n, lass das Feuer fall\'n,\nlass das Pfingstfeuer fall\'n.'),
(9, '1811', 'Vater mach uns eins  -  Father make us one   (Psalm 133)', 'Father, make us one,\nFather, make us one.\nThat the world may know,\nThou hast sent Thy Son.\nFather, make us one.\r\nBehold how pleasant and how good it is,\nfor brethren to dwell in unity.\nFor there the Lord commands the blessing.\nLife forever more.', 'Vater, mach uns eins,\nVater, mach uns eins.\nDass die Welt erkennt,\nDu hast den Sohn gesandt.\nVater, mach uns eins.\r\nSiehe, wie fein und wie lieblich ist\'s,\nwenn Brüder in Einheit zusammen sind.\nDenn dort hast Du den Segen verheißen.\nLeben in Ewigkeit.'),
(9, '1812', 'Vater wir danken Dir; wir preisen Dich; wir lieben Dich; wir loben Dich   (4 Chorusse)', NULL, 'Vater, wir danken Dir, Vater, wir danken Dir,\nVater, im Himmel, wir danken Dir!\r\nVater, wir preisen Dich, Vater, wir preisen Dich,\nVater, im Himmel, wir preisen Dich!\r\nVater, wir lieben Dich, Vater, wir lieben Dich,\nVater, im Himmel, wir lieben Dich!\r\nVater, wir loben Dich, Vater, wir loben Dich,\nVater, im Himmel, wir loben Dich!'),
(9, '1813', 'Vater, Vater, Dir sei Anbetung, Vater Dir allein', NULL, 'Vater, Vater, Dir sei Anbetung,\nVater, Dir allein! (2x)\r\nUnd die Himmel und die Erde,\nsie rufen Dir zu:\n"Heilig, heilig bist nur Du!"\nUnd die Himmel und die Erde,\nsie rufen Dir zu:\n"Heilig, heilig, heilig bist Du!"'),
(9, '1814', 'Vater, wir lieben, wir ehren und anbeten Dich  -  Father we love You, we worship and adore You   (Chorus)', 'Father, we love You, we worship and adore You.\nGlorify Your name in all the earth.\nGlorify your name, glorify your name,\nglorify your name in all the earth.', 'Vater, wir lieben, wir ehren und anbeten Dich.\nEhre Deinem Namen auf der Erd\'.\nEhre Deinem Nam\', Ehre Deinem Nam\',\nEhre Deinem Namen auf der Erd\'.'),
(9, '1815', 'Vergiss nicht zu danken dem ewigen Herrn   (Barmherzig, geduldig und gnädig ist Er)   (Psalm 103)', NULL, 'Vergiss nicht zu danken dem ewigen Herrn,\nEr hat dir viel Gutes getan.\nBedenke, in Jesus vergibt Er dir gern,\ndu darfst Ihm, so wie du bist, nah\'n.\r\nBarmherzig, geduldig und gnädig ist Er,\nviel mehr als ein Vater es kann.\nEr warf uns\'re Sünden ins äußerste Meer,\nd\'rum betet den Ewigen an!\r\nDu kannst Ihm vertrauen in dunkelster Nacht,\nwenn alles verloren erscheint.\nEr liebt dich, auch wenn du Ihm Kummer gemacht,\nist näher, als je du gemeint.\r\nIm Danken kommt Neues ins Leben hinein,\nein Wünschen, das nie du gekannt,\ndass jeder wie du Gottes Kind möchte sein,\nvom Vater zum Erben ernannt.\r\nIn Jesus gehörst du zur ewigen Welt,\nzum Glaubensgehorsam befreit.\nEr hat dich in Seine Gemeinde gestellt\nund macht dich zum Dienen bereit.'),
(9, '1816', 'Vergiss nie, Gott hört Gebet   (Chorus)', NULL, 'Vergiss nie, Gott hört Gebet,\nVergiss nie, Gott hört Gebet!\nSein Wort hat noch nie Er gebrochen,\no glaub\'s, Gott erhört Gebet,'),
(9, '1817', 'Viel Glück und viel Segen auf all deinen Wegen   (Chorus)', NULL, 'Viel Glück und viel Segen,\nauf all deinen Wegen,\nGesundheit und Frohsinn\nsei auch mit dabei!'),
(9, '1818', 'Viele suchen noch das Verheißungsland wo die Nacht vorbei  -  Do you seek a Land where there comes no Night   (Willst du glauben was Gott verheißt)', 'Do you seek a land where there comes no night,\nblessed Beulah land, where the sun shines bright.\nWhere we walk by faith and not by sight,\nbaptized with the Holy Ghost?\r\nWill you be baptized in this faith?\nBaptized with the Holy Ghost?\nTo be free indeed, ’tis the pow’r you need,\nBaptized with the Holy Ghost.\r\nWill you take Him now as your all in all,\nlet the self be slain, that that pow’r may fall?\nWill you now in faith for the blessing call,\nbaptized with the Holy Ghost?\r\n‘Tis the Canaan-land for our weary feet,\nwith our wand’rings o’er and our rest complete.\nWhere we dwell with Christ in communion sweet,\nbaptized with the Holy Ghost.\r\nYes, we gladly come, blessed Lord, to Thee,\nfrom the carnal mind that we may be free.\nAnd we look in faith, for we long to be\nbaptized with the Holy Ghost.\r\nYes, I’ll be baptized in this faith,\nbaptized with the Holy Ghost.\nTo be free indeed, ’tis the pow’r I need,\nbaptized with the Holy Ghost.', 'Viele suchen noch das Verheißungsland,\nwo die Nacht vorbei und die Sonne lacht,\nwo der Glaube fasst was kein Sinn erdacht -\ngetauft mit dem Heiligen Geist.\r\nWillst du glauben was Gott verheißt, verheißt?\nEr tauft dich mit Heiligem Geist!\nUm ganz frei zu sein, musst du getauft sein,\ngetauft mit dem Heiligen Geist.\r\nWillst du Ihm nicht jetzt ganz dein Leben weih\'n?\nBleibt im Tod dein Ich, Gottes Kraft zieht ein.\nFleh\' im Glauben jetzt um den Segen Sein -\ngetauft mit dem heiligen Geist.\r\nO Verheißungsland, wo wir jeden Streit\nin der Gotteskraft überwinden weit!\nUnd in Ihm ganz ruh\'n, welche Seligkeit -\ngetauft mit dem heiligen Geist.\r\nJa, wir kommen froh, teurer Herr, zu Dir.\nIn ein volles Heil öffnest Du die Tür.\nWas Du uns verheißt, seh\'n im Glauben wir -\ngetauft mit dem Heiligen Geist.\r\nJa, ich glaube, was Gott verheißt, verheißt:\nEr tauft mich mit Heil\'gem Geist!\nUm ganz frei zu sein, muss getauft ich sein,\ngetauft mit dem Heil\'gen Geist.'),
(9, '1819', 'Voll Staunen schau ich auf das Kreuz, dort starb der Fürst der Herrlichkeit  -  When I survey the wond\'rous Cross, on which the Prince of Glory died   [Melodie HAMBURG]', 'When I survey the wond\'rous Cross\non which the Prince of Glory died,\nmy richest gain I count but loss,\nand pour contempt on all my pride.\r\nForbid it, Lord, that I should boast,\nsave in the death of Christ my God.\nAll the vain things that charm me most,\nI sacrifice them to His blood.\r\nSee from His head, His hands, His feet,\nsorrow and love flow mingled down!\nDid e\'er such love and sorrow meet?\nOr thorns compose so rich a crown?\r\nHis dying crimson, like a robe,\nspreads o\'er His body on the tree.\nThen I am dead to all the globe,\nand all the globe is dead to me.\r\nWere the whole realm of nature mine,\nthat were a present far too small.\nLove so amazing, so divine,\ndemands my soul, my life, my all.', 'Voll Staunen schau ich auf das Kreuz,\ndort starb der Fürst der Herrlichkeit,\nund nichts mehr wert scheint mir die Welt\nvor Gottes Lamm und Seinem Leid.\r\nHier schau ich nur noch Jesus an,\nweil sonst nichts mehr bestehen kann,\nHier starb Er selbst, mein Herr und Gott,\nund ich bin Sein durch´s Blut allein.\r\nSchau, wie Sein Haupt, Sein ganzer Leib\nvoll Schmerzen war, voll Not und Leid,\nund Dornen waren Seine Kron\',\ndafür darf ich heut\' sein Sein Sohn.\r\nFür Ihn die Not, für mich das Glück,\nwas geb\' ich Ihm dafür zurück?\nJa, jede Gabe wär\' zu klein,\nich kann es doch nur selber sein.\r\nHier bin ich, Herr, nimm mich doch an,\nauch wenn ich Dir nichts bringen kann,\nweil doch in mir nichts Gutes ist,\nmach Gutes d´raus, Herr Jesus Christ.'),
(9, '1820', 'Voller Freude muss ich singen seit ich Ihm mein Leben gab   (2 Chorusse)', NULL, 'Voller Freude muss ich singen,\nseit ich Ihm mein Leben gab,\nmeinem Heiland Lobpreis bringen,\nseit ich Ihm mein sünd\'ges Leben gab.\r\nGlorie, Glorie, Halleluja,\nseit ich Ihm mein Leben gab.\nGlorie, Glorie, Halleluja, ja,\nseit ich Ihm mein sünd\'ges Leben gab.'),
(9, '1821', 'Voller Macht, voller Kraft, unserer Not zu begegnen   (Wir dienen einem großen Gott)', NULL, 'Wir dienen einem großen Gott,\nmächtig und übernatürlich,\nund allezeit zu helfen bereit,\nwir dienen einem großen Gott!\r\nVoller Macht, voller Kraft,\nunserer Not zu begegnen,\nvoller Macht, voller Kraft,\num Sein Volk heute zu segnen.\r\nWelche Kraft in Ihm liegt,\nhat er uns heut\' sehen lassen,\nGottes Hand hat den Engel gesandt,\ntat durch ihn gewaltige Taten!\r\nWenn Er spricht, wirft das Licht\nFinsternis aus uns\'rem Leben,\nGeister flieh\'n, Nöte geh\'n,\nwir könn\'n uns siegreich erheben!'),
(9, '1822', 'Vom Aufgang der Sonne bis zu ihrem Niedergang  -  From the rising of the Sun to the going down of the Same   (Psalm 113, 1-3', 'From the rising of the sun\nto the going down of the same\nthe Lord\'s Name is to be praised. (2x)\r\nPraise ye the Lord,\npraise Him all ye servants of the Lord!\nPraise the Name of the Lord!\nBlessed be the Name of the Lord,\nfrom this time forth and forevermore.', 'Vom Aufgang der Sonne\nbis zu ihrem Niedergang\nsei gelobt der Name des Herrn. (2x)\r\nPreiset den Herrn,\npreist Ihn, alle Knechte des Herrn!\nPreiset den Namen des Herrn!\nLobet laut den Namen des Herrn,\nvon nun an fort bis in Ewigkeit.'),
(9, '1823', 'Vom himmlischen Thron stieg herab Gottes Sohn   (Er ist mein Heiland allein)', NULL, 'Vom himmlischen Thron stieg herab Gottes Sohn,\nvon Sünde mich ganz zu befrei\'n.\nEs zerbrach Ihm sein Herz,\nals Er trug meinen Schmerz.\r\nEr ist mein Heiland allein.\nMein Jesus, ja, Er nur allein\nkann Retter und Heiland mir sein.\nDenn er nahm meine Not,\nlitt am Kreuze den Tod,\num mein Heiland und Retter zu sein.\r\nDie dunkele Nacht hat Er oft zugebracht,\num betend mein Priester zu sein.\nDenn Er nahm meine Not,\nlitt am Kreuze den Tod.\r\nMit Dornen gekrönt,\nvon den Menschen verhöhnt,\nverurteilt zu leiden die Pein.\nDoch Er litt dort für mich,\nals am Kreuz Er verblich.'),
(9, '1824', 'Vom Palast in der Höh, ich das Leuchten schon seh, wenn am Ende des Weges ich steh   (Wenn der Tag einst vergangen, die Reise vorbei)', NULL, 'Vom Palast in der Höh\'\nich das Leuchten schon seh\',\nwenn am Ende des Weges ich steh\'.\nJede Bürde wird leicht,\njede Sorge entweicht,\nwenn am Ende des Weges ich steh\'.\r\nWenn der Tag einst vergangen,\ndie Reise vorbei,\ndann verlass\' ich die Welt und ihr Weh.\nUnd der Herr, den ich liebe,\nbegegnet mir frei,\nwenn am Ende des Weges ich steh\'.\r\nUnd mit lächelndem Blick\nschau den Weg ich zurück,\nwenn am Ende des Weges ich steh\'.\nJenes feindliche Heer,\nes erschreckt mich nicht mehr,\nwenn am Ende des Weges ich steh\'.\r\nNur ein Tor offen weit\nund ein Freund mir zur Seit\',\nwenn am Ende des Weges ich steh\'.\nDas allein sei die Kron\',\nfür die Arbeit mein Lohn,\nwenn am Ende des Weges ich steh\'.'),
(9, '1825', 'Von allen Königen die je regierten  -  Of all the Kings that ever reigned', 'Of all the kings that ever reigned\nof all the powers known\nhe was the greatest king of all\nbut never had a throne\na crown of thorns they made him wear\nfor all the world to see\nbut it was love and not the nails\nthat held my saviour to the tree\r\nHe walked among the souls of men\nteaching truth and love\nhis kingdom was not of this world\nbut somewhere of above\nhe gave his life and shed his blood\nso all men could be free\nyes it was love and not the nails\nthat held my saviour to the tree\r\nHe could have climbed down from that cross\nand spared himself the shame\nbut he was the son of god and so he bore the pain\nhe cried forgive them father\nas he hung between two thieves\nyes it was love and not the nails\nthat held my saviour to the tree\nYes it was love and not the nails\nthat held my saviour to the tree', 'Von allen Königen, die je regierten\nvon allen bekannten Mächten,\nwar Er der größte König,\naber er hatte nie einen Thron.\nEine Krone aus Dornen ließen sie ihn tragen,\ndass alle Welt es sieht,\naber es war seine Liebe und nicht die Nägel,\nwelche ihn am Kreuze hielt.\r\nEr wandelte unter den Menschen\nund lehrte die Wahrheit und die Liebe.\nSein Königreich war nicht von dieser Welt,\nes war im Himmel.\nEr gab sein Leben und vergoss sein Blut\ndamit alle Menschen befreit werden.\nJa, es war seine Liebe und nicht die Nägel,\nwelche ihn am Kreuze hielt.\r\nEr hätte vom Kreuz herabsteigen\nund sich die Schande ersparen können,\naber er war Gottes Sohn und so ertrug er die Qual.\nEr schrie: Vater vergib ihnen!\nWährend er zwischen zwei Dieben hing.\nJa, es war Liebe und nicht die Nägel,\nwelche ihn am Kreuze hielt.'),
(9, '1826', 'Von dem Heiland an dem Kreuze will ich singen   (Halleluja, frei bin ich)', NULL, 'Von dem Heiland an dem Kreuze will ich singen,\nvon dem Blut, das alle Sündenflecken nahm.\nIch will jubeln, denn ich hab\' das Heil gefunden\nan dem Kreuz, als Jesus auf die Erde kam.\r\nHalleluja! Frei bin ich!\nHalleluja! Heim zieht\'s mich.\nHalleluja! Bald seh\' ich,\no mein Jesus, Dich.\r\nIch will singen von der Gnade der Bewahrung,\ndie mein Heiland täglich, stündlich reicht mir dar;\nschaut mich freundlich an und schenkt mir Seine Stärke.\nAuf dem schmalen Weg führt Er mich wunderbar.\r\nIch will singen von dem Brand, den Er entfachte,\nals Sein Heilandsherze brach auf Golgatha.\nWenn nun auf dem Heimweg mir Versuchung drohet,\nist der Sieger über Welt und Sünd\' mir nah\'.\r\nIch will singen von dem Heim, das mich erwartet,\nnach dem Tränental winkt Zions Höh\' als Lohn.\nMeinen lieben, treuen Heiland will ich preisen,\nbis einst Engelhand mir reicht die Lebenskron\'.'),
(9, '1827', 'Von dem Kreuz aus Jesu Wunden   (Jesu Liebe seh ich winken)', NULL, 'Von dem Kreuz aus Jesu Wunden\nquillt ein Brünnlein völlig frei,\ndas die Kranken lässt gesunden;\neilet, Sünder, kommt herbei!\r\nJesu Liebe seh ich winken,\nHalleluja, Gloria!\nDarf aus Gottes Brünnlein trinken,\nLebenswasser quillt mir da!\r\nGottes Brünnlein fließt für Sünder,\nderen Schuld den Tod verdient.\nHörts, belad\'ne Menschenkinder:\nEr hat euch mit sich versöhnt!\r\nZu dem Brünnlein kam ich Armer,\nmüd von meiner Sündenlast;\nund da fand ich beim Erbarmer\nneues Leben, Frieden, Rast.\r\nO, wie wohl ist\'s meinem Herzen\nbei des Heilands Gnadenquell\';\nda schmeck ich in Freud und Schmerzen\nSeine Liebe klar und hell!\r\nKomm zu Gottes Brünnlein, Sünder!\nTrink, und du sollst selig sein!\nKomm, der Herr und Seine Kinder\nladen dich so freundlich ein!'),
(9, '1828', 'Von der Liebe lasst uns singen  -  Sing the wondrous Love of Jesus   (Wenn wir ziehn in den Himmel)   [Westertimke]', 'Sing the wondrous love of Jesus,\nsing His mercy and His grace.\nIn the mansions, bright and blessed,\nHe\'ll prepare for us a place.\r\nWhen we all get to heaven,\nwhat a day of rejoicing that will be!\nWhen we all see Jesus,\nwe\'ll sing and shout the victory.\r\nWhile we walk the pilgrim pathway,\nclouds will overspread the sky.\nBut when trav\'ling days are over,\nnot a shadow, not a sigh.\r\nLet us then be true and faithful,\ntrusting, serving, ev\'ry day.\nJust one glimpse of Him in glory\nwill the toils of life repay.\r\nOnward to the prize before us!\nSoon His beauty we\'ll behold.\nSoon the pearly gates will open,\nwe shall tread the streets of gold.', 'Von der Liebe lasst uns singen,\npreisen Ihn und Seine Gnad\',\ndenn Er hat für uns bereitet\neine sel\'ge Gottesstadt.\r\nWenn wir alle im Himmel,\nwelche Freude und Wonne wird es sein!\nWenn wir seh\'n den Heiland,\ndann singen wir mit Ihm vereint.\r\nWir sind Pilger hier auf Erden,\nwandeln oft durch dunkle Nacht,\naber wenn der Lauf vollendet,\nunser Herze fröhlich lacht.\r\nLasst uns denn im Glauben wandeln,\ntrauen Ihm von Tag zu Tag.\nNur ein Blick zu Ihm nach oben\nlohnt der Arbeit Müh\' und Plag\'.\r\nVorwärts, aufwärts nun zum Ziele,\ndenn der Lohn ist uns gewiss.\nWenn wir dort mit jenen Lieben\newig sind im Paradies.'),
(9, '1829', 'Von der Schuld ward ich rein  -  I am saved from my Sin, and to Joy enter in   (Ja, ich glaub, ja, ich glaub)', 'I am saved from my sin, and to joy enter in,\nwith the heart I believe on the Saviour.\nI have wonderful peace, from my burdens release,\nI believe on the Son of God.\r\nI believe, I believe,\nwith the heart I believe on the Saviour.\nI believe, I believe,\nI believe on the Son of God.\r\n\'Tis by faith I can say Jesus saves me today,\nwith the heart I believe on the Saviour.\nWaves of love o’er me roll, all is well with my soul,\nI believe on the Son of God.\r\nThere is comfort and rest on His sheltering breast,\nwith the heart I believe on the Saviour.\nI will praise Him in song, tell His love all day long.\nI believe on the Son of God.', 'Von der Schuld ward ich rein, ging zur Freude nun ein,\newig preise ich Ihn, den Erlöser.\nIch hab Frieden und Ruh, denn das Blut deckte zu,\nwas so schwer auf mir lastend lag.\r\nJa, ich glaub, ja, ich glaub,\nja, von Herzen glaub ich an den Heiland.\nJa, ich glaub, ja, ich glaub,\nan den ewigen Gottesohn!\r\nFroh im Glauben sprech\' ich: "Jesus rettete mich."\nEwig preise ich Ihn, den Erlöser.\nNur Sein strahlendes Bild meine Seele erfüllt,\nund ich juble, dass Er mich fand.\r\nDa ist Trost und ist Lust an des Heilandes Brust.\nEwig preise ich Ihn, den Erlöser.\nIch bezeuge es laut, selig, wer Ihm vertraut,\nder am Kreuz uns das Leben gab.'),
(9, '1830', 'Von Gnade und Recht will ich singen   (Lob, Ehre, Preis, Ruhm und Anbetung sei Dir)', NULL, 'Von Gnade und Recht will ich singen,\nund danken dem Herrn, der so gut.\nIhm Ehre und Anbetung bringen,\nfür alles was Er an mir tut.\r\nLob, Ehre, Preis, Ruhm und Anbetung sei Dir,\naus dankbarem Herzen Herr Jesus, von mir,\nfür all Deine Liebe und all Deine Treu\',\ndie Du stets beweisest auf\'s Neu.\r\nIch preis Ihn, denn Er ließ sich finden,\nda Er ja mein Elend geseh\'n.\nUnd dass Er trotz all meinen Sünden\nmir Gnade für Recht ließ ergeh\'n.\r\nIch lobe den Herrn für die Bibel,\ndie Schrift aus den himmlischen Höh\'n.\nSie lehrt mich zu meiden das Übel\nund göttliche Wege zu geh\'n.\r\nWenn manchmal die Stürme auch toben\nund sich der Versucher mir naht.\nDann blick ich im Glauben nach oben,\nund Gott gibt mir Hilfe und Rat.'),
(9, '1831', 'Von lichtumflossnen Bergeshöhn  -  Encamped along the Hills of Light   (Glaube gibt Siegeskraft)', 'Encamped along the hills of light, ye Christian soldiers, rise,\nand press the battle ere the night shall veil the glowing skies.\nAgainst the foe in vales below let all our strength be hurled.\nFaith is the victory, we know, that overcomes the world.\r\nFaith is the victory!\nFaith is the victory!\nOh, glorious victory,\nthat overcomes the world.\r\nHis banner over us is love, our sword the Word of God.\nWe tread the road the saints above with shouts of triumph trod.\nBy faith, they like a whirlwind’s breath, swept on o’er every field.\nThe faith by which they conquered death is still our shining shield.\r\nOn every hand the foe we find drawn up in dread array.\nLet tents of ease be left behind, and onward to the fray.\nSalvation’s helmet on each head, with truth all girt about.\nThe earth shall tremble ’neath our tread, and echo with our shout.\r\nTo him that overcomes the foe, white raiment shall be giv’n.\nBefore the angels he shall know his name confessed in heav’n.\nThen onward from the hills of light, our hearts with love aflame.,\nWe’ll vanquish all the hosts of night, In Jesus’ conqu’ring name.', 'Von lichtumflossn\'en Bergeshöh\'n, ihr Streiter, zieht zu Tal!\nEs gilt, lasst hoch das Banner weh\'n: "Mit Gott", noch dieses Mal!\nDort unten lagert\'s schattenhaft; hinab zum Feinde dringt.\nDer Glaube ist die Siegeskraft, der alle Welt bezwingt.\r\nGlaube gibt Siegeskraft,\nGlaube gibt Siegeskraft.\nOh glorreiche Siegeskraft,\ndie alle Welt bezwingt!\r\nDer Fürst Immanuel zieht mit, sein Wort ist unsr\'e Wehr.\nDen Weg den jetzt dein Fuß betritt, zog einst der Heil\'gen Heer.\nDas Wort vom Kreuz wie Sonnenglut durchflog die dunkle Welt.\nO Glaubenskraft, o Zeugenblut! Ein jeder sei ein Held!\r\nIn dunk\'ler Masse, Glied an Glied, seht ihr die Feinde dort?\nEin heilig\' Feuer uns durchglüht, jetzt, träge Muße, fort!\nDes Heiles Helm auf jedem Haupt, der Schild des Glaubens sei\ndie Rüstung, die kein Feind uns raubt. "Mit Gott!" das Kampfgeschrei.\r\nDem Überwinder winkt die Kron\', des Siegers weißes Kleid,\ndes treuen Knechtes großer Lohn, die Ruhe nach dem Streit.\nD\'rum auf zum Kampf, es naht die Nacht, die Kreuzesfah\'n umringt!\nDer Glaube ist die Siegeskraft, der alle Welt bezwingt.'),
(9, '1832', 'Vor dem König Jesus wird einst jeder stehn  -  At the Name of Jesus, every knee shall bow', 'At the name of Jesus ev\'ry knee shall bow,\nev\'ry tongue confess Him King of glory now.\n\'Tis the Father\'s pleasure we should call Him Lord,\nWho from the beginning was the mighty Word.\r\nHumbled for a season to receive a name\nfrom the lips of sinners unto whom He came.\nFaithfully He bore it spotless to the last,\nbrought it back victorious, when from death He passed.\r\nIn your hearts enthrone Him; there let Him subdue\nall that is not holy, all that is not true.\nCrown Him as your Captain in temptation\'s hour,\nlet His will enfold you in its light and power.', 'Vor dem König Jesus wird einst jeder steh\'n.\nAlle werden Ihn preisen, Seine Herrlichkeit seh\'n.\nWenn die Zeit vergangen und der Herr erscheint,\ndann sind alle Völker preisend Ihn vereint.\r\nEr kam meinst auf Erden, arm und ohne Ehr\'.\nWir sollten all\' frei werden, darum starb Er, der Herr.\nTrug den Spott der Sünder, litt als Gottes Lamm,\ndoch am dritten Tage Er dem Tod entrann.\r\nGib in deinem Herzen Ihm den Herrschaftsthron,\ndenn du bist verloren ohne Gottes Sohn.\nLass Ihn ganz dein Herr sein, Er gibt dir den Lohn,\nwenn am letzten Tag du kniest vor Seinem Thron.'),
(9, '1833', 'Vor meines Herzens König leg eine Gab ich hin', NULL, 'Vor meines Herzens König leg eine Gab\' ich hin,\nund ist\'s auch arm und wenig, ich weiß, es freut doch Ihn.\nEs ist mein eig\'ner Wille, den geb\' ich in den Tod,\nauf dass mich ganz erfülle, Dein Wille, Herr, mein Gott.\r\nIch brauche nicht zu zagen in banger Ahnung Schmerz,\nnein, freudig will ich\'s wagen, zu fallen an Sein Herz.\nDer für mich gab Sein Leben, mich wusch in Seinem Blut,\nwird Er nicht alles geben, was heilsam ist und gut?\r\nIch weiß, dass Sein Erbarmen ganz unaussprechlich ist,\ndass Er den ärmsten Armen in Liebe fest umschließt.\nIch weiß, Sein Liebeswille ist meine Heil\'gung nur;\nd\'rum will ich halten stille und folgen Seiner Spur.\r\nWill auch nicht ängstlich flehen: Herr, gib mir dies und das!\nO nein, was Er ersehen, das ich mir auch erlas\'.\nIst auch der Weg verborgen, der heim mich führen soll,\nbin dennoch ohne Sorgen, den Führer kenn\' ich wohl.\r\nJawohl, Er blickt hernieder auf mich, Sein schwaches Kind.\nZu Ihm schau\' ich auch wieder und Kraft und Frieden find\'.\nIch lege meine Hände in Seine starke Hand\nund weiß, Er führt am Ende mich heim ins Vaterland.'),
(9, '1834', 'Vor zweitausend Jahren kam Gott im Fleisch, Jesus Sein Nam   (Christus ist gekommen, zu suchen und zu retten, was verloren ist)', NULL, 'Christus ist gekommen, zu suchen\nund zu retten, was verloren ist.\nChristus ist gekommen, zu suchen\nund zu retten, was verloren ist.\r\nVor zweitausend Jahren kam\nGott im Fleisch, Jesus Sein Nam\',\nJesus heißt: Gott rettet gern\nSeine Kinder die noch fern\'.\r\nUnd auch noch in dieser Zeit\nkam der Herr und suchte weit und breit\nSeine Kinder, ruft sie laut\naus den Gemeinden in die Braut.\r\nUnd in Offenbarung Zehn\nkannst du Jesus heute seh\'n\nund Er rief so laut, dass man\'s\nin allen Ländern hören kann:'),
(9, '1835', 'Voran, voran für Jesus nun im Wachen, im Wirken   (Geht hin und wachet, wirkt und fleht)', NULL, 'Voran, voran für Jesus nun\nim Wachen, im Wirken;\nEr zeigt euch selbst was ihr sollt tun.\nJa, wacht und fleht,\nihr habt nicht rechts noch links zu seh\'n,\nwas Er euch sagt, das muss gescheh\'n,\nd\'rum wachet, d\'rum wirket, d\'rum betet!\r\nGeht hin und wachet, wirkt und fleht,\nder Meister sucht Schnitter\ndas Feld schon weiß zur Ernte steht,\nauf auf, eh es zu spät.\r\nVoran, voran in alle Welt,\nentsagen und wagen\nmuss, wer des Königs Banner hält,\nvon Lieb erfüllt!\nO singt das Lied der Liebe laut,\nschafft, dass sie jeder an euch schaut,\nja wachet und wirket und betet!\r\nVoran, voran in Gottes Kraft,\nim Wirken, im Wachen;\nGott ist\'s, der alles in euch schafft,\nwas Er euch sagt.\nZieht voll gerüstet in den Krieg,\nder König gibt euch Heil und Sieg\nim Wachen und Wirken und Beten.'),
(9, '1836', 'Voran, voran mit Jesus, du bluterkaufte Schar  -  Stand up, stand up for Jesus ye Soldiers of the Cross', 'Stand up, stand up for Jesus ye soldiers of the cross.\nLift high his royal banner, it must not suffer loss.\nFrom vict\'ry unto vict\'ry his army he shall lead,\n\'til ev\'ry foe is vanquished, and Christ is Lord indeed.\r\nStand up, stand up for Jesus, the trumpet call obey.\nForth to the mighty conflict in this His glorious day.\nYe that are men now serve Him against unnumbered foes.\nLet courage rise with danger, and strength to strength oppose.\r\nStand up, stand up for Jesus, stand in His strength alone.\nThe arm of flesh will fail you, ye dare not trust your own.\nPut on the gospel armor, each piece put on with pray\'r.\nWhere duty calls, or danger, be never wanting there.', 'Voran, voran mit Jesus, du bluterkaufte Schar!\nErhebt Sein Siegesbanner im Kampf und in Gefahr.\nFolg\' Ihm, der Seine Streiter von Sieg zu Siege führt,\nbis jeder Feind bezwungen und Er allein regiert!\r\nVoran, voran mit Jesus, folgt der Posaune Ton!\nEs führt euch an im Kampfe der mächt\'ge Gottessohn.\nSeid Helden, dient Ihm treulich, sind auch der Feinde viel;\nes wächst euch Mut und Stärke im heißen Kampfgewühl.\r\nVoran, voran mit Jesus, in Seiner Kraft allein!\nDer schwache Arm des Fleisches kann niemals Sieger sein.\nLegt an die Geistesrüstung mit innigem Gebet!\nSeid stets auf eurem Posten, wenn es zum Kampfe geht!'),
(9, '1837', 'Vorwärts, Christi Streiter! Auf zum heil\'gen Krieg  -  Onward, Christian Solders! Marching as to War   (Vorwärts, Christi Streiter! Auf zum heilen Krieg)', 'Onward, Christian soldiers! Marching as to war,\nWith the cross of Jesus going on before,\nChrist, the royal Master, leads against the foe,\nForward into battle, see His banners go!\r\nOnward, Christian soldiers!\nMarching as to war,\nWith the cross of Jesus\nGoing on before.\r\nLike a mighty army Moves the Church of God;\nBrothers, we are treading where the saints have trod.\nWe are not divided, all one body we.\nOne in hope and doctrine, one in charity.\r\nCrowns and thrones may perish, kingdoms rise and wane,\nbut the Church of Jesus constant will remain.\nGates of hell can never \'Gainst that Church prevail.\nWe have Christ\'s own promise, which can never fail.\r\nOnward, then ye people! Join our happy throng.\nBlend with ours your voices in the triumph song.\nGlory, laud, and honor, unto Christ the King.\nThis through countless ages men and angels sing.', 'Vorwärts, Christi Streiter! Auf, zum heil\'gen Krieg!\nMit dem Kreuzeszeichen ziehen wir zum Sieg.\nChristus, unser König, führet selbst uns an.\nFolgt ihm unerschrocken, vorwärts, Mann für Mann!\r\nVorwärts, Christi Streiter!\nAuf zum heil\'gen Krieg!\nMit dem Kreuzeszeichen\nziehen wir zum Sieg.\r\nGottes Kreuzgemeinde, ist ein streitbar Heer.\nGottes Geist die Waffe, Gottes Wort die Wehr.\nWir sind nicht zerteilet, eine Ritterschaft,\nEins in Lieb und Lehre, eins in Glaubenskraft.\r\nKönigreiche stürzen, Zepter fällt und Kron.\nEwig unerschüttert raget Christi Thron.\nWill der Feind uns schrecken, tobt der Hölle Pfort\',\ntrau\'n wir der Verheißung, bau\'n auf unsern Hort.\r\nVorwärts nun, ihr Brüder, tretet in die Reih\'n,\nstimmt mit kräftgem Klange in das Loblied ein.\nLob und Preis und Ehre unsern König singt,\nund durch alle Zeiten ihm Anbetung bringt.'),
(9, '1838', 'Wach auf mein Herz mit freud\'gem Klang  -  Awake my Soul, in joyful Lays', 'Awake my Soul, in joyful Lays\nand sing your great Redeemers praise.\nHe justly claims a song from me,\nHis loving kindness is so free.\nJesus love, Jesus love,\nHis loving kindness is so free.\r\nHe saw me ruined in the fall,\nyet loved me not with standing all,\nand safed me from my lost estate,\nHis loving kindness is so great.\nJesus love, Jesus love,\nHis loving kindness is so great.\r\nThrough mighty hosts of cruel foes,\nwhere earth and hell my way oppose,\nHe safely leads my soul along,\nHis loving kindness is so strong.\nJesus love, Jesus love,\nHis loving kindness is so strong.\r\nSo, when I pass death\'s gloomy vale,\nand life and mortal pow\'rs shall fail,\no may my last expiring breath\nHis loving kindness sing in death.\nJesus love, Jesus love,\nHis loving kindness sing in death.', 'Wach auf mein Herz mit freud\'gem Klang\nund sing des Heilands Lobgesang.\nStimm\' an die frohe Melodie,\ndenn Jesu Liebe ist so frei.\nJesu Liebe, Jesu Liebe,\nja, Jesu Liebe ist so frei.\r\nEr sah in Sündenfesseln mich,\nSein großes Herz erbarmte sich.\nEr machte mich von Banden los,\ndenn Jesu Liebe ist so groß.\nJesu Liebe, Jesu Liebe,\nja Jesu Liebe ist so groß.\r\nUnd kommt der Feinde ganzer Hauf\'\nund lehnt sich auch die Hölle auf,\nmein Herz auf Jesus sich verlässt,\ndenn Jesu Liebe ist so fest.\nJesu Liebe, Jesu Liebe,\nja Jesu Liebe ist so fest.\r\nKommt Sorge auch gezogen her,\nwie Sturmeswolke schwarz und schwer,\nmein Herz in Seiner Treue ruht,\ndenn Jesu Liebe ist so gut.\nJesu Liebe, Jesu Liebe,\nja Jesu Liebe ist so gut.'),
(9, '1839', 'Wachet auf, ruft uns die Stimme der Wächter sehr hoch auf der Zinne', NULL, '"Wachet auf!" ruft uns die Stimme\nder Wächter sehr hoch auf der Zinne:\n"Wach auf, du Stadt Jerusalem!"\nMitternacht heißt diese Stunde!\nSie rufen uns mit hellem Munde:\n"Wo seid ihr klugen Jungfrauen?\nWohlauf, der Bräut\'gam kommt,\nsteht auf, die Lampen nehmt!\nHalleluja! Macht euch bereit zu der Hochzeit:\nIhr müsset Ihm entgegen geh\'n!"\r\nZion hört die Wächter singen,\ndas Herz tut ihr vor Freuden springen,\nsie wachet und steht eilend auf.\nIhr Freund kommt vom Himmel prächtig,\nvon Gnaden stark, von Wahrheit mächtig;\nihr Licht wird hell, ihr Stern geht auf.\nNun komm, du werte Kron\',\nHerr Jesu, Gottes Sohn! Hosianna!\nWir folgen all zum Freudensaal\nund halten mit das Abendmahl.\r\nGloria sei Dir gesungen\nmit Menschen- und mit Engelzungen,\nmit Harfen und mit Zimbeln schön!\nVon zwölf Perlen sind die Tore\nan Deiner Stadt, wir steh\'n im Chore\nder Engel hoch um Deinen Thron.\nKein Aug hat je gespürt,\nkein Ohr hat je gehört solche Freude;\nd\'rum jauchzen wir und singen Dir\ndas Halleluja für und für.'),
(9, '1840', 'Waiting on the Lord, for the Promise given   (The power, the Power, gives Victory over Sin)', 'Waiting on the Lord, for the promise given.\nWaiting on the Lord, to send from heaven.\nWaiting on the Lord, by our faith receiving.\nWaiting in the upper room.\r\nThe power! the power!\nGives vict\'ry over sin, and purity within.\nThe power! the power!\nThe pow\'r they had at Pentecost.\r\nWaiting on the Lord, giving all to Jesus.\nWaiting on the Lord, till from sin He frees us.\nWaiting on the Lord, for the heav\'nly breezes.\nWaiting in the upper room.\r\nWaiting on the Lord, longing to mount higher.\nWaiting on the Lord, having great desire.\nWaiting on the Lord, for the heav\'nly fire.\nWaiting in the upper room.', NULL),
(9, '1841', 'Wandel, wandel, wandel im Licht   (2 Chorusse)', NULL, 'Wandel, wandel, wandel im Licht,\nwandel im Licht, ja wandel im Licht!\nWandel, wandel, wandel im Licht,\nwandel im Licht von Gott!\r\nWir Wandeln in dem Licht,\nwandeln in dem Licht,\nwandeln in dem Licht,\nwandeln in dem Licht von Gott.'),
(9, '1842', 'Wann dämmert der Morgen, wann endet die Nacht?   (Bald, bald, bald, o Braut, dein Auge den kommenden König erschaut)', NULL, 'Wann dämmert der Morgen, wann endet die Nacht?\nIch stehe auf dunkler und einsamer Wacht.\nEs bebt meine Seele, die Luft weht so kalt!\nO König, Geliebter, o nahest Du bald?\r\nBald, bald, bald, o Braut,\ndein Auge den kommenden König erschaut.\r\nEs ziehen die Schatten so finster und dicht,\nals wollten sie hüllen der Sterne Licht.\nIhr Sterne des Himmels, habt Dank für den Schein,\ndoch herrlicher strahlt der Geliebte mein!\r\nRings schlafen die Leute, sie wollen nicht schau\'n\ndie drohenden Wolken, das nächtliche Grau\'n.\nDein Kind ist ein Fremdling, verächtlich, ein Tor.\nO Goldener Morgen, wann brichst du hervor?\r\nLass drohen die Schatten, die Schrecken der Nacht,\nes dämmert, es nahet die himmlische Pracht,\ndie Herrlichkeit Gottes, der strahlende Schein;\ner selber, der kommende König ist mein!'),
(9, '1843', 'Wann schlägt die Stunde, ach, wann darf ich gehn?', NULL, 'Wann schlägt die Stunde, ach, wann darf ich geh\'n?\nHeim, ach nur heim! Heim, ach nur heim!\nMöcht\' meinen Heiland im Himmel bald seh\'n!\nHeim, ach nur heim! Heim, ach nur heim!\nHier auf der Erde ist Trübsal und Schmerz.\nDroben wär\' selig auf ewig mein Herz.\nDarum verlangt mich so sehr himmelwärts.\nHeim, ach nur heim! Heim, ach nur heim!\r\nDoch, lieber Heiland, wie Dir es gefällt;\nbin auch gern hier, bin auch gern hier.\nKämpfe und streit\' gegen Sünde und Welt;\nbin auch gern hier, bin auch gern hier.\nLiebe die Brüder und Schwestern im Herrn,\nsehe Dein Kommen auf Erden so gern.\nSchaue im Glauben die Heimat nicht fern;\nBin auch gern hier, bin auch gern hier.\r\nGlücklich hienieden und glücklicher dort;\nwünsche nichts mehr, wünsche nichts mehr.\nWenn ich nur Dich habe, ewiger Hort;\nwünsche nichts mehr, wünsche nichts mehr.\nFröhlich im Leiden und Trübsal ich bin,\nselig, wenn sterbend ich scheide dahin.\nChristus mein Leben und Sterben Gewinn;\nwünsche nichts mehr, wünsche nichts mehr.'),
(9, '1844', 'Wardst du schon zum Segen für andre  -  Is your Life a Channel of blessing   (Mach mich zum Segen für andere hier)   [Pfingstjubel]', 'Is your life a channel of blessing?\nIs the love of God flowing through you?\nAre you telling the lost of the Saviour?\nAre you ready His service to do?\r\nMake me a channel of blessing today,\nmake me a channel of blessing, I pray.\nMy life possessing, my service blessing,\nmake me a channel of blessing today.\r\nIs your life a channel of blessing?\nAre you burdened for those that are lost?\nHave you urged upon those who are straying\nthe Saviour Who died on the cross?\r\nIs your life a channel of blessing?\nIs it a daily telling for Him?\nHave you spoken the Word of salvation\nto those who are dying in sin?\r\nWe cannot be channels of blessing,\nif our lives are not free from known sin.\nWe will barriers be and a hindrance\nto those we are trying to win.', 'Warst du schon zum Segen für and\'re,\nströmt die Liebe des Herrn durch dein Herz?\nUnd verkündigst du Ihn als den Retter\nvon Sünde und Not allerwärts?\r\nMach mich zum Segen für andere hier,\nmach mich zum Segen, ich fleh\' d\'rum zu Dir.\nNimm hin mein Leben, Dir will ich\'s geben,\nmach es zum Segen für andere hier.\r\nWarst du schon zum Segen für and\'re,\nträgst die Last du der sterbenden Welt?\nHast du ihr wohl das Kreuz des Erlösers\nschon klar vor die Augen gestellt?\r\nWarst du schon zum Segen für and\'re,\nist dein Wandel ein Zeugnis vom Herrn?\nHast du denen hier Liebe bewiesen,\ndie kalt sind, ja feindlich und fern?\r\nDer ist nicht ein Segen für and\'re,\nder nicht frei ist von Sünde und Bann.\nDarum, willst du den Segen nicht hindern,\ngib Jesu dich völlig fortan.'),
(9, '1845', 'Warte nur, warte nur, höhnt auch die Welt   (Warte, warte still, Jesus retten will)', NULL, 'Warte nur, warte nur, höhnt auch die Welt.\nEinmal ist alles zu End\'.\nWeinst du auch Tränen, sie werden gezählt,\nJesus, dein Heiland, sie kennt.\r\nWarte, warte still, Jesus retten will,\nSeelen, die noch irren in Sünde.\nBete jeden Tag, alles Jesus sag.\nWarte nur, warte nur still.\r\nWarte nur, warte nur und murre nicht,\nJesus hält, was Er verspricht.\nWarte nur, warte, der Heiland kommt bald,\nEr dich dann heimholt zu Sich.\r\nWarte geduldig, wenn Wolken auch dräu\'n,\nwenn Stürme toben umher.\nWarte nur, warte, es kommt bald der Tag,\nwo die Erlösung dir nah.\r\nWarte, der Bräut\'gam steht schon vor der Tür,\nholen dich zur Herrlichkeit,\ndann wirst du jubelnd Ihn preisen dafür,\nferne von Kummer und Leid.\r\nWo die Sonne scheint,\nwo man nicht mehr weint,\ndort wird deine Heimat dann sein!.\nWo die Sonne scheint,\nwo man nicht mehr weint,\nwird deine Heimat dann sein!'),
(9, '1846', 'Warum blickst du trübe, armes Herze mein  -  Why that look of Sadness, why that downcast eye', 'Why that look of sadness? Why that downcast eye?\nCan no thought of gladness lift thy soul on high?\r\nIs thy burdened spirit agonized for sin?\nThink of Jesus\' merit, He can make thee clean.\r\nO thou heir of heaven, think of Jesus\' love,\nwhile to thee is given, all his grace to prove.', 'Warum blickst du trübe, armes Herze mein?\nKann denn Jesu Liebe Dich nicht mehr erfreu\'n?\nO du Himmelserbe, sieh auf Jesus Christ!\nUm die Krone werbe, die verheißen ist!\r\nSchmerzen dich die Sünden, tritt die Angst dir nah,\nkannst nicht Ruhe finden: Denk an Golgatha!\nIst dort nicht geflossen Jesu teures Blut?\nGlaube unverdrossen, so wird alles gut!\r\nWill dich gar erschrecken des Versuchers Macht,\no, dich kann wohl decken Gottes heil\'ge Wacht!\nD\'rum blick nicht mehr trübe! Freu\' dich, Herze mein!\nDenk an Jesu Liebe! Selig sollst du sein!'),
(9, '1847', 'Warum sollt ich entmutigt mich fühlen und allein  -  His Eye is on thee why should I feel discouraged   (Ich singe, ich bin glücklich)', 'His eye is on thee why should I feel discouraged,\nwhy should the shadows come.\nWhy should my heart be lonely, and long for heaven and home.\nWhen Jesus is my portion? My constant friend is He:\nHis eye is on the sparrow, and I know He watches me.\r\nI sing because I’m happy,\nI sing because I’m free,\nFor His eye is on the sparrow,\nand I know He watches me.\r\nWhenever I am tempted, whenever clouds arise,\nwhen songs give place to sighing, when hope within me dies.\nI draw the closer to Him, from care He sets me free:\nHis eye is on the sparrow, and I know He watches me.\r\n"Let not your heart be troubled!” His tender word I hear,\nand resting on His goodness, I lose my doubts and fears.\nThough by the path He leadeth, but one step I may see:\nHis eye is on the sparrow, and I know He watches me.', 'Warum sollt ich entmutigt mich fühlen und allein,\nwarum mich seufzend sehnen daheim beim Herrn zu sein,\nwenn ich doch weiß, dass Jesus nie von den Seinen wich?\nDer Acht hat auf den Sperling, achtet der nicht auch auf mich?\nDer Acht hat auf den Sperling, achtet der nicht auch auf mich?\r\nIch singe, ich bin glücklich.\nIch sing und freu\' mich sehr,\ndenn er achtet auf den Sperling,\nund Er liebt mich noch viel mehr!\r\nWenn mir Versuchung nahet, am Himmel Wolken steh\'n,\nwenn alle Freudenklänge in Seufzen übergeh\'n,\nzieht Er mich näher zu Sich und meine Hand Er fasst.\nDer Acht hat auf den Sperling, trägt Er nicht auch meine Las?\nDer Acht hat auf den Sperling, achtet der nicht auch auf mich?\r\n"Lass nie dein Herz erschrecken und fürchte, Kind dich nicht!"\nso hör ich Seine Stimme, die leise zu mir spricht.\nWenn auch auf meinem Pfade ich Schritt für Schritt nur seh\':\nEr denkt ja an den Sperling, und Er denkt auch an mein Weh.\nEr denkt ja an den Sperling, und Er denkt auch an mein Weh.'),
(9, '1848', 'Was Gott dir selbst gegeben hat', NULL, 'Was Gott dir selbst gegeben hat,\ndas kann dir keiner nehmen,\nda ist ein ganz bestimmter Platz,\nden füllt sonst niemand aus,\nGott hat Gedanken über dich\nund darin kannst du ruhn,\nda ist ein ganz bestimmtes Werk,\ndas kannst allein du tun!\r\nGott hat gute Gedanken über dich,\nja, und Gottes Gedanken, die sind ewig,\nGott hat Pläne, und dafür braucht Er dich,\nwenn du Ihm dein Leben gibst,\nwirst du sehn, wie es geschieht...\r\nAuch der Feind hat für dich schon einen Plan,\nwelchen du willst, das musst du selbst entscheiden,\ndoch der Weg Gottes, der ist schon gebahnt,\nschenk Ihm deine Lebenszeit\nfür ein Werk der Ewigkeit...\r\nUnd wenn du auf dem Wege Gottes bist,\nkann kein anderer sonst den Platz einnehmen,\nwas auch immer geschieht, wart nur auf Gott,\nSeine Gaben gibt der Herr\nselber dir vom Himmel her...'),
(9, '1849', 'Was Gott dir verheißet das trifft dann auch ein   (O zweifle doch niemals, vertrau stets aufs neu)', NULL, 'Was Gott dir verheißet,\ndas trifft dann auch ein,\nes ist ja kein nichtiger Schimmer.\nWohl mag es so scheinen,\nals könnt es nicht sein;\nGott hält Sein Versprechen für immer.\r\nO zweifle doch niemals,\nvertrau stets auf\'s neu,\nsonst machst du die Sache nur schlimmer:\nGehorche nur treu\nund glaub ohne Scheu!\nGott hält Sein Versprechen für immer.\r\nDie Welt traut dem Eitlen,\nsie liebt ihren Tand und hängt an\ndem Schein und am Flimmer.\nDer Herr führt dich ein\nins verheißene Land;\nEr hält sein Versprechen für immer.\r\nO selig bist du,\nwenn du traust deinem Herrn!\nEr ist ja so treu und täuscht nimmer.\nEr hört deine Bittten\nund hilft dir gar gern;\nEr hält Sein Versprechen für immer.\r\nEinst bist du am Ziel,\nwenn geendet dein Lauf,\ndann führt dich der König ins Zimmer\nund tut Seine himmlischen\nSchätze dir auf:\nEr hält Sein Versprechen für immer.'),
(9, '1850', 'Was Gott verheißen das bleibt bestehen   (Was Gott verheißen, das wird Er geben)', NULL, 'Was Gott verheißen, das bleibt bestehen,\nund wenn auch Himmel und Erd\' vergehen.\nWenn uns\'re Stützen zerbrechen alle,\nwas Gott verheißen, hält Er.\r\nWas Gott verheißen, das wird Er geben,\nmag alles beben, es bleibt besteh\'n.\nWenn auch erlöschen die Sterne alle,\nwas Gott verheißen, bleibt besteh\'n!\r\nWas Gott verheißt, hält in schweren Zeiten,\nwenn Mut und Hoffnung uns will entschwinden.\nUnd müd\' wir sinken in heißen Streiten,\nwas Gott verheißen, wankt nie.\r\nWas Gott verheißen, hält auch im Sterben,\nim heißen Fieber, wenn\'s Leben schwindet.\nDes Heilands Hände dann für mich werben,\nwas Gott verheißen, hält Er.\r\nWas Gott verheißen, hält auch am Tage,\nwo Gott uns rettet aus Not und Plage.\nDie Siegeskrone dort dann empfangen,\ndie überwunden durchs Blut.'),
(9, '1851', 'Was Jesus in die Hände nimmt   (Auf Jesus vertrau ich, auf Jesus allein)', NULL, 'Was Jesus in die Hände nimmt,\nund sei es noch so klein,\ndas muss, ich weiß es ganz bestimmt,\nmir auch zum Segen sein.\r\nAuf Jesus vertrau ich, auf Jesus allein!\nWie Er es macht, ist\'s herrlich,\nwird\'s heilsam mir sein!\nWie Er es macht, ist\'s herrlich,\nwird\'s heilsam mir sein!\r\nAuf Jesus traue ich allein,\nwie Er es macht, wird\'s gut;\nSein Rat und Tat wird heilsam sein\nund gibt mir frohen Mut.\r\nDoch das, was ich, mir selbst genug,\nund sei es noch so groß,\nallein beginne, wird zum Fluch\nund lässt mich arm und bloß.\r\nD\'rum geb\' ich all mein Werk und Tun\nin Jesu Willen hin.\nUnd folge meinem Heiland nun\nmit eines Kindes Sinn.\r\nSo kann ich lauter Wunder seh\'n.\nUnd jeden neuen Tag\nganz fröhlich und in Frieden gehen,\nwie Er auch führen mag.'),
(9, '1852', 'Was könnte mich trennen von der Liebe meines Herrn   (Römer 8, 38-39)', NULL, '[: Was könnte mich trennen von der Liebe meines Herrn? :]\nWeder der Tod noch das Leben, weder Engel,\nMächte noch Gewalten, weder die Gegenwart noch die Zukunft,\nweder Hohes noch Tiefes noch eine andere Kreatur\n[: kann mich scheiden von der Liebe meines Herrn. :]'),
(9, '1853', 'Was macht mich von Sünden rein  -  What can wash away my Sin   (Oh, köstlich ist die Flut / Oh! precious is the Flow)', 'What can wash away my sin?\nNothing but the blood of Jesus.\nWhat can make me whole again?\nNothing but the blood of Jesus.\r\nOh! precious is the flow,\nthat makes me white as snow.\nNo other fount I know,\nnothing but the blood of Jesus.\r\nFor my cleansing this I see,\nnothing but the blood of Jesus.\nFor my pardon this my plea,\nnothing but the blood of Jesus.\r\nNothing can for sin atone,\nnothing but the blood of Jesus.\nNought of good that I have done,\nnothing but the blood of Jesus.\r\nThis is all my hope and peace,\nnothing but the blood of Jesus.\nThis is all my righteousness,\nnothing but the blood of Jesus.\r\nNow by this I\'ll overcome,\nnothing but the blood of Jesus.\nNow by this I\'ll reach my home,\nnothing but the blood of Jesus.\r\nWhat wipes out all earthly pain?\nNothing but the blood of Jesus.\nWhat leads to heaven\'s heights?\nNothing but the blood of Jesus.', 'Was macht mich von Sünden rein?\nNur das Blut des Lammes Jesus.\nWo mag für mich Heilung sein?\nNur im Blut des Lammes Jesus.\r\nOh, köstlich ist die Flut,\nmacht allen Schaden gut.\nHier meine Seele ruht,\nin dem Blut des Lammes Jesus.\r\nWas erlöst mich von der Schuld?\nNur das Blut des Lammes Jesus.\nWas schenkt mir des Vaters Huld?\nNur das Blut des Lammes Jesus.\r\nWas versöhnet mich mit Gott?\nNur das Blut des Lammes Jesus.\nWas errettet aus der Not?\nNur das Blut des Lammes Jesus.\r\nWas macht grad\' was krumm und schlecht?\nNur das Blut des Lammes Jesus.\nWas macht mich vor Gott gerecht?\nNur das Blut des Lammes Jesus.\r\nWas bezwinget Sünd\' und Welt?\nNur das Blut des Lammes Jesus.\nWas macht mich zum Gottesheld?\nNur das Blut des Lammes Jesus.\r\nWas tilgt alles Erdenweh\'?\nNur das Blut des Lammes Jesus.\nWas führt in des Himmels Höh\'?\nNur das Blut des Lammes Jesus.'),
(9, '1854', 'Was mein Herz erfreut, ist das sel\'ge "Heut"', NULL, 'Was mein Herz erfreut,\nist das sel\'ge "Heut".\nO, wer sagt\'s, wie kostbar ist die Gnadenzeit!\r\nGottes Wort ruft: "Heut\'\nnimm, was Jesus beut!"\nAlles, alles, hör es doch, ist dir bereit!\r\nFriede statt dem Streit,\nFreude für das Leid;\nGlaube nur, so schenkt es dir der Herr noch heut\'!'),
(9, '1855', 'Was würd ich tun ohne Jesus, was würd\' ich tun ohne Ihn', NULL, 'Was würd\' ich tun ohne Jesus?\nWas würd\' ich tun ohne Ihn?\nKeiner dann wär\', mich zu führen\ndurch dieses Leben dahin!\nWas sollt\' ich tun, wenn ich müde\nund von den Sorgen bedrängt,\noder wenn schwer ich versuchet?\nEr dann stets meiner gedenkt.\r\nWas würd\' ich tun ohne Jesus\nin Zeit der Krankheit und Schmerz?\nDa wäre keiner zu heilen,\nkein Trost mehr an Jesu Herz.\nWie wär\' das Leben so öde,\nwenn nicht mein Jesus mir nah,\nDer gerne tröstet und hilft mir,\nwie schon so oft es geschah.\r\nWas würd\' ich tun ohne Jesus,\nwenn einst der Tod tritt ins Haus,\nmir nehmend eines der Lieben,\nwer füllt die Lücke dann aus?\nKönnte die Welt mir dann bieten\ndas, was mein Herze begehrt?\nJesus allein kann dann heben\ndas, was mein Herze beschwert.\r\nWas würd\' ich tun ohne Jesus,\nwenn einst das Leben vorbei?\nWer führte dann mich zum Himmel,\nwo alles herrlich und neu?\nWas sollt\' ich tun im Gerichte,\nwenn ohne Jesus ich wär\'?\nWas würde sein dann mein Schicksal?\nHeiland, ich brauche Dich sehr!'),
(9, '1856', 'Waves of Glory over my Soul   (Chorus)', 'Waves of glory,\nwaves of glory,\nwaves of glory over my soul.\nJesus now is here\nthere is no need to fear,\nwaves of glory over my soul.', NULL),
(9, '1857', 'Waymaker - Wegbereiter (You are here, Jesus among us - Du bist hier, Jesus, unter uns)', 'You are here, moving in our midst,\nI worship You, I worship You.\nYou are here, working in this place,\nI worship You, I worship You. (2x)\r\nWaymaker,\nMiracle Worker,\nPromise Keeper,\nLight in the Darkness,\nMy God,\nThat is Who You are.\r\nYou are here, touching every heart,\nI worship You, I worship You,\nYou are here, healing every heart,\nI worship You, I worship You,\nYou are here, turning lives around,\nI worship You, I worship You,\nYou are here, mending every heart,\nI worship You, I worship You.\r\nEven when I don\'t feel it,\nYou\'re working,\nEven when I don\'t see it,\nYou\'re working,\nYou never stop working,\nYou never stop working. (2x)\r\nThat is who you are,\nThat is who you are,\nThat is who you are,\nThat is who you are,', 'Du bist hier, Jesus, unter uns,\nich bet\' Dich an, ich bet\' Dich an,\nDu bist hier, wirkst heut\' unter uns,\nich bet\' Dich an, ich bet\' Dich an. (2x)\r\nDu bist\nMein Helfer,\nMein Wegbereiter,\nWundertäter,\nTreu der Verheißung,\nMein Gott,\nDas ist, wer Du bist.\r\nDu bist hier, rührst die Herzen an,\nich bet\' Dich an, ich bet\' Dich an,\nDu bist hier, schenkst uns Heilung, Herr,\nich bet\' Dich an, ich bet\' Dich an,\nDu bist hier, verbindest Wunden, Herr,\nich bet\' Dich an, ich bet\' Dich an,\nDu bist hier, machst das Leben neu,\nich bet\' Dich an, ich bet\' Dich an!\r\nAuch wenn ich Dich nicht spür\',\nbist Du hier, Herr,\nauch wenn ich Dich nicht seh\',\nbist Du hier, Herr,\nDu hörst nie auf, Du bist nie am Ende,\nDu hörst nie auf, Du hörst nie auf. (2x)\r\nDas ist wer Du bist.\nDas ist wer Du bist.\nDas ist wer Du bist.\nDas ist wer Du bist.'),
(9, '1858', 'Wär gleich blutrot die Sünde, soll sie werden weiß wie Schnee  -  Though your Sins be as Scarlet, they shall be as white as Snow', 'Though your sins be as scarlet,\nthey shall be as white as snow.\nThough your sins be as scarlet,\nthey shall be as white as snow.\nThough they be red like crimson,\nthey shall be as wool!\r\nHear the voice that entreats you,\noh, return ye unto God!\nHear the voice that entreats you,\noh, return ye unto God!\nHe is of great compassion,\nand of wondrous love.\r\nHe’ll forgive your transgressions,\nand remember them no more.\nHe’ll forgive your transgressions,\nand remember them no more.\nLook unto Me, ye people,\nsaith the Lord your God!', 'Wär\' gleich blutrot die Sünde,\nsoll sie werden weiß wie Schnee.\nWär\' gleich blutrot die Sünde,\nsoll sie werden weiß wie Schnee.\nUnd was so rot wie Scharlach,\nsoll wie Wolle sein.\r\nHört die Stimme, die ladet,\nwendet euch nicht ab von Gott!\nHört die Stimme, die ladet,\nwendet euch nicht ab von Gott.\nDenn Er ist voll Erbarmen,\nSeine Treu ist groß.\r\nEr vergibt Übertretung\nund gedenkt der Sünde nicht!\nEr vergibt Übertretung\nund gedenkt der Sünde nicht!\nKommt zu Ihm, ihr Müden,\ndenn bei Ihm ist Ruh\'.'),
(9, '1859', 'Wärst du gern frei von der Last deiner Schuld  -  If you are tired of the Load of your Sin   (Grad jetzt ruft Jesus nach dir)', 'If you are tired of the load of your sin,\nlet Jesus come into your heart.\nIf you desire a new life to begin,\nlet Jesus come into your heart.\r\nJust now, your doubtings give o\'er,\njust now, reject Him no more.\nJust now, throw open the door,\nlet Jesus come into your heart.\r\nIf it\'s for purity now that you sigh,\nlet Jesus come into your heart.\nFountains for cleansing are flowing nearby,\nlet Jesus come into your heart.\r\nIf there\'s a tempest your voice cannot still,\nlet Jesus come into your heart;\nIf there\'s a void this world never can fill,\nlet Jesus come into your heart.\r\nIf you would join the glad songs of the blest,\nlet Jesus come into your heart.\nIf you would enter the mansions of rest,\nlet Jesus come into your heart.', 'Wärst du gern frei von der Last deiner Schuld?\nLass Jesus in\'s Herz dir einzieh\'n!\nWillst du erfahren die göttliche Huld?\nLass Jesus in\'s Herz dir einzieh\'n!\r\nGrad\' jetzt ruft Jesus nach dir!\nGrad\' jetzt dein Heiland ist hier!\nGrad\' jetzt schließ\' auf Ihm die Tür!\nLass Jesus ins Herz dir einzieh\'n!\r\nSehnest du dich, reines Herzens zu sein?\nLass Jesus in\'s Herz dir einzieh\'n!\nHier ist der Born, der von Sünde macht rein!\nLass Jesus in\'s Herz dir einzieh\'n!\r\nStehst du im Sturm, den dein Ruf nimmer stillt?\nLass Jesus in\'s Herz dir einzieh\'n!\nFühlst du die Leere, die nie die Welt füllt?\nLass Jesus in\'s Herz dir einzieh\'n!\r\nStimmst du im Jubel der Heil\'gen mit ein?\nLass Jesus in\'s Herz dir einzieh\'n.\nSoll einst der Himmel dein Ruheort sein?\nLass Jesus in\'s Herz dir einzieh\'n.'),
(9, '1860', 'Wärst du gern für immer von der Sünde frei  -  Would you be redeemed from ev\'ry inbred Sin   (Lass den Heilgen Geist ziehn ein)', 'Would you be redeemed from ev\'ry inbred sin,\nhave the Holy Spirit constantly within?\nMake the consecration, trust in God, and then,\nlet the Holy Ghost come in.\r\nLet the Holy Ghost come in,\nlet the Holy Ghost come in.\nMake the consecration, trust in God, and then,\nlet the Holy Ghost come in.\r\nWould you have the Spirit in your heart to cheer?\nWould you be relieved from ev’ry doubt and fear?\nMake the consecration, trust in God, and then,\nlet the Holy Ghost come in.\r\nDo you want the fire of God to fill your soul,\nburn up all the dross, and sanctify the whole?\nMake the consecration, trust in God, and then,\nlet the Holy Ghost come in.\r\nDo you want the pow’r to make you true and brave,\nso that you can rescue those that Christ would save?\nMake the consecration, trust in God, and then,\nlet the Holy Ghost come in.', 'Wärst du gern für immer von der Sünde frei?\nWillst du, dass der Heil\'ge Geist dein Führer sei?\nWeih dich Gott aufs neue, traue Ihm allein:\nLass den Heil\'gen Geist zieh\'n ein.\r\nLass den Heil\'gen Geist zieh\'n ein.\nLass den Heil\'gen Geist zieh\'n ein.\nWeih dich Gott aufs neue, traue Ihm allein,\nlass den Heil\'gen Geist zieh\'n ein.\r\nSoll der Geist der Freude stets im Herzen sein?\nSoll von Furcht und Zweifel Er dich stets befrei\'n?\nWeih dich Gott aufs neue, traue Ihm allein:\nLass den Heil\'gen Geist zieh\'n ein.\r\nSoll in deiner Seele Himmelsfreude glüh\'n?\nSoll sie ganz verzehr\'n eig\'nes Tun und Müh\'n?\nWeih dich Gott aufs neue, traue Ihm allein:\nLass den Heil\'gen Geist zieh\'n ein.\r\nWillst du Kraft von oben, Geisteskraft vom Herrn?\nSeelen dem zuführen, der sie rettet gern?\nWeih dich Gott aufs neue, traue Ihm allein:\nLass den Heil\'gen Geist zieh\'n ein.'),
(9, '1861', 'We are a Moment, You are forever  -  Wir sind ein Augenblick, Du bist ewig', 'We are a moment, You are forever,\nLord of the Ages, God before time.\nWe are a vapor, You are eternal,\nlove everlasting, reigning on high.\r\nHoly, holy, Lord God Almighty,\nworthy is the Lamb Who was slain.\nHighest praises, honor and glory,\nbe unto Your name, be unto Your name.\r\nWe are the broken, You are the healer,\nJesus, Redeemer, mighty to save.\nYou are the love song we\'ll sing forever,\nbowing before You, blessing Your name.', 'Wir sind ein Augenblick, Du bist ewig,\nHerr der Zeitalter, Gott, bevor die Zeit begann.\nWir sind ein Dunst, Du bist ewig,\ndie ewige Liebe, die in der Höhe regiert.\r\nHeilig, heilig, Herr, Gott, der Allmächtige,\nwürdig ist das Lamm, das geschlachtet wurde.\nHöchster Lobpreis, Ehre und Herrlichkeit,\nsei Deinem Namen, sei Deinem Namen.\r\nWir sind die Zerbrochenen, Du bist der Heiler,\nJesus, Erlöser, mächtig zu retten.\nDu bist das Liebeslied, das wir ewig singen werden,\nwir verneigen uns vor Dir und loben Deinen Namen.'),
(9, '1862', 'We are free to praise You', 'We are free to praise You,\nWe are free to praise You.\nWe are free to praise You, Lord.\r\nFree, free, You have set me free,\nFree, free, You have set me free.\r\nWe are free to love You…\nWe are free to thank You…\nWe are free to serve You…\nI am free…', NULL),
(9, '1863', 'We are never, never weary of the grand old Song   (Oh the Children of the Lord have a Right to Shout and Sing)', 'We are never, never weary of the grand old song:\nGlory to God, halleluja!\nWe can sing it loud as ever, with our faith more strong:\nGlory to God, halleluja!\r\nOh the children of the Lord have a right to shout and sing,\nfor the way is growing bright and our souls are on the wing.\nWe are going by and by to the palace of a King!\nGlory to God, halleluja!\r\nWe are lost amid the rapture of redeeming love:\nGlory to God, halleluja!\nWe are rising on its pinions to the hills above:\nGlory to God, halleluja!\r\nWe are going to a palace that is built of gold:\nGlory to God, halleluja!\nWhere the King in all His splendorwe shall soon behold:\nGlory to God, halleluja!\r\nThere we\'ll shout redeeming mercy in a glad, new song:\nGlory to God, halleluja!\nThere we\'ll sing the praise of Jesuswith the blood-washed throng:\nGlory to God, halleluja!', NULL),
(9, '1864', 'We are the Generation, the final Voice the World will hear  -  Wir sind die Generation,wir sind die Krönung,die letzte Stimme, die die Welt hören wird', 'We are the generation,\nwe\'re the culmination,\nthe final voice the world will hear.\nThe coming of the Lord is near.\nLiving out the revelation,\novercoming sin\'s temptation.\nThe truth will go to every tongue and nation.\nWe are the chosen generation.', 'Wir sind die Generation,\nwir sind die Krönung,\ndie letzte Stimme, die die Welt hören wird.\nDas Kommen des Herrn ist nahe.\nWir leben die Offenbarung aus,\nüberwinden die Versuchung der Sünde.\nDie Wahrheit wird zu jeder Zunge und jeder Nation gehen.\nWir sind die auserwählte Generation.'),
(9, '1865', 'We bring the Sacrifice of Praise   (2 Chorusse)', 'We bring the sacrifice of praise,\ninto the house of the Lord.\nWe bring the sacrifice of praise,\ninto the house of the Lord\r\nAnd we offer up to You\nthe sacrifices of thanksgiving.\nAnd we offer up to You\nthe sacrifices of joy.', NULL),
(9, '1866', 'We give You Praise   (Chorus)', 'We give You praise, we give You praise,\nWe give You praise Lord You\'re worthy.\nWith hands upraised we give You praise,\nWe give You glory and praise.', NULL),
(9, '1867', 'We glorify Your holy Name', 'We glorify your holy name,\nwe bow before your throne!\nWe glorify your holy name,\nwe bow before your throne!\nWe glorify your holy name,\nwe bow before your throne!\nWe glorify your holy name,\nwe bow before your throne!', NULL),
(9, '1868', 'We have come into His House to magnify His Name', 'We have come into His house,\nto magnify His Name\nand worship Him.    (2x)\nWe have come into His house,\nto magnify His Name\nand worship Christ the Lord.\nWorship him, Jesus Christ the Lord.\r\nSo forget about yourself,\nconcentrate on Him\nand worship Him.     (2x)\nSo forget about yourself,\nconcentrate on Him,\nand worship Christ the Lord.\nWorship Him, Jesus Christ the Lord.\r\nLet us lift up holy hands,\nmagnify His Name\nand worship Him.     (2x)\nLet us lift up holy hands,\nmagnify His Name,\nand worship Christ the Lord.\nWorship Him, Jesus Christ the Lord.', NULL),
(9, '1869', 'We have heard the joyful Sound: Jesus saves, Jesus saves', 'We have heard the joyful sound:\nJesus saves! Jesus saves!\nSpread the tidings all around:\nJesus saves! Jesus saves!\nBear the news to every land,\nclimb the steeps and cross the waves.\nOnward! \'tis our Lord\'s command:\nJesus saves! Jesus saves!\r\nWaft it on the rolling tide:\nJesus saves! Jesus saves!\nTell to sinners far and wide:\nJesus saves! Jesus saves!\nSing, ye islands of the sea.\nEcho back, ye ocean caves.\nEarth shall keep her jubilee:\nJesus saves! Jesus saves!\r\nSing above the battle strife:\nJesus saves! Jesus saves!\nBy His death and endless life:\nJesus saves! Jesus saves!\nSing it softly through the gloom,\nwhen the heart for mercy craves.\nSing in triumph o\'er the tomb:\nJesus saves! Jesus saves!\r\nGive the winds a mighty voice:\nJesus saves! Jesus saves!\nLet the nations now rejoice:\nJesus saves! Jesus saves!\nShout salvation full and free.\nHighest hill and deepest caves.\nThis our song of victory:\nJesus saves! Jesus saves!', NULL),
(9, '1870', 'We have overcome by the Blood of the Lamb', 'We have overcome,\nwe have overcome.\nBy the blood of the lamb,\nby the word of the Lord.\nWe have overcome.\r\nJesus Christ is king,\nJesus Christ is king.\nAs He ascends to the throne,\nall creation bows down.\nJesus Christ is king.\r\nHe has overcome,\nHe has overcome.\nThe strong man is bound,\nand the victory is won.\nHe has overcome.', NULL),
(9, '1871', 'We shall be changed   (Chorus)', 'We shall be changed, we shall be changed.\nChanged from the mortal to immortality,\nin the twinkling of an eye.\nWe shall be changed, we shall be changed.', NULL),
(9, '1872', 'We will cross every Border', 'We will cross every border\nthrow wide every door.\nJoining our hands across the nations\nwe will proclaim Jesus is Lord.\r\nWe will break sins oppression\nspeak out for the poor.\nAnnounce the coming of Christ\'s kingdom\nfrom east to west and shore to shore.\r\nWe will gather in the harvest\nand work while it\'s day.\nThough we may sow with tears of sadness\nwe will reap with shouts of joy.\r\nSoon our eyes shall see his glory\nthe Lamb, our risen Lord.\nWhen he receives from every nation\nhis blood-bought Bride, his great reward.', NULL),
(9, '1873', 'We worship and adore You   (Chorus)', 'We worship and adore You,\nbowing down before You.\nSongs of praises singing,\nHallelujah\'s ringing.\nHallelujah, Hallelujah,\nHallelujah, Amen. (2x)', NULL),
(9, '1874', 'We\'ll not leave our little ones behind', 'We\'ll not leave our little ones behind.\nFor our Father had them in mind.\nSome are weak and some are feeble,\nothers may not feel they\'re able.\nWe\'ll not leave a single one behind.', NULL),
(9, '1875', 'We\'re gonna keep pressing on   (Chorus)', 'We\'re gonna keep pressing on,\nWe\'re gonna keep pressing on,\nWe\'re gonna keep pressing on\nto the higher calling of our Lord.', NULL),
(9, '1876', 'We\'ve been made more than Conquerors', 'We\'ve been made more than conquerors,\novercomers in this life.\nWe\'ve been made victorious,\nthrough the blood of Jesus Christ!\r\nWhen troubles come knockin\' at your door,\ndon\'t be afraid, you know it\'s not like before.\nDon\'t you give in, don\'t let it bring you down,\ncause you dont have to worry anymore!\r\nHold on, we\'re getting stronger everyday,\nthere\'s no reason for you to go astray.\nDon\'t go leaning to your understanding,\ncause you dont have to worry anyway!', 'Wir sind zu mehr als nur Überwindern\ngemacht worden, zu Überwinder in diesem Leben. \nwir sind durch das Blut Jesus \nChristus zum Sieger gemacht worden\r\n\r\n'),
(9, '1877', 'We\'ve come to celebrate the King', 'We\'ve come to celebrate\nfor the Lord is great.\nWe\'ve come to celebrate\nthe King.     (2x)\r\nFor He is Mighty\nand He is Marvellous!\nFor He is great\nand He is glorious!\nWe shall forever stand\nbefore His presence and sing:\nWe\'ve come to celebrate the King!', 'Wir sind gekommen um zu feiern\ndenn der Herr ist groß\nWir sind gekommen um den König zu feiern\r\nDenn Er ist mächtig und Er ist wunderbar!\nDenn Er ist groß und Er ist herrlich!\nWir werden für immer in Seiner Gegenwart\nstehen und singen: WIr sind gekommen um den\nKönig zu feiern!'),
(9, '1878', 'Website Konferenz', 'www.conference-holland.nl', 'Stream Audio&Video in allen Sprachen\nStream Audio&Video in all languages\nTelefonübetragung über die bekannte Telefonnummer Linn läuft ebenfalls weiter.'),
(9, '1879', 'Weil aus Liebe Du starbst, mir Erlösung erwarbst   (Sieh, ich liebe nun hier, übergebe mich Dir)', NULL, 'Weil aus Liebe Du starbst,\nmir Erlösung erwarbst,\nkomm ich, Heiland und König zu Dir.\nMich zum Dienst Dir zu weih\'n,\nDein auf ewig zu sein,\nDeinen Segen, o Jesus, gib mir.\r\nSieh, ich liebe nun hier,\nübergebe mich Dir,\nleg mich willig auf Deinen Altar!\nSend\' Dein Feuer, o Herr,\nalle Sünden verzehr,\nbind mich fest, ich bin Dein immerdar.\r\nNimm mich, Herr, wie ich bin,\nLeib und Seele nimm hin,\nund von Flecken mach völlig mich rein!\nHeil\'ge, Heiland, Du mich ganz\nzum Tempel für Dich,\nwo Du wohnst und regierest allein!\r\nNimm mein alles, o Herr,\nwas ich liebe so sehr,\nich will leben für Dich nur allein!\nHerz und Augen nimm hin,\nheil\'ge Lippen und Sinn,\nja, mein Wille, Erlöser, sei Dein!\r\nNicht mehr mein, aber Dein,\nJesu Name allein meine Kraft sei,\nmein Schutz und mein Schild.\nJa, ich glaube voll Freud,\nDu wirst mich nach der Zeit\neinst verklären in Dein Ebenbild.'),
(9, '1880', 'Weil Jesus lebt, sorg ich nicht für morgen (Gott sandte Jesus, den Erlöser  -  God sent His Son and they called Him Jesus)', 'God sent His son and they called Him Jesus,\nHe came to love, heal and forgive.\nHe lived and He died to buy my pardon\nan empty grave is there to prove my Saviour lives.\r\nBecause He lives I can face tomorrow,\nbecause He lives all fear is gone.\nBecause I know He holds the future,\nmy life is worth the living just because He lives!\r\n\r\nThen one day I\'m gonna cross that river.\nI\'m gonna fight life\'s final, life\'s final war with pain.\nAnd then as death someday gives way to victory\nI\'m gonna see those lights of glory and know that my Saviour reigns.\r\n', 'Gott sandte Jesus, den Erlöser,\nEr liebt, Er heilt und Er vergibt.\nEr lebte, um für uns zu sterben,\nein leeres Grab beweist uns, dass heut\' Jesus lebt.\r\nWeil Jesus lebt, sorg\' ich nicht für morgen,\nweil Jesus lebt, ist die Furcht dahin.\nDenn weil ich weiß, Er hält die Zukunft,\ndas Leben ist nur lebenswert, weil Jesus lebt.\r\nDie Schönheit hier, auf dieser Erde,\ndie Freude und das ird\'sche Glück,\nsie können niemals das ersetzen,\nden Reichtum, der allein in Ihm zu finden ist.\r\nBald überqueren wir den Jordan,\nwenn dieses Leben ist vorbei.\nDann sehen wir, was wir hier glaubten, o Halleluja,\nJesus lebt und wir durch Ihn.\r\nWir sind bereits im dritten Auszug,\ndie Feuersäule geht voran.\nDie Reise geht durch\'s Friedensreich\nund in das ew\'ge, schöne Himmelsland hinein.'),
(9, '1881', 'Weinen möcht\' ich, bitter weinen, Jesus Anblick bricht mein Herz', NULL, 'Weinen möcht\' ich, bitter weinen,\nJesus Anblick bricht mein Herz;\nselbst die Sonn mag nicht mehr scheinen,\nFelsen beben gar vor Schmerz.\nDort, auf jenem Marterhügel\nleidet Jesus Angst und Not,\nin dem heißen Trübsalstiegel\nist betrübt Er bis zum Tod.\r\nMöcht\' in Tränen ganz zerfließen,\nach, wie rinnt Sein blut\'ger Schweiß!\nStröme Blutes sich ergießen\naus der Brust, die liebeheiß.\nKlaffend steh\'n die Wunden offen,\ndürstend ringt das Gotteslamm;\nnicht auf Labung darf es hoffen,\nhingeschlacht\' am Kreuzesstamm!\r\nO, welch Anblick voller Schauer!\nJesus, ach erbarm\' Dich mein!\nSieh, mein Herz in tiefer Trauer;\nich bin schuld an Deiner Pein!\nAch, wie hab ich dich betrübet,\nhab verwundet Dir das Herz,\nund wie hast Du mich geliebet!\nDeine Lieb bricht mir das Herz!\r\nNimmer will ich\'s mehr vergessen,\nalles hast Du dort vollbracht!\nAls ich so am Kreuz gesessen,\nhast Du selig mich gemacht.\nO, ich hab es wohl empfunden,\nDein Blut macht von Sünden rein,\nund durch Deine heil\'gen Wunden\ngeh auch ich zum Himmel ein.'),
(9, '1882', 'Weit über der Welt, ist eine Bewegung  -  All over the World, the Spirit is moving', 'All over the world, the spirit is moving,\nall over the world, as the prophet said it would be.\nAll over the world, there\'s a mighty revelation\nof the glory of the Lord,\nas the waters cover the sea.\r\nDeep down in my heart, the spirit is moving,\ndeep down in my heart, as the bible said it would be.\nDeep down in my heart there\'s a mighty revelation\nof the glory of the Lord,\nas the waters cover the sea.', 'Weit über der Welt, ist eine Bewegung,\nweit über der Welt, hat uns gesagt der Prophet.\nWeit über der Welt, ist eine Offenbarung,\nvon Jesu Ehr\' und Ruhm,\nwie das Wasser den Meergrund bedeckt.\r\nTief in meiner Seel\', ist eine Bewegung.\nTief, tief in mir, hat uns gesagt der Prophet.\nTief, tief in mir, ist eine Offenbarung,\nvon dem Kommen unseres Herrn,\nwie das Wasser den Meergrund bedeckt.'),
(9, '1883', 'Weit vor Gründung der Welt, hast Du mich schon erwählt   (Jetzt gehöre ich Dir und Deine Treue gilt mir)', NULL, 'Weit vor Gründung der Welt\nhast Du mich schon erwählt,\nJesus, heut\' Deine Braut zu sein\nin der Abendzeit.\r\nJetzt gehöre ich Dir\nund Deine Treue gilt mir,\nnichts kann uns scheiden,\nwas auch geschieht,\nfür Zeit und Ewigkeit.\r\nJahre gingen vorbei,\nJesus, Du bliebst mir treu,\nwas im Leben auch vor mir stand,\nich ging an Deiner Hand.\r\nHerr, als Liebesbeweis\nzahltest Du selbst den Preis,\nund wie tief Deine Liebe war\nseh\' ich auf Golgatha.\r\nDann war meine Zeit da,\nDu zogst mich zum Altar.\nJesus, dort sprach ich:\n"Ja, ich will Dein für immer sein."\r\nHerr, auch wenn ich versagt,\nging sogar durch die Nacht,\nimmer stand fest dies\' Fundament,\ndass Gott die Seinen kennt.\r\nWeil Du mich so geliebt\nDir mein Herz Antwort gibt:\nJesus, Bräutigam, Heil und Licht,\nHerr, ich lasse Dich nicht.'),
(9, '1884', 'Weiß ich den Weg auch nicht, Du weißt ihn wohl', NULL, 'Weiß ich den Weg auch nicht, Du weißt ihn wohl!\nDas macht die Seele still und friedevoll.\nIst’s doch umsonst, dass ich mich sorgend müh,\ndass ängstlich schlägt mein Herz, sei\'s spät, sei\'s früh.\r\nDu weißt den Weg ja doch, Du weißt die Zeit;\nDein Plan ist fertig schon und liegt bereit.\nIch preise Dich für Deiner Liebe Macht,\nich rüh\'m die Gnade, die mir Heil gebracht.\r\nDu weißt, woher der Wind so stürmisch weht,\nund Du gebietest ihm, kommst nie zu spät.\nD\'rum wart ich still; Dein Wort ist ohne Trug.\nDu weißt den Weg für mich, das ist genug.'),
(9, '1885', 'Weißt du schon, mein Freund, dass dich Jesus retten kann   (Weißt du, wie Er litt, wie Er mit dem Tode stritt)', NULL, 'Weißt Du schon, mein Freund,\ndass dich Jesus retten kann,\ndenn Er nimmt die Sünder an,\nauch dich, auch dich.\nWeißt du schon mein Freund,\ndass Jesu teures Blut,\ndeinen Schaden machte gut,\nam Kreuz.\r\nWeißt du, wie Er litt,\nwie Er mit dem Tode stritt?\nWie viel Tränen er vergoss\nfür dich, für dich.\nWeißt du, wie er starb,\nwie er dir das Heil erwarb?\nOh, dann komm zu Ihm noch heut\',\nmein Freund.\r\nWeißt du schon, mein Freund,\ndass der Heiland kommt zurück,\ndann beginnt das wahre Glück\nin Ewigkeit.\nWeißt du schon, mein Freund,\nwenn der ew\'ge Morgen graut,\ndann wird heim geholt die Braut\ndes Herrn.\r\nWeißt du schon, mein Freund,\ndass auch du verloren bist,\nwenn der Heiland noch nicht ist\ndein Eigentum.\nBring Ihm deine Sünd\'!\nOh, komm heim, verlor\'nes Kind!\nJesus nimmt auch dich noch an,\nmein Freund.'),
(9, '1886', 'Welch ein Freund ist unser Jesus  -  What a Friend we have in Jesus', 'What a Friend we have in Jesus,\nall our sins and griefs to bear!\nWhat a privilege to carry\neverything to God in prayer!\nOh, what peace we often forfeit,\noh, what needless pain we bear,\nAll because we do not carry\neverything to God in prayer!\r\nHave we trials and temptations?\nIs there trouble anywhere?\nWe should never be discouraged,\ntake it to the Lord in prayer.\nCan we find a friend so faithful\nwho will all our sorrows share?\nJesus knows our every weakness,\ntake it to the Lord in prayer.\r\nAre we weak and heavy laden,\ncumbered with a load of care?\nPrecious Saviour, still our refuge,\ntake it to the Lord in prayer.\nDo thy friends despise, forsake thee?\nTake it to the Lord in prayer.\nIn His arms He\'ll take and shield thee,\nthou wilt find a solace there.\r\n(Come trials and tribulations,\nit seems as if it can\'t go on,\nthe need becomes the greatest of all,\nflee to Jesus in prayer!\nJesus remains the refuge of the heart,\nBlessed is he who in faith supplicates.\nHe covers us with strong arms,\nGives us rest in prayer.)', 'Welch ein Freund ist unser Jesus,\no wie hoch ist Er erhöht!\nEr hat uns mit Gott versöhnet\nund vertritt uns im Gebet.\nWer kann sagen und ermessen,\nwie viel Heil verloren geht,\nwenn wir nicht zu Ihm uns wenden\nund Ihn suchen im Gebet?\r\nWenn des Feindes Macht uns drohet\nund manch Sturm rings um uns weht,\nbrauchen wir uns nicht zu fürchten,\nsteh\'n wir gläubig im Gebet.\nDa erweist sich Jesu Treue,\nwie Er uns zur Seite steht\nals ein mächtiger Erretter,\nder erhört ein ernst Gebet.\r\nSind mit Sorgen wir beladen,\nsei es frühe oder spät,\nhilft uns sicher unser Jesus,\nflieh\'n zu Ihm wir im Gebet.\nSind von Freunden wir verlassen,\nund wir gehen ins Gebet,\no so ist uns Jesus alles:\nKönig, Priester und Prophet.\r\nKommen Prüfungen und Leiden,\nscheint\'s, als ob\'s nicht weiter geht,\nwird die Not am allergrößten,\nflieh\' zu Jesus im Gebet!\nJesus bleibt des Herzens Zuflucht,\nselig, wer im Glauben fleht.\nEr deckt uns mit starken Armen,\nschenkt uns Ruhe im Gebet.'),
(9, '1887', 'Welch ein Heiland hoch und rein, Er ist mein und ich bin sein  -  What a Saviour Jesus is, He is mine, and I am His   (Welch ein Heiland, welch ein Heiland)', 'What a Saviour Jesus is!\nHe is mine, and I am His.\nHe the price of sin has paid,\nand for me atonement made.\r\nWhat a Saviour, what a Saviour,\nwhat a Saviour Jesus is!\nI will praise Him, ever praise Him,\nHe is mine, and I am His!\r\nWhat a Saviour! praise His name,\nthat to earth for me He came.\nNot the least, but all He gave,\nmy mortal soul to save.\r\nWhat a Saviour! all the way\nwalking with me, day by day.\nGuiding by His holy will,\nguarding me from ev’ry ill.\r\nWhat a Saviour! and I know\nwhen to that bright world I go.\nSaved by His redeeming grace,\nI shall see Him face to face.\r\nWhat a Saviour! how He loves,\nev’ry hour His mercy proves.\nListen, for He speaks to thee:\nTake thy cross, and follow Me!', 'Welch ein Heiland hoch und rein!\nEr ist mein, und ich bin Sein,\nEr erkaufte mich mit Blut,\nmachte meinen Schaden gut.\r\nWelch ein Heiland,\nwelch ein Heiland,\no wie selig, Sein zu sein!\nLoben muss ich Ihn und preisen!\nIch bin Sein, und Er ist mein!\nIch bin Sein, und Er ist mein!\r\nWelch ein Heiland! Er gab Sich\nund Sein Alles hin für mich,\nSeine Liebe wundersam ist\'s,\ndie mich gefangen nahm.\r\nWelch ein Heiland! Schritt für Schritt\nträgt Er mich und wandelt mit,\nleitet, hütet und bewahrt\ntreu mich auf der Pilgerfahrt.\r\nWelch ein Heiland! Seine Hand\nbringt mich in das Heimatland,\nund in jenem ew\'gen Licht\nschau ich einst Sein Angesicht.\r\nWelch ein Heiland! Wie Er liebt!\nImmer neue Gnad\' Er gibt,\nund Er spricht auch heut\' zu dir:\n"Nimm dein Kreuz und folge Mir!"'),
(9, '1888', 'Welch Glück ist\'s, erlöst zu sein  -  Oh Bliss of the purified, Bliss of the free   (O preist Seiner Liebe Macht)', 'Oh bliss of the purified, bliss of the free!\nI plunge in the crimson tide opened for me.\nO’er sin and uncleanness exulting I stand,\nAnd point to the print of the nails in his hand.\r\nOh sing of his mighty love,\nSing of his mighty love,\nSing of his mighty love,\nMighty to save!\r\nOh bliss of the purified, Jesus is mine!\nNo longer in dread condemnation I pine.\nQuite sure of salvation I sing of his grace,\nWho lifted upon me the smile of his face.\r\nOh bliss of the purified, bliss of the pure!\nNo wound hath the soul that his blood cannot cure.\nThe sorrowing heart shall in Jesus find rest,\nThe tears of the mourner be dried on his breast.\r\nOh Jesus the crucified, thee will I sing,\nmy blessèd redeemer, my God and my King!\nMy soul filled with rapture shall shout o’er the grave,\nand triumph in death in the mighty to save.', 'Welch Glück ist\'s, erlöst zu sein, Herr, durch Dein Blut!\nIch tauche mich tief hinein in diese Flut.\nVon Sünd\' und Unreinigkeit bin ich hier frei\nund jauchze voll sel\'ger Freud: "Jesus ist treu!"\r\nO preist Seiner Liebe Macht!\nPreist Seiner Liebe Macht!\nPreist Seiner Liebe Macht,\ndie uns erlöst.\r\nWelch Glück ist\'s, erlöst zu sein, Herr, durch Dein Blut!\nIch leide nicht länger Pein, habe nun Mut;\nmir ging ja ein neues Licht gnadenvoll auf,\nd\'rum zweifle ich ferner nicht in meinem Lauf.\r\nWelch Glück ist\'s, erlöst zu sein, Herr, durch Dein Blut!\nDas heilt die Gebrechen fein, macht alles gut.\nHier wandelt der Sorgen Heer schnell sich in Lust.\nMan weinet und klagt nicht mehr an Jesu Brust.\r\nO Jesus, Gekreuzigter, Dir jauchz\' ich zu!\nMein Heiland, mein Gott und Herr, in Dir ist Ruh\'.\nMit Dir überwind\' ich weit des Todes Macht!\nO Wort voller Seligkeit: Es ist vollbracht!'),
(9, '1889', 'Welch herrliche Zeit erwartet uns  -  A wonderful Time is just ahead   (Welch herrliche Zeit für dich)', 'A wonderful time is just ahead,\nthe Lord Whom we love and own.\nWill open the gates of gloryland,\nrevealing His glory throne.\r\nA wonderful time for you,\na wonderful time for me.\nIf we are prepared to meet Jesus the King,\na wonderful time it will be.\r\nA wonderful time is just ahead,\nour conflicts and trials passed.\nOur wilderness journey at an end,\nsafe home everyone at last.\r\nA wonderful time is just ahead,\nthe groans of creation cease.\nAnd all that is held in bondage now\nthe Lord will that day release.', 'Welch herrliche Zeit erwartet uns,\nwelch herrlicher großer Lohn!\nBald sieht seine Braut die Ihm geglaubt\nden Heiland auf Seinem Thron.\r\nWelch herrliche Zeit für dich!\nWelch herrliche Zeit für mich!\nWenn wir sind bereit, unser\'m König geweiht,\nwelch herrliche, herrliche Zeit.\r\nWelch herrliche Zeit erwartet uns,\nwie wird uns so frei und so leicht!\nDer Weg durch dies Leben ist vorbei,\nwir haben das Ziel erreicht.\r\nWelch herrliche Zeit erwartet uns,\nkein Klagen, kein Weinen mehr.\nDas Alte vorbei und allezeit\nGemeinschaft mit unser\'m Herrn.'),
(9, '1890', 'Welch sel\'ge Gewissheit und höchstes Gut  (Anbetung sei Jesus, Er hat\'s vollbracht)', NULL, 'Welch sel\'ge Gewissheit und höchstes Gut:\nDie Schuld ist getilgt durch des Lammes Blut!\nO Liebe, du machtest mir alles neu:\nNun bin ich voll Freude, erlöst und frei!\r\nAnbetung sei Jesus, Er hat\'s vollbracht,\nEr hat\'s vollbracht, Er hat\'s vollbracht.\nSo schön hab\' ich es mir im Traum nie gedacht.\nO Wunder der Gnade, erlöst und frei, erlöst und frei.\nIch singe und juble, es ist alles neu, es ist alles, alles neu!\r\nIch kam zu dem Heiland, Er nahm mich an\nund hat dieses Wunder an mir getan\nSo zeuge ich davon jetzt froh und laut:\nWie ist Er es wert, dass man Ihm vertraut!\r\nO Seele, die Sühnung von Golgatha\nist frei und umsonst und für jeden da!\nKomm eilends und nimm sie im Glauben an;\nso wirst du erlöst, bist glückselig dann!'),
(9, '1891', 'Welch Seligkeit ist nun mein Teil  -  A Friend of Jesus, oh, what Bliss   (Freundschaft mit Jesus)', 'A friend of Jesus, oh, what bliss,\nthat one so vile as I\nshould ever have a friend like this\nto lead me to the sky.\r\nFriendship with Jesus, fellowship divine,\noh, what blessed, sweet communion,\nJesus is a friend of mine.\r\nA friend when other friendship cease,\na friend when others fail,\na friend who gives me joy and peace,\na friend when foes assail.\r\nA friend when sickness lays me low,\na friend when death draws near,\na friend as through the vale I go,\na friend to help and cheer.\r\nA friend when life\'s short race is o\'er,\na friend when earth is past,\na friend to meet on heaven\'s shore,\na friend when home at last.', 'Welch\' Seligkeit ist nun mein Teil,\ndenn Jesus ist mein Freund.\nEr schenkt mir Frieden, Freud\' und Heil,\nbewahrt vor jedem Feind.\r\nFreundschaft mit Jesus, dieses Glück ist mein!\nO die köstliche Gemeinschaft:\nEr ist mein und ich bin Sein!\r\nWenn and\'re Freunde von mir gehn,\nbleibt Er als Freund mir treu.\nWenn andere mich nicht versteh\'n,\nist seine Liebe neu.\r\nEin Freund, wenn Prüfung mich bedroht,\nein Freund im dunklen Tal.\nEin Freund bei Schmerz und Todesnot,\nEr hilft mir überall.\r\nEin Freund, wenn meines Lebenslauf\nwird einst zu Ende sein.\nDann nimmt Er mich im Himmel auf:\nich bin bei Ihm daheim.'),
(9, '1892', 'Welchem großen Gott dien ich  -  What a mighty God we serve', 'What a mighty God we serve,\nwhat a mighty God we serve.\nWhat a mighty, what a mighty,\nwhat a mighty God we serve.\r\nLet us sing and praise the Lord,\nlet us sing and praise the Lord.\nLet us sing, let us sing,\nlet us sing and praise the Lord.\r\nLet us go and preach the Word,\nlet us go and preach the Word.\nPreach the Word, preach the word,\nlet us go and preach the Word.', 'Welchem großen Gott dien\' ich,\nwelchem großen Gott dien\' ich.\nO wie groß, o wie groß,\nwelchem großen Gott dien\' ich!\r\nSingt und preist mit uns den Herrn,\nsingt und preist mit uns den Herrn.\nSingt und preist, singt und preist,\nsingt und preist mit uns den Herrn!\r\nGeh und predige das Wort,\ngeh und predige das Wort.\nPredige, predige,\ngeh und predige das Wort!'),
(9, '1893', 'Welcom Holy Spirit, we are in Your Presence   (2 Chorusse)', 'Welcom Holy Spirit\nWe are in Your presence\nFill us with Your power\nLive inside of me\r\nYou\'re the Living water\nNever drying Fountain\nComforter and Counselor\nTake complete control', NULL),
(9, '1894', 'Welcome Holy Spirit', 'Welcome Holy Spirit\nWe are in Your presence\nFill us with Your power\nLive inside of me\r\nYou’re the Living Water\nNever drying Fountain\nComforter and Counselor\nTake complete control', 'Willkommen heiliger Geist,\nwir sind in deiner Gegenwart.\nFüll\' uns mit deiner Kraft,\nlebe in mir.\r\nDu bist das lebendige Wasser,\nniemals versiegende Quelle.\nTröster und Berater,\nübernimm vollständig die Kontrolle.'),
(9, '1895', 'Wen habe ich im Himmel als Dich   (Psalm 73, 25-26)', NULL, 'Wen habe ich im Himmel als Dich,\nund nichts auf der Erde ist mir lieber als Du, oh Herr.\nWenn mir gleich Leib und Seele verschmachtet,\nso bist Du, mein Gott, doch für immer mein Trost und Teil.'),
(9, '1896', 'Wendet euch zu mir', NULL, '"Wendet euch zu Mir\naller Welt Enden, aller Welt Enden!\nWendet euch zu Mir,\ndenn Ich bin Gott und sonst keiner mehr."\r\nSagt mir, welcher Gott sprach schon von alters her,\nwer hat solche Gnade verkündigt?\nEr hat uns errettet als wir Feinde war\'n,\nliebte uns, als wir noch gesündigt.\r\nAlle, die von Herzen suchen ihren Gott,\nwerden ganz gewiss nicht zuschanden;\ndie aus allen Völkern, die aus Angst und Not\nzu Ihm kommen, sollen Ihn finden.\r\nNiemand außer Ihm ist ein gerechter Gott\nniemand außer Ihm unser Heiland.\nAlle soll\'n sich beugen vor Ihm, unser\'m Gott,\nsollen sagen: "Herr, meine Stärke!"\r\nHört, wie unser Herr sprach, als im Fleisch Er war,\nWorte, die für immer bestehen:\n"Wenn Ich einst erhöht bin dort auf Golgatha,\nwerd Ich alle zu Mir ziehen."'),
(9, '1897', 'Wenn Alt und Jung zusammen sich erfreuen   (Ja, durch den Heilgen Geist sind wir verbunden)', NULL, 'Wenn Alt und Jung zusammen sich erfreuen,\nan Gottes Wort, an Seiner großen Lieb\'.\nUnd wir den Herrn von ganzem Herzen lieben,\nzählt überhaupt kein Altersunterschied.\r\nJa, durch den Heil\'gen Geist sind wir verbunden,\ndurch Seinen Geist getauft zu einem Leib.\nUnd alles Trennende ist überwunden,\ndas Band der Liebe hält in Freud\' und Leid.\r\nJa, alle Christen haben eine Heimat,\naus allen Völkern werden sie vereint.\nOb schwarz ob weiß, es zählen keine Rassen,\nin Christo Jesu sind wir alle gleich.\r\nOb du bist adlig oder bist ein Bettler,\nin Sünde war\'n wir allesamt verlor\'n.\nEs hilft uns nicht ein kirchliches Bekenntnis,\nwir müssen sein vom Geiste neu gebor\'n.\r\nOb du bist feurig, oder bist ein Stiller,\nerwarte nicht, vom Bruder, dass er ist wie du.\nDer Leib von Christus hat verschied\'ne Glieder,\ndoch in den Gliedern fließt dasselbe Blut.\r\nSag, hast du Sehnsucht heute ernst zu machen\nund willst du sein ein echter, wahrer Christ?\nGott wird dich taufen mit dem Heil\'gen Geiste,\nwenn du dem ganzen Wort gehorsam bist.'),
(9, '1898', 'Wenn am Morgen ich erwach  -  In the morning when I rise   (Spiritual)', 'In the morning when I rise, in the morning when I rise,\nin the morning when I rise, give me Jesus.\nGive me Jesus, give me Jesus!\nYou can have all this world, but give me Jesus.\r\nAnd when I am alone, and when I am alone,\nand when I am alone,  give me Jesus!\nGive me Jesus, give me Jesus!\nYou can have all this world, but give me Jesus.\r\nAnd when I am in Prayer, and whenn I am in Prayer,\nand whenn I am in Prayer, give me Jesus!\nGive me Jesus, give me Jesus!\nYou can have all this world, but give me Jesus.\r\nAnd when I come to die, and when I come to die,\nand when I come to die, Give me Jesus.\nGive me Jesus, give me Jesus!\nYou can have all this world, but give me Jesus.', 'Wenn am Morgen ich erwach\', wenn am Morgen ich erwach\',\nwenn am Morgen ich erwach\', komm, Herr Jesus!\nKomm, Herr Jesus, komm, Herr Jesus!\nWas fehlt mir in dieser Welt? Nur Du, mein Jesus.\r\nUnd bin ich ganz allein\', und bin ich ganz allein\'\nund bin ich ganz allein\', komm, Herr jesu!\nKomm, Herr Jesus, komm, Herr Jesus!\nWas fehlt mir in dieser Welt? Nur Du, mein Jesus.\r\nUnd bin ich im Gebet, und bin ich im Gebet,\nund bin ich im Gebet, komm, Herr Jesus!\nKomm, Herr Jesus, komm, Herr Jesus!\nWas fehlt mir in dieser Welt? Nur Du, mein Jesus.\r\nUnd werd\' ich einmal geh\'n, und werd\' ich einmal geh\'n,\nund werd\' ich einmal geh\'n, komm, Herr Jesus!\nKomm, Herr Jesus, komm, Herr Jesus!\nWas fehlt mir in dieser Welt? Nur Du, mein Jesus.'),
(9, '1899', 'Wenn auch dein Leben nicht gerade verläuft   (Alles ist gut, alles ist gut)', NULL, 'Alles ist gut, alles ist gut,\nalles ist gut in Jesus,\nwas auch geschieht, was sich auch tut,\nalles ist gut in Jesus.\r\nWenn auch dein Leben nicht gerade verläuft,\nwenn vor der Türe die Sorge sich häuft,\nwenn vielleicht Angst deine Seele ergreift –\nalles ist gut in Jesus!\r\nWenn du grad\' nicht verstehst was dir passiert,\nwenn dich das Leben auf Umwegen führt,\ngeh doch zu dem, den dein Schicksal berührt,\nalles ist gut in Jesus!\r\nDer Gott, der liebevoll heut‘ mit dir geht,\nist auch der Gott, der dich morgen versteht,\nwenn sich die Welt wieder schnell um dich dreht:\nalles ist gut in Jesus!\r\nDer Gott, der so lange schon mit dir war,\nder dich begleitet hat durchs ganze Jahr,\nist in der kommenden Zeit für dich da,\nalles ist gut in Jesus!'),
(9, '1900', 'Wenn auch steile und ragende Berge   (Nach unserm festen Glauben wirds geschehen)', NULL, 'Wenn auch steile und ragende Berge\nmir jetzt sperren zum Ziele den Weg,\nschreit ich vorwärts in freudigem Glauben,\nGott selbst zeigt mir all\'zeit den Steg!\r\nNach unserm festen Glauben wird\'s geschehen,\nnach unserm festen Glauben wird\'s geschehen,\ndie Berge müssen flieh\'n, wenn Gottes Kinder zieh\'n,\nvorwärts im Glauben mit dem Heiland.\r\nIn der Stunde der schwersten Versuchung,\nwenn es scheint, als hörte Gott nicht,\nlasst uns ruh\'n auf dem Felsen des Wortes,\no glaub nur, und alles wird licht.\r\nAn dem Tage der heißen Verfolgung,\nwenn der Feinde sind viel um uns her,\nlasst uns suchen allein ihre Rettung;\nGott sorgt für Sein Werk und Sein Heer!\r\nJa, wir wollen durch Glauben Ihn ehren,\nunsern Gott, der uns sendet zum Krieg.\nSeine Sache ist\'s, uns zu bewahren,\nEr führt uns durch Glauben zum Sieg.'),
(9, '1901', 'Wenn auf Erden teurer Freund  -  If we never meet again   (Wir sehn uns an dem Morgen, dem Auferstehungsmorgen)', 'If we never meet again,\non this earth, my precious friend,\nif to God we have been true\nand have lived above all sin,\noh, than for us there\'ll be a greeting,\nthere\'s going to be a meeting.\nI\'ll see you in the rapture some sweet day.\r\nI\'ll see you in the rapture,\nI\'ll see you in the rapture,\nI\'ll see you in that meeting in the air.\nThere with our blessed saviour\nto live and reign forever.\nI\'ll see you in the rapture some sweet day.\r\nTo my loved ones let me say:\nThere will surely come a day,\nwhen our Lord will come again\nto catch His bride away.\nSo get ready now to meet Him,\nand with "Halleluja" sweet Him.\nI\'ll see you in the rapture some sweet day.\r\nI\'ll see you in the rapture,\nI\'ll see youin the rapture,\nI\'ll see you at that meeting in the air.\nThere with our blessed saviour,\nto live and reign forever.\nI\'ll see you in the rapture some sweet day.', 'Wenn auf Erden teurer Freund,\nwir uns nicht mehr wiederseh\'n,\nwenn vor Gott wir ehrlich war\'n\nund geheiligt vor ihm steh\'n\nwelche Freud, wenn ich dich sehe\nund mit dir zum Mahle gehe!\nJa ich seh\' dich, wenn er ruft an jenem Tag!\r\nWir seh\'n uns an dem Morgen,\ndem Auferstehungsmorgen,\nwir seh\'n uns bei dem Treffen in der Luft!\nWenn dann mit unserm König\nauf ewig wir regieren;\nja wir seh\'n uns, wenn er ruft an jenem Tag!\r\nMeinen Lieben sage ich,\nes kommt ein Tag ganz sicherlich,\nwo mein Herr hernieder kommt\nund die Braut dann zu sich nimmt.\nSei bereit, nur Ihn zu sehen\nund mit Ihm dann heimzugeh\'n!\nJa ich seh\' dich, wenn Er ruft an jenem Tag!\r\n'),
(9, '1902', 'Wenn den Lauf ich vollendet, werd ich vor dem Heiland stehn  -  When my Lifework is ended and I cross the swelling Tide   (Meinen Heiland werd ich kennen)', 'When my life-work is ended and I cross the swelling tide,\nwhen the bright and glorious morning I shall see.\nI shall know my Redeemer when I  reach the other side,\nand His smile will be the first to welcome me.\r\nI shall know Him, I shall know Him,\nas redeemed by His side I shall stand,\nI shall know Him, I shall know Him,\nby the prints of the nails in His hands.\r\nO the soul-thrilling rapture when I view His blessed face,\nand the luster of His kindly beaming eye.\nHow my full heart will praise Him for the mercy, love and grace,\nthat prepare for me a mansion in the sky.\r\nO the dear ones in glory, how they beckon me to come,\nand our parting at the river I recall.\nTo the sweet vales of Eden they will sing my welcome home,\nBut I long to meet my Saviour first of all.\r\nThru the gates to the city, in a robe of spotless white,\nHe will lead me where no tears will ever fall.\nIn the glad song of ages I shall mingle with delight,\nbut I long to meet my Saviour first of all.', 'Wenn den Lauf ich vollendet, werd\' ich vor dem Heiland steh\'n\nund die Herrlichkeit der Auferstehung seh\'n.\nWerd\' den Heiland ich kennen und Sein holdes Antlitz seh\'n?\nJa, als erstes will den Heiland ich dort seh\'n.\r\nMeinen Heiland werd\' ich kennen\neinst verklärt dort im seligen Land,\nmeinen Heiland werd\' ich kennen\nan den Malen der Nägel in der Hand.\r\nIn dem himmlischen Land, da dringen keine Sorgen ein\nund der Kummer macht nicht mehr die Herzen bang.\nNein, nur Freude und Wonne wird der Sel\'gen Los dort sein,\ndoch als erstes will den Heiland ich dort seh\'n.\r\nViele Lieben dort oben winken uns aus sel\'gen Höh\'n,\nwo wir nimmermehr dann auseinander geh\'n.\nO, wie herrlich wird dieses Widerseh\'n dort sein, wie schön,\ndoch als erstes will den Heiland ich dort seh\'n.\r\nDurch Jerusalems Tore und in Kleidern weiß und rein\nwerd\' ich mit den Scharen der Erlösten geh\'n.\nO, wie herrlich wird dieses Widerseh\'n dort sein, wie schön,\ndoch als erstes will den Heiland ich dort seh\'n.'),
(9, '1903', 'Wenn der ew\'ge Morgen taget  -  When the Trumpet of the Lord shall sound   (Wenn der Herr die Seinen rufet)   [Pfingstjubel]', 'When the trumpet of the Lord shall sound and time shall be no more,\nand the morning breaks, eternal, bright and fair.\nWhen the saved of earth shall gather over on the other shore,\nand the roll is called up yonder, I\'ll be there.\r\nWhen the roll is called up yonder,\nwhen the roll is called up yonder,\nwhen the roll is called up yonder,\nwhen the roll is called up yonder, I\'ll be there.\r\nOn that bright and cloudless morning when the dead in Christ shall rise,\nand the glory of his resurrection share.\nWhen his chosen ones shall gather to their home beyond the skies,\nand the roll is called up yonder, I\'ll be there.\r\nLet us labor for the Master from the dawn till setting sun,\nlet us talk of all his wondrous love and care.\nThen when all of life is over and our work on earth is done,\nand the roll is called up yonder, I\'ll be there.', 'Wenn der ew\'ge Morgen taget und die Zeit wird nicht mehr sein,\nwenn in allen Gräber tönt des Königs Wort;\nwenn einst Millionen kommen vor den Richter, groß und klein,\nund der Herr die Seinen rufet, bin ich dort.\r\nWenn der Herr die Seinen rufet,\nwenn der Herr die Seinen rufet,\nwenn der Herr die Seinen rufet,\ndurch die Gnade meines Heilands bin ich dort.\r\nWenn die Wetter Gottes flammen in dem großen Weltenbrand,\nund Gott Seinen Feinden zuruft: "Weichet fort",\naber freundlich denen nahet, die da steh\'n zur rechten Hand,\nund der Herr die Seinen rufet, bin ich dort.\r\nLasst uns doch mit Ernst bedenken jenes Tages Wichtigkeit\nund mit heil\'gem Eifer folgen Gottes Wort,\ndass wir freudig flehen können: "Komme bald, ich bin bereit!"\nWenn der Herr die Seinen rufet, bin ich dort.'),
(9, '1904', 'Wenn der Geist des Herrn sich in mir bewegt  -  When the spirit of the Lord moves in my Heart', 'When the Spirit of the Lord moves in my heart,\nI will sing like David sang.\nWhen the Spirit of the Lord moves in my heart,\nI will sing like David sang.\nI will sing, I will sing, I will sing like David sang.\nI will sing, I will sing, I will sing like David sang.\r\nWhen the Spirit of the Lord moves in my heart,\nI will praise like David praised.\nWhen the Spirit of the Lord moves in my heart,\nI will praise like David praised.\nI will praise, I will praise, I will praise like David praised\nI will praise, I will praise, I will praise like David praised.\r\nWhen the Spirit of the Lord moves in my heart,\nI will pray like David prayed.\nWhen the Spirit of the Lord moves in my heart,\nI will pray like David prayed.\nI will pray, I will pray, I will pray like David prayed.\nI will pray, I will pray, I will pray like David prayed.', 'Wenn der Geist des Herrn sich in mir bewegt\nsinge ich wie\'s David tat.\nWenn der Geist des Herrn sich in mir bewegt\nsinge ich wie\'s David tat.\nSinge ich, singe ich, singe ich wie\'s David tat.\nSinge ich, singe ich, singe ich wie\'s David tat.\r\nWenn der Geist des Herrn sich in mir bewegt\npreise ich wie\'s David tat.\nWenn der Geist des Herrn sich in mir bewegt\npreise ich wie\'s David tat.\nPreise ich, preise ich, preise ich wie\'s David tat.\nPreise ich, preise ich, preise ich wie\'s David tat.\r\nWenn der Geist des Herrn sich in mir bewegt\nbete ich wie\'s David tat.\nWenn der Geist des Herrn sich in mir bewegt\nbete ich wie\'s David tat.\nBete ich, bete ich, bete ich wie\'s David tat.\nBete ich, bete ich, bete ich wie\'s David tat.'),
(9, '1905', 'Wenn der Heiland ruft werd ich hören  -  When the Saviour calls I will answer   (Ich höre meinen Namen)', 'When the Saviour calls I will answer,\nwhen He calls for me I will hear.\nWhen the Saviour calls I will answer,\nI\'ll be somewhere listening for my name\r\nI\'ll be somewhere listening,\nI\'ll be somewhere listening,\nI\'ll be somewhere listening for my name (yes for my name).\nI\'ll be somewhere listening,\nI\'ll be somewhere listening,\nI\'ll be somewhere listening for my name.\r\nIf my heart is right when He calls me,\nIf my heart is right I will hear.\nIf my heart is right when He calls me,\nI\'ll be somewhere listening for my name.\r\nIf my robe is white when He calls me,\nIf my robe is white I will hear.\nIf my robe is white when He calls me,\nI\'ll be somewhere listening for my name.', 'Wenn der Heiland ruft, werd\' ich hören,\nwenn Er nach mir ruft, hör\' ich Ihn.\nWenn der Heiland ruft, werd\' ich hören,\nhören, wie Er meinen Namen ruft.\r\nIch höre meinen Namen,\nich höre meinen Namen,\nich hör\', wie Er meinen Namen ruft.\nIch höre meinen Namen,\nich höre meinen Namen,\nich hör\', wie Er meinen Namen ruft.\r\nBin ich frei von Sünd\', wenn Er ruft?\nWenn ich frei von Sünd\', hör\' ich Ihn.\nBin ich frei von Sünd\', werd\' ich hören,\nhören, wie Er meinen Namen ruft.\r\nIst mein Leben rein, wenn Er ruft?\nIst mein Leben rein, hör\' ich Ihn.\nIst mein leben rein, werd\' ich hören,\nhören, wie Er meinen Namen ruft.'),
(9, '1906', 'Wenn der Heiland, wenn der Heiland als König erscheint  -  When He cometh, when He cometh to make up his Jewels   (O dann werden sie glänzen wie Sterne so rein)', 'When He cometh, when He cometh\nto make up his jewels.\nAll his jewels, precious jewels,\nhis loved and his own.\r\nLike the stars of the morning,\nhis bright crown adorning,\nthey shall shine in their beauty,\nbright gems for his crown.\r\n\r\nLittle children, little children\nwho love their Redeemer.\nAre the jewels, precious jewels\nHis loved and His own.\r\n', 'Wenn der Heiland, wenn der Heiland\nals König erscheint.\nUnd die Seinen als Erlöste\nim Himmel vereint.\r\nO dann werden sie glänzen\nwie Sterne so rein.\nIn des Heilandes Krone\nals Edelgestein!\r\nEr wird sammeln, Er wird sammeln\nzur heiligen Schar.\nAll die Seelen, die im Blute\nsich wuschen recht klar.\r\nUnd die Kindlein und die Kindlein\nzieht Er an die Brust.\nDie Ihm kindlich Ihre Herzen\nhier schenken voll Lust.\r\nD\'rum, ihr Großen und ihr Kleinen,\ngebt Jesu das Herz!\nEr macht selig, Er macht herrlich,\nEr führt himmelwärts.'),
(9, '1907', 'Wenn der schöne Morgen grauet und die Braut wird heimwärts ziehn   (Wenn die Heiligen Er sammelt)   [Jesu Name Band 1]', NULL, 'Wenn der schöne Morgen grauet\nund die Braut wird heimwärts zieh\'n,\num für ewig vor dem Gottesthron zu steh\'n.\nMillionen Bluterkaufte, von dem Erdenleid entrückt,\nwerden Jesus, ihren Herzenskönig, seh\'n!\r\nWenn die Heiligen Er sammelt\naus den Völkern und den Stämmen,\nwir dann stehen voll Erstaunen\nvor dem Throne Seiner großen Herrlichkeit!\r\nFern von Indien sieht man kommen eine Überwinderschar.\nAuch von Afrika sie kommen Stamm für Stamm.\nDie mit Freuden dürfen ernten, die mit Tränen mussten sä\'n,\ndürfen jetzt zusammen preisen Gottes Lamm!\r\nWenn von Chinas Millionen große Scharen ziehen ein,\nauch von vielen Inseln kommt die Siegerschar,\ndann vergessen wir die Schmerzen, samt manch bitt\'rer Not und Leid,\nund wir bringen unserm Herrn Huld\'gung dar.\r\nDie Gefang\'nen von Sibirien kommen frei von Angst und Not,\nBrasilianer kommen auch mit frohem Mut.\nWelchen Jubel, welche Ehre sie dem Heiland bringen dar,\nder sie hat erkauft mit Seinem teurem Blut!\r\nAuch Zigeuner sind geladen zu dem großen Hochzeitsmahl,\njubelnd kommen sie herbei von nah und fern.\nAus den Zelten, aus den Wagen, von dem Platz am Straßenrand,\ndenn sie sind geliebte Gäste ihres Herrn.\r\nDort wird Israel man treffen, dass sich endlich auch bekehrt\nund dem Heiland bringt der Schmerzen voller Lohn.\nDas so lange in der Irre, ward vom Vater heim gebracht\nalles jubelt über den verlor\'nen Sohn.\r\nLasst uns eilen mit der Botschaft, die uns Jesus anvertraut,\nretten will Er Gelbe, Schwarze, Weiß\' und Braun\'.\nSieh\' Er hat Sein Blut vergossen, komm, nimm diese Botschaft an,\ndann wirst du für ewig deinen Heiland schau\'n!'),
(9, '1908', 'Wenn der Tag liegt dunkel vor dir  -  When the Day is dark before you   (Jesus nur allein, Er soll alles sein)', 'When the day is dark before you,\nand the clouds are hanging low.\nThere is One who watches o\'er you,\neverywhere that you may go.\r\nJesus is the One, yes, He\'s the only One,\nlet Him have His way until the day is done.\nWhen He speaks, you know the clouds will have to go,\njust because He loves you so.\r\nOh, if you are sad and lonely,\nlife is but an empty tomb.\nBreathe a prayer to Jesus only,\nHe will drive away the gloom.\r\nWhen you come to cross the river,\nHe will be your Friend and guide.\nyou can live with Him forever,\nover on the other side.', 'Wenn der Tag liegt dunkel vor dir,\ntiefe Wolken ziehen auf.\nEiner ist\'s, der wachet über dir,\nwohin mag auch geh\'n dein Lauf.\r\nJesus nur allein, Er soll alles sein.\nIn dem Herzen mein soll Er der König sein.\nWenn Er spricht, weiß ich, dass dunkle Wolken flieh\'n,\ndenn ich weiß, Er liebt mich so.\r\nWenn du traurig und alleine,\nmüde bist und voller Furcht.\nSchaue auf zu Ihm und bete,\ndann hilft Er dir immer durch.\r\nWenn du dann wirst steh\'n am Ufer,\nwird Er Freund und Führer sein.\nKannst Ihn freundlich hör\'n dann rufen:\n"Kind, du warst schon immer mein!"'),
(9, '1909', 'Wenn der Welt du hast entsagt mit dem Silber und dem Gold   -  If the World from you withhold of its Silver and its Gold   (Lass sie dort, lass sie dort)', 'If the world from you withhold of its silver and its gold,\nand you have to get along with meager fare,\njJust remember, in His Word, How He feeds the little bird.\nTake your burden to the Lord and leave it there.\r\nLeave it there, leave it there,\ntake your burden to the Lord and leave it there.\nIf you trust and never doubt, He will surely bring you out.\nTake your burden to the Lord and leave it there.\r\nIf your body suffers pain and your health you can\'t regain,\nand your soul is almost sinking in despair,\nJesus knows the pain you feel, He can save and He can heal.\nTake your burden to the Lord nd leave it there.\r\nWhen your enemies assail and your heart begins to fail,\ndon\'t forget that God in heaven answers prayer!\nHe will make a way for you and will lead you safely through.\nTake your burden to the Lord and leave it there.\r\nWhen your youthful days are gone and old age is stealing on,\nAnd your body bends beneath the weight of care.\nHe will never leave you then, He\'ll go with you to the end.\nTake your burden to the Lord and leave it there.', 'Wenn der Welt du hast entsagt, mit dem Silber und dem Gold,\nund wenn\'s mangelt dir am nöt\'gen täglich\' Brot,\ndann bedenke doch Sein Wort, wie Er für den Sperling sorgt;\nwirf die Sorgen auf den Herrn und lass sie dort.\r\nLass sie dort, lass sie dort,\nbring die Last zu Deinem Herrn und lass sie dort.\nWenn du traust und zweifelst nicht, wird Er sicher leiten dich.\nBring die Last zu Deinem Herrn und lass sie dort.\r\nWenn du Schmerzen leidest hier und Gesundheit mangelt dir,\nund Verzweiflung sinkt hinab in deine Seel\',\nJesus kennt denselben Schmerz, heilt und rettet dich so gern;\nwirf die Sorgen auf den Herrn und lass sie dort.\r\nWenn der Feind dich hier anficht und du schaffst es beinah\' nicht,\ndann vergiss es niemals, Gott erhört Gebet!\nJa, Er bahnt dir einen Weg, führet sicher dich ans Ziel;\nwirf die Sorgen auf den Herrn und lass sie dort.\r\nWenn die Jugend von dir geht und das Alter naht heran,\nund du gehst gebeugt durch manche schwere Last;\nja, auch dann ist Er dir nah, lässt dich sicher nicht allein;\nwirf die Sorgen auf den Herrn und lass sie dort.'),
(9, '1910', 'Wenn des Lebens Stürme tosen  -  When the Storms of Life are raging   (Er bedeckt mich, Er bedeckt mich)', 'When the storms of life are raging,\ntempests wild on sea and land,\nI will seek a place of refuge\nin the shadow of God’s hand.\r\nHe will hide me, He will hide me,\nwhere no harm can e’er betide me.\nHe will hide me, safely hide me,\nin the shadow of His hand.\r\nThough He may send some affliction,\n’twill but make me long for home.\nFor in love and not in anger,\nall His chastenings will come.\r\nEnemies may strive to injure,\nsatan all his arts employ.\nHe will turn what seems to harm me\ninto everlasting joy.\r\nSo while here the cross I’m bearing,\nmeeting storms and billows wild,\nJesus for my soul is caring,\nnaught can harm His Father’s child.', 'Wenn des Lebens Stürme tosen,\nwenn der Stärkste kaum hält stand,\nwill ich ganz getrost mich bergen\nin dem Schatten Seiner Hand.\r\nEr bedeckt mich, Er bedeckt mich,\ndass kein Sturm je stört noch schreckt mich.\nEr bedeckt mich, Er bedeckt mich\nmit dem Schatten Seiner Hand.\r\nWenn der Trübsal Last mich beuget,\ndaran auch erkenn\' ich Ihn.\nDenn die Trübsal soll mich prüfen,\nsoll mich näher zu Ihm zieh\'n.\r\nWenn Versuchung rings mich locket,\nwenn der Feind mir listig dräut,\nschafft Er mir aus den Gefahren\nnur noch größ\'re Kraft und Freud\'.\r\nMögen d\'rum die Stürme tosen\nund die Wellen brausend geh\'n,\nmeine Seele soll nicht zagen,\nsoll getrost auf Jesus seh\'n.'),
(9, '1911', 'Wenn die Freunde von dir gehen   (Jesus bleibt getreu)', NULL, 'Wenn die Freunde von dir geh\'n,\nFurcht und Zweifel dräun,\nEiner bleibt und wird\'s versteh\'n,\nEiner bleibt getreu.\r\nJesus bleibt getreu,\nJesus bleibt getreu.\nErd\' und Himmel mag vergeh\'n,\ndoch Jesus bleibt getreu.\r\nWenn der Himmel dunkel ist\nund der Sturmwind dräut,\nwisse, dass Er nahe ist,\nJesus bleibt getreu.\r\nIn des Lebens bitt\'rer Nacht\nliebt Er dich stets neu.\nTraue Seiner ew\'gen Macht,\nJesus bleibt getreu.\r\nBald wirst du Sein Antlitz schau\'n,\nrühmen Jesus Treu.\nSeiner Gnade darfst du trau\'n,\nJesus bleibt getreu.'),
(9, '1912', 'Wenn die Welt dich lockt, wenn du in Not   (Bleib bis in den Tod treu deinem Gott)', NULL, 'Wenn die Welt dich lockt, wenn du in Not,\nEiner, Er ist dir getreu!\nBist du in Gefahr, glaub\' es fürwahr,\nEiner ist immer getreu!\r\nBleib\' bis in den Tod treu deinem Gott.\nEr ist dein wahrhafter Freund.\nEr hat dich so lieb, Ihm alles gib.\nBleib bis zum Tod Ihm getreu!\r\nDenk\', wenn Satans List dich oft bedroht,\neiner, Er ist dir getreu!\nZiehst du übers Meer, weit in die Fern,\neiner ist immer getreu!\r\nJesus ist getreu wenn alles bricht,\nwenn du traurig und allein!\nJesus ist getreu, oh, zweifle nicht,\nEr wird dir immer treu sein!'),
(9, '1913', 'Wenn du bedrückt von Lasten und Sorgen   (An jenem Tage weg sind die Tränen, fort alle Lasten, vorbei die Nacht)', NULL, 'Wenn du bedrückt von Lasten und Sorgen,\nund wenn du keinen Ausweg mehr weißt,\nblicke auf Jesus, Er kommt ja morgen\nund macht wahr, was Sein Wort uns verheißt.\r\nAn jenem Tage weg sind die Tränen,\nfort alle Lasten, vorbei die Nacht.\nDort ist nur Freude, weg sind die Leiden.\nHerrlich wird alles an jenem Tag.\r\n"Treu bis zum Tod", ermahnet der Meister,\n"nur noch ein wenig Arbeit und Müh\'",\nJesus hilft Seinen auf jedem Wege.\nNichts kann dir schaden in Seinem Licht.\r\nGlorreicher Morgen, wenn Er kommt wieder,\nkommt von dem schönen Heim in der Höh\'.\nHerrlicher Morgen, wenn niemand weinet,\newig vorbei sind Schmerzen und Weh.'),
(9, '1914', 'Wenn du in des Lebens Stürmen bist verzagt  -  When upon life\'s billows you are tempest tossed   (Zähl das Gute, denke doch daran)', 'When upon life\'s billows you are tempest tossed,\nwhen you are discouraged, thinking all is lost.\nCount your many blessings, name them one by one,\nand it will surprise you what the Lord hath done.\r\nCount your blessings, name them one by one,\ncount your blessings, see what God hath done!\nCount your blessings, name them one by one,\ncount your many blessings, see what God hath done!\r\nAre you ever burdened with a load of care?\nDoes the cross seem heavy you are called to bear?\nCount your many blessings, every doubt will fly,\nand you will keep singing as the days go by.\r\nWhen you look at others with their lands and gold,\nthink that Christ has promised you His wealth untold.\nCount your many blessings. Wealth can never buy\nyour reward in heaven, nor your home on high.\r\nSo, amid the conflict whether great or small,\ndo not be disheartened, God is over all.\nCount your many blessings, angels will attend,\nhelp and comfort give you to your journey\'s end.', 'Wenn in des Lebens Stürmen du bist verzagt,\nwenn dein Herz voll Sorge mutlos bangt und klagt,\nzähl dir auf das Gute, denke doch daran,\nund du wirst dich wundern, was dir Gott getan.\r\nZähl das Gute, denke doch daran!\nZähl das Gute, sieh, was Gott getan.\nZähl das Gute, denke täglich dran,\nund du wirst dich wundern, was dir Gott getan.\r\nWenn du müde seufzest, von der Last beschwert,\nwenn dein Herz nach Frieden tränenvoll begehrt,\nzähl dir auf das Gute, denk an Christi Blut,\nJesu Heilandsliebe macht den Schaden gut.\r\nAndern wurden Güter dieser Welt zuteil,\ndir ward Jesus selber und Sein ew\'ges Heil!\nZähl dir auf das Gute, lass der Welt die Lust;\ndu hast größ\'ren Reichtum tief in deiner Brust.\r\nIn des Lebens Nöten sei der Friede dein;\ngrößer als der Helfer kann die Not nicht sein.\nZähl dir auf das Gute, dein ist diese Zeit,\ndein das ew\'ge Leben, dein die Herrlichkeit.'),
(9, '1915', 'Wenn du Jesus kennst bist du nicht einsam mehr  -  If you know the Lord, you need Nobody else   (Halt einmal still, sprich mit dem Herrn)   [Jesu Name Band 2]', 'If you know the Lord, you need nobody else,\nto see you through, the darkest night.\nYou can walk alone, you only need the Lord,\nHe\'ll keep you on, the road marked right.\r\nTake time to pray every day,\nand when you\'re heading home,\nHe\'ll show you the way.\nIf you know the Lord, you need nobody else,\nto see the light, His wonderful light.\r\n\r\n', 'Wenn du Jesus kennst, bist du nicht einsam mehr,\nEr hält die Wacht auch in der Nacht.\nGeh mit Ihm den Weg, denn Jesus hält dich fest,\nbist du allein, wird Er bei dir sein.\r\nHalt einmal still, sprich mit dem Herrn,\nruf Ihn um Hilfe an, Er ist dir nicht fern.\nWenn du Jesus kennst, bist du nicht einsam mehr,\nEr ist dir nah, immer für dich da.\r\nWenn du Jesus kennst, bist du nicht furchtsam mehr,\nEr geht voran auf der Lebensbahn.\nFühlst du dich bedroht, siehst nur Dunkelheit,\nEr ist dein Licht, d\'rum fürchte dich nicht.\r\nWenn du Jesus kennst, bist du nicht traurig mehr,\nSeiner Freude Glanz erfüllt dich ganz.\nDu bist Gottes Kind, weißt um ein Vaterhaus,\nnach der Erdenzeit in der Herrlichkeit.'),
(9, '1916', 'Wenn einsam du gehst, durch dieses Erdental  -  I traveled alone upon this lonesome Way   (Es hilft nur Jesus allein in allen Sorgen)', 'I traveled alone upon this lonesome way,\nMy burdens were heavy and dark was my day.\nI looked for a friend not knowing that He\nHad all of this time been looking for me.\r\nNow it is Jesus and me for each tomorrow,\nfor every heartache, and every sorrow.\nI know that I can depend upon my newfound friend,\nand so till the end, it’s Jesus and me.\r\nThe road may be long to heaven’s pearly gate,\nI know that it’s narrow; I know that it’s straight.\nBut Jesus is there through eternity,\nwe’ll travel along, just Jesus and me.\r\nForever I’ll sing of his great love for me,\nforever I’ll tell it on land and on sea.\nI’ll stay by his side, contented I’ll be.\nFor all of my life it’s Jesus and me.', 'Wenn einsam du gehst, durch dieses Erdental,\nund Sünde und Sorgen, bereiten dir Qual.\nO blicke auf Ihn, Sein Blut mach dich rein,\naus all deiner Not, hilft Jesus allein!\r\nEs hilft nur Jesus allein in allen Sorgen,\nEr kennt das Heute und kennt das Morgen.\nWenn jede Stütze zerbricht, dann Herz verzage nicht,\nKraft, Leben und Licht gibt Jesus allein!\r\nEr starb einst für dich, damit du froh und frei,\nnicht länger mehr einsam dein Weg fortan sei!\nEr sorgt für dich treu, führt sicher dich heim,\nden wahren Weg kennt nur Jesus allein!\r\nBald kommt Er zurück in Herrlichkeit und Pracht,\ndem herrlichen Morgen weicht schnell dann die Nacht.\nWillst du auch mein Freund dort mit Ihm einst sein,\nso komm jetzt zu Ihm, zu Jesus allein!'),
(9, '1917', 'Wenn einst alle Heil\'gen vor dem Throne stehen   (Ehre, Ehre unserm König, Halleluja)', NULL, 'Wenn einst alle Heil\'gen vor dem Throne stehen,\nvöllig rein, völlig rein.\nWenn verherrlicht und beglückt sie Jesus sehen,\nwelch ein Jubel wird das sein.\r\nEhre, Ehre unserm König, Halleluja!\nFür die große Gnade die Er uns erwies.\nWie ein Brausen von dem Meer,\ntönt das neue Lied einher\nin dem wunderschönen Paradies.\r\nBald sind alle Sorgen dieser Erd\' entschwunden,\nes wird sein alles neu.\nBald ist auch die letzte Prüfung überwunden\nund die Kämpfe sind vorbei.\r\nAlle Trübsal alle Not bedeutet wenig,\nbald, ja bald, bald, ja bald.\nSteht die blutgewasch\'ne Schar vor ihrem König,\nin verherrlichter Gestalt.'),
(9, '1918', 'Wenn einst durch den Wolkenhimmel wieder Christus kommt zur Erd  -  When upon the Clouds of Heaven Christ shall come to earth   (Welch ein Singen, welch ein Jubeln)', 'When upon the clouds of heaven,\nChrist shall come to earth again,\nwill the world be glad to see Him,\nwhen our Lord shall come again?\r\nThere\'ll be singing, there\'ll be shouting,\nthere\'ll be sorrow, there\'ll be pain,\nthere\'ll be weeping, there\'ll be praying,\nwhen our Lord shall come again.\r\nWill His coming bring rejoicing?\nOr will it bring tears and pain?\nAre you ready to receive Him,\nwhen our Lord shall come again?\r\nWill you join in lamentation?\nOr the angel\'s glad refrain?\nWill you help His people crown Him,\nwhen our Lord shall come again?\r\nWork and pray till Jesus calls you,\nhelp to gather in the grain,\nthen with joy you\'ll meet the Saviour,\nwhen our Lord shall come again.', 'Wenn einst durch den Wolkenhimmel\nwieder Christus kommt zur Erd\'.\nWird die Welt Ihn dann erwarten,\nwenn der König dann erscheint?\r\nWelch ein Singen, welch ein Jubeln!\nKeine Sorgen und kein Schmerz,\nauch kein Weinen, nur Anbetung,\nwenn der Herr dann uns erscheint.\r\nBringt Sein Kommen dir die Freude\noder Traurigkeit und Schmerz?\nBist bereit du für den Meister,\nwenn der König dann erscheint?\r\nStimmst du ein in lauten Jammer\noder in der Engel \'Sang?\nWirst du helfen Ihn zu krönen\nwenn der König dann erscheint?\r\nBet\' und arbeit\' bis der Herr ruft!\nFahr\' die Ernte doch voll ein!\nDann mit Freud\' du triffst den Heiland,\nwenn der König dann erscheint.'),
(9, '1919', 'Wenn einst nach diesem Lebensweg ich geh ins bessre Land   (Bald geht es heim, ins bessre Land)', NULL, 'Wenn einst nach diesem Lebensweg ich geh\' in\'s bess\'re Land,\nwenn alle Sorgen sind vorbei und alle Nacht verschwand,\ndann ewig ich bei Jesus bin, errettet froh und frei,\ndas Alte dann vergangen ist, Er machte alles neu!\r\nBald geht es heim, in\'s bess\'re Land,\nzur Heimat an dem gold\'nen Strand.\nDort keine Sünd\' und Sorg\' mich drückt,\newige Ruh\' mein Herz erquickt!\r\nDie Tränen trocknet Jesus ab, in Liebe zart und fein;\nvergessen sind die Prüfungen und alle Angst und Pein!\nMein Geist zur ew\'gen Ruh\' gebracht nur Jesus rühmen kann,\nverschwunden ist die lange Nacht, ein neuer Tag bricht an!\r\nEwig daheim, oh, welche Freud\', vorbei die Pilgerfahrt!\nDen Wanderstab brauch\' ich nicht mehr, die Krone meiner harrt!\nDann in der Schar der Heiligen, ich steh\' vor Gottes Thron,\nfroh singen wir das neue Lied: Heil Dir, Du Gottessohn!\r\nDie Botschaft brachte uns zurück zum originalen Wort.\nWir werden bald hinweg entrückt  zu dem verheiß\'nen Ort.\nAuf immer wir beim Bräutigam als Braut mit Ihm vereint,\nsitzend mit Ihm beim Hochzeitsmahl in großer Herrlichkeit.\r\nWie freu\'n wir uns! Noch kurze Zeit,\ndann wandeln wir im weißen Kleid.\nAuch dann wir seh\'n den Prophet,\nder uns hinwies, den schmalen Weg.'),
(9, '1920', 'Wenn Friede mit Gott meine Seele durchdringt  -  When Peace like a River attendeth my Way   (Mir ist wohl in dem Herrn)', 'When peace like a river attendeth my way,\nwhen sorrows like sea billows roll.\nWhatever my lot, Thou hast taught me to say,\nit is well, it is well with my soul.\r\nIt is well with my soul.\nIt is well, it is well with my soul.\r\nThough satan should buffet, if trials should come,\nlet this blest assurance control:\n"That Christ hath regarded my helpless estate,\nand hath shed His own Blood for my soul."\r\nMy sin, oh the bliss of this glorious thought,\nmy sin, not in part, but the whole is nailed to the Cross.\nAnd I bear it no more, praise the Lord, praise the Lord,\npraise the Lord, oh my soul.\r\nFor me, be it Christ, be it Christ hence to live,\nif Jordan above me shall roll.\nNo pang shall be mine, for in death as in life\nthou wilt whisper Thy peace to my soul.', 'Wenn Friede mit Gott meine Seele durchdringt,\nob Stürme auch drohen von fern,\nmein Herze im Glauben doch allezeit singt:\n"Mir ist wohl, mir ist wohl in dem Herrn."\r\nMir ist wohl in dem Herrn.\nMir ist wohl, mir ist wohl in dem Herrn!\r\nWenn Satan mir nachstellt und bange mir macht,\nso leuchtet dies Wort mir als Stern:\n"Mein Jesus hat alles für mich schon vollbracht,\nich bin rein durch das Blut meines Herrn."\r\nDie Last meiner Sünde trug Jesus, das Lamm,\nund warf sie weit weg in die Fern.\nEr starb ja für mich auch am blutigen Stamm,\nmeine Seele lobpreiset den Herrn.\r\nNun leb\' ich in Christo für Christum allein,\nSein Wort ist mein leitender Stern.\nIn Ihm hab ich Fried\' und Erlösung von Pein.\nMeine Seele ist selig im Herrn.'),
(9, '1921', 'Wenn ich bedenke was er für mich tat  -  When I remember what He\'s done for me', 'When I remember what He\'s done for me,\nI can never turn back anymore.\nWhen I remember what He\'s done for me,\nI can never turn back anymore.\nNo, no, no, no, no!\nI can never turn back anymore.\nNo, no, no, no, no!\nI can never turn back anymore.', 'Wenn ich bedenke, was Er für mich tat,\nkann niemals von Ihm ich geh\'n!\nWenn ich bedenke, was Er für mich tat,\nkann niemals von Ihm ich geh\'n!\nNein, nein, nein, nein, nein,\nkann niemals von Ihm ich geh\'n!\nWenn ich bedenke, was Er für mich tat,\nkann niemals von Ihm ich geh\'n!'),
(9, '1922', 'Wenn ich Deine Herrlichkeit bestaune  -  When I look into Your Holiness', 'When I look into your holiness,\nwhen I gaze into your loveliness,\nwhen all things that surround become shadows\nin the light of you.\r\nWhen I’ve found the joy of reaching your heart,\nwhen my will becomes enthroned in your love,\nwhen all things that surround become shadows\nin the light of you.\r\nI worship you, I worship you,\nthe reason I live is to worship you.\nI worship you, I worship you\nthe reason I live is to worship you.', 'Wenn ich Deine Herrlichkeit bestaune,\nDeine Schönheit klar vor Augen seh\',\ndann verblasst was ich um mich sehe\nin Deinem Licht.\r\nWenn ich Deine Nähe deutlich spüre,\nDeine Liebe völlig mich umhüllt,\ndann verblasst was ich um mich sehe\nin Deinem Licht.\r\nIch bete Dich an, ich bete Dich an,\nDich allein anzubeten ist meines Lebens Sinn.\nIch bete Dich an, ich bete Dich an,\nDich allein anzubeten ist meines Lebens Sinn.'),
(9, '1923', 'Wenn ich denk an die Entrückung  -  I am thinking of the Rapture   (Wenn die Erlösten ziehen dort ein)', 'I am thinking of the rapture\nin our blessed home on high,\nwhen the redeemed are gathering in.\nHow we\'ll raise the heavenly anthem\nin that city in the sky,\nwhen the redeemed are gathering in.\r\nWhen the redeemed are gathering in,\nwashed like the snow and free from all sin,\nhow we will shout, and how we will sing,\nwhen the redeemed are gathering in.\r\nThere will be a great procession\nover on the streets of gold,\nwhen the redeemed are gathering in.\nOh, what music, oh, what singing,\no\'er the city will be rolled,\nwhen the redeemed are gathering in.\r\nSaints will sing redemption\'s story\nwith their voices clear and strong,\nwhen the redeemed are gathering in.\nthen the angels all will listen,\nfor they cannot join that song,\nwhen the redeemed will gathering in.\r\nThen the Saviour will give orders\nto prepare the banquet board,\nwhen the redeemed are gathering in,\nand we\'ll hear His invitation:\n"Come, ye blessed of the Lord!"\nwhen the redeemed are gathering in.', 'Wenn ich denk an die Entdrückung\nhin zu unserm Heimatland,\nwenn die Erlösten ziehen dort ein.\nWir erheben Siegeslieder\nin der Stadt so licht und rein,\nwenn die Erlösten ziehen dort ein.\r\nWenn die Erlösten ziehen dort ein,\nweißer denn Schnee,\nvon Sünden ganz rein.\nWelch ein Singen\nwird es dann sein,\nwenn die Erlösten ziehen dort ein.\r\nDort wird sein ein großer Einzug\nauf den Straßen, die von Gold,\nwenn die Erlösten ziehen dort ein.\nWelch ein Singen, Musizieren\nin der Stadt zu hören ist,\nwenn die Erlösten ziehen dort ein.\r\nHeil\'ge singen Rettungslieder,\nman hört Stimmen laut und klar,\nwenn die Erlösten ziehen dort ein.\nAlle Engel werden lauschen,\nwissen nicht, was uns geschah,\nwenn die Erlösten ziehen dort ein.\r\nUnser Heiland alle einlädt\nan den reich gedeckten Tisch.\nWenn die Erlösten ziehen dort ein.\nUnd wir hören seine Worte:\n"Überwinder, freue dich!"\nWenn die Erlösten ziehen dort ein.'),
(9, '1924', 'Wenn Jesus kommt, wird Satans Macht gebrochen (Ein Bettler saß allein am Wegesrande  -  One sat alone beside the Highway begging)', 'One sat alone beside the highway begging.\nHis eyes were blind, the light he could not see.\nHe clutched his rags and shivered in the shadows,\nthen Jesus came and bade his darkness flee.\r\nWhen Jesus comes the tempter\'s pow\'r is broken,\nwhen Jesus comes the tears are wiped away.\nHe takes the gloom and fills the life with glory,\nfor all is changed when Jesus comes to stay.\r\nFrom home and friends the evil spirits drove him,\namong the tombs he dwelt in misery;\nhe cut himself as demon pow\'rs possessed him.\nThen Jesus came and set the captive free.\r\nUnclean! Unclean! The leper cried intorment,\nthe deaf, the dumb, in helplessness stood near;\nthe fever raged, disease had gripped its victim,\nthen Jesus came and cast out every fear.\r\nSo men today have found the Saviour able,\nthey could not conquer passion, lust and sin;\ntheir broken hearts had left them sad and lonely,\nthen Jesus came and dwelt Himself within.', 'Einsam ein Bettler saß am Wegesrande,\nin Lumpentracht, in Armut und in Not,\nund die erlosch\'nen Augen hob er aufwärts,\nals Jesus kam und ihm Sein Heil anbot.\r\nWenn Jesus kommt, wird Satans Macht gebrochen,\nwenn Jesus kommt ist es für ihn vorbei!\nDas Finst\'re flieht, die Sonne scheint dann wieder,\nalles wird neu und Seelen werden frei!\r\nVon Haus und Freunden trieben ihn Dämonen\nzu Gräbern hin in Not und Einsamkeit,\ner musste draußen in den Höhlen wohnen,\nals Jesus kam, da wurde er befreit.\r\nAussätz\'ge Männer riefen: "Unrein! Unrein!"\nund einen ander\'n Jesus taubstumm fand;\nim Fieber glänzten vieler Kranken Augen,\nals Jesus kam, die Krankheitsmacht verschwand.\r\nEr ist derselbe Jesus wie vor Zeiten,\nund jeder Mensch, der glaubend Ihn berührt,\ntrotz aller Schmerzen, die die Sünde brachte,\nbei Jesus Kraft und Heilung schnell verspürt!'),
(9, '1925', 'Wenn mein Becher fließt über vor Freud  -  When my Cup runneth over with Joy   (Chorus)', 'When my cup runneth over with joy,\nwhen my cup runneth over with joy,\nI find it easy to pray,\nand to sing all the day,\nwhen my cup runneth over with joy.', 'Wenn mein Becher fließt über vor Freud\',\nwenn mein Becher fließt über vor Freud\',\nwird das Beten zur Lust,\nLobgesang füllt die Brust,\nwenn mein Becher fließt über vor Freud\'.'),
(9, '1926', 'Wenn mein Glaube schwinden will  -  When I fear my Faith will fail   (Christus hält mich fest / He will hold me fast)   [Keith & Kristyn Getty Version]', 'When I fear my faith will fail,\nChrist will hold me fast.\nWhen the tempter would prevail,\nHe will hold me fast.\nI could never keep my hold,\nthrough life\'s fearful path.\nFor my love is often could,\nHe must hold me fast.\r\nHe will hold me fast,\nHe will hold me fast.\nFor my Saviour loves me so,\nHe will hold me fast.\r\nThose He saves are His delight,\nChrist will hold me fast.\nPrecious in His holy sight,\nHe will hold me fast.\nHe\'ll not let my soul be lost,\nHis promisses shall last.\nBought by Him at such a cost,\nHe will hold me fast.\r\nFor my life He bled and died,\nChrist will hold me fast.\nJustice has been satisfied,\nHe will hold me fast.\nRaised with Him to endless life,\nHe will hold me fast.\nTill our faith is turn to sight,\nwhen He comes at last.', 'Wenn mein Glaube schwinden will,\nhält mich Christus fest.\nSatans List wird mir zu viel,\nChristus hält mich fest.\nAlleine kann ich nicht besteh\'n\nauf dem Lebensweg.\nAlleine müsste ich vergeh\'n,\nChristus hält mich fest.\r\nChristus hält mich fest.\nChristus hält mich fest.\nMein Erlöser liebt mich sehr,\nChristus hält mich fest.\r\nJesus nimmt den Sünder an;\nChristus hält mich fest.\nKeine Macht mich trennen kann;\nChristus hält mich fest.\nMeine Seele bleibt bewahrt,\nSein Versprechen gilt.\nDenn er hat den Preis bezahlt;\nChristus hält mich fest.\r\nFür mich ging er in den Tod;\nChristus hält mich fest.\nJetzt steh ich gerecht vor Gott;\nChristus hält mich fest.\nMit ihm werd\' ich aufersteh\'n;\nChristus hält mich fest.\nIhn mit eignen Augen seh\'n,\nwenn er wiederkommt.'),
(9, '1927', 'Wenn mein Leben hier endet und am Jordan ich steh  -  When I come to the River at the ending of Day   (Durch den Jordan geh ich nicht allein / I won\'t have to cross Jordan alone)', 'When I come to the river at the ending of day,\nwhen the last winds of sorrow have blown.\nThere\'ll be somebody waiting to show me the way\nI won\'t have to cross Jordan alone.\r\nI won\'t have to cross Jordan alone.\nJesus died all my sins to atone.\nIn the darkness I see He\'ll be waiting for me.\nI won\'t have to cross Jordan alone.\r\nThough the billows of sorrow and trouble may sweep.\nChrist the Saviour will care for his own.\n\'Til the end of the journey my soul He will keep,\nand I won\'t have to cross Jordan alone.\r\nOften times I\'m forsaken and weary and sad,\nwhen it seems that my friends have all gone.\nThere is one thought that cheers me and makes my heart glad.\nI won\'t have to cross Jordan alone.\r\n(Take, O Lord, my hands and lead me,\nfor my life is but a short time.\nDo not seek the joy that quickly escapes here;\nthen lead me home through the Jordan.)', 'Wenn mein Leben hier endet\nund am Jordan ich steh,\njede Not, jedes Leid ist vorbei,\nJemand wartet auf mich\nund zeigt mir dann den Weg;\ndurch den Jordan geh ich nicht allein.\r\nDurch den Jordan geh ich nicht allein.\nMeine Schuld sühnte Jesus am Kreuz.\nWenn das Dunkle ich seh\', wartet Jesus auf mich;\ndurch den Jordan geh ich nicht allein.\r\nWenn verzagt und entmutigt mein Herz manchmal ist,\nso wird Jesus doch sorgen für mich.\nBis zum Ende des Lebens wird führen Er mich;\ndurch den Jordan geh ich nicht allein.\r\nOftmals bin ich hier einsam, verlassen und schwach,\nund die Freunde sind mir manchmal fern.\nEs gibt Jemand, der Freude und Kraft mir dann gibt;\ndurch den Jordan geh ich nicht allein.\r\nNimm, oh Herr, meine Hände und führe Du mich,\ndenn mein Leben währt nur kurze Zeit.\nWill nicht suchen die Freude, die hier schnell entweicht;\ndurch den Jordan füh\'r Du mich dann heim.'),
(9, '1928', 'Wenn mein Wandern endet, seh vom Glanz geblendet   (Über Wolken weit in der Herrlichkeit)', NULL, 'Wenn mein Wandern endet, seh\' vom Glanz geblendet\nich den Himmelsmorgen in der Herrlichkeit.\nOh, welch große Gabe ich in Christus habe,\ndenn ein Heim dort droben ist für mich bereit.\r\nÜber Wolken weit in der Herrlichkeit\nhab ich ein Heim, ein himmlisches Heim,\nüber Wolken weit.\nÜber Wolken weit in der Herrlichkeit\nhab ich ein Heim, ein himmlisches Heim,\nüber Wolken weit.\r\nWenn auch hier auf Erden ich will müde werden,\nweiß ich doch, der Heiland steht mir treu zur Seit\'.\nJa, auf allen Wegen führt mich Gottes Segen,\nbis ich Jesus schaue, über Wolken weit.\r\nHör\', dein Heiland ruft dich, Ja, Sein Herz es sehnt sich,\nherrlich dich zu retten für die Ewigkeit.\nBald wird Jesus kommen um dann all\' die Frommen\nzu sich heim zu nehmen, über Wolken weit.'),
(9, '1929', 'Wenn nach der Erde Leid, Arbeit und Pein  -  When all my Labors and Trials are over   (Das wird allein Herrlichkeit sein)', 'When all my labors and trials are o\'er,\nand I am safe on that beautiful shore,\njust to be near the dear Lord I adore,\nwill through the ages be glory for me.\r\nO that will be, glory for me,\no that will be, glory for me,\nwhen by His grace I shall look on His face,\no that will be, be glory for me!\r\nWhen by the gift of His infinite grace,\nI am accorded in heaven a place,\njust to be there and to look on His face,\nwill through the ages be glory for me.\r\nFriends will be there I have loved long ago.\nJoy like a river around me will flow.\nYet just a smile from my Saviour, I know,\nwill through the ages be glory for me.\r\nGlory to You, Jesus alone!\nGlory to You, Jesus alone!\nEverything that has breath joins in:\nGlory to Jesus, yes to Jesus alone!', 'Wenn nach der Erde Leid, Arbeit und Pein,\nich in die goldenen Gassen zieh ein,\nwird nur das Schau\'n meines Heilands allein,\nGrund meiner Freude und Anbetung sein.\r\nDas wird allein Herrlichkeit sein,\ndas wird allein Herrlichkeit sein,\nwenn frei von Weh ich Sein Angesicht seh\',\nwenn frei von Weh ich Sein Angesicht seh\'.\r\nWenn dann die Gnade, mit der ich geliebt,\ndort eine Wohnung im Himmel mir gibt,\nwird doch nur Jesus und Jesus allein,\nGrund meiner Freude und Anbetung sein.\r\nDort vor dem Throne im himmlischen Land,\ntreff\' ich die Freunde, die hier ich gekannt,\ndennoch wird Jesus und Jesus allein,\nGrund meiner Freude und Anbetung sein.\r\nHerrlichkeit Dir, Jesus allein!\nHerrlichkeit Dir, Jesus allein!\nAlles was Odem hat stimme mit ein:\nHerrlichkeit Jesus, ja Jesus allein!'),
(9, '1930', 'Wenn Sorgenlast und Schmerz mich plagt  -  When pangs of Death seized on my Soul   (Er weist mich niemals ab)', 'When pangs of death seized on my soul,\nunto the Lord I cried.\nTill Jesus came and made me whole,\nI would not be denied.\r\nI would not be denied,\nI would not be denied,\ntill Jesus came and made me whole,\nI would not be denied.\r\nAs Jacob in the days of old,\nI wrestled with the Lord.\nAnd instant, with a courage bold,\nI stood upon His Word.\r\nOld Satan said my Lord was gone\nand would not hear my prayer.\nBut praise the Lord, the work is done,\nand Christ the Lord is here.\r\n\r\n', 'Wenn Sorgenlast und Schmerz mich plagt,\nein Tröster ist in mir.\nBis Jesus kommt, Sein Wort mir sagt:\n"Mein Kind, Ich bin bei dir."\r\nEr weist mich niemals ab,\nniemals weist er mich ab.\nBis Er mich durch und durch erlöst,\nweist Jesus mich nicht ab.\r\nWie Jakob in den Tagen einst\nmit Gottes Engel rang,\nso kam ich einst zu meinem Herrn\nund wartete nicht lang.\r\nWenn Satan kommt dann sagt er mir:\n"Gott hört nicht dein Gebet."\nDoch "Preis dem Herrn!" es ist vollbracht,\nund Jesus in mir lebt.\r\nSolange ich auf Erden bin,\nformt Er in mir sein Bild.\nDer Abschluss ist ein neuer Leib,\nmein Sehnen wird gestillt.\r\nBevor ein Stern am Himmel war,\nhat Gott uns schon geseh\'n.\nSo sprech\' ich aus, was Sein Wort sagt,\nund Er lässt es gescheh\'n.'),
(9, '1931', 'Wenn wir einst gehn mit dem Herrn in die Herrlichkeit  -  When with the Saviour we enter the Gloryland   (Wird es nicht herrlich dort sein)', 'When with the Saviour we enter the glory land.\nWon\'t it be wonderful there?\nEnded the troubles and cares of the story land.\nWon\'t it be wonderful there?\r\nWon\'t it be wonderful there?\nHaving no burdens to bear.\nJoyously singing, with heartbells all ringing.\nWon\'t it be wonderful there?\r\nWalking and talking with Christ, the Supernal One.\nWon\'t it be wonderful there?\nPraising, adoring the Matchless Eternal One.\nWon\'t it be wonderful there?\r\nThere where the tempest will never be sweeping us.\nWon\'t it be wonderful there?\nSure that forever the Lord will be keeping us.\nWon\'t it be wonderful there?\r\nYou meet they, there names stands in the book.\nWon\'t it be wonderful there?\nAll the names written by His hand.\nWon\'t it be wonderful there?', 'Wenn wir einst geh\'n mit dem Herrn in die Herrlichkeit.\nWird es nicht herrlich dort sein?\ndann ist vorbei was bedrückt uns zur Erdenzeit.\nWird es nicht herrlich dort sein?\r\nWird es nicht herrlich dort sein,\nwenn wir sind endlich daheim?\nLoblieder klingen, wenn wir einst dort singen.\nO, wird es nicht herrlich dort sein?\r\nWenn wir bei Christus sind für alle Ewigkeit.\nWird es nicht herrlich dort sein?\nUnd Ihn anbeten, der uns aus der Sünd\' befreit.\nWird es nicht herrlich dort sein?\r\nDort, wo der Sturm des Lebens uns nicht erreicht.\nWird es nicht herrlich dort sein?\nWo uns der Heiland nie mehr von der Seite weicht.\nWird es nicht herrlich dort sein?\r\nDort, wo du jeden triffst, der in dem Buche stand.\nWird es nicht herrlich dort sein?\nAlle die Namen geschrieben von Seiner Hand.\nWird es nicht herrlich dort sein?'),
(9, '1932', 'Wenn wir vollendet am Throne Gottes stehn   (Herrlich verklärt, Halleluja)', '\r\nGlory, glory, hallelujah!\nGlory, glory, hallelujah!\nGlory, glory, hallelujah!\nHis truth is marching on.\r\n\r\n\r\n', 'Wenn wir vollendet am Throne Gottes steh\'n,\nalle gewaschen in Jesu Blut uns seh\'n,\nalle gekleidet in Leinen weiß und rein.\nO, wie wird uns dann sein!\r\nHerrlich verklärt, Halleluja!\nHerrlich, herrlich, Halleluja!\nHerrlich verklärt, Halleluja!\nAuf ewig daheim!\r\nWenn wir vollendet am Throne Gottes steh\'n,\njubelnd und jauchzend auf gold\'nen Gassen geh\'n,\nalle vergessen der Erde Leid und Pein.\nO, wie wird uns dann sein!\r\nWenn wir vollendet am Throne Gottes steh\'n,\nstaunend den Reichtum der Gnade an uns seh\'n,\ndie uns erhoben ins Paradies hinein.\nO, wie wird uns dann sein!\r\nNoch uns umhüllet der Erde Pilgerkleid,\ndoch uns\'re Heimat ist droben uns bereit;\ngläubig erblicken wir schon den lichten Schein,\nbald werden wir dort sein!'),
(9, '1933', 'Wenn wir wandeln im Herrn, Gottes Wort unser Stern  -  When we walk with the Lord in the light of His Word   (Folgen und Traun wird zum Siegen und Schaun)', 'When we walk with the Lord in the light of His Word,\nwhat a glory He sheds on our way!\nWhile we do His good will, He abides with us still,\nand with all who will trust and obey.\r\nTrust and obey, for there\'s no other way,\nto be happy with Jesus, but to trust and obey.\r\nNot a shadow can rise, not a cloud in the skies,\nbut His smile quickly drives it away.\nNot a doubt or a fear, not a sigh or a tear,\ncan abide while we trust and obey.\r\nNot a burden we bear, not a sorrow we share,\nbut our toil He doth richly repay.\nNot a grief or a loss, not a frown or a cross,\nbut is blessed if we trust and obey.\r\nBut we never can prove the delights of His love\nuntil all on the altar we lay.\nFor the favor He shows, for the joy He bestows,\nare for them who will trust and obey.\r\nThen in fellowship sweet we will sit at His feet,\nor we\'ll walk by His side in the way.\nWhat He says we will do, where He sends we will go,\nnever fear, only trust and obey.', 'Wenn wir wandeln im Herrn, Gottes Wort unser Stern,\no, wie schwinden da Dunkel und Grau\'n.\nDenn Er lenkt jeden Schritt, Seine Gnade geht mit\nbei uns allen, die folgen und trau\'n.\r\nFolgen und Trau\'n wird zum Siegen und Schau\'n.\nWillst du Frieden der Seel\', musst du folgen und trau\'n.\r\nNicht ein Schatten entsteht, jede Wolke vergeht,\nwenn Sein Lächeln die Seele erfreut.\nWeder Zweifel noch Schmerz können ängst\'en das Herz,\nwenn wir trau\'n und gehorchen all\'zeit.\r\nUns bedrückt keine Last, die nicht Er auch erfasst,\nauf Ihn dürfen wir allezeit bau\'n.\nEr hat Segen bereit, auch im Kreuz und im Leid,\nwenn gehorsam wir folgen und trau\'n.\r\nUnser Leben und Sein gehört Jesus allein,\nauf dem Brandaltar will Er es schau\'n.\nDenn die Zucht, die Er übt, und die Kraft, die Er gibt,\nsind für die, die Ihm folgen und trau\'n.\r\nEinst wird Er offenbar Seiner wartenden Schar,\ndie den König in Schöne soll schau\'n.\nEinen Platz auf dem Thron, ja, das Reich und die Kron\'\ngibt Er denen, die folgen und trau\'n.'),
(9, '1934', 'Wer auf Gott vertraut, braucht sich nicht zu fürchten   (Denn er hat seinen Engeln befohlen über dir, dass sie dich behüten)   (Psalm 91)', NULL, 'Wer auf Gott vertraut, braucht sich nicht zu fürchten\nvor den Träumen der Nacht und der Einsamkeit.\nEr darf mit Hoffnung in den neuen Tag gehen.\r\nDenn er hat seinen Engeln befohlen über dir,\ndass sie dich behüten.\nDenn er hat seinen Engeln befohlen über dir,\ndass sie dich beschützen Tag und Nacht.\r\nWer auf Gott vertraut, darf sich sicher wissen\nin den Händen der Liebe, die ihn halten.\nEr darf mit Freude Gottes Hilfe sehen.\r\nWer auf Gott vertraut, kann sich glücklich schätzen.\nEinen Weg muss er nicht alleine gehen.\nVon Gottes Liebe weiß er sich umgeben.'),
(9, '1935', 'Wer da will der nehme, hört es doch  -  Whosoever heareth, shout, shout the Sound   (Wer da will, komm her)', 'Whosoever heareth, shout, shout the sound!\nSpread the blessèd tidings all the world around.\nSpread the joyful news wherever man is found:\nwhosoever will may come.\r\nWhosoever will, whosoever will,\nsend the proclamation over vale and hill.\n’Tis a loving Father, calls the wanderer home:\nwhosoever will, may come.\r\nWhosoever cometh need not delay,\nnow the door is open, enter while you may.\nJesus is the true, the only Living Way,\nwhosoever will may come.\r\nWhosoever cometh need not delay,\nnow the door is open, enter while you may.\nJesus is the true, the only Living Way,\nwhosoever will may come.', 'Wer da will, der nehme! Hört es doch!\nO verkündigt\'s allen, allen Menschen noch,\nallen, die da tragen schwer am Sündenjoch:\nWer da will, der nehme frei!\r\nWer da will, komm her! Wer da will komm her!\nBreitet aus die frohe Botschaft immer mehr,\ndass das Lebenswasser allen offen sei.\nWer da will, der nehme frei!\r\nWer da will, der komme! O, säumet nicht.\nJetzt noch ist es Tag, es scheint das Gnadenlicht.\nJesus ist der Weg, o höret, wie Er spricht:\nWer da will, der nehme frei!\r\nWer da will, der nehme! Ja, dies ist wahr.\nWer da will, dabei wird\'s bleiben immerdar,\nwer da will, o glaubet\'s, glaubet\'s ganz und gar:\nWer da will, der nehme frei!'),
(9, '1936', 'Wer da will, der komm Jesus nimmt dich an  -  Whosoever will to the Lord may come   (2 Chorusse)', 'Whosoever will to the Lord may come.\nWhosoever will to the Lord may come.\nWhosoever will to the Lord may come,\nHe\'ll not turn one away.\r\nJesus heals the broken hearted.\nJesus heals the broken hearted.\nJesus heals the broken hearted.\nHe will set you free.', 'Wer da will, der komm\'! Jesus nimmt dich an.\nWer da will, der komm\'! Jesus nimmt dich an.\nWer da will, der komm\'! Jesus nimmt dich an,\nEr starb für jedermann.\r\nJesus heilt zerbroch\'ne Herzen,\nJesus heilt zerbroch\'ne Herzen,\nJesus heilt zerbroch\'ne Herzen,\nEr macht völlig frei!'),
(9, '1937', 'Wer hat dem Bösen die Macht genommen   (Gnade, so wunderbar, Liebe so unfehlbar)', NULL, 'Wer hat dem Bösen die Macht genommen?\nWer ist so mächtig, liebt so vollkommen.\nDer Herr des Himmels, König der Herrlichkeit.\r\nWer bringt mit Donner die Welt ins Wanken?\nWer lässt uns staunen, auf Knien danken?\nDer Herr des Himmels, König der Herrlichkeit.\r\nGnade, so wunderbar, Liebe so unfehlbar.\nDu trugst das Kreuz für mich, Du nahmst die Schuld auf dich.\nDu gabst Dein Leben hin, damit ich frei sein kann.\nO, Jesus, das alles hast du für mich getan.\r\nWer bringt das Chaos wieder in Ordnung?\nWer macht die Waisen zu seinen Kindern?\nDer Herr des Himmels, König der Herrlichkeit.\r\nWer herrscht mit Weisheit, bringt Recht und Wahrheit,\nstrahlt wie die Sonne in ihrer Schönheit?\nDer Herr des Himmels, König der Herrlichkeit.\r\nWürdig ist das Lamm, das sich gab.\nWürdig ist der Herr, besiegt ist das Grab.\nWürdig ist das Lamm, das sich gab.\nWürdig ist der Herr, besiegt ist das Grab.\nWürdig ist das Lamm, das sich gab.\nWürdig ist der Herr, besiegt ist das Grab.\nWürdig ist das Lamm, das sich gab.\nwürdig, würdig, würdig!'),
(9, '1938', 'Wer Jesus am Kreuze im Glauben erblickt  -  There is Life for a Look at the crucified One   (Sieh, sieh, Sünder, sieh! Wer Jesus am Kreuze im Glauben erblickt)', 'There is life for a look at the crucified One,\nthere is life at this moment for thee.\nThen look, sinner, look unto Him and be saved,\nunto Him who was nailed to the tree.\r\nLook, look, look and live.\nThere is life for a look at the crucified One,\nthere is life at this moment for thee.\r\nO why was he there as the bearer of sin,\nif on Jesus thy sins were not laid?\nO why from his side flowed the sin-cleansing blood,\nif his dying thy debt had not paid?\r\nIt is not thy tears of repentance or prayers,\nbut the blood that atones for the soul.\nOn Him then who shed it thou mayest at once\nthy weight of iniquities roll.\r\n\r\nThen take with rejoicing from Jesus at once\nthe life everlasting He gives.\nAnd know, with assurance, thou need’st never die\nsince Jesus, thy righteousness, lives.', 'Wer Jesus am Kreuze im Glauben erblickt,\nwird heil zu derselbigen Stund\';\nd\'rum blick nur auf Ihn, den der Vater geschickt,\nder einst auch für dich ward verwund\'t.\r\nSieh, sieh, Sünder, sieh!\nWer Jesus am Kreuze im Glauben erblickt,\nwird heil zu derselbigen Stund\'.\r\nO hat nicht Dein Jesus getragen die Schuld,\ngebüßet am Kreuz auch für dich?\nO floss nicht Sein Blut voll erbarmender Huld\nzur Erlösung für dich und für mich?\r\nDein Weinen und deine Gebete sind\'s nicht,\nwodurch du mit Gott wirst versöhnt;\ndas Blut Deines Heilands befreit vom Gericht,\nEr ist\'s, der mit Gnade dich krönt.\r\nO zweifle nicht länger, o glaub es gewiss,\ndu hast nun sonst nichts mehr zu tun;\nDein Jesus, Er trat auch für dich in den Riss,\nin Ihm kannst du seliglich ruh\'n.\r\nSo nimm denn mit Freuden, was Jesus dir beut,\nEr gibt dir das ewige Heil; o glaub es gewiss,\no ergreif\' es noch heut\', so bleibt es dein ewiges Teil!'),
(9, '1939', 'Wer nahm mir alle meine Schuld   (Chorus)', NULL, 'Wer nahm mir alle meine Schuld?\nJesus, Jesus!\nWer schenkte mir des Vaters Huld?\nJesus, mein Heiland!\nJesus, Jesus, wer kann es sein\nals Jesus, Jesus, Jesus, Er allein.'),
(9, '1940', 'Wer sind meine Brüder? Wer die Schwestern mein?', NULL, 'Wer sind meine Brüder?\nWer die Schwestern mein?\nDas sind Christi Glieder,\ndie nur sollen\'s sein.\r\nJene kleine Herde,\ndie den Hirten kennt,\nund Ihn auf der Erde\nIhren Heiland nennt.\r\nJene Gotteskinder,\ndie die Welt verhöhnt,\ndie als Überwinder\neinst der Höchste krönt.\r\nDas sind meine Brüder,\ndas die Schwestern mein,\nimmer sag\' ich\'s wieder,\ndie nur sollen\'s sein.'),
(9, '1941', 'Wer zieht als Sieger durchs Perlentor  -  Some one will enter the Pearly Gate', 'Some one will enter the pearly gate?\nBy and by, by and by.\nTaste of the glories that there await,\nshall you? shall I? Shall you? shall I?\nSome one will travel the streets of gold,\nbeautiful visions will there behold.\nFeast on the pleasures so long foretold:\nShall you? shall I? Shall you? shall I?\r\nSome one will gladly his cross lay down?\nBy and by, by and by.\nFaithful, approved, shall receive a crown,\nshall you? shall I? Shall you? shall I?\nSome one the glorious King will see,\never from sorrow of earth be free.\nHappy with Him thro\' eternity:\nShall you? shall I? Shall you? shall I?\r\nSome one will knock when the door is shut.\nBy and by, by and by.\nHear a voice saying, "I know you not,"\nshall you? shall I? Shall you? shall I?\nSome one will call and shall not be heard,\nvainly will strive when the door is barred,\nsome one will fail of the saint\'s reward:\nShall you? shall I? Shall you? shall I?\r\n', 'Wer zieht als Sieger durchs Perlentor?\nBald, ja bald! Bald, ja bald!\nWer wird begrüßt durch der Engel Chor?\nWirst du es sein, werd\' ich es sein?\nWer wird auf goldenen Straßen geh\'n?\nWer wird mit jauchzenden Scharen steh\'n?\nWer wird den strahlenden König seh\'n?\nWirst du es sein, werd\' ich es sein?\r\nWer ist\'s, der freudig sein Kreuz hinlegt?\nBald, ja bald! Bald, ja bald!\nJubelnd die Krone des Lebens trägt.\nWirst du es sein, werd\' ich es sein?\nWer wird dort wallen im weißen Kleid?\nWer wird vergessen der Erde Leid?\nWer wird erwachen in Herrlichkeit?\nWirst du es sein, werd\' ich es sein?\r\nWer ist\'s, der bang vor dem Throne steht?\nBald, ja bald! Bald, ja bald!\nWer klopfet an, wenn es längst zu spät?\nWirst du es sein, werd\' ich es sein?\nWem wird verlöschen der Hoffnung Licht?\nWer muss es hören, dass Jesus spricht:\n"Weiche von Mir, denn Ich kenn dich nicht!"\nWirst du es sein, werd\' ich es sein?\r\nWer stimmt mit ein in des Lammes Lied?\nBald, ja bald! Bald, ja bald!\nWenn es melodisch zum Throne zieht?\nWirst du es sein, werd\' ich es sein?\nWer knüpft von neuem der Liebe Band?\nWer wallt mit Freuden dort Hand in Hand,\nnie mehr getrennet am gold\'nen Strand?\nWirst du es sein, werd\' ich es sein?\nSome one will sing the triumphant song?\nBy and by, by and by.\nJoin in the praise with the blood-bought throng,\nshall you? shall I? shall you? shall I?\nSome one will greet on the golden shore\nloved ones of earth who have gone before,\nsafe in the glory for evermore:\nShall you? shall I? Shall you? shall I?'),
(9, '1942', 'What a faithful God have I', 'Lord, i come before Your throne of grace\nI find rest in Your presence,\nAnd fullness of Joy\nIn worship and wonder\nI behold Your face\nSinging what a faithful God have I\r\nWhat a faithful God have I\nWhat a faithful God\nWhat a faithful God have I\nFaithful in every way\r\nLord of mercy, You have heard my cry\nThrough the storm Youre the beacon\nMy song in the night\nIn the shelter of Your wings\nHear my hearts reply\nSinging what a faithful God have I\r\nLord all sovereign\nGranting peace from heaven\nLet me comfort those who suffer\nWith the comfort You have given\nI will tell of Your great love\nFor as long as i live\nSinging what a faithful God have I', 'Herr ich komme vor den Thron der Gnade\nIch finde Ruhe in deiner Gegenwart\nund Fülle der Freude\nIn Anbetung und Wunder schaue ich Dein Angesicht\nUnd singe welchen treuen Gott habe ich\r\nWelch ein treuen Gott hab ich\nWelch ein treuen Gott\nWelch ein treuen Gott hab ich\nTreu in Ewigkeit\r\nHerr der Barmherzigkeit du hast meinen Ruf gehört\nim Sturm bis du der Leuchtturm, mein Lied in der Nacht\nIm Schutz deiner Flügel höre mein Herz antworten\nSinge welchen treuen Gott habe ich\r\nHerr der Souveräne der Friede vom Himmel gibt\nLass mich trösten die leiden mit em Trost den du gabst\nIch werde von deiner großen Liebe erzählen\nso lange ich lebe\nSinge welchen treuen Gott habe ich'),
(9, '1943', 'What a lovely Name, the name of Jesus', 'What a lovely name, the name of Jesus,\nreaching higher far, than the brightest star.\nSweeter than the songs they sing in heaven.\nLet the saints proclaim, what a lovely name.\r\nSoon He\'ll come in clouds of glory.\nSaints of every race shall behold His face.\nWith Him enter heaven\'s city,\never to acclaim, what a lovely name.', NULL),
(9, '1944', 'What are you doing for the King   (Take up the Cross to follow Jesus)', 'Take up the cross to follow Jesus.\nTake up the cross every day.\nDon\'t be ashamed to say that you love Him.\nCount the cost, take up your cross and follow Him.\r\nWhat are you doing for the King?\nHave you really given everything?\nTo the One who gave His all for you.\nNow don\'t you be satisfied just to know,\nthat the Lord has saved your soul\nHave you forgotten what you need to do?', NULL),
(9, '1945', 'What does the Cross of Jesus mean   (Just for me, just for me)', 'What does the cross\nof Jesus mean?\nIt\'s more than songs we sing.\nmuch more than that\nemblem on your chain\nbut it means I\'m free\nfrom the chains of slavery\nand the blood that sheds\nwon\'t let my sins remain.\r\nJust for me, just for me,\nJesus came and did it just for me.\nJust for me, just for me,\nJesus came and did it just for me.\r\nUpon the cross my Saviour died,\nthe Lamb was crucified\nShowed us love that this world\nhas never known.\nOh what love devine,\ntruer love you\'ll never find.\nSo that we might live\nLove came and died alone.\r\nWell the cross will always represent\nthe Love God has for me\nWhen the Lord of glory heaven\nsent gave alll on Calvary.\nHe did it just for me, just for me,\nJesus came and did just for me.', NULL),
(9, '1946', 'What will it be when we get over yonder', 'What will it be when we get over yonder\nand join the throng upon the glassy sea.\nWe\'ll join our loved ones\nand crown Christ forever.\nOh this is just what heaven means to me.', NULL),
(9, '1947', 'What would Jesus say', 'What would Jesus say?\nWhat would Jesus do?\nWhere would Jesus go?\nWe\'ve got to go there too.\nHe wants to love them,\nlove them through me and you.\r\nWe must be His voice,\nwe must be His hands,\nwe must show His love,\nso they understand.\nBrothers and sisters,\nwe\'ve got His work to do.\nIt\'s a labor of love.', NULL),
(9, '1948', 'Whatever you need God\'s got it', 'Whatever you need\nGod\'s got it!\nWhatever you need\nGod\'s got it!\nWhatever you need\nGod\'s got it!\nHe\'s got it! And he wants\nto give it to you.\r\nIf you want joy...\nIf you want peace...', NULL),
(9, '1949', 'Whatsoever things are true   (Philipper 4, 8)', 'Whatsoever things are true,\nwhatsoever things are honest,\nwhatsoever things are just are just,\nwhatsoever things are pure are pure,\nwhatsoever things are lovely.\nThings that are of good report,\nif there be any virtue,\nif there be any praise,\nif we desire the mind of Christ,\nLord, help us to think on these things.', NULL),
(9, '1950', 'When darkness veiled th sky   (RISEN! To set the captives free)', 'When darkness veiled the sky, the day that Jesus died,\nin agony upon the bitter cross.\nThe took His body down, and laid it in a tomb,\nhis friends believed that everything was lost.\nBut when the third day came, the darkness turned to light,\nfor Mary heard her name an saw the living Christ.\r\nRISEN! To set the captives free, RISEN! To ransom you and me,\nto bind up every broken heart, to conquer death and sin.\nRISEN! To bring us home again.\r\nAnd in that barren place, the world for ever changed.\nFor hope was born when Jesus rose that day.\nAnd still His wounded hands, reveal the love He has,\nfor every fallen soul He came to save.\nAnd He will come again, and one by one we’ll rise,\nto praise his holy name and see the living Christ.\r\nRISEN! To set the captives free, RISEN! To ransom you and me,\nto bind up every broken heart, to conquer death and sin.\nRISEN! To bring us home again.\nHallelujah! He lives!\nHallelujah! He is RISEN! To set the captives free.\nOh He is RISEN! To ransom you and me,\nto bind up every broken heart, to conquer death and sin.\nRISEN! To bring us home again. RISEN!', 'Als Dunkelheit den Himmel verhüllte, an dem Tag, an dem Jesus unter bitteren Todesqualen am starb.\nSie nahmen seinen Leichnam herunter und legten ihn in ein Grab, seine Freunde glaubten, dass alles verloren sei.\nAber als der dritte Tag kam, wurde die Dunkelheit zum Licht,\ndenn Maria hörte ihren Namen und sah den lebendigen Christus.\r\nAUFERSTANDEN! Um die Gefangenen zu befreien,\nAUFERSTANDEN! Um dich und mich freizukaufen,\num jedes gebrochene Herz zu verbinden,\num Tod und Sünde zu besiegen.\nAUFERSTANDEN! Um uns wieder nach Hause zu bringen.\r\nUnd an diesem kargen Ort hat sich die Welt für immer verändert. Denn die Hoffnung wurde geboren, als Jesus an diesem Tag auferstand.\nUnd noch immer offenbaren Seine verwundeten Hände die Liebe die Er hatte,\nfür jede gefallene Seele, die Er retten wollte.\nUnd Er wird wiederkommen, und einer nach dem anderen werden wir auferstehen,\num Seinen heiligen Namen zu preisen und den lebendigen Christus zu sehen.\r\nAUFSTANDEN! Um die Gefangenen zu befreien,\nAUFSTANDEN! Um dich und mich freizukaufen,\num jedes gebrochene Herz zu verbinden,\num Tod und Sünde zu besiegen.\nAUFERSTANDEN! Um uns wieder nach Hause zu bringen.\nHalleluja! Er lebt!\nHalleluja! Er ist AUFERSTANDEN! Um die Gefangenen zu befreien.\nO, Er ist AUFERSTANDEN! Um dich und mich freizukaufen,\num jedes gebrochene Herz zu verbinden, um Tod und Sünde zu besiegen.\nAUFERSTANDEN! Um uns wieder nach Hause zu bringen. AUFERSTANDEN!'),
(9, '1951', 'When HE was on the cross', 'I\'m not on an ego trip I\'m nothing on my own\nI made mistakes I often slip\nJust common flesh and bones\nBut I\'ll prove someday just why I say\nI\'m of a special kind\nWhen he was on the cross\nI was on his mind\r\nThe look of love was on his face\nThorns were on his head\nThe blood was on his scarlet robe\nStained a crimson red\nThough his eyes were on the crowd that day\nHe looked ahead in time\nCause when he was on the cross\nI was on his mind\r\nHe knew me, yet he loved me\nHe whose glory makes the heavens shine\nSo unworthy of such mercy\nYet when he was on the cross\nI was on his mind', '(Ich bin nicht egoistisch, bin nichts aus mir selbst\nIch mache Fehler und falle oft, einfach Fleisch und Blut\nAber eines Tages zeige ich was ich sage,  ich bin von einer besonderen Art\nAls Er am Kreuz war,  war ich in seinen Gedanken)\r\nDer Blick der Liebe was auf Seinem Gesicht\nDornen auf seinem Haupt, das Blut auf Seinem Gewand,  blutrot getränkt\nObwohl Seine Augen auf die Menge schauten,  blickte Er weit voraus, denn als Er am Kreuz war,  war ich in Seinen Gedanken\r\nEr kannte mich, dennoch liebte er mich\nEr dessen Herrlichkeit die Himmel erleuchtet\nSo unwürdig von solcher Barmherzigkeit\nDennoch,  als Er am Kreuz war, war ich in Seinen Gedanken'),
(9, '1952', 'When I die, gonna live again   (Chorus)', 'When I die, gonna live again!\nSinging glory, hallelujah.\nSanctified, holy on my way to glory.\nWhen I die, gonna live again.', NULL),
(9, '1953', 'When I feel the Touch of Your Hand upon my Life', 'When I feel the touch\nof Your hand upon my life,\nit causes me to sing a song,\nthat I love You, Lord.\nSo from deep within,\nmy spirit sings a song to You,\nYou are my king, You are my God\nand I love You, Lord.', NULL),
(9, '1954', 'When I first found Jesus something o\'er me stole   (I am determined to hold out to the End)', 'When I first found Jesus something o\'er me stole,\nlike lightening it went thru me, and glory filled my soul.\nSalvation made me happy and took my fears away,\nand when I meet old Satan, to him I always say.\r\nI am determined to hold out to the end,\nJesus is with me, on Him I can depend.\nAnd I know I have salvation, for I feel it in my soul,\nI am determined to hold out till the end.\r\nSatan was so angry, said he\'d soon be back,\njust let the path get narrow, and he will lose the track.\nBut I\'m so full of glory, my Lord I always find,\nand I just say to Satan, "Old man, get thee behind".\r\nThis old-time religion makes me sometimes shout,\nI don\'t have time to gossip nor any time to pout.\nThey say that I\'m too noisy, but when these blessings flow,\nI shout, "O hallelujah, I want the world to know."\r\nWhen I hear the trumpet sounding in the sky,\nand see the mountains trembling, to heaven I will fly.\nFor Jesus will be calling, there\'ll be no time to mend,\nwith joy I\'ll go up singing, "I\'ve held out to the end!"', NULL),
(9, '1955', 'When I think of the Goodness of Jesus   (Chorus)', 'When I think of the goodness of Jesus,\nand all He has done for me.\nThen my soul cries out: "Hallelujah,\npraise God for saving me."', NULL),
(9, '1956', 'When it\'s all been said and done', 'When it\'s all been said and done\nThere is just one thing that matters\nDid I do my best to live for truth?\nDid I live my life for you?\r\nWhen it\'s all been said and done\nAll my treasures will mean nothing\nOnly what I\'ve done for love\'s reward\nWill stand the test of time\r\nLord, your mercy is so great\nThat you look beyond our weakness\nAnd find purest gold in miry clay\nTurning sinners into saints\nHallelujah\r\nAnd I will always sing Your praise\nHere on Earth and ever after\nFor You\'ve shown me heavens, my true home\nWhen it\'s all been said and done\nYou\'re my life when life is gone', NULL),
(9, '1957', 'When our faith\'s tried by Fire, we still know that it\'s true   (Jesus we\'re depending on You)', 'When our faith\'s tried by fire,\nwe still know that it\'s true.\nWe know the devil\'s a liar,\nthere\'s not much he can do.\nAnd when he tries hard to stop us,\nwe know that You\'ll see us through,\noh Jesus, we\'re depending on You!\r\nJesus we\'re depending on You,\nJesus we\'re depending on You,\nJesus we\'re depending on You.\nDepending on You to see us through.\r\nWhen they came to the water,\nthey didn\'t know what to do.\nThere was no one to help them,\nthey couldn\'t see their way through.\nThen, Lord, You moved the water,\nand they walked right on through.\nOh, Jesus, we\'re depending on You.', NULL),
(9, '1958', 'When Storms of Life are round me beating   (Alone with God, the world forbidden)', 'When storms of life are round me beating,\nWhen rough the path that I have trod,\nwithin my closet door retreating,\nI love to be alone with God.\r\nAlone with God, the world forbidden,\nalone with God, oh blest retreat!\nAlone with God and in Him hidden,\nto hold with Him communion sweet.\r\nWhat tho\' the clouds have gathered o\'er me?\nWhat tho\' I\'ve passed beneath the rod?\nGod\'s perfect will there lies before me,\nwhen I am thus alone with God.\r\n\'Tis there I find new strength for duty,\nas o\'er the sands of time I plod.\nI see the King in all His beauty,\nwhile resting there alone with God.\r\nAnd when I see the moment nearing\nwhen I shall sleep beneath the sod.\nWhen time with me is disappearing,\nI want to be alone with God.', NULL),
(9, '1959', 'When the great Plants of our Cities   (What then? What then?)', 'When the great plants of our cities\nhave turned out their last finished work,\nwhen our merchants have sold their last yard of goods\nand dismissed the last tired clerk,\nwhen our banks have raked in their last dollar\nand paid the last dividends,\nwhen the judge of the earth says "closed for the night"\nand asks for a balance - What Then?\r\nWhat then? What then?\nWhen the great Book is opened, what then?\nWhen the ones that\'s rejecting this Message tonight,\nwill be asked to give a reason- What Then?\r\nWhen the choir has sung its last song\nand the preacher has said his last prayer,\nwhen the people have heard their last sermon\nand the sound has died out in the air,\nwhen the Bible lies closed on the altar\nand the pews are all empty of folks,\nand each one stands facing his record\nand the great Book is opened - What Then?\r\nWhen the actors have played their last drama\nand the mimic has made his last fun,\nwhen the film has flashed its last film\nand the billboard displayed its last run,\nwhen the crowds seeking pleasure have vanished\nand all the liquor stores and beer joints have been closed,\nand the salesman sold his last drink and gone out in the darkness,\nwhen the trumpet of ages is sounded and we stand before Him -\nWhat Then?\r\nWhen the bugle call sinks into silence\nand the long marching columns stand still,\nand the captain repeats his last orders,\nand the flag has been hauled from the mast,\nand the wounded afield checked in\nand a world that rejects its Saviour\nis asked for a reason - What Then?', NULL),
(9, '1960', 'When the Hosts of Israel led by God   (Victory ahead, Victory ahead)', 'When the hosts of Israel, led by God,\nround the walls of Jericho softly trod.\nTrusting in the Lord, they felt the conqueror\'s tread,\nby faith they saw the victory ahead.\r\nVictory ahead! Victory ahead!\nThrough the blood of Jesus, victory ahead.\nTrusting in the Lord, I hear the conqueror\'s tread,\nby faith I see the victory ahead.\r\nDavid, with a shepherd\'s sling and five stones,\nmet the giant on the field all alone.\nTrusting in the Lord, he knew what God had said,\nby faith he saw the victory ahead.\r\nDaniel prayed unto the Lord thrice each day,\nthen unto the lion\'s den led the way.\nTrusting in the Lord, he did not fear or dread,\nby faith he saw the victory ahead.\r\nOften with the carnal mind I was tried,\nasking for deliverance oft I cried;\nTrusting in the Lord, I reckoned I was dead,\nby faith I saw the victory ahead.\r\nWhen like those who\'ve gone before to that land,\nby death\'s river cold and dark I shall stand.\nTrusting in the Lord, I will not fear or dread,\nby faith I see the victory ahead.', NULL),
(9, '1961', 'When you’re up against a Struggle that shatters all your Dreams   (Praise the Lord! He can work through Those who praise Him)', 'When you’re up against a struggle that shatters all your dreams,\nand your hopes have been cruelly crushed by Satan’s manifested schemes,\nand you feel the urge within you to submit to earthly fears,\ndon’t let the faith you’re standing in seem to disappear.\r\nPraise the Lord! He can work through those who praise Him.\nPraise the Lord! For our God inhabits praise.\nPraise the Lord! For the chains that seem to bind you,\nServe only to remind you that they drop powerless behind you,\nWhen you praise Him.\r\nNow Satan is a liar and he wants to make us think\nthat we are paupers when he knows himself we’re children of the King.\nSo lift up the mighty shield of faith for the battle must be won.\nWe know that Jesus Christ is risen so the work’s already done.', 'Wenn du mit einem Kampf konfrontiert bist der alle deine Träume\nzerschlägt,\nund deine Hoffnungen grausam zerschlagen wurden durch Satans manifestierte Pläne;\nund du den Drang in dir spürst, dich den irdischen Ängsten zu unterwerfen,\ndann lass nicht zu, dass der Glaube, in dem du stehst, zu verschwinden scheint.\r\n(Preis den Herrn! Er kann durch die wirken, die ihn preisen.\nPreis den Herrn! Denn unser Gott wohnt im Lobpreis.\nPreis den Herrn! Denn die Ketten, die dich zu binden scheinen,\ndienen nur dazu dich zu erinnern, dass sie machtlos von dir abfallen, wenn du Ihn preist.)\r\nNun, Satan ist ein Lügner und er will uns glauben machen,\ndass wir Almosenempfänger sind, während er selbst weiß, dass wir Kinder des Königs sind!\nAlso erhebt den mächtigen Schild des Glaubens, denn die Schlacht muss gewonnen werden.\nWir wissen, dass Jesus Christus auferstanden ist, also ist die Arbeit bereits getan.'),
(9, '1962', 'Wherever I go I\'ll praise Him', 'Wherever I go, I\'ll praise Him,\nwhenever I can, I\'ll praise Him,\nfor His love surrounds me like a sea.\nI\'ll praise the name of Jesus,\nlift up the name of Jesus,\nfor the name of Jesus lifted me.', NULL),
(9, '1963', 'Who can cheer the Heart like Jesus   (All that thrills my Soul is Jesus)', 'Who can cheer the heart like Jesus,\nby His presence all divine?\nTrue and Tender, pure and precious,\nOh how blest to call Him mine!\r\nAll that thrills my soul is Jesus,\nHe is more than life to me.\nAnd the fairest of ten thousand,\nin my blessed Lord I see.\r\nLove of Christ so freely given,\ngrace of God beyond degree.\nMercy higher than the heaven,\ndeeper than the deepest sea.\r\nWhat a wonderful redemption!\nNever can a mortal know.\nHow my sin, tho\' red like crimson,\ncan be whiter than the snow.\r\nEvery need His hand supplying,\nEvery good in Him I see.\nOn His strength divine relying,\nHe is all in all to me.\r\nBy the crystal flowing river\nwith the ransomed I will sing.\nAnd forever and forever\npraise and glorify the King.', NULL),
(9, '1964', 'Who is like unto Thee! Oh Lord among the God\'s   (2. Mose 15, 11)', 'Who is like unto Thee\noh Lord among the God\'s?\nWho is like unto Thee,\nglorious in holiness,\nfearful in praises,\ndoing wonders?\nWho is like unto Thee?', 'Herr, wer ist Dir gleich\nunter den Göttern?\nHerr, wer ist Dir gleich,\nherrlich in Heiligkeit,\nEhrfürchtig preisen wir\nDen Gott, der Wunder tut,\nHerr, wer ist Dir gleich?'),
(9, '1965', 'Who you say I am', 'Who am I that the highest King would welcome me?\nI was lost, but He brought me in\nOh His love for me\nOh His love for me\r\nWho the Son sets free\nOh, is free indeed\nI\'m a child of God, yes, I am\r\nFree at last, He has ransomed me\nHis grace runs deep\nWhile I was a slave to sin, Jesus died for me\nYes, He died for me\r\nWho the Son sets free\nOh is free indeed\nI\'m a child of God, yes, I am\nIn my Father\'s house\nThere\'s a place for me\nI\'m a child of God, yes, I am\r\nI am chosen, not forsaken\nI am who You say I am\nYou are for me, not against me\nI am who You say I am\nI am who You say I am\r\nThank God I am free, from this world of sin.\nI am washed in the blood, I’ve been born again.\nThank God I am free, from this world of sin.\nI am washed in the blood, I’ve been born again.', NULL),
(9, '1966', 'Wie bist Du mir so innig gut, mein Hoherpriester, Du', NULL, 'Wie bist Du mir so innig gut,\nmein Hoherpriester, Du!\nWie kräftig spricht Dein teures Blut\nund bringt mein Herz zur Ruh\'.\r\nWenn mein Gewissen zagen will\nvor meiner Sündenschuld,\nso macht Dein Blut mich wieder still,\nsetzt mich bei Gott in Huld.\r\nEs gibt dem schwerbedrückten Sinn\nFreimütigkeit zu Dir,\ndass ich in Dir zufrieden bin,\nwie arm ich bin in mir.\r\nBin ich gestrauchelt hier und da\nund will verzagen fast,\nspür\' Dein Versöhnungsblut ich nah;\ndas nimmt mir meine Last.\r\nEs lindert meinen tiefen Schmerz\ndurch seine milde Kraft,\nes stillet mein verstörtes Herz\nund neuen Glauben schafft.\r\nZieh mich in Dein versöhnend Herz,\nmein Jesus, tief hinein,\nlass es in aller Not und Schmerz\nmir Burg und Zuflucht sein!'),
(9, '1967', 'Wie der Efeu sich rankt um die Mauer   (Chorus)', NULL, 'Wie der Efeu sich rankt um die Mauer,\nso fest will zu Jesus ich steh\'n.\nUnd niemals, nein niemals\nwill ich von Ihm geh\'n.\nUnd niemals, nein niemals\nwill ich von Ihm geh\'n.'),
(9, '1968', 'Wie die Frau am Brunnen dort suchte nach Leben  -  Like the Woman at the Well, I was seeking   (Füll mein Gefäß, Herr)', 'Like the woman at the well, I was seeking,\nfor things that could not satisfy.\nAnd then I heard my Saviour speaking:\n“Draw from My well that never shall run dry.”\r\nFill my cup, Lord, I lift it up Lord!\nCome and quench this thirsting of my soul.\nBread of Heaven, feed me till I want no more.\nFill my cup, fill it up and make me whole.\r\nThere are millions in this world who are seeking,\nfor pleasures earthly goods afford.\nBut none can match the wondrous treasure,\nthat I find in Jesus Christ my Lord.\r\nSo my children if the things this world gave you,\nleave a hunger that just won\'t pass away.\nMy blessed Lord will come and save you,\nif you\'ll kneel to Him and humbly pray.\r\nFull of joy in the Lord I go on,\nHis grace is ever faithful to me.\nI come to the rock and I drink\nwater of life every day anew.', 'Wie die Frau am Brunnen dort suchte nach Leben,\nwar auch ich und suchte in der Welt.\nDoch dann hört ich Ihn freundlich sagen:\n"Komm zum Quell, der nie vertrocknen kann."\r\nFüll\' mein Gefäß, Herr! Ich heb\' es hoch, Herr!\nKomm und still den Durst in meiner Seel\'.\nBrot des Himmels, füll mich bis ich überfließ!\nHier ist mein Kelch, gieß ihn voll und mach mich heil!\r\nMillionen in der Welt jagen täglich\nnach Erfolg, Vergnügen dieser Welt.\nAber nichts kann dem verglichen werden,\nwas ich fand bei Jesus, meinem Herrn.\r\nO mein Freund, warum kommst du nicht zur Quelle,\nauch noch heute fließet sie für dich.\nDenn Er kann retten dich und segnen.\nWeih dich Ihm und bitte Ihn grad\' jetzt.\r\nVoller Freude in dem Herrn geh ich weiter,\nSeine Gnade bleibt mir immer treu.\nIch komm zum Felsen und ich trinke\nLebenswasser jeden Tag aufs neu.'),
(9, '1969', 'Wie ein Born mit frischem Wasser   (Offen stehn die Perlentore für mich in der Herrlichkeit)', NULL, 'Wie ein Born mit frischem Wasser,\nwie Kristall so rein und klar.\nIst die Liebe, Gnad\' und Wahrheit\nin dem Heiland offenbar.\r\nOffen steh\'n die Perlentore\nfür mich in der Herrlichkeit.\nDurch Sein Blut bin ich gerettet\nund bewahrt zur Seligkeit.\r\nEinst wie eine scheue Taube,\ndem gejagten Hirsche gleich.\nFand mich Jesus, und aus Liebe\nführt Er mich ins Himmelreich.\r\nOh welch Wunder aller Wunder!\nEr vergab mir meine Schuld.\nPreisen will ich diesen Jesus\nfür die Liebe, Gnad\' und Huld.\r\nWenn ich einst am Lebensmorgen\ndurch das Perlentor zieh ein.\nDarf das Lamm ich ewig preisen\nund vorm gold\'nen Thron mich freu\'n.'),
(9, '1970', 'Wie ein Hirsch lechzt nach frischem Wasser  -  As the Deer panteth for the Water   (Du allein bist mir Kraft und Schild)', 'As the deer panteth for the water,\nso my soul longeth after Thee.\nYou alone are my heart\'s desire,\nand I long to worship Thee.\r\nYou alone are my strength, my shield;\nTo You alone may my spirit yield.\nYou alone are my heart\'s desire,\nand I long to worship Thee.\r\nYou\'re my friend and you are my brother,\neven though you are my King.\nI love you more than any other,\nso much more than anything.\r\nI want you more than gold and silver,\nonly you can satisfy.\nYou alone are the real joy giver\nand the apple of my eye.', 'Wie ein Hirsch lechzt nach frischem Wasser,\nso sehn’ ich mich Herrn nach Dir.\nAus der Tiefe meines Herzens\nbete ich Dich an, o Herr.\r\nDu allein bist mir Kraft und Schild,\nvon Dir allein sei mein Geist erfüllt.\nAus der Tiefe meines Herzens\nbete ich Dich an, o Herr.\r\nDu, o Herr, bist mir Freund und Bruder,\nDu mein König und mein Gott!\nDich begehre ich mehr als alles,\nso viel mehr als höchstes Gut.\r\nWas bedeuten mir Gold und Silber,\nHerr nur du kannst Erfüllung sein.\nDu allein bist der Freudengeber,\nwurdest mir zum hellen Schein.'),
(9, '1971', 'Wie ein Strom von oben aus der Herrlichkeit  -  Like a River glorious is God’s perfect Peace   (Friede meines Gottes stille tiefe Ruh)', 'Like a river glorious is God’s perfect peace,\nover all victorious, in its bright increase.\nPerfect, yet it floweth fuller every day,\nperfect, yet it groweth deeper all the way.\r\nStayed upon Jehovah, hearts are fully blest,\nfinding, as He promised, perfect peace and rest.\r\nHidden in the hollow of His blessed hand,\nnever foe can follow, never traitor stand.\nNot a surge of worry, not a shade of care,\nnot a blast of hurry touch the spirit there.\r\nEvery joy or trial falleth from above,\ntraced upon our dial by the Sun of Love.\nWe may trust Him fully, all for us to do.\nThey who trust Him wholly find Him wholly true.', 'Wie ein Strom von oben, aus der Herrlichkeit\nfließt der Friede Gottes durch das Land der Zeit.\nTiefer, reicher, klarer strömt er Tag und Nacht\nmit unwiderstehlich wunderbarer Macht.\r\nFriede meines Gottes stille tiefe Ruh\',\nalle meine Sorgen, alles deckst Du zu.\r\nStrömt der Friede Gottes über mich dahin,\nmüssen alle finster\'n Mächte von mir flieh\'n.\nSeine Fluten tragen Hast und Sorge fort.\nFriede meines Gottes, sel\'ger Ruheort.\r\nWechselt auch hienieden Licht und Schatten ab,\nstrahlt doch meine Sonne warm auf mich herab.\nWunderbar getragen von der Friedensflut\nsing ich froh dem Ew\'gen: "Herr wie hab ich\'s gut"'),
(9, '1972', 'Wie ein Wunder beglückt mich der Heilige Geist  -  What a wonderful Change in my Life has been wrought   (Seit Jesus mir kam in das Herz)   [Pfingstjubel]', 'What a wonderful change in my life has been wrought,\nsince Jesus came into my heart!\nI have light in my soul for which long I have sought,\nsince Jesus came into my heart!\r\nSince Jesus came into my heart,\nsince Jesus came into my heart,\nfloods of joy o\'er my soul like the sea billows roll;\nsince Jesus came into my heart.\r\n\r\n\r\nI have ceased from my wand\'ring and going astray,\nsince Jesus came into my heart!\nAnd my sins, which were many, are all washed away,\nsince Jesus came into my heart!\r\nI shall go there to dwell in that city, I know,\nsince Jesus came into my heart!\nAnd I\'m happy, so happy, as onward I go,\nsince Jesus came into my heart!', 'Wie ein Wunder beglückt mich der Heilige Geist,\nseit Jesus mir kam in das Herz.\nEs beseelt mich der Tröster, den Gott uns verheißt,\nseit Jesus mir kam in das Herz.\r\nSeit Jesus mir kam in das Herz,\nseit Jesus mir kam in das Herz,\nbin ich froh allerwärts auch bei Trübsal und Schmerz;\ndenn Jesus erfüllt jetzt mein Herz.\r\nWie ist alles verwandelt der Geist ist nun da,\nseit Jesus mir kam in das Herz.\nO wie habe ich meinen Erlöser so nah,\nseit Jesus mir kam in das Herz.\r\nWelch ein köstliches Lebensglück ward mir zuteil,\nseit Jesus mir kam in das Herz.\nIch empfing da auf einmal ein völliges Heil,\nseit Jesus mir kam in das Herz.\r\nAch wie hat doch die Sünde mich einstmals beschwert,\neh Jesus mir kam in das Herz.\nDoch der Geist hat mir hell die Erlösung verklärt,\nals Jesus mir kam in das Herz.\r\nWelche Wonne, welch Friede beseligt mich jetzt,\nseit Jesus mir kam in das Herz.\nIn das Himmelreich bin ich gar gnädig versetzt,\nseit Jesus mir kam in das Herz.'),
(9, '1973', 'Wie Er ist, seh ich den Heiland  -  Face to Face with Christ, my Saviour   (Wie Er ist, werd ich Ihn sehen)   [Siegesklänge]', 'Face to face with Christ, my Saviour,\nface to face - what will it be.\nWhen with rapture I behold him,\nJesus Christ who died for me?\r\nFace to face I shall behold him,\nfar beyond the starry sky.\nFace to face in all his glory,\nI shall see him by and by.\r\nOnly faintly now I see him\nwith the darkened veil between.\nBut a blessed day is coming\nwhen his glory shall be seen.\r\nWhat rejoicing in his presence,\nwhen are banished grief and pain.\nWhen the crooked ways are straightened\nand the dark things shall be plain.\r\nFace to face - oh, blissful moment!\nFace to face - to see and know.\nFace to face with my Redeemer,\nJesus Christ who loves me so.', 'Wie Er ist, seh\' ich den Heiland,\nwie Er ist, was wird es sein,\nwenn verklärt ich vor Ihm stehe,\nder für mich einst trug die Pein.\r\nWie Er ist, werd\' ich Ihn sehen,\nschau\'n Sein strahlend Angesicht.\nWie Er ist, so hold, so herrlich,\nseh\' ich Ihn im ew\'gen Licht.\r\nBei Ihm ist der Freuden Fülle,\nLeid und Schmerzen sind nicht mehr.\nAlles Dunkel ist verschwunden,\ndenn des Himmels Licht ist Er.\r\nAm kristall\'nen Strom des Lebens\nmit der bluterkauften Schar\nbringe ich dem Lamme Gottes\nLob und Ehre immerdar.\r\nIhn zu sehen, welche Wonne,\nwelch Erkennen wird das sein!\nJesus, Du mein teurer Heiland,\nich bin Dein und Du bist mein.'),
(9, '1974', 'Wie groß bist Du, Herr, wie groß Dein Erbarmen  -  How great are You Lord, how great is your Mercy', 'How great are You, Lord,\nhow great is your mercy,\nhow great are the things\nthat You have done for me.\nHow great are You, Lord,\nYour lovingkindness\nis filling my heart, as I sing:\nHow great are You, Lord.\r\nHow great is Your love,\nit reaches to the heavens,\nhow great is the heart\nthat sought and rescued me,\nhow great are You, Lord,\nYour Loving kindness\nis filling my heart, as I sing:\nHow great are You, Lord.', 'Wie groß bist Du, Herr,\nwie groß Dein Erbarmen,\nwie groß ist all\' das,\nwas Du für mich getan,\nwie groß bist Du, Herr,\nund Deine Liebe\nerfüllt nun mein Herz, und ich sing:\nWie groß bist Du, Herr!\r\nWie groß Deine Lieb,\nsie reicht bis an den Himmel,\nwie groß ist Dein Herz,\ndas sucht\' und rettet mich,\nwie groß bist Du, Herr,\nund Deine Liebe\nerfüllt nun mein Herz, und ich sing:\nWie groß bist Du, Herr!'),
(9, '1975', 'Wie groß ist des Allmächtgen Güte!', NULL, 'Wie groß ist des Allmächt\'gen Güte!\nIst der ein Mensch, den sie nicht rührt,\nder mit verhärtetem Gemüte\nden Dank erstickt, der Ihm gebührt?\nNein, seine Liebe zu ermessen,\nsei ewig meine größte Pflicht.\nDer Herr hat mein noch nie vergessen,\nvergiss, mein Herz, auch Seiner nicht!\r\nWer hat mich wunderbar bereitet?\nDer Gott, der meiner nicht bedarf.\nWer hat mit Langmut mich geleitet?\nEr, dessen Rat ich oft verwarf.\nWer stärkt den Frieden im Gewissen?\nWer gibt dem Geiste neue Kraft?\nWer lässt mich so viel Glück genießen?\nIst´s nicht Sein Arm, der alles schafft?\r\nSchau, o mein Geist, in jenes Leben,\nzu welchem du erschaffen bist,\nwo du, mit Herrlichkeit umgeben,\nGott ewig sehn wirst, wie Er ist.\nDu hast ein Recht zu diesen Freuden,\ndurch Gottes Güte sind sie dein.\nSieh, darum musste Christus leiden,\ndamit du könntest selig sein.\r\nUnd diesen Gott sollt ich nicht ehren\nund Seine Güte nicht versteh\'n?\nEr sollte rufen, ich nicht hören,\nden Weg, den Er mir zeigt, nicht geh\'n?\nSein Will\' ist mir in\'s Herz geschrieben,\nSein Wort bestärkt Ihn ewiglich:\nGott soll ich über alles lieben\nund meinen Nächsten gleich als mich.\r\nDies ist mein Dank, dies ist Sein Wille,\nich soll vollkommen sein wie Er.\nSolang ich dies Gebot erfülle,\nstell ich Sein Bildnis in mir her.\nLebt Seine Lieb\' in meiner Seele,\nso treibt sie mich zu jeder Pflicht;\nund ob ich schon aus Schwachheit fehle,\nherrscht doch in mir die Sünde nicht.\r\nO Gott, lass Deine Güt\' und Liebe\nmir immerdar vor Augen sein!\nSie stärk\' in mir die guten Triebe,\nmein ganzes Leben Dir zu weih\'n;\nsie tröste mich zur Zeit der Schmerzen;\nsie leite mich zur Zeit des Glücks;\nund sie besieg\' in meinem Herzen\ndie Furcht des letzten Augenblicks.'),
(9, '1976', 'Wie groß ist mein Gott, kein anderer wie Er  -  How great is our God! How great is His Word!', 'How great is our God! How great is His Word!\nHe\'s the greatest one that ever was heard.\nHe rolled back the waters of the mighty Red Sea,\nand He said: "I will lead you, put your trust in Me."\r\nWhen I consider the works of my God,\nthe moon and the stars, the path that He trod,\nthe sheep and the oxen, the beast of the field,\nall of these wonders make me know that He\'s real.\r\nHe used our prophet in many a way\nto show forth His greatness in this our day.\nHe never changes, He\'s always the same,\nso worship and praise Him and love His dear name.', 'Wie groß ist mein Gott, kein anderer wie Er,\nkein Name so hoch, nur Er ist der Herr!\nEr teilte die Fluten vom Roten Meer,\nhat auch heute noch dieselbe Kraft,\nnichts ist Ihm zu schwer.\r\nWenn ich seh\' auf das, was mein Gott ersann,\ndie Sterne, der Mond zieh\'n ihre Bahn.\nDie Tiere im Felde, die Blumen im Gras;\nall dies\' zeigt mir Seine große Macht\nmein Gott ist real!\r\nAuch seh\'n wir Ihn heut\', Er tut sich uns kund,\nzeigt uns Seine Kraft, durch des Propheten Mund.\nDenn Er ist derselbe für allezeit.\nJa wir lieben und wir ehren Ihn: Preis sei Seinem Nam\'.'),
(9, '1977', 'Wie lang ist es her, seit du sprachst mit dem Herrn  -  How long has it been, since you talked with the Lord   (Kennst du Ihn als den Freund)', 'How long has it been, since you talked with the Lord,\nand told Him your hearts hidden secrets?\nHow long since you prayed,\nhow long since your stayed on your knees,\ntill the light shone through?\nHow long has it been, since your mind felt at ease?\nHow long since your heart knew no burden?\r\nCan you call Him your friend?\nHow long has it been,\nsince your knew that He cares for you?\r\nHow long has it been, since you knelt by your bed\nand prayed to the Lord up in heaven?\nHow long since you knew, that He\'d answer you\nand would keep you the long night through?\nHow long has it been, since you woke with the dawn,\nand felt, that the day\'s worth living?', 'Wie lang ist es her, seit du sprachst mit dem Herrn,\nund hast ihm dein Herz ausgeschüttet?\nWann hast du gefleht in deinem Gebet\nauf den Knien, bis die Sonne schien?\nWie lang ist es her, dass die Seele voll Fried\',\nwie lang dass du frei warst von Sorgen?\r\nKennst du Ihn als den Freund?\nWie lang ist es her,\ndass du wusstest, dass er dich liebt?\r\nWie lang ist es her, seit du knietest bei Nacht\nallein vor dem Vater im Himmel?\nWann warst du gewiss, dass er dich erhört\nund durch Dunkel dich sicher führt?\nWie lang ist es her, dass du früh vor dem Tag\ndich weihtest, nur für Gott zu leben?'),
(9, '1978', 'Wie lieblich Herr ist Deine Wohnung', NULL, 'Wie lieblich, Herr, ist Deine Wohnung,\nich sehn\' mich nach dem Vorhof des Herrn.\nMein Herz und mein Leib singt vor Freude,\ndem lebend\'gen Gott.\nDu bist mein König allein.\r\nWohl denen, die in Dir sich stärken\nund erneuern in Dir Ihre Kraft.\nWohl dem, der auf Dich baut\nund in Nöten auf den Herrn vertraut.\nDem bist Du Sonne und Schild.\r\nWie lieblich ist\'s in Deiner Nähe.\nVoller Ehrfurcht neigt mein Herz sich vor Dir.\nHerr, empfange Lob und Preis,\nalle Ehre dem lebend\'gen Gott.\nDu bist mein König und Gott.'),
(9, '1979', 'Wie sehr hat Gott die Welt geliebt, die Sünder allzumal  -  God loved the World of Sinners lost   (Welche Lieb, o welche Lieb)', 'God loved the world of sinners lost\nand ruined by the fall.\nSalvation full, at highest cost,\nHe offers free to all.\r\nO ‘twas love, ‘twas wondrous love,\nthe love of God to me.\nIt brought my Saviour from above,\nto die on Calvary!\r\nE’en now by faith I claim Him mine,\nthe risen Son of God.\nRedemption by His death I find,\nand cleansing through the blood.\r\nLove brings the glorious fulness in,\nand to His saints makes known.\nThe blessèd rest from inbred sin,\nthrough faith in Christ alone.\r\nBelieving souls, rejoicing go,\nthere shall to you be given.\nA glorious foretaste, here below,\nof endless life in Heaven.', 'Wie sehr hat Gott die Welt geliebt,\ndie Sünder allzumal;\nein freies, volles Heil Er gibt,\nErlösung vor dem Fall.\r\nWelche Lieb\', o welche Lieb\',\ndass solches mir geschah!\nMein Heiland starb aus freiem Trieb\nfür mich auf Golgatha.\r\nIm Glauben spricht mein Herze nun:\nO Heiland, Du bist mein!\nIn Deinem Tode kann ich ruh\'n,\nDein Blut, Herr, macht mich rein.\r\nIhr Seelen, die ihr Jesu glaubt,\ngeht hin und freuet euch:\nDer Herr gibt euch, was niemand raubt,\nSein eigen Himmelreich.\r\nO, singt vom Sieg durch Jesus Christ,\no, singt hienieden schon;\nund wenn es hier vollendet ist,\nsingt ewig vor dem Thron!'),
(9, '1980', 'Wie süß ist\'s doch, wenn im Gebet  -  Sweet Hour of Prayer, sweet Hour of Prayer   [Gebhardt]', 'Sweet hour of prayer! sweet hour of prayer!\nthat calls me from a world of care,\nand bids me at my Father\'s throne\nmake all my wants and wishes known.\nIn seasons of distress and grief,\nmy soul has often found relief,\nand oft escaped the tempter\'s snare\nby thy return, sweet hour of prayer!\r\nSweet hour of prayer! sweet hour of prayer!\nthe joys I feel, the bliss I share\nof those whose anxious spirits burn\nwith strong desires for Thy return!\nWith such I hasten to the place\nwhere God my Saviour shows His face,\nand gladly take my station there,\nand wait for thee, sweet hour of prayer!\r\nSweet hour of prayer! sweet hour of prayer!\nThy wings shall my petition bear\nto Him, whose truth and faithfulness\nengage the waiting soul to bless.\nAnd since He bids me seek His face,\nbelieve His word, and trust His grace,\nI\'ll cast on Him my every care,\nand wait for thee, sweet hour of prayer!', 'Wie süß ist\'s doch, wenn im Gebet\nmich hehre Himmelsluft umweht!\nDa flieg ich an des Vaters Herz\nund klag Ihm allen meinen Schmerz!\nDann, wenn auch Dunkel mich umhüllt\nund Feinde um mich toben wild,\nwenn Jesu Arm mich sanft umfäht,\nbeströhmt mich Ruhe im Gebet.\r\nWie süß ist\'s doch, wenn im Gebet\ndes Heilands Bild recht vor mir steht,\nwenn Er voll Wahrheit, Lieb und Treu\nmir sagt, dass Er mir gnädig sei.\nWenn Er zum Herzen fort und fort\nspricht: "Glaub\' und halt\' dich nur ans Wort!"\nSo traue ich Ihm früh und spät\nund harre seiner im Gebet.\r\nWie süß ist\'s doch, wenn im Gebet\nauf Glaubensflügeln hoch erhöht\nmein Herz mit fröhlich klarem Blick\nim Tode schaut der Sel\'gen Glück!\nDann leg ich ab mein Pilgerkleid\nund jauchze in der Herrlichkeit,\nwohin durch Jesus einzig geht\nmein täglich Sehnen und Gebet.'),
(9, '1981', 'Wie tief kann ich fallen, wenn alles zerfällt', NULL, 'Wie tief kann ich fallen, wenn alles zerfällt,\nwenn Brücken und Stützen verschwinden?\nWie lang muss ich laufen auf dieser Welt,\num sicheren Boden zu finden?\nNie tiefer als in Gottes Hand,\nnie länger als in Seiner Nähe.\nNie bau\' ich mein Leben auf Sand,\nwenn ich jeden Schritt mit Ihm gehe.\r\nWie frei kann ich werden? Man hält sich für frei\nund hört doch nicht auf sich zu binden.\nWie klar kann ich sehen? Wer hilft mir dabei,\ndas Ziel meines Lebens zu finden?\nNie freier als in Gottes Hand,\nnie klarer als in Seiner Nähe.\nNie bau\' ich mein Leben auf Sand,\nwenn ich jeden Schritt mit Ihm gehe.\r\nWie weit kann ich denken? Wie komm ich dahin,\nnicht nur für mich selber zu leben?\nWie gut kann ich helfen, wenn and\'re sich müh\'n,\nden Berg ihrer Sorgen zu heben?\nNie weiter als in Gottes Hand,\nnie besser als in seiner Nähe.\nNie bau\' ich mein Leben auf Sand,\nwenn ich jeden Schritt mit Ihm gehe.'),
(9, '1982', 'Wie tief muss Gottes Liebe sein  -  How deep the Father’s Love for us', 'How deep the Father’s love for us,\nhow vast beyond all measure.\nThat He should give His only Son\nto make a wretch His treasure.\r\nHow great the pain of searing loss,\nthe Father turns His face away.\nAs wounds which mar the Chosen One\nbring many sons to glory.\r\nBehold the man upon a cross,\nmy sin upon His shoulders.\nAshamed, I hear my mocking voice\ncall out among the scoffers.\r\nIt was my sin that held Him there,\nuntil it was accomplished.\nHis dying breath has brought me life,\nI know that it is finished.\r\nI will not boast in anything,\nno gifts, no power, no wisdom.\nBut I will boast in Jesus Christ,\nHis death and resurrection.\r\nWhy should I gain from His reward?\nI cannot give an answer.\nBut this I know with all my heart,\nHis wounds have paid my ransom.', 'Wie tief muss Gottes Liebe sein,\nEr liebt uns ohne maßen.\nHat seinen Sohn an unsrer Statt\nfür alles büßen lassen.\r\nAls alle Sünde auf ihm lag,\nder Vater sein Gesicht verbarg.\nAls Er, der Auserwählte starb,\ngab Er uns neues Leben.\r\nIch schaue auf den Mann am Kreuz,\nkann meine Schuld dort sehen.\nUnd voll Beschämung sehe ich\nmich bei den Spöttern stehen.\r\nFür meine Sünden hing er dort,\nsie brachten ihm ums Leben.\nSein Sterben hat sie ausgelöscht\nich weiß, mir ist vergeben.\r\nIch werde keiner Macht der Welt\nund keiner Weisheit trauen.\nAuf Jesu Tod und Aufersteh\'n\nwill ich mein Leben bauen.\r\nIch hab\' das alles nicht verdient,\nich leb\' durch seine Gnade.\nSein Blut bezahlte für meine Schuld,\ndamit ich Leben habe.'),
(9, '1983', 'Wieder und wieder nimmt Er mich und formt mich (Leer und zerbrochen kam ich zurück zu Ihm  -  Empty and broken I came back to Him)', 'Empty and broken I came back to Him,\na vessel unworthy so scarred with sin.\nBut He did not dispair He started over again;\nand I bless the day He didn\'t throw the clay away.\r\nOver and over, He molds me and makes me,\ninto His likeness, He fashions the clay.\nA vessel of honor, I am today.\nAll because Jesus didn\'t throw the clay away.\r\nHe is the potter and I am the clay,\nmolded in His image He wants me to stay.\nBut when I stumble and fall and vessel breaks.\nHe just picks up the pieces, He doesn\'t throw the clay away!', 'Leer und zerbrochen kam ich zu Ihm zurück,\nbeschmutzt von der Sünde, die niemals bringt Glück.\nDoch er ließ mich nicht liegen, Er begann wieder neu;\nund gesegnet bin ich heut\', denn Er blieb dem Ton doch treu.\r\nWieder und wieder nimmt er mich und formt mich,\nhinein in sein Bildnis, drückt er diesen Ton.\nEin Gefäß Seiner Ehre, darf ich heute sein.\nDu mein Jesus, hältst mich fest, bis wie Du, Herr, ich darf sein.\r\nEr ist der Töpfer, der Ton, das bin ich;\ngeformt in Sein Bildnis will Er sehen mich.\nWenn ich strauchle und falle, mein Gefäß ganz zerbricht.\nNimmt Er wieder auf die Stücke, Seinen Ton verlässt Er nicht!'),
(9, '1984', 'Wieder zurück zu der Bibel  -  Back to the blessed old Bible   (Wieder zurück zu der Bibel, hin zu dem Licht in dem Wort)', 'Back to the blessed old Bible,\nback to the city of God.\nBack to the oneness of heaven,\nback where the faithful have trod.\nBack from the land of confusion,\npassing the wrecks and the creeds.\nBack to the light of the morning,\nJesus our Captain leads.\r\nBack to the blessed old Bible,\nback to the light of its word.\nBe on our banners forever:\n“Holiness unto the Lord.”\r\nBack to the blessed old Bible,\nsaints of Jehovah, rejoice.\nJesus is calling His people\nback to the land of their choice.\nOften our fathers have sought it\nwhile we in Babel abode.\nNow we have found the fair city,\nchurch of the living God.\r\nBack to the blessed old Bible,\nleaving confusion and strife.\nFleeing from Babel to Zion,\nback to the joy of our life.\nOver the mountains we wandered,\nlooking in vain for the right.\nNow in the evening we’ve found it:\nTruth of the gospel light.\r\nBack to the blessed old Bible,\nback at the Master’s call.\nBack to the words of our Saviour,\nloving, obeying them all.\nNever in sects to be scattered,\nnever again to do wrong.\nUnity, holiness, heaven,\never shall be our song.', 'Wieder zurück zu der Bibel,\nzu der Stadt Gottes zurück,\nhin zu der Einheit des Himmels,\no welch ein seliges Glück!\nWieder zurück aus Verwirrung,\ndort ist viel totes Gestein;\nhin zu dem Lichte des Morgens\nJesus führt die Gemeind\'.\r\nWieder zurück zu der Bibel,\nhin zu dem Licht in dem Wort,\nunsere Losung sei immer:\nHeilig dem Herrn immerfort.\r\nWieder zurück zu der Bibel:\nDas nur den Heiland erfreut;\nJesus nun rufet die Seinen;\nfolgt seiner Stimme noch heut\'!\nOft uns\'re Väter sich sehnten,\nals sie in Babel gewohnt;\nwir nun das Zion erreichten,\nwo wahre Einheit thront.\r\nWieder zurück zu der Bibel,\nwo alle Trennung hört auf,\nfliehend aus Babel nach Zion,\no welch gesegneter Lauf!\nO wie schon lange wir suchten,\nsehnten uns so nach dem Licht,\ndoch nun am Abend wir\'s fanden,\nso wie\'s das Wort verspricht.\r\nWieder zurück zu der Bibel,\nfolgend dem Rufe des Herrn,\nhin zu den Worten des Heilands,\ndie wir befolgen so gern.\nNimmer von Ihm mehr zu weichen,\nder uns so herrlich befreit;\nhimmlisches Wesen auf Erden,\no welche Seligkeit!'),
(9, '1985', 'Will gar nichts mehr sein, nichts gelten  -  Oh, to be nothing, nothing', 'Oh, to be nothing, nothing!\nOnly to lie at His feet,\na broken and emptied vessel,\nfor the Master’s use made meet.\nEmptied that He might fill me,\nas forth to His service I go.\nBroken, that so unhindered\nHis life through me might flow.\r\nOh, to be nothing, nothing!\nOnly as led by His hand.\nA messenger at His gateway,\nonly waiting for His command.\nOnly an instrument ready\nHis praises to sound at His will,\nwilling, should He not require me,\nin silence to wait on Him still.\r\nOh, to be nothing, nothing!\nPainful the humbling may be,\nyet low in the dust I’d lay me\nthat the world might my Saviour see.\nRather be nothing, nothing!\nTo Him let their voices be raised:\nHe is the fountain of blessing,\nHe only is meet to be praised.', 'Will gar nichts mehr sein, nichts gelten,\nauf Jesum nur wart ich still,\nwie Er mich, den armen Scherben,\nnoch irgend gebrauchen will.\nEntleert lieg\' ich Ihm zu Füßen,\nbis Er mich erfüllet mit Öl,\ndass einzig sein Leben mög\' fließen\nin Strömen von Leib und von Seel\'.\r\nWill gar nichts mehr sein, nichts gelten,\nEr führ\' mich allein hinfort;\nwill Er mich als Werkzeug brauchen,\nso diene ich Ihm aufs Wort.\nWohin Er mich dann mag senden,\nweih ich Ihm mein Leben zum Preis;\nwill Er, dass mein Schaffen soll enden,\nso ruh\' ich nach Seinem Geheiß.\r\nO selig, nichts sein, nichts gelten,\nmag\'s schwer auch dem Fleisch eingeh\'n,\ngern will ich in Staub mich beugen,\ndass man nur mag Jesum seh\'n.\nIch nichts, Er alles in allem,\nwie quillt dann der Segen so rein!\nLasst jubelnd die Stimme erschallen\nzum Lob und zum Preis Ihm allein!'),
(9, '1986', 'Will ich des Kreuzes Streiter sein und Christo folgen nach  -  Am I a Soldier of the Cross, a Follwer of the Lamb', 'Am I a soldier of the cross,\na foll\'wer of the Lamb,\nand shall I fear to own his cause,\nor blush to speak his name?\r\nMust I be carried to the skies\non flow\'ry beds of ease,\nwhile others fought to win the prize,\nand sailed thro\' bloody seas?\r\nAre there no foes for me to face?\nMust I not stem the flood?\nIs this vile world a friend to grace,\nto help me on to God?\r\nSince I must fight if I would reign:\nincrease my courage, Lord.\nI\'ll bear the toil, endure the pain,\nsupported by thy Word.\r\nThy saints, in all this glorious war,\nshall conquer, though they die.\nThey view the triumph from afar,\nand seize it with their eye.\r\nWhen that illustrious day shall rise,\nand all Thine armies shine.\nIn robes of vict\'ry through the skies,\nthe glory shall be Thine.', 'Will ich des Kreuzes Streiter sein\nund Christo folgen nach,\nund nicht für Jesus stehen ein,\nnicht tragen seine Schmach?\r\nDer Weg ist rot von Zeugenblut;\nsollt ich auf Rosen gehen?\nWo andre einst durchkreuzt die Flut,\nsoll ich am Ufer steh\'n?\r\nGibt\'s keinen Feind, der mir sich stellt?\nKein Werk für meine Hand?\nTrägt mich vielleicht die falsche Welt\nsanft ins gelobte Land?\r\nJa, streiten muss, wer siegen will,\nd\'rum, Heiland gib mir Kraft,\nzu kämpfen recht, zu leiden still\nin treuer Ritterschaft!\r\n\r\n'),
(9, '1987', 'Willkomm\' Heil\'ger Geist wir warten Dein  -  Welcome, Holy Ghost, we welcome Thee   (2 Chorusse)', 'Welcome, welcome, welcome,\nHoly Ghost, we welcome Thee.\nCome with power, this very hour.\nHoly Ghost, we welcome Thee!\r\nWelcome, welcome, welcome,\nHoly Ghost we welcome Thee,\nCome in power and fill Thy temple,\nHoly Ghost we welcome Thee.', 'Willkomm\', willkomm\', willkomm\',\nHeil\'ger Geist wir warten Dein.\nKomm mit Kraft in dieser Stunde.\nHeil\'ger Geist wir warten Dein!\r\nWillkomm\', willkomm\', willkomm\',\nHeil\'ger Geist wir warten Dein.\nKomm mit Kraft, füll\' diesen Tempel.\nHeil\'ger Geist wir warten Dein!'),
(9, '1988', 'Winde wehen über mein Erdenzelt   (Lass die Stürme toben und die Winde wehn)', NULL, 'Winde wehen über mein Erdenzelt,\nGottes Augen durchschau\'n die ganze Welt.\nEr weiß all mein Denken und mein Tun,\nich darf still in Seinen Armen ruh\'n.\r\nLass die Stürme toben und die Winde weh\'n,\nich schau nur nach oben, wo die Sterne steh\'n.\nEinmal ist zu Ende aller Kampf und Streit,\ndann bin ich bei Jesus in der Herrlichkeit.\r\nEinst versank ich tief in dem Sündenschlamm,\nplötzlich hört ich das Wort vom Kreuzesstamm.\nFür mich armen Sünder starb der Herr!\nWelche Gnade, Herz, was willst du mehr.\r\nEine Stunde schlägt bald für Groß und Klein,\ndann wird Gnade nicht mehr zu finden sein,\ndann wird suchen, wer es jetzt verschmäht.\nFreund, o hör, dann ist es schon zu spät.'),
(9, '1989', 'Wir ergreifen alle unsre Waff und Wehr  -  We are marching on with Shield and Banner bright   (Lob und Preis, Lob und Preis)', 'We are marching on with shield and banner bright,\nwe will work for God and battle for the right,\nwe will praise His Name, rejoicing in His might,\nand we’ll work till Jesus calls.\r\nThen awake, then awake, happy song, happy song,\nshout for joy, shout for joy, as we gladly march along.\nWe are marching onward, singing as we go,\nto the promised land where living waters flow.\nCome and join our ranks as soldiers here below,\nand we’ll work till Jesus calls.\r\nFor His army, robed in white we will prepare,\nas we rally round our blessed standard there,\nand the Saviour’s cross we gladly learn to bear,\nwhile we work till Jesus calls.\r\nWe are marching on; our Captain, ever near,\nwill protect us still, His guiding voice we hear.\nLet the foe advance, we’ll never, never fear,\nfor we’ll work till Jesus calls.\r\nWe are happy as we sing the victor’s song,\nhear our shouts of joy - the battle won’t be long.\nIn the Lord of Hosts let every heart be strong,\nwhile we work till Jesus calls.', 'Wir ergreifen alle unsre Waff\' und Wehr\nund versammeln uns um Jesu Banner her.\nIn dem Kampf um Gottes Reich und Gottes Ehr\nwanken wir nicht bis zum Tod.\r\nLob und Preis, Lob und Preis, Kraft und Macht, Kraft und Macht\nsei dem Herrn, sei dem Herrn nun und in der Ewigkeit.\nGottes Volke schließen freudig wir uns an,\nzieh\'n im Glauben hin nach jenem Kanaan,\nwo die Kron\' uns winkt am End\' der Siegesbahn,\nwanken nicht bis in den Tod!\r\nIm Gebet und Worte rüsten wir uns aus\nmit des Geistes Kraft zu jedem schweren Strauß,\nund dann ziehen freudig wir ins Feld hinaus,\nwanken nicht bis in den Tod.\r\nIn dem Kampfgewühl ist Jesus immer nah,\nwenn Gefahr uns droht, ist Er als Helfer da.\nDarum jauchzen wir getrost, Halleluja,\nwanken nicht bis in den Tod.\r\nAuf des Kampfes Ringen folgt die ew\'ge Freud.\nUnd auf Salems Auen schweiget alles Leid.\nDort ist alles, alles Glück und Seligkeit.\nWanket nicht bis in den Tod.'),
(9, '1990', 'Wir erklimmen Jakobs Leiter  -  We ar climbing Jacobs Ladder', 'We are climbing Jacobs ladder,\nwe are climbing Jacobs ladder,\nwe are climbing Jacobs ladder,\nsoldiers of the Lord.\r\nRung by rung, higher and higher,\nrung by rung, higher and higher,\nrung by rung, higher and higher,\nsoldiers of the Lord.\r\nUpward, forward, give God the glory,\nupward, forward,give God the glory,\nupward, forward, give God the glory,\nsoldiers of the Lord.', 'Wir erklimmen Jakobs Leiter,\nwir erklimmen Jakobs Leiter,\nwir erklimmen Jakobs Leiter,\nSoldaten von dem Herrn.\r\nSprosse um Sprosse, höher und höher,\nSprosse um Sprosse, höher und höher,\nSprosse um Sprosse, höher und höher,\nSoldaten von dem Herrn.\r\nAufwärts, scheine, gib Gott die Ehre,\naufwärts, scheine, gib Gott die Ehre,\naufwärts, scheine, gib Gott die Ehre,\nSoldaten von dem Herrn.'),
(9, '1991', 'Wir ernten im Herbst was wir säten   (Ja, wir wissen, es ist Erntezeit)', NULL, 'Wir ernten im Herbst was wir säten,\njeder Same bringt hier seine Frucht,\ndenn jeder wird ernten die Früchte,\ndie er hier in die Erde gelegt.\r\nJa, wir wissen, es ist Erntezeit,\ndenn der Bräut\'gam ist nicht mehr weit.\nLasst uns leben und handeln wie Jesus,\nund so sind auch wir dann bereit.\r\nWir ernten die Worte und Taten,\nwir ernten nur das, was wir sä\'n.\nAlles, was wir hier wirken, bringt Früchte,\ndoch nur Gutes allein\' wird besteh\'n.\r\nMöchten wandeln auf Erden wie Jesus,\njeden Tag woll\'n wir Gutes hier sä\'n,\ndenn wir wissen, wir ernten die Früchte\ndie wir täglich auf Erden hier sä\'n.'),
(9, '1992', 'Wir geben Jesus die Ehre  -  We\'ll give the Glory to Jesus   (Chorus)', 'We\'ll give the glory to Jesus,\nand tell of His love,\nand tell of his love.\nWe\'ll give the glory to Jesus,\nand tell of His wonderful love.', 'Wir geben Jesus die Ehre\nund zeugen von Ihm,\nund zeugen von Ihm.\nWir geben Jesus die Ehre\nund zeugen von Seiner herrlichen Lieb\'.'),
(9, '1993', 'Wir haben einen Felsen, der unbeweglich steht', NULL, 'Wir haben einen Felsen, der unbeweglich steht,\nwir haben eine Wahrheit, die niemals untergeht;\nwir haben Wehr und Waffen in jedem Kampf und Streit,\nwir haben eine Wolke von Gottes Herrlichkeit,\nwir haben eine Wolke von Gottes Herrlichkeit.\r\nWir haben eine Speise, der Welt hier unbekannt,\nwir haben einen Schatten im heißen Sonnenbrand;\nwir haben eine Quelle, die niemals je versiegt,\nwir haben Kraft zum Tragen, die keiner Last erliegt,\nwir haben Kraft zum Tragen, die keiner Last erliegt.\r\nWir haben einen Tröster voll heiliger Geduld,\nwir haben einen Helfer von liebevoller Huld;\nwir haben eine Freude, die niemand von uns raubt,\nwir haben durch die Gnade des Königs Wort geglaubt,\nwir haben durch die Gnade des Königs Wort geglaubt.\r\nWir haben eine Zuflucht in Sturm und jeder Not,\nwir haben einen Reichtum, der nie zu schwinden droht;\nwir haben eine Gnade, die jeden Morgen neu,\nwir haben ein Erbarmen, das mächtig ist und treu,\nwir haben ein Erbarmen, das mächtig ist und treu.\r\nWir haben hier die Fülle, seitdem der Heiland kam,\nwir haben dort ein Erbe so reich und wundersam;\nwir haben Glück, das leuchtend und unbeschreiblich ist,\nwir haben alles, alles in Dir, Herr Jesus Christ,\nwir haben alles, alles in Dir, Herr Jesus Christ.'),
(9, '1994', 'Wir halten fest in dieser Zeit ein Wort, das laut erschallt   (Ja, Jesus kommt, bist du bereit)', NULL, 'Wir halten fest in dieser Zeit\nein Wort, das laut erschallt,\nes tröstet uns in Kampf und Streit:\nSiehe, ich komme bald!\r\nJa, Jesus kommt! Bist du bereit?\nEr kommt gewiss, wir werden bald\nhinweg gerückt aus allem Leid,\nwenn der Posaunenton erschallt!\r\nWeg sind dann Tränen, Angst und Not,\nweg Kummer Schmerz und Leid.\nWir sind dann frei von Sünd\' und Tod\nin alle Ewigkeit.\r\nDort wartet uns verheiß\'ner Lohn,\ndie Freude ewig währt,\nwir schauen Jesum, Gottes Sohn\nin Herrlichkeit verklärt.'),
(9, '1995', 'Wir leben in dem Kommen des Herrn   (O diese Jubelzeit, wir ziehen himmelan)', NULL, 'Wir leben in dem Kommen des Herrn.\nSiehe, der Bräutigam! Ja, es ist wahr,\nSein Kommen begann!\nIst Er nicht wunderbar?\r\nO, diese Jubelzeit, wir ziehen himmelan.\nWas auch kommt, wie es sei,\nuns zieht der Schlussstein an.\r\nEs ist jetzt die Vereinigungszeit\ndurch das lebend\'ge Wort.\nDie Liebe Gottes uns vereint\nin diesem Himmelsort.\r\nEs kann ja jeden Tag gescheh\'n,\nEr holt zu sich die Braut.\nO, willst auch du mit heimwärts geh\'n,\nwarte auf Ihn, das Haupt!'),
(9, '1996', 'Wir maschieren hinüber nach Jerusalem  -  We are marching over to Jerusalem   (Chorus)', 'We are marching over to Jerusalem.\nWe are marching over to Jerusalem.\nJerusalem, Jerusalem,\nJerusalem, Jerusalem.', 'Wir marschieren hinüber nach Jerusalem,\nwir marschieren hinüber nach Jerusalem,\nJerusalem, Jerusalem,\nJerusalem, Jerusalem.'),
(9, '1997', 'Wir rühmen vom himmlischen Lande   (O, wie fein wirds dort sein)', NULL, 'Wir rühmen vom himmlischen Lande,\nvon allen, die schon sind daheim,\nund fühlen als traute Verwandte;\ndoch Seele, wie wird\'s dort erst sein?\r\nO, wie fein wird\'s dort sein!\nO Seele, wie wird\'s dort erst sein!\nO, wie fein wird\'s dort sein!\nO Seele, wie wird\'s dort erst sein!\r\nWir rühmen Jerusalem\'s Schöne,\nsein Gold und sein Edelgestein.\nWir lauschen dem Jubelgetöne;\ndoch Seele, wie wird\'s dort erst sein?\r\nWir rühmen die Liebe, den Frieden,\ndie Kleider, so helle, so rein, die Krone,\nden Siegern beschieden; doch Seele,\nwie wird\'s dort erst sein?'),
(9, '1998', 'Wir schwimmen durch den Strom der Zeit  -  We\'re floating down the Stream of Time   (Nun freu dich, Bruder, freue dich)', 'We\'re floating down the stream of time,\nwe have not long to stay;\nthe stormy clouds of darkness\nwill turn to brightest day.\nThen let us all take courage,\nfor we\'re not left alone;\nthe lifeboat soon is coming\nto gather the Jewels home.\r\nThen cheer, my brother, cheer,\nour trial will soon be o\'er,\nour loved ones we shall meet, shall meet,\nupon the golden shore.\nWe\'re pilgrims and we\'re strangers here,\nwe\'re seeking a city to come,\nthe lifeboat soon is coming,\nto gather the Jewels home.\r\nSometimes the Devil tempts me,\nand says it\'s all in vain.\nTo try to live a Christian life\nand walk in Jesus\' name;\nbut then we hear the Master say,\n"I\'ll lend you a helping hand,\nand if you\'ll only trust Me,\nI\'ll guide you to the land."\r\nThe lifeboat soon is coming,\nby eyes of faith I see.\nAs it sweeps through the waters\nto rescue you and me.\nAnd land us safely in the port\nwith friends we love so dear.\n"Get ready," cries the Captain;\n"oh, look, it\'s almost here."\r\nOh, now\'s the time to get on board,\nwhile it is passing by;\nbut if you stand and wait too long,\nyou shall forever die.\nThe fare is paid for one and all,\nthe Captain bids you come,\nand get on board the lifeboat,\nit\'ll carry you safely home.', 'Wir schwimmen durch den Strom der Zeit,\nhier bleiben wir nicht mehr so lang,\ndie stürm\'schen Wolken der Dunkelheit,\nsie werden zu hellem Tag dann.\nLasst uns denn nun recht mutig sein,\nEr lässt uns ja niemals allein.\nDas Lebensboot, es kommt bald,\nund holt die Juwelen heim.\r\nNun freu\' dich, Bruder, freue dich,\ndie Prüfungen sind bald vorbei,\nuns\'re Lieben werden wir treffen,\ndort an dem gold\'nen Strand.\nWir sind Pilger und auch Fremde hier,\nwir suchen die himmlische Stadt.\nDas Lebensboot, es kommt bald,\nund holt die Juwelen heim.\r\nManchmal versucht der Teufel uns,\nund sagt, es sei alles umsonst,\nder Versuch wie ein Christ zu leben,\nzu wandeln in Jesu Nam\'.\nDann hören wir den Meister:\n"Ich reich\' Dir die helfende Hand,\nund wenn Du mir vertrauen wirst,\ndann bring ich Dich in dies Land."\r\nDas Lebensboot, es kommt bald,\ndurch Augen des Glaubens zu seh\'n,\nes rauscht jetzt durch die Wasser,\nzu retten dich und mich.\nIn den Hafen bringt\'s uns sicher,\nmit lieben Freunden vereint.\nDer Käpt\'n ruft: "Macht fertig euch,\noh, seht, es fährt schon ein."\r\nNun ist die Zeit an Bord zu geh\'n.\njetzt kommt das Boot hier vorbei,\ndoch wenn du unbewegt wartest,\nkommt ew\'ger Tod herbei.\nDie Fahrt hat Er für immer bezahlt.\nDer Käpt\'n, er bittet dich:  "Komm\nan Bord des Lebensbootes,\nnur das bringt sicher dich heim."'),
(9, '1999', 'Wir sind auf der Pilgerreise   (Ein wenig Leiden noch, ein wenig Tränen noch)', NULL, 'Wir sind auf der Pilgerreise\nin ein bess\'res, schön\'res Land.\nGeht es uns nach Pilgerweise,\nwird uns schwer der Pilgerstand;\ngeht es uns nach Pilgerweise,\nwird uns schwer der Pilgerstand.\r\nEin wenig Leiden noch,\nein wenig Tränen noch,\ndann folgt die Ruhe am kristall\'nen Meer.\nDann sind im weißen Kleid,\nwir bei dem Herrn all\'zeit,\nda gibt\'s kein scheiden mehr,\nmach dich bereit.\r\nGeht der Weg auch durch Gefahren,\ndurch manch trübe, schwere Zeit;\nführt er doch zur wunderbaren,\nschönen Himmelsherrlichkeit;\nführt er doch zur wunderbaren,\nschönen Himmelsherrlichkeit.\r\nD\'rum will uns das Kreuz auch drücken,\ntrau\'n wir fest auf Ihn allein.\nLasst uns gläubig dahin blicken,\nwo wir ewig sind Daheim;\nlasst uns gläubig dahin blicken,\nwo wir ewig sind Daheim.'),
(9, '2000', 'Wir sind auf der Reise heim ins bess\'re Land   (Alles, was Odem hat, lobe den Herrn)', NULL, 'Wir sind auf der Reise heim ins bess\'re Land,\ndort, wo Sünd\' und Schmerzen sind ganz unbekannt,\nwo die Engel singen und mit Harfenton,\nDank dem Schöpfer bringen vor dem Gnadenthron.\r\nAlles, was Odem hat, lobe den Herrn,\nja lobe den Herrn, ja lobe den Herrn!\nAlles, was Odem hat, lobe den Herrn!\nEr hilft und errettet so gern.\r\nJesus steht schon wartend vor dem Perlentor.\nEngel Ihn umschweben in dem schönsten Flor.\nVoller Liebe leuchtet mir Sein Angesicht;\nich hör Seine Stimme: "Glaub und fürchte dich nicht!"\r\nMuss ich auch noch wandern, hier im Pilgertal,\neinen Tag zum anderen, ist der Weg auch schmal.\nVoller Freud\' und Loben zeuge ich so gern,\nwie es ist dort oben in dem Lichte des Herrn.');
INSERT INTO song_list (LISTID, NUM, NAME, TEXT_EN, TEXT_DE) VALUES
(9, '2001', 'Wir sind gekommen zu dem großen König Jesus   (Und darum wollen wir Ihn heute hoch erheben)', NULL, 'Wir sind gekommen zu dem großen König Jesus,\ndenn wir haben heute Seinen Stern geseh\'n,\nals wir ihm folgten, führte er uns hin zu Jesus,\ndarum dürfen wir voll Freude vor Ihm steh\'n.\nWir sind gekommen zu dem großen König Jesus,\ndenn Sein Engel hat Sein Kommen kundgetan,\nda gingen wir hin und wir fanden unsren Jesus,\nund wir beten Ihn aus ganzem Herzen an.\r\nUnd darum wollen wir Ihn heute hoch erheben,\nSeine Größe, Seine Majestät und Pracht,\nwir sind gekommen und wir wollen Ehre geben\nunsrem König, der uns bis hierher gebracht.\r\nWir sind gekommen zu dem großen König Jesus,\nunsre Wahrheit, unser Weg und unser Licht,\nin unsren Herzen leuchtet heute unser Jesus,\nEr, der machtvoll unsre Finsternis durchbricht.\nWir sind gekommen zu dem großen König Jesus,\nEr, der Aufgang aus der höchsten Herrlichkeit,\nSein helles Licht scheint über dem, der glaubt an Jesus,\nder uns leuchtet bis in alle Ewigkeit.\r\nWir sind gekommen und wir haben uns entschieden,\ndass die Dinge, die wir glauben, Wahrheit sind,\nwir sind gekommen und wir sind bei Ihm geblieben,\nbei dem König, dem wir treu ergeben sind.\nWir sind gekommen und Er hat sein Herz geöffnet,\nund er hat sich uns in Fülle offenbart,\nund voller Staunen sahen wir: So groß ist Jesus!\nUnd heut\' stehen wir in  Seiner Gegenwart.'),
(9, '2002', 'Wir sind hier im Haus des Herrn versammelt um Ihn anzubeten  -  We\'ve com into His House to magnify His name', 'We have come into His house,\nto magnify His Name and worship Him.\nWe have come into His house,\nto magnify His Name and worship Him.\nWe have come into His house,\nto magnify His Name and worship Christ the Lord,\nworship, Jesus Christ, the Lord.\r\nLet us lift up holy hands,\nmagnify His Name and worship Him.\nLet us lift up holy hands,\nmagnify His Name and worship Him.\nLet us lift up holy hands,\nmagnify His Name and worship Christ the Lord,\nworship, Jesus Christ, the Lord.\r\nSo forget about yourself,\nconcentrate on Him and worship Him.\nSo forget about yourself,\nconcentrate on Him and worship Him.\nSo forget about yourself,\nconcentrate on Him and worship Christ the Lord,\nworship, Jesus Christ, the Lord.', 'Wir sind hier im Haus des Herrn\nversammelt, um Ihn anzubeten.\nWir sind hier im Haus des Herrn\nversammelt, um Ihn anzubeten.\nWir sind hier im Haus des Herrn\nversammelt, um Ihn anzubeten allezeit,\nbetet an, Jesus, unsern Herrn.\r\nWir woll\'n heil\'ge Hände heben\nund ehren Seinen großen Namen.\nWir woll\'n heil\'ge Hände heben\nund ehren Seinen großen Namen.\nWir woll\'n heil\'ge Hände heben\nund ehren Seinen großen Namen allezeit,\nliebet Ihn, Christus, unsern Herrn.\r\nDarum schau nicht mehr auf Dich\nund richte Deinen Blick auf Jesus.\nDarum schau nicht mehr auf Dich\nund richte Deinen Blick auf Jesus.\nDarum schau nicht mehr auf Dich\nund richte Deinen Blick auf Jesus allezeit,\nschau auf Ihn, betet Ihn an.'),
(9, '2003', 'Wir sind hier zusammen, wollen dich erhöhn  -  We are here to praise You', '\r\nWe are here to praise you, to lift our hearts and sing;\nWe are here to give you, the best that we can bring;\nAnd it is our love, rising from our hearts;\nEv’rything within us cries, "Abba, Father";\nHelp us now to give you, Pleasure and delight;\nHeart and mind and will that say, "I love you, Lord".', 'Wir sind hier zusammen, wollen dich erhöh’n,\nsingend auf den Stufen deines Thrones steh’n.\nLiebe und Anbetung Bringen wir vor dich.\nAlles in uns jubelt laut: "Abba, Vater!"\nÖffne unsre Lippen, tu uns auf das Herz.\nDu bist unser guter Herr. Wir lieben dich.\r\n'),
(9, '2004', 'Wir sind Kinder eines Vaters  -  We are Children of the Father', 'We are children of the father,\nwe are joint-heirs with the son.\nWe are people of His kingdom,\nwe\'re a family, we are one.\r\nWe are washed, we are sanctified,\nwe are cleansed by His Blood.\nWe are born of the Spirit,\nwe are children, we are one.\r\nWe are longing for His Coming,\nwe are looking to the skies.\nWe are watching, we are waiting,\nwe shall dwell with Him, we shall rise.', 'Wir sind Kinder eines Vaters,\nsind die Erben mit dem Sohn,\ndie Einwohner Seines Reiches,\nja, Familie von dem Thron.\r\n\r\n'),
(9, '2005', 'Wir sind sein Eigentumsvolk und auf dem Weg nach Haus   (2 Chorusse)', '\r\nHalleluja, Halleluja,\nHalleluja, Halleluja, Halleluja.\nHalleluja, Halleluja,\nHalleluja, Halleluja, Halleluja.', 'Wir sind Sein Eigentumsvolk und auf dem Weg nach Haus.\nHalleluja, Halleluja.\nWir sind Sein Eigentumsvolk und auf dem Weg nach Haus.\nHalleluja, Halleluja.\r\n'),
(9, '2006', 'Wir sind wieder versammelt, zu preisen den Herrn  -  We\'re together again just praising the Lord   (Chorus)', 'We\'re together again, just praising the Lord!\nWe\'re together again, in one accord.\nSomething good is going to happen,\nsomething good is in the store.\nWe\'re together again, just praising the Lord!', 'Wir sind wieder versammelt, zu preisen den Herrn.\nWir sind wieder versammelt, das Volk des Herrn.\nEtwas Gutes ist geschehen, etwas Bess\'res ist bereit.\nWir sind wieder versammelt, zu preisen den Herrn.'),
(9, '2007', 'Wir singen vom himmlischen Land, wo Gottes Volk ziehet hinein   (Doch wie, doch wie, doch, wie wirds der Seele dort sein)', NULL, 'Wir singen vom himmlischen Land,\nwo Gottes Volk ziehet hinein.\nSein Ruhm ist uns allen bekannt;\ndoch, wie wird\'s der Seele dort sein?\r\nDoch wie, doch wie,\ndoch, wie wird\'s der Seele dort sein?\nSein Ruhm ist uns allen bekannt;\ndoch wie wird\'s der Seele dort sein?\r\nDort sind wir auf ewig beim Herrn,\nerlöst von Versuchung und Pein;\nwir rühmen uns dessen so gern,\ndoch wie wird\'s der Seele dort sein?\r\nDort winket dem Sieger die Kron\'\nund Kleider gar glänzend und fein.\nHier singen wir manchmal davon;\ndoch wie wird\'s der Seele dort sein?\r\nO Gott, schenk\' uns allen die Gnad\'\nund mach uns\'re Herzen recht rein,\ndamit wir einst schauen die Stadt\nund wie es ist, bei Dir zu sein!'),
(9, '2008', 'Wir singen von Jesus, Sein ist Gewalt und Macht   (4 Chorusse)', NULL, 'Wir singen von Jesus, Sein ist Gewalt und Macht,\nEr hat auf Golgatha, das Heil der Welt gebracht.\nDer große Gott ist Er und aller Herren Herr.\nWir singen von Jesus mehr und mehr\r\nWir singen von Jesus, Er ist das Lebensbrot,\nstillt Hunger in der Welt, tröstet dich in der Not.\nEr trägt die Herrschaftskron\', regiert vom Himmelsthron,\nreicht Lebenswasser dir zum Lohn.\r\nWir singen von Jesus, Er ist der Friedefürst,\nheilt dich von Sorgenlast, wenn du Sein Bruder bist.\nWeiß ist Sein Festgewand, blutig die wunde Hand,\nsie führt dich heim ins heil\'ge Land.\r\nWir singen von Jesus, Er ist der starke Fels,\nEr ist das Sündenlamm, geschlachtet für die Welt.\nEr ist der Bräutigam, zünd\'t Ihm die Lichter an,\ndamit die Welt Ihn sehen kann.'),
(9, '2009', 'Wir trauen dir', NULL, 'Wir trauen Dir\nwir trauen Dir Großes zu\nDein Name ist wunderbar\nDein Name macht Wunder wahr\nStarker Heiler\nTreuer Versorger\nEwige Hoffnung\nDu bist wunderbar'),
(9, '2010', 'Wir versammeln uns zu Dir, o großer Gott   (Chorus)', NULL, 'Wir versammeln uns zu Dir, oh, großer Gott.\nWir versammeln uns zu Dir, oh, großer Gott.\nNur zu Dir soll Dein Volk sich sammeln, denn Du bist gut.\nWir versammeln uns zu Dir, oh, großer Gott.'),
(9, '2011', 'Wir wandeln im Licht Gottes  -  We walk in the Light of God   (2 Chorusse)', 'Wandeln, wandeln, wandeln im Licht,\nwandeln, wandeln, wandeln im Licht,\nwandeln, wandeln, wandeln im Licht,\nwandeln im Licht Gottes.\nWe walk in the light\nWe walk in the light\nWe walk in the Light\nWalk in the Light of God.\nWalk, walk, walk in the Light\nWalk, walk, walk in the Light\nWalk, walk, walk in the Light,\nWalk in the Light of God.', 'Wir wandeln im Licht,\nwir wandeln im Licht,\nwir wandeln im Licht,\nwandeln im Lichte Gottes.'),
(9, '2012', 'Wir wandeln im Licht, herrlichen Licht   (5 Chorusse)', NULL, 'Wir wandeln im Licht, herrlichen Licht,\ndas in dem Tau Seiner Gnade sich bricht.\nGanz um uns leuchtet bei Tag und bei Nacht,\nJesus, das Licht dieser Welt.\r\nWir begannen im Licht, herrlichen Licht,\ndas in dem Tau Seiner Gnade sich bricht.\nGanz um uns leuchtet bei Tag und bei Nacht,\nJesus, das Licht dieser Welt.\r\nWir leben im Licht, herrlichen Licht,\ndas in dem Tau Seiner Gnade sich bricht.\nGanz um uns leuchtet bei Tag und bei Nacht,\nJesus, das Licht dieser Welt.\r\nWir freu\'n uns im Licht, herrlichen Licht,\ndas in dem Tau Seiner Gnade sich bricht.\nGanz um uns leuchtet bei Tag und bei Nacht,\nJesus, das Licht dieser Welt.\r\nWir bleiben im Licht, herrlichen Licht,\ndas in dem Tau Seiner Gnade sich bricht.\nGanz um uns leuchtet bei Tag und bei Nacht,\nJesus, das Licht dieser Welt.'),
(9, '2013', 'Wir wandeln mit; Wir zeugen von; Wir warten auf Jesus, Sein ist Gewalt und Macht   (3 Chorusse)', NULL, 'Wir wandeln mit Jesus, ja das ist herrlich schön,\nbald werden wir verklärt, sein strahlend\' Antlitz seh\'n.\nWir werden sein wie Er, so sagt sein heilig\' Wort,\nwir wandeln mit Jesus fort und fort.\r\nWir zeugen von Jesus, Sein ist Gewalt und Macht,\nEr hat auf Golgatha das Heil der Welt gebracht.\nDer große Gott ist Er und aller Herren Herr.\nWir zeugen von Jesus mehr und mehr.\r\nWir warten auf Jesus, Sein ist Gewalt und Macht,\nEr hat auf Golgatha das Heil der Welt gebracht.\nDer große Gott ist Er und aller Herren Herr.\nWir warten auf Jesus bald kommt Er!'),
(9, '2014', 'Wir warten auf Sein Kommen in den Himmelswolken  -  We\'re looking for His Coming, in the Clouds of Heaven   (Voller Freud verkünden wir die Botschaft Seines Kommens)', 'We\'re looking for His coming, in the clouds of heaven,\ncoming back to earth to catch away His own.\nThen may we all be ready, when midnight cry is given,\nto go and reign with Christ on His throne.\r\nGladly may we herald the message of His blessed appearing,\nsoon He\'s coming in glory, tell to one and all.\nThen awake, ye saints of the Lord,\nwhy slumber when the end is nearing,\nBut get ready for the final call.\r\nWe see the signs appearing of His blessed coming,\noh, behold the fig leaves now becoming green.\nThe gospel of His kingdom has gone to every nation,\nthat we are near the end can be seen.\r\nWe\'re longing for the glory that awaits the faithful,\nwho shall overcome, and ev\'ry conflict win.\nPress ever bravely onward, the prize is life eternal,\nto all who win the fight over sin.', 'Wir warten auf Sein Kommen in den Himmelswolken,\nJesus kommt bald wieder, holt zu Sich die Braut.\nDann mögen wir bereit sein, in dieser sel\'gen Stunde,\nzu geh\'n mit unserem Bräutigam zum Mahl.\r\nVoller Freud\' verkünden wir die Botschaft Seines Kommens,\nhör doch Gottes Stimme, wie Er die Seinen ruft.\nWachet auf, ihr Heil\'gen, der Weckruf ist ergangen!\nBald schon treffen wir ihn in der Luft.\r\nWir sehen, Wort erfüllt sich, sichtbar sind die Zeichen:\nDa und dort Erdbeben, wie\'s geschrieben steht.\nDer Feigenbaum treibt Blätter, der Sommer ist so nahe,\no höre es doch: Der Tag des Herrn ist nah!\r\nJa, sehnsuchtsvoll wir schauen, gläubig wir vertrauen,\ndass wer überwindet, sitzt mit Ihm im Thron.\nBleib nur im Glaubenskampfe, der Preis ist ew\'ges Leben\nfür den der überwindet durch sein Blut.'),
(9, '2015', 'Wir woll\'n uns in dem Herrn versammeln   (Chorus)', NULL, 'Wir woll\'n uns in dem Herrn versammeln,\nwo Seine Kraft ist.\nWir woll\'n uns in dem Herrn versammeln,\nwo Seine Kraft ist.\nHalleluja, Halleluja,\nHalleluja, Halleluja!'),
(9, '2016', 'Wird dir beim Pilgern der Fuß auch müd', NULL, 'Wird dir beim Pilgern der Fuß auch müd\';\ndenk\', dass die weiße Schar\ndie dort lobpreisend am Throne steht,\nhier in viel Trübsal war.\n|: Jesus, mein Heiland,  ich bitte Dich,\nwie auch mein Weg hier geht,\nlass ihn nur enden bei jener Schar,\ndie dort am Throne steht. :|\r\nHängt sich auch Staub an das Pilgerkleid,\nrollt manche Träne drauf,\ndroben wischt Jesus die Tränen ab\nund alles Weh hört auf.\n|: Und ist auch steinig mein Pilgerpfad,\nund ist er dorn\'besät:\nJesus, bring mich nur zu jener Schar,\ndie dort am Throne steht. :|\r\nAuch jene Schar, sie ist kampfbewährt,\nsie ging durch manche Not.\nSei nur getrost! Wir sind nicht allein!\nBei uns ist unser Gott!\n|: Lehr\' uns, Herr Jesus, trotz Sturmgebraus\njetzt schon Dein Siegeslied,\ndass wir\'s mitjubeln in jener Schar,\ndie dort Dein Antlitz sieht.'),
(9, '2017', 'Wirf die Sorgen nur auf Jesus  -  Cast your Burdens unto Jesus', 'Cast your burdens unto Jesus,\nfor He cares for You.\nCast your burdens unto Jesus,\nfor He cares for You.\r\nHigher, higher, higher, higher, higher,\nhigher, higher, lift Jesus higher.\r\nLower, lower, lower, lower, lower\nlower, lower, stamp satan lower.', 'Wirf die Sorgen nur auf Jesus,\ndenn Er sorgt für dich.\nWirf die Sorgen nur auf Jesus,\ndenn Er sorgt für dich.\r\nHöher, höher, höher, höher, höher,\nhöher, höher, hebt Jesus höher.\r\nTiefer, tiefer, tiefer, tiefer, tiefer\ntiefer, tiefer, drücke Saten tiefer.'),
(9, '2018', 'Wirf doch alle deine Sorgen auf den Herrn', NULL, 'Wirf doch alle deine Sorgen auf den Herrn,\nEr sorgt als Vater für dich.\nWirf doch alle deine Sorgen auf den Herrn,\nEr sorgt als Vater für dich!\nKannst auf deine Stärke ja nicht bau\'n,\nsolltest darum Ihm vertrau\'n.\nWirf doch alle deine Sorgen auf den Herrn,\nEr sorgt als Vater für dich!'),
(9, '2019', 'Wissen sollte jeder Mann, wissen sollte jede Frau, wissen sollte jedes Kind, wer Jesus ist', NULL, '||: Wissen sollte jeder Mann,\nwissen sollte jede Frau,\nwissen sollte jedes Kind,\nwer Jesus ist. :||\r\nEr, die Lilie im Tale,\nEr, der helle Morgenstern,\nEr, der Schönste von Zehntausend,\nwer Ihn kennt, der hat Ihn gern.'),
(9, '2020', 'Wisst ihr nicht, wisst ihr nicht, ihr seid ein Tempel?  -  Know ye not, know ye not, you are a Temple?', 'Know ye not, know ye not, you are a temple,\nknow ye not, know ye not, you are a temple,\nknow ye not, know ye not, you are a temple,\nyou are a temple of the Holy Ghost.\r\nYes I know, yes I know I am a temple,\nyes I know, yes I know I am a temple,\nyes I know, yes I know I am a temple,\nI am a temple for the Holy Ghost.\r\nFull of praise, full of power, full of glory,\nfull of praise, full of power, full of glory,\nfull of praise, full of power, full of glory,\nI am a temple for the Holy Ghost.\r\n', 'Wisst ihr nicht, wisst ihr nicht, ihr seid ein Tempel?\nWisst ihr nicht, wisst ihr nicht, ihr seid ein Tempel?\nWisst ihr nicht, wisst ihr nicht, ihr seid ein Tempel?\nIhr seid ein Tempel von dem heil\'gen Geist!\r\nJa ich weiß, ja ich weiß ich bin der Tempel!\nJa ich weiß, ja ich weiß ich bin der Tempel!\nJa ich weiß, ja ich weiß ich bin der Tempel!\nIch bin der Tempel von dem Heil\'gen Geist!\r\nVoller Gnade, voller Kraft, voller Herrlichkeit!\nVoller Gnade, voller Kraft, voller Herrlichkeit!\nVoller Gnade, voller Kraft, voller Herrlichkeit!\nIhr seid der Tempel von dem Heil\'gen Geist!\r\nHeimgehend sieben Stufen zur Vollkommenheit!\nHeimgehend sieben Stufen zur Vollkommenheit!\nHeimgehend sieben Stufen zur Vollkommenheit!\nEmpfangt die Fülle mit dem Heil\'gen Geist!'),
(9, '2021', 'With all I am', 'Into Your hands\nI commit again With all I am, for You, Lord\nYou hold my world\nIn the palm of Your hand\nAnd I am Yours forever\r\nJesus I believe in You\nJesus I belong to You\nYou\'re the reason that I live\nThe reason that I sing\nWith all I am\r\nI\'ll walk with You\nWherever You go\nThrough tears and joy\nI\'ll trust in You\nAnd I will live\nIn all of Your ways\nAnd Your promises, forever', 'In deine Hände überge ich mich vollständig\nDU hältst meine Welt in deinen Händen\nUnd ich bien Dein für immer\r\nJesus ich glaube an dich\nJesus ich gehöre dir\nDU bist der Grund dass ich lebe\nder Grund dass ich singe\nvon ganzen Herzen\r\nIch wandle mit dir wo immer du hingehst\nDurch Tränen und Freude vertraue ich dir\nUnd ich werde leben in allen deinen Wegen\nund deinen Verheißungen, für immer'),
(9, '2022', 'Without Him I could do nothing  -  Ohne Ihn kann ich nichts tun', 'Without Him I could do nothing,\nwithout Him I\'d surely fail.\nWithout Him I would be drifting\nlike a ship without a sail.\r\nJesus, oh Jesus,\ndo you know Him today?\nFriend, don\'t turn Him away.\nOh Jesus, my Jesus, without Him\nhow lost I would be.', 'Ohne Ihn kann ich nichts tun,\nohne Ihn würde ich sicher versagen.\nOhne Ihn würde ich umhertreiben,\nwie ein Schiff ohne Segel.\r\nJesus, o Jesus, kennst du Ihn heute?\nFreund, lehne Ihn nicht ab.\nO Jesus, mein Jesus,\nwie wäre ich verloren ohne Dich.'),
(9, '2023', 'Wo Gottes Liebe füllt die Herzen, da gibt es selge Harmonie', NULL, 'Wo Gottes Liebe füllt die Herzen,\nda gibt es sel\'ge Harmonie.\nDahin sind alle Sündenschmerzen,\ndenn Jesu Liebe heilte sie.\nO selig, ganz in Ihm verloren,\nnichts will ich und nichts wünsch ich mehr,\nals tiefer noch hineinzutauchen\nin dieses große Liebesmeer.\r\nWo Jesu Liebe füllt die Herzen,\nda hört das eigne Lieben auf;\ndenn, wo die Selbstsucht noch regieret,\nda stehet still der Liebe Lauf.\nDoch ist man Ihm ganz hingegeben,\ndann strömt in uns die Liebe mild\nund macht uns immer klarer, reiner,\nbis aus uns strahlt des Lammes Bild.\r\nWo Gottes Liebe füllt die Herzen,\nda ziehen Fried\' und Freude ein.\nDa hat man nicht mehr harte Worte,\ndenn Jesu Liebe macht uns klein.\nEr will sich ganz in uns verklären,\nbis unser Bild Ihm völlig gleicht.\nO herrlich Ziel, uns winkt die Krone,\nwenn wir\'s durch Jesu Lieb erreicht!\r\nO sel\'ge, ew\'ge Gottesliebe,\ndie sich in Jesu offenbart,\nund die, o Wunder aller Gnade,\nauch in mir ausgegossen ward.\nO Jesus, lass noch heller brennen\ndas Feuer Deiner Liebesglut,\ndamit es jeder mög\' erkennen,\nes ist Dein Geist, der auf uns ruht.'),
(9, '2024', 'Wo ich auch stehe', NULL, 'Wo ich auch stehe, du warst schon da\nWenn ich auch fliehe, du bist mir nah\nWas ich auch denke, du weißt es schon\nWas ich auch fühle, du wirst verstehn\r\nUnd ich danke dir, dass du mich kennst und trotzdem liebst\nUnd, dass du mich beim Namen nennst und mir vergibst\nHerr, du richtest mich wieder auf\nUnd du hebst mich zu dir hinauf\nIch danke dir, dass du mich kennst und trotzdem liebst\r\nDu kennst mein Herz, die Sehnsucht in mir\nAls wahrer Gott und Mensch warst du hier\nIn allem uns gleich und doch ohne Schuld\nDu bist barmherzig, voller Geduld'),
(9, '2025', 'Wo keine Wolke mehr sich türmt noch Nacht die Welt umhüllt  -  Beyond the Light of setting suns, beyond the clouded Sky   (Ich hab ein Heim, es wartet mein)', 'Beyond the light of setting suns,\nbeyond the clouded sky,\nbeyond where starlight fades in night,\nI have a home on high.\r\nA mansion there, not made with hands,\na place prepared for me.\nAnd while God lives, and angels sing,\nthat home my home shall be.\r\nBeyond all pain, beyond all care,\nbeyond life’s mystery,\nbeyond the range of time and change,\nmy home’s reserved for me.\r\nSwift flying worlds, their nights that roll\nfar out on seas of light,\nwill bring no darkness to my soul.\nMy home’s beyond the night.\r\nMy sins and sorrows, strifes and fears,\nI bid them all farewell.\nHigh up amid th’eternal years,\nwith Christ, my Lord, to dwell.', 'Wo keine Wolke mehr sich türmt\nnoch Nacht die Welt umhüllt,\nda steht die Wohnung mir bereit,\ndie all mein Heimweh stillt.\r\nIch hab ein Heim, es wartet mein,\nein Heim, von Gott erbaut.\nOh, ewig Gottes Liebe währt;\ndort ist mein Heim so traut.\r\nKein Schmerz, kein Leid und kein Geschrei\ntrübt dort der Heil\'gen Glück.\nO Himmelsheimat, glücklich schaut\ndich mein verklärter Blick.\r\nHier steigt hinab der Sonne Glanz,\nerlischt des Tages Pracht.\nNichts Irdisches hat hier Bestand;\ndort gibt es keine Nacht.\r\nSchmerz, Krankheit, Not und Sündenqual\nder, Erde, fahrt hin!\nIch will zur Ruhe in dem Herrn\nin meine Heimat zieh\'n.'),
(9, '2026', 'Wo soll ich hin fliehn, Herr, mit meinen Lasten', NULL, 'Wo soll ich hin flieh\'n, Herr, mit meinen Lasten?\nWo soll ich hin mit meiner Schuld?\nWo soll ich bleiben, und wo soll ich rasten?\nIch komm zu Dir, Du hast Geduld.\r\nIch klamm\'re mich mit meinen beiden Händen,\nHerr, an Dein Kreuz, nur da ist Ruh\'.\nDu wirst Dein Angesicht nicht von mir wenden,\nDu ewiges Erbarmen, Du.\r\nAuf nichts, auf nichts will ich mein Anrecht gründen,\nals auf Dein rettend heil\'ges Blut,\nda wird der Weltgejagte Ruhe finden,\nund Friede quillt aus dieser Flut.\r\nIch berg\' mein Haupt in Deines Kleides Falten,\nich glaub\'s, Du nimmst auch mich noch an.\nFest will ich die durchgrab\'nen Hände halten,\naus denen nichts mich reißen kann.\r\nBewahre mich im Schutze Deiner Flügel,\nnimm mich, ich bin nun völlig Dein,\nund drück\' auf meine Stirn das Gnadensiegel\nder Kindschaft durch den Geist allein.'),
(9, '2027', 'Wohne nun im heilgen Land, wo die Liebe knüpft das Band   (Glücklich immer glücklich meine Zung\' Ihn preist)', NULL, 'Wohne nun im heil\'gen Land, wo die Liebe knüpft das Band,\no wie köstlich und wie herrlich ist die Ruh\'.\nJesus lächelt freundlich mild, in mir trage ich sein Bild,\no ich wohne nun in Zion immerzu.\r\nGlücklich immer glücklich meine Zung\' Ihn preist,\nbin nun auch geheiligt durch den Heil\'gen Geist.\nJa mein ganzen Wesen ist mit Ihm erfüllt,\nsanft ich ruh\' in Jesu\' Er mein Sehnen stillt.\r\nBin nun von der Knechtschaft frei, alles ist jetzt in mir neu\nund die Wüste ist des Geistes Wohnort nicht.\nDenn ich schmecke Honig süß, Vorgeschmack vom Paradies,\noh die Herrlichkeit ist zu beschreiben nicht.\r\nLebensströme rauschen hier, klares Wasser stillet mir,\nmeinen Durst nach Seligkeit und süßer Ruh\'.\nO die Herrlichkeit ist mein und der Schönheit blendend Schein,\nja mein Glück und meine Freude Herr bist Du.\r\nBin vom Samen Abraham, Gottes Erbe durch das Lamm,\nwelch ein sel\'ges Land hat Er für mich erse\'hn.\nKomm und kreuz\' des Jordans Flut, trete an dein Erb\' und Gut,\ndenn der Herr tut über Bitten und versteh\'n.'),
(9, '2028', 'Word of God speak', 'Word of God speak, pour down like rain\nwashing my eyes to see your majesty\nTo be still and know, You\'re in this place\nplease let me stay and rest in Your holiness', 'Wort Gottes sprich, gieße hinab wie Regen\nwasche meien Augen, dass ich deine Majestät sehe\nStill zu sein und zu wissen,  dass Du hier bist\nbitte lass mich bleiben und ruhen in Deiner Heiligkeit'),
(9, '2029', 'Worship the Lord, in His Presence we stand', 'Worship the Lord,\nIn His presence we stand.\nHe cares for you\nAnd He understands.\nCome Holy Spirit\nAnd speak to us now,\nGrace, joy and peace\nAnd love abound.\r\nHe is Worthy,\nWorthy, Worthy,\nWorthy is the Lord.\r\nHe is Mighty,\nMighty, Mighty,\nMighty is the Lord.\r\nHe is Holy,\nHoly, Holy,\nHoly is the Lord.\r\nHe is Faithful,\nFaithful, Faithful,\nFaithful is the Lord.', NULL),
(9, '2030', 'Worte des ewigen Lebens und Jesu kostbares Blut   (Chorus)', NULL, 'Worte des ewigen Lebens und Jesu\' kostbares Blut.\nRettet und reinigt von Sünden, und jeder Schaden wird gut.\nKöstlicher Friede vom Vater dringt tief ins Herz mir hinein.\n||: Herrliche Botschaft des ewigen Lebens,\nich weiß es, der Heiland ist mein. :||'),
(9, '2031', 'Worthy is the Lamb, the Hosts of Heaven sing   (Oh, this bleeding Lamb)', '"Worthy is the Lamb", the hosts of heaven sing,\nas before the throne they make His praises ring.\n"Worthy is the Lamb the book to open wide,\nworthy is the Lamb who once was crucified".\r\nOh, this bleeding Lamb, Oh, this bleeding Lamb,\nOh, this dying Lamb, He was found worthy.\nOh, this bleeding Lamb, Oh, this bleeding Lamb,\noh, this dying Lamb, He was found worthy.\r\nWorthy is the Lamb who shed His precious blood,\nto restore a world to happiness and God.\n"When no eye could pity and no arm could save",\nJesus, for our ransom, Himself freely gave.\r\nWorthy is the Lamb, the bleeding sacrifice,\nwho for Adam\'s race paid such a fearful price.\nWorthy is the Lamb, The Paschal Lamb of God,\nfor the world received "Redemption thro\' His blood."\r\n"Worthy is the Lamb," let men and angels sing,\n"Worthy is the Lamb", let halleluja\'s ring.\nAnd when life is past, upon the golden shore,\n"Worthy is the Lamb", we\'ll shout forevermore.', NULL),
(9, '2032', 'Worthy of it all', 'All the saints and angels\nThey bow before Your throne\nAll the elders cast their crowns\nBefore the Lamb of God and sing\r\nYou are worthy of it all\nYou are worthy of it all\nFor from You are all things\nAnd to You are all things\nYou deserve the glory\r\nDay and night night and day let incense arise\nDay and night night and day let incense arise\nDay and night night and day let incense arise\nDay and night night and day let incense arise\r\nI exalt Thee\nI exalt Thee\nI exalt Thee oh Lord (x2)', 'Alle Heiligen und Engel\nBeugen sich vor Deinem Thron\nAlle Ältesten legen ihre Kronen\nvor das Lamm Gottes und singen)\r\nDu bist würdig von Allem\nDenn durch Dich sind alle Dinge\nund pür Dich sind alle Dinge\nDir gebührt die Herrlichkeit\r\nTag und Nacht lass Räucherwerk aufsteigen\r\n(Ich erhebe dich Oh Herr)'),
(9, '2033', 'Worthy, Worthy, Worthy the Lamb that was slain   (4 Chorusse)', 'Worthy, Worthy,\nworthy the Lamb that was slain.\nWorthy, Worthy,\nworthy the Lamb that was slain.\r\nPraise Him, praise Him,\npraise the Lamb that was slain.\nPraise Him, praise Him,\npraise the Lamb that was slain.\r\nLove Him, love Him,\nlove the Lamb that was slain.\nLove Him, love Him,\nlove the Lamb that was slain.\r\nServe Him, serve Him,\nserve the Lamb that was slain.\nServe Him, serve Him,\nserve the Lamb that was slain.', NULL),
(9, '2034', 'Would you be numbered as one of His Fold   (He’s coming again)', 'O would you be numbered as one of His fold?\nBe spotless within.\nBe watching and waiting that sight to behold,\nHe’s coming again!\r\nHe’s coming again!\nHe’s coming again!\nBe watching and waiting that sight to behold.\nHe’s coming again!\r\nNot known is the moment when He shall appear,\nto gather them in.\nThe souls who have followed Him faithfully here.\nHe’s coming again!\r\nThe voice of His Spirit says, ready, then be,\no will you begin?\nIf peace in His presence you hope then to see.\nHe’s coming again!\r\nRisk not, an acceptance of Him in that day,\nall covered with sin.\nBe robed and all ready, the Spirit doth say,\nHe’s coming again!', NULL),
(9, '2035', 'Wunder der Gnade Jesu, größer als all meine Sünd  -  Wonderful Grace of Jesus, greater than all my Sin   (Unvergleichlich wunderbare Gnade)   [Liederschatz]', 'Wonderful grace of Jesus,\ngreater than all my sin;\nhow shall my tongue describe it,\nwhere shall its praise begin?\nTaking away my burden,\nsetting my spirit free;\nfor the wonderful grace of Jesus reaches me.\r\nWonderful the matchless grace of Jesus,\ndeeper than the mighty rolling sea,\nhigher than the mountain, sparkling like a fountain,\nall sufficient grace for even me;\nbroader than the scope of my transgressions, sing it!\ngreater far than all my sin and shame.\nO magnify the precious name of Jesus, praise his name!\r\nWonderful grace of Jesus,\nreaching to all the lost,\nby it I have been pardoned,\nsaved to the uttermost.\nChains have been torn asunder,\ngiving me liberty,\nfor the wonderful grace of Jesus reaches me.\r\nWonderful grace of Jesus,\nreaching the most reviled,\nby its transforming power\nmaking me God’s dear child,\npurchasing peace and heaven\nfor all eternity,\nfor the wonderful grace of Jesus reaches me.', 'Wunder der Gnade Jesu,\ngrößer als all meine Sünd\',\nwie soll mein Mund sie beschreiben,\npreisen was in ihm ich find\'?\nSie nimmt hinweg meine Bürde,\nFreiheit mein Geist gewinnt,\nd\'rum die wunderbare Gnade in Jesu ich verkünd\'.\r\nUnvergleichlich wunderbare Gnade,\ntiefer als das Meer, das wogt mit Macht,\nBerge überglühend, wie ein Brunnquell sprühend,\nGnad\' die überschwenglich mich bedacht,\ndie all meine Übertretung deckte,\ngrößer ist als alle meine Schuld.\nO verherrlicht diesen teuren Namen Jesus! Preiset Ihn!\r\nWunder der Gnade Jesu,\ndie mich Verlor\'nen entrückt;\nsie schenkt mir volle Vergebung,\nlöst mich, worin ich verstrickt.\nSie hat die Ketten zerbrochen,\nFreiheit mich nun entzückt,\nseit die wunderbare Gnade in Jesu mich beglückt.\r\nWunder der Gnade Jesu,\nalle Befleckung zerrinnt.\nSie weckt erneuernde Kräfte,\nmacht mich zu Gottes Kind;\nschenkt ewig Frieden und Freude,\nob alles sonst verschwind\'t.\nO der wunderbaren Gnade in Jesu trau ich blind.'),
(9, '2036', 'Wunder der Gnade Jesu, größer als alle Sünd  -  Wonderful Grace of Jesus, greater than all my Sin   (Unvergleichlich wunderbare Gnade)   [Janz]', 'Wonderful grace of Jesus, greater than all my sin.\nHow shall my tongue describe it, where shall its praise begin?\nTaking away my burden, setting my spirit free,\nfor the wonderful grace of Jesus reaches me.\r\nWonderful the matchless grace of Jesus,\ndeeper than the mighty rolling sea,\nhigher than the mountain, sparkling like a fountain,\nall sufficient grace for even me.\nBroader than the scope of my transgressions, sing it!\nGreater far than all my sin and shame.\nO magnify the precious name of Jesus, praise his name!\r\nWonderful grace of Jesus, reaching to all the lost,\nby it I have been pardoned, saved to the uttermost.\nChains have been torn asunder, giving me liberty,\nfor the wonderful grace of Jesus reaches me.\r\nWonderful grace of Jesus, reaching the most reviled,\nby its transforming power, making me God’s dear child.\nPurchasing peace and heaven for all eternity,\nfor the wonderful grace of Jesus reaches me.', 'Wunder der Gnade Jesu, größer als alle Sünd\';\nwie soll ich\'s recht verkünden, was ich beim Heiland find\'.\nAll meine Bürden schwinden, was meine Last auch sei,\ndenn das Wunder der Gnade Jesu, macht mich frei.\r\nUnvergleichlich wunderbare Gnade,\ntiefer als das Meer, das wogt mit Macht,\nBerge überglühend, wie ein Brunnquell sprühend,\nGnad\', die  überschwänglich mich bedacht.\nAlle Übertretung ist getilget, alle meine Schande ist dahin!\nVerherrlicht diesen teuren Namen Jesus! Preiset Ihn!\r\nWunder der Gnade Jesu strömt den Verlor\'nen zu;\nhier findest du Vergebung, rettende, sel\'ge Ruh\'.\nHier lösen sich die Bande, Freiheit wird dir zuteil.\nAus dem Wunder der Gnade Jesu, quillt das Heil.\r\nWunder der Gnade Jesu! Wo alle Schuld zerrinnt,\nkann selbst der Allerärmste werden ein Gotteskind.\nHebt uns des Himmels Friede dann über Raum und Zeit,\nwird das Wunder der Gnade Jesu, Ewigkeit.'),
(9, '2037', 'Wunderbar herrlicher Retter, teurer Erlöser und Freund  -  Wonderful merciful Saviour, precious Redeemer and Friend   [Original]', 'Wonderful, merciful Saviour,\nprecious Redeemer and Friend.\nWho would have thought that a Lamb,\ncould rescue the souls of men,\noh you rescue the souls of men.\r\nCounselor, Comforter, Keeper,\nspirit we long to embrace.\nYou offer hope when our hearts have,\nhopelessly lost the way,\noh, we hopelessly lost the way.\r\nYou are the One that we praise,\nYou are the One we adore.\nYou give the healing and grace,\nour hearts always hunger for,\noh, our hearts always hunger for.\r\nAlmighty, infinite Father,\nfaithfully loving Your own.\nHere in our weakness You find us,\nfalling before Your throne,\noh, we\'re falling before Your throne.', 'Wunderbar herrlicher Retter,\nteurer Erlöser und Freund.\nWer hätt\' gedacht, dass ein Lamm\nuns Menschen erretten kann,\nja, uns Menschen erretten kann.\r\nRatgeber, Tröster, Bewahrer,\nGeist, der uns gnädig umgibt.\nRettest die irrende Seele,\nweil Du uns so geliebt,\nja, weil Du uns so geliebt.\r\nDu bist der Gott, den wir preisen,\nDu bist der Gott, den wir ehr\'n.\nGibst uns\'ren durstigen Herzen\nHeilung und Gnade, Herr,\nja, Heilung und Gnade, Herr.\r\nAllmächtig ewiger Vater,\nDu, der uns unendlich liebt.\nWir sind das Volk Deiner Gnade,\ndas Dir die Ehre gibt,\nja, das Dir die Ehre gibt.'),
(9, '2038', 'Wunderbar, herrlich und groß ist Jesus, mein Herr und Gott', NULL, 'Wunderbar herrlich und groß\nist Jesus, mein Herr und Gott.\nGab mir ein liebliches Los,\nja, hob mich aus Angst und Not.\nDunkel und Nacht sind dahin,\ndenn er ist mein Sonnenschein.\nLeben, so wunderbar, Liebe, so rein und klar,\nist nur in Jesus allein.'),
(9, '2039', 'Wunderbar, wunderbar, Gottes große Liebe ist wunderbar', NULL, 'Wunderbar, wunderbar,\nGottes große Liebe ist wunderbar.\nFür alle ist sie gleich,\nuns alle macht sie reich.\nGottes große Liebe ist wunderbar!\r\nWunderbar, wunderbar,\nGottes große Gnade ist wunderbar.\nSie geht dem Sünder nach,\nob sie ihn finden mag,\nGottes große Gnade ist wunderbar!\r\nWunderbar, wunderbar,\nGottes große Treue ist wunderbar.\nAus Satans Sklaverei\nmacht Er uns völlig frei.\nGottes große Treue ist wunderbar!'),
(9, '2040', 'Wundervoller Heiland, der vom Himmel kam   (Weißer als der Schnee, weißer als der Schnee)', NULL, 'Wundervoller Heiland, der vom Himmel kam,\nunsre Schuld zu tilgen willig übernahm,\nbringet Freud und Wonne in das Erdenweh,\nwäscht in Seinem Blute weißer uns als Schnee.\r\nWeißer als der Schnee, weißer als der Schnee.\nHeiland, der Du starbst für mich,\nwasche und entsünd\'ge mich\nweißer als der Schnee, weißer als der Schnee.\r\nHeller als die Sonne strahlt sein Gnadenlicht\nund die Nacht der Sünde es mit Macht durchbricht.\nSchau, betrübte Seele, gläubig in die Höh\';\nJesus will dich machen weißer noch als Schnee.\r\nVielgeliebter Heiland, auf Dein Kreuz wir schau\'n,\nkommen ohne Zahlung, doch im Gottvertraun.\nGnädig, o Lamm Gottes, auf uns niederseh,\nmach, wie Du verheißen, weißer uns als Schnee.\r\nJesus, mein Erlöser, meiner Seele Heil,\nnun kann ich Dich preisen, denn Du bist mein Teil;\nsei Du mein Begleiter, wo ich geh und steh,\ndass ich bleiben möge weißer noch als Schnee.'),
(9, '2041', 'Würdig ist das Lamm - Danke für das Kreuz, Herr', 'Thank you for the cross Lord,\nthank you for the price You paid,\nbearing all my sin and shame\nin love You came and gave amazing grace.\r\nThank you for this love Lord,\nthank you for the nail pierced hands.\nWashed me in Your cleansing flow\nnow all I know is Your forgiveness and embrace.\r\nWorthy is the Lamb, seated on the throne.\nWe crown You now with many crowns,\nYou reign victorious.\nHigh and lifted up, Jesus, Son of God.\nThe treasure of heaven crucified.\n|: Worthy is the Lamb. :|', 'Danke für das Kreuz Herr,\ndort hast Du den Preis bezahlt\nfür die Sünde und die Schuld\naus Liebe und aus Gnade wunderbar.\r\nDanke für die Liebe Herr,\ndie durchbohrten Hände, Herr\nreinigst mich mit Deinem Blut\nich weiß es nun, du vergibst und nimmst mich an.\r\nWürdig ist das Lamm, Herrscher auf dem Thron,\nviele Kronen schmücken Dich, den König der regiert.\nDu bist hoch erhöht, Jesus Gottes Sohn\nder Herrlichste starb für uns am Kreuz\n|: würdig ist das Lamm. :|'),
(9, '2042', 'Würdig und herrlich ist das Lamm', NULL, 'Würdig und herrlich ist das Lamm\nJesus, Dir allein sei Ehre\nDu, der Du sitzt auf deinem Thron\nDir sei Ruhm in Ewigkeit\r\nHalleluja! Sei erhoben, o Herr\nDu bist König, und wir beugen uns, Herr\nIn Anbetung singen wir zu Dir'),
(9, '2043', 'Würdig, würdig, würdig ist das Gotteslamm  -  Worthy, worthy, worthy is the Lamb of God', 'Worthy, worthy, worthy\nis the lamb of God.\nWorthy, worthy, worthy\nis the lamb.\r\nHoly, holy, holy\nis the lamb of God.\nHoly, holy, holy\nis the lamb.\r\nJesus, Jesus, Jesus\nis the lamb of God.\nJesus, Jesus, Jesus\nis the lamb.', 'Würdig, würdig,\nwürdig ist das Gotteslamm,\nwürdig, würdig,\nwürdig ist das Lamm.\r\nHeilig, heilig,\nheilig ist das Gotteslamm,\nheilig, heilig,\nheilig ist das Lamm.\r\nJesus, Jesus,\nJesus ist das Gotteslamm,\nJesus, Jesus,\nJesus ist das Lamm.'),
(9, '2044', 'Yes Lord, yes Lord, from the Bottom of my Heart   (2 Chorusse)', 'Yes Lord, yes Lord,\nfrom the bottom of my heart\nto the depths of my soul.\nYes Lord, completely yes.\nMy soul says yes.\r\nI love You, I love You,\nfrom the bottom of my heart\nto the depths of my soul.\nI love You, I really do.\nMy soul says yes', NULL),
(9, '2045', 'Yes, oh Yes, there is something more than Gold   (Chorus)', 'Yes, oh Yes, there is something more than gold.\nOh Yes, oh Yes,\nThere is something more than gold in my soul,\nthere is something more than gold.', NULL),
(9, '2046', 'You are Alpha and Omega   (2 Chorusse)', 'II:You are Alpha and Omega\nWe worship you oh Lord\nYou are worthy to be praised.:II\r\nII:We give You all the glory\nWe worship You our Lord\nYou are worthy to be praised.:II', NULL),
(9, '2047', 'You are beautiful beyond Description   (And I stand, I stand in Awe of You)', 'You are beautiful beyond description,\nToo marvelous for words,\nToo wonderful for comprehension,\nLike nothing ever seen or heard.\nWho can grasp Your infinite wisdom ?\nWho can fathom the depth of Your Love ?\nYou are beautiful beyond description,\nMajesty enthroned above.\r\nAnd I stand, I stand in awe of You.\nI stand, I stand in awe of You.\nHoly God, to Whom all praise is due,\nI stand in awe of You.', NULL),
(9, '2048', 'You are blessed, you are blessed   (2 Chorusse)', 'You are blessed, you are blessed,\nyou are blessed, you are blessed.\nYou are blessed, you are blessed,\nyou are blessed, you are blessed.\r\nYou don\'t deserve it\nbut yet you are blessed,\nYou don\'t deserve it\nbut yet you are blessed.', NULL),
(9, '2049', 'You are God Alone', 'You are not a God created by human hands\nYou are not a God dependent on any mortal man\nYou are not a God in need of anything we can give\nBy Your plan\nThat\'s just the way it is\r\nYou are God alone, from before time began\nYou are on Your throne\nYou are God alone\nAnd right now, in the good times and bad\nYou are on Your throne, You are God alone\r\nYou\'re the only God whose power, none can contend\nYou\'re the only God whose name and praise will never end\nYou\'re the only God who\'s worthy of everything we can give\nYou are God\nThat\'s just the way it is\r\nYou\'re unchangeable\nUnshakable\nUnstoppable\nThat\'s who You are\nYou\'re unchangeable\nYou\'re unshakable\nUnstoppable\nThat\'s who You are', 'Du bist kein von Menschenhand geschaffener Gott\nDu bist kein Gott, der von irgendeinem sterblichen Menschen abhängig ist\nDu bist kein Gott, der etwas braucht, was wir geben können\nNach Deinem Plan\nSo ist es nun einmal\r\nDu bist Gott allein,  schon von Anfang der Zeit,\nDu bist auf dem Thron, Du bist Gott allein\nUnd grad jetzt, ob in Freud\' oder Leid,\nDu bist auf dem Thron, Du bist Gott allein\r\nDu bist der einzige Gott, dessen Macht niemand bestreiten kann\nDu bist der einzige Gott, dessen Name und Lob niemals enden werden. Du bist der einzige Gott, der alles verdient, was wir geben können. Du bist Gott,  so ist es nun einmal\r\nDu bist unveränderlich\nUnerschütterlich\nNicht zu stoppen\nDas bist du\nDu bist unveränderlich\nDu bist unerschütterlich\nNicht zu stoppen\nDas bist du'),
(9, '2050', 'You are Lord', 'You are my light and salvation\nWhom shall I fear?\nYou are the strength of all my days\nAnd whom shall I be afraid?\nThough war may rise against me\nOf this will I be sure\r\nThat I will bless the Lord forever\nI\'ll bless Your holy Name\nYes, I will bless the Lord forever\nI\'ll bless Your holy Name\r\nLord, it is You I desire\nIt\'s You that I seek\nTo live with You in Your house forever\nBeholding Your beauty\nAnd in the time of trouble\nOf this will I be sure', 'Du bist mein Licht und meine Rettung\nWen soll ich fürchten?\nDu bist die Kraft aller meiner Tage\nUnd vor wem soll ich mich fürchten?\nAuch wenn sich der Krieg gegen mich erhebt\nso bin ich doch gewiss\r\nDass ich den Herrn für immer loben werde\nIch werde Deinen heiligen Namen loben\nJa, ich will den Herrn loben für immer\nIch werde Deinen heiligen Namen loben\r\nHerr, Du bist es, den ich begehre\nDu bist es, den ich suche\nUm mit Dir in Deinem Haus für immer zu leben\nDeine Schönheit zu sehen\nUnd in der Zeit der Not\nwerde ich sicher sein'),
(9, '2051', 'You are my hiding place', 'Verse 1:\nIn the distance I can see the storm clouds coming my way,\nand I need to find a shelter before it starts to rain,\nso I turn and run to you, Lord,\nyou\'re the only place to go,\nwhere unfailing love surrounds me,\nwhen I need it most.', NULL),
(9, '2052', 'You are worthy to receive all the Honour', 'You are worthy to receive all the honour.\nYou are worthy to receive all the glory.\nYou are worthy to receive all the power.\nYou have purchased us,\nYou have purchased us,\nYou have purchased us with Your blood.', NULL),
(9, '2053', 'You ask me why I\'m happy, so I\'ll just tell you why   (They\'re underneath the Blood)', 'You ask me why I\'m happy,\nso I\'ll just tell you why,\nbecause my sins are gone.\nAnd when I meet the scoffers\nwho ask me where they are,\nI say, my sins are gone.\r\nThey\'re underneath the Blood\nof the Cross of Calvary.\nAs far removed as darkness\nis from dawn.\nIn the sea of God\'s forgetfulness,\nthat\'s good enough for me.\nPraise God, my sins are gone..\r\n\'Twas at the old-time altar\nwhere God came in my heart,\nand now my sins are gone.\nThe Lord took full possession,\nthe devil did depart,\nI\'m glad my sins are gone.\r\nWhen Satan comes to tempt me\nand tries to make me doubt,\nI say, my sins are gone.\nYou got me into trouble,\nbut Jesus got me out,\nI\'m glad my sins are gone.\r\nI\'m living now for Jesus,\nI\'m happy night and day,\nbecause my sins are gone.\nMy soul is filled with music,\nwith all my heart I say,\nI know my sins are gone.', NULL),
(9, '2054', 'You don\'t have to worry and don\'t you be afraid   (I know that I can make it)', 'You don\'t have to worry\nAnd don\'t you be afraid\nJoy comes in the morning\nTroubles they don\'t last always\nFor there\'s a friend in Jesus\nWho will wipe your tears away\nAnd if your heart is broken\nJust lift your hands and say\r\nI know that I can make it\nI know that I can stand\nNo matter what may come my way\nMy life is in your hands\nWith Jesus I can take it\nWith Him I know I can stand\nNo matter what may come my way\nMy life is in your hands\r\nSo when your tests and trials\nThey seem to get you down\nAnd all your friends and loved ones\nAre nowhere to be found\nRemember there\'s a friend in Jesus\nWho will wipe your tears away\nAnd if your heart is broken\nJust lift your hands and say', 'Du brauchst dich nicht sorgen,\nund habe keine Angst.\nFreude kommt am Morgen,\nProbleme bleiben nicht für immer\nDenn da ist ein Freund in Jesus,\nwelcher dein Tränen abwischen wird.\nUnd wenn dein Herz gebrochen ist,\nhebe einfach deine Hände und sage:\r\nIch weiß, dass ich es schaffen kann,\nich weiß, dass ich durchhalten kann.\nEgal, was auf meinen Weg kommt,\nmein Leben ist in deiner Hand.\nMit Jesus kann ich es tragen,\nmit ihm weiß ich, dass es durchstehe.\nEgal, was auf meinen Weg kommt,\nmein Leben ist in deiner Hand.\r\nWenn also deine Tests und Prüfungen\ndich zu Fall bringen.\nUnd alle Freunde und Geliebten\nsind nirgendwo zu sehen.\nErinner\' dich, dort ist ein Freund in Jesus,\nwelcher dein Tränen abwischen wird.\nUnd wenn dein Herz gebrochen ist,\nhebe einfach deine Hände und sage:'),
(9, '2055', 'You may think it\'s foolish what I\'m going to say   (Born again, there\'s really been a Change in me)', 'You may think it\'s foolish what I\'m going to say,\nI\'m not ashamed, no not ashamed.\nOne day I prayed Jesus, take my sin away,\nand that\'s when I was born again.\r\nBorn again, there\'s really been a change in me,\nborn again, just like Jesus said,\nborn again, and all because of calvary,\nI\'m glad so glad that I\'ve been born again.\r\nOne man came to Jesus, John and chapter 3,\noh so afraid, oh so afraid.\nMaster your from God, I really do believe,\nand Jesus said, be born again.\r\nBorn again, there\'s really been a change in me,\nborn again, just like Jesus said,\nborn again, and all because of calvary,\nI\'m glad so glad that I\'ve been born again,\nI\'m glad so glad that I\'ve been born again.', NULL),
(9, '2056', 'You say', 'I keep fighting voices in my mind that say I\'m not enough\nEvery single lie that tells me I will never measure up\nAm I more than just the sum of every high and every low\nRemind me once again just who I am because I need to know\r\nYou say I am loved when I can\'t feel a thing\nYou say I am strong when I think I am weak\nAnd you say I am held when I am falling short\nAnd when I don\'t belong, oh You say I am Yours\nAnd I believe (I)\nOh, I believe (I)\nWhat You say of me (I)\nI believe\r\nThe only thing that matters now is everything You think of me\nIn You I find my worth, in You I find my identity\r\nTaking all I have, and now I\'m laying it at Your feet\nYou have every failure, God, You have every victory', NULL),
(9, '2057', 'You were despised, You were rejected, Lord  -  Du wurd\'st verachtet, Du wurd\'st verworfen, Herr', 'You were despised,\nYou were rejected, Lord.\nThose who passed by\neven averted their gaze from the sight.\nSuch was the suffering you bore for us.\nLed like a lamb,\nlamb to the slaughter\nYou spoke not a word,\nbut chose to be silent Lord You did no wrong,\nnor was deceitfullness found in You.\r\nYet by Your wounds our salvation has come.\nYet by Your suffering our freedom is won.\nFor God has higly exalted Your name.\nHe has enthroned You on high.\nJesus, the name above all names.\nFor God has higly exalted your name.\nHe has enthroned You on high.\nJesus, the name above all names.\r\nYou were despised,\nYou were rejected, Lord.\nThose who passed by\neven averted their gaze from the sight.\nSuch was the suffering you bore for us.\nLed like a lamb,\nlamb to the slaughter\nYou spoke not a word,\nbut chose to be silent Lord You did no wrong,\nnor was deceitfullness found in You.\r\nYet by Your wounds our salvation has come.\nYet by Your suffering our freedom is won.\nFor God has higly exalted Your name.\nHe has enthroned You on high.\nJesus, the name above all names.\nFor God has higly exalted your name.\nHe has enthroned You on high.\nJesus, the name above all names.\r\nYou were despised,\nYou were rejected, Lord.\nThose who passed by\neven averted their gaze from the sight.\nSuch was the suffering you bore for us.', '(Du wurd\'st verachtet,\nDu wurd\'st verworfen, Herr.\nDiejenigen, die vorbeigingen\nwendeten sogar ihren Blick von Deinem Anblick ab.\nDas war das Leiden, das Du für uns ertragen hast.\nGeführt wie ein Lamm,\nein Lamm zur Schlachtbank\nDu sprachst nicht ein Wort,\nsondern wähltest zu schweigen Herr, Du hast kein Unrecht getan\nnoch wurde Arglist in Dir gefunden.)\r\n(Doch durch Deine Wunden ist unsere Erlösung gekommen.\nDoch durch Dein Leiden ist unsere Freiheit gewonnen.\nDenn Gott hat Deinen Namen hoch erhoben.\nEr hat Deinen Thron hoch erhoben.\nJesus, der Name über alle Namen.\nGott hat Deinen Namen hoch erhoben.\nEr hat Deinen Thron hoch erhoben.\nJesus, der Name, der über allen Namen steht.)\r\n(Du wurdest verachtet,\nDu wurdest verworfen, Herr.\nDiejenigen, die vorbeigingen\nwendeten sogar ihren Blick von Deinem Anblick ab.\nDas war das Leiden, das Du für uns ertragen hast.\nGeführt wie ein Lamm,\nein Lamm zur Schlachtbank\nDu sprachst nicht ein Wort,\nsondern wähltest zu schweigen Herr, Du hast kein Unrecht getan\nnoch wurde Arglist in Dir gefunden.)\r\n(Doch durch Deine Wunden ist unsere Erlösung gekommen.\nDoch durch Dein Leiden ist unsere Freiheit gewonnen.\nDenn Gott hat Deinen Namen hoch erhoben.\nEr hat Deinen Thron hoch erhoben.\nJesus, der Name über alle Namen.\nGott hat Deinen Namen hoch erhoben.\nEr hat Deinen Thron hoch erhoben.\nJesus, der Name, der über allen Namen steht.)\r\nDu wurdest verachtet,\nDu wurdest verworfen, Herr.\nDiejenigen, die vorbeigingen\nwendeten sogar ihren Blick von Deinem Anblick ab.\nDas war das Leiden, das Du für uns ertragen hast.'),
(9, '2058', 'You\'re all I want heavenly Father', 'You’re all I want heavenly father.\nYou’re all that I need.\nLord we worship You in the beauty of holiness,\nfor what Your Word has done for us.\nWe hide it in our hearts,\nwe will not let the enemy steal it away.\nYou’re all I want Heavenly Father (2x)', NULL),
(9, '2059', 'You\'ve got to keep walking, keep right on walking', 'You\'ve got to keep walking,\nkeep right on walking,\nkeep walking in the light of the Lord.\nYou\'ll get to heaven some day,\nif you walk the right way.\nKeep walking in the Light of the Lord.', '(Du musst weiter wandeln,\nweiter richtig wandeln,\nwandeln in dem Lichte des Herrn.\nDu wirst den Himmel erreichen,\nwenn du den richtigen Weg gehst.\nWandle weiter im Lichte des Herrn.)'),
(9, '2060', 'You\'ve gotta run, run, run, run, run with the Message of Malachi 4', 'You\'ve gotta run, run, run, run,\nrun with the Message of Malachi 4.\nYou\'ve got to tell it\nlike you\'ve never told it before.\nLet him that readeth run,\nlet him that heareth run,\nfor this Message\nis the coming of the Lord.', NULL),
(9, '2061', 'Your Grace Still Amazes Me - Special', 'My faithful father\nEnduring friend\nYour tender mercy is like a river with no end\nIt overwhelms me\nCovers my sin\nEach time I come into your presence\nI stand in wonder once again\r\nYour grace still amazes me\nYour love is still a mystery\nEach day I fall on my knees\n\'Cause your grace still amazes me\nYour grace still amazes me\r\nOh, patient savior\nYou make me whole\nYou are the author and the healer of my soul\nWhat can I give you?\nLord, what can I say?\nI know there\'s no way to repay you\nOnly to offer you my praise\r\nIt\'s deeper, it\'s wider\nIt\'s stronger, it\'s higher\nIt\'s deeper, it\'s wider (it\'s deeper, it\'s wider)\nIt\'s stronger, it\'s higher (it\'s stronger, it\'s higher)\nThan anything my eyes can see', NULL),
(9, '2062', 'You´ve already won', 'There\'s peace that outlasts darkness\nHope that\'s in the blood\nThere\'s future grace that\'s mine today\nThat Jesus Christ has won\nSo I can face tomorrow\nFor tomorrow\'s  in Your hands\nAll I need you will provide\nJust like you always have\r\nI\'m fighting a battle\nThat you\'ve already won\nNo matter what comes my way\nI will overcome\nI don\'t know what you\'re doing\nBut I know what you\'ve done\nI\'m fighting a battle that\nYou\'ve already won\r\nThere\'s mercy in the waiting\nMana for today\nAnd when it\'s gone I know your\'re not\nYou are my hope and stay\nWhen the sea is raging\nYour Spirit is my help\nHe\'ll fix my eyes on Jesus Christ\nAnd I\'ll say that it is well\nOh I know that it is well\r\nI know how the story ends\nWe will be with you again\nYou\'re my Savior my defense\nNo More fear in life or death         2x\nI know how this story ends', NULL),
(9, '2063', 'Zarte Liebe von dem Herrn, vor ihr beug ich mich so gern   (Lieb, o so groß, Lieb o so groß)', NULL, 'Zarte Liebe von dem Herrn,\nvor ihr beug\' ich mich so gern.\nVon der Liebe möcht\' ich mehr,\nLieb\', o so groß!\nJesus, der auf Erden kam,\nunsre Sünden auf Sich nahm,\nzünd in mir die Liebe an!\r\nLieb\', o so groß! Lieb\', o so groß!\nLieb\', o so groß!\nGrundlose, herrliche Liebe von Gott!\nLieb\', o so groß!\r\nBlinden gab Er das Gesicht,\nKrüppel hat Er aufgericht\',\nToten bracht Er Lebenslicht.\nLieb\', o so groß!\nSünder, so verkehrt und schlecht,\nbracht die Liebe ganz zurecht.\nEr ward aller Knechte Knecht.\r\nSünder, blick nach Golgatha;\nsieh, was dort für dich geschah!\nEr starb dort auch dir zugut\'.\nLieb\', o so groß!\nHeil und frei wirst du nur hier\nan der off\'nen Gnadentür.\nGlaube nur; Er schenkt Sich dir.\r\nSeele, komm, lass alles steh\'n,\nlass zu dieser Lieb\' uns geh\'n!\nNimm des Heiles Botschaft an.\nLieb\', o so groß.\nJesus ruft dich, hör die Stimm\',\nwart nicht länger, komm zu Ihm.\nSieh, dir winkt Jerusalem.'),
(9, '2064', 'Zeig mir den Weg, Herr, ich will mit Dir gehn  -  Show me Your Way that I may walk with You', 'Show me Your way that I may walk with You.\nShow me Your way I put my hope in You.\nThe cry of my heart is to love You more,\nto live with the touch of Your Hand.\nStronger each day show me Your Way.', 'Zeig\' mir den Weg, Herr, ich will mit Dir geh\'n,\nZeig\' mir den Weg, Herr, Deine Spuren seh\'n,\noh, Herr, meine Seele verlangt nach Dir\nund nach Deiner führenden Hand\njeden Tag mehr, zeig mir den Weg.'),
(9, '2065', 'Zeige Dich Herr meinem Herzen, ich will Dich sehen', NULL, 'Zeige Dich Herr meinem Herzen,\nzeige Dich Herr meinem Herz,\nich will Dich sehen,\nich will Dich sehen. (2x)\r\nDich sehen hoch erhoben, Herr,\nleuchtend in dem Licht Deiner Gnade,\nvollkommen in Liebe und Kraft.\nDann sing\' ich: "Heilig, heilig, heilig!"\nIch will Dich sehen, ich will Dich sehen!'),
(9, '2066', 'Zieh mich hin zu Dir -  Draw me close to You', 'Draw me close to You, never let me go.\nI lay it all down again, to hear You say that I\'m Your friend.\nYou are my desire, there is none like You.\nCause no one else can take the place, to feel the warmth of Your embrace.\nHelp me find the way, to bring me back to You.\nYou\'re all I want, You\'re all I\'ve ever needed.\nYou\'re all I want, help me know You are near.', 'Zieh\' mich hin zu Dir, lass\' mich niemals los.\nIch lege alles vor Dich hin, und dank\' Dir dass ich Dein Freund bin.\nDich begehre ich, keiner ist wie Du.\nDu gibst, was niemand geben kann, Geborgenheit in Deinem Arm.\nZeige mir den Weg, führ\' mich zurück zu Dir.\nIch brauche Dich, ich will nur Dich alleine.\nIch brauche Dich, komm, sei ganz nah bei mir.'),
(9, '2067', 'Zion', 'O daughters of Zion\nO Abraham\'s sons\nHear the words of your Father\nHear His promise of love\nI will make you a blessing\nSo count the stars if you can\nYou will be a great nation\nI will give you this land\r\nI will bring you back home\nI\'ll bring you back home, oh my children\nYou will no longer roam\nLost and alone in the night\nThere is nothing on earth that could take you away\nOnce I gather you under my wings\nI will bring you all back home again\r\nThough you\'ve wandered like strangers\nTo the ends of the earth\nI will send you a savior\nI will finish my work\nYou have no other shepherd\nYou have no other lord\nGreen pastures are waiting in Zion once more\r\nSo we pray for the peace\nBut look to the East\nFor the Sun rises sudden and fierce\nEvery prophet and priest and king in the City\nWill look on the One they have pierced\nWe will mourn for the One we have pierced\r\nBut don\'t fear o my daughters\nOr sons of Abraham\nI will wash you with water\nI will offer the Lamb\nThough your sins were like scarlet\nThey\'ll be whiter than snow\nI have always been with you\nI will never let go', NULL),
(9, '2068', 'Zu Deinen Jesusaugen heb ich den Blick empor', NULL, 'Zu Deinen Jesusaugen heb\' ich den Blick empor\nund lausche Deinen Winken mit hingegeb\'nem Ohr.\nVon Deinem Angesichte strömt mir gar süße Ruh\',\no Jesus, o Geliebter, wie schön, wie hold bist Du!\r\nO Jesus, o Geliebter, es ist um mich gescheh\'n!\nMir ist die Welt versunken, seitdem ich Dich geseh\'n.\nOb ich auf Erden weile, ob in der Herrlichkeit,\nich ruh\' in Deinem Herzen für Zeit und Ewigkeit!\r\nDoch prüfe mich und schaue, ob ich Dein Bild schon trag\';\nich will Dir stille halten, gehorsam Tag für Tag,\nbis völlig ich verwandelt, bis ich durchheiligt bin,\nDir völlig gleich gestaltet an Seele, Geist und Sinn!\r\nO völlig gleich Dir werden, es wird, es muss so sein!\nMit Flammenzügen schriebst Du mir dies ins Herz hinein.\nUnd ehe Du nicht völlig Dein Bild in ihr geschaut,\nkannst nimmer Du entrücken die Königin, die Braut.\r\nHier kämpfe ich; doch hoffend schau ich nach droben schon,\nwo einst im weißen Kleide ich steh an Deinem Thron.\nOb ich auf Erden weile, ob in der Herrlichkeit,\nich ruh\' in Deinem Herzen für Zeit und Ewigkeit.'),
(9, '2069', 'Zu dem Wasser will ich gehen  -  To the River I am going   (Teurer Jesus, sieh hier bin ich / Precious Jesus, I am ready)', 'To the river I am going,\nbringing sins I cannot bear.\nCome and cleanse me, come forgive me,\nLord, I need to meet You there.\r\nIn these waters, healing mercy\nflows with freedom from despair.\nI am going to that river,\nLord, I need to meet You there.\r\nPrecious Jesus, I am ready\nto surrender every care.\nTake my hand now, lead me closer,\nLord, I need to meet You there.\r\nCome and join us, in the river,\nCome find life beyond compare.\nHe is calling, He is waiting,\nJesus longs to meet You there.', 'Zu dem Wasser will ich gehen,\nmache die Entscheidung fest,\nHerr, mein Leben will ich geben,\nweih\' es Dir, mein Jesus, jetzt.\r\nIn dem Wasser find\' ich Gnade,\nFriedensstrom, der mich durchfließt,\ntief will ich mich hier eintauchen,\nhier, wo Du, mein Jesus, bist.\r\nTeurer Jesus, sieh hier bin ich,\nhabe alles Dir bekannt,\nleg\' die Sorgen vor Dir nieder,\nJesus, nimm mich bei der Hand.\r\nKomm und bleib nicht an dem Ufer,\netwas Großes ist gescheh\'n,\nJesus ruft dich, Jesus sucht dich,\nJesus sehnt sich auch nach dir.'),
(9, '2070', 'Zu den Bergen blicke ich auf, wo kann Hilfe sein?   (Psalm 121)', NULL, 'Zu den Bergen blicke ich auf, wo kann Hilfe sein?\nDie Hilfe kommt von dem Herrn\nder Himmel und Erde gemacht!\nEr bewahrt dich vor dem Fall\ngibt auf dich acht\nder Retter Israels\nwird niemals müde noch matt\r\nJa der Herr ist dein Schutz\nder Herr ist dein Schild\nüber deiner rechten Hand\nüber deiner rechten Hand\ndass die Sonne nicht steche am Tag\nnoch der Mond bei Nacht.\nDein Leben wird bewahrt\njetzt bis in Ewigkeit.\r\nMeine - Hilfe - meine\nmeine Hilfe kommt von dem Herrn!'),
(9, '2071', 'Zu des Heilands Füßen, horchend auf sein Wort  -  At the Feet of Jesus, list’ning to His Word', 'At the feet of Jesus, list’ning to His word.\nLearning wisdom’s lesson from her loving Lord.\nMary, led by heav’nly grace, chose the meek disciple’s place.\nAt the feet of Jesus is the place for me.\nThere a humble learner would I choose to be.\r\nAt the feet of Jesus, pouring perfume rare.\nMary did her Saviour for the grave prepare.\nAnd, from love the “good work” done, she her Lord’s approval won.\nAt the feet of Jesus is the place for me.\nThere, in sweetest service would I ever be.\r\nAt the feet of Jesus, in that morning hour.\nLoving hearts, receiving resurrection pow’r.\nHaste with joy to preach the word: “Christ is risen, praise the Lord!”\nAt the feet of Jesus, risen now for me.\nI shall sing His praises through eternity.', 'Zu des Heilands Füßen, horchend auf Sein Wort,\nsetzte sich Maria in Bethanien dort;\nsie erwählt das gute Teil, suchte Jesum und Sein Heil.\nZu des Heilands Füßen ist mein Lieblingsort,\nwo ich still will sitzen, horchend auf Sein Wort.\r\nZu des Heilands Füßen, salbend ihren Herrn,\nlag Maria wieder, goss ihr Öl so gern!\nGnädig sah der Herr es an, denn aus Liebe war\'s getan.\nZu des Heilands Füßen dienend meinem Herrn,\nwill auch ich mich legen, geb\' ihm alles gern.\r\nZu des Heilands Füßen, früh zur Morgenstund,\nwurde der Maria Jesu Leben kund.\nGeh, verkünd\'ge, was geschah: Jesus lebt, Halleluja!\nZu des Heilands Füßen soll mein armer Mund\nSeine Gnad\' und Liebe ewig machen kund.'),
(9, '2072', 'Zu meines Heilands Füßen, lag ich in tiefem Schmerz', NULL, 'Zu meines Heilands Füßen lag ich in tiefem Schmerz;\nes wollt vor Weh zerfließen mein reuevolles Herz.\nDa hat Er mich erblicket, hat sich nicht abgewandt,\nhat mich ans Herz gedrücket, Er hat mich Freund genannt;\nhat mich ans Herz gedrücket, Er hat mich Freund genannt.\r\nO Welt mit deinen Schätzen, mit deinem eitlen Glanz\nes kann mich nicht ergötzen dein Ruhm und Ehrenkranz.\nEs ist mir viel zu wenig dein leerer, güld\'ner Tand,\nImmanuel, mein König, Er hat mich Freund genannt;\nImmanuel, mein König, Er hat mich Freund genannt.\r\nO Freund, der mich geliebet, nimm ganz mein Herze hin!\nJe mehr es sich Dir gibet, je größer mein Gewinn.\nUnd gilt\'s auch mit Dir leiden in diesem Freundschaftsstand.\nMein Herr, ich tu\'s mit Freuden, weil Du mich Freund genannt;\nMein Herr, ich tu\'s mit Freuden, weil Du mich Freund genannt.'),
(9, '2073', 'Zu Seiner Zeit macht Er alles wunderschön -  In His Time He makes all Things beautiful', 'In His time, in His time,\nHe makes all things beautiful,\nin His time.\nLord, please show me every day,\nas You\'re teaching me Your way,\nthat You do just what You say,\nin Your time.', 'Zu Seiner Zeit, zu Seiner Zeit,\nmacht Er alles wunderschön,\nzu Seiner Zeit.\nHerr, Du zeigst uns jeden Tag,\nwährend Du uns lehrst den Weg,\ndass Du tust, was Du sagst,\nzu Deiner Zeit.'),
(9, '2074', 'Zu tief der Abgrund der uns eins trennte  -  How great the Chasm that lay between us   (Halleluja, preist Den der mir Freiheit gab / Hallelujah, praise the One who set me free)', 'How great the chasm that lay between us,\nhow high the mountain I could not climb.\nIn desperation, I turned to heaven\nand spoke Your name into the night.\nThen through the darkness\nYour loving kindness tore through the shadows of my soul.\nThe work is ﬁnished, the end is written,\nJesus Christ, my living hope.\r\nHallelujah, praise the One who set me free,\nHallelujah, death has lost its grip on me.\nYou have broken every chain,\nthere\'s salvation in Your name.\nJesus Christ, my living hope. (2x)\r\nWho could imagine so great a mercy?\nWhat heart could fathom such boundless grace?\nThe God of ages stepped down from glory\nto wear my sin and bear my shame.\nThe cross has spoken, I am forgiven,\nthe king of kings calls me His own.\nBeautiful saviour, I\'m Yours forever,\nJesus Christ, my living hope.\r\n|:Then came the morning that sealed the promise,\nYour buried body began to breathe.\nOut of the silence, the roaring lion\ndeclared the grave has no claim on me.:|\nJesus, yours is the victory.', 'Zu tief der Abgrund der uns einst trennte,\nso hoch der Gipfel der vor mir lag.\nVoller Verzweiflung sah ich zum Himmel,\nsprach Deinen Namen in die Nacht.\nUnd in das Dunkel kam Deine Güte,\nzerriss die Schatten tief in mir.\nDie Nacht bezwungen der Sieg errungen,\nJesus meine Hoffnung lebt.\r\nHalleluja, preist Den der mir Freiheit gab,\nHalleluja, Er besiegte Tod und Grab.\nAlle Ketten sind gesprengt,\nvon dem Gott der Rettung bringt.\nJesus meine Hoffnung lebt. (2x)\r\nSo unvorstellbar ist Deine Gnade,\nso unbegreiflich ist Deine Gunst.\nDer Herr der Zeiten verließ den Himmel,\nnahm auf Sich meine Scham und Schuld.\nDas Kreuz bezeugt es mir ist vergeben,\nder König selbst nennt mich Sein Kind.\nEr ist mein Retter und ich gehör\' Ihm,\nJesus meine Hoffnung lebt.\r\n|:Dann kam der Morgen, so wie verheißen,\nDein toter Körper ist neu erwacht.\nMit lauter Stimme hast Du verkündet,\nkein Grab hat nun Anspruch mehr auf Mich:|\nJesus Dein Sieg bleibt ewiglich.'),
(9, '2075', 'Zum Himmel schaue ich empor  -  I\'m pressing on the upward Way   (Nach Dir, nach Dir verlangt mein Herz / Lord, lift me up and let me stand)', 'I\'m pressing on the upward way,\nnew heights I\'m gaining every day.\nStill praying as I\'m onward bound,\n"Lord, plant my feet on higher ground."\r\nLord, lift me up and let me stand,\nby faith, on heaven\'s table land.\nA higher plane than I have found,\nLord, plant my feet on higher ground.\r\nMy heart has no desire to stay,\nwhere doubts arise and fears dismay.\nTho\' some may dwell where these abound,\nmy prayer, my aim, is higher ground.\r\nI want to live above the world,\nthough Satan’s darts at me are hurled.\nFor faith has caught the joyful sound,\nthe song of saints on higher ground.\r\nI want to scale the utmost height\nand catch a gleam of glory bright.\nBut still I’ll pray till heav’n I’ve found,\n“Lord, plant my feet on higher ground.”\r\n(And once at the end of my path,\nthe heavens will be opened to me.\nThen I will see You in glory\non a higher ground always.)\r\n(O God, how blessed I am now;\nI am displaced to the kingdom of heaven.\nYes, spirit and soul are healthy:\nThou hast set me on higher ground.)', 'Zum Himmel schaue ich empor,\nwo man Dich preist im höher\'n Chor.\nDa wird in mir die Sehnsucht kund:\nHerr stelle mich auf höher\'n Grund.\r\nNach Dir, nach Dir verlangt mein Herz,\nzieh mich, Herr Jesus, himmelwärts!\nNur so wird Geist und Sinn gesund,\nHerr, stelle mich auf höher\'n Grund!\r\nAnbetung gibt es für den Geist,\nder sich dem Irdischen entreißt.\nD\'rum flehe ich zu jeder Stund\':\n"Herr, stelle mich auf höher\'n Grund!"\r\nSei still, mein Herz, und bete an!\nDas Werk ist schon für dich getan.\nAuf Golgatha im neuen Bund\nbist Du gestellt auf höher\'n Grund.\r\nSeit ich dies Heiligtum betrat,\nist jeder Weg ein Himmelspfad.\nSonst war mein Fuß stets matt und wund,\njetzt wandelt er auf höher\'m Grund.\r\nUnd einst am Ende meiner Bahn,\nwird mir der Himmel aufgetan.\nDann schau ich Dich in Herrlichkeit\nauf höher\'m Grunde allezeit.\r\nO Gott, wie selig bin ich jetzt;\nich bin ins Himmelreich versetzt.\nJa, Geist und Seele sind gesund:\nDu stelltest mich auf höher\'n Grund.'),
(9, '2076', 'Zur Heimat da droben ziehts mich aus der Welt', NULL, 'Zur Heimat da droben zieht\'s mich aus der Welt;\ndie Heimat da droben allein mir gefällt.\nNichts stillt hier mein Sehnen, mein Herz bleibt ja leer,\ndort ewig zu wohnen, ist, was ich begehr\',\ndort ewig zu wohnen, ist, was ich begehr\'.\r\nWas beugst du dich nieder, o Seele, in mir?\nWas suchst du vergebens die Ruhe allhier?\nEs brausen die Wogen der Trübsal daher;\noft schwankt da mein Schifflein auf tobendem Meer,\noft schwankt da mein Schifflein auf tobendem Meer.\r\nDort rinnt keine Zähre, dort wird es nie Nacht;\ndort leuchten die Sterne in himmlischer Pracht.\nUnd was dort vor allem mein Auge entzückt,\nist, dass es dort ewig den Heiland erblickt,\nist, dass es dort ewig den Heiland erblickt.\r\nLeb\' wohl denn, o Erde, ich bin nur dein Gast,\nbehalt\' deine Freunden, behalt\' deine Last!\nEs sind deine Berge und Täler gar schön,\ndoch nicht zu vergleichen den himmlischen Höh\'n,\ndoch nicht zu vergleichen den himmlischen Höh\'n.'),
(9, '2077', 'Zur Zeit des Abends, da wird es licht sein  -  Beyond the Sunset, oh blissful Morning', 'Beyond the sunset, oh blissful morning,\nwhen with our Saviour heaven is begun.\nEarth\'s toiling ended, oh glorious dawning,\nbeyond the sunset, when day is done.\r\nBeyond the sunset no clouds will gather,\nno storms will threaten, no fears annoy.\nOh day of gladness, oh day unending.\nbeyond the sunset, eternal joy.\r\nBeyond the sunset, a hand will guide me,\nto God, the Father, whom I adore.\nHis glorious presence, His words of welcome,\nwill be my portion on that fair shore.\r\nBeyond the sunset, oh glad reunion,\nwith our dear loved ones who\'ve gone before.\nIn that fair homeland we\'ll know no parting,\nbeyond the sunset forevermore.', 'Zur Zeit des Abends, da wird es licht sein,\nwenn Menschen irren von Gottes Wort,\ndann wird Er senden den Geist Elias,\ndie Braut zu führen zum ew\'gen Hort.\r\nZur Zeit des Abends, wenn\'s Wort wird leuchten\nund Plagen fallen auf Meer und Land,\ndann wird Er rufen, mein Herr und Heiland,\nden Staub zum Leben, im Lichtgewand.\r\nZur Zeit des Abends, wenn\'s Licht wird scheinen\nund Schatten dunkeln dies Erdental,\ndann wird ertönen die Festposaune,\ndie Braut zu holen zum Hochzeitsmahl.\r\nZur Zeit des Abends, wenn\'s Wort erfüllt ist\nund auch die Schatten im Licht vergeh\'n,\ndann werden Sel\'ge voller Anbetung\ndurch Freudentränen ihren König seh\'n.'),
(9, '2078', 'Zünde an Dein Feuer, Herr, im Herzen mir   (Quelle des Lebens und der Freude Quell)', NULL, 'Zünde an Dein Feuer, Herr, im Herzen mir,\nhell mög’ es brennen, lieber Heiland Dir.\nWas ich bin und habe, soll Dein eigen sein,\nin Deine Hände schließe fest mich ein.\r\nQuelle des Lebens und der Freude Quell,\nDu machst das Dunkel meiner Seele hell.\nDu hörst mein Beten, hilfst aus aller Not,\nJesus mein Heiland, mein Herr und Gott.\r\nWollest mich bewahren, wenn der Satan droht,\nDu bist der Retter, Herr, von Sünd\' und Tod.\nIn der Weltnacht Dunkel leuchtet mir als Stern,\nHerr, bleibe bei mir sei mir niemals fern.\r\nBald wird uns leuchten Gottes ew\'ges Licht,\nfreue dich Seele und verzage nicht.\nLass die Klagen schweigen, wenn das Lied erschallt,\nfröhlichen Glaubens, unser Herr kommt bald!'),
(9, '2079', 'Zwölf Jünger, ein Boot, vom Sturmwind bedroht   (Was immer Gott tut, es ist gut)', NULL, 'Zwölf Jünger, ein Boot, vom Sturmwind bedroht,\nsie riefen zu Jesus in ihrer Not.\nDoch als Er dem Wind und den Wellen gebot,\nsah\'n sie ihren König und Gott!\r\nWas immer Gott tut, es ist gut,\nauch wenn du\'s vielleicht nicht verstehst.\nBedenke, wenn du durch Nöte gehst:\nWas immer Gott tut, es ist gut!\r\nEin anderer Tag, ein anderer Kahn,\ndie Jünger, sie rudern, es geht nicht voran.\nDa geht auf dem Wasser ihr Jesus und spricht:\n"Ich bin es, nun fürchtet euch nicht!"\r\nEin Schiff auf dem Meer, verloren geglaubt,\ndie Mannschaft an Bord aller Hoffnung beraubt.\nGott sand\'t Seinen Engel zu Paulus bei Nacht,\nhat Rettung und Leben gebracht!\r\nUnd wenn auch die Welt aus den Fugen gerät,\nund sich nie mehr wieder so wie früher dreht.\nDann kommt umso näher dein König und Herr,\ndein Felsen, dein Anker, dein Gott!');
